  const keys = new Set(dataSafetyProtectedStorageKeys);
  for (let index = 0; index < storage.length; index += 1) {
    const key = rawDataSafetyKey(index);
    if (isDataSafetyProtectedStorageKey(key)) {
      keys.add(key);
    }
  }
