  targetState.restartPhase = {
    type: "kickoff",
    teamId,
    label: setPiecePhaseProfiles.kickoff.label,
    supportPlayerId: support?.id ?? null,
    openingKey: openingProfile.key,
    openingLabel: openingProfile.label,
  };
