  const title = String(values?.title ?? "").trim();
  if (!currentUser || !title) {
    return null;
  }
  const task = normalizeDashboardTask({
    title,
    note: values?.note ?? "",
    assignedTo: values?.assignedTo || currentUser.id,
    createdBy: currentUser.id,
    scope: values?.scope ?? "team",
  });
