  const firstKeys = [
    firstUser.id,
    firstUser.email,
    firstUser.username,
  ].map(normalizeDashboardUserIdentityValue).filter(Boolean);
  const secondKeys = new Set([
    secondUser.id,
    secondUser.email,
    secondUser.username,
  ].map(normalizeDashboardUserIdentityValue).filter(Boolean));
  return firstKeys.some((key) => secondKeys.has(key));
