function createSessionPlannerLibraryExercise(source = {}) {
  const now = getSessionPlannerLibraryNow();
  const createdAt = normalizeSessionPlannerTimestamp(source.createdAt) || now;
  const updatedAt = normalizeSessionPlannerTimestamp(source.updatedAt) || createdAt;
  const archivedAt = normalizeSessionPlannerTimestamp(source.archivedAt);
  const sourceType = String(source.source || "").trim() || "library";
  const createdBy = String(source.createdBy || "").trim();
  const updatedBy = String(source.updatedBy || createdBy || "").trim();
  const archivedBy = archivedAt ? String(source.archivedBy || "").trim() : "";

  return {
    ...createSessionPlannerBlock({
      ...source,
      id: source.id || createSessionPlannerStableId("exercise"),
      label: source.label || "Library Exercise",
      title: source.title || "Untitled Exercise",
      createdAt,
      updatedAt,
    }),
    archivedAt,
    archivedBy,
    createdBy,
    updatedBy,
    source: sourceType,
    tags: normalizeSessionPlannerLibraryTags(source.tags),
    versions: normalizeSessionPlannerLibraryVersions(source.versions),
  };
}

function cloneSessionPlannerLibraryExercise(exercise = {}) {
  return createSessionPlannerLibraryExercise({
    ...exercise,
    playerBoardPositions: normalizeSessionPlannerPlayerBoardPositions(exercise.playerBoardPositions),
    playerBoardColors: normalizeSessionPlannerPlayerBoardColors(exercise.playerBoardColors),
    tacticalElements: Array.isArray(exercise.tacticalElements)
      ? exercise.tacticalElements.map(cloneSessionPlannerTacticalElement)
      : [],
  });
}

function normalizeSessionPlannerExerciseLibraryList(sourceLibrary = []) {
  if (!Array.isArray(sourceLibrary)) {
    return [];
  }

  const usedIds = new Set();

  return sourceLibrary
    .filter((exercise) => exercise && typeof exercise === "object" && !Array.isArray(exercise))
    .map((exercise) => {
      const clonedExercise = cloneSessionPlannerLibraryExercise(exercise);
      let exerciseId = String(clonedExercise.id || "").trim() || createSessionPlannerStableId("exercise");
      while (usedIds.has(exerciseId)) {
        exerciseId = createSessionPlannerStableId("exercise");
      }
      usedIds.add(exerciseId);
      return {
        ...clonedExercise,
        id: exerciseId,
      };
    });
}

function normalizeSessionPlannerLibraryVersions(sourceVersions = []) {
  if (!Array.isArray(sourceVersions)) {
    return [];
  }

  return sourceVersions
    .filter((version) => version && typeof version === "object" && !Array.isArray(version))
    .map((version) => ({
      id: String(version.id || "").trim() || createSessionPlannerStableId("version"),
      createdAt: normalizeSessionPlannerTimestamp(version.createdAt) || getSessionPlannerLibraryNow(),
      createdBy: String(version.createdBy || "").trim(),
      reason: String(version.reason || "Updated").trim() || "Updated",
      title: String(version.title || "").trim(),
      focus: String(version.focus || "").trim(),
      phase: formatSessionPlannerMultiValue(version.phase),
      subPhase: formatSessionPlannerMultiValue(version.subPhase),
      tags: normalizeSessionPlannerLibraryTags(version.tags),
      minutes: Number.isFinite(Number(version.minutes)) ? Math.max(0, Number(version.minutes)) : 0,
      time: String(version.time || "").trim(),
      intensity: Number.isFinite(Number(version.intensity)) ? clamp(Number(version.intensity), 1, 5) : 3,
      pitchSize: String(version.pitchSize || "").trim(),
      material: String(version.material || "").trim(),
      objective: String(version.objective || "").trim(),
      why: String(version.why || "").trim(),
      organization: String(version.organization || "").trim(),
      principles: String(version.principles || "").trim(),
      diagram: String(version.diagram || "").trim() || "empty",
      tacticalPitchMode: normalizeSessionPlannerTacticalPitchMode(version.tacticalPitchMode),
      playerBoardLayoutMode: version.playerBoardLayoutMode === "manual" ? "manual" : "auto",
    }))
    .slice(0, sessionPlannerExerciseLibraryVersionLimit);
}

function createSessionPlannerLibraryVersionSnapshot(exercise = {}, reason = "Updated") {
  return {
    id: createSessionPlannerStableId("version"),
    createdAt: getSessionPlannerLibraryNow(),
    createdBy: getSessionPlannerLibraryUserId(),
    reason: String(reason || "Updated").trim() || "Updated",
    title: String(exercise.title || "").trim(),
    focus: String(exercise.focus || "").trim(),
    phase: formatSessionPlannerMultiValue(exercise.phase),
    subPhase: formatSessionPlannerMultiValue(exercise.subPhase),
    tags: normalizeSessionPlannerLibraryTags(exercise.tags),
    minutes: Number.isFinite(Number(exercise.minutes)) ? Math.max(0, Number(exercise.minutes)) : 0,
    time: String(exercise.time || "").trim(),
    intensity: Number.isFinite(Number(exercise.intensity)) ? clamp(Number(exercise.intensity), 1, 5) : 3,
    pitchSize: String(exercise.pitchSize || "").trim(),
    material: String(exercise.material || "").trim(),
    objective: String(exercise.objective || "").trim(),
    why: String(exercise.why || "").trim(),
    organization: String(exercise.organization || "").trim(),
    principles: String(exercise.principles || "").trim(),
    diagram: String(exercise.diagram || "").trim() || "empty",
    tacticalPitchMode: normalizeSessionPlannerTacticalPitchMode(exercise.tacticalPitchMode),
    playerBoardLayoutMode: exercise.playerBoardLayoutMode === "manual" ? "manual" : "auto",
  };
}

function appendSessionPlannerLibraryVersion(exercise = {}, reason = "Updated") {
  return [
    createSessionPlannerLibraryVersionSnapshot(exercise, reason),
    ...normalizeSessionPlannerLibraryVersions(exercise.versions),
  ].slice(0, sessionPlannerExerciseLibraryVersionLimit);
}

function isSessionPlannerLibraryExerciseArchived(exercise = {}) {
  return Boolean(normalizeSessionPlannerTimestamp(exercise.archivedAt));
}

function getSessionPlannerLibraryExercisesByArchiveState(archiveView = sessionPlannerLibraryArchiveView) {
  const view = archiveView === "archived" ? "archived" : "active";
  return getSessionPlannerExerciseLibrary().filter((exercise) =>
    view === "archived"
      ? isSessionPlannerLibraryExerciseArchived(exercise)
      : !isSessionPlannerLibraryExerciseArchived(exercise)
  );
}

function getSessionPlannerActiveExerciseLibrary() {
  return getSessionPlannerLibraryExercisesByArchiveState("active");
}

function getSessionPlannerLibraryArchiveCounts() {
  return getSessionPlannerExerciseLibrary().reduce(
    (counts, exercise) => {
      if (isSessionPlannerLibraryExerciseArchived(exercise)) {
        counts.archived += 1;
      } else {
        counts.active += 1;
      }
      return counts;
    },
    { active: 0, archived: 0 }
  );
}

function parseSessionPlannerExerciseLibraryPayload(rawLibrary) {
  if (!rawLibrary) {
    return null;
  }

  try {
    const parsedLibrary = JSON.parse(rawLibrary);
    const sourceLibrary = Array.isArray(parsedLibrary)
      ? parsedLibrary
      : parsedLibrary?.schema === sessionPlannerExerciseLibraryBackupSchema && Array.isArray(parsedLibrary.exercises)
        ? parsedLibrary.exercises
        : null;

    if (!Array.isArray(sourceLibrary)) {
      return null;
    }

    return normalizeSessionPlannerExerciseLibraryList(sourceLibrary);
  } catch {
    return null;
  }
}

function readSessionPlannerExerciseLibraryFromStorage(storageKey) {
  try {
    const rawLibrary = window.localStorage.getItem(storageKey);
    if (rawLibrary === null) {
      return null;
    }

    const exercises = parseSessionPlannerExerciseLibraryPayload(rawLibrary);
    return exercises ? { storageKey, exercises } : null;
  } catch {
    return null;
  }
}

function createSessionPlannerExerciseLibraryBackupEnvelope(exercises = []) {
  return {
    schema: sessionPlannerExerciseLibraryBackupSchema,
    savedAt: new Date().toISOString(),
    count: exercises.length,
    exercises,
  };
}

function writeSessionPlannerExerciseLibraryToStorage(exercises = []) {
  const normalizedLibrary = normalizeSessionPlannerExerciseLibraryList(exercises);
  const libraryText = JSON.stringify(normalizedLibrary);

  try {
    window.localStorage.setItem(sessionPlannerExerciseLibraryStorageKey, libraryText);
  } catch (error) {
    logEvent(error?.message || "Exercise library could not be saved centrally.");
    return {
      saved: false,
      backupSaved: false,
      exercises: normalizedLibrary,
      error,
    };
  }

  let backupSaved = true;
  try {
    window.localStorage.setItem(
      sessionPlannerExerciseLibraryBackupStorageKey,
      JSON.stringify(createSessionPlannerExerciseLibraryBackupEnvelope(normalizedLibrary))
    );
  } catch (error) {
    backupSaved = false;
    logEvent(error?.message || "Exercise library backup could not be saved centrally.");
  }

  if (typeof saveDataSafetySnapshot === "function") {
    saveDataSafetySnapshot("exercise-library-save");
  }

  return {
    saved: true,
    backupSaved,
    exercises: normalizedLibrary,
    error: null,
  };
}

async function findSessionPlannerExerciseLibraryInSnapshots() {
  try {
    const database = await openDataSafetyDatabase();
    const snapshots = await new Promise((resolve, reject) => {
      const transaction = database.transaction(dataSafetySnapshotStoreName, "readonly");
      const request = transaction.objectStore(dataSafetySnapshotStoreName).getAll();
      request.onsuccess = () => resolve(Array.from(request.result || []));
      request.onerror = () => reject(request.error);
    });

    const orderedSnapshots = snapshots.sort((a, b) =>
      String(b?.createdAt || b?.id || "").localeCompare(String(a?.createdAt || a?.id || ""))
    );

    for (const snapshot of orderedSnapshots) {
      const storage = snapshot?.storage && typeof snapshot.storage === "object" ? snapshot.storage : {};
      const candidates = [
        storage[sessionPlannerExerciseLibraryStorageKey],
        storage[sessionPlannerExerciseLibraryBackupStorageKey],
      ];

      for (const rawLibrary of candidates) {
        const exercises = parseSessionPlannerExerciseLibraryPayload(rawLibrary);
        if (exercises) {
          return exercises;
        }
      }
    }
  } catch {
    return null;
  }

  return null;
}

function queueSessionPlannerExerciseLibrarySnapshotRecovery() {
  if (sessionPlannerExerciseLibrarySnapshotRecoveryQueued) {
    return;
  }

  sessionPlannerExerciseLibrarySnapshotRecoveryQueued = true;
  findSessionPlannerExerciseLibraryInSnapshots().then((recoveredExercises) => {
    sessionPlannerExerciseLibrarySnapshotRecoveryQueued = false;
    if (!recoveredExercises || readSessionPlannerExerciseLibraryFromStorage(sessionPlannerExerciseLibraryStorageKey)) {
      return;
    }

    const writeResult = writeSessionPlannerExerciseLibraryToStorage(recoveredExercises);
    if (!writeResult.saved) {
      return;
    }

    sessionPlannerExerciseLibrary = writeResult.exercises;
    if (hubState?.activeWorkspaceId === "session-planner") {
      renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
      showSessionPlannerToast("Exercise Library restored from local backup.");
    }
  });
}

function readSessionPlannerExerciseLibrary() {
  const mainLibrary = readSessionPlannerExerciseLibraryFromStorage(sessionPlannerExerciseLibraryStorageKey);
  if (mainLibrary) {
    return mainLibrary.exercises;
  }

  const backupLibrary = readSessionPlannerExerciseLibraryFromStorage(sessionPlannerExerciseLibraryBackupStorageKey);
  if (backupLibrary) {
    writeSessionPlannerExerciseLibraryToStorage(backupLibrary.exercises);
    return backupLibrary.exercises;
  }

  queueSessionPlannerExerciseLibrarySnapshotRecovery();
  return normalizeSessionPlannerExerciseLibraryList(sessionPlannerDefaultExerciseLibrary);
}

function getSessionPlannerExerciseLibrary() {
  if (!Array.isArray(sessionPlannerExerciseLibrary)) {
    sessionPlannerExerciseLibrary = readSessionPlannerExerciseLibrary();
  }

  return sessionPlannerExerciseLibrary;
}

function normalizeSessionPlannerLibraryFolderVisibility(value) {
  return value === "personal" ? "personal" : "team";
}

function normalizeSessionPlannerLibraryFolderExerciseIds(sourceIds = []) {
  if (!Array.isArray(sourceIds)) {
    return [];
  }

  return Array.from(
    new Set(
      sourceIds
        .map((exerciseId) => String(exerciseId || "").trim())
        .filter(Boolean)
    )
  );
}

function createSessionPlannerLibraryFolder(source = {}) {
  const now = getSessionPlannerLibraryNow();
  const createdAt = normalizeSessionPlannerTimestamp(source.createdAt) || now;
  const updatedAt = normalizeSessionPlannerTimestamp(source.updatedAt) || createdAt;
  const archivedAt = normalizeSessionPlannerTimestamp(source.archivedAt);
  const createdBy = String(source.createdBy || "").trim();
  const updatedBy = String(source.updatedBy || createdBy || "").trim();

  return {
    id: String(source.id || "").trim() || createSessionPlannerStableId("folder"),
    name: String(source.name || "Untitled Folder").trim() || "Untitled Folder",
    visibility: normalizeSessionPlannerLibraryFolderVisibility(source.visibility),
    exerciseIds: normalizeSessionPlannerLibraryFolderExerciseIds(source.exerciseIds),
    createdAt,
    createdBy,
    updatedAt,
    updatedBy,
    archivedAt,
    archivedBy: archivedAt ? String(source.archivedBy || "").trim() : "",
    source: String(source.source || "").trim() || "library",
  };
}

function createSessionPlannerDefaultExerciseLibraryFolders() {
  const now = getSessionPlannerLibraryNow();
  return [
    createSessionPlannerLibraryFolder({
      id: "team-exercises",
      name: "Team Exercises",
      visibility: "team",
      exerciseIds: [],
      createdAt: now,
      updatedAt: now,
      source: "default",
    }),
  ];
}

function normalizeSessionPlannerExerciseLibraryFolders(sourceFolders = []) {
  if (!Array.isArray(sourceFolders)) {
    return [];
  }

  const usedIds = new Set();
  return sourceFolders
    .filter((folder) => folder && typeof folder === "object" && !Array.isArray(folder))
    .map((folder) => {
      const normalizedFolder = createSessionPlannerLibraryFolder(folder);
      let folderId = String(normalizedFolder.id || "").trim() || createSessionPlannerStableId("folder");
      while (usedIds.has(folderId)) {
        folderId = createSessionPlannerStableId("folder");
      }
      usedIds.add(folderId);
      return {
        ...normalizedFolder,
        id: folderId,
      };
    });
}

function isSessionPlannerLibraryFolderArchived(folder = {}) {
  return Boolean(normalizeSessionPlannerTimestamp(folder.archivedAt));
}

function parseSessionPlannerExerciseLibraryFoldersPayload(rawFolders) {
  if (!rawFolders) {
    return null;
  }

  try {
    const parsedFolders = JSON.parse(rawFolders);
    const sourceFolders = Array.isArray(parsedFolders)
      ? parsedFolders
      : parsedFolders?.schema === sessionPlannerExerciseLibraryFoldersBackupSchema && Array.isArray(parsedFolders.folders)
        ? parsedFolders.folders
        : null;

    if (!Array.isArray(sourceFolders)) {
      return null;
    }

    return normalizeSessionPlannerExerciseLibraryFolders(sourceFolders);
  } catch {
    return null;
  }
}

function readSessionPlannerExerciseLibraryFoldersFromStorage(storageKey) {
  try {
    const rawFolders = window.localStorage.getItem(storageKey);
    if (rawFolders === null) {
      return null;
    }

    const folders = parseSessionPlannerExerciseLibraryFoldersPayload(rawFolders);
    return folders ? { storageKey, folders } : null;
  } catch {
    return null;
  }
}

function createSessionPlannerExerciseLibraryFoldersBackupEnvelope(folders = []) {
  return {
    schema: sessionPlannerExerciseLibraryFoldersBackupSchema,
    savedAt: new Date().toISOString(),
    count: folders.length,
    folders,
  };
}

function writeSessionPlannerExerciseLibraryFoldersToStorage(folders = []) {
  const normalizedFolders = normalizeSessionPlannerExerciseLibraryFolders(folders);
  const foldersText = JSON.stringify(normalizedFolders);

  try {
    window.localStorage.setItem(sessionPlannerExerciseLibraryFoldersStorageKey, foldersText);
  } catch (error) {
    logEvent(error?.message || "Exercise library folders could not be saved centrally.");
    return {
      saved: false,
      backupSaved: false,
      folders: normalizedFolders,
      error,
    };
  }

  let backupSaved = true;
  try {
    window.localStorage.setItem(
      sessionPlannerExerciseLibraryFoldersBackupStorageKey,
      JSON.stringify(createSessionPlannerExerciseLibraryFoldersBackupEnvelope(normalizedFolders))
    );
  } catch (error) {
    backupSaved = false;
    logEvent(error?.message || "Exercise library folders backup could not be saved centrally.");
  }

  if (typeof saveDataSafetySnapshot === "function") {
    saveDataSafetySnapshot("exercise-library-folders-save");
  }

  return {
    saved: true,
    backupSaved,
    folders: normalizedFolders,
    error: null,
  };
}

function readSessionPlannerExerciseLibraryFolders() {
  const mainFolders = readSessionPlannerExerciseLibraryFoldersFromStorage(sessionPlannerExerciseLibraryFoldersStorageKey);
  if (mainFolders) {
    return mainFolders.folders;
  }

  const backupFolders = readSessionPlannerExerciseLibraryFoldersFromStorage(sessionPlannerExerciseLibraryFoldersBackupStorageKey);
  if (backupFolders) {
    writeSessionPlannerExerciseLibraryFoldersToStorage(backupFolders.folders);
    return backupFolders.folders;
  }

  return normalizeSessionPlannerExerciseLibraryFolders(createSessionPlannerDefaultExerciseLibraryFolders());
}

function getSessionPlannerExerciseLibraryFolders() {
  if (!Array.isArray(sessionPlannerExerciseLibraryFolders)) {
    sessionPlannerExerciseLibraryFolders = readSessionPlannerExerciseLibraryFolders();
  }

  return sessionPlannerExerciseLibraryFolders;
}

function writeSessionPlannerExerciseLibrary() {
  if (!Array.isArray(sessionPlannerExerciseLibrary)) {
    return false;
  }

  const result = writeSessionPlannerExerciseLibraryToStorage(sessionPlannerExerciseLibrary);
  if (result.saved) {
    sessionPlannerExerciseLibrary = result.exercises;
  }
  return result.saved;
}

function normalizeSessionPlannerMultiValue(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item).trim()).filter(Boolean);
  }

  return String(value || "")
    .split(/[,;\n]+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function formatSessionPlannerMultiValue(value) {
  return normalizeSessionPlannerMultiValue(value).join(", ");
}

function normalizeSessionPlannerLibraryTags(value) {
  const seenTags = new Set();
  return normalizeSessionPlannerMultiValue(value)
    .map((tag) => String(tag || "").replace(/^#+/, "").trim().replace(/\s+/g, " "))
    .filter(Boolean)
    .filter((tag) => {
      const normalizedTag = tag.toLowerCase();
      if (seenTags.has(normalizedTag)) {
        return false;
      }

      seenTags.add(normalizedTag);
      return true;
    })
    .slice(0, 24);
}

function formatSessionPlannerLibraryTags(value) {
  return normalizeSessionPlannerLibraryTags(value).join(", ");
}

function getSessionPlannerMultiValueSummary(value, fallback) {
  const values = normalizeSessionPlannerMultiValue(value);
  return values.length ? values.join(", ") : fallback;
}

function normalizeSessionPlannerPlayerBoardPositions(source = {}) {
  if (!source || typeof source !== "object" || Array.isArray(source)) {
    return {};
  }

  return Object.entries(source).reduce((positions, [playerId, value]) => {
    const x = Number(value?.x);
    const y = Number(value?.y);
    if (!playerId || !Number.isFinite(x) || !Number.isFinite(y)) {
      return positions;
    }

    positions[playerId] = {
      x: clamp(x, 0, 100),
      y: clamp(y, 0, 100),
    };
    return positions;
  }, {});
}

function normalizeSessionPlannerPlayerBoardColors(source = {}) {
  if (!source || typeof source !== "object" || Array.isArray(source)) {
    return {};
  }

  return Object.entries(source).reduce((colors, [playerId, value]) => {
    const color = normalizeTacticalColor(value, "");
    if (playerId && color) {
      colors[playerId] = color;
    }
    return colors;
  }, {});
}

function getSessionPlannerMultiSelectFieldConfig(field) {
  const configs = {
    phase: {
      label: "Phase",
      listOptions: periodizationOptionLibrary.matchPhases,
    },
    subPhase: {
      label: "Sub Phase",
      listOptions: periodizationOptionLibrary.subPhases,
    },
  };

  return configs[field] ?? null;
}

function refreshSessionPlannerMultiSelectFields(fields = []) {
  const block = getSessionPlannerSelectedBlock();
  const fieldList = Array.from(new Set((Array.isArray(fields) ? fields : [fields]).filter(Boolean)));

  if (!block || !fieldList.length) {
    return;
  }

  let refreshedAnyField = false;
  fieldList.forEach((field) => {
    const config = getSessionPlannerMultiSelectFieldConfig(field);
    const fieldElement = ui.sessionPlannerWorkspace?.querySelector(`[data-session-multiselect="${field}"]`);

    if (!config || !fieldElement) {
      return;
    }

    fieldElement.outerHTML = renderSessionPlannerMultiSelectField(block, field, config.label, {
      long: false,
      listOptions: config.listOptions,
    });
    refreshedAnyField = true;
  });

  if (!refreshedAnyField) {
    renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  }
}

function toggleSessionPlannerMultiSelectValue(field, value) {
  if (!sessionPlannerMultiSelectFields.has(field) || !value) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const values = normalizeSessionPlannerMultiValue(block[field]);
  const nextValues = values.includes(value)
    ? values.filter((item) => item !== value)
    : [...values, value];

  updateSelectedSessionPlannerBlockField(field, nextValues.join(", "));
  sessionPlannerMultiSelectOpenField = field;
  refreshSessionPlannerMultiSelectFields([field]);
}

function clearSessionPlannerMultiSelectValue(field) {
  if (!sessionPlannerMultiSelectFields.has(field)) {
    return;
  }

  updateSelectedSessionPlannerBlockField(field, "");
  sessionPlannerMultiSelectOpenField = field;
  refreshSessionPlannerMultiSelectFields([field]);
}

function normalizeSessionPlannerLibraryFilterValues(value) {
  const values = Array.isArray(value) ? value : normalizeSessionPlannerMultiValue(value);
  return Array.from(
    new Set(
      values
        .map((item) => String(item || "").trim())
        .filter((item) => item && item.toLowerCase() !== "all")
    )
  );
}

function getSessionPlannerLibraryFilterValues(filterKey) {
  if (filterKey === "phase") {
    return normalizeSessionPlannerLibraryFilterValues(
      sessionPlannerLibraryPhaseFilters.length ? sessionPlannerLibraryPhaseFilters : sessionPlannerLibraryPhaseFilter
    );
  }

  if (filterKey === "subPhase") {
    return normalizeSessionPlannerLibraryFilterValues(
      sessionPlannerLibrarySubPhaseFilters.length
        ? sessionPlannerLibrarySubPhaseFilters
        : sessionPlannerLibrarySubPhaseFilter
    );
  }

  return [];
}

function setSessionPlannerLibraryFilterValues(filterKey, values = []) {
  const normalizedValues = normalizeSessionPlannerLibraryFilterValues(values);
  if (filterKey === "phase") {
    sessionPlannerLibraryPhaseFilters = normalizedValues;
    sessionPlannerLibraryPhaseFilter = normalizedValues[0] || "all";
  }

  if (filterKey === "subPhase") {
    sessionPlannerLibrarySubPhaseFilters = normalizedValues;
    sessionPlannerLibrarySubPhaseFilter = normalizedValues[0] || "all";
  }
}

function toggleSessionPlannerLibraryFilterOpen(filterKey) {
  sessionPlannerLibraryFilterOpen = sessionPlannerLibraryFilterOpen === filterKey ? "" : filterKey;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function toggleSessionPlannerLibraryFilterValue(filterKey, value) {
  const cleanValue = String(value || "").trim();
  if (!cleanValue) {
    return;
  }

  const currentValues = getSessionPlannerLibraryFilterValues(filterKey);
  const nextValues = currentValues.includes(cleanValue)
    ? currentValues.filter((item) => item !== cleanValue)
    : [...currentValues, cleanValue];

  setSessionPlannerLibraryFilterValues(filterKey, nextValues);
  sessionPlannerLibraryFilterOpen = filterKey;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function clearSessionPlannerLibraryFilter(filterKey) {
  setSessionPlannerLibraryFilterValues(filterKey, []);
  sessionPlannerLibraryFilterOpen = filterKey;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function exerciseMatchesSessionPlannerLibraryFilterValue(exerciseValue, selectedValues = []) {
  if (!selectedValues.length) {
    return true;
  }

  const exerciseValues = normalizeSessionPlannerMultiValue(exerciseValue);
  return selectedValues.some((value) => exerciseValues.includes(value));
}

function getSessionPlannerVisibleLibraryFolders() {
  return getSessionPlannerExerciseLibraryFolders()
    .filter((folder) => !isSessionPlannerLibraryFolderArchived(folder))
    .sort((a, b) => {
      const visibilitySort = a.visibility.localeCompare(b.visibility);
      return visibilitySort || a.name.localeCompare(b.name);
    });
}

function getSessionPlannerArchivedLibraryFolders() {
  return getSessionPlannerExerciseLibraryFolders()
    .filter((folder) => isSessionPlannerLibraryFolderArchived(folder))
    .sort((a, b) => String(b.archivedAt || "").localeCompare(String(a.archivedAt || "")) || a.name.localeCompare(b.name));
}

function getSessionPlannerLibraryFolderById(folderId) {
  const targetId = String(folderId || "").trim();
  if (!targetId) {
    return null;
  }

  return getSessionPlannerExerciseLibraryFolders().find((folder) => folder.id === targetId) || null;
}

function getSessionPlannerLibraryFolderExerciseIdSet(folderId = sessionPlannerLibrarySelectedFolderId) {
  const targetFolderId = String(folderId || "all");
  const currentUserId = getSessionPlannerLibraryUserId();
  const visibleFolders = getSessionPlannerVisibleLibraryFolders();

  if (targetFolderId === "all") {
    return null;
  }

  if (targetFolderId === "team") {
    return new Set(
      visibleFolders
        .filter((folder) => folder.visibility === "team")
        .flatMap((folder) => normalizeSessionPlannerLibraryFolderExerciseIds(folder.exerciseIds))
    );
  }

  if (targetFolderId === "mine") {
    return new Set(
      visibleFolders
        .filter((folder) => folder.visibility === "personal" && (!folder.createdBy || folder.createdBy === currentUserId))
        .flatMap((folder) => normalizeSessionPlannerLibraryFolderExerciseIds(folder.exerciseIds))
    );
  }

  const folder = getSessionPlannerLibraryFolderById(targetFolderId);
  return new Set(normalizeSessionPlannerLibraryFolderExerciseIds(folder?.exerciseIds));
}

function exerciseMatchesSessionPlannerLibraryFolder(exercise = {}) {
  const folderExerciseIds = getSessionPlannerLibraryFolderExerciseIdSet();
  return !folderExerciseIds || folderExerciseIds.has(exercise.id);
}

function getSessionPlannerLibraryFolderCount(folderId, archiveView = sessionPlannerLibraryArchiveView) {
  const folderExerciseIds = getSessionPlannerLibraryFolderExerciseIdSet(folderId);
  return getSessionPlannerLibraryExercisesByArchiveState(archiveView).filter((exercise) =>
    !folderExerciseIds || folderExerciseIds.has(exercise.id)
  ).length;
}

function getSessionPlannerLibraryFolderName(folderId = sessionPlannerLibrarySelectedFolderId) {
  if (folderId === "all") {
    return "All Exercises";
  }

  if (folderId === "team") {
    return "Team";
  }

  if (folderId === "mine") {
    return "Mine";
  }

  return getSessionPlannerLibraryFolderById(folderId)?.name || "Folder";
}

function getUniqueSessionPlannerLibraryFolderName(baseName = "Untitled Folder", excludeFolderId = "") {
  const cleanBaseName = String(baseName || "Untitled Folder").trim().replace(/\s+/g, " ") || "Untitled Folder";
  const existingFolderNames = new Set(
    getSessionPlannerExerciseLibraryFolders()
      .filter((folder) => folder.id !== excludeFolderId && !isSessionPlannerLibraryFolderArchived(folder))
      .map((folder) => normalizeSessionPlannerLibraryTitle(folder.name))
      .filter(Boolean)
  );

  let candidate = cleanBaseName;
  let suffix = 2;
  while (existingFolderNames.has(normalizeSessionPlannerLibraryTitle(candidate))) {
    candidate = `${cleanBaseName} ${suffix}`;
    suffix += 1;
  }

  return candidate;
}

function selectSessionPlannerLibraryFolder(folderId = "all") {
  const normalizedFolderId = String(folderId || "all").trim() || "all";
  const isVirtualFolder = ["all", "team", "mine"].includes(normalizedFolderId);
  const targetFolder = getSessionPlannerLibraryFolderById(normalizedFolderId);
  const targetFolderId = isVirtualFolder || (targetFolder && !isSessionPlannerLibraryFolderArchived(targetFolder))
    ? normalizedFolderId
    : "all";

  sessionPlannerLibrarySelectedFolderId = targetFolderId;
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryEditingFolderId = "";
  sessionPlannerLibraryFilterOpen = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function startSessionPlannerExerciseLibraryFolderEdit(folderId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const folder = getSessionPlannerLibraryFolderById(folderId);
  if (!folder || isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  sessionPlannerLibraryEditingFolderId = folder.id;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function cancelSessionPlannerExerciseLibraryFolderEdit() {
  sessionPlannerLibraryEditingFolderId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function createSessionPlannerExerciseLibraryFolderFromForm(form) {
  if (!canEditSessionPlanner() || !form) {
    return;
  }

  const nameField = form.querySelector("[data-session-library-folder-name]");
  const visibilityField = form.querySelector("[data-session-library-folder-visibility]");
  const folderName = String(nameField?.value || "").trim().replace(/\s+/g, " ");
  if (!folderName) {
    showSessionPlannerToast("Add a folder name first.", "warning");
    return;
  }

  const folders = getSessionPlannerExerciseLibraryFolders();
  const folderNameExists = folders.some(
    (folder) =>
      !isSessionPlannerLibraryFolderArchived(folder) &&
      normalizeSessionPlannerLibraryTitle(folder.name) === normalizeSessionPlannerLibraryTitle(folderName)
  );
  if (folderNameExists) {
    showSessionPlannerToast("A folder with that name already exists.", "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const newFolder = createSessionPlannerLibraryFolder({
    id: createSessionPlannerStableId("folder"),
    name: folderName,
    visibility: normalizeSessionPlannerLibraryFolderVisibility(visibilityField?.value),
    exerciseIds: [],
    createdAt: now,
    createdBy: currentUserId,
    updatedAt: now,
    updatedBy: currentUserId,
    source: "user",
  });
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage([newFolder, ...folders]);

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be saved. No exercises were changed.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  sessionPlannerLibrarySelectedFolderId = newFolder.id;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Created folder: "${newFolder.name}".`
      : `Created folder: "${newFolder.name}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function updateSessionPlannerExerciseLibraryFolderFromForm(form) {
  if (!canEditSessionPlanner() || !form) {
    return;
  }

  const folder = getSessionPlannerLibraryFolderById(form.dataset.sessionLibraryFolderEditForm);
  if (!folder || isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  const nameField = form.querySelector("[data-session-library-folder-edit-name]");
  const visibilityField = form.querySelector("[data-session-library-folder-edit-visibility]");
  const folderName = String(nameField?.value || "").trim().replace(/\s+/g, " ");
  if (!folderName) {
    showSessionPlannerToast("Folder name cannot be empty.", "warning");
    return;
  }

  const folderNameExists = getSessionPlannerExerciseLibraryFolders().some(
    (item) =>
      item.id !== folder.id &&
      !isSessionPlannerLibraryFolderArchived(item) &&
      normalizeSessionPlannerLibraryTitle(item.name) === normalizeSessionPlannerLibraryTitle(folderName)
  );
  if (folderNameExists) {
    showSessionPlannerToast("A folder with that name already exists.", "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const nextFolder = createSessionPlannerLibraryFolder({
    ...folder,
    name: folderName,
    visibility: normalizeSessionPlannerLibraryFolderVisibility(visibilityField?.value),
    updatedAt: now,
    updatedBy: currentUserId,
  });
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage(
    getSessionPlannerExerciseLibraryFolders().map((item) => (item.id === folder.id ? nextFolder : item))
  );

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be updated. Exercises were not changed.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  sessionPlannerLibrarySelectedFolderId = nextFolder.id;
  sessionPlannerLibraryEditingFolderId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Updated folder: "${nextFolder.name}".`
      : `Updated folder: "${nextFolder.name}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function archiveSessionPlannerExerciseLibraryFolder(folderId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const folder = getSessionPlannerLibraryFolderById(folderId);
  if (!folder || isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  const shouldArchive = window.confirm(`Archive folder "${folder.name}"?\n\nExercises inside it will stay in the library and remain available from All Exercises.`);
  if (!shouldArchive) {
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage(
    getSessionPlannerExerciseLibraryFolders().map((item) =>
      item.id === folder.id
        ? {
            ...item,
            archivedAt: now,
            archivedBy: currentUserId,
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be archived. Exercises were not changed.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  if (sessionPlannerLibrarySelectedFolderId === folder.id) {
    sessionPlannerLibrarySelectedFolderId = "all";
  }
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryEditingFolderId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(`Archived folder: "${folder.name}". Exercises stayed saved.`);
}

function restoreSessionPlannerExerciseLibraryFolder(folderId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const folder = getSessionPlannerLibraryFolderById(folderId);
  if (!folder || !isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const restoredName = getUniqueSessionPlannerLibraryFolderName(folder.name, folder.id);
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage(
    getSessionPlannerExerciseLibraryFolders().map((item) =>
      item.id === folder.id
        ? {
            ...item,
            name: restoredName,
            archivedAt: "",
            archivedBy: "",
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be restored. Exercises were not changed.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  sessionPlannerLibrarySelectedFolderId = folder.id;
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryEditingFolderId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Restored folder: "${restoredName}".`
      : `Restored folder: "${restoredName}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function addSessionPlannerExerciseToLibraryFolder(exerciseId, folderId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  const folder = getSessionPlannerLibraryFolderById(folderId);
  if (!exercise || !folder || isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  if (isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast("Restore the exercise before placing it in a folder.", "warning");
    return;
  }

  const existingExerciseIds = normalizeSessionPlannerLibraryFolderExerciseIds(folder.exerciseIds);
  if (existingExerciseIds.includes(exercise.id)) {
    sessionPlannerLibrarySelectedFolderId = folder.id;
    renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
    showSessionPlannerToast(`"${exercise.title || "Exercise"}" is already in "${folder.name}".`, "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage(
    getSessionPlannerExerciseLibraryFolders().map((item) =>
      item.id === folder.id
        ? {
            ...item,
            exerciseIds: [...existingExerciseIds, exercise.id],
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be updated. The exercise stayed unchanged.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  sessionPlannerLibrarySelectedFolderId = folder.id;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Added "${exercise.title || "Exercise"}" to "${folder.name}".`
      : `Added "${exercise.title || "Exercise"}" to "${folder.name}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function removeSessionPlannerExerciseFromLibraryFolder(exerciseId, folderId = sessionPlannerLibrarySelectedFolderId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  const folder = getSessionPlannerLibraryFolderById(folderId);
  if (!exercise || !folder || isSessionPlannerLibraryFolderArchived(folder)) {
    return;
  }

  const existingExerciseIds = normalizeSessionPlannerLibraryFolderExerciseIds(folder.exerciseIds);
  if (!existingExerciseIds.includes(exercise.id)) {
    showSessionPlannerToast(`"${exercise.title || "Exercise"}" is not in "${folder.name}".`, "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const writeResult = writeSessionPlannerExerciseLibraryFoldersToStorage(
    getSessionPlannerExerciseLibraryFolders().map((item) =>
      item.id === folder.id
        ? {
            ...item,
            exerciseIds: existingExerciseIds.filter((itemExerciseId) => itemExerciseId !== exercise.id),
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );

  if (!writeResult.saved) {
    showSessionPlannerToast("The folder could not be updated. The exercise stayed in place.", "error");
    return;
  }

  sessionPlannerExerciseLibraryFolders = writeResult.folders;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Removed "${exercise.title || "Exercise"}" from "${folder.name}".`
      : `Removed "${exercise.title || "Exercise"}" from "${folder.name}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function getSessionPlannerLibraryOptionValues(key) {
  const values = getSessionPlannerLibraryExercisesByArchiveState()
    .flatMap((exercise) => normalizeSessionPlannerMultiValue(exercise[key]))
    .filter(Boolean);

  return Array.from(new Set(values)).sort((a, b) => a.localeCompare(b));
}

function normalizeSessionPlannerLibrarySortMode(value) {
  const sortValue = String(value || "").trim();
  return sessionPlannerLibrarySortOptions.some((option) => option.value === sortValue) ? sortValue : "updated";
}

function getSessionPlannerLibrarySortTimestamp(exercise = {}, key = "updated") {
  const value = key === "created" ? exercise.createdAt : exercise.updatedAt || exercise.createdAt;
  const timestamp = Date.parse(normalizeSessionPlannerTimestamp(value) || "");
  return Number.isFinite(timestamp) ? timestamp : 0;
}

function compareSessionPlannerLibraryExerciseTitles(a = {}, b = {}) {
  return String(a.title || "").localeCompare(String(b.title || ""), undefined, { sensitivity: "base" });
}

function compareSessionPlannerLibraryExercises(a = {}, b = {}) {
  const sortMode = normalizeSessionPlannerLibrarySortMode(sessionPlannerLibrarySortMode);

  if (sortMode === "created") {
    return (
      getSessionPlannerLibrarySortTimestamp(b, "created") -
        getSessionPlannerLibrarySortTimestamp(a, "created") ||
      compareSessionPlannerLibraryExerciseTitles(a, b)
    );
  }

  if (sortMode === "title") {
    return compareSessionPlannerLibraryExerciseTitles(a, b);
  }

  if (sortMode === "phase") {
    return (
      `${a.phase || ""} ${a.subPhase || ""} ${a.title || ""}`.localeCompare(
        `${b.phase || ""} ${b.subPhase || ""} ${b.title || ""}`,
        undefined,
        { sensitivity: "base" }
      ) ||
      getSessionPlannerLibrarySortTimestamp(b, "updated") -
        getSessionPlannerLibrarySortTimestamp(a, "updated")
    );
  }

  return (
    getSessionPlannerLibrarySortTimestamp(b, "updated") -
      getSessionPlannerLibrarySortTimestamp(a, "updated") ||
    compareSessionPlannerLibraryExerciseTitles(a, b)
  );
}

function getFilteredSessionPlannerExerciseLibrary() {
  const phaseFilters = getSessionPlannerLibraryFilterValues("phase");
  const subPhaseFilters = getSessionPlannerLibraryFilterValues("subPhase");
  const searchQuery = String(sessionPlannerLibrarySearchQuery || "").trim().toLowerCase();

  return getSessionPlannerLibraryExercisesByArchiveState()
    .filter((exercise) => {
      const phaseMatches = exerciseMatchesSessionPlannerLibraryFilterValue(exercise.phase, phaseFilters);
      const subPhaseMatches = exerciseMatchesSessionPlannerLibraryFilterValue(exercise.subPhase, subPhaseFilters);
      const folderMatches = exerciseMatchesSessionPlannerLibraryFolder(exercise);
      const searchableText = [
        exercise.title,
        exercise.focus,
        exercise.objective,
        exercise.phase,
        exercise.subPhase,
        formatSessionPlannerLibraryTags(exercise.tags),
      ]
        .filter(Boolean)
        .join(" ")
        .toLowerCase();
      const searchMatches = !searchQuery || searchableText.includes(searchQuery);
      return folderMatches && phaseMatches && subPhaseMatches && searchMatches;
    })
    .sort(compareSessionPlannerLibraryExercises);
}

function updateSessionPlannerLibraryFilter(filterKey, value) {
  setSessionPlannerLibraryFilterValues(filterKey, normalizeSessionPlannerLibraryFilterValues(value));
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function updateSessionPlannerLibraryArchiveView(value) {
  sessionPlannerLibraryArchiveView = value === "archived" ? "archived" : "active";
  sessionPlannerLibraryFilterOpen = "";
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function updateSessionPlannerLibrarySortMode(value) {
  sessionPlannerLibrarySortMode = normalizeSessionPlannerLibrarySortMode(value);
  sessionPlannerLibraryFilterOpen = "";
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function renderSessionPlannerLibraryResults() {
  const filteredExercises = getFilteredSessionPlannerExerciseLibrary();
  const libraryGrid = ui.sessionPlannerWorkspace?.querySelector(".session-library-modal-grid");
  const folderPanel = ui.sessionPlannerWorkspace?.querySelector(".session-library-folder-panel");
  const libraryModal = ui.sessionPlannerWorkspace?.querySelector(".session-library-modal");
  const editDialog = ui.sessionPlannerWorkspace?.querySelector("[data-session-library-edit-dialog]");
  const libraryCount = ui.sessionPlannerWorkspace?.querySelector(".session-library-count");
  const archiveTabs = ui.sessionPlannerWorkspace?.querySelector(".session-library-archive-tabs");
  const editExercise = getSessionPlannerLibraryEditExercise();

  if (libraryGrid) {
    libraryGrid.innerHTML = renderSessionPlannerLibrary(filteredExercises);
  }

  if (folderPanel) {
    folderPanel.outerHTML = renderSessionPlannerLibraryFolders();
  }

  if (editDialog) {
    if (editExercise) {
      editDialog.outerHTML = renderSessionPlannerLibraryEditDialog(editExercise);
    } else {
      editDialog.remove();
    }
  } else if (libraryModal && editExercise) {
    libraryModal.insertAdjacentHTML("beforeend", renderSessionPlannerLibraryEditDialog(editExercise));
  }

  if (libraryCount) {
    libraryCount.textContent = getSessionPlannerLibraryCountLabel(filteredExercises.length);
  }

  if (archiveTabs) {
    archiveTabs.outerHTML = renderSessionPlannerLibraryArchiveTabs();
  }
}

function updateSessionPlannerLibrarySearch(value) {
  sessionPlannerLibrarySearchQuery = String(value || "");
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerLibraryResults();
}

function getSessionPlannerLibraryExerciseById(exerciseId) {
  const targetId = String(exerciseId || "").trim();
  if (!targetId) {
    return null;
  }

  return getSessionPlannerExerciseLibrary().find((exercise) => exercise.id === targetId) || null;
}

function getSessionPlannerLibraryEditExercise() {
  if (!sessionPlannerLibraryEditExerciseId) {
    return null;
  }

  const exercise = getSessionPlannerLibraryExerciseById(sessionPlannerLibraryEditExerciseId);
  if (!exercise || isSessionPlannerLibraryExerciseArchived(exercise)) {
    sessionPlannerLibraryEditExerciseId = "";
    return null;
  }

  return exercise;
}

function startSessionPlannerLibraryExerciseEdit(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  if (!exercise) {
    return;
  }

  if (isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast("Restore the exercise before editing it.", "warning");
    return;
  }

  sessionPlannerLibraryEditExerciseId = exercise.id;
  sessionPlannerLibraryFilterOpen = "";
  renderSessionPlannerLibraryResults();
}

function cancelSessionPlannerLibraryExerciseEdit() {
  const exercise = getSessionPlannerLibraryExerciseById(sessionPlannerLibraryEditExerciseId);
  if (
    exercise &&
    hasSessionPlannerLibraryExerciseEditChanges(exercise) &&
    !window.confirm("Discard unsaved exercise edits?")
  ) {
    return;
  }

  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerLibraryResults();
}

function getUniqueSessionPlannerLibraryTitle(baseTitle = "Untitled Exercise", excludeExerciseId = "") {
  const cleanBaseTitle = String(baseTitle || "Untitled Exercise").trim() || "Untitled Exercise";
  const existingTitles = new Set(
    getSessionPlannerExerciseLibrary()
      .filter((exercise) => exercise.id !== excludeExerciseId)
      .map((exercise) => normalizeSessionPlannerLibraryTitle(exercise.title))
      .filter(Boolean)
  );

  let candidate = cleanBaseTitle;
  let suffix = 2;
  while (existingTitles.has(normalizeSessionPlannerLibraryTitle(candidate))) {
    candidate = `${cleanBaseTitle} ${suffix}`;
    suffix += 1;
  }

  return candidate;
}

function duplicateSessionPlannerLibraryExercise(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  if (!exercise) {
    return;
  }

  if (isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast("Restore the exercise before duplicating it.", "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const duplicateTitle = getUniqueSessionPlannerLibraryTitle(`${exercise.title || "Untitled Exercise"} Copy`);
  const duplicate = cloneSessionPlannerLibraryExercise({
    ...exercise,
    id: createSessionPlannerStableId("exercise"),
    title: duplicateTitle,
    createdAt: now,
    createdBy: currentUserId,
    updatedAt: now,
    updatedBy: currentUserId,
    archivedAt: "",
    archivedBy: "",
    source: "duplicate",
    versions: [createSessionPlannerLibraryVersionSnapshot(exercise, "Duplicated from original")],
  });

  const library = getSessionPlannerExerciseLibrary().map(cloneSessionPlannerLibraryExercise);
  const writeResult = writeSessionPlannerExerciseLibraryToStorage([duplicate, ...library]);
  if (!writeResult.saved) {
    showSessionPlannerToast("The duplicate could not be saved. The library was not changed.", "error");
    return;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryArchiveView = "active";
  sessionPlannerLibraryFilterOpen = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Duplicated and saved: "${duplicate.title}".`
      : `Duplicated and saved: "${duplicate.title}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function updateSessionPlannerLibraryExerciseFromEdit(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  if (!exercise || isSessionPlannerLibraryExerciseArchived(exercise)) {
    return;
  }

  const editFields = getSessionPlannerLibraryExerciseEditFields();
  const nextSnapshot = getSessionPlannerLibraryExerciseEditSnapshot(editFields);
  const nextTitle = nextSnapshot.title || "Untitled Exercise";
  const titleConflict = getSessionPlannerExerciseLibrary().some(
    (item) =>
      item.id !== exercise.id &&
      normalizeSessionPlannerLibraryTitle(item.title) === normalizeSessionPlannerLibraryTitle(nextTitle)
  );

  if (titleConflict) {
    showSessionPlannerToast("Another library exercise already uses that title.", "warning");
    return;
  }

  const hasChanges = hasSessionPlannerLibraryExerciseEditChanges(exercise, editFields);
  if (!hasChanges) {
    sessionPlannerLibraryEditExerciseId = "";
    renderSessionPlannerLibraryResults();
    showSessionPlannerToast("No library changes to save.", "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const nextExercise = cloneSessionPlannerLibraryExercise({
    ...exercise,
    ...nextSnapshot,
    updatedAt: now,
    updatedBy: currentUserId,
    versions: appendSessionPlannerLibraryVersion(exercise, "Edited"),
  });

  const writeResult = writeSessionPlannerExerciseLibraryToStorage(
    getSessionPlannerExerciseLibrary().map((item) => (item.id === exercise.id ? nextExercise : item))
  );
  if (!writeResult.saved) {
    showSessionPlannerToast("The edit could not be saved. The original exercise stayed intact.", "error");
    return;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  sessionPlannerLibraryEditExerciseId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Updated in library: "${nextExercise.title}".`
      : `Updated in library: "${nextExercise.title}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function getSessionPlannerLibraryExerciseEditFields() {
  const editFields = {};
  ui.sessionPlannerWorkspace
    ?.querySelectorAll("[data-session-library-edit-field]")
    .forEach((field) => {
      const fieldKey = field.dataset.sessionLibraryEditField;
      if (fieldKey) {
        editFields[fieldKey] = field.value;
      }
    });
  return editFields;
}

function getSessionPlannerLibraryExerciseEditSnapshot(source = {}) {
  return {
    title: String(source.title || "").trim() || "Untitled Exercise",
    focus: String(source.focus || "").trim(),
    phase: formatSessionPlannerMultiValue(source.phase),
    subPhase: formatSessionPlannerMultiValue(source.subPhase),
    tags: normalizeSessionPlannerLibraryTags(source.tags),
    minutes: Number.isFinite(Number(source.minutes)) ? Math.max(0, Number(source.minutes)) : 0,
    time: String(source.time || "").trim(),
    intensity: Number.isFinite(Number(source.intensity)) ? clamp(Number(source.intensity), 1, 5) : 3,
    pitchSize: String(source.pitchSize || "").trim(),
    material: String(source.material || "").trim(),
    objective: String(source.objective || "").trim(),
    why: String(source.why || "").trim(),
    organization: String(source.organization || "").trim(),
    principles: String(source.principles || "").trim(),
  };
}

function getSessionPlannerLibraryExerciseComparableSnapshot(exercise = {}) {
  return getSessionPlannerLibraryExerciseEditSnapshot({
    title: exercise.title,
    focus: exercise.focus,
    phase: exercise.phase,
    subPhase: exercise.subPhase,
    tags: exercise.tags,
    minutes: exercise.minutes,
    time: exercise.time,
    intensity: exercise.intensity,
    pitchSize: exercise.pitchSize,
    material: exercise.material,
    objective: exercise.objective,
    why: exercise.why,
    organization: exercise.organization,
    principles: exercise.principles,
  });
}

function hasSessionPlannerLibraryExerciseEditChanges(exercise = {}, editFields = getSessionPlannerLibraryExerciseEditFields()) {
  return JSON.stringify(getSessionPlannerLibraryExerciseComparableSnapshot(exercise)) !==
    JSON.stringify(getSessionPlannerLibraryExerciseEditSnapshot(editFields));
}

function saveSessionPlannerLibraryExerciseEditAsCopy(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerLibraryExerciseById(exerciseId);
  if (!exercise || isSessionPlannerLibraryExerciseArchived(exercise)) {
    return;
  }

  const nextSnapshot = getSessionPlannerLibraryExerciseEditSnapshot(getSessionPlannerLibraryExerciseEditFields());
  const requestedTitle = nextSnapshot.title || exercise.title || "Untitled Exercise";
  const copyTitle = getUniqueSessionPlannerLibraryTitle(
    normalizeSessionPlannerLibraryTitle(requestedTitle) === normalizeSessionPlannerLibraryTitle(exercise.title)
      ? `${requestedTitle} Copy`
      : requestedTitle
  );
  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const copiedExercise = cloneSessionPlannerLibraryExercise({
    ...exercise,
    ...nextSnapshot,
    id: createSessionPlannerStableId("exercise"),
    title: copyTitle,
    createdAt: now,
    createdBy: currentUserId,
    updatedAt: now,
    updatedBy: currentUserId,
    archivedAt: "",
    archivedBy: "",
    source: "edited-copy",
    versions: [createSessionPlannerLibraryVersionSnapshot(exercise, "Copied before edit")],
  });
  const writeResult = writeSessionPlannerExerciseLibraryToStorage(
    [copiedExercise, ...getSessionPlannerExerciseLibrary()]
  );
  if (!writeResult.saved) {
    showSessionPlannerToast("The copy could not be saved. The original exercise stayed intact.", "error");
    return;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryArchiveView = "active";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved
      ? `Saved copy: "${copiedExercise.title}".`
      : `Saved copy: "${copiedExercise.title}". Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
}

function normalizeSessionPlannerLibraryTitle(title = "") {
  return String(title || "")
    .trim()
    .replace(/\s+/g, " ")
    .toLowerCase();
}

function findSessionPlannerLibraryExerciseIndexByTitle(title = "", options = {}) {
  const normalizedTitle = normalizeSessionPlannerLibraryTitle(title);
  if (!normalizedTitle) {
    return -1;
  }

  const includeArchived = options.includeArchived ?? false;
  return getSessionPlannerExerciseLibrary().findIndex(
    (item) =>
      (includeArchived || !isSessionPlannerLibraryExerciseArchived(item)) &&
      normalizeSessionPlannerLibraryTitle(item.title) === normalizedTitle
  );
}

function buildSessionPlannerLibraryExerciseFromBlock(block) {
  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  return createSessionPlannerLibraryExercise({
    ...block,
    id: createSessionPlannerStableId("exercise"),
    label: "Library Exercise",
    createdAt: now,
    updatedAt: now,
    createdBy: currentUserId,
    updatedBy: currentUserId,
    archivedAt: "",
    archivedBy: "",
    source: "session",
    title: String(block.title || "").trim() || "Untitled Exercise",
    focus: String(block.focus || "").trim(),
    phase: block.phase || "",
    subPhase: block.subPhase || "",
    tags: [],
    minutes: block.minutes,
    time: block.time || "",
    intensity: block.intensity,
    pitchSize: block.pitchSize || "",
    material: block.material || "",
    objective: block.objective || "",
    why: block.why || "",
    organization: block.organization || "",
    principles: block.principles || "",
    diagram: block.diagram || "empty",
    tacticalPitchMode: normalizeSessionPlannerTacticalPitchMode(block.tacticalPitchMode),
    playerBoardLayoutMode: block.playerBoardLayoutMode === "manual" ? "manual" : "auto",
    visualImage: block.visualImage || "",
    playerBoardPositions: normalizeSessionPlannerPlayerBoardPositions(block.playerBoardPositions),
    playerBoardColors: normalizeSessionPlannerPlayerBoardColors(block.playerBoardColors),
    tacticalElements: Array.isArray(block.tacticalElements)
      ? block.tacticalElements.map(cloneSessionPlannerTacticalElement)
      : [],
  });
}

function renderSessionPlannerToast() {
  if (!ui.sessionPlannerWorkspace) {
    return;
  }

  const existingToast = ui.sessionPlannerWorkspace.querySelector("[data-session-toast]");
  if (!sessionPlannerToastMessage) {
    existingToast?.remove();
    return;
  }

  const toastMarkup = `
    <div class="session-toast is-${escapeHtml(sessionPlannerToastTone)}" data-session-toast role="status" aria-live="polite">
      <strong>${escapeHtml(sessionPlannerToastMessage)}</strong>
    </div>
  `;

  if (existingToast) {
    existingToast.outerHTML = toastMarkup;
    return;
  }

  ui.sessionPlannerWorkspace.insertAdjacentHTML("beforeend", toastMarkup);
}

function showSessionPlannerToast(message, tone = "success") {
  sessionPlannerToastMessage = String(message || "");
  sessionPlannerToastTone = tone;
  renderSessionPlannerToast();

  if (sessionPlannerToastTimeoutId) {
    window.clearTimeout(sessionPlannerToastTimeoutId);
  }

  sessionPlannerToastTimeoutId = window.setTimeout(() => {
    sessionPlannerToastMessage = "";
    renderSessionPlannerToast();
  }, 3200);
}

function commitSessionPlannerExerciseToLibrary(exercise, mode = "new", existingExerciseId = "") {
  if (!exercise) {
    return false;
  }

  const library = getSessionPlannerExerciseLibrary().map(cloneSessionPlannerLibraryExercise);
  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const replaceIndex =
    mode === "replace"
      ? library.findIndex((item) =>
          existingExerciseId
            ? item.id === existingExerciseId
            : normalizeSessionPlannerLibraryTitle(item.title) === normalizeSessionPlannerLibraryTitle(exercise.title)
        )
      : -1;

  let toastMessage = `Saved to library: "${exercise.title || "Untitled Exercise"}".`;

  if (replaceIndex >= 0) {
    const existingExercise = library[replaceIndex];
    exercise.id = library[replaceIndex].id;
    library[replaceIndex] = cloneSessionPlannerLibraryExercise({
      ...exercise,
      createdAt: existingExercise.createdAt || exercise.createdAt || now,
      createdBy: existingExercise.createdBy || exercise.createdBy || currentUserId,
      updatedAt: now,
      updatedBy: currentUserId,
      archivedAt: "",
      archivedBy: "",
      source: existingExercise.source || exercise.source || "session",
      versions: appendSessionPlannerLibraryVersion(existingExercise, "Replaced from session"),
    });
    toastMessage = `Updated in library: "${exercise.title || "Untitled Exercise"}".`;
  } else {
    const nextExerciseTitle =
      mode === "duplicate"
        ? getUniqueSessionPlannerLibraryTitle(`${exercise.title || "Untitled Exercise"} Copy`, existingExerciseId)
        : exercise.title;
    library.unshift(cloneSessionPlannerLibraryExercise({
      ...exercise,
      title: nextExerciseTitle,
      createdAt: exercise.createdAt || now,
      createdBy: exercise.createdBy || currentUserId,
      updatedAt: now,
      updatedBy: currentUserId,
      archivedAt: "",
      archivedBy: "",
      source: exercise.source || "session",
      versions:
        mode === "duplicate"
          ? [createSessionPlannerLibraryVersionSnapshot(exercise, "Duplicated from session")]
          : normalizeSessionPlannerLibraryVersions(exercise.versions),
    }));
    if (mode === "duplicate") {
      toastMessage = `Duplicated and saved: "${nextExerciseTitle || "Untitled Exercise"}".`;
    }
  }

  const writeResult = writeSessionPlannerExerciseLibraryToStorage(library);
  if (!writeResult.saved) {
    showSessionPlannerToast("The library could not be saved. Nothing was overwritten.", "error");
    return false;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  setSessionPlannerLibraryFilterValues("phase", normalizeSessionPlannerMultiValue(exercise.phase));
  setSessionPlannerLibraryFilterValues("subPhase", normalizeSessionPlannerMultiValue(exercise.subPhase));
  sessionPlannerLibrarySearchQuery = "";
  sessionPlannerLibraryOpen = true;
  sessionPlannerLibraryEditExerciseId = "";
  sessionPlannerLibraryFilterOpen = "";
  sessionPlannerPendingLibrarySave = null;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    writeResult.backupSaved ? toastMessage : `${toastMessage} Backup could not be updated.`,
    writeResult.backupSaved ? "success" : "warning"
  );
  return true;
}

function queueSessionPlannerLibrarySaveConflict(exercise, existingExercise) {
  sessionPlannerPendingLibrarySave = {
    exercise: cloneSessionPlannerLibraryExercise(exercise),
    existingExerciseId: existingExercise.id,
    existingTitle: existingExercise.title || exercise.title || "Untitled Exercise",
  };
  sessionPlannerLibraryOpen = false;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function resolveSessionPlannerLibrarySaveConflict(action) {
  if (!sessionPlannerPendingLibrarySave) {
    return;
  }

  const { exercise, existingExerciseId } = sessionPlannerPendingLibrarySave;
  if (action === "replace" || action === "duplicate") {
    commitSessionPlannerExerciseToLibrary(
      cloneSessionPlannerLibraryExercise(exercise),
      action,
      existingExerciseId
    );
    return;
  }

  sessionPlannerPendingLibrarySave = null;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function assignSessionPlannerBlockFieldValue(block, field, rawValue) {
  if (!block || !(field in block)) {
    return false;
  }

  if (field === "minutes") {
    block[field] = Math.max(0, Number(rawValue) || 0);
  } else if (field === "intensity") {
    block[field] = clamp(Number(rawValue) || 1, 1, 5);
  } else if (sessionPlannerMultiSelectFields.has(field)) {
    block[field] = formatSessionPlannerMultiValue(rawValue);
  } else {
    block[field] = rawValue;
  }

  return true;
}

function syncSelectedSessionPlannerBlockFieldsFromDom() {
  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  let hasChanged = false;
  const changedFields = [];
  ui.sessionPlannerWorkspace
    ?.querySelectorAll("[data-session-field]")
    .forEach((field) => {
      const fieldKey = field.dataset.sessionField;
      if (!fieldKey || !(fieldKey in block)) {
        return;
      }

      const previousValue = block[fieldKey];
      if (assignSessionPlannerBlockFieldValue(block, fieldKey, field.value) && block[fieldKey] !== previousValue) {
        hasChanged = true;
        changedFields.push(fieldKey);
      }
    });

  if (hasChanged) {
    markSessionPlannerBlockFieldsUpdated(block, changedFields);
    writeSessionPlannerState();
  }
}

function saveSelectedSessionPlannerExerciseToLibrary() {
  if (!canEditSessionPlanner()) {
    return;
  }

  syncSelectedSessionPlannerBlockFieldsFromDom();

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const exercise = buildSessionPlannerLibraryExerciseFromBlock(block);
  const existingIndex = findSessionPlannerLibraryExerciseIndexByTitle(exercise.title);

  if (existingIndex >= 0) {
    queueSessionPlannerLibrarySaveConflict(exercise, getSessionPlannerExerciseLibrary()[existingIndex]);
    return;
  }

  commitSessionPlannerExerciseToLibrary(exercise, "new");
}

function deleteSessionPlannerLibraryExercise(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const library = getSessionPlannerExerciseLibrary();
  const exercise = library.find((item) => item.id === exerciseId);
  if (!exercise) {
    return;
  }

  if (isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast(`"${exercise.title || "Exercise"}" is already archived.`, "warning");
    return;
  }

  const shouldArchive = window.confirm(`Archive "${exercise.title || "this exercise"}" from the library?\n\nIt will stay saved and can be restored from Archive.`);
  if (!shouldArchive) {
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const writeResult = writeSessionPlannerExerciseLibraryToStorage(
    library.map((item) =>
      item.id === exerciseId
        ? {
            ...item,
            archivedAt: now,
            archivedBy: currentUserId,
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );
  if (!writeResult.saved) {
    showSessionPlannerToast("The library could not be updated. The exercise stayed active.", "error");
    return;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(`Archived in library: "${exercise.title || "Exercise"}".`);
}

function restoreSessionPlannerLibraryExercise(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const library = getSessionPlannerExerciseLibrary();
  const exercise = library.find((item) => item.id === exerciseId);
  if (!exercise) {
    return;
  }

  if (!isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast(`"${exercise.title || "Exercise"}" is already active.`, "warning");
    return;
  }

  const now = getSessionPlannerLibraryNow();
  const currentUserId = getSessionPlannerLibraryUserId();
  const writeResult = writeSessionPlannerExerciseLibraryToStorage(
    library.map((item) =>
      item.id === exerciseId
        ? {
            ...item,
            archivedAt: "",
            archivedBy: "",
            updatedAt: now,
            updatedBy: currentUserId,
          }
        : item
    )
  );
  if (!writeResult.saved) {
    showSessionPlannerToast("The exercise could not be restored. It stayed archived.", "error");
    return;
  }

  sessionPlannerExerciseLibrary = writeResult.exercises;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(`Restored to library: "${exercise.title || "Exercise"}".`);
}

function createSessionPlannerDefaultSession(dateValue = formatScheduleDateValue(new Date())) {
  const possessionBlock = getSessionPlannerActiveExerciseLibrary()[0] || sessionPlannerDefaultExerciseLibrary[0];
  const blocks = [
    createSessionPlannerBlock({
      id: "warm-up",
      label: "Warm Up",
      title: "Activation",
      focus: "Prepare the body and the football brain",
      minutes: 12,
      intensity: 2,
      pitchSize: "20m x 20m",
      diagram: "build-up",
    }),
    createSessionPlannerBlock({
      id: "block-1",
      label: "Block 1",
      title: "Technical Rhythm",
      focus: "Passing detail and first touch direction",
      minutes: 16,
      intensity: 3,
      pitchSize: "30m x 24m",
      diagram: "build-up",
    }),
    createSessionPlannerBlock({
      ...possessionBlock,
      id: "block-2",
      label: "Block 2",
    }),
    createSessionPlannerBlock({
      id: "game",
      label: "Game",
      title: "Game Form",
      focus: "Transfer the block into live decisions",
      minutes: 20,
      intensity: 4,
      pitchSize: "BSG",
      diagram: "final-third",
    }),
  ];

  return {
    id: `session-${dateValue}`,
    date: dateValue,
    title: "Training Session",
    theme: "Possession and pressing connection",
    selectedBlockId: "block-2",
    blocks,
  };
}

function createSessionPlannerEmptySession(dateValue = formatScheduleDateValue(new Date())) {
  return {
    id: `session-${dateValue}`,
    date: dateValue,
    title: getScheduledSessionTitleForDate(dateValue) || "Session",
    theme: "",
    selectedBlockId: "",
    blocks: [],
  };
}

function cloneSessionPlannerSession(session = {}) {
  const date = session.date || formatScheduleDateValue(new Date());
  const blocks = Array.isArray(session.blocks) ? session.blocks.map(createSessionPlannerBlock) : [];
  const selectedBlockId = blocks.some((block) => block.id === session.selectedBlockId)
    ? session.selectedBlockId
    : blocks[0]?.id ?? "";
  const rawTitle = String(session.title ?? "").trim();
  const isLegacyEmptyTitle = rawTitle.toLowerCase() === "no session planned";
  const title = !isLegacyEmptyTitle && rawTitle
    ? rawTitle
    : getScheduledSessionTitleForDate(date) || (blocks.length ? "Training Session" : "Session");

  return {
    id: session.id || `session-${date}`,
    date,
    title,
    theme: session.theme || "",
    selectedBlockId,
    blocks,
  };
}

function createSessionPlannerDefaultState() {
  const selectedDate = formatScheduleDateValue(new Date());
  const defaultSession = createSessionPlannerDefaultSession(selectedDate);

  return {
    selectedDate,
    sessions: {
      [selectedDate]: defaultSession,
    },
  };
}

function parseSessionPlannerBlockReductionGuardTime(value) {
  const timestamp = typeof value === "number" ? value : new Date(value || 0).getTime();
  return Number.isFinite(timestamp) ? timestamp : 0;
}

function normalizeSessionPlannerBlockReductionGuard(source = {}) {
  const guard = source?.[sessionPlannerBlockReductionGuardKey];
  if (!guard || typeof guard !== "object" || Array.isArray(guard)) {
    return {};
  }

  const now = Date.now();
  return Object.entries(guard).reduce((normalizedGuard, [dateValue, timestampValue]) => {
    const timestamp = parseSessionPlannerBlockReductionGuardTime(timestampValue);
    if (timestamp && now - timestamp <= sessionPlannerBlockReductionGuardMaxAgeMs) {
      normalizedGuard[dateValue] = timestamp;
    }
    return normalizedGuard;
  }, {});
}

function canReduceSessionPlannerBlocksForDate(source, dateValue) {
  return Boolean(normalizeSessionPlannerBlockReductionGuard(source)[dateValue]);
}

function normalizeSessionPlannerBlockDeletionTombstones(source = {}) {
  const tombstones = source?.[sessionPlannerBlockDeletionTombstoneKey];
  if (!tombstones || typeof tombstones !== "object" || Array.isArray(tombstones)) {
    return {};
  }

  return Object.entries(tombstones).reduce((normalized, [dateValue, blockMap]) => {
    if (!blockMap || typeof blockMap !== "object" || Array.isArray(blockMap)) {
      return normalized;
    }

    const normalizedBlocks = Object.entries(blockMap).reduce((blocks, [blockId, timestampValue]) => {
      const cleanBlockId = String(blockId || "").trim();
      const timestamp = parseSessionPlannerBlockReductionGuardTime(timestampValue);
      if (cleanBlockId && timestamp) {
        blocks[cleanBlockId] = new Date(timestamp).toISOString();
      }
      return blocks;
    }, {});

    const cleanDate = String(dateValue || "").trim();
    if (cleanDate && Object.keys(normalizedBlocks).length) {
      normalized[cleanDate] = normalizedBlocks;
    }
    return normalized;
  }, {});
}

function markSessionPlannerBlockReductionAllowed(dateValue) {
  if (!sessionPlannerState || !dateValue) {
    return;
  }

  sessionPlannerState[sessionPlannerBlockReductionGuardKey] = {
    ...normalizeSessionPlannerBlockReductionGuard(sessionPlannerState),
    [dateValue]: Date.now(),
  };
}

function markSessionPlannerBlockDeleted(dateValue, blockId) {
  const cleanDate = String(dateValue || "").trim();
  const cleanBlockId = String(blockId || "").trim();
  if (!sessionPlannerState || !cleanDate || !cleanBlockId) {
    return;
  }

  const tombstones = normalizeSessionPlannerBlockDeletionTombstones(sessionPlannerState);
  sessionPlannerState[sessionPlannerBlockDeletionTombstoneKey] = {
    ...tombstones,
    [cleanDate]: {
      ...(tombstones[cleanDate] || {}),
      [cleanBlockId]: new Date().toISOString(),
    },
  };
  markSessionPlannerBlockReductionAllowed(cleanDate);
}

function applySessionPlannerBlockReductionGuard(targetState, sourceState) {
  const guard = normalizeSessionPlannerBlockReductionGuard(sourceState);
  if (Object.keys(guard).length) {
    targetState[sessionPlannerBlockReductionGuardKey] = guard;
  } else {
    delete targetState[sessionPlannerBlockReductionGuardKey];
  }
  return targetState;
}

function applySessionPlannerBlockDeletionTombstones(targetState, ...sourceStates) {
  const tombstones = sourceStates.reduce((merged, sourceState) => {
    const next = normalizeSessionPlannerBlockDeletionTombstones(sourceState);
    Object.entries(next).forEach(([dateValue, blockMap]) => {
      merged[dateValue] = {
        ...(merged[dateValue] || {}),
        ...blockMap,
      };
    });
    return merged;
  }, {});

  if (Object.keys(tombstones).length) {
    targetState[sessionPlannerBlockDeletionTombstoneKey] = tombstones;
  } else {
    delete targetState[sessionPlannerBlockDeletionTombstoneKey];
  }
  return targetState;
}

function getSessionPlannerDeletedBlockIds(source, dateValue) {
  return new Set(Object.keys(normalizeSessionPlannerBlockDeletionTombstones(source)[dateValue] || {}));
}

function cloneSessionPlannerBlockMergeValue(value) {
  if (!value || typeof value !== "object") {
    return value;
  }

  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return Array.isArray(value) ? [...value] : { ...value };
  }
}

function isSessionPlannerBlockFieldEmptyValue(value) {
  if (value === null || value === undefined) {
    return true;
  }
  if (typeof value === "string") {
    return value.trim() === "";
  }
  if (Array.isArray(value)) {
    return value.length === 0;
  }
  if (typeof value === "object") {
    return Object.keys(value).length === 0;
  }
  return false;
}

function getSessionPlannerBlockFieldUpdatedAtMs(block = {}, field) {
  return parseSessionPlannerTimestampMs(block?.[sessionPlannerBlockFieldUpdatedAtKey]?.[field]);
}

function markSessionPlannerBlockFieldsUpdated(block, fields = []) {
  if (!block) {
    return;
  }

  const validFields = fields.filter((field) => sessionPlannerBlockMergeFieldSet.has(field));
  if (!validFields.length) {
    return;
  }

  const timestamp = new Date().toISOString();
  block[sessionPlannerBlockFieldUpdatedAtKey] = {
    ...normalizeSessionPlannerBlockFieldMeta(block[sessionPlannerBlockFieldUpdatedAtKey]),
  };
  validFields.forEach((field) => {
    block[sessionPlannerBlockFieldUpdatedAtKey][field] = timestamp;
  });
  block.updatedAt = timestamp;
}

function mergeSessionPlannerBlockForWrite(existingBlock, incomingBlock) {
  const existing = createSessionPlannerBlock(existingBlock);
  const incoming = createSessionPlannerBlock(incomingBlock);
  const merged = createSessionPlannerBlock({
    ...incoming,
    id: incoming.id || existing.id,
    createdAt: incoming.createdAt || existing.createdAt,
  });
  const mergedMeta = {
    ...normalizeSessionPlannerBlockFieldMeta(existing[sessionPlannerBlockFieldUpdatedAtKey]),
    ...normalizeSessionPlannerBlockFieldMeta(incoming[sessionPlannerBlockFieldUpdatedAtKey]),
  };

  sessionPlannerBlockMergeFields.forEach((field) => {
    const existingTimestamp = getSessionPlannerBlockFieldUpdatedAtMs(existing, field);
    const incomingTimestamp = getSessionPlannerBlockFieldUpdatedAtMs(incoming, field);
    const existingValue = existing[field];
    const incomingValue = incoming[field];

    if (existingTimestamp && (!incomingTimestamp || existingTimestamp > incomingTimestamp)) {
      merged[field] = cloneSessionPlannerBlockMergeValue(existingValue);
      mergedMeta[field] = new Date(existingTimestamp).toISOString();
      return;
    }

    if (!existingTimestamp && !incomingTimestamp && isSessionPlannerBlockFieldEmptyValue(incomingValue) && !isSessionPlannerBlockFieldEmptyValue(existingValue)) {
      merged[field] = cloneSessionPlannerBlockMergeValue(existingValue);
      return;
    }

    merged[field] = cloneSessionPlannerBlockMergeValue(incomingValue);
    if (incomingTimestamp) {
      mergedMeta[field] = new Date(incomingTimestamp).toISOString();
    }
  });

  const newestFieldTimestamp = Object.values(mergedMeta).reduce(
    (latest, timestampValue) => Math.max(latest, parseSessionPlannerTimestampMs(timestampValue)),
    0
  );
  const newestBlockTimestamp = Math.max(
    parseSessionPlannerTimestampMs(existing.updatedAt),
    parseSessionPlannerTimestampMs(incoming.updatedAt),
    newestFieldTimestamp
  );
  merged[sessionPlannerBlockFieldUpdatedAtKey] = mergedMeta;
  merged.updatedAt = newestBlockTimestamp ? new Date(newestBlockTimestamp).toISOString() : incoming.updatedAt || existing.updatedAt || "";
  return createSessionPlannerBlock(merged);
}

function filterSessionPlannerDeletedBlocksForWrite(session, dateValue, deletedBlockIds = new Set()) {
  const filteredSession = cloneSessionPlannerSession({ ...session, date: session?.date || dateValue });
  if (!deletedBlockIds.size) {
    return filteredSession;
  }

  filteredSession.blocks = filteredSession.blocks.filter((block) => !deletedBlockIds.has(block.id));
  if (!filteredSession.blocks.some((block) => block.id === filteredSession.selectedBlockId)) {
    filteredSession.selectedBlockId = filteredSession.blocks[0]?.id ?? "";
  }
  return filteredSession;
}

function mergeSessionPlannerSessionForWrite(existingSession, incomingSession, dateValue, canReduceBlocks = false, deletedBlockIds = new Set()) {
  const existing = cloneSessionPlannerSession({ ...existingSession, date: existingSession?.date || dateValue });
  const incoming = cloneSessionPlannerSession({ ...incomingSession, date: incomingSession?.date || dateValue });
  const existingById = new Map(existing.blocks.map((block) => [block.id, block]));
  const incomingIds = new Set();
  const blocks = incoming.blocks.flatMap((incomingBlock) => {
    incomingIds.add(incomingBlock.id);
    if (deletedBlockIds.has(incomingBlock.id)) {
      return [];
    }
    const existingBlock = existingById.get(incomingBlock.id);
    return [existingBlock ? mergeSessionPlannerBlockForWrite(existingBlock, incomingBlock) : createSessionPlannerBlock(incomingBlock)];
  });

  if (!canReduceBlocks) {
    existing.blocks.forEach((existingBlock) => {
      if (!incomingIds.has(existingBlock.id) && !deletedBlockIds.has(existingBlock.id)) {
        blocks.push(createSessionPlannerBlock(existingBlock));
      }
    });
  }

  const selectedBlockId = blocks.some((block) => block.id === incoming.selectedBlockId)
    ? incoming.selectedBlockId
    : blocks.some((block) => block.id === existing.selectedBlockId)
      ? existing.selectedBlockId
      : blocks[0]?.id ?? "";

  return {
    ...existing,
    ...incoming,
    title: isSessionPlannerBlockFieldEmptyValue(incoming.title) && !isSessionPlannerBlockFieldEmptyValue(existing.title)
      ? existing.title
      : incoming.title,
    theme: isSessionPlannerBlockFieldEmptyValue(incoming.theme) && !isSessionPlannerBlockFieldEmptyValue(existing.theme)
      ? existing.theme
      : incoming.theme,
    date: incoming.date || existing.date || dateValue,
    selectedBlockId,
    blocks,
  };
}

function cloneSessionPlannerState(source = createSessionPlannerDefaultState()) {
  const fallback = createSessionPlannerDefaultState();
  const selectedDate = source.selectedDate || fallback.selectedDate;
  const sessions = {};

  Object.entries(source.sessions ?? {}).forEach(([dateValue, session]) => {
    sessions[dateValue] = cloneSessionPlannerSession({ ...session, date: session.date || dateValue });
  });

  if (!Object.keys(sessions).length) {
    sessions[fallback.selectedDate] = fallback.sessions[fallback.selectedDate];
  }

  return applySessionPlannerBlockDeletionTombstones(applySessionPlannerBlockReductionGuard({
    selectedDate,
    sessions,
  }, source), source);
}

function readSessionPlannerState() {
  try {
    const raw = window.localStorage.getItem(sessionPlannerStorageKey);
    return raw ? cloneSessionPlannerState(JSON.parse(raw)) : createSessionPlannerDefaultState();
  } catch {
    return createSessionPlannerDefaultState();
  }
}

function mergeSessionPlannerStateForWrite(existingState, incomingState) {
  const existing = cloneSessionPlannerState(existingState);
  const incoming = cloneSessionPlannerState(incomingState);
  const merged = {
    ...incoming,
    sessions: {},
  };
  applySessionPlannerBlockDeletionTombstones(merged, existing, incoming);

  const sessionDates = new Set([
    ...Object.keys(existing.sessions || {}),
    ...Object.keys(incoming.sessions || {}),
  ]);

  sessionDates.forEach((dateValue) => {
    const existingSession = existing.sessions?.[dateValue];
    const incomingSession = incoming.sessions?.[dateValue];
    if (existingSession && incomingSession) {
      merged.sessions[dateValue] = mergeSessionPlannerSessionForWrite(
        existingSession,
        incomingSession,
        dateValue,
        canReduceSessionPlannerBlocksForDate(incoming, dateValue),
        getSessionPlannerDeletedBlockIds(merged, dateValue)
      );
      return;
    }

    const deletedBlockIds = getSessionPlannerDeletedBlockIds(merged, dateValue);
    if (existingSession) {
      merged.sessions[dateValue] = filterSessionPlannerDeletedBlocksForWrite(existingSession, dateValue, deletedBlockIds);
      return;
    }

    if (incomingSession) {
      merged.sessions[dateValue] = filterSessionPlannerDeletedBlocksForWrite(incomingSession, dateValue, deletedBlockIds);
    }
  });

  return applySessionPlannerBlockDeletionTombstones(applySessionPlannerBlockReductionGuard(merged, incoming), existing, incoming);
}

function mergeSessionPlannerStateFromBackup(currentState, backupState) {
  const current = cloneSessionPlannerState(currentState);
  const backup = cloneSessionPlannerState(backupState);
  const merged = {
    ...current,
    sessions: {
      ...current.sessions,
    },
  };
  let recoveredSessions = 0;

  Object.entries(backup.sessions || {}).forEach(([dateValue, backupSession]) => {
    const currentSession = merged.sessions?.[dateValue];
    const currentBlockCount = Array.isArray(currentSession?.blocks) ? currentSession.blocks.length : 0;
    const backupSessionWithoutDeletedBlocks = filterSessionPlannerDeletedBlocksForWrite(
      backupSession,
      dateValue,
      getSessionPlannerDeletedBlockIds(current, dateValue)
    );
    const backupBlockCount = Array.isArray(backupSessionWithoutDeletedBlocks?.blocks) ? backupSessionWithoutDeletedBlocks.blocks.length : 0;
    if (
      backupBlockCount > currentBlockCount &&
      !canReduceSessionPlannerBlocksForDate(current, dateValue)
    ) {
      merged.sessions[dateValue] = backupSessionWithoutDeletedBlocks;
      recoveredSessions += 1;
    }
  });

  return {
    state: applySessionPlannerBlockDeletionTombstones(applySessionPlannerBlockReductionGuard(merged, current), current, backup),
    recoveredSessions,
  };
}

async function findSessionPlannerStateInSnapshots(currentState) {
  try {
    const database = await openDataSafetyDatabase();
    const snapshots = await new Promise((resolve, reject) => {
      const transaction = database.transaction(dataSafetySnapshotStoreName, "readonly");
      const request = transaction.objectStore(dataSafetySnapshotStoreName).getAll();
      request.onsuccess = () => resolve(Array.from(request.result || []));
      request.onerror = () => reject(request.error);
    });

    const orderedSnapshots = snapshots.sort((a, b) =>
      String(b?.createdAt || b?.id || "").localeCompare(String(a?.createdAt || a?.id || ""))
    );
    let recoveredState = cloneSessionPlannerState(currentState);
    let recoveredSessions = 0;

    orderedSnapshots.forEach((snapshot) => {
      const storage = snapshot?.storage && typeof snapshot.storage === "object" ? snapshot.storage : {};
      const rawState = storage[sessionPlannerStorageKey];
      if (typeof rawState !== "string") {
        return;
      }

      try {
        const backupState = cloneSessionPlannerState(JSON.parse(rawState));
        const mergeResult = mergeSessionPlannerStateFromBackup(recoveredState, backupState);
        recoveredState = mergeResult.state;
        recoveredSessions += mergeResult.recoveredSessions;
      } catch {
        // Ignore malformed local backup snapshots.
      }
    });

    return recoveredSessions ? recoveredState : null;
  } catch {
    return null;
  }
}

function queueSessionPlannerSnapshotRecovery() {
  if (sessionPlannerSnapshotRecoveryQueued) {
    return;
  }

  sessionPlannerSnapshotRecoveryQueued = true;
  const currentState = sessionPlannerState || readSessionPlannerState();
  findSessionPlannerStateInSnapshots(currentState).then((recoveredState) => {
    sessionPlannerSnapshotRecoveryQueued = false;
    if (!recoveredState) {
      return;
    }

    sessionPlannerState = recoveredState;
    if (!writeSessionPlannerState()) {
      return;
    }

    if (hubState?.activeWorkspaceId === "session-planner") {
      renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
      showSessionPlannerToast("Session planner restored from local backup.");
    }
  });
}

function writeSessionPlannerState() {
  if (!sessionPlannerState) {
    return false;
  }

  try {
    let existingState = null;
    try {
      const rawExistingState = window.localStorage.getItem(sessionPlannerStorageKey);
      existingState = rawExistingState ? cloneSessionPlannerState(JSON.parse(rawExistingState)) : null;
    } catch {
      existingState = null;
    }
    const nextState = existingState
      ? mergeSessionPlannerStateForWrite(existingState, sessionPlannerState)
      : cloneSessionPlannerState(sessionPlannerState);
    sessionPlannerState = nextState;
    window.localStorage.setItem(sessionPlannerStorageKey, JSON.stringify(nextState));
    return true;
  } catch {
    logEvent("Session planner could not be written to local storage.");
    return false;
  }
}

function getSessionPlannerSelectedSession() {
  if (!sessionPlannerState) {
    sessionPlannerState = createSessionPlannerDefaultState();
  }

  return sessionPlannerState.sessions?.[sessionPlannerState.selectedDate] ??
    createSessionPlannerEmptySession(sessionPlannerState.selectedDate);
}

function ensureSessionPlannerSelectedSession() {
  if (!sessionPlannerState) {
    sessionPlannerState = createSessionPlannerDefaultState();
  }

  if (!sessionPlannerState.sessions) {
    sessionPlannerState.sessions = {};
  }

  if (!sessionPlannerState.sessions[sessionPlannerState.selectedDate]) {
    sessionPlannerState.sessions[sessionPlannerState.selectedDate] = createSessionPlannerEmptySession(
      sessionPlannerState.selectedDate
    );
  }

  return sessionPlannerState.sessions[sessionPlannerState.selectedDate];
}

function getSessionPlannerSelectedBlock() {
  const session = getSessionPlannerSelectedSession();
  return session.blocks.find((block) => block.id === session.selectedBlockId) ?? session.blocks[0] ?? null;
}

function selectSessionPlannerDate(dateValue) {
  if (!sessionPlannerState || !dateValue) {
    return;
  }

  sessionPlannerState.selectedDate = dateValue;
  sessionPlannerPeriodizationOverlayDate = null;
  sessionPlannerPeriodizationOverlayMode = "view";
  sessionPlannerLibraryOpen = false;
  sessionPlannerAddMenuOpen = false;
  sessionPlannerVisualPreviewOpen = false;
  sessionPlannerTacticalboardOpen = false;
  sessionPlannerPlayerBoardOpen = false;
  sessionPlannerPlayerBoardAssistantOpen = false;
  sessionPlannerPlayerBoardSelectedPlayerId = "";
  sessionPlannerPlayerBoardSelectedPlayerIds = [];
  sessionPlannerPlayerBoardSelectionState = null;
  sessionPlannerTacticalPendingPoint = null;
  getSessionPlannerSelectedSession();
  writeSessionPlannerState();
  renderSessionPlannerWorkspace();
}

function selectSessionPlannerBlock(blockId) {
  const session = getSessionPlannerSelectedSession();
  if (!session.blocks.some((block) => block.id === blockId)) {
    return;
  }

  session.selectedBlockId = blockId;
  sessionPlannerAddMenuOpen = false;
  sessionPlannerVisualPreviewOpen = false;
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function addSessionPlannerBlock() {
  if (!canEditSessionPlanner()) {
    return;
  }

  const session = ensureSessionPlannerSelectedSession();
  const blockNumber = session.blocks.length + 1;
  const block = createSessionPlannerBlock({
    label: `Block ${blockNumber}`,
    title: "New Exercise",
    focus: "",
    minutes: 15,
    intensity: 3,
    diagram: "empty",
    tacticalElements: [],
  });

  session.blocks.push(block);
  session.selectedBlockId = block.id;
  sessionPlannerAddMenuOpen = false;
  renumberSessionPlannerExerciseBlocks(session);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  return block;
}

function renumberSessionPlannerExerciseBlocks(session) {
  if (!session?.blocks?.length) {
    return;
  }

  let exerciseNumber = 1;
  session.blocks.forEach((block) => {
    if (/^Block\s+\d+$/i.test(String(block.label || ""))) {
      const nextLabel = `Block ${exerciseNumber}`;
      if (block.label !== nextLabel) {
        block.label = nextLabel;
        markSessionPlannerBlockFieldsUpdated(block, ["label"]);
      }
      exerciseNumber += 1;
    }
  });
}

function moveSessionPlannerBlock(blockId, direction) {
  if (!canEditSessionPlanner() || !direction) {
    return;
  }

  const session = ensureSessionPlannerSelectedSession();
  const currentIndex = session.blocks.findIndex((block) => block.id === blockId);
  const nextIndex = currentIndex + direction;

  if (currentIndex === -1 || nextIndex < 0 || nextIndex >= session.blocks.length) {
    return;
  }

  const [block] = session.blocks.splice(currentIndex, 1);
  session.blocks.splice(nextIndex, 0, block);
  session.selectedBlockId = block.id;
  renumberSessionPlannerExerciseBlocks(session);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function reorderSessionPlannerBlock(sourceBlockId, targetBlockId, placement = "before") {
  if (!canEditSessionPlanner() || !sourceBlockId || !targetBlockId || sourceBlockId === targetBlockId) {
    return;
  }

  const session = ensureSessionPlannerSelectedSession();
  const sourceIndex = session.blocks.findIndex((block) => block.id === sourceBlockId);
  const targetBlock = session.blocks.find((block) => block.id === targetBlockId);

  if (sourceIndex === -1 || !targetBlock) {
    return;
  }

  const [block] = session.blocks.splice(sourceIndex, 1);
  const targetIndex = session.blocks.findIndex((item) => item.id === targetBlock.id);
  const insertIndex = placement === "after" ? targetIndex + 1 : targetIndex;
  session.blocks.splice(insertIndex, 0, block);
  session.selectedBlockId = block.id;
  renumberSessionPlannerExerciseBlocks(session);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function getSessionPlannerBlockDropPlacement(event, row) {
  const rect = row.getBoundingClientRect();
  return event.clientY > rect.top + rect.height / 2 ? "after" : "before";
}

function clearSessionPlannerBlockDragState() {
  sessionPlannerDraggedBlockId = "";
  ui.sessionPlannerWorkspace
    ?.querySelectorAll(".session-block-row.is-dragging, .session-block-row.is-drop-before, .session-block-row.is-drop-after")
    .forEach((row) => row.classList.remove("is-dragging", "is-drop-before", "is-drop-after"));
}

function clearSessionPlannerLibraryDragState() {
  sessionPlannerDraggedLibraryExerciseId = "";
  sessionPlannerLibraryPointerDrag = null;
  ui.sessionPlannerWorkspace
    ?.querySelectorAll(".session-library-item.is-dragging, .session-library-folder-card.is-drop-target")
    .forEach((element) => element.classList.remove("is-dragging", "is-drop-target"));
}

function updateSessionPlannerLibraryPointerDropTarget(clientX, clientY) {
  const target = document.elementFromPoint(clientX, clientY)?.closest?.("[data-session-library-folder-drop]");
  ui.sessionPlannerWorkspace
    ?.querySelectorAll(".session-library-folder-card.is-drop-target")
    .forEach((folderCard) => {
      if (folderCard !== target) {
        folderCard.classList.remove("is-drop-target");
      }
    });
  target?.classList.add("is-drop-target");
  return target || null;
}

function startSessionPlannerLibraryPointerDrag(event) {
  const item = event.target.closest?.("[data-session-library-drag-exercise]");
  if (!item || !canEditSessionPlanner() || event.button !== 0 || event.target.closest(".session-library-actions")) {
    return false;
  }

  sessionPlannerLibraryPointerDrag = {
    exerciseId: item.dataset.sessionLibraryDragExercise,
    startX: event.clientX,
    startY: event.clientY,
    active: false,
  };
  return true;
}

function updateSessionPlannerLibraryPointerDrag(event) {
  if (!sessionPlannerLibraryPointerDrag?.exerciseId) {
    return false;
  }

  const deltaX = Math.abs(event.clientX - sessionPlannerLibraryPointerDrag.startX);
  const deltaY = Math.abs(event.clientY - sessionPlannerLibraryPointerDrag.startY);
  if (!sessionPlannerLibraryPointerDrag.active && deltaX + deltaY < 10) {
    return true;
  }

  sessionPlannerLibraryPointerDrag.active = true;
  sessionPlannerDraggedLibraryExerciseId = sessionPlannerLibraryPointerDrag.exerciseId;
  ui.sessionPlannerWorkspace
    ?.querySelectorAll("[data-session-library-drag-exercise]")
    .forEach((item) => {
      if (item.dataset.sessionLibraryDragExercise === sessionPlannerDraggedLibraryExerciseId) {
        item.classList.add("is-dragging");
      }
    });
  updateSessionPlannerLibraryPointerDropTarget(event.clientX, event.clientY);
  event.preventDefault();
  return true;
}

function finishSessionPlannerLibraryPointerDrag(event) {
  if (!sessionPlannerLibraryPointerDrag?.exerciseId) {
    return false;
  }

  const dragState = sessionPlannerLibraryPointerDrag;
  const shouldDrop = Boolean(dragState.active);
  const folderDropTarget = shouldDrop ? updateSessionPlannerLibraryPointerDropTarget(event.clientX, event.clientY) : null;
  if (folderDropTarget) {
    sessionPlannerLibrarySuppressNextClick = true;
    addSessionPlannerExerciseToLibraryFolder(
      dragState.exerciseId,
      folderDropTarget.dataset.sessionLibraryFolderDrop
    );
  }

  clearSessionPlannerLibraryDragState();
  return shouldDrop;
}

function deleteSessionPlannerBlock(blockId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const session = ensureSessionPlannerSelectedSession();
  const blockIndex = session.blocks.findIndex((block) => block.id === blockId);

  if (blockIndex === -1) {
    return;
  }

  const block = session.blocks[blockIndex];
  const exerciseName = block?.title || block?.label || "this exercise";
  const shouldDelete = window.confirm(`Are you sure you want to delete "${exerciseName}" from this session?`);
  if (!shouldDelete) {
    return;
  }

  session.blocks.splice(blockIndex, 1);
  markSessionPlannerBlockDeleted(session.date, blockId);

  if (session.selectedBlockId === blockId) {
    session.selectedBlockId = session.blocks[Math.min(blockIndex, session.blocks.length - 1)]?.id ?? "";
  }

  if (!session.blocks.length) {
    session.title = getScheduledSessionTitleForDate(session.date) || "Session";
  }

  renumberSessionPlannerExerciseBlocks(session);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function setSessionPlannerLibraryOpen(isOpen) {
  sessionPlannerLibraryOpen = Boolean(isOpen);
  if (sessionPlannerLibraryOpen) {
    sessionPlannerAddMenuOpen = false;
    sessionPlannerPlayerBoardOpen = false;
    sessionPlannerPrintOverlayOpen = false;
  } else {
    sessionPlannerLibraryFilterOpen = "";
    sessionPlannerLibraryEditExerciseId = "";
  }
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function closeSessionPlannerLibrary() {
  const editExercise = getSessionPlannerLibraryEditExercise();
  if (
    editExercise &&
    hasSessionPlannerLibraryExerciseEditChanges(editExercise) &&
    !window.confirm("Discard unsaved exercise edits?")
  ) {
    return;
  }

  setSessionPlannerLibraryOpen(false);
}

function setSessionPlannerAddMenuOpen(isOpen) {
  sessionPlannerAddMenuOpen = Boolean(isOpen);
  if (sessionPlannerAddMenuOpen) {
    sessionPlannerLibraryOpen = false;
    sessionPlannerPrintOverlayOpen = false;
  }
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function setSessionPlannerVisualPreviewOpen(isOpen) {
  sessionPlannerVisualPreviewOpen = Boolean(isOpen);
  if (sessionPlannerVisualPreviewOpen) {
    sessionPlannerAddMenuOpen = false;
    sessionPlannerPlayerBoardOpen = false;
    sessionPlannerPrintOverlayOpen = false;
  }
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function syncSessionPlannerPrintModeClass() {
  document.body?.classList.toggle("is-session-printing", Boolean(sessionPlannerPrintOverlayOpen));
}

function setSessionPlannerPrintOverlayOpen(isOpen) {
  sessionPlannerPrintOverlayOpen = Boolean(isOpen);
  if (sessionPlannerPrintOverlayOpen) {
    sessionPlannerAddMenuOpen = false;
    sessionPlannerLibraryOpen = false;
    sessionPlannerVisualPreviewOpen = false;
    sessionPlannerTacticalboardOpen = false;
    sessionPlannerPlayerBoardOpen = false;
    sessionPlannerPlayerBoardAssistantOpen = false;
    ensureSessionPlannerPrintPageStyle();
  }
  syncSessionPlannerPrintModeClass();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function setSessionPlannerTacticalboardOpen(isOpen) {
  sessionPlannerTacticalboardOpen = Boolean(isOpen);
  if (sessionPlannerTacticalboardOpen) {
    sessionPlannerAddMenuOpen = false;
    sessionPlannerVisualPreviewOpen = false;
    sessionPlannerPlayerBoardOpen = false;
    sessionPlannerPlayerBoardAssistantOpen = false;
    sessionPlannerPrintOverlayOpen = false;
  }
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalSelectionState = null;
  sessionPlannerTacticalNumberPickerElementId = "";
  setSessionPlannerTacticalClickSuppression(false);
  clearSessionPlannerTacticalSelection();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function setSessionPlannerPlayerBoardOpen(isOpen) {
  sessionPlannerPlayerBoardOpen = Boolean(isOpen);
  sessionPlannerPlayerBoardAssistantOpen = false;
  if (sessionPlannerPlayerBoardOpen) {
    sessionPlannerAddMenuOpen = false;
    sessionPlannerLibraryOpen = false;
    sessionPlannerVisualPreviewOpen = false;
    sessionPlannerTacticalboardOpen = false;
    sessionPlannerPrintOverlayOpen = false;
    syncSessionPlannerPlayerBoardSelection(getSessionPlannerSelectedBlock());
  } else {
    sessionPlannerPlayerBoardDragState = null;
    sessionPlannerPlayerBoardSelectionState = null;
    sessionPlannerPlayerBoardSelectedPlayerId = "";
    sessionPlannerPlayerBoardSelectedPlayerIds = [];
  }
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function openSessionPlannerPlayerBoardProfile(playerId) {
  if (!playerId) {
    return;
  }

  const isVisiblePlayer = getSessionPlannerPlayerBoardPlayers().some((item) => item.player.id === playerId);
  if (!isVisiblePlayer) {
    return;
  }

  sessionPlannerPlayerBoardSelectedPlayerId = playerId;
  sessionPlannerPlayerBoardAssistantOpen = false;
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function closeSessionPlannerPlayerBoardProfile() {
  sessionPlannerPlayerBoardSelectedPlayerId = "";
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function getSessionPlannerPlayerBoardVisiblePlayerIds(block = getSessionPlannerSelectedBlock()) {
  return new Set(getSessionPlannerPlayerBoardPlayers(block).map((item) => item.player.id));
}

function normalizeSessionPlannerPlayerBoardSelectedIds(playerIds = [], block = getSessionPlannerSelectedBlock()) {
  const visibleIds = getSessionPlannerPlayerBoardVisiblePlayerIds(block);
  const selectedIds = [];
  playerIds.forEach((playerId) => {
    if (visibleIds.has(playerId) && !selectedIds.includes(playerId)) {
      selectedIds.push(playerId);
    }
  });
  return selectedIds;
}

function setSessionPlannerPlayerBoardSelectedPlayers(playerIds = [], options = {}) {
  sessionPlannerPlayerBoardSelectedPlayerIds = normalizeSessionPlannerPlayerBoardSelectedIds(playerIds);
  if (options.render) {
    renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
    return;
  }
  syncSessionPlannerPlayerBoardSelectionUi();
}

function toggleSessionPlannerPlayerBoardSelectedPlayer(playerId, options = {}) {
  if (!playerId) {
    return;
  }

  const currentIds = normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds);
  const nextIds = currentIds.includes(playerId)
    ? currentIds.filter((selectedId) => selectedId !== playerId)
    : [...currentIds, playerId];
  setSessionPlannerPlayerBoardSelectedPlayers(nextIds, options);
}

function syncSessionPlannerPlayerBoardSelectionUi() {
  const selectedIds = new Set(normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds));
  const selectedCount = selectedIds.size;
  ui.sessionPlannerWorkspace
    ?.querySelectorAll("[data-session-player-board-token]")
    .forEach((token) => {
      token.classList.toggle("is-selected", selectedIds.has(token.dataset.sessionPlayerBoardToken));
    });

  ui.sessionPlannerWorkspace
    ?.querySelectorAll("[data-session-player-board-selected-count]")
    .forEach((item) => {
      item.textContent = `${selectedCount} selected`;
    });

  ui.sessionPlannerWorkspace
    ?.querySelectorAll(
      [
        "[data-session-player-board-color]",
        "[data-session-player-board-color-select]",
        "[data-session-player-board-clear-colors]",
        "[data-session-player-board-apply-formation]",
        "[data-session-player-board-prioritize]",
      ].join(", ")
    )
    .forEach((button) => {
      button.disabled = selectedCount === 0;
    });
}

function getSessionPlannerPlayerBoardSelectedColorIds() {
  return normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds);
}

function updateSessionPlannerPlayerBoardSelectedColor(colorValue) {
  const block = getSessionPlannerSelectedBlock();
  const selectedIds = getSessionPlannerPlayerBoardSelectedColorIds();
  if (!block || !selectedIds.length) {
    return;
  }

  const color = colorValue ? normalizeTacticalColor(colorValue, "") : "";
  if (!block.playerBoardColors || typeof block.playerBoardColors !== "object") {
    block.playerBoardColors = {};
  }

  selectedIds.forEach((playerId) => {
    if (color) {
      block.playerBoardColors[playerId] = color;
    } else {
      delete block.playerBoardColors[playerId];
    }
  });
  markSessionPlannerBlockFieldsUpdated(block, ["playerBoardColors"]);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function clearSessionPlannerPlayerBoardSelectedColors() {
  const selectedIds = getSessionPlannerPlayerBoardSelectedColorIds();
  if (!selectedIds.length) {
    showSessionPlannerToast("Select players before clearing colours.", "error");
    return;
  }

  updateSessionPlannerPlayerBoardSelectedColor("");
  showSessionPlannerToast(`Colour cleared for ${selectedIds.length} player${selectedIds.length === 1 ? "" : "s"}.`);
}

function resetSessionPlannerPlayerBoardPositions() {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const shouldReset = window.confirm(
    "Reset player board? This will move the players back to their starting positions and restore the player buttons."
  );
  if (!shouldReset) {
    return;
  }

  block.playerBoardLayoutMode = "auto";
  block.playerBoardPositions = {};
  block.playerBoardColors = {};
  markSessionPlannerBlockFieldsUpdated(block, ["playerBoardLayoutMode", "playerBoardPositions", "playerBoardColors"]);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast("Players reset to starting positions and default buttons.");
}

function refreshSessionPlannerTacticalboardCanvas(options = {}) {
  const block = getSessionPlannerSelectedBlock();
  if (options.persist) {
    markSessionPlannerBlockFieldsUpdated(block, ["tacticalElements"]);
    writeSessionPlannerState();
  }

  const canvasWrap = ui.sessionPlannerWorkspace?.querySelector("[data-session-tactical-canvas-wrap]");

  if (!sessionPlannerTacticalboardOpen || !canvasWrap || !block) {
    renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
    return;
  }

  canvasWrap.innerHTML = renderSessionPlannerExerciseVisual(block, { large: true, editor: true });
  syncSessionPlannerTacticalboardInspector();
}

function isSessionPlannerTacticalLineTool(tool = sessionPlannerTacticalTool) {
  return ["arrow", "pass", "run", "line", "dashed-line", "curve", "zone", "dashed-zone", "ellipse"].includes(tool);
}

function isSessionPlannerTacticalStrokeElement(element = {}) {
  return Boolean(element) && (isSessionPlannerTacticalLineTool(element.type) || element.type === "freehand");
}

function isSessionPlannerTacticalPlacementTool(tool = sessionPlannerTacticalTool) {
  return Boolean(tool) && tool !== "remove" && tool !== "freehand" && !isSessionPlannerTacticalLineTool(tool);
}

function uniqueValues(values = []) {
  const seen = new Set();
  return (Array.isArray(values) ? values : [values]).filter((value) => {
    if (seen.has(value)) {
      return false;
    }

    seen.add(value);
    return true;
  });
}

function getSessionPlannerTacticalSelectedElementIds() {
  const block = getSessionPlannerSelectedBlock();
  if (!block || !Array.isArray(block.tacticalElements)) {
    sessionPlannerTacticalSelectedElementIds = [];
    sessionPlannerTacticalSelectedElementId = "";
    return [];
  }

  const validIds = new Set(block.tacticalElements.map((element) => element.id));
  const nextIds = uniqueValues([
    ...sessionPlannerTacticalSelectedElementIds,
    sessionPlannerTacticalSelectedElementId,
  ]).filter((id) => id && validIds.has(id));

  sessionPlannerTacticalSelectedElementIds = nextIds;
  sessionPlannerTacticalSelectedElementId =
    nextIds.includes(sessionPlannerTacticalSelectedElementId)
      ? sessionPlannerTacticalSelectedElementId
      : nextIds[0] ?? "";

  return nextIds;
}

function setSessionPlannerTacticalSelectedElements(elementIds = [], primaryId = "") {
  const block = getSessionPlannerSelectedBlock();
  const validIds = new Set(
    block && Array.isArray(block.tacticalElements)
      ? block.tacticalElements.map((element) => element.id)
      : []
  );
  const nextIds = uniqueValues(elementIds).filter((id) => id && validIds.has(id));

  sessionPlannerTacticalSelectedElementIds = nextIds;
  sessionPlannerTacticalSelectedElementId =
    primaryId && nextIds.includes(primaryId)
      ? primaryId
      : nextIds[0] ?? "";
}

function isSessionPlannerTacticalSelectionToggleModifier(event) {
  return Boolean(event?.metaKey || event?.ctrlKey);
}

function toggleSessionPlannerTacticalElementSelection(elementId) {
  if (!elementId) {
    return;
  }

  const selectedIds = getSessionPlannerTacticalSelectedElementIds();
  const isSelected = selectedIds.includes(elementId);
  const nextIds = isSelected
    ? selectedIds.filter((selectedId) => selectedId !== elementId)
    : [...selectedIds, elementId];

  setSessionPlannerTacticalSelectedElements(nextIds, isSelected ? nextIds[0] ?? "" : elementId);
  sessionPlannerTacticalNumberPickerElementId = "";
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalSelectionState = null;
  syncSessionPlannerTacticalboardInspector();
  refreshSessionPlannerTacticalboardCanvas();
}

function clearSessionPlannerTacticalSelection() {
  setSessionPlannerTacticalSelectedElements([]);
  sessionPlannerTacticalNumberPickerElementId = "";
}

function setSessionPlannerTacticalClickSuppression(isSuppressed) {
  sessionPlannerTacticalSuppressNextClick = Boolean(isSuppressed);
  sessionPlannerTacticalSuppressNextClickAt = sessionPlannerTacticalSuppressNextClick ? Date.now() : 0;
}

function setSessionPlannerTacticalPitchMode(mode) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const nextMode = normalizeSessionPlannerTacticalPitchMode(mode);
  if (block.tacticalPitchMode === nextMode) {
    return;
  }

  block.tacticalPitchMode = nextMode;
  markSessionPlannerBlockFieldsUpdated(block, ["tacticalPitchMode"]);
  writeSessionPlannerState();
  refreshSessionPlannerTacticalboardCanvas();
}

function openSessionPlannerTacticalNumberPicker(elementId) {
  const element = getSessionPlannerTacticalElementById(elementId);
  if (!isSessionPlannerTacticalPlayerType(element?.type)) {
    return;
  }

  sessionPlannerTacticalNumberPickerElementId = element.id;
  setSessionPlannerTacticalSelectedElements([element.id], element.id);
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalSelectionState = null;
  refreshSessionPlannerTacticalboardCanvas();
}

function updateSessionPlannerTacticalPlayerNumber(elementId, rawNumber) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const element = getSessionPlannerTacticalElementById(elementId);
  if (!isSessionPlannerTacticalPlayerType(element?.type)) {
    return;
  }

  const playerBadge = normalizeSessionPlannerTacticalPlayerBadge(rawNumber);
  element.playerNumber = playerBadge || null;
  sessionPlannerTacticalNumberPickerElementId = "";
  markSessionPlannerBlockFieldsUpdated(getSessionPlannerSelectedBlock(), ["tacticalElements"]);
  writeSessionPlannerState();
  refreshSessionPlannerTacticalboardCanvas();
}

function updateSelectedSessionPlannerTacticalPlayerBadges(rawBadge) {
  if (!canEditSessionPlanner()) {
    return false;
  }

  const playerBadge = normalizeSessionPlannerTacticalPlayerBadge(rawBadge);
  if (!playerBadge) {
    return false;
  }

  const selectedPlayers = getSelectedSessionPlannerTacticalElements()
    .filter((element) => isSessionPlannerTacticalPlayerType(element?.type));

  if (!selectedPlayers.length) {
    return false;
  }

  selectedPlayers.forEach((element) => {
    element.playerNumber = playerBadge;
  });
  sessionPlannerTacticalNumberPickerElementId = "";
  markSessionPlannerBlockFieldsUpdated(getSessionPlannerSelectedBlock(), ["tacticalElements"]);
  writeSessionPlannerState();
  refreshSessionPlannerTacticalboardCanvas();
  return true;
}

function isSessionPlannerTacticalElementSelected(elementId) {
  return getSessionPlannerTacticalSelectedElementIds().includes(elementId);
}

function shouldDragSessionPlannerTacticalSelectionGroup(event, elementId) {
  const selectedIds = getSessionPlannerTacticalSelectedElementIds();
  return selectedIds.length > 1 &&
    selectedIds.includes(elementId) &&
    Boolean(event.shiftKey || event.metaKey || event.ctrlKey);
}

function getSessionPlannerTacticalDragElementIds(event, elementId) {
  if (!elementId) {
    return [];
  }

  return shouldDragSessionPlannerTacticalSelectionGroup(event, elementId)
    ? getSessionPlannerTacticalSelectedElementIds()
    : [elementId];
}

function setSessionPlannerTacticalTool(tool) {
  const allowedTools = new Set([
    "blue-player",
    "red-player",
    "neutral-player",
    "coach",
    "ball",
    "cone",
    "mini-goal",
    "big-goal",
    "mannequin",
    "pole",
    "gate",
    "dashed-line",
    "zone",
    "dashed-zone",
    "ellipse",
    "arrow",
    "pass",
    "run",
    "line",
    "curve",
    "freehand",
    "text",
    "remove",
  ]);

  if (!allowedTools.has(tool)) {
    return;
  }

  sessionPlannerTacticalTool = tool;
  if (tool !== "remove") {
    sessionPlannerTacticalColor = getDefaultTacticalColor(tool);
    sessionPlannerTacticalLineStyle = getDefaultTacticalLineStyle(tool);
  }
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalFreehandState = null;
  sessionPlannerTacticalSelectionState = null;
  sessionPlannerTacticalLastPlacementClick = null;
  sessionPlannerTacticalLastPlacement = null;
  setSessionPlannerTacticalClickSuppression(false);
  clearSessionPlannerTacticalSelection();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function clearSelectedSessionPlannerTacticalBoard() {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const hasDrawings = Array.isArray(block.tacticalElements) && block.tacticalElements.length > 0;
  if (!hasDrawings) {
    return;
  }

  const shouldDeleteAll = window.confirm("Delete all drawings from this exercise board?");
  if (!shouldDeleteAll) {
    return;
  }

  block.tacticalElements = [];
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalFreehandState = null;
  sessionPlannerTacticalSelectionState = null;
  clearSessionPlannerTacticalSelection();
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function undoSelectedSessionPlannerTacticalBoardAction() {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block || !Array.isArray(block.tacticalElements) || !block.tacticalElements.length) {
    return;
  }

  const removedElement = block.tacticalElements.pop();
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  setSessionPlannerTacticalSelectedElements(
    getSessionPlannerTacticalSelectedElementIds().filter((elementId) => elementId !== removedElement?.id)
  );
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function removeSessionPlannerTacticalElement(elementId) {
  if (!canEditSessionPlanner() || !elementId) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block || !Array.isArray(block.tacticalElements)) {
    return;
  }

  block.tacticalElements = block.tacticalElements.filter((element) => element.id !== elementId);
  setSessionPlannerTacticalSelectedElements(
    getSessionPlannerTacticalSelectedElementIds().filter((selectedId) => selectedId !== elementId)
  );
  sessionPlannerTacticalDraftLineState = null;
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function removeSelectedSessionPlannerTacticalElement() {
  const selectedIds = getSessionPlannerTacticalSelectedElementIds();
  if (!selectedIds.length) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block || !Array.isArray(block.tacticalElements)) {
    return;
  }

  const selectedIdSet = new Set(selectedIds);
  block.tacticalElements = block.tacticalElements.filter((element) => !selectedIdSet.has(element.id));
  clearSessionPlannerTacticalSelection();
  sessionPlannerTacticalDraftLineState = null;
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function addSessionPlannerTacticalElement(element) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  if (!Array.isArray(block.tacticalElements)) {
    block.tacticalElements = [];
  }

  const clonedElement = cloneSessionPlannerTacticalElement(element);
  block.tacticalElements.push(clonedElement);
  setSessionPlannerTacticalSelectedElements([clonedElement.id], clonedElement.id);
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function getSessionPlannerTacticalCanvasPoint(event, canvas) {
  const rect = canvas.getBoundingClientRect();
  return getSessionPlannerTacticalPointFromRect(event, rect);
}

function getSessionPlannerTacticalPointFromRect(event, rect) {
  const width = rect.width || 1;
  const height = rect.height || 1;

  return {
    x: clamp(((event.clientX - rect.left) / width) * 100, 0, 100),
    y: clamp(((event.clientY - rect.top) / height) * 100, 0, 100),
  };
}

function getSessionPlannerTacticalElementById(elementId) {
  const block = getSessionPlannerSelectedBlock();
  if (!block || !Array.isArray(block.tacticalElements)) {
    return null;
  }

  return block.tacticalElements.find((element) => element.id === elementId) ?? null;
}

function getSessionPlannerTacticalSelectionRect(selection = sessionPlannerTacticalSelectionState) {
  if (!selection?.startPoint || !selection?.currentPoint) {
    return null;
  }

  const left = Math.min(selection.startPoint.x, selection.currentPoint.x);
  const top = Math.min(selection.startPoint.y, selection.currentPoint.y);
  const right = Math.max(selection.startPoint.x, selection.currentPoint.x);
  const bottom = Math.max(selection.startPoint.y, selection.currentPoint.y);

  return {
    left,
    top,
    right,
    bottom,
    x: left,
    y: top,
    width: right - left,
    height: bottom - top,
  };
}

function getSessionPlannerTacticalElementBounds(element) {
  if (!element) {
    return null;
  }

  const points = [];
  const addPoint = (x, y) => {
    const pointX = Number(x);
    const pointY = Number(y);

    if (Number.isFinite(pointX) && Number.isFinite(pointY)) {
      points.push({
        x: clamp(pointX, 0, 100),
        y: clamp(pointY, 0, 100),
      });
    }
  };

  addPoint(element.x, element.y);
  addPoint(element.x2, element.y2);

  if (element.type === "curve") {
    const curveCoordinates = getSessionPlannerTacticalEndpointCoordinates(element);
    addPoint(curveCoordinates?.controlX, curveCoordinates?.controlY);
  }

  if (Array.isArray(element.points)) {
    element.points.forEach((point) => addPoint(point.x, point.y));
  }

  if (!points.length) {
    return null;
  }

  const left = Math.min(...points.map((point) => point.x));
  const top = Math.min(...points.map((point) => point.y));
  const right = Math.max(...points.map((point) => point.x));
  const bottom = Math.max(...points.map((point) => point.y));
  const boundsPaddingByType = {
    "blue-player": 2.4,
    "red-player": 2.4,
    "neutral-player": 2.4,
    coach: 2.5,
    ball: 1.8,
    cone: 2.1,
    "mini-goal": 4.2,
    "big-goal": 5.2,
    mannequin: 2.8,
    pole: 1.6,
    gate: 3.2,
    text: 6,
  };
  const padding = isSessionPlannerTacticalStrokeElement(element)
    ? 1.2
    : boundsPaddingByType[element.type] ?? 2.4;

  return {
    left: clamp(left - padding, 0, 100),
    top: clamp(top - padding, 0, 100),
    right: clamp(right + padding, 0, 100),
    bottom: clamp(bottom + padding, 0, 100),
  };
}

function doSessionPlannerTacticalBoundsIntersect(bounds, rect) {
  return Boolean(bounds && rect) &&
    bounds.left <= rect.right &&
    bounds.right >= rect.left &&
    bounds.top <= rect.bottom &&
    bounds.bottom >= rect.top;
}

function isSessionPlannerTacticalPointInRect(point, rect) {
  return Boolean(point && rect) &&
    Number(point.x) >= rect.left &&
    Number(point.x) <= rect.right &&
    Number(point.y) >= rect.top &&
    Number(point.y) <= rect.bottom;
}

function getSessionPlannerTacticalElementSelectionPoints(element) {
  if (!element) {
    return [];
  }

  const points = [];
  const addPoint = (x, y) => {
    const pointX = Number(x);
    const pointY = Number(y);

    if (Number.isFinite(pointX) && Number.isFinite(pointY)) {
      points.push({
        x: clamp(pointX, 0, 100),
        y: clamp(pointY, 0, 100),
      });
    }
  };

  addPoint(element.x, element.y);

  if (Number.isFinite(Number(element.x2)) && Number.isFinite(Number(element.y2))) {
    addPoint(element.x2, element.y2);
    addPoint((Number(element.x) + Number(element.x2)) / 2, (Number(element.y) + Number(element.y2)) / 2);
  }

  if (element.type === "curve") {
    const coordinates = getSessionPlannerTacticalEndpointCoordinates(element);
    addPoint(coordinates?.controlX, coordinates?.controlY);
  }

  if (Array.isArray(element.points)) {
    element.points.forEach((point) => addPoint(point.x, point.y));
  }

  const bounds = getSessionPlannerTacticalElementBounds(element);
  if (bounds) {
    addPoint((bounds.left + bounds.right) / 2, (bounds.top + bounds.bottom) / 2);
  }

  return points;
}

function isSessionPlannerTacticalElementInSelectionRect(element, rect) {
  if (!element || !rect) {
    return false;
  }

  return getSessionPlannerTacticalElementSelectionPoints(element).some((point) =>
    isSessionPlannerTacticalPointInRect(point, rect)
  );
}

function getSessionPlannerTacticalElementsInRect(rect) {
  const block = getSessionPlannerSelectedBlock();
  if (!rect || !block || !Array.isArray(block.tacticalElements)) {
    return [];
  }

  return block.tacticalElements.filter((element) =>
    isSessionPlannerTacticalElementInSelectionRect(element, rect)
  );
}

function renderSessionPlannerTacticalSelectionBox() {
  const rect = getSessionPlannerTacticalSelectionRect();
  if (!rect || rect.width < 0.2 || rect.height < 0.2) {
    return "";
  }

  return `
    <rect
      class="session-tactical-selection-box"
      x="${rect.left}"
      y="${rect.top}"
      width="${rect.width}"
      height="${rect.height}"
      rx="1.4"
    ></rect>
  `;
}

function getSelectedSessionPlannerTacticalElement() {
  if (!sessionPlannerTacticalSelectedElementId) {
    return null;
  }

  return getSessionPlannerTacticalElementById(sessionPlannerTacticalSelectedElementId);
}

function getSelectedSessionPlannerTacticalElements() {
  return getSessionPlannerTacticalSelectedElementIds()
    .map((elementId) => getSessionPlannerTacticalElementById(elementId))
    .filter(Boolean);
}

function syncSessionPlannerTacticalboardInspector() {
  const colorInput = ui.sessionPlannerWorkspace?.querySelector("[data-session-tactical-color]");
  const widthInput = ui.sessionPlannerWorkspace?.querySelector("[data-session-tactical-width]");
  const styleInput = ui.sessionPlannerWorkspace?.querySelector("[data-session-tactical-style]");
  if (!colorInput || !widthInput) {
    return;
  }

  const selectedElement = getSelectedSessionPlannerTacticalElement();
  if (selectedElement) {
    sessionPlannerTacticalColor = normalizeTacticalColor(
      selectedElement.color,
      getDefaultTacticalColor(selectedElement.type)
    );
  }

  if (isSessionPlannerTacticalStrokeElement(selectedElement)) {
    sessionPlannerTacticalLineWidth = normalizeTacticalLineWidth(selectedElement.lineWidth);
    sessionPlannerTacticalLineStyle = normalizeTacticalLineStyle(selectedElement.lineStyle);
  }

  colorInput.value = sessionPlannerTacticalColor;
  widthInput.value = String(sessionPlannerTacticalLineWidth);
  if (styleInput) {
    styleInput.value = sessionPlannerTacticalLineStyle;
  }
}

function updateSelectedSessionPlannerTacticalElement(updates = {}) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const selectedElements = getSelectedSessionPlannerTacticalElements();
  if (!selectedElements.length) {
    return;
  }

  selectedElements.forEach((element) => {
    if (Object.prototype.hasOwnProperty.call(updates, "color")) {
      element.color = normalizeTacticalColor(updates.color, getDefaultTacticalColor(element.type));
    }

    if (
      Object.prototype.hasOwnProperty.call(updates, "lineWidth") &&
      isSessionPlannerTacticalStrokeElement(element)
    ) {
      element.lineWidth = normalizeTacticalLineWidth(updates.lineWidth);
    }

    if (
      Object.prototype.hasOwnProperty.call(updates, "lineStyle") &&
      isSessionPlannerTacticalStrokeElement(element)
    ) {
      element.lineStyle = normalizeTacticalLineStyle(updates.lineStyle);
    }
  });

  const primaryElement = getSelectedSessionPlannerTacticalElement();
  if (primaryElement && Object.prototype.hasOwnProperty.call(updates, "rotation")) {
    primaryElement.rotation = normalizeTacticalRotation(updates.rotation);
  }

  refreshSessionPlannerTacticalboardCanvas({ persist: true });
}

function updateSessionPlannerTacticalLineStyle(lineStyleValue) {
  sessionPlannerTacticalLineStyle = normalizeTacticalLineStyle(lineStyleValue);
  const styleInput = ui.sessionPlannerWorkspace?.querySelector("[data-session-tactical-style]");
  if (styleInput) {
    styleInput.value = sessionPlannerTacticalLineStyle;
  }

  if (getSelectedSessionPlannerTacticalElements().some(isSessionPlannerTacticalStrokeElement)) {
    updateSelectedSessionPlannerTacticalElement({ lineStyle: sessionPlannerTacticalLineStyle });
  }
}

function clampMovedTacticalPoint(point, deltaX, deltaY) {
  return {
    x: clamp(Number(point.x) + deltaX, 0, 100),
    y: clamp(Number(point.y) + deltaY, 0, 100),
  };
}

function moveSessionPlannerTacticalElementFromInitial(element, initial, deltaX, deltaY) {
  if (!element || !initial) {
    return;
  }

  const moved = clampMovedTacticalPoint(initial, deltaX, deltaY);
  element.x = moved.x;
  element.y = moved.y;

  if (Number.isFinite(Number(initial.x2)) && Number.isFinite(Number(initial.y2))) {
    const movedEnd = clampMovedTacticalPoint({ x: initial.x2, y: initial.y2 }, deltaX, deltaY);
    element.x2 = movedEnd.x;
    element.y2 = movedEnd.y;
  }

  if (Number.isFinite(Number(initial.controlX)) && Number.isFinite(Number(initial.controlY))) {
    const movedControl = clampMovedTacticalPoint(
      { x: initial.controlX, y: initial.controlY },
      deltaX,
      deltaY
    );
    element.controlX = movedControl.x;
    element.controlY = movedControl.y;
  }

  if (Array.isArray(initial.points)) {
    element.points = initial.points.map((point) => clampMovedTacticalPoint(point, deltaX, deltaY));
  }
}

function moveSessionPlannerTacticalElement(elementId, deltaX, deltaY) {
  const element = getSessionPlannerTacticalElementById(elementId);
  moveSessionPlannerTacticalElementFromInitial(
    element,
    sessionPlannerTacticalDragState?.initialElement,
    deltaX,
    deltaY
  );
}

function moveSessionPlannerTacticalElements(elementIds = [], deltaX, deltaY) {
  const initialElements = Array.isArray(sessionPlannerTacticalDragState?.initialElements)
    ? sessionPlannerTacticalDragState.initialElements
    : [];
  const initialById = new Map(initialElements.map((element) => [element.id, element]));

  elementIds.forEach((elementId) => {
    const element = getSessionPlannerTacticalElementById(elementId);
    const initial = initialById.get(elementId);

    if (element && initial) {
      moveSessionPlannerTacticalElementFromInitial(element, initial, deltaX, deltaY);
    }
  });
}

function copySelectedSessionPlannerTacticalElements() {
  if (!canEditSessionPlanner()) {
    return false;
  }

  const selectedElements = getSelectedSessionPlannerTacticalElements();
  if (!selectedElements.length) {
    showSessionPlannerToast("Select players or tools first.", "error");
    return false;
  }

  sessionPlannerTacticalClipboard = selectedElements.map(cloneSessionPlannerTacticalElement);
  sessionPlannerTacticalClipboardPasteCount = 0;
  showSessionPlannerToast(
    `Copied: ${selectedElements.length} item${selectedElements.length === 1 ? "" : "s"}. Paste with Cmd/Ctrl+V.`
  );
  return true;
}

function pasteSessionPlannerTacticalClipboard() {
  if (!canEditSessionPlanner()) {
    return false;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return false;
  }

  if (!sessionPlannerTacticalClipboard.length) {
    showSessionPlannerToast("Nothing copied yet.", "error");
    return false;
  }

  if (!Array.isArray(block.tacticalElements)) {
    block.tacticalElements = [];
  }

  const baseOffset = Math.min(
    4.5,
    Math.max(2.2, sessionPlannerTacticalClipboard.length > 1 ? 2.8 : 3.6)
  );
  const copyOffset = baseOffset * (sessionPlannerTacticalClipboardPasteCount + 1);
  const duplicatedElements = sessionPlannerTacticalClipboard.map((element) => {
    const duplicate = cloneSessionPlannerTacticalElement({
      ...element,
      id: createSessionPlannerStableId("tactical"),
    });
    moveSessionPlannerTacticalElementFromInitial(duplicate, element, copyOffset, copyOffset);
    return duplicate;
  });

  block.tacticalElements.push(...duplicatedElements);
  sessionPlannerTacticalClipboardPasteCount += 1;
  setSessionPlannerTacticalSelectedElements(
    duplicatedElements.map((element) => element.id),
    duplicatedElements[0]?.id || ""
  );
  sessionPlannerTacticalPendingPoint = null;
  sessionPlannerTacticalDraftLineState = null;
  sessionPlannerTacticalSelectionState = null;
  refreshSessionPlannerTacticalboardCanvas({ persist: true });
  showSessionPlannerToast(`Pasted: ${duplicatedElements.length} item${duplicatedElements.length === 1 ? "" : "s"}.`);
  return true;
}

function isSessionPlannerTacticalEndpointElement(element = {}) {
  return isSessionPlannerTacticalLineTool(element.type);
}

function updateSessionPlannerTacticalElementHandle(elementId, handle, point) {
  const element = getSessionPlannerTacticalElementById(elementId);
  if (!element || !isSessionPlannerTacticalEndpointElement(element)) {
    return;
  }

  const nextPoint = {
    x: clamp(Number(point.x), 0, 100),
    y: clamp(Number(point.y), 0, 100),
  };

  if (handle === "start") {
    element.x = nextPoint.x;
    element.y = nextPoint.y;
    return;
  }

  if (handle === "control" && element.type === "curve") {
    element.controlX = nextPoint.x;
    element.controlY = nextPoint.y;
    return;
  }

  if (handle === "end") {
    element.x2 = nextPoint.x;
    element.y2 = nextPoint.y;
  }
}

function getSessionPlannerTacticalRotationFromEvent(event, element, rect) {
  const centerX = (clamp(Number(element.x), 0, 100) / 100) * rect.width;
  const centerY = (clamp(Number(element.y), 0, 100) / 100) * rect.height;
  const pointerX = event.clientX - rect.left;
  const pointerY = event.clientY - rect.top;
  const angle = Math.atan2(pointerY - centerY, pointerX - centerX) * (180 / Math.PI) + 90;

  return normalizeTacticalRotation(angle);
}

function shouldPlaceSessionPlannerTacticalDoubleClick(point) {
  if (!point || !isSessionPlannerTacticalPlacementTool()) {
    sessionPlannerTacticalLastPlacementClick = null;
    return false;
  }

  const now = Date.now();
  const previousClick = sessionPlannerTacticalLastPlacementClick;
  sessionPlannerTacticalLastPlacementClick = {
    tool: sessionPlannerTacticalTool,
    x: point.x,
    y: point.y,
    time: now,
  };

  if (!previousClick || previousClick.tool !== sessionPlannerTacticalTool) {
    return false;
  }

  const distance = Math.hypot(point.x - previousClick.x, point.y - previousClick.y);
  return now - previousClick.time <= 520 && distance <= 4.5;
}

function shouldSkipRepeatedSessionPlannerTacticalPlacement(point) {
  const now = Date.now();
  const previousPlacement = sessionPlannerTacticalLastPlacement;
  sessionPlannerTacticalLastPlacement = {
    tool: sessionPlannerTacticalTool,
    x: point.x,
    y: point.y,
    time: now,
  };

  if (!previousPlacement || previousPlacement.tool !== sessionPlannerTacticalTool) {
    return false;
  }

  const distance = Math.hypot(point.x - previousPlacement.x, point.y - previousPlacement.y);
  return now - previousPlacement.time < 350 && distance < 0.8;
}

function addSessionPlannerTacticalPlacementElement(point) {
  if (!point || !isSessionPlannerTacticalPlacementTool()) {
    return false;
  }

  if (shouldSkipRepeatedSessionPlannerTacticalPlacement(point)) {
    return false;
  }

  const { x, y } = point;

  if (sessionPlannerTacticalTool === "text") {
    const label = window.prompt("Text on board", "Coaching point");
    if (!label) {
      return false;
    }

    addSessionPlannerTacticalElement({
      type: "text",
      x,
      y,
      label,
      color: sessionPlannerTacticalColor,
    });
    return true;
  }

  addSessionPlannerTacticalElement({
    type: sessionPlannerTacticalTool,
    x,
    y,
    color: sessionPlannerTacticalColor,
  });
  return true;
}

function handleSessionPlannerTacticalCanvasClick(event, canvas) {
  if (!canEditSessionPlanner() || !canvas) {
    return;
  }

  const clickedElement = event.target.closest?.("[data-session-tactical-element-id]");
  if (sessionPlannerTacticalSuppressNextClick) {
    const shouldSuppressClick = Date.now() - sessionPlannerTacticalSuppressNextClickAt <= 240;
    setSessionPlannerTacticalClickSuppression(false);
    if (shouldSuppressClick) {
      return;
    }
  }

  if (sessionPlannerTacticalTool === "remove" && clickedElement) {
    sessionPlannerTacticalNumberPickerElementId = "";
    removeSessionPlannerTacticalElement(clickedElement.dataset.sessionTacticalElementId);
    return;
  }

  if (clickedElement) {
    const elementId = clickedElement.dataset.sessionTacticalElementId || "";
    if (isSessionPlannerTacticalSelectionToggleModifier(event)) {
      toggleSessionPlannerTacticalElementSelection(elementId);
      return;
    }
    sessionPlannerTacticalNumberPickerElementId =
      sessionPlannerTacticalNumberPickerElementId === elementId ? sessionPlannerTacticalNumberPickerElementId : "";
    setSessionPlannerTacticalSelectedElements([elementId], elementId);
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = null;
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  clearSessionPlannerTacticalSelection();
  sessionPlannerTacticalNumberPickerElementId = "";
  sessionPlannerTacticalDraftLineState = null;
  syncSessionPlannerTacticalboardInspector();

  if (sessionPlannerTacticalTool === "freehand") {
    return;
  }

  const point = getSessionPlannerTacticalCanvasPoint(event, canvas);
  const { x, y } = point;

  if (isSessionPlannerTacticalLineTool()) {
    if (sessionPlannerTacticalTool === "curve") {
      const pendingCurve = sessionPlannerTacticalPendingPoint?.type === "curve"
        ? sessionPlannerTacticalPendingPoint
        : null;

      if (!pendingCurve) {
        sessionPlannerTacticalPendingPoint = {
          ...point,
          type: "curve",
          startPoint: point,
          controlPoint: null,
        };
        refreshSessionPlannerTacticalboardCanvas();
        return;
      }

      if (!pendingCurve.controlPoint) {
        sessionPlannerTacticalPendingPoint = {
          ...pendingCurve,
          controlPoint: point,
        };
        refreshSessionPlannerTacticalboardCanvas();
        return;
      }

      addSessionPlannerTacticalElement(
        createSessionPlannerLineElement("curve", pendingCurve.startPoint || pendingCurve, point, {
          controlPoint: pendingCurve.controlPoint,
        })
      );
      sessionPlannerTacticalPendingPoint = null;
      return;
    }

    if (!sessionPlannerTacticalPendingPoint) {
      sessionPlannerTacticalPendingPoint = { ...point, type: sessionPlannerTacticalTool };
      refreshSessionPlannerTacticalboardCanvas();
      return;
    }

    addSessionPlannerTacticalElement(
      createSessionPlannerLineElement(
        sessionPlannerTacticalTool,
        sessionPlannerTacticalPendingPoint,
        point
      )
    );
    sessionPlannerTacticalPendingPoint = null;
    return;
  }

  const clickCount = Number(event.detail) || 1;
  if (isSessionPlannerTacticalPlacementTool() && clickCount >= 2) {
    addSessionPlannerTacticalPlacementElement(point);
  }
}

function handleSessionPlannerTacticalCanvasDoubleClick(event, canvas) {
  if (!canEditSessionPlanner() || !canvas) {
    return;
  }

  event.preventDefault();
  event.stopPropagation();
  setSessionPlannerTacticalClickSuppression(false);

  const clickedElement = event.target.closest?.("[data-session-tactical-element-id]");
  if (clickedElement) {
    const elementId = clickedElement.dataset.sessionTacticalElementId || "";
    const element = getSessionPlannerTacticalElementById(elementId);
    if (isSessionPlannerTacticalPlayerType(element?.type)) {
      openSessionPlannerTacticalNumberPicker(elementId);
    } else {
      sessionPlannerTacticalNumberPickerElementId = "";
      setSessionPlannerTacticalSelectedElements([elementId], elementId);
      refreshSessionPlannerTacticalboardCanvas();
    }
    return;
  }

  if (!isSessionPlannerTacticalPlacementTool()) {
    return;
  }

  const point = getSessionPlannerTacticalCanvasPoint(event, canvas);
  addSessionPlannerTacticalPlacementElement(point);
}

function startSessionPlannerTacticalDrag(event) {
  if (!canEditSessionPlanner() || !sessionPlannerTacticalboardOpen) {
    return;
  }

  if (event.target.closest?.(".session-tactical-number-picker")) {
    return;
  }

  const canvas = event.target.closest?.("[data-session-tactical-canvas]");
  if (!canvas) {
    return;
  }

  const toggleTrigger = event.target.closest?.("[data-session-tactical-element-id]");
  if (toggleTrigger && isSessionPlannerTacticalSelectionToggleModifier(event) && sessionPlannerTacticalTool !== "remove") {
    event.preventDefault();
    event.stopPropagation();
    toggleSessionPlannerTacticalElementSelection(toggleTrigger.dataset.sessionTacticalElementId || "");
    setSessionPlannerTacticalClickSuppression(true);
    return;
  }

  const handleTrigger = event.target.closest?.("[data-session-tactical-handle]");
  if (handleTrigger && sessionPlannerTacticalTool !== "remove") {
    const element = getSessionPlannerTacticalElementById(handleTrigger.dataset.sessionTacticalElementId);
    if (!element) {
      return;
    }

    event.preventDefault();
    setSessionPlannerTacticalSelectedElements([element.id], element.id);
    sessionPlannerTacticalNumberPickerElementId = "";
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = null;
    sessionPlannerTacticalDragState = {
      elementId: element.id,
      handle: handleTrigger.dataset.sessionTacticalHandle,
      canvasRect: canvas.getBoundingClientRect(),
      moved: false,
    };
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  const rotateTrigger = event.target.closest?.("[data-session-tactical-rotate-handle]");
  if (rotateTrigger && sessionPlannerTacticalTool !== "remove") {
    const element = getSessionPlannerTacticalElementById(rotateTrigger.dataset.sessionTacticalElementId);
    if (!isSessionPlannerTacticalGoalType(element?.type)) {
      return;
    }

    event.preventDefault();
    setSessionPlannerTacticalSelectedElements([element.id], element.id);
    sessionPlannerTacticalNumberPickerElementId = "";
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = null;
    sessionPlannerTacticalDragState = {
      elementId: element.id,
      rotate: true,
      canvasRect: canvas.getBoundingClientRect(),
      moved: false,
    };
    return;
  }

  const elementTrigger = event.target.closest?.("[data-session-tactical-element-id]");
  if (elementTrigger && sessionPlannerTacticalTool !== "remove") {
    const element = getSessionPlannerTacticalElementById(elementTrigger.dataset.sessionTacticalElementId);
    if (!element) {
      return;
    }

    event.preventDefault();
    const dragIds = getSessionPlannerTacticalDragElementIds(event, element.id);
    const initialElements = dragIds
      .map((elementId) => getSessionPlannerTacticalElementById(elementId))
      .filter(Boolean)
      .map(cloneSessionPlannerTacticalElement);
    setSessionPlannerTacticalSelectedElements(dragIds, element.id);
    sessionPlannerTacticalNumberPickerElementId = "";
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = null;
    syncSessionPlannerTacticalboardInspector();
    sessionPlannerTacticalDragState = {
      elementId: element.id,
      elementIds: dragIds,
      canvasRect: canvas.getBoundingClientRect(),
      startPoint: getSessionPlannerTacticalCanvasPoint(event, canvas),
      initialElement: cloneSessionPlannerTacticalElement(element),
      initialElements,
      moved: false,
    };
    return;
  }

  if (isSessionPlannerTacticalPlacementTool()) {
    event.preventDefault();
    sessionPlannerTacticalNumberPickerElementId = "";
    const canvasRect = canvas.getBoundingClientRect();
    const point = getSessionPlannerTacticalCanvasPoint(event, canvas);
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = null;
    sessionPlannerTacticalSelectionState = {
      canvasRect,
      startPoint: point,
      currentPoint: point,
      moved: false,
    };
    return;
  }

  if (sessionPlannerTacticalTool === "freehand") {
    event.preventDefault();
    const canvasRect = canvas.getBoundingClientRect();
    const point = getSessionPlannerTacticalCanvasPoint(event, canvas);
    sessionPlannerTacticalFreehandState = {
      canvasRect,
      points: [point],
      color: sessionPlannerTacticalColor,
      lineWidth: sessionPlannerTacticalLineWidth,
      lineStyle: sessionPlannerTacticalLineStyle,
    };
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  if (isSessionPlannerTacticalLineTool()) {
    event.preventDefault();
    const canvasRect = canvas.getBoundingClientRect();
    const point = getSessionPlannerTacticalCanvasPoint(event, canvas);
    const pendingPointAtStart = sessionPlannerTacticalPendingPoint
      ? { ...sessionPlannerTacticalPendingPoint }
      : null;
    clearSessionPlannerTacticalSelection();
    sessionPlannerTacticalPendingPoint = null;
    sessionPlannerTacticalDraftLineState = {
      type: sessionPlannerTacticalTool,
      canvasRect,
      startPoint: point,
      currentPoint: point,
      pendingPointAtStart,
      moved: false,
    };
    refreshSessionPlannerTacticalboardCanvas();
  }
}

function updateSessionPlannerTacticalDrag(event) {
  if (sessionPlannerTacticalDraftLineState) {
    const point = getSessionPlannerTacticalPointFromRect(event, sessionPlannerTacticalDraftLineState.canvasRect);
    const distance = Math.hypot(
      point.x - sessionPlannerTacticalDraftLineState.startPoint.x,
      point.y - sessionPlannerTacticalDraftLineState.startPoint.y
    );
    sessionPlannerTacticalDraftLineState.currentPoint = point;
    sessionPlannerTacticalDraftLineState.moved = distance > 0.35;
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  if (sessionPlannerTacticalSelectionState) {
    const point = getSessionPlannerTacticalPointFromRect(event, sessionPlannerTacticalSelectionState.canvasRect);
    const distance = Math.hypot(
      point.x - sessionPlannerTacticalSelectionState.startPoint.x,
      point.y - sessionPlannerTacticalSelectionState.startPoint.y
    );
    sessionPlannerTacticalSelectionState.currentPoint = point;
    sessionPlannerTacticalSelectionState.moved = distance > 0.35;
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  if (sessionPlannerTacticalDragState) {
    const point = getSessionPlannerTacticalPointFromRect(event, sessionPlannerTacticalDragState.canvasRect);

    if (sessionPlannerTacticalDragState.handle) {
      updateSessionPlannerTacticalElementHandle(
        sessionPlannerTacticalDragState.elementId,
        sessionPlannerTacticalDragState.handle,
        point
      );
      sessionPlannerTacticalDragState.moved = true;
      refreshSessionPlannerTacticalboardCanvas();
      return;
    }

    if (sessionPlannerTacticalDragState.rotate) {
      const element = getSessionPlannerTacticalElementById(sessionPlannerTacticalDragState.elementId);
      if (isSessionPlannerTacticalGoalType(element?.type)) {
        element.rotation = getSessionPlannerTacticalRotationFromEvent(
          event,
          element,
          sessionPlannerTacticalDragState.canvasRect
        );
        sessionPlannerTacticalDragState.moved = true;
        refreshSessionPlannerTacticalboardCanvas();
      }
      return;
    }

    const deltaX = point.x - sessionPlannerTacticalDragState.startPoint.x;
    const deltaY = point.y - sessionPlannerTacticalDragState.startPoint.y;

    if (Math.abs(deltaX) > 0.1 || Math.abs(deltaY) > 0.1) {
      sessionPlannerTacticalDragState.moved = true;
      moveSessionPlannerTacticalElements(
        sessionPlannerTacticalDragState.elementIds ?? [sessionPlannerTacticalDragState.elementId],
        deltaX,
        deltaY
      );
      refreshSessionPlannerTacticalboardCanvas();
    }
    return;
  }

  if (sessionPlannerTacticalFreehandState) {
    const point = getSessionPlannerTacticalPointFromRect(event, sessionPlannerTacticalFreehandState.canvasRect);
    const lastPoint = sessionPlannerTacticalFreehandState.points.at(-1);
    const distance = Math.hypot(point.x - lastPoint.x, point.y - lastPoint.y);

    if (distance > 0.55) {
      sessionPlannerTacticalFreehandState.points.push(point);
      refreshSessionPlannerTacticalboardCanvas();
    }
  }
}

function finishSessionPlannerTacticalDrag() {
  if (sessionPlannerTacticalDraftLineState) {
    const draftLine = sessionPlannerTacticalDraftLineState;
    sessionPlannerTacticalDraftLineState = null;
    setSessionPlannerTacticalClickSuppression(true);

    if (draftLine.moved) {
      addSessionPlannerTacticalElement(
        createSessionPlannerLineElement(draftLine.type, draftLine.startPoint, draftLine.currentPoint)
      );
      return;
    }

    if (draftLine.pendingPointAtStart) {
      if (draftLine.type === "curve") {
        const pendingCurve = draftLine.pendingPointAtStart.type === "curve"
          ? draftLine.pendingPointAtStart
          : { ...draftLine.pendingPointAtStart, type: "curve", startPoint: draftLine.pendingPointAtStart };

        if (!pendingCurve.controlPoint) {
          sessionPlannerTacticalPendingPoint = {
            ...pendingCurve,
            type: "curve",
            startPoint: pendingCurve.startPoint || draftLine.pendingPointAtStart,
            controlPoint: draftLine.startPoint,
          };
          refreshSessionPlannerTacticalboardCanvas();
          return;
        }

        addSessionPlannerTacticalElement(
          createSessionPlannerLineElement(
            "curve",
            pendingCurve.startPoint || pendingCurve,
            draftLine.startPoint,
            { controlPoint: pendingCurve.controlPoint }
          )
        );
        return;
      }

      addSessionPlannerTacticalElement(
        createSessionPlannerLineElement(draftLine.type, draftLine.pendingPointAtStart, draftLine.startPoint)
      );
      return;
    }

    sessionPlannerTacticalPendingPoint =
      draftLine.type === "curve"
        ? {
            ...draftLine.startPoint,
            type: "curve",
            startPoint: draftLine.startPoint,
            controlPoint: null,
          }
        : { ...draftLine.startPoint, type: draftLine.type };
    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  if (sessionPlannerTacticalSelectionState) {
    const selection = sessionPlannerTacticalSelectionState;
    const rect = getSessionPlannerTacticalSelectionRect(selection);
    sessionPlannerTacticalSelectionState = null;
    setSessionPlannerTacticalClickSuppression(selection.moved);

    if (!selection.moved && isSessionPlannerTacticalPlacementTool()) {
      if (shouldPlaceSessionPlannerTacticalDoubleClick(selection.startPoint)) {
        setSessionPlannerTacticalClickSuppression(true);
        if (!addSessionPlannerTacticalPlacementElement(selection.startPoint)) {
          refreshSessionPlannerTacticalboardCanvas();
        }
        return;
      }

      clearSessionPlannerTacticalSelection();
    }

    if (selection.moved && rect) {
      const selectedIds = getSessionPlannerTacticalElementsInRect(rect).map((element) => element.id);
      setSessionPlannerTacticalSelectedElements(selectedIds);
    }

    refreshSessionPlannerTacticalboardCanvas();
    return;
  }

  if (sessionPlannerTacticalDragState) {
    setSessionPlannerTacticalClickSuppression(sessionPlannerTacticalDragState.moved);
    sessionPlannerTacticalDragState = null;
    refreshSessionPlannerTacticalboardCanvas({ persist: true });
  }

  if (sessionPlannerTacticalFreehandState) {
    const freehand = sessionPlannerTacticalFreehandState;
    sessionPlannerTacticalFreehandState = null;

    if (freehand.points.length > 1) {
      addSessionPlannerTacticalElement({
        type: "freehand",
        x: freehand.points[0].x,
        y: freehand.points[0].y,
        points: freehand.points,
        color: freehand.color,
        lineWidth: freehand.lineWidth,
        lineStyle: freehand.lineStyle,
      });
      return;
    }

    clearSessionPlannerTacticalSelection();
    refreshSessionPlannerTacticalboardCanvas();
  }
}

function startSessionPlannerPlayerBoardDrag(event) {
  if (!canEditSessionPlanner()) {
    return false;
  }

  const token = event.target.closest?.("[data-session-player-board-token]");
  const board = token?.closest?.("[data-session-player-board]");
  const block = getSessionPlannerSelectedBlock();
  if (!token || !board || !block) {
    return false;
  }

  const playerId = token.dataset.sessionPlayerBoardToken;
  if (!playerId) {
    return false;
  }

  const currentSelectedIds = normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds, block);
  if (event.shiftKey || event.metaKey || event.ctrlKey) {
    toggleSessionPlannerPlayerBoardSelectedPlayer(playerId);
  } else if (!currentSelectedIds.includes(playerId)) {
    setSessionPlannerPlayerBoardSelectedPlayers([playerId]);
  }

  const selectedIds = normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds, block);
  const dragPlayerIds = selectedIds.includes(playerId) ? selectedIds : [playerId];
  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const startPositions = dragPlayerIds.reduce((positions, selectedPlayerId) => {
    positions[selectedPlayerId] = getSessionPlannerPlayerBoardPositionById(block, selectedPlayerId, boardPlayers);
    return positions;
  }, {});
  const tokenRect = token.getBoundingClientRect();
  sessionPlannerPlayerBoardDragState = {
    blockId: block.id,
    playerId,
    playerIds: dragPlayerIds,
    board,
    token,
    pointerId: event.pointerId,
    startX: event.clientX,
    startY: event.clientY,
    startPositions,
    anchorStartPosition: startPositions[playerId] ?? getSessionPlannerPlayerBoardPositionById(block, playerId, boardPlayers),
    pointerOffsetX: event.clientX - (tokenRect.left + tokenRect.width / 2),
    pointerOffsetY: event.clientY - (tokenRect.top + tokenRect.height / 2),
    moved: false,
  };

  event.preventDefault();
  token.classList.add("is-dragging");
  token.setPointerCapture?.(event.pointerId);
  return true;
}

function updateSessionPlannerPlayerBoardDrag(event) {
  if (!sessionPlannerPlayerBoardDragState) {
    return false;
  }

  const block = getSessionPlannerSelectedBlock();
  const dragState = sessionPlannerPlayerBoardDragState;
  if (!block || block.id !== dragState.blockId) {
    sessionPlannerPlayerBoardDragState = null;
    return false;
  }

  const boardRect = dragState.board.getBoundingClientRect();
  const moveDistance = Math.hypot(event.clientX - dragState.startX, event.clientY - dragState.startY);
  if (!dragState.moved && moveDistance < 8) {
    return true;
  }

  const x = clamp(((event.clientX - boardRect.left - dragState.pointerOffsetX) / boardRect.width) * 100, 0, 100);
  const y = clamp(((event.clientY - boardRect.top - dragState.pointerOffsetY) / boardRect.height) * 100, 0, 100);

  if (!block.playerBoardPositions || typeof block.playerBoardPositions !== "object") {
    block.playerBoardPositions = {};
  }
  block.playerBoardLayoutMode = "manual";

  const anchorStartPosition = dragState.anchorStartPosition ?? { x, y };
  const deltaX = x - anchorStartPosition.x;
  const deltaY = y - anchorStartPosition.y;
  const movingPlayerIds = Array.isArray(dragState.playerIds) && dragState.playerIds.length
    ? dragState.playerIds
    : [dragState.playerId];

  movingPlayerIds.forEach((playerId) => {
    const startPosition = dragState.startPositions?.[playerId] ?? anchorStartPosition;
    const nextPosition = {
      x: clamp(startPosition.x + deltaX, 0, 100),
      y: clamp(startPosition.y + deltaY, 0, 100),
    };
    block.playerBoardPositions[playerId] = nextPosition;
    const playerToken = Array.from(dragState.board.querySelectorAll("[data-session-player-board-token]"))
      .find((candidate) => candidate.dataset.sessionPlayerBoardToken === playerId);
    if (playerToken) {
      playerToken.style.left = `${nextPosition.x}%`;
      playerToken.style.top = `${nextPosition.y}%`;
    }
  });
  dragState.moved = true;
  return true;
}

function finishSessionPlannerPlayerBoardDrag() {
  if (!sessionPlannerPlayerBoardDragState) {
    return false;
  }

  const { token, moved, pointerId } = sessionPlannerPlayerBoardDragState;
  token?.classList.remove("is-dragging");
  token?.releasePointerCapture?.(pointerId);
  sessionPlannerPlayerBoardDragState = null;

  if (moved) {
    const block = getSessionPlannerSelectedBlock();
    markSessionPlannerBlockFieldsUpdated(block, ["playerBoardLayoutMode", "playerBoardPositions"]);
    writeSessionPlannerState();
  }

  return true;
}

function getSessionPlannerPlayerBoardEventPoint(event, board) {
  const rect = board.getBoundingClientRect();
  return {
    x: clamp(((event.clientX - rect.left) / rect.width) * 100, 0, 100),
    y: clamp(((event.clientY - rect.top) / rect.height) * 100, 0, 100),
  };
}

function getSessionPlannerPlayerBoardSelectionRect(selection) {
  if (!selection) {
    return null;
  }

  return {
    left: Math.min(selection.startPoint.x, selection.currentPoint.x),
    top: Math.min(selection.startPoint.y, selection.currentPoint.y),
    width: Math.abs(selection.currentPoint.x - selection.startPoint.x),
    height: Math.abs(selection.currentPoint.y - selection.startPoint.y),
  };
}

function syncSessionPlannerPlayerBoardSelectionBox() {
  const selection = sessionPlannerPlayerBoardSelectionState;
  const box = selection?.board?.querySelector("[data-session-player-board-selection-box]");
  if (!box) {
    return;
  }

  const rect = getSessionPlannerPlayerBoardSelectionRect(selection);
  if (!selection?.moved || !rect) {
    box.style.display = "none";
    return;
  }

  box.style.display = "block";
  box.style.left = `${rect.left}%`;
  box.style.top = `${rect.top}%`;
  box.style.width = `${rect.width}%`;
  box.style.height = `${rect.height}%`;
}

function startSessionPlannerPlayerBoardSelection(event) {
  if (!canEditSessionPlanner()) {
    return false;
  }

  const board = event.target.closest?.("[data-session-player-board]");
  if (!board || event.target.closest?.("[data-session-player-board-token]")) {
    return false;
  }

  const startPoint = getSessionPlannerPlayerBoardEventPoint(event, board);
  sessionPlannerPlayerBoardSelectionState = {
    board,
    pointerId: event.pointerId,
    startClientX: event.clientX,
    startClientY: event.clientY,
    startPoint,
    currentPoint: startPoint,
    additive: event.shiftKey || event.metaKey || event.ctrlKey,
    moved: false,
  };

  event.preventDefault();
  board.setPointerCapture?.(event.pointerId);
  return true;
}

function updateSessionPlannerPlayerBoardSelection(event) {
  if (!sessionPlannerPlayerBoardSelectionState) {
    return false;
  }

  const selection = sessionPlannerPlayerBoardSelectionState;
  const moveDistance = Math.hypot(event.clientX - selection.startClientX, event.clientY - selection.startClientY);
  selection.currentPoint = getSessionPlannerPlayerBoardEventPoint(event, selection.board);
  selection.moved = moveDistance >= 8;
  syncSessionPlannerPlayerBoardSelectionBox();
  return true;
}

function finishSessionPlannerPlayerBoardSelection() {
  if (!sessionPlannerPlayerBoardSelectionState) {
    return false;
  }

  const selection = sessionPlannerPlayerBoardSelectionState;
  const rect = getSessionPlannerPlayerBoardSelectionRect(selection);
  selection.board?.releasePointerCapture?.(selection.pointerId);
  sessionPlannerPlayerBoardSelectionState = null;
  selection.board?.querySelector("[data-session-player-board-selection-box]")?.removeAttribute("style");

  if (!selection.moved || !rect) {
    if (!selection.additive) {
      setSessionPlannerPlayerBoardSelectedPlayers([]);
    }
    return true;
  }

  const selectedIds = Array.from(selection.board.querySelectorAll("[data-session-player-board-token]"))
    .filter((token) => {
      const x = Number.parseFloat(token.style.left);
      const y = Number.parseFloat(token.style.top);
      return (
        Number.isFinite(x) &&
        Number.isFinite(y) &&
        x >= rect.left &&
        x <= rect.left + rect.width &&
        y >= rect.top &&
        y <= rect.top + rect.height
      );
    })
    .map((token) => token.dataset.sessionPlayerBoardToken)
    .filter(Boolean);

  const nextIds = selection.additive
    ? [...sessionPlannerPlayerBoardSelectedPlayerIds, ...selectedIds]
    : selectedIds;
  setSessionPlannerPlayerBoardSelectedPlayers(nextIds);
  return true;
}

const sessionPlannerVisualUploadMaxSide = 1600;
const sessionPlannerVisualUploadMaxPassthroughBytes = 700000;
const sessionPlannerVisualUploadQuality = 0.84;
const sessionPlannerVisualUploadPassthroughTypes = new Set(["image/gif", "image/svg+xml"]);

function readSessionPlannerFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.addEventListener("load", () => resolve(String(reader.result || "")));
    reader.addEventListener("error", () => reject(reader.error || new Error("Image could not be read.")));
    reader.readAsDataURL(file);
  });
}

function loadSessionPlannerUploadImage(dataUrl) {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.addEventListener("load", () => resolve(image));
    image.addEventListener("error", () => reject(new Error("Image could not be loaded.")));
    image.src = dataUrl;
  });
}

function findSessionPlannerBlockById(blockId) {
  const sessions = sessionPlannerState?.sessions || {};
  for (const session of Object.values(sessions)) {
    const block = Array.isArray(session?.blocks)
      ? session.blocks.find((candidate) => candidate.id === blockId)
      : null;
    if (block) {
      return block;
    }
  }

  return null;
}

async function normalizeSessionPlannerVisualUpload(file) {
  const originalDataUrl = await readSessionPlannerFileAsDataUrl(file);
  if (sessionPlannerVisualUploadPassthroughTypes.has(file.type)) {
    return originalDataUrl;
  }

  try {
    const image = await loadSessionPlannerUploadImage(originalDataUrl);
    const sourceWidth = image.naturalWidth || image.width;
    const sourceHeight = image.naturalHeight || image.height;
    const largestSide = Math.max(sourceWidth, sourceHeight);

    if (file.size <= sessionPlannerVisualUploadMaxPassthroughBytes && largestSide <= sessionPlannerVisualUploadMaxSide) {
      return originalDataUrl;
    }

    const scale = Math.min(1, sessionPlannerVisualUploadMaxSide / largestSide);
    const canvas = document.createElement("canvas");
    canvas.width = Math.max(1, Math.round(sourceWidth * scale));
    canvas.height = Math.max(1, Math.round(sourceHeight * scale));
    const context = canvas.getContext("2d");
    if (!context) {
      return originalDataUrl;
    }

    context.fillStyle = "#ffffff";
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.drawImage(image, 0, 0, canvas.width, canvas.height);
    return canvas.toDataURL("image/jpeg", sessionPlannerVisualUploadQuality);
  } catch {
    return originalDataUrl;
  }
}

async function handleSessionPlannerVisualUpload(file) {
  if (!canEditSessionPlanner() || !file) {
    return;
  }

  if (!file.type.startsWith("image/")) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const blockId = block.id;
  const previousVisualImage = block.visualImage || "";

  try {
    const visualImage = await normalizeSessionPlannerVisualUpload(file);
    const targetBlock = findSessionPlannerBlockById(blockId);
    if (!targetBlock) {
      return;
    }

    targetBlock.visualImage = visualImage;
    markSessionPlannerBlockFieldsUpdated(targetBlock, ["visualImage"]);
    if (!writeSessionPlannerState()) {
      targetBlock.visualImage = previousVisualImage;
      markSessionPlannerBlockFieldsUpdated(targetBlock, ["visualImage"]);
      writeSessionPlannerState();
      showSessionPlannerToast("The image could not be saved. Try a smaller file.", "error");
      return;
    }

    renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
    showSessionPlannerToast("Uploaded image saved.");
  } catch {
    showSessionPlannerToast("The image could not be uploaded.", "error");
  }
}

function applySessionPlannerExercise(exerciseId) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const exercise = getSessionPlannerExerciseLibrary().find((item) => item.id === exerciseId);
  const block = getSessionPlannerSelectedBlock();
  if (!exercise || !block) {
    return;
  }

  if (isSessionPlannerLibraryExerciseArchived(exercise)) {
    showSessionPlannerToast("Restore the exercise before using it in a session.", "warning");
    return;
  }

  const {
    archivedAt,
    archivedBy,
    createdAt,
    createdBy,
    source,
    tags,
    updatedAt,
    updatedBy,
    versions,
    ...exerciseContent
  } = exercise;

  Object.assign(block, {
    ...exerciseContent,
    id: block.id,
    label: block.label,
    visualImage: exercise.visualImage || "",
    playerBoardPositions: normalizeSessionPlannerPlayerBoardPositions(exercise.playerBoardPositions),
    playerBoardColors: normalizeSessionPlannerPlayerBoardColors(exercise.playerBoardColors),
    tacticalElements: Array.isArray(exercise.tacticalElements)
      ? exercise.tacticalElements.map(cloneSessionPlannerTacticalElement)
      : [],
  });
  markSessionPlannerBlockFieldsUpdated(block, sessionPlannerBlockMergeFields);
  sessionPlannerLibraryOpen = false;
  sessionPlannerAddMenuOpen = false;
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
}

function updateSelectedSessionPlannerBlockField(field, rawValue) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  const previousValue = block?.[field];
  if (!assignSessionPlannerBlockFieldValue(block, field, rawValue)) {
    return;
  }

  if (block[field] !== previousValue) {
    markSessionPlannerBlockFieldsUpdated(block, [field]);
  }
  writeSessionPlannerState();
}

function getSessionPlannerDateLabel(dateValue, options = {}) {
  return new Intl.DateTimeFormat("en-GB", options).format(parseScheduleDateValue(dateValue));
}

function renderSessionPlannerDateStrip() {
  const selectedDate = parseScheduleDateValue(sessionPlannerState.selectedDate);
  const startDate = new Date(selectedDate);
  startDate.setDate(selectedDate.getDate() - 10);

  return Array.from({ length: 21 }, (_, index) => {
    const date = new Date(startDate);
    date.setDate(startDate.getDate() + index);
    const dateValue = formatScheduleDateValue(date);
    const isSelected = dateValue === sessionPlannerState.selectedDate;
    const hasSession =
      Boolean(sessionPlannerState.sessions?.[dateValue]?.blocks?.length) ||
      Boolean(getScheduleSessionEventForDate(dateValue));
    return `
      <button
        type="button"
        class="session-date-pill${isSelected ? " is-active" : ""}${hasSession ? " has-session" : ""}"
        data-session-date="${escapeHtml(dateValue)}"
      >
        <span>${escapeHtml(getSessionPlannerDateLabel(dateValue, { weekday: "short" }))}</span>
        <strong>${escapeHtml(getSessionPlannerDateLabel(dateValue, { day: "numeric" }))}</strong>
        <em>${escapeHtml(getSessionPlannerDateLabel(dateValue, { month: "short" }))}</em>
      </button>
    `;
  }).join("");
}

function syncSessionPlannerDateStripState(dateControls = ui.sessionPlannerWorkspace?.querySelector(".session-date-controls")) {
  const dateStrip = dateControls?.querySelector(".session-date-strip");
  if (!dateStrip || !sessionPlannerState) {
    return;
  }

  dateStrip.querySelectorAll("[data-session-date]").forEach((dateButton) => {
    const dateValue = dateButton.dataset.sessionDate;
    const isSelected = dateValue === sessionPlannerState.selectedDate;
    const hasSession =
      Boolean(sessionPlannerState.sessions?.[dateValue]?.blocks?.length) ||
      Boolean(getScheduleSessionEventForDate(dateValue));

    dateButton.classList.toggle("is-active", isSelected);
    dateButton.classList.toggle("has-session", hasSession);
  });
}

function scrollSessionPlannerSelectedDateIntoView(options = {}) {
  const selectedDateButton = ui.sessionPlannerWorkspace?.querySelector(".session-date-pill.is-active");
  selectedDateButton?.scrollIntoView({
    behavior: options.behavior || "auto",
    block: "nearest",
    inline: "center",
  });
}

function renderSessionPlannerPitchDiagram(diagram = "empty", options = {}) {
  const markersByDiagram = {
    empty: [],
    "possession-lanes": [
      [13, 46, "blue"], [22, 40, "blue"], [33, 50, "blue"], [43, 44, "blue"], [54, 52, "blue"], [68, 58, "blue"],
      [18, 60, "red"], [31, 67, "red"], [42, 62, "red"], [56, 69, "red"], [75, 64, "red"], [46, 38, "red"],
      [26, 30, "ball"],
    ],
    "build-up": [
      [16, 76, "blue"], [28, 64, "blue"], [42, 72, "blue"], [55, 58, "blue"], [68, 68, "blue"],
      [34, 48, "red"], [50, 44, "red"], [66, 48, "red"], [44, 62, "ball"],
    ],
    "final-third": [
      [18, 44, "blue"], [31, 38, "blue"], [45, 45, "blue"], [58, 34, "blue"], [72, 50, "blue"],
      [35, 55, "red"], [50, 58, "red"], [66, 56, "red"], [22, 44, "ball"],
    ],
  };
  const resolvedDiagram = markersByDiagram[diagram] ? diagram : "empty";
  const markers = markersByDiagram[resolvedDiagram];
  const isEmptyDiagram = resolvedDiagram === "empty";
  const pitchMode = normalizeSessionPlannerTacticalPitchMode(options.pitchMode);
  const pitchModeOption = getSessionPlannerTacticalPitchModeOption(pitchMode);
  const isLandscape = Boolean(options.landscape || pitchModeOption.landscape);

  return `
    <div class="session-pitch-diagram session-pitch-diagram-${escapeHtml(resolvedDiagram)} session-pitch-diagram-mode-${escapeHtml(pitchMode)}${isLandscape ? " session-pitch-diagram-landscape" : ""}" aria-label="Exercise pitch diagram">
      <div class="session-pitch-goal session-pitch-goal-top"></div>
      <div class="session-pitch-goal session-pitch-goal-bottom"></div>
      <div class="session-pitch-box session-pitch-box-top"></div>
      <div class="session-pitch-box session-pitch-box-bottom"></div>
      <div class="session-pitch-goal-area session-pitch-goal-area-top"></div>
      <div class="session-pitch-goal-area session-pitch-goal-area-bottom"></div>
      <span class="session-pitch-penalty-spot session-pitch-penalty-spot-top"></span>
      <span class="session-pitch-penalty-spot session-pitch-penalty-spot-bottom"></span>
      <div class="session-pitch-halfway-edge session-pitch-halfway-edge-top"></div>
      <div class="session-pitch-halfway-edge session-pitch-halfway-edge-bottom"></div>
      <div class="session-pitch-circle"></div>
      ${
        isEmptyDiagram
          ? ""
          : `
            <div class="session-pitch-zone"></div>
            <div class="session-pitch-dashed session-pitch-dashed-top"></div>
            <div class="session-pitch-dashed session-pitch-dashed-bottom"></div>
            <div class="session-mini-goal" style="left: 24%; top: 30%;"></div>
            <div class="session-mini-goal" style="left: 48%; top: 30%;"></div>
            <div class="session-mini-goal" style="left: 72%; top: 30%;"></div>
            <div class="session-mini-goal" style="left: 24%; top: 78%;"></div>
            <div class="session-mini-goal" style="left: 48%; top: 78%;"></div>
            <div class="session-mini-goal" style="left: 72%; top: 78%;"></div>
          `
      }
      ${markers
        .map(([left, top, team]) => `
          <span
            class="session-player-marker session-player-marker-${escapeHtml(team)}"
            style="left: ${left}%; top: ${top}%;"
          ></span>
        `)
        .join("")}
    </div>
  `;
}

function getSessionPlannerVisualElementId(block) {
  return `session-arrow-${String(block?.id || "block").replace(/[^a-zA-Z0-9_-]/g, "-")}`;
}

function renderSessionPlannerTacticalSvgElement(element, arrowId) {
  const idAttribute = `data-session-tactical-element-id="${escapeHtml(element.id)}"`;
  const selectedClass = isSessionPlannerTacticalElementSelected(element.id) ? " is-selected" : "";
  const previewClass = element.preview ? " is-preview" : "";
  const x = Number.isFinite(Number(element.x)) ? clamp(Number(element.x), 0, 100) : 50;
  const y = Number.isFinite(Number(element.y)) ? clamp(Number(element.y), 0, 100) : 50;
  const hasEndPoint = Number.isFinite(Number(element.x2)) && Number.isFinite(Number(element.y2));
  const isRectangularElement = element.type === "zone" || element.type === "dashed-zone";
  const x2 = hasEndPoint ? clamp(Number(element.x2), 0, 100) : clamp(x + (isRectangularElement ? 24 : 10), 0, 100);
  const y2 = hasEndPoint ? clamp(Number(element.y2), 0, 100) : clamp(y + (isRectangularElement ? 14 : 0), 0, 100);
  const color = normalizeTacticalColor(element.color, getDefaultTacticalColor(element.type));
  const lineWidth = getSessionPlannerTacticalRenderStrokeWidth(element.lineWidth);
  const dashArray = getTacticalStrokeDasharray(element.lineStyle || getDefaultTacticalLineStyle(element.type));
  const dashAttribute = dashArray ? `stroke-dasharray="${escapeHtml(dashArray)}"` : "";

  if (["arrow", "pass", "line", "dashed-line"].includes(element.type)) {
    const shouldUseArrow = element.type !== "line" && element.type !== "dashed-line";
    return `
      <line
        ${idAttribute}
        class="session-tactical-${escapeHtml(element.type)}${selectedClass}${previewClass}"
        x1="${x}"
        y1="${y}"
        x2="${x2}"
        y2="${y2}"
        stroke="${escapeHtml(color)}"
        stroke-width="${lineWidth}"
        ${dashAttribute}
        ${shouldUseArrow ? `marker-end="url(#${escapeHtml(arrowId)})"` : ""}
      ></line>
      <line
        ${idAttribute}
        class="session-tactical-hit-target"
        x1="${x}"
        y1="${y}"
        x2="${x2}"
        y2="${y2}"
      ></line>
    `;
  }

  if (element.type === "curve" || element.type === "run") {
    const controlPoint = element.type === "curve"
      ? getSessionPlannerTacticalCurveControlPoint(element, { x, y, x2, y2 })
      : getSessionPlannerTacticalDefaultCurveControlPoint({ x, y }, { x: x2, y: y2 });
    const controlX = controlPoint.x;
    const controlY = controlPoint.y;

    return `
      <path
        ${idAttribute}
        class="session-tactical-${escapeHtml(element.type)}${selectedClass}${previewClass}"
        d="M ${x} ${y} Q ${controlX} ${controlY} ${x2} ${y2}"
        stroke="${escapeHtml(color)}"
        stroke-width="${lineWidth}"
        ${dashAttribute}
        ${element.type === "run" ? `marker-end="url(#${escapeHtml(arrowId)})"` : ""}
      ></path>
      <path
        ${idAttribute}
        class="session-tactical-hit-target"
        d="M ${x} ${y} Q ${controlX} ${controlY} ${x2} ${y2}"
      ></path>
    `;
  }

  if (isRectangularElement) {
    const rectX = Math.min(x, x2);
    const rectY = Math.min(y, y2);
    const rectWidth = Math.max(Math.abs(x2 - x), 4);
    const rectHeight = Math.max(Math.abs(y2 - y), 4);
    const isDashedZone = element.type === "dashed-zone";

    return `
      <rect
        ${idAttribute}
        class="session-tactical-${escapeHtml(element.type)}${selectedClass}${previewClass}"
        x="${rectX}"
        y="${rectY}"
        width="${rectWidth}"
        height="${rectHeight}"
        rx="3"
        fill="${isDashedZone ? "none" : escapeHtml(color)}"
        stroke="${escapeHtml(color)}"
        stroke-width="${Math.max(0.16, lineWidth * 0.72)}"
        ${dashAttribute}
      ></rect>
      <rect
        ${idAttribute}
        class="session-tactical-hit-target session-tactical-shape-hit-target"
        x="${rectX}"
        y="${rectY}"
        width="${rectWidth}"
        height="${rectHeight}"
        rx="3"
      ></rect>
    `;
  }

  if (element.type === "ellipse") {
    const rectX = Math.min(x, x2);
    const rectY = Math.min(y, y2);
    const rectWidth = Math.max(Math.abs(x2 - x), 5);
    const rectHeight = Math.max(Math.abs(y2 - y), 5);

    return `
      <ellipse
        ${idAttribute}
        class="session-tactical-ellipse${selectedClass}${previewClass}"
        cx="${rectX + rectWidth / 2}"
        cy="${rectY + rectHeight / 2}"
        rx="${rectWidth / 2}"
        ry="${rectHeight / 2}"
        fill="${escapeHtml(color)}"
        stroke="${escapeHtml(color)}"
        stroke-width="${Math.max(0.16, lineWidth * 0.72)}"
        ${dashAttribute}
      ></ellipse>
      <ellipse
        ${idAttribute}
        class="session-tactical-hit-target session-tactical-shape-hit-target"
        cx="${rectX + rectWidth / 2}"
        cy="${rectY + rectHeight / 2}"
        rx="${rectWidth / 2}"
        ry="${rectHeight / 2}"
      ></ellipse>
    `;
  }

  if (element.type === "freehand" && Array.isArray(element.points) && element.points.length > 1) {
    const d = element.points
      .map((point, index) => `${index === 0 ? "M" : "L"} ${clamp(point.x, 0, 100)} ${clamp(point.y, 0, 100)}`)
      .join(" ");

    return `
      <path
        ${idAttribute}
        class="session-tactical-freehand${selectedClass}${previewClass}"
        d="${escapeHtml(d)}"
        stroke="${escapeHtml(color)}"
        stroke-width="${lineWidth}"
        ${dashAttribute}
      ></path>
      <path
        ${idAttribute}
        class="session-tactical-hit-target"
        d="${escapeHtml(d)}"
      ></path>
    `;
  }

  return "";
}

function renderSessionPlannerTacticalHtmlElement(element) {
  const x = Number.isFinite(Number(element.x)) ? Number(element.x) : 50;
  const y = Number.isFinite(Number(element.y)) ? Number(element.y) : 50;
  const color = normalizeTacticalColor(element.color, getDefaultTacticalColor(element.type));
  const rotation = isSessionPlannerTacticalGoalType(element.type) ? normalizeTacticalRotation(element.rotation) : 0;
  const style = `left: ${x}%; top: ${y}%; --session-tactical-color: ${escapeHtml(color)}; --session-tactical-rotation: ${rotation}deg;`;
  const dataAttribute = `data-session-tactical-element-id="${escapeHtml(element.id)}"`;
  const selectedClass = isSessionPlannerTacticalElementSelected(element.id) ? " is-selected" : "";

  if (element.type === "text") {
    return `
      <span
        class="session-tactical-marker session-tactical-text${selectedClass}"
        ${dataAttribute}
        style="${style}"
      >${escapeHtml(element.label || "Text")}</span>
    `;
  }

  if (element.type === "mini-goal") {
    return `
      <span
        class="session-tactical-marker session-tactical-mini-goal${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "big-goal") {
    return `
      <span
        class="session-tactical-marker session-tactical-big-goal${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "coach") {
    return `
      <span
        class="session-tactical-marker session-tactical-coach${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-label="Coach"
      >C</span>
    `;
  }

  if (element.type === "mannequin") {
    return `
      <span
        class="session-tactical-marker session-tactical-mannequin${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "pole") {
    return `
      <span
        class="session-tactical-marker session-tactical-pole${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "gate") {
    return `
      <span
        class="session-tactical-marker session-tactical-gate${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "cone") {
    return `
      <span
        class="session-tactical-marker session-tactical-cone${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "ball") {
    return `
      <span
        class="session-tactical-marker session-tactical-ball${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      ></span>
    `;
  }

  if (element.type === "blue-player" || element.type === "red-player" || element.type === "neutral-player") {
    const playerBadge = normalizeSessionPlannerTacticalPlayerBadge(element.playerNumber);
    const badgeClass = playerBadge ? " has-badge" : "";
    const badgeSizeClass = playerBadge.length > 1 ? " is-wide" : "";
    return `
      <span
        class="session-tactical-marker session-tactical-player session-tactical-${escapeHtml(element.type)}${badgeClass}${selectedClass}"
        ${dataAttribute}
        style="${style}"
        aria-hidden="true"
      >${playerBadge ? `<span class="session-tactical-player-badge${badgeSizeClass}">${escapeHtml(playerBadge)}</span>` : ""}</span>
    `;
  }

  return "";
}

function getSessionPlannerTacticalEndpointCoordinates(element) {
  if (!element || !isSessionPlannerTacticalEndpointElement(element)) {
    return null;
  }

  const x = Number.isFinite(Number(element.x)) ? clamp(Number(element.x), 0, 100) : 50;
  const y = Number.isFinite(Number(element.y)) ? clamp(Number(element.y), 0, 100) : 50;
  const isRectangularElement = element.type === "zone" || element.type === "dashed-zone";
  const hasEndPoint = Number.isFinite(Number(element.x2)) && Number.isFinite(Number(element.y2));
  const x2 = hasEndPoint ? clamp(Number(element.x2), 0, 100) : clamp(x + (isRectangularElement ? 24 : 10), 0, 100);
  const y2 = hasEndPoint ? clamp(Number(element.y2), 0, 100) : clamp(y + (isRectangularElement ? 14 : 0), 0, 100);

  const coordinates = { x, y, x2, y2 };

  if (element.type === "curve") {
    const controlPoint = getSessionPlannerTacticalCurveControlPoint(element, coordinates);

    return {
      ...coordinates,
      controlX: controlPoint.x,
      controlY: controlPoint.y,
    };
  }

  return coordinates;
}

function getSessionPlannerTacticalPointDistanceMeters(from = {}, to = {}) {
  const dimensions = getSessionPlannerTacticalPitchDimensionsForBlock();
  const deltaX = ((Number(to.x) || 0) - (Number(from.x) || 0)) * dimensions.x / 100;
  const deltaY = ((Number(to.y) || 0) - (Number(from.y) || 0)) * dimensions.y / 100;
  return Math.hypot(deltaX, deltaY);
}

function formatSessionPlannerTacticalMeters(value) {
  const safeValue = Math.max(Number(value) || 0, 0);
  if (safeValue < 10) {
    return `${safeValue.toFixed(1)} m`;
  }
  return `${Math.round(safeValue)} m`;
}

function getSessionPlannerTacticalCurveLengthMeters(element, coordinates) {
  const controlPoint = element.type === "curve"
    ? getSessionPlannerTacticalCurveControlPoint(element, coordinates)
    : getSessionPlannerTacticalDefaultCurveControlPoint(
        { x: coordinates.x, y: coordinates.y },
        { x: coordinates.x2, y: coordinates.y2 }
      );
  let previousPoint = { x: coordinates.x, y: coordinates.y };
  let length = 0;

  for (let index = 1; index <= 18; index += 1) {
    const t = index / 18;
    const inverseT = 1 - t;
    const point = {
      x:
        inverseT * inverseT * coordinates.x +
        2 * inverseT * t * controlPoint.x +
        t * t * coordinates.x2,
      y:
        inverseT * inverseT * coordinates.y +
        2 * inverseT * t * controlPoint.y +
        t * t * coordinates.y2,
    };
    length += getSessionPlannerTacticalPointDistanceMeters(previousPoint, point);
    previousPoint = point;
  }

  return length;
}

function getSessionPlannerTacticalFreehandLengthMeters(element) {
  if (!Array.isArray(element?.points) || element.points.length < 2) {
    return 0;
  }

  return element.points.reduce((total, point, index, points) => {
    if (index === 0) {
      return total;
    }
    return total + getSessionPlannerTacticalPointDistanceMeters(points[index - 1], point);
  }, 0);
}

function getSessionPlannerTacticalElementMeasurement(element) {
  if (!element) {
    return null;
  }

  if (element.type === "freehand") {
    const length = getSessionPlannerTacticalFreehandLengthMeters(element);
    if (!length) {
      return null;
    }
    return {
      label: formatSessionPlannerTacticalMeters(length),
      x: clamp(Number(element.x) || 50, 5, 95),
      y: clamp(Number(element.y) || 50, 5, 95),
    };
  }

  const coordinates = getSessionPlannerTacticalEndpointCoordinates(element);
  if (!coordinates) {
    return null;
  }

  if (element.type === "zone" || element.type === "dashed-zone" || element.type === "ellipse") {
    const dimensions = getSessionPlannerTacticalPitchDimensionsForBlock();
    const width = Math.abs(coordinates.x2 - coordinates.x) * dimensions.x / 100;
    const length = Math.abs(coordinates.y2 - coordinates.y) * dimensions.y / 100;
    return {
      label: `${formatSessionPlannerTacticalMeters(width)} x ${formatSessionPlannerTacticalMeters(length)}`,
      x: clamp((coordinates.x + coordinates.x2) / 2, 8, 92),
      y: clamp((coordinates.y + coordinates.y2) / 2, 8, 92),
    };
  }

  const length = element.type === "curve" || element.type === "run"
    ? getSessionPlannerTacticalCurveLengthMeters(element, coordinates)
    : getSessionPlannerTacticalPointDistanceMeters(
        { x: coordinates.x, y: coordinates.y },
        { x: coordinates.x2, y: coordinates.y2 }
      );

  if (!length) {
    return null;
  }

  return {
    label: formatSessionPlannerTacticalMeters(length),
    x: clamp((coordinates.x + coordinates.x2) / 2, 6, 94),
    y: clamp((coordinates.y + coordinates.y2) / 2, 6, 94),
  };
}

function renderSessionPlannerTacticalMeasurementLabel(element) {
  const measurement = getSessionPlannerTacticalElementMeasurement(element);
  if (!measurement) {
    return "";
  }

  return `
    <span
      class="session-tactical-measurement${element.preview ? " is-preview" : ""}"
      style="left: ${measurement.x}%; top: ${measurement.y}%;"
      aria-hidden="true"
    >${escapeHtml(measurement.label)}</span>
  `;
}

function renderSessionPlannerTacticalMeasurementLabels(elements = []) {
  return elements
    .filter(Boolean)
    .map(renderSessionPlannerTacticalMeasurementLabel)
    .join("");
}

function renderSessionPlannerTacticalSelectionHandles(element) {
  const coordinates = getSessionPlannerTacticalEndpointCoordinates(element);
  if (!coordinates) {
    return "";
  }

  const elementId = escapeHtml(element.id);
  const renderHandle = (handle, x, y) => `
    <span
      class="session-tactical-edit-handle session-tactical-edit-handle-${escapeHtml(handle)}"
      data-session-tactical-element-id="${elementId}"
      data-session-tactical-handle="${escapeHtml(handle)}"
      style="left: ${x}%; top: ${y}%;"
      aria-hidden="true"
    ></span>
  `;

  return `
    ${renderHandle("start", coordinates.x, coordinates.y)}
    ${
      element.type === "curve"
        ? renderHandle("control", coordinates.controlX, coordinates.controlY)
        : ""
    }
    ${renderHandle("end", coordinates.x2, coordinates.y2)}
  `;
}

function renderSessionPlannerTacticalRotationHandle(element) {
  if (!isSessionPlannerTacticalGoalType(element?.type)) {
    return "";
  }

  const x = Number.isFinite(Number(element.x)) ? clamp(Number(element.x), 0, 100) : 50;
  const y = Number.isFinite(Number(element.y)) ? clamp(Number(element.y), 0, 100) : 50;
  const rotation = normalizeTacticalRotation(element.rotation);
  const offset = element.type === "big-goal" ? "-3.05rem" : "-2.5rem";

  return `
    <span
      class="session-tactical-rotate-handle"
      data-session-tactical-element-id="${escapeHtml(element.id)}"
      data-session-tactical-rotate-handle
      style="left: ${x}%; top: ${y}%; --session-tactical-rotation: ${rotation}deg; --session-tactical-rotate-offset: ${offset};"
      aria-hidden="true"
    >
      <span></span>
    </span>
  `;
}

function renderSessionPlannerTacticalPendingMarkers() {
  if (!sessionPlannerTacticalPendingPoint) {
    return "";
  }

  const pendingPoint = sessionPlannerTacticalPendingPoint;
  const startPoint = pendingPoint.startPoint || pendingPoint;
  const controlPoint = pendingPoint.type === "curve" ? pendingPoint.controlPoint : null;
  const renderPendingPoint = (point, className = "") => {
    if (!point || !Number.isFinite(Number(point.x)) || !Number.isFinite(Number(point.y))) {
      return "";
    }

    return `
      <span
        class="session-tactical-marker session-tactical-pending${className ? ` ${className}` : ""}"
        style="left: ${clamp(Number(point.x), 0, 100)}%; top: ${clamp(Number(point.y), 0, 100)}%; --session-tactical-color: ${escapeHtml(sessionPlannerTacticalColor)};"
      ></span>
    `;
  };

  return `
    ${renderPendingPoint(startPoint)}
    ${renderPendingPoint(controlPoint, "session-tactical-pending-control")}
  `;
}

function renderSessionPlannerTacticalNumberPicker(elements = []) {
  if (!sessionPlannerTacticalNumberPickerElementId) {
    return "";
  }

  const element = elements.find((candidate) => candidate.id === sessionPlannerTacticalNumberPickerElementId);
  if (!isSessionPlannerTacticalPlayerType(element?.type)) {
    sessionPlannerTacticalNumberPickerElementId = "";
    return "";
  }

  const x = Number.isFinite(Number(element.x)) ? clamp(Number(element.x), 8, 92) : 50;
  const y = Number.isFinite(Number(element.y)) ? clamp(Number(element.y) - 6, 8, 92) : 50;
  return `
    <div class="session-tactical-number-picker" style="left: ${x}%; top: ${y}%;">
      <span>Player number</span>
      <div>
        ${Array.from({ length: 11 }, (_, index) => index + 1)
          .map((number) => `
            <button
              type="button"
              class="${normalizeSessionPlannerTacticalPlayerBadge(element.playerNumber) === String(number) ? "is-active" : ""}"
              data-session-tactical-number="${number}"
              data-session-tactical-number-element="${escapeHtml(element.id)}"
            >${number}</button>
          `)
          .join("")}
      </div>
    </div>
  `;
}

function renderSessionPlannerExerciseVisual(block, options = {}) {
  if (!block) {
    return "";
  }

  const elementsSource = Array.isArray(block.tacticalElements)
    ? block.tacticalElements.map(cloneSessionPlannerTacticalElement)
    : [];
  const elements = elementsSource;
  const pitchMode = normalizeSessionPlannerTacticalPitchMode(block.tacticalPitchMode);
  const pitchModeOption = getSessionPlannerTacticalPitchModeOption(pitchMode);
  const selectedElement =
    options.editor && sessionPlannerTacticalSelectedElementId
      ? elements.find((element) => element.id === sessionPlannerTacticalSelectedElementId)
      : null;
  const arrowId = getSessionPlannerVisualElementId(block);
  const freehandPreview =
    options.editor && sessionPlannerTacticalFreehandState?.points?.length > 1
      ? sessionPlannerTacticalFreehandState.points
          .map((point, index) => `${index === 0 ? "M" : "L"} ${clamp(point.x, 0, 100)} ${clamp(point.y, 0, 100)}`)
          .join(" ")
      : "";
  const draftLineElement =
    options.editor &&
    sessionPlannerTacticalDraftLineState?.startPoint &&
    sessionPlannerTacticalDraftLineState?.currentPoint
      ? {
          ...createSessionPlannerLineElement(
            sessionPlannerTacticalDraftLineState.type,
            sessionPlannerTacticalDraftLineState.startPoint,
            sessionPlannerTacticalDraftLineState.currentPoint
          ),
          id: "session-tactical-draft-line",
          preview: true,
        }
      : null;
  const classNames = [
    "session-visual-board",
    block.visualImage ? "has-uploaded-image" : "",
    options.large ? "session-visual-board-large" : "",
    options.editor ? "session-visual-board-editor" : "",
    options.printRotated ? "session-visual-board-print-rotated" : "",
    options.landscape ? "session-visual-board-print-landscape" : "",
    pitchModeOption.landscape ? "session-visual-board-landscape" : "",
    `session-visual-board-mode-${pitchMode}`,
  ].filter(Boolean).join(" ");

  return `
    <div
      class="${classNames}"
      aria-label="Exercise tactical visual"
    >
      <div class="session-visual-board-surface" ${options.editor ? 'data-session-tactical-canvas' : ""}>
        ${
          block.visualImage
            ? `<img class="session-visual-image" src="${escapeHtml(block.visualImage)}" alt="Exercise visual" />`
            : renderSessionPlannerPitchDiagram(block.diagram, { landscape: options.landscape, pitchMode })
        }
        <svg class="session-tactical-svg-layer" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden="true">
          <defs>
            <marker id="${escapeHtml(arrowId)}" markerWidth="5.2" markerHeight="5.2" refX="4.85" refY="2.6" orient="auto">
              <path d="M0.35,0.35 L4.9,2.6 L0.35,4.85 Z" fill="context-stroke"></path>
            </marker>
          </defs>
          ${elements.map((element) => renderSessionPlannerTacticalSvgElement(element, arrowId)).join("")}
          ${draftLineElement ? renderSessionPlannerTacticalSvgElement(draftLineElement, arrowId) : ""}
          ${
            freehandPreview
              ? `<path class="session-tactical-freehand session-tactical-freehand-preview" d="${escapeHtml(freehandPreview)}" stroke="${escapeHtml(sessionPlannerTacticalColor)}" stroke-width="${getSessionPlannerTacticalRenderStrokeWidth(sessionPlannerTacticalLineWidth)}"></path>`
              : ""
          }
          ${options.editor ? renderSessionPlannerTacticalSelectionBox() : ""}
        </svg>
        <div class="session-tactical-html-layer" aria-hidden="true">
          ${elements.map(renderSessionPlannerTacticalHtmlElement).join("")}
          ${options.editor ? renderSessionPlannerTacticalMeasurementLabels([selectedElement, draftLineElement]) : ""}
          ${selectedElement ? renderSessionPlannerTacticalSelectionHandles(selectedElement) : ""}
          ${selectedElement ? renderSessionPlannerTacticalRotationHandle(selectedElement) : ""}
          ${options.editor ? renderSessionPlannerTacticalPendingMarkers() : ""}
          ${options.editor ? renderSessionPlannerTacticalNumberPicker(elements) : ""}
        </div>
      </div>
    </div>
  `;
}

function renderSessionPlannerMultiSelectField(block, key, label, options = {}) {
  const value = block[key] ?? "";
  const selectedValues = normalizeSessionPlannerMultiValue(value);
  const selectedSet = new Set(selectedValues);
  const listOptions = Array.isArray(options.listOptions) ? options.listOptions.map(String) : [];
  const isOpen = sessionPlannerMultiSelectOpenField === key;
  const isAdmin = canEditSessionPlanner();

  if (!isAdmin) {
    if (!selectedValues.length) {
      return "";
    }

    return `
      <section class="session-field-readonly">
        <span>${escapeHtml(label)}</span>
        <p>${escapeHtml(selectedValues.join(", "))}</p>
      </section>
    `;
  }

  return `
    <div class="session-builder-field session-builder-multiselect-field" data-session-multiselect="${escapeHtml(key)}">
      <span>${escapeHtml(label)}</span>
      <button
        type="button"
        class="session-multiselect-trigger${selectedValues.length ? " has-value" : ""}"
        data-session-multiselect-toggle="${escapeHtml(key)}"
        aria-expanded="${isOpen ? "true" : "false"}"
      >
        <span class="session-multiselect-value-list">
          ${
            selectedValues.length
              ? selectedValues.map((item) => `<i>${escapeHtml(item)}</i>`).join("")
              : `<em>Select ${escapeHtml(label)}</em>`
          }
        </span>
        <span class="session-multiselect-caret">⌄</span>
      </button>
      ${
        isOpen
          ? `
            <div class="session-multiselect-menu">
              <button
                type="button"
                class="session-multiselect-clear"
                data-session-multiselect-clear="${escapeHtml(key)}"
              >
                Clear selection
              </button>
              ${listOptions
                .map((option) => {
                  const selected = selectedSet.has(option);
                  return `
                    <button
                      type="button"
                      class="session-multiselect-option${selected ? " is-selected" : ""}"
                      data-session-multiselect-option="${escapeHtml(key)}"
                      data-session-multiselect-value="${escapeHtml(option)}"
                    >
                      <span class="session-multiselect-check">${selected ? "✓" : ""}</span>
                      <span>${escapeHtml(option)}</span>
                    </button>
                  `;
                })
                .join("")}
            </div>
          `
          : ""
      }
    </div>
  `;
}

function renderSessionPlannerEditableField(block, key, label, options = {}) {
  const value = block[key] ?? "";
  const isAdmin = canEditSessionPlanner();
  const isLong = options.long ?? true;
  const rows = options.rows ?? 3;
  const inputType = options.type ?? "text";
  const listOptions = Array.isArray(options.listOptions) ? options.listOptions : [];
  const isMultiSelect = !isLong && sessionPlannerMultiSelectFields.has(key) && listOptions.length;

  if (isMultiSelect) {
    return renderSessionPlannerMultiSelectField(block, key, label, options);
  }

  const listId = listOptions.length ? `session-${key}-options` : "";

  if (!isAdmin) {
    if (!String(value).trim()) {
      return "";
    }

    return `
      <section class="session-field-readonly${isLong ? " session-field-long" : ""}">
        <span>${escapeHtml(label)}</span>
        <p>${escapeHtml(value).replaceAll("\n", "<br>")}</p>
      </section>
    `;
  }

  if (isLong) {
    return `
      <label class="session-builder-field session-builder-field-long">
        <span>${escapeHtml(label)}</span>
        <textarea data-session-field="${escapeHtml(key)}" rows="${rows}">${escapeHtml(value)}</textarea>
      </label>
    `;
  }

  return `
    <label class="session-builder-field">
      <span>${escapeHtml(label)}</span>
      <input
        data-session-field="${escapeHtml(key)}"
        type="${escapeHtml(inputType)}"
        value="${escapeHtml(value)}"
        ${listId ? `list="${escapeHtml(listId)}"` : ""}
      />
      ${
        listId
          ? `<datalist id="${escapeHtml(listId)}">${listOptions
              .map((option) => `<option value="${escapeHtml(String(option))}"></option>`)
              .join("")}</datalist>`
          : ""
      }
    </label>
  `;
}

function renderSessionPlannerHeaderField(block, key, fallback, options = {}) {
  const value = block[key] ?? "";
  const isAdmin = canEditSessionPlanner();
  const tag = options.tag ?? "input";
  const className = options.className ?? "";

  if (!isAdmin) {
    if (key === "title") {
      return `<h2>${escapeHtml(value || fallback)}</h2>`;
    }

    return value
      ? `<p>${escapeHtml(value).replaceAll("\n", "<br>")}</p>`
      : "";
  }

  if (tag === "textarea") {
    return `
      <textarea
        class="session-builder-header-field ${escapeHtml(className)}"
        data-session-field="${escapeHtml(key)}"
        rows="1"
        aria-label="${escapeHtml(fallback)}"
        placeholder="${escapeHtml(fallback)}"
      >${escapeHtml(value)}</textarea>
    `;
  }

  return `
    <input
      class="session-builder-header-field ${escapeHtml(className)}"
      data-session-field="${escapeHtml(key)}"
      type="text"
      value="${escapeHtml(value)}"
      aria-label="${escapeHtml(fallback)}"
      placeholder="${escapeHtml(fallback)}"
    />
  `;
}

function resizeSessionPlannerTextarea(textarea) {
  if (!textarea || textarea.tagName !== "TEXTAREA") {
    return;
  }

  textarea.style.height = "auto";
  textarea.style.height = `${textarea.scrollHeight}px`;
}

function resizeSessionPlannerTextareas() {
  ui.sessionPlannerWorkspace
    ?.querySelectorAll("textarea[data-session-field]")
    .forEach((textarea) => resizeSessionPlannerTextarea(textarea));
}

function scrollSessionPlannerDateStrip(direction) {
  const dateStrip = ui.sessionPlannerWorkspace?.querySelector(".session-date-strip");
  if (!dateStrip) {
    return;
  }

  const datePill = dateStrip.querySelector(".session-date-pill");
  const pillGap = 8;
  const pillWidth = datePill?.getBoundingClientRect().width ?? 52;
  const scrollDistance = (pillWidth + pillGap) * 7;
  const targetLeft = Math.max(0, dateStrip.scrollLeft + direction * scrollDistance);
  const prefersReducedMotion = window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;

  dateStrip.scrollTo({
    left: targetLeft,
    behavior: prefersReducedMotion ? "auto" : "smooth",
  });
}

function jumpSessionPlannerToToday() {
  selectSessionPlannerDate(formatScheduleDateValue(new Date()));
}

function renderSessionPlannerBlockList(session) {
  if (!session.blocks.length) {
    const scheduledEvent = getScheduleSessionEventForDate(session.date);
    return `
      <div class="session-block-empty">
        <strong>${scheduledEvent ? "Training is scheduled" : "No exercise blocks yet"}</strong>
        <span>${
          scheduledEvent
            ? `${escapeHtml(scheduledEvent.title)} is in Schedule. Add blocks when you are ready to build the plan.`
            : "Add a block when this date should contain a training session."
        }</span>
      </div>
    `;
  }

  const isAdmin = canEditSessionPlanner();

  return session.blocks
    .map((block, index) => {
      const isSelected = block.id === session.selectedBlockId;
      const blockTitle = block.title || block.label || "Empty block";
      const meta = [
        block.minutes ? `${block.minutes} min` : "",
      ].filter(Boolean).join(" · ");
      return `
        <article
          class="session-block-row${isSelected ? " is-active" : ""}"
          data-session-block-drop-id="${escapeHtml(block.id)}"
          draggable="${isAdmin ? "true" : "false"}"
        >
          <button
            type="button"
            class="session-block-button${isSelected ? " is-active" : ""}"
            data-session-block-id="${escapeHtml(block.id)}"
            title="${escapeHtml(blockTitle)}"
          >
            <span>${escapeHtml(block.label)}</span>
            <strong>${escapeHtml(block.title || "Empty block")}</strong>
            <small>${escapeHtml(meta || "Ready to build")}</small>
          </button>
          ${
            isAdmin
              ? `
                <div class="session-block-order-controls" aria-label="Move ${escapeHtml(blockTitle)}">
                  <button
                    type="button"
                    data-session-move-block="${escapeHtml(block.id)}"
                    data-session-move-direction="-1"
                    aria-label="Move ${escapeHtml(blockTitle)} up"
                    ${index === 0 ? "disabled" : ""}
                  >
                    ↑
                  </button>
                  <button
                    type="button"
                    data-session-move-block="${escapeHtml(block.id)}"
                    data-session-move-direction="1"
                    aria-label="Move ${escapeHtml(blockTitle)} down"
                    ${index === session.blocks.length - 1 ? "disabled" : ""}
                  >
                    ↓
                  </button>
                </div>
                <button
                  type="button"
                  class="session-block-delete-button"
                  data-session-delete-block="${escapeHtml(block.id)}"
                  aria-label="Delete ${escapeHtml(blockTitle)}"
                >
                  <svg viewBox="0 0 24 24" aria-hidden="true">
                    <path d="M9 4h6l1 2h4v2H4V6h4l1-2Z"></path>
                    <path d="M6.5 10h11l-.8 10H7.3l-.8-10Z"></path>
                    <path d="M10 12.5v5M14 12.5v5"></path>
                  </svg>
                </button>
              `
              : ""
          }
        </article>
      `;
    })
    .join("");
}

function renderSessionPlannerLibraryFilter(label, filterKey, options) {
  const selectedValues = getSessionPlannerLibraryFilterValues(filterKey);
  const selectedSet = new Set(selectedValues);
  const isOpen = sessionPlannerLibraryFilterOpen === filterKey;
  const summaryLabel = selectedValues.length ? selectedValues.join(", ") : `All ${label.toLowerCase()}s`;

  return `
    <div class="session-library-filter${isOpen ? " is-open" : ""}">
      <span>${escapeHtml(label)}</span>
      <button
        type="button"
        class="session-library-filter-trigger${selectedValues.length ? " has-value" : ""}"
        data-session-library-filter-toggle="${escapeHtml(filterKey)}"
        aria-expanded="${isOpen ? "true" : "false"}"
      >
        <span>${escapeHtml(summaryLabel)}</span>
        <small>${selectedValues.length || "All"}</small>
      </button>
      ${
        isOpen
          ? `
            <div class="session-library-filter-menu">
              <button
                type="button"
                class="session-library-filter-clear"
                data-session-library-filter-clear="${escapeHtml(filterKey)}"
              >
                Clear selection
              </button>
              ${
                options.length
                  ? options
                      .map((option) => {
                        const selected = selectedSet.has(option);
                        return `
                          <button
                            type="button"
                            class="session-library-filter-option${selected ? " is-selected" : ""}"
                            data-session-library-filter-option="${escapeHtml(filterKey)}"
                            data-session-library-filter-value="${escapeHtml(option)}"
                            aria-pressed="${selected ? "true" : "false"}"
                          >
                            <i>${selected ? "✓" : ""}</i>
                            <span>${escapeHtml(option)}</span>
                          </button>
                        `;
                      })
                      .join("")
                  : `<p class="session-library-filter-empty">No values yet</p>`
              }
            </div>
          `
          : ""
      }
    </div>
  `;
}

function formatSessionPlannerLibraryDate(value = "") {
  const timestamp = normalizeSessionPlannerTimestamp(value);
  if (!timestamp) {
    return "";
  }

  return new Intl.DateTimeFormat("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
  }).format(new Date(timestamp));
}

function formatSessionPlannerLibraryDateTime(value = "") {
  const timestamp = normalizeSessionPlannerTimestamp(value);
  if (!timestamp) {
    return "";
  }

  return new Intl.DateTimeFormat("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(timestamp));
}

function renderSessionPlannerLibraryArchiveTabs() {
  const counts = getSessionPlannerLibraryArchiveCounts();
  const tabs = [
    ["active", `Active ${counts.active}`],
    ["archived", `Archive ${counts.archived}`],
  ];

  return `
    <div class="session-library-archive-tabs" role="tablist" aria-label="Library status">
      ${tabs
        .map(([value, label]) => `
          <button
            type="button"
            class="${sessionPlannerLibraryArchiveView === value ? "is-active" : ""}"
            data-session-library-archive-view="${escapeHtml(value)}"
            role="tab"
            aria-selected="${sessionPlannerLibraryArchiveView === value ? "true" : "false"}"
          >
            ${escapeHtml(label)}
          </button>
        `)
        .join("")}
    </div>
  `;
}

function renderSessionPlannerLibrarySortControl() {
  const sortMode = normalizeSessionPlannerLibrarySortMode(sessionPlannerLibrarySortMode);
  return `
    <label class="session-library-sort">
      <span>Sort</span>
      <select data-session-library-sort aria-label="Sort exercises">
        ${sessionPlannerLibrarySortOptions
          .map((option) => `
            <option value="${escapeHtml(option.value)}"${option.value === sortMode ? " selected" : ""}>
              ${escapeHtml(option.label)}
            </option>
          `)
          .join("")}
      </select>
    </label>
  `;
}

function getSessionPlannerLibraryCountLabel(count) {
  const statusLabel = sessionPlannerLibraryArchiveView === "archived" ? "archived " : "";
  const folderName = getSessionPlannerLibraryFolderName();
  const folderLabel = sessionPlannerLibrarySelectedFolderId === "all" ? "" : ` in ${folderName}`;
  return `${count} ${statusLabel}exercise${count === 1 ? "" : "s"}${folderLabel}`;
}

function renderSessionPlannerLibraryFolderButton(folderId, label, count, options = {}) {
  const isSelected = sessionPlannerLibrarySelectedFolderId === folderId;
  return `
    <button
      type="button"
      class="session-library-folder-button${isSelected ? " is-selected" : ""}${options.drop ? " is-droppable" : ""}"
      data-session-library-folder="${escapeHtml(folderId)}"
      ${options.drop ? `data-session-library-folder-drop="${escapeHtml(folderId)}"` : ""}
      aria-pressed="${isSelected ? "true" : "false"}"
    >
      <span>${escapeHtml(label)}</span>
      <small>${count}</small>
    </button>
  `;
}

function renderSessionPlannerLibraryFolderEditForm(folder) {
  return `
    <form
      class="session-library-folder-form session-library-folder-edit-form"
      data-session-library-folder-edit-form="${escapeHtml(folder.id)}"
    >
      <input
        type="text"
        value="${escapeHtml(folder.name)}"
        maxlength="80"
        data-session-library-folder-edit-name
        aria-label="Folder name"
      />
      <select data-session-library-folder-edit-visibility aria-label="Folder visibility">
        <option value="team"${folder.visibility === "team" ? " selected" : ""}>Team</option>
        <option value="personal"${folder.visibility === "personal" ? " selected" : ""}>Personal</option>
      </select>
      <div class="session-library-folder-form-actions">
        <button type="submit">Save</button>
        <button
          type="button"
          class="session-library-folder-cancel"
          data-session-library-cancel-folder-edit
        >
          Cancel
        </button>
      </div>
    </form>
  `;
}

function renderSessionPlannerLibraryFolderCard(folder, options = {}) {
  const isAdmin = canEditSessionPlanner();
  const currentUserId = getSessionPlannerLibraryUserId();
  const isArchived = options.archived ?? isSessionPlannerLibraryFolderArchived(folder);
  const count = isArchived
    ? normalizeSessionPlannerLibraryFolderExerciseIds(folder.exerciseIds).length
    : getSessionPlannerLibraryFolderCount(folder.id);
  const ownerLabel = folder.visibility === "personal"
    ? folder.createdBy && folder.createdBy !== currentUserId
      ? "Personal"
      : "Mine"
    : "Team";
  const isSelected = !isArchived && sessionPlannerLibrarySelectedFolderId === folder.id;

  if (isAdmin && !isArchived && sessionPlannerLibraryEditingFolderId === folder.id) {
    return `
      <div
        class="session-library-folder-card is-editing${isSelected ? " is-selected" : ""}"
        data-session-library-folder-drop="${escapeHtml(folder.id)}"
      >
        ${renderSessionPlannerLibraryFolderEditForm(folder)}
      </div>
    `;
  }

  return `
    <div
      class="session-library-folder-card${isSelected ? " is-selected" : ""}${isArchived ? " is-archived" : ""}"
      ${isArchived ? "" : `data-session-library-folder-drop="${escapeHtml(folder.id)}"`}
    >
      ${
        isArchived
          ? `
            <div class="session-library-folder-card-main" aria-label="${escapeHtml(folder.name)}">
              <span>Archived ${escapeHtml(ownerLabel)}</span>
              <strong>${escapeHtml(folder.name)}</strong>
              <small>${count} saved reference${count === 1 ? "" : "s"}</small>
            </div>
          `
          : `
            <button
              type="button"
              class="session-library-folder-card-main"
              data-session-library-folder="${escapeHtml(folder.id)}"
              aria-pressed="${isSelected ? "true" : "false"}"
            >
              <span>${escapeHtml(ownerLabel)}</span>
              <strong>${escapeHtml(folder.name)}</strong>
              <small>${count} exercise${count === 1 ? "" : "s"}</small>
            </button>
          `
      }
      ${
        isAdmin
          ? `
            <div class="session-library-folder-card-actions">
              ${
                isArchived
                  ? `
                    <button
                      type="button"
                      class="session-library-folder-restore"
                      data-session-library-restore-folder="${escapeHtml(folder.id)}"
                      aria-label="Restore folder ${escapeHtml(folder.name)}"
                    >
                      Restore
                    </button>
                  `
                  : `
                    <button
                      type="button"
                      class="session-library-folder-edit"
                      data-session-library-edit-folder="${escapeHtml(folder.id)}"
                      aria-label="Rename folder ${escapeHtml(folder.name)}"
                    >
                      Rename
                    </button>
                    ${
                      folder.source !== "default"
                        ? `
                          <button
                            type="button"
                            class="session-library-folder-archive"
                            data-session-library-archive-folder="${escapeHtml(folder.id)}"
                            aria-label="Archive folder ${escapeHtml(folder.name)}"
                          >
                            Archive
                          </button>
                        `
                        : ""
                    }
                  `
              }
            </div>
          `
          : ""
      }
    </div>
  `;
}

function renderSessionPlannerLibraryArchivedFolders() {
  const archivedFolders = getSessionPlannerArchivedLibraryFolders();
  if (!canEditSessionPlanner() || !archivedFolders.length) {
    return "";
  }

  return `
    <details class="session-library-folder-archive-panel">
      <summary>
        <span>Archived folders</span>
        <small>${archivedFolders.length}</small>
      </summary>
      <div class="session-library-folder-list">
        ${archivedFolders.map((folder) => renderSessionPlannerLibraryFolderCard(folder, { archived: true })).join("")}
      </div>
    </details>
  `;
}

function renderSessionPlannerLibraryFolders() {
  const isAdmin = canEditSessionPlanner();
  const folders = getSessionPlannerVisibleLibraryFolders();

  return `
    <aside class="session-library-folder-panel">
      <div class="session-library-folder-head">
        <span>Folders</span>
        <strong>${escapeHtml(getSessionPlannerLibraryFolderName())}</strong>
      </div>
      <div class="session-library-folder-quick">
        ${renderSessionPlannerLibraryFolderButton("all", "All Exercises", getSessionPlannerLibraryFolderCount("all"))}
        ${renderSessionPlannerLibraryFolderButton("team", "Team", getSessionPlannerLibraryFolderCount("team"))}
        ${renderSessionPlannerLibraryFolderButton("mine", "Mine", getSessionPlannerLibraryFolderCount("mine"))}
      </div>
      ${
        isAdmin
          ? `
            <form class="session-library-folder-form" data-session-library-folder-form>
              <input
                type="text"
                placeholder="New folder..."
                maxlength="80"
                data-session-library-folder-name
                aria-label="New folder name"
              />
              <select data-session-library-folder-visibility aria-label="Folder visibility">
                <option value="team">Team</option>
                <option value="personal">Personal</option>
              </select>
              <button type="submit">Create</button>
            </form>
          `
          : ""
      }
      <div class="session-library-folder-list">
        ${
          folders.length
            ? folders.map((folder) => renderSessionPlannerLibraryFolderCard(folder)).join("")
            : `<p class="session-library-folder-empty">No folders yet.</p>`
        }
      </div>
      ${renderSessionPlannerLibraryArchivedFolders()}
    </aside>
  `;
}

function renderSessionPlannerLibraryTagChips(tags) {
  const normalizedTags = normalizeSessionPlannerLibraryTags(tags);
  if (!normalizedTags.length) {
    return "";
  }

  return `
    <div class="session-library-custom-tags" aria-label="Exercise tags">
      ${normalizedTags.map((tag) => `<span>#${escapeHtml(tag)}</span>`).join("")}
    </div>
  `;
}

function renderSessionPlannerLibraryFieldText(value, fallback = "Not set") {
  const cleanValue = String(value || "").trim();
  return cleanValue ? escapeHtml(cleanValue).replaceAll("\n", "<br>") : escapeHtml(fallback);
}

function renderSessionPlannerLibraryDetail(label, value) {
  return `
    <div class="session-library-preview-detail">
      <span>${escapeHtml(label)}</span>
      <p>${renderSessionPlannerLibraryFieldText(value)}</p>
    </div>
  `;
}

function renderSessionPlannerLibraryEditField(exercise, key, label, options = {}) {
  const value = key === "tags" ? formatSessionPlannerLibraryTags(exercise.tags) : exercise[key] ?? "";
  const isLong = options.long ?? true;
  const rows = options.rows ?? 3;
  const type = options.type || "text";
  const minAttribute = options.min !== undefined ? `min="${escapeHtml(options.min)}"` : "";
  const maxAttribute = options.max !== undefined ? `max="${escapeHtml(options.max)}"` : "";
  const stepAttribute = options.step !== undefined ? `step="${escapeHtml(options.step)}"` : "";

  if (isLong) {
    return `
      <label class="session-library-edit-field session-library-edit-field-long">
        <span>${escapeHtml(label)}</span>
        <textarea
          rows="${rows}"
          data-session-library-edit-field="${escapeHtml(key)}"
        >${escapeHtml(value)}</textarea>
      </label>
    `;
  }

  return `
    <label class="session-library-edit-field">
      <span>${escapeHtml(label)}</span>
      <input
        type="${escapeHtml(type)}"
        value="${escapeHtml(value)}"
        data-session-library-edit-field="${escapeHtml(key)}"
        ${minAttribute}
        ${maxAttribute}
        ${stepAttribute}
      />
    </label>
  `;
}

function renderSessionPlannerLibraryEditSection(label, fields = []) {
  return `
    <section class="session-library-edit-section">
      <span>${escapeHtml(label)}</span>
      <div class="session-library-edit-grid">
        ${fields.join("")}
      </div>
    </section>
  `;
}

function renderSessionPlannerLibraryEditPanel(exercise) {
  return `
    <div class="session-library-edit-panel">
      <div class="session-library-edit-head">
        <span>Edit exercise</span>
        <strong>${escapeHtml(exercise.title || "Untitled Exercise")}</strong>
      </div>
      ${renderSessionPlannerLibraryEditSection("Identity", [
        renderSessionPlannerLibraryEditField(exercise, "title", "Title", { long: false }),
        renderSessionPlannerLibraryEditField(exercise, "tags", "Tags", { long: false }),
        renderSessionPlannerLibraryEditField(exercise, "phase", "Phase", { long: false }),
        renderSessionPlannerLibraryEditField(exercise, "subPhase", "Sub-phase", { long: false }),
      ])}
      ${renderSessionPlannerLibraryEditSection("Load", [
        renderSessionPlannerLibraryEditField(exercise, "minutes", "Minutes", { long: false, type: "number", min: 0 }),
        renderSessionPlannerLibraryEditField(exercise, "intensity", "Intensity", { long: false, type: "number", min: 1, max: 5 }),
        renderSessionPlannerLibraryEditField(exercise, "time", "Time", { long: false }),
        renderSessionPlannerLibraryEditField(exercise, "pitchSize", "Pitch size", { long: false }),
      ])}
      ${renderSessionPlannerLibraryEditSection("Purpose", [
        renderSessionPlannerLibraryEditField(exercise, "focus", "Focus", { rows: 2 }),
        renderSessionPlannerLibraryEditField(exercise, "objective", "Objective", { rows: 3 }),
        renderSessionPlannerLibraryEditField(exercise, "why", "Why", { rows: 3 }),
      ])}
      ${renderSessionPlannerLibraryEditSection("Setup", [
        renderSessionPlannerLibraryEditField(exercise, "organization", "Organization", { rows: 3 }),
        renderSessionPlannerLibraryEditField(exercise, "material", "Measure & Material", { rows: 2 }),
      ])}
      ${renderSessionPlannerLibraryEditSection("Coaching", [
        renderSessionPlannerLibraryEditField(exercise, "principles", "Principles & Coaching Points", { rows: 4 }),
      ])}
      <div class="session-library-preview-actions">
        <button
          type="button"
          class="session-library-use-button"
          data-session-save-library-edit="${escapeHtml(exercise.id)}"
        >
          Save changes
        </button>
        <button
          type="button"
          class="session-library-secondary-button"
          data-session-save-library-edit-copy="${escapeHtml(exercise.id)}"
        >
          Save as copy
        </button>
        <button
          type="button"
          class="session-library-secondary-button"
          data-session-cancel-library-edit
        >
          Cancel
        </button>
      </div>
    </div>
  `;
}

function renderSessionPlannerLibraryEditDialog(exercise) {
  if (!exercise) {
    return "";
  }

  return `
    <div class="session-library-edit-dialog-backdrop" data-session-library-edit-dialog>
      <section class="session-library-edit-dialog" role="dialog" aria-modal="true" aria-label="Edit library exercise">
        <header class="session-library-edit-dialog-head">
          <div>
            <span>Library edit</span>
            <h3>${escapeHtml(exercise.title || "Untitled Exercise")}</h3>
          </div>
          <button type="button" class="session-library-close-button" data-session-cancel-library-edit aria-label="Close edit">Close</button>
        </header>
        ${renderSessionPlannerLibraryEditPanel(exercise)}
      </section>
    </div>
  `;
}

function canRemoveSessionPlannerLibraryExerciseFromSelectedFolder(exercise = {}) {
  const selectedFolder = getSessionPlannerLibraryFolderById(sessionPlannerLibrarySelectedFolderId);
  return Boolean(
    canEditSessionPlanner() &&
      exercise.id &&
      !isSessionPlannerLibraryExerciseArchived(exercise) &&
      selectedFolder &&
      !isSessionPlannerLibraryFolderArchived(selectedFolder) &&
      normalizeSessionPlannerLibraryFolderExerciseIds(selectedFolder.exerciseIds).includes(exercise.id)
  );
}

function renderSessionPlannerLibraryCardDetails(exercise = {}) {
  const details = [
    ["Objective", exercise.objective || exercise.focus],
    ["Why", exercise.why],
    ["Organization", exercise.organization],
    ["Measure & Material", exercise.material],
    ["Principles", exercise.principles],
    ["Pitch", exercise.pitchSize],
  ].filter(([, value]) => String(value || "").trim());

  if (!details.length) {
    return "";
  }

  return `
    <div class="session-library-preview-details session-library-card-details">
      ${details.map(([label, value]) => renderSessionPlannerLibraryDetail(label, value)).join("")}
    </div>
  `;
}

function renderSessionPlannerLibraryVersions(exercise) {
  const versions = normalizeSessionPlannerLibraryVersions(exercise?.versions);
  if (!versions.length) {
    return `<p class="session-library-preview-note">No previous versions yet.</p>`;
  }

  return `
    <div class="session-library-version-list">
      ${versions
        .slice(0, 4)
        .map((version) => {
          const versionDate = formatSessionPlannerLibraryDateTime(version.createdAt);
          return `
            <div class="session-library-version-item">
              <strong>${escapeHtml(version.reason || "Updated")}</strong>
              <span>${escapeHtml(version.title || "Untitled Exercise")}</span>
              ${versionDate ? `<small>${escapeHtml(versionDate)}</small>` : ""}
            </div>
          `;
        })
        .join("")}
    </div>
  `;
}

function renderSessionPlannerLibrary(exercises = getFilteredSessionPlannerExerciseLibrary()) {
  const isAdmin = canEditSessionPlanner();
  if (!exercises.length) {
    return `<p class="session-library-empty">No ${sessionPlannerLibraryArchiveView === "archived" ? "archived " : ""}exercises found for this filter.</p>`;
  }

  return exercises
    .map((exercise) => {
      const isArchived = isSessionPlannerLibraryExerciseArchived(exercise);
      const metaDate = isArchived
        ? formatSessionPlannerLibraryDate(exercise.archivedAt)
        : formatSessionPlannerLibraryDate(exercise.updatedAt || exercise.createdAt);
      const updatedDate = formatSessionPlannerLibraryDateTime(
        isArchived ? exercise.archivedAt : exercise.updatedAt || exercise.createdAt
      );
      const versionCount = normalizeSessionPlannerLibraryVersions(exercise.versions).length;
      const selectedFolder = getSessionPlannerLibraryFolderById(sessionPlannerLibrarySelectedFolderId);
      const canRemoveFromSelectedFolder = canRemoveSessionPlannerLibraryExerciseFromSelectedFolder(exercise);

      return `
        <article
          class="session-library-item${isArchived ? " is-archived" : ""}"
          data-session-library-drag-exercise="${escapeHtml(exercise.id)}"
          draggable="${isAdmin && !isArchived ? "true" : "false"}"
        >
          <div class="session-library-item-main">
            <div class="session-library-tags">
              <span>${escapeHtml(getSessionPlannerMultiValueSummary(exercise.phase, "No phase"))}</span>
              <span>${escapeHtml(getSessionPlannerMultiValueSummary(exercise.subPhase, "No sub-phase"))}</span>
              ${isArchived ? `<span class="session-library-archive-chip">Archived</span>` : ""}
            </div>
            ${renderSessionPlannerLibraryTagChips(exercise.tags)}
            <strong>${escapeHtml(exercise.title || "Untitled Exercise")}</strong>
            <p>${escapeHtml(exercise.focus || exercise.objective || "No description yet.")}</p>
            <small class="session-library-meta">
              ${escapeHtml(isArchived ? "Archived" : "Updated")}
              ${updatedDate ? ` ${escapeHtml(updatedDate)}` : metaDate ? ` ${escapeHtml(metaDate)}` : ""}
              · ${versionCount} version${versionCount === 1 ? "" : "s"}
            </small>
            ${renderSessionPlannerLibraryCardDetails(exercise)}
          </div>
          ${
            isAdmin
              ? `
                <div class="session-library-actions">
                  ${
                    isArchived
                      ? `
                        <button
                          type="button"
                          class="session-library-restore-button"
                          data-session-restore-library-exercise="${escapeHtml(exercise.id)}"
                          aria-label="Restore ${escapeHtml(exercise.title || "exercise")}"
                        >
                          Restore
                        </button>
                      `
                      : `
                        <button type="button" class="session-library-use-button" data-session-use-exercise="${escapeHtml(
                          exercise.id
                        )}">Use</button>
                        <button
                          type="button"
                          class="session-library-secondary-button"
                          data-session-duplicate-library-exercise="${escapeHtml(exercise.id)}"
                          aria-label="Duplicate ${escapeHtml(exercise.title || "exercise")}"
                        >
                          Duplicate
                        </button>
                        <button
                          type="button"
                          class="session-library-secondary-button"
                          data-session-edit-library-exercise="${escapeHtml(exercise.id)}"
                          aria-label="Edit ${escapeHtml(exercise.title || "exercise")}"
                        >
                          Edit
                        </button>
                        ${
                          canRemoveFromSelectedFolder
                            ? `
                              <button
                                type="button"
                                class="session-library-secondary-button"
                                data-session-remove-library-exercise-from-folder="${escapeHtml(exercise.id)}"
                                data-session-remove-library-folder="${escapeHtml(selectedFolder.id)}"
                              >
                                Remove from folder
                              </button>
                            `
                            : ""
                        }
                        <button
                          type="button"
                          class="session-library-delete-button"
                          data-session-delete-library-exercise="${escapeHtml(exercise.id)}"
                          aria-label="Archive ${escapeHtml(exercise.title || "exercise")}"
                        >
                          Archive
                        </button>
                      `
                  }
                </div>
              `
              : ""
          }
        </article>
      `;
    })
    .join("");
}

function renderSessionPlannerLibraryOverlay() {
  if (!sessionPlannerLibraryOpen) {
    return "";
  }

  const filteredExercises = getFilteredSessionPlannerExerciseLibrary();
  const editExercise = getSessionPlannerLibraryEditExercise();
  const phaseOptions = getSessionPlannerLibraryOptionValues("phase");
  const subPhaseOptions = getSessionPlannerLibraryOptionValues("subPhase");

  return `
    <div class="session-library-overlay" data-session-library-overlay>
      <section class="session-library-modal" role="dialog" aria-modal="true" aria-label="Exercise Library">
        <header class="session-library-modal-head">
          <div>
            <span>Library</span>
            <h2>Exercise Library</h2>
          </div>
          <button type="button" class="session-library-close-button" data-session-close-library aria-label="Close library">Close</button>
        </header>
        <div class="session-library-controls">
          <label class="session-library-search">
            <span>Search</span>
            <input
              type="search"
              value="${escapeHtml(sessionPlannerLibrarySearchQuery)}"
              placeholder="Find exercise..."
              data-session-library-search
            />
          </label>
          <div class="session-library-filter-row">
            ${renderSessionPlannerLibraryArchiveTabs()}
            ${renderSessionPlannerLibraryFilter("Phase", "phase", phaseOptions)}
            ${renderSessionPlannerLibraryFilter("Sub-phase", "subPhase", subPhaseOptions)}
            ${renderSessionPlannerLibrarySortControl()}
          </div>
          <span class="session-library-count">
            ${getSessionPlannerLibraryCountLabel(filteredExercises.length)}
          </span>
        </div>
        <div class="session-library-modal-body">
          ${renderSessionPlannerLibraryFolders()}
          <div class="session-library-modal-grid">
            ${renderSessionPlannerLibrary(filteredExercises)}
          </div>
        </div>
        ${renderSessionPlannerLibraryEditDialog(editExercise)}
      </section>
    </div>
  `;
}

function renderSessionPlannerLibrarySaveConflictOverlay() {
  if (!sessionPlannerPendingLibrarySave) {
    return "";
  }

  const title = sessionPlannerPendingLibrarySave.existingTitle || "Untitled Exercise";

  return `
    <div class="session-library-overlay session-save-conflict-overlay" data-session-save-conflict-overlay>
      <section class="session-library-modal session-save-conflict-modal" role="dialog" aria-modal="true" aria-label="Exercise already exists">
        <header class="session-library-modal-head">
          <div>
            <span>Library</span>
            <h2>This name already exists</h2>
          </div>
          <button
            type="button"
            class="session-library-close-button"
            data-session-save-conflict-action="cancel"
            aria-label="Cancel"
          >
            Cancel
          </button>
        </header>
        <div class="session-save-conflict-copy">
          <strong>${escapeHtml(title)}</strong>
          <p>Do you want to replace the saved exercise with your latest changes, or save this as a copy?</p>
        </div>
        <div class="session-save-conflict-actions">
          <button type="button" class="session-save-conflict-secondary" data-session-save-conflict-action="duplicate">
            Duplicate
          </button>
          <button type="button" class="session-save-conflict-primary" data-session-save-conflict-action="replace">
            Replace
          </button>
        </div>
      </section>
    </div>
  `;
}

function renderSessionPlannerActionIcon(name) {
  const icons = {
    eye: `
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d="M2.8 12S6.2 5.8 12 5.8 21.2 12 21.2 12 17.8 18.2 12 18.2 2.8 12 2.8 12Z"></path>
        <circle cx="12" cy="12" r="3.1"></circle>
      </svg>
    `,
    pencil: `
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d="M4.5 19.5l4.1-.9 10-10a2.2 2.2 0 0 0-3.1-3.1l-10 10-.9 4Z"></path>
        <path d="M13.8 7.2l3 3"></path>
      </svg>
    `,
    upload: `
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d="M12 15V4"></path>
        <path d="M7.5 8.5 12 4l4.5 4.5"></path>
        <path d="M5 15v4.5h14V15"></path>
      </svg>
    `,
  };

  return icons[name] ?? "";
}

function renderSessionPlannerVisualPreviewOverlay(block) {
  if (!sessionPlannerVisualPreviewOpen || !block) {
    return "";
  }

  return `
    <div class="session-library-overlay session-visual-preview-overlay" data-session-visual-preview-overlay>
      <section class="session-library-modal session-visual-modal" role="dialog" aria-modal="true" aria-label="Exercise visual preview">
        <header class="session-library-modal-head">
          <div>
            <span>Preview</span>
            <h2>${escapeHtml(block.title || "Exercise Visual")}</h2>
          </div>
          <button type="button" class="session-library-close-button" data-session-close-visual-preview aria-label="Close preview">Close</button>
        </header>
        ${renderSessionPlannerExerciseVisual(block, { large: true })}
      </section>
    </div>
  `;
}

