function renderSessionPlannerTacticalboardOverlay(block) {
  if (!sessionPlannerTacticalboardOpen || !block) {
    return "";
  }

  const toolGroups = [
    {
      label: "Players",
      tools: [
        ["blue-player", "Blue"],
        ["red-player", "Red"],
        ["neutral-player", "Neutral"],
        ["ball", "Ball"],
        ["coach", "Coach"],
      ],
    },
    {
      label: "Equipment",
      tools: [
        ["cone", "Cone"],
        ["mini-goal", "Goal"],
        ["big-goal", "11v11 Goal"],
        ["mannequin", "Dummy"],
        ["pole", "Pole"],
        ["gate", "Gate"],
        ["dashed-line", "Dashed Line"],
        ["zone", "Zone"],
        ["dashed-zone", "Dashed Box"],
        ["ellipse", "Circle"],
      ],
    },
    {
      label: "Draw",
      tools: [
        ["arrow", "Arrow"],
        ["pass", "Pass"],
        ["run", "Run"],
        ["line", "Line"],
        ["curve", "Curve"],
        ["freehand", "Free"],
        ["text", "Text"],
        ["remove", "Erase"],
      ],
    },
  ];
  const lineStyleOptions = ["solid", "dashed", "dotted"]
    .map((lineStyle) => `
      <option value="${lineStyle}"${sessionPlannerTacticalLineStyle === lineStyle ? " selected" : ""}>
        ${lineStyle.charAt(0).toUpperCase() + lineStyle.slice(1)}
      </option>
    `)
    .join("");
  const tacticalPitchMode = normalizeSessionPlannerTacticalPitchMode(block.tacticalPitchMode);
  const pitchModeOptions = sessionPlannerTacticalPitchModeOptions
    .map((option) => `
      <option value="${escapeHtml(option.key)}"${tacticalPitchMode === option.key ? " selected" : ""}>
        ${escapeHtml(option.label)}
      </option>
    `)
    .join("");
  const pitchDimensions = getSessionPlannerTacticalPitchDimensionsForBlock(block);
  const pitchMeasurementLabel = `${pitchDimensions.x} x ${pitchDimensions.y} m`;

  return `
    <div class="session-library-overlay session-tacticalboard-overlay" data-session-tacticalboard-overlay>
      <section class="session-library-modal session-tacticalboard-modal" role="dialog" aria-modal="true" aria-label="Tacticalboard">
        <header class="session-library-modal-head">
          <div>
            <span>Tacticalboard</span>
            <h2>${escapeHtml(block.title || "Exercise Board")}</h2>
          </div>
          <button type="button" class="session-library-close-button" data-session-close-tacticalboard aria-label="Close tacticalboard">Close</button>
        </header>
        <div class="session-tacticalboard-layout">
          <aside class="session-tacticalboard-side session-tacticalboard-toolbox">
            <div class="session-tacticalboard-tools" aria-label="Tacticalboard tools">
              ${toolGroups
                .map((group) => `
                  <div class="session-tacticalboard-tool-group">
                    <span>${escapeHtml(group.label)}</span>
                    <div class="session-tacticalboard-tool-row">
                      ${group.tools
                        .map(([tool, label]) => `
                          <button
                            type="button"
                            class="session-tactical-tool-button${sessionPlannerTacticalTool === tool ? " is-active" : ""}"
                            data-session-tactical-tool="${escapeHtml(tool)}"
                            title="${escapeHtml(label)}"
                            aria-label="${escapeHtml(label)}"
                          >
                            <span class="session-tactical-tool-icon" aria-hidden="true">${renderSessionPlannerTacticalToolIcon(tool)}</span>
                            <span>${escapeHtml(label)}</span>
                          </button>
                        `)
                        .join("")}
                    </div>
                  </div>
                `)
                .join("")}
            </div>
          </aside>
          <div class="session-tacticalboard-canvas-wrap" data-session-tactical-canvas-wrap>
            ${renderSessionPlannerExerciseVisual(block, { large: true, editor: true })}
          </div>
          <aside class="session-tacticalboard-side session-tacticalboard-inspector">
            <div class="session-tacticalboard-settings" aria-label="Drawing settings">
              <label>
                <span>Pitch view</span>
                <select data-session-tactical-pitch-mode>${pitchModeOptions}</select>
              </label>
              <label>
                <span>Colour</span>
                <input type="color" value="${escapeHtml(sessionPlannerTacticalColor)}" data-session-tactical-color />
              </label>
              <label>
                <span>Width</span>
                <input type="range" min="0.25" max="6" step="0.25" value="${sessionPlannerTacticalLineWidth}" data-session-tactical-width />
              </label>
              <label>
                <span>Style</span>
                <select data-session-tactical-style>${lineStyleOptions}</select>
              </label>
            </div>
            <div class="session-tacticalboard-hint">
              <strong>Sharp board mode</strong>
              <span>Measurements use this view: ${escapeHtml(pitchMeasurementLabel)}. Cmd/Ctrl+C copies, Cmd/Ctrl+V pastes, Delete removes.</span>
            </div>
            <label class="session-media-upload-button session-tacticalboard-upload">
              ${renderSessionPlannerActionIcon("upload")}
              <span>Upload image</span>
              <input class="session-upload-input" type="file" accept="image/*" data-session-upload-visual />
            </label>
            <div class="session-tacticalboard-actions">
              <button type="button" class="session-tacticalboard-copy-selected" data-session-copy-tactical-selected>Copy selected</button>
              <button type="button" class="session-tacticalboard-paste" data-session-paste-tactical-clipboard>Paste</button>
              <button type="button" class="session-tacticalboard-delete-selected" data-session-delete-tactical-selected>Delete selected</button>
              <button type="button" class="session-tacticalboard-undo" data-session-undo-board>Undo last</button>
              <button type="button" class="session-tacticalboard-clear" data-session-clear-board title="Delete all drawings">Delete all</button>
            </div>
          </aside>
        </div>
      </section>
    </div>
  `;
}

function getSessionPlannerBlockNumber(block = getSessionPlannerSelectedBlock()) {
  const session = getSessionPlannerSelectedSession();
  const index = session?.blocks?.findIndex((candidate) => candidate.id === block?.id) ?? -1;
  return index >= 0 ? index + 1 : 1;
}

function getSessionPlannerPlayerBoardRule(block = getSessionPlannerSelectedBlock()) {
  const blockNumber = getSessionPlannerBlockNumber(block);
  if (blockNumber <= 1) {
    return { blockNumber, label: "Block 1", valueLabel: "10%+", min: 10 };
  }
  if (blockNumber === 2) {
    return { blockNumber, label: "Block 2", valueLabel: "25%+", min: 25 };
  }
  if (blockNumber === 3) {
    return { blockNumber, label: "Block 3", valueLabel: "50%+", min: 50 };
  }
  return { blockNumber, label: `Block ${blockNumber}`, valueLabel: "75%+", min: 75 };
}

const sessionPlannerPlayerBoardPositionGroups = [
  { key: "goalkeeper", label: "Goalkeepers", shortLabel: "GK", order: 1, x: 12 },
  { key: "defender", label: "Defenders", shortLabel: "DEF", order: 2, x: 35 },
  { key: "midfielder", label: "Midfielders", shortLabel: "MID", order: 3, x: 58 },
  { key: "forward", label: "Forwards", shortLabel: "FWD", order: 4, x: 82 },
];

function getSessionPlannerPlayerBoardPositionGroup(player = {}) {
  const explicitRoleGroup = String(player?.roleGroup ?? "").trim().toLowerCase();
  const explicitGroup = sessionPlannerPlayerBoardPositionGroups.find((group) => group.key === explicitRoleGroup);
  if (explicitGroup) {
    return explicitGroup;
  }

  const roleText = [
    player?.position,
    player?.primaryRole,
    player?.role,
    ...(Array.isArray(player?.secondaryRoles) ? player.secondaryRoles : []),
  ].join(" ");
  const position = String(roleText).toLowerCase();
  const normalizedPosition = position.replace(/[^a-z0-9åäö]/gi, " ");
  const positionParts = normalizedPosition.split(/\s+/).filter(Boolean);
  const hasPositionPart = (...parts) => parts.some((part) => positionParts.includes(part));
  if (
    position.includes("goal") ||
    position.includes("keeper") ||
    hasPositionPart("gk", "målvakt", "malvakt")
  ) {
    return sessionPlannerPlayerBoardPositionGroups[0];
  }
  if (
    position.includes("def") ||
    position.includes("back") ||
    hasPositionPart("lb", "cb", "rb", "lcb", "rcb", "wb")
  ) {
    return sessionPlannerPlayerBoardPositionGroups[1];
  }
  if (
    position.includes("forward") ||
    position.includes("striker") ||
    position.includes("winger") ||
    position.includes("attack") ||
    position.includes("anfall") ||
    hasPositionPart("st", "cf", "fw", "w", "lw", "rw", "9")
  ) {
    return sessionPlannerPlayerBoardPositionGroups[3];
  }
  return sessionPlannerPlayerBoardPositionGroups[2];
}

function normalizeSessionPlannerPlayerBoardProfileKey(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9åäö]/g, "");
}

function getSessionPlannerPlayerBoardProfileState() {
  try {
    return ensurePlayerProfilesState();
  } catch {
    return playerProfilesState;
  }
}

function getSessionPlannerPlayerBoardProfileForPlayer(player = {}) {
  const profileState = getSessionPlannerPlayerBoardProfileState();
  const profiles = Array.isArray(profileState?.players) ? profileState.players : [];
  if (!profiles.length) {
    return null;
  }

  const playerIds = [player.id, player.playerId, player.profileId, player.medicalPlayerId]
    .map((value) => String(value ?? "").trim())
    .filter(Boolean);
  const idMatch = profiles.find((profile) =>
    [profile.id, profile.playerId, profile.medicalPlayerId, profile.sourceId]
      .map((value) => String(value ?? "").trim())
      .filter(Boolean)
      .some((value) => playerIds.includes(value))
  );
  if (idMatch) {
    return idMatch;
  }

  const nameKey = normalizeSessionPlannerPlayerBoardProfileKey(player.name);
  if (nameKey) {
    const nameMatch = profiles.find((profile) => normalizeSessionPlannerPlayerBoardProfileKey(profile.name) === nameKey);
    if (nameMatch) {
      return nameMatch;
    }
  }

  const numberKey = String(player.number ?? "").trim();
  if (numberKey) {
    const numberMatches = profiles.filter((profile) => String(profile.number ?? "").trim() === numberKey);
    if (numberMatches.length === 1) {
      return numberMatches[0];
    }
  }

  return null;
}

function getSessionPlannerPlayerBoardSquadStatusPriority(statusKey) {
  const priorityByStatus = {
    important: 100,
    rotation: 74,
    depth: 48,
    development: 32,
    loan: 12,
  };
  return priorityByStatus[String(statusKey ?? "").trim()] ?? null;
}

function getSessionPlannerPlayerBoardProfileRoleFitMap(profile = {}) {
  if (!profile) {
    return {};
  }

  if (profile.roleFit && typeof profile.roleFit === "object" && !Array.isArray(profile.roleFit)) {
    return profile.roleFit;
  }

  try {
    return Object.fromEntries(playerProfileRoleOptions.map((role) => [role, getPlayerProfileRoleFitScore(profile, role)]));
  } catch {
    return {};
  }
}

function getSessionPlannerPlayerBoardFutureMinutesValue(source) {
  if (!source) {
    return null;
  }
  if (typeof source === "number") {
    return Number.isFinite(source) ? source : null;
  }
  if (Array.isArray(source)) {
    const total = source.reduce((sum, item) => {
      const value =
        getSessionPlannerPlayerBoardNumericPriorityValue(item?.minutes) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item?.played) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item?.value) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item?.total) ??
        0;
      return sum + value;
    }, 0);
    return total > 0 ? total : null;
  }
  if (typeof source === "object") {
    const directValue =
      getSessionPlannerPlayerBoardNumericPriorityValue(source.minutes) ??
      getSessionPlannerPlayerBoardNumericPriorityValue(source.played) ??
      getSessionPlannerPlayerBoardNumericPriorityValue(source.value) ??
      getSessionPlannerPlayerBoardNumericPriorityValue(source.total);
    if (directValue !== null) {
      return directValue;
    }
  }
  return null;
}

function getSessionPlannerPlayerBoardSyncedPlayer(player = {}) {
  const profile = getSessionPlannerPlayerBoardProfileForPlayer(player);
  if (!profile) {
    return player;
  }

  const roleFit = getSessionPlannerPlayerBoardProfileRoleFitMap(profile);
  const futureMinutes = getSessionPlannerPlayerBoardFutureMinutesValue(profile.futureData?.minutes);
  const squadStatusPriority = getSessionPlannerPlayerBoardSquadStatusPriority(profile.squadStatus);

  return {
    ...player,
    number: profile.number || player.number,
    name: profile.name || player.name,
    position: profile.position || player.position,
    photoUrl: profile.photoUrl || player.photoUrl,
    sourceUrl: profile.sourceUrl || player.sourceUrl,
    rosterOrder: Number.isFinite(Number(profile.rosterOrder)) ? Number(profile.rosterOrder) : player.rosterOrder,
    profileId: profile.id,
    medicalPlayerId: player.id,
    squadStatus: profile.squadStatus,
    careerPhase: profile.careerPhase,
    primaryRole: profile.primaryRole,
    secondaryRoles: Array.isArray(profile.secondaryRoles) ? [...profile.secondaryRoles] : [],
    preferredSide: profile.preferredSide,
    roleGroup: profile.roleGroup,
    attributeRatings: profile.attributeRatings,
    idp: profile.idp,
    futureData: profile.futureData,
    coachNotes: profile.coachNotes,
    roleFit,
    rolePriority: roleFit,
    positionPriority: roleFit,
    squadImportance: squadStatusPriority,
    seasonMinutes: futureMinutes ?? player.seasonMinutes,
  };
}

function getSessionPlannerPlayerBoardBridgeContract(player = {}) {
  const profile = getSessionPlannerPlayerBoardProfileForPlayer(player);
  if (!profile) {
    return null;
  }

  return createSessionPlannerPlayerProfileContract(profile, sessionPlannerState?.selectedDate);
}

function getSessionPlannerPlayerBoardBridgeRoleLabel(player = {}) {
  const primaryRole = normalizePlayerProfileRole(player.primaryRole, "");
  if (primaryRole) {
    return primaryRole;
  }

  const roleFit = player.roleFit && typeof player.roleFit === "object" && !Array.isArray(player.roleFit)
    ? player.roleFit
    : {};
  const bestRole = Object.entries(roleFit)
    .filter(([role, score]) => playerProfileRoleOptions.includes(role) && Number.isFinite(Number(score)))
    .sort((first, second) => Number(second[1]) - Number(first[1]))[0]?.[0];

  return bestRole || "";
}

function getSessionPlannerPlayerBoardBridgeBestMatches(player = {}, limit = 3) {
  const roleFit = player.roleFit && typeof player.roleFit === "object" && !Array.isArray(player.roleFit)
    ? player.roleFit
    : {};

  return Object.entries(roleFit)
    .filter(([role, score]) => playerProfileRoleOptions.includes(role) && Number.isFinite(Number(score)))
    .sort((first, second) => Number(second[1]) - Number(first[1]))
    .slice(0, limit)
    .map(([role, score]) => ({
      role,
      score: Math.round(Number(score)),
      definition: getPlayerRoleDnaDefinition(role),
    }));
}

function getSessionPlannerPlayerBoardBridgeSummary(boardPlayers = []) {
  const linkedItems = boardPlayers.filter((item) => item.player?.profileId);
  const roleDnaItems = linkedItems.filter((item) => Object.keys(item.player?.roleFit || {}).length > 0);
  const roleCounts = linkedItems.reduce((counts, item) => {
    const role = getSessionPlannerPlayerBoardBridgeRoleLabel(item.player) || "Unset";
    counts[role] = (counts[role] || 0) + 1;
    return counts;
  }, {});
  const roleSummary = Object.entries(roleCounts)
    .sort((first, second) => second[1] - first[1] || first[0].localeCompare(second[0]))
    .slice(0, 4)
    .map(([role, count]) => `${role} ${count}`)
    .join(" / ");

  return {
    linkedCount: linkedItems.length,
    roleDnaCount: roleDnaItems.length,
    totalCount: boardPlayers.length,
    roleSummary,
    linkedItems,
  };
}

function renderSessionPlannerSquadBridgeStrip(boardPlayers = []) {
  const summary = getSessionPlannerPlayerBoardBridgeSummary(boardPlayers);
  if (!summary.totalCount) {
    return "";
  }

  return `
    <div class="session-squad-bridge-strip">
      <span>Squad Bridge</span>
      <strong>${summary.linkedCount}/${summary.totalCount} linked</strong>
      <small>${escapeHtml(summary.roleSummary || "No Squad role data yet")}</small>
    </div>
  `;
}

function renderSessionPlannerSquadBridgePanel(boardPlayers = []) {
  const summary = getSessionPlannerPlayerBoardBridgeSummary(boardPlayers);
  const topMatches = summary.linkedItems
    .map((item) => ({
      item,
      matches: getSessionPlannerPlayerBoardBridgeBestMatches(item.player, 2),
    }))
    .filter((entry) => entry.matches.length)
    .slice(0, 6);

  return `
    <section class="session-squad-bridge-panel" aria-label="Squad Bridge">
      <header>
        <div>
          <span>Squad Bridge</span>
          <strong>Read-only Player Profiles</strong>
        </div>
        <small>${summary.linkedCount}/${summary.totalCount} linked from Squad</small>
      </header>
      <div class="session-squad-bridge-metrics">
        <span><strong>${summary.linkedCount}</strong><small>Linked</small></span>
        <span><strong>${summary.roleDnaCount}</strong><small>Role DNA</small></span>
        <span><strong>${summary.totalCount - summary.linkedCount}</strong><small>Fallback</small></span>
      </div>
      <div class="session-squad-bridge-role-list">
        ${
          topMatches.length
            ? topMatches
                .map(({ item, matches }) => `
                  <button type="button" data-session-squad-bridge-player="${escapeHtml(item.player.id)}">
                    <strong>${escapeHtml(item.player.name)}</strong>
                    <span>${matches.map((match) => `${match.role} ${match.score}%`).join(" / ")}</span>
                  </button>
                `)
                .join("")
            : `<span class="session-squad-bridge-empty">Squad profiles will appear here when players are linked.</span>`
        }
      </div>
    </section>
  `;
}

function renderSessionPlannerPlayerBoardSquadProfile(contract) {
  if (!contract) {
    return `
      <div class="session-player-board-profile-squad is-empty">
        <span>Squad Bridge</span>
        <p>No linked Squad profile yet. Session Planner is using the existing medical/player fallback.</p>
      </div>
    `;
  }

  const bestMatches = Object.entries(contract.roleFit || {})
    .filter(([role, score]) => playerProfileRoleOptions.includes(role) && Number.isFinite(Number(score)))
    .sort((first, second) => Number(second[1]) - Number(first[1]))
    .slice(0, 4);
  const secondaryRoles = Array.isArray(contract.secondaryRoles) ? contract.secondaryRoles : [];

  return `
    <div class="session-player-board-profile-squad">
      <span>Squad Bridge</span>
      <div class="session-player-board-squad-roles">
        <strong>${escapeHtml(contract.primaryRole || "No primary role")}</strong>
        <small>${escapeHtml(secondaryRoles.length ? secondaryRoles.join(" / ") : "No secondary roles")}</small>
      </div>
      <div class="session-player-board-squad-fit">
        ${bestMatches
          .map(([role, score]) => `
            <span>
              <strong>${escapeHtml(role)}</strong>
              <small>${Math.round(Number(score))}%</small>
            </span>
          `)
          .join("")}
      </div>
      <p>${escapeHtml(contract.idp?.primaryFocus || "No IDP focus set for this player.")}</p>
    </div>
  `;
}

function getSessionPlannerSelectionAssistantBlockText(block = getSessionPlannerSelectedBlock()) {
  return [
    block?.label,
    block?.title,
    block?.focus,
    block?.phase,
    block?.subPhase,
    block?.objective,
    block?.why,
    block?.organization,
    block?.principles,
    block?.intensity,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
}

function getSessionPlannerSelectionAssistantProfile(block = getSessionPlannerSelectedBlock()) {
  const text = getSessionPlannerSelectionAssistantBlockText(block);
  const includesAny = (...patterns) => patterns.some((pattern) => pattern.test(text));

  if (includesAny(/final|finish|shoot|shot|score|chance|box|cross|cutback|attack|attacking|avslut|anfall|mål|mal/)) {
    return {
      key: "final-third",
      label: "Final third",
      detail: "Prioritises creators, wide attackers and finishers.",
      roles: ["LW", "RW", "ST", "10", "8"],
    };
  }
  if (includesAny(/defen|press|block|out of possession|compact|mark|duel|protect|försvar|forsvar|pressing/)) {
    return {
      key: "defensive",
      label: "Defensive block",
      detail: "Prioritises back line, screening and availability security.",
      roles: ["GK", "CB", "LB", "RB", "6", "8"],
    };
  }
  if (includesAny(/transition|counter|recover|regain|omställ|omstall|counterpress/)) {
    return {
      key: "transition",
      label: "Transition",
      detail: "Prioritises runners, central connectors and front-line threat.",
      roles: ["6", "8", "10", "LW", "RW", "ST"],
    };
  }
  if (includesAny(/possession|build|rondo|passing|pass|circulation|switch|tempo|retain|uppspel|bollinnehav|speluppbygg/)) {
    return {
      key: "possession",
      label: "Possession",
      detail: "Prioritises centre-backs, pivots, connectors and creators.",
      roles: ["CB", "6", "8", "10", "LB", "RB"],
    };
  }
  if (includesAny(/speed|sprint|physical|conditioning|load|running|fitness|fys|löp|lop/)) {
    return {
      key: "physical",
      label: "Physical / load",
      detail: "Prioritises wide runners, box-to-box profiles and robust availability.",
      roles: ["LWB", "RWB", "LB", "RB", "8", "LW", "RW", "ST"],
    };
  }

  return {
    key: "balanced",
    label: "Balanced exercise",
    detail: "Builds a balanced group across lines with Squad role context.",
    roles: ["GK", "CB", "LB", "RB", "6", "8", "10", "LW", "RW", "ST"],
  };
}

function getSessionPlannerSelectionAssistantTargetCount(boardPlayers = []) {
  const formationCount = parseSessionPlannerPlayerBoardFormation(sessionPlannerPlayerBoardFormationInput)
    .reduce((total, lineCount) => total + lineCount, 0);
  if (formationCount > 0) {
    return Math.min(formationCount, boardPlayers.length);
  }

  return Math.min(boardPlayers.length, boardPlayers.length >= 12 ? 10 : boardPlayers.length);
}

function getSessionPlannerSelectionAssistantRoleScore(player = {}, targetRoles = []) {
  const roleFit = player.roleFit && typeof player.roleFit === "object" && !Array.isArray(player.roleFit)
    ? player.roleFit
    : {};
  const directScore = targetRoles.reduce((best, role) => {
    const value = Number(roleFit[role]);
    return Number.isFinite(value) ? Math.max(best, value) : best;
  }, 0);
  if (directScore > 0) {
    return directScore;
  }

  const primaryRole = normalizePlayerProfileRole(player.primaryRole, "");
  if (targetRoles.includes(primaryRole)) {
    return 78;
  }
  const secondaryRoles = Array.isArray(player.secondaryRoles)
    ? player.secondaryRoles.map((role) => normalizePlayerProfileRole(role, "")).filter(Boolean)
    : [];
  if (secondaryRoles.some((role) => targetRoles.includes(role))) {
    return 68;
  }
  const targetGroups = new Set(targetRoles.map((role) => getPlayerProfileRoleGroupForRole(role)));
  if (targetGroups.has(player.roleGroup)) {
    return 58;
  }

  return 48;
}

function getSessionPlannerSelectionAssistantReason(item, profile, roleScore) {
  const player = item?.player ?? {};
  const bestMatches = getSessionPlannerPlayerBoardBridgeBestMatches(player, 2);
  const primaryRole = normalizePlayerProfileRole(player.primaryRole, "");
  const secondaryRoles = Array.isArray(player.secondaryRoles) ? player.secondaryRoles : [];
  const reasons = [];

  if (bestMatches.length) {
    reasons.push(`Role DNA ${bestMatches[0].role} ${bestMatches[0].score}%`);
  } else if (primaryRole) {
    reasons.push(`Primary ${primaryRole}`);
  } else {
    reasons.push("Medical fallback profile");
  }
  if (profile.roles.includes(primaryRole)) {
    reasons.push(`Natural ${primaryRole}`);
  } else if (secondaryRoles.some((role) => profile.roles.includes(role))) {
    reasons.push("Secondary role fit");
  }
  if (item?.participation !== null && item?.participation !== undefined) {
    reasons.push(`${item.participation}% available`);
  }
  if (player.idp?.primaryFocus) {
    reasons.push(`IDP: ${player.idp.primaryFocus}`);
  }
  if (roleScore < 60) {
    reasons.push("Fallback selection");
  }

  return reasons.slice(0, 3).join(" / ");
}

function scoreSessionPlannerSelectionAssistantItem(item, profile) {
  const player = item?.player ?? {};
  const roleScore = getSessionPlannerSelectionAssistantRoleScore(player, profile.roles);
  const availabilityScore = Number.isFinite(Number(item?.participation)) ? Number(item.participation) : 0;
  const squadImportance = Number.isFinite(Number(player.squadImportance)) ? Number(player.squadImportance) : 45;
  const primaryRole = normalizePlayerProfileRole(player.primaryRole, "");
  const secondaryRoles = Array.isArray(player.secondaryRoles) ? player.secondaryRoles : [];
  const roleBonus =
    profile.roles.includes(primaryRole)
      ? 8
      : secondaryRoles.some((role) => profile.roles.includes(role))
        ? 5
        : 0;
  const linkedBonus = player.profileId ? 4 : 0;
  const score = Math.round(roleScore * 0.48 + availabilityScore * 0.34 + squadImportance * 0.08 + roleBonus + linkedBonus);

  return {
    item,
    score: clamp(score, 0, 100),
    roleScore: Math.round(roleScore),
    availabilityScore,
    reason: getSessionPlannerSelectionAssistantReason(item, profile, roleScore),
  };
}

function buildSessionPlannerSelectionAssistant(block, boardPlayers = getSessionPlannerPlayerBoardPlayers(block)) {
  const profile = getSessionPlannerSelectionAssistantProfile(block);
  const targetCount = getSessionPlannerSelectionAssistantTargetCount(boardPlayers);
  const ranked = boardPlayers
    .map((item) => scoreSessionPlannerSelectionAssistantItem(item, profile))
    .sort((first, second) =>
      second.score - first.score ||
      second.roleScore - first.roleScore ||
      compareMedicalPlayers(first.item.player, second.item.player)
    );
  const suggestions = ranked.slice(0, targetCount);
  const selectedRoleCoverage = profile.roles.map((role) => {
    const best = suggestions.reduce((bestScore, suggestion) => {
      const value = Number(suggestion.item.player?.roleFit?.[role]);
      return Number.isFinite(value) ? Math.max(bestScore, value) : bestScore;
    }, 0);
    return { role, covered: best >= 66, score: Math.round(best) };
  });

  return {
    profile,
    targetCount,
    ranked,
    suggestions,
    selectedRoleCoverage,
    missingRoles: selectedRoleCoverage.filter((entry) => !entry.covered),
  };
}

function renderSessionPlannerSelectionAssistantPanel(block, boardPlayers = [], options = {}) {
  const assistant = buildSessionPlannerSelectionAssistant(block, boardPlayers);
  if (!boardPlayers.length) {
    return "";
  }
  const withCloseButton = Boolean(options.withCloseButton);

  return `
    <section class="session-selection-assistant-panel" aria-label="Selection Assistant">
      <header>
        <div>
          <span>Selection Assistant</span>
          <strong>${escapeHtml(assistant.profile.label)}</strong>
          <small>${escapeHtml(assistant.profile.detail)}</small>
        </div>
        <div class="session-selection-assistant-actions">
          <button
            type="button"
            data-session-selection-assistant-apply
            ${assistant.suggestions.length ? "" : "disabled"}
          >Select ${assistant.suggestions.length}</button>
          ${
            withCloseButton
              ? `<button type="button" class="session-selection-assistant-close" data-session-selection-assistant-close>Close</button>`
              : ""
          }
        </div>
      </header>
      <div class="session-selection-assistant-coverage">
        ${assistant.selectedRoleCoverage
          .map((entry) => `
            <span class="${entry.covered ? "is-covered" : "is-missing"}">
              <strong>${escapeHtml(entry.role)}</strong>
              <small>${entry.covered ? `${entry.score}%` : "gap"}</small>
            </span>
          `)
          .join("")}
      </div>
      <div class="session-selection-assistant-list">
        ${assistant.suggestions
          .slice(0, 8)
          .map((suggestion, index) => `
            <button
              type="button"
              data-session-squad-bridge-player="${escapeHtml(suggestion.item.player.id)}"
            >
              <b>${index + 1}</b>
              <span>
                <strong>${escapeHtml(suggestion.item.player.name)}</strong>
                <small>${escapeHtml(suggestion.reason)}</small>
              </span>
              <em>${suggestion.score}%</em>
            </button>
          `)
          .join("")}
      </div>
      ${
        assistant.missingRoles.length
          ? `<p class="session-selection-assistant-note">Coverage gaps: ${escapeHtml(assistant.missingRoles.map((entry) => entry.role).join(", "))}</p>`
          : `<p class="session-selection-assistant-note is-clear">Role coverage looks balanced for this block.</p>`
      }
    </section>
  `;
}

function renderSessionPlannerSelectionAssistantOverlay(block, boardPlayers = []) {
  if (!sessionPlannerPlayerBoardAssistantOpen || !boardPlayers.length) {
    return "";
  }

  return `
    <div class="session-selection-assistant-overlay" data-session-selection-assistant-overlay>
      <section class="session-selection-assistant-dialog" role="dialog" aria-modal="true" aria-label="Selection Assistant">
        ${renderSessionPlannerSquadBridgePanel(boardPlayers)}
        ${renderSessionPlannerSelectionAssistantPanel(block, boardPlayers, { withCloseButton: true })}
      </section>
    </div>
  `;
}

function applySessionPlannerSelectionAssistant() {
  const block = getSessionPlannerSelectedBlock();
  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const assistant = buildSessionPlannerSelectionAssistant(block, boardPlayers);
  const playerIds = assistant.suggestions.map((suggestion) => suggestion.item.player.id);

  if (!playerIds.length) {
    showSessionPlannerToast("No suggested players available for this block.", "error");
    return;
  }

  sessionPlannerPlayerBoardAssistantOpen = false;
  setSessionPlannerPlayerBoardSelectedPlayers(playerIds, { render: true });
  showSessionPlannerToast(`Selection Assistant selected ${playerIds.length} player${playerIds.length === 1 ? "" : "s"}.`);
}

function compareSessionPlannerPlayerBoardItems(first, second) {
  const firstGroup = getSessionPlannerPlayerBoardPositionGroup(first?.player);
  const secondGroup = getSessionPlannerPlayerBoardPositionGroup(second?.player);
  const groupComparison = firstGroup.order - secondGroup.order;
  if (groupComparison !== 0) {
    return groupComparison;
  }
  return compareMedicalPlayers(first.player, second.player);
}

function isSessionPlannerPlayerVisibleForBoard(participation, rule) {
  if (participation === null || participation === undefined || participation <= 0) {
    return false;
  }

  return participation >= rule.min;
}

function getSessionPlannerPlayerBoardPlayers(block = getSessionPlannerSelectedBlock()) {
  const rule = getSessionPlannerPlayerBoardRule(block);
  return getMedicalAvailabilityItems(sessionPlannerState?.selectedDate)
    .filter((item) => item.record && isSessionPlannerPlayerVisibleForBoard(item.participation, rule))
    .map((item) => ({
      ...item,
      player: getSessionPlannerPlayerBoardSyncedPlayer(item.player),
    }))
    .sort(compareSessionPlannerPlayerBoardItems);
}

function getSessionPlannerPlayerBoardSummary(block = getSessionPlannerSelectedBlock()) {
  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const availabilityItems = getMedicalAvailabilityItems(sessionPlannerState?.selectedDate);
  const rule = getSessionPlannerPlayerBoardRule(block);
  return {
    boardPlayers,
    rule,
    belowLimitCount: availabilityItems.filter(
      (item) => item.record && item.participation > 0 && item.participation < rule.min
    ).length,
    hiddenZeroCount: availabilityItems.filter((item) => item.record && item.participation === 0).length,
    unconfirmedCount: availabilityItems.filter((item) => !item.record).length,
  };
}

function getSessionPlannerPlayerBoardWarnings(block = getSessionPlannerSelectedBlock(), dateValue = sessionPlannerState?.selectedDate) {
  const rule = getSessionPlannerPlayerBoardRule(block);
  const availabilityItems = getMedicalAvailabilityItems(dateValue);
  const available = availabilityItems.filter((item) => item.record && isSessionPlannerPlayerVisibleForBoard(item.participation, rule));
  const belowLimit = availabilityItems.filter((item) => item.record && item.participation > 0 && item.participation < rule.min);
  const unavailable = availabilityItems.filter((item) => item.record && item.participation === 0);
  const unconfirmed = availabilityItems.filter((item) => !item.record);

  return {
    rule,
    available,
    belowLimit,
    unavailable,
    unconfirmed,
    hasWarnings: Boolean(belowLimit.length || unavailable.length || unconfirmed.length),
  };
}

function formatSessionPlannerPlayerWarningNames(items = [], limit = 3) {
  const names = items.slice(0, limit).map((item) => item.player?.name).filter(Boolean);
  const extraCount = Math.max(0, items.length - names.length);
  if (!names.length) {
    return "No players";
  }
  return `${names.join(", ")}${extraCount ? ` +${extraCount}` : ""}`;
}

function renderSessionPlannerPlayerBoardWarnings(block, options = {}) {
  const warnings = getSessionPlannerPlayerBoardWarnings(block, sessionPlannerState?.selectedDate);
  if (!warnings.hasWarnings && options.compact) {
    return "";
  }

  const rows = [
    {
      key: "below",
      label: `Below ${warnings.rule.valueLabel}`,
      count: warnings.belowLimit.length,
      detail: formatSessionPlannerPlayerWarningNames(warnings.belowLimit),
    },
    {
      key: "out",
      label: "0% unavailable",
      count: warnings.unavailable.length,
      detail: formatSessionPlannerPlayerWarningNames(warnings.unavailable),
    },
    {
      key: "unset",
      label: "Not set",
      count: warnings.unconfirmed.length,
      detail: formatSessionPlannerPlayerWarningNames(warnings.unconfirmed),
    },
  ].filter((row) => row.count > 0);

  if (!rows.length) {
    return `
      <div class="session-player-board-warnings is-clear">
        <strong>${escapeHtml(warnings.available.length)} match block rule</strong>
        <span>${escapeHtml(warnings.rule.label)} / ${escapeHtml(warnings.rule.valueLabel)}</span>
      </div>
    `;
  }

  return `
    <div class="session-player-board-warnings${options.compact ? " is-compact" : ""}">
      ${rows
        .map(
          (row) => `
            <div class="session-player-board-warning-row is-${escapeHtml(row.key)}">
              <strong>${row.count}</strong>
              <span>${escapeHtml(row.label)}</span>
              <small>${escapeHtml(row.detail)}</small>
            </div>
          `
        )
        .join("")}
    </div>
  `;
}

function getSessionPlannerPlayerBoardLabelCandidates(player) {
  const words = String(player?.name ?? "").trim().split(/\s+/).filter(Boolean);
  const first = words[0] ?? "Player";
  const last = words.length > 1 ? words[words.length - 1] : "";
  const base = getMedicalPlayerInitials(player);
  const candidates = [
    base,
    `${first.slice(0, 1)}${last.slice(0, 2)}`,
    `${first.slice(0, 2)}${last.slice(0, 1)}`,
    `${first.slice(0, 1)}${last.slice(0, 3)}`,
    `${first.slice(0, 3)}${last.slice(0, 1)}`,
    first.slice(0, 3),
    String(player?.number ?? "").trim() ? `${base}${String(player.number).trim().slice(0, 1)}` : "",
  ];

  return [...new Set(candidates.map((candidate) => candidate.replace(/[^a-z0-9]/gi, "").toUpperCase()).filter(Boolean))];
}

function getSessionPlannerPlayerBoardInitialLabelMap(boardPlayers = []) {
  const baseCounts = boardPlayers.reduce((counts, item) => {
    const base = getMedicalPlayerInitials(item.player);
    counts.set(base, (counts.get(base) ?? 0) + 1);
    return counts;
  }, new Map());
  const usedLabels = new Set();

  return boardPlayers.reduce((labels, item, index) => {
    const base = getMedicalPlayerInitials(item.player);
    const candidates = getSessionPlannerPlayerBoardLabelCandidates(item.player);
    const label =
      candidates.find((candidate) => {
        if (candidate === base && (baseCounts.get(base) ?? 0) > 1) {
          return false;
        }
        return !usedLabels.has(candidate);
      }) ?? `${base}${index + 1}`;

    usedLabels.add(label);
    labels.set(item.player.id, label);
    return labels;
  }, new Map());
}

function syncSessionPlannerPlayerBoardSelection(block = getSessionPlannerSelectedBlock()) {
  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const visibleIds = new Set(boardPlayers.map((item) => item.player.id));
  sessionPlannerPlayerBoardSelectedPlayerIds = sessionPlannerPlayerBoardSelectedPlayerIds.filter((playerId) =>
    visibleIds.has(playerId)
  );

  if (!boardPlayers.length || !sessionPlannerPlayerBoardSelectedPlayerId) {
    sessionPlannerPlayerBoardSelectedPlayerId = "";
    return null;
  }

  const selectedItem = boardPlayers.find((item) => item.player.id === sessionPlannerPlayerBoardSelectedPlayerId) ?? null;
  if (!selectedItem) {
    sessionPlannerPlayerBoardSelectedPlayerId = "";
  }
  return selectedItem;
}

function getSessionPlannerPlayerBoardDefaultGridPosition(index, total) {
  const playerTotal = Math.max(Number(total) || 1, 1);
  const columns =
    playerTotal > 30
      ? 6
      : playerTotal > 22
        ? 5
        : playerTotal > 12
          ? 4
          : playerTotal > 4
            ? 3
            : Math.max(playerTotal, 1);
  const rows = Math.max(Math.ceil(playerTotal / columns), 1);
  const column = index % columns;
  const row = Math.floor(index / columns);
  const x = columns === 1 ? 50 : 10 + column * (80 / (columns - 1));
  const y = rows === 1 ? 50 : 12 + row * (76 / (rows - 1));
  return {
    x: clamp(x, 8, 92),
    y: clamp(y, 12, 88),
  };
}

function getSessionPlannerPlayerBoardDefaultPosition(item, index, boardPlayers = []) {
  const playerId = item?.player?.id ?? item?.id ?? "";
  if (!playerId || !Array.isArray(boardPlayers) || !boardPlayers.length) {
    return getSessionPlannerPlayerBoardDefaultGridPosition(index, boardPlayers?.length || 1);
  }

  const group = getSessionPlannerPlayerBoardPositionGroup(item.player);
  const groupPlayers = boardPlayers.filter(
    (candidate) => getSessionPlannerPlayerBoardPositionGroup(candidate.player).key === group.key
  );
  const groupIndex = Math.max(groupPlayers.findIndex((candidate) => candidate.player.id === playerId), 0);
  const groupTotal = Math.max(groupPlayers.length, 1);
  const step = groupTotal > 7 ? 7.4 : groupTotal > 4 ? 9.2 : 12;
  const span = Math.min(60, (groupTotal - 1) * step);
  const y = groupTotal === 1 ? 50 : 50 - span / 2 + groupIndex * (span / (groupTotal - 1));
  return {
    x: group.x,
    y: clamp(y, 18, 84),
  };
}

function normalizeSessionPlannerPlayerBoardFormationValue(value) {
  return String(value ?? "")
    .replace(/[–—−]/g, "-")
    .replace(/[x×]/gi, "-")
    .replace(/[^0-9\-\s]/g, "")
    .replace(/\s+/g, "")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
}

function cleanSessionPlannerPlayerBoardFormationInput(value) {
  return String(value ?? "")
    .replace(/[–—−]/g, "-")
    .replace(/[x×]/gi, "-")
    .replace(/[^0-9\-\s]/g, "")
    .replace(/\s+/g, "")
    .replace(/-+/g, "-")
    .replace(/^-/, "")
    .slice(0, 18);
}

function parseSessionPlannerPlayerBoardFormation(value) {
  const normalizedValue = normalizeSessionPlannerPlayerBoardFormationValue(value);
  if (!normalizedValue) {
    return [];
  }

  return normalizedValue
    .split("-")
    .map((item) => Number(item))
    .filter((item) => Number.isInteger(item) && item > 0 && item <= 11);
}

function normalizeSessionPlannerPlayerBoardTeamCount(value) {
  const numericValue = Math.round(Number(value));
  if (!Number.isFinite(numericValue)) {
    return 2;
  }
  return clamp(numericValue, 1, sessionPlannerPlayerBoardMaxTeamCount);
}

function normalizeSessionPlannerPlayerBoardAutoMode(value) {
  const mode = String(value ?? "").trim();
  return sessionPlannerPlayerBoardAutoModeOptions.some((option) => option.key === mode) ? mode : "balanced";
}

function getSessionPlannerPlayerBoardRoleOrder(roleKey) {
  const orderByRole = {
    goalkeeper: 0,
    defender: 1,
    midfielder: 2,
    forward: 3,
  };
  return orderByRole[roleKey] ?? 2;
}

function getSessionPlannerPlayerBoardPlayerRoleProfile(player = {}) {
  const position = [
    player.position,
    player.primaryRole,
    player.role,
    player.roleGroup,
    ...(Array.isArray(player.secondaryRoles) ? player.secondaryRoles : []),
  ]
    .join(" ")
    .toLowerCase();
  const normalizedPosition = position.replace(/[^a-z0-9åäö]/gi, " ");
  const parts = normalizedPosition.split(/\s+/).filter(Boolean);
  const hasPart = (...tokens) => tokens.some((token) => parts.includes(token));
  const group = getSessionPlannerPlayerBoardPositionGroup(player);
  const preferredSide = String(player.preferredSide ?? "").trim().toLowerCase();
  let side = ["left", "center", "right"].includes(preferredSide) ? preferredSide : "center";

  if (side === "center" && (
    position.includes("left") ||
    position.includes("vänster") ||
    position.includes("vanster") ||
    hasPart("lb", "lcb", "lm", "lw", "lwb")
  )) {
    side = "left";
  } else if (side === "center" && (
    position.includes("right") ||
    position.includes("höger") ||
    position.includes("hoger") ||
    hasPart("rb", "rcb", "rm", "rw", "rwb")
  )) {
    side = "right";
  } else if (side === "center" && (
    position.includes("center") ||
    position.includes("centre") ||
    position.includes("central") ||
    position.includes("mitt") ||
    hasPart("cb", "cm", "dm", "am", "cf", "st", "9", "6", "8", "10")
  )) {
    side = "center";
  }

  return {
    roleKey: group.key,
    roleOrder: getSessionPlannerPlayerBoardRoleOrder(group.key),
    side,
  };
}

function getSessionPlannerPlayerBoardFormationLineRole(lineIndex, lineTotal) {
  if (lineTotal <= 1) {
    return "midfielder";
  }

  if (lineIndex === 0) {
    return "defender";
  }

  if (lineIndex === lineTotal - 1) {
    return "forward";
  }

  return "midfielder";
}

function getSessionPlannerPlayerBoardFormationSide(slotIndex, lineCount) {
  if (lineCount <= 1) {
    return "center";
  }

  const ratio = slotIndex / (lineCount - 1);
  if (ratio <= 0.34) {
    return "left";
  }
  if (ratio >= 0.66) {
    return "right";
  }
  return "center";
}

function getSessionPlannerPlayerBoardFormationSideOrder(side) {
  const orderBySide = {
    left: 0,
    center: 0.5,
    right: 1,
  };
  return orderBySide[side] ?? 0.5;
}

function getSessionPlannerPlayerBoardFormationSlotX(slotIndex, lineCount) {
  if (lineCount <= 1) {
    return 50;
  }

  const spreadByCount = {
    2: 8,
    3: 16,
    4: 24,
    5: 31,
    6: 37,
  };
  const spread = spreadByCount[lineCount] ?? Math.min(42, 12 + (lineCount - 2) * 5.5);
  const left = 50 - spread / 2;
  const right = 50 + spread / 2;
  return left + slotIndex * ((right - left) / (lineCount - 1));
}

function getSessionPlannerPlayerBoardFormationLineY(lineIndex, lineTotal, hasGoalkeeperSlot = false) {
  if (lineTotal <= 1) {
    return hasGoalkeeperSlot ? 52 : 50;
  }

  const top = hasGoalkeeperSlot ? 36 : 34;
  const bottom = hasGoalkeeperSlot ? 62 : 66;
  return bottom - lineIndex * ((bottom - top) / (lineTotal - 1));
}

function createSessionPlannerPlayerBoardFormationSlots(formation, hasGoalkeeperSlot = false) {
  const lineTotal = formation.length;
  const slots = [];

  if (hasGoalkeeperSlot) {
    slots.push({
      roleKey: "goalkeeper",
      roleOrder: getSessionPlannerPlayerBoardRoleOrder("goalkeeper"),
      side: "center",
      x: 50,
      y: 80,
    });
  }

  formation.forEach((lineCount, lineIndex) => {
    const roleKey = getSessionPlannerPlayerBoardFormationLineRole(lineIndex, lineTotal);
    const y = getSessionPlannerPlayerBoardFormationLineY(lineIndex, lineTotal, hasGoalkeeperSlot);
    for (let slotIndex = 0; slotIndex < lineCount; slotIndex += 1) {
      const side = getSessionPlannerPlayerBoardFormationSide(slotIndex, lineCount);
      slots.push({
        roleKey,
        roleOrder: getSessionPlannerPlayerBoardRoleOrder(roleKey),
        side,
        x: clamp(getSessionPlannerPlayerBoardFormationSlotX(slotIndex, lineCount), 18, 82),
        y: clamp(y, 14, 88),
      });
    }
  });

  return slots;
}

function getSessionPlannerPlayerBoardNumericPriorityValue(value) {
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : null;
}

function getSessionPlannerPlayerBoardRolePriorityKeys(slot = {}) {
  const roleKey = String(slot.roleKey ?? "").trim().toLowerCase();
  const side = String(slot.side ?? "center").trim().toLowerCase();
  const keys = [
    roleKey,
    side && side !== "center" ? `${side}-${roleKey}` : "",
    side && side !== "center" ? `${roleKey}-${side}` : "",
  ];

  if (roleKey === "goalkeeper") {
    keys.push("GK", "gk", "keeper", "goalkeeper");
  } else if (roleKey === "defender") {
    if (side === "left") {
      keys.push("LB", "LWB", "leftBack", "leftWingBack", "left-defender");
    } else if (side === "right") {
      keys.push("RB", "RWB", "rightBack", "rightWingBack", "right-defender");
    } else {
      keys.push("CB", "LCB", "RCB", "centerBack", "centreBack", "central-defender");
    }
    keys.push("DEF", "defender", "back");
  } else if (roleKey === "midfielder") {
    keys.push("6", "8", "10", "CM", "DM", "AM", "MID", "midfielder");
    if (side === "left") {
      keys.push("LM", "leftMidfielder");
    } else if (side === "right") {
      keys.push("RM", "rightMidfielder");
    }
  } else if (roleKey === "forward") {
    if (side === "left") {
      keys.push("LW", "leftWing", "leftForward");
    } else if (side === "right") {
      keys.push("RW", "rightWing", "rightForward");
    } else {
      keys.push("ST", "CF", "9", "striker", "centerForward", "centreForward");
    }
    keys.push("FWD", "forward", "attacker");
  }

  return Array.from(new Set(keys.filter(Boolean)));
}

function getSessionPlannerPlayerBoardRolePriorityValue(player = {}, slot = {}) {
  const roleKeys = getSessionPlannerPlayerBoardRolePriorityKeys(slot);
  const profileSources = [
    player.roleFit,
    player.positionPriority,
    player.rolePriority,
    player.roleRatings,
    player.positionRatings,
    player.positionMinutes,
    player.minutesByPosition,
    player.nwslMinutesByPosition,
    player.nwslMinutes,
  ].filter((source) => source && typeof source === "object" && !Array.isArray(source));

  for (const source of profileSources) {
    for (const key of roleKeys) {
      const keyVariants = [
        key,
        String(key).toUpperCase(),
        String(key).toLowerCase(),
        String(key).replace(/(^|-)([a-z])/g, (match) => match.toUpperCase()).replace(/-/g, ""),
        String(key).replace(/[^a-z0-9]/gi, "").toLowerCase(),
      ];

      const directValue = keyVariants.reduce((value, variant) => {
        if (value !== null) {
          return value;
        }
        return getSessionPlannerPlayerBoardNumericPriorityValue(source[variant]);
      }, null);
      if (directValue !== null) {
        return directValue;
      }
    }
  }

  return null;
}

function getSessionPlannerPlayerBoardImportanceScore(player = {}) {
  const statusPriority =
    getSessionPlannerPlayerBoardNumericPriorityValue(player.squadImportance) ??
    getSessionPlannerPlayerBoardSquadStatusPriority(player.squadStatus);
  if (statusPriority !== null) {
    return statusPriority;
  }

  const rawImportance =
    getSessionPlannerPlayerBoardNumericPriorityValue(player.importance) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.teamImportance) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.roleImportance) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.priority) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.priorityScore);
  if (rawImportance === null) {
    return null;
  }

  if (rawImportance <= 1) {
    return rawImportance * 100;
  }
  if (rawImportance <= 5) {
    return rawImportance * 20;
  }
  if (rawImportance <= 10) {
    return rawImportance * 10;
  }
  return clamp(rawImportance, 0, 100);
}

function getSessionPlannerPlayerBoardMinutesScore(player = {}) {
  return (
    getSessionPlannerPlayerBoardNumericPriorityValue(player.nwslMinutes) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.seasonMinutes) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.minutesPlayed) ??
    getSessionPlannerPlayerBoardNumericPriorityValue(player.minutes) ??
    0
  );
}

function getSessionPlannerPlayerBoardPriorityScore(item, slot) {
  const player = item?.player ?? {};
  const rolePriority = getSessionPlannerPlayerBoardRolePriorityValue(player, slot);
  const importanceScore = getSessionPlannerPlayerBoardImportanceScore(player) ?? 0;
  const minutesScore = getSessionPlannerPlayerBoardMinutesScore(player);
  const rosterOrder = Number(player.rosterOrder);
  const rosterScore = Number.isFinite(rosterOrder) ? Math.max(0, 1000 - rosterOrder) / 10 : 0;
  return (rolePriority ?? 0) * 100 + importanceScore * 10 + minutesScore * 0.05 + rosterScore;
}

function getSessionPlannerPlayerBoardItemPriorityScore(item) {
  const profile = getSessionPlannerPlayerBoardPlayerRoleProfile(item?.player);
  return getSessionPlannerPlayerBoardPriorityScore(item, profile);
}

function getSessionPlannerPlayerBoardRelationLookupValue(source, otherPlayer = {}) {
  if (!source) {
    return null;
  }

  const playerKeys = [
    otherPlayer.id,
    otherPlayer.playerId,
    otherPlayer.profileId,
    otherPlayer.slug,
    otherPlayer.name,
    getMedicalPlayerInitials(otherPlayer),
  ]
    .map((key) => String(key ?? "").trim())
    .filter(Boolean);

  if (typeof source === "object" && !Array.isArray(source)) {
    for (const key of playerKeys) {
      const directValue = getSessionPlannerPlayerBoardNumericPriorityValue(source[key]);
      if (directValue !== null) {
        return directValue;
      }
    }
  }

  if (Array.isArray(source)) {
    for (const item of source) {
      if (!item || typeof item !== "object") {
        continue;
      }
      const relationKeys = [item.playerId, item.id, item.profileId, item.name]
        .map((key) => String(key ?? "").trim())
        .filter(Boolean);
      if (!relationKeys.some((key) => playerKeys.includes(key))) {
        continue;
      }
      const value =
        getSessionPlannerPlayerBoardNumericPriorityValue(item.score) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item.minutes) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item.sharedMinutes) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item.count) ??
        getSessionPlannerPlayerBoardNumericPriorityValue(item.value);
      if (value !== null) {
        return value;
      }
    }
  }

  return null;
}

function getSessionPlannerPlayerBoardStoredRelationScore(firstPlayer = {}, secondPlayer = {}) {
  const sources = [
    firstPlayer.relationships,
    firstPlayer.relations,
    firstPlayer.partnerships,
    firstPlayer.chemistry,
    firstPlayer.sharedMinutes,
    firstPlayer.minutesWith,
    firstPlayer.playingTimeWith,
    firstPlayer.lineupMinutesWith,
    firstPlayer.nwslMinutesWith,
  ];

  for (const source of sources) {
    const value = getSessionPlannerPlayerBoardRelationLookupValue(source, secondPlayer);
    if (value !== null) {
      return value;
    }
  }

  return null;
}

function getSessionPlannerPlayerBoardRelationScore(firstItem, secondItem, block) {
  const firstPlayer = firstItem?.player ?? {};
  const secondPlayer = secondItem?.player ?? {};
  const storedScore =
    getSessionPlannerPlayerBoardStoredRelationScore(firstPlayer, secondPlayer) ??
    getSessionPlannerPlayerBoardStoredRelationScore(secondPlayer, firstPlayer);
  if (storedScore !== null) {
    return storedScore;
  }

  const firstProfile = getSessionPlannerPlayerBoardPlayerRoleProfile(firstPlayer);
  const secondProfile = getSessionPlannerPlayerBoardPlayerRoleProfile(secondPlayer);
  const firstPosition = getSessionPlannerPlayerBoardPositionById(block, firstPlayer.id);
  const secondPosition = getSessionPlannerPlayerBoardPositionById(block, secondPlayer.id);
  const distance = Math.hypot(firstPosition.x - secondPosition.x, firstPosition.y - secondPosition.y);
  const roleGap = Math.abs(firstProfile.roleOrder - secondProfile.roleOrder);
  let score = Math.max(0, 28 - distance * 0.55);

  if (firstProfile.side === secondProfile.side) {
    score += 7;
  }
  if (roleGap === 1) {
    score += 8;
  } else if (roleGap === 0) {
    score += 4;
  }
  return score;
}

function createSessionPlannerPlayerBoardAutoTeams(teamCount) {
  return Array.from({ length: normalizeSessionPlannerPlayerBoardTeamCount(teamCount) }, () => ({
    items: [],
    priorityTotal: 0,
    roleCounts: {},
  }));
}

function addSessionPlannerPlayerBoardItemToAutoTeam(team, item) {
  const profile = getSessionPlannerPlayerBoardPlayerRoleProfile(item?.player);
  const priorityScore = getSessionPlannerPlayerBoardItemPriorityScore(item);
  team.items.push(item);
  team.priorityTotal += priorityScore;
  team.roleCounts[profile.roleKey] = (team.roleCounts[profile.roleKey] ?? 0) + 1;
}

function pickSessionPlannerPlayerBoardBalancedTeamIndex(teams, item, allowedTeamIndexes = null) {
  const profile = getSessionPlannerPlayerBoardPlayerRoleProfile(item?.player);
  const indexes = allowedTeamIndexes?.length ? allowedTeamIndexes : teams.map((team, index) => index);
  let bestIndex = indexes[0] ?? 0;
  let bestScore = Number.POSITIVE_INFINITY;

  indexes.forEach((teamIndex) => {
    const team = teams[teamIndex];
    const score =
      team.items.length * 100 +
      (team.roleCounts[profile.roleKey] ?? 0) * 18 +
      team.priorityTotal * 0.002 +
      teamIndex * 0.01;
    if (score < bestScore) {
      bestIndex = teamIndex;
      bestScore = score;
    }
  });

  return bestIndex;
}

function createSessionPlannerPlayerBoardAutoAssignmentsFromTeams(teams) {
  return teams.flatMap((team, teamIndex) =>
    team.items.map((item) => ({
      playerId: item.player.id,
      teamIndex,
    }))
  );
}

function getSessionPlannerPlayerBoardRelationPairs(items, block) {
  const remainingItems = [...items].sort(
    (first, second) => getSessionPlannerPlayerBoardItemPriorityScore(second) - getSessionPlannerPlayerBoardItemPriorityScore(first)
  );
  const pairs = [];

  while (remainingItems.length) {
    const firstItem = remainingItems.shift();
    if (!remainingItems.length) {
      pairs.push([firstItem]);
      break;
    }

    let bestIndex = 0;
    let bestScore = Number.NEGATIVE_INFINITY;
    remainingItems.forEach((candidate, index) => {
      const score = getSessionPlannerPlayerBoardRelationScore(firstItem, candidate, block);
      if (score > bestScore) {
        bestIndex = index;
        bestScore = score;
      }
    });

    const [secondItem] = remainingItems.splice(bestIndex, 1);
    pairs.push([firstItem, secondItem].filter(Boolean));
  }

  return pairs;
}

function assignSessionPlannerPlayerBoardAutoTeams(items, teamCount, mode, block) {
  const teams = createSessionPlannerPlayerBoardAutoTeams(teamCount);
  const normalizedMode = normalizeSessionPlannerPlayerBoardAutoMode(mode);
  const sortedItems = [...items].sort((first, second) => {
    const firstPriority = getSessionPlannerPlayerBoardItemPriorityScore(first);
    const secondPriority = getSessionPlannerPlayerBoardItemPriorityScore(second);
    return normalizedMode === "rotation" ? firstPriority - secondPriority : secondPriority - firstPriority;
  });

  if (normalizedMode === "relations") {
    getSessionPlannerPlayerBoardRelationPairs(sortedItems, block).forEach((pair) => {
      const teamIndex = pickSessionPlannerPlayerBoardBalancedTeamIndex(teams, pair[0]);
      pair.forEach((item) => addSessionPlannerPlayerBoardItemToAutoTeam(teams[teamIndex], item));
    });
    return createSessionPlannerPlayerBoardAutoAssignmentsFromTeams(teams);
  }

  if (normalizedMode === "best-xi") {
    const topTeamCount = Math.min(sortedItems.length, 11);
    sortedItems.slice(0, topTeamCount).forEach((item) => addSessionPlannerPlayerBoardItemToAutoTeam(teams[0], item));

    const remainingTeamIndexes = teams.length > 1 ? teams.slice(1).map((team, index) => index + 1) : [];
    sortedItems.slice(topTeamCount).forEach((item) => {
      if (!remainingTeamIndexes.length) {
        return;
      }
      const teamIndex = pickSessionPlannerPlayerBoardBalancedTeamIndex(teams, item, remainingTeamIndexes);
      addSessionPlannerPlayerBoardItemToAutoTeam(teams[teamIndex], item);
    });
    return createSessionPlannerPlayerBoardAutoAssignmentsFromTeams(teams);
  }

  sortedItems.forEach((item) => {
    const teamIndex = pickSessionPlannerPlayerBoardBalancedTeamIndex(teams, item);
    addSessionPlannerPlayerBoardItemToAutoTeam(teams[teamIndex], item);
  });

  return createSessionPlannerPlayerBoardAutoAssignmentsFromTeams(teams);
}

function getSessionPlannerPlayerBoardAutoTargetItems(block) {
  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const selectedIds = normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds, block);
  if (!selectedIds.length) {
    return boardPlayers;
  }

  const selectedIdSet = new Set(selectedIds);
  return boardPlayers.filter((item) => selectedIdSet.has(item.player.id));
}

function getSessionPlannerPlayerBoardAutoSelectFormation() {
  let formationValue = normalizeSessionPlannerPlayerBoardFormationValue(sessionPlannerPlayerBoardFormationInput);
  if (!parseSessionPlannerPlayerBoardFormation(formationValue).length) {
    const promptValue = window.prompt("Set formation for Auto Select", formationValue || "3-3-1");
    if (promptValue === null) {
      return null;
    }
    formationValue = normalizeSessionPlannerPlayerBoardFormationValue(promptValue);
  }

  const formation = parseSessionPlannerPlayerBoardFormation(formationValue);
  if (!formation.length) {
    showSessionPlannerToast("Enter a formation, for example 3-3-1.", "error");
    return null;
  }

  sessionPlannerPlayerBoardFormationInput = formationValue;
  return formation;
}

function getSessionPlannerPlayerBoardAutoTeamGrid(teamCount) {
  const normalizedTeamCount = normalizeSessionPlannerPlayerBoardTeamCount(teamCount);
  const columns = normalizedTeamCount <= 3 ? normalizedTeamCount : Math.ceil(normalizedTeamCount / 2);
  const rows = Math.ceil(normalizedTeamCount / columns);
  return {
    columns,
    rows,
  };
}

function getSessionPlannerPlayerBoardAutoTeamCell(teamIndex, teamCount) {
  const grid = getSessionPlannerPlayerBoardAutoTeamGrid(teamCount);
  const column = teamIndex % grid.columns;
  const row = Math.floor(teamIndex / grid.columns);
  const width = 100 / grid.columns;
  const height = 100 / grid.rows;
  return {
    left: column * width,
    top: row * height,
    width,
    height,
  };
}

function mapSessionPlannerPlayerBoardSlotToAutoTeamCell(slot, cell) {
  const horizontalScale = cell.width < 34 ? 1.38 : 1.24;
  const verticalScale = cell.height < 58 ? 1.05 : 0.86;
  const x = cell.left + cell.width / 2 + (slot.x - 50) * (cell.width / 100) * horizontalScale;
  const y = cell.top + cell.height / 2 + (slot.y - 50) * (cell.height / 100) * verticalScale;
  return {
    ...slot,
    x: clamp(x, cell.left + 4, cell.left + cell.width - 4),
    y: clamp(y, cell.top + 8, cell.top + cell.height - 6),
  };
}

function createSessionPlannerPlayerBoardExtraTeamSlots(extraCount, cell) {
  if (!extraCount) {
    return [];
  }

  const columns = Math.min(extraCount, 4);
  const rows = Math.ceil(extraCount / columns);
  return Array.from({ length: extraCount }, (_, index) => {
    const column = index % columns;
    const row = Math.floor(index / columns);
    const x = columns === 1 ? 50 : 50 - 18 + column * (36 / (columns - 1));
    const y = rows === 1 ? 86 : 82 + row * (10 / Math.max(rows - 1, 1));
    return mapSessionPlannerPlayerBoardSlotToAutoTeamCell(
      {
        roleKey: "midfielder",
        roleOrder: getSessionPlannerPlayerBoardRoleOrder("midfielder"),
        side: getSessionPlannerPlayerBoardFormationSide(column, columns),
        x,
        y,
      },
      cell
    );
  });
}

function createSessionPlannerPlayerBoardAutoTeamFormationSlots(teamItems, formation, teamIndex, teamCount) {
  const outfieldSlotCount = formation.reduce((total, count) => total + count, 0);
  const hasGoalkeeper = teamItems.some(
    (item) => getSessionPlannerPlayerBoardPlayerRoleProfile(item.player).roleKey === "goalkeeper"
  );
  const hasGoalkeeperSlot = hasGoalkeeper && teamItems.length >= outfieldSlotCount + 1;
  const cell = getSessionPlannerPlayerBoardAutoTeamCell(teamIndex, teamCount);
  const formationSlots = createSessionPlannerPlayerBoardFormationSlots(formation, hasGoalkeeperSlot).map((slot) =>
    mapSessionPlannerPlayerBoardSlotToAutoTeamCell(slot, cell)
  );
  const extraSlots = createSessionPlannerPlayerBoardExtraTeamSlots(Math.max(0, teamItems.length - formationSlots.length), cell);
  return [...formationSlots, ...extraSlots];
}

function shouldSessionPlannerPlayerBoardAutoUseGoalkeeperSlots(items, formation, teamCount) {
  const normalizedTeamCount = normalizeSessionPlannerPlayerBoardTeamCount(teamCount);
  const outfieldSlotCount = formation.reduce((total, count) => total + count, 0);
  if (!outfieldSlotCount) {
    return false;
  }

  const goalkeeperCount = items.filter(
    (item) => getSessionPlannerPlayerBoardPlayerRoleProfile(item.player).roleKey === "goalkeeper"
  ).length;
  return goalkeeperCount >= normalizedTeamCount && items.length >= normalizedTeamCount * (outfieldSlotCount + 1);
}

function scoreSessionPlannerPlayerBoardAutoTeamSlotCandidate(item, slot, teamItems, mode, block) {
  const normalizedMode = normalizeSessionPlannerPlayerBoardAutoMode(mode);
  let score = scoreSessionPlannerPlayerBoardFormationFit(item, slot, {
    prioritize: true,
    rotation: normalizedMode === "rotation",
  });

  if (normalizedMode === "relations" && teamItems.length) {
    const relationAverage =
      teamItems.reduce((total, teamItem) => total + getSessionPlannerPlayerBoardRelationScore(item, teamItem, block), 0) /
      teamItems.length;
    score -= relationAverage * 0.1;
  }

  return score;
}

function pickSessionPlannerPlayerBoardAutoTeamSlotItem(remainingItems, slot, teamItems, mode, block) {
  let bestIndex = 0;
  let bestScore = Number.POSITIVE_INFINITY;
  remainingItems.forEach((item, index) => {
    const score = scoreSessionPlannerPlayerBoardAutoTeamSlotCandidate(item, slot, teamItems, mode, block);
    if (score < bestScore) {
      bestIndex = index;
      bestScore = score;
    }
  });
  return bestIndex;
}

function createSessionPlannerPlayerBoardAutoTeamSlotPlan(formation, teamIndex, teamCount, includeGoalkeeperSlot) {
  const cell = getSessionPlannerPlayerBoardAutoTeamCell(teamIndex, teamCount);
  return createSessionPlannerPlayerBoardFormationSlots(formation, includeGoalkeeperSlot).map((slot) =>
    mapSessionPlannerPlayerBoardSlotToAutoTeamCell(slot, cell)
  );
}

function assignSessionPlannerPlayerBoardAutoFormationTeams(items, teamCount, mode, block, formation) {
  const normalizedTeamCount = normalizeSessionPlannerPlayerBoardTeamCount(teamCount);
  const normalizedMode = normalizeSessionPlannerPlayerBoardAutoMode(mode);
  const includeGoalkeeperSlot = shouldSessionPlannerPlayerBoardAutoUseGoalkeeperSlots(items, formation, normalizedTeamCount);
  const teams = Array.from({ length: normalizedTeamCount }, () => []);
  const assignments = [];
  const remainingItems = [...items];

  for (let teamIndex = 0; teamIndex < normalizedTeamCount; teamIndex += 1) {
    const slots = createSessionPlannerPlayerBoardAutoTeamSlotPlan(
      formation,
      teamIndex,
      normalizedTeamCount,
      includeGoalkeeperSlot
    );
    for (const slot of slots) {
      if (!remainingItems.length) {
        break;
      }

      const bestIndex = pickSessionPlannerPlayerBoardAutoTeamSlotItem(
        remainingItems,
        slot,
        teams[teamIndex],
        normalizedMode,
        block
      );
      const [item] = remainingItems.splice(bestIndex, 1);
      if (!item?.player?.id) {
        continue;
      }
      teams[teamIndex].push(item);
      assignments.push({
        playerId: item.player.id,
        teamIndex,
        position: {
          x: slot.x,
          y: slot.y,
        },
      });
    }
  }

  if (remainingItems.length) {
    const sortedRemainingItems = remainingItems.sort((first, second) => {
      const firstPriority = getSessionPlannerPlayerBoardItemPriorityScore(first);
      const secondPriority = getSessionPlannerPlayerBoardItemPriorityScore(second);
      return normalizedMode === "rotation" ? firstPriority - secondPriority : secondPriority - firstPriority;
    });

    sortedRemainingItems.forEach((item, index) => {
      const teamIndex = index % normalizedTeamCount;
      const cell = getSessionPlannerPlayerBoardAutoTeamCell(teamIndex, normalizedTeamCount);
      const slot = createSessionPlannerPlayerBoardExtraTeamSlots(1, cell)[0];
      if (!slot || !item?.player?.id) {
        return;
      }
      assignments.push({
        playerId: item.player.id,
        teamIndex,
        position: {
          x: clamp(slot.x + (Math.floor(index / normalizedTeamCount) % 4) * 4, cell.left + 4, cell.left + cell.width - 4),
          y: clamp(slot.y, cell.top + 8, cell.top + cell.height - 6),
        },
      });
    });
  }

  return assignments;
}

function applySessionPlannerPlayerBoardAutoTeamFormation(block, targetItems, assignments, formation) {
  if (assignments.some((assignment) => assignment?.position)) {
    if (!block.playerBoardPositions || typeof block.playerBoardPositions !== "object") {
      block.playerBoardPositions = {};
    }

    block.playerBoardLayoutMode = "manual";
    targetItems.forEach((item) => {
      if (item?.player?.id) {
        delete block.playerBoardPositions[item.player.id];
      }
    });
    assignments.forEach((assignment) => {
      if (assignment?.playerId && assignment.position) {
        block.playerBoardPositions[assignment.playerId] = assignment.position;
      }
    });
    return;
  }

  const itemsById = new Map(targetItems.map((item) => [item.player.id, item]));
  const teams = Array.from({ length: sessionPlannerPlayerBoardTeamCount }, () => []);

  assignments.forEach((assignment) => {
    const item = itemsById.get(assignment.playerId);
    if (item && teams[assignment.teamIndex]) {
      teams[assignment.teamIndex].push(item);
    }
  });

  if (!block.playerBoardPositions || typeof block.playerBoardPositions !== "object") {
    block.playerBoardPositions = {};
  }

  block.playerBoardLayoutMode = "manual";
  targetItems.forEach((item) => {
    if (item?.player?.id) {
      delete block.playerBoardPositions[item.player.id];
    }
  });

  teams.forEach((teamItems, teamIndex) => {
    if (!teamItems.length) {
      return;
    }

    const slots = createSessionPlannerPlayerBoardAutoTeamFormationSlots(
      teamItems,
      formation,
      teamIndex,
      sessionPlannerPlayerBoardTeamCount
    );
    const positionAssignments = assignSessionPlannerPlayerBoardFormationSlots(teamItems, slots, {
      prioritize: sessionPlannerPlayerBoardAutoMode === "best-xi",
    });
    positionAssignments.forEach((assignment) => {
      block.playerBoardPositions[assignment.playerId] = assignment.position;
    });
  });
}

function applySessionPlannerPlayerBoardAutoSelect() {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  sessionPlannerPlayerBoardTeamCount = normalizeSessionPlannerPlayerBoardTeamCount(sessionPlannerPlayerBoardTeamCount);
  sessionPlannerPlayerBoardAutoMode = normalizeSessionPlannerPlayerBoardAutoMode(sessionPlannerPlayerBoardAutoMode);

  const targetItems = getSessionPlannerPlayerBoardAutoTargetItems(block);
  if (!targetItems.length) {
    showSessionPlannerToast("No available players to auto-select.", "error");
    return;
  }

  const formation = getSessionPlannerPlayerBoardAutoSelectFormation();
  if (!formation) {
    return;
  }

  const assignments = assignSessionPlannerPlayerBoardAutoFormationTeams(
    targetItems,
    sessionPlannerPlayerBoardTeamCount,
    sessionPlannerPlayerBoardAutoMode,
    block,
    formation
  );
  if (!assignments.length) {
    showSessionPlannerToast("Auto Select could not find any players to colour.", "error");
    return;
  }

  if (!block.playerBoardColors || typeof block.playerBoardColors !== "object") {
    block.playerBoardColors = {};
  }

  const assignedIds = new Set(assignments.map((assignment) => assignment.playerId));
  targetItems.forEach((item) => {
    if (item?.player?.id) {
      delete block.playerBoardColors[item.player.id];
    }
  });
  assignments.forEach((assignment) => {
    const color = sessionPlannerPlayerBoardColorOptions[assignment.teamIndex % sessionPlannerPlayerBoardColorOptions.length]?.value;
    if (color && assignedIds.has(assignment.playerId)) {
      block.playerBoardColors[assignment.playerId] = color;
    }
  });

  applySessionPlannerPlayerBoardAutoTeamFormation(block, targetItems, assignments, formation);
  markSessionPlannerBlockFieldsUpdated(block, ["playerBoardLayoutMode", "playerBoardPositions", "playerBoardColors"]);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  const modeLabel =
    sessionPlannerPlayerBoardAutoModeOptions.find((option) => option.key === sessionPlannerPlayerBoardAutoMode)?.label ??
    "Auto Select";
  showSessionPlannerToast(
    `${modeLabel}: ${assignments.length} player${assignments.length === 1 ? "" : "s"} assigned across ${sessionPlannerPlayerBoardTeamCount} team${sessionPlannerPlayerBoardTeamCount === 1 ? "" : "s"} in ${formation.join("-")}.`
  );
}

function scoreSessionPlannerPlayerBoardFormationFit(item, slot, options = {}) {
  const profile = getSessionPlannerPlayerBoardPlayerRoleProfile(item?.player);
  const roleDistance = Math.abs(profile.roleOrder - slot.roleOrder);
  const sideDistance = Math.abs(
    getSessionPlannerPlayerBoardFormationSideOrder(profile.side) -
      getSessionPlannerPlayerBoardFormationSideOrder(slot.side)
  );
  const rosterOrder = Number(item?.player?.rosterOrder) || 999;
  const rolePriority = getSessionPlannerPlayerBoardRolePriorityValue(item?.player, slot) ?? 0;
  const importanceScore = getSessionPlannerPlayerBoardImportanceScore(item?.player) ?? 0;
  const minutesScore = getSessionPlannerPlayerBoardMinutesScore(item?.player);
  const priorityScore = options.prioritize ? getSessionPlannerPlayerBoardPriorityScore(item, slot) : 0;
  const priorityAdjustment = priorityScore * 0.003;
  const rotationAdjustment = options.rotation ? priorityAdjustment : -priorityAdjustment;

  return (
    roleDistance * 120 +
    sideDistance * 28 -
    rolePriority * 0.22 -
    importanceScore * 0.18 -
    minutesScore * 0.012 +
    rosterOrder * 0.01 +
    rotationAdjustment
  );
}

function assignSessionPlannerPlayerBoardFormationSlots(selectedItems, slots, options = {}) {
  const remainingItems = [...selectedItems];
  const assignments = [];

  slots.forEach((slot) => {
    if (!remainingItems.length) {
      return;
    }

    let bestIndex = 0;
    let bestScore = Number.POSITIVE_INFINITY;
    remainingItems.forEach((item, index) => {
      const score = scoreSessionPlannerPlayerBoardFormationFit(item, slot, options);
      if (score < bestScore) {
        bestIndex = index;
        bestScore = score;
      }
    });

    const [item] = remainingItems.splice(bestIndex, 1);
    if (item?.player?.id) {
      assignments.push({
        playerId: item.player.id,
        position: {
          x: slot.x,
          y: slot.y,
        },
      });
    }
  });

  return assignments;
}

function applySessionPlannerPlayerBoardFormation(options = {}) {
  if (!canEditSessionPlanner()) {
    return;
  }

  const block = getSessionPlannerSelectedBlock();
  if (!block) {
    return;
  }

  const selectedIds = normalizeSessionPlannerPlayerBoardSelectedIds(sessionPlannerPlayerBoardSelectedPlayerIds, block);
  if (!selectedIds.length) {
    showSessionPlannerToast("Select players first.", "error");
    return;
  }

  const formation = parseSessionPlannerPlayerBoardFormation(sessionPlannerPlayerBoardFormationInput);
  const outfieldSlotCount = formation.reduce((total, count) => total + count, 0);
  if (!outfieldSlotCount) {
    showSessionPlannerToast("Enter a formation, for example 3-3-1.", "error");
    return;
  }

  const boardPlayers = getSessionPlannerPlayerBoardPlayers(block);
  const selectedItems = selectedIds
    .map((playerId) => boardPlayers.find((item) => item.player.id === playerId))
    .filter(Boolean);
  const hasGoalkeeper = selectedItems.some(
    (item) => getSessionPlannerPlayerBoardPlayerRoleProfile(item.player).roleKey === "goalkeeper"
  );
  const hasGoalkeeperSlot = hasGoalkeeper && selectedItems.length === outfieldSlotCount + 1;
  const expectedCount = outfieldSlotCount + (hasGoalkeeperSlot ? 1 : 0);

  if (selectedItems.length < expectedCount || (!options.prioritize && selectedItems.length !== expectedCount)) {
    const expectedLabel = hasGoalkeeper
      ? `${outfieldSlotCount} or ${outfieldSlotCount + 1} with goalkeeper`
      : String(outfieldSlotCount);
    showSessionPlannerToast(
      `The formation needs ${expectedLabel} players. You selected ${selectedItems.length}.`,
      "error"
    );
    return;
  }

  const slots = createSessionPlannerPlayerBoardFormationSlots(formation, hasGoalkeeperSlot);
  const assignments = assignSessionPlannerPlayerBoardFormationSlots(selectedItems, slots, options);
  if (!assignments.length) {
    return;
  }

  if (!block.playerBoardPositions || typeof block.playerBoardPositions !== "object") {
    block.playerBoardPositions = {};
  }

  block.playerBoardLayoutMode = "manual";
  assignments.forEach((assignment) => {
    block.playerBoardPositions[assignment.playerId] = assignment.position;
  });

  markSessionPlannerBlockFieldsUpdated(block, ["playerBoardLayoutMode", "playerBoardPositions"]);
  writeSessionPlannerState();
  renderSessionPlannerWorkspace({ preserveDateStripScroll: true });
  showSessionPlannerToast(
    `${options.prioritize ? "Prioritized formation" : "Formation"} ${formation.join("-")} placed for ${assignments.length} player${assignments.length === 1 ? "" : "s"}.`
  );
}

function getSessionPlannerPlayerBoardPosition(block, item, index, boardPlayers = []) {
  const playerId = typeof item === "string" ? item : item?.player?.id;
  if (!block.playerBoardPositions || typeof block.playerBoardPositions !== "object") {
    block.playerBoardPositions = {};
  }

  const savedPosition = block.playerBoardPositions[playerId];
  if (block.playerBoardLayoutMode === "manual" && savedPosition) {
    return {
      x: clamp(Number(savedPosition.x) || 50, 0, 100),
      y: clamp(Number(savedPosition.y) || 50, 0, 100),
    };
  }

  return getSessionPlannerPlayerBoardDefaultPosition(item, index, boardPlayers);
}

function getSessionPlannerPlayerBoardPositionById(block, playerId, boardPlayers = getSessionPlannerPlayerBoardPlayers(block)) {
  const index = boardPlayers.findIndex((item) => item.player.id === playerId);
  const item = boardPlayers[index] ?? { player: { id: playerId, position: "" } };
  return getSessionPlannerPlayerBoardPosition(block, item, Math.max(index, 0), boardPlayers);
}

function getSessionPlannerPlayerBoardTone(participation) {
  if (participation <= 10) {
    return "low";
  }
  if (participation <= 25) {
    return "rehab";
  }
  if (participation <= 50) {
    return "controlled";
  }
  if (participation < 100) {
    return "modified";
  }
  return "full";
}

function getSessionPlannerPlayerBoardCustomColor(block, playerId) {
  if (!block?.playerBoardColors || typeof block.playerBoardColors !== "object") {
    return "";
  }

  return normalizeTacticalColor(block.playerBoardColors[playerId], "");
}

function getSessionPlannerPlayerBoardTextColor(backgroundColor) {
  const color = normalizeTacticalColor(backgroundColor, "");
  const match = color.match(/^#([0-9a-f]{6})$/i);
  if (!match) {
    return "#1d1d1f";
  }

  const value = match[1];
  const red = parseInt(value.slice(0, 2), 16) / 255;
  const green = parseInt(value.slice(2, 4), 16) / 255;
  const blue = parseInt(value.slice(4, 6), 16) / 255;
  const luminance = 0.2126 * red + 0.7152 * green + 0.0722 * blue;
  return luminance > 0.62 ? "#1d1d1f" : "#ffffff";
}

function getSessionPlannerPlayerBoardColorStyle(color) {
  const normalizedColor = normalizeTacticalColor(color, "");
  if (!normalizedColor) {
    return "";
  }

  return `--session-player-board-color: ${normalizedColor}; --session-player-board-text: ${getSessionPlannerPlayerBoardTextColor(normalizedColor)};`;
}

function renderSessionPlannerPlayerBoardLines() {
  return `
    <div class="session-player-board-lines" aria-hidden="true">
      <span></span>
      <span></span>
      <span></span>
    </div>
  `;
}

function renderSessionPlannerPlayerBoardPositionLabels() {
  return `
    <div class="session-player-board-position-labels" aria-hidden="true">
      ${sessionPlannerPlayerBoardPositionGroups
        .map(
          (group) => `
            <span style="left: ${group.x}%;">
              <strong>${escapeHtml(group.shortLabel)}</strong>
              <small>${escapeHtml(group.label)}</small>
            </span>
          `
        )
        .join("")}
    </div>
  `;
}

function renderSessionPlannerPlayerBoardToken(item, index, block, total, labelMap, selectedPlayerIds = new Set(), boardPlayers = []) {
  const position = getSessionPlannerPlayerBoardPosition(block, item, index, boardPlayers);
  const tone = getSessionPlannerPlayerBoardTone(item.participation);
  const label = labelMap.get(item.player.id) ?? getMedicalPlayerInitials(item.player);
  const customColor = getSessionPlannerPlayerBoardCustomColor(block, item.player.id);
  const colorStyle = getSessionPlannerPlayerBoardColorStyle(customColor);
  const bridgeRole = getSessionPlannerPlayerBoardBridgeRoleLabel(item.player);
  const bridgeTitle = bridgeRole ? ` · Squad role ${bridgeRole}` : "";
  return `
    <button
      type="button"
      class="session-player-board-token is-${escapeHtml(tone)}${customColor ? " has-custom-color" : ""}${selectedPlayerIds.has(item.player.id) ? " is-selected" : ""}"
      data-session-player-board-token="${escapeHtml(item.player.id)}"
      style="left: ${position.x}%; top: ${position.y}%; ${colorStyle}"
      title="${escapeHtml(`${item.player.name} · ${item.participation}%${bridgeTitle}`)}"
      aria-label="${escapeHtml(`${item.player.name}, ${item.participation}% available${bridgeTitle}`)}"
    >
      <strong>${escapeHtml(label)}</strong>
      ${bridgeRole ? `<span>${escapeHtml(bridgeRole)}</span>` : ""}
    </button>
  `;
}

function renderSessionPlannerPlayerBoardProfile(item, block, rule, totalPlayers) {
  if (!item) {
    return `
      <aside class="session-player-board-profile">
        <div class="session-player-board-profile-empty">
          <strong>No players for this block</strong>
          <span>Add medical availability for this date to place players on the board.</span>
        </div>
      </aside>
    `;
  }

  const { player, record, status, participation } = item;
  const actualParticipation = normalizeMedicalActualParticipation(record?.actualParticipation ?? medicalActualParticipationFallback);
  const actualLabel = actualParticipation === medicalActualParticipationFallback ? "Not logged" : `${actualParticipation}%`;
  const rtpPhase = record?.rtpPhase ? getMedicalRtpPhaseOption(record.rtpPhase).label : "Not set";
  const coachNote = getMedicalCoachComment(record);
  const sourceLabel = record?.source === "injury-plan" ? "Availability plan" : "Daily medical log";
  const dateLabel = formatMedicalDateLabel(sessionPlannerState?.selectedDate, "long");
  const squadContract = getSessionPlannerPlayerBoardBridgeContract(player);
  const squadPrimaryRole = squadContract?.primaryRole || getSessionPlannerPlayerBoardBridgeRoleLabel(player) || "Not linked";
  const squadBestMatch = squadContract
    ? Object.entries(squadContract.roleFit || {})
        .filter(([role, score]) => playerProfileRoleOptions.includes(role) && Number.isFinite(Number(score)))
        .sort((first, second) => Number(second[1]) - Number(first[1]))[0]
    : null;

  return `
    <aside class="session-player-board-profile">
      <header class="session-player-board-profile-head">
        ${renderMedicalPlayerAvatar(player, "session-player-board-profile-avatar")}
        <div>
          <span>${escapeHtml(sourceLabel)}</span>
          <strong>${escapeHtml(player.name)}</strong>
          <small>${player.number ? `#${escapeHtml(player.number)} / ` : ""}${escapeHtml(player.position || "Position")}</small>
        </div>
      </header>
      <div class="session-player-board-profile-kpis">
        <span>
          <strong>${participation}%</strong>
          <small>Planned today</small>
        </span>
        <span>
          <strong>${escapeHtml(actualLabel)}</strong>
          <small>Actual</small>
        </span>
        <span>
          <strong>${escapeHtml(squadPrimaryRole)}</strong>
          <small>Squad role</small>
        </span>
        <span>
          <strong>${squadBestMatch ? `${Math.round(Number(squadBestMatch[1]))}%` : "Fallback"}</strong>
          <small>Role DNA</small>
        </span>
      </div>
      <dl class="session-player-board-profile-list">
        <div>
          <dt>Status</dt>
          <dd>${escapeHtml(status?.label ?? "Not set")}</dd>
        </div>
        <div>
          <dt>RTP phase</dt>
          <dd>${escapeHtml(rtpPhase)}</dd>
        </div>
        <div>
          <dt>Training date</dt>
          <dd>${escapeHtml(dateLabel)}</dd>
        </div>
        <div>
          <dt>Board rule</dt>
          <dd>${escapeHtml(rule.label)} shows ${escapeHtml(rule.valueLabel)}</dd>
        </div>
        <div>
          <dt>Squad roles</dt>
          <dd>${escapeHtml(
            squadContract
              ? [
                  squadContract.primaryRole,
                  ...(Array.isArray(squadContract.secondaryRoles) ? squadContract.secondaryRoles : []),
                ].filter(Boolean).join(" / ") || "No roles set"
              : "No Squad profile linked"
          )}</dd>
        </div>
        <div>
          <dt>Preferred side</dt>
          <dd>${escapeHtml(squadContract?.preferredSide || "Not set")}</dd>
        </div>
      </dl>
      ${renderSessionPlannerPlayerBoardSquadProfile(squadContract)}
      <div class="session-player-board-profile-note">
        <span>Coach note</span>
        <p>${escapeHtml(coachNote || "No coach note shared.")}</p>
      </div>
      <p class="session-player-board-profile-foot">
        ${escapeHtml(player.name)} is one of ${totalPlayers} player${totalPlayers === 1 ? "" : "s"} visible for this block.
      </p>
    </aside>
  `;
}

