function loadLowBlockPressExample() {
  cancelSequenceAdvance();
  state = createInitialState();
  lastFrame = null;

  const example = createLowBlockPressExample();
  state.sequence.steps = example.steps;
  state.sequence.initialSnapshot = cloneSnapshot(example.initialSnapshot);
  state.sequence.isPlaying = false;
  state.sequence.playbackIndex = -1;
  state.sequence.currentFrameIndex = -1;
  state.sequence.phase = null;
  state.sequence.transition = null;
  state.sequence.actionTargets = null;
  state.scenario = example.scenario;
  state.example = {
    id: "low-block-4141",
    overlaySteps: example.overlaySteps,
  };

  applySnapshot(example.initialSnapshot);
  clearBallAction();
  ui.playPauseButton.textContent = "Start";
  updateModeButtons();
  updateSequenceButtons();
  logEvent("4-1-4-1 example loaded: centre-back drives forward and the nearest No. 8 presses.");
}

function cloneScenarioInfo(info = defaultScenarioInfo) {
  return {
    title: info.title,
    text: info.text,
    meta: info.meta,
  };
}

function markSimulatorDirty() {
  state.simulatorDirty = true;
}

function markSequenceDirty() {
  state.sequence.dirty = true;
  markSimulatorDirty();
}

function markSimulatorSaved() {
  state.simulatorDirty = false;
  state.sequence.dirty = false;
}

function readSavedSequenceLibrary() {
  try {
    const raw = window.localStorage.getItem(sequenceLibraryStorageKey);
    if (!raw) {
      return [];
    }

    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [];
    }

    return parsed
      .filter((entry) => entry && entry.id && entry.name && entry.sequence?.steps)
      .sort((a, b) => new Date(b.savedAt ?? 0) - new Date(a.savedAt ?? 0));
  } catch {
    return [];
  }
}

function writeSavedSequenceLibrary(entries) {
  const sortedEntries = [...entries].sort(
    (a, b) => new Date(b.savedAt ?? 0) - new Date(a.savedAt ?? 0)
  );
  state.savedSequences = sortedEntries;

  try {
    window.localStorage.setItem(
      sequenceLibraryStorageKey,
      JSON.stringify(sortedEntries)
    );
    if (sortedEntries[0]?.sequence) {
      window.localStorage.setItem(
        sequenceStorageKey,
        JSON.stringify(sortedEntries[0].sequence)
      );
    } else {
      window.localStorage.removeItem(sequenceStorageKey);
    }
  } catch {
    logEvent("The browser could not write to local storage.");
  }
}

function sanitizeFileName(input) {
  return input
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48) || "football-sequence";
}

function getRemainingBallDistance() {
  if (state.ball.trackDistanceTotal > 0 && (state.ball.actionType !== "dribble" || state.ball.dribblePath)) {
    return Math.max(0, state.ball.trackDistanceTotal - state.ball.trackDistanceCovered);
  }

  return distance(state.ball.position, state.ball.target);
}

function hasBallAction() {
  return state.ball.actionType !== null && (getRemainingBallDistance() > 0.05 || state.ball.inTransit);
}

function getActionOrigin(player) {
  return player.actionOrigin ?? player.position;
}

function getProjectedActionDuration() {
  if (state.sequence.phase === "transition" && state.sequence.transition) {
    return state.sequence.transition.duration;
  }

  if (!hasBallAction()) {
    return 0;
  }

  return state.ball.elapsedTravelTime + getRemainingBallTravelTime();
}

function getCurrentActionDuration() {
  if (state.sequence.phase === "transition" && state.sequence.transition) {
    return state.sequence.transition.elapsed;
  }

  return hasBallAction() ? state.ball.elapsedTravelTime : 0;
}

function getActionInitiator() {
  if (state.ball.actionType === "dribble") {
    return getPlayerById(state.ball.carrierPlayerId ?? state.ball.initiatorPlayerId);
  }

  return getPlayerById(state.ball.initiatorPlayerId);
}

function getOrientationTurnDelay(player, targetPoint = state.ball.target) {
  if (!targetPoint) {
    return 0;
  }

  const desiredAngle = angleBetween(player.position, targetPoint);
  const bodyAngle = getPlayerFacingAngle(player);
  const angleGap = angleDifference(bodyAngle, desiredAngle) / Math.PI;
  const profile = player.intelligenceProfile ?? buildPlayerIntelligenceProfile(player);

  return clamp(
    angleGap * (0.03 + (1 - profile.tacticalDiscipline) * 0.14 + (1 - profile.perception) * 0.06),
    0,
    0.22
  );
}

function getOrientationMovementProfile(player, targetPoint = state.ball.target) {
  if (!targetPoint) {
    return {
      angleGap: 0,
      angleGapRatio: 0,
      accelerationMultiplier: 1,
      speedMultiplier: 1,
      coverModifier: 1,
      receiveModifier: 1,
      recoveryModifier: 1,
    };
  }

  const desiredAngle = angleBetween(player.position, targetPoint);
  const angleGap = angleDifference(getPlayerFacingAngle(player), desiredAngle);
  const angleGapDegrees = (angleGap * 180) / Math.PI;

  if (angleGapDegrees <= 30) {
    return {
      angleGap,
      angleGapRatio: angleGap / Math.PI,
      accelerationMultiplier: 1,
      speedMultiplier: 1,
      coverModifier: 1,
      receiveModifier: 1,
      recoveryModifier: 1,
    };
  }

  if (angleGapDegrees <= 75) {
    return {
      angleGap,
      angleGapRatio: angleGap / Math.PI,
      accelerationMultiplier: 0.93,
      speedMultiplier: 0.97,
      coverModifier: 0.92,
      receiveModifier: 0.94,
      recoveryModifier: 0.95,
    };
  }

  if (angleGapDegrees <= 135) {
    return {
      angleGap,
      angleGapRatio: angleGap / Math.PI,
      accelerationMultiplier: 0.82,
      speedMultiplier: 0.9,
      coverModifier: 0.79,
      receiveModifier: 0.82,
      recoveryModifier: 0.84,
    };
  }

  return {
    angleGap,
    angleGapRatio: angleGap / Math.PI,
    accelerationMultiplier: 0.68,
    speedMultiplier: 0.82,
    coverModifier: 0.64,
    receiveModifier: 0.7,
    recoveryModifier: 0.72,
  };
}

function getCoverShadowInfluence(player, lanePoint, sourcePoint = state.ball.position) {
  const laneProfile = getOrientationMovementProfile(player, lanePoint);
  const ballAngle = sourcePoint ? angleBetween(player.position, sourcePoint) : getPlayerFacingAngle(player);
  const bodyAngle = getPlayerFacingAngle(player);
  const bodyToBall = 1 - angleDifference(bodyAngle, ballAngle) / Math.PI;
  const forwardCover = laneProfile.coverModifier;

  return clamp(
    0.34 + forwardCover * 0.46 + bodyToBall * 0.2,
    0.3,
    1.02
  );
}

function getReceiveOrientationScore(player, incomingPoint = state.ball.startPosition) {
  if (!incomingPoint) {
    return 0.84;
  }

  const idealHalfOpenAngle = getBestReceiveBodyAngle(player, incomingPoint);
  const bodyAngle = getPlayerFacingAngle(player);
  const receiveProfile = getOrientationMovementProfile(player, incomingPoint);
  const halfOpenAlignment = 1 - angleDifference(bodyAngle, idealHalfOpenAngle) / Math.PI;

  return clamp(
    halfOpenAlignment * 0.66 + receiveProfile.receiveModifier * 0.34,
    0.18,
    0.98
  );
}

function getBestReceiveBodyAngle(player, incomingPoint = state.ball.startPosition) {
  const nextPlayAngle = getTeamAttackAngle(player.team);
  if (!incomingPoint) {
    return normalizeAngle(nextPlayAngle + Math.PI / 7.5);
  }

  const receiveFromBallAngle = angleBetween(player.position, incomingPoint);
  const relativeBallAngle = normalizeAngle(receiveFromBallAngle - nextPlayAngle);
  const fallbackSide =
    Math.sign(normalizeAngle(getPlayerFacingAngle(player) - nextPlayAngle)) ||
    (incomingPoint.y < player.position.y ? -1 : 1);
  const openSide = Math.sign(relativeBallAngle) || fallbackSide;
  const openOffsetMagnitude = clamp(
    Math.max(Math.abs(relativeBallAngle) * 0.28, Math.PI / 9),
    Math.PI / 9,
    Math.PI / 5.2
  );
  const openBodyAngle = normalizeAngle(nextPlayAngle + openSide * openOffsetMagnitude);

  return blendAngles(receiveFromBallAngle, openBodyAngle, 0.28, 0.72);
}

function getReceiveFootUsageScore(player, incomingPoint = state.ball.startPosition) {
  if (!player || !incomingPoint) {
    return 0.82;
  }

  const receiveFromBallAngle = angleBetween(player.position, incomingPoint);
  const idealReceiveAngle = getBestReceiveBodyAngle(player, incomingPoint);
  return getFootUsageScore(player, receiveFromBallAngle, idealReceiveAngle);
}

function applyBestReceiveBodyAngle(player, incomingPoint = state.ball.startPosition, blend = 1) {
  if (!player) {
    return;
  }

  const desiredAngle = getBestReceiveBodyAngle(player, incomingPoint);
  const currentAngle = getPlayerFacingAngle(player);
  const delta = normalizeAngle(desiredAngle - currentAngle);
  player.bodyAngle = normalizeAngle(currentAngle + delta * clamp(blend, 0, 1));
}

function getFirstTouchModeLabel(mode) {
  return firstTouchModes[mode] ?? firstTouchModes.auto;
}

function resolveFirstTouchMode(player, incomingPoint, requestedMode = state.firstTouchMode) {
  if (!player) {
    return "auto";
  }

  if (requestedMode && requestedMode !== "auto" && firstTouchModes[requestedMode]) {
    return requestedMode;
  }

  const context = getPlayerDecisionContext(player);
  const pressure = getPlayerPressureLoad(player, getPlayerBallControlPoint(player));
  const isWide = isWideChannel(player.position);
  const isPassToFeet = state.ball.targetKind === "to-feet" || state.ball.receiverPlayerId === player.id;
  const profileKey = state.ball.profileKey ?? "";
  const isProgressiveReceivingProfile =
    profileKey === "line-break" ||
    profileKey === "onto-9" ||
    profileKey === "lead-space" ||
    profileKey === "into-space";
  const canPlayForward =
    context.profile.decisionQuality >= 0.72 &&
    context.profile.technicalSecurity >= 0.7 &&
    pressure <= 0.5;

  if (pressure >= 0.62) {
    return "kill";
  }

  if (isPassToFeet && !isProgressiveReceivingProfile) {
    return "kill";
  }

  if (isWide && pressure <= 0.42 && !isPassToFeet) {
    return "inside";
  }

  if (canPlayForward) {
    return "forward";
  }

  const incomingAngle = incomingPoint ? angleBetween(incomingPoint, player.position) : getPlayerFacingAngle(player);
  const isPassAcrossBody =
    angleDifference(incomingAngle, getTeamAttackAngle(player.team)) > Math.PI / 3.2;

  return isPassAcrossBody && !isPassToFeet ? "across" : "kill";
}

function getFirstTouchDirectionAngle(player, mode, incomingPoint = state.ball.startPosition) {
  const attackDirection = getAttackDirectionSign(player.team);
  const towardCenterSign = Math.sign(pitch.width / 2 - player.position.y) || 1;

  if (mode === "kill") {
    return getBestReceiveBodyAngle(player, incomingPoint);
  }

  if (mode === "forward") {
    return getTeamAttackAngle(player.team);
  }

  if (mode === "inside") {
    return Math.atan2(towardCenterSign * 0.95, attackDirection * 0.65);
  }

  if (mode === "outside") {
    return Math.atan2(-towardCenterSign * 0.95, attackDirection * 0.55);
  }

  if (mode === "back") {
    return Math.atan2(towardCenterSign * 0.25, -attackDirection);
  }

  const incomingSide =
    incomingPoint ? Math.sign(player.position.y - incomingPoint.y) || towardCenterSign : towardCenterSign;
  return Math.atan2(-incomingSide * 0.88, attackDirection * 0.72);
}

function getFirstTouchDistance(player, mode, firstTouchQuality, requestedMode = state.ball.firstTouchMode) {
  if (mode === "kill") {
    return 0;
  }

  const pressure = getPlayerPressureLoad(player, getPlayerBallControlPoint(player));
  const quality = clamp(firstTouchQuality, 0.2, 0.98);
  const pressureReduction = pressure * 0.72;
  const autoTouchMultiplier = requestedMode === "auto" ? 0.68 : 1;
  const baseDistances = {
    forward: [0.85, 2.05],
    inside: [0.72, 1.75],
    outside: [0.68, 1.65],
    back: [0.45, 1.15],
    across: [0.62, 1.55],
  };
  const [minDistance, maxDistance] = baseDistances[mode] ?? baseDistances.forward;

  return clamp(
    (lerp(minDistance, maxDistance, quality) - pressureReduction) * autoTouchMultiplier,
    mode === "back" ? 0.28 : 0.42,
    maxDistance * autoTouchMultiplier
  );
}

function clearAutoPilotReceiveMomentum(ownerPlayerId = null) {
  if (!state.autoPilotPlay?.receiveMomentum) {
    return;
  }

  if (!ownerPlayerId || state.autoPilotPlay.receiveMomentum.ownerPlayerId !== ownerPlayerId) {
    state.autoPilotPlay.receiveMomentum = null;
  }
}

function setAutoPilotReceiveMomentum(
  player,
  mode,
  incomingPoint,
  firstTouchQuality,
  directionAngle,
  touchDistance
) {
  if (!state.autoPilotPlay || !player) {
    return;
  }

  const attackAngle = getTeamAttackAngle(player.team);
  const receivePoint = cloneVector(getPlayerBallControlPoint(player));
  const pressureAtReceive = getPlayerPressureLoad(player, receivePoint);

  state.autoPilotPlay.receiveMomentum = {
    ownerPlayerId: player.id,
    teamId: player.team,
    mode,
    quality: clamp(firstTouchQuality, 0, 1),
    directionAngle,
    touchDistance: Math.max(0, touchDistance),
    forwardIntent: Math.cos(normalizeAngle(directionAngle - attackAngle)),
    lateralIntent: Math.sin(normalizeAngle(directionAngle - attackAngle)),
    pressureAtReceive,
    point: receivePoint,
    createdAt: state.time,
    expiresAt: state.time + 5.5,
    stepIndex: (state.sequence?.steps?.length ?? 0) + 1,
  };
}

function getAutoPilotReceiveMomentum(carrier, startPoint) {
  const momentum = state.autoPilotPlay?.receiveMomentum;
  if (!carrier || !momentum || momentum.ownerPlayerId !== carrier.id || momentum.teamId !== carrier.team) {
    return null;
  }

  const currentStepIndex = state.sequence?.steps?.length ?? 0;
  if (currentStepIndex > momentum.stepIndex) {
    clearAutoPilotReceiveMomentum();
    return null;
  }

  if (state.time > momentum.expiresAt) {
    clearAutoPilotReceiveMomentum();
    return null;
  }

  if (distance(momentum.point, startPoint) > 5.5) {
    clearAutoPilotReceiveMomentum();
    return null;
  }

  return momentum;
}

function getAutoPilotReceiveMomentumAdjustment(candidate, carrier, startPoint, profile) {
  const momentum = getAutoPilotReceiveMomentum(carrier, startPoint);
  if (!momentum || !candidate?.target) {
    return { score: 0, labels: [] };
  }

  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const actionDistance = distance(startPoint, candidate.target);
  const actionAngle = actionDistance > 0.2 ? angleBetween(startPoint, candidate.target) : momentum.directionAngle;
  const alignment = Math.cos(normalizeAngle(actionAngle - momentum.directionAngle));
  const attackSign = getAttackDirectionSign(carrier.team);
  const forwardGain = Number.isFinite(candidate.forwardGain)
    ? candidate.forwardGain
    : (candidate.target.x - startPoint.x) * attackSign;
  const passDistance = candidate.actionType === "pass" ? actionDistance : 0;
  const isControlledTouch = momentum.quality >= 0.62;
  const labels = [];
  let score = 0;

  if (momentum.mode === "kill" || momentum.mode === "back") {
    if (candidate.actionType === "pass" && passDistance <= 20 && forwardGain >= -6) {
      score += 0.12 + Math.max(0, pressure - 0.25) * 0.18;
      labels.push("Secure next action");
    }

    if (forwardGain >= 12 && pressure >= 0.55 && !candidate.isLineBreak) {
      score -= 0.18 + pressure * 0.12;
    }
  } else {
    if (candidate.actionType === "dribble" && forwardGain >= 3 && alignment >= 0.18) {
      score += 0.2 + momentum.touchDistance * 0.08 + Math.max(0, alignment) * 0.12;
      labels.push("Carry first touch");
    }

    if (
      candidate.actionType === "pass" &&
      (candidate.isLineBreak || forwardGain >= 6) &&
      alignment >= -0.1
    ) {
      score += 0.14 + (profile.tempo ?? 0) * 0.08 + momentum.quality * 0.08;
      labels.push("Play from receive");
    }

    if (forwardGain <= -4 && pressure <= 0.48 && isControlledTouch) {
      score -= 0.28 + Math.max(0, momentum.forwardIntent) * 0.18;
    }

    if (candidate.isSwitch && momentum.mode === "inside") {
      score += 0.08 + (profile.switchBias ?? 0) * 0.08;
      labels.push("Open body switch");
    }
  }

  if (
    momentum.touchDistance >= 0.8 &&
    candidate.actionType === "dribble" &&
    actionDistance <= 12 &&
    alignment >= 0.45
  ) {
    score += 0.14;
  }

  return {
    score: clamp(score, -0.5, 0.7),
    labels: uniquePrincipleLabels(labels),
  };
}

function getAutoPilotFirstActionAfterReceiveAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier) {
    return { score: 0, labels: [] };
  }

  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const momentum = getAutoPilotReceiveMomentum(carrier, startPoint);
  if (!flow.carrierJustReceived && !momentum) {
    return { score: 0, labels: [] };
  }

  const teamId = carrier.team;
  const pressure = flow.pressure;
  const depth = getAttackingDepth(startPoint, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const targetThreat = getPitchThreatProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const receivedBetweenLines =
    startThreat.betweenLines >= 0.36 ||
    startThreat.centralPocket >= 0.28 ||
    (depth >= 42 && depth <= 74 && Math.abs(startPoint.y - pitch.width / 2) <= 23);
  const openBody =
    isPlayerFacingForward(carrier, Math.PI / 2.15) ||
    (momentum?.forwardIntent ?? 0) >= 0.2 ||
    momentum?.mode === "inside";
  const hasForwardTime = pressure <= 0.52 && (openBody || startThreat.centrality >= 0.5);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const highValueNextAction =
    candidate.isLineBreak ||
    candidate.isBoxPass ||
    targetThreat.value >= startThreat.value + 0.08 ||
    actionSpace.value >= 0.46 ||
    forwardGain >= 6.5;
  const bounceBackToPasser =
    candidate.actionType === "pass" &&
    candidate.receiverPlayerId &&
    candidate.receiverPlayerId === flow.lastCarrierId &&
    flow.lastReceiverId === carrier.id;
  const sterileSideways =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    Math.abs(forwardGain) < 3.2 &&
    passDistance <= 18 &&
    targetThreat.value <= startThreat.value + 0.04;
  const supportSecure =
    candidate.actionType === "pass" &&
    passDistance <= 18 &&
    (isSupportRole(receiverRoleKey) || receiverRoleKey === "gk" || receiverRoleKey === "rest");
  const labels = [];
  let score = 0;

  if (hasForwardTime && receivedBetweenLines) {
    if (candidate.actionType === "dribble" && forwardGain >= 3.5) {
      score +=
        0.42 +
        (progressionWindow.openLane ?? 0) * 0.24 +
        getPlayerTendency(carrier, "dribble") * 0.16;
      labels.push("Carry from receive");
    }

    if (candidate.actionType === "pass" && highValueNextAction && forwardGain >= 1.5) {
      score +=
        0.34 +
        actionSpace.value * 0.28 +
        (candidate.isLineBreak ? 0.18 : 0) +
        (isFrontLineRole(receiverRoleKey) ? 0.08 : 0);
      labels.push("Receive to play forward");
    }

    if (candidate.actionType === "shot" && (startThreat.box >= 0.18 || depth >= 68)) {
      score += 0.28 + profile.shootBias * 0.18;
      labels.push("Face goal");
    }

    if (forwardGain <= -4.5 && !candidate.isSwitch) {
      score -= 0.68 + profile.progressionUrgency * 0.28 + startThreat.value * 0.16;
    } else if (sterileSideways) {
      score -= 0.34 + profile.progressionUrgency * 0.18;
    }
  }

  if (momentum) {
    const actionAngle = passDistance > 0.2
      ? angleBetween(startPoint, candidate.target)
      : momentum.directionAngle;
    const receiveAlignment = Math.cos(normalizeAngle(actionAngle - momentum.directionAngle));

    if (candidate.actionType === "dribble" && receiveAlignment >= 0.28 && forwardGain >= 3) {
      score += 0.16 + momentum.quality * 0.12;
    }

    if (candidate.actionType === "pass" && highValueNextAction && receiveAlignment >= -0.15) {
      score += 0.12 + momentum.quality * 0.08;
    }

    if (receiveAlignment <= -0.45 && pressure <= 0.5 && !supportSecure && !candidate.isSwitch) {
      score -= 0.22 + momentum.quality * 0.12;
    }
  }

  if (bounceBackToPasser) {
    const thirdPlayerAllowance =
      pressure >= 0.58 ||
      candidate.isLineBreak ||
      highValueNextAction ||
      (supportSecure && getPlayerTendency(carrier, "passAndMove") >= 0.68);
    score -= thirdPlayerAllowance ? 0.18 : 0.82;
  }

  if (pressure >= 0.62 && supportSecure && forwardGain >= -7) {
    score += 0.22 + profile.shortSupport * 0.18;
    labels.push("Secure under pressure");
  }

  if (
    candidate.actionType === "pass" &&
    forwardGain <= -6 &&
    pressure <= 0.42 &&
    receivedBetweenLines &&
    targetThreat.value < startThreat.value + 0.02
  ) {
    score -= 0.34 + profile.progressionUrgency * 0.22;
  }

  return {
    score: clamp(score, -1.15, 0.9),
    labels: uniquePrincipleLabels(labels),
  };
}

function getAutoPilotReceiveFlowContext(carrier, startPoint, profile) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const momentum = getAutoPilotReceiveMomentum(carrier, startPoint);
  if (!flow.carrierJustReceived && !momentum) {
    return { active: false };
  }

  const teamId = carrier.team;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const depth = getAttackingDepth(startPoint, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const nearestOpponentGap = getNearestOpponentGap(carrier, startPoint);
  const closeOpponents = getOpponentDensityAtPoint(teamId, startPoint, 6);
  const supportCount = getTeamDensityAtPoint(teamId, startPoint, 13, new Set([carrier.id]));
  const forwardProbe = clampToPitch({
    x: startPoint.x + getAttackDirectionSign(teamId) * 14,
    y: lerp(startPoint.y, pitch.width / 2, 0.22),
  }, 2.5);
  const openLane = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, forwardProbe));
  const facingForward =
    isPlayerFacingForward(carrier, Math.PI / 2.25) ||
    (momentum?.forwardIntent ?? 0) >= 0.18 ||
    momentum?.mode === "inside";
  const receivedBetweenLines =
    startThreat.betweenLines >= 0.34 ||
    startThreat.centralPocket >= 0.26 ||
    (depth >= 42 && depth <= 76 && Math.abs(startPoint.y - pitch.width / 2) <= 23);
  const canTurn = clamp(
    (facingForward ? 0.28 : 0) +
      openLane * 0.28 +
      clamp((nearestOpponentGap - 2.4) / 7.8, 0, 1) * 0.22 +
      (receivedBetweenLines ? 0.18 : 0) +
      (momentum?.quality ?? 0.6) * 0.1 -
      pressure * 0.22 -
      closeOpponents * 0.06,
    0,
    1
  );
  const secureNeed = clamp(
    pressure * 0.52 +
      closeOpponents * 0.15 +
      (nearestOpponentGap <= 2.4 ? 0.18 : 0) -
      supportCount * 0.06 -
      (momentum?.quality ?? 0.6) * 0.08,
    0,
    1
  );
  const finishNeed = clamp(
    startThreat.box * 0.42 +
      startThreat.centralPocket * 0.28 +
      (depth >= 70 ? 0.18 : 0) +
      (pressure <= 0.5 ? 0.1 : 0) +
      (profile.shootBias ?? 0.45) * 0.16,
    0,
    1
  );
  const switchWindow = clamp(
    (profile.switchBias ?? 0.45) * 0.26 +
      (flow.recentWideTargets >= 1 ? 0.14 : 0) +
      (pressure >= 0.42 ? 0.12 : 0) +
      (Math.abs(startPoint.y - pitch.width / 2) >= 13 ? 0.12 : 0),
    0,
    1
  );

  return {
    active: true,
    flow,
    momentum,
    pressure,
    depth,
    startThreat,
    nearestOpponentGap,
    closeOpponents,
    supportCount,
    openLane,
    facingForward,
    receivedBetweenLines,
    canTurn,
    secureNeed,
    finishNeed,
    switchWindow,
  };
}

function getAutoPilotReceiveFlowAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier) {
    return { score: 0, labels: [] };
  }

  const context = getAutoPilotReceiveFlowContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [] };
  }

  const teamId = carrier.team;
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const supportTarget =
    candidate.actionType === "pass" &&
    passDistance <= 19 &&
    (isSupportRole(receiverRoleKey) || receiverRoleKey === "rest" || receiverRoleKey === "gk");
  const progressiveTarget =
    forwardGain >= 4.5 &&
    (candidate.isLineBreak ||
      candidate.isBoxPass ||
      actionSpace.value >= 0.38 ||
      targetThreat.value >= context.startThreat.value + 0.06);
  const sterileRecycle =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 2 &&
    targetThreat.value <= context.startThreat.value + 0.04 &&
    actionSpace.lineBreakCount === 0;
  const bounceBackToPasser =
    candidate.actionType === "pass" &&
    candidate.receiverPlayerId &&
    candidate.receiverPlayerId === context.flow.lastCarrierId &&
    context.flow.lastReceiverId === carrier.id;
  const labels = [];
  let score = 0;

  if (context.canTurn >= 0.58) {
    if (candidate.actionType === "dribble" && forwardGain >= 3) {
      score += 0.28 + context.canTurn * 0.26 + context.openLane * 0.18;
      labels.push("Turn and carry");
    }

    if (candidate.actionType === "pass" && progressiveTarget) {
      score += 0.24 + actionSpace.value * 0.24 + context.canTurn * 0.14;
      labels.push("Turn to play forward");
    }

    if (candidate.actionType === "shot" && context.finishNeed >= 0.38) {
      score += 0.26 + context.finishNeed * 0.28;
      labels.push("Receive to finish");
    }

    if (sterileRecycle && context.pressure <= 0.52) {
      score -= 0.42 + context.canTurn * 0.22 + (profile.progressionUrgency ?? 0.5) * 0.18;
    }
  }

  if (context.secureNeed >= 0.56) {
    if (supportTarget && forwardGain >= -8) {
      score += 0.22 + context.secureNeed * 0.2 + (profile.shortSupport ?? 0.5) * 0.12;
      labels.push("Secure next pass");
    }

    if (candidate.actionType === "dribble" && (context.closeOpponents >= 2 || context.openLane <= 0.42)) {
      score -= 0.34 + context.secureNeed * 0.18;
    }

    if (
      candidate.actionType === "pass" &&
      passDistance >= 25 &&
      !candidate.isSwitch &&
      !candidate.isBoxPass &&
      actionSpace.openTarget < 0.62
    ) {
      score -= 0.28 + context.secureNeed * 0.16;
    }
  }

  if (context.switchWindow >= 0.42 && candidate.isSwitch) {
    score += 0.16 + context.switchWindow * 0.22 + (profile.switchBias ?? 0.45) * 0.08;
    labels.push("Receive and switch");
  }

  if (bounceBackToPasser) {
    const usefulBounce =
      context.secureNeed >= 0.64 ||
      context.pressure >= 0.62 ||
      candidate.isLineBreak ||
      (supportTarget && context.supportCount <= 1);
    score += usefulBounce ? 0.08 : -0.5;
  }

  if (
    context.receivedBetweenLines &&
    candidate.actionType === "pass" &&
    forwardGain <= -5 &&
    context.pressure <= 0.44 &&
    !candidate.isSwitch
  ) {
    score -= 0.38 + context.startThreat.value * 0.18;
  }

  return {
    score: clamp(score, -0.95, 1.05),
    labels: uniquePrincipleLabels(labels),
    context,
  };
}

function getReceiveContinuationCarryTarget(carrier, startPoint, context, profile = {}) {
  const attackAngle = getTeamAttackAngle(carrier.team);
  const directionAngle = context.momentum?.directionAngle ?? attackAngle;
  const forwardIntent = Math.cos(normalizeAngle(directionAngle - attackAngle));
  const canDriveForward = context.canTurn >= 0.54 && context.openLane >= 0.42;
  const distanceMeters = clamp(
    5.5 +
      context.openLane * 6.4 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 2.8 +
      (profile.dribbleBias ?? 0.5) * 1.6 -
      context.pressure * 2.6,
    4.2,
    canDriveForward ? 13.5 : 8.5
  );
  const correctedAngle =
    forwardIntent >= 0.12 || context.momentum?.mode === "inside"
      ? blendAngles(directionAngle, attackAngle, 0.72, 0.28)
      : blendAngles(directionAngle, attackAngle, 0.46, 0.54);

  return clampToPitch({
    x: startPoint.x + Math.cos(correctedAngle) * distanceMeters,
    y: startPoint.y + Math.sin(correctedAngle) * distanceMeters,
  }, 2.5);
}

function buildAutoPilotReceiveContinuationCandidate(carrier, startPoint, profile) {
  const context = getAutoPilotReceiveFlowContext(carrier, startPoint, profile);
  if (!context.active || state.restartPhase?.type) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const options = [];
  const addPassOption = (receiver, target, meta = {}) => {
    if (!receiver || receiver.team !== teamId || receiver.id === carrier.id || isPassReceiverOffside(receiver, startPoint)) {
      return;
    }

    const passDistance = distance(startPoint, target);
    if (passDistance < 3.4 || passDistance > (meta.maxDistance ?? 28)) {
      return;
    }

    const roleKey = getOffensiveRoleKey(receiver, formation);
    const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
    const laneClarity = computePassLaneClarity(carrier, target, { receiverPlayerId: receiver.id });
    const receiverPressure = getPlayerPressureLoad(receiver, target);
    const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
    const targetThreat = actionSpace.targetThreat;
    const isLineBreak = forwardGain >= 6.5 && (actionSpace.lineBreakCount >= 1 || targetThreat.value >= context.startThreat.value + 0.08);
    const isBoxPass = targetThreat.box >= 0.24 || (getAttackingDepth(target, teamId) >= 74 && Math.abs(target.y - pitch.width / 2) <= 17);
    const isSwitch = Math.abs(getPitchLaneIndex(target) - getPitchLaneIndex(startPoint)) >= 2 && passDistance >= 15;
    const isSidewaysPass = Math.abs(forwardGain) < 4 && Math.abs(target.y - startPoint.y) >= 6.5 && !isSwitch;
    const bounceBackToPasser = receiver.id === context.flow.lastCarrierId && context.flow.lastReceiverId === carrier.id;
    const supportNearTarget = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, receiver.id]), passDistance >= 22 ? 15 : 11);
    const roleFit =
      meta.kind === "escape"
        ? (isSupportRole(roleKey) || roleKey === "rest" || roleKey === "gk" ? 0.42 : 0.14)
        : isFrontLineRole(roleKey)
          ? 0.36
          : roleKey === "connector"
            ? 0.32
            : roleKey === "pivot"
              ? 0.22
              : 0.12;
    const score =
      (meta.baseScore ?? 1.35) +
      laneClarity * 0.92 +
      getAutoPilotRoleStrength(receiver, "receiver") * 0.34 +
      roleFit +
      actionSpace.value * 0.42 +
      Math.max(0, targetThreat.value - context.startThreat.value) * 0.64 +
      (isLineBreak ? 0.42 + (profile.lineBreakBias ?? 0.5) * 0.22 : 0) +
      (isBoxPass ? 0.3 + (profile.deliveryBias ?? 0.45) * 0.16 : 0) +
      (meta.kind === "escape" ? context.secureNeed * 0.46 + (profile.shortSupport ?? 0.5) * 0.2 : 0) +
      (meta.kind === "thirdMan" ? context.canTurn * 0.24 + (profile.tempo ?? 0.5) * 0.14 : 0) +
      (isSwitch ? context.switchWindow * 0.32 + (profile.switchBias ?? 0.45) * 0.16 : 0) +
      clamp(supportNearTarget, 0, 3) * 0.08 -
      receiverPressure * 0.42 -
      Math.max(0, passDistance - 18) * 0.035 -
      (bounceBackToPasser && context.pressure < 0.58 ? 0.78 : 0) -
      (forwardGain <= -5 && context.canTurn >= 0.56 && context.pressure <= 0.48 ? 0.54 : 0);

    if (score < (meta.minScore ?? 1.7)) {
      return;
    }

    options.push({
      actionType: "pass",
      target,
      receiverPlayerId: receiver.id,
      receiverRoleKey: roleKey,
      passDistance,
      forwardGain,
      laneClarity,
      receiverPressure,
      supportNearTarget,
      isLineBreak,
      isSwitch,
      isSidewaysPass,
      isBoxPass,
      isPrinciplePattern: true,
      principleKey: meta.kind === "escape" ? "receive-escape" : "receive-third-player",
      principleLabel: meta.kind === "escape"
        ? `Receive flow: ${getPlayerMagnetLabel(carrier)} secures the next pass under pressure`
        : `Receive flow: ${getPlayerMagnetLabel(carrier)} finds the next player after first touch`,
      score,
      firstTouchMode: isLineBreak || isBoxPass ? "forward" : isSwitch ? "inside" : meta.kind === "escape" ? "inside" : "forward",
      label: meta.kind === "escape" ? "receive escape" : isLineBreak ? "receive third-player" : "receive continuation",
      reason: meta.kind === "escape"
        ? "receiver is under pressure and plays the next support angle"
        : "first touch opens the next forward action",
    });
  };

  state.players.forEach((receiver) => {
    if (receiver.team !== teamId || receiver.id === carrier.id) {
      return;
    }

    const roleKey = getOffensiveRoleKey(receiver, formation);
    const target = getPlayerBallControlPoint(receiver);
    const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
    const isThirdManRole =
      isFrontLineRole(roleKey) ||
      roleKey === "connector" ||
      (roleKey === "wideBack" && (profile.overlapBias ?? 0) >= 0.56);
    const isSupportRoleTarget =
      isSupportRole(roleKey) ||
      roleKey === "rest" ||
      roleKey === "gk";

    if (
      context.canTurn >= 0.48 &&
      isThirdManRole &&
      forwardGain >= -1 &&
      receiver.id !== context.flow.lastCarrierId
    ) {
      addPassOption(receiver, target, {
        kind: "thirdMan",
        baseScore: 1.48,
        minScore: 1.78,
        maxDistance: context.receivedBetweenLines ? 30 : 24,
      });
    }

    if (context.secureNeed >= 0.54 && isSupportRoleTarget) {
      addPassOption(receiver, target, {
        kind: "escape",
        baseScore: 1.42,
        minScore: 1.62,
        maxDistance: 19,
      });
    }
  });

  if (context.canTurn >= 0.52 && context.openLane >= 0.38 && context.pressure <= 0.68) {
    const target = getReceiveContinuationCarryTarget(carrier, startPoint, context, profile);
    const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
    const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
    const actionDistance = distance(startPoint, target);
    const score =
      1.5 +
      context.canTurn * 0.52 +
      context.openLane * 0.42 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 0.38 +
      (profile.carryBias ?? 0.5) * 0.22 +
      Math.max(0, forwardGain) * 0.035 +
      actionSpace.value * 0.32 -
      context.pressure * 0.34;

    if (forwardGain >= 2.5 && actionDistance >= 4 && score >= 1.72) {
      options.push({
        actionType: "dribble",
        target,
        receiverPlayerId: null,
        passDistance: actionDistance,
        forwardGain,
        laneClarity: 0.72,
        receiverPressure: context.pressure,
        isLineBreak: actionSpace.lineBreakCount >= 1,
        isSwitch: false,
        isSidewaysPass: false,
        isBoxPass: actionSpace.targetThreat.box >= 0.22,
        isPrinciplePattern: true,
        principleKey: "receive-carry",
        principleLabel: `Receive flow: ${getPlayerMagnetLabel(carrier)} takes the first touch into space`,
        score,
        firstTouchMode: null,
        label: "receive and carry",
        reason: "first touch opens a carry lane",
      });
    }
  }

  if (!options.length) {
    return null;
  }

  return options.sort((a, b) => b.score - a.score)[0];
}

function applyControlledFirstTouch(player, incomingPoint, firstTouchQuality, requestedMode = state.ball.firstTouchMode) {
  if (!player) {
    return null;
  }

  const mode = resolveFirstTouchMode(player, incomingPoint, requestedMode);
  const directionAngle = getFirstTouchDirectionAngle(player, mode, incomingPoint);
  rotatePlayerBodyTowardAngle(player, directionAngle, mode === "kill" ? 0.55 : 0.86);

  const touchDistance = getFirstTouchDistance(player, mode, firstTouchQuality, requestedMode);
  if (touchDistance <= 0.05) {
    state.ball.ownerPlayerId = player.id;
    keepSecurePossessionOnlyForOwner(player.id);
    state.ball.position = cloneVector(getPlayerBallControlPoint(player));
    state.ball.target = cloneVector(state.ball.position);
    setSecurePossessionAfterControlledTouch(player, state.ball.position, {
      quality: firstTouchQuality,
      reason: "controlled-reception",
      minDistanceToExpire: mode === "kill" ? 3.6 : 4.6,
      minTimeToExpire: mode === "kill" ? 0.78 : 1.08,
    });
    setAutoPilotReceiveMomentum(player, mode, incomingPoint, firstTouchQuality, directionAngle, touchDistance);
    return mode;
  }

  const controlOffset = getBallControlOffsetMeters();
  const currentControlPoint = getPlayerBallControlPoint(player);
  const desiredControlPoint = clampToPitch({
    x: currentControlPoint.x + Math.cos(directionAngle) * touchDistance,
    y: currentControlPoint.y + Math.sin(directionAngle) * touchDistance,
  });
  player.position = clampToPitch({
    x: desiredControlPoint.x - Math.cos(directionAngle) * controlOffset,
    y: desiredControlPoint.y - Math.sin(directionAngle) * controlOffset,
  });
  player.bodyAngle = directionAngle;
  state.ball.ownerPlayerId = player.id;
  state.ball.secondBallContext = null;
  keepSecurePossessionOnlyForOwner(player.id);
  state.ball.position = cloneVector(getPlayerBallControlPoint(player));
  state.ball.target = cloneVector(state.ball.position);
  setSecurePossessionAfterControlledTouch(player, state.ball.position, {
    quality: firstTouchQuality,
    reason: "controlled-reception",
    minDistanceToExpire: mode === "kill" ? 3.8 : 5.2,
    minTimeToExpire: mode === "kill" ? 0.82 : 1.18,
  });
  setAutoPilotReceiveMomentum(player, mode, incomingPoint, firstTouchQuality, directionAngle, touchDistance);

  return mode;
}

function shouldUseAutoPilotActiveFirstTouch(receiver, firstTouchQuality) {
  const requestedMode = state.draftStep?.firstTouchMode ?? state.ball.firstTouchMode;
  if (!state.draftStep?.autoGenerated || !requestedMode || requestedMode === "auto" || requestedMode === "kill") {
    return false;
  }

  const pressure = receiver ? getPlayerPressureLoad(receiver, getPlayerBallControlPoint(receiver)) : 1;
  return firstTouchQuality >= 0.56 && pressure <= 0.62;
}

function getLiveBallFocusPoint() {
  if (!state.ball.inTransit) {
    const owner = getBallOwner();
    if (owner) {
      return getPlayerBallControlPoint(owner);
    }
  }

  return state.ball.position;
}

function getSpacePassTargetPoint() {
  if (state.ball.actionType === "pass" && !state.ball.receiverPlayerId && state.ball.target) {
    return state.ball.target;
  }

  if (state.draftStep?.actionType === "pass" && !state.draftStep.receiverPlayerId && state.draftStep.target) {
    return state.draftStep.target;
  }

  return null;
}

function getPlayerOrientationFocus(player) {
  const liveBallPoint = getLiveBallFocusPoint();
  const spacePassTarget = getSpacePassTargetPoint();

  if (!player || !spacePassTarget) {
    return {
      point: liveBallPoint,
      influenceRange: 11.5,
    };
  }

  const distanceToTarget = distance(player.position, spacePassTarget);
  const distanceToLiveBall = distance(player.position, liveBallPoint);
  const shouldPrioritizeTargetSpace =
    distanceToTarget <= 15.5 ||
    distanceToTarget <= distanceToLiveBall + 2.4;

  return {
    point: shouldPrioritizeTargetSpace ? spacePassTarget : liveBallPoint,
    influenceRange: shouldPrioritizeTargetSpace ? 14.5 : 11.5,
  };
}

function getActiveMovementTarget(playerId) {
  if (state.sequence.isPlaying && state.sequence.phase === "action" && state.sequence.actionTargets?.has(playerId)) {
    return state.sequence.actionTargets.get(playerId);
  }

  if (state.sequence.isPlaying && state.sequence.phase === "transition" && state.sequence.transition?.playerTargets?.has(playerId)) {
    return state.sequence.transition.playerTargets.get(playerId).end;
  }

  if (state.isRunning && state.activeActionTargets?.has(playerId)) {
    return state.activeActionTargets.get(playerId);
  }

  return null;
}

function isPlayerReservedForReceiveShape(player) {
  if (!player) {
    return false;
  }

  if (state.ball.actionType === "pass" && state.ball.receiverPlayerId === player.id) {
    return true;
  }

  if (state.draftStep?.actionType === "pass" && state.draftStep.receiverPlayerId === player.id) {
    return true;
  }

  if (state.sequence.isPlaying && state.sequence.phase === "action") {
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.actionType === "pass" && step.receiverPlayerId === player.id) {
      return true;
    }
  }

  return false;
}

function applyNearbyBallOrientation(dt) {
  const isLivePhase = state.isRunning || state.sequence.isPlaying;
  const draggedPlayerIds = new Set(
    state.drag?.type === "player"
      ? state.drag.playerIds ?? [state.drag.playerId].filter(Boolean)
      : []
  );

  state.players.forEach((player) => {
    if (draggedPlayerIds.has(player.id)) {
      return;
    }

    if (state.ball.ownerPlayerId === player.id || state.ball.carrierPlayerId === player.id) {
      return;
    }

    if (isPlayerReservedForReceiveShape(player)) {
      return;
    }

    const activeMovementTarget = getActiveMovementTarget(player.id);
    if (activeMovementTarget && distance(player.position, activeMovementTarget) > 0.08) {
      return;
    }

    const { point: focusPoint, influenceRange } = getPlayerOrientationFocus(player);
    if (!focusPoint) {
      return;
    }

    const distanceToBall = distance(player.position, focusPoint);
    const proximity = clamp(1 - (distanceToBall - 2.2) / influenceRange, 0, 1);
    if (proximity <= 0.001) {
      return;
    }

    const blend = clamp(
      dt * (isLivePhase ? 0.42 + proximity * 1.15 : 0.7 + proximity * 2.2),
      0,
      isLivePhase ? 0.07 : 0.12
    );
    const desiredAngle = getBallAwareBodyAngle(player, focusPoint);
    const maxTurn = dt * (isLivePhase ? 0.58 + proximity * 1.05 : 0.95 + proximity * 1.8);
    rotatePlayerBodyTowardAngle(player, desiredAngle, blend, maxTurn);
  });
}

function getPotentialPassReceiverAtTarget(initiator, target, receiverPlayerId = null) {
  if (!initiator || !target) {
    return null;
  }

  if (receiverPlayerId) {
    return getPlayerById(receiverPlayerId);
  }

  return state.players
    .filter((player) => player.team === initiator.team && player.id !== initiator.id)
    .map((player) => ({
      player,
      gap: distance(getPlayerBallControlPoint(player), target),
    }))
    .filter((entry) => entry.gap <= 2.2)
    .sort((a, b) => a.gap - b.gap)[0]?.player ?? null;
}

function getPassLaneRiskProfile(initiator, target, options = {}) {
  if (!initiator) {
    return {
      clarity: 0.72,
      obstruction: 0,
      timingRisk: 0,
      coverShadow: 0,
      interceptors: 0,
      averageSpeed: 11.5,
    };
  }

  const context = getPlayerDecisionContext(initiator);
  const startPoint = getPlayerBallControlPoint(initiator);
  const receiver = getPotentialPassReceiverAtTarget(initiator, target, options.receiverPlayerId ?? null);
  const ballProfile = resolveAutoBallProfile("pass", startPoint, target, initiator, receiver?.id ?? null);
  const laneLength = Math.max(distance(startPoint, target), 0.01);
  const averageSpeed = Math.max(ballProfile.averageSpeed ?? 11.5, 0.01);
  const isAerial = isAerialFlightStyle(ballProfile.flightStyle);
  const landingStart = ballProfile.landingPhaseStart ?? 0.58;
  let obstruction = 0;
  let timingRisk = 0;
  let coverShadow = 0;
  let interceptors = 0;

  state.players.forEach((player) => {
    if (player.team === initiator.team) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, target);
    const lanePoint = projection.point;
    const laneProgress = clamp(projection.ratio, 0, 1);
    if (laneProgress < 0.07 || laneProgress > 0.96) {
      return;
    }

    const laneDistance = distance(player.position, lanePoint);
    const laneWidth = lerp(2.15, 4.65, clamp(laneLength / 34, 0, 1)) * (isAerial ? 0.78 : 1);
    if (laneDistance > laneWidth + 3.2) {
      return;
    }

    const centrality = 1 - Math.abs(0.5 - laneProgress) * 1.4;
    const coverInfluence = getCoverShadowInfluence(player, lanePoint, startPoint);
    const ballTimeToLane = (laneLength * laneProgress) / averageSpeed;
    const defenderReachDistance = Math.max(
      laneDistance - playerRadiusMeters * 0.68 - ballRadiusMeters * 0.42,
      0
    );
    const defenderTimeToLane = computeTimeToCoverDistance(player, defenderReachDistance, lanePoint);
    const aerialControlFactor = isAerial
      ? laneProgress >= landingStart
        ? 0.96
        : lerp(0.24, 0.58, laneProgress / Math.max(landingStart, 0.01))
      : 1;
    const timingFit = clamp((ballTimeToLane - defenderTimeToLane + 0.28) / 0.9, 0, 1);
    const staticBlock = clamp(1 - laneDistance / Math.max(laneWidth + 1.2, 0.01), 0, 1);
    const readQuality =
      player.intelligenceProfile.perception * 0.36 +
      player.intelligenceProfile.decisionSpeed * 0.26 +
      player.intelligenceProfile.tacticalDiscipline * 0.18 +
      player.intelligenceProfile.technicalSecurity * 0.1;
    const segmentRisk =
      staticBlock *
      Math.max(0.22, centrality) *
      aerialControlFactor *
      (0.38 + timingFit * 0.72 + coverInfluence * 0.24) *
      (0.74 + readQuality * 0.34);

    obstruction +=
      staticBlock * Math.max(0.25, centrality) * aerialControlFactor * (0.72 + coverInfluence * 0.42);
    timingRisk = Math.max(timingRisk, segmentRisk);
    coverShadow += coverInfluence * staticBlock * aerialControlFactor;
    if (segmentRisk >= 0.5) {
      interceptors += 1;
    }
  });

  const clarity = clamp(
    0.34 +
      context.profile.perception * 0.28 +
      context.profile.decisionQuality * 0.16 +
      context.profile.technicalSecurity * 0.1 -
      obstruction * 0.1 -
      timingRisk * 0.2 -
      Math.min(coverShadow, 2.4) * 0.035 -
      Math.min(interceptors, 3) * 0.045 -
      context.pressure * 0.1,
    0.12,
    0.98
  );

  return {
    clarity,
    obstruction,
    timingRisk,
    coverShadow,
    interceptors,
    averageSpeed,
  };
}

function computePassLaneClarity(initiator, target, options = {}) {
  return getPassLaneRiskProfile(initiator, target, options).clarity;
}

function getGoalMouthTarget(teamId, y, netDepth = 2.6) {
  const side = getOpponentGoalSide(teamId);
  const sign = getGoalDirectionSign(side);
  const goalLineX = getGoalLineX(side);
  const postPadding = 0.18;

  return {
    x: goalLineX + sign * netDepth,
    y: clamp(y, pitch.width / 2 - 7.32 / 2 + postPadding, pitch.width / 2 + 7.32 / 2 - postPadding),
  };
}

function getShotAngleQuality(startPoint, teamId) {
  if (!startPoint || !teamId) {
    return 0.42;
  }

  const goalLineX = getGoalLineX(getOpponentGoalSide(teamId));
  const upperPost = { x: goalLineX, y: pitch.width / 2 - 7.32 / 2 };
  const lowerPost = { x: goalLineX, y: pitch.width / 2 + 7.32 / 2 };
  const openAngle = angleDifference(
    angleBetween(startPoint, upperPost),
    angleBetween(startPoint, lowerPost)
  );

  return clamp((openAngle - 0.055) / 0.62, 0, 1);
}

function getShotBlockRisk(shooter, target) {
  if (!shooter || !target) {
    return 0.18;
  }

  const startPoint = getPlayerBallControlPoint(shooter);
  const laneLength = Math.max(distance(startPoint, target), 0.01);
  const shotProfile = resolveAutoBallProfile("shot", startPoint, target, shooter, null);
  const averageShotSpeed = Math.max(shotProfile.averageSpeed ?? 18, 0.01);
  let obstruction = 0;

  state.players.forEach((player) => {
    if (player.team === shooter.team || isGoalkeeper(player)) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, target);
    if (projection.ratio <= 0.05 || projection.ratio >= 0.96) {
      return;
    }

    const laneGap = distance(player.position, projection.point);
    const laneWidth = lerp(3.15, 4.75, clamp(laneLength / 34, 0, 1));
    if (laneGap > laneWidth) {
      return;
    }

    const ballTimeToLane = (laneLength * projection.ratio) / averageShotSpeed;
    const defenderTimeToLane = computeTimeToCoverDistance(
      player,
      distance(player.position, projection.point),
      projection.point
    );
    const timingFit = clamp((ballTimeToLane - defenderTimeToLane + 0.32) / 0.92, 0, 1);
    const progressWeight = projection.ratio < 0.28 ? 0.85 : projection.ratio < 0.72 ? 1 : 0.74;
    const coverInfluence = getCoverShadowInfluence(player, projection.point, startPoint);

    obstruction +=
      (1 - laneGap / laneWidth) *
      progressWeight *
      (0.48 + timingFit * 0.72) *
      (0.78 + coverInfluence * 0.34);
  });

  return clamp(obstruction * 0.38, 0, 0.94);
}

function getGoalkeeperTargetOpenness(teamId, target) {
  const goalkeeper = getGoalkeeperForTeam(getOtherTeamId(teamId));
  if (!goalkeeper || !target) {
    return 0.58;
  }

  const side = getOpponentGoalSide(teamId);
  const sign = getGoalDirectionSign(side);
  const savePoint = clampToPitch({
    x: getGoalLineX(side) - sign * 0.9,
    y: target.y,
  }, 0.25);
  const context = getPlayerDecisionContext(goalkeeper);
  const gap = distance(goalkeeper.position, savePoint);
  const reachProfile =
    1.25 +
    context.profile.perception * 0.42 +
    context.profile.decisionSpeed * 0.32 +
    clamp(context.maxSpeed / 8.2, 0, 1) * 0.46;

  return clamp((gap - reachProfile * 0.72) / 6.2, 0, 1);
}

function computeShotLaneClarity(shooter, target) {
  if (!shooter) {
    return 0.62;
  }

  const context = getPlayerDecisionContext(shooter);
  const blockRisk = getShotBlockRisk(shooter, target);
  const angleQuality = getShotAngleQuality(getPlayerBallControlPoint(shooter), shooter.team);
  const goalkeeperOpenness = getGoalkeeperTargetOpenness(shooter.team, target);

  return clamp(
    0.3 +
      context.profile.perception * 0.17 +
      context.profile.decisionQuality * 0.15 +
      context.profile.technicalSecurity * 0.12 +
      angleQuality * 0.22 +
      goalkeeperOpenness * 0.18 -
      blockRisk * 0.58 -
      context.pressure * 0.12,
    0.08,
    0.98
  );
}

function getShotWindowProfile(shooter, startPoint, target) {
  const teamId = shooter?.team;
  const goal = teamId ? getOpponentGoalCenter(teamId) : target;
  const goalDistance = distance(startPoint, goal);
  const centrality = 1 - Math.abs(startPoint.y - pitch.width / 2) / (pitch.width / 2);
  const angleQuality = teamId ? getShotAngleQuality(startPoint, teamId) : 0.42;
  const blockRisk = getShotBlockRisk(shooter, target);
  const laneClarity = computeShotLaneClarity(shooter, target);
  const goalkeeperOpenness = teamId ? getGoalkeeperTargetOpenness(teamId, target) : 0.58;
  const pressure = shooter ? getPlayerPressureLoad(shooter, getPlayerBallControlPoint(shooter)) : 0.5;
  const finisherStrength = getAutoPilotRoleStrength(shooter, "finisher");
  const quality = clamp(
    angleQuality * 0.28 +
      laneClarity * 0.26 +
      goalkeeperOpenness * 0.18 +
      finisherStrength * 0.18 +
      centrality * 0.1 -
      pressure * 0.18,
    0,
    1
  );

  return {
    goalDistance,
    centrality,
    angleQuality,
    blockRisk,
    laneClarity,
    goalkeeperOpenness,
    pressure,
    finisherStrength,
    quality,
  };
}

function getDeterministicShotNoise(seedText, salt = 0) {
  const text = `${seedText}|${salt}`;
  let hash = 2166136261;
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  const value = Math.sin((hash >>> 0) * 12.9898 + salt * 78.233) * 43758.5453;
  return (value - Math.floor(value)) * 2 - 1;
}

function resolveExecutedShotTarget(shooter, intendedTarget, ballProfile = null) {
  if (!shooter || !intendedTarget) {
    state.ball.shotPlacement = null;
    return intendedTarget ? cloneVector(intendedTarget) : null;
  }

  const startPoint = cloneVector(state.ball.startPosition ?? getPlayerBallControlPoint(shooter));
  const shotWindow = getShotWindowProfile(shooter, startPoint, intendedTarget);
  const context = getPlayerDecisionContext(shooter);
  const footExecutionScore = getFootUsageScore(shooter, angleBetween(shooter.position, intendedTarget));
  const executionQuality = clamp(
    state.ball.executionQuality ??
      (context.profile.technicalSecurity * 0.28 +
        context.profile.executionUnderPressure * 0.22 +
        context.profile.composure * 0.16 +
        context.profile.decisionQuality * 0.14 +
        footExecutionScore * 0.1 +
        shotWindow.laneClarity * 0.1),
    0.36,
    0.98
  );
  const side = getOpponentGoalSide(shooter.team);
  const sign = getGoalDirectionSign(side);
  const goalLineX = getGoalLineX(side);
  const intendedSideValue = (intendedTarget.x - goalLineX) * sign;
  const intendedIsGoalward = intendedSideValue >= -1.25;
  const targetKind = ballProfile?.targetKind ?? state.ball.targetKind ?? "shot";
  const distanceStress = clamp((shotWindow.goalDistance - 13) / 30, 0, 1);
  const pressureStress = clamp(shotWindow.pressure, 0, 1);
  const angleStress = 1 - shotWindow.angleQuality;
  const blockStress = clamp(shotWindow.blockRisk, 0, 1);
  const opennessStress = 1 - shotWindow.goalkeeperOpenness;
  const missRisk = clamp(
    0.035 +
      distanceStress * 0.16 +
      pressureStress * 0.2 +
      angleStress * 0.15 +
      blockStress * 0.13 +
      opennessStress * 0.06 -
      executionQuality * 0.22 -
      shotWindow.finisherStrength * 0.08,
    0.02,
    0.42
  );
  const seed = [
    shooter.id,
    state.sequence.steps.length,
    startPoint.x.toFixed(2),
    startPoint.y.toFixed(2),
    intendedTarget.x.toFixed(2),
    intendedTarget.y.toFixed(2),
    targetKind,
    state.ball.profileKey ?? "",
  ].join("|");
  const lateralNoise = getDeterministicShotNoise(seed, 1);
  const shapeNoise = getDeterministicShotNoise(seed, 2);
  const mistakeNoise = getDeterministicShotNoise(seed, 3);
  const baseSpread =
    0.16 +
    shotWindow.goalDistance * 0.015 +
    pressureStress * 0.82 +
    blockStress * 0.58 +
    angleStress * 0.42 +
    (1 - executionQuality) * 1.15;
  const missBurst = mistakeNoise > 1 - missRisk * 2
    ? Math.sign(lateralNoise || 1) * lerp(0.55, 1.75, clamp(missRisk / 0.42, 0, 1))
    : 0;
  const lateralError = lateralNoise * baseSpread + shapeNoise * baseSpread * 0.34 + missBurst;
  const executedTarget = {
    x: intendedIsGoalward ? goalLineX + sign * 2.6 : intendedTarget.x,
    y: clamp(intendedTarget.y + lateralError, 0.4, pitch.width - 0.4),
  };

  state.ball.shotPlacement = {
    intendedTarget: cloneVector(intendedTarget),
    executedTarget: cloneVector(executedTarget),
    errorMeters: Math.abs(lateralError),
    missRisk,
    executionQuality,
    pressure: pressureStress,
    angleQuality: shotWindow.angleQuality,
    blockRisk: shotWindow.blockRisk,
    goalDistance: shotWindow.goalDistance,
  };

  return executedTarget;
}

function getAttackDirectionSign(teamId) {
  return teamId === "home" ? 1 : -1;
}

function getAttackingDepth(point, teamId) {
  return teamId === "home" ? point.x : pitch.length - point.x;
}

function getOpponentGoalCenter(teamId) {
  return vec(teamId === "home" ? pitch.length : 0, pitch.width / 2);
}

function getDepthZoneKey(point, teamId) {
  const depth = getAttackingDepth(point, teamId);
  if (depth < 24) return "firstLine";
  if (depth < 42) return "buildUp";
  if (depth < 64) return "progression";
  if (depth < 83) return "creation";
  if (depth < 100) return "box";
  return "goalLine";
}

function getDepthZoneLabel(depthZoneKey) {
  const labels = {
    firstLine: "first build-up space",
    buildUp: "build-up space",
    progression: "progression space",
    creation: "chance-creation space",
    box: "box space",
    goalLine: "goal-line space",
  };

  return labels[depthZoneKey] ?? "open space";
}

function getLaneLabel(laneKey) {
  const labels = {
    leftWide: "left wide corridor",
    leftHalf: "left half-space",
    central: "central corridor",
    rightHalf: "right half-space",
    rightWide: "right wide corridor",
  };

  return labels[laneKey] ?? "corridor";
}

function getGoldenZoneScore(point, teamId) {
  if (!point || !teamId) {
    return 0;
  }

  const depth = getAttackingDepth(point, teamId);
  const centralDistance = Math.abs(point.y - pitch.width / 2);
  const centrality = clamp(1 - centralDistance / 15.5, 0, 1);
  const depthValue =
    depth < 56
      ? 0
      : depth < 68
        ? (depth - 56) / 12
        : depth <= 82
          ? 1
          : clamp(1 - (depth - 82) / 10, 0, 1);

  return clamp(depthValue * centrality, 0, 1);
}

function isGoldenZone(point, teamId, threshold = 0.52) {
  return getGoldenZoneScore(point, teamId) >= threshold;
}

function getMedianNumber(values, fallback = 0) {
  const finiteValues = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!finiteValues.length) {
    return fallback;
  }

  const middle = Math.floor(finiteValues.length / 2);
  return finiteValues.length % 2
    ? finiteValues[middle]
    : (finiteValues[middle - 1] + finiteValues[middle]) / 2;
}

function getDepthQuantile(values, ratio, fallback = 0) {
  const finiteValues = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!finiteValues.length) {
    return fallback;
  }

  const index = clamp(Math.round((finiteValues.length - 1) * ratio), 0, finiteValues.length - 1);
  return finiteValues[index];
}

function getOpponentLineDepthsForAttackingTeam(teamId, referencePoint = state.ball.position) {
  const opponentTeamId = getOtherTeamId(teamId);
  if (!opponentTeamId) {
    return {
      forward: 34,
      midfield: 54,
      back: 78,
      gk: pitch.length - 2,
    };
  }

  const formation = teams[opponentTeamId]?.formation ?? "4-3-3";
  const phaseKey = getDefensivePhaseKey(opponentTeamId, referencePoint ?? state.ball.position);
  const lineDepths = {
    forward: [],
    midfield: [],
    back: [],
    gk: [],
  };
  const fieldDepths = [];

  state.players
    .filter((player) => player.team === opponentTeamId)
    .forEach((player) => {
      const lineKey = getDefensiveAutopilotLineKey(player, formation, phaseKey);
      const depth = getAttackingDepth(player.position, teamId);
      if (lineDepths[lineKey]) {
        lineDepths[lineKey].push(depth);
      }

      if (lineKey !== "gk") {
        fieldDepths.push(depth);
      }
    });

  let forward = getMedianNumber(lineDepths.forward, getDepthQuantile(fieldDepths, 0.2, 34));
  let midfield = getMedianNumber(lineDepths.midfield, getDepthQuantile(fieldDepths, 0.5, 54));
  let back = getMedianNumber(lineDepths.back, getDepthQuantile(fieldDepths, 0.82, 78));
  let gk = getMedianNumber(lineDepths.gk, pitch.length - 2);

  forward = clamp(forward, 8, pitch.length - 32);
  midfield = clamp(Math.max(midfield, forward + 6.5), forward + 6.5, pitch.length - 20);
  back = clamp(Math.max(back, midfield + 7), midfield + 7, pitch.length - 8);
  gk = clamp(Math.max(gk, back + 5.5), back + 5.5, pitch.length);

  return {
    forward,
    midfield,
    back,
    gk,
  };
}

function getAttackingGameSpaceProfile(point, teamId) {
  if (!point || !teamId) {
    return {
      key: "outlet",
      label: "outlet space",
      index: 0,
      depth: 0,
      size: 0,
      nextLineDepth: 34,
      previousLineDepth: 0,
      lineDepths: getOpponentLineDepthsForAttackingTeam(teamId, point),
    };
  }

  const depth = getAttackingDepth(point, teamId);
  const lineDepths = getOpponentLineDepthsForAttackingTeam(teamId, point);
  const spaces = [
    {
      key: "outlet",
      label: "outlet space",
      index: 0,
      from: 0,
      to: lineDepths.forward,
    },
    {
      key: "space1",
      label: "space 1",
      index: 1,
      from: lineDepths.forward,
      to: lineDepths.midfield,
    },
    {
      key: "space2",
      label: "space 2",
      index: 2,
      from: lineDepths.midfield,
      to: lineDepths.back,
    },
    {
      key: "space3",
      label: "space 3",
      index: 3,
      from: lineDepths.back,
      to: lineDepths.gk,
    },
  ];
  const activeSpace =
    spaces.find((space) => depth >= space.from - 0.5 && depth < space.to + 0.5) ??
    spaces[spaces.length - 1];

  return {
    ...activeSpace,
    depth,
    size: Math.max(0, activeSpace.to - activeSpace.from),
    nextLineDepth: activeSpace.to,
    previousLineDepth: activeSpace.from,
    lineDepths,
  };
}

function getPitchSpaceProfile(point, teamId) {
  if (!point || !teamId) {
    return {
      laneKey: "central",
      laneLabel: "central corridor",
      depthZoneKey: "buildUp",
      depthZoneLabel: "build-up space",
      gameSpaceKey: "outlet",
      gameSpaceLabel: "outlet space",
      gameSpaceIndex: 0,
      gameSpaceSize: 0,
      centralPocket: 0,
      halfSpace: 0,
      wideCorridor: 0,
      betweenLines: 0,
      assistZone: 0,
      cutbackZone: 0,
      box: 0,
      behindLine: 0,
      depth: 0,
      centrality: 0,
      value: 0,
      primaryLabel: "open space",
    };
  }

  const depth = getAttackingDepth(point, teamId);
  const centralDistance = Math.abs(point.y - pitch.width / 2);
  const centrality = clamp(1 - centralDistance / (pitch.width / 2), 0, 1);
  const laneKey = getPitchLaneKey(point);
  const depthZoneKey = getDepthZoneKey(point, teamId);
  const isHalfSpaceLane = laneKey === "leftHalf" || laneKey === "rightHalf";
  const isWideLane = laneKey === "leftWide" || laneKey === "rightWide";
  const gameSpace = getAttackingGameSpaceProfile(point, teamId);
  const centralPocket = getGoldenZoneScore(point, teamId);
  const dynamicBetweenLines = gameSpace.key === "space2"
    ? clamp(gameSpace.size / 18, 0.25, 1) *
      clamp(0.42 + centrality * 0.26 + (isHalfSpaceLane ? 0.18 : 0) - (isWideLane ? 0.12 : 0), 0, 1)
    : 0;
  const dynamicBehindLine = gameSpace.key === "space3"
    ? clamp(gameSpace.size / 15, 0.18, 1) *
      clamp(0.38 + centrality * 0.2 + (isHalfSpaceLane ? 0.12 : 0), 0, 1)
    : 0;
  const dynamicSpaceOne = gameSpace.key === "space1"
    ? clamp(gameSpace.size / 20, 0.2, 1) *
      clamp(0.22 + centrality * 0.18 + (isHalfSpaceLane ? 0.1 : 0), 0, 0.62)
    : 0;
  const halfSpace = isHalfSpaceLane && depth >= 42 && depth <= 88
    ? clamp(0.28 + (depth >= 58 ? 0.34 : 0.12) + (depth >= 72 ? 0.18 : 0), 0, 1)
    : 0;
  const wideCorridor = isWideLane && depth >= 34
    ? clamp(0.22 + (depth >= 58 ? 0.22 : 0) + (depth >= 74 ? 0.18 : 0), 0, 0.82)
    : 0;
  const betweenLines = Math.max(
    depth >= 42 && depth <= 74 && centralDistance <= 23
      ? clamp(0.34 + centrality * 0.24 + (isHalfSpaceLane ? 0.16 : 0), 0, 1)
      : 0,
    dynamicBetweenLines
  );
  const box = depth >= 83 && depth <= 100
    ? clamp((1 - centralDistance / 22) * 0.78 + (depth >= 88 ? 0.22 : 0), 0, 1)
    : 0;
  const assistZone = depth >= 70 && depth <= 96 && centralDistance >= 18
    ? clamp((depth - 70) / 18, 0, 1) * clamp((centralDistance - 18) / 12, 0, 1)
    : 0;
  const cutbackZone = depth >= 84 && depth <= 98 && centralDistance >= 8 && centralDistance <= 24
    ? clamp((depth - 84) / 8, 0, 1) * clamp(1 - Math.abs(centralDistance - 15) / 10, 0, 1)
    : 0;
  const behindLine = Math.max(
    depth >= 78
      ? clamp((depth - 78) / 14, 0, 1) * clamp(1 - centralDistance / 30, 0, 1)
      : 0,
    dynamicBehindLine
  );
  const value = clamp(
    centralPocket * 0.24 +
      betweenLines * 0.2 +
      dynamicSpaceOne * 0.06 +
      halfSpace * 0.16 +
      wideCorridor * 0.08 +
      assistZone * 0.16 +
      cutbackZone * 0.2 +
      box * 0.3 +
      behindLine * 0.18,
    0,
    1
  );
  const primaryLabel =
    box >= 0.4
      ? "box space"
      : cutbackZone >= 0.42
        ? "cutback space"
        : centralPocket >= 0.42
          ? "central pocket"
          : betweenLines >= 0.42
            ? "between-lines space"
            : assistZone >= 0.42
              ? "assist corridor"
              : halfSpace >= 0.42
                ? getLaneLabel(laneKey)
                : wideCorridor >= 0.42
                  ? getLaneLabel(laneKey)
                  : getDepthZoneLabel(depthZoneKey);

  return {
    laneKey,
    laneLabel: getLaneLabel(laneKey),
    depthZoneKey,
    depthZoneLabel: getDepthZoneLabel(depthZoneKey),
    gameSpaceKey: gameSpace.key,
    gameSpaceLabel: gameSpace.label,
    gameSpaceIndex: gameSpace.index,
    gameSpaceSize: gameSpace.size,
    opponentLineDepths: gameSpace.lineDepths,
    centralPocket,
    zone14: centralPocket,
    halfSpace,
    wideCorridor,
    betweenLines,
    assistZone,
    cutbackZone,
    box,
    behindLine,
    depth,
    centrality,
    value,
    primaryLabel,
  };
}

function getPitchThreatProfile(point, teamId) {
  if (!point || !teamId) {
    return {
      value: 0,
      goldenZone: 0,
      centralPocket: 0,
      zone14: 0,
      box: 0,
      assistZone: 0,
      cutbackZone: 0,
      halfSpace: 0,
      wideCorridor: 0,
      betweenLines: 0,
      behindLine: 0,
      centrality: 0,
      depth: 0,
      laneKey: "central",
      laneLabel: "central corridor",
      depthZoneKey: "buildUp",
      depthZoneLabel: "build-up space",
      gameSpaceKey: "outlet",
      gameSpaceLabel: "outlet space",
      gameSpaceIndex: 0,
      gameSpaceSize: 0,
      primaryLabel: "open space",
    };
  }

  const space = getPitchSpaceProfile(point, teamId);
  const value = clamp(
    space.value +
      (space.depth >= 58 ? space.centrality * 0.06 : 0),
    0,
    1
  );

  return {
    value,
    goldenZone: space.centralPocket,
    centralPocket: space.centralPocket,
    zone14: space.centralPocket,
    box: space.box,
    assistZone: space.assistZone,
    cutbackZone: space.cutbackZone,
    halfSpace: space.halfSpace,
    wideCorridor: space.wideCorridor,
    betweenLines: space.betweenLines,
    behindLine: space.behindLine,
    centrality: space.centrality,
    depth: space.depth,
    laneKey: space.laneKey,
    laneLabel: space.laneLabel,
    depthZoneKey: space.depthZoneKey,
    depthZoneLabel: space.depthZoneLabel,
    gameSpaceKey: space.gameSpaceKey,
    gameSpaceLabel: space.gameSpaceLabel,
    gameSpaceIndex: space.gameSpaceIndex,
    gameSpaceSize: space.gameSpaceSize,
    opponentLineDepths: space.opponentLineDepths,
    primaryLabel: space.primaryLabel,
  };
}

function getOpponentPressureAtPoint(teamId, point, radius = 14) {
  if (!teamId || !point) {
    return 1;
  }

  let pressure = 0;
  state.players.forEach((player) => {
    if (player.team === teamId) {
      return;
    }

    const gap = distance(player.position, point);
    if (gap > radius) {
      return;
    }

    const closeWeight = gap <= 3.5 ? 1.1 : gap <= 7 ? 0.76 : 0.38;
    pressure += (1 - gap / radius) * closeWeight;
  });

  return clamp(pressure / 1.85, 0, 1);
}

function getNearestOpponentGapToPoint(teamId, point) {
  if (!teamId || !point) {
    return Infinity;
  }

  return state.players.reduce((nearest, player) => {
    if (player.team === teamId) {
      return nearest;
    }

    return Math.min(nearest, distance(player.position, point));
  }, Infinity);
}

function getOpponentsBypassedByAction(startPoint, targetPoint, teamId) {
  if (!startPoint || !targetPoint || !teamId) {
    return 0;
  }

  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  if (forwardGain <= 3) {
    return 0;
  }

  const startDepth = getAttackingDepth(startPoint, teamId);
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  const laneLength = Math.max(distance(startPoint, targetPoint), 0.01);

  return state.players.reduce((count, player) => {
    if (player.team === teamId) {
      return count;
    }

    const playerDepth = getAttackingDepth(player.position, teamId);
    if (playerDepth <= startDepth + 1.5 || playerDepth >= targetDepth - 1) {
      return count;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, targetPoint);
    if (projection.ratio <= 0.08 || projection.ratio >= 0.96) {
      return count;
    }

    const laneGap = distance(player.position, projection.point);
    const laneWidth = lerp(5.2, 8.8, clamp(laneLength / 36, 0, 1));
    return count + (laneGap <= laneWidth ? 1 : 0);
  }, 0);
}

function getFootballSpacePriority(startPoint, targetPoint, teamId, profile = {}) {
  if (!startPoint || !targetPoint || !teamId) {
    return {
      score: 0,
      label: "open space",
      targetSpace: getPitchSpaceProfile(targetPoint, teamId),
      startSpace: getPitchSpaceProfile(startPoint, teamId),
      lineBreakCount: 0,
      forwardGain: 0,
      targetPressure: 1,
      gameSpaceGain: 0,
      targetGameSpaceKey: "outlet",
      startGameSpaceKey: "outlet",
    };
  }

  const targetSpace = getPitchSpaceProfile(targetPoint, teamId);
  const startSpace = getPitchSpaceProfile(startPoint, teamId);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const gameSpaceGain = (targetSpace.gameSpaceIndex ?? 0) - (startSpace.gameSpaceIndex ?? 0);
  const lineBreakCount = getOpponentsBypassedByAction(startPoint, targetPoint, teamId);
  const targetPressure = getOpponentPressureAtPoint(teamId, targetPoint);
  const wideStyle = clamp(
    (profile.widthDiscipline ?? 0.48) * 0.34 +
      (profile.crossBias ?? 0.42) * 0.28 +
      (profile.overlapBias ?? 0.42) * 0.28 +
      (profile.switchBias ?? 0.42) * 0.1,
    0,
    1
  );
  const centralStyle = clamp(
    (profile.shortSupport ?? 0.5) * 0.25 +
      (profile.lineBreakBias ?? 0.5) * 0.28 +
      (profile.progressionUrgency ?? 0.5) * 0.25 +
      (profile.tempo ?? 0.5) * 0.22,
    0,
    1
  );
  const verticalStyle = clamp(
    (profile.directness ?? 0.5) * 0.36 +
      (profile.lineBreakBias ?? 0.5) * 0.32 +
      (profile.carryBias ?? 0.42) * 0.16 +
      (profile.risk ?? 0.42) * 0.16,
    0,
    1
  );
  const progressionValue = clamp(forwardGain / 22, -0.18, 0.78);
  const threatGain = targetSpace.value - startSpace.value;
  const centralAccess =
    targetSpace.centralPocket * (0.42 + centralStyle * 0.24) +
    targetSpace.betweenLines * (0.38 + centralStyle * 0.26);
  const halfSpaceAccess =
    targetSpace.halfSpace * (0.22 + centralStyle * 0.16 + wideStyle * 0.14) +
    (targetSpace.assistZone >= 0.38 ? targetSpace.assistZone * (0.18 + wideStyle * 0.22) : 0);
  const wideAccess =
    targetSpace.wideCorridor * (0.08 + wideStyle * 0.3) +
    targetSpace.assistZone * (0.2 + wideStyle * 0.28);
  const finalActionAccess =
    targetSpace.box * 0.52 +
    targetSpace.cutbackZone * (0.34 + wideStyle * 0.24) +
    targetSpace.behindLine * (0.22 + verticalStyle * 0.34 + (lineBreakCount >= 1 ? 0.18 : 0));
  const lineBreakValue = clamp(lineBreakCount / 3, 0, 1) * (0.18 + verticalStyle * 0.28);
  const gameSpaceEntryValue = clamp(gameSpaceGain / 2, 0, 1) * (0.2 + verticalStyle * 0.2);
  const targetGameSpaceValue =
    targetSpace.gameSpaceKey === "space3"
      ? 0.22 + verticalStyle * 0.22 + targetSpace.centrality * 0.08
      : targetSpace.gameSpaceKey === "space2"
        ? 0.16 + centralStyle * 0.22 + targetSpace.centrality * 0.08 + (targetSpace.halfSpace >= 0.34 ? 0.08 : 0)
        : targetSpace.gameSpaceKey === "space1" && forwardGain >= 3
          ? 0.08 + centralStyle * 0.08
          : 0;
  const openTargetValue = clamp((getNearestOpponentGapToPoint(teamId, targetPoint) - 2.4) / 9.2, 0, 1) * 0.12;
  const lowValueWidePenalty =
    targetSpace.wideCorridor >= 0.42 &&
    targetSpace.depth < 62 &&
    forwardGain < 4 &&
    targetSpace.assistZone < 0.24
      ? 0.18 - wideStyle * 0.08
      : 0;
  const sterileRecyclePenalty =
    forwardGain < 1.5 &&
    targetSpace.value <= startSpace.value + 0.03 &&
    targetSpace.depth < 72
      ? 0.22 + (profile.progressionUrgency ?? 0.5) * 0.16
      : 0;
  const backwardsSpacePenalty =
    gameSpaceGain < 0 &&
    targetSpace.value <= startSpace.value + 0.04 &&
    targetPressure < 0.62
      ? Math.abs(gameSpaceGain) * (0.16 + (profile.progressionUrgency ?? 0.5) * 0.08)
      : 0;
  const pressurePenalty = targetPressure * (targetSpace.depth >= 64 ? 0.18 : 0.12);
  const score = clamp(
    centralAccess +
      halfSpaceAccess +
      wideAccess +
      finalActionAccess +
      targetGameSpaceValue +
      Math.max(0, threatGain) * 0.34 +
      progressionValue * 0.22 +
      lineBreakValue +
      gameSpaceEntryValue +
      openTargetValue -
      pressurePenalty -
      lowValueWidePenalty -
      sterileRecyclePenalty,
    -0.55,
    1.2
  );
  const adjustedScore = clamp(
    score - backwardsSpacePenalty,
    -0.55,
    1.2
  );

  return {
    score: adjustedScore,
    label: targetSpace.primaryLabel,
    targetSpace,
    startSpace,
    lineBreakCount,
    forwardGain,
    targetPressure,
    threatGain,
    gameSpaceGain,
    targetGameSpaceKey: targetSpace.gameSpaceKey,
    startGameSpaceKey: startSpace.gameSpaceKey,
    centralAccess,
    halfSpaceAccess,
    wideAccess,
    finalActionAccess,
  };
}

function getActionSpaceValue(startPoint, targetPoint, teamId, profile = {}) {
  const targetThreat = getPitchThreatProfile(targetPoint, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const threatGain = targetThreat.value - startThreat.value;
  const targetPressure = getOpponentPressureAtPoint(teamId, targetPoint);
  const nearestOpponentGap = getNearestOpponentGapToPoint(teamId, targetPoint);
  const openTarget = Number.isFinite(nearestOpponentGap)
    ? clamp((nearestOpponentGap - 2.2) / 8.8, 0, 1)
    : 1;
  const lineBreakCount = getOpponentsBypassedByAction(startPoint, targetPoint, teamId);
  const progressionValue = clamp(forwardGain / 24, -0.2, 0.85);
  const centralLaneValue =
    Math.abs(targetPoint.y - pitch.width / 2) <= 20 && targetThreat.depth >= 42
      ? 0.16
      : 0;
  const spacePriority = getFootballSpacePriority(startPoint, targetPoint, teamId, profile);
  const value = clamp(
    targetThreat.value * 0.28 +
      Math.max(0, threatGain) * 0.48 +
      progressionValue * 0.24 +
      openTarget * 0.16 +
      clamp(lineBreakCount / 3, 0, 1) * 0.26 +
      clamp(spacePriority.gameSpaceGain / 2, 0, 1) * 0.18 +
      spacePriority.score * 0.34 +
      centralLaneValue -
      targetPressure * 0.12,
    0,
    1.35
  );

  return {
    value,
    targetPressure,
    nearestOpponentGap,
    openTarget,
    lineBreakCount,
    forwardGain,
    threatGain,
    targetThreat,
    startThreat,
    spacePriority,
    gameSpaceGain: spacePriority.gameSpaceGain,
    targetGameSpaceKey: spacePriority.targetGameSpaceKey,
    startGameSpaceKey: spacePriority.startGameSpaceKey,
  };
}

function getTeamDensityAtPoint(teamId, point, radius = 12, excludedIds = new Set()) {
  if (!teamId || !point) {
    return 0;
  }

  return state.players.reduce((count, player) => {
    if (player.team !== teamId || excludedIds.has(player.id) || isGoalkeeper(player)) {
      return count;
    }

    return count + (distance(player.position, point) <= radius ? 1 : 0);
  }, 0);
}

function getOpponentDensityAtPoint(teamId, point, radius = 12) {
  if (!teamId || !point) {
    return 0;
  }

  return state.players.reduce((count, player) => {
    if (player.team === teamId || isGoalkeeper(player)) {
      return count;
    }

    return count + (distance(player.position, point) <= radius ? 1 : 0);
  }, 0);
}

function getSpaceDominanceProfile(startPoint, targetPoint, teamId, profile = {}, options = {}) {
  if (!startPoint || !targetPoint || !teamId) {
    return {
      score: 0,
      labels: [],
      openAccess: 0,
      supportBalance: 0,
      congestion: 0,
      turnWindow: 0,
      lineBreakReward: 0,
      overloadAdvantage: 0,
      actionSpace: getActionSpaceValue(startPoint, targetPoint, teamId, profile),
    };
  }

  const actionType = options.actionType ?? "pass";
  const excludedIds = new Set(options.excludedIds ?? []);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const startThreat = actionSpace.startThreat;
  const forwardGain = actionSpace.forwardGain;
  const passDistance = distance(startPoint, targetPoint);
  const nearRadius = actionType === "dribble" ? 9.5 : passDistance >= 26 ? 14 : 11.5;
  const supportCount = getTeamDensityAtPoint(teamId, targetPoint, nearRadius, excludedIds);
  const opponentCount = getOpponentDensityAtPoint(teamId, targetPoint, nearRadius);
  const closeOpponents = getOpponentDensityAtPoint(teamId, targetPoint, 5.6);
  const nearestOpponentGap = Number.isFinite(actionSpace.nearestOpponentGap)
    ? actionSpace.nearestOpponentGap
    : getNearestOpponentGapToPoint(teamId, targetPoint);
  const openAccess = Number.isFinite(nearestOpponentGap)
    ? clamp((nearestOpponentGap - 2.4) / 8.6, 0, 1)
    : 1;
  const supportBalance = clamp((supportCount + 1) / Math.max(opponentCount + 1, 1), 0, 2.2);
  const overloadAdvantage = clamp((supportCount - opponentCount + 1) / 4, -0.35, 0.85);
  const congestion = clamp(
    opponentCount * 0.18 +
      closeOpponents * 0.26 +
      actionSpace.targetPressure * 0.38 -
      supportCount * 0.06,
    0,
    1.25
  );
  const targetIsValuable =
    targetThreat.value >= 0.46 ||
    targetThreat.betweenLines >= 0.44 ||
    targetThreat.centralPocket >= 0.4 ||
    targetThreat.halfSpace >= 0.46 ||
    targetThreat.box >= 0.26 ||
    targetThreat.cutbackZone >= 0.34;
  const turnWindow = clamp(
    openAccess * 0.46 +
      (supportBalance >= 1 ? 0.14 : 0) +
      (targetThreat.betweenLines >= 0.36 || targetThreat.halfSpace >= 0.42 ? 0.18 : 0) +
      (forwardGain >= 2 ? 0.12 : 0) -
      closeOpponents * 0.12,
    0,
    1
  );
  const lineBreakReward = clamp(
    actionSpace.lineBreakCount * 0.18 +
      Math.max(0, forwardGain) / 30 +
      Math.max(0, actionSpace.threatGain) * 0.42,
    0,
    1
  );
  const sterileArea =
    forwardGain < 2 &&
    targetThreat.value <= startThreat.value + 0.04 &&
    actionSpace.lineBreakCount === 0 &&
    targetThreat.depth < 72;
  const isolatedLongBall =
    actionType === "pass" &&
    passDistance >= 27 &&
    forwardGain >= 8 &&
    supportCount <= 0 &&
    targetThreat.box < 0.2 &&
    targetThreat.behindLine < 0.34;
  const dribbleIntoTraffic =
    actionType === "dribble" &&
    forwardGain >= 3 &&
    (closeOpponents >= 2 || (nearestOpponentGap <= 4.4 && actionSpace.lineBreakCount === 0));
  const score = clamp(
    actionSpace.value * 0.36 +
      actionSpace.spacePriority.score * 0.28 +
      openAccess * 0.2 +
      overloadAdvantage * 0.18 +
      turnWindow * 0.22 +
      lineBreakReward * 0.24 +
      (targetIsValuable && openAccess >= 0.46 ? 0.18 : 0) -
      congestion * (targetIsValuable ? 0.22 : 0.34) -
      (sterileArea ? 0.34 + (profile.progressionUrgency ?? 0.5) * 0.18 : 0) -
      (isolatedLongBall ? 0.42 + (1 - (profile.routeOneBias ?? 0)) * 0.18 : 0) -
      (dribbleIntoTraffic ? 0.46 - (profile.dribbleBias ?? 0.45) * 0.14 : 0),
    -0.95,
    1.05
  );
  const labels = [];

  if (targetIsValuable && openAccess >= 0.5) {
    labels.push(`Own ${targetThreat.primaryLabel}`);
  }

  if (turnWindow >= 0.58) {
    labels.push("Can receive on the turn");
  }

  if (overloadAdvantage >= 0.26 && targetThreat.depth >= 38) {
    labels.push("Local overload");
  }

  if (lineBreakReward >= 0.42) {
    labels.push("Space behind next line");
  }

  if (congestion >= 0.72 && !targetIsValuable) {
    labels.push("Avoid crowded space");
  }

  return {
    score,
    labels: uniquePrincipleLabels(labels),
    openAccess,
    supportBalance,
    supportCount,
    opponentCount,
    closeOpponents,
    congestion,
    turnWindow,
    lineBreakReward,
    overloadAdvantage,
    sterileArea,
    isolatedLongBall,
    dribbleIntoTraffic,
    targetIsValuable,
    actionSpace,
  };
}

function getAutoPilotSpaceDominanceAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier) {
    return {
      score: 0,
      labels: [],
      dominance: null,
    };
  }

  const excludedIds = [
    carrier.id,
    candidate.receiverPlayerId,
  ].filter(Boolean);
  const dominance = getSpaceDominanceProfile(startPoint, candidate.target, carrier.team, profile, {
    actionType: candidate.actionType,
    excludedIds,
  });
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetThreat = dominance.actionSpace.targetThreat;
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const labels = [...dominance.labels];
  let score = dominance.score;

  if (candidate.actionType === "pass") {
    if (
      dominance.turnWindow >= 0.56 &&
      forwardGain >= 1 &&
      passDistance <= 26 &&
      (targetThreat.betweenLines >= 0.34 || targetThreat.halfSpace >= 0.38 || targetThreat.centralPocket >= 0.28)
    ) {
      score += 0.2 + profile.shortSupport * 0.08;
      labels.push("Play into turn window");
    }

    if (dominance.isolatedLongBall && profile.routeOneBias < 0.56) {
      score -= 0.32;
    }

    if (
      dominance.sterileArea &&
      !candidate.isSwitch &&
      !candidate.isBoxPass &&
      profile.phaseKey !== "buildUp"
    ) {
      score -= 0.2 + profile.progressionUrgency * 0.18;
    }
  }

  if (candidate.actionType === "dribble") {
    if (dominance.openAccess >= 0.62 && forwardGain >= 5) {
      score += 0.18 + profile.carryBias * 0.12;
      labels.push("Carry into open lane");
    }

    if (dominance.dribbleIntoTraffic) {
      score -= 0.3;
    }
  }

  if (candidate.actionType === "shot") {
    score += targetThreat.box * 0.14 + targetThreat.centralPocket * 0.12;
    if (targetThreat.box >= 0.3 || targetThreat.centralPocket >= 0.42) {
      labels.push("Shot from high-value space");
    }
  }

  return {
    score: clamp(score, -1.1, 1.25),
    labels: uniquePrincipleLabels(labels),
    dominance,
  };
}

function getAutoPilotGameSpaceAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier || !startPoint) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const teamId = carrier.team;
  const startSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const targetSpace = getAttackingGameSpaceProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const startThreat = actionSpace.startThreat;
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const gameSpaceGain = targetSpace.index - startSpace.index;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const runner = candidate.principleRunnerPlayerId ? getPlayerById(candidate.principleRunnerPlayerId) : null;
  const excludedIds = new Set([carrier.id, receiver?.id, runner?.id].filter(Boolean));
  const supportNearTarget = getTeamSupportCountAroundPoint(teamId, candidate.target, excludedIds, passDistance >= 25 ? 16 : 12);
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver
      ? getPlayerPressureLoad(receiver, candidate.target)
      : actionSpace.targetPressure;
  const openTarget = actionSpace.openTarget;
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, candidate.target)
      : 0.62;
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.25);
  const labels = [];
  let score = 0;

  const entersSpaceTwo =
    targetSpace.key === "space2" &&
    gameSpaceGain >= 1 &&
    forwardGain >= 2 &&
    openTarget >= 0.36 &&
    laneClarity >= 0.34;
  const entersSpaceThree =
    targetSpace.key === "space3" &&
    gameSpaceGain >= 1 &&
    forwardGain >= 5 &&
    laneClarity >= 0.38;
  const oneSpaceProgression =
    gameSpaceGain === 1 &&
    forwardGain >= 3 &&
    actionSpace.lineBreakCount >= 1;
  const skippedTooMuch =
    candidate.actionType === "pass" &&
    gameSpaceGain >= 2 &&
    passDistance >= 30 &&
    profile.routeOneBias < 0.58 &&
    supportNearTarget <= 0 &&
    targetThreat.box < 0.28 &&
    targetThreat.behindLine < 0.42;

  if (entersSpaceTwo) {
    score += 0.26 + actionSpace.value * 0.28 + profile.lineBreakBias * 0.16;
    labels.push("Enter space 2");
  }

  if (entersSpaceThree) {
    score += 0.24 + targetThreat.behindLine * 0.32 + profile.directness * 0.14;
    labels.push("Attack space 3");
  }

  if (oneSpaceProgression) {
    score += 0.18 + profile.progressionUrgency * 0.14;
    labels.push("Play through the next space");
  }

  if (
    candidate.actionType === "pass" &&
    targetSpace.key === "space2" &&
    receiverPressure <= 0.58 &&
    (targetThreat.betweenLines >= 0.34 || targetThreat.halfSpace >= 0.34)
  ) {
    score += 0.2 + Math.max(0, targetThreat.value - startThreat.value) * 0.34;
    labels.push("Find player between lines");
  }

  if (
    candidate.actionType === "dribble" &&
    startSpace.index >= 1 &&
    targetSpace.index >= startSpace.index &&
    forwardGain >= 4.5 &&
    openTarget >= 0.52 &&
    pressure <= 0.56
  ) {
    score += 0.2 + openTarget * 0.18 + profile.carryBias * 0.12;
    labels.push("Carry through open space");
  }

  if (
    startSpace.key === "space2" &&
    facingForward &&
    pressure <= 0.48 &&
    candidate.actionType === "pass" &&
    forwardGain < 2 &&
    !candidate.isSwitch &&
    targetThreat.value <= startThreat.value + 0.04
  ) {
    score -= 0.52 + profile.progressionUrgency * 0.22;
  }

  if (
    gameSpaceGain < 0 &&
    pressure <= 0.52 &&
    !candidate.isSwitch &&
    targetThreat.value <= startThreat.value + 0.05
  ) {
    score -= Math.abs(gameSpaceGain) * (0.24 + profile.progressionUrgency * 0.12);
  }

  if (skippedTooMuch) {
    score -= 0.46 + (1 - profile.directness) * 0.2;
  }

  if (
    targetSpace.index >= 2 &&
    actionSpace.targetPressure >= 0.72 &&
    supportNearTarget <= 0 &&
    !candidate.isBoxPass &&
    candidate.actionType !== "shot"
  ) {
    score -= 0.24;
  }

  if (
    candidate.actionType === "shot" &&
    (startSpace.key === "space3" || targetThreat.box >= 0.3 || startThreat.centralPocket >= 0.42)
  ) {
    score += 0.16 + profile.shootBias * 0.12;
    labels.push("Finish from space 3");
  }

  return {
    score: clamp(score, -1.25, 1.25),
    labels: uniquePrincipleLabels(labels),
    context: {
      startSpace,
      targetSpace,
      gameSpaceGain,
      supportNearTarget,
      receiverPressure,
      openTarget,
      laneClarity,
    },
  };
}

function getAutoPilotSpatialDecisionAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier || !startPoint) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const teamId = carrier.team;
  const startSpace = getPitchSpaceProfile(startPoint, teamId);
  const targetSpace = getPitchSpaceProfile(candidate.target, teamId);
  const startGameSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const targetGameSpace = getAttackingGameSpaceProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const actionDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestOpponentGap = getNearestOpponentGap(carrier, startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(candidate.target) - getPitchLaneIndex(startPoint));
  const startLane = getPitchLaneKey(startPoint);
  const targetLane = getPitchLaneKey(candidate.target);
  const startIsWide = startLane === "leftWide" || startLane === "rightWide";
  const targetIsWide = targetLane === "leftWide" || targetLane === "rightWide";
  const targetIsHalfSpace = targetLane === "leftHalf" || targetLane === "rightHalf";
  const targetIsCentral = targetLane === "central";
  const gameSpaceGain = targetGameSpace.index - startGameSpace.index;
  const targetDensity = getTeamDensityAtPoint(
    teamId,
    candidate.target,
    targetGameSpace.key === "space3" ? 8.8 : 10.5,
    new Set([carrier.id, candidate.receiverPlayerId].filter(Boolean))
  );
  const canFaceForward =
    isPlayerFacingForward(carrier, Math.PI / 2.15) ||
    (pressure <= 0.38 && nearestOpponentGap >= 3.8) ||
    startSpace.betweenLines >= 0.42;
  const underControl = pressure <= 0.5 && nearestOpponentGap >= 2.7;
  const highValueForwardAction =
    forwardGain >= 4 &&
    (actionSpace.value >= 0.38 ||
      targetSpace.value >= startSpace.value + 0.06 ||
      targetSpace.gameSpaceIndex > startSpace.gameSpaceIndex ||
      candidate.isLineBreak ||
      candidate.isBoxPass);
  const sterileAction =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 2.5 &&
    targetSpace.value <= startSpace.value + 0.035 &&
    actionSpace.lineBreakCount === 0;
  const excessiveJump =
    candidate.actionType === "pass" &&
    gameSpaceGain >= 2 &&
    actionDistance >= 29 &&
    profile.routeOneBias < 0.58 &&
    targetSpace.box < 0.24 &&
    targetSpace.behindLine < 0.42 &&
    actionSpace.openTarget < 0.72;
  const labels = [];
  let score = 0;

  if (startGameSpace.key === "outlet" || startGameSpace.key === "space1") {
    if (gameSpaceGain === 1 && forwardGain >= 3 && actionSpace.lineBreakCount >= 1) {
      score += 0.3 + profile.lineBreakBias * 0.16 + actionSpace.value * 0.18;
      labels.push("Spelyta decision: enter next space");
    }

    if (
      targetGameSpace.key === "space2" &&
      (targetIsHalfSpace || targetIsCentral) &&
      forwardGain >= 4 &&
      actionSpace.targetPressure <= 0.64
    ) {
      score += 0.22 + profile.shortSupport * 0.12;
      labels.push("Spelyta decision: find pocket behind midfield");
    }

    if (excessiveJump) {
      score -= 0.46 + (1 - profile.directness) * 0.22;
      labels.push("Spelyta decision: avoid hopeful skip");
    }
  }

  if (startGameSpace.key === "space2" || startSpace.betweenLines >= 0.36 || startSpace.centralPocket >= 0.26) {
    if (canFaceForward && underControl && highValueForwardAction) {
      score += 0.42 + actionSpace.value * 0.3 + profile.progressionUrgency * 0.16;
      labels.push("Spelyta decision: attack forward-facing space 2");
    }

    if (
      canFaceForward &&
      underControl &&
      candidate.actionType === "dribble" &&
      forwardGain >= 4 &&
      actionSpace.openTarget >= 0.48
    ) {
      score += 0.24 + profile.carryBias * 0.16;
      labels.push("Spelyta decision: drive at the back line");
    }

    if (
      canFaceForward &&
      underControl &&
      !candidate.isSwitch &&
      (forwardGain <= -4 || sterileAction)
    ) {
      score -= 0.66 + startSpace.value * 0.22 + profile.progressionUrgency * 0.22;
      labels.push("Spelyta decision: do not waste forward-facing space");
    }
  }

  if (startGameSpace.key === "space3" || startSpace.box >= 0.18 || startSpace.centralPocket >= 0.38) {
    if (candidate.actionType === "shot") {
      score += 0.34 + profile.shootBias * 0.26 + startSpace.box * 0.18;
      labels.push("Spelyta decision: finish from space 3");
    }

    if (
      candidate.actionType === "pass" &&
      (targetSpace.box >= 0.28 || targetSpace.cutbackZone >= 0.34 || candidate.isBoxPass)
    ) {
      score += 0.26 + profile.shortSupport * 0.1;
      labels.push("Spelyta decision: play final action");
    }

    if (
      candidate.actionType !== "shot" &&
      forwardGain <= -5 &&
      pressure <= 0.48 &&
      !candidate.isSwitch
    ) {
      score -= 0.42 + profile.shootBias * 0.2;
    }
  }

  if (startIsWide && !targetIsWide && (targetIsHalfSpace || targetIsCentral) && forwardGain >= 1.5) {
    score += 0.18 + profile.overlapBias * 0.08 + profile.shortSupport * 0.08;
    labels.push("Spelyta decision: come inside from width");
  }

  if (
    !startIsWide &&
    targetIsWide &&
    (pressure >= 0.48 || profile.switchBias >= 0.62 || profile.widthDiscipline >= 0.68) &&
    targetSpace.depth >= 38
  ) {
    score += 0.14 + profile.switchBias * 0.12;
    labels.push("Spelyta decision: stretch the block");
  }

  if (
    laneShift === 0 &&
    sterileAction &&
    pressure <= 0.46 &&
    targetSpace.depth < 72
  ) {
    score -= 0.24 + profile.progressionUrgency * 0.18;
  }

  if (
    targetDensity >= 3 &&
    targetSpace.box < 0.26 &&
    targetSpace.cutbackZone < 0.28 &&
    !candidate.isSwitch
  ) {
    score -= 0.18 + (targetDensity - 2) * 0.08;
    labels.push("Spelyta decision: avoid crowding");
  }

  if (
    candidate.actionType === "pass" &&
    targetSpace.gameSpaceIndex < startSpace.gameSpaceIndex &&
    pressure <= 0.42 &&
    !candidate.isSwitch &&
    startSpace.depth >= 44
  ) {
    score -= 0.28 + profile.progressionUrgency * 0.12;
  }

  return {
    score: clamp(score, -1.3, 1.35),
    labels: uniquePrincipleLabels(labels),
    context: {
      startSpace,
      targetSpace,
      startGameSpace,
      targetGameSpace,
      gameSpaceGain,
      laneShift,
      canFaceForward,
      underControl,
      highValueForwardAction,
      sterileAction,
      targetDensity,
    },
  };
}

function getActionThreatGain(startPoint, targetPoint, teamId) {
  const startThreat = getPitchThreatProfile(startPoint, teamId).value;
  const targetThreat = getPitchThreatProfile(targetPoint, teamId).value;
  return targetThreat - startThreat;
}

function isPlayerFacingForward(player, tolerance = Math.PI / 3.2) {
  if (!player) {
    return false;
  }

  return angleDifference(getPlayerFacingAngle(player), getTeamAttackAngle(player.team)) <= tolerance;
}

function getForwardFacingSpaceTwoContext(player, point = player?.position) {
  if (!player || !point) {
    return {
      active: false,
      depth: 0,
      pressure: 1,
      facingForward: false,
      goldenScore: 0,
    };
  }

  const depth = getAttackingDepth(point, player.team);
  const pressure = getPlayerPressureLoad(player, point);
  const facingForward = isPlayerFacingForward(player);
  const active = depth >= 38 && depth <= 72 && pressure <= 0.46 && facingForward;

  return {
    active,
    depth,
    pressure,
    facingForward,
    goldenScore: getGoldenZoneScore(point, player.team),
  };
}

function getAutoPilotSpaceTwoAdvantageAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const teamId = carrier.team;
  const gameSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.45);
  const isSpaceTwo =
    gameSpace.key === "space2" ||
    startThreat.betweenLines >= 0.28 ||
    (gameSpace.index >= 2 && gameSpace.index <= 3 && startThreat.centrality >= 0.42);
  const active =
    isSpaceTwo &&
    facingForward &&
    pressure <= 0.56 &&
    getAttackingDepth(startPoint, teamId) >= 38 &&
    getAttackingDepth(startPoint, teamId) <= 78;

  if (!active) {
    return {
      score: 0,
      labels: [],
      context: {
        active: false,
        gameSpaceKey: gameSpace.key,
        pressure,
        facingForward,
      },
    };
  }

  const target = candidate.target;
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const targetThreat = getPitchThreatProfile(target, teamId);
  const targetSpace = getAttackingGameSpaceProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const targetGoalDistance = distance(target, getOpponentGoalCenter(teamId));
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const isProgressivePass =
    candidate.actionType === "pass" &&
    forwardGain >= 3.5 &&
    (
      actionSpace.lineBreakCount >= 1 ||
      targetSpace.index > gameSpace.index ||
      targetThreat.value >= startThreat.value + 0.04 ||
      targetThreat.betweenLines >= 0.32 ||
      targetThreat.centralPocket >= 0.26 ||
      isFrontLineRole(receiverRoleKey)
    );
  const isProgressiveCarry =
    candidate.actionType === "dribble" &&
    forwardGain >= 3.5 &&
    (
      actionSpace.value >= 0.26 ||
      targetThreat.value >= startThreat.value + 0.035 ||
      targetGoalDistance <= goalDistance - 3.5
    );
  const isShotWindow =
    candidate.actionType === "shot" &&
    goalDistance <= 32 &&
    pressure <= 0.62;
  const isLowValueRecycle =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 2 &&
    targetThreat.value <= startThreat.value + 0.05 &&
    actionSpace.lineBreakCount === 0 &&
    targetSpace.index <= gameSpace.index;
  const isBackwardsEscape =
    candidate.actionType === "pass" &&
    forwardGain <= -4 &&
    pressure <= 0.44 &&
    passDistance <= 24;
  const safeSupportAllowance =
    pressure >= 0.42 &&
    passDistance <= 13 &&
    (receiverRoleKey === "pivot" || receiverRoleKey === "connector");
  const score =
    (isProgressivePass
      ? 0.42 +
        actionSpace.value * 0.38 +
        clamp(forwardGain / 18, 0, 0.46) +
        (targetThreat.centralPocket >= 0.28 ? 0.18 : 0) +
        (targetSpace.index > gameSpace.index ? 0.18 : 0)
      : 0) +
    (isProgressiveCarry
      ? 0.38 +
        actionSpace.openTarget * 0.26 +
        clamp(forwardGain / 16, 0, 0.42) +
        getPlayerTendency(carrier, "dribble") * 0.12
      : 0) +
    (isShotWindow ? 0.24 + clamp((32 - goalDistance) / 18, 0, 0.28) : 0) -
    (isLowValueRecycle
      ? (safeSupportAllowance ? 0.24 : 0.68 + profile.progressionUrgency * 0.36)
      : 0) -
    (isBackwardsEscape ? 0.5 + profile.progressionUrgency * 0.28 : 0);
  const labels = [];

  if (isProgressivePass || isProgressiveCarry || isShotWindow) {
    labels.push("Use space 2 advantage");
  }

  if (isProgressivePass && actionSpace.lineBreakCount >= 1) {
    labels.push("Attack the next line");
  } else if (isProgressiveCarry) {
    labels.push("Carry into open lane");
  }

  return {
    score: clamp(score, -1.25, 1.25),
    labels: uniquePrincipleLabels(labels),
    context: {
      active: true,
      gameSpaceKey: gameSpace.key,
      targetGameSpaceKey: targetSpace.key,
      pressure,
      facingForward,
      forwardGain,
      lineBreakCount: actionSpace.lineBreakCount,
      isProgressivePass,
      isProgressiveCarry,
      isShotWindow,
      isLowValueRecycle,
    },
  };
}

function getForwardProgressionWindow(carrier, startPoint = carrier?.position, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const sign = getAttackDirectionSign(carrier.team);
  const depth = getAttackingDepth(startPoint, carrier.team);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.35);
  const probe = clampToPitch({
    x: startPoint.x + sign * 18,
    y: lerp(startPoint.y, pitch.width / 2, 0.26),
  }, 2.5);
  const openLane = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, probe));
  const goldenAhead = getGoldenZoneScore(probe, carrier.team);
  const spaceTwo = depth >= 36 && depth <= 74;
  const active =
    spaceTwo &&
    pressure <= 0.54 &&
    openLane >= 0.42 &&
    (facingForward || profile.firstTouchForwardBias >= 0.7 || profile.directness >= 0.64);

  return {
    active,
    depth,
    pressure,
    facingForward,
    openLane,
    goldenAhead,
    probe,
    urgency: clamp((profile.progressionUrgency ?? 0.5) * 0.58 + openLane * 0.34 + (facingForward ? 0.16 : 0), 0, 1.2),
  };
}

function getOpponentGoalSide(teamId) {
  return teamId === "home" ? "right" : "left";
}

function getGoalLineX(side) {
  return side === "right" ? pitch.length : 0;
}

function getGoalDirectionSign(side) {
  return side === "right" ? 1 : -1;
}

function isBetweenGoalPosts(y, margin = 0) {
  const halfGoalWidth = 7.32 / 2;
  return y >= pitch.width / 2 - halfGoalWidth - margin &&
    y <= pitch.width / 2 + halfGoalWidth + margin;
}

function getGoalNetDisplayPoint(side, y) {
  return {
    x: side === "right" ? pitch.length - 0.55 : 0.55,
    y: clamp(y, pitch.width / 2 - 3.4, pitch.width / 2 + 3.4),
  };
}

function resolveShotTarget(targetPoint, initiator = null) {
  const teamId =
    initiator?.team ??
    getPlannedPossessionTeamId() ??
    getBallOwner()?.team ??
    (targetPoint.x >= pitch.length / 2 ? "home" : "away");
  const side = getOpponentGoalSide(teamId);
  const sign = getGoalDirectionSign(side);
  const goalLineX = getGoalLineX(side);
  const nearGoalLine =
    side === "right"
      ? targetPoint.x >= pitch.length - 8
      : targetPoint.x <= 8;

  if (!nearGoalLine) {
    return clampToPitch(targetPoint, 0);
  }

  return {
    x: goalLineX + sign * 2.6,
    y: clamp(targetPoint.y, 0, pitch.width),
  };
}

function getOwnGoalCenter(teamId) {
  return vec(teamId === "home" ? 0 : pitch.length, pitch.width / 2);
}

function getOpponentPenaltySpot(teamId) {
  return vec(teamId === "home" ? pitch.length - 11 : 11, pitch.width / 2);
}

function getSecondLastOpponentLineX(attackingTeamId) {
  const opponentXs = state.players
    .filter((player) => player.team !== attackingTeamId)
    .map((player) => player.position.x)
    .sort((a, b) => attackingTeamId === "home" ? b - a : a - b);

  if (opponentXs.length < 2) {
    return null;
  }

  return opponentXs[1];
}

function getOffsideInfo(receiver, passStartPoint) {
  if (!receiver || !passStartPoint) {
    return { isOffside: false, lineX: null, reason: null };
  }

  const teamId = receiver.team;
  const attackSign = getAttackDirectionSign(teamId);
  const receiverPoint = getPlayerBallControlPoint(receiver);
  const receiverDepth = getAttackingDepth(receiverPoint, teamId);
  const ballDepth = getAttackingDepth(passStartPoint, teamId);
  const lineX = getSecondLastOpponentLineX(teamId);
  if (lineX === null || receiverDepth <= pitch.length / 2) {
    return { isOffside: false, lineX, reason: null };
  }

  const offsideTolerance = 0.25;
  const beyondBall = (receiverPoint.x - passStartPoint.x) * attackSign > offsideTolerance;
  const beyondSecondLast = (receiverPoint.x - lineX) * attackSign > offsideTolerance;
  const isOffside = beyondBall && beyondSecondLast;

  return {
    isOffside,
    lineX,
    receiverPoint,
    reason: isOffside
      ? `${receiver.shortLabel} ${receiver.role} is beyond the ball and the second-last defender.`
      : null,
  };
}

function isPassReceiverOffside(receiver, passStartPoint = state.ball.position) {
  return getOffsideInfo(receiver, passStartPoint).isOffside;
}

function isWideChannel(point) {
  return point.y <= 14 || point.y >= pitch.width - 14;
}

function isBylineZone(point, teamId) {
  return teamId === "home" ? point.x >= pitch.length - 8 : point.x <= 8;
}

function isInsideOpponentBox(point, teamId) {
  if (teamId === "home") {
    return point.x >= pitch.length - 16.5 && point.y >= 13.8 && point.y <= pitch.width - 13.8;
  }

  return point.x <= 16.5 && point.y >= 13.8 && point.y <= pitch.width - 13.8;
}

function isInsideOwnBox(point, teamId) {
  if (teamId === "home") {
    return point.x <= 16.5 && point.y >= 13.8 && point.y <= pitch.width - 13.8;
  }

  return point.x >= pitch.length - 16.5 && point.y >= 13.8 && point.y <= pitch.width - 13.8;
}

function isCutbackTarget(point, teamId) {
  const penaltySpot = getOpponentPenaltySpot(teamId);
  return distance(point, penaltySpot) <= 10.5;
}

function isGoalkeeper(player) {
  return /goalkeeper/i.test(player?.role ?? "") || player?.shortLabel === "GK";
}

function getBallProfileDistanceRatio(profile, distanceMeters) {
  const span = Math.max(profile.maxDistance - profile.minDistance, 0.01);
  return clamp((distanceMeters - profile.minDistance) / span, 0, 1);
}

function getPitchSurfacePreset(surfaceKey = state.surfacePreset) {
  return pitchSurfacePresets[surfaceKey] ?? pitchSurfacePresets["hybrid-grass"];
}

function getWeatherPreset(weatherKey = state.weatherPreset) {
  return weatherPresets[weatherKey] ?? weatherPresets.damp;
}

function getDefensiveAggressionPreset() {
  return (
    defensiveAggressionPresets[state.defensiveAggressionPreset] ??
    defensiveAggressionPresets.balanced
  );
}

function isAerialFlightStyle(flightStyle) {
  return flightStyle === "clipped" || flightStyle === "lofted";
}

function getFlightStyleLabel(flightStyle) {
  if (flightStyle === "lofted") {
    return "Lofted";
  }

  if (flightStyle === "clipped") {
    return "Clipped";
  }

  if (flightStyle === "driven") {
    return "Driven";
  }

  return "Ground";
}

function resolveBallCurveDirection(startPoint, targetPoint, initiator) {
  const travelAngle = angleBetween(startPoint, targetPoint);
  if (initiator) {
    const bodyDelta = normalizeAngle(travelAngle - getPlayerFacingAngle(initiator));
    if (Math.abs(bodyDelta) > 0.08) {
      return bodyDelta >= 0 ? 1 : -1;
    }

    if (initiator.preferredFoot === "left") {
      return 1;
    }

    if (initiator.preferredFoot === "right") {
      return -1;
    }
  }

  const lateralTravel = targetPoint.y - startPoint.y;
  if (Math.abs(lateralTravel) > 0.4) {
    return lateralTravel >= 0 ? 1 : -1;
  }

  return startPoint.y <= pitch.width / 2 ? 1 : -1;
}

function getBallTravelProgress() {
  const totalDistance = state.ball.trackDistanceTotal || distance(state.ball.startPosition, state.ball.target);
  if (totalDistance <= 0.01) {
    return 1;
  }

  if (state.ball.trackDistanceCovered > 0) {
    return clamp(state.ball.trackDistanceCovered / totalDistance, 0, 1);
  }

  return clamp(distance(state.ball.startPosition, state.ball.position) / totalDistance, 0, 1);
}

function getBallTravelPoint(progress) {
  const clampedProgress = clamp(progress, 0, 1);
  const basePoint = {
    x: lerp(state.ball.startPosition.x, state.ball.target.x, clampedProgress),
    y: lerp(state.ball.startPosition.y, state.ball.target.y, clampedProgress),
  };
  const totalDistance = state.ball.trackDistanceTotal || distance(state.ball.startPosition, state.ball.target);
  if (totalDistance <= 0.01 || Math.abs(state.ball.curveAmount) <= 0.01) {
    return basePoint;
  }

  const direction = normalize(state.ball.startPosition, state.ball.target);
  const lateral = { x: -direction.y, y: direction.x };
  const curveShape = Math.sin(Math.PI * clampedProgress) * (0.96 + (1 - clampedProgress) * 0.08);
  const offset = state.ball.curveAmount * curveShape * (state.ball.curveDirection || 1);

  return {
    x: basePoint.x + lateral.x * offset,
    y: basePoint.y + lateral.y * offset,
  };
}

function materializeBallProfile(profileKey, distanceMeters, targetKind, source = "auto") {
  const template = autoBallProfiles[profileKey] ?? autoBallProfiles["firm-feet"];
  const ratio = getBallProfileDistanceRatio(template, distanceMeters);
  const ballPowerMultiplier = source === "auto"
    ? getCompetitionPhysicalProfile().ballPowerMultiplier
    : 1;

  return {
    key: template.key,
    label: template.label,
    source,
    targetKind,
    averageSpeed: lerp(template.averageSpeedRange[0], template.averageSpeedRange[1], ratio) * ballPowerMultiplier,
    launchMultiplier: lerp(template.launchMultiplierRange[0], template.launchMultiplierRange[1], ratio),
    rollFloor: lerp(template.rollFloorRange[0], template.rollFloorRange[1], ratio) * ballPowerMultiplier,
    flightStyle: template.flightStyle ?? "ground",
    peakHeight: lerp(template.peakHeightRange?.[0] ?? 0, template.peakHeightRange?.[1] ?? 0, ratio),
    controlHeightThreshold: lerp(
      template.controlHeightRange?.[0] ?? 0.12,
      template.controlHeightRange?.[1] ?? 0.12,
      ratio
    ),
    landingPhaseStart: lerp(
      template.landingPhaseRange?.[0] ?? 0.58,
      template.landingPhaseRange?.[1] ?? 0.58,
      ratio
    ),
    curveAmount: lerp(template.curveRange?.[0] ?? 0, template.curveRange?.[1] ?? 0, ratio),
    spinRate: lerp(template.spinRateRange?.[0] ?? 0, template.spinRateRange?.[1] ?? 0, ratio),
    distanceRatio: ratio,
  };
}

function getManualBallProfile(actionType, baseProfile = null) {
  if (actionType === "dribble") {
    return {
      key: "carry",
      label: "Carry",
      source: "manual",
      targetKind: "carry",
      averageSpeed: state.dribbleSpeed,
      launchMultiplier: 1,
      rollFloor: state.dribbleSpeed,
      flightStyle: "ground",
      peakHeight: 0,
      controlHeightThreshold: 0.12,
      landingPhaseStart: 0.58,
      curveAmount: 0,
      spinRate: 0,
      distanceRatio: 0,
    };
  }

  if (baseProfile) {
    return {
      ...baseProfile,
      source: "manual",
      averageSpeed: state.ball.manualSpeed,
    };
  }

  return {
    key: "firm-feet",
    label: "Firm To Feet",
    source: "manual",
    targetKind: actionType === "shot" ? "goal" : "to-feet",
    averageSpeed: state.ball.manualSpeed,
    launchMultiplier: actionType === "shot" ? 1.24 : 1.14,
    rollFloor: actionType === "shot" ? 2.4 : 1.2,
    flightStyle: actionType === "shot" ? "driven" : "ground",
    peakHeight: actionType === "shot" ? 0.5 : 0,
    controlHeightThreshold: actionType === "shot" ? 0.26 : 0.12,
    landingPhaseStart: actionType === "shot" ? 0.72 : 0.58,
    curveAmount: 0,
    spinRate: actionType === "shot" ? 2.2 : 0,
    distanceRatio: 0,
  };
}

function getDribbleRoleFamily(player) {
  const magnetLabel = getPlayerMagnetLabel(player);
  const role = player?.role ?? "";

  if (magnetLabel === "GK" || /goalkeeper/i.test(role)) {
    return "gk-carry";
  }

  if (magnetLabel === "CB" || /center back/i.test(role)) {
    return "centre-back-carry";
  }

  if (magnetLabel === "6" || /holding midfielder/i.test(role)) {
    return "six-carry";
  }

  if (magnetLabel === "10" || /attacking midfielder/i.test(role)) {
    return "ten-carry";
  }

  if (magnetLabel === "8" || /central midfielder/i.test(role)) {
    return "eight-carry";
  }

  if (magnetLabel === "W" || /winger/i.test(role)) {
    return "winger-carry";
  }

  if (magnetLabel === "WB" || /wing-back/i.test(role)) {
    return "wingback-carry";
  }

  if (magnetLabel === "LB" || magnetLabel === "RB" || /left back|right back/i.test(role)) {
    return "fullback-carry";
  }

  if (magnetLabel === "9" || /striker|centre forward/i.test(role)) {
    return "striker-carry";
  }

  return "eight-carry";
}

function resolveAutoDribbleProfile(startPoint, targetPoint, carrier) {
  if (!carrier) {
    return getManualBallProfile("dribble");
  }

  const context = getPlayerDecisionContext(carrier);
  const surfacePreset = getPitchSurfacePreset();
  const weatherPreset = getWeatherPreset();
  const profileKey = getDribbleRoleFamily(carrier);
  const profile = autoDribbleProfiles[profileKey] ?? autoDribbleProfiles["eight-carry"];
  const actionDistance = distance(startPoint, targetPoint);
  const forwardMeters = (targetPoint.x - startPoint.x) * getAttackDirectionSign(carrier.team);
  const isWideCarry = isWideChannel(startPoint) || isWideChannel(targetPoint);
  const isForwardCarry = forwardMeters >= 5;
  const distanceRatio = clamp(actionDistance / 18, 0, 1);
  const nearestOpponentGap = getNearestOpponentGapInCarryLane(carrier, targetPoint);
  const openSpaceScore = getCarryLaneOpenSpaceScore(nearestOpponentGap);
  const lanePressureScore = 1 - openSpaceScore;
  const carryAngle = angleBetween(startPoint, targetPoint);
  const turnPenalty = clamp(
    angleDifference(getPlayerFacingAngle(carrier), carryAngle) / (Math.PI * 0.75),
    0,
    1
  );
  const technicalScore =
    context.profile.technicalSecurity * 0.34 +
    context.profile.pressResistance * 0.2 +
    context.profile.decisionSpeed * 0.16 +
    context.profile.decisionQuality * 0.14 +
    context.profile.composure * 0.16;
  const directionalBonus =
    (isForwardCarry ? 0.015 : 0) +
    (isWideCarry && ["winger-carry", "wingback-carry", "fullback-carry"].includes(profileKey) ? 0.018 : 0) +
    (profileKey === "striker-carry" && actionDistance >= 10 ? 0.014 : 0);
  const pressureFactor = clamp(
    1 -
      context.pressure * profile.pressurePenalty * (1.15 - context.profile.pressResistance * 0.18) -
      lanePressureScore * profile.lanePressurePenalty,
    0.68,
    1
  );
  const surfaceFactor = surfacePreset.dribbleCarryFactor * weatherPreset.dribbleTractionFactor;
  const playerPaceFactor = lerp(
    0.92,
    1.1,
    clamp((context.maxSpeed - 6.8) / 2.3, 0, 1)
  );
  const technicalFactor = clamp(
    0.9 + technicalScore * 0.18 + weatherPreset.dribbleControlFactor * 0.02,
    0.86,
    1.06
  );
  const openSpaceSpeed = lerp(profile.tightSpeed, profile.openSpeed, openSpaceScore);
  const physicalCarryMultiplier = carrier.physicalProfile?.dribbleSpeedMultiplier ?? 1;
  const distanceBoost =
    lerp(profile.distanceBoost[0], profile.distanceBoost[1], distanceRatio) *
    lerp(0.28, 1, openSpaceScore);
  const turnFactor = lerp(1, 0.82, turnPenalty);
  const averageSpeed = clamp(
    (openSpaceSpeed + distanceBoost) *
      physicalCarryMultiplier *
      playerPaceFactor *
      technicalFactor *
      (1 + directionalBonus) *
      pressureFactor *
      surfaceFactor *
      turnFactor,
    profile.minSpeed * physicalCarryMultiplier,
    profile.maxSpeed * physicalCarryMultiplier
  );

  return {
    key: profile.key,
    label: profile.label,
    source: "auto",
    targetKind: "carry",
    averageSpeed,
    launchMultiplier: 1,
    rollFloor: averageSpeed,
    flightStyle: "ground",
    peakHeight: 0,
    controlHeightThreshold: 0.12,
    landingPhaseStart: 0.58,
    distanceRatio,
  };
}

function getNearestOpponentGapInCarryLane(carrier, targetPoint) {
  const carryDirection = normalize(carrier.position, targetPoint);
  const hasDirection = Math.abs(carryDirection.x) > 0.001 || Math.abs(carryDirection.y) > 0.001;
  if (!hasDirection) {
    return Infinity;
  }

  let nearestGap = Infinity;
  const carryDistance = distance(carrier.position, targetPoint);
  const scanDistance = Math.max(11, Math.min(carryDistance + 2.5, 32));
  const scanRadius = Math.max(14, Math.min(carryDistance + 4, 36));

  state.players.forEach((player) => {
    if (player.team === carrier.team) {
      return;
    }

    const toOpponent = subtract(player.position, carrier.position);
    const opponentGap = Math.sqrt(toOpponent.x * toOpponent.x + toOpponent.y * toOpponent.y);
    if (opponentGap > scanRadius) {
      return;
    }

    const projection = toOpponent.x * carryDirection.x + toOpponent.y * carryDirection.y;
    if (projection < -1.5 || projection > scanDistance) {
      return;
    }

    const lateral = Math.sqrt(Math.max(opponentGap * opponentGap - projection * projection, 0));
    const laneWidth = lerp(4.1, 5.4, clamp(carryDistance / 26, 0, 1));
    if (lateral > laneWidth) {
      return;
    }

    nearestGap = Math.min(nearestGap, opponentGap);
  });

  return nearestGap;
}

function getCarryLaneOpenSpaceScore(nearestOpponentGap) {
  return Number.isFinite(nearestOpponentGap)
    ? clamp((nearestOpponentGap - 2.4) / 9.6, 0, 1)
    : 1;
}

function getCarryRunwayRoleCap(roleKey, goalDistance) {
  const baseCap =
    roleKey === "wideForward"
      ? 36
      : roleKey === "striker" || roleKey === "secondStriker"
        ? 33
        : roleKey === "connector"
          ? 30
          : roleKey === "wideBack"
            ? 28
            : roleKey === "pivot"
              ? 21
              : roleKey === "rest"
                ? 16
                : 24;

  return clamp(baseCap, 11, goalDistance <= 30 ? 24 : 38);
}

function getCarryRunwayProfile(carrier, startPoint, targetPoint, profile = {}) {
  if (!carrier || !startPoint || !targetPoint) {
    return {
      active: false,
      shouldExtend: false,
      runwayScore: 0,
      score: 0,
      labels: [],
    };
  }

  const teamId = carrier.team;
  const roleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  const goal = getOpponentGoalCenter(teamId);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  const goalDistance = distance(startPoint, goal);
  const targetGoalDistance = distance(targetPoint, goal);
  const nearestLaneGap = getNearestOpponentGapInCarryLane(carrier, targetPoint);
  const openSpaceScore = getCarryLaneOpenSpaceScore(nearestLaneGap);
  const lanePressure = getOpponentPressureAtPoint(teamId, targetPoint, 10);
  const carrierPressure = getPlayerPressureLoad(carrier, startPoint);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat ?? getPitchThreatProfile(targetPoint, teamId);
  const startThreat = actionSpace.startThreat ?? getPitchThreatProfile(startPoint, teamId);
  const threatGain = Math.max(0, targetThreat.value - startThreat.value);
  const dribbleStrength = getAutoPilotRoleStrength(carrier, "dribbler");
  const runnerStrength = getAutoPilotRoleStrength(carrier, "runner");
  const isWideRunway = isWideChannel(startPoint) || isWideChannel(targetPoint);
  const isFinalThirdRunway =
    goalDistance <= 52 &&
    startDepth >= 44 &&
    targetGoalDistance <= goalDistance - 6;
  const roleFit =
    roleKey === "wideForward"
      ? 0.14
      : roleKey === "striker" || roleKey === "secondStriker"
        ? 0.12
        : roleKey === "connector"
          ? 0.08
          : roleKey === "wideBack"
            ? 0.06
            : roleKey === "pivot"
              ? -0.06
              : roleKey === "rest" || roleKey === "gk"
                ? -0.2
                : 0;
  const sterileCarryPenalty =
    forwardGain < 4 &&
    targetThreat.value <= startThreat.value + 0.04 &&
    !isWideRunway
      ? 0.2
      : 0;
  const runwayScore = clamp(
    openSpaceScore * 0.42 +
      actionSpace.openTarget * 0.18 +
      actionSpace.value * 0.22 +
      clamp(forwardGain / 30, 0, 1) * 0.2 +
      threatGain * 0.22 +
      targetThreat.behindLine * 0.16 +
      targetThreat.centralPocket * 0.1 +
      dribbleStrength * 0.12 +
      runnerStrength * 0.08 +
      roleFit +
      (isFinalThirdRunway ? 0.16 : 0) +
      (isWideRunway && forwardGain >= 7 ? 0.06 : 0) -
      lanePressure * 0.18 -
      carrierPressure * 0.13 -
      sterileCarryPenalty,
    0,
    1.35
  );
  const runwayKind =
    isFinalThirdRunway && targetThreat.behindLine >= 0.3
      ? "breakaway"
      : isWideRunway && targetDepth >= 56
        ? "wide-runway"
        : targetThreat.centralPocket >= 0.34 || targetThreat.betweenLines >= 0.36
          ? "central-runway"
          : "progressive-runway";
  const requiredOpenSpace = carrierPressure <= 0.36 ? 0.52 : 0.58;
  const shouldExtend =
    roleKey !== "gk" &&
    roleKey !== "rest" &&
    forwardGain >= 6 &&
    openSpaceScore >= requiredOpenSpace &&
    carrierPressure <= 0.62 &&
    lanePressure <= 0.74 &&
    runwayScore >= 0.68;

  return {
    active: shouldExtend,
    shouldExtend,
    runwayKind,
    runwayScore,
    score: runwayScore,
    forwardGain,
    startDepth,
    targetDepth,
    goalDistance,
    targetGoalDistance,
    openSpaceScore,
    nearestLaneGap,
    lanePressure,
    carrierPressure,
    actionSpace,
    targetThreat,
    startThreat,
    isWideRunway,
    isFinalThirdRunway,
    labels: shouldExtend ? ["Open-grass runway"] : [],
  };
}

function getRunwayCarryTarget(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return null;
  }

  const teamId = carrier.team;
  const roleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  if (roleKey === "gk" || roleKey === "rest") {
    return null;
  }

  const sign = getAttackDirectionSign(teamId);
  const goal = getOpponentGoalCenter(teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const goalDistance = distance(startPoint, goal);
  if (pressure >= 0.66 || goalDistance <= 13) {
    return null;
  }

  const attackAngle = getTeamAttackAngle(teamId);
  const towardGoalAngle = angleBetween(startPoint, goal);
  const sideToCenter = Math.sign(pitch.width / 2 - startPoint.y) || (getWideSideSign(startPoint) ? -getWideSideSign(startPoint) : 1);
  const roleCap = getCarryRunwayRoleCap(roleKey, goalDistance);
  const referenceTarget = clampToPitch({
    x: startPoint.x + sign * Math.min(24, Math.max(12, goalDistance - 13)),
    y: lerp(startPoint.y, pitch.width / 2, isWideChannel(startPoint) ? 0.48 : 0.22),
  }, 2.5);
  const referenceOpenSpace = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, referenceTarget));
  const desiredDistance = clamp(
    13 +
      referenceOpenSpace * 12 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 5.5 +
      getAutoPilotRoleStrength(carrier, "runner") * 3.6 +
      (profile.carryBias ?? 0.5) * 4.4 +
      (getAttackingDepth(startPoint, teamId) >= 50 ? 2.6 : 0) -
      pressure * 5.8,
    9.5,
    Math.min(roleCap, Math.max(9, goalDistance - (goalDistance <= 30 ? 9.5 : 13)))
  );

  if (desiredDistance < 9) {
    return null;
  }

  const breakawayBuffer = goalDistance <= 30 ? 10 : 13.5;
  const buildAngleTarget = (angle, distanceLimit, key, weight) => ({
    key,
    weight,
    target: clampToPitch({
      x: startPoint.x + Math.cos(angle) * distanceLimit,
      y: startPoint.y + Math.sin(angle) * distanceLimit,
    }, 2.5),
  });
  const candidates = [
    buildAngleTarget(towardGoalAngle, desiredDistance, "breakaway", goalDistance <= 52 ? 1.1 : 0.92),
    buildAngleTarget(normalizeAngle(attackAngle + sideToCenter * 0.2), desiredDistance * 0.96, "inside-runway", isWideChannel(startPoint) ? 1.12 : 0.98),
    {
      key: "central-runway",
      weight: isWideChannel(startPoint) ? 1.04 : 0.96,
      target: clampToPitch({
        x: startPoint.x + sign * desiredDistance,
        y: lerp(startPoint.y, pitch.width / 2, isWideChannel(startPoint) ? 0.58 : 0.26),
      }, 2.5),
    },
    {
      key: "goal-runway",
      weight: goalDistance <= 44 ? 1.14 : 0.88,
      target: clampToPitch({
        x: goal.x - sign * breakawayBuffer,
        y: lerp(startPoint.y, pitch.width / 2, isWideChannel(startPoint) ? 0.66 : 0.42),
      }, 2.5),
    },
  ]
    .map((candidate) => {
      const forwardGain = (candidate.target.x - startPoint.x) * sign;
      const travelDistance = distance(startPoint, candidate.target);
      if (forwardGain < 6 || travelDistance < 8.5 || travelDistance > roleCap + 1) {
        return null;
      }

      const runway = getCarryRunwayProfile(carrier, startPoint, candidate.target, profile);
      return {
        ...runway,
        key: candidate.key,
        target: candidate.target,
        score: runway.runwayScore + candidate.weight * 0.08 + clamp(travelDistance / 36, 0, 0.12),
        distance: travelDistance,
      };
    })
    .filter((candidate) => candidate?.shouldExtend)
    .sort((a, b) => b.score - a.score);

  const best = candidates[0] ?? null;
  if (!best) {
    return null;
  }

  return {
    ...best,
    active: true,
    label:
      best.runwayKind === "breakaway"
        ? "open-grass runway"
        : best.runwayKind === "wide-runway"
          ? "wide runway carry"
          : "progressive runway carry",
  };
}

function getBreakawayCarryTarget(carrier, startPoint, profile) {
  const runway = getRunwayCarryTarget(carrier, startPoint, profile);
  if (runway?.runwayKind === "breakaway" && runway.target) {
    return runway.target;
  }

  const teamId = carrier.team;
  const sign = getAttackDirectionSign(teamId);
  const goal = getOpponentGoalCenter(teamId);
  const goalDistance = distance(startPoint, goal);
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const towardGoalPoint = clampToPitch({
    x: goal.x - sign * 15.5,
    y: pitch.width / 2,
  }, 2.5);
  const openSpaceScore = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, towardGoalPoint));
  const roleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  const canBreakAway =
    goalDistance <= 48 &&
    ballDepth >= 48 &&
    pressure <= 0.46 &&
    openSpaceScore >= 0.62 &&
    roleKey !== "gk" &&
    roleKey !== "rest" &&
    roleKey !== "pivot";

  if (!canBreakAway) {
    return null;
  }

  const targetDistance = clamp(
    14 +
      openSpaceScore * 11 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 5 +
      (profile?.tempo ?? 0.55) * 3,
    13,
    goalDistance <= 31 ? 19 : 30
  );
  const maxXBeforeShot = goal.x - sign * (goalDistance <= 26 ? 11.8 : 15.2);
  const targetX =
    sign > 0
      ? Math.min(startPoint.x + targetDistance, maxXBeforeShot)
      : Math.max(startPoint.x - targetDistance, maxXBeforeShot);
  const centralPull = isWideChannel(startPoint) ? 0.56 : 0.38;

  return clampToPitch({
    x: targetX,
    y: lerp(startPoint.y, pitch.width / 2, centralPull),
  }, 2.5);
}

function getOpenGrassCarryContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return null;
  }

  const teamId = carrier.team;
  const roleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  if (roleKey === "gk") {
    return null;
  }

  const runwayCarry = getRunwayCarryTarget(carrier, startPoint, profile);
  if (runwayCarry?.target) {
    return runwayCarry;
  }

  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const goal = getOpponentGoalCenter(teamId);
  const goalDistance = distance(startPoint, goal);
  const dribbleStrength = getAutoPilotRoleStrength(carrier, "dribbler");
  const runnerStrength = getAutoPilotRoleStrength(carrier, "runner");
  const attackAngle = getTeamAttackAngle(teamId);
  const towardGoalAngle = angleBetween(startPoint, goal);
  const sideToCenter = Math.sign(pitch.width / 2 - startPoint.y) || (getWideSideSign(startPoint) ? -getWideSideSign(startPoint) : 1);
  const roleDistanceCap =
    roleKey === "wideForward"
      ? 33
      : roleKey === "striker" || roleKey === "secondStriker"
        ? 30
        : roleKey === "wideBack" || roleKey === "connector"
          ? 26
          : roleKey === "pivot"
            ? 19
            : 17;
  const openDistanceBase = clamp(
    12 +
      dribbleStrength * 7 +
      runnerStrength * 3.5 +
      profile.carryBias * 5 +
      profile.dribbleBias * 3 -
      pressure * 6,
    roleKey === "rest" ? 7.5 : 10,
    roleDistanceCap
  );
  const distanceLimit = clamp(
    Math.min(openDistanceBase, goalDistance - (goalDistance <= 26 ? 9.5 : 13.5)),
    7,
    roleDistanceCap
  );
  if (distanceLimit < 8.5 || pressure >= 0.62) {
    return null;
  }

  const angleOptions = [
    {
      key: "through-centre",
      angle: towardGoalAngle,
      weight: roleKey === "wideForward" || roleKey === "wideBack" ? 0.88 : 1,
    },
    {
      key: "inside-diagonal",
      angle: normalizeAngle(attackAngle + sideToCenter * 0.24),
      weight: isWideChannel(startPoint) ? 1.12 : 0.96,
    },
    {
      key: "outside-arc",
      angle: normalizeAngle(attackAngle - sideToCenter * 0.19),
      weight: roleKey === "wideForward" || roleKey === "wideBack" ? 1.04 : 0.82,
    },
  ];

  const candidates = angleOptions
    .map((option) => {
      const target = clampToPitch({
        x: startPoint.x + Math.cos(option.angle) * distanceLimit,
        y: startPoint.y + Math.sin(option.angle) * distanceLimit,
      }, 2.5);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      if (forwardGain < 5.5) {
        return null;
      }

      const openSpaceScore = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
      const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
      const targetThreat = actionSpace.targetThreat;
      const targetPressure = getOpponentPressureAtPoint(teamId, target, 9.5);
      const finalThirdBonus = ballDepth >= 54 && goalDistance <= 48 ? 0.16 : 0;
      const roleFit =
        roleKey === "wideForward"
          ? 0.18
          : roleKey === "striker" || roleKey === "secondStriker"
            ? 0.12
            : roleKey === "connector"
              ? 0.08
              : roleKey === "rest"
                ? -0.22
                : 0;
      const score =
        openSpaceScore * 0.62 +
        actionSpace.openTarget * 0.26 +
        actionSpace.value * 0.36 +
        clamp(forwardGain / 24, 0, 1) * 0.28 +
        targetThreat.behindLine * 0.18 +
        targetThreat.centralPocket * 0.12 +
        finalThirdBonus +
        roleFit +
        option.weight * 0.08 -
        pressure * 0.22 -
        targetPressure * 0.18;

      return {
        ...option,
        target,
        score,
        openSpaceScore,
        actionSpace,
        targetThreat,
        forwardGain,
        targetPressure,
        distance: distance(startPoint, target),
      };
    })
    .filter(Boolean)
    .sort((a, b) => b.score - a.score);

  const best = candidates[0] ?? null;
  if (!best || best.score < 0.72 || best.openSpaceScore < 0.56) {
    return null;
  }

  return {
    ...best,
    active: true,
    label: goalDistance <= 42 || best.targetThreat.behindLine >= 0.38
      ? "open-grass attack"
      : "progressive carry",
  };
}

function getQuadraticPoint(startPoint, controlPoint, endPoint, progress) {
  const inverse = 1 - progress;
  return {
    x:
      inverse * inverse * startPoint.x +
      2 * inverse * progress * controlPoint.x +
      progress * progress * endPoint.x,
    y:
      inverse * inverse * startPoint.y +
      2 * inverse * progress * controlPoint.y +
      progress * progress * endPoint.y,
  };
}

function buildSampledCurvePath(startPoint, controlPoint, endPoint, samples = 28) {
  const points = [];
  let previousPoint = cloneVector(startPoint);
  let totalDistance = 0;

  points.push({
    distance: 0,
    point: cloneVector(startPoint),
  });

  for (let index = 1; index <= samples; index += 1) {
    const progress = index / samples;
    const point = getQuadraticPoint(startPoint, controlPoint, endPoint, progress);
    totalDistance += distance(previousPoint, point);
    points.push({
      distance: totalDistance,
      point,
    });
    previousPoint = point;
  }

  return {
    kind: "curve",
    start: cloneVector(startPoint),
    control: cloneVector(controlPoint),
    end: cloneVector(endPoint),
    points,
    totalDistance,
  };
}

function getSampledPathPoint(path, traveledDistance) {
  if (!path?.points?.length) {
    return cloneVector(path?.end ?? state.ball.target);
  }

  const clampedDistance = clamp(traveledDistance, 0, path.totalDistance ?? 0);
  for (let index = 1; index < path.points.length; index += 1) {
    const previous = path.points[index - 1];
    const current = path.points[index];
    if (clampedDistance > current.distance) {
      continue;
    }

    const segmentDistance = Math.max(current.distance - previous.distance, 0.001);
    const segmentProgress = (clampedDistance - previous.distance) / segmentDistance;
    return {
      x: lerp(previous.point.x, current.point.x, segmentProgress),
      y: lerp(previous.point.y, current.point.y, segmentProgress),
    };
  }

  return cloneVector(path.points[path.points.length - 1].point);
}

function buildDribbleCarryPath(carrier, startPoint, targetPoint) {
  const straightDistance = distance(startPoint, targetPoint);
  if (straightDistance <= 0.01) {
    return {
      kind: "straight",
      start: cloneVector(startPoint),
      end: cloneVector(targetPoint),
      totalDistance: 0,
    };
  }

  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(carrier.team);
  const lateralGain = Math.abs(targetPoint.y - startPoint.y);
  const openSpaceScore = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, targetPoint));
  const runwayProfile = getCarryRunwayProfile(
    carrier,
    startPoint,
    targetPoint,
    getOffensiveAutopilotProfile(carrier.team, startPoint)
  );
  const shouldCurve =
    straightDistance >= 8 &&
    forwardGain >= 4 &&
    (runwayProfile.shouldExtend || openSpaceScore >= 0.52 || lateralGain >= 4 || isWideChannel(startPoint));

  if (!shouldCurve) {
    return {
      kind: "straight",
      start: cloneVector(startPoint),
      end: cloneVector(targetPoint),
      totalDistance: straightDistance,
    };
  }

  const direction = normalize(startPoint, targetPoint);
  const lateral = { x: -direction.y, y: direction.x };
  const towardCenterSign = Math.sign(pitch.width / 2 - startPoint.y);
  const bendDirection =
    towardCenterSign !== 0
      ? Math.sign(lateral.y) === towardCenterSign ? 1 : -1
      : carrier.preferredFoot === "left" ? 1 : -1;
  const bendAmount = clamp(
    straightDistance * (
      runwayProfile.shouldExtend
        ? lerp(0.11, 0.24, openSpaceScore)
        : lerp(0.08, 0.18, openSpaceScore)
    ),
    0.75,
    runwayProfile.shouldExtend
      ? isWideChannel(startPoint) ? 7.2 : 4.8
      : isWideChannel(startPoint) ? 5.2 : 3.4
  );
  const controlPoint = clampToPitch({
    x: lerp(startPoint.x, targetPoint.x, runwayProfile.shouldExtend ? 0.5 : 0.46) + lateral.x * bendAmount * bendDirection,
    y: lerp(startPoint.y, targetPoint.y, runwayProfile.shouldExtend ? 0.5 : 0.46) + lateral.y * bendAmount * bendDirection,
  }, 2);

  if (distance(startPoint, controlPoint) <= 0.45 || distance(controlPoint, targetPoint) <= 0.45) {
    return {
      kind: "straight",
      start: cloneVector(startPoint),
      end: cloneVector(targetPoint),
      totalDistance: straightDistance,
    };
  }

  const path = buildSampledCurvePath(startPoint, controlPoint, targetPoint);
  path.runwayKind = runwayProfile.runwayKind;
  path.openSpaceScore = openSpaceScore;
  return path;
}

function getDribbleCarryPathPoint(path, traveledDistance) {
  if (!path || path.kind === "straight") {
    return moveTowards(path?.start ?? state.ball.startPosition, path?.end ?? state.ball.target, traveledDistance);
  }

  return getSampledPathPoint(path, traveledDistance);
}

function setDribbleCarryPathForBall(carrier, startPoint, targetPoint) {
  const path = buildDribbleCarryPath(carrier, startPoint, targetPoint);
  state.ball.dribblePath = path;
  state.ball.trackDistanceTotal = Math.max(path.totalDistance, distance(startPoint, targetPoint));
  state.ball.trackDistanceCovered = 0;
  return path;
}

function getLiveDribbleSpeed(carrier, targetPoint) {
  const context = getPlayerDecisionContext(carrier);
  const orientationProfile = getOrientationMovementProfile(carrier, targetPoint);
  const averageCarrySpeed = state.ball.speed || state.draftStep?.speed || state.dribbleSpeed;
  const totalDistance = Math.max(
    state.ball.trackDistanceTotal || distance(state.ball.startPosition, state.ball.target),
    0.01
  );
  const progress = state.ball.trackDistanceTotal
    ? clamp((state.ball.trackDistanceCovered ?? 0) / totalDistance, 0, 1)
    : clamp(1 - distance(carrier.position, targetPoint) / totalDistance, 0, 1);
  const nearestOpponentGap = getNearestOpponentGapInCarryLane(carrier, targetPoint);
  const openSpaceScore = getCarryLaneOpenSpaceScore(nearestOpponentGap);
  const lanePressureScore = 1 - openSpaceScore;
  const forwardAngle = angleBetween(carrier.position, targetPoint);
  const bodyAngleDelta = angleDifference(getPlayerFacingAngle(carrier), forwardAngle);
  const turnPenalty = clamp(bodyAngleDelta / (Math.PI * 0.8), 0, 1);
  const footCarryScore = getFootUsageScore(carrier, forwardAngle);
  const technicalSecurity =
    context.profile.technicalSecurity * 0.4 +
    context.profile.pressResistance * 0.22 +
    context.profile.composure * 0.2 +
    context.profile.decisionSpeed * 0.18;
  const touchFreedom = clamp(
    0.78 +
      openSpaceScore * 0.16 +
      technicalSecurity * 0.08 -
      context.pressure * 0.14 -
      lanePressureScore * 0.09,
    0.62,
    1.02
  );
  const carryPhaseFactor =
    progress < 0.18
      ? lerp(0.86, 1, progress / 0.18)
      : progress < 0.76
        ? lerp(1, 1.03 + openSpaceScore * 0.03, (progress - 0.18) / 0.58)
        : lerp(1, 0.88, (progress - 0.76) / 0.24);
  const pressurePenalty = clamp(
    1 -
      context.pressure * (0.18 + (1 - context.profile.pressResistance) * 0.14) -
      lanePressureScore * 0.08,
    0.66,
    1
  );
  const turnPenaltyFactor = lerp(1, 0.82, turnPenalty);
  const cap = Math.min(
    context.maxSpeed * lerp(0.48, 0.68, openSpaceScore),
    averageCarrySpeed * lerp(1.02, 1.12, openSpaceScore)
  );

  return clamp(
    averageCarrySpeed *
      orientationProfile.speedMultiplier *
      lerp(0.9, 1.04, footCarryScore) *
      touchFreedom *
      carryPhaseFactor *
      pressurePenalty *
      turnPenaltyFactor,
    1.95,
    Math.max(2.05, cap)
  );
}

function resolveAutoBallProfile(actionType, startPoint, targetPoint, initiator, receiverPlayerId = null) {
  const actionDistance = distance(startPoint, targetPoint);
  const teamId = initiator?.team ?? getBallOwner()?.team ?? "home";
  const forwardMeters = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const lateralMeters = Math.abs(targetPoint.y - startPoint.y);
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));

  if (actionType === "shot") {
    if (goalDistance <= 12) {
      return materializeBallProfile("box-shot", actionDistance, "goal");
    }

    if (goalDistance <= 23.5) {
      return materializeBallProfile("edge-shot", actionDistance, "goal");
    }

    return materializeBallProfile("long-shot", actionDistance, "goal");
  }

  if (actionType === "dribble") {
    return getManualBallProfile("dribble");
  }

  if (actionType === "pass" && state.restartPhase?.type === "throwIn") {
    return materializeBallProfile("throw-in", actionDistance, receiverPlayerId ? "to-feet" : "into-space");
  }

  const receiver = receiverPlayerId ? getPlayerById(receiverPlayerId) : null;
  const receiverRole = receiver?.role ?? "";
  const startsWide = isWideChannel(startPoint);
  const startsByline = isBylineZone(startPoint, teamId);
  const targetInBox = isInsideOpponentBox(targetPoint, teamId);
  const targetIsCutback = isCutbackTarget(targetPoint, teamId);
  const finalThirdDelivery = attackingDepth >= 68 && startsWide;
  const freeKickDelivery = state.restartPhase?.type === "freeKick" && targetInBox;

  if (freeKickDelivery) {
    return materializeBallProfile("cross", actionDistance, receiver ? "to-feet" : "into-space");
  }

  if (receiver) {
    if (isGoalkeeper(initiator) && actionDistance <= 18) {
      return materializeBallProfile("gk-short-build", actionDistance, "to-feet");
    }

    if (finalThirdDelivery && targetIsCutback) {
      return materializeBallProfile("cutback", actionDistance, "to-feet");
    }

    if (finalThirdDelivery && targetInBox) {
      return materializeBallProfile("cross", actionDistance, "to-feet");
    }

    if (lateralMeters >= 18 && actionDistance >= 24) {
      return materializeBallProfile("switch", actionDistance, "to-feet");
    }

    if (/striker|centre forward/i.test(receiverRole) && actionDistance >= 16 && forwardMeters >= 8) {
      return materializeBallProfile("onto-9", actionDistance, "to-feet");
    }

    if (actionDistance <= 8.5) {
      return materializeBallProfile("short-feet", actionDistance, "to-feet");
    }

    if (forwardMeters >= 6 && actionDistance <= 22) {
      return materializeBallProfile("line-break", actionDistance, "to-feet");
    }

    if (actionDistance >= 18) {
      return materializeBallProfile("driven-feet", actionDistance, "to-feet");
    }

    return materializeBallProfile("firm-feet", actionDistance, "to-feet");
  }

  if (finalThirdDelivery && (targetIsCutback || (startsByline && forwardMeters <= 2))) {
    return materializeBallProfile("cutback", actionDistance, "into-space");
  }

  if (finalThirdDelivery && targetInBox) {
    return materializeBallProfile("cross", actionDistance, "into-space");
  }

  if (lateralMeters >= 18 && actionDistance >= 24) {
    return materializeBallProfile("switch", actionDistance, "into-space");
  }

  if (actionDistance <= 12) {
    return materializeBallProfile("lead-space", actionDistance, "into-space");
  }

  return materializeBallProfile("into-space", actionDistance, "into-space");
}

function resolveBallActionProfile(
  actionType,
  startPoint,
  targetPoint,
  initiator,
  receiverPlayerId = null,
  speedMode = null
) {
  const resolvedSpeedMode =
    speedMode ?? (actionType === "dribble" ? state.dribbleSpeedMode : state.ballSpeedMode);

  if (actionType === "dribble") {
    return resolvedSpeedMode === "manual"
      ? getManualBallProfile("dribble")
      : resolveAutoDribbleProfile(startPoint, targetPoint, initiator);
  }

  if (resolvedSpeedMode === "manual") {
    const autoProfile = resolveAutoBallProfile(
      actionType,
      startPoint,
      targetPoint,
      initiator,
      receiverPlayerId
    );
    return getManualBallProfile(actionType, autoProfile);
  }

  return resolveAutoBallProfile(actionType, startPoint, targetPoint, initiator, receiverPlayerId);
}

function resolveRecordedStepProfile(step) {
  const startPoint = step.beforeSnapshot?.ball?.position ?? state.ball.position;
  const initiator = getPlayerById(step.beforeSnapshot?.ball?.ownerPlayerId);
  const distanceMeters = distance(startPoint, step.target);

  if (step.actionType === "dribble") {
    return {
      ...getManualBallProfile("dribble"),
      key: step.profileKey ?? "carry",
      label: step.profileLabel ?? "Carry",
      source: step.speedMode ?? "manual",
      averageSpeed: step.speed,
      targetKind: step.targetKind ?? "carry",
    };
  }

  if (step.actionType === "recovery") {
    return {
      key: step.profileKey ?? "loose-ball-recovery",
      label: step.profileLabel ?? "Loose Ball Recovery",
      source: step.speedMode ?? "auto",
      averageSpeed: step.speed ?? 0,
      targetKind: step.targetKind ?? "loose-ball",
      launchMultiplier: 1,
      rollFloor: 0,
      flightStyle: "ground",
      peakHeight: 0,
      controlHeightThreshold: 0.12,
      landingPhaseStart: 0.58,
      curveAmount: 0,
      spinRate: 0,
    };
  }

  if ((step.speedMode ?? state.ballSpeedMode) === "manual") {
    const savedProfileKey = step.profileKey && step.profileKey !== "manual"
      ? step.profileKey
      : null;
    const autoContextProfile = savedProfileKey
      ? materializeBallProfile(
          savedProfileKey,
          distanceMeters,
          step.targetKind ?? (step.receiverPlayerId ? "to-feet" : "into-space"),
          "auto"
        )
      : resolveAutoBallProfile(
          step.actionType,
          startPoint,
          step.target,
          initiator,
          step.receiverPlayerId ?? null
        );

    return {
      ...getManualBallProfile(step.actionType, autoContextProfile),
      key: savedProfileKey ?? autoContextProfile.key,
      label: step.profileLabel && step.profileLabel !== "Manual Speed"
        ? step.profileLabel
        : autoContextProfile.label,
      source: "manual",
      averageSpeed: step.speed,
      targetKind: step.targetKind ?? autoContextProfile.targetKind,
    };
  }

  const autoProfile = step.profileKey
    ? materializeBallProfile(
        step.profileKey,
        distanceMeters,
        step.targetKind ?? (step.receiverPlayerId ? "to-feet" : "into-space"),
        "auto"
      )
    : resolveAutoBallProfile(
        step.actionType,
        startPoint,
        step.target,
        initiator,
        step.receiverPlayerId ?? null
      );

  return {
    ...autoProfile,
    label: step.profileLabel ?? autoProfile.label,
    averageSpeed: step.speed,
    targetKind: step.targetKind ?? autoProfile.targetKind,
  };
}

function applyResolvedBallProfile(profile) {
  state.ball.profileKey = profile?.key ?? null;
  state.ball.profileLabel = profile?.label ?? null;
  state.ball.profileMode = profile?.source ?? state.ballSpeedMode;
  state.ball.targetKind = profile?.targetKind ?? null;
  state.ball.flightStyle = profile?.flightStyle ?? "ground";
  state.ball.peakHeight = profile?.peakHeight ?? 0;
  state.ball.height = 0;
  state.ball.controlHeightThreshold = profile?.controlHeightThreshold ?? 0.12;
  state.ball.landingPhaseStart = profile?.landingPhaseStart ?? 0.58;
  state.ball.curveAmount = profile?.curveAmount ?? 0;
  state.ball.spinRate = profile?.spinRate ?? 0;
  state.ball.spinAngle = 0;
  state.ball.trackDistanceCovered = 0;
  state.ball.bounceCount = 0;

  if (profile) {
    state.ball.speed = profile.averageSpeed;
  }
}

function getBallProfileLabel() {
  if (state.sequence.phase === "transition") {
    return "Transition";
  }

  if (state.ball.profileLabel) {
    const flightLabel = getFlightStyleLabel(state.ball.flightStyle);
    return state.ball.flightStyle === "ground"
      ? state.ball.profileLabel
      : `${state.ball.profileLabel} • ${flightLabel}`;
  }

  if (state.ball.actionType === "dribble") {
    return "Carry";
  }

  if (state.ball.actionType === "recovery") {
    return "Loose Ball Recovery";
  }

  return state.ballSpeedMode === "auto" ? "Auto" : "Manual";
}

function getDisplayedBallSpeed() {
  if (state.sequence.phase === "transition" && state.sequence.transition) {
    const freeBallDistance = distance(
      state.sequence.transition.ballStart,
      state.sequence.transition.ballEnd
    );
    if (
      state.sequence.transition.ballOwnerPlayerId ||
      freeBallDistance <= 0.05 ||
      state.sequence.transition.duration <= 0.01
    ) {
      return null;
    }
    return freeBallDistance / state.sequence.transition.duration;
  }

  if (state.ball.inTransit) {
    return state.ball.currentSpeed || state.ball.launchSpeed || getActionSpeed();
  }

  if (hasBallAction()) {
    return state.ball.speed;
  }

  return null;
}

function getRemainingBallTravelTime() {
  if (!hasBallAction()) {
    return 0;
  }

  if (state.ball.actionType === "recovery") {
    return Math.max((state.ball.recoveryDuration ?? 0) - state.ball.elapsedTravelTime, 0);
  }

  if (state.ball.actionType === "dribble") {
    return getRemainingBallDistance() / Math.max(getActionSpeed(), 0.01);
  }

  const remainingDistance = getRemainingBallDistance();
  if (remainingDistance <= 0.01) {
    return 0;
  }

  const speedStart = Math.max(
    state.ball.currentSpeed || state.ball.launchSpeed || getActionSpeed(),
    0.01
  );
  const speedEnd = clamp(
    state.ball.finalSpeed || Math.max(0.45, speedStart * 0.22),
    0.01,
    speedStart
  );

  return (2 * remainingDistance) / Math.max(speedStart + speedEnd, 0.01);
}

function updateBallFlightHeight() {
  if (!isAerialFlightStyle(state.ball.flightStyle)) {
    state.ball.height = 0;
    return;
  }

  const progress = getBallTravelProgress();
  const arcHeight = 4 * progress * (1 - progress);
  const styleMultiplier =
    state.ball.flightStyle === "clipped"
      ? 0.72
      : state.ball.flightStyle === "driven"
        ? 0.46
        : 1;
  state.ball.height = Math.max(0, state.ball.peakHeight * arcHeight * styleMultiplier);
}

function getBallFlightControlFactor(actionType = state.ball.actionType) {
  if (!isAerialFlightStyle(state.ball.flightStyle)) {
    return 1;
  }

  const progress = getBallTravelProgress();
  const threshold = Math.max(state.ball.controlHeightThreshold, 0.12);
  const heightFactor = clamp(1 - state.ball.height / (threshold * 2.4), 0, 1);
  const landingFactor = clamp(
    (progress - (state.ball.landingPhaseStart - 0.12)) / 0.22,
    0,
    1
  );

  if (actionType === "shot" && state.ball.flightStyle === "driven") {
    return clamp(0.42 + Math.max(heightFactor, landingFactor) * 0.58, 0.42, 1);
  }

  return Math.max(heightFactor, landingFactor);
}

function applyBallExecutionProfile(actionType, initiator, target, ballProfile = null) {
  const laneClarity =
    actionType === "pass"
      ? computePassLaneClarity(initiator, target)
      : actionType === "shot"
        ? computeShotLaneClarity(initiator, target)
        : 0.84;
  const context = initiator ? getPlayerDecisionContext(initiator) : null;
  const footExecutionScore =
    initiator && target
      ? getFootUsageScore(initiator, angleBetween(initiator.position, target))
      : 0.84;
  const shotWindow =
    actionType === "shot" && initiator
      ? getShotWindowProfile(initiator, getPlayerBallControlPoint(initiator), target)
      : null;
  const executionQuality = clamp(
    initiator && context
      ? (actionType === "shot"
          ? 0.22 * context.profile.decisionQuality +
            0.28 * context.profile.technicalSecurity +
            0.2 * context.profile.executionUnderPressure +
            0.12 * context.profile.composure +
            0.08 * footExecutionScore +
            0.12 * laneClarity +
            0.12 * (shotWindow?.angleQuality ?? 0.42) +
            0.08 * (shotWindow?.goalkeeperOpenness ?? 0.5) -
            context.pressure * 0.12 -
            (shotWindow?.blockRisk ?? 0) * 0.08
          : 0.26 * context.profile.decisionQuality +
            0.32 * context.profile.technicalSecurity +
            0.24 * context.profile.executionUnderPressure +
            0.1 * context.profile.composure +
            0.06 * footExecutionScore +
            0.08 * laneClarity -
            context.pressure * 0.08)
      : 0.76,
    0.42,
    0.98
  );
  const targetKind = ballProfile?.targetKind ?? null;
  const claimBase = targetKind === "into-space" ? 2.15 : 1.8;
  const claimCeiling = targetKind === "into-space"
    ? actionType === "shot" ? 6 : 5.2
    : actionType === "shot" ? 5.8 : 4.8;
  const claimRadius = clamp(
    claimBase + (1 - executionQuality) * (actionType === "shot" ? 4.2 : 3.2),
    1.6,
    claimCeiling
  );
  const controlBase = targetKind === "to-feet" ? 0.82 : 0.68;
  const controlRadius = clamp(
    controlBase + executionQuality * 1.4 + laneClarity * 0.55,
    0.8,
    targetKind === "to-feet" ? 2.3 : 2.55
  );

  state.ball.laneClarity = laneClarity;
  state.ball.executionQuality = executionQuality;
  state.ball.claimRadius = claimRadius;
  state.ball.controlRadius = controlRadius;
}

function getLooseBallClaimScore(player, point) {
  const context = getPlayerDecisionContext(player);
  const gap = distance(player.position, point);
  const timeToBall = computeTimeToCoverDistance(player, gap, point);
  const proximity = clamp(1 - gap / 8.5, 0, 1);

  return (
    context.profile.perception * 0.17 +
    context.profile.decisionSpeed * 0.16 +
    context.profile.decisionQuality * 0.14 +
    context.profile.technicalSecurity * 0.17 +
    context.profile.pressResistance * 0.14 +
    context.profile.composure * 0.12 +
    proximity * 0.5 -
    timeToBall * 0.16
  );
}

function getShotReboundClaimContext(point, options = {}) {
  if (!point) {
    return { active: false };
  }

  const sourceText = [
    options.source,
    options.reboundType,
    state.ball.secondBallContext?.source,
    state.ball.profileKey,
    state.ball.actionType,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
  const isShotRebound =
    sourceText.includes("shot") ||
    sourceText.includes("parry") ||
    sourceText.includes("save") ||
    sourceText.includes("block");

  if (!isShotRebound) {
    return { active: false };
  }

  const initiator = getActionInitiator();
  const attackingTeamId =
    options.attackingTeamId ??
    state.ball.secondBallContext?.attackingTeamId ??
    initiator?.team ??
    getPlayerById(state.ball.initiatorPlayerId)?.team ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId)?.team ??
    getPlannedPossessionTeamId() ??
    null;

  if (!attackingTeamId) {
    return { active: false };
  }

  const defendingTeamId =
    options.defendingTeamId ??
    state.ball.secondBallContext?.defendingTeamId ??
    getOtherTeamId(attackingTeamId);
  const attackSign = Math.cos(getTeamAttackAngle(attackingTeamId)) >= 0 ? 1 : -1;
  const goalPoint = {
    x: attackSign > 0 ? pitch.length : 0,
    y: pitch.width / 2,
  };
  const penaltySpot = {
    x: goalPoint.x - attackSign * 11,
    y: pitch.width / 2,
  };
  const threat = getPitchThreatProfile(point, attackingTeamId);

  return {
    active: true,
    sourceText,
    attackingTeamId,
    defendingTeamId,
    attackSign,
    goalPoint,
    penaltySpot,
    threat,
    insideAttackingBox: isInsideOpponentBox(point, attackingTeamId),
    insideDefendingBox: defendingTeamId ? isInsideOwnBox(point, defendingTeamId) : false,
    urgency: clamp(
      options.urgency ?? state.ball.secondBallContext?.urgency ?? 0.56,
      0.2,
      0.96
    ),
    isParry: sourceText.includes("parry") || sourceText.includes("save"),
    isBlockedShot: sourceText.includes("block") || sourceText.includes("deflection"),
  };
}

function getShotReboundClaimAdjustment(player, point, context) {
  if (!context?.active || !player || !point) {
    return 0;
  }

  const label = getPlayerMagnetLabel(player);
  const gap = distance(player.position, point);
  const proximity = clamp(1 - gap / 12, 0, 1);
  const orientation = getOrientationMovementProfile(player, point).receiveModifier;
  const contextProfile = getPlayerDecisionContext(player).profile;
  const isAttacking = player.team === context.attackingTeamId;
  const isDefending = player.team === context.defendingTeamId;
  const goalSide = context.attackSign * (player.position.x - point.x);
  const poacherSide = clamp(goalSide / 8, 0, 1);
  const defenderGoalSide = clamp(goalSide / 7, 0, 1);
  const centralRebound =
    context.threat.centrality * 0.08 +
    context.threat.box * 0.05 +
    clamp(1 - distance(point, context.penaltySpot) / 16, 0, 1) * 0.08;
  let adjustment = (orientation - 0.5) * 0.05 + proximity * 0.04;

  if (isAttacking) {
    if (isGoalkeeper(player)) {
      return adjustment - 0.45;
    }

    if (label === "9") adjustment += 0.2;
    if (label === "W") adjustment += 0.15;
    if (label === "10") adjustment += 0.13;
    if (label === "8") adjustment += 0.1;
    if (label === "6") adjustment += 0.04;
    if (label === "LB" || label === "RB" || label === "WB") adjustment += context.threat.cutbackZone * 0.05;

    adjustment +=
      context.threat.value * 0.1 +
      context.urgency * 0.05 +
      poacherSide * 0.08 +
      centralRebound +
      contextProfile.decisionSpeed * 0.04 +
      contextProfile.composure * 0.04;

    if (!context.insideAttackingBox && context.threat.depth < 55) {
      adjustment -= 0.04;
    }
  }

  if (isDefending) {
    if (isGoalkeeper(player)) adjustment += context.insideDefendingBox ? 0.23 : 0.08;
    if (label === "CB") adjustment += 0.21;
    if (label === "LB" || label === "RB" || label === "WB") adjustment += 0.14;
    if (label === "6") adjustment += 0.13;
    if (label === "8" || label === "10") adjustment += 0.07;
    if (label === "W" || label === "9") adjustment += context.insideDefendingBox ? -0.04 : 0.02;

    adjustment +=
      defenderGoalSide * 0.1 +
      centralRebound * 0.9 +
      context.threat.value * 0.07 +
      context.urgency * 0.04 +
      contextProfile.perception * 0.035 +
      contextProfile.tacticalDiscipline * 0.055;

  }

  return clamp(adjustment, -0.5, 0.5);
}

function getBallContestControlScore(player, point, actionType) {
  const context = getPlayerDecisionContext(player);
  const orientation = getOrientationMovementProfile(player, point).receiveModifier;
  const actionDifficulty = actionType === "shot" ? 0.12 : 0;

  return clamp(
    context.profile.technicalSecurity * 0.28 +
      context.profile.perception * 0.18 +
      context.profile.decisionSpeed * 0.14 +
      context.profile.pressResistance * 0.16 +
      context.profile.composure * 0.14 +
      orientation * 0.14 -
      context.pressure * 0.1 -
      actionDifficulty,
    0.18,
    0.98
  );
}

function getAerialPresence(player) {
  const label = getPlayerMagnetLabel(player);

  if (label === "GK") return 0.96;
  if (label === "CB") return 0.9;
  if (label === "9") return 0.84;
  if (label === "6") return 0.78;
  if (label === "8" || label === "10") return 0.74;
  if (label === "WB" || label === "LB" || label === "RB") return 0.72;
  if (label === "W") return 0.64;

  return 0.72;
}

function getAerialContestScore(player, point, incomingPoint, preferredPlayerId = null, preferredBoost = 0) {
  const context = getPlayerDecisionContext(player);
  const gap = distance(player.position, point);
  const proximity = clamp(1 - gap / 3.6, 0, 1);
  const orientation = getOrientationMovementProfile(player, point).coverModifier;
  const ballSight = incomingPoint
    ? clamp(1 - angleDifference(getPlayerFacingAngle(player), angleBetween(player.position, incomingPoint)) / Math.PI, 0, 1)
    : 0.82;

  return (
    getAerialPresence(player) * 0.28 +
    context.profile.perception * 0.14 +
    context.profile.decisionSpeed * 0.12 +
    context.profile.composure * 0.12 +
    context.profile.pressResistance * 0.1 +
    context.profile.technicalSecurity * 0.08 +
    orientation * 0.08 +
    ballSight * 0.08 +
    proximity * 0.22 +
    (player.id === preferredPlayerId ? preferredBoost : 0)
  );
}

function getAerialFirstContactContext(actionType, point, incomingPoint, receiver = null) {
  const initiator = getActionInitiator();
  const attackingTeamId =
    initiator?.team ??
    receiver?.team ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId)?.team ??
    getPlayerById(state.ball.initiatorPlayerId)?.team ??
    null;
  const defendingTeamId = attackingTeamId ? getOtherTeamId(attackingTeamId) : null;
  const profileText = [
    state.ball.profileKey,
    state.ball.profileLabel,
    state.ball.targetKind,
    state.draftStep?.profileKey,
    state.draftStep?.profileLabel,
    ...(state.draftStep?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const targetThreat = attackingTeamId ? getPitchThreatProfile(point, attackingTeamId) : null;
  const inAttackingBox = attackingTeamId ? isInsideOpponentBox(point, attackingTeamId) : false;
  const inDefendingBox = defendingTeamId ? isInsideOwnBox(point, defendingTeamId) : false;
  const crossLike =
    profileText.includes("cross") ||
    profileText.includes("delivery") ||
    profileText.includes("lofted") ||
    (inAttackingBox && state.ball.flightStyle === "lofted");
  const secondBallZone =
    inAttackingBox ||
    (targetThreat?.assistZone ?? 0) >= 0.28 ||
    (targetThreat?.behindLine ?? 0) >= 0.22;

  return {
    actionType,
    attackingTeamId,
    defendingTeamId,
    incomingPoint,
    point,
    profileText,
    targetThreat,
    inAttackingBox,
    inDefendingBox,
    crossLike,
    secondBallZone,
  };
}

function getAerialFirstContactScore(player, point, incomingPoint, context, preferredPlayerId = null, preferredBoost = 0) {
  const baseScore = getAerialContestScore(player, point, incomingPoint, preferredPlayerId, preferredBoost);
  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const teamIsAttacking = player.team === context.attackingTeamId;
  const teamIsDefending = player.team === context.defendingTeamId;
  const gap = distance(player.position, point);
  const timeToBall = computeTimeToCoverDistance(player, gap, point);
  const arrivalFit = clamp(1 - timeToBall / 1.25, -0.12, 0.22);
  const ownBoxClaim =
    isGoalkeeper(player) && teamIsDefending && context.inDefendingBox
      ? 0.24 + getAerialPresence(player) * 0.08
      : 0;
  const defensiveClearanceBonus =
    teamIsDefending && context.secondBallZone
      ? (roleKey === "rest" ? 0.08 : 0) + (getPlayerMagnetLabel(player) === "CB" ? 0.12 : 0.04)
      : 0;
  const attackingContactBonus =
    teamIsAttacking && context.crossLike && context.inAttackingBox
      ? (roleKey === "striker" || roleKey === "wideForward" || roleKey === "secondStriker" ? 0.14 : 0.05)
      : 0;
  const underBallBonus =
    Math.abs(player.position.y - point.y) <= 2.8 ? 0.04 : 0;

  return (
    baseScore +
    arrivalFit +
    ownBoxClaim +
    defensiveClearanceBonus +
    attackingContactBonus +
    underBallBonus
  );
}

function getAerialDefensiveClearanceAngle(winner, contestPoint, incomingAngle) {
  const teamExitAngle = getTeamAttackAngle(winner.team);
  const sideSign = Math.sign(contestPoint.y - pitch.width / 2) || (winner.position.y >= pitch.width / 2 ? 1 : -1);
  const wideExit = normalizeAngle(teamExitAngle + sideSign * 0.22);
  return blendAngles(wideExit, incomingAngle, 0.74, 0.26);
}

function getAerialAttackingKnockdownAngle(winner, contestPoint, context) {
  const goal = getOpponentGoalCenter(winner.team);
  const penaltySpot = getOpponentPenaltySpot(winner.team);
  const towardGoal = angleBetween(contestPoint, goal);
  const towardSecondBall = angleBetween(contestPoint, {
    x: lerp(contestPoint.x, penaltySpot.x, 0.58),
    y: lerp(contestPoint.y, pitch.width / 2, 0.72),
  });

  if ((context.targetThreat?.box ?? 0) >= 0.28 && getAerialPresence(winner) >= 0.78) {
    return blendAngles(towardGoal, towardSecondBall, 0.58, 0.42);
  }

  return blendAngles(towardSecondBall, getTeamAttackAngle(winner.team), 0.72, 0.28);
}

function getAerialControlScore(player, incomingPoint) {
  const context = getPlayerDecisionContext(player);
  const receiveOrientationScore = getReceiveOrientationScore(player, incomingPoint);
  const footScore = getReceiveFootUsageScore(player, incomingPoint);

  return clamp(
    context.profile.technicalSecurity * 0.26 +
      context.profile.pressResistance * 0.18 +
      context.profile.composure * 0.16 +
      context.profile.decisionQuality * 0.12 +
      getAerialPresence(player) * 0.14 +
      receiveOrientationScore * 0.08 +
      footScore * 0.06 -
      context.pressure * 0.08,
    0.18,
    0.98
  );
}

function getBallDuelScore(player, point) {
  const context = getPlayerDecisionContext(player);
  const gap = distance(player.position, point);
  const orientation = getOrientationMovementProfile(player, point).coverModifier;
  const proximity = clamp(1 - gap / 3.2, 0, 1);

  return (
    context.profile.pressResistance * 0.24 +
    context.profile.composure * 0.16 +
    context.profile.technicalSecurity * 0.14 +
    context.profile.tacticalDiscipline * 0.12 +
    context.profile.decisionQuality * 0.12 +
    orientation * 0.12 +
      proximity * 0.22
  );
}

function clearSecurePossession() {
  state.ball.securePossession = null;
}

function getBallWinEscapeTouch(winner, loser, point = state.ball.position, reason = "tackle") {
  if (!winner || !loser || winner.team === loser.team) {
    return null;
  }

  const contestPoint = clampToPitch(point ?? getPlayerBallControlPoint(winner), 1.5);
  const winnerContext = getPlayerDecisionContext(winner);
  const roleKey = getOffensiveRoleKey(winner, teams[winner.team]?.formation);
  const attackSign = getAttackDirectionSign(winner.team);
  const awayFromLoser = normalize(loser.position ?? contestPoint, contestPoint);
  const forwardVector = { x: attackSign, y: 0 };
  const insideTarget = {
    x: contestPoint.x + attackSign * 2.8,
    y: pitch.width / 2,
  };
  const insideVector = normalize(contestPoint, insideTarget);
  const isRestOrBack = roleKey === "rest" || roleKey === "wideBack" || roleKey === "gk";
  const pressure = getPlayerPressureLoad(winner, contestPoint);
  const security =
    winnerContext.profile.pressResistance * 0.34 +
    winnerContext.profile.composure * 0.24 +
    winnerContext.profile.technicalSecurity * 0.22 +
    winnerContext.profile.decisionQuality * 0.12;
  const counterBias = isTransitionAttackStyle(getTeamAttackStyleKey(winner.team)) ? 0.22 : 0;
  const forwardWeight = clamp(
    0.2 +
      counterBias +
      (roleKey === "wideForward" || roleKey === "striker" || roleKey === "secondStriker" ? 0.16 : 0) -
      (isRestOrBack ? 0.1 : 0) -
      pressure * 0.08,
    0.08,
    0.54
  );
  const insideWeight = clamp(
    0.28 +
      (isRestOrBack ? 0.16 : 0) +
      pressure * 0.1,
    0.2,
    0.58
  );
  const awayWeight = clamp(
    0.62 +
      pressure * 0.16 +
      (reason === "tackle" ? 0.1 : 0),
    0.48,
    0.84
  );
  const combined = {
    x: awayFromLoser.x * awayWeight + insideVector.x * insideWeight + forwardVector.x * forwardWeight,
    y: awayFromLoser.y * awayWeight + insideVector.y * insideWeight + forwardVector.y * forwardWeight,
  };
  const combinedLength = Math.hypot(combined.x, combined.y) || 1;
  const escapeDirection = {
    x: combined.x / combinedLength,
    y: combined.y / combinedLength,
  };
  const touchDistance = clamp(
    0.78 +
      security * 0.58 +
      (reason === "interception" ? 0.32 : 0.16) -
      pressure * 0.24,
    0.68,
    reason === "interception" ? 1.72 : 1.42
  );
  const escapePoint = clampToPitch({
    x: contestPoint.x + escapeDirection.x * touchDistance,
    y: contestPoint.y + escapeDirection.y * touchDistance,
  }, 1.5);
  const playerTarget = getPlayerPositionForControlPoint(
    winner,
    escapePoint,
    angleBetween(contestPoint, escapePoint)
  );

  return {
    contestPoint,
    escapePoint,
    playerTarget: clampToPitch(playerTarget, 1.5),
    facingAngle: angleBetween(contestPoint, escapePoint),
    touchDistance,
    pressure,
  };
}

function applyBallWinEscapeTouch(winner, loser, point = state.ball.position, reason = "tackle") {
  const escape = getBallWinEscapeTouch(winner, loser, point, reason);
  if (!escape) {
    return null;
  }

  const currentControlPoint = getPlayerBallControlPoint(winner);
  const currentGap = distance(currentControlPoint, escape.escapePoint);
  const maxAdjustment = reason === "interception" ? 1.05 : 0.86;
  const adjustmentRatio = currentGap <= 0.01 ? 0 : clamp(maxAdjustment / currentGap, 0, 1);
  const nextControlPoint = {
    x: lerp(currentControlPoint.x, escape.escapePoint.x, adjustmentRatio),
    y: lerp(currentControlPoint.y, escape.escapePoint.y, adjustmentRatio),
  };
  const playerTarget = getPlayerPositionForControlPoint(winner, nextControlPoint, escape.facingAngle);

  winner.position = clampToPitch(playerTarget, 1.5);
  winner.bodyAngle = escape.facingAngle;
  winner.movementProgress = 0;
  state.ball.ownerPlayerId = winner.id;
  state.ball.position = cloneVector(getPlayerBallControlPoint(winner));
  state.ball.target = cloneVector(state.ball.position);

  return {
    ...escape,
    appliedPoint: cloneVector(state.ball.position),
  };
}

function setSecurePossessionAfterBallWin(winner, loser, point = state.ball.position, reason = "tackle") {
  if (!winner || !loser || winner.team === loser.team) {
    clearSecurePossession();
    return;
  }

  const escape = applyBallWinEscapeTouch(winner, loser, point, reason);

  state.ball.securePossession = {
    ownerPlayerId: winner.id,
    opponentPlayerId: loser.id,
    point: cloneVector(point),
    escapePoint: escape?.appliedPoint ? cloneVector(escape.appliedPoint) : null,
    createdAt: state.time,
    reason,
    minDistanceToExpire: reason === "interception" ? 6.1 : 7.8,
    minTimeToExpire: reason === "interception" ? 1.45 : 1.85,
  };
}

function getPossessionShieldOpponents(owner, point, radius = 4.8) {
  if (!owner || !point) {
    return [];
  }

  return state.players
    .filter((player) => player.team !== owner.team && !isGoalkeeper(player))
    .map((player) => ({
      player,
      gap: distance(player.position, point),
    }))
    .filter((entry) => entry.gap <= radius)
    .sort((a, b) => a.gap - b.gap);
}

function setSecurePossessionAfterControlledTouch(owner, point = state.ball.position, options = {}) {
  if (!owner || !point) {
    return;
  }

  const currentSecure = state.ball.securePossession;
  const currentReason = currentSecure?.reason ?? "";
  const keepStrongerBallWinShield =
    currentSecure?.ownerPlayerId === owner.id &&
    (currentReason === "tackle" || currentReason === "interception");
  if (keepStrongerBallWinShield) {
    return;
  }

  const context = getPlayerDecisionContext(owner);
  const quality = clamp(
    options.quality ??
      (
        context.profile.technicalSecurity * 0.36 +
        context.profile.pressResistance * 0.24 +
        context.profile.composure * 0.18 +
        context.profile.decisionQuality * 0.12 -
        context.pressure * 0.08
      ),
    0.34,
    0.98
  );
  const reason = options.reason ?? "controlled-reception";
  const shieldRadius = clamp(
    options.shieldRadius ?? lerp(3.15, 4.75, quality),
    2.6,
    5.4
  );
  const nearbyOpponents = getPossessionShieldOpponents(owner, point, shieldRadius + 0.85);
  const nearestOpponent = nearbyOpponents[0]?.player ?? null;
  const activePressure = Math.max(context.pressure, nearbyOpponents.length ? 0.34 : 0);
  const reasonStrength =
    reason === "loose-ball-collect"
      ? 0.44
      : reason === "rebound-control"
        ? 0.36
        : 0.48;

  state.ball.securePossession = {
    ownerPlayerId: owner.id,
    opponentPlayerId: nearestOpponent?.id ?? null,
    opponentPlayerIds: nearbyOpponents.slice(0, 4).map((entry) => entry.player.id),
    point: cloneVector(point),
    escapePoint: cloneVector(getPlayerBallControlPoint(owner)),
    createdAt: state.time,
    reason,
    shieldRadius,
    shieldStrength: clamp(
      reasonStrength +
        quality * 0.2 +
        activePressure * 0.08 +
        clamp(nearbyOpponents.length / 4, 0, 1) * 0.06,
      0.36,
      0.76
    ),
    minDistanceToExpire: clamp(
      options.minDistanceToExpire ?? lerp(3.7, 6.2, quality),
      3.1,
      6.8
    ),
    minTimeToExpire: clamp(
      options.minTimeToExpire ?? lerp(0.7, 1.28, quality),
      0.55,
      1.45
    ),
  };
}

function keepSecurePossessionOnlyForOwner(ownerPlayerId) {
  if (state.ball.securePossession && state.ball.securePossession.ownerPlayerId !== ownerPlayerId) {
    clearSecurePossession();
  }
}

function getSecurePossessionContext(owner, challenger) {
  const secure = state.ball.securePossession;
  if (!secure || !owner || !challenger || owner.id !== secure.ownerPlayerId) {
    return null;
  }

  const explicitOpponentMatch =
    challenger.id === secure.opponentPlayerId ||
    (Array.isArray(secure.opponentPlayerIds) && secure.opponentPlayerIds.includes(challenger.id));
  const controlledTouchShield =
    (secure.reason === "controlled-reception" ||
      secure.reason === "loose-ball-collect" ||
      secure.reason === "rebound-control") &&
    distance(challenger.position, owner.position) <= (secure.shieldRadius ?? 3.4);

  if (!explicitOpponentMatch && !controlledTouchShield) {
    return null;
  }

  const origin = secure.point ?? owner.position;
  const movedFromDuel = distance(owner.position, origin);
  const actionElapsed = state.ball.inTransit ? state.ball.elapsedTravelTime : 0;
  const distanceProgress = movedFromDuel / Math.max(secure.minDistanceToExpire ?? 5, 0.01);
  const timeProgress = actionElapsed / Math.max(secure.minTimeToExpire ?? 1, 0.01);
  const protectionRatio = clamp(
    (1 - Math.max(distanceProgress, timeProgress)) * (secure.shieldStrength ?? 1),
    0,
    1
  );

  if (protectionRatio <= 0.01) {
    clearSecurePossession();
    return null;
  }

  return {
    movedFromDuel,
    actionElapsed,
    protectionRatio,
  };
}

function getDribbleTackleCandidate(carrier) {
  if (!carrier || state.ball.actionType !== "dribble" || state.ball.elapsedTravelTime < 0.28) {
    return null;
  }

  const startPoint = state.ball.startPosition;
  const targetPoint = state.ball.target;
  const totalLaneDistance = distance(startPoint, targetPoint);
  if (totalLaneDistance <= 0.25) {
    return null;
  }

  const ballProgress = getBallTravelProgress();
  const currentCarrySpeed = Math.max(state.ball.currentSpeed || getLiveDribbleSpeed(carrier, targetPoint), 0.1);
  const carrierContext = getPlayerDecisionContext(carrier);
  const aggression = getDefensiveAggressionPreset();
  const baseCarrierControlScore =
    getBallDuelScore(carrier, state.ball.position) +
    carrierContext.profile.pressResistance * 0.2 +
    carrierContext.profile.technicalSecurity * 0.15 +
    carrierContext.profile.composure * 0.12 +
    clamp(currentCarrySpeed / 8.5, 0, 1) * 0.07;
  let bestCandidate = null;

  state.players.forEach((player) => {
    if (player.team === carrier.team || player.id === carrier.id || isGoalkeeper(player)) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, targetPoint);
    const laneGap = distance(player.position, projection.point);
    const bodyGap = distance(player.position, carrier.position);
    const ballGap = distance(player.position, state.ball.position);
    const defenderContext = getPlayerDecisionContext(player);
    const tackleReach = clamp(
      (1.12 +
        defenderContext.profile.perception * 0.22 +
        defenderContext.profile.decisionSpeed * 0.2 +
        defenderContext.profile.tacticalDiscipline * 0.18) *
        aggression.reachMultiplier,
      1.12,
      2.05
    );
    const bodyContactScore = clamp(1 - (bodyGap - 1.35) / (1.35 * aggression.contactWindow), 0, 1);
    const ballContactScore = clamp(1 - (ballGap - 0.75) / (1.75 * aggression.contactWindow), 0, 1);
    const laneProgressWindow =
      projection.ratio >= ballProgress - aggression.laneBehindWindow &&
      projection.ratio <= ballProgress + aggression.laneAheadWindow;
    const carrierTimeToLane = distance(carrier.position, projection.point) / currentCarrySpeed;
    const defenderTimeToLane = computeTimeToCoverDistance(
      player,
      distance(player.position, projection.point),
      projection.point
    );
    const etaScore = laneProgressWindow
      ? clamp(1 - Math.abs(defenderTimeToLane - carrierTimeToLane) / aggression.etaTolerance, 0, 1)
      : 0;
    const laneScore = laneProgressWindow
      ? clamp(1 - laneGap / tackleReach, 0, 1) * etaScore
      : 0;
    const closeEnoughForTackle =
      (bodyGap <= playerRadiusMeters * 1.95 * aggression.contactWindow &&
        ballGap <= state.ball.controlRadius + 1.35 * aggression.contactWindow) ||
      laneScore >= aggression.laneScoreThreshold;

    if (!closeEnoughForTackle) {
      return;
    }

    const approachAngle = angleBetween(player.position, state.ball.position);
    const carrierCarryAngle = angleBetween(carrier.position, targetPoint);
    const frontOrSidePressure = clamp(
      1 - Math.max(0, Math.cos(normalizeAngle(approachAngle - carrierCarryAngle))) * 0.55,
      0.35,
      1
    );
    const defenderScore =
      getBallDuelScore(player, state.ball.position) +
      defenderContext.profile.tacticalDiscipline * 0.13 +
      defenderContext.profile.decisionSpeed * 0.1 +
      bodyContactScore * 0.28 +
      ballContactScore * 0.2 +
      laneScore * 0.34 +
      etaScore * 0.1 +
      frontOrSidePressure * 0.08 +
      aggression.scoreBonus;
    const secureContext = getSecurePossessionContext(carrier, player);
    const secureProtection = secureContext?.protectionRatio ?? 0;
    const adjustedCarrierControlScore =
      baseCarrierControlScore +
      secureProtection * 0.36 +
      clamp(currentCarrySpeed / 5.5, 0, 1) * secureProtection * 0.06;
    const adjustedDefenderScore = defenderScore - secureProtection * 0.2;
    const margin = adjustedDefenderScore - adjustedCarrierControlScore;
    const requiredMargin = aggression.marginThreshold + secureProtection * 0.22;
    const requiredContestedMargin = aggression.contestedMargin + secureProtection * 0.14;
    const decisiveContact =
      bodyContactScore >= 0.58 + secureProtection * 0.18 &&
      ballContactScore >= 0.42 + secureProtection * 0.18;
    const decisiveLaneTiming = laneScore >= 0.62 + secureProtection * 0.18;

    if (
      margin < requiredMargin &&
      !(margin >= requiredContestedMargin && (decisiveContact || decisiveLaneTiming))
    ) {
      return;
    }

    const candidate = {
      player,
      point: cloneVector(state.ball.position),
      bodyGap,
      ballGap,
      laneGap,
      laneScore,
      etaScore,
      score: adjustedDefenderScore + Math.max(bodyContactScore, laneScore) * 0.16 - secureProtection * 0.18,
    };

    if (!bestCandidate || candidate.score > bestCandidate.score) {
      bestCandidate = candidate;
    }
  });

  return bestCandidate;
}

function getDribbleFoulCandidate(carrier) {
  if (!carrier || state.ball.actionType !== "dribble" || state.ball.elapsedTravelTime < 0.34) {
    return null;
  }

  const startPoint = state.ball.startPosition;
  const targetPoint = state.ball.target;
  const totalLaneDistance = distance(startPoint, targetPoint);
  if (totalLaneDistance <= 0.25) {
    return null;
  }

  const ballProgress = getBallTravelProgress();
  const currentCarrySpeed = Math.max(state.ball.currentSpeed || getLiveDribbleSpeed(carrier, targetPoint), 0.1);
  const aggression = getDefensiveAggressionPreset();
  const aggressionFoulRisk =
    state.defensiveAggressionPreset === "aggressive"
      ? 0.13
      : state.defensiveAggressionPreset === "conservative"
        ? -0.08
        : 0.02;
  let bestCandidate = null;

  state.players.forEach((player) => {
    if (player.team === carrier.team || player.id === carrier.id || isGoalkeeper(player)) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, targetPoint);
    const bodyGap = distance(player.position, carrier.position);
    const ballGap = distance(player.position, state.ball.position);
    const laneGap = distance(player.position, projection.point);
    const defenderContext = getPlayerDecisionContext(player);
    const bodyContactScore = clamp(1 - (bodyGap - 1.25) / (1.4 * aggression.contactWindow), 0, 1);
    const ballContactScore = clamp(1 - (ballGap - 0.65) / (1.7 * aggression.contactWindow), 0, 1);
    const laneProgressWindow =
      projection.ratio >= ballProgress - aggression.laneBehindWindow * 1.25 &&
      projection.ratio <= ballProgress + aggression.laneAheadWindow * 0.75;
    const carrierTimeToLane = distance(carrier.position, projection.point) / currentCarrySpeed;
    const defenderTimeToLane = computeTimeToCoverDistance(
      player,
      distance(player.position, projection.point),
      projection.point
    );
    const lateScore = laneProgressWindow
      ? clamp((defenderTimeToLane - carrierTimeToLane + 0.18) / 0.62, 0, 1)
      : 0;
    const approachAngle = angleBetween(player.position, state.ball.position);
    const carrierCarryAngle = angleBetween(carrier.position, targetPoint);
    const behindScore = clamp(Math.cos(normalizeAngle(approachAngle - carrierCarryAngle)), 0, 1);
    const carelessContact =
      bodyContactScore >= 0.58 &&
      ballContactScore <= 0.42 &&
      (behindScore >= 0.38 || lateScore >= 0.28 || laneGap <= playerRadiusMeters * 1.55);

    if (!carelessContact) {
      return;
    }

    const foulScore =
      bodyContactScore * 0.4 +
      (1 - ballContactScore) * 0.24 +
      lateScore * 0.22 +
      behindScore * 0.18 +
      aggressionFoulRisk -
      defenderContext.profile.tacticalDiscipline * 0.13 -
      defenderContext.profile.decisionQuality * 0.07;
    const isPenalty = isInsideOpponentBox(state.ball.position, carrier.team);
    const threshold = isPenalty ? 0.74 : 0.66;

    if (foulScore < threshold) {
      return;
    }

    const candidate = {
      player,
      fouledPlayer: carrier,
      point: cloneVector(state.ball.position),
      restartType: isPenalty ? "penalty" : "freeKick",
      score: foulScore,
      bodyGap,
      ballGap,
      lateScore,
      behindScore,
    };

    if (!bestCandidate || candidate.score > bestCandidate.score) {
      bestCandidate = candidate;
    }
  });

  return bestCandidate;
}

function completeDribbleFoulRestart(foul, completedTravelTime) {
  const restartTeamName = teams[foul.fouledPlayer.team]?.name ?? "Attacking team";
  const foulTypeLabel = foul.restartType === "penalty" ? "penalty" : "free-kick";
  state.ball.inTransit = false;
  state.ball.height = 0;
  state.ball.position = cloneVector(foul.point);
  state.ball.target = cloneVector(foul.point);
  state.ball.ownerPlayerId = null;
  clearSecurePossession();

  if (state.sequence.isPlaying) {
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.carrierPlayerId = null;
    state.ball.receiverPlayerId = null;
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.afterSnapshot) {
      applyCommittedSnapshot(step.afterSnapshot);
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    logEvent(
      `${foul.player.shortLabel} ${foul.player.role} fouls ${foul.fouledPlayer.shortLabel} ${foul.fouledPlayer.role}. ${restartTeamName} restart with a ${foulTypeLabel}.`
    );
    queueNextSequenceStep();
    return;
  }

  completeLiveActionPlayersBeforeCommit(foul.point);
  if (state.draftStep) {
    state.draftStep.nextRestartPhase = {
      type: foul.restartType,
      teamId: foul.fouledPlayer.team,
      label: setPiecePhaseProfiles[foul.restartType].label,
      point: foul.restartType === "freeKick" ? cloneVector(foul.point) : null,
    };
    state.draftStep.target = cloneVector(foul.point);
  }
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.carrierPlayerId = null;
  state.ball.receiverPlayerId = null;
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(
    `${foul.player.shortLabel} ${foul.player.role} fouls ${foul.fouledPlayer.shortLabel} ${foul.fouledPlayer.role} after ${formatTime(completedTravelTime)}. ${restartTeamName} restart with a ${foulTypeLabel}.`
  );
  scheduleAutoPilotContinuation(null, "dribble");
}

function resolveDribbleDefensiveChallenge() {
  const carrier = getPlayerById(state.ball.carrierPlayerId);
  const candidate = getDribbleTackleCandidate(carrier);

  if (!candidate) {
    const foul = getDribbleFoulCandidate(carrier);
    if (foul) {
      completeDribbleFoulRestart(foul, state.ball.elapsedTravelTime);
      return true;
    }

    return false;
  }

  state.ball.inTransit = false;
  connectBallToPlayerForNextAction(candidate.player, candidate.point, 0.7);
  setSecurePossessionAfterBallWin(candidate.player, carrier, candidate.point, "tackle");
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.carrierPlayerId = null;
  state.ball.receiverPlayerId = null;

  if (state.sequence.isPlaying) {
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step) {
      step.afterSnapshot = cloneSnapshot(captureSnapshot());
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    logEvent(
      `${candidate.player.shortLabel} ${candidate.player.role} wins the ball with a tackle on ${carrier.shortLabel} ${carrier.role}.`
    );
    queueNextSequenceStep();
    return true;
  }

  completeLiveActionPlayersBeforeCommit(state.ball.position);
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(
    `${candidate.player.shortLabel} ${candidate.player.role} wins the ball with a tackle on ${carrier.shortLabel} ${carrier.role}.`
  );
  scheduleAutoPilotContinuation();
  return true;
}

function resolveLooseBallClaim(point, claimRadius, preferredPlayerId = null, preferredBoost = 0, options = {}) {
  let bestImmediate = null;
  let bestSecondBall = null;
  const reboundContext = getShotReboundClaimContext(point, options);

  state.players.forEach((player) => {
    if (options.canClaimPlayer && !options.canClaimPlayer(player)) {
      return;
    }

    const gap = distance(player.position, point);
    const timeToBall = computeTimeToCoverDistance(player, gap, point);
    const reboundTimeWindow = reboundContext.active
      ? lerp(
          reboundContext.insideAttackingBox || reboundContext.insideDefendingBox ? 1.72 : 1.46,
          reboundContext.insideAttackingBox || reboundContext.insideDefendingBox ? 2.24 : 1.82,
          reboundContext.urgency
        )
      : 1.45;
    const baseScore =
      getLooseBallClaimScore(player, point) +
      getShotReboundClaimAdjustment(player, point, reboundContext) +
      (player.id === preferredPlayerId ? preferredBoost : 0);

    if (gap <= claimRadius) {
      const candidate = {
        player,
        gap,
        timeToBall,
        score: baseScore + clamp(1 - gap / Math.max(claimRadius, 0.01), 0, 1) * 0.22,
        claimType: "immediate",
      };
      if (!bestImmediate || candidate.score > bestImmediate.score) {
        bestImmediate = candidate;
      }
      return;
    }

    const secondBallRadius = claimRadius + (
      reboundContext.active
        ? lerp(
            reboundContext.insideAttackingBox || reboundContext.insideDefendingBox ? 4.4 : 3.6,
            reboundContext.insideAttackingBox || reboundContext.insideDefendingBox ? 6.9 : 5.2,
            reboundContext.urgency
          )
        : 3.6
    );
    if (gap > secondBallRadius || timeToBall > reboundTimeWindow) {
      return;
    }

    const candidate = {
      player,
      gap,
      timeToBall,
      score:
        baseScore +
        clamp(1 - (gap - claimRadius) / Math.max(secondBallRadius - claimRadius, 0.01), 0, 1) * 0.18 -
        timeToBall * 0.05,
      claimType: "second-ball",
    };

    if (!bestSecondBall || candidate.score > bestSecondBall.score) {
      bestSecondBall = candidate;
    }
  });

  if (bestImmediate) {
    return bestImmediate;
  }

  const secondBallThreshold = reboundContext.active
    ? clamp(0.34 - reboundContext.urgency * 0.08, 0.24, 0.34)
    : 0.36;
  const secondBallGapBonus = reboundContext.active
    ? lerp(1.6, 2.55, reboundContext.urgency)
    : 1.4;
  if (bestSecondBall && (bestSecondBall.score >= secondBallThreshold || bestSecondBall.gap <= claimRadius + secondBallGapBonus)) {
    return bestSecondBall;
  }

  return {
    player: null,
    gap: null,
    timeToBall: null,
    score: null,
    claimType: "unclaimed",
  };
}

function connectBallToPlayerForNextAction(player, focusPoint = state.ball.position, blend = 0.4) {
  if (!player) {
    return false;
  }

  clearAutoPilotReceiveMomentum(player.id);
  rotatePlayerBodyToward(player, focusPoint, blend);
  state.ball.ownerPlayerId = player.id;
  keepSecurePossessionOnlyForOwner(player.id);
  state.ball.position = cloneVector(getPlayerBallControlPoint(player));
  state.ball.target = cloneVector(state.ball.position);
  return true;
}

function applyShotReboundControlTouch(player, point, context) {
  if (!player || !point || !context?.active) {
    return false;
  }

  const isAttacking = player.team === context.attackingTeamId;
  const isDefending = player.team === context.defendingTeamId;
  if (!isAttacking && !isDefending) {
    return false;
  }

  const pressure = getPlayerPressureLoad(player, point);
  const label = getPlayerMagnetLabel(player);
  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const contextProfile = getPlayerDecisionContext(player).profile;
  let facingAngle = getTeamAttackAngle(player.team);
  let touchDistance = 0.75;

  if (isAttacking) {
    const goal = getOpponentGoalCenter(player.team);
    const penaltySpot = getOpponentPenaltySpot(player.team);
    const directGoalAngle = angleBetween(point, goal);
    const centralFinishAngle = angleBetween(point, {
      x: lerp(point.x, penaltySpot.x, context.insideAttackingBox ? 0.42 : 0.68),
      y: lerp(point.y, pitch.width / 2, 0.62),
    });
    const poacherBoost = label === "9" || roleKey === "striker" || roleKey === "secondStriker" ? 0.22 : 0;
    facingAngle = blendAngles(directGoalAngle, centralFinishAngle, 0.58, 0.42);
    touchDistance = clamp(
      0.46 +
        contextProfile.technicalSecurity * 0.34 +
        contextProfile.composure * 0.22 +
        getAutoPilotRoleStrength(player, "finisher") * 0.28 +
        poacherBoost -
        pressure * 0.22,
      0.42,
      context.insideAttackingBox ? 1.28 : 1.62
    );
  } else {
    const sideSign = Math.sign(point.y - pitch.width / 2) || (player.position.y >= pitch.width / 2 ? 1 : -1);
    const teamExitAngle = getTeamAttackAngle(player.team);
    const wideExitAngle = normalizeAngle(teamExitAngle + sideSign * 0.32);
    const safetyAngle = angleBetween(point, {
      x: point.x + Math.cos(teamExitAngle) * 10,
      y: clamp(point.y + sideSign * 8, 4, pitch.width - 4),
    });
    const clearanceBias = label === "CB" || label === "GK" || label === "6" ? 0.7 : 0.54;
    facingAngle = blendAngles(wideExitAngle, safetyAngle, clearanceBias, 1 - clearanceBias);
    touchDistance = clamp(
      0.74 +
        contextProfile.tacticalDiscipline * 0.28 +
        contextProfile.composure * 0.22 +
        context.urgency * 0.32 -
        pressure * 0.1,
      isGoalkeeper(player) ? 0.42 : 0.72,
      isGoalkeeper(player) ? 1.05 : 1.95
    );
  }

  const controlPoint = clampToPitch({
    x: point.x + Math.cos(facingAngle) * touchDistance,
    y: point.y + Math.sin(facingAngle) * touchDistance,
  }, 1.4);
  clearAutoPilotReceiveMomentum(player.id);
  placePlayerWithControlPoint(player, controlPoint, facingAngle);
  state.ball.ownerPlayerId = player.id;
  keepSecurePossessionOnlyForOwner(player.id);
  state.ball.position = cloneVector(getPlayerBallControlPoint(player));
  state.ball.target = cloneVector(state.ball.position);
  setSecurePossessionAfterControlledTouch(player, state.ball.position, {
    quality: clamp(0.62 + contextProfile.technicalSecurity * 0.18 + contextProfile.composure * 0.12 - pressure * 0.16, 0.38, 0.92),
    reason: "rebound-control",
    minDistanceToExpire: isAttacking ? 3.2 : 4.2,
    minTimeToExpire: isAttacking ? 0.62 : 0.9,
  });
  state.ball.secondBallContext = null;
  return true;
}

function keepBallPlayableForNextAction(point, preferredPlayer = null, options = {}) {
  const safePoint = clampToPitch(point ?? state.ball.position);
  const preferredRadius = options.preferredRadius ?? state.ball.controlRadius + 0.75;
  const claimRadius = options.claimRadius ?? state.ball.claimRadius + 0.85;

  if (preferredPlayer) {
    const preferredControlPoint = getPlayerBallControlPoint(preferredPlayer);
    if (distance(preferredControlPoint, safePoint) <= preferredRadius) {
      return connectBallToPlayerForNextAction(preferredPlayer, safePoint, 0.52);
    }
  }

  const claim = resolveLooseBallClaim(
    safePoint,
    claimRadius,
    preferredPlayer?.id ?? null,
    preferredPlayer ? 0.08 : 0,
    {
      canClaimPlayer: options.canClaimPlayer,
    }
  );

  if (claim.player) {
    return connectBallToPlayerForNextAction(claim.player, safePoint, 0.42);
  }

  state.ball.ownerPlayerId = null;
  clearAutoPilotReceiveMomentum();
  clearSecurePossession();
  state.ball.position = safePoint;
  state.ball.target = cloneVector(safePoint);
  return false;
}

function createLooseBallSpill(point, angle, distanceMeters, preferredPlayerId = null, preferredBoost = 0, options = {}) {
  const spillPoint = clampToPitch({
    x: point.x + Math.cos(angle) * distanceMeters,
    y: point.y + Math.sin(angle) * distanceMeters,
  });
  const claim = resolveLooseBallClaim(
    spillPoint,
    state.ball.claimRadius + distanceMeters * 0.3,
    preferredPlayerId,
    preferredBoost,
    {
      canClaimPlayer: options.canClaimPlayer,
      source: options.source,
      reboundType: options.reboundType,
      attackingTeamId: options.attackingTeamId,
      defendingTeamId: options.defendingTeamId,
      urgency: options.urgency,
    }
  );
  const winner = claim.player;
  const initiator = getActionInitiator();
  const preferredPlayer = preferredPlayerId ? getPlayerById(preferredPlayerId) : null;
  const attackingTeamId =
    options.attackingTeamId ??
    initiator?.team ??
    preferredPlayer?.team ??
    null;
  const defendingTeamId =
    options.defendingTeamId ??
    (attackingTeamId ? getOtherTeamId(attackingTeamId) : null);

  state.ball.position = spillPoint;
  state.ball.target = cloneVector(spillPoint);
  state.ball.height = 0;
  state.ball.ownerPlayerId = winner?.id ?? null;
  if (winner) {
    keepSecurePossessionOnlyForOwner(winner.id);
    const reboundContext = getShotReboundClaimContext(spillPoint, options);
    const controlledRebound = applyShotReboundControlTouch(winner, spillPoint, reboundContext);
    if (!controlledRebound) {
      rotatePlayerBodyToward(winner, spillPoint, 0.45);
      state.ball.position = cloneVector(getPlayerBallControlPoint(winner));
      state.ball.target = cloneVector(state.ball.position);
      state.ball.secondBallContext = null;
    }
  } else {
    clearSecurePossession();
    state.ball.secondBallContext = {
      source: options.source ?? state.ball.profileKey ?? state.ball.actionType ?? "loose-ball",
      originPoint: cloneVector(point),
      spillPoint: cloneVector(spillPoint),
      incomingAngle: angle,
      distanceMeters,
      preferredPlayerId: preferredPlayerId ?? null,
      preferredTeamId: options.preferredTeamId ?? preferredPlayer?.team ?? attackingTeamId,
      attackingTeamId,
      defendingTeamId,
      createdAtActionType: state.ball.actionType,
      urgency: clamp(
        (options.urgency ?? 0.48) +
          (attackingTeamId && isInsideOpponentBox(spillPoint, attackingTeamId) ? 0.18 : 0) +
          (distanceMeters >= 4 ? 0.08 : 0),
        0.2,
        0.92
      ),
    };
  }

  return {
    spillPoint,
    winner,
    claimType: claim.claimType,
    claimGap: claim.gap,
    claimTime: claim.timeToBall,
  };
}

function resolveShotBlockCommitment(previousPosition) {
  if (state.ball.actionType !== "shot") {
    return null;
  }

  const shooter =
    getActionInitiator() ??
    getPlayerById(state.ball.initiatorPlayerId) ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId);
  const shotStart = state.ball.startPosition ?? previousPosition;
  const shotTarget = state.ball.target;
  if (!shooter || !shotStart || !shotTarget) {
    return null;
  }

  const trackTotal = Math.max(state.ball.trackDistanceTotal || distance(shotStart, shotTarget), 0.01);
  const currentProgress = getBallTravelProgress();
  const previousProgress = clamp(
    projectPointOnSegmentWithRatio(previousPosition, shotStart, shotTarget).ratio,
    0,
    1
  );
  const ballSpeed = Math.max(state.ball.currentSpeed || state.ball.launchSpeed || state.ball.speed || 14, 0.1);
  const lowShotFactor = clamp(1 - (state.ball.height ?? 0) / 1.45, 0.18, 1);
  const shotAngle = angleBetween(shotStart, shotTarget);
  const attackingTeamId = shooter.team;
  let bestBlock = null;

  state.players.forEach((player) => {
    if (player.team === attackingTeamId || player.id === shooter.id || isGoalkeeper(player)) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(player.position, shotStart, shotTarget);
    if (projection.ratio <= 0.07 || projection.ratio >= 0.92) {
      return;
    }

    const ownGoalDistance = getDistanceFromOwnGoal(player.team, projection.point);
    const boxUrgency =
      ownGoalDistance <= 24 || isInsideOwnBox(projection.point, player.team) ? 0.2 : ownGoalDistance <= 34 ? 0.1 : 0;
    const readAheadWindow = 0.035 + player.intelligenceProfile.perception * 0.035 + boxUrgency * 0.08;
    if (projection.ratio < previousProgress - 0.055 || projection.ratio > currentProgress + readAheadWindow) {
      return;
    }

    const laneGap = distance(player.position, projection.point);
    const coverInfluence = getCoverShadowInfluence(player, projection.point, shotStart);
    const bodyAlignment = clamp(1 - Math.abs(angleDifference(getPlayerFacingAngle(player), shotAngle + Math.PI)) / Math.PI, 0, 1);
    const blockReach = clamp(
      (0.72 +
        player.intelligenceProfile.perception * 0.34 +
        player.intelligenceProfile.decisionSpeed * 0.22 +
        player.intelligenceProfile.tacticalDiscipline * 0.2 +
        coverInfluence * 0.28 +
        bodyAlignment * 0.18) *
        lowShotFactor,
      0.72,
      2.35
    );
    const remainingDistanceToLane = Math.max((projection.ratio - currentProgress) * trackTotal, 0);
    const ballTimeToLane = remainingDistanceToLane / ballSpeed;
    const reactionDelay = Math.max(
      player.reactionTime *
        (0.5 - player.intelligenceProfile.perception * 0.14 - player.intelligenceProfile.decisionSpeed * 0.1),
      0.04
    );
    const moveNeed = Math.max(laneGap - blockReach * 0.72, 0);
    const defenderTimeToLane = computeTimeToCoverDistance(player, moveNeed, projection.point) + reactionDelay;
    const canReachLane = laneGap <= blockReach || defenderTimeToLane <= ballTimeToLane + 0.16 + boxUrgency * 0.12;
    if (!canReachLane) {
      return;
    }

    const proximity = clamp(1 - laneGap / Math.max(blockReach + 0.9, 0.01), 0, 1);
    const timing = clamp((ballTimeToLane - defenderTimeToLane + 0.28) / 0.72, 0, 1);
    const shotPressure = clamp((ballSpeed - 11) / 15, 0, 1);
    const score =
      proximity * 0.34 +
      timing * 0.2 +
      coverInfluence * 0.16 +
      bodyAlignment * 0.12 +
      player.intelligenceProfile.tacticalDiscipline * 0.12 +
      player.intelligenceProfile.composure * 0.08 +
      boxUrgency -
      shotPressure * 0.06;
    const threshold = clamp(0.58 - boxUrgency * 0.32 + (1 - lowShotFactor) * 0.14, 0.42, 0.68);
    if (score < threshold) {
      return;
    }

    const candidate = {
      player,
      point: projection.point,
      score,
      proximity,
      timing,
      controlScore: clamp(
        proximity * 0.42 +
          timing * 0.2 +
          player.intelligenceProfile.technicalSecurity * 0.14 +
          player.intelligenceProfile.composure * 0.12 +
          coverInfluence * 0.12,
        0,
        1
      ),
    };

    if (!bestBlock || candidate.score > bestBlock.score) {
      bestBlock = candidate;
    }
  });

  if (!bestBlock) {
    return null;
  }

  rotatePlayerBodyToward(bestBlock.player, bestBlock.point, 0.72);
  const ownGoal = getOwnGoalCenter(bestBlock.player.team);
  const awayFromGoalAngle = angleBetween(ownGoal, bestBlock.point);
  const sideSign = Math.sign(bestBlock.player.position.y - pitch.width / 2) || 1;
  const ricochetAngle = normalizeAngle(
    awayFromGoalAngle * 0.55 +
      (shotAngle + sideSign * lerp(0.42, 1.12, 1 - bestBlock.controlScore)) * 0.45
  );
  const spillDistance = clamp(
    1.2 + clamp((ballSpeed - 10) / 16, 0, 1) * 4.2 + (1 - bestBlock.controlScore) * 1.2,
    1.1,
    6.9
  );
  const spill = createLooseBallSpill(
    bestBlock.point,
    ricochetAngle,
    spillDistance,
    bestBlock.player.id,
    0.08 + bestBlock.controlScore * 0.06,
    {
      source: "shot-body-block",
      reboundType: "shot-block",
      attackingTeamId,
      defendingTeamId: bestBlock.player.team,
      urgency: clamp(0.58 + bestBlock.score * 0.28, 0.58, 0.9),
    }
  );

  if (spill.winner && spill.winner.team !== attackingTeamId) {
    setSecurePossessionAfterBallWin(spill.winner, shooter, spill.spillPoint, "interception");
  }

  return {
    kind: "block",
    player: bestBlock.player,
    point: spill.spillPoint,
    winner: spill.winner,
  };
}

function resolvePassTransitInterception(previousPosition, actionType) {
  if (actionType !== "pass" && actionType !== "shot") {
    return null;
  }

  const initiator = getActionInitiator();
  const passTeamId =
    actionType === "pass"
      ? initiator?.team ??
        getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId)?.team ??
        getPlayerById(state.ball.initiatorPlayerId)?.team ??
        null
      : null;
  const flightControlFactor = getBallFlightControlFactor(actionType);
  if (actionType === "pass" && flightControlFactor <= 0.06) {
    return null;
  }
  const receiver = actionType === "pass" && state.ball.receiverPlayerId
    ? getPlayerById(state.ball.receiverPlayerId)
    : null;
  const receiverControlPoint = receiver ? getPlayerBallControlPoint(receiver) : null;
  const passProgress = getBallTravelProgress();
  const candidates = [];

  state.players.forEach((player) => {
    if (player.id === initiator?.id) {
      return;
    }

    if (actionType === "pass" && passTeamId && player.team === passTeamId) {
      return;
    }

    const lanePoint = projectPointOnSegment(player.position, previousPosition, state.ball.position);
    const isPassToFeet = actionType === "pass" && state.ball.targetKind === "to-feet";
    if (
      isPassToFeet &&
      receiverControlPoint &&
      passProgress >= 0.7 &&
      distance(lanePoint, receiverControlPoint) <= state.ball.controlRadius + 0.95
    ) {
      // Near arrival, let the receiver duel/control the pass instead of creating cheap late interceptions.
      return;
    }

    const gap = distance(player.position, lanePoint);
    const interceptRadius = clamp(
      (0.55 +
        player.intelligenceProfile.perception * 0.55 +
        player.intelligenceProfile.technicalSecurity * 0.35 +
        getCoverShadowInfluence(player, lanePoint, previousPosition) * 0.24) *
        (actionType === "shot"
          ? lerp(0.74, 1, flightControlFactor)
          : isPassToFeet
            ? lerp(0.16, 0.86, flightControlFactor)
            : lerp(0.22, 1, flightControlFactor)),
      0.75,
      isPassToFeet ? 1.38 : 1.65
    );
    const secureContext = getSecurePossessionContext(initiator, player);
    const secureProtection = secureContext?.protectionRatio ?? 0;
    const adjustedInterceptRadius = interceptRadius * (1 - secureProtection * 0.32);

    if (gap > adjustedInterceptRadius) {
      return;
    }

    const controlScore = clamp(
      getBallContestControlScore(player, lanePoint, actionType) - secureProtection * 0.2,
      0,
      1
    );
    const proximity = clamp(1 - gap / adjustedInterceptRadius, 0, 1);
    const coverInfluence = getCoverShadowInfluence(player, lanePoint, previousPosition);
    const score =
      controlScore * 0.58 +
      player.intelligenceProfile.decisionSpeed * 0.18 +
      player.intelligenceProfile.perception * 0.12 +
      proximity * 0.24 +
      coverInfluence * 0.14 +
      flightControlFactor * 0.1 -
      secureProtection * 0.28;

    candidates.push({
      player,
      lanePoint,
      gap,
      interceptRadius: adjustedInterceptRadius,
      controlScore,
      score,
      secureProtection,
    });
  });

  if (!candidates.length) {
    return null;
  }

  candidates.sort((a, b) => b.score - a.score);
  const best = candidates[0];
  const isOpponent = best.player.team !== initiator?.team;
  const isPassToFeet = actionType === "pass" && state.ball.targetKind === "to-feet";

  if (actionType === "pass") {
    const canAffectPass =
      best.gap <= (isPassToFeet ? 0.52 : 0.95) ||
      (best.score >= (isPassToFeet ? 0.9 : 0.78) && best.controlScore >= (isPassToFeet ? 0.68 : 0.62));

    if (!canAffectPass) {
      return null;
    }
  }

  if (best.controlScore >= (actionType === "pass" ? (isPassToFeet ? 0.72 : 0.65) : 0.57)) {
    rotatePlayerBodyToward(best.player, best.lanePoint, 0.45);
    state.ball.ownerPlayerId = best.player.id;
    state.ball.position = cloneVector(getPlayerBallControlPoint(best.player));
    state.ball.target = cloneVector(state.ball.position);
    if (isOpponent) {
      setSecurePossessionAfterBallWin(best.player, initiator, best.lanePoint, "interception");
    } else {
      keepSecurePossessionOnlyForOwner(best.player.id);
    }
    return {
      kind: isOpponent ? "interception" : "early-claim",
      player: best.player,
      point: best.lanePoint,
    };
  }

  if (actionType === "pass" && (best.score < (isPassToFeet ? 0.84 : 0.76) || best.gap > (isPassToFeet ? 0.48 : 0.82))) {
    return null;
  }

  const deflectAngle =
    normalizeAngle(
      angleBetween(previousPosition, state.ball.position) * 0.55 +
      getPlayerFacingAngle(best.player) * 0.45
    ) + (isOpponent ? 0.18 : -0.12);
  const shotAttackingTeamId =
    actionType === "shot"
      ? initiator?.team ??
        getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId)?.team ??
        getPlayerById(state.ball.initiatorPlayerId)?.team ??
        getPlannedPossessionTeamId() ??
        null
      : null;
  const deflection = createLooseBallSpill(
    best.lanePoint,
    deflectAngle,
    clamp((1 - best.controlScore) * 3.4, 0.9, 3.8),
    best.player.id,
    0.04,
    actionType === "shot"
      ? {
          source: "shot-block-deflection",
          reboundType: "shot-block",
          attackingTeamId: shotAttackingTeamId,
          defendingTeamId: shotAttackingTeamId ? getOtherTeamId(shotAttackingTeamId) : null,
          urgency: clamp(best.score + (1 - best.controlScore) * 0.2, 0.48, 0.88),
        }
      : {}
  );
  if (isOpponent && deflection.winner?.id === best.player.id) {
    setSecurePossessionAfterBallWin(best.player, initiator, deflection.spillPoint, "interception");
  }

  return {
    kind: "deflection",
    player: best.player,
    point: deflection.spillPoint,
    winner: deflection.winner,
  };
}

function resolveAerialArrivalContest(actionType, receiver = null) {
  if (actionType !== "pass" && actionType !== "shot") {
    return false;
  }

  if (!isAerialFlightStyle(state.ball.flightStyle) && state.ball.height <= state.ball.controlHeightThreshold * 0.65) {
    return false;
  }

  const contestPoint = cloneVector(state.ball.position);
  const incomingPoint = cloneVector(state.ball.startPosition);
  const incomingAngle = angleBetween(incomingPoint, contestPoint);
  const firstContactContext = getAerialFirstContactContext(actionType, contestPoint, incomingPoint, receiver);
  const contestRadius = clamp(
    state.ball.controlRadius + 1.05 + state.ball.height * 0.28,
    1.9,
    firstContactContext.crossLike || firstContactContext.secondBallZone ? 4.35 : 3.7
  );
  const candidates = state.players
    .map((player) => ({
      player,
      gap: distance(player.position, contestPoint),
    }))
    .filter((entry) => entry.gap <= contestRadius)
    .map((entry) => ({
      ...entry,
      aerialScore: getAerialFirstContactScore(
        entry.player,
        contestPoint,
        incomingPoint,
        firstContactContext,
        receiver?.id ?? null,
        receiver ? 0.05 : 0
      ),
    }))
    .sort((a, b) => b.aerialScore - a.aerialScore);

  if (!candidates.length) {
    return false;
  }

  const winner = candidates[0];
  const challenger = candidates[1] ?? null;
  const winnerControlScore = getAerialControlScore(winner.player, incomingPoint);
  const margin = winner.aerialScore - (challenger?.aerialScore ?? 0);
  const winnerIsDefending = winner.player.team === firstContactContext.defendingTeamId;
  const winnerIsAttacking = winner.player.team === firstContactContext.attackingTeamId;
  const winnerInOwnBox = isInsideOwnBox(contestPoint, winner.player.team);

  if (
    isGoalkeeper(winner.player) &&
    winnerInOwnBox &&
    winnerControlScore >= 0.5 &&
    margin >= -0.03
  ) {
    connectBallToPlayerForNextAction(winner.player, contestPoint, 0.82);
    keepSecurePossessionOnlyForOwner(winner.player.id);
    return true;
  }

  if (challenger && margin <= (firstContactContext.crossLike ? 0.1 : 0.07)) {
    const looseAngle = blendAngles(
      getPlayerFacingAngle(winner.player),
      incomingAngle,
      0.58,
      0.42
    );
    createLooseBallSpill(
      contestPoint,
      looseAngle,
      clamp(1.45 + state.ball.height * 0.48 + (firstContactContext.secondBallZone ? 0.55 : 0), 1.1, 4.4),
      winner.player.id,
      0.02
    );
    return true;
  }

  if (
    winnerIsDefending &&
    (firstContactContext.crossLike || firstContactContext.secondBallZone || firstContactContext.inDefendingBox) &&
    (state.ball.height >= state.ball.controlHeightThreshold * 0.9 || margin >= 0.04)
  ) {
    const clearanceAngle = getAerialDefensiveClearanceAngle(winner.player, contestPoint, incomingAngle);
    createLooseBallSpill(
      contestPoint,
      clearanceAngle,
      clamp(4.8 + getAerialPresence(winner.player) * 4.4 + winnerControlScore * 2.2, 4.2, 11.5),
      winner.player.id,
      0.03
    );
    return true;
  }

  if (
    winnerIsAttacking &&
    firstContactContext.crossLike &&
    firstContactContext.inAttackingBox &&
    state.ball.height >= state.ball.controlHeightThreshold * 0.8
  ) {
    const knockdownAngle = getAerialAttackingKnockdownAngle(winner.player, contestPoint, firstContactContext);
    createLooseBallSpill(
      contestPoint,
      knockdownAngle,
      clamp(1.8 + winnerControlScore * 3.4 + Math.max(margin, 0) * 5.2, 1.5, 6.4),
      winner.player.id,
      0.08
    );
    return true;
  }

  const isReceiverTeamWinner = receiver ? winner.player.team === receiver.team : true;
  if (winnerControlScore >= 0.7 && margin >= 0.04 && state.ball.height <= state.ball.controlHeightThreshold * 1.6) {
    if (receiver && winner.player.id === receiver.id) {
      applyControlledFirstTouch(
        winner.player,
        incomingPoint,
        winnerControlScore,
        state.ball.firstTouchMode
      );
    } else {
      rotatePlayerBodyToward(winner.player, receiver ? state.ball.target : contestPoint, 0.42);
      state.ball.ownerPlayerId = winner.player.id;
      keepSecurePossessionOnlyForOwner(winner.player.id);
      state.ball.position = cloneVector(getPlayerBallControlPoint(winner.player));
      state.ball.target = cloneVector(state.ball.position);
    }
    return true;
  }

  const directionalAngle = isReceiverTeamWinner
    ? blendAngles(getTeamAttackAngle(winner.player.team), incomingAngle, 0.72, 0.28)
    : normalizeAngle(
        getTeamAttackAngle(winner.player.team) +
        (contestPoint.y <= pitch.width / 2 ? 0.26 : -0.26)
      );
  const spillDistance = clamp(
    2.2 + (winnerControlScore - 0.4) * 2.4 + state.ball.height * 0.28,
    1.8,
    isReceiverTeamWinner ? 5.4 : 7.2
  );
  createLooseBallSpill(
    contestPoint,
    directionalAngle,
    spillDistance,
    winner.player.id,
    0.05
  );
  return true;
}

function shouldTriggerLandingBounce(actionType, reachedReceiverControlZone) {
  if (actionType !== "pass" && actionType !== "shot") {
    return false;
  }

  if (state.ball.bounceCount > 0) {
    return false;
  }

  if (reachedReceiverControlZone && state.ball.targetKind === "to-feet") {
    return false;
  }

  if (state.ball.trackDistanceTotal < 14) {
    return false;
  }

  if (isAerialFlightStyle(state.ball.flightStyle)) {
    return true;
  }

  return actionType === "shot" || state.ball.targetKind === "into-space";
}

function startLandingBounceSkid(previousPosition) {
  const landingPoint = cloneVector(state.ball.position);
  const incomingAngle =
    distance(previousPosition, landingPoint) > 0.01
      ? angleBetween(previousPosition, landingPoint)
      : angleBetween(state.ball.startPosition, state.ball.target);
  const surfacePreset = getPitchSurfacePreset();
  const weatherPreset = getWeatherPreset();
  const skidFactor = surfacePreset.groundRollFactor * weatherPreset.ballSkidFactor;
  const baseCarry =
    Math.max(state.ball.currentSpeed, state.ball.finalSpeed, 5.2) *
    (0.24 + skidFactor * 0.11);
  const bounceDistance = clamp(
    baseCarry + (isAerialFlightStyle(state.ball.flightStyle) ? 0.85 : 0.35),
    1.3,
    isAerialFlightStyle(state.ball.flightStyle) ? 7.4 : 4.9
  );
  const bounceTarget = clampToPitch({
    x: landingPoint.x + Math.cos(incomingAngle) * bounceDistance,
    y: landingPoint.y + Math.sin(incomingAngle) * bounceDistance,
  });
  const bounceTravelDistance = distance(landingPoint, bounceTarget);

  if (bounceTravelDistance <= 0.25) {
    return false;
  }

  const bounceProfile = {
    key: `${state.ball.profileKey ?? "ball"}-bounce`,
    label: `${state.ball.profileLabel ?? "Ball"} Bounce`,
    source: state.ball.profileMode,
    targetKind: "into-space",
    averageSpeed: clamp(
      Math.max(state.ball.finalSpeed, state.ball.currentSpeed * 0.72) * weatherPreset.ballRollFactor,
      4.8,
      11.5
    ),
    launchMultiplier: isAerialFlightStyle(state.ball.flightStyle) ? 1.14 : 1.08,
    rollFloor: clamp(0.9 * skidFactor, 0.8, 2.2),
    flightStyle: "driven",
    peakHeight: clamp(
      state.ball.height * 0.3 + (isAerialFlightStyle(state.ball.flightStyle) ? 0.34 : 0.16),
      0.12,
      0.52
    ),
    controlHeightThreshold: 0.18,
    landingPhaseStart: 0.4,
    curveAmount: (state.ball.curveAmount ?? 0) * 0.18,
    spinRate: (state.ball.spinRate ?? 0) * 0.66,
  };

  state.ball.position = landingPoint;
  state.ball.startPosition = cloneVector(landingPoint);
  state.ball.target = bounceTarget;
  state.ball.ownerPlayerId = null;
  clearSecurePossession();
  state.ball.bounceCount += 1;
  configureBallTravelProfile(
    state.ball.actionType,
    bounceTravelDistance,
    bounceProfile.averageSpeed,
    bounceProfile
  );
  state.ball.inTransit = true;
  return true;
}

function settleBallForNextAction(actionType) {
  const receiver = state.ball.receiverPlayerId ? getPlayerById(state.ball.receiverPlayerId) : null;
  const passReceiverClaimFilter =
    actionType === "pass" && receiver
      ? (player) => player.id === receiver.id || player.team !== receiver.team
      : null;

  if (resolveAerialArrivalContest(actionType, receiver)) {
    if (!state.ball.ownerPlayerId) {
      keepBallPlayableForNextAction(state.ball.position, receiver, {
        preferredRadius: state.ball.controlRadius + 1,
        claimRadius: state.ball.claimRadius + 1.1,
        canClaimPlayer: passReceiverClaimFilter,
      });
    }
    return;
  }

  if (actionType === "pass" && receiver && state.restartPhase?.type !== "throwIn") {
    const receiverControlPoint = getPlayerBallControlPoint(receiver);
    const receiverContext = getPlayerDecisionContext(receiver);
    const receiverGap = distance(receiverControlPoint, state.ball.position);
    const cleanControlScore =
      state.ball.executionQuality * 0.46 +
      state.ball.laneClarity * 0.24 +
      receiverContext.profile.technicalSecurity * 0.16 +
      receiverContext.profile.pressResistance * 0.14;
    const receiveOrientationScore = getReceiveOrientationScore(receiver, state.ball.startPosition);
    const receiveFootScore = getReceiveFootUsageScore(receiver, state.ball.startPosition);
    const firstTouchQuality = clamp(
      receiverContext.profile.technicalSecurity * 0.34 +
        receiverContext.profile.pressResistance * 0.22 +
        receiverContext.profile.composure * 0.16 +
        receiverContext.profile.decisionQuality * 0.14 +
        receiveOrientationScore * 0.1 +
        receiveFootScore * 0.08 -
        receiverContext.pressure * 0.07,
      state.ball.targetKind === "to-feet" ? 0.52 : 0.42,
      0.98
    );
    const isPassToFeet = state.ball.targetKind === "to-feet";
    const controlThreshold = isPassToFeet ? 0.4 : 0.58;
    const nearestOpponentGap = getNearestOpponentGap(receiver, receiverControlPoint);
    const isReceiverPressed =
      Number.isFinite(nearestOpponentGap) &&
      (nearestOpponentGap <= 2.75 || receiverContext.pressure >= 0.52);
    const isReceiverUnderDuelPressure =
      Number.isFinite(nearestOpponentGap) &&
      (nearestOpponentGap <= 1.65 || receiverContext.pressure >= 0.68);

    if (
      isPassToFeet &&
      !isReceiverPressed &&
      receiverGap <= state.ball.controlRadius + 2.2 &&
      state.ball.executionQuality >= 0.44
    ) {
      const activeFirstTouchMode = shouldUseAutoPilotActiveFirstTouch(receiver, firstTouchQuality)
        ? state.draftStep?.firstTouchMode ?? state.ball.firstTouchMode
        : "kill";
      applyControlledFirstTouch(
        receiver,
        state.ball.startPosition,
        Math.max(firstTouchQuality, 0.74),
        activeFirstTouchMode
      );
      return;
    }

    const duelRadius = isPassToFeet
      ? clamp(state.ball.controlRadius - 0.05, 1.1, 1.62)
      : state.ball.controlRadius + 1.05;
    const duelOpponents = state.players
      .filter((player) => player.team !== receiver.team)
      .map((player) => ({ player, gap: distance(player.position, receiverControlPoint) }))
      .filter((entry) => entry.gap <= duelRadius && (!isPassToFeet || isReceiverUnderDuelPressure))
      .sort((a, b) => a.gap - b.gap);
    const primaryDuel = duelOpponents[0] ?? null;
    const receiverDuelScore =
      getBallDuelScore(receiver, receiverControlPoint) +
      firstTouchQuality * 0.18 +
      state.ball.executionQuality * 0.08;

    if (receiverGap <= state.ball.controlRadius && cleanControlScore * lerp(0.94, 1.06, receiveFootScore) >= controlThreshold) {
      if (primaryDuel) {
        const defenderDuelScore =
          getBallDuelScore(primaryDuel.player, receiverControlPoint) +
          (primaryDuel.player.intelligenceProfile.decisionSpeed * 0.08);

        const decisiveReceiverPressure = primaryDuel.gap <= (isPassToFeet ? 1.18 : 1.55);
        if (
          decisiveReceiverPressure &&
          defenderDuelScore > receiverDuelScore + (isPassToFeet ? 0.3 : 0.12)
        ) {
          connectBallToPlayerForNextAction(primaryDuel.player, receiverControlPoint, 0.45);
          setSecurePossessionAfterBallWin(primaryDuel.player, receiver, receiverControlPoint, "tackle");
          return;
        }

        if (isPassToFeet && receiverDuelScore >= defenderDuelScore - 0.12) {
          applyControlledFirstTouch(receiver, state.ball.startPosition, firstTouchQuality, "kill");
          return;
        }

        if (Math.abs(defenderDuelScore - receiverDuelScore) <= (isPassToFeet ? 0.02 : 0.07)) {
          const duelAngle = normalizeAngle(
            angleBetween(receiver.position, receiverControlPoint) * 0.5 +
            angleBetween(primaryDuel.player.position, receiverControlPoint) * 0.5
          );
          const spill = createLooseBallSpill(
            receiverControlPoint,
            duelAngle,
            clamp(1.1 + primaryDuel.gap * 0.45, 1, 3.2),
            receiver.id,
            0.03,
            {
              canClaimPlayer: passReceiverClaimFilter,
            }
          );
          if (!spill.winner) {
            keepBallPlayableForNextAction(spill.spillPoint, receiver, {
              preferredRadius: isPassToFeet ? state.ball.controlRadius + 1.15 : state.ball.controlRadius + 0.55,
              claimRadius: state.ball.claimRadius + 0.75,
              canClaimPlayer: passReceiverClaimFilter,
            });
          }
          return;
        }
      }

      const shouldSecureToFeetPass = isPassToFeet && firstTouchQuality >= 0.3;
      if (firstTouchQuality >= 0.45 || shouldSecureToFeetPass) {
        const appliedFirstTouch = applyControlledFirstTouch(
          receiver,
          state.ball.startPosition,
          firstTouchQuality,
          firstTouchQuality < 0.56 && state.ball.firstTouchMode === "auto"
            ? "kill"
            : state.ball.firstTouchMode
        );
        if (appliedFirstTouch && appliedFirstTouch !== "kill") {
          logEvent(
            `${receiver.shortLabel} ${receiver.role} takes the first touch ${getFirstTouchModeLabel(appliedFirstTouch).toLowerCase()}.`
          );
        }
        return;
      }

      const incomingAngle = angleBetween(state.ball.startPosition, receiverControlPoint);
      const spillAngle = normalizeAngle(
        incomingAngle * 0.45 + getPlayerFacingAngle(receiver) * 0.55
      );
      const spillDistance = clamp(
        (1 - firstTouchQuality) * 4.2 + receiverContext.pressure * 1.25,
        0.9,
        4.8
      );
      const spillPoint = clampToPitch({
        x: receiverControlPoint.x + Math.cos(spillAngle) * spillDistance,
        y: receiverControlPoint.y + Math.sin(spillAngle) * spillDistance,
      });
      const spill = createLooseBallSpill(
        spillPoint,
        spillAngle,
        0,
        receiver.id,
        0.02,
        {
          canClaimPlayer: passReceiverClaimFilter,
        }
      );
      if (!spill.winner) {
        keepBallPlayableForNextAction(spillPoint, receiver, {
          preferredRadius: state.ball.controlRadius + 0.65,
          claimRadius: state.ball.claimRadius + 0.75,
          canClaimPlayer: passReceiverClaimFilter,
        });
      }
      return;
    }

    if (isPassToFeet) {
      if (!isReceiverPressed) {
        const activeFirstTouchMode = shouldUseAutoPilotActiveFirstTouch(receiver, firstTouchQuality)
          ? state.draftStep?.firstTouchMode ?? state.ball.firstTouchMode
          : "kill";
        applyControlledFirstTouch(
          receiver,
          state.ball.startPosition,
          Math.max(firstTouchQuality, 0.68),
          activeFirstTouchMode
        );
        return;
      }

      keepBallPlayableForNextAction(state.ball.position, receiver, {
        preferredRadius: state.ball.controlRadius + 1.45,
        claimRadius: state.ball.claimRadius + 0.8,
        canClaimPlayer: passReceiverClaimFilter,
      });
      return;
    }
  }

  const spaceRunner =
    actionType === "pass" && !receiver
      ? getPlayerById(state.draftStep?.principleRunnerPlayerId)
      : null;
  const spaceClaimFilter = spaceRunner
    ? (player) => player.id === spaceRunner.id || player.team !== spaceRunner.team
    : passReceiverClaimFilter;
  const winner = resolveLooseBallClaim(
    state.ball.target,
    state.ball.claimRadius,
    receiver?.id ?? spaceRunner?.id ?? null,
    receiver ? 0.05 : spaceRunner ? 0.14 : 0,
    {
      canClaimPlayer: spaceClaimFilter,
    }
  ).player;

  if (winner) {
    connectBallToPlayerForNextAction(winner, state.ball.target, 0.4);
    return;
  }

  keepBallPlayableForNextAction(state.ball.target, receiver ?? spaceRunner, {
    preferredRadius: receiver || spaceRunner ? state.ball.controlRadius + 0.9 : state.ball.controlRadius + 0.3,
    claimRadius: state.ball.claimRadius + 0.65,
    canClaimPlayer: spaceClaimFilter,
  });
}

function getDefensiveAutopilotFocusPoint(actionMeta, fallbackPoint = state.ball.target) {
  if (!actionMeta?.defensiveAutopilot?.teamId) {
    return null;
  }

  return actionMeta.defensiveAutopilot.ballFocusPoint
    ? cloneVector(actionMeta.defensiveAutopilot.ballFocusPoint)
    : cloneVector(fallbackPoint ?? actionMeta.target ?? state.ball.target);
}

function getOffensiveAutopilotFocusPoint(actionMeta, fallbackPoint = state.ball.position) {
  if (!actionMeta?.offensiveAutopilot?.teamId) {
    return null;
  }

  return actionMeta.offensiveAutopilot.ballFocusPoint
    ? cloneVector(actionMeta.offensiveAutopilot.ballFocusPoint)
    : cloneVector(fallbackPoint ?? actionMeta.target ?? state.ball.position);
}

function isDefensiveAutopilotPlayer(player, actionMeta) {
  return (
    !!player &&
    !!actionMeta?.defensiveAutopilot?.teamId &&
    player.team === actionMeta.defensiveAutopilot.teamId
  );
}

function isOffensiveAutopilotPlayer(player, actionMeta) {
  return (
    !!player &&
    !!actionMeta?.offensiveAutopilot?.teamId &&
    player.team === actionMeta.offensiveAutopilot.teamId
  );
}

function isDefensiveDribblePresser(player, actionMeta) {
  return (
    !!player &&
    actionMeta?.actionType === "dribble" &&
    isDefensiveAutopilotPlayer(player, actionMeta) &&
    player.id === actionMeta.defensiveAutopilot?.presserPlayerId
  );
}

function getLiveDefensiveDribblePressTarget(player, actionMeta, fallbackTarget) {
  if (!isDefensiveDribblePresser(player, actionMeta)) {
    return fallbackTarget;
  }

  const reference = getDribblePressureReference(actionMeta);
  if (!reference) {
    return fallbackTarget;
  }

  const profile = getDefensiveAutopilotProfile(
    player.team,
    actionMeta.target ?? reference.targetPoint,
    actionMeta.defensiveAutopilot?.phaseKey ?? null
  );

  return getDefensiveDribblePressTarget(player, reference, profile, state.ball.position);
}

function alignArrivedDefensiveAutopilotPlayers(actionMeta, targetMap, focusPoint = null) {
  const defensiveFocusPoint = focusPoint ?? getDefensiveAutopilotFocusPoint(actionMeta);
  if (!targetMap || !defensiveFocusPoint) {
    return;
  }

  state.players.forEach((player) => {
    if (!isDefensiveAutopilotPlayer(player, actionMeta)) {
      return;
    }

    const targetPosition = targetMap.get(player.id);
    if (!targetPosition || distance(player.position, targetPosition) > 0.12) {
      return;
    }

    rotatePlayerBodyToward(player, defensiveFocusPoint, 0.92);
  });
}

function completeLiveActionPlayersBeforeCommit(focusPoint = state.ball.position) {
  if (!state.activeActionTargets || !state.draftStep) {
    return;
  }

  updateActionPlayers(state.activeActionTargets, state.draftStep);
  alignArrivedDefensiveAutopilotPlayers(
    state.draftStep,
    state.activeActionTargets,
    focusPoint
  );
}

function getActionSpeed() {
  const dribbleDraftSpeed =
    state.draftStep?.actionType === "dribble" ? state.draftStep.speed : null;
  const baseSpeed = state.ball.actionType === "dribble"
    ? dribbleDraftSpeed ?? state.ball.speed ?? state.dribbleSpeed
    : state.ball.speed;
  const initiator = getActionInitiator();
  if (!initiator) {
    return baseSpeed;
  }

  const context = getPlayerDecisionContext(initiator);
  const actionSecurity =
    context.profile.executionUnderPressure * 0.75 +
    context.profile.decisionQuality * 0.25;
  const pressurePenalty =
    context.pressure *
    (state.ball.actionType === "dribble" ? 0.18 : 0.12) *
    (1 - actionSecurity);

  if (state.ball.actionType === "dribble") {
    return baseSpeed;
  }

  const laneBonus = state.ball.actionType === "pass"
    ? 0.92 + state.ball.laneClarity * 0.08
    : 1;

  return baseSpeed * clamp((1 - pressurePenalty) * laneBonus, 0.82, 1.04);
}

function configureBallTravelProfile(actionType, distance, averageSpeed, ballProfile = null) {
  if (actionType === "dribble") {
    state.ball.launchSpeed = averageSpeed;
    state.ball.currentSpeed = averageSpeed;
    state.ball.finalSpeed = averageSpeed;
    state.ball.deceleration = 0;
    state.ball.flightStyle = "ground";
    state.ball.peakHeight = 0;
    state.ball.height = 0;
    state.ball.controlHeightThreshold = 0.12;
    state.ball.landingPhaseStart = 0.58;
    state.ball.curveAmount = 0;
    state.ball.curveDirection = 1;
    state.ball.spinRate = 0;
    state.ball.spinAngle = 0;
    state.ball.trackDistanceTotal = Math.max(distance, 0);
    state.ball.trackDistanceCovered = 0;
    return;
  }

  const safeDistance = Math.max(distance, 0.01);
  const safeAverageSpeed = Math.max(averageSpeed, 0.01);
  const surfacePreset = getPitchSurfacePreset();
  const weatherPreset = getWeatherPreset();
  const resolvedProfile =
    ballProfile ??
    materializeBallProfile(
      actionType === "shot" ? "shot" : "firm-feet",
      safeDistance,
      actionType === "shot" ? "goal" : "to-feet",
      state.ball.profileMode ?? state.ballSpeedMode
    );
  const executionBlend = clamp(state.ball.executionQuality, 0.42, 0.98);
  const isGroundLike = !isAerialFlightStyle(resolvedProfile.flightStyle);
  const groundSurfaceRatio = clamp(
    (surfacePreset.groundRollFactor - 0.94) / 0.13,
    0,
    1
  );
  const launchSurfaceFactor = isGroundLike
    ? lerp(0.985, 1.015, groundSurfaceRatio)
    : surfacePreset.airCarryFactor;
  const launchSpeed =
    safeAverageSpeed *
    (resolvedProfile.launchMultiplier + (1 - executionBlend) * (actionType === "shot" ? 0.04 : 0.03)) *
    launchSurfaceFactor;
  const finalFloor = Math.max(
    actionType === "shot" ? 1.8 : 0.45,
    resolvedProfile.rollFloor *
      (isGroundLike ? surfacePreset.groundRollFactor : lerp(0.9, 1.03, groundSurfaceRatio)) *
      weatherPreset.ballRollFactor *
      (0.96 + executionBlend * 0.05)
  );
  const finalSpeed = clamp(
    2 * safeAverageSpeed - launchSpeed,
    finalFloor,
    Math.max(finalFloor, launchSpeed - 0.12)
  );
  const travelDuration = (2 * safeDistance) / Math.max(launchSpeed + finalSpeed, 0.01);
  const deceleration = Math.max((launchSpeed - finalSpeed) / Math.max(travelDuration, 0.01), 0);

  state.ball.launchSpeed = launchSpeed;
  state.ball.currentSpeed = launchSpeed;
  state.ball.finalSpeed = finalSpeed;
  state.ball.deceleration = deceleration;
  state.ball.flightStyle = resolvedProfile.flightStyle ?? "ground";
  state.ball.peakHeight = resolvedProfile.peakHeight ?? 0;
  state.ball.height = 0;
  state.ball.controlHeightThreshold = resolvedProfile.controlHeightThreshold ?? 0.12;
  state.ball.landingPhaseStart = resolvedProfile.landingPhaseStart ?? 0.58;
  state.ball.curveAmount = resolvedProfile.curveAmount ?? 0;
  state.ball.curveDirection = resolveBallCurveDirection(
    state.ball.startPosition,
    state.ball.target,
    getActionInitiator()
  );
  state.ball.spinRate = resolvedProfile.spinRate ?? 0;
  state.ball.spinAngle = 0;
  state.ball.trackDistanceTotal = safeDistance;
  state.ball.trackDistanceCovered = 0;
}

function getActionDistance() {
  if (state.ball.actionType !== null || state.ball.inTransit || state.draftStep) {
    return distance(state.ball.startPosition, state.ball.target);
  }

  return 0;
}

function getRequestedActionMode() {
  return state.keyboardActionMode ?? state.actionMode;
}

function computeReachDistance(player, actionDuration, targetPoint = state.ball.target) {
  const context = getPlayerDecisionContext(player);
  const orientationProfile = getOrientationMovementProfile(player, targetPoint);
  const intendedDistance = targetPoint
    ? distance(getActionOrigin(player), targetPoint)
    : 0;
  const shortBurstRatio = clamp(
    1 - intendedDistance / Math.max(context.sprintProfile.burstDistance, 0.01),
    0,
    1
  );
  const runTime = Math.max(0, actionDuration - context.reactionTime - getOrientationTurnDelay(player, targetPoint));
  if (runTime <= 0) {
    return 0;
  }

  const effectiveAcceleration = Math.max(
    context.acceleration *
      orientationProfile.accelerationMultiplier *
      (1 + context.sprintProfile.shortBurstBoost * shortBurstRatio),
    0.01
  );
  const effectiveMaxSpeed = Math.max(context.maxSpeed * orientationProfile.speedMultiplier, 0.01);
  const timeToTopSpeed = effectiveMaxSpeed / effectiveAcceleration;

  if (runTime <= timeToTopSpeed) {
    return 0.5 * effectiveAcceleration * runTime * runTime;
  }

  const accelerationDistance = 0.5 * effectiveAcceleration * timeToTopSpeed * timeToTopSpeed;
  const sprintTime = runTime - timeToTopSpeed;
  return accelerationDistance + effectiveMaxSpeed * sprintTime;
}

function computeTimeToCoverDistance(player, targetDistance, targetPoint = state.ball.target) {
  if (targetDistance <= 0) {
    return 0;
  }

  const context = getPlayerDecisionContext(player);
  const orientationProfile = getOrientationMovementProfile(player, targetPoint);
  const intendedDistance = targetPoint
    ? distance(getActionOrigin(player), targetPoint)
    : targetDistance;
  const shortBurstRatio = clamp(
    1 - intendedDistance / Math.max(context.sprintProfile.burstDistance, 0.01),
    0,
    1
  );
  const acceleration = Math.max(
    context.acceleration *
      orientationProfile.accelerationMultiplier *
      (1 + context.sprintProfile.shortBurstBoost * shortBurstRatio),
    0.01
  );
  const maxSpeed = Math.max(context.maxSpeed * orientationProfile.speedMultiplier, 0.01);
  const timeToTopSpeed = maxSpeed / acceleration;
  const accelerationDistance = 0.5 * acceleration * timeToTopSpeed * timeToTopSpeed;

  if (targetDistance <= accelerationDistance) {
    return context.reactionTime + getOrientationTurnDelay(player, targetPoint) + Math.sqrt((2 * targetDistance) / acceleration);
  }

  return (
    context.reactionTime +
    getOrientationTurnDelay(player, targetPoint) +
    timeToTopSpeed +
    (targetDistance - accelerationDistance) / maxSpeed
  );
}

function shouldUseCurvedRecoveryRun(player, startPoint, endPoint) {
  const straightDistance = distance(startPoint, endPoint);
  if (straightDistance < 5.5) {
    return false;
  }

  const label = getPlayerMagnetLabel(player);
  const towardOwnGoal =
    distance(endPoint, getOwnGoalCenter(player.team)) <
    distance(startPoint, getOwnGoalCenter(player.team)) - 1.1;
  const towardInside =
    Math.abs(endPoint.y - pitch.width / 2) <
    Math.abs(startPoint.y - pitch.width / 2) - 1.2;

  return towardOwnGoal || towardInside || ["CB", "LB", "RB", "WB", "6", "8", "10"].includes(label);
}

function getCurvedRecoveryWaypoint(player, startPoint, endPoint) {
  if (!shouldUseCurvedRecoveryRun(player, startPoint, endPoint)) {
    return null;
  }

  const straightDistance = distance(startPoint, endPoint);
  const distanceRatio = clamp(straightDistance / 18, 0, 1);
  const ownGoalDirection = player.team === "home" ? -1 : 1;
  const towardCenterSign = Math.sign(pitch.width / 2 - startPoint.y) || 1;
  const xBias = ownGoalDirection * lerp(0.45, 2.2, distanceRatio);
  const yBias = towardCenterSign * lerp(0.3, 1.9, distanceRatio);
  const waypoint = clampToPitch({
    x: lerp(startPoint.x, endPoint.x, 0.34) + xBias,
    y: lerp(startPoint.y, endPoint.y, 0.34) + yBias,
  }, 0.2);

  if (distance(startPoint, waypoint) <= 0.55 || distance(waypoint, endPoint) <= 0.55) {
    return null;
  }

  return waypoint;
}

function shouldUseOffBallCounterMovementRun(player, startPoint, endPoint, actionMeta = null) {
  if (!player || !startPoint || !endPoint || !actionMeta || isGoalkeeper(player)) {
    return false;
  }

  if (!isOffensiveAutopilotPlayer(player, actionMeta)) {
    return false;
  }

  if (
    player.id === actionMeta.carrierPlayerId ||
    player.id === actionMeta.receiverPlayerId ||
    player.id === actionMeta.beforeSnapshot?.ball?.ownerPlayerId
  ) {
    return false;
  }

  const straightDistance = distance(startPoint, endPoint);
  if (straightDistance < 5.75) {
    return false;
  }

  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  if (!["wideForward", "striker", "secondStriker", "connector", "wideBack"].includes(roleKey)) {
    return false;
  }

  const targetDepth = getAttackingDepth(endPoint, player.team);
  const targetThreat = getPitchThreatProfile(endPoint, player.team);
  const gameSpace = getAttackingGameSpaceProfile(endPoint, player.team);
  const principleText = [
    actionMeta.label,
    actionMeta.autoReason,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isRunPrinciple =
    principleText.includes("blindside") ||
    principleText.includes("overlap") ||
    principleText.includes("underlap") ||
    principleText.includes("box") ||
    principleText.includes("third-man") ||
    principleText.includes("channel") ||
    principleText.includes("run");
  const isHighValueRun =
    targetDepth >= 58 &&
    (
      gameSpace.key === "space2" ||
      gameSpace.key === "space3" ||
      targetThreat.box >= 0.18 ||
      targetThreat.behindLine >= 0.22 ||
      targetThreat.cutbackZone >= 0.22 ||
      targetThreat.assistZone >= 0.3
    );

  return isRunPrinciple || isHighValueRun;
}

function getOffBallCounterMovementWaypoint(player, startPoint, endPoint, actionMeta = null) {
  if (!shouldUseOffBallCounterMovementRun(player, startPoint, endPoint, actionMeta)) {
    return null;
  }

  const straightDistance = distance(startPoint, endPoint);
  const direction = normalize(startPoint, endPoint);
  const lateral = { x: -direction.y, y: direction.x };
  const attackSign = getAttackDirectionSign(player.team);
  const targetThreat = getPitchThreatProfile(endPoint, player.team);
  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const depthDip = clamp(straightDistance * 0.11, 0.75, targetThreat.box >= 0.2 ? 2.25 : 1.65);
  const lateralDip = clamp(straightDistance * 0.08, 0.55, roleKey === "wideBack" ? 2.2 : 1.55);
  const finalLaneSign =
    Math.sign(endPoint.y - startPoint.y) ||
    Math.sign(endPoint.y - pitch.width / 2) ||
    1;
  const lateralDirection = Math.sign(lateral.y) === -finalLaneSign ? 1 : -1;
  const waypoint = clampToPitch({
    x: startPoint.x - attackSign * depthDip + lateral.x * lateralDip * lateralDirection,
    y: startPoint.y + lateral.y * lateralDip * lateralDirection,
  }, 2.2);

  if (
    distance(startPoint, waypoint) <= 0.45 ||
    distance(waypoint, endPoint) <= 0.75 ||
    distance(startPoint, waypoint) > Math.max(straightDistance * 0.38, 3.4)
  ) {
    return null;
  }

  return waypoint;
}

function buildMovementPath(player, startPoint, endPoint, actionMeta = null) {
  const waypoint =
    getOffBallCounterMovementWaypoint(player, startPoint, endPoint, actionMeta) ??
    getCurvedRecoveryWaypoint(player, startPoint, endPoint);
  if (!waypoint) {
    const straightDistance = distance(startPoint, endPoint);
    return {
      start: startPoint,
      end: endPoint,
      waypoint: null,
      totalDistance: straightDistance,
    };
  }

  return {
    start: startPoint,
    end: endPoint,
    waypoint,
    segmentOneDistance: distance(startPoint, waypoint),
    segmentTwoDistance: distance(waypoint, endPoint),
    totalDistance: distance(startPoint, waypoint) + distance(waypoint, endPoint),
  };
}

function getMovementPathPoint(path, traveledDistance) {
  if (!path.waypoint) {
    return moveTowards(path.start, path.end, traveledDistance);
  }

  if (traveledDistance <= path.segmentOneDistance) {
    return moveTowards(path.start, path.waypoint, traveledDistance);
  }

  return moveTowards(
    path.waypoint,
    path.end,
    traveledDistance - path.segmentOneDistance
  );
}

function getSnapshotPlayerMap(snapshot) {
  return new Map(
    (snapshot?.players ?? []).map((player) => [player.id, cloneVector(player.position)])
  );
}

function getRecordedStepEndSnapshot(step) {
  return step.afterSnapshot ?? step.beforeSnapshot;
}

function getRecordedStepDuration(step) {
  const startPoint = step.beforeSnapshot?.ball?.position ?? state.ball.position;
  return distance(startPoint, step.target) / Math.max(step.speed, 0.01);
}

function snapshotsMatch(a, b, tolerance = 0.08) {
  if (!a || !b) {
    return false;
  }

  if (
    (a.formations?.home ?? teams.home.formation) !==
      (b.formations?.home ?? teams.home.formation) ||
    (a.formations?.away ?? teams.away.formation) !==
      (b.formations?.away ?? teams.away.formation)
  ) {
    return false;
  }

  if (
    (a.teamIdentities?.home?.attackStyle ?? teams.home.identity.attackStyle) !==
      (b.teamIdentities?.home?.attackStyle ?? teams.home.identity.attackStyle) ||
    (a.teamIdentities?.home?.defenseStyle ?? teams.home.identity.defenseStyle) !==
      (b.teamIdentities?.home?.defenseStyle ?? teams.home.identity.defenseStyle) ||
    (a.teamIdentities?.away?.attackStyle ?? teams.away.identity.attackStyle) !==
      (b.teamIdentities?.away?.attackStyle ?? teams.away.identity.attackStyle) ||
    (a.teamIdentities?.away?.defenseStyle ?? teams.away.identity.defenseStyle) !==
      (b.teamIdentities?.away?.defenseStyle ?? teams.away.identity.defenseStyle)
  ) {
    return false;
  }

  if ((a.physicalProfile ?? state.physicalProfile) !== (b.physicalProfile ?? state.physicalProfile)) {
    return false;
  }

  if (distance(a.ball.position, b.ball.position) > tolerance) {
    return false;
  }

  if ((a.ball.ownerPlayerId ?? null) !== (b.ball.ownerPlayerId ?? null)) {
    return false;
  }

  const bPlayers = getSnapshotPlayerMap(b);
  return a.players.every((player) => {
    const targetPosition = bPlayers.get(player.id);
    return targetPosition ? distance(player.position, targetPosition) <= tolerance : false;
  });
}

function createTransitionPlan(startSnapshot, targetSnapshot) {
  const startPositions = getSnapshotPlayerMap(startSnapshot);
  const targetPositions = getSnapshotPlayerMap(targetSnapshot);
  const playerTargets = new Map();
  let duration = 0;

  state.players.forEach((player) => {
    const start = startPositions.get(player.id) ?? cloneVector(player.position);
    const end = targetPositions.get(player.id) ?? cloneVector(start);
    playerTargets.set(player.id, {
      start,
      end,
    });
    duration = Math.max(
      duration,
      computeTimeToCoverDistance(player, distance(start, end), end)
    );
  });

  const ballStart = cloneVector(startSnapshot.ball.position);
  const ballEnd = cloneVector(targetSnapshot.ball.position);
  const hasFreeBall = !targetSnapshot.ball.ownerPlayerId;
  if (hasFreeBall) {
    duration = Math.max(duration, distance(ballStart, ballEnd) / Math.max(state.ball.speed, 12));
  }

  return {
    startSnapshot,
    targetSnapshot,
    duration,
    elapsed: 0,
    playerTargets,
    ballStart,
    ballEnd,
    ballOwnerPlayerId: targetSnapshot.ball.ownerPlayerId ?? null,
  };
}

function clampToCircle(point, center, radius) {
  if (!Number.isFinite(radius) || radius <= 0) {
    return cloneVector(center);
  }

  const gap = distance(center, point);
  if (gap <= radius) {
    return point;
  }

  return moveTowards(center, point, radius);
}

function getEditableRadius(player) {
  if (!hasBallAction()) {
    return Infinity;
  }

  if (state.ball.elapsedTravelTime > 0) {
    return computeReachDistance(player, getCurrentActionDuration());
  }

  return computeReachDistance(player, getProjectedActionDuration());
}

function getOtherTeamId(teamId) {
  if (teamId === "home") return "away";
  if (teamId === "away") return "home";
  return null;
}

function getPlannedPossessionTeamId() {
  const candidateIds = [
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.initiatorPlayerId,
    state.draftStep?.carrierPlayerId,
    state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId,
    state.selectedPlayerId,
  ];

  for (const playerId of candidateIds) {
    const player = getPlayerById(playerId);
    if (player?.team) {
      return player.team;
    }
  }

  return null;
}

function getDefendingDirectionSign(teamId) {
  return teamId === "home" ? 1 : -1;
}

function getDepthX(teamId, depth) {
  return teamId === "home" ? depth : pitch.length - depth;
}

function getDistanceFromOwnGoal(teamId, point) {
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  return clamp((point.x - ownGoalX) * getDefendingDirectionSign(teamId), 0, pitch.length);
}

function getOffensivePhaseKey(teamId, ballPoint, actionType = state.ball.actionType ?? state.draftStep?.actionType) {
  if (state.restartPhase?.type) {
    return "setPiece";
  }

  const ballDepth = getAttackingDepth(ballPoint, teamId);
  if (actionType === "shot" || ballDepth >= 72) {
    return "finalThird";
  }

  if (ballDepth <= 34) {
    return "buildUp";
  }

  return "progression";
}

function getOffensiveAutopilotProfile(teamId, ballPoint = state.ball.target ?? state.ball.position, phaseKey = null) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const formationProfile = offensiveAutopilotProfiles[formation] ?? offensiveAutopilotProfiles["4-3-3"];
  const resolvedPhaseKey = phaseKey ?? getOffensivePhaseKey(teamId, ballPoint);
  const phaseProfile = offensivePhaseProfiles[resolvedPhaseKey] ?? offensivePhaseProfiles.progression;
  const styleKey = getTeamAttackStyleKey(teamId);
  const styleProfile = getTeamAttackStyleProfile(teamId);
  const rhythmProfile = getAttackStyleRhythmProfile(styleKey);

  return {
    ...formationProfile,
    ...phaseProfile,
    formation,
    phaseKey: resolvedPhaseKey,
    phaseLabel: phaseProfile.label,
    styleKey,
    styleLabel: styleProfile.label,
    stylePrincipleLabel: styleProfile.principleLabel,
    principleLabel: `${formationProfile.principleLabel}; ${styleProfile.principleLabel}`,
    width: clamp(formationProfile.width * phaseProfile.widthMultiplier * styleProfile.widthMultiplier, 40, 66),
    restBehind: clamp(
      formationProfile.restBehind + phaseProfile.restBehindOffset + styleProfile.restBehindOffset,
      15,
      33
    ),
    frontAhead: clamp(
      formationProfile.frontAhead + phaseProfile.depthStretch + styleProfile.frontAheadOffset,
      7,
      22
    ),
    supportCompactness: clamp(
      (phaseProfile.supportCompactness ?? 0.12) * styleProfile.supportCompactnessMultiplier,
      0.04,
      0.3
    ),
    directness: styleProfile.directness,
    shortSupport: styleProfile.shortSupport,
    lineBreakBias: styleProfile.lineBreakBias,
    switchBias: styleProfile.switchBias,
    crossBias: styleProfile.crossBias,
    overlapBias: styleProfile.overlapBias,
    dribbleBias: styleProfile.dribbleBias,
    shootBias: styleProfile.shootBias,
    tempo: styleProfile.tempo,
    risk: styleProfile.risk,
    firstTouchForwardBias: styleProfile.firstTouchForwardBias,
    passBias: styleProfile.passBias ?? clamp(0.4 + styleProfile.shortSupport * 0.35 - styleProfile.directness * 0.08, 0.2, 0.92),
    carryBias: styleProfile.carryBias ?? styleProfile.dribbleBias,
    deliveryBias: styleProfile.deliveryBias ?? styleProfile.crossBias,
    routeOneBias: styleProfile.routeOneBias ?? 0,
    rhythm: rhythmProfile,
    targetPossessionSeconds: rhythmProfile.targetSeconds,
    progressionUrgency: rhythmProfile.progressionUrgency,
    sidewaysTolerance: rhythmProfile.sidewaysTolerance,
    recycleWindow: rhythmProfile.recycleWindow,
    widthDiscipline: clamp(
      0.54 + styleProfile.switchBias * 0.16 + styleProfile.crossBias * 0.14 + (styleProfile.directness < 0.42 ? 0.08 : 0),
      0.54,
      0.88
    ),
  };
}

function getOffensiveRoleKey(player, formation = teams[player.team]?.formation) {
  const label = getPlayerMagnetLabel(player);
  if (label === "GK") return "gk";
  if (label === "CB") return "rest";
  if (label === "LB" || label === "RB" || label === "WB") return "wideBack";
  if (label === "6") return "pivot";
  if (formation === "4-4-2" && label === "10") return "secondStriker";
  if (label === "8" || label === "10") return "connector";
  if (label === "W") return "wideForward";
  if (label === "9") return "striker";
  return "connector";
}

const pitchLaneKeys = ["leftWide", "leftHalf", "central", "rightHalf", "rightWide"];

function getPitchLaneKey(point) {
  const y = point?.y ?? pitch.width / 2;
  if (y <= 9.5) return "leftWide";
  if (y <= 25.5) return "leftHalf";
  if (y <= 42.5) return "central";
  if (y <= 58.5) return "rightHalf";
  return "rightWide";
}

function getPitchLaneIndex(pointOrLane) {
  const laneKey = typeof pointOrLane === "string" ? pointOrLane : getPitchLaneKey(pointOrLane);
  return Math.max(0, pitchLaneKeys.indexOf(laneKey));
}

function getAttackingThirdKey(point, teamId) {
  const depth = getAttackingDepth(point, teamId);
  if (depth < 34) return "build";
  if (depth < 68) return "progress";
  return "finish";
}

function getLaneCenterY(laneKey, profile = {}) {
  const centerY = pitch.width / 2;
  const width = clamp(profile.width ?? 58, 42, 66);
  const wideOffset = clamp(width * 0.49, 25.5, 31.5);
  const halfOffset = clamp(width * 0.24, 12, 17);
  const centers = {
    leftWide: centerY - wideOffset,
    leftHalf: centerY - halfOffset,
    central: centerY,
    rightHalf: centerY + halfOffset,
    rightWide: centerY + wideOffset,
  };

  return clamp(centers[laneKey] ?? centerY, 4, pitch.width - 4);
}

function getSideLaneKeys(baseY) {
  return baseY <= pitch.width / 2
    ? { wide: "leftWide", half: "leftHalf" }
    : { wide: "rightWide", half: "rightHalf" };
}

function getRecentPossessionSteps(teamId, limit = 5) {
  const steps = state.sequence?.steps ?? [];
  const recent = [];

  for (let index = steps.length - 1; index >= 0 && recent.length < limit; index -= 1) {
    const step = steps[index];
    const ownerId =
      step.beforeSnapshot?.ball?.ownerPlayerId ??
      step.carrierPlayerId ??
      step.initiatorPlayerId ??
      null;
    const owner = getPlayerById(ownerId);
    const receiver = getPlayerById(step.receiverPlayerId);

    if (owner?.team === teamId || receiver?.team === teamId) {
      recent.push(step);
    }
  }

  return recent;
}

function getRecordedStepPossessionTeamId(step) {
  const ownerAfter = getPlayerById(step?.afterSnapshot?.ball?.ownerPlayerId);
  if (ownerAfter?.team) {
    return ownerAfter.team;
  }

  const receiver = getPlayerById(step?.receiverPlayerId);
  if (receiver?.team) {
    return receiver.team;
  }

  const carrier = getPlayerById(step?.carrierPlayerId);
  if (carrier?.team) {
    return carrier.team;
  }

  const ownerBefore = getPlayerById(step?.beforeSnapshot?.ball?.ownerPlayerId);
  return ownerBefore?.team ?? null;
}

function getPossessionRhythmContext(teamId, limit = 8) {
  const steps = state.sequence?.steps ?? [];
  const context = {
    steps: 0,
    duration: 0,
    sidewaysPasses: 0,
    backPasses: 0,
    forwardPasses: 0,
    lineBreaks: 0,
    lastActionType: null,
    lastStep: null,
  };

  for (let index = steps.length - 1; index >= 0 && context.steps < limit; index -= 1) {
    const step = steps[index];
    const stepTeamId = getRecordedStepPossessionTeamId(step);

    if (!stepTeamId || stepTeamId !== teamId) {
      break;
    }

    const startPoint = step.beforeSnapshot?.ball?.position;
    const target = step.target;
    const forwardGain =
      startPoint && target
        ? (target.x - startPoint.x) * getAttackDirectionSign(teamId)
        : 0;
    const lateralMeters = startPoint && target ? Math.abs(target.y - startPoint.y) : 0;

    context.steps += 1;
    context.duration += getRecordedStepDuration(step);
    context.lastActionType = context.lastActionType ?? step.actionType;
    context.lastStep = context.lastStep ?? step;

    if (step.actionType !== "pass") {
      continue;
    }

    if (Math.abs(forwardGain) < 4 && lateralMeters >= 6.5) {
      context.sidewaysPasses += 1;
    }

    if (forwardGain <= -4.5) {
      context.backPasses += 1;
    }

    if (forwardGain >= 6) {
      context.forwardPasses += 1;
    }

    if (forwardGain >= 8.5) {
      context.lineBreaks += 1;
    }
  }

  return context;
}

const autoPilotPossessionIntentLabels = {
  secure: "Secure possession",
  progress: "Progress through pressure",
  switch: "Change point of attack",
  wide: "Build wide overload",
  accelerate: "Accelerate into valuable space",
  finish: "Finish the attack",
};

function getLaneForSideSign(sideSign, laneType = "half") {
  if (laneType === "wide") {
    return sideSign < 0 ? "leftWide" : "rightWide";
  }

  return sideSign < 0 ? "leftHalf" : "rightHalf";
}

function getAutoPilotPossessionStartIndex(teamId) {
  const continuousRhythm = getPossessionRhythmContext(teamId, 40);
  return Math.max((state.sequence?.steps?.length ?? 0) - continuousRhythm.steps, 0);
}

function getAutoPilotStyleIntentSequence(styleKey = "balanced") {
  if (styleKey === "wing-play" || styleKey === "overlap-wide") {
    return ["secure", "wide", "switch", "wide", "accelerate", "finish"];
  }

  if (styleKey === "control-possession" || styleKey === "tiki-taka" || styleKey === "fluid-combinations") {
    return ["secure", "progress", "switch", "progress", "accelerate", "finish"];
  }

  if (styleKey === "vertical-tiki-taka" || styleKey === "vertical-play" || styleKey === "gegenpress") {
    return ["progress", "secure", "accelerate", "finish"];
  }

  if (styleKey === "direct-transition" || styleKey === "counter-attack" || styleKey === "fluid-counter-attack") {
    return ["progress", "accelerate", "finish"];
  }

  if (styleKey === "route-one") {
    return ["progress", "finish", "secondBall"];
  }

  return ["secure", "progress", "switch", "accelerate", "finish"];
}

const autoPilotPossessionRouteProfiles = {
  "central-third-man": {
    label: "central third-man route",
    lanes: ["central", "leftHalf", "central", "rightHalf", "central"],
    intents: ["secure", "progress", "progress", "accelerate", "finish"],
    weight: ({ profile }) =>
      0.48 + profile.shortSupport * 0.54 + profile.lineBreakBias * 0.28 + (profile.directness < 0.56 ? 0.18 : 0),
  },
  "wide-overload-switch": {
    label: "wide overload to weak-side switch",
    lanes: ({ sideSign, farSideSign }) => [
      getLaneForSideSign(sideSign, "wide"),
      getLaneForSideSign(sideSign, "half"),
      getLaneForSideSign(farSideSign, "half"),
      getLaneForSideSign(farSideSign, "wide"),
      "central",
    ],
    intents: ["wide", "progress", "switch", "wide", "finish"],
    weight: ({ profile }) =>
      0.38 + profile.widthDiscipline * 0.3 + profile.switchBias * 0.34 + profile.overlapBias * 0.28 + profile.crossBias * 0.22,
  },
  "overlap-cutback": {
    label: "overlap to cutback route",
    lanes: ({ sideSign }) => [
      getLaneForSideSign(sideSign, "half"),
      getLaneForSideSign(sideSign, "wide"),
      getLaneForSideSign(sideSign, "half"),
      "central",
    ],
    intents: ["wide", "wide", "accelerate", "finish"],
    weight: ({ profile }) =>
      0.24 + profile.overlapBias * 0.62 + profile.crossBias * 0.32 + profile.widthDiscipline * 0.22,
  },
  "vertical-half-space": {
    label: "vertical half-space route",
    lanes: ({ sideSign }) => [
      getLaneForSideSign(sideSign, "half"),
      "central",
      getLaneForSideSign(sideSign, "half"),
      "central",
    ],
    intents: ["progress", "secure", "accelerate", "finish"],
    weight: ({ profile }) =>
      0.34 + profile.directness * 0.42 + profile.lineBreakBias * 0.44 + profile.progressionUrgency * 0.28,
  },
  "direct-second-ball": {
    label: "direct second-ball route",
    lanes: ({ sideSign }) => [
      "central",
      getLaneForSideSign(sideSign, "half"),
      "central",
      getLaneForSideSign(sideSign, "wide"),
    ],
    intents: ["progress", "accelerate", "finish", "finish"],
    weight: ({ profile }) =>
      0.18 + profile.routeOneBias * 0.78 + profile.directness * 0.38 + (profile.tempo >= 0.72 ? 0.16 : 0),
  },
  "patient-switch": {
    label: "patient switch route",
    lanes: ({ sideSign, farSideSign }) => [
      getLaneForSideSign(sideSign, "half"),
      "central",
      getLaneForSideSign(farSideSign, "half"),
      getLaneForSideSign(farSideSign, "wide"),
      "central",
    ],
    intents: ["secure", "progress", "switch", "wide", "finish"],
    weight: ({ profile }) =>
      0.34 + profile.switchBias * 0.48 + profile.shortSupport * 0.26 + (profile.directness < 0.5 ? 0.18 : 0),
  },
};

const autoPilotOpeningVariationProfiles = {
  "control-settle": {
    label: "settle possession before progression",
    lanes: ({ sideSign, farSideSign }) => ["central", getLaneForSideSign(sideSign, "half"), getLaneForSideSign(farSideSign, "half")],
    families: ["support-link", "line-break", "switch", "carry-control"],
    receiverRoles: ["pivot", "connector", "wideBack"],
    stepLimit: 4,
    longPassPenalty: 0.52,
    weight: ({ profile }) =>
      0.32 + profile.shortSupport * 0.58 + (profile.directness < 0.5 ? 0.22 : 0) + profile.switchBias * 0.18,
  },
  "wide-probe": {
    label: "create width before attacking inside",
    lanes: ({ sideSign, farSideSign }) => [
      getLaneForSideSign(sideSign, "wide"),
      getLaneForSideSign(sideSign, "half"),
      getLaneForSideSign(farSideSign, "wide"),
    ],
    families: ["wide-overload", "support-link", "switch", "cutback", "cross"],
    receiverRoles: ["wideForward", "wideBack", "connector"],
    stepLimit: 5,
    longPassPenalty: 0.28,
    weight: ({ profile }) =>
      0.22 + profile.widthDiscipline * 0.42 + profile.overlapBias * 0.46 + profile.crossBias * 0.34 + profile.switchBias * 0.16,
  },
  "half-space-probe": {
    label: "find the half-space connector",
    lanes: ({ sideSign, farSideSign }) => [getLaneForSideSign(sideSign, "half"), "central", getLaneForSideSign(farSideSign, "half")],
    families: ["line-break", "support-link", "front-line", "carry-forward"],
    receiverRoles: ["connector", "striker", "wideForward", "pivot"],
    stepLimit: 4,
    longPassPenalty: 0.34,
    weight: ({ profile }) =>
      0.28 + profile.lineBreakBias * 0.46 + profile.progressionUrgency * 0.3 + profile.tempo * 0.18,
  },
  "vertical-threat": {
    label: "threaten depth early",
    lanes: ({ sideSign }) => ["central", getLaneForSideSign(sideSign, "half"), getLaneForSideSign(sideSign, "wide")],
    families: ["line-break", "front-line", "carry-forward", "shot"],
    receiverRoles: ["striker", "wideForward", "secondStriker", "connector"],
    stepLimit: 3,
    longPassPenalty: 0.12,
    weight: ({ profile }) =>
      0.18 + profile.directness * 0.56 + profile.lineBreakBias * 0.34 + profile.progressionUrgency * 0.24 + profile.routeOneBias * 0.28,
  },
  "switch-to-weak-side": {
    label: "move the block then switch",
    lanes: ({ sideSign, farSideSign }) => [
      getLaneForSideSign(sideSign, "half"),
      "central",
      getLaneForSideSign(farSideSign, "half"),
      getLaneForSideSign(farSideSign, "wide"),
    ],
    families: ["support-link", "switch", "wide-overload", "line-break"],
    receiverRoles: ["pivot", "connector", "wideBack", "wideForward"],
    stepLimit: 5,
    longPassPenalty: 0.32,
    weight: ({ profile }) =>
      0.2 + profile.switchBias * 0.62 + profile.shortSupport * 0.22 + (profile.directness < 0.58 ? 0.12 : 0),
  },
};

const autoPilotPlanMemory = {
  home: [],
  away: [],
};

function resolvePossessionRouteLanes(routeProfile, context) {
  const lanes = typeof routeProfile.lanes === "function"
    ? routeProfile.lanes(context)
    : routeProfile.lanes;

  return (lanes ?? ["central"]).filter((laneKey) => pitchLaneKeys.includes(laneKey));
}

function resolveOpeningVariationLanes(openingProfile, context) {
  const lanes = typeof openingProfile.lanes === "function"
    ? openingProfile.lanes(context)
    : openingProfile.lanes;

  return (lanes ?? ["central"]).filter((laneKey) => pitchLaneKeys.includes(laneKey));
}

function getRecentAutoPilotPlanMemory(teamId, profile = {}, limit = 6) {
  const memory = autoPilotPlanMemory[teamId] ?? [];
  return memory
    .filter((entry) => !profile.styleKey || entry.styleKey === profile.styleKey)
    .filter((entry) => !profile.formation || entry.formation === profile.formation)
    .slice(0, limit);
}

function getAutoPilotPlanRepeatPenalty(teamId, profile, key, value, limit = 6) {
  if (value === null || value === undefined) {
    return 0;
  }

  return getRecentAutoPilotPlanMemory(teamId, profile, limit).reduce((penalty, entry, index) => {
    if (entry[key] !== value) {
      return penalty;
    }

    return penalty + (index === 0 ? 0.46 : 0.22 / (index + 0.85));
  }, 0);
}

function rememberAutoPilotPossessionPlan(plan) {
  if (!plan?.teamId || !autoPilotPlanMemory[plan.teamId]) {
    return;
  }

  const memory = autoPilotPlanMemory[plan.teamId];
  const signature = [
    plan.styleKey,
    plan.formation,
    plan.routeKey,
    plan.openingKey,
    plan.preferredLane,
    plan.secondaryLane,
  ].join(":");

  if (memory[0]?.signature === signature && state.time - (memory[0].createdAt ?? 0) < 0.2) {
    return;
  }

  memory.unshift({
    signature,
    teamId: plan.teamId,
    styleKey: plan.styleKey,
    formation: plan.formation,
    routeKey: plan.routeKey,
    openingKey: plan.openingKey,
    preferredLane: plan.preferredLane,
    secondaryLane: plan.secondaryLane,
    routeLabel: plan.routeLabel,
    openingLabel: plan.openingLabel,
    createdAt: state.time,
  });

  if (memory.length > 24) {
    memory.length = 24;
  }
}

function invalidateAutoPilotPossessionPlan(targetState = state) {
  if (!targetState?.autoPilotPlay) {
    return;
  }

  targetState.autoPilotPlay.possessionPlan = null;
  targetState.autoPilotPlay.receiveMomentum = null;
}

function createAutoPilotPossessionRoute(teamId, profile, sideSign, farSideSign) {
  const context = { profile, sideSign, farSideSign, teamId };
  const routeEntries = Object.entries(autoPilotPossessionRouteProfiles);
  const selectedEntry = chooseWeightedOption(routeEntries, ([routeKey, routeProfile]) => {
    const repeatPenalty = getAutoPilotPlanRepeatPenalty(teamId, profile, "routeKey", routeKey, 5);
    const stylisticNoise = randomBetween(-0.04, 0.09);
    return routeProfile.weight(context) + stylisticNoise - repeatPenalty;
  });
  const [routeKey, routeProfile] = selectedEntry ?? routeEntries[0];

  return {
    key: routeKey,
    label: routeProfile.label,
    lanes: resolvePossessionRouteLanes(routeProfile, context),
    intents: routeProfile.intents ?? getAutoPilotStyleIntentSequence(profile.styleKey),
    stepSpan: randomBetween(profile.tempo >= 0.75 ? 0.85 : 1.1, profile.directness >= 0.68 ? 1.35 : 1.85),
  };
}

function createAutoPilotOpeningVariation(teamId, profile, sideSign, farSideSign, route) {
  const context = { profile, sideSign, farSideSign, route, teamId };
  const entries = Object.entries(autoPilotOpeningVariationProfiles);
  const selectedEntry = chooseWeightedOption(entries, ([key, openingProfile]) => {
    const routeFit =
      route.key === "wide-overload-switch" && key === "wide-probe"
        ? 0.28
        : route.key === "overlap-cutback" && key === "wide-probe"
          ? 0.34
          : route.key === "vertical-half-space" && key === "half-space-probe"
            ? 0.3
            : route.key === "direct-second-ball" && key === "vertical-threat"
              ? 0.34
            : route.key === "patient-switch" && key === "switch-to-weak-side"
                ? 0.3
                : 0;
    const repeatPenalty = getAutoPilotPlanRepeatPenalty(teamId, profile, "openingKey", key, 5);
    return openingProfile.weight(context) + routeFit + randomBetween(-0.05, 0.1) - repeatPenalty;
  });
  const [key, openingProfile] = selectedEntry ?? entries[0];

  return {
    key,
    label: openingProfile.label,
    lanes: resolveOpeningVariationLanes(openingProfile, context),
    families: openingProfile.families ?? ["support-link", "line-break"],
    receiverRoles: openingProfile.receiverRoles ?? ["pivot", "connector"],
    stepLimit: openingProfile.stepLimit ?? 4,
    longPassPenalty: openingProfile.longPassPenalty ?? 0.32,
    tempoNudge: randomBetween(-0.06, 0.08),
  };
}

function getAutoPilotPossessionRouteStage(plan, rhythm, depth) {
  const laneCount = Math.max(plan.routeLanes?.length ?? 0, 1);
  const rawStage = Math.floor((rhythm.steps + Math.max(0, rhythm.forwardPasses - 1) * 0.35) / Math.max(plan.routeStepSpan ?? 1.2, 0.65));
  const depthBoost = depth >= 68 ? 1 : depth >= 54 && rhythm.forwardPasses >= 1 ? 0.5 : 0;
  return clamp(Math.floor(rawStage + depthBoost), 0, laneCount - 1);
}

function createAutoPilotPossessionPlan(teamId, startPoint, profile) {
  const sideSign = getWideSideSign(startPoint) || randomSign();
  const farSideSign = -sideSign;
  const directStyle = profile.directness >= 0.68 || isTransitionAttackStyle(profile.styleKey);
  const wideStyle = profile.crossBias >= 0.62 || profile.overlapBias >= 0.62;
  const route = createAutoPilotPossessionRoute(teamId, profile, sideSign, farSideSign);
  const opening = createAutoPilotOpeningVariation(teamId, profile, sideSign, farSideSign, route);
  const preferredLaneOptions = wideStyle
    ? [getLaneForSideSign(sideSign, "wide"), getLaneForSideSign(sideSign, "half"), getLaneForSideSign(farSideSign, "wide")]
    : directStyle
      ? ["central", getLaneForSideSign(sideSign, "half")]
      : ["central", getLaneForSideSign(sideSign, "half"), getLaneForSideSign(farSideSign, "half")];
  const preferredLane = chooseWeightedOption(preferredLaneOptions, (lane) => {
    const baseWeight = lane === "central"
      ? directStyle ? 1.15 : 1.08
      : lane.includes("Wide")
        ? wideStyle ? 1.18 : 0.72
        : 0.92;
    const routeLaneFit = route.lanes?.includes(lane) ? 0.22 : 0;
    const openingLaneFit = opening.lanes?.includes(lane) ? 0.18 : 0;
    const repeatPenalty = getAutoPilotPlanRepeatPenalty(teamId, profile, "preferredLane", lane, 4) * 0.82;
    return baseWeight + routeLaneFit + openingLaneFit + randomBetween(-0.04, 0.08) - repeatPenalty;
  });
  const secondaryLane = preferredLane === "central"
    ? getLaneForSideSign(sideSign, wideStyle ? "wide" : "half")
    : getLaneForSideSign(farSideSign, wideStyle ? "wide" : "half");

  const plan = {
    teamId,
    startIndex: getAutoPilotPossessionStartIndex(teamId),
    styleKey: profile.styleKey,
    formation: profile.formation,
    preferredLane,
    secondaryLane,
    routeKey: route.key,
    routeLabel: route.label,
    routeLanes: route.lanes,
    routeIntents: route.intents,
    routeStepSpan: route.stepSpan,
    openingKey: opening.key,
    openingLabel: opening.label,
    openingLanes: opening.lanes,
    openingFamilies: opening.families,
    openingReceiverRoles: opening.receiverRoles,
    openingStepLimit: opening.stepLimit,
    openingLongPassPenalty: opening.longPassPenalty,
    intentSequence: getAutoPilotStyleIntentSequence(profile.styleKey),
    switchAfter: Math.round(randomBetween(wideStyle ? 2 : 3, wideStyle ? 4 : 5)),
    escalateAfter: Math.round(randomBetween(directStyle ? 1 : 3, directStyle ? 3 : 6)),
    lanePatience: randomBetween(0.82, 1.18),
    tempoNudge: randomBetween(-0.08, 0.1) + opening.tempoNudge,
    createdAt: state.time,
  };

  rememberAutoPilotPossessionPlan(plan);
  return plan;
}

function getAutoPilotPossessionPlan(teamId, startPoint, profile) {
  const startIndex = getAutoPilotPossessionStartIndex(teamId);
  if (
    !state.autoPilotPlay?.possessionPlan ||
    state.autoPilotPlay.possessionPlan.teamId !== teamId ||
    state.autoPilotPlay.possessionPlan.startIndex !== startIndex ||
    state.autoPilotPlay.possessionPlan.styleKey !== profile.styleKey
  ) {
    state.autoPilotPlay.possessionPlan = createAutoPilotPossessionPlan(teamId, startPoint, profile);
  }

  return state.autoPilotPlay.possessionPlan;
}

function getAutoPilotPossessionIntentContext(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const rhythm = getPossessionRhythmContext(teamId);
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const plan = getAutoPilotPossessionPlan(teamId, startPoint, profile);
  const depth = getAttackingDepth(startPoint, teamId);
  const pressure = flow.pressure;
  const currentLane = getPitchLaneKey(startPoint);
  const currentThird = getAttackingThirdKey(startPoint, teamId);
  const laneRepeats = getRecentLaneRepeatCount(teamId, currentLane, currentThird, 5);
  const threat = getPitchThreatProfile(startPoint, teamId);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const routeStage = getAutoPilotPossessionRouteStage(plan, rhythm, depth);
  const routeTargetLane =
    plan.routeLanes?.[routeStage] ??
    plan.routeLanes?.[0] ??
    plan.preferredLane;
  const routeIntent =
    plan.routeIntents?.[Math.min(routeStage, (plan.routeIntents?.length ?? 1) - 1)] ??
    plan.intentSequence[Math.min(plan.intentSequence.length - 1, rhythm.steps)] ??
    "progress";
  const weights = {
    secure: clamp(0.2 + profile.shortSupport * 0.32 - profile.directness * 0.08 + (rhythm.steps <= 1 ? 0.14 : 0), 0, 1),
    progress: clamp(0.24 + profile.lineBreakBias * 0.38 + profile.progressionUrgency * 0.26 + (depth >= 34 && depth < 68 ? 0.12 : 0), 0, 1),
    switch: clamp(0.14 + profile.switchBias * 0.32 + rhythm.sidewaysPasses * 0.12 + laneRepeats * 0.1, 0, 1),
    wide: clamp(0.12 + profile.widthDiscipline * 0.16 + profile.crossBias * 0.22 + profile.overlapBias * 0.22, 0, 1),
    accelerate: clamp(0.14 + profile.directness * 0.24 + profile.tempo * 0.18 + profile.progressionUrgency * 0.22 + (depth >= 58 ? 0.16 : 0), 0, 1),
    finish: clamp(0.08 + profile.shootBias * 0.28 + threat.value * 0.34 + (depth >= 72 ? 0.24 : 0), 0, 1),
  };
  const plannedIntent = plan.intentSequence[
    Math.min(plan.intentSequence.length - 1, rhythm.steps)
  ];

  if (weights[plannedIntent] !== undefined) {
    weights[plannedIntent] = clamp(weights[plannedIntent] + 0.22 + Math.abs(plan.tempoNudge), 0, 1.22);
  }

  if (weights[routeIntent] !== undefined) {
    weights[routeIntent] = clamp(
      weights[routeIntent] + 0.18 + Math.abs(plan.tempoNudge) * 0.6,
      0,
      1.28
    );
  }

  if (routeTargetLane && routeTargetLane !== currentLane && rhythm.steps >= 1) {
    weights.switch = clamp(weights.switch + 0.08 + profile.switchBias * 0.08, 0, 1.28);
  }

  if (pressure >= 0.62) {
    weights.secure = clamp(weights.secure + 0.24, 0, 1.25);
    weights.progress = clamp(weights.progress + 0.08, 0, 1.15);
  }

  if (progressionWindow.active) {
    weights.progress = clamp(weights.progress + 0.26 + progressionWindow.urgency * 0.16, 0, 1.3);
    weights.accelerate = clamp(weights.accelerate + 0.18 + progressionWindow.openLane * 0.18, 0, 1.28);
    weights.secure = clamp(weights.secure - 0.18 * progressionWindow.urgency, 0, 1.05);
  }

  if (laneRepeats >= plan.switchAfter || rhythm.sidewaysPasses >= 2) {
    weights.switch = clamp(weights.switch + 0.3 * plan.lanePatience, 0, 1.34);
    weights.progress = clamp(weights.progress + 0.1, 0, 1.18);
  }

  if (rhythm.steps >= plan.escalateAfter || depth >= 64) {
    weights.accelerate = clamp(weights.accelerate + 0.24 + profile.risk * 0.14, 0, 1.34);
    weights.finish = clamp(weights.finish + (depth >= 70 ? 0.22 : 0.08), 0, 1.3);
  }

  if (threat.centralPocket >= 0.42 || threat.betweenLines >= 0.5 || threat.box >= 0.32) {
    weights.finish = clamp(weights.finish + 0.24 + threat.box * 0.18, 0, 1.35);
    weights.accelerate = clamp(weights.accelerate + 0.16, 0, 1.28);
  }

  const top = Object.entries(weights)
    .sort((a, b) => b[1] - a[1])[0] ?? ["progress", 0.5];

  return {
    plan,
    rhythm,
    flow,
    depth,
    pressure,
    currentLane,
    currentThird,
    laneRepeats,
    threat,
    progressionWindow,
    routeStage,
    routeTargetLane,
    routeIntent,
    weights,
    topIntent: top[0],
    topWeight: top[1],
  };
}

function getAutoPilotPossessionIntentFit(candidate, carrier, startPoint, profile, context) {
  const targetLane = getPitchLaneKey(candidate.target);
  const startLane = getPitchLaneKey(startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(startLane));
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetThreat = getPitchThreatProfile(candidate.target, carrier.team);
  const startThreat = getPitchThreatProfile(startPoint, carrier.team);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, carrier.team, profile);
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver
      ? getPlayerPressureLoad(receiver, candidate.target)
      : 0.42;
  const targetIsWide = targetLane === "leftWide" || targetLane === "rightWide";
  const supportRole = isSupportRole(receiverRoleKey) || receiverRoleKey === "gk" || receiverRoleKey === "rest";
  const highValueTarget =
    targetThreat.value >= 0.48 ||
    targetThreat.centralPocket >= 0.4 ||
    targetThreat.betweenLines >= 0.46 ||
    targetThreat.box >= 0.28 ||
    actionSpace.value >= 0.52;
  const fit = {
    secure: candidate.actionType === "pass"
      ? clamp((passDistance <= 18 ? 0.48 : 0.18) + (supportRole ? 0.28 : 0) + (receiverPressure <= 0.62 ? 0.18 : 0) + (forwardGain >= -8 ? 0.12 : -0.16), 0, 1)
      : 0,
    progress: clamp((forwardGain >= 5 ? 0.36 : 0) + (candidate.isLineBreak ? 0.34 : 0) + actionSpace.lineBreakCount * 0.12 + (candidate.actionType === "dribble" && forwardGain >= 4 ? 0.22 : 0), 0, 1),
    switch: candidate.actionType === "pass"
      ? clamp((candidate.isSwitch ? 0.72 : 0) + (laneShift >= 2 && passDistance >= 14 ? 0.42 : 0) + (targetLane === context.plan.secondaryLane ? 0.18 : 0), 0, 1)
      : 0,
    wide: clamp((targetIsWide ? 0.42 : 0) + (receiverRoleKey === "wideBack" || receiverRoleKey === "wideForward" ? 0.3 : 0) + (candidate.principleKey?.includes("wide") || candidate.principleKey?.includes("overlap") ? 0.34 : 0), 0, 1),
    accelerate: clamp((forwardGain >= 7 ? 0.32 : 0) + (highValueTarget ? 0.32 : 0) + (candidate.isBoxPass ? 0.24 : 0) + (candidate.actionType === "dribble" && forwardGain >= 6 ? 0.24 : 0), 0, 1),
    finish: clamp(
      (candidate.actionType === "shot" ? 0.9 : 0) +
        (candidate.isBoxPass ? 0.34 : 0) +
        targetThreat.box * 0.34 +
        targetThreat.centralPocket * 0.18 +
        targetThreat.cutbackZone * 0.16,
      0,
      1
    ),
  };

  return {
    fit,
    targetLane,
    forwardGain,
    targetThreat,
    startThreat,
    actionSpace,
  };
}

function getAutoPilotPossessionIntentAdjustment(candidate, carrier, startPoint, profile) {
  const context = getAutoPilotPossessionIntentContext(carrier, startPoint, profile);
  const details = getAutoPilotPossessionIntentFit(candidate, carrier, startPoint, profile, context);
  const weightedFit = Object.entries(context.weights).reduce(
    (total, [intentKey, weight]) => total + (details.fit[intentKey] ?? 0) * weight,
    0
  ) / Math.max(Object.values(context.weights).reduce((total, value) => total + value, 0), 0.01);
  const topFit = details.fit[context.topIntent] ?? 0;
  const preferredLaneFit = details.targetLane === context.plan.preferredLane && context.rhythm.steps <= context.plan.switchAfter
    ? 0.13
    : 0;
  const secondaryLaneFit = details.targetLane === context.plan.secondaryLane && (context.laneRepeats >= 2 || context.topIntent === "switch")
    ? 0.16
    : 0;
  const routeLaneDistance = context.routeTargetLane
    ? Math.abs(getPitchLaneIndex(details.targetLane) - getPitchLaneIndex(context.routeTargetLane))
    : 0;
  const routeLaneFit = context.routeTargetLane
    ? routeLaneDistance === 0
      ? 0.2 + Math.min(context.routeStage, 3) * 0.035
      : routeLaneDistance === 1 && details.forwardGain >= 2
        ? 0.08
        : 0
    : 0;
  const routeIntentFit = details.fit[context.routeIntent] ?? 0;
  const staleLanePenalty =
    details.targetLane === context.currentLane &&
    context.laneRepeats >= context.plan.switchAfter &&
    !candidate.isLineBreak &&
    !candidate.isBoxPass &&
    candidate.actionType !== "shot"
      ? 0.24 + context.laneRepeats * 0.08
      : 0;
  const forwardFacingLowValuePenalty =
    context.progressionWindow.active &&
    candidate.actionType === "pass" &&
    details.forwardGain < 2 &&
    details.targetThreat.value <= details.startThreat.value + 0.04 &&
    context.pressure <= 0.52
      ? 0.34 + context.progressionWindow.urgency * 0.22
      : 0;
  const topIntentMissPenalty =
    topFit < 0.28 && candidate.actionType !== "shot"
      ? context.topWeight * 0.24
      : 0;
  const routeMissPenalty =
    context.routeTargetLane &&
    context.rhythm.steps >= 1 &&
    routeLaneDistance >= 2 &&
    !candidate.isSwitch &&
    !candidate.isLineBreak &&
    !candidate.isBoxPass &&
    candidate.actionType !== "shot"
      ? 0.12 + Math.min(routeLaneDistance, 4) * 0.055
      : 0;
  const score = clamp(
    weightedFit * 0.72 +
      topFit * 0.22 +
      routeIntentFit * 0.12 +
      preferredLaneFit +
      secondaryLaneFit -
      routeMissPenalty +
      routeLaneFit -
      staleLanePenalty -
      forwardFacingLowValuePenalty -
      topIntentMissPenalty,
    -0.85,
    0.95
  );
  const labels = [];

  if (topFit >= 0.36 && autoPilotPossessionIntentLabels[context.topIntent]) {
    labels.push(autoPilotPossessionIntentLabels[context.topIntent]);
  }

  if (details.targetThreat.value >= 0.5 || details.targetThreat.box >= 0.3) {
    labels.push(`Attack ${details.targetThreat.primaryLabel}`);
  }

  if (details.targetLane === context.plan.secondaryLane && context.topIntent === "switch") {
    labels.push("Change point of attack");
  }

  if (routeLaneFit >= 0.16) {
    labels.push(context.plan.routeLabel ?? "Follow possession route");
  }

  if (
    context.routeTargetLane &&
    routeLaneDistance >= 2 &&
    (candidate.isSwitch || context.routeIntent === "switch")
  ) {
    labels.push("Use weak side");
  }

  return {
    score,
    labels: uniquePrincipleLabels(labels),
    intentKey: context.topIntent,
    intentLabel: autoPilotPossessionIntentLabels[context.topIntent] ?? "Possession plan",
  };
}

const autoPilotTempoPhaseLabels = {
  settle: "Tempo phase: settle first pass",
  probe: "Tempo phase: probe the block",
  moveBlock: "Tempo phase: move the block",
  accelerate: "Tempo phase: accelerate",
  finish: "Tempo phase: finish attack",
};

function getAutoPilotTempoPhaseContext(carrier, startPoint, profile = {}) {
  if (!carrier?.team || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const rhythm = getPossessionRhythmContext(teamId, 10);
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const threat = getPitchThreatProfile(startPoint, teamId);
  const gameSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const depth = getAttackingDepth(startPoint, teamId);
  const targetSeconds =
    profile.targetPossessionSeconds ??
    getAttackStyleRhythmProfile(profile.styleKey).targetSeconds ??
    possessionRhythmDefaults.targetSeconds;
  const maturity = clamp(rhythm.duration / Math.max(targetSeconds, 0.1), 0, 1.6);
  const currentLane = getPitchLaneKey(startPoint);
  const currentThird = getAttackingThirdKey(startPoint, teamId);
  const laneRepeats = getRecentLaneRepeatCount(teamId, currentLane, currentThird, 6);
  const recent = getRecentPossessionSteps(teamId, 6);
  const recentFinalThirdActions = recent.filter((step) => {
    const target = step.target ?? step.afterSnapshot?.ball?.position ?? null;
    return target && getAttackingDepth(target, teamId) >= 66;
  }).length;
  const recentShots = recent.filter((step) => step.actionType === "shot").length;
  const noProgress =
    rhythm.steps >= 2 &&
    rhythm.forwardPasses === 0 &&
    rhythm.lineBreaks === 0;
  const staleCirculation =
    rhythm.lineBreaks === 0 &&
    (rhythm.sidewaysPasses >= 2 || rhythm.backPasses >= 1 || laneRepeats >= 2);
  const finalThirdState =
    depth >= 68 ||
    threat.box >= 0.2 ||
    threat.cutbackZone >= 0.26 ||
    threat.centralPocket >= 0.42 ||
    gameSpace.key === "space3" ||
    recentFinalThirdActions >= 2;
  const directStyle =
    profile.directness >= 0.68 ||
    isTransitionAttackStyle(profile.styleKey) ||
    profile.styleKey === "route-one";
  let phaseKey = "probe";

  if (finalThirdState) {
    phaseKey = "finish";
  } else if (staleCirculation || noProgress) {
    phaseKey = "moveBlock";
  } else if (
    maturity >= 0.62 ||
    depth >= 54 ||
    rhythm.steps >= Math.max(3, Math.round(targetSeconds / 3.4)) ||
    flow.carrierJustReceived
  ) {
    phaseKey = "accelerate";
  } else if (rhythm.steps <= 1 && flow.pressure <= 0.58 && !directStyle) {
    phaseKey = "settle";
  }

  return {
    active: true,
    teamId,
    rhythm,
    flow,
    threat,
    gameSpace,
    depth,
    targetSeconds,
    maturity,
    currentLane,
    currentThird,
    laneRepeats,
    recentFinalThirdActions,
    recentShots,
    noProgress,
    staleCirculation,
    finalThirdState,
    directStyle,
    phaseKey,
  };
}

function getAutoPilotTempoPhaseAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotTempoPhaseContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const targetLane = getPitchLaneKey(target);
  const laneShift = Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(context.currentLane));
  const targetThreat = getPitchThreatProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const supportPass =
    candidate.actionType === "pass" &&
    passDistance <= 20 &&
    forwardGain >= -8 &&
    (isSupportRole(receiverRoleKey) || receiverRoleKey === "rest" || receiverRoleKey === "gk");
  const highValueAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.value >= context.threat.value + 0.08 ||
    targetThreat.box >= 0.26 ||
    actionSpace.lineBreakCount >= 1;
  const sterileAction =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 2.5 &&
    targetThreat.value <= context.threat.value + 0.04 &&
    actionSpace.lineBreakCount === 0;
  const progressiveAction =
    (candidate.actionType === "pass" || candidate.actionType === "dribble") &&
    forwardGain >= 4 &&
    (
      candidate.isLineBreak ||
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.34 ||
      targetThreat.value >= context.threat.value + 0.055
    );
  const switchAction =
    candidate.actionType === "pass" &&
    (candidate.isSwitch || (laneShift >= 2 && passDistance >= 15));
  const carryToGoal =
    candidate.actionType === "dribble" &&
    forwardGain >= 4 &&
    distance(target, getOpponentGoalCenter(teamId)) <= distance(startPoint, getOpponentGoalCenter(teamId)) - 3;
  const labels = [];
  let score = 0;

  if (autoPilotTempoPhaseLabels[context.phaseKey]) {
    labels.push(autoPilotTempoPhaseLabels[context.phaseKey]);
  }

  if (context.phaseKey === "settle") {
    if (supportPass) {
      score += 0.22 + profile.shortSupport * 0.22;
    }

    if (progressiveAction && passDistance <= 24) {
      score += 0.1 + profile.tempo * 0.08;
    }

    if (
      candidate.actionType === "pass" &&
      passDistance >= 27 &&
      !candidate.isSwitch &&
      !candidate.isLineBreak &&
      !candidate.isBoxPass
    ) {
      score -= 0.34 + (1 - profile.directness) * 0.22;
    }

    if (candidate.actionType === "shot" && !candidate.mustShoot) {
      score -= 0.28;
    }
  } else if (context.phaseKey === "probe") {
    if (progressiveAction || targetThreat.betweenLines >= 0.32 || targetThreat.halfSpace >= 0.36) {
      score += 0.18 + actionSpace.value * 0.24;
    }

    if (switchAction && context.rhythm.sidewaysPasses >= 1) {
      score += 0.14 + profile.switchBias * 0.14;
    }

    if (sterileAction && targetLane === context.currentLane && context.flow.pressure <= 0.52) {
      score -= 0.2 + profile.progressionUrgency * 0.16;
    }
  } else if (context.phaseKey === "moveBlock") {
    if (switchAction) {
      score += 0.34 + profile.switchBias * 0.26 + Math.min(context.laneRepeats, 4) * 0.08;
    }

    if (progressiveAction) {
      score += 0.24 + profile.progressionUrgency * 0.2;
    }

    if (carryToGoal && context.flow.pressure <= 0.64) {
      score += 0.22 + profile.carryBias * 0.16;
    }

    if (sterileAction && !switchAction) {
      score -= 0.46 + context.maturity * 0.22;
    }
  } else if (context.phaseKey === "accelerate") {
    if (progressiveAction) {
      score += 0.32 + actionSpace.value * 0.3 + profile.progressionUrgency * 0.2;
    }

    if (carryToGoal) {
      score += 0.26 + profile.carryBias * 0.18;
    }

    if (candidate.actionType === "shot" && (context.depth >= 58 || context.threat.centralPocket >= 0.34)) {
      score += 0.22 + profile.shootBias * 0.18;
    }

    if (sterileAction && context.flow.pressure <= 0.52) {
      score -= 0.42 + profile.progressionUrgency * 0.22;
    }
  } else if (context.phaseKey === "finish") {
    if (candidate.actionType === "shot") {
      score +=
        0.36 +
        profile.shootBias * 0.28 +
        (candidate.mustShoot ? 0.28 : 0) +
        (candidate.insideBox ? 0.24 : 0);
    }

    if (
      candidate.actionType === "pass" &&
      (candidate.isBoxPass || candidate.label === "cutback" || targetThreat.cutbackZone >= 0.3)
    ) {
      score += 0.28 + profile.deliveryBias * 0.18 + targetThreat.box * 0.16;
    }

    if (carryToGoal && actionSpace.openTarget >= 0.38) {
      score += 0.2 + profile.dribbleBias * 0.16;
    }

    if (
      sterileAction &&
      context.flow.pressure <= 0.56 &&
      !candidate.isSwitch &&
      !highValueAction
    ) {
      score -= 0.54 + (context.recentShots === 0 ? 0.18 : 0);
    }
  }

  if (
    context.maturity >= 1 &&
    !highValueAction &&
    !switchAction &&
    candidate.actionType !== "shot" &&
    forwardGain < 4
  ) {
    score -= 0.18 + Math.min(context.maturity - 1, 0.6) * 0.28;
  }

  if (
    context.recentFinalThirdActions >= 2 &&
    context.recentShots === 0 &&
    candidate.actionType === "shot"
  ) {
    score += 0.18 + profile.shootBias * 0.16;
    labels.push("Stop overplaying");
  }

  if (pattern.family === "recycle" && context.phaseKey !== "settle" && context.flow.pressure <= 0.45) {
    score -= 0.16 + profile.progressionUrgency * 0.12;
  }

  return {
    score: clamp(score, -1.25, 1.35),
    labels: uniquePrincipleLabels(labels),
    context: {
      phaseKey: context.phaseKey,
      maturity: context.maturity,
      laneRepeats: context.laneRepeats,
      staleCirculation: context.staleCirculation,
      noProgress: context.noProgress,
      recentFinalThirdActions: context.recentFinalThirdActions,
      recentShots: context.recentShots,
      pattern,
    },
  };
}

function getAutoPilotRhythmGovernorAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const rhythm = getPossessionRhythmContext(teamId, 10);
  if (!rhythm.steps) {
    return { score: 0, labels: [], context: null };
  }

  const recent = getRecentPossessionSteps(teamId, 7);
  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const targetThreat = getPitchThreatProfile(candidate.target, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const targetSeconds = profile.targetPossessionSeconds ?? possessionRhythmDefaults.targetSeconds;
  const averageActionTime = rhythm.duration / Math.max(rhythm.steps, 1);
  const targetActionTime = clamp(1.42 - (profile.tempo ?? 0.55) * 0.42, 0.72, 1.35);
  const maturity = clamp(rhythm.duration / Math.max(targetSeconds, 0.1), 0, 1.8);
  const recentPatterns = recent
    .map((step) => getRecordedStepPattern(step, teamId))
    .filter(Boolean);
  const recentVerticalActions = recentPatterns
    .slice(0, 3)
    .filter((entry) => ["line-break", "carry-forward", "front-line"].includes(entry.family)).length;
  const recentRecycles = recentPatterns
    .slice(0, 4)
    .filter((entry) => entry.family === "recycle" || entry.forwardGain <= -4.5).length;
  const recentFinalThird = recent.filter((step) => {
    const point = step.target ?? step.afterSnapshot?.ball?.position ?? null;
    return point && getAttackingDepth(point, teamId) >= 67;
  }).length;
  const recentShots = recent.filter((step) => step.actionType === "shot").length;
  const directStyle = profile.directness >= 0.68 || isTransitionAttackStyle(profile.styleKey) || profile.styleKey === "route-one";
  const rushedTempo =
    rhythm.steps >= 2 &&
    averageActionTime < targetActionTime * 0.72 &&
    !directStyle &&
    pressure <= 0.58;
  const stalePossession =
    rhythm.steps >= 3 &&
    rhythm.lineBreaks === 0 &&
    (rhythm.sidewaysPasses >= 2 || rhythm.backPasses >= 1 || recentRecycles >= 2);
  const overTargetWithoutThreat =
    maturity >= 0.9 &&
    targetThreat.value < startThreat.value + 0.06 &&
    rhythm.lineBreaks === 0;
  const finalThirdNeedsEndProduct =
    recentFinalThird >= 2 &&
    recentShots === 0 &&
    (getAttackingDepth(startPoint, teamId) >= 64 || startThreat.value >= 0.5);
  const supportAction =
    candidate.actionType === "pass" &&
    pattern.passDistance <= 20 &&
    pattern.forwardGain >= -8 &&
    (isSupportRole(pattern.receiverRoleKey) || pattern.receiverRoleKey === "rest" || pattern.receiverRoleKey === "gk");
  const valueAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.value >= 0.62 ||
    actionSpace.lineBreakCount >= 1 ||
    pattern.forwardGain >= 7;
  const sterileAction =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    pattern.forwardGain < 3 &&
    targetThreat.value <= startThreat.value + 0.04 &&
    actionSpace.lineBreakCount === 0;
  const switchOrChangeLane =
    candidate.actionType === "pass" &&
    (candidate.isSwitch || Math.abs(getPitchLaneIndex(pattern.laneKey) - getPitchLaneIndex(getPitchLaneKey(startPoint))) >= 2);
  const labels = [];
  let score = 0;

  if (rushedTempo) {
    if (supportAction) {
      score += 0.2 + (profile.shortSupport ?? 0.5) * 0.18;
      labels.push("Rhythm: regain control");
    }

    if (
      candidate.actionType === "pass" &&
      pattern.passDistance >= 28 &&
      !candidate.isSwitch &&
      !candidate.isLineBreak &&
      !candidate.isBoxPass
    ) {
      score -= 0.36 + (1 - (profile.directness ?? 0.5)) * 0.22;
      labels.push("Rhythm: avoid rushed turnover");
    }

    if (candidate.actionType === "dribble" && pattern.forwardGain >= 4 && pressure <= 0.46) {
      score += 0.1 + (profile.carryBias ?? 0.5) * 0.08;
    }
  }

  if (recentVerticalActions >= 2 && !directStyle) {
    if (supportAction || switchOrChangeLane) {
      score += 0.12 + (profile.shortSupport ?? 0.5) * 0.08;
      labels.push("Rhythm: connect after vertical play");
    } else if (pattern.forwardGain >= 9 && !valueAction) {
      score -= 0.22 + (1 - (profile.directness ?? 0.5)) * 0.16;
    }
  }

  if (stalePossession || overTargetWithoutThreat) {
    if (valueAction || switchOrChangeLane) {
      score += 0.26 + (profile.progressionUrgency ?? 0.5) * 0.24;
      labels.push(stalePossession ? "Rhythm: change tempo" : "Rhythm: progress now");
    }

    if (sterileAction) {
      score -= 0.36 + (profile.progressionUrgency ?? 0.5) * 0.26 + maturity * 0.08;
      labels.push("Rhythm: stop sterile circulation");
    }
  }

  if (finalThirdNeedsEndProduct) {
    if (
      candidate.actionType === "shot" ||
      candidate.label === "cutback" ||
      candidate.label === "cross" ||
      candidate.isBoxPass ||
      targetThreat.cutbackZone >= 0.32
    ) {
      score += 0.32 + (profile.shootBias ?? 0.5) * 0.18 + (profile.deliveryBias ?? 0.5) * 0.12;
      labels.push("Rhythm: create end product");
    } else if (sterileAction && pressure <= 0.58) {
      score -= 0.42 + (profile.progressionUrgency ?? 0.5) * 0.2;
    }
  }

  if (
    rhythm.steps <= 1 &&
    !directStyle &&
    candidate.actionType === "shot" &&
    !candidate.mustShoot &&
    startThreat.value < 0.62
  ) {
    score -= 0.18;
  }

  return {
    score: clamp(score, -1.18, 1.1),
    labels: uniquePrincipleLabels(labels),
    context: {
      averageActionTime,
      targetActionTime,
      maturity,
      rushedTempo,
      stalePossession,
      overTargetWithoutThreat,
      finalThirdNeedsEndProduct,
      recentVerticalActions,
      recentRecycles,
      recentFinalThird,
      recentShots,
      pattern,
    },
  };
}

function getAutoPilotOpeningVariationAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier?.team) {
    return { score: 0, labels: [] };
  }

  const plan = getAutoPilotPossessionPlan(carrier.team, startPoint, profile);
  const rhythm = getPossessionRhythmContext(carrier.team);
  const stepLimit = plan.openingStepLimit ?? 0;
  if (!plan.openingKey || rhythm.steps >= stepLimit) {
    return { score: 0, labels: [] };
  }

  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const openingProgress = clamp(rhythm.steps / Math.max(stepLimit, 1), 0, 1);
  const laneFit = (plan.openingLanes ?? []).includes(pattern.laneKey);
  const familyFit = (plan.openingFamilies ?? []).includes(pattern.family);
  const receiverRoleFit = pattern.receiverRoleKey
    ? (plan.openingReceiverRoles ?? []).includes(pattern.receiverRoleKey)
    : candidate.actionType === "dribble" || candidate.actionType === "shot";
  const isLongUnsupported =
    candidate.actionType === "pass" &&
    pattern.passDistance >= 28 &&
    !candidate.isSwitch &&
    !candidate.isLineBreak &&
    !candidate.isBoxPass &&
    (candidate.supportNearTarget ?? 0) <= 0;
  const isSterileSideways =
    candidate.isSidewaysPass &&
    rhythm.sidewaysPasses >= 1 &&
    !familyFit &&
    !laneFit;
  const isEarlyBackPass =
    pattern.forwardGain <= -5 &&
    rhythm.steps >= 1 &&
    rhythm.forwardPasses === 0 &&
    candidate.receiverRoleKey !== "gk" &&
    profile.directness >= 0.5;
  const valuableException =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    getPitchThreatProfile(candidate.target, carrier.team).value >= 0.62;
  let score = 0;

  if (laneFit) {
    score += 0.18 + (1 - openingProgress) * 0.12;
  }

  if (familyFit) {
    score += 0.26 + (1 - openingProgress) * 0.16;
  }

  if (receiverRoleFit) {
    score += 0.15;
  }

  if (pattern.family === "switch" && plan.openingKey === "switch-to-weak-side" && rhythm.steps >= 1) {
    score += 0.28 + profile.switchBias * 0.18;
  }

  if (pattern.family === "wide-overload" && plan.openingKey === "wide-probe") {
    score += 0.32 + profile.overlapBias * 0.2;
  }

  if (pattern.family === "line-break" && plan.openingKey === "half-space-probe") {
    score += 0.24 + profile.lineBreakBias * 0.22;
  }

  if (pattern.family === "front-line" && plan.openingKey === "vertical-threat") {
    score += 0.28 + profile.directness * 0.18;
  }

  if (!valuableException) {
    if (isLongUnsupported) {
      score -= plan.openingLongPassPenalty ?? 0.32;
    }

    if (isSterileSideways) {
      score -= 0.24 + profile.progressionUrgency * 0.18;
    }

    if (isEarlyBackPass) {
      score -= 0.22 + profile.progressionUrgency * 0.16;
    }
  }

  const labels = [];
  if (score >= 0.24) {
    labels.push(`Opening variation: ${plan.openingLabel}`);
  }

  return {
    score: clamp(score, -0.72, 0.82),
    labels: uniquePrincipleLabels(labels),
    openingKey: plan.openingKey,
  };
}

function getOpponentBlockReadProfile(teamId, ballPoint = state.ball.position) {
  const opponentTeamId = getOtherTeamId(teamId);
  if (!opponentTeamId) {
    return {
      compactCenter: 0,
      stretchedWidth: 0,
      ballSideCompression: 0,
      lineGap: 0,
      highLine: 0,
      deepBlock: 0,
      nearBallPressure: 0,
      lineDepths: getOpponentLineDepthsForAttackingTeam(teamId, ballPoint),
    };
  }

  const opponents = state.players.filter((player) => player.team === opponentTeamId && !isGoalkeeper(player));
  const lineDepths = getOpponentLineDepthsForAttackingTeam(teamId, ballPoint);
  if (!opponents.length) {
    return {
      compactCenter: 0,
      stretchedWidth: 0,
      ballSideCompression: 0,
      lineGap: 0,
      highLine: 0,
      deepBlock: 0,
      nearBallPressure: 0,
      lineDepths,
    };
  }

  const ys = opponents.map((player) => player.position.y);
  const blockWidth = Math.max(...ys) - Math.min(...ys);
  const centralPlayers = opponents.filter((player) => Math.abs(player.position.y - pitch.width / 2) <= 18).length;
  const centralDensity = centralPlayers / opponents.length;
  const ballSide = getWideSideSign(ballPoint) || 1;
  const ballSidePlayers = opponents.filter((player) => {
    const side = getWideSideSign(player) || ballSide;
    return side === ballSide || Math.abs(player.position.y - pitch.width / 2) <= 8;
  }).length;
  const farSidePlayers = opponents.length - ballSidePlayers;
  const midfieldBackGap = Math.max(0, lineDepths.back - lineDepths.midfield);
  const forwardMidfieldGap = Math.max(0, lineDepths.midfield - lineDepths.forward);
  const lineGap = Math.max(midfieldBackGap, forwardMidfieldGap);
  const nearBallOpponents = getOpponentDensityAtPoint(teamId, ballPoint, 12.5);

  return {
    compactCenter: clamp(centralDensity * 0.72 + (1 - blockWidth / 54) * 0.42, 0, 1),
    stretchedWidth: clamp((blockWidth - 42) / 22, 0, 1),
    ballSideCompression: clamp((ballSidePlayers - farSidePlayers + 1) / Math.max(opponents.length * 0.55, 1), 0, 1),
    lineGap: clamp((lineGap - 7) / 8, 0, 1),
    rawLineGapMeters: lineGap,
    highLine: clamp((64 - lineDepths.back) / 16, 0, 1),
    deepBlock: clamp((lineDepths.back - 76) / 16, 0, 1),
    nearBallPressure: clamp(nearBallOpponents / 4, 0, 1),
    ballSide,
    blockWidth,
    lineDepths,
  };
}

function getAutoPilotOpponentBlockReadAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return {
      score: 0,
      labels: [],
      block: null,
    };
  }

  const teamId = carrier.team;
  const block = getOpponentBlockReadProfile(teamId, startPoint);
  const targetThreat = getPitchThreatProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const targetLane = getPitchLaneKey(candidate.target);
  const startLane = getPitchLaneKey(startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(startLane));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const targetIsWide = targetLane === "leftWide" || targetLane === "rightWide";
  const targetIsCentral =
    targetLane === "central" ||
    targetLane === "leftHalf" ||
    targetLane === "rightHalf";
  const highValueException =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    targetThreat.value >= 0.64 ||
    targetThreat.box >= 0.3;
  const labels = [];
  let score = 0;

  if (
    block.ballSideCompression >= 0.5 &&
    candidate.actionType === "pass" &&
    (candidate.isSwitch || laneShift >= 2) &&
    passDistance >= 16
  ) {
    score += 0.24 + block.ballSideCompression * 0.28 + profile.switchBias * 0.18;
    labels.push("Exploit weak side");
  }

  if (block.compactCenter >= 0.58) {
    if (targetIsWide && forwardGain >= -2) {
      score += 0.16 + block.compactCenter * 0.18 + profile.widthDiscipline * 0.12;
      labels.push("Stretch compact block");
    } else if (
      !highValueException &&
      targetIsCentral &&
      actionSpace.lineBreakCount === 0 &&
      actionSpace.openTarget < 0.46 &&
      forwardGain < 5
    ) {
      score -= 0.24 + block.compactCenter * 0.22;
    }
  }

  if (
    block.stretchedWidth >= 0.42 &&
    targetIsCentral &&
    forwardGain >= 3 &&
    (targetThreat.betweenLines >= 0.3 || actionSpace.lineBreakCount >= 1 || targetThreat.centralPocket >= 0.28)
  ) {
    score += 0.18 + block.stretchedWidth * 0.24 + profile.lineBreakBias * 0.16;
    labels.push("Play through stretched block");
  }

  if (
    block.lineGap >= 0.42 &&
    candidate.actionType === "pass" &&
    forwardGain >= 3 &&
    (targetThreat.betweenLines >= 0.34 || actionSpace.targetGameSpaceKey === "space2")
  ) {
    score += 0.22 + block.lineGap * 0.28 + profile.shortSupport * 0.12;
    labels.push("Find gap between lines");
  }

  if (block.highLine >= 0.38) {
    const attacksDepth =
      actionSpace.targetGameSpaceKey === "space3" ||
      targetThreat.behindLine >= 0.3 ||
      candidate.isLineBreak ||
      pattern.family === "front-line";

    if ((candidate.actionType === "pass" || candidate.actionType === "dribble") && attacksDepth && forwardGain >= 6) {
      score += 0.22 + block.highLine * 0.32 + profile.directness * 0.16;
      labels.push("Attack high line");
    }
  }

  if (block.deepBlock >= 0.38) {
    if (
      candidate.actionType === "shot" ||
      candidate.label === "cutback" ||
      candidate.label === "cross" ||
      candidate.isBoxPass ||
      targetThreat.cutbackZone >= 0.32
    ) {
      score += 0.18 + block.deepBlock * 0.22 + profile.deliveryBias * 0.12;
      labels.push("Break down deep block");
    } else if (
      !highValueException &&
      candidate.actionType === "pass" &&
      passDistance >= 28 &&
      forwardGain >= 8 &&
      actionSpace.targetGameSpaceKey === "space3"
    ) {
      score -= 0.22 + block.deepBlock * 0.18;
    }
  }

  if (block.nearBallPressure >= 0.5) {
    if (
      candidate.actionType === "pass" &&
      (candidate.isSwitch || pattern.family === "support-link" || pattern.family === "line-break") &&
      (candidate.laneClarity ?? 0.5) >= 0.42
    ) {
      score += 0.12 + block.nearBallPressure * 0.18;
      labels.push("Play away from pressure");
    }

    if (
      !highValueException &&
      candidate.actionType === "dribble" &&
      actionSpace.openTarget < 0.46 &&
      forwardGain < 7
    ) {
      score -= 0.2 + block.nearBallPressure * 0.22;
    }
  }

  return {
    score: clamp(score, -0.88, 1),
    labels: uniquePrincipleLabels(labels),
    block,
  };
}

function isLastStepKickoffResetForTeam(teamId) {
  const lastStep = state.sequence?.steps?.[state.sequence.steps.length - 1];
  return (
    lastStep?.restartPhase?.type === "kickoff" &&
    getRecordedStepPossessionTeamId(lastStep) === teamId
  );
}

function getRecentLaneRepeatCount(teamId, laneKey, thirdKey = null, limit = 4) {
  return getRecentPossessionSteps(teamId, limit).reduce((count, step) => {
    const target = step.target;
    if (!target || getPitchLaneKey(target) !== laneKey) {
      return count;
    }

    if (thirdKey && getAttackingThirdKey(target, teamId) !== thirdKey) {
      return count;
    }

    return count + 1;
  }, 0);
}

function isFrontLineRole(roleKey) {
  return roleKey === "striker" || roleKey === "secondStriker" || roleKey === "wideForward";
}

function isSupportRole(roleKey) {
  return roleKey === "pivot" || roleKey === "connector" || roleKey === "wideBack";
}

function getStepReceiverRoleKey(step, teamId) {
  const receiver = getPlayerById(step?.receiverPlayerId);
  if (!receiver || receiver.team !== teamId) {
    return null;
  }

  return getOffensiveRoleKey(receiver, teams[teamId]?.formation);
}

function getAutoPilotFlowContext(carrier, startPoint) {
  const teamId = carrier.team;
  const recent = getRecentPossessionSteps(teamId, 6);
  const lastStep = recent[0] ?? null;
  const carrierRoleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  let consecutivePasses = 0;
  let recentFrontLineTargets = 0;
  let recentSupportTargets = 0;
  let recentWideTargets = 0;
  const receiverRoleCounts = new Map();

  recent.forEach((step, index) => {
    if (index === consecutivePasses && step.actionType === "pass") {
      consecutivePasses += 1;
    }

    const receiverRoleKey = getStepReceiverRoleKey(step, teamId);
    if (receiverRoleKey) {
      receiverRoleCounts.set(receiverRoleKey, (receiverRoleCounts.get(receiverRoleKey) ?? 0) + 1);
      if (isFrontLineRole(receiverRoleKey)) {
        recentFrontLineTargets += 1;
      }

      if (isSupportRole(receiverRoleKey)) {
        recentSupportTargets += 1;
      }
    }

    if (step.target) {
      const laneKey = getPitchLaneKey(step.target);
      if (laneKey === "leftWide" || laneKey === "rightWide") {
        recentWideTargets += 1;
      }
    }
  });

  const carrierJustReceived =
    lastStep?.actionType === "pass" &&
    lastStep.receiverPlayerId === carrier.id &&
    getRecordedStepDuration(lastStep) <= 3.2;
  const lastCarrierId = lastStep?.beforeSnapshot?.ball?.ownerPlayerId ?? lastStep?.carrierPlayerId ?? null;
  const lastReceiverId = lastStep?.receiverPlayerId ?? null;

  return {
    recent,
    lastStep,
    carrierRoleKey,
    carrierJustReceived,
    consecutivePasses,
    recentFrontLineTargets,
    recentSupportTargets,
    recentWideTargets,
    receiverRoleCounts,
    lastCarrierId,
    lastReceiverId,
    pressure: getPlayerPressureLoad(carrier, startPoint),
  };
}

function getLastAutoPrincipleSet(teamId) {
  const lastStep = getRecentPossessionSteps(teamId, 4)[0] ?? null;
  const labels = [
    ...(lastStep?.autoPrinciples ?? []),
    lastStep?.offensiveAutopilot?.principleLabel,
    lastStep?.offensiveAutopilot?.principleKey,
  ].filter(Boolean);

  return new Set(labels);
}

function principleSetIncludes(principles, text) {
  return [...principles].some((label) => `${label}`.toLowerCase().includes(text.toLowerCase()));
}

function isTransitionAttackStyle(styleKey) {
  return [
    "direct-transition",
    "counter-attack",
    "fluid-counter-attack",
    "gegenpress",
    "vertical-play",
    "vertical-tiki-taka",
  ].includes(styleKey);
}

function getSecurePossessionSnapshotForTeam(teamId, actionMeta = null) {
  const secure = state.ball.securePossession ?? actionMeta?.beforeSnapshot?.ball?.securePossession ?? null;
  if (!secure?.ownerPlayerId) {
    return null;
  }

  const owner = getPlayerById(secure.ownerPlayerId);
  return owner?.team === teamId ? secure : null;
}

function getAutoPilotRegainContext(carrier, startPoint = carrier?.position, profile = {}) {
  if (!carrier) {
    return { active: false };
  }

  const secure = getSecurePossessionSnapshotForTeam(carrier.team);
  if (!secure || secure.ownerPlayerId !== carrier.id) {
    return { active: false };
  }

  const origin = secure.point ?? startPoint ?? carrier.position;
  const movedFromRegain = distance(startPoint ?? carrier.position, origin);
  const elapsed = Math.max(0, state.time - (secure.createdAt ?? state.time));
  const minDistance = secure.minDistanceToExpire ?? 6;
  const minTime = secure.minTimeToExpire ?? 1.35;
  const freshness = clamp(
    1 - Math.max(movedFromRegain / Math.max(minDistance * 1.25, 0.01), elapsed / Math.max(minTime * 1.25, 0.01)),
    0,
    1
  );

  if (freshness <= 0.02) {
    return { active: false };
  }

  const pressure = getPlayerPressureLoad(carrier, startPoint ?? carrier.position);
  const forwardProbe = clampToPitch({
    x: (startPoint?.x ?? carrier.position.x) + getAttackDirectionSign(carrier.team) * 18,
    y: lerp(startPoint?.y ?? carrier.position.y, pitch.width / 2, 0.28),
  }, 2.5);
  const forwardOpenSpace = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, forwardProbe));
  const localSupport = getTeamSupportCountAroundPoint(carrier.team, startPoint ?? carrier.position, new Set([carrier.id]), 13);
  const directStyle = isTransitionAttackStyle(profile.styleKey);
  const counterIntent = clamp(
    (profile.directness ?? 0.5) * 0.42 +
      (profile.progressionUrgency ?? 0.5) * 0.32 +
      (profile.tempo ?? 0.5) * 0.14 +
      (directStyle ? 0.22 : 0) +
      (secure.reason === "interception" ? 0.1 : 0),
    0,
    1.25
  );
  const secureIntent = clamp(
    (profile.shortSupport ?? 0.5) * 0.38 +
      (profile.recycleWindow ?? 0.4) * 0.22 +
      pressure * 0.34 +
      (localSupport >= 2 ? 0.14 : 0) +
      (directStyle ? -0.08 : 0.18),
    0,
    1.2
  );

  return {
    active: true,
    reason: secure.reason ?? "regain",
    origin: cloneVector(origin),
    movedFromRegain,
    elapsed,
    freshness,
    pressure,
    forwardOpenSpace,
    localSupport,
    directStyle,
    counterIntent,
    secureIntent,
  };
}

function getAutoPilotCandidatePattern(candidate, carrier, startPoint) {
  if (!candidate || !carrier || !candidate.target) {
    return {
      family: "unknown",
      laneKey: "central",
      thirdKey: "build",
      receiverRoleKey: null,
      targetSpaceLabel: "open space",
      forwardGain: 0,
      passDistance: 0,
    };
  }

  const targetLaneKey = getPitchLaneKey(candidate.target);
  const targetThirdKey = getAttackingThirdKey(candidate.target, carrier.team);
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const targetSpace = getPitchThreatProfile(candidate.target, carrier.team);
  let family = "connect";

  if (candidate.actionType === "shot") {
    family = "shot";
  } else if (candidate.actionType === "dribble") {
    family = forwardGain >= 6 ? "carry-forward" : "carry-control";
  } else if (candidate.actionType === "pass") {
    if (candidate.label === "cutback") {
      family = "cutback";
    } else if (candidate.label === "cross") {
      family = "cross";
    } else if (candidate.isSwitch) {
      family = "switch";
    } else if (candidate.principleKey?.includes("wide") || candidate.label === "wide entry") {
      family = "wide-overload";
    } else if (candidate.isLineBreak || forwardGain >= 8) {
      family = "line-break";
    } else if (forwardGain <= -4.5) {
      family = "recycle";
    } else if (passDistance <= 17 && isSupportRole(receiverRoleKey)) {
      family = "support-link";
    } else if (isFrontLineRole(receiverRoleKey)) {
      family = "front-line";
    }
  }

  return {
    family,
    laneKey: targetLaneKey,
    thirdKey: targetThirdKey,
    receiverRoleKey,
    targetSpaceLabel: targetSpace.primaryLabel,
    forwardGain,
    passDistance,
  };
}

function getRecordedStepPattern(step, teamId) {
  if (!step?.target || !teamId) {
    return null;
  }

  const startPoint = step.beforeSnapshot?.ball?.position ?? null;
  const target = step.target;
  const targetLaneKey = getPitchLaneKey(target);
  const targetThirdKey = getAttackingThirdKey(target, teamId);
  const forwardGain =
    startPoint && target
      ? (target.x - startPoint.x) * getAttackDirectionSign(teamId)
      : 0;
  const lateralMeters = startPoint && target ? Math.abs(target.y - startPoint.y) : 0;
  const passDistance = startPoint && target ? distance(startPoint, target) : 0;
  const receiverRoleKey = getStepReceiverRoleKey(step, teamId);
  const targetSpace = getPitchThreatProfile(target, teamId);
  const principleText = [
    ...(step.autoPrinciples ?? []),
    step.offensiveAutopilot?.principleKey,
    step.offensiveAutopilot?.principleLabel,
    step.profileLabel,
  ].filter(Boolean).join(" ").toLowerCase();
  let family = "connect";

  if (step.actionType === "shot") {
    family = "shot";
  } else if (step.actionType === "dribble") {
    family = forwardGain >= 6 ? "carry-forward" : "carry-control";
  } else if (step.actionType === "pass") {
    if (principleText.includes("cutback") || step.profileLabel?.toLowerCase?.().includes("cutback")) {
      family = "cutback";
    } else if (principleText.includes("cross")) {
      family = "cross";
    } else if (principleText.includes("change corridor") || (lateralMeters >= 19 && passDistance >= 22)) {
      family = "switch";
    } else if (principleText.includes("wide") || principleText.includes("overlap")) {
      family = "wide-overload";
    } else if (principleText.includes("line break") || forwardGain >= 8) {
      family = "line-break";
    } else if (forwardGain <= -4.5) {
      family = "recycle";
    } else if (passDistance <= 17 && isSupportRole(receiverRoleKey)) {
      family = "support-link";
    } else if (isFrontLineRole(receiverRoleKey)) {
      family = "front-line";
    }
  }

  return {
    family,
    laneKey: targetLaneKey,
    thirdKey: targetThirdKey,
    receiverRoleKey,
    targetSpaceLabel: targetSpace.primaryLabel,
    forwardGain,
    passDistance,
  };
}

function getRecordedStepActorIds(step) {
  return {
    carrierId:
      step?.beforeSnapshot?.ball?.ownerPlayerId ??
      step?.carrierPlayerId ??
      step?.initiatorPlayerId ??
      null,
    receiverId:
      step?.receiverPlayerId ??
      step?.afterSnapshot?.ball?.ownerPlayerId ??
      null,
  };
}

function getAutoPilotPossessionLoopAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const recent = getRecentPossessionSteps(teamId, 8);
  if (!recent.length) {
    return { score: 0, labels: [], context: null };
  }

  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const rhythm = getPossessionRhythmContext(teamId, 8);
  const lastStep = recent[0] ?? null;
  const lastActors = getRecordedStepActorIds(lastStep);
  const candidateReceiverId = candidate.receiverPlayerId ?? null;
  const targetThreat = getPitchThreatProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const laneShiftFromLast = lastStep?.target
    ? Math.abs(getPitchLaneIndex(pattern.laneKey) - getPitchLaneIndex(getPitchLaneKey(lastStep.target)))
    : 0;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const sameLaneThirdCount = recent
    .map((step) => getRecordedStepPattern(step, teamId))
    .filter(Boolean)
    .filter((entry) => entry.laneKey === pattern.laneKey && entry.thirdKey === pattern.thirdKey)
    .length;
  const sameTargetClusterCount = recent
    .filter((step) => step.target && distance(step.target, candidate.target) <= 8.5)
    .length;
  const sameReceiverCount = candidateReceiverId
    ? recent.filter((step) => (getRecordedStepActorIds(step).receiverId ?? null) === candidateReceiverId).length
    : 0;
  const samePairCount = candidateReceiverId
    ? recent.filter((step) => {
        const actors = getRecordedStepActorIds(step);
        return actors.carrierId === carrier.id && actors.receiverId === candidateReceiverId;
      }).length
    : 0;
  const directReturn =
    candidate.actionType === "pass" &&
    candidateReceiverId &&
    lastActors.carrierId === candidateReceiverId &&
    lastActors.receiverId === carrier.id;
  const thirdPlayerRelease =
    candidate.actionType === "pass" &&
    candidateReceiverId &&
    candidateReceiverId !== lastActors.carrierId &&
    candidateReceiverId !== lastActors.receiverId &&
    pattern.forwardGain >= 2.5;
  const highValueException =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.value >= 0.66 ||
    actionSpace.lineBreakCount >= 2;
  const staleLowValue =
    !highValueException &&
    pattern.forwardGain < 4 &&
    !candidate.isSwitch &&
    actionSpace.value < 0.42;
  const labels = [];
  let score = 0;

  if (directReturn && staleLowValue && pressure < 0.62) {
    score -= 0.92 + profile.progressionUrgency * 0.34;
    labels.push("Avoid two-player loop");
  } else if (directReturn && pattern.forwardGain >= 5 && (candidate.isLineBreak || actionSpace.lineBreakCount >= 1)) {
    score += 0.18;
    labels.push("Bounce forward");
  }

  if (samePairCount >= 1 && staleLowValue && pressure < 0.66) {
    score -= 0.42 + Math.min(samePairCount, 3) * 0.22;
    labels.push("Find third player");
  }

  if (sameReceiverCount >= 2 && staleLowValue) {
    score -= 0.26 + Math.min(sameReceiverCount - 1, 3) * 0.16;
  }

  if (sameTargetClusterCount >= 2 && staleLowValue) {
    score -= 0.36 + Math.min(sameTargetClusterCount, 4) * 0.18;
    labels.push("Leave repeated zone");
  }

  if (sameLaneThirdCount >= 3 && staleLowValue) {
    score -= 0.34 + Math.min(sameLaneThirdCount - 2, 3) * 0.18;
    labels.push("Change corridor");
  }

  if (
    rhythm.steps >= 3 &&
    rhythm.forwardPasses === 0 &&
    rhythm.lineBreaks === 0 &&
    pattern.forwardGain < 3 &&
    !candidate.isSwitch &&
    candidate.actionType !== "shot"
  ) {
    score -= 0.48 + profile.progressionUrgency * 0.42;
    labels.push("Break sterile circulation");
  }

  if (
    rhythm.steps >= 2 &&
    (candidate.isLineBreak || actionSpace.lineBreakCount >= 1 || pattern.forwardGain >= 7) &&
    (sameLaneThirdCount >= 2 || rhythm.backPasses >= 1 || rhythm.sidewaysPasses >= 2)
  ) {
    score += 0.26 + profile.progressionUrgency * 0.22;
    labels.push("Play out of the loop");
  }

  if (
    thirdPlayerRelease &&
    (samePairCount >= 1 || directReturn || sameLaneThirdCount >= 2 || rhythm.sidewaysPasses >= 2) &&
    actionSpace.targetPressure <= 0.74
  ) {
    score += 0.22 + profile.shortSupport * 0.12 + profile.tempo * 0.1;
    labels.push("Third-player release");
  }

  if (
    candidate.actionType === "dribble" &&
    pattern.forwardGain >= 4.5 &&
    (rhythm.sidewaysPasses >= 2 || sameLaneThirdCount >= 2) &&
    pressure <= 0.68
  ) {
    score += 0.24 + profile.carryBias * 0.22;
    labels.push("Carry out of pressure");
  }

  if (
    candidate.isSwitch &&
    laneShiftFromLast >= 2 &&
    (sameLaneThirdCount >= 2 || rhythm.sidewaysPasses >= 1) &&
    (candidate.laneClarity ?? 0.5) >= 0.42
  ) {
    score += 0.24 + profile.switchBias * 0.22;
    labels.push("Escape to weak side");
  }

  return {
    score: clamp(score, -1.75, 0.88),
    labels: uniquePrincipleLabels(labels),
    context: {
      sameLaneThirdCount,
      sameTargetClusterCount,
      sameReceiverCount,
      samePairCount,
      directReturn,
      thirdPlayerRelease,
      pattern,
    },
  };
}

function getAutoPilotCorridorTempoReleaseAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const recent = getRecentPossessionSteps(teamId, 7);
  if (recent.length < 2) {
    return { score: 0, labels: [], context: null };
  }

  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const recentPatterns = recent
    .map((step) => getRecordedStepPattern(step, teamId))
    .filter(Boolean);
  const rhythm = getPossessionRhythmContext(teamId, 8);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const targetThreat = getPitchThreatProfile(candidate.target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const startGameSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const targetGameSpace = getAttackingGameSpaceProfile(candidate.target, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const startLaneIndex = getPitchLaneIndex(startPoint);
  const targetLaneIndex = getPitchLaneIndex(pattern.laneKey);
  const laneShiftFromStart = Math.abs(targetLaneIndex - startLaneIndex);
  const lastPattern = recentPatterns[0] ?? null;
  const laneShiftFromLast = lastPattern
    ? Math.abs(targetLaneIndex - getPitchLaneIndex(lastPattern.laneKey))
    : laneShiftFromStart;
  const currentThirdKey = getAttackingThirdKey(startPoint, teamId);
  const sameCorridorRecent = recentPatterns
    .slice(0, 4)
    .filter((entry) => entry.laneKey === getPitchLaneKey(startPoint) && entry.thirdKey === currentThirdKey)
    .length;
  const consecutiveSameCorridor = (() => {
    let count = 0;
    for (const entry of recentPatterns) {
      if (entry.laneKey === getPitchLaneKey(startPoint) && entry.thirdKey === currentThirdKey) {
        count += 1;
      } else {
        break;
      }
    }
    return count;
  })();
  const recentThreatGain = recent
    .slice(0, 4)
    .reduce((total, step) => {
      const from = step.beforeSnapshot?.ball?.position ?? null;
      const to = step.target ?? step.afterSnapshot?.ball?.position ?? null;
      return from && to ? total + Math.max(0, getActionThreatGain(from, to, teamId)) : total;
    }, 0);
  const corridorLoad = clamp(
    sameCorridorRecent * 0.22 +
      consecutiveSameCorridor * 0.28 +
      rhythm.sidewaysPasses * 0.14 +
      rhythm.backPasses * 0.18 +
      (rhythm.lineBreaks === 0 ? 0.22 : -0.16) +
      (recentThreatGain <= 0.12 ? 0.18 : -0.12),
    0,
    1.45
  );
  const finalThirdStart = getAttackingDepth(startPoint, teamId) >= 66 || startThreat.value >= 0.52;
  const wideStart = isWideChannel(startPoint);
  const highValueAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.value >= startThreat.value + 0.09 ||
    actionSpace.lineBreakCount >= 1 ||
    targetGameSpace.index > startGameSpace.index;
  const switchRelease =
    candidate.actionType === "pass" &&
    (candidate.isSwitch || laneShiftFromStart >= 2 || laneShiftFromLast >= 2) &&
    (candidate.laneClarity ?? 0.55) >= 0.42 &&
    actionSpace.targetPressure <= 0.76;
  const diagonalRelease =
    candidate.actionType === "pass" &&
    laneShiftFromStart >= 1 &&
    pattern.forwardGain >= 4.5 &&
    actionSpace.targetPressure <= 0.7 &&
    (targetGameSpace.index >= startGameSpace.index || targetThreat.value >= startThreat.value + 0.05);
  const carryRelease =
    candidate.actionType === "dribble" &&
    pattern.forwardGain >= 4.5 &&
    actionSpace.openTarget >= 0.45 &&
    pressure <= 0.68;
  const endProductRelease =
    finalThirdStart &&
    (
      candidate.actionType === "shot" ||
      candidate.label === "cutback" ||
      candidate.label === "cross" ||
      targetThreat.cutbackZone >= 0.32 ||
      targetThreat.box >= 0.28
    );
  const sterileSameCorridor =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    laneShiftFromStart <= 1 &&
    pattern.forwardGain < 3.5 &&
    actionSpace.lineBreakCount === 0 &&
    targetThreat.value <= startThreat.value + 0.04;
  const hopefulRelease =
    switchRelease &&
    (candidate.laneClarity ?? 0.55) < 0.52 &&
    actionSpace.targetPressure >= 0.62 &&
    !highValueAction;
  const stylePrefersCirculation =
    profile.styleKey === "control-possession" ||
    profile.styleKey === "tiki-taka" ||
    profile.styleKey === "fluid-combinations";
  const stylePrefersWidth =
    profile.styleKey === "wing-play" ||
    profile.styleKey === "overlap-wide" ||
    profile.crossBias >= 0.64;
  const labels = [];
  let score = 0;

  if (corridorLoad >= 0.58) {
    if (diagonalRelease) {
      score += 0.28 + profile.lineBreakBias * 0.16 + (stylePrefersCirculation ? 0.1 : 0);
      labels.push("Corridor: diagonal release");
    }

    if (switchRelease) {
      score += 0.22 + profile.switchBias * 0.2 + (stylePrefersWidth ? 0.08 : 0);
      labels.push("Corridor: change point of attack");
    }

    if (carryRelease) {
      score += 0.22 + profile.carryBias * 0.18;
      labels.push("Corridor: carry out of lane");
    }

    if (endProductRelease) {
      score += 0.3 + profile.shootBias * 0.16 + profile.deliveryBias * 0.12;
      labels.push("Corridor: create end product");
    }

    if (sterileSameCorridor && pressure <= 0.62) {
      score -= 0.36 + corridorLoad * 0.42 + profile.progressionUrgency * 0.2;
      labels.push("Corridor: stop same-lane circulation");
    }
  }

  if (
    wideStart &&
    stylePrefersWidth &&
    sameCorridorRecent >= 2 &&
    !endProductRelease &&
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    targetThreat.assistZone < 0.28 &&
    targetThreat.cutbackZone < 0.28
  ) {
    score -= 0.2 + profile.crossBias * 0.12;
    labels.push("Corridor: finish wide overload");
  }

  if (hopefulRelease) {
    score -= 0.18 + (1 - (candidate.laneClarity ?? 0.55)) * 0.22;
  }

  if (corridorLoad < 0.46 && sterileSameCorridor && rhythm.steps <= 1 && stylePrefersCirculation) {
    score += 0.08;
  }

  return {
    score: clamp(score, -1.25, 1.05),
    labels: uniquePrincipleLabels(labels),
    context: {
      corridorLoad,
      sameCorridorRecent,
      consecutiveSameCorridor,
      recentThreatGain,
      laneShiftFromStart,
      laneShiftFromLast,
      startGameSpaceKey: startGameSpace.key,
      targetGameSpaceKey: targetGameSpace.key,
      switchRelease,
      diagonalRelease,
      carryRelease,
      endProductRelease,
      sterileSameCorridor,
    },
  };
}

function getAutoPilotCombinationChainContext(carrier, startPoint, profile = {}) {
  if (!carrier?.team || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const recent = getRecentPossessionSteps(teamId, 6);
  const lastStep = recent[0] ?? null;
  if (!lastStep || lastStep.actionType !== "pass") {
    return {
      active: false,
      recent,
    };
  }

  const actors = getRecordedStepActorIds(lastStep);
  const carrierReceived =
    actors.receiverId === carrier.id ||
    lastStep.afterSnapshot?.ball?.ownerPlayerId === carrier.id;
  const duration = getRecordedStepDuration(lastStep);
  if (!carrierReceived || duration > 3.4) {
    return {
      active: false,
      recent,
      carrierReceived,
      duration,
    };
  }

  const incomingStart =
    lastStep.beforeSnapshot?.ball?.position ??
    lastStep.beforeSnapshot?.ball?.startPosition ??
    null;
  const incomingTarget = lastStep.target ?? startPoint;
  const incomingLane = incomingStart ? getPitchLaneKey(incomingStart) : getPitchLaneKey(incomingTarget);
  const currentLane = getPitchLaneKey(startPoint);
  const incomingForwardGain =
    incomingStart && incomingTarget
      ? (incomingTarget.x - incomingStart.x) * getAttackDirectionSign(teamId)
      : 0;
  const incomingLaneShift =
    incomingLane && currentLane
      ? Math.abs(getPitchLaneIndex(currentLane) - getPitchLaneIndex(incomingLane))
      : 0;
  let consecutivePasses = 0;

  for (const step of recent) {
    if (step.actionType !== "pass") {
      break;
    }
    consecutivePasses += 1;
  }

  return {
    active: true,
    teamId,
    recent,
    lastStep,
    lastCarrierId: actors.carrierId,
    lastReceiverId: actors.receiverId,
    duration,
    incomingStart,
    incomingTarget,
    incomingLane,
    currentLane,
    incomingForwardGain,
    incomingLaneShift,
    consecutivePasses,
    pressure: getPlayerPressureLoad(carrier, startPoint),
    nearestGap: getNearestOpponentGap(carrier, startPoint),
    startThreat: getPitchThreatProfile(startPoint, teamId),
    startSpace: getAttackingGameSpaceProfile(startPoint, teamId),
    carrierRoleKey: getOffensiveRoleKey(carrier, teams[teamId]?.formation),
    tempoFit: clamp((profile.tempo ?? 0.5) * 0.58 + (profile.shortSupport ?? 0.5) * 0.42, 0, 1),
  };
}

function getAutoPilotCombinationChainAdjustment(candidate, carrier, startPoint, profile = {}) {
  const context = getAutoPilotCombinationChainContext(carrier, startPoint, profile);
  if (!context.active || !candidate?.target) {
    return {
      score: 0,
      labels: [],
      context,
    };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetLane = getPitchLaneKey(target);
  const laneShiftFromCurrent = Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(context.currentLane));
  const laneShiftFromIncoming = context.incomingLane
    ? Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(context.incomingLane))
    : laneShiftFromCurrent;
  const candidateReceiver = getAutoPilotCandidateReceiver(candidate, carrier);
  const candidateReceiverId =
    candidate.receiverPlayerId ??
    candidate.principleRunnerPlayerId ??
    candidateReceiver?.id ??
    null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (candidateReceiver ? getOffensiveRoleKey(candidateReceiver, teams[teamId]?.formation) : null);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const directReturn =
    candidate.actionType === "pass" &&
    candidateReceiverId &&
    candidateReceiverId === context.lastCarrierId;
  const thirdPlayerRelease =
    candidate.actionType === "pass" &&
    candidateReceiverId &&
    candidateReceiverId !== context.lastCarrierId &&
    candidateReceiverId !== context.lastReceiverId &&
    (
      forwardGain >= 2.5 ||
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.38 ||
      laneShiftFromIncoming >= 1
    );
  const wallPassWithPurpose =
    directReturn &&
    (
      context.pressure >= 0.58 ||
      forwardGain >= 5 ||
      candidate.isLineBreak ||
      actionSpace.lineBreakCount >= 1 ||
      targetThreat.value >= context.startThreat.value + 0.08
    );
  const deadBounce =
    directReturn &&
    !wallPassWithPurpose &&
    context.pressure < 0.58 &&
    targetThreat.value <= context.startThreat.value + 0.04 &&
    !candidate.isSwitch;
  const aroundCorner =
    thirdPlayerRelease &&
    passDistance <= 22 &&
    laneShiftFromCurrent >= 1 &&
    (receiverRoleKey === "connector" || receiverRoleKey === "pivot" || receiverRoleKey === "wideBack");
  const receiveAndDrive =
    candidate.actionType === "dribble" &&
    forwardGain >= 4.2 &&
    context.pressure <= 0.68 &&
    (
      actionSpace.openTarget >= 0.42 ||
      context.startSpace.key === "space2" ||
      context.startThreat.betweenLines >= 0.3 ||
      context.startThreat.halfSpace >= 0.3
    );
  const lowValueSafety =
    candidate.actionType === "pass" &&
    forwardGain <= -4.5 &&
    context.pressure <= 0.48 &&
    targetThreat.value <= context.startThreat.value + 0.035 &&
    actionSpace.lineBreakCount === 0;
  const labels = [];
  let score = 0;

  if (thirdPlayerRelease) {
    score +=
      0.24 +
      context.tempoFit * 0.24 +
      (profile.lineBreakBias ?? 0.5) * 0.12 +
      Math.max(0, targetThreat.value - context.startThreat.value) * 0.3 +
      (actionSpace.lineBreakCount >= 1 ? 0.16 : 0);
    labels.push("Third-man chain");
  }

  if (aroundCorner) {
    score += 0.16 + (profile.shortSupport ?? 0.5) * 0.12;
    labels.push("Play around the corner");
  }

  if (wallPassWithPurpose) {
    score += 0.14 + context.pressure * 0.12 + (candidate.isLineBreak ? 0.12 : 0);
    labels.push("Wall pass with purpose");
  }

  if (receiveAndDrive) {
    score +=
      0.22 +
      (profile.carryBias ?? 0.5) * 0.18 +
      actionSpace.openTarget * 0.16 +
      (context.consecutivePasses >= 2 ? 0.12 : 0);
    labels.push("Receive and drive");
  }

  if (deadBounce) {
    score -= 0.78 + Math.max(0, 0.62 - context.pressure) * 0.28;
    labels.push("Avoid dead bounce");
  }

  if (lowValueSafety && !deadBounce) {
    score -= 0.28 + (profile.progressionUrgency ?? 0.5) * 0.2;
  }

  if (
    context.consecutivePasses >= 2 &&
    candidate.actionType === "pass" &&
    !thirdPlayerRelease &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    forwardGain < 3 &&
    context.pressure < 0.56
  ) {
    score -= 0.18 + Math.min(context.consecutivePasses, 4) * 0.08;
  }

  return {
    score: clamp(score, -1.35, 1.05),
    labels: uniquePrincipleLabels(labels),
    context: {
      directReturn,
      thirdPlayerRelease,
      wallPassWithPurpose,
      receiveAndDrive,
      laneShiftFromIncoming,
      incomingForwardGain: context.incomingForwardGain,
      consecutivePasses: context.consecutivePasses,
    },
  };
}

function getAutoPilotPassLaneDenialAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!carrier || candidate?.actionType !== "pass" || !candidate.target) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const risk = getPassLaneRiskProfile(carrier, candidate.target, {
    receiverPlayerId: candidate.receiverPlayerId ?? null,
  });
  const targetThreat = getPitchThreatProfile(candidate.target, carrier.team);
  const laneDanger = clamp(
    Math.max(0, 0.58 - risk.clarity) * 0.7 +
      Math.max(0, risk.timingRisk - 0.48) * 0.46 +
      Math.max(0, risk.coverShadow - 0.9) * 0.14 +
      Math.min(risk.interceptors, 3) * 0.09,
    0,
    1.25
  );
  const valueTolerance = clamp(
    (profile.risk ?? 0.5) * 0.22 +
      targetThreat.value * 0.18 +
      (candidate.isLineBreak ? 0.16 : 0) +
      (candidate.isBoxPass ? 0.16 : 0) +
      (candidate.isSwitch ? 0.12 : 0),
    0.08,
    0.58
  );
  const avoidRisk = Math.max(0, laneDanger - valueTolerance);
  const score =
    avoidRisk > 0
      ? -clamp(avoidRisk * (0.58 + (profile.directness ?? 0.5) * 0.12), 0, 0.72)
      : risk.clarity >= 0.74 && candidate.forwardGain >= 3
        ? 0.04
        : 0;
  const labels = [];

  if (score < -0.08) {
    labels.push("Respect cover shadow");
  }

  if (risk.interceptors >= 1 && risk.clarity <= 0.5) {
    labels.push("Avoid covered lane");
  }

  return {
    score,
    labels: uniquePrincipleLabels(labels),
    context: {
      clarity: risk.clarity,
      timingRisk: risk.timingRisk,
      coverShadow: risk.coverShadow,
      interceptors: risk.interceptors,
      laneDanger,
      valueTolerance,
    },
  };
}

function getAutoPilotCounterPressEscapeAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!carrier || !candidate?.target) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  if (!regain.active || regain.freshness < 0.08) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const lossPoint = regain.origin ?? startPoint;
  const startLossDistance = distance(startPoint, lossPoint);
  const targetLossDistance = distance(target, lossPoint);
  const escapeGain = targetLossDistance - startLossDistance;
  const targetRadius = candidate.actionType === "dribble" ? 8.5 : passDistance >= 22 ? 13.5 : 10.5;
  const startPressure = regain.pressure;
  const targetPressure = candidate.receiverPressure ?? getOpponentPressureAtPoint(teamId, target, targetRadius + 2);
  const startOpponentDensity = getOpponentDensityAtPoint(teamId, startPoint, 7.5);
  const targetOpponentDensity = getOpponentDensityAtPoint(teamId, target, targetRadius);
  const targetSupport = getTeamDensityAtPoint(
    teamId,
    target,
    targetRadius,
    new Set([carrier.id, candidate.receiverPlayerId].filter(Boolean))
  );
  const laneClarity =
    candidate.actionType === "pass"
      ? candidate.laneClarity ?? computePassLaneClarity(carrier, target, {
          receiverPlayerId: candidate.receiverPlayerId ?? null,
        })
      : getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const trapLoad = clamp(
    startPressure * 0.44 +
      Math.min(startOpponentDensity, 4) * 0.13 +
      regain.freshness * 0.26 +
      (regain.reason === "tackle" ? 0.08 : 0),
    0,
    1.25
  );
  const escapesCrowd =
    escapeGain >= 2.8 ||
    targetPressure <= startPressure - 0.16 ||
    targetOpponentDensity <= Math.max(0, startOpponentDensity - 1);
  const safeOutlet =
    candidate.actionType === "pass" &&
    passDistance >= 7 &&
    passDistance <= 24 &&
    laneClarity >= 0.54 &&
    targetPressure <= 0.62 &&
    targetSupport >= 1;
  const transitionRelease =
    candidate.actionType === "pass" &&
    forwardGain >= 7 &&
    laneClarity >= 0.5 &&
    targetPressure <= 0.68 &&
    (profile.directness >= 0.58 || regain.counterIntent >= 0.58);
  const escapeCarry =
    candidate.actionType === "dribble" &&
    forwardGain >= 3 &&
    laneClarity >= 0.5 &&
    (escapesCrowd || targetPressure <= 0.52);
  const crowdedReturn =
    candidate.actionType === "pass" &&
    passDistance <= 11.5 &&
    escapeGain < 1.2 &&
    targetOpponentDensity >= Math.max(2, startOpponentDensity) &&
    targetPressure >= 0.5;
  const backwardsIntoTrap =
    candidate.actionType === "pass" &&
    forwardGain < -5 &&
    !escapesCrowd &&
    targetPressure >= 0.46;

  let score = 0;
  const labels = [];

  if (safeOutlet && trapLoad >= 0.38) {
    score += 0.18 + trapLoad * 0.22 + regain.secureIntent * 0.14;
    labels.push("Secure away from regain crowd");
  }

  if (transitionRelease && trapLoad <= 0.94) {
    score += 0.14 + regain.counterIntent * regain.freshness * 0.3 + Math.max(0, forwardGain) * 0.006;
    labels.push("Attack transition space");
  }

  if (escapeCarry) {
    score += 0.12 + laneClarity * 0.18 + Math.max(0, escapeGain) * 0.025 + regain.counterIntent * 0.08;
    labels.push("Carry out of counter-press");
  }

  if (crowdedReturn) {
    score -= 0.34 + trapLoad * 0.28 + targetPressure * 0.18;
    labels.push("Avoid regain crowd");
  }

  if (backwardsIntoTrap) {
    score -= 0.18 + trapLoad * 0.18;
    labels.push("Avoid counter-press trap");
  }

  if (trapLoad >= 0.58 && !escapesCrowd && candidate.actionType !== "shot") {
    score -= clamp((trapLoad - 0.5) * 0.24 + targetPressure * 0.08, 0, 0.22);
  }

  return {
    score: clamp(score, -0.86, 0.74),
    labels: uniquePrincipleLabels(labels),
    context: {
      trapLoad,
      escapeGain,
      startPressure,
      targetPressure,
      startOpponentDensity,
      targetOpponentDensity,
      targetSupport,
      laneClarity,
      safeOutlet,
      transitionRelease,
      escapeCarry,
      crowdedReturn,
    },
  };
}

function getAutoPilotRecoveryFirstActionContext(carrier, startPoint, profile = {}) {
  if (!carrier?.team || !startPoint) {
    return { active: false };
  }

  const recent = getRecentPossessionSteps(carrier.team, 5);
  const lastStep = recent[0] ?? null;
  const isRecovery =
    lastStep?.actionType === "recovery" ||
    lastStep?.profileKey === "loose-ball-recovery" ||
    `${lastStep?.profileLabel ?? ""}`.toLowerCase().includes("loose ball");

  if (!isRecovery) {
    return { active: false, lastStep };
  }

  const actors = getRecordedStepActorIds(lastStep);
  const recoveredByCarrier =
    actors.receiverId === carrier.id ||
    actors.carrierId === carrier.id ||
    lastStep?.carrierPlayerId === carrier.id ||
    lastStep?.afterSnapshot?.ball?.ownerPlayerId === carrier.id;

  if (!recoveredByCarrier) {
    return { active: false, lastStep, recoveredByCarrier };
  }

  const recoveryPoint =
    lastStep?.target ??
    lastStep?.afterSnapshot?.ball?.position ??
    startPoint;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const opponentDensity = getOpponentDensityAtPoint(carrier.team, startPoint, 8.5);
  const closeOpponentDensity = getOpponentDensityAtPoint(carrier.team, startPoint, 5.2);
  const localSupport = getTeamSupportCountAroundPoint(
    carrier.team,
    startPoint,
    new Set([carrier.id]),
    13
  );
  const forwardProbe = clampToPitch({
    x: startPoint.x + getAttackDirectionSign(carrier.team) * 18,
    y: lerp(startPoint.y, pitch.width / 2, 0.28),
  }, 2.5);
  const forwardOpenSpace = getCarryLaneOpenSpaceScore(
    getNearestOpponentGapInCarryLane(carrier, forwardProbe)
  );
  const recoveryDuration =
    lastStep?.recoveryDuration ??
    getRecordedStepDuration(lastStep);
  const localTrap = clamp(
    pressure * 0.52 +
      Math.min(opponentDensity, 4) * 0.12 +
      Math.min(closeOpponentDensity, 3) * 0.08 +
      (localSupport <= 0 ? 0.18 : 0) +
      (recoveryDuration >= 0.9 ? 0.06 : 0),
    0,
    1.25
  );

  return {
    active: true,
    lastStep,
    recoveryPoint: cloneVector(recoveryPoint),
    recoveryDuration,
    pressure,
    opponentDensity,
    closeOpponentDensity,
    localSupport,
    localTrap,
    forwardOpenSpace,
    directStyle: isTransitionAttackStyle(profile.styleKey),
    carrierRoleKey: getOffensiveRoleKey(carrier, teams[carrier.team]?.formation),
    startThreat: getPitchThreatProfile(startPoint, carrier.team),
  };
}

function getAutoPilotRecoveryFirstActionAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotRecoveryFirstActionContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const targetRadius = candidate.actionType === "dribble"
    ? 8.5
    : passDistance >= 24
      ? 13.5
      : 10.5;
  const targetPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : getOpponentPressureAtPoint(teamId, target, targetRadius + 1.5);
  const targetOpponentDensity = getOpponentDensityAtPoint(teamId, target, targetRadius);
  const targetSupport = getTeamSupportCountAroundPoint(
    teamId,
    target,
    new Set([carrier.id, candidate.receiverPlayerId].filter(Boolean)),
    candidate.actionType === "pass" && passDistance >= 22 ? 15 : 12
  );
  const laneClarity =
    Number.isFinite(candidate.laneClarity)
      ? candidate.laneClarity
      : candidate.actionType === "pass"
        ? computePassLaneClarity(carrier, target, {
            receiverPlayerId: candidate.receiverPlayerId ?? null,
          })
        : getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const escapeGain =
    distance(target, context.recoveryPoint) -
    distance(startPoint, context.recoveryPoint);
  const spaceGain =
    (targetThreat.value ?? 0) -
    (context.startThreat?.value ?? 0);
  const lateralEscape = Math.abs(target.y - startPoint.y);
  const safeFirstPass =
    candidate.actionType === "pass" &&
    passDistance >= 6 &&
    passDistance <= 22 &&
    laneClarity >= 0.5 &&
    targetPressure <= 0.68 &&
    targetSupport >= 1 &&
    forwardGain >= -8 &&
    (escapeGain >= 1.2 || lateralEscape >= 5 || targetOpponentDensity <= context.opponentDensity);
  const carryOut =
    candidate.actionType === "dribble" &&
    forwardGain >= 2.5 &&
    laneClarity >= 0.48 &&
    targetPressure <= Math.max(0.48, context.pressure + 0.03) &&
    targetOpponentDensity <= Math.max(2, context.opponentDensity);
  const transitionRelease =
    candidate.actionType === "pass" &&
    forwardGain >= 7 &&
    laneClarity >= 0.52 &&
    targetPressure <= 0.7 &&
    targetSupport >= 0 &&
    (
      context.directStyle ||
      (profile.directness ?? 0.5) >= 0.6 ||
      context.forwardOpenSpace >= 0.6 ||
      spaceGain >= 0.18
    );
  const forcedLong =
    candidate.actionType === "pass" &&
    passDistance >= 28 &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    !transitionRelease &&
    context.localTrap >= 0.42;
  const backwardsTrap =
    candidate.actionType === "pass" &&
    forwardGain < -6 &&
    targetPressure >= 0.46 &&
    targetSupport <= 1 &&
    targetOpponentDensity >= Math.max(1, context.opponentDensity - 1);
  const crowdedSameZone =
    candidate.actionType !== "shot" &&
    Math.abs(forwardGain) <= 3.5 &&
    lateralEscape <= 4.5 &&
    targetOpponentDensity >= context.opponentDensity &&
    targetPressure >= 0.5;
  const lowValueInstantShot =
    candidate.actionType === "shot" &&
    !candidate.mustShoot &&
    (targetThreat.value ?? 0) < (context.startThreat?.value ?? 0) + 0.16 &&
    (context.pressure >= 0.42 || context.localTrap >= 0.52);
  const labels = [];
  let score = 0;

  if (context.localTrap >= 0.42 && safeFirstPass) {
    score += 0.22 + context.localTrap * 0.24 + (profile.shortSupport ?? 0.5) * 0.12;
    labels.push("Recovery first action: secure first pass");
  }

  if (carryOut) {
    score +=
      0.12 +
      laneClarity * 0.18 +
      Math.max(0, escapeGain) * 0.02 +
      (profile.carryBias ?? 0.5) * 0.1;
    labels.push("Recovery first action: carry out");
  }

  if (transitionRelease) {
    score +=
      0.16 +
      (profile.directness ?? 0.5) * 0.18 +
      context.forwardOpenSpace * 0.14 +
      Math.max(0, spaceGain) * 0.28;
    labels.push("Recovery first action: attack transition");
  }

  if (forcedLong) {
    score -= 0.42 + context.localTrap * 0.22 + Math.max(0, 0.58 - laneClarity) * 0.24;
    labels.push("Recovery first action: avoid forced long ball");
  }

  if (backwardsTrap) {
    score -= 0.28 + targetPressure * 0.18;
    labels.push("Recovery first action: avoid backwards trap");
  }

  if (crowdedSameZone) {
    score -= 0.18 + context.localTrap * 0.16;
    labels.push("Recovery first action: leave the collision zone");
  }

  if (lowValueInstantShot) {
    score -= 0.22;
  }

  if (context.localSupport <= 0 && candidate.actionType === "pass" && !transitionRelease) {
    score -= 0.12;
  }

  return {
    score: clamp(score, -0.9, 0.78),
    labels: uniquePrincipleLabels(labels),
    context: {
      localTrap: context.localTrap,
      pressure: context.pressure,
      opponentDensity: context.opponentDensity,
      targetOpponentDensity,
      localSupport: context.localSupport,
      targetSupport,
      forwardOpenSpace: context.forwardOpenSpace,
      laneClarity,
      escapeGain,
      spaceGain,
      safeFirstPass,
      carryOut,
      transitionRelease,
      forcedLong,
      backwardsTrap,
      crowdedSameZone,
    },
  };
}

function getAutoPilotPostRecoveryPhaseContext(carrier, startPoint, profile = {}) {
  if (!carrier?.team || !startPoint) {
    return { active: false };
  }

  const steps = state.sequence?.steps ?? [];
  let recoveryIndex = -1;
  for (let index = steps.length - 1; index >= 0; index -= 1) {
    const step = steps[index];
    const possessionTeamId = getRecordedStepPossessionTeamId(step);
    const isRecovery =
      step?.actionType === "recovery" ||
      step?.profileKey === "loose-ball-recovery" ||
      `${step?.profileLabel ?? ""}`.toLowerCase().includes("loose ball");

    if (isRecovery && possessionTeamId === carrier.team) {
      recoveryIndex = index;
      break;
    }

    if (possessionTeamId && possessionTeamId !== carrier.team) {
      break;
    }
  }

  if (recoveryIndex < 0) {
    return { active: false };
  }

  const actionsAfterRecovery = steps.slice(recoveryIndex + 1);
  if (!actionsAfterRecovery.length || actionsAfterRecovery.length > 4) {
    return { active: false, actionsAfterRecovery: actionsAfterRecovery.length };
  }

  if (actionsAfterRecovery.some((step) => getRecordedStepPossessionTeamId(step) !== carrier.team)) {
    return { active: false, actionsAfterRecovery: actionsAfterRecovery.length };
  }

  const recoveryStep = steps[recoveryIndex];
  const origin =
    recoveryStep?.target ??
    recoveryStep?.afterSnapshot?.ball?.position ??
    startPoint;
  const elapsed = actionsAfterRecovery.reduce(
    (total, step) => total + getRecordedStepDuration(step),
    0
  );

  if (elapsed > 10.5) {
    return { active: false, actionsAfterRecovery: actionsAfterRecovery.length, elapsed };
  }

  const originDepth = getAttackingDepth(origin, carrier.team);
  const currentDepth = getAttackingDepth(startPoint, carrier.team);
  const depthGain = currentDepth - originDepth;
  const patterns = actionsAfterRecovery
    .map((step) => getRecordedStepPattern(step, carrier.team))
    .filter(Boolean);
  const sidewaysOrBackCount = patterns.filter((pattern) => pattern.forwardGain <= 2.5).length;
  const backwardsCount = patterns.filter((pattern) => pattern.forwardGain < -4).length;
  const forwardCount = patterns.filter((pattern) => pattern.forwardGain >= 6).length;
  const lineBreakCount = patterns.filter((pattern) => pattern.family === "line-break" || pattern.forwardGain >= 9).length;
  const switchCount = patterns.filter((pattern) => pattern.family === "switch").length;
  const lanes = patterns.map((pattern) => pattern.laneKey).filter(Boolean);
  const laneVariety = new Set(lanes).size;
  const sameLaneStall = actionsAfterRecovery.length >= 2 && laneVariety <= 1 && depthGain < 8;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const localSupport = getTeamSupportCountAroundPoint(
    carrier.team,
    startPoint,
    new Set([carrier.id]),
    13
  );
  const opponentDensity = getOpponentDensityAtPoint(carrier.team, startPoint, 9);
  const forwardProbe = clampToPitch({
    x: startPoint.x + getAttackDirectionSign(carrier.team) * 20,
    y: lerp(startPoint.y, pitch.width / 2, 0.26),
  }, 2.5);
  const forwardOpenSpace = getCarryLaneOpenSpaceScore(
    getNearestOpponentGapInCarryLane(carrier, forwardProbe)
  );
  const directStyle = isTransitionAttackStyle(profile.styleKey);
  const controlStyle = ["control-possession", "tiki-taka", "fluid-combinations"].includes(profile.styleKey);
  const counterWindow = clamp(
    (directStyle ? 0.34 : 0) +
      (profile.directness ?? 0.5) * 0.26 +
      (profile.progressionUrgency ?? 0.5) * 0.16 +
      forwardOpenSpace * 0.24 +
      (pressure <= 0.42 ? 0.12 : 0) -
      Math.max(0, actionsAfterRecovery.length - 2) * 0.08,
    0,
    1.1
  );
  const secureNeed = clamp(
    pressure * 0.38 +
      Math.min(opponentDensity, 4) * 0.11 +
      (localSupport <= 1 ? 0.18 : 0) +
      (controlStyle ? 0.14 : 0) +
      (depthGain < 4 ? 0.08 : 0),
    0,
    1.1
  );
  const stalePossession =
    actionsAfterRecovery.length >= 2 &&
    depthGain < 8 &&
    sidewaysOrBackCount >= 2 &&
    lineBreakCount === 0;
  const mode =
    counterWindow >= Math.max(0.58, secureNeed + 0.12)
      ? "counter"
      : secureNeed >= 0.58
        ? "secure"
        : "establish";

  return {
    active: true,
    recoveryIndex,
    actionsAfterRecovery: actionsAfterRecovery.length,
    elapsed,
    origin: cloneVector(origin),
    originDepth,
    currentDepth,
    depthGain,
    sidewaysOrBackCount,
    backwardsCount,
    forwardCount,
    lineBreakCount,
    switchCount,
    laneVariety,
    sameLaneStall,
    pressure,
    localSupport,
    opponentDensity,
    forwardOpenSpace,
    directStyle,
    controlStyle,
    counterWindow,
    secureNeed,
    stalePossession,
    mode,
  };
}

function getAutoPilotPostRecoveryPhaseAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotPostRecoveryPhaseContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const targetThreat = getPitchThreatProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const threatGain = targetThreat.value - startThreat.value;
  const targetPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : getOpponentPressureAtPoint(teamId, target, candidate.actionType === "dribble" ? 8.5 : 11.5);
  const targetSupport = getTeamSupportCountAroundPoint(
    teamId,
    target,
    new Set([carrier.id, candidate.receiverPlayerId].filter(Boolean)),
    candidate.actionType === "pass" && passDistance >= 22 ? 15 : 12
  );
  const laneShift = Math.abs(getPitchLaneIndex(target) - getPitchLaneIndex(startPoint));
  const laneClarity =
    Number.isFinite(candidate.laneClarity)
      ? candidate.laneClarity
      : candidate.actionType === "pass"
        ? computePassLaneClarity(carrier, target, {
            receiverPlayerId: candidate.receiverPlayerId ?? null,
          })
        : getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const transitionAttack =
    (candidate.actionType === "pass" || candidate.actionType === "dribble") &&
    forwardGain >= 6 &&
    (
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.42 ||
      targetThreat.value >= startThreat.value + 0.08 ||
      targetThreat.centralPocket >= 0.28 ||
      targetThreat.behindLine >= 0.22
    ) &&
    laneClarity >= 0.44 &&
    targetPressure <= 0.74;
  const secureSupport =
    candidate.actionType === "pass" &&
    passDistance >= 6 &&
    passDistance <= 22 &&
    targetPressure <= 0.68 &&
    targetSupport >= 1 &&
    forwardGain >= -8 &&
    (isSupportRole(receiverRoleKey) || receiverRoleKey === "wideBack" || laneShift >= 1);
  const switchOut =
    candidate.actionType === "pass" &&
    (candidate.isSwitch || laneShift >= 2) &&
    passDistance >= 16 &&
    laneClarity >= 0.54 &&
    targetPressure <= 0.62;
  const carryProgress =
    candidate.actionType === "dribble" &&
    forwardGain >= 4 &&
    laneClarity >= 0.5 &&
    targetPressure <= Math.max(0.52, context.pressure + 0.04);
  const finishAttack =
    candidate.actionType === "shot" &&
    (candidate.mustShoot || candidate.insideBox || startThreat.centralPocket >= 0.36 || startThreat.box >= 0.18);
  const lowValueRecycle =
    candidate.actionType === "pass" &&
    forwardGain <= -4 &&
    targetThreat.value <= startThreat.value + 0.04 &&
    !candidate.isSwitch &&
    context.pressure <= 0.5;
  const sameLaneChurn =
    candidate.actionType === "pass" &&
    Math.abs(forwardGain) <= 3.5 &&
    laneShift <= 1 &&
    targetThreat.value <= startThreat.value + 0.05 &&
    actionSpace.lineBreakCount === 0 &&
    !candidate.isSwitch;
  const forcedLong =
    candidate.actionType === "pass" &&
    passDistance >= 30 &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    !candidate.isLineBreak &&
    targetSupport <= 0 &&
    laneClarity < 0.62;

  const labels = [];
  let score = 0;

  if (context.mode === "counter") {
    if (transitionAttack) {
      score += 0.2 + context.counterWindow * 0.34 + Math.max(0, threatGain) * 0.32;
      labels.push("Post-recovery: keep counter alive");
    }

    if (carryProgress) {
      score += 0.12 + context.forwardOpenSpace * 0.22 + (profile.carryBias ?? 0.5) * 0.12;
      labels.push("Post-recovery: drive transition");
    }

    if (finishAttack) {
      score += 0.14 + context.counterWindow * 0.18;
      labels.push("Post-recovery: finish transition");
    }

    if (lowValueRecycle || sameLaneChurn) {
      score -= 0.32 + context.counterWindow * 0.24 + (context.actionsAfterRecovery >= 2 ? 0.12 : 0);
      labels.push("Post-recovery: do not kill the counter");
    }
  } else if (context.mode === "secure") {
    if (secureSupport) {
      score += 0.2 + context.secureNeed * 0.26 + (profile.shortSupport ?? 0.5) * 0.12;
      labels.push("Post-recovery: stabilise possession");
    }

    if (switchOut) {
      score += 0.14 + context.secureNeed * 0.14 + (profile.switchBias ?? 0.5) * 0.16;
      labels.push("Post-recovery: move away from pressure");
    }

    if (carryProgress && targetPressure <= context.pressure + 0.02) {
      score += 0.1 + (profile.carryBias ?? 0.5) * 0.1;
      labels.push("Post-recovery: carry into control");
    }

    if (forcedLong && !transitionAttack) {
      score -= 0.34 + context.secureNeed * 0.22;
      labels.push("Post-recovery: avoid forced release");
    }
  } else {
    if (transitionAttack && context.forwardCount === 0) {
      score += 0.16 + actionSpace.value * 0.24;
      labels.push("Post-recovery: progress after secure pass");
    }

    if (switchOut && (context.sameLaneStall || context.sidewaysOrBackCount >= 1)) {
      score += 0.18 + (profile.switchBias ?? 0.5) * 0.18;
      labels.push("Post-recovery: change corridor");
    }

    if (secureSupport && context.pressure >= 0.48 && context.localSupport <= 1) {
      score += 0.12 + context.secureNeed * 0.16;
      labels.push("Post-recovery: create support angle");
    }

    if (sameLaneChurn && context.sidewaysOrBackCount >= 1) {
      score -= 0.24 + (profile.progressionUrgency ?? 0.5) * 0.18;
      labels.push("Post-recovery: avoid same-zone loop");
    }
  }

  if (context.stalePossession) {
    if (transitionAttack || switchOut || carryProgress) {
      score += 0.18 + (profile.progressionUrgency ?? 0.5) * 0.18;
      labels.push("Post-recovery: restart momentum");
    } else if (sameLaneChurn || lowValueRecycle) {
      score -= 0.28 + (profile.progressionUrgency ?? 0.5) * 0.22;
    }
  }

  if (forcedLong && context.mode !== "counter" && (profile.routeOneBias ?? 0.5) < 0.58) {
    score -= 0.18;
  }

  return {
    score: clamp(score, -0.95, 0.9),
    labels: uniquePrincipleLabels(labels),
    context: {
      mode: context.mode,
      actionsAfterRecovery: context.actionsAfterRecovery,
      elapsed: context.elapsed,
      depthGain: context.depthGain,
      pressure: context.pressure,
      localSupport: context.localSupport,
      forwardOpenSpace: context.forwardOpenSpace,
      counterWindow: context.counterWindow,
      secureNeed: context.secureNeed,
      stalePossession: context.stalePossession,
      sameLaneStall: context.sameLaneStall,
      laneClarity,
      targetPressure,
      transitionAttack,
      secureSupport,
      switchOut,
      carryProgress,
      finishAttack,
      lowValueRecycle,
      sameLaneChurn,
      forcedLong,
    },
  };
}

function getAutoPilotTransitionNumbersContext(carrier, startPoint, profile = {}) {
  if (!carrier?.team || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  const postRecovery = getAutoPilotPostRecoveryPhaseContext(carrier, startPoint, profile);
  const activeRegain = regain.active && regain.freshness >= 0.08;
  const activePostRecovery = postRecovery.active && postRecovery.elapsed <= 8.5;
  if (!activeRegain && !activePostRecovery) {
    return { active: false, regain, postRecovery };
  }

  const sign = getAttackDirectionSign(teamId);
  const pressure = activeRegain ? regain.pressure : postRecovery.pressure;
  const forwardOpenSpace = activeRegain ? regain.forwardOpenSpace : postRecovery.forwardOpenSpace;
  const currentDepth = getAttackingDepth(startPoint, teamId);
  const maxForwardBand = currentDepth >= 68 ? 28 : 42;
  const laneWidth = currentDepth >= 68 ? 28 : 34;
  const attackersAhead = state.players
    .filter((player) => {
      if (player.team !== teamId || player.id === carrier.id || isGoalkeeper(player)) {
        return false;
      }

      const forwardMeters = (player.position.x - startPoint.x) * sign;
      return forwardMeters >= 1.5 &&
        forwardMeters <= maxForwardBand &&
        Math.abs(player.position.y - startPoint.y) <= laneWidth;
    })
    .reduce((total, player) => {
      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      const roleWeight = isFrontLineRole(roleKey)
        ? 1
        : roleKey === "connector"
          ? 0.72
          : roleKey === "wideBack"
            ? 0.58
            : roleKey === "pivot"
              ? 0.46
              : 0.34;
      const runnerWeight = getAutoPilotRoleStrength(player, "runner") * 0.18;
      return total + roleWeight + runnerWeight;
    }, 0);
  const defendersAhead = state.players
    .filter((player) => {
      if (player.team === teamId || isGoalkeeper(player)) {
        return false;
      }

      const forwardMeters = (player.position.x - startPoint.x) * sign;
      return forwardMeters >= -3 &&
        forwardMeters <= maxForwardBand + 8 &&
        Math.abs(player.position.y - startPoint.y) <= laneWidth + 5;
    })
    .reduce((total, player) => {
      const forwardMeters = (player.position.x - startPoint.x) * sign;
      const centralWeight = 1 - clamp(Math.abs(player.position.y - startPoint.y) / (laneWidth + 5), 0, 0.42);
      const depthWeight = forwardMeters >= 0 ? 1 : 0.72;
      return total + centralWeight * depthWeight;
    }, 0);
  const nearbySupport = getTeamSupportCountAroundPoint(teamId, startPoint, new Set([carrier.id]), 15);
  const transitionAdvantage = clamp(
    attackersAhead - defendersAhead * 0.82 + nearbySupport * 0.18 + forwardOpenSpace * 0.72 - pressure * 0.55,
    -3.5,
    3.5
  );
  const counterWindow = clamp(
    (activeRegain ? regain.counterIntent * regain.freshness : postRecovery.counterWindow) +
      forwardOpenSpace * 0.28 +
      Math.max(transitionAdvantage, 0) * 0.16 +
      (pressure <= 0.42 ? 0.12 : 0) +
      (isTransitionAttackStyle(profile.styleKey) ? 0.18 : 0),
    0,
    1.45
  );
  const secureNeed = clamp(
    (activeRegain ? regain.secureIntent * regain.freshness : postRecovery.secureNeed) +
      pressure * 0.28 +
      Math.max(defendersAhead - attackersAhead, 0) * 0.1 +
      (nearbySupport <= 1 ? 0.14 : 0) -
      forwardOpenSpace * 0.1,
    0,
    1.35
  );

  return {
    active: true,
    source: activeRegain ? "freshRegain" : "postRecovery",
    pressure,
    forwardOpenSpace,
    currentDepth,
    attackersAhead,
    defendersAhead,
    nearbySupport,
    transitionAdvantage,
    counterWindow,
    secureNeed,
  };
}

function getAutoPilotTransitionNumbersAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotTransitionNumbersContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const targetThreat = getPitchThreatProfile(target, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const laneShift = Math.abs(getPitchLaneIndex(target) - getPitchLaneIndex(startPoint));
  const laneClarity =
    Number.isFinite(candidate.laneClarity)
      ? candidate.laneClarity
      : candidate.actionType === "pass"
        ? computePassLaneClarity(carrier, target, {
            receiverPlayerId: candidate.receiverPlayerId ?? null,
          })
        : getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const targetPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : getOpponentPressureAtPoint(teamId, target, candidate.actionType === "dribble" ? 8.5 : 11.5);
  const supportNearTarget = Number.isFinite(candidate.supportNearTarget)
    ? candidate.supportNearTarget
    : getTeamSupportCountAroundPoint(
        teamId,
        target,
        new Set([carrier.id, candidate.receiverPlayerId].filter(Boolean)),
        passDistance >= 24 ? 16 : 12
      );
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const directAction =
    (candidate.actionType === "pass" || candidate.actionType === "dribble") &&
    forwardGain >= 6 &&
    (
      candidate.isLineBreak ||
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.38 ||
      targetThreat.value >= startThreat.value + 0.07 ||
      targetThreat.behindLine >= 0.18
    ) &&
    laneClarity >= 0.42 &&
    targetPressure <= 0.78;
  const secureAction =
    candidate.actionType === "pass" &&
    passDistance >= 5.5 &&
    passDistance <= 22 &&
    forwardGain >= -8 &&
    targetPressure <= 0.72 &&
    (
      supportNearTarget >= 1 ||
      isSupportRole(receiverRoleKey) ||
      receiverRoleKey === "wideBack" ||
      laneShift >= 1
    );
  const carryExploit =
    candidate.actionType === "dribble" &&
    forwardGain >= 4.5 &&
    actionSpace.openTarget >= 0.48 &&
    context.pressure <= 0.66;
  const finishTransition =
    candidate.actionType === "shot" &&
    (
      candidate.mustShoot ||
      targetThreat.box >= 0.2 ||
      startThreat.centralPocket >= 0.34 ||
      context.currentDepth >= 66
    );
  const unsupportedForward =
    candidate.actionType === "pass" &&
    passDistance >= 24 &&
    forwardGain >= 8 &&
    !candidate.isSwitch &&
    supportNearTarget <= 0 &&
    targetPressure >= 0.56 &&
    laneClarity < 0.68 &&
    context.transitionAdvantage < 0.2;
  const lowValueKill =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 2 &&
    targetThreat.value <= startThreat.value + 0.045 &&
    context.counterWindow >= 0.58 &&
    context.pressure <= 0.52;
  const labels = [];
  let score = 0;

  if (context.transitionAdvantage >= 0.35 && context.counterWindow >= 0.54) {
    if (directAction) {
      score += 0.24 + context.counterWindow * 0.24 + Math.max(context.transitionAdvantage, 0) * 0.08;
      labels.push("Transition numbers: exploit advantage");
    }

    if (carryExploit) {
      score += 0.16 + context.forwardOpenSpace * 0.22 + (profile.carryBias ?? 0.5) * 0.1;
      labels.push("Transition numbers: carry into open grass");
    }

    if (finishTransition) {
      score += 0.16 + (profile.shootBias ?? 0.5) * 0.14;
      labels.push("Transition numbers: finish the break");
    }

    if (lowValueKill) {
      score -= 0.32 + context.counterWindow * 0.22;
      labels.push("Transition numbers: do not kill advantage");
    }
  }

  if (context.transitionAdvantage <= -0.35 || context.secureNeed >= 0.68) {
    if (secureAction) {
      score += 0.2 + context.secureNeed * 0.24 + (profile.shortSupport ?? 0.5) * 0.1;
      labels.push("Transition numbers: secure against pressure");
    }

    if (unsupportedForward) {
      score -= 0.38 + Math.min(Math.abs(context.transitionAdvantage), 1.4) * 0.18;
      labels.push("Transition numbers: avoid unsupported release");
    }
  }

  if (
    context.source === "freshRegain" &&
    context.pressure <= 0.38 &&
    context.transitionAdvantage >= 0 &&
    candidate.actionType === "pass" &&
    forwardGain <= -4 &&
    !candidate.isSwitch
  ) {
    score -= 0.22 + context.counterWindow * 0.16;
  }

  return {
    score: clamp(score, -1.05, 1.05),
    labels: uniquePrincipleLabels(labels),
    context: {
      source: context.source,
      transitionAdvantage: context.transitionAdvantage,
      attackersAhead: context.attackersAhead,
      defendersAhead: context.defendersAhead,
      nearbySupport: context.nearbySupport,
      counterWindow: context.counterWindow,
      secureNeed: context.secureNeed,
      laneClarity,
      targetPressure,
      supportNearTarget,
      directAction,
      secureAction,
      carryExploit,
      finishTransition,
      unsupportedForward,
      lowValueKill,
    },
  };
}

function getAutoPilotPressureEscapeContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestGap = getNearestOpponentGapToPoint(teamId, startPoint);
  const opponentDensity = getOpponentDensityAtPoint(teamId, startPoint, 8.5);
  const closeOpponentDensity = getOpponentDensityAtPoint(teamId, startPoint, 5.4);
  const supportDensity = getTeamDensityAtPoint(teamId, startPoint, 11.5, new Set([carrier.id]));
  const currentThreat = getPitchThreatProfile(startPoint, teamId);
  const currentSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const laneKey = getPitchLaneKey(startPoint);
  const sideSign = getWideSideSign(startPoint) || 1;
  const isWideTrap = isWidePrincipleZone(startPoint) && opponentDensity >= 2;
  const centralTrap =
    Math.abs(startPoint.y - pitch.width / 2) <= 15 &&
    (pressure >= 0.54 || closeOpponentDensity >= 2);
  const trapLoad = clamp(
    pressure * 0.52 +
      Math.min(opponentDensity, 4) * 0.13 +
      Math.min(closeOpponentDensity, 3) * 0.13 -
      Math.min(supportDensity, 3) * 0.05 +
      (isWideTrap ? 0.12 : 0) +
      (centralTrap ? 0.08 : 0) +
      (profile.tempo >= 0.64 ? 0.04 : 0),
    0,
    1.35
  );
  const active =
    trapLoad >= 0.48 ||
    pressure >= 0.58 ||
    nearestGap <= 3.6 ||
    (opponentDensity >= 3 && supportDensity <= 1);

  return {
    active,
    teamId,
    pressure,
    nearestGap,
    opponentDensity,
    closeOpponentDensity,
    supportDensity,
    currentThreat,
    currentSpace,
    laneKey,
    sideSign,
    isWideTrap,
    centralTrap,
    trapLoad,
  };
}

function buildAutoPilotPressureTrapEscapeCandidate(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint || state.restartPhase?.type) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const context = getAutoPilotPressureEscapeContext(carrier, startPoint, profile);
  const block = getOpponentBlockReadProfile(teamId, startPoint);
  const sideSign = context.sideSign || getWideSideSign(startPoint) || 1;
  const sideLocked =
    block.ballSideCompression >= 0.52 &&
    (
      isWidePrincipleZone(startPoint) ||
      context.pressure >= 0.36 ||
      (profile.switchBias ?? 0.5) >= 0.56
    );

  if (!context.active && !sideLocked) {
    return null;
  }

  const options = [];
  const startLaneIndex = getPitchLaneIndex(getPitchLaneKey(startPoint));
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const attackSign = getAttackDirectionSign(teamId);
  const trapLoad = Math.max(context.trapLoad ?? 0, sideLocked ? 0.54 + block.ballSideCompression * 0.18 : 0);
  const addPassOption = (receiver, kind) => {
    if (!receiver || receiver.team !== teamId || receiver.id === carrier.id || isPassReceiverOffside(receiver, startPoint)) {
      return;
    }

    const target = getPlayerBallControlPoint(receiver);
    const passDistance = distance(startPoint, target);
    if (passDistance < 4.2 || passDistance > (kind === "switchAway" ? 44 : kind === "highestOutlet" ? 32 : 24)) {
      return;
    }

    const roleKey = getOffensiveRoleKey(receiver, formation);
    const targetLaneIndex = getPitchLaneIndex(getPitchLaneKey(target));
    const laneShift = Math.abs(targetLaneIndex - startLaneIndex);
    const forwardGain = (target.x - startPoint.x) * attackSign;
    const laneClarity = computePassLaneClarity(carrier, target, { receiverPlayerId: receiver.id });
    const receiverPressure = getPlayerPressureLoad(receiver, target);
    const targetOpponentDensity = getOpponentDensityAtPoint(teamId, target, kind === "switchAway" ? 13.5 : 10.5);
    const targetSupport = getTeamDensityAtPoint(
      teamId,
      target,
      kind === "switchAway" ? 15.5 : 11.5,
      new Set([carrier.id, receiver.id])
    );
    const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
    const targetThreat = actionSpace.targetThreat;
    const receiverSide = getWideSideSign(target) || getWideSideSign(receiver) || 0;
    const isSwitch = kind === "switchAway" || (laneShift >= 2 && passDistance >= 16);
    const isLineBreak =
      forwardGain >= 6.5 &&
      (actionSpace.lineBreakCount >= 1 || targetThreat.value >= startThreat.value + 0.07);
    const isBoxPass = targetThreat.box >= 0.22 || targetThreat.cutbackZone >= 0.26;
    const escapesCrowd =
      receiverPressure <= Math.max(0, context.pressure - 0.12) ||
      targetOpponentDensity <= Math.max(0, context.opponentDensity - 1) ||
      laneShift >= 1 ||
      isSwitch;
    const sameTrap =
      !isSwitch &&
      laneShift === 0 &&
      receiverPressure >= Math.max(0.44, context.pressure - 0.08) &&
      targetOpponentDensity >= Math.max(2, context.opponentDensity);
    const roleFit =
      kind === "switchAway"
        ? (["wideBack", "wideForward"].includes(roleKey) ? 0.42 : roleKey === "connector" ? 0.24 : 0.08)
        : kind === "thirdMan"
          ? (["pivot", "connector", "wideBack", "secondStriker"].includes(roleKey) ? 0.4 : 0.1)
          : kind === "underEscape"
            ? (["pivot", "rest", "wideBack", "connector"].includes(roleKey) ? 0.38 : 0.08)
            : isFrontLineRole(roleKey)
              ? 0.32
              : 0.08;
    const kindBonus =
      kind === "switchAway"
        ? (profile.switchBias ?? 0.5) * 0.36 + block.ballSideCompression * 0.28 + (receiverSide === -sideSign ? 0.18 : 0)
        : kind === "thirdMan"
          ? (profile.tempo ?? 0.5) * 0.24 + (profile.shortSupport ?? 0.5) * 0.18
          : kind === "underEscape"
            ? (profile.shortSupport ?? 0.5) * 0.26 + trapLoad * 0.12
            : (profile.directness ?? 0.5) * 0.2 + (profile.lineBreakBias ?? 0.5) * 0.18;
    const score =
      1.18 +
      laneClarity * 0.95 +
      clamp(1 - receiverPressure, 0, 1) * 0.42 +
      clamp(targetSupport, 0, 3) * 0.08 +
      trapLoad * 0.38 +
      roleFit +
      kindBonus +
      (escapesCrowd ? 0.3 : -0.16) +
      (isLineBreak ? 0.28 + actionSpace.value * 0.18 : actionSpace.value * 0.16) +
      (isBoxPass ? 0.18 : 0) +
      clamp(forwardGain / 18, -0.12, 0.3) -
      Math.max(0, passDistance - (kind === "switchAway" ? 28 : 16)) * (kind === "switchAway" ? 0.018 : 0.028) -
      (sameTrap ? 0.72 + trapLoad * 0.2 : 0) -
      (forwardGain < -8 && kind !== "underEscape" && !isSwitch ? 0.28 : 0) -
      (laneClarity < 0.42 && !isSwitch && !isLineBreak ? 0.24 : 0);
    const minScore =
      kind === "switchAway"
        ? 1.72
        : kind === "highestOutlet"
          ? 1.78
          : 1.6;

    if (score < minScore) {
      return;
    }

    const label =
      kind === "switchAway"
        ? "pressure switch"
        : kind === "thirdMan"
          ? "third-man escape"
          : kind === "underEscape"
            ? "under escape"
            : "highest outlet";
    const reason =
      kind === "switchAway"
        ? "the ball-side is locked, so the team changes corridor away from pressure"
        : kind === "thirdMan"
          ? "the carrier finds a third-player angle to escape the trap"
          : kind === "underEscape"
            ? "the carrier secures the ball through support under the pressure"
            : "the carrier releases the highest playable outlet before the trap closes";

    options.push({
      actionType: "pass",
      target,
      receiverPlayerId: receiver.id,
      receiverRoleKey: roleKey,
      passDistance,
      forwardGain,
      laneClarity,
      receiverPressure,
      supportNearTarget: targetSupport,
      isLineBreak,
      isSwitch,
      isSidewaysPass: Math.abs(forwardGain) < 4 && laneShift >= 1 && !isSwitch,
      isBoxPass,
      isPrinciplePattern: true,
      principleKey: `pressure-trap-${kind}`,
      principleLabel: `Pressure trap escape: ${getPlayerMagnetLabel(receiver)} opens the ${kind === "switchAway" ? "weak-side" : kind === "thirdMan" ? "third-man" : "support"} exit`,
      principleLabels: ["Press escape", kind === "switchAway" ? "Switch away from trap" : "Third-man escape"],
      score,
      firstTouchMode: isSwitch ? "inside" : isLineBreak || forwardGain >= 5 ? "forward" : "inside",
      label,
      reason,
    });
  };

  state.players.forEach((receiver) => {
    if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
      return;
    }

    const roleKey = getOffensiveRoleKey(receiver, formation);
    const receiverSide = getWideSideSign(receiver) || getWideSideSign(receiver.position) || 0;
    const target = getPlayerBallControlPoint(receiver);
    const forwardGain = (target.x - startPoint.x) * attackSign;
    const laneShift = Math.abs(getPitchLaneIndex(getPitchLaneKey(target)) - startLaneIndex);

    if (
      (sideLocked || context.isWideTrap || (profile.switchBias ?? 0.5) >= 0.6) &&
      receiverSide === -sideSign &&
      laneShift >= 2 &&
      ["wideForward", "wideBack", "connector"].includes(roleKey)
    ) {
      addPassOption(receiver, "switchAway");
    }

    if (
      laneShift >= 1 &&
      forwardGain >= -3 &&
      ["pivot", "connector", "wideBack", "secondStriker"].includes(roleKey)
    ) {
      addPassOption(receiver, "thirdMan");
    }

    if (
      context.pressure >= 0.54 &&
      forwardGain <= 1.5 &&
      forwardGain >= -10 &&
      ["pivot", "rest", "wideBack", "connector"].includes(roleKey)
    ) {
      addPassOption(receiver, "underEscape");
    }

    if (
      trapLoad >= 0.62 &&
      forwardGain >= 6 &&
      isFrontLineRole(roleKey)
    ) {
      addPassOption(receiver, "highestOutlet");
    }
  });

  const carryMeters = clamp(
    5.2 +
      (profile.carryBias ?? 0.5) * 3.6 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 2.2 -
      context.pressure * 2.1,
    4.4,
    10.5
  );
  const centralExitSide = (() => {
    const leftTarget = clampToPitch({ x: startPoint.x + attackSign * 4.8, y: startPoint.y - 6.5 }, 2.5);
    const rightTarget = clampToPitch({ x: startPoint.x + attackSign * 4.8, y: startPoint.y + 6.5 }, 2.5);
    const leftDensity = getOpponentDensityAtPoint(teamId, leftTarget, 8);
    const rightDensity = getOpponentDensityAtPoint(teamId, rightTarget, 8);
    return leftDensity <= rightDensity ? -1 : 1;
  })();
  const carryTarget = clampToPitch({
    x: startPoint.x + attackSign * carryMeters,
    y: isWidePrincipleZone(startPoint)
      ? lerp(startPoint.y, pitch.width / 2, 0.54)
      : clamp(startPoint.y + centralExitSide * Math.min(carryMeters * 0.78, 7.5), 5, pitch.width - 5),
  }, 2.5);
  const carryForwardGain = (carryTarget.x - startPoint.x) * attackSign;
  const carryPressure = getOpponentPressureAtPoint(teamId, carryTarget, 8.5);
  const carryOpponentDensity = getOpponentDensityAtPoint(teamId, carryTarget, 8.5);
  const carryOpenSpace = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, carryTarget));
  const carryActionSpace = getActionSpaceValue(startPoint, carryTarget, teamId, profile);
  const carryScore =
    1.22 +
    trapLoad * 0.26 +
    carryOpenSpace * 0.64 +
    getAutoPilotRoleStrength(carrier, "dribbler") * 0.36 +
    (profile.carryBias ?? 0.5) * 0.22 +
    clamp(carryForwardGain / 12, 0, 0.32) +
    carryActionSpace.value * 0.22 -
    carryPressure * 0.48 -
    Math.max(0, carryOpponentDensity - Math.max(1, context.opponentDensity)) * 0.16;

  if (
    carryForwardGain >= 3.2 &&
    carryOpenSpace >= 0.48 &&
    carryPressure <= Math.max(0.68, context.pressure + 0.06) &&
    carryScore >= 1.58
  ) {
    options.push({
      actionType: "dribble",
      target: carryTarget,
      receiverPlayerId: null,
      passDistance: distance(startPoint, carryTarget),
      forwardGain: carryForwardGain,
      laneClarity: carryOpenSpace,
      receiverPressure: carryPressure,
      supportNearTarget: getTeamDensityAtPoint(teamId, carryTarget, 11.5, new Set([carrier.id])),
      isLineBreak: carryActionSpace.lineBreakCount >= 1,
      isSwitch: false,
      isSidewaysPass: false,
      isBoxPass: carryActionSpace.targetThreat.box >= 0.22,
      isPrinciplePattern: true,
      principleKey: "pressure-trap-carry-out",
      principleLabel: `Pressure trap escape: ${getPlayerMagnetLabel(carrier)} carries out of the trap`,
      principleLabels: ["Press escape", "Carry out of trap"],
      score: carryScore,
      firstTouchMode: null,
      label: "carry out of trap",
      reason: "the closest escape is to carry diagonally away from the pressure",
    });
  }

  if (!options.length) {
    return null;
  }

  return chooseScoredCandidateWithVariation(options, profile, {
    carrier,
    startPoint,
    tolerance: 0.42,
    temperature: 0.18,
  });
}

function getAutoPilotPressureEscapeAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotPressureEscapeContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const targetThreat = getPitchThreatProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const targetPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : candidate.actionType === "pass"
      ? actionSpace.targetPressure
      : getOpponentPressureAtPoint(teamId, target, 8.5);
  const targetOpponentDensity = getOpponentDensityAtPoint(teamId, target, candidate.actionType === "pass" ? 10.5 : 8.5);
  const targetSupport = getTeamDensityAtPoint(
    teamId,
    target,
    candidate.actionType === "pass" && passDistance >= 22 ? 15 : 11.5,
    new Set([carrier.id, candidate.receiverPlayerId, candidate.principleRunnerPlayerId].filter(Boolean))
  );
  const laneClarity =
    Number.isFinite(candidate.laneClarity)
      ? candidate.laneClarity
      : candidate.actionType === "pass"
        ? computePassLaneClarity(carrier, target, {
            receiverPlayerId: candidate.receiverPlayerId ?? null,
          })
        : getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const targetLane = getPitchLaneKey(target);
  const laneShift =
    targetLane && context.laneKey
      ? Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(context.laneKey))
      : 0;
  const escapesPressure =
    targetPressure <= context.pressure - 0.14 ||
    targetOpponentDensity <= Math.max(0, context.opponentDensity - 1) ||
    laneShift >= 1 ||
    candidate.isSwitch;
  const safeShortExit =
    candidate.actionType === "pass" &&
    passDistance >= 6 &&
    passDistance <= 20 &&
    laneClarity >= 0.52 &&
    targetPressure <= 0.64 &&
    targetSupport >= 1 &&
    (escapesPressure || forwardGain >= 1.5);
  const thirdPlayerExit =
    candidate.actionType === "pass" &&
    passDistance >= 7 &&
    passDistance <= 24 &&
    laneShift >= 1 &&
    forwardGain >= -2 &&
    laneClarity >= 0.48 &&
    targetPressure <= 0.68 &&
    (
      targetThreat.halfSpace >= 0.26 ||
      targetThreat.betweenLines >= 0.24 ||
      candidate.receiverRoleKey === "connector" ||
      candidate.receiverRoleKey === "pivot" ||
      candidate.receiverRoleKey === "wideBack"
    );
  const switchExit =
    candidate.actionType === "pass" &&
    candidate.isSwitch &&
    passDistance >= 20 &&
    laneClarity >= 0.62 &&
    targetPressure <= 0.58 &&
    targetOpponentDensity <= Math.max(1, context.opponentDensity - 1);
  const carryExit =
    candidate.actionType === "dribble" &&
    forwardGain >= 2.5 &&
    laneClarity >= 0.5 &&
    targetPressure <= context.pressure - 0.08 &&
    targetOpponentDensity <= Math.max(1, context.opponentDensity);
  const crowdedReturn =
    candidate.actionType === "pass" &&
    passDistance <= 12 &&
    forwardGain <= 2 &&
    laneShift === 0 &&
    targetPressure >= 0.5 &&
    targetOpponentDensity >= context.opponentDensity &&
    !candidate.isSwitch;
  const dribbleIntoTrap =
    candidate.actionType === "dribble" &&
    targetPressure >= 0.62 &&
    targetOpponentDensity >= context.opponentDensity &&
    actionSpace.lineBreakCount === 0;
  const hopefulLongEscape =
    candidate.actionType === "pass" &&
    passDistance >= 28 &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    !candidate.isLineBreak &&
    targetSupport <= 0 &&
    laneClarity < 0.62 &&
    profile.routeOneBias < 0.6;
  const labels = [];
  let score = 0;

  if (safeShortExit) {
    score += 0.16 + context.trapLoad * 0.22 + (profile.shortSupport ?? 0.5) * 0.1;
    labels.push("Pressure escape: safe exit");
  }

  if (thirdPlayerExit) {
    score += 0.2 + context.trapLoad * 0.24 + (profile.tempo ?? 0.5) * 0.1;
    labels.push("Pressure escape: third player");
  }

  if (switchExit) {
    score += 0.18 + context.trapLoad * 0.28 + (profile.switchBias ?? 0.5) * 0.16;
    labels.push("Pressure escape: switch away");
  }

  if (carryExit) {
    score += 0.14 + context.trapLoad * 0.18 + (profile.carryBias ?? 0.5) * 0.12;
    labels.push("Pressure escape: carry out");
  }

  if (crowdedReturn) {
    score -= 0.34 + context.trapLoad * 0.34 + targetPressure * 0.14;
    labels.push("Avoid passing back into trap");
  }

  if (dribbleIntoTrap) {
    score -= 0.3 + context.trapLoad * 0.28;
    labels.push("Avoid carrying into trap");
  }

  if (hopefulLongEscape) {
    score -= 0.24 + context.trapLoad * 0.2;
    labels.push("Avoid hopeful escape ball");
  }

  return {
    score: clamp(score, -1.05, 0.95),
    labels: uniquePrincipleLabels(labels),
    context: {
      trapLoad: context.trapLoad,
      pressure: context.pressure,
      nearestGap: context.nearestGap,
      opponentDensity: context.opponentDensity,
      targetOpponentDensity,
      supportDensity: context.supportDensity,
      targetSupport,
      targetPressure,
      laneClarity,
      laneShift,
      safeShortExit,
      thirdPlayerExit,
      switchExit,
      carryExit,
      crowdedReturn,
      dribbleIntoTrap,
      hopefulLongEscape,
    },
  };
}

function getAutoPilotPatternDiversityAdjustment(candidate, carrier, startPoint, profile) {
  const recent = getRecentPossessionSteps(carrier.team, 7)
    .map((step) => getRecordedStepPattern(step, carrier.team))
    .filter(Boolean);

  if (!recent.length) {
    return { score: 0, labels: [] };
  }

  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const sameFamilyCount = recent.filter((entry) => entry.family === pattern.family).length;
  const sameLaneCount = recent.filter((entry) => entry.laneKey === pattern.laneKey && entry.thirdKey === pattern.thirdKey).length;
  const sameReceiverRoleCount = pattern.receiverRoleKey
    ? recent.filter((entry) => entry.receiverRoleKey === pattern.receiverRoleKey).length
    : 0;
  const sameSpaceCount = recent.filter((entry) => entry.targetSpaceLabel === pattern.targetSpaceLabel).length;
  let consecutiveFamily = 0;
  let consecutiveLane = 0;

  for (const entry of recent) {
    if (entry.family === pattern.family) {
      consecutiveFamily += 1;
    } else {
      break;
    }
  }

  for (const entry of recent) {
    if (entry.laneKey === pattern.laneKey && entry.thirdKey === pattern.thirdKey) {
      consecutiveLane += 1;
    } else {
      break;
    }
  }

  const identityFamily =
    ((profile.styleKey === "wing-play" || profile.styleKey === "overlap-wide") &&
      ["wide-overload", "cross", "cutback", "switch"].includes(pattern.family)) ||
    ((profile.styleKey === "control-possession" || profile.styleKey === "tiki-taka" || profile.styleKey === "fluid-combinations") &&
      ["support-link", "line-break", "switch", "cutback"].includes(pattern.family)) ||
    (isTransitionAttackStyle(profile.styleKey) &&
      ["line-break", "carry-forward", "front-line", "shot"].includes(pattern.family));
  const familyTolerance = identityFamily ? 0.58 : 1;
  const highValueException =
    candidate.actionType === "shot" ||
    candidate.isBoxPass ||
    candidate.mustShoot ||
    candidate.isLineBreak ||
    getPitchThreatProfile(candidate.target, carrier.team).value >= 0.68;
  const stalePatternPenalty = highValueException
    ? 0
    : clamp(
        sameFamilyCount * 0.055 * familyTolerance +
          consecutiveFamily * 0.16 * familyTolerance +
          sameLaneCount * 0.045 +
          consecutiveLane * 0.13 +
          sameReceiverRoleCount * 0.035 +
          sameSpaceCount * 0.035,
        0,
        0.92
      );
  const lastPattern = recent[0];
  const laneShiftFromLast = lastPattern
    ? Math.abs(getPitchLaneIndex(pattern.laneKey) - getPitchLaneIndex(lastPattern.laneKey))
    : 0;
  const rhythmChangeBonus =
    (consecutiveLane >= 2 && laneShiftFromLast >= 2 ? 0.22 + profile.switchBias * 0.16 : 0) +
    (consecutiveFamily >= 2 && pattern.family !== lastPattern?.family ? 0.16 + profile.tempo * 0.08 : 0) +
    (recent.filter((entry) => entry.family === "recycle").length >= 1 && pattern.forwardGain >= 6 ? 0.14 + profile.progressionUrgency * 0.18 : 0);
  const labels = [];

  if (rhythmChangeBonus >= 0.18) {
    labels.push("Change rhythm");
  }

  if (consecutiveLane >= 2 && laneShiftFromLast >= 2) {
    labels.push("Move the block");
  }

  return {
    score: clamp(rhythmChangeBonus - stalePatternPenalty, -0.95, 0.58),
    labels: uniquePrincipleLabels(labels),
    pattern,
  };
}

function getAutoPilotRepetitionPenalty(candidate, carrier, startPoint, profile) {
  const recent = getRecentPossessionSteps(carrier.team, 5);
  if (!recent.length) {
    return 0;
  }

  const targetLane = getPitchLaneKey(candidate.target);
  const targetThird = getAttackingThirdKey(candidate.target, carrier.team);
  const sameLaneRepeats = getRecentLaneRepeatCount(carrier.team, targetLane, targetThird, 4);
  const lastStep = recent[0];
  const lastCarrierId = lastStep.beforeSnapshot?.ball?.ownerPlayerId ?? lastStep.carrierPlayerId ?? null;
  const lastReceiverId = lastStep.receiverPlayerId ?? null;
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const passDistance = distance(startPoint, candidate.target);
  let penalty = sameLaneRepeats * 0.24;

  if (lastStep.target && distance(lastStep.target, candidate.target) <= 7) {
    penalty += 0.52;
  }

  if (
    candidate.actionType === "pass" &&
    candidate.receiverPlayerId &&
    lastCarrierId === candidate.receiverPlayerId &&
    lastReceiverId === carrier.id
  ) {
    const wallPassAllowance =
      profile.tempo >= 0.72 &&
      getPlayerTendency(carrier, "passAndMove") >= 0.62 &&
      pressure >= 0.42;
    penalty += wallPassAllowance ? 0.26 : 1.05;
  }

  if (
    candidate.actionType === "pass" &&
    candidate.receiverPlayerId &&
    candidate.receiverPlayerId === lastReceiverId &&
    pressure < 0.58
  ) {
    penalty += 0.42;
  }

  const recentShortSameZone = recent
    .slice(0, 3)
    .filter((step) => step.target && getPitchLaneKey(step.target) === targetLane && getRecordedStepDuration(step) <= 1.4)
    .length;

  if (candidate.actionType === "pass" && passDistance <= 13 && recentShortSameZone >= 2) {
    penalty += 0.5;
  }

  if (candidate.actionType === "dribble" && lastStep.actionType === "dribble" && sameLaneRepeats >= 1) {
    penalty += 0.35;
  }

  if (candidate.actionType === "shot") {
    const recentShots = recent.filter((step) => step.actionType === "shot").length;
    const isLongShot = (candidate.goalDistance ?? passDistance) > 27;

    if (lastStep.actionType === "shot") {
      penalty += candidate.mustShoot && !isLongShot ? 0.35 : isLongShot ? 3.4 : 1.45;
    }

    if (lastStep.target && isLongShot && distance(lastStep.target, candidate.target) <= 7) {
      penalty += 2.25;
    }

    if (recentShots >= 1 && isLongShot) {
      penalty += recentShots * 1.55;
    }

    if (recentShots >= 2 && !candidate.insideBox) {
      penalty += 1.65;
    }
  }

  return penalty;
}

function getAutoPilotFlowAdjustment(candidate, carrier, startPoint, profile) {
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const rhythm = getPossessionRhythmContext(carrier.team);
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const lastPrinciples = getLastAutoPrincipleSet(carrier.team);
  const possessionMaturity = clamp(
    rhythm.duration / Math.max(profile.targetPossessionSeconds ?? 8.8, 0.1),
    0,
    1.45
  );
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetLaneKey = getPitchLaneKey(candidate.target);
  const targetIsWide = targetLaneKey === "leftWide" || targetLaneKey === "rightWide";
  let adjustment = 0;

  if (candidate.actionType === "dribble") {
    if (progressionWindow.active && forwardGain >= 4) {
      adjustment += 0.28 + progressionWindow.openLane * 0.26 + progressionWindow.urgency * 0.18;
    }

    if (regain.active) {
      adjustment +=
        regain.counterIntent * regain.freshness * 0.34 +
        (forwardGain >= 6 ? regain.forwardOpenSpace * 0.24 : 0) -
        (forwardGain < 2 && regain.pressure <= 0.42 ? 0.22 : 0);
    }

    const previousWideQuestion =
      principleSetIncludes(lastPrinciples, "Ask question wide") ||
      principleSetIncludes(lastPrinciples, "overlap") ||
      principleSetIncludes(lastPrinciples, "wide");
    const previousHighValue =
      principleSetIncludes(lastPrinciples, "central pocket") ||
      principleSetIncludes(lastPrinciples, "valuable space") ||
      principleSetIncludes(lastPrinciples, "between-lines") ||
      principleSetIncludes(lastPrinciples, "cutback");

    if (
      previousWideQuestion &&
      (flow.carrierRoleKey === "wideForward" || flow.carrierRoleKey === "wideBack") &&
      forwardGain >= 3
    ) {
      adjustment += 0.34 + profile.dribbleBias * 0.2;
    }

    if (previousHighValue && forwardGain >= 4 && flow.pressure <= 0.62) {
      adjustment += 0.22 + profile.progressionUrgency * 0.18;
    }

    if (flow.carrierJustReceived) {
      adjustment += 0.72 + profile.carryBias * 0.28;
    }

    if (flow.consecutivePasses >= 2) {
      adjustment += 0.44 + Math.min(flow.consecutivePasses, 4) * 0.11;
    }

    if (isFrontLineRole(flow.carrierRoleKey) && flow.recentFrontLineTargets >= 2) {
      adjustment += 0.24;
    }

    if (profile.directness < 0.45 && flow.pressure <= 0.45) {
      adjustment += 0.14;
    }

    if (rhythm.sidewaysPasses >= 2 && profile.progressionUrgency >= 0.48) {
      adjustment += 0.28 + profile.progressionUrgency * 0.22;
    }

    return adjustment;
  }

  if (candidate.actionType !== "pass") {
    return adjustment;
  }

  const previousWideQuestion =
    principleSetIncludes(lastPrinciples, "Ask question wide") ||
    principleSetIncludes(lastPrinciples, "overlap") ||
    principleSetIncludes(lastPrinciples, "wide");
  const previousThirdPlayer = principleSetIncludes(lastPrinciples, "Find the Third");
  const previousChangeCorridor = principleSetIncludes(lastPrinciples, "Change corridor");
  const previousHighValue =
    principleSetIncludes(lastPrinciples, "central pocket") ||
    principleSetIncludes(lastPrinciples, "valuable space") ||
    principleSetIncludes(lastPrinciples, "between-lines") ||
    principleSetIncludes(lastPrinciples, "cutback");

  if (regain.active) {
    if (forwardGain >= 7 && (candidate.isLineBreak || isFrontLineRole(receiverRoleKey) || candidate.receiverPlayerId === null)) {
      adjustment += 0.2 + regain.counterIntent * regain.freshness * 0.48;
    }

    if (passDistance <= 19 && (isSupportRole(receiverRoleKey) || receiverRoleKey === "wideBack")) {
      adjustment += 0.16 + regain.secureIntent * regain.freshness * 0.34;
    }

    if (
      forwardGain <= -6 &&
      regain.pressure <= 0.42 &&
      profile.directness >= 0.58 &&
      !candidate.isSwitch
    ) {
      adjustment -= 0.32 + regain.counterIntent * 0.24;
    }
  }

  if (progressionWindow.active) {
    const actionSpace = getActionSpaceValue(startPoint, candidate.target, carrier.team, profile);

    if (forwardGain >= 5 && (candidate.isLineBreak || actionSpace.lineBreakCount >= 1 || actionSpace.value >= 0.36)) {
      adjustment += 0.24 + actionSpace.value * 0.34 + progressionWindow.urgency * 0.2;
    }

    if (
      forwardGain < 2 &&
      !candidate.isSwitch &&
      actionSpace.value < 0.28 &&
      flow.pressure < 0.56
    ) {
      adjustment -= 0.36 + progressionWindow.urgency * 0.34;
    }
  }

  if (candidate.isPrinciplePattern) {
    adjustment += 0.32;
    if (candidate.principleKey === "wide-overlap-entry" && profile.overlapBias >= 0.56) {
      adjustment += 0.24 + profile.widthDiscipline * 0.18;
    }

    if (candidate.principleKey === "wide-overlap" && flow.carrierJustReceived) {
      adjustment += 0.42 + profile.overlapBias * 0.18;
    }
  }

  if (previousWideQuestion) {
    if (receiverRoleKey === "wideBack" && forwardGain >= -1) {
      adjustment += 0.46 + profile.overlapBias * 0.28;
    }

    if (candidate.label === "cutback" || candidate.label === "cross" || candidate.isBoxPass) {
      adjustment += 0.36 + profile.deliveryBias * 0.24;
    }

    if (
      receiverRoleKey === "wideForward" &&
      candidate.passDistance <= 16 &&
      !candidate.isLineBreak &&
      !candidate.isSwitch &&
      flow.pressure < 0.52
    ) {
      adjustment -= 0.34;
    }
  }

  if (previousThirdPlayer) {
    if (forwardGain >= 6 || candidate.isLineBreak || candidate.isBoxPass) {
      adjustment += 0.42 + profile.lineBreakBias * 0.24;
    }

    if (forwardGain <= -5 && flow.pressure < 0.48) {
      adjustment -= 0.32;
    }
  }

  if (previousChangeCorridor) {
    if (isFrontLineRole(receiverRoleKey) || targetIsWide || candidate.isBoxPass) {
      adjustment += 0.22 + profile.progressionUrgency * 0.18;
    }

    if (candidate.isSwitch && flow.pressure < 0.44) {
      adjustment -= 0.38;
    }
  }

  if (previousHighValue) {
    if (forwardGain >= 3 || candidate.isBoxPass || candidate.actionType === "shot") {
      adjustment += 0.2 + profile.progressionUrgency * 0.14;
    }

    if (forwardGain < -4 && flow.pressure < 0.54) {
      adjustment -= 0.26;
    }
  }

  if (flow.carrierJustReceived && !candidate.isLineBreak && !candidate.isSwitch && flow.pressure < 0.58) {
    adjustment -= 0.5;
  }

  if (flow.consecutivePasses >= 3 && !candidate.isLineBreak && !candidate.isSwitch && flow.pressure < 0.62) {
    adjustment -= 0.55 + Math.min(flow.consecutivePasses - 2, 3) * 0.18;
  }

  if (candidate.isSidewaysPass && rhythm.sidewaysPasses >= Math.max(1, Math.round(profile.sidewaysTolerance * 3))) {
    adjustment -= 0.46 + profile.progressionUrgency * 0.48 + possessionMaturity * 0.28;
  }

  if ((candidate.isLineBreak || candidate.isBoxPass) && possessionMaturity >= 0.34) {
    adjustment += 0.26 + profile.progressionUrgency * 0.44;
  }

  if (forwardGain <= -5 && rhythm.backPasses >= 1 && rhythm.forwardPasses === 0 && rhythm.steps >= 2) {
    adjustment -= 0.24 + profile.progressionUrgency * 0.34;
  }

  if (receiverRoleKey) {
    const roleRepeatCount = flow.receiverRoleCounts.get(receiverRoleKey) ?? 0;
    adjustment -= Math.min(roleRepeatCount, 3) * 0.18;

    if (
      isFrontLineRole(receiverRoleKey) &&
      flow.recentFrontLineTargets >= 2 &&
      profile.phaseKey !== "finalThird" &&
      !candidate.isLineBreak &&
      !candidate.isSwitch
    ) {
      adjustment -= 1.15;
    }

    if (
      isFrontLineRole(flow.carrierRoleKey) &&
      isFrontLineRole(receiverRoleKey) &&
      profile.phaseKey !== "finalThird" &&
      !candidate.isSwitch
    ) {
      adjustment -= 0.85;
    }

    if (isSupportRole(receiverRoleKey) && flow.recentFrontLineTargets >= 2 && passDistance <= 26) {
      adjustment += 0.86;
    }

    if (receiverRoleKey === "pivot" && profile.shortSupport >= 0.72 && passDistance <= 20) {
      adjustment += 0.45;
    }

    if (receiverRoleKey === "connector" && profile.shortSupport >= 0.64 && passDistance <= 22) {
      adjustment += 0.38;
    }

    if (receiverRoleKey === "wideBack" && (profile.overlapBias >= 0.56 || profile.widthDiscipline >= 0.68)) {
      adjustment += 0.45;
    }
  }

  if (targetIsWide && flow.recentWideTargets === 0) {
    adjustment += 0.28 + profile.widthDiscipline * 0.18;
  }

  if (
    flow.lastCarrierId === candidate.receiverPlayerId &&
    flow.lastReceiverId === carrier.id &&
    flow.pressure < 0.48 &&
    !candidate.isLineBreak
  ) {
    adjustment -= 0.42;
  }

  return adjustment;
}

function getAutoPilotCarryEndProductContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const lastStep = flow.lastStep;
  if (!lastStep || lastStep.actionType !== "dribble") {
    return { active: false, flow };
  }

  const sign = getAttackDirectionSign(teamId);
  const carryStart =
    lastStep.beforeSnapshot?.ball?.position ??
    lastStep.beforeSnapshot?.ball?.startPosition ??
    lastStep.beforeSnapshot?.players?.find?.((player) => player.id === carrier.id)?.position ??
    startPoint;
  const carryEnd = lastStep.target ?? startPoint;
  const carryDistance = distance(carryStart, carryEnd);
  const carryForwardGain = (carryEnd.x - carryStart.x) * sign;
  const carryEndedHere = distance(carryEnd, startPoint) <= 8.5;
  const sameCarrier =
    lastStep.carrierPlayerId === carrier.id ||
    lastStep.afterSnapshot?.ball?.ownerPlayerId === carrier.id ||
    state.ball.ownerPlayerId === carrier.id;
  const principles = getLastAutoPrincipleSet(teamId);
  const wasRunwayCarry =
    principleSetIncludes(principles, "Open-grass runway") ||
    principleSetIncludes(principles, "runway carry");
  const wasOpenCarry =
    wasRunwayCarry ||
    principleSetIncludes(principles, "Open-grass carry") ||
    principleSetIncludes(principles, "Carry through open") ||
    principleSetIncludes(principles, "Drive at the back line");
  const meaningfulCarry =
    carryDistance >= 6 ||
    carryForwardGain >= 4.5 ||
    wasOpenCarry;

  if (!sameCarrier || !carryEndedHere || !meaningfulCarry) {
    return {
      active: false,
      flow,
      carryDistance,
      carryForwardGain,
      wasOpenCarry,
    };
  }

  const goalTarget = getAutoPilotShotTarget(teamId, carrier);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const shotWindow = getShotWindowProfile(carrier, startPoint, goalTarget);
  const startLane = getPitchLaneKey(startPoint);
  const isWide = startLane === "leftWide" || startLane === "rightWide";
  const finishWindow =
    goalDistance <= (wasRunwayCarry ? 38 : 34) &&
    attackingDepth >= (wasRunwayCarry ? 63 : 66) &&
    shotWindow.angleQuality >= (wasRunwayCarry ? 0.12 : 0.15) &&
    shotWindow.blockRisk <= (wasRunwayCarry ? 0.88 : 0.84) &&
    pressure <= (wasRunwayCarry ? 0.88 : 0.84) &&
    (
      shotWindow.quality >= (wasRunwayCarry ? 0.17 : 0.2) ||
      shotWindow.laneClarity >= (wasRunwayCarry ? 0.32 : 0.38) ||
      getAutoPilotRoleStrength(carrier, "finisher") >= 0.7
    );
  const cutbackWindow =
    isWide &&
    attackingDepth >= (wasRunwayCarry ? 72 : 76) &&
    goalDistance <= (wasRunwayCarry ? 40 : 36) &&
    pressure <= (wasRunwayCarry ? 0.86 : 0.82);
  const boxEntryWindow =
    attackingDepth >= (wasRunwayCarry ? 64 : 68) &&
    (startThreat.centralPocket >= 0.28 ||
      startThreat.halfSpace >= 0.34 ||
      startThreat.betweenLines >= 0.34 ||
      startThreat.box >= 0.18 ||
      startThreat.cutbackZone >= 0.24 ||
      (wasRunwayCarry && shotWindow.laneClarity >= 0.3));
  const endProductUrgency = clamp(
    (attackingDepth - 60) / 28 +
      (finishWindow ? 0.28 : 0) +
      (cutbackWindow ? 0.2 : 0) +
      (boxEntryWindow ? 0.18 : 0) +
      Math.max(0, carryForwardGain - 5) / 22 +
      (wasRunwayCarry ? 0.28 : 0) +
      (wasOpenCarry ? 0.16 : 0) -
      pressure * 0.16,
    0,
    1.35
  );

  return {
    active: endProductUrgency >= 0.34,
    flow,
    principles,
    carryDistance,
    carryForwardGain,
    wasRunwayCarry,
    wasOpenCarry,
    goalDistance,
    attackingDepth,
    pressure,
    startThreat,
    shotWindow,
    startLane,
    isWide,
    finishWindow,
    cutbackWindow,
    boxEntryWindow,
    endProductUrgency,
  };
}

function getAutoPilotCarryEndProductAdjustment(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier || !startPoint) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const context = getAutoPilotCarryEndProductContext(carrier, startPoint, profile);
  if (!context.active) {
    return {
      score: 0,
      labels: [],
      context,
    };
  }

  const teamId = carrier.team;
  const targetThreat = candidate.actionType === "shot"
    ? context.startThreat
    : getPitchThreatProfile(candidate.target, teamId);
  const actionSpace = candidate.actionType === "shot"
    ? null
    : getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const targetLane = getPitchLaneKey(candidate.target);
  const targetIsBoxOrCutback =
    candidate.isBoxPass ||
    candidate.label === "cutback" ||
    candidate.label === "cross" ||
    targetThreat.box >= 0.24 ||
    targetThreat.cutbackZone >= 0.3;
  const targetIsFinalThirdPocket =
    targetThreat.centralPocket >= 0.34 ||
    targetThreat.betweenLines >= 0.42 ||
    targetThreat.halfSpace >= 0.42 ||
    targetThreat.assistZone >= 0.36;
  const sterileRecycle =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !targetIsBoxOrCutback &&
    !targetIsFinalThirdPocket &&
    forwardGain < 2 &&
    targetThreat.value <= context.startThreat.value + 0.04 &&
    passDistance <= 24;
  const backwardsRecycle =
    candidate.actionType === "pass" &&
    forwardGain <= -5 &&
    !candidate.isSwitch &&
    !targetIsBoxOrCutback;
  const repeatedLowValueCarry =
    candidate.actionType === "dribble" &&
    context.attackingDepth >= 68 &&
    forwardGain < 7 &&
    (actionSpace?.openTarget ?? 0) < 0.64 &&
    targetThreat.box < 0.22 &&
    targetThreat.behindLine < 0.34;
  const continuationCarry =
    candidate.actionType === "dribble" &&
    forwardGain >= 6 &&
    (actionSpace?.openTarget ?? 0) >= 0.56 &&
    (targetThreat.box >= 0.18 || targetThreat.behindLine >= 0.28 || context.goalDistance > 27);
  const labels = [];
  let score = 0;

  if (candidate.actionType === "shot" && context.finishWindow) {
    score +=
      0.5 +
      context.endProductUrgency * 0.38 +
      context.shotWindow.quality * 0.32 +
      (context.wasRunwayCarry ? 0.22 : 0);
    labels.push(context.wasRunwayCarry ? "Runway end product: shoot" : "Carry end product: shoot");
  }

  if (candidate.actionType === "pass" && targetIsBoxOrCutback) {
    score +=
      0.42 +
      context.endProductUrgency * 0.3 +
      (targetThreat.cutbackZone >= 0.3 ? 0.16 : 0) +
      (context.wasRunwayCarry ? 0.14 : 0);
    labels.push(candidate.label === "cutback" ? "Runway end product: cutback" : "Carry end product: attack box");
  }

  if (
    candidate.actionType === "pass" &&
    targetIsFinalThirdPocket &&
    forwardGain >= -1 &&
    !targetIsBoxOrCutback
  ) {
    score += 0.24 + context.endProductUrgency * 0.18;
    labels.push("Carry end product: connect in final third");
  }

  if (
    candidate.actionType === "pass" &&
    candidate.isSwitch &&
    context.isWide &&
    targetLane !== context.startLane &&
    forwardGain >= -4
  ) {
    score += 0.16 + (profile.switchBias ?? 0.5) * 0.12;
    labels.push("Carry end product: release weak side");
  }

  if (continuationCarry && !context.finishWindow && !context.cutbackWindow) {
    score += 0.18 + (profile.carryBias ?? 0.5) * 0.12 + (context.wasRunwayCarry ? 0.1 : 0);
    labels.push(context.wasRunwayCarry ? "Runway: keep attacking" : "Carry end product: keep driving");
  }

  if (sterileRecycle) {
    score -=
      0.42 +
      context.endProductUrgency * 0.34 +
      (profile.progressionUrgency ?? 0.5) * 0.18 +
      (context.wasRunwayCarry ? 0.36 : 0);
    labels.push(context.wasRunwayCarry ? "Do not waste runway" : "Avoid recycle after carry");
  }

  if (backwardsRecycle && context.pressure <= 0.62) {
    score -= 0.36 + context.endProductUrgency * 0.26 + (context.wasRunwayCarry ? 0.28 : 0);
  }

  if (repeatedLowValueCarry) {
    score -= 0.34 + context.endProductUrgency * 0.22 + (context.wasRunwayCarry ? 0.18 : 0);
  }

  return {
    score: clamp(score, -1.05, 1.25),
    labels: uniquePrincipleLabels(labels),
    context,
  };
}

function getAutoPilotSpacingBonus(candidate, carrier, startPoint, profile) {
  const startLaneIndex = getPitchLaneIndex(startPoint);
  const targetLaneKey = getPitchLaneKey(candidate.target);
  const targetLaneIndex = getPitchLaneIndex(targetLaneKey);
  const laneShift = Math.abs(targetLaneIndex - startLaneIndex);
  const passDistance = distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetThird = getAttackingThirdKey(candidate.target, carrier.team);
  const repeatedLane = getRecentLaneRepeatCount(carrier.team, targetLaneKey, targetThird, 4);
  const isWideLane = targetLaneKey === "leftWide" || targetLaneKey === "rightWide";
  const isNonProgressiveLaneShift =
    candidate.actionType === "pass" &&
    Math.abs(forwardGain) < 4 &&
    passDistance < 24 &&
    !candidate.isSwitch;
  const lateralMultiplier = isNonProgressiveLaneShift
    ? clamp(profile.sidewaysTolerance + profile.switchBias * 0.22, 0.24, 0.86)
    : 1;
  let bonus = 0;

  if (laneShift >= 2 && passDistance >= 15) {
    bonus += (0.28 + profile.switchBias * 0.34 + repeatedLane * 0.12) * lateralMultiplier;
  }

  if (isWideLane && candidate.actionType === "pass") {
    bonus += (0.16 + profile.crossBias * 0.18 + profile.widthDiscipline * 0.2) * lateralMultiplier;
  }

  if (candidate.actionType === "pass" && passDistance >= 8 && passDistance <= 20 && laneShift >= 1) {
    bonus += (0.16 + profile.shortSupport * 0.14) * lateralMultiplier;
  }

  if (candidate.actionType === "dribble" && laneShift >= 1) {
    bonus += 0.12 + profile.carryBias * 0.16;
  }

  return bonus;
}

