function mergeIntentionWeights(...profiles) {
  const merged = {};
  Object.keys(autoPilotPrincipleLabels).forEach((key) => {
    const values = profiles
      .map((profile) => profile?.[key])
      .filter((value) => Number.isFinite(value));

    if (!values.length) {
      merged[key] = 0;
      return;
    }

    const average = values.reduce((total, value) => total + value, 0) / values.length;
    const peak = Math.max(...values);
    merged[key] = clamp(average * 0.62 + peak * 0.38, 0, 1.15);
  });

  return merged;
}

function getAutoPilotIntentionModel(carrier, startPoint, profile) {
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const rhythm = getPossessionRhythmContext(carrier.team);
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  const phaseWeights =
    autoPilotPhaseIntentionWeights[profile.phaseKey] ?? autoPilotPhaseIntentionWeights.progression;
  const styleWeights =
    autoPilotStyleIntentionWeights[profile.styleKey] ?? autoPilotStyleIntentionWeights.balanced;
  const formationWeights =
    autoPilotFormationIntentionWeights[profile.formation] ?? autoPilotFormationIntentionWeights["4-3-3"];
  const weights = mergeIntentionWeights(phaseWeights, styleWeights, formationWeights);
  const ballDepth = getAttackingDepth(startPoint, carrier.team);
  const carrierRoleKey = getOffensiveRoleKey(carrier, teams[carrier.team]?.formation);

  if (flow.pressure >= 0.58) {
    weights.secure = clamp(weights.secure + 0.24, 0, 1.25);
    weights.thirdPlayer = clamp(weights.thirdPlayer + 0.14, 0, 1.25);
    weights.driveSpace = clamp(weights.driveSpace + (getPlayerTendency(carrier, "dribble") >= 0.58 ? 0.16 : 0.04), 0, 1.25);
  }

  if (rhythm.sidewaysPasses >= 1) {
    weights.switchPlay = clamp(weights.switchPlay + 0.18 + Math.min(rhythm.sidewaysPasses, 3) * 0.08, 0, 1.28);
    weights.breakLine = clamp(weights.breakLine + 0.12, 0, 1.25);
  }

  if (rhythm.backPasses >= 1 && rhythm.forwardPasses === 0 && rhythm.steps >= 2) {
    weights.breakLine = clamp(weights.breakLine + 0.22, 0, 1.28);
    weights.driveSpace = clamp(weights.driveSpace + 0.12, 0, 1.22);
    weights.secure = clamp(weights.secure - 0.12, 0, 1.1);
  }

  if (flow.consecutivePasses >= 2) {
    weights.thirdPlayer = clamp(weights.thirdPlayer + 0.16, 0, 1.25);
    weights.breakLine = clamp(weights.breakLine + 0.12, 0, 1.25);
  }

  if (ballDepth >= 66) {
    weights.shoot = clamp(weights.shoot + 0.22, 0, 1.3);
    weights.cutback = clamp(weights.cutback + 0.14, 0, 1.25);
    weights.boxDelivery = clamp(weights.boxDelivery + 0.12, 0, 1.25);
  }

  if (carrierRoleKey === "wideForward" || carrierRoleKey === "wideBack") {
    weights.wideOverload = clamp(weights.wideOverload + 0.16, 0, 1.25);
    weights.isolate1v1 = clamp(weights.isolate1v1 + 0.12, 0, 1.22);
    weights.cutback = clamp(weights.cutback + (ballDepth >= 62 ? 0.12 : 0), 0, 1.25);
  }

  if (carrierRoleKey === "pivot" || carrierRoleKey === "connector") {
    weights.thirdPlayer = clamp(weights.thirdPlayer + 0.12, 0, 1.25);
    weights.switchPlay = clamp(weights.switchPlay + 0.08, 0, 1.18);
  }

  const forwardFacingSpaceTwo = getForwardFacingSpaceTwoContext(carrier, startPoint);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  if (forwardFacingSpaceTwo.active) {
    weights.goldenZone = clamp((weights.goldenZone ?? 0) + 0.34, 0, 1.35);
    weights.breakLine = clamp(weights.breakLine + 0.24, 0, 1.3);
    weights.driveSpace = clamp(weights.driveSpace + 0.18, 0, 1.25);
    weights.secure = clamp(weights.secure - 0.22, 0, 1.05);
    weights.restDefence = clamp(weights.restDefence - 0.18, 0, 1.05);
  }

  if (progressionWindow.active) {
    weights.goldenZone = clamp((weights.goldenZone ?? 0) + 0.22 + progressionWindow.goldenAhead * 0.16, 0, 1.42);
    weights.breakLine = clamp(weights.breakLine + 0.2 + progressionWindow.openLane * 0.14, 0, 1.38);
    weights.driveSpace = clamp(weights.driveSpace + 0.2 + progressionWindow.openLane * 0.18, 0, 1.34);
    weights.shoot = clamp(weights.shoot + (progressionWindow.depth >= 62 ? 0.14 : 0), 0, 1.34);
    weights.secure = clamp(weights.secure - 0.14 * progressionWindow.urgency, 0, 1.08);
    weights.restDefence = clamp(weights.restDefence - 0.1 * progressionWindow.urgency, 0, 1.08);
  }

  if (regain.active) {
    const fresh = regain.freshness;
    const secureNeed = regain.secureIntent * fresh;
    const counterNeed = regain.counterIntent * fresh;

    weights.secure = clamp(weights.secure + secureNeed * 0.36 + (regain.pressure >= 0.52 ? 0.2 : 0), 0, 1.35);
    weights.thirdPlayer = clamp(weights.thirdPlayer + secureNeed * 0.18 + fresh * 0.08, 0, 1.3);
    weights.restDefence = clamp(weights.restDefence + secureNeed * 0.16, 0, 1.25);
    weights.counterAttack = clamp(weights.counterAttack + counterNeed * 0.48 + regain.forwardOpenSpace * 0.18, 0, 1.42);
    weights.breakLine = clamp(weights.breakLine + counterNeed * 0.28, 0, 1.35);
    weights.driveSpace = clamp(weights.driveSpace + counterNeed * 0.18 + regain.forwardOpenSpace * 0.12, 0, 1.3);
    weights.goldenZone = clamp((weights.goldenZone ?? 0) + counterNeed * 0.18, 0, 1.4);

    if (regain.pressure <= 0.34 && regain.forwardOpenSpace >= 0.62) {
      weights.secure = clamp(weights.secure - 0.08, 0, 1.25);
      weights.counterAttack = clamp(weights.counterAttack + 0.16, 0, 1.45);
    }
  }

  return {
    weights,
    flow,
    rhythm,
    ballDepth,
    carrierRoleKey,
    forwardFacingSpaceTwo,
    progressionWindow,
    regain,
  };
}

function getAutoPilotCandidatePrincipleMetrics(candidate, carrier, startPoint, profile, model) {
  const targetLaneKey = getPitchLaneKey(candidate.target);
  const startLaneKey = getPitchLaneKey(startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetLaneKey) - getPitchLaneIndex(startLaneKey));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetDepth = getAttackingDepth(candidate.target, carrier.team);
  const targetIsWide = targetLaneKey === "leftWide" || targetLaneKey === "rightWide";
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(carrier.team));
  const targetGoalDistance = distance(candidate.target, getOpponentGoalCenter(carrier.team));
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver
      ? getPlayerPressureLoad(receiver, candidate.target)
      : 0.35;
  const targetThreat = getPitchThreatProfile(candidate.target, carrier.team);
  const threatGain = getActionThreatGain(startPoint, candidate.target, carrier.team);
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, carrier.team, profile);
  const centralPocketScore = targetThreat.centralPocket;
  const supportRole = receiverRoleKey === "pivot" || receiverRoleKey === "connector" || receiverRoleKey === "secondStriker";
  const forwardRole = receiverRoleKey === "striker" || receiverRoleKey === "wideForward" || receiverRoleKey === "secondStriker";
  const isLongForwardPass = candidate.actionType === "pass" && passDistance >= 26 && forwardGain >= 8;
  const insideBoxShot = candidate.actionType === "shot" && (candidate.insideBox || goalDistance <= 22);
  const metrics = {
    secure: 0,
    attractPressure: 0,
    goldenZone: 0,
    breakLine: 0,
    thirdPlayer: 0,
    switchPlay: 0,
    wideOverload: 0,
    overlapUnderlap: 0,
    driveSpace: 0,
    isolate1v1: 0,
    boxDelivery: 0,
    cutback: 0,
    shoot: 0,
    secondBall: 0,
    counterAttack: 0,
    restDefence: 0,
  };

  if (candidate.actionType === "pass") {
    metrics.secure = clamp(
      (passDistance <= 18 ? 0.62 : 0.26) +
        (receiverPressure <= 0.52 ? 0.24 : 0) +
        (forwardGain >= -7 ? 0.12 : -0.16) +
        (supportRole ? 0.18 : 0),
      0,
      1
    );
    metrics.attractPressure = clamp(
      (Math.abs(forwardGain) < 4 && passDistance <= 16 ? 0.42 : 0) +
        (model.flow.pressure >= 0.46 ? 0.24 : 0) +
        (supportRole ? 0.18 : 0),
      0,
      1
    );
    metrics.breakLine = clamp(
      (candidate.isLineBreak ? 0.76 : 0) +
        clamp(forwardGain / 18, 0, 0.62) +
        (forwardRole && targetDepth >= model.ballDepth + 6 ? 0.2 : 0) +
        clamp(actionSpace.lineBreakCount / 3, 0, 1) * 0.22,
      0,
      1
    );
    metrics.goldenZone = clamp(
      centralPocketScore * 0.68 +
        targetThreat.betweenLines * 0.24 +
        targetThreat.cutbackZone * 0.18 +
        Math.max(0, threatGain) * 0.24 +
        actionSpace.value * 0.16 +
        (forwardGain >= 5 ? 0.16 : 0) +
        (receiverPressure <= 0.56 ? 0.12 : 0) +
        (model.forwardFacingSpaceTwo.active && forwardGain >= 2 ? 0.2 : 0) +
        (model.progressionWindow?.active && forwardGain >= 3 ? 0.16 : 0),
      0,
      1
    );
    metrics.thirdPlayer = clamp(
      (supportRole && passDistance <= 24 ? 0.48 : 0) +
        (model.flow.consecutivePasses >= 1 || model.flow.carrierJustReceived ? 0.28 : 0) +
        (receiver ? getPlayerTendency(receiver, "passAndMove") * 0.22 : 0),
      0,
      1
    );
    metrics.switchPlay = clamp(
      (candidate.isSwitch ? 0.78 : 0) +
        (laneShift >= 2 && passDistance >= 16 ? 0.42 : 0) +
        (model.rhythm.sidewaysPasses >= 1 ? 0.22 : 0),
      0,
      1
    );
    metrics.wideOverload = clamp(
      (targetIsWide && (receiverRoleKey === "wideForward" || receiverRoleKey === "wideBack") ? 0.58 : 0) +
        (candidate.isPrinciplePattern ? 0.32 : 0) +
        (targetDepth >= 42 ? 0.14 : 0),
      0,
      1
    );
    metrics.overlapUnderlap = clamp(
      (candidate.principleKey === "wide-overlap" || candidate.principleKey === "wide-overlap-entry" ? 0.86 : 0) +
        (receiverRoleKey === "wideBack" && targetIsWide && forwardGain >= -1 ? 0.28 : 0),
      0,
      1
    );
    metrics.isolate1v1 = clamp(
      (receiverRoleKey === "wideForward" && targetIsWide && targetDepth >= 48 ? 0.48 : 0) +
        (candidate.laneClarity >= 0.72 ? 0.16 : 0),
      0,
      1
    );
    metrics.boxDelivery = clamp(
      (candidate.isBoxPass ? 0.62 : 0) +
        (candidate.label === "cross" ? 0.76 : 0) +
        targetThreat.assistZone * 0.26 +
        (targetDepth >= 72 && Math.abs(candidate.target.y - pitch.width / 2) <= 18 ? 0.28 : 0),
      0,
      1
    );
    metrics.cutback = candidate.label === "cutback" ? 1 : 0;
    metrics.secondBall = clamp(
      (isLongForwardPass && (receiverRoleKey === "striker" || receiverRoleKey === "secondStriker") ? 0.68 : 0) +
        (isLongForwardPass ? clamp(candidate.supportNearTarget ?? 0, 0, 3) * 0.12 : 0) +
        (profile.routeOneBias >= 0.55 ? 0.22 : 0),
      0,
      1
    );
    metrics.counterAttack = clamp(
      (forwardGain >= 10 && passDistance >= 12 ? 0.44 : 0) +
        (targetGoalDistance <= goalDistance - 8 ? 0.32 : 0) +
        (profile.directness >= 0.68 ? 0.18 : 0) +
        (actionSpace.openTarget >= 0.62 && forwardGain >= 7 ? 0.16 : 0),
      0,
      1
    );
    metrics.restDefence = clamp(
      ((receiverRoleKey === "pivot" || receiverRoleKey === "rest" || receiverRoleKey === "gk") && targetDepth <= 58 ? 0.56 : 0) +
        (forwardGain <= -4 && model.rhythm.steps <= 1 ? 0.22 : 0),
      0,
      1
    );
  }

  if (candidate.actionType === "dribble") {
    metrics.driveSpace = clamp(
      (forwardGain >= 4.5 ? 0.46 : 0) +
        (targetGoalDistance <= goalDistance - 3 ? 0.26 : 0) +
        Math.max(0, threatGain) * 0.28 +
        actionSpace.value * 0.18 +
        (model.flow.pressure <= 0.58 ? 0.18 : 0) +
        getPlayerTendency(carrier, "dribble") * 0.18,
      0,
      1
    );
    metrics.goldenZone = clamp(
      centralPocketScore * 0.58 +
        targetThreat.betweenLines * 0.22 +
        targetThreat.halfSpace * 0.16 +
        Math.max(0, threatGain) * 0.28 +
        (model.forwardFacingSpaceTwo.active && forwardGain >= 3 ? 0.26 : 0) +
        (targetGoalDistance <= goalDistance - 4 ? 0.12 : 0),
      0,
      1
    );
    metrics.breakLine = clamp(forwardGain / 18, 0, 0.72);
    metrics.breakLine = clamp(metrics.breakLine + clamp(actionSpace.lineBreakCount / 3, 0, 1) * 0.18, 0, 1);
    metrics.isolate1v1 = clamp(
      ((model.carrierRoleKey === "wideForward" || model.carrierRoleKey === "wideBack") && targetIsWide ? 0.52 : 0) +
        (model.flow.pressure >= 0.28 && model.flow.pressure <= 0.68 ? 0.16 : 0),
      0,
      1
    );
    metrics.counterAttack = clamp(
      (targetGoalDistance <= goalDistance - 7 ? 0.48 : 0) +
        (profile.directness >= 0.62 ? 0.22 : 0) +
        (forwardGain >= 10 ? 0.18 : 0),
      0,
      1
    );
  }

  if (candidate.actionType === "shot") {
    metrics.shoot = clamp(
      (insideBoxShot ? 0.82 : 0.38) +
        (candidate.mustShoot ? 0.28 : 0) +
        (candidate.laneClarity >= 0.45 ? 0.16 : 0),
      0,
      1
    );
    metrics.goldenZone = clamp(getPitchThreatProfile(startPoint, carrier.team).centralPocket * 0.74, 0, 1);
    metrics.cutback = insideBoxShot && model.rhythm.lastStep?.label === "cutback" ? 0.42 : 0;
  }

  if (model.regain?.active) {
    const transitionForce = model.regain.freshness;
    const counterFit = model.regain.counterIntent * transitionForce;
    const secureFit = model.regain.secureIntent * transitionForce;

    if (candidate.actionType === "pass") {
      metrics.secure = clamp(
        metrics.secure +
          secureFit * (passDistance <= 19 && receiverPressure <= 0.68 ? 0.46 : 0.16) +
          (supportRole ? 0.18 : 0),
        0,
        1.12
      );
      metrics.thirdPlayer = clamp(metrics.thirdPlayer + (supportRole ? secureFit * 0.2 : 0), 0, 1.08);
      metrics.counterAttack = clamp(
        metrics.counterAttack +
          counterFit * (forwardGain >= 6 ? 0.52 : 0.12) +
          (candidate.principleKey === "regain-forward-release" ? 0.38 : 0) +
          (targetGoalDistance <= goalDistance - 8 ? 0.16 : 0),
        0,
        1.15
      );
      metrics.breakLine = clamp(metrics.breakLine + counterFit * (candidate.isLineBreak ? 0.28 : 0.1), 0, 1.12);
      metrics.restDefence = clamp(
        metrics.restDefence +
          (forwardGain <= -3 && (receiverRoleKey === "pivot" || receiverRoleKey === "rest" || receiverRoleKey === "gk")
            ? secureFit * 0.24
            : 0),
        0,
        1.08
      );
    }

    if (candidate.actionType === "dribble") {
      metrics.driveSpace = clamp(metrics.driveSpace + counterFit * 0.34 + model.regain.forwardOpenSpace * 0.14, 0, 1.1);
      metrics.counterAttack = clamp(metrics.counterAttack + counterFit * (forwardGain >= 6 ? 0.34 : 0.08), 0, 1.08);
    }

    if (candidate.actionType === "shot") {
      metrics.shoot = clamp(metrics.shoot + counterFit * 0.16 + (goalDistance <= 28 ? 0.12 : 0), 0, 1.08);
    }
  }

  return metrics;
}

function getUniversalFootballDecisionAdjustment(candidate, carrier, startPoint, profile, model, metrics) {
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetThreat = getPitchThreatProfile(candidate.target, carrier.team);
  const startThreat = getPitchThreatProfile(startPoint, carrier.team);
  const threatGain = targetThreat.value - startThreat.value;
  const actionSpace = getActionSpaceValue(startPoint, candidate.target, carrier.team, profile);
  const targetDepth = getAttackingDepth(candidate.target, carrier.team);
  const pressure = model.flow.pressure;
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver
      ? getPlayerPressureLoad(receiver, candidate.target)
      : 0.45;
  const goalDistance = distance(startPoint, getOpponentGoalCenter(carrier.team));
  const labels = [];
  let score = 0;

  if (model.progressionWindow?.active) {
    const progressionUrgency = model.progressionWindow.urgency;
    const lowValueRecycle =
      candidate.actionType === "pass" &&
      forwardGain < 2 &&
      targetThreat.value <= startThreat.value + 0.04 &&
      actionSpace.lineBreakCount === 0 &&
      pressure <= 0.5;
    const progressiveAction =
      (candidate.actionType === "pass" || candidate.actionType === "dribble") &&
      forwardGain >= 4 &&
      (actionSpace.value >= 0.34 || actionSpace.lineBreakCount >= 1 || targetThreat.value >= 0.42);

    if (progressiveAction) {
      score += 0.18 + actionSpace.value * 0.48 + progressionUrgency * 0.22;
      labels.push("Exploit forward-facing advantage");
    }

    if (candidate.actionType === "shot" && goalDistance <= 33 && pressure <= 0.72) {
      score += 0.12 + progressionUrgency * 0.18;
      labels.push("Use open shooting window");
    }

    if (lowValueRecycle) {
      score -=
        0.38 +
        profile.progressionUrgency * 0.36 +
        model.progressionWindow.openLane * 0.28 +
        (forwardGain < -5 ? 0.18 : 0);
    }
  }

  if (model.regain?.active) {
    const regainFreshness = model.regain.freshness;
    const transitionIntent = model.regain.counterIntent * regainFreshness;
    const secureIntent = model.regain.secureIntent * regainFreshness;
    const isLowValueRecycle =
      candidate.actionType === "pass" &&
      forwardGain <= -5 &&
      targetThreat.value <= startThreat.value + 0.04 &&
      pressure <= 0.42;

    if (candidate.actionType === "pass" && passDistance <= 20 && receiverPressure <= 0.7) {
      score += secureIntent * 0.28;
      labels.push("Secure first pass");
    }

    if (
      (candidate.actionType === "pass" || candidate.actionType === "dribble") &&
      forwardGain >= 7 &&
      (threatGain >= 0.04 || model.regain.forwardOpenSpace >= 0.58)
    ) {
      score += 0.18 + transitionIntent * 0.42 + Math.max(0, threatGain) * 0.22;
      labels.push("Attack transition space");
    }

    if (isLowValueRecycle && profile.directness >= 0.58 && model.regain.pressure <= 0.48) {
      score -= 0.34 + transitionIntent * 0.28;
    }

    if (candidate.actionType === "shot" && (goalDistance <= 28 || targetThreat.box >= 0.28)) {
      score += 0.14 + transitionIntent * 0.22;
      labels.push("End transition with shot");
    }
  }

  if (targetThreat.value >= 0.62 || (targetThreat.betweenLines >= 0.48 && threatGain >= 0.08)) {
    score += 0.28 + targetThreat.value * 0.26 + Math.max(0, threatGain) * 0.42;
    labels.push(`Attack ${targetThreat.primaryLabel}`);
  }

  if (candidate.actionType === "shot" && (targetThreat.box >= 0.28 || startThreat.centralPocket >= 0.45)) {
    score += 0.22 + metrics.shoot * 0.28;
    labels.push("Find sweet spot");
  }

  if (
    candidate.actionType === "dribble" &&
    forwardGain >= 5 &&
    pressure <= 0.52 &&
    (metrics.driveSpace >= 0.48 || metrics.goldenZone >= 0.42)
  ) {
    score += 0.2 + metrics.driveSpace * 0.28 + Math.max(0, threatGain) * 0.32;
    labels.push("Drive past press");
  }

  if (
    model.forwardFacingSpaceTwo.active &&
    candidate.actionType === "pass" &&
    forwardGain < 2 &&
    targetThreat.value <= startThreat.value + 0.05 &&
    pressure <= 0.38
  ) {
    score -= 0.52 + profile.progressionUrgency * 0.32;
  }

  if (
    candidate.actionType === "pass" &&
    passDistance >= 30 &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    targetThreat.value < 0.52 &&
    profile.routeOneBias < 0.56
  ) {
    score -=
      0.42 +
      (1 - profile.directness) * 0.28 +
      ((candidate.supportNearTarget ?? 0) <= 0 ? 0.28 : 0);
  }

  if (
    candidate.actionType === "pass" &&
    targetDepth >= 58 &&
    forwardGain >= 7 &&
    metrics.breakLine >= 0.44 &&
    pressure <= 0.62
  ) {
    score += 0.18 + profile.lineBreakBias * 0.22;
    labels.push("Break the next line");
  }

  if (
    candidate.actionType === "pass" &&
    candidate.isSidewaysPass &&
    model.rhythm.sidewaysPasses >= 2 &&
    pressure <= 0.48 &&
    threatGain <= 0.03
  ) {
    score -= 0.34 + profile.progressionUrgency * 0.24;
  }

  return {
    score,
    labels: uniquePrincipleLabels(labels),
  };
}

function getAutoPilotVisionScanAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getPlayerDecisionContext(carrier);
  const intelligence = context.profile ?? buildPlayerIntelligenceProfile(carrier);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const actionAngle =
    candidate.actionType === "shot"
      ? angleBetween(startPoint, getOpponentGoalCenter(carrier.team))
      : angleBetween(startPoint, candidate.target);
  const bodyAngle = getPlayerFacingAngle(carrier);
  const angleGap = angleDifference(bodyAngle, actionAngle);
  const visibleCone = clamp(1 - angleGap / (Math.PI * 0.72), 0, 1);
  const peripheralVision = clamp(1 - angleGap / (Math.PI * 0.95), 0, 1);
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const laneShift = Math.abs(getPitchLaneIndex(candidate.target) - getPitchLaneIndex(startPoint));
  const targetThreat = getPitchThreatProfile(candidate.target, carrier.team);
  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const shortSupport =
    candidate.actionType === "pass" &&
    passDistance <= 18 &&
    forwardGain >= -7 &&
    (isSupportRole(receiverRoleKey) || receiverRoleKey === "rest" || receiverRoleKey === "gk");
  const highValueForward =
    forwardGain >= 4 &&
    (targetThreat.value >= 0.36 ||
      targetThreat.betweenLines >= 0.34 ||
      targetThreat.centralPocket >= 0.28 ||
      candidate.isLineBreak ||
      candidate.isBoxPass);
  const scanCapacity = clamp(
    intelligence.perception * 0.34 +
      intelligence.decisionQuality * 0.24 +
      intelligence.decisionSpeed * 0.18 +
      intelligence.tacticalDiscipline * 0.14 +
      intelligence.composure * 0.1 -
      pressure * (0.18 + (1 - intelligence.pressResistance) * 0.2),
    0,
    1
  );
  const actionComplexity = clamp(
    (passDistance >= 27 ? 0.22 : 0) +
      (laneShift >= 2 ? 0.2 : 0) +
      (candidate.isSwitch ? 0.16 : 0) +
      (candidate.isLineBreak ? 0.18 : 0) +
      (pattern.family === "third-player" ? 0.14 : 0) +
      (targetThreat.behindLine >= 0.28 ? 0.12 : 0) +
      (targetThreat.value >= 0.48 ? 0.1 : 0) +
      pressure * 0.16,
    0,
    1
  );
  const scanGap = actionComplexity - scanCapacity * 0.72 - peripheralVision * 0.34;
  const blindRisk = clamp(scanGap, 0, 1);
  const labels = [];
  let score = 0;

  if (visibleCone >= 0.64 && highValueForward) {
    score += 0.14 + scanCapacity * 0.16 + (profile.tempo ?? 0.5) * 0.04;
    labels.push("Vision: sees forward option");
  }

  if (shortSupport && pressure >= 0.48 && peripheralVision >= 0.48) {
    score += 0.12 + intelligence.decisionSpeed * 0.08 + intelligence.pressResistance * 0.06;
    labels.push("Vision: simple support angle");
  }

  if (
    candidate.actionType === "pass" &&
    (candidate.isSwitch || laneShift >= 2) &&
    passDistance >= 18
  ) {
    if (scanCapacity >= 0.72 && pressure <= 0.62) {
      score += 0.1 + intelligence.perception * 0.08 + (candidate.isSwitch ? 0.06 : 0);
      labels.push("Vision: scanned weak side");
    } else if (visibleCone < 0.34 && !candidate.isBoxPass) {
      score -= 0.18 + blindRisk * 0.32;
      labels.push("Vision: blind-side option");
    }
  }

  if (
    blindRisk >= 0.18 &&
    !shortSupport &&
    candidate.actionType !== "shot" &&
    !candidate.mustShoot
  ) {
    score -= 0.12 + blindRisk * 0.46;
  }

  if (
    candidate.actionType === "dribble" &&
    forwardGain >= 5 &&
    visibleCone >= 0.58 &&
    pressure <= 0.58
  ) {
    score += 0.1 + intelligence.decisionSpeed * 0.06;
    labels.push("Vision: carries what is open");
  }

  if (
    candidate.actionType === "pass" &&
    forwardGain <= -5 &&
    visibleCone < 0.28 &&
    pressure <= 0.46 &&
    targetThreat.value <= getPitchThreatProfile(startPoint, carrier.team).value + 0.04
  ) {
    score -= 0.16 + (profile.progressionUrgency ?? 0.5) * 0.16;
  }

  return {
    score: clamp(score, -0.9, 0.72),
    labels: uniquePrincipleLabels(labels),
    context: {
      visibleCone,
      peripheralVision,
      scanCapacity,
      actionComplexity,
      blindRisk,
      angleGap,
      pressure,
      highValueForward,
      shortSupport,
    },
  };
}

function scoreAutoPilotCandidateByIntentions(candidate, carrier, startPoint, profile) {
  const model = getAutoPilotIntentionModel(carrier, startPoint, profile);
  const metrics = getAutoPilotCandidatePrincipleMetrics(candidate, carrier, startPoint, profile, model);
  const decisionAdjustment = getUniversalFootballDecisionAdjustment(
    candidate,
    carrier,
    startPoint,
    profile,
    model,
    metrics
  );
  const weighted = Object.entries(metrics)
    .map(([key, value]) => ({
      key,
      value,
      score: value * (model.weights[key] ?? 0),
    }))
    .filter((entry) => entry.score > 0.06)
    .sort((a, b) => b.score - a.score);
  const score = clamp(
    weighted.reduce((total, entry) => total + entry.score, 0) * 0.42 + decisionAdjustment.score,
    -0.75,
    1.85
  );
  const labels = weighted
    .filter((entry) => entry.value >= 0.36)
    .slice(0, 3)
    .map((entry) => autoPilotPrincipleLabels[entry.key]);

  return {
    score,
    labels: uniquePrincipleLabels([...decisionAdjustment.labels, ...labels]),
    metrics,
    model,
  };
}

function getAutoPilotStylePrincipleWeights(profile) {
  return {
    ...autoPilotStylePrincipleWeights.balanced,
    ...(autoPilotStylePrincipleWeights[profile?.styleKey] ?? {}),
  };
}

function uniquePrincipleLabels(labels) {
  return [...new Set(labels.filter(Boolean))].slice(0, 3);
}

function getAutoPilotPrincipleAdjustment(candidate, carrier, startPoint, profile) {
  const weights = getAutoPilotStylePrincipleWeights(profile);
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const rhythm = getPossessionRhythmContext(carrier.team);
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const targetLaneKey = getPitchLaneKey(candidate.target);
  const startLaneKey = getPitchLaneKey(startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetLaneKey) - getPitchLaneIndex(startLaneKey));
  const targetDepth = getAttackingDepth(candidate.target, carrier.team);
  const targetIsWide = targetLaneKey === "leftWide" || targetLaneKey === "rightWide";
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[carrier.team]?.formation) : null);
  const labels = [];
  const intentionAdjustment = scoreAutoPilotCandidateByIntentions(candidate, carrier, startPoint, profile);
  let score = 0;

  if (candidate.principleLabel) {
    labels.push(candidate.principleLabel);
  }

  score += intentionAdjustment.score;
  labels.push(...intentionAdjustment.labels);

  if (candidate.actionType === "pass") {
    const sameWideLaneRepeat =
      targetIsWide && getRecentLaneRepeatCount(carrier.team, targetLaneKey, null, 4) >= 1;
    const changeCorridorCue =
      candidate.isSwitch ||
      (laneShift >= 2 &&
        passDistance >= 16 &&
        (rhythm.sidewaysPasses >= 1 || sameWideLaneRepeat || flow.pressure >= 0.44));

    if (changeCorridorCue) {
      score += 0.18 + weights.changeCorridor * 0.52 + Math.min(rhythm.sidewaysPasses, 3) * 0.12;
      labels.push("Change corridor");
    }

    const thirdPlayerCue =
      passDistance <= 24 &&
      forwardGain >= -1 &&
      (receiverRoleKey === "connector" ||
        receiverRoleKey === "pivot" ||
        receiverRoleKey === "secondStriker") &&
      (flow.consecutivePasses >= 1 || flow.carrierJustReceived || profile.shortSupport >= 0.7);

    if (thirdPlayerCue) {
      score +=
        0.2 +
        weights.thirdPlayer * 0.46 +
        (receiver ? getPlayerTendency(receiver, "passAndMove") : 0.5) * 0.18;
      labels.push("Find the Third");
    }

    const highestPointCue =
      receiverRoleKey === "striker" && forwardGain >= 5.5 && passDistance <= 28 && targetDepth >= 46;

    if (highestPointCue) {
      score += 0.12 + profile.lineBreakBias * 0.22 + weights.directTransition * 0.18;
      labels.push("Exit: highest point");
    }

    const wideQuestionCue =
      receiverRoleKey === "wideForward" && targetIsWide && targetDepth >= 42 && forwardGain >= -2;

    if (wideQuestionCue) {
      score += 0.18 + weights.wideQuestion * 0.5 + profile.widthDiscipline * 0.16;
      labels.push("Ask question wide");
    }

    const finalThirdCombinationCue =
      targetDepth >= 64 &&
      (candidate.isBoxPass ||
        candidate.label === "cutback" ||
        candidate.label === "cross" ||
        receiverRoleKey === "connector" ||
        receiverRoleKey === "secondStriker");

    if (finalThirdCombinationCue) {
      score += 0.16 + weights.finalThirdCombination * 0.42;
      labels.push(candidate.label === "cutback" ? "Cutback zone" : "Final-third combination");
    }
  }

  if (candidate.actionType === "dribble") {
    const goal = getOpponentGoalCenter(carrier.team);
    const goalDistance = distance(startPoint, goal);
    const targetGoalDistance = distance(candidate.target, goal);
    const drivePastPressCue =
      forwardGain >= 4.5 &&
      targetGoalDistance <= goalDistance - 3 &&
      flow.pressure <= 0.58;

    if (drivePastPressCue) {
      score += 0.18 + profile.carryBias * 0.28 + weights.directTransition * 0.26;
      labels.push(targetDepth >= 58 ? "Attack open space" : "Drive past press");
    }
  }

  if (candidate.actionType === "shot") {
    if (candidate.insideBox) {
      score += 0.22 + weights.finalThirdCombination * 0.18;
      labels.push("Find sweet spot");
    } else if ((candidate.goalDistance ?? passDistance) >= 23) {
      score += 0.08 + profile.shootBias * 0.16;
      labels.push("Distance shooting");
    }
  }

  return {
    score,
    labels: uniquePrincipleLabels(labels),
  };
}

function getAutoPilotLaneRealityAdjustment(candidate, carrier, startPoint, profile) {
  if (candidate.actionType !== "pass" || !candidate.target) {
    return { score: 0, labels: [] };
  }

  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : computePassLaneClarity(carrier, candidate.target, {
        receiverPlayerId: candidate.receiverPlayerId ?? null,
      });
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const valuablePass =
    candidate.isLineBreak ||
    candidate.isBoxPass ||
    forwardGain >= 7 ||
    getActionSpaceValue(startPoint, candidate.target, carrier.team, profile).value >= 0.5;
  const labels = [];
  let score = 0;

  if (laneClarity < 0.24) {
    score -= valuablePass ? 0.78 : 0.48;
  } else if (laneClarity < 0.36) {
    score -= valuablePass || passDistance >= 20 ? 0.46 : 0.24;
  } else if (laneClarity < 0.48 && (valuablePass || passDistance >= 24)) {
    score -= 0.18;
  }

  if (laneClarity >= 0.74 && valuablePass) {
    score += 0.14 + (profile.lineBreakBias ?? 0.45) * 0.08;
    labels.push("Clean passing lane");
  }

  if (laneClarity >= 0.82 && candidate.isSwitch) {
    score += 0.08 + (profile.switchBias ?? 0) * 0.08;
    labels.push("Safe switch lane");
  }

  if (candidate.isBoxPass && laneClarity < 0.42) {
    score -= 0.18;
  }

  return {
    score: clamp(score, -0.9, 0.38),
    labels: uniquePrincipleLabels(labels),
  };
}

function getAutoPilotCandidateReceiver(candidate, carrier) {
  if (!candidate || candidate.actionType !== "pass") {
    return null;
  }

  if (candidate.receiverPlayerId) {
    return getPlayerById(candidate.receiverPlayerId);
  }

  if (candidate.principleRunnerPlayerId) {
    return getPlayerById(candidate.principleRunnerPlayerId);
  }

  return getPotentialPassReceiverAtTarget(carrier, candidate.target);
}

function getAutoPilotRoleResponsibilityAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const roleKey = getOffensiveRoleKey(carrier, formation);
  const pattern = getAutoPilotCandidatePattern(candidate, carrier, startPoint);
  const family = pattern.family;
  const receiver = getAutoPilotCandidateReceiver(candidate, carrier);
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    pattern.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, formation) : null);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const targetThreat =
    candidate.actionType === "shot"
      ? startThreat
      : getPitchThreatProfile(candidate.target, teamId);
  const actionSpace =
    candidate.actionType === "shot"
      ? {
          value: startThreat.value,
          lineBreakCount: 0,
          openTarget: 0,
          targetPressure: getOpponentPressureAtPoint(teamId, startPoint),
          targetThreat,
          startThreat,
        }
      : getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const forwardGain = pattern.forwardGain;
  const passDistance = pattern.passDistance;
  const depth = getAttackingDepth(startPoint, teamId);
  const targetDepth = candidate.actionType === "shot" ? depth : getAttackingDepth(candidate.target, teamId);
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, candidate.target, {
          receiverPlayerId: candidate.receiverPlayerId ?? null,
        })
      : actionSpace.openTarget ?? 0.55;
  const principleText = [
    candidate.principleKey,
    candidate.principleLabel,
    ...(candidate.principleLabels ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const supportReceiver =
    receiverRoleKey === "gk" ||
    receiverRoleKey === "rest" ||
    receiverRoleKey === "wideBack" ||
    receiverRoleKey === "pivot" ||
    receiverRoleKey === "connector";
  const forwardReceiver = isFrontLineRole(receiverRoleKey);
  const wideAction =
    family === "wide-overload" ||
    family === "cross" ||
    family === "cutback" ||
    principleText.includes("wide") ||
    principleText.includes("overlap");
  const highValueAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.value >= 0.58 ||
    targetThreat.box >= 0.2 ||
    targetThreat.centralPocket >= 0.34 ||
    (actionSpace.lineBreakCount ?? 0) >= 1;
  const lowValueReset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain < 1.5 &&
    targetThreat.value <= startThreat.value + 0.04 &&
    (actionSpace.lineBreakCount ?? 0) === 0 &&
    pressure <= 0.58;
  const labels = [];
  let score = 0;

  const add = (amount, label = null) => {
    score += amount;
    if (label) {
      labels.push(label);
    }
  };

  if (roleKey === "gk") {
    if (
      candidate.actionType === "pass" &&
      ["rest", "wideBack", "pivot"].includes(receiverRoleKey) &&
      passDistance <= 34
    ) {
      add(0.24, "Role fit: first build pass");
    }

    if (
      candidate.actionType === "pass" &&
      forwardReceiver &&
      (pressure >= 0.5 || (profile.directness ?? 0.5) >= 0.62)
    ) {
      add(0.14, "Role fit: pressure release");
    }

    if (candidate.actionType === "dribble") {
      add(-0.48);
    }

    if (candidate.actionType === "shot") {
      add(-0.9);
    }
  } else if (roleKey === "rest") {
    if (
      candidate.actionType === "pass" &&
      ["gk", "rest", "wideBack", "pivot"].includes(receiverRoleKey) &&
      depth < 58 &&
      pressure <= 0.62
    ) {
      add(0.14, "Role fit: secure first line");
    }

    if (candidate.actionType === "pass" && (candidate.isSwitch || family === "switch") && laneClarity >= 0.5) {
      add(0.18, "Role fit: change corridor");
    }

    if (candidate.actionType === "pass" && candidate.isLineBreak && laneClarity >= 0.44) {
      add(0.16, "Role fit: break first pressure");
    }

    if (candidate.actionType === "dribble" && forwardGain >= 4 && pressure <= 0.42 && depth < 58) {
      add(0.1, "Role fit: step in");
    }

    if (candidate.actionType === "shot" || (targetDepth >= 72 && !highValueAction)) {
      add(-0.36);
    }

    if (candidate.actionType === "pass" && passDistance >= 34 && !candidate.isSwitch && !candidate.isLineBreak) {
      add(-0.26, "Role check: avoid hopeful long ball");
    }
  } else if (roleKey === "wideBack") {
    if (wideAction || candidate.isBoxPass) {
      add(0.24, "Role fit: wide relation");
    }

    if (candidate.actionType === "pass" && (candidate.isSwitch || family === "switch")) {
      add(0.1, "Role fit: weak-side switch");
    }

    if (
      candidate.actionType === "pass" &&
      ["wideForward", "connector"].includes(receiverRoleKey) &&
      forwardGain >= -2
    ) {
      add(0.13, "Role fit: connect outside lane");
    }

    if (candidate.actionType === "dribble" && forwardGain >= 5 && targetThreat.wideCorridor >= 0.3) {
      add(0.12, "Role fit: carry the flank");
    }

    if (candidate.actionType === "shot" && targetThreat.box < 0.22) {
      add(-0.34);
    }

    if (lowValueReset && depth >= 52 && pressure <= 0.46) {
      add(-0.24, "Role check: keep wide attack alive");
    }
  } else if (roleKey === "pivot") {
    if (candidate.actionType === "pass" && supportReceiver && pressure >= 0.42 && passDistance <= 20) {
      add(0.14, "Role fit: play out of pressure");
    }

    if (candidate.actionType === "pass" && (candidate.isSwitch || family === "switch") && laneClarity >= 0.48) {
      add(0.2, "Role fit: switch from six");
    }

    if (
      candidate.actionType === "pass" &&
      (candidate.isLineBreak || targetThreat.centralPocket >= 0.28 || actionSpace.targetGameSpaceKey === "space2") &&
      forwardGain >= 4.5
    ) {
      add(0.22, "Role fit: find space two");
    }

    if (candidate.actionType === "dribble" && forwardGain >= 4 && pressure <= 0.34) {
      add(0.08, "Role fit: carry through midfield");
    }

    if (candidate.actionType === "shot" && depth < 68) {
      add(-0.44);
    }

    if (candidate.actionType === "dribble" && targetDepth >= 74 && pressure >= 0.34) {
      add(-0.2);
    }
  } else if (roleKey === "connector") {
    if (
      candidate.actionType === "pass" &&
      (candidate.isLineBreak || family === "third-player" || targetThreat.centralPocket >= 0.3 || highValueAction)
    ) {
      add(0.23, "Role fit: connect and break lines");
    }

    if (candidate.actionType === "dribble" && forwardGain >= 4 && pressure <= 0.56) {
      add(0.17, "Role fit: drive between lines");
    }

    if (candidate.actionType === "shot" && (depth >= 64 || startThreat.centralPocket >= 0.32 || startThreat.box >= 0.16)) {
      add(0.18, "Role fit: attack the box");
    }

    if (candidate.actionType === "pass" && wideAction && receiverRoleKey === "wideBack") {
      add(0.08, "Role fit: release overlap");
    }

    if (lowValueReset && depth >= 45 && pressure <= 0.5) {
      add(-0.38, "Role check: protect forward advantage");
    }
  } else if (roleKey === "wideForward") {
    if (candidate.actionType === "dribble" && forwardGain >= 3) {
      add(0.22, "Role fit: attack outside lane");
    }

    if (wideAction || candidate.isBoxPass) {
      add(0.22, "Role fit: create from wide");
    }

    if (candidate.actionType === "shot" && (depth >= 66 || startThreat.box >= 0.18 || startThreat.halfSpace >= 0.32)) {
      add(0.18, "Role fit: finish from front line");
    }

    if (candidate.actionType === "pass" && ["wideBack", "connector"].includes(receiverRoleKey) && pressure >= 0.38) {
      add(0.08, "Role fit: bounce and move");
    }

    if (lowValueReset && depth >= 50 && pressure <= 0.5) {
      add(-0.36, "Role check: threaten before reset");
    }
  } else if (roleKey === "striker" || roleKey === "secondStriker") {
    if (candidate.actionType === "shot") {
      add(0.28, "Role fit: finish attack");
    }

    if (
      candidate.actionType === "pass" &&
      (candidate.isBoxPass || candidate.isLineBreak || family === "front-line" || highValueAction)
    ) {
      add(0.17, "Role fit: combine in final line");
    }

    if (candidate.actionType === "pass" && supportReceiver && passDistance <= 16 && pressure >= 0.36) {
      add(0.12, "Role fit: set and spin");
    }

    if (candidate.actionType === "dribble" && forwardGain >= 3 && (depth >= 58 || targetThreat.box >= 0.16)) {
      add(0.14, "Role fit: attack goal");
    }

    if (lowValueReset && pressure <= 0.5) {
      add(-0.38, "Role check: keep final-line threat");
    }

    if (candidate.actionType === "pass" && ["gk", "rest"].includes(receiverRoleKey) && depth >= 48) {
      add(-0.42, "Role check: avoid deep reset from front line");
    }
  }

  if (
    candidate.actionType === "pass" &&
    receiverRoleKey === "gk" &&
    depth >= 42 &&
    pressure <= 0.52 &&
    !candidate.isSwitch
  ) {
    add(-0.36, "Role check: avoid unnecessary goalkeeper reset");
  }

  if (
    highValueAction &&
    candidate.actionType !== "shot" &&
    laneClarity >= 0.56 &&
    ["pivot", "connector", "wideForward", "striker", "secondStriker"].includes(roleKey)
  ) {
    add(0.08, "Role fit: take the advantage");
  }

  return {
    score: clamp(score, -1.05, 0.9),
    labels: uniquePrincipleLabels(labels),
    context: {
      roleKey,
      receiverRoleKey,
      family,
      highValueAction,
      lowValueReset,
      pressure,
      depth,
      targetDepth,
      laneClarity,
    },
  };
}

function getAutoPilotLocalSuperiorityProfile(teamId, point, excludedIds = new Set(), radius = 15) {
  if (!teamId || !point) {
    return {
      supportCount: 0,
      opponentCount: 0,
      closeOpponents: 0,
      underSupport: false,
      forwardSupport: false,
      lateralSupport: false,
      geometryScore: 0,
    };
  }

  const attackSign = getAttackDirectionSign(teamId);
  const teammates = [];
  const opponents = [];
  let closeOpponents = 0;
  let underSupport = false;
  let forwardSupport = false;
  let lateralSupport = false;
  const supportSectors = new Set();

  state.players.forEach((player) => {
    if (isGoalkeeper(player)) {
      return;
    }

    const gap = distance(player.position, point);
    if (gap > radius) {
      return;
    }

    if (player.team === teamId) {
      if (excludedIds.has(player.id)) {
        return;
      }

      teammates.push(player);
      const forwardOffset = (player.position.x - point.x) * attackSign;
      const lateralOffset = player.position.y - point.y;

      if (forwardOffset <= -2.2 && Math.abs(lateralOffset) <= 17) {
        underSupport = true;
        supportSectors.add("under");
      }

      if (forwardOffset >= 3.2 && Math.abs(lateralOffset) <= 18) {
        forwardSupport = true;
        supportSectors.add("ahead");
      }

      if (Math.abs(lateralOffset) >= 6.8) {
        lateralSupport = true;
        supportSectors.add(lateralOffset > 0 ? "outsidePlus" : "outsideMinus");
      }

      if (Math.abs(forwardOffset) <= 5 && Math.abs(lateralOffset) <= 9) {
        supportSectors.add("bounce");
      }
      return;
    }

    opponents.push(player);
    if (gap <= 5.5) {
      closeOpponents += 1;
    }
  });

  const supportCount = teammates.length;
  const opponentCount = opponents.length;
  const sectorVariety = supportSectors.size;
  const geometryScore = clamp(
    (underSupport ? 0.28 : 0) +
      (lateralSupport ? 0.2 : 0) +
      (forwardSupport ? 0.18 : 0) +
      clamp(supportCount / 3, 0, 1) * 0.22 +
      clamp(sectorVariety / 4, 0, 1) * 0.18 -
      clamp(closeOpponents / 3, 0, 1) * 0.16,
    0,
    1
  );

  return {
    supportCount,
    opponentCount,
    closeOpponents,
    underSupport,
    forwardSupport,
    lateralSupport,
    sectorVariety,
    geometryScore,
  };
}

function getAutoPilotLocalSuperiorityAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier?.team || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const receiver = getAutoPilotCandidateReceiver(candidate, carrier);
  const receiverId = receiver?.team === teamId ? receiver.id : candidate.receiverPlayerId ?? null;
  const excludedIds = new Set([
    carrier.id,
    receiverId,
    candidate.principleRunnerPlayerId,
  ].filter(Boolean));
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const radius =
    candidate.actionType === "dribble"
      ? 13.5
      : passDistance >= 26
        ? 17
        : 14.5;
  const local = getAutoPilotLocalSuperiorityProfile(teamId, candidate.target, excludedIds, radius);
  const actionSpace = candidate.actionType === "shot"
    ? null
    : getActionSpaceValue(startPoint, candidate.target, teamId, profile);
  const targetThreat = candidate.actionType === "shot"
    ? getPitchThreatProfile(startPoint, teamId)
    : getPitchThreatProfile(candidate.target, teamId);
  const startThreat = getPitchThreatProfile(startPoint, teamId);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver?.team === teamId
      ? getPlayerPressureLoad(receiver, candidate.target)
      : actionSpace?.targetPressure ?? getOpponentPressureAtPoint(teamId, candidate.target, 11);
  const openTarget = actionSpace?.openTarget ?? clamp((getNearestOpponentGapToPoint(teamId, candidate.target) - 2.2) / 8.8, 0, 1);
  const targetDepth = getAttackingDepth(candidate.target, teamId);
  const highValueAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.isLineBreak ||
    targetThreat.box >= 0.22 ||
    targetThreat.cutbackZone >= 0.24 ||
    targetThreat.centralPocket >= 0.34 ||
    targetThreat.behindLine >= 0.28 ||
    (actionSpace?.lineBreakCount ?? 0) >= 1;
  const localPresence = local.supportCount + (candidate.actionType === "dribble" ? 1 : 0);
  const numericalBalance = localPresence - local.opponentCount;
  const playableTriangle = local.underSupport && local.lateralSupport && local.geometryScore >= 0.48;
  const isolatedTarget =
    candidate.actionType !== "shot" &&
    local.supportCount <= 0 &&
    local.opponentCount >= 1 &&
    receiverPressure >= 0.5 &&
    openTarget < 0.58;
  const underloadedAction =
    candidate.actionType !== "shot" &&
    numericalBalance <= -1 &&
    local.closeOpponents >= 1 &&
    openTarget < 0.5;
  const crowdedSameSide =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    local.supportCount >= 3 &&
    local.opponentCount >= 3 &&
    forwardGain < 4 &&
    targetThreat.value <= startThreat.value + 0.05 &&
    targetDepth < 74;
  const noBounceForPressedReceiver =
    candidate.actionType === "pass" &&
    receiverPressure >= 0.62 &&
    !local.underSupport &&
    !local.lateralSupport &&
    !highValueAction;
  const switchIntoWeakSide =
    candidate.actionType === "pass" &&
    candidate.isSwitch &&
    (local.supportCount >= 1 || openTarget >= 0.62) &&
    local.opponentCount <= 2;
  const dribbleWithSupport =
    candidate.actionType === "dribble" &&
    forwardGain >= 3 &&
    openTarget >= 0.5 &&
    (local.underSupport || local.lateralSupport || local.supportCount >= 2);
  const labels = [];
  let score = 0;

  if (playableTriangle) {
    score += 0.22 + (profile.shortSupport ?? 0.5) * 0.12;
    labels.push("Local superiority: playable triangle");
  } else if (local.geometryScore >= 0.6 && local.supportCount >= 2) {
    score += 0.14 + (profile.shortSupport ?? 0.5) * 0.08;
    labels.push("Local superiority: support around ball");
  }

  if (switchIntoWeakSide) {
    score += 0.18 + (profile.switchBias ?? 0.5) * 0.12;
    labels.push("Local superiority: weak-side access");
  }

  if (dribbleWithSupport) {
    score += 0.12 + (profile.carryBias ?? 0.5) * 0.08;
    labels.push("Local superiority: carry with support");
  }

  if (isolatedTarget && !highValueAction) {
    score -= 0.42 + receiverPressure * 0.18;
    labels.push("Avoid isolated target");
  } else if (isolatedTarget && highValueAction && openTarget < 0.42) {
    score -= 0.18;
  }

  if (underloadedAction && !highValueAction) {
    score -= 0.32 + Math.abs(numericalBalance) * 0.1;
    labels.push("Avoid playing into underload");
  }

  if (crowdedSameSide) {
    score -= 0.3 + (profile.progressionUrgency ?? 0.5) * 0.12;
    labels.push("Avoid same-side crowd");
  }

  if (noBounceForPressedReceiver) {
    score -= 0.2 + receiverPressure * 0.12;
    labels.push("Receiver needs a bounce option");
  }

  if (
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    forwardGain >= 4 &&
    local.underSupport &&
    openTarget >= 0.42 &&
    receiverPressure <= 0.66
  ) {
    score += 0.1 + (profile.tempo ?? 0.5) * 0.08;
  }

  return {
    score: clamp(score, -0.95, 0.72),
    labels: uniquePrincipleLabels(labels),
    context: {
      supportCount: local.supportCount,
      opponentCount: local.opponentCount,
      closeOpponents: local.closeOpponents,
      underSupport: local.underSupport,
      lateralSupport: local.lateralSupport,
      forwardSupport: local.forwardSupport,
      geometryScore: local.geometryScore,
      numericalBalance,
      receiverPressure,
      openTarget,
      isolatedTarget,
      underloadedAction,
      crowdedSameSide,
      playableTriangle,
    },
  };
}

function getReceiverAvailabilityProfile(candidate, carrier, startPoint, profile) {
  const receiver = getAutoPilotCandidateReceiver(candidate, carrier);
  if (!receiver || receiver.team !== carrier.team || !candidate?.target) {
    return null;
  }

  const target = candidate.target;
  const roleKey =
    candidate.receiverRoleKey ??
    getOffensiveRoleKey(receiver, teams[carrier.team]?.formation);
  const pressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : getPlayerPressureLoad(receiver, target);
  const receiveOrientation = getReceiveOrientationScore(receiver, startPoint);
  const receiveFoot = getReceiveFootUsageScore(receiver, startPoint);
  const context = getPlayerDecisionContext(receiver);
  const attackSign = getAttackDirectionSign(receiver.team);
  const nearestGap = getNearestOpponentGap(receiver, target);
  const receiveSpace = clamp((nearestGap - 1.4) / 5.4, 0, 1);
  const exitPoint = clampToPitch({
    x: target.x + attackSign * (isSupportRole(roleKey) ? 3.2 : 5.4),
    y: lerp(target.y, pitch.width / 2, isWideChannel(target) ? 0.22 : 0.08),
  }, 2);
  const exitGap = getNearestOpponentGap(receiver, exitPoint);
  const firstActionSpace = clamp((exitGap - 1.8) / 5.8, 0, 1);
  let goalSidePressure = 0;
  let touchTrap = 0;
  let closeMarkers = 0;

  state.players.forEach((opponent) => {
    if (opponent.team === receiver.team) {
      return;
    }

    const gap = distance(opponent.position, target);
    if (gap > 7.5) {
      return;
    }

    const goalSide = (opponent.position.x - target.x) * attackSign;
    const closeness = clamp(1 - gap / 7.5, 0, 1);
    const coverInfluence = getCoverShadowInfluence(opponent, target, startPoint);

    if (gap <= 3.2) {
      closeMarkers += 1;
    }

    if (goalSide >= -0.7 && goalSide <= 7.5) {
      goalSidePressure = Math.max(
        goalSidePressure,
        closeness * (0.58 + coverInfluence * 0.42)
      );
    }

    touchTrap += closeness * coverInfluence * 0.28;
  });

  const technicalSecurity =
    context.profile.technicalSecurity * 0.34 +
    context.profile.pressResistance * 0.26 +
    context.profile.composure * 0.18 +
    context.profile.perception * 0.12;
  const availability = clamp(
    receiveSpace * 0.28 +
      (1 - pressure) * 0.2 +
      receiveOrientation * 0.18 +
      receiveFoot * 0.08 +
      firstActionSpace * 0.16 +
      technicalSecurity * 0.18 -
      goalSidePressure * 0.24 -
      Math.min(touchTrap, 1.2) * 0.1 -
      Math.min(closeMarkers, 2) * 0.04,
    0,
    1
  );

  return {
    receiver,
    roleKey,
    availability,
    pressure,
    nearestGap,
    receiveSpace,
    firstActionSpace,
    receiveOrientation,
    goalSidePressure,
    closeMarkers,
  };
}

function getAutoPilotReceiverAvailabilityAdjustment(candidate, carrier, startPoint, profile) {
  if (candidate.actionType !== "pass" || !candidate.target) {
    return { score: 0, labels: [] };
  }

  const availabilityProfile = getReceiverAvailabilityProfile(candidate, carrier, startPoint, profile);
  if (!availabilityProfile) {
    return { score: 0, labels: [] };
  }

  const {
    availability,
    roleKey,
    pressure,
    nearestGap,
    firstActionSpace,
    receiveOrientation,
    goalSidePressure,
  } = availabilityProfile;
  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const supportRole = isSupportRole(roleKey) || roleKey === "gk" || roleKey === "rest";
  const forwardRole = isFrontLineRole(roleKey);
  const highValuePass = candidate.isLineBreak || candidate.isBoxPass || forwardGain >= 7;
  const labels = [];
  let score = 0;

  if (availability <= 0.26) {
    score -= highValuePass || passDistance >= 18 ? 0.62 : 0.34;
  } else if (availability <= 0.38) {
    score -= highValuePass ? 0.36 : 0.18;
  }

  if (pressure >= 0.72 && nearestGap <= 2.2 && receiveOrientation < 0.56) {
    score -= supportRole ? 0.22 : 0.36;
  }

  if (goalSidePressure >= 0.58 && forwardRole && passDistance <= 24) {
    score -= 0.18;
  }

  if (availability >= 0.66 && firstActionSpace >= 0.48) {
    score += 0.14 + (supportRole ? (profile.shortSupport ?? 0) * 0.08 : (profile.lineBreakBias ?? 0) * 0.08);
    labels.push("Available receiver");
  }

  if (availability >= 0.72 && highValuePass && pressure <= 0.48) {
    score += 0.14;
    labels.push("Receive and play forward");
  }

  if (supportRole && passDistance <= 18 && availability >= 0.52 && pressure <= 0.62) {
    score += 0.08 + (profile.shortSupport ?? 0) * 0.08;
  }

  return {
    score: clamp(score, -0.76, 0.42),
    labels: uniquePrincipleLabels(labels),
    availability,
  };
}

function getAutoPilotReceivePressureTrapAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (candidate.actionType !== "pass" || !candidate.target) {
    return { score: 0, labels: [], context: null };
  }

  const receiver = getAutoPilotCandidateReceiver(candidate, carrier);
  if (!receiver || receiver.team !== carrier.team) {
    return { score: 0, labels: [], context: null };
  }

  const target = candidate.target;
  const roleKey =
    candidate.receiverRoleKey ??
    getOffensiveRoleKey(receiver, teams[carrier.team]?.formation);
  const attackSign = getAttackDirectionSign(receiver.team);
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * attackSign);
  const supportRole = isSupportRole(roleKey) || roleKey === "gk" || roleKey === "rest";
  const forwardRole = isFrontLineRole(roleKey);
  const touchlineTrap = isWideChannel(target);
  const laneRisk = getPassLaneRiskProfile(carrier, target, {
    receiverPlayerId: receiver.id,
  });
  const ballEta = passDistance / Math.max(laneRisk.averageSpeed ?? 11.5, 0.01);
  const receiverContext = getPlayerDecisionContext(receiver);
  const receiveOrientation = getReceiveOrientationScore(receiver, startPoint);
  const receiveFoot = getReceiveFootUsageScore(receiver, startPoint);
  const exitPoint = clampToPitch({
    x: target.x + attackSign * (supportRole ? 4.2 : 6.4),
    y: lerp(target.y, pitch.width / 2, touchlineTrap ? 0.32 : 0.12),
  }, 2);
  const exitGap = getNearestOpponentGap(receiver, exitPoint);
  const exitSpace = clamp((exitGap - 1.8) / 6, 0, 1);
  let trapPressure = 0;
  let closeJumpers = 0;
  let fastestTrapTime = Infinity;
  let blindSidePressure = 0;

  state.players.forEach((opponent) => {
    if (opponent.team === receiver.team) {
      return;
    }

    const gap = distance(opponent.position, target);
    if (gap > 9) {
      return;
    }

    const projection = projectPointOnSegmentWithRatio(opponent.position, startPoint, target);
    const laneDistance = distance(opponent.position, projection.point);
    const lateLane =
      projection.ratio >= 0.72 &&
      projection.ratio <= 1.02 &&
      laneDistance <= 4.2;
    const defenderReachDistance = Math.max(
      gap - playerRadiusMeters * 0.75 - ballRadiusMeters * 0.35,
      0
    );
    const defenderTime = computeTimeToCoverDistance(opponent, defenderReachDistance, target);
    const canArrive = defenderTime <= ballEta + 0.58;
    const closeness = clamp(1 - gap / 9, 0, 1);
    const coverInfluence = getCoverShadowInfluence(opponent, target, startPoint);
    const goalSide = (opponent.position.x - target.x) * attackSign;
    const goalSidePressure = goalSide >= -1.2 && goalSide <= 7.5;
    const receiverFacing = getPlayerFacingAngle(receiver);
    const defenderAngle = angleBetween(target, opponent.position);
    const blindSide = angleDifference(receiverFacing, defenderAngle) >= Math.PI / 2.15;
    const trapInfluence =
      closeness *
      (0.28 +
        coverInfluence * 0.28 +
        (blindSide ? 0.18 : 0) +
        (goalSidePressure ? 0.18 : 0) +
        (lateLane && canArrive ? 0.22 : 0) +
        (touchlineTrap && goalSidePressure ? 0.14 : 0));

    trapPressure += trapInfluence;
    fastestTrapTime = Math.min(fastestTrapTime, defenderTime);
    blindSidePressure = Math.max(blindSidePressure, blindSide ? closeness : 0);

    if ((canArrive && gap <= 4.2) || (lateLane && canArrive)) {
      closeJumpers += 1;
    }
  });

  trapPressure = clamp(trapPressure, 0, 1.4);
  const receiverQuality =
    receiverContext.profile.technicalSecurity * 0.3 +
    receiverContext.profile.pressResistance * 0.24 +
    receiverContext.profile.composure * 0.18 +
    receiverContext.profile.perception * 0.16 +
    receiverContext.profile.decisionSpeed * 0.12;
  const escapeQuality = clamp(
    receiveOrientation * 0.22 +
      receiveFoot * 0.1 +
      exitSpace * 0.22 +
      receiverQuality * 0.32 +
      (1 - (candidate.receiverPressure ?? getPlayerPressureLoad(receiver, target))) * 0.14 -
      trapPressure * 0.34 -
      Math.min(laneRisk.coverShadow ?? 0, 2) * 0.05,
    0,
    1
  );
  const labels = [];
  let score = 0;

  if (trapPressure >= 0.72 && escapeQuality < 0.52) {
    score -= 0.34 + (trapPressure - escapeQuality) * 0.46 + (touchlineTrap ? 0.12 : 0);
    labels.push("Receive trap: avoid locked feet");
  } else if (escapeQuality >= 0.68 && trapPressure <= 0.74) {
    score += 0.12 + exitSpace * 0.12 + receiverQuality * 0.08;
    labels.push("Receive trap: first touch can escape");
  }

  if (closeJumpers >= 2 && !supportRole) {
    score -= 0.14 + Math.min(closeJumpers - 1, 2) * 0.06;
  }

  if (supportRole && passDistance <= 18 && escapeQuality >= 0.56) {
    score += 0.06 + (profile.shortSupport ?? 0) * 0.05;
    labels.push("Receive trap: clean bounce option");
  }

  if (forwardRole && forwardGain >= 5 && blindSidePressure >= 0.45 && escapeQuality < 0.6) {
    score -= 0.14;
  }

  return {
    score: clamp(score, -0.92, 0.52),
    labels: uniquePrincipleLabels(labels),
    context: {
      receiverId: receiver.id,
      trapPressure: Number(trapPressure.toFixed(3)),
      escapeQuality: Number(escapeQuality.toFixed(3)),
      closeJumpers,
      fastestTrapTime: Number.isFinite(fastestTrapTime)
        ? Number(fastestTrapTime.toFixed(2))
        : null,
      exitSpace: Number(exitSpace.toFixed(3)),
    },
  };
}

function estimateAutoPilotCandidateDuration(candidate, carrier, startPoint) {
  if (!candidate?.target || !carrier || !startPoint) {
    return 0;
  }

  const actionDistance = distance(startPoint, candidate.target);
  if (actionDistance <= 0.01) {
    return 0;
  }

  const actionProfile = resolveBallActionProfile(
    candidate.actionType,
    startPoint,
    candidate.target,
    carrier,
    candidate.receiverPlayerId ?? null,
    "auto"
  );

  return actionDistance / Math.max(actionProfile.averageSpeed ?? 8, 0.01);
}

function getNextSupportSlotRoleFit(roleKey, slot) {
  const slotFits = {
    under: { pivot: 0.42, connector: 0.36, wideBack: 0.26, rest: 0.22, secondStriker: 0.1 },
    inside: { connector: 0.42, pivot: 0.26, wideForward: 0.24, secondStriker: 0.24, wideBack: 0.12 },
    outside: { wideBack: 0.44, wideForward: 0.34, connector: 0.08 },
    beyond: { striker: 0.42, wideForward: 0.34, secondStriker: 0.34, connector: 0.12 },
    weakSide: { wideForward: 0.38, wideBack: 0.3, connector: 0.14 },
    restLink: { rest: 0.42, pivot: 0.34, wideBack: 0.12 },
  };

  return slotFits[slot]?.[roleKey] ?? 0;
}

function getAutoPilotNextSupportNetworkProfile(candidate, carrier, startPoint, profile) {
  if (!candidate?.target || !carrier || !startPoint || candidate.actionType === "shot") {
    return null;
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const receiver = getAutoPilotCandidateReceiver(candidate, carrier);
  const targetDepth = getAttackingDepth(target, teamId);
  const targetIsWide = isWidePrincipleZone(target);
  const targetThreat = getPitchThreatProfile(target, teamId);
  const actionDuration = estimateAutoPilotCandidateDuration(candidate, carrier, startPoint);
  const arrivalWindow =
    actionDuration +
    0.38 +
    (profile.shortSupport ?? 0.55) * 0.32 +
    (candidate.actionType === "dribble" ? 0.34 : 0);
  const sideSign =
    getWideSideSign(target) ||
    getWideSideSign(receiver) ||
    getWideSideSign(carrier) ||
    1;
  const slots = [
    { key: "under", required: true },
    { key: "inside", required: true },
    { key: "restLink", required: false },
  ];

  if (targetDepth >= 38 || targetThreat.betweenLines >= 0.28) {
    slots.push({ key: "beyond", required: targetDepth >= 52 || candidate.actionType === "dribble" });
  }

  if (targetIsWide || (profile.overlapBias ?? 0) >= 0.54 || (profile.widthDiscipline ?? 0) >= 0.64) {
    slots.push({ key: "outside", required: targetIsWide });
  }

  if (!targetIsWide && ((profile.switchBias ?? 0) >= 0.56 || targetThreat.centralPocket >= 0.28)) {
    slots.push({ key: "weakSide", required: false });
  }

  const excludedIds = new Set([carrier.id, receiver?.id, candidate.principleRunnerPlayerId].filter(Boolean));
  const usedIds = new Set(excludedIds);
  const supportOptions = [];

  slots.forEach((slot) => {
    const slotTarget = getReceptionSupportTarget(teamId, target, slot.key, sideSign, profile);
    const best = state.players
      .filter((player) => player.team === teamId && !usedIds.has(player.id) && !isGoalkeeper(player))
      .map((player) => {
        const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
        const runDistance = distance(player.position, slotTarget);
        const timeToSlot = computeTimeToCoverDistance(player, runDistance, slotTarget);
        const roleFit = getNextSupportSlotRoleFit(roleKey, slot.key);
        const supportStrength =
          getAutoPilotRoleStrength(player, "receiver") * 0.24 +
          getAutoPilotRoleStrength(player, "creator") * 0.18 +
          getPlayerTendency(player, "passAndMove") * 0.14;
        const canArrive = timeToSlot <= arrivalWindow + roleFit * 0.42;
        const score =
          roleFit +
          supportStrength +
          (canArrive ? 0.36 : 0) +
          clamp((arrivalWindow - timeToSlot) / 2.8, -0.36, 0.42) -
          runDistance * 0.006;

        return {
          player,
          roleKey,
          slot: slot.key,
          target: slotTarget,
          runDistance,
          timeToSlot,
          roleFit,
          canArrive,
          required: slot.required,
          score,
        };
      })
      .sort((a, b) => b.score - a.score)[0] ?? null;

    if (!best) {
      return;
    }

    if (best.canArrive || best.score >= 0.28) {
      supportOptions.push(best);
      usedIds.add(best.player.id);
    }
  });

  const arrivalOptions = supportOptions.filter((option) => option.canArrive);
  const slotSet = new Set(arrivalOptions.map((option) => option.slot));
  const requiredSlots = slots.filter((slot) => slot.required).map((slot) => slot.key);
  const coveredRequiredSlots = requiredSlots.filter((slot) => slotSet.has(slot)).length;
  const receiverPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : receiver
      ? getPlayerPressureLoad(receiver, target)
      : getOpponentPressureAtPoint(teamId, target, 12);

  return {
    actionDuration,
    arrivalWindow,
    options: supportOptions,
    arrivalOptions,
    arrivalCount: arrivalOptions.length,
    requiredCount: requiredSlots.length,
    coveredRequiredSlots,
    underAvailable: slotSet.has("under"),
    insideAvailable: slotSet.has("inside"),
    beyondAvailable: slotSet.has("beyond"),
    outsideAvailable: slotSet.has("outside"),
    weakSideAvailable: slotSet.has("weakSide"),
    receiverPressure,
    targetDepth,
    targetThreat,
  };
}

function getAutoPilotNextSupportNetworkAdjustment(candidate, carrier, startPoint, profile) {
  const network = getAutoPilotNextSupportNetworkProfile(candidate, carrier, startPoint, profile);
  if (!network) {
    return { score: 0, labels: [], network: null };
  }

  const passDistance = candidate.passDistance ?? distance(startPoint, candidate.target);
  const forwardGain =
    candidate.forwardGain ??
    ((candidate.target.x - startPoint.x) * getAttackDirectionSign(carrier.team));
  const highValueAction =
    candidate.isLineBreak ||
    candidate.isBoxPass ||
    candidate.actionType === "dribble" ||
    forwardGain >= 7 ||
    network.targetThreat.value >= 0.52;
  const isolated =
    network.arrivalCount === 0 ||
    (network.arrivalCount === 1 && network.receiverPressure >= 0.52) ||
    (candidate.actionType === "pass" && passDistance >= 18 && network.coveredRequiredSlots === 0);
  const labels = [];
  let score = 0;

  if (network.arrivalCount >= 2) {
    score += 0.18 + Math.min(network.arrivalCount, 4) * 0.055;
    labels.push("Next support ready");
  }

  if (network.underAvailable && network.insideAvailable) {
    score += 0.2 + (profile.shortSupport ?? 0.55) * 0.12;
    labels.push("Reception triangle ready");
  } else if (network.underAvailable || network.insideAvailable) {
    score += 0.08;
  }

  if (network.beyondAvailable && (highValueAction || network.targetDepth >= 52)) {
    score += 0.12 + (profile.directness ?? 0.5) * 0.08;
    labels.push("Depth option ready");
  }

  if (network.outsideAvailable && (isWidePrincipleZone(candidate.target) || (profile.overlapBias ?? 0) >= 0.58)) {
    score += 0.1 + (profile.overlapBias ?? 0.5) * 0.08;
  }

  if (network.weakSideAvailable && ((profile.switchBias ?? 0) >= 0.56 || network.targetThreat.centralPocket >= 0.28)) {
    score += 0.08 + (profile.switchBias ?? 0.5) * 0.08;
  }

  if (isolated) {
    score -=
      0.34 +
      (network.receiverPressure >= 0.56 ? 0.2 : 0) +
      (passDistance >= 22 ? 0.22 : 0) +
      (highValueAction ? 0.08 : 0);
    labels.push("Avoid isolated receiver");
  }

  if (
    candidate.actionType === "pass" &&
    forwardGain < 3 &&
    network.arrivalCount >= 2 &&
    network.targetThreat.value < 0.42
  ) {
    score += 0.06 + (profile.shortSupport ?? 0.55) * 0.08;
  }

  return {
    score: clamp(score, -0.9, 0.72),
    labels: uniquePrincipleLabels(labels),
    network,
  };
}

function getAutoPilotSpaceLadderContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return {
      active: false,
      pressureType: "unknown",
    };
  }

  const teamId = carrier.team;
  const currentThreat = getPitchThreatProfile(startPoint, teamId);
  const currentSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestGap = getNearestOpponentGap(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.35);
  const pressureType =
    pressure >= 0.64 || nearestGap <= 2.35
      ? "direct"
      : pressure >= 0.38 || nearestGap <= 4.8
        ? "indirect"
        : "free";
  const depth = getAttackingDepth(startPoint, teamId);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const canProgress =
    pressureType !== "direct" &&
    depth >= 34 &&
    depth <= 86 &&
    (
      facingForward ||
      progressionWindow.active ||
      currentThreat.betweenLines >= 0.3 ||
      currentThreat.centralPocket >= 0.22
    );
  const dangerAvailable =
    currentThreat.centralPocket >= 0.24 ||
    currentThreat.betweenLines >= 0.34 ||
    currentThreat.halfSpace >= 0.34 ||
    currentSpace.key === "space2" ||
    currentSpace.key === "space3";

  return {
    active: true,
    teamId,
    currentThreat,
    currentSpace,
    pressure,
    nearestGap,
    facingForward,
    pressureType,
    depth,
    progressionWindow,
    canProgress,
    dangerAvailable,
  };
}

function getAutoPilotSpaceLadderAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotSpaceLadderContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetThreat = getPitchThreatProfile(target, teamId);
  const targetSpace = getAttackingGameSpaceProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const threatGain = targetThreat.value - context.currentThreat.value;
  const gameSpaceGain = targetSpace.index - context.currentSpace.index;
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, target)
      : 0.64;
  const targetPriority = clamp(
    targetThreat.box * 1 +
      targetThreat.cutbackZone * 0.82 +
      targetThreat.centralPocket * 0.74 +
      targetThreat.betweenLines * 0.58 +
      targetThreat.behindLine * 0.6 +
      targetThreat.halfSpace * 0.42 +
      targetThreat.assistZone * 0.42 +
      (candidate.isBoxPass ? 0.24 : 0) +
      (candidate.isLineBreak ? 0.2 : 0) +
      (candidate.actionType === "shot" ? 0.28 : 0),
    0,
    1.45
  );
  const actionOpensDanger =
    targetPriority >= 0.48 ||
    actionSpace.value >= 0.46 ||
    threatGain >= 0.07 ||
    gameSpaceGain >= 1 ||
    candidate.mustShoot;
  const lowValueRecycle =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    forwardGain < 2.2 &&
    targetThreat.value <= context.currentThreat.value + 0.045 &&
    actionSpace.lineBreakCount === 0 &&
    targetSpace.index <= context.currentSpace.index &&
    targetThreat.depth < 78;
  const wastefulBackPass =
    lowValueRecycle &&
    forwardGain <= -3 &&
    context.pressureType !== "direct" &&
    context.depth >= 42;
  const wideHighContext =
    isWidePrincipleZone(startPoint) &&
    context.depth >= 66 &&
    context.pressureType !== "direct";
  const finalThirdCentralContext =
    context.depth >= 68 &&
    Math.abs(startPoint.y - pitch.width / 2) <= 22 &&
    context.pressureType !== "direct";
  const labels = [];
  let score = 0;

  if (context.canProgress && actionOpensDanger) {
    score +=
      0.2 +
      targetPriority * 0.42 +
      Math.max(0, threatGain) * 0.38 +
      clamp(forwardGain / 18, 0, 0.42) +
      (gameSpaceGain > 0 ? 0.14 + gameSpaceGain * 0.08 : 0);
    labels.push(targetThreat.primaryLabel === "open space" ? "Climb the next space" : `Attack ${targetThreat.primaryLabel}`);
  }

  if (
    context.canProgress &&
    context.currentSpace.key === "space2" &&
    context.facingForward &&
    (candidate.actionType === "shot" || candidate.isBoxPass || targetThreat.centralPocket >= 0.3 || targetThreat.box >= 0.22)
  ) {
    score += 0.34 + (profile.shootBias ?? 0.48) * 0.1;
    labels.push("Do not waste space 2");
  }

  if (
    context.canProgress &&
    candidate.actionType === "dribble" &&
    forwardGain >= 5 &&
    actionSpace.openTarget >= 0.48
  ) {
    score += 0.22 + (profile.carryBias ?? 0.5) * 0.18;
    labels.push("Carry through the ladder");
  }

  if (wideHighContext) {
    if (candidate.isBoxPass || targetThreat.cutbackZone >= 0.28 || targetThreat.box >= 0.26) {
      score += 0.26 + (profile.crossBias ?? 0.46) * 0.12 + (profile.overlapBias ?? 0.48) * 0.08;
      labels.push("Wide route to goal");
    } else if (
      lowValueRecycle &&
      context.pressure <= 0.48 &&
      !candidate.isSwitch
    ) {
      score -= 0.34;
    }
  }

  if (finalThirdCentralContext && candidate.actionType !== "shot" && lowValueRecycle) {
    score -= 0.42 + (profile.shootBias ?? 0.48) * 0.18;
  }

  if (context.canProgress && lowValueRecycle && context.dangerAvailable) {
    score -= 0.48 + (profile.progressionUrgency ?? 0.5) * 0.28;
    labels.push("Avoid low-value recycle");
  }

  if (wastefulBackPass) {
    score -= 0.24 + clamp(context.depth / 100, 0, 1) * 0.18;
  }

  if (
    candidate.actionType === "pass" &&
    actionOpensDanger &&
    passDistance >= 16 &&
    laneClarity < 0.34 &&
    !candidate.mustShoot
  ) {
    score -= 0.26;
  }

  if (
    context.pressureType === "direct" &&
    candidate.actionType === "pass" &&
    passDistance <= 16 &&
    forwardGain >= -6 &&
    laneClarity >= 0.44
  ) {
    score += 0.12 + (profile.shortSupport ?? 0.55) * 0.08;
    labels.push("Secure under direct pressure");
  }

  return {
    score: clamp(score, -1.25, 1.35),
    labels: uniquePrincipleLabels(labels),
    context: {
      pressureType: context.pressureType,
      canProgress: context.canProgress,
      startSpaceKey: context.currentSpace.key,
      targetSpaceKey: targetSpace.key,
      targetPriority,
      lowValueRecycle,
      actionOpensDanger,
    },
  };
}

function getAutoPilotAdvantageRetentionContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const currentThreat = getPitchThreatProfile(startPoint, teamId);
  const currentSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestGap = getNearestOpponentGap(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.25);
  const depth = getAttackingDepth(startPoint, teamId);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const rhythm = getPossessionRhythmContext(teamId);
  const pressureMode =
    pressure >= 0.66 || nearestGap <= 2.15
      ? "direct"
      : pressure >= 0.44 || nearestGap <= 4.6
        ? "indirect"
        : "free";
  const inValuableSpace =
    currentSpace.key === "space2" ||
    currentSpace.key === "space3" ||
    currentThreat.betweenLines >= 0.34 ||
    currentThreat.centralPocket >= 0.24 ||
    currentThreat.halfSpace >= 0.38 ||
    currentThreat.box >= 0.14 ||
    currentThreat.cutbackZone >= 0.18;
  const canExploit =
    pressureMode !== "direct" &&
    (
      facingForward ||
      currentThreat.betweenLines >= 0.34 ||
      currentThreat.centralPocket >= 0.24 ||
      currentSpace.key === "space3"
    );
  const advantageStrength = clamp(
    currentThreat.value * 0.52 +
      currentThreat.betweenLines * 0.24 +
      currentThreat.centralPocket * 0.24 +
      currentThreat.halfSpace * 0.14 +
      currentThreat.box * 0.22 +
      currentThreat.cutbackZone * 0.18 +
      currentSpace.index * 0.08 +
      (facingForward ? 0.14 : 0) +
      (pressureMode === "free" ? 0.1 : pressureMode === "indirect" ? 0.04 : -0.08) -
      pressure * 0.16,
    0,
    1.35
  );
  const mustConvert =
    canExploit &&
    (
      currentSpace.key === "space3" ||
      currentThreat.box >= 0.18 ||
      currentThreat.cutbackZone >= 0.24 ||
      (depth >= 66 && goalDistance <= 42)
    );
  const mustAttackNextLine =
    canExploit &&
    !mustConvert &&
    (
      currentSpace.key === "space2" ||
      currentThreat.betweenLines >= 0.34 ||
      currentThreat.centralPocket >= 0.24
    );
  const active = inValuableSpace && (advantageStrength >= 0.26 || currentSpace.index >= 2);

  return {
    active,
    teamId,
    currentThreat,
    currentSpace,
    pressure,
    nearestGap,
    facingForward,
    depth,
    goalDistance,
    rhythm,
    pressureMode,
    inValuableSpace,
    canExploit,
    advantageStrength,
    mustConvert,
    mustAttackNextLine,
  };
}

function getAutoPilotAdvantageRetentionAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return {
      score: 0,
      labels: [],
      context: null,
    };
  }

  const context = getAutoPilotAdvantageRetentionContext(carrier, startPoint, profile);
  if (!context.active) {
    return {
      score: 0,
      labels: [],
      context,
    };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetThreat = getPitchThreatProfile(target, teamId);
  const targetSpace = getAttackingGameSpaceProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, target)
      : 0.62;
  const supportNearTarget = getTeamSupportCountAroundPoint(
    teamId,
    target,
    new Set([carrier.id, candidate.receiverPlayerId, candidate.principleRunnerPlayerId].filter(Boolean)),
    passDistance >= 24 ? 15 : 11
  );
  const targetPressure = Number.isFinite(candidate.receiverPressure)
    ? candidate.receiverPressure
    : actionSpace.targetPressure;
  const threatGain = targetThreat.value - context.currentThreat.value;
  const gameSpaceGain = targetSpace.index - context.currentSpace.index;
  const lineBreakAction =
    candidate.isLineBreak ||
    actionSpace.lineBreakCount >= 1 ||
    (gameSpaceGain >= 1 && forwardGain >= 3.5);
  const finalAction =
    candidate.actionType === "shot" ||
    candidate.isBoxPass ||
    targetThreat.box >= 0.24 ||
    targetThreat.cutbackZone >= 0.28 ||
    targetThreat.assistZone >= 0.36 ||
    targetThreat.behindLine >= 0.34;
  const carryAdvantage =
    candidate.actionType === "dribble" &&
    forwardGain >= 3.8 &&
    actionSpace.openTarget >= 0.42;
  const usefulSameSpace =
    candidate.actionType === "pass" &&
    targetSpace.index === context.currentSpace.index &&
    forwardGain >= -1.5 &&
    targetThreat.value >= context.currentThreat.value - 0.035 &&
    (supportNearTarget >= 1 || laneClarity >= 0.58) &&
    passDistance <= 23;
  const purposefulSwitch =
    candidate.isSwitch &&
    targetThreat.value >= context.currentThreat.value - 0.06 &&
    laneClarity >= 0.62 &&
    (profile.switchBias >= 0.58 || context.rhythm.sidewaysPasses >= 1 || targetPressure <= 0.5);
  const lowValueReset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    forwardGain <= -2.5 &&
    targetSpace.index < context.currentSpace.index &&
    targetThreat.value <= context.currentThreat.value + 0.025 &&
    context.pressureMode !== "direct";
  const sterileSideways =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    Math.abs(forwardGain) < 2.4 &&
    targetSpace.index <= context.currentSpace.index &&
    targetThreat.value <= context.currentThreat.value + 0.035 &&
    actionSpace.lineBreakCount === 0 &&
    context.pressureMode !== "direct";
  const overplayedIntoPressure =
    candidate.actionType !== "shot" &&
    targetPressure >= 0.76 &&
    supportNearTarget <= 0 &&
    laneClarity < 0.52 &&
    !candidate.isBoxPass;
  const labels = [];
  let score = 0;

  if (candidate.actionType === "shot" && context.mustConvert) {
    const shotWindow = getShotWindowProfile(carrier, startPoint, target);
    score += 0.34 + shotWindow.quality * 0.42 + (profile.shootBias ?? 0.5) * 0.12;
    labels.push("Convert advantage");
  }

  if (lineBreakAction || finalAction) {
    score +=
      0.18 +
      context.advantageStrength * 0.18 +
      actionSpace.value * 0.24 +
      Math.max(0, threatGain) * 0.36 +
      (finalAction ? 0.22 : 0) +
      (lineBreakAction ? 0.18 : 0);
    labels.push(context.mustConvert ? "Turn advantage into final action" : "Keep advantage moving forward");
  }

  if (carryAdvantage) {
    score +=
      0.22 +
      (profile.carryBias ?? 0.5) * 0.18 +
      actionSpace.openTarget * 0.18 +
      (context.mustAttackNextLine ? 0.16 : 0);
    labels.push("Carry the advantage");
  }

  if (usefulSameSpace && !lineBreakAction && !finalAction) {
    score += 0.08 + (profile.shortSupport ?? 0.55) * 0.08;
    labels.push("Retain valuable space");
  }

  if (purposefulSwitch) {
    score += 0.12 + (profile.switchBias ?? 0.5) * 0.12;
    labels.push("Switch to keep advantage");
  }

  if (context.mustAttackNextLine && !lineBreakAction && !finalAction && !carryAdvantage && !purposefulSwitch) {
    score -= 0.28 + context.advantageStrength * 0.24;
  }

  if (context.mustConvert && !finalAction && !carryAdvantage && !purposefulSwitch) {
    score -= 0.34 + context.advantageStrength * 0.28 + (profile.shootBias ?? 0.5) * 0.12;
  }

  if (lowValueReset) {
    score -= 0.58 + context.advantageStrength * 0.34 + (profile.progressionUrgency ?? 0.5) * 0.22;
    labels.push("Do not reset the advantage");
  }

  if (sterileSideways) {
    score -= 0.32 + context.advantageStrength * 0.24;
    labels.push("Avoid sterile sideways after advantage");
  }

  if (overplayedIntoPressure) {
    score -= 0.22 + targetPressure * 0.18;
    labels.push("Do not force advantage into pressure");
  }

  if (
    context.rhythm.backPasses >= 1 &&
    context.rhythm.forwardPasses === 0 &&
    (lowValueReset || sterileSideways)
  ) {
    score -= 0.18 + (profile.progressionUrgency ?? 0.5) * 0.14;
  }

  return {
    score: clamp(score, -1.45, 1.35),
    labels: uniquePrincipleLabels(labels),
    context: {
      currentSpaceKey: context.currentSpace.key,
      targetSpaceKey: targetSpace.key,
      pressureMode: context.pressureMode,
      advantageStrength: context.advantageStrength,
      mustConvert: context.mustConvert,
      mustAttackNextLine: context.mustAttackNextLine,
      lineBreakAction,
      finalAction,
      carryAdvantage,
      usefulSameSpace,
      purposefulSwitch,
      lowValueReset,
      sterileSideways,
      targetPressure,
      supportNearTarget,
      laneClarity,
    },
  };
}

function getAutoPilotEndProductUrgencyContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const threat = getPitchThreatProfile(startPoint, teamId);
  const gameSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestGap = getNearestOpponentGap(carrier, startPoint);
  const pressureType =
    pressure >= 0.68 || nearestGap <= 2.25
      ? "direct"
      : pressure >= 0.42 || nearestGap <= 4.7
        ? "indirect"
        : "free";
  const depth = getAttackingDepth(startPoint, teamId);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const centrality = 1 - Math.abs(startPoint.y - pitch.width / 2) / (pitch.width / 2);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.25);
  const recent = getRecentPossessionSteps(teamId, 5);
  const recentFinalThirdActions = recent.filter((step) => {
    const target = step.target ?? step.afterSnapshot?.ball?.position ?? null;
    return target && getAttackingDepth(target, teamId) >= 66;
  }).length;
  const recentShots = recent.filter((step) => step.actionType === "shot").length;
  const chanceState =
    threat.box >= 0.14 ||
    threat.cutbackZone >= 0.22 ||
    threat.centralPocket >= 0.24 ||
    threat.betweenLines >= 0.42 ||
    gameSpace.key === "space3" ||
    depth >= 66;
  const active =
    chanceState &&
    depth >= 54 &&
    pressureType !== "direct" &&
    goalDistance <= 44;
  const urgency = clamp(
    threat.box * 0.42 +
      threat.cutbackZone * 0.3 +
      threat.centralPocket * 0.28 +
      threat.betweenLines * 0.18 +
      threat.halfSpace * 0.14 +
      clamp((depth - 58) / 30, 0, 1) * 0.24 +
      clamp((44 - goalDistance) / 24, 0, 1) * 0.22 +
      (facingForward ? 0.16 : 0) +
      (pressureType === "free" ? 0.12 : 0) +
      Math.min(recentFinalThirdActions, 3) * 0.06 +
      (recentShots === 0 && recentFinalThirdActions >= 2 ? 0.18 : 0) +
      (profile.shootBias ?? 0.48) * 0.12 -
      pressure * 0.18,
    0,
    1.35
  );

  return {
    active,
    teamId,
    threat,
    gameSpace,
    pressure,
    nearestGap,
    pressureType,
    depth,
    goalDistance,
    centrality,
    facingForward,
    recentFinalThirdActions,
    recentShots,
    urgency,
  };
}

function getAutoPilotEndProductUrgencyAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotEndProductUrgencyContext(carrier, startPoint, profile);
  if (!context.active || context.urgency <= 0.2) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetThreat = getPitchThreatProfile(target, teamId);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const targetGoalDistance = distance(target, getOpponentGoalCenter(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, target)
      : candidate.laneClarity ?? 0.62;
  const highValueTarget =
    targetThreat.box >= 0.24 ||
    targetThreat.cutbackZone >= 0.28 ||
    targetThreat.centralPocket >= 0.34 ||
    candidate.isBoxPass ||
    candidate.mustShoot;
  const routeToGoal =
    targetGoalDistance <= context.goalDistance - 3.2 ||
    forwardGain >= 4 ||
    highValueTarget;
  const lowValueReset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !candidate.isBoxPass &&
    forwardGain < 1.8 &&
    targetThreat.value <= context.threat.value + 0.035 &&
    targetThreat.depth < 75 &&
    actionSpace.lineBreakCount === 0;
  const needlessBackwards =
    lowValueReset &&
    forwardGain < -2.5 &&
    context.pressureType !== "direct";
  const labels = [];
  let score = 0;

  if (candidate.actionType === "shot") {
    const shotQuality =
      candidate.shotQuality ??
      clamp(
        (candidate.laneClarity ?? laneClarity) * 0.32 +
          (candidate.angleQuality ?? 0.34) * 0.24 +
          (candidate.goalkeeperOpenness ?? 0.45) * 0.22 +
          (1 - (candidate.blockRisk ?? 0.52)) * 0.22,
        0,
        1
      );
    score +=
      0.34 +
      context.urgency * 0.54 +
      shotQuality * 0.42 +
      (candidate.insideBox ? 0.38 : 0) +
      (candidate.mustShoot ? 0.52 : 0);
    labels.push("End product: shoot");
  } else if (candidate.actionType === "pass" && highValueTarget) {
    const cutbackBonus = targetThreat.cutbackZone >= 0.28 || candidate.label === "cutback" ? 0.2 : 0;
    const boxSupportBonus = clamp(candidate.supportNearTarget ?? 0, 0, 4) * 0.055;
    score +=
      0.24 +
      context.urgency * 0.38 +
      targetThreat.box * 0.28 +
      targetThreat.cutbackZone * 0.24 +
      boxSupportBonus +
      cutbackBonus -
      (laneClarity < 0.36 && passDistance >= 14 ? 0.18 : 0);
    labels.push(targetThreat.cutbackZone >= 0.28 || candidate.label === "cutback" ? "End product: cutback" : "End product: final pass");
  } else if (
    candidate.actionType === "dribble" &&
    routeToGoal &&
    actionSpace.openTarget >= 0.42
  ) {
    score +=
      0.18 +
      context.urgency * 0.28 +
      actionSpace.openTarget * 0.18 +
      (targetGoalDistance <= 28 ? 0.14 : 0);
    labels.push("End product: commit defender");
  } else if (
    candidate.actionType === "pass" &&
    routeToGoal &&
    targetThreat.value >= context.threat.value + 0.05
  ) {
    score += 0.08 + context.urgency * 0.12;
  }

  if (lowValueReset) {
    score -= 0.42 + context.urgency * 0.42 + (context.facingForward ? 0.16 : 0);
    labels.push("Avoid resetting a chance");
  }

  if (needlessBackwards) {
    score -= 0.22 + context.urgency * 0.16;
  }

  if (
    context.recentFinalThirdActions >= 3 &&
    context.recentShots === 0 &&
    candidate.actionType !== "shot" &&
    !candidate.isBoxPass &&
    !highValueTarget
  ) {
    score -= 0.18 + context.urgency * 0.16;
  }

  return {
    score: clamp(score, -1.2, 1.45),
    labels: uniquePrincipleLabels(labels),
    context: {
      pressureType: context.pressureType,
      urgency: context.urgency,
      goalDistance: context.goalDistance,
      highValueTarget,
      lowValueReset,
      recentFinalThirdActions: context.recentFinalThirdActions,
      recentShots: context.recentShots,
    },
  };
}

function getAutoPilotChanceHierarchyContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const threat = getPitchThreatProfile(startPoint, teamId);
  const goal = getOpponentGoalCenter(teamId);
  const goalDistance = distance(startPoint, goal);
  const depth = getAttackingDepth(startPoint, teamId);
  const centrality = 1 - Math.abs(startPoint.y - pitch.width / 2) / (pitch.width / 2);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const nearestGap = getNearestOpponentGap(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.35);
  const shotTarget = getAutoPilotShotTarget(teamId, carrier);
  const shotWindow = getShotWindowProfile(carrier, startPoint, shotTarget);
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const recentFinalThirdActions = flow.recent.filter((step) => {
    const target = step.target ?? step.afterSnapshot?.ball?.position ?? null;
    return target && getAttackingDepth(target, teamId) >= 66;
  }).length;
  const recentShots = flow.recent.filter((step) => step.actionType === "shot").length;
  const freeToAct = pressure <= 0.52 && nearestGap >= 3.2;
  const centralFinishState =
    depth >= 67 &&
    centrality >= 0.28 &&
    goalDistance <= 37 &&
    shotWindow.angleQuality >= 0.14 &&
    shotWindow.blockRisk <= 0.84;
  const boxFinishState =
    threat.box >= 0.16 ||
    threat.centralPocket >= 0.32 ||
    (depth >= 76 && goalDistance <= 31);
  const cutbackState =
    threat.cutbackZone >= 0.2 ||
    (depth >= 72 && isWideChannel(startPoint) && goalDistance <= 39);
  const chanceValue = clamp(
    threat.box * 0.34 +
      threat.centralPocket * 0.28 +
      threat.cutbackZone * 0.2 +
      shotWindow.quality * 0.34 +
      shotWindow.laneClarity * 0.2 +
      shotWindow.angleQuality * 0.16 +
      centrality * 0.12 +
      clamp((38 - goalDistance) / 24, 0, 1) * 0.22 +
      (facingForward ? 0.14 : 0) +
      (freeToAct ? 0.12 : 0) +
      (recentFinalThirdActions >= 2 && recentShots === 0 ? 0.16 : 0) -
      pressure * 0.22,
    0,
    1.35
  );
  const active =
    depth >= 62 &&
    goalDistance <= 42 &&
    pressure <= 0.78 &&
    (centralFinishState || boxFinishState || cutbackState || chanceValue >= 0.44);

  return {
    active,
    teamId,
    threat,
    goalDistance,
    depth,
    centrality,
    pressure,
    nearestGap,
    facingForward,
    shotWindow,
    flow,
    recentFinalThirdActions,
    recentShots,
    freeToAct,
    centralFinishState,
    boxFinishState,
    cutbackState,
    chanceValue,
  };
}

function getAutoPilotChanceHierarchyAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotChanceHierarchyContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetThreat = candidate.actionType === "shot"
    ? context.threat
    : getPitchThreatProfile(target, teamId);
  const actionSpace = candidate.actionType === "shot"
    ? null
    : getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const receiver = candidate.receiverPlayerId ? getPlayerById(candidate.receiverPlayerId) : null;
  const receiverRoleKey =
    candidate.receiverRoleKey ??
    (receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null);
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, target)
      : context.shotWindow.laneClarity;
  const isFinalPass =
    candidate.actionType === "pass" &&
    (
      candidate.isBoxPass ||
      candidate.label === "cutback" ||
      targetThreat.box >= 0.22 ||
      targetThreat.cutbackZone >= 0.26 ||
      (targetThreat.centralPocket >= 0.34 && forwardGain >= -1)
    );
  const canShootNow =
    candidate.actionType === "shot" &&
    (
      context.boxFinishState ||
      context.centralFinishState ||
      context.shotWindow.quality >= 0.24 ||
      context.goalDistance <= 29 ||
      candidate.mustShoot
    );
  const canCarryToFinish =
    candidate.actionType === "dribble" &&
    forwardGain >= 4 &&
    (actionSpace?.openTarget ?? 0) >= 0.42 &&
    distance(target, getOpponentGoalCenter(teamId)) <= context.goalDistance - 3;
  const supportReset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !isFinalPass &&
    forwardGain < 2.5 &&
    passDistance <= 24 &&
    (
      isSupportRole(receiverRoleKey) ||
      receiverRoleKey === "rest" ||
      targetThreat.value <= context.threat.value + 0.04
    );
  const backwardsReset = supportReset && forwardGain < -2.5;
  const lowAngleWideShot =
    candidate.actionType === "shot" &&
    !context.boxFinishState &&
    context.shotWindow.angleQuality < 0.16 &&
    context.cutbackState;
  const labels = [];
  let score = 0;

  if (canShootNow && !lowAngleWideShot) {
    score +=
      0.34 +
      context.chanceValue * 0.5 +
      context.shotWindow.quality * 0.34 +
      (context.freeToAct ? 0.14 : 0) +
      (context.recentFinalThirdActions >= 2 && context.recentShots === 0 ? 0.18 : 0) +
      (candidate.mustShoot ? 0.28 : 0);
    labels.push("Chance hierarchy: shoot");
  }

  if (isFinalPass) {
    const cutbackBonus = candidate.label === "cutback" || targetThreat.cutbackZone >= 0.26 ? 0.2 : 0;
    const boxBonus = targetThreat.box * 0.24 + targetThreat.centralPocket * 0.18;
    score +=
      0.24 +
      context.chanceValue * 0.34 +
      cutbackBonus +
      boxBonus -
      (laneClarity < 0.34 && passDistance >= 12 ? 0.18 : 0);
    labels.push(candidate.label === "cutback" || targetThreat.cutbackZone >= 0.26
      ? "Chance hierarchy: cutback"
      : "Chance hierarchy: final pass");
  }

  if (canCarryToFinish && !context.centralFinishState) {
    score += 0.14 + context.chanceValue * 0.2 + (actionSpace?.openTarget ?? 0) * 0.16;
    labels.push("Chance hierarchy: carry to finish");
  }

  if (supportReset && context.pressure <= 0.6) {
    score -=
      0.38 +
      context.chanceValue * 0.42 +
      (context.facingForward ? 0.18 : 0) +
      (context.freeToAct ? 0.12 : 0);
    labels.push("Avoid resetting a chance");
  }

  if (backwardsReset) {
    score -= 0.18 + context.chanceValue * 0.18;
  }

  if (lowAngleWideShot) {
    score -= 0.22;
  }

  return {
    score: clamp(score, -1.15, 1.4),
    labels: uniquePrincipleLabels(labels),
    context: {
      chanceValue: context.chanceValue,
      goalDistance: context.goalDistance,
      pressure: context.pressure,
      centralFinishState: context.centralFinishState,
      boxFinishState: context.boxFinishState,
      cutbackState: context.cutbackState,
      supportReset,
      isFinalPass,
    },
  };
}

function getAutoPilotLineBreakAdvantageAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const teamId = carrier.team;
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const lastStep = flow.lastStep;
  if (!flow.carrierJustReceived || !lastStep || lastStep.actionType !== "pass") {
    return { score: 0, labels: [], context: null };
  }

  const lastStart =
    lastStep.beforeSnapshot?.ball?.position ??
    lastStep.beforeSnapshot?.ball?.startPosition ??
    null;
  const lastTarget = lastStep.target ?? startPoint;
  const lastPrincipleText = [
    lastStep.profileLabel,
    lastStep.offensiveAutopilot?.principleKey,
    lastStep.offensiveAutopilot?.principleLabel,
    ...(lastStep.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const previousActionSpace = lastStart
    ? getActionSpaceValue(lastStart, lastTarget, teamId, profile)
    : null;
  const previousForwardGain = lastStart
    ? (lastTarget.x - lastStart.x) * getAttackDirectionSign(teamId)
    : 0;
  const previousLineBreak =
    lastStep.profileLabel?.toLowerCase?.().includes("line-breaking") ||
    lastPrincipleText.includes("line break") ||
    lastPrincipleText.includes("line-breaking") ||
    lastPrincipleText.includes("third-player") ||
    lastPrincipleText.includes("between-lines") ||
    lastPrincipleText.includes("space 2") ||
    lastPrincipleText.includes("spelyta") ||
    (previousActionSpace?.lineBreakCount ?? 0) >= 1 ||
    (previousForwardGain >= 7.5 && (previousActionSpace?.targetThreat?.value ?? 0) >= 0.34);

  if (!previousLineBreak) {
    return { score: 0, labels: [], context: null };
  }

  const currentThreat = getPitchThreatProfile(startPoint, teamId);
  const currentSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const pressure = flow.pressure;
  const nearestGap = getNearestOpponentGap(carrier, startPoint);
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.15);
  const depth = getAttackingDepth(startPoint, teamId);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const advantageValue = clamp(
    currentThreat.box * 0.34 +
      currentThreat.centralPocket * 0.3 +
      currentThreat.betweenLines * 0.24 +
      currentThreat.halfSpace * 0.16 +
      currentThreat.behindLine * 0.18 +
      clamp((depth - 46) / 34, 0, 1) * 0.22 +
      clamp(previousForwardGain / 18, 0, 0.38) +
      clamp((previousActionSpace?.lineBreakCount ?? 0) / 2, 0, 1) * 0.22 +
      (currentSpace.key === "space2" || currentSpace.key === "space3" ? 0.14 : 0) +
      (facingForward ? 0.16 : 0) +
      (nearestGap >= 3.2 ? 0.08 : 0) -
      pressure * 0.22,
    0,
    1.35
  );

  if (advantageValue < 0.24 || pressure >= 0.86) {
    return {
      score: 0,
      labels: [],
      context: {
        active: false,
        advantageValue,
        pressure,
        previousForwardGain,
      },
    };
  }

  const target = candidate.target;
  const targetThreat = candidate.actionType === "shot"
    ? currentThreat
    : getPitchThreatProfile(target, teamId);
  const actionSpace = candidate.actionType === "shot"
    ? null
    : getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const laneClarity = Number.isFinite(candidate.laneClarity)
    ? candidate.laneClarity
    : candidate.actionType === "pass"
      ? computePassLaneClarity(carrier, target)
      : actionSpace?.openTarget ?? 0.56;
  const highValueContinuation =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.label === "cutback" ||
    targetThreat.box >= 0.22 ||
    targetThreat.cutbackZone >= 0.24 ||
    targetThreat.centralPocket >= 0.3 ||
    targetThreat.behindLine >= 0.24;
  const carriesAdvantage =
    candidate.actionType === "dribble" &&
    forwardGain >= 3.5 &&
    (actionSpace?.openTarget ?? 0) >= 0.38 &&
    distance(target, getOpponentGoalCenter(teamId)) <= goalDistance - 2.4;
  const connectsAdvantage =
    candidate.actionType === "pass" &&
    !highValueContinuation &&
    forwardGain >= 3.5 &&
    (targetThreat.value >= currentThreat.value + 0.045 || (actionSpace?.lineBreakCount ?? 0) >= 1) &&
    laneClarity >= 0.42;
  const supportReset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !highValueContinuation &&
    forwardGain < 2.4 &&
    passDistance <= 25 &&
    targetThreat.value <= currentThreat.value + 0.04 &&
    (actionSpace?.lineBreakCount ?? 0) === 0;
  const backwardsReset = supportReset && forwardGain < -2.5 && pressure <= 0.66;
  const labels = [];
  let score = 0;

  if (candidate.actionType === "shot") {
    const shotWindow = getShotWindowProfile(carrier, startPoint, candidate.target);
    score +=
      0.24 +
      advantageValue * 0.5 +
      shotWindow.quality * 0.34 +
      (candidate.mustShoot ? 0.28 : 0) -
      (shotWindow.blockRisk >= 0.88 && !candidate.mustShoot ? 0.2 : 0);
    labels.push("Line-break advantage: shoot");
  } else if (highValueContinuation) {
    score +=
      0.22 +
      advantageValue * 0.38 +
      targetThreat.box * 0.22 +
      targetThreat.cutbackZone * 0.18 +
      targetThreat.centralPocket * 0.16 -
      (laneClarity < 0.34 && passDistance >= 14 ? 0.16 : 0);
    labels.push(candidate.label === "cutback" || targetThreat.cutbackZone >= 0.24
      ? "Line-break advantage: cutback"
      : "Line-break advantage: final action");
  } else if (carriesAdvantage) {
    score += 0.16 + advantageValue * 0.24 + (actionSpace?.openTarget ?? 0) * 0.18;
    labels.push("Line-break advantage: drive at goal");
  } else if (connectsAdvantage) {
    score += 0.08 + advantageValue * 0.16;
    labels.push("Line-break advantage: keep attacking");
  }

  if (supportReset) {
    score -= 0.34 + advantageValue * 0.4 + (facingForward ? 0.16 : 0);
    labels.push("Do not reset line-break advantage");
  }

  if (backwardsReset) {
    score -= 0.2 + advantageValue * 0.18;
  }

  return {
    score: clamp(score, -1.2, 1.35),
    labels: uniquePrincipleLabels(labels),
    context: {
      advantageValue,
      pressure,
      facingForward,
      depth,
      goalDistance,
      previousForwardGain,
      previousLineBreakCount: previousActionSpace?.lineBreakCount ?? 0,
      highValueContinuation,
      carriesAdvantage,
      supportReset,
    },
  };
}

function getAutoPilotAdvantageLifecycleContext(carrier, startPoint, profile = {}) {
  if (!carrier || !startPoint) {
    return { active: false };
  }

  const teamId = carrier.team;
  const recent = getRecentPossessionSteps(teamId, 4);
  if (!recent.length) {
    return { active: false };
  }

  let bestSignal = 0;
  let latestAdvantageStep = null;
  let resetPenalty = 0;
  const signalLabels = [];

  recent.forEach((step, index) => {
    const start =
      step.beforeSnapshot?.ball?.position ??
      step.beforeSnapshot?.ball?.startPosition ??
      null;
    const target = step.target ?? step.afterSnapshot?.ball?.position ?? null;
    if (!target) {
      return;
    }

    const principleText = [
      step.profileLabel,
      step.offensiveAutopilot?.principleKey,
      step.offensiveAutopilot?.principleLabel,
      ...(step.autoPrinciples ?? []),
    ].filter(Boolean).join(" ").toLowerCase();
    const threat = getPitchThreatProfile(target, teamId);
    const space = getAttackingGameSpaceProfile(target, teamId);
    const actionSpace = start ? getActionSpaceValue(start, target, teamId, profile) : null;
    const forwardGain = start
      ? (target.x - start.x) * getAttackDirectionSign(teamId)
      : 0;
    const isAdvantageCue =
      principleText.includes("line-break advantage") ||
      principleText.includes("line break") ||
      principleText.includes("line-breaking") ||
      principleText.includes("third-player") ||
      principleText.includes("between-lines") ||
      principleText.includes("space 2") ||
      principleText.includes("spelyta") ||
      principleText.includes("do not reset line-break") ||
      (actionSpace?.lineBreakCount ?? 0) >= 1 ||
      (forwardGain >= 7 && threat.value >= 0.34);

    const threatSignal =
      threat.box * 0.42 +
      threat.cutbackZone * 0.34 +
      threat.centralPocket * 0.32 +
      threat.behindLine * 0.24 +
      threat.betweenLines * 0.2 +
      (space.key === "space2" || space.key === "space3" ? 0.18 : 0) +
      (isAdvantageCue ? 0.38 : 0) +
      Math.max(0, forwardGain) * 0.01;
    const ageDecay = Math.max(0.36, 1 - index * 0.22);
    const signal = clamp(threatSignal * ageDecay, 0, 1.35);

    if (signal > bestSignal) {
      bestSignal = signal;
      latestAdvantageStep = step;
    }

    if (isAdvantageCue) {
      signalLabels.push(space.label);
    }

    if (
      step.actionType === "pass" &&
      start &&
      forwardGain <= -6 &&
      threat.value <= 0.38
    ) {
      resetPenalty += 0.22 + index * 0.08;
    }
  });

  const currentThreat = getPitchThreatProfile(startPoint, teamId);
  const currentSpace = getAttackingGameSpaceProfile(startPoint, teamId);
  const currentDepth = getAttackingDepth(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const rhythm = getPossessionRhythmContext(teamId, 6);
  const finalThirdStillAlive =
    currentDepth >= 58 ||
    currentThreat.centralPocket >= 0.24 ||
    currentThreat.betweenLines >= 0.28 ||
    currentThreat.box >= 0.12 ||
    currentThreat.cutbackZone >= 0.18 ||
    currentSpace.key === "space2" ||
    currentSpace.key === "space3";
  const facingForward = isPlayerFacingForward(carrier, Math.PI / 2.15);
  const lifecycleValue = clamp(
    bestSignal +
      (finalThirdStillAlive ? 0.22 : 0) +
      (facingForward ? 0.1 : 0) +
      (rhythm.lineBreaks >= 1 ? 0.12 : 0) -
      resetPenalty -
      rhythm.backPasses * 0.08 -
      pressure * 0.1,
    0,
    1.35
  );

  return {
    active: lifecycleValue >= 0.34,
    lifecycleValue,
    bestSignal,
    pressure,
    facingForward,
    finalThirdStillAlive,
    currentThreat,
    currentSpace,
    currentDepth,
    rhythm,
    resetPenalty,
    latestAdvantageStep,
    signalLabels: uniquePrincipleLabels(signalLabels),
  };
}

function getAutoPilotAdvantageLifecycleAdjustment(candidate, carrier, startPoint, profile = {}) {
  if (!candidate?.target || !carrier || !startPoint) {
    return { score: 0, labels: [], context: null };
  }

  const context = getAutoPilotAdvantageLifecycleContext(carrier, startPoint, profile);
  if (!context.active) {
    return { score: 0, labels: [], context };
  }

  const teamId = carrier.team;
  const target = candidate.target;
  const targetThreat = candidate.actionType === "shot"
    ? context.currentThreat
    : getPitchThreatProfile(target, teamId);
  const actionSpace = candidate.actionType === "shot"
    ? null
    : getActionSpaceValue(startPoint, target, teamId, profile);
  const forwardGain =
    candidate.forwardGain ??
    ((target.x - startPoint.x) * getAttackDirectionSign(teamId));
  const passDistance = candidate.passDistance ?? distance(startPoint, target);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const targetGoalDistance = candidate.actionType === "shot"
    ? 0
    : distance(target, getOpponentGoalCenter(teamId));
  const finalAction =
    candidate.actionType === "shot" ||
    candidate.mustShoot ||
    candidate.isBoxPass ||
    candidate.label === "cutback" ||
    targetThreat.box >= 0.2 ||
    targetThreat.cutbackZone >= 0.22 ||
    targetThreat.centralPocket >= 0.3 ||
    targetThreat.behindLine >= 0.22;
  const carryAdvantage =
    candidate.actionType === "dribble" &&
    forwardGain >= 3 &&
    (actionSpace?.openTarget ?? 0) >= 0.38 &&
    targetGoalDistance <= goalDistance - 2.2;
  const keepPressure =
    candidate.actionType === "pass" &&
    !finalAction &&
    forwardGain >= 3 &&
    (targetThreat.value >= context.currentThreat.value + 0.04 ||
      (actionSpace?.lineBreakCount ?? 0) >= 1);
  const reset =
    candidate.actionType === "pass" &&
    !candidate.isSwitch &&
    !finalAction &&
    forwardGain < 1.5 &&
    passDistance <= 26 &&
    targetThreat.value <= context.currentThreat.value + 0.04 &&
    (actionSpace?.lineBreakCount ?? 0) === 0;
  const labels = [];
  let score = 0;

  if (finalAction) {
    score += 0.18 + context.lifecycleValue * 0.38;
    labels.push("Keep advantage alive: final action");
  } else if (carryAdvantage) {
    score += 0.12 + context.lifecycleValue * 0.22;
    labels.push("Keep advantage alive: drive");
  } else if (keepPressure) {
    score += 0.08 + context.lifecycleValue * 0.14;
    labels.push("Keep advantage alive");
  }

  if (reset && context.pressure <= 0.7) {
    score -= 0.28 + context.lifecycleValue * 0.34;
    labels.push("Do not let advantage die");
  }

  return {
    score: clamp(score, -1, 1.15),
    labels: uniquePrincipleLabels(labels),
    context: {
      active: context.active,
      lifecycleValue: context.lifecycleValue,
      bestSignal: context.bestSignal,
      pressure: context.pressure,
      currentSpace: context.currentSpace?.key,
      finalThirdStillAlive: context.finalThirdStillAlive,
      finalAction,
      carryAdvantage,
      keepPressure,
      reset,
    },
  };
}

function getWideSideSign(pointOrPlayer) {
  const y = Number.isFinite(pointOrPlayer?.y)
    ? pointOrPlayer.y
    : Number.isFinite(pointOrPlayer?.position?.y)
      ? pointOrPlayer.position.y
      : null;

  if (!Number.isFinite(y)) {
    return 0;
  }

  const offset = y - pitch.width / 2;
  if (Math.abs(offset) < 4) {
    return 0;
  }

  return offset < 0 ? -1 : 1;
}

function isWidePrincipleZone(point) {
  if (!point) {
    return false;
  }

  return Math.abs(point.y - pitch.width / 2) >= 12;
}

function getWideOverlapPrincipleFit(profile) {
  const formationFit = {
    "4-3-3": 1,
    "4-2-3-1": 0.88,
    "3-4-3": 0.84,
    "4-1-4-1": 0.7,
    "3-5-2": 0.62,
    "4-4-2": 0.52,
  }[profile.formation] ?? 0.56;
  const identityFit =
    profile.overlapBias * 0.48 +
    profile.widthDiscipline * 0.24 +
    profile.crossBias * 0.18 +
    profile.switchBias * 0.1;

  return clamp(formationFit * 0.58 + identityFit * 0.72, 0, 1.35);
}

function getWideOverlapRunTarget(teamId, anchorPoint, sideSign, profile) {
  const sign = getAttackDirectionSign(teamId);
  const anchorDepth = getAttackingDepth(anchorPoint, teamId);
  const forwardPush =
    7.2 +
    profile.overlapBias * 4.8 +
    (profile.phaseKey === "finalThird" ? 2.2 : 0);
  const outsideWidth = 4.4 + profile.widthDiscipline * 2.2;
  const targetDepth = clamp(anchorDepth + forwardPush, 42, 96);

  return clampToPitch({
    x: getDepthX(teamId, targetDepth) + sign * 0.4,
    y: clamp(anchorPoint.y + sideSign * outsideWidth, 3.4, pitch.width - 3.4),
  }, 2);
}

function getSameSideWideBacks(teamId, sideSign, excludedPlayerIds = new Set()) {
  const formation = teams[teamId]?.formation;

  return state.players.filter((player) => {
    if (player.team !== teamId || excludedPlayerIds.has(player.id)) {
      return false;
    }

    if (getOffensiveRoleKey(player, formation) !== "wideBack") {
      return false;
    }

    const playerSide = getWideSideSign(player);
    return playerSide === 0 || playerSide === sideSign;
  });
}

function chooseWideOverlapRunner(teamId, sideSign, anchorPoint, profile, excludedPlayerIds = new Set()) {
  if (!sideSign || !anchorPoint) {
    return null;
  }

  const principleFit = getWideOverlapPrincipleFit(profile);
  if (principleFit < 0.5) {
    return null;
  }

  const anchorDepth = getAttackingDepth(anchorPoint, teamId);
  const target = getWideOverlapRunTarget(teamId, anchorPoint, sideSign, profile);
  let best = null;
  let bestScore = -Infinity;

  getSameSideWideBacks(teamId, sideSign, excludedPlayerIds).forEach((player) => {
    const playerDepth = getAttackingDepth(player.position, teamId);
    const distanceToTarget = distance(player.position, target);
    const distanceToAnchor = distance(player.position, anchorPoint);
    const timingScore = playerDepth <= anchorDepth + 2.5
      ? 0.55
      : playerDepth <= anchorDepth + 9
        ? 0.18
        : -0.34;
    const overlapTendency = getPlayerTendency(player, "overlap");
    const athleticScore = clamp((player.maxSpeed - 6.6) / 2.1, 0, 1) * 0.42 +
      clamp((player.acceleration - 2.2) / 1.1, 0, 1) * 0.22;
    const roleStrength =
      getAutoPilotRoleStrength(player, "runner") * 0.5 +
      getAutoPilotRoleStrength(player, "crosser") * 0.34;
    const score =
      principleFit * 1.2 +
      overlapTendency * 0.82 +
      athleticScore +
      roleStrength +
      timingScore -
      distanceToTarget * 0.035 -
      Math.max(0, distanceToAnchor - 28) * 0.035;

    if (score > bestScore) {
      bestScore = score;
      best = {
        player,
        target,
        score,
        principleFit,
      };
    }
  });

  return best && best.score >= 0.72 ? best : null;
}

function getWideEntryPrincipleContext(carrier, receiver, startPoint, target, profile) {
  if (!carrier || !receiver || carrier.team !== receiver.team) {
    return null;
  }

  const receiverRoleKey = getOffensiveRoleKey(receiver, teams[carrier.team]?.formation);
  if (receiverRoleKey !== "wideForward" || !isWidePrincipleZone(target)) {
    return null;
  }

  const teamId = carrier.team;
  const targetDepth = getAttackingDepth(target, teamId);
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
  if (targetDepth < 38 || forwardGain < -3 || targetDepth < ballDepth - 2) {
    return null;
  }

  const sideSign = getWideSideSign(target) || getWideSideSign(receiver);
  const overlap = chooseWideOverlapRunner(
    teamId,
    sideSign,
    target,
    profile,
    new Set([carrier.id, receiver.id])
  );

  if (!overlap) {
    return null;
  }

  return {
    key: "wide-overlap-entry",
    label: "Wide entry",
    runner: overlap.player,
    runnerTarget: overlap.target,
    sideSign,
    scoreBonus: 0.34 + overlap.principleFit * 0.58 + getPlayerTendency(overlap.player, "overlap") * 0.22,
  };
}

function getOffensiveActionPrinciple(teamId, ballPoint, actionMeta, profile) {
  if (actionMeta?.actionType !== "pass") {
    return null;
  }

  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const carrier = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const startPoint = actionMeta.beforeSnapshot?.ball?.position ?? carrier?.position ?? state.ball.position;
  const principle = getWideEntryPrincipleContext(carrier, receiver, startPoint, ballPoint, profile);

  if (!principle) {
    return null;
  }

  return {
    ...principle,
    label: `Wide overload: W receives, ${getPlayerMagnetLabel(principle.runner)} overlaps`,
  };
}

function getPlayerRoleModel(player, formation = teams[player.team]?.formation) {
  const roleKey = getOffensiveRoleKey(player, formation);
  return gameRoleProfiles[roleKey] ?? gameRoleProfiles.connector;
}

function getOffensiveLaneY(baseY, ballPoint, profile, roleKey) {
  const centerY = pitch.width / 2;
  const side = Math.sign(baseY - centerY) || Math.sign(ballPoint.y - centerY) || 1;
  const laneKeys = getSideLaneKeys(baseY);
  const wideY = getLaneCenterY(laneKeys.wide, profile);
  const halfSpaceY = getLaneCenterY(laneKeys.half, profile);
  const narrowWideY = lerp(wideY, halfSpaceY, profile.wideForwardNarrowing ?? 0);
  const centralHalfSpaceY = lerp(halfSpaceY, centerY, profile.centralOverload ?? 0);
  const compactness = profile.supportCompactness ?? 0.12;
  const widthDiscipline = profile.widthDiscipline ?? 0.62;

  if (roleKey === "wideBack") {
    const supportPull = compactness * (profile.overlapBias >= 0.7 ? 0.14 : 0.08);
    return clamp(lerp(wideY, ballPoint.y, supportPull * (1 - widthDiscipline * 0.42)), 4, pitch.width - 4);
  }

  if (roleKey === "wideForward") {
    const shouldHoldTouchline = profile.crossBias >= 0.72 || profile.switchBias >= 0.7;
    const preferredLaneY = shouldHoldTouchline
      ? lerp(wideY, narrowWideY, 0.24)
      : narrowWideY;
    return clamp(lerp(preferredLaneY, ballPoint.y, compactness * 0.12), 5, pitch.width - 5);
  }

  if (roleKey === "connector") {
    return clamp(lerp(centralHalfSpaceY, ballPoint.y, compactness * 0.38), 8, pitch.width - 8);
  }

  if (roleKey === "pivot") {
    return clamp(lerp(centerY, ballPoint.y, 0.12 + (1 - (profile.centralOverload ?? 0.4)) * 0.08), 12, pitch.width - 12);
  }

  if (roleKey === "secondStriker") {
    return clamp(lerp(centerY + side * 7.5, ballPoint.y, 0.14), 14, pitch.width - 14);
  }

  if (roleKey === "striker") {
    return clamp(lerp(centerY, ballPoint.y, 0.12), 15, pitch.width - 15);
  }

  return clamp(lerp(centerY, ballPoint.y, compactness), 9, pitch.width - 9);
}

function shouldSkipOffensiveAutopilotPlayer(player, actionMeta) {
  return (
    player.id === actionMeta?.carrierPlayerId ||
    player.id === actionMeta?.receiverPlayerId ||
    player.id === actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ||
    player.id === state.ball.carrierPlayerId ||
    player.id === state.ball.receiverPlayerId ||
    player.id === state.ball.initiatorPlayerId
  );
}

function getOffensiveAutopilotTarget(player, ballPoint, actionMeta, profile, baseY, isPrimaryRunner = false) {
  const roleKey = getOffensiveRoleKey(player, profile.formation);
  const ballDepth = getAttackingDepth(ballPoint, player.team);
  const attackSign = getAttackDirectionSign(player.team);
  const side = Math.sign(baseY - pitch.width / 2) || 1;
  const ballSide = Math.sign(ballPoint.y - pitch.width / 2) || side;
  const isBallSide = side === ballSide || Math.abs(ballPoint.y - pitch.width / 2) < 5;
  let depth = ballDepth;
  let y = getOffensiveLaneY(baseY, ballPoint, profile, roleKey);

  if (roleKey === "gk") {
    depth = clamp(ballDepth - 55, 7, 15);
    y = clamp(lerp(pitch.width / 2, ballPoint.y, 0.08), 28, 40);
  } else if (roleKey === "rest") {
    const restOffset = profile.restBehind + (isBallSide ? -2 : 1.5);
    depth = clamp(ballDepth - restOffset, 16, 56);
    y = clamp(lerp(getOffensiveLaneY(baseY, ballPoint, profile, "connector"), pitch.width / 2, 0.46), 13, 55);
  } else if (roleKey === "wideBack") {
    const supportBoost = isBallSide
      ? profile.wideDepthBoost * 0.5 * (profile.wideBackAdvance ?? 1)
      : -profile.restBehind * 0.22;
    const overlapPush = (profile.overlapBias - 0.5) * 4.2;
    const runnerBoost = isPrimaryRunner ? profile.runnerBoost * 0.72 * (profile.wideBackAdvance ?? 1) : 0;
    depth = clamp(ballDepth - 9 + supportBoost + runnerBoost, 20, 84);
    depth = clamp(depth + overlapPush, 20, 88);
    y = clamp(lerp(y, ballPoint.y, isBallSide ? 0.12 : 0.03), 4, pitch.width - 4);
  } else if (roleKey === "pivot") {
    depth = clamp(ballDepth - profile.pivotBehind - (profile.pivotDrop ?? 0), 20, 72);
  } else if (roleKey === "connector") {
    const ahead =
      (isBallSide ? profile.connectorAhead * 0.6 : profile.connectorAhead * 1.05) +
      (profile.connectorAdvance ?? 0);
    depth = clamp(ballDepth + ahead, 28, 88);
  } else if (roleKey === "wideForward") {
    const diagonalRun = isBallSide
      ? profile.wideDepthBoost + (profile.dribbleBias - 0.5) * 2
      : profile.frontAhead + 2 + (profile.directness - 0.5) * 3;
    depth = clamp(ballDepth + diagonalRun + (isPrimaryRunner ? profile.runnerBoost : 0), 36, 98);
    y = isBallSide
      ? y
      : clamp(lerp(y, pitch.width / 2 + side * 11, 0.54), 8, pitch.width - 8);
  } else if (roleKey === "striker") {
    depth = clamp(ballDepth + profile.frontAhead + profile.finalThirdPin + (isPrimaryRunner ? profile.runnerBoost : 0), 38, 99);
    const pairedLaneOffset = (profile.strikerPairSupport ?? 0) * side * 6;
    y = clamp(
      lerp(y, pitch.width / 2 + pairedLaneOffset - ballSide * 2.5, isPrimaryRunner ? 0.35 : 0.16),
      14,
      pitch.width - 14
    );
  } else if (roleKey === "secondStriker") {
    depth = clamp(
      ballDepth + profile.frontAhead * 0.74 + profile.finalThirdPin + (isPrimaryRunner ? profile.runnerBoost * 0.7 : 0),
      36,
      96
    );
    y = clamp(lerp(y, pitch.width / 2 + side * 4.5, 0.34), 14, pitch.width - 14);
  }

  if (
    actionMeta?.actionType === "shot" &&
    (roleKey === "striker" || roleKey === "secondStriker" || roleKey === "wideForward" || roleKey === "connector")
  ) {
    depth = clamp(Math.max(depth, getAttackingDepth(ballPoint, player.team) + 4), 50, 99);
    y = clamp(lerp(y, pitch.width / 2 + side * 8, 0.4), 10, pitch.width - 10);
  }

  return clampToPitch({
    x: getDepthX(player.team, depth) + attackSign * (roleKey === "wideForward" && isPrimaryRunner ? 1.5 : 0),
    y,
  }, 3);
}

function chooseOffensiveAutopilotRunner(teamId, targets, actionMeta, ballPoint, profile) {
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  if (ballDepth < 38 && actionMeta?.actionType !== "pass") {
    return null;
  }

  let bestCandidate = null;
  let bestScore = -Infinity;

  state.players
    .filter((player) => player.team === teamId && !shouldSkipOffensiveAutopilotPlayer(player, actionMeta))
    .forEach((player) => {
      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      const roleBonus = profile.runnerPreferences?.[roleKey] ?? 0;
      if (roleBonus <= 0) {
        return;
      }

      const target = targets.get(player.id);
      if (!target) {
        return;
      }

      const targetDepth = getAttackingDepth(target, teamId);
      const speedValue = player.maxSpeed + player.acceleration * 0.38;
      const score =
        targetDepth * 0.12 +
        speedValue * 0.72 +
        player.intelligenceProfile.perception * 1.8 +
        Math.max(getPlayerTendency(player, "boxRun"), getPlayerTendency(player, "overlap")) * 1.2 +
        profile.directness * 0.9 +
        roleBonus -
        distance(player.position, target) * 0.08;

      if (score > bestScore) {
        bestScore = score;
        bestCandidate = player;
      }
    });

  return bestCandidate;
}

function enforceOffensiveTargetSpacing(teamId, targets, ballPoint, profile, protectedIds = new Set()) {
  const entries = state.players
    .filter((player) => player.team === teamId && targets.has(player.id))
    .map((player) => ({
      player,
      roleKey: getOffensiveRoleKey(player, profile.formation),
      target: cloneVector(targets.get(player.id)),
      protected: protectedIds.has(player.id),
    }))
    .sort((a, b) => a.target.y - b.target.y);

  const minGap = profile.phaseKey === "finalThird" ? 4.6 : 6.1;

  entries.forEach((entry) => {
    if (entry.protected) {
      return;
    }

    if (entry.roleKey === "wideBack" || entry.roleKey === "wideForward") {
      const baseY = getFormationPositions(profile.formation, teamId)[
        (teamRosterOrder[teamId] ?? []).indexOf(entry.player.id)
      ]?.y ?? entry.player.position.y;
      const disciplinedY = getOffensiveLaneY(baseY, ballPoint, profile, entry.roleKey);
      entry.target.y = lerp(entry.target.y, disciplinedY, profile.widthDiscipline ?? 0.62);
    }
  });

  for (let pass = 0; pass < 2; pass += 1) {
    for (let index = 1; index < entries.length; index += 1) {
      const previous = entries[index - 1];
      const current = entries[index];
      const verticalGap = current.target.y - previous.target.y;
      const depthGap = Math.abs(current.target.x - previous.target.x);

      if (verticalGap >= minGap || depthGap > 18) {
        continue;
      }

      const adjustment = (minGap - verticalGap) * 0.52;
      if (previous.protected && current.protected) {
        continue;
      }

      if (previous.protected) {
        current.target.y = clamp(current.target.y + adjustment * 1.9, 4, pitch.width - 4);
        continue;
      }

      if (current.protected) {
        previous.target.y = clamp(previous.target.y - adjustment * 1.9, 4, pitch.width - 4);
        continue;
      }

      previous.target.y = clamp(previous.target.y - adjustment, 4, pitch.width - 4);
      current.target.y = clamp(current.target.y + adjustment, 4, pitch.width - 4);
    }
  }

  entries.forEach((entry) => {
    targets.set(entry.player.id, clampToPitch(entry.target, 3));
  });
}

function getOffensiveOnsideLineContext(teamId, ballPoint) {
  const lineX = getSecondLastOpponentLineX(teamId);
  if (lineX === null || !ballPoint) {
    return null;
  }

  const attackSign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const lineDepth = getAttackingDepth({ x: lineX, y: pitch.width / 2 }, teamId);
  const active = Math.max(ballDepth, lineDepth) >= pitch.length / 2 - 0.4;
  const legalBoundaryX = attackSign > 0
    ? Math.max(lineX, ballPoint.x)
    : Math.min(lineX, ballPoint.x);

  if (!active) {
    return null;
  }

  return {
    lineX,
    legalBoundaryX,
    attackSign,
    ballDepth,
    lineDepth,
  };
}

function enforceOffensiveOnsideLineAwareness(
  teamId,
  targets,
  ballPoint,
  profile,
  hardFixedIds = new Set()
) {
  const context = getOffensiveOnsideLineContext(teamId, ballPoint);
  if (!context) {
    return [];
  }

  const labels = [];
  let adjusted = false;
  const shoulderMargin =
    profile.phaseKey === "finalThird"
      ? 0.38
      : profile.directness >= 0.68
        ? 0.46
        : 0.62;

  state.players
    .filter((player) => player.team === teamId && targets.has(player.id) && !isGoalkeeper(player))
    .forEach((player) => {
      if (hardFixedIds.has(player.id)) {
        return;
      }

      const roleKey = getOffensiveRoleKey(player, profile.formation);
      const target = cloneVector(targets.get(player.id));
      const currentDepth = getAttackingDepth(player.position, teamId);
      const targetDepth = getAttackingDepth(target, teamId);
      const lineRelevant =
        isFrontLineRole(roleKey) ||
        roleKey === "connector" ||
        (roleKey === "wideBack" && targetDepth >= 58);

      if (!lineRelevant || targetDepth <= pitch.length / 2 - 0.2) {
        return;
      }

      const beyondLine = (target.x - context.legalBoundaryX) * context.attackSign;
      if (beyondLine <= -0.05) {
        return;
      }

      const holdLineX = context.legalBoundaryX - context.attackSign * shoulderMargin;
      const laneCurve =
        isFrontLineRole(roleKey)
          ? (Math.sign(target.y - pitch.width / 2) || getWideSideSign(target) || 1) * 0.85
          : 0;
      const urgencyWeight =
        currentDepth > context.lineDepth + 0.4
          ? 0.84
          : isFrontLineRole(roleKey)
            ? 0.68
            : 0.52;
      const nextTarget = clampToPitch({
        x: lerp(target.x, holdLineX, urgencyWeight),
        y: clamp(target.y + laneCurve, 3.2, pitch.width - 3.2),
      }, 2.2);

      if (distance(target, nextTarget) > 0.08) {
        adjusted = true;
      }

      targets.set(player.id, nextTarget);
    });

  if (adjusted) {
    labels.push("Onside line awareness");
  }

  return labels;
}

function enforceOffensiveOccupationZones(teamId, targets, ballPoint, profile) {
  const roster = teamRosterOrder[teamId] ?? [];
  const basePositions = getFormationPositions(profile.formation, teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const ballSide = getWideSideSign(ballPoint) || 1;

  state.players
    .filter((player) => player.team === teamId && targets.has(player.id))
    .forEach((player) => {
      const roleKey = getOffensiveRoleKey(player, profile.formation);
      const target = cloneVector(targets.get(player.id));
      const baseY = basePositions[roster.indexOf(player.id)]?.y ?? player.position.y;
      const playerSide = getWideSideSign({ y: baseY }) || getWideSideSign(player);
      const isWeakSide = playerSide && playerSide === -ballSide;
      const isStrongSide = playerSide && playerSide === ballSide;

      if (roleKey === "wideForward" || roleKey === "wideBack") {
        const laneY = getOffensiveLaneY(baseY, ballPoint, profile, roleKey);
        const widthPull = isWeakSide
          ? 0.9
          : isStrongSide
            ? roleKey === "wideForward" ? 0.58 : 0.72
            : 0.62;
        target.y = lerp(target.y, laneY, clamp(widthPull * (profile.widthDiscipline ?? 0.64), 0.42, 0.92));

        if (isWeakSide) {
          target.x = getDepthX(teamId, clamp(Math.max(getAttackingDepth(target, teamId), ballDepth - 2), 34, 86));
        }

        if (isStrongSide && roleKey === "wideBack" && profile.overlapBias >= 0.62) {
          target.x = getDepthX(teamId, clamp(Math.max(getAttackingDepth(target, teamId), ballDepth - 1), 34, 88));
        }
      }

      if (roleKey === "pivot") {
        target.x = getDepthX(teamId, clamp(ballDepth - 9 - profile.shortSupport * 4, 18, 70));
        target.y = clamp(lerp(target.y, pitch.width / 2 - ballSide * 4.5, 0.48), 12, pitch.width - 12);
      }

      if (roleKey === "rest") {
        target.x = getDepthX(teamId, clamp(ballDepth - profile.restBehind, 14, 56));
        target.y = clamp(lerp(target.y, pitch.width / 2, 0.62), 13, pitch.width - 13);
      }

      if (roleKey === "striker" && ballDepth >= 54) {
        target.x = getDepthX(teamId, clamp(Math.max(getAttackingDepth(target, teamId), ballDepth + 7), 56, 98));
        target.y = clamp(lerp(target.y, pitch.width / 2, 0.42), 14, pitch.width - 14);
      }

      targets.set(player.id, clampToPitch(target, 3));
    });
}

function getOffensiveStructureBalanceTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const width = clamp(profile.width ?? 58, 42, 66);
  const wideOffset = clamp(width * 0.48, 24, 31.5);
  const halfOffset = clamp(width * 0.24, 11.5, 16.8);
  const strongWideY = clamp(pitch.width / 2 + sideSign * wideOffset, 3.5, pitch.width - 3.5);
  const weakWideY = clamp(pitch.width / 2 - sideSign * wideOffset, 3.5, pitch.width - 3.5);
  const strongHalfY = clamp(pitch.width / 2 + sideSign * halfOffset, 8, pitch.width - 8);
  const weakHalfY = clamp(pitch.width / 2 - sideSign * halfOffset, 8, pitch.width - 8);
  const points = {
    strongWidth: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.widthDiscipline * 3, 34, 88), {
      y: strongWideY,
    }),
    weakWidth: getDepthPoint(teamId, clamp(ballDepth + 1 + profile.switchBias * 6, 34, 86), {
      y: weakWideY,
    }),
    strongHalf: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.shortSupport * 3, 36, 82), {
      y: strongHalfY,
    }),
    weakHalf: getDepthPoint(teamId, clamp(ballDepth + 4 + profile.switchBias * 4, 38, 84), {
      y: weakHalfY,
    }),
    underSupport: getDepthPoint(teamId, clamp(ballDepth - 9 - profile.supportCompactness * 6, 18, 74), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.8, 0.42), 10, pitch.width - 10),
    }),
    depthPin: getDepthPoint(teamId, clamp(ballDepth + 12 + profile.directness * 4, 52, 98), {
      y: clamp(lerp(pitch.width / 2, ballPoint.y, 0.16), 14, pitch.width - 14),
    }),
    farDepth: getDepthPoint(teamId, clamp(ballDepth + 11 + profile.runnerBoost * 0.45, 50, 96), {
      y: clamp(weakHalfY, 9, pitch.width - 9),
    }),
    restCentral: clampToPitch({
      x: ballPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.74), 14, pitch.width - 14),
    }, 3),
    restFar: clampToPitch({
      x: ballPoint.x - sign * (24 + (profile.restBehind ?? 22) * 0.16),
      y: clamp(pitch.width / 2 - sideSign * 11.2, 10, pitch.width - 10),
    }, 3),
  };

  return points[slot] ?? points.underSupport;
}

function getStructureBalanceCandidates(teamId, targets, excludedIds, roleKeys, referencePoint, sideSign = 0) {
  const roleSet = new Set(roleKeys);
  const desiredSide = sideSign ? Math.sign(sideSign) : 0;

  return state.players
    .filter((player) => {
      if (player.team !== teamId || excludedIds.has(player.id) || !targets.has(player.id)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      if (!roleSet.has(roleKey)) {
        return false;
      }

      if (!desiredSide) {
        return true;
      }

      const playerSide = getWideSideSign(player);
      return playerSide === 0 || playerSide === desiredSide;
    })
    .sort((a, b) => {
      const aRole = getOffensiveRoleKey(a, teams[teamId]?.formation);
      const bRole = getOffensiveRoleKey(b, teams[teamId]?.formation);
      const aRoleFit = roleKeys.indexOf(aRole);
      const bRoleFit = roleKeys.indexOf(bRole);
      if (aRoleFit !== bRoleFit) {
        return aRoleFit - bRoleFit;
      }

      const aTarget = targets.get(a.id) ?? a.position;
      const bTarget = targets.get(b.id) ?? b.position;
      return distance(aTarget, referencePoint) - distance(bTarget, referencePoint);
    });
}

function enforceOffensiveStructureBalance(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (profile.phaseKey === "setPiece") {
    return [];
  }

  const labels = [];
  const assignedIds = new Set([...protectedIds].filter(Boolean));
  const sideSign = getWideSideSign(ballPoint) || 1;
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const targetSpace = getPitchSpaceProfile(ballPoint, teamId);
  const isFinalThird = ballDepth >= 66 || targetSpace.box >= 0.24 || targetSpace.cutbackZone >= 0.28;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getOffensiveStructureBalanceTarget(teamId, ballPoint, slot, sideSign, profile);
    const player = getStructureBalanceCandidates(teamId, targets, assignedIds, roleKeys, target, preferredSide)[0] ?? null;
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("underSupport", ["pivot", "connector", "wideBack"], "Structure: under support");
  assign("weakWidth", ["wideForward", "wideBack"], "Structure: weak-side width", -sideSign);

  if (targetSpace.wideCorridor >= 0.34 || isWidePrincipleZone(ballPoint)) {
    assign("strongHalf", ["connector", "wideForward", "secondStriker"], "Structure: half-space connection", sideSign);
    if ((profile.overlapBias ?? 0) >= 0.54 || (profile.widthDiscipline ?? 0) >= 0.66) {
      assign("strongWidth", ["wideBack", "wideForward"], "Structure: outside lane", sideSign);
    }
  } else {
    assign("strongHalf", ["connector", "wideForward", "secondStriker"], "Structure: near half-space", sideSign);
    if ((profile.switchBias ?? 0) >= 0.56) {
      assign("weakHalf", ["connector", "wideForward"], "Structure: switch connection", -sideSign);
    }
  }

  if (ballDepth >= 42) {
    assign(isFinalThird ? "farDepth" : "depthPin", ["striker", "wideForward", "secondStriker"], "Structure: depth threat");
  }

  assign("restCentral", ["rest", "pivot"], "Structure: rest-defence");
  if (ballDepth >= 48 || actionMeta?.actionType === "dribble") {
    assign("restFar", ["rest", "pivot", "wideBack"], "Structure: far rest cover", -sideSign);
  }

  const crowdedEntries = state.players
    .filter((player) => player.team === teamId && targets.has(player.id) && !assignedIds.has(player.id))
    .map((player) => ({
      player,
      target: targets.get(player.id),
      roleKey: getOffensiveRoleKey(player, profile.formation),
    }))
    .filter((entry) => distance(entry.target, ballPoint) <= (isFinalThird ? 7.2 : 8.8));

  crowdedEntries.forEach((entry, index) => {
    if (entry.roleKey === "wideForward" || entry.roleKey === "wideBack") {
      const slot = getWideSideSign(entry.player) === -sideSign ? "weakWidth" : "strongWidth";
      targets.set(entry.player.id, getOffensiveStructureBalanceTarget(teamId, ballPoint, slot, sideSign, profile));
    } else if (entry.roleKey === "pivot" || entry.roleKey === "rest") {
      targets.set(entry.player.id, getOffensiveStructureBalanceTarget(teamId, ballPoint, index % 2 ? "restFar" : "restCentral", sideSign, profile));
    } else if (entry.roleKey === "striker" || entry.roleKey === "secondStriker") {
      targets.set(entry.player.id, getOffensiveStructureBalanceTarget(teamId, ballPoint, "depthPin", sideSign, profile));
    } else {
      targets.set(entry.player.id, getOffensiveStructureBalanceTarget(teamId, ballPoint, index % 2 ? "weakHalf" : "strongHalf", sideSign, profile));
    }
  });

  if (crowdedEntries.length >= 2) {
    labels.push("Structure: decongest ball area");
  }

  return uniquePrincipleLabels(labels);
}

function getFiveLaneOccupationSlotTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const strongWideLane = sideSign < 0 ? "leftWide" : "rightWide";
  const strongHalfLane = sideSign < 0 ? "leftHalf" : "rightHalf";
  const weakHalfLane = sideSign < 0 ? "rightHalf" : "leftHalf";
  const weakWideLane = sideSign < 0 ? "rightWide" : "leftWide";
  const points = {
    strongWide: getDepthPoint(teamId, clamp(ballDepth + 2.5 + profile.widthDiscipline * 4, 34, 88), {
      y: getLaneCenterY(strongWideLane, profile),
    }),
    strongHalf: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.shortSupport * 4, 36, 84), {
      y: getLaneCenterY(strongHalfLane, profile),
    }),
    central: getDepthPoint(teamId, clamp(ballDepth - 2.5 + profile.shortSupport * 3, 28, 78), {
      y: getLaneCenterY("central", profile),
    }),
    weakHalf: getDepthPoint(teamId, clamp(ballDepth + 4 + profile.switchBias * 4, 38, 86), {
      y: getLaneCenterY(weakHalfLane, profile),
    }),
    weakWide: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.switchBias * 6, 36, 88), {
      y: getLaneCenterY(weakWideLane, profile),
    }),
    restCentral: clampToPitch({
      x: ballPoint.x - sign * (21 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.78), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.central;
}

function getFiveLaneOccupationCandidates(teamId, targets, protectedIds, roleKeys, target, preferredSide = 0) {
  const roleSet = new Set(roleKeys);
  const desiredSide = preferredSide ? Math.sign(preferredSide) : 0;

  return state.players
    .filter((player) => {
      if (player.team !== teamId || protectedIds.has(player.id) || !targets.has(player.id)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      if (!roleSet.has(roleKey)) {
        return false;
      }

      if (!desiredSide) {
        return true;
      }

      const playerSide = getWideSideSign(player);
      return playerSide === 0 || playerSide === desiredSide;
    })
    .sort((a, b) => {
      const aRole = getOffensiveRoleKey(a, teams[teamId]?.formation);
      const bRole = getOffensiveRoleKey(b, teams[teamId]?.formation);
      const aRoleFit = roleKeys.indexOf(aRole);
      const bRoleFit = roleKeys.indexOf(bRole);
      if (aRoleFit !== bRoleFit) {
        return aRoleFit - bRoleFit;
      }

      const aTarget = targets.get(a.id) ?? a.position;
      const bTarget = targets.get(b.id) ?? b.position;
      const aSideFit = desiredSide && getWideSideSign(a) !== desiredSide ? 0.8 : 0;
      const bSideFit = desiredSide && getWideSideSign(b) !== desiredSide ? 0.8 : 0;
      return distance(aTarget, target) + aSideFit - (distance(bTarget, target) + bSideFit);
    });
}

function enforceOffensiveFiveLaneOccupation(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (profile.phaseKey === "setPiece" || !ballPoint) {
    return [];
  }

  const ballDepth = getAttackingDepth(ballPoint, teamId);
  if (ballDepth < 30) {
    return [];
  }

  const sideSign = getWideSideSign(ballPoint) || 1;
  const targetSpace = getPitchSpaceProfile(ballPoint, teamId);
  const isFinalThird = ballDepth >= 66 || targetSpace.box >= 0.22 || targetSpace.cutbackZone >= 0.28;
  const shouldHoldFullWidth =
    profile.widthDiscipline >= 0.56 ||
    profile.switchBias >= 0.5 ||
    profile.overlapBias >= 0.5 ||
    targetSpace.wideCorridor >= 0.28 ||
    isFinalThird;
  const assignedIds = new Set([...protectedIds].filter(Boolean));
  const slotDefinitions = [
    {
      slot: "strongWide",
      lanes: sideSign < 0 ? ["leftWide"] : ["rightWide"],
      roleKeys: ["wideBack", "wideForward"],
      label: "Five-lane: strong-side width",
      preferredSide: sideSign,
      minDepth: 34,
      active: shouldHoldFullWidth,
    },
    {
      slot: "strongHalf",
      lanes: sideSign < 0 ? ["leftHalf"] : ["rightHalf"],
      roleKeys: ["connector", "wideForward", "secondStriker"],
      label: "Five-lane: strong half-space",
      preferredSide: sideSign,
      minDepth: 34,
      active: true,
    },
    {
      slot: "central",
      lanes: ["central"],
      roleKeys: ["pivot", "connector", "secondStriker"],
      label: "Five-lane: central link",
      preferredSide: 0,
      minDepth: 30,
      active: true,
    },
    {
      slot: "weakHalf",
      lanes: sideSign < 0 ? ["rightHalf"] : ["leftHalf"],
      roleKeys: ["connector", "wideForward", "secondStriker"],
      label: "Five-lane: weak half-space",
      preferredSide: -sideSign,
      minDepth: 38,
      active: profile.switchBias >= 0.42 || profile.shortSupport >= 0.58 || isFinalThird,
    },
    {
      slot: "weakWide",
      lanes: sideSign < 0 ? ["rightWide"] : ["leftWide"],
      roleKeys: ["wideForward", "wideBack"],
      label: "Five-lane: weak-side width",
      preferredSide: -sideSign,
      minDepth: 36,
      active: shouldHoldFullWidth,
    },
  ];
  const labels = [];
  const laneHasOccupation = (definition) =>
    state.players.some((player) => {
      if (player.team !== teamId || !targets.has(player.id)) {
        return false;
      }

      const target = targets.get(player.id);
      const laneKey = getPitchLaneKey(target);
      const depth = getAttackingDepth(target, teamId);
      return definition.lanes.includes(laneKey) && depth >= definition.minDepth && distance(target, ballPoint) >= 4.8;
    });

  slotDefinitions
    .filter((definition) => definition.active)
    .forEach((definition) => {
      if (laneHasOccupation(definition)) {
        return;
      }

      const target = getFiveLaneOccupationSlotTarget(teamId, ballPoint, definition.slot, sideSign, profile);
      const player = getFiveLaneOccupationCandidates(
        teamId,
        targets,
        assignedIds,
        definition.roleKeys,
        target,
        definition.preferredSide
      )[0] ?? null;

      if (!player) {
        return;
      }

      targets.set(player.id, target);
      assignedIds.add(player.id);
      labels.push(definition.label);
    });

  const crowdedNearBall = state.players
    .filter((player) => player.team === teamId && targets.has(player.id) && !assignedIds.has(player.id))
    .map((player) => ({
      player,
      target: targets.get(player.id),
      roleKey: getOffensiveRoleKey(player, profile.formation),
    }))
    .filter((entry) => distance(entry.target, ballPoint) <= (isFinalThird ? 6.6 : 8.2));

  crowdedNearBall.slice(0, 2).forEach((entry, index) => {
    const slot = entry.roleKey === "wideForward" || entry.roleKey === "wideBack"
      ? index % 2 ? "weakWide" : "strongWide"
      : entry.roleKey === "pivot" || entry.roleKey === "rest"
        ? "restCentral"
        : index % 2 ? "weakHalf" : "strongHalf";
    targets.set(entry.player.id, getFiveLaneOccupationSlotTarget(teamId, ballPoint, slot, sideSign, profile));
  });

  if (crowdedNearBall.length >= 2) {
    labels.push("Five-lane: decongest around ball");
  }

  return uniquePrincipleLabels(labels);
}

function getAutopilotTargetVariationRadius(player, profile, mode = "attack") {
  if (!player || isGoalkeeper(player)) {
    return 0;
  }

  const roleKey = mode === "attack"
    ? getOffensiveRoleKey(player, profile.formation)
    : getDefensiveAutopilotLineKey(player, teams[player.team]?.formation, profile.phaseKey);
  const tempo = profile.tempo ?? profile.pressingIntensity ?? 0.5;
  const risk = profile.risk ?? profile.tackleIntent ?? 0.48;
  const phaseFactor =
    profile.phaseKey === "finalThird"
      ? 0.85
      : profile.phaseKey === "buildUp"
        ? 0.55
        : profile.phaseKey === "highPress"
          ? 0.82
          : 0.68;
  const roleFactor =
    roleKey === "wideForward" || roleKey === "wideBack" || roleKey === "forward"
      ? 1.16
      : roleKey === "striker" || roleKey === "secondStriker" || roleKey === "connector"
        ? 0.96
        : roleKey === "rest" || roleKey === "back"
          ? 0.55
          : 0.72;
  const modeBase = mode === "attack" ? 0.55 : 0.38;

  return clamp(
    modeBase + tempo * 0.34 + risk * 0.24 + phaseFactor * 0.26,
    0.32,
    1.35
  ) * roleFactor;
}

function applyAutopilotTargetVariation(teamId, targets, profile, mode = "attack", protectedIds = new Set()) {
  if (profile.phaseKey === "setPiece") {
    return;
  }

  state.players.forEach((player) => {
    if (player.team !== teamId || protectedIds.has(player.id) || !targets.has(player.id)) {
      return;
    }

    const radius = getAutopilotTargetVariationRadius(player, profile, mode);
    if (radius <= 0.02) {
      return;
    }

    targets.set(player.id, addPointNoise(targets.get(player.id), radius, 3));
  });
}

function getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, excludedIds = new Set(), referencePoint = null) {
  const roleSet = new Set(roleKeys);
  return state.players
    .filter((player) => {
      if (player.team !== teamId || excludedIds.has(player.id) || !targets.has(player.id)) {
        return false;
      }

      return roleSet.has(getOffensiveRoleKey(player, teams[teamId]?.formation));
    })
    .sort((a, b) => {
      const aRole = getOffensiveRoleKey(a, teams[teamId]?.formation);
      const bRole = getOffensiveRoleKey(b, teams[teamId]?.formation);
      const aRoleFit = roleKeys.indexOf(aRole);
      const bRoleFit = roleKeys.indexOf(bRole);
      if (aRoleFit !== bRoleFit) {
        return aRoleFit - bRoleFit;
      }

      if (!referencePoint) {
        return getAutoPilotRoleStrength(b, "runner") - getAutoPilotRoleStrength(a, "runner");
      }

      return distance(a.position, referencePoint) - distance(b.position, referencePoint);
    })[0] ?? null;
}

function getMovableAutopilotPlayerByRolesOnSide(
  teamId,
  roleKeys,
  targets,
  excludedIds = new Set(),
  sideSign = 0,
  referencePoint = null
) {
  const roleSet = new Set(roleKeys);
  const desiredSide = sideSign === 0 ? 0 : Math.sign(sideSign);
  const candidates = state.players.filter((player) => {
    if (player.team !== teamId || excludedIds.has(player.id) || !targets.has(player.id)) {
      return false;
    }

    if (!roleSet.has(getOffensiveRoleKey(player, teams[teamId]?.formation))) {
      return false;
    }

    if (!desiredSide) {
      return true;
    }

    const playerSide = getWideSideSign(player);
    return playerSide === 0 || playerSide === desiredSide;
  });

  if (!candidates.length) {
    return getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, excludedIds, referencePoint);
  }

  return candidates
    .sort((a, b) => {
      const aRole = getOffensiveRoleKey(a, teams[teamId]?.formation);
      const bRole = getOffensiveRoleKey(b, teams[teamId]?.formation);
      const aRoleFit = roleKeys.indexOf(aRole);
      const bRoleFit = roleKeys.indexOf(bRole);
      if (aRoleFit !== bRoleFit) {
        return aRoleFit - bRoleFit;
      }

      const aSideFit = getWideSideSign(a) === desiredSide ? 0 : 1;
      const bSideFit = getWideSideSign(b) === desiredSide ? 0 : 1;
      if (aSideFit !== bSideFit) {
        return aSideFit - bSideFit;
      }

      if (!referencePoint) {
        return getAutoPilotRoleStrength(b, "runner") - getAutoPilotRoleStrength(a, "runner");
      }

      return distance(a.position, referencePoint) - distance(b.position, referencePoint);
    })[0] ?? null;
}

function setAutopilotPrincipleTarget(targets, player, target) {
  if (!player || !targets.has(player.id)) {
    return false;
  }

  targets.set(player.id, clampToPitch(target, 3));
  return true;
}

function getSupportUnderBallTarget(teamId, ballPoint, sideSign, profile) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const supportDepth = clamp(depth - 8.5 - profile.supportCompactness * 8, 18, 78);
  return getDepthPoint(teamId, supportDepth, {
    y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 8.5, 0.42), 8, pitch.width - 8),
  });
}

function getThirdManRunnerTarget(teamId, ballPoint, sideSign, profile) {
  const depth = getAttackingDepth(ballPoint, teamId);
  const runnerDepth = clamp(depth + 9 + profile.runnerBoost * 0.72, 38, 96);
  return getDepthPoint(teamId, runnerDepth, {
    y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 11, 0.42), 8, pitch.width - 8),
  });
}

function getBoxOccupationTarget(teamId, ballPoint, slot) {
  const sign = getAttackDirectionSign(teamId);
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const ballSide = Math.sign(ballPoint.y - pitch.width / 2) || 1;
  const points = {
    nearPost: {
      x: penaltySpot.x + sign * 3.4,
      y: pitch.width / 2 + ballSide * 8.8,
    },
    farPost: {
      x: penaltySpot.x + sign * 4.2,
      y: pitch.width / 2 - ballSide * 12.5,
    },
    penaltySpot: {
      x: penaltySpot.x - sign * 0.8,
      y: pitch.width / 2,
    },
    edge: {
      x: penaltySpot.x - sign * 8.2,
      y: pitch.width / 2 - ballSide * 2.8,
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 2);
}

function getShotReboundGeometryContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (actionMeta?.actionType !== "shot") {
    return null;
  }

  const shooter = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    (shooter ? getPlayerBallControlPoint(shooter) : null) ??
    state.ball.position;
  const intendedTarget =
    actionMeta.target ??
    state.ball.target ??
    ballPoint ??
    getOpponentGoalCenter(teamId);

  if (!startPoint || !intendedTarget) {
    return null;
  }

  const sign = getAttackDirectionSign(teamId);
  const goalCenter = getOpponentGoalCenter(teamId);
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const shotWindow = shooter ? getShotWindowProfile(shooter, startPoint, intendedTarget) : null;
  const resolvedProfile = shooter
    ? resolveBallActionProfile("shot", startPoint, intendedTarget, shooter, null)
    : null;
  const shotDistance = distance(startPoint, goalCenter);
  const targetY = Number.isFinite(intendedTarget.y) ? intendedTarget.y : goalCenter.y;
  const shotSide =
    Math.sign(targetY - pitch.width / 2) ||
    Math.sign(startPoint.y - pitch.width / 2) ||
    1;
  const shotSpeed = Math.max(
    state.ball.currentSpeed ||
      state.ball.launchSpeed ||
      state.ball.speed ||
      resolvedProfile?.averageSpeed ||
      18,
    0.1
  );
  const shotPower = clamp((shotSpeed - 9.5) / 17, 0, 1);
  const blockRisk = shotWindow?.blockRisk ?? 0.42;
  const goalkeeperOpenness = shotWindow?.goalkeeperOpenness ?? 0.54;
  const shotQuality = shotWindow?.quality ?? 0.52;
  const laneClarity = shotWindow?.laneClarity ?? 0.54;
  const closeRange = clamp((24 - shotDistance) / 20, 0, 1);
  const cornerReach = clamp(Math.abs(targetY - pitch.width / 2) / (7.32 / 2), 0, 1.15);
  const likelyBlock = blockRisk >= 0.52 && shotDistance >= 13;
  const likelyParry =
    !likelyBlock &&
    (
      goalkeeperOpenness <= 0.62 ||
      shotQuality <= 0.62 ||
      cornerReach >= 0.52 ||
      shotPower >= 0.5
    );
  const reboundProbability = clamp(
    blockRisk * 0.34 +
      (1 - goalkeeperOpenness) * 0.28 +
      (1 - shotQuality) * 0.2 +
      shotPower * 0.08 +
      cornerReach * 0.08 +
      (1 - laneClarity) * 0.08 +
      profile.directness * 0.02,
    0,
    1
  );
  let spillPoint;

  if (likelyBlock) {
    const blockRatio = clamp(0.34 + blockRisk * 0.22 - closeRange * 0.08, 0.32, 0.62);
    const blockPoint = {
      x: lerp(startPoint.x, intendedTarget.x, blockRatio),
      y: lerp(startPoint.y, intendedTarget.y, blockRatio),
    };
    spillPoint = {
      x: blockPoint.x - sign * (1.8 + blockRisk * 3.2),
      y: blockPoint.y + shotSide * (2.1 + shotPower * 2.8),
    };
  } else if (likelyParry) {
    spillPoint = {
      x: penaltySpot.x + sign * clamp(0.8 + shotQuality * 2.6 - closeRange * 0.8, 0.6, 3.4),
      y: lerp(targetY, pitch.width / 2 + shotSide * (6.8 + cornerReach * 4.8), 0.62),
    };
  } else {
    spillPoint = {
      x: penaltySpot.x - sign * clamp(1.6 + shotDistance * 0.04, 1.8, 3.8),
      y: pitch.width / 2 + shotSide * clamp(2.4 + shotPower * 2.6, 2.4, 5.2),
    };
  }

  return {
    startPoint: cloneVector(startPoint),
    shotTarget: cloneVector(intendedTarget),
    goalCenter,
    penaltySpot,
    sign,
    shotSide,
    shotDistance,
    shotPower,
    blockRisk,
    goalkeeperOpenness,
    shotQuality,
    laneClarity,
    cornerReach,
    reboundProbability,
    likelyBlock,
    likelyParry,
    highReboundChance:
      likelyBlock ||
      likelyParry ||
      reboundProbability >= 0.44,
    spillPoint: clampToPitch(spillPoint, 2.2),
  };
}

function getShotReboundTarget(teamId, ballPoint, slot, geometry = null) {
  const sign = getAttackDirectionSign(teamId);
  const penaltySpot = geometry?.penaltySpot ?? getOpponentPenaltySpot(teamId);
  const shotSide =
    geometry?.shotSide ??
    (Math.sign((ballPoint?.y ?? pitch.width / 2) - pitch.width / 2) || 1);
  const spillPoint = geometry?.spillPoint ?? null;

  if (geometry && spillPoint) {
    const points = {
      crash: geometry.likelyBlock
        ? {
            x: spillPoint.x + sign * 2.2,
            y: lerp(spillPoint.y, pitch.width / 2 + shotSide * 3.2, 0.36),
          }
        : {
            x: lerp(spillPoint.x, penaltySpot.x + sign * 4.4, 0.38),
            y: lerp(spillPoint.y, pitch.width / 2 + shotSide * 4.2, 0.46),
          },
      farRebound: {
        x: penaltySpot.x + sign * (geometry.likelyParry ? 3.8 : 2.8),
        y: pitch.width / 2 - shotSide * (geometry.likelyBlock ? 7.6 : 10.4),
      },
      centralSecondBall: geometry.likelyBlock
        ? {
            x: spillPoint.x - sign * 3.6,
            y: lerp(spillPoint.y, pitch.width / 2, 0.62),
          }
        : {
            x: lerp(spillPoint.x, penaltySpot.x - sign * 1.2, 0.62),
            y: lerp(spillPoint.y, pitch.width / 2 - shotSide * 1.8, 0.56),
          },
      edgeLock: {
        x: penaltySpot.x - sign * (geometry.likelyBlock ? 12.2 : 9.8),
        y: pitch.width / 2 - shotSide * (3.6 + geometry.reboundProbability * 2.2),
      },
    };

    return clampToPitch(points[slot] ?? points.centralSecondBall, 2);
  }

  const points = {
    crash: {
      x: penaltySpot.x + sign * 5.6,
      y: pitch.width / 2 + shotSide * 4.4,
    },
    farRebound: {
      x: penaltySpot.x + sign * 4.2,
      y: pitch.width / 2 - shotSide * 8.8,
    },
    centralSecondBall: {
      x: penaltySpot.x - sign * 1.5,
      y: pitch.width / 2 - shotSide * 1.4,
    },
    edgeLock: {
      x: penaltySpot.x - sign * 9.4,
      y: pitch.width / 2 - shotSide * 3.8,
    },
  };

  return clampToPitch(points[slot] ?? points.centralSecondBall, 2);
}

function applyShotReboundPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds = new Set()) {
  if (actionMeta?.actionType !== "shot") {
    return [];
  }

  const labels = [];
  const geometry = getShotReboundGeometryContext(teamId, ballPoint, actionMeta, profile);
  const shooter = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const shotWindow = shooter
    ? getShotWindowProfile(
        shooter,
        actionMeta.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position,
        ballPoint
      )
    : null;
  const highReboundChance =
    geometry?.highReboundChance ??
    (
      !shotWindow ||
      shotWindow.blockRisk >= 0.28 ||
      shotWindow.goalkeeperOpenness <= 0.56 ||
      shotWindow.quality <= 0.66
    );

  const crashRunner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["striker", "wideForward", "secondStriker"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, crashRunner, getShotReboundTarget(teamId, ballPoint, "crash", geometry))) {
    excludedIds.add(crashRunner.id);
    labels.push(geometry?.likelyBlock ? "Attack blocked-shot rebound" : "Crash rebound");
  }

  if (highReboundChance) {
    const farRunner = getMovableAutopilotPlayerByRoles(
      teamId,
      ["wideForward", "secondStriker", "connector"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, farRunner, getShotReboundTarget(teamId, ballPoint, "farRebound", geometry))) {
      excludedIds.add(farRunner.id);
      labels.push(geometry?.likelyParry ? "Far-side parry runner" : "Far-post rebound");
    }
  }

  const secondBall = getMovableAutopilotPlayerByRoles(
    teamId,
    ["connector", "pivot", "wideForward"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(
    targets,
    secondBall,
    getShotReboundTarget(teamId, ballPoint, highReboundChance ? "centralSecondBall" : "edgeLock", geometry)
  )) {
    excludedIds.add(secondBall.id);
    labels.push(highReboundChance ? "Second-ball finish" : "Edge rebound lock");
  }

  const edgeLock = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "rest"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, edgeLock, getShotReboundTarget(teamId, ballPoint, "edgeLock", geometry))) {
    excludedIds.add(edgeLock.id);
    labels.push("Rest-defence after shot");
  }

  if (labels.length && geometry?.reboundProbability >= 0.44) {
    labels.unshift("Shot rebound geometry");
  }

  return labels;
}

function getSecondBallAnticipationContext(teamId, ballPoint, actionMeta, profile = {}) {
  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType !== "pass" || state.restartPhase?.type || profile?.phaseKey === "setPiece") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position;
  const targetPoint = actionMeta?.target ?? ballPoint ?? state.ball.target;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const initiator = getPlayerById(
    actionMeta?.carrierPlayerId ??
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const passDistance = distance(startPoint, targetPoint);
  if (passDistance < 16) {
    return null;
  }

  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const resolvedProfile = resolveBallActionProfile(
    actionType,
    startPoint,
    targetPoint,
    initiator,
    actionMeta?.receiverPlayerId ?? null
  );
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const profileText = [
    resolvedProfile.key,
    resolvedProfile.label,
    actionMeta?.profileKey,
    actionMeta?.profileLabel,
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const aerial = isAerialFlightStyle(resolvedProfile.flightStyle);
  const delivery =
    profileText.includes("cross") ||
    profileText.includes("delivery") ||
    profileText.includes("switch") ||
    profileText.includes("onto-9") ||
    profileText.includes("second-ball") ||
    profileText.includes("route-one");
  const finalThirdLanding =
    targetThreat.box >= 0.16 ||
    targetThreat.assistZone >= 0.34 ||
    targetThreat.cutbackZone >= 0.22 ||
    getAttackingDepth(targetPoint, teamId) >= 66;
  const lineBreakLanding =
    actionSpace.lineBreakCount >= 1 ||
    targetThreat.behindLine >= 0.22 ||
    (forwardGain >= 9 && passDistance >= 18);
  const shouldAnticipate =
    (passDistance >= 22 && (aerial || delivery || lineBreakLanding)) ||
    (passDistance >= 18 && finalThirdLanding) ||
    (receiver && passDistance >= 20 && getPlayerPressureLoad(receiver, targetPoint) >= 0.5);

  if (!shouldAnticipate) {
    return null;
  }

  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    getWideSideSign(receiver) ||
    1;

  return {
    actionType,
    startPoint: cloneVector(startPoint),
    targetPoint: clampToPitch(targetPoint, 2.2),
    initiator,
    receiver,
    passDistance,
    forwardGain,
    resolvedProfile,
    actionSpace,
    targetThreat,
    aerial,
    delivery,
    finalThirdLanding,
    lineBreakLanding,
    sideSign,
  };
}

function getOffensiveSecondBallAnticipationTarget(teamId, context, slot) {
  const sign = getAttackDirectionSign(teamId);
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const points = {
    contestSupport: {
      x: target.x - sign * (context.finalThirdLanding ? 1.8 : 2.8),
      y: lerp(target.y, pitch.width / 2, context.finalThirdLanding ? 0.12 : 0.22),
    },
    dropZone: {
      x: target.x - sign * (context.aerial ? 7.2 : 5.2),
      y: lerp(target.y, pitch.width / 2, context.finalThirdLanding ? 0.42 : 0.54),
    },
    farCollect: {
      x: target.x - sign * 4.4,
      y: clamp(target.y - sideSign * (context.finalThirdLanding ? 9.8 : 12.4), 5, pitch.width - 5),
    },
    edgeLock: {
      x: context.finalThirdLanding ? penaltySpot.x - sign * 9.2 : target.x - sign * 12.2,
      y: clamp(lerp(target.y, pitch.width / 2 - sideSign * 4.8, 0.52), 11, pitch.width - 11),
    },
    restLock: {
      x: target.x - sign * (context.lineBreakLanding ? 22 : 18),
      y: clamp(lerp(target.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    },
  };

  return clampToPitch(points[slot] ?? points.dropZone, 2.2);
}

function applyOffensiveSecondBallAnticipationTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getSecondBallAnticipationContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    context.initiator?.id,
    context.receiver?.id,
  ].filter(Boolean));
  const protectedSecondBallIds = new Set();
  const assign = (slot, roleKeys, label) => {
    const target = getOffensiveSecondBallAnticipationTarget(teamId, context, slot);
    const player = getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, target);
    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedSecondBallIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("contestSupport", ["striker", "wideForward", "secondStriker", "connector"], "Second ball: contest support");
  assign("dropZone", ["connector", "pivot", "wideBack"], "Second ball: drop-zone collector");

  if (context.finalThirdLanding || context.delivery) {
    assign("farCollect", ["wideForward", "secondStriker", "wideBack"], "Second ball: far-side collector");
    assign("edgeLock", ["connector", "pivot", "wideForward"], "Second ball: edge lock");
  }

  assign("restLock", ["pivot", "rest", "wideBack"], "Second ball: rest-defence lock");

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedSecondBallIds,
  };
}

function applyCornerDeliveryPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds = new Set()) {
  const restart = actionMeta?.beforeSnapshot?.restartPhase;
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isCornerAction =
    restart?.type === "corner" ||
    state.restartPhase?.type === "corner" ||
    principleText.includes("corner");

  if (!isCornerAction) {
    return [];
  }

  const sideY = Number.isFinite(restart?.sideY)
    ? restart.sideY
    : Number.isFinite(state.restartPhase?.sideY)
      ? state.restartPhase.sideY
      : actionMeta?.beforeSnapshot?.ball?.position?.y ?? ballPoint.y;
  const labels = [];
  const plannedRunner = getPlayerById(actionMeta?.principleRunnerPlayerId);
  if (
    plannedRunner?.team === teamId &&
    !excludedIds.has(plannedRunner.id) &&
    setAutopilotPrincipleTarget(targets, plannedRunner, clampToPitch(ballPoint, 2))
  ) {
    excludedIds.add(plannedRunner.id);
    labels.push("Primary corner runner");
  }

  const nearRunner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["striker", "secondStriker", "wideForward"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, nearRunner, getCornerDeliveryTarget(teamId, sideY, "nearPost"))) {
    excludedIds.add(nearRunner.id);
    labels.push("Near-post corner run");
  }

  const farRunner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["wideForward", "striker", "secondStriker"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, farRunner, getCornerDeliveryTarget(teamId, sideY, "farPost"))) {
    excludedIds.add(farRunner.id);
    labels.push("Far-post corner run");
  }

  const centralRunner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["connector", "striker", "secondStriker"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, centralRunner, getCornerDeliveryTarget(teamId, sideY, "penaltySpot"))) {
    excludedIds.add(centralRunner.id);
    labels.push("Penalty-spot attack");
  }

  const edgePlayer = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "connector", "wideBack"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, edgePlayer, getCornerDeliveryTarget(teamId, sideY, "edge"))) {
    excludedIds.add(edgePlayer.id);
    labels.push("Edge box lock");
  }

  return labels;
}

function getGoalkeeperBuildOutSupportTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const widthScale = profile.widthDiscipline ?? 0.64;
  const points = {
    splitNear: getDepthPoint(teamId, 18, {
      y: clamp(pitch.width / 2 + sideSign * lerp(10.5, 15.5, widthScale), 7, pitch.width - 7),
    }),
    splitFar: getDepthPoint(teamId, 20, {
      y: clamp(pitch.width / 2 - sideSign * lerp(10.5, 15.5, widthScale), 7, pitch.width - 7),
    }),
    wideOutlet: getDepthPoint(teamId, 31, {
      y: clamp(pitch.width / 2 + sideSign * lerp(24, 30, widthScale), 4.5, pitch.width - 4.5),
    }),
    pivotDrop: getDepthPoint(teamId, clamp(27 + (profile.shortSupport ?? 0.55) * 5, 27, 34), {
      y: clamp(lerp(pitch.width / 2, ballPoint.y, 0.12), 20, 48),
    }),
    secondBall: getDepthPoint(teamId, 48, {
      y: clamp(pitch.width / 2 - sideSign * 7, 12, pitch.width - 12),
    }),
  };

  return points[slot] ?? points.pivotDrop;
}

function applyGoalkeeperBuildOutPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds = new Set()) {
  const goalkeeper = getPlayerById(
    actionMeta?.carrierPlayerId ??
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  if (!goalkeeper || !isGoalkeeper(goalkeeper)) {
    return [];
  }

  const labels = [];
  const sideSign = getWideSideSign(ballPoint) || 1;
  const directRelease = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase()
    .includes("gk release");

  const nearCenterBack = getMovableAutopilotPlayerByRolesOnSide(
    teamId,
    ["rest"],
    targets,
    excludedIds,
    sideSign,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, nearCenterBack, getGoalkeeperBuildOutSupportTarget(teamId, ballPoint, "splitNear", sideSign, profile))) {
    excludedIds.add(nearCenterBack.id);
    labels.push("Split centre-back");
  }

  const farCenterBack = getMovableAutopilotPlayerByRolesOnSide(
    teamId,
    ["rest"],
    targets,
    excludedIds,
    -sideSign,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, farCenterBack, getGoalkeeperBuildOutSupportTarget(teamId, ballPoint, "splitFar", sideSign, profile))) {
    excludedIds.add(farCenterBack.id);
    labels.push("Opposite centre-back support");
  }

  const wideOutlet = getMovableAutopilotPlayerByRolesOnSide(
    teamId,
    ["wideBack"],
    targets,
    excludedIds,
    sideSign,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, wideOutlet, getGoalkeeperBuildOutSupportTarget(teamId, ballPoint, "wideOutlet", sideSign, profile))) {
    excludedIds.add(wideOutlet.id);
    labels.push("Wide build-out outlet");
  }

  const pivot = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "connector"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, pivot, getGoalkeeperBuildOutSupportTarget(teamId, ballPoint, directRelease ? "secondBall" : "pivotDrop", sideSign, profile))) {
    excludedIds.add(pivot.id);
    labels.push(directRelease ? "Second-ball screen" : "6 drops to connect");
  }

  return labels;
}

function applyBoxOccupationPrincipleTargets(teamId, targets, ballPoint, excludedIds = new Set()) {
  const labels = [];
  const striker = getMovableAutopilotPlayerByRoles(teamId, ["striker", "secondStriker"], targets, excludedIds, ballPoint);
  if (setAutopilotPrincipleTarget(targets, striker, getBoxOccupationTarget(teamId, ballPoint, "nearPost"))) {
    excludedIds.add(striker.id);
    labels.push("Near-post run");
  }

  const farRunner = getMovableAutopilotPlayerByRoles(teamId, ["wideForward", "secondStriker"], targets, excludedIds, ballPoint);
  if (setAutopilotPrincipleTarget(targets, farRunner, getBoxOccupationTarget(teamId, ballPoint, "farPost"))) {
    excludedIds.add(farRunner.id);
    labels.push("Far-post run");
  }

  const centralRunner = getMovableAutopilotPlayerByRoles(teamId, ["connector", "striker"], targets, excludedIds, ballPoint);
  if (setAutopilotPrincipleTarget(targets, centralRunner, getBoxOccupationTarget(teamId, ballPoint, "penaltySpot"))) {
    excludedIds.add(centralRunner.id);
    labels.push("Penalty-spot occupation");
  }

  const edgePlayer = getMovableAutopilotPlayerByRoles(teamId, ["connector", "pivot"], targets, excludedIds, ballPoint);
  if (setAutopilotPrincipleTarget(targets, edgePlayer, getBoxOccupationTarget(teamId, ballPoint, "edge"))) {
    labels.push("Edge support");
  }

  return labels;
}

function getTimedBoxArrivalContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile.phaseKey === "setPiece") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType === "shot" || actionType === "recovery") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetThreat = getPitchThreatProfile(ballPoint, teamId);
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const principleText = [
    actionMeta?.profileLabel,
    actionMeta?.label,
    actionMeta?.autoReason,
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isWideSource = isWidePrincipleZone(startPoint);
  const isRunwayAction =
    principleText.includes("runway") ||
    principleText.includes("open-grass") ||
    principleText.includes("carry end product") ||
    principleText.includes("runway end product");
  const isCentralCarry =
    actionType === "dribble" &&
    Math.abs(ballPoint.y - pitch.width / 2) <= 18 &&
    targetDepth >= 56;
  const isEndProductAction =
    principleText.includes("end product") ||
    principleText.includes("final pass") ||
    principleText.includes("chance") ||
    principleText.includes("shooting window");
  const runwayFinishCue =
    isRunwayAction &&
    (
      targetDepth >= 58 ||
      targetThreat.behindLine >= 0.18 ||
      targetThreat.centralPocket >= 0.24 ||
      targetThreat.value >= 0.42
    );
  const isFinalAction =
    targetDepth >= 70 ||
    targetThreat.box >= 0.2 ||
    targetThreat.cutbackZone >= 0.24 ||
    runwayFinishCue ||
    isEndProductAction ||
    isCentralCarry ||
    principleText.includes("cutback") ||
    principleText.includes("cross") ||
    principleText.includes("delivery") ||
    principleText.includes("final-third") ||
    principleText.includes("end product") ||
    (actionType === "dribble" && targetDepth >= 64) ||
    (actionType === "pass" && isWideSource && targetDepth >= 62);

  if (!isFinalAction) {
    return null;
  }

  const initiator = getPlayerById(
    actionMeta?.carrierPlayerId ??
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const receiverPlayerId = actionMeta?.receiverPlayerId ?? null;
  const actionDistance = distance(startPoint, ballPoint);
  const resolvedProfile = resolveBallActionProfile(
    actionType,
    startPoint,
    ballPoint,
    initiator,
    receiverPlayerId
  );
  const actionSpeed = Math.max(
    actionMeta?.speed ??
      state.ball.speed ??
      resolvedProfile.averageSpeed ??
      (actionType === "dribble" ? 5.2 : 12),
    0.1
  );
  const eta = actionDistance / actionSpeed;
  const sideSign =
    getWideSideSign(startPoint) ||
    getWideSideSign(ballPoint) ||
    1;
  const deliveryKind =
    principleText.includes("cutback") || targetThreat.cutbackZone >= 0.24
      ? "cutback"
      : principleText.includes("cross") || principleText.includes("delivery") || (isWideSource && targetThreat.box >= 0.16)
        ? "cross"
        : runwayFinishCue
          ? "runway"
          : actionType === "dribble"
          ? isCentralCarry ? "centralCarry" : "carry"
          : "finalPass";

  return {
    actionType,
    startPoint,
    targetPoint: ballPoint,
    targetThreat,
    targetDepth,
    startDepth,
    eta,
    arrivalWindow: eta + 0.65 + (profile.tempo ?? 0.5) * 0.26,
    sideSign,
    deliveryKind,
    isWideSource,
    isRunwayAction,
    runwayFinishCue,
    isCentralCarry,
    isEndProductAction,
  };
}

function getTimedBoxArrivalTarget(teamId, context, slot) {
  const sign = getAttackDirectionSign(teamId);
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const sideSign = context.sideSign || 1;
  const bylinePull = context.deliveryKind === "cutback" ? -1.8 : 0;
  const centralCarryPull = context.deliveryKind === "centralCarry" || context.deliveryKind === "runway" ? 1 : 0;
  const points = {
    nearPost: {
      x: penaltySpot.x + sign * (4.4 + (context.deliveryKind === "cross" ? 0.9 : centralCarryPull ? 0.35 : 0.2)),
      y: pitch.width / 2 + sideSign * (centralCarryPull ? 4.6 : 5.6),
    },
    farPost: {
      x: penaltySpot.x + sign * (4.2 + (context.deliveryKind === "cross" ? 0.7 : centralCarryPull ? 0.45 : 0.1)),
      y: pitch.width / 2 - sideSign * (context.deliveryKind === "cross" ? 10.4 : 9.2),
    },
    centralGold: {
      x: penaltySpot.x + sign * (context.deliveryKind === "runway" ? 1.6 : 0.9),
      y: pitch.width / 2 + sideSign * (context.deliveryKind === "cross" ? 1.6 : 0.4),
    },
    penaltySpot: {
      x: penaltySpot.x - sign * (0.8 + bylinePull),
      y: pitch.width / 2 - sideSign * 0.7,
    },
    cutbackEdge: {
      x: penaltySpot.x - sign * (7.2 + (context.deliveryKind === "cutback" ? 1.6 : centralCarryPull ? 0.9 : 0.4)),
      y: pitch.width / 2 - sideSign * (centralCarryPull ? 5.8 : 4.8),
    },
    lateEdge: {
      x: penaltySpot.x - sign * 10.6,
      y: pitch.width / 2 + sideSign * 5.2,
    },
    reverseSquare: {
      x: penaltySpot.x - sign * 5.8,
      y: pitch.width / 2 + sideSign * 9.2,
    },
    restLock: clampToPitch({
      x: context.targetPoint.x - sign * 20.5,
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    }, 3),
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 2);
}

function chooseTimedBoxArrivalPlayer(teamId, targets, excludedIds, roleKeys, target, context) {
  const roleSet = new Set(roleKeys);
  const arrivalWindow = Math.max(context.arrivalWindow, 0.75);

  return state.players
    .filter((player) => {
      if (player.team !== teamId || excludedIds.has(player.id) || !targets.has(player.id) || isGoalkeeper(player)) {
        return false;
      }

      return roleSet.has(getOffensiveRoleKey(player, teams[teamId]?.formation));
    })
    .map((player) => {
      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      const runDistance = distance(player.position, target);
      const timeToTarget = computeTimeToCoverDistance(player, runDistance, target);
      const timingFit = clamp(1 - Math.abs(timeToTarget - arrivalWindow) / 1.55, 0, 1);
      const canArrive = timeToTarget <= arrivalWindow + 1.05;
      const roleIndex = roleKeys.indexOf(roleKey);
      const roleFit = roleIndex >= 0 ? 1 - roleIndex * 0.08 : 0.4;
      const score =
        roleFit * 0.34 +
        timingFit * 0.42 +
        getAutoPilotRoleStrength(player, "runner") * 0.22 +
        getAutoPilotRoleStrength(player, "finisher") * 0.2 +
        getPlayerTendency(player, "boxRun") * 0.14 -
        Math.max(timeToTarget - arrivalWindow, 0) * 0.16 -
        runDistance * 0.006 +
        (canArrive ? 0.22 : -0.24);

      return {
        player,
        score,
        canArrive,
        timeToTarget,
      };
    })
    .filter((entry) => entry.canArrive || entry.score >= 0.42)
    .sort((a, b) => b.score - a.score)[0]?.player ?? null;
}

function applyTimedFinalThirdBoxArrivals(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getTimedBoxArrivalContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([...protectedIds].filter(Boolean));
  const protectedArrivalIds = new Set();
  const plannedRunner = getPlayerById(actionMeta?.principleRunnerPlayerId);
  if (plannedRunner?.team === teamId) {
    assignedIds.add(plannedRunner.id);
  }

  const assign = (slot, roleKeys, label) => {
    const target = getTimedBoxArrivalTarget(teamId, context, slot);
    const player = chooseTimedBoxArrivalPlayer(teamId, targets, assignedIds, roleKeys, target, context);
    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedArrivalIds.add(player.id);
    labels.push(label);
    return player;
  };

  if (context.deliveryKind === "cross") {
    assign("nearPost", ["striker", "secondStriker", "wideForward"], "Timed box: near-post attack");
    assign("farPost", ["wideForward", "striker", "secondStriker"], "Timed box: far-post attack");
    assign("penaltySpot", ["connector", "striker", "secondStriker"], "Timed box: penalty spot");
    assign("lateEdge", ["connector", "pivot", "wideForward"], "Timed box: edge lock");
  } else if (context.deliveryKind === "cutback") {
    assign("penaltySpot", ["connector", "striker", "secondStriker"], "Timed box: cutback target");
    assign("farPost", ["wideForward", "striker", "secondStriker"], "Timed box: far-post hold");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Timed box: cutback edge");
    assign("nearPost", ["striker", "secondStriker", "wideForward"], "Timed box: front run");
  } else if (context.deliveryKind === "runway" || context.deliveryKind === "centralCarry") {
    assign("centralGold", ["striker", "secondStriker", "wideForward"], "Finish lane: central goal run");
    assign("nearPost", ["striker", "wideForward", "secondStriker"], "Finish lane: near-post pin");
    assign("farPost", ["wideForward", "secondStriker", "striker"], "Finish lane: far-post hold");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Finish lane: cutback edge");
    assign("reverseSquare", ["connector", "wideForward", "secondStriker"], "Finish lane: reverse pass option");
  } else {
    assign("penaltySpot", ["striker", "secondStriker", "wideForward"], "Timed box: central arrival");
    assign("farPost", ["wideForward", "striker", "secondStriker"], "Timed box: far-post arrival");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Timed box: second wave");
  }

  const restLock = chooseTimedBoxArrivalPlayer(
    teamId,
    targets,
    assignedIds,
    ["pivot", "rest", "wideBack"],
    getTimedBoxArrivalTarget(teamId, context, "restLock"),
    {
      ...context,
      arrivalWindow: context.arrivalWindow + 0.8,
    }
  );
  if (setAutopilotPrincipleTarget(targets, restLock, getTimedBoxArrivalTarget(teamId, context, "restLock"))) {
    protectedArrivalIds.add(restLock.id);
    labels.push("Timed box: rest-defence lock");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedArrivalIds,
  };
}

function getAttackingBoxOccupationChainContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile.phaseKey === "setPiece") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType === "shot" || actionType === "recovery") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta?.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const sourcePoint = actionType === "dribble" ? targetPoint : startPoint;
  const sourceThreat = getPitchThreatProfile(sourcePoint, teamId);
  const targetThreat = getPitchThreatProfile(targetPoint, teamId);
  const sourceDepth = getAttackingDepth(sourcePoint, teamId);
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const actionDistance = distance(startPoint, targetPoint);
  const sideSign =
    getWideSideSign(sourcePoint) ||
    getWideSideSign(targetPoint) ||
    1;
  const principleText = [
    actionMeta?.profileKey,
    actionMeta?.profileLabel,
    actionMeta?.label,
    actionMeta?.autoReason,
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const sourceIsWide =
    isWidePrincipleZone(sourcePoint) ||
    sourceThreat.assistZone >= 0.24 ||
    Math.abs(sourcePoint.y - pitch.width / 2) >= 17;
  const finalThirdCue =
    sourceDepth >= 66 ||
    targetDepth >= 68 ||
    targetThreat.box >= 0.12 ||
    targetThreat.cutbackZone >= 0.14 ||
    targetThreat.assistZone >= 0.28 ||
    actionSpace.targetThreat.behindLine >= 0.18;
  const deliveryCue =
    principleText.includes("cross") ||
    principleText.includes("delivery") ||
    principleText.includes("cutback") ||
    principleText.includes("box") ||
    principleText.includes("final-third") ||
    principleText.includes("end product") ||
    principleText.includes("wide") ||
    (actionType === "pass" && (targetThreat.box >= 0.12 || targetThreat.cutbackZone >= 0.16)) ||
    (actionType === "dribble" && sourceIsWide && sourceDepth >= 66);
  const active =
    finalThirdCue &&
    (
      deliveryCue ||
      sourceIsWide ||
      profile.crossBias >= 0.56 ||
      profile.overlapBias >= 0.58 ||
      (forwardGain >= 6 && targetThreat.behindLine >= 0.2)
    );

  if (!active) {
    return null;
  }

  const deliveryKind =
    principleText.includes("cutback") || targetThreat.cutbackZone >= 0.2 || (sourceIsWide && forwardGain <= 1.5 && targetDepth >= 72)
      ? "cutback"
      : principleText.includes("cross") || principleText.includes("delivery") || sourceIsWide
        ? "cross"
        : "finalPass";

  return {
    actionType,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    sourcePoint: cloneVector(sourcePoint),
    sourceThreat,
    targetThreat,
    sourceDepth,
    targetDepth,
    actionSpace,
    forwardGain,
    actionDistance,
    sideSign,
    sourceIsWide,
    deliveryKind,
  };
}

function getAttackingBoxOccupationChainTarget(teamId, context, slot) {
  const sign = getAttackDirectionSign(teamId);
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const sideSign = context.sideSign || 1;
  const target = context.targetPoint;
  const cutbackBias = context.deliveryKind === "cutback" ? 1 : 0;
  const crossBias = context.deliveryKind === "cross" ? 1 : 0;
  const points = {
    nearPostPin: {
      x: penaltySpot.x + sign * (4.8 + crossBias * 0.5),
      y: clamp(pitch.width / 2 + sideSign * (5.4 + crossBias * 1.2), 8, pitch.width - 8),
    },
    penaltySpotArrive: {
      x: penaltySpot.x - sign * (0.4 + cutbackBias * 1.2),
      y: clamp(pitch.width / 2 - sideSign * 0.5, 10, pitch.width - 10),
    },
    farPostHold: {
      x: penaltySpot.x + sign * (4.1 + crossBias * 0.4),
      y: clamp(pitch.width / 2 - sideSign * (10.4 + crossBias * 1), 7, pitch.width - 7),
    },
    cutbackEdge: {
      x: penaltySpot.x - sign * (7.4 + cutbackBias * 1.7),
      y: clamp(pitch.width / 2 - sideSign * 5.2, 12, pitch.width - 12),
    },
    secondWave: {
      x: penaltySpot.x - sign * 11.2,
      y: clamp(pitch.width / 2 + sideSign * 4.6, 12, pitch.width - 12),
    },
    weakSideWidth: getDepthPoint(teamId, clamp(Math.max(context.targetDepth, 76), 70, 92), {
      y: clamp(pitch.width / 2 - sideSign * 26, 3.8, pitch.width - 3.8),
    }),
    recycleSupport: clampToPitch({
      x: target.x - sign * 11.5,
      y: clamp(lerp(target.y, pitch.width / 2 + sideSign * 8.5, 0.52), 9, pitch.width - 9),
    }, 3),
    restLock: clampToPitch({
      x: target.x - sign * (21 + (context.sourceIsWide ? 2.2 : 0)),
      y: clamp(lerp(target.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    }, 3),
  };

  return clampToPitch(points[slot] ?? points.penaltySpotArrive, 2);
}

function applyAttackingBoxOccupationChainTargets(
  teamId,
  targets,
  ballPoint,
  actionMeta,
  profile,
  protectedIds = new Set()
) {
  const context = getAttackingBoxOccupationChainContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const protectedBoxIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getAttackingBoxOccupationChainTarget(teamId, context, slot);
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, target)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, target);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedBoxIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("nearPostPin", ["striker", "secondStriker", "wideForward"], "Box chain: near-post pin");

  if (context.deliveryKind === "cutback") {
    assign("penaltySpotArrive", ["connector", "striker", "secondStriker"], "Box chain: cutback target");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Box chain: cutback edge");
    assign("farPostHold", ["wideForward", "striker", "secondStriker"], "Box chain: far-post hold", -context.sideSign);
  } else {
    assign("penaltySpotArrive", ["striker", "secondStriker", "connector"], "Box chain: penalty-spot arrival");
    assign("farPostHold", ["wideForward", "striker", "secondStriker"], "Box chain: far-post hold", -context.sideSign);
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Box chain: cutback edge");
  }

  if (context.sourceIsWide || profile.switchBias >= 0.56) {
    assign("weakSideWidth", ["wideForward", "wideBack"], "Box chain: weak-side width", -context.sideSign);
  }

  assign("secondWave", ["connector", "pivot", "wideForward"], "Box chain: second wave");
  assign("recycleSupport", ["wideBack", "connector", "pivot"], "Box chain: recycle support", context.sideSign);
  assign("restLock", ["pivot", "rest", "wideBack"], "Box chain: rest-defence lock");

  if (labels.length) {
    labels.unshift(
      context.deliveryKind === "cutback"
        ? "Prepare cutback occupation"
        : context.deliveryKind === "cross"
          ? "Prepare box occupation"
          : "Prepare final-pass occupation"
    );
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedBoxIds,
  };
}

function getTransitionAttackTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const points = {
    secureOutlet: getDepthPoint(teamId, clamp(ballDepth - 8.5, 20, 72), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 7.5, 0.46), 9, pitch.width - 9),
    }),
    pressureRelease: getDepthPoint(teamId, clamp(ballDepth - 4.8, 18, 78), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 6.5, 0.34), 8, pitch.width - 8),
    }),
    carryLane: getDepthPoint(teamId, clamp(ballDepth + 5.5 + (profile.tempo ?? 0.55) * 4.5, 36, 88), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 13.5, 0.58), 7, pitch.width - 7),
    }),
    counterRunner: getDepthPoint(teamId, clamp(ballDepth + 18 + (profile.frontAhead ?? 12) * 0.18, 52, 95), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 8.5, 0.38), 9, pitch.width - 9),
    }),
    centralPin: getDepthPoint(teamId, clamp(ballDepth + 14 + (profile.directness ?? 0.55) * 6, 54, 96), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 12, pitch.width - 12),
    }),
    weakSideRelease: getDepthPoint(teamId, clamp(ballDepth + 10, 44, 88), {
      y: clamp(pitch.width / 2 - sideSign * 25, 4.5, pitch.width - 4.5),
    }),
    lateTrailer: getDepthPoint(teamId, clamp(ballDepth - 1.8 + (profile.shortSupport ?? 0.55) * 4.5, 32, 82), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.5, 0.5), 10, pitch.width - 10),
    }),
    boxSurge: getDepthPoint(teamId, clamp(78 + (profile.directness ?? 0.55) * 12, 76, 98), {
      y: clamp(pitch.width / 2 + sideSign * 7.5, 11, pitch.width - 11),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (18 + (profile.restBehind ?? 22) * 0.12),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.74), 16, pitch.width - 16),
    }, 3),
  };

  return points[slot] ?? points.secureOutlet;
}

function applyTransitionAttackPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  const secure = getSecurePossessionSnapshotForTeam(teamId, actionMeta);
  if (!secure) {
    return [];
  }

  const owner = getPlayerById(secure.ownerPlayerId);
  const origin = secure.point ?? actionMeta?.beforeSnapshot?.ball?.position ?? ballPoint;
  const movedFromRegain = distance(ballPoint, origin);
  const freshness = clamp(
    1 - movedFromRegain / Math.max((secure.minDistanceToExpire ?? 6) * 1.45, 0.01),
    0,
    1
  );
  if (!owner || freshness <= 0.05) {
    return [];
  }

  const labels = [];
  const sideSign = getWideSideSign(ballPoint) || getWideSideSign(owner) || 1;
  const directStyle = isTransitionAttackStyle(profile.styleKey);
  const pressure = getPlayerPressureLoad(owner, ballPoint);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const ownHalfRegain = ballDepth < 48;
  const middleThirdRegain = ballDepth >= 35 && ballDepth < 68;
  const finalThirdRegain = ballDepth >= 68;
  const counterIntent = clamp(
    (profile.directness ?? 0.52) * 0.34 +
      (profile.progressionUrgency ?? 0.5) * 0.26 +
      (profile.tempo ?? 0.5) * 0.18 +
      (directStyle ? 0.22 : 0) +
      (secure.reason === "interception" ? 0.08 : 0) -
      pressure * 0.12,
    0,
    1.18
  );
  const secureIntent = clamp(
    pressure * 0.42 +
      (profile.shortSupport ?? 0.5) * 0.24 +
      (profile.recycleWindow ?? 0.4) * 0.16 +
      (ownHalfRegain ? 0.12 : 0) -
      (directStyle ? 0.08 : 0),
    0,
    1.08
  );

  const assignTransitionTarget = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(
          teamId,
          roleKeys,
          targets,
          excludedIds,
          preferredSide,
          ballPoint
        )
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, excludedIds, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getTransitionAttackTarget(teamId, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    excludedIds.add(player.id);
    labels.push(label);
    return player;
  };

  assignTransitionTarget("secureOutlet", ["pivot", "connector", "wideBack"], "Transition: secure first pass");

  if (secureIntent >= 0.46 || pressure >= 0.45 || ownHalfRegain) {
    assignTransitionTarget(
      "pressureRelease",
      ["connector", "pivot", "wideBack"],
      "Transition: pressure-release angle"
    );
  }

  if (counterIntent >= 0.42 || pressure <= 0.38 || middleThirdRegain || finalThirdRegain) {
    assignTransitionTarget(
      "counterRunner",
      ["striker", "wideForward", "secondStriker"],
      "Transition: depth runner"
    );

    assignTransitionTarget(
      "centralPin",
      ["striker", "secondStriker", "wideForward"],
      "Transition: pin the last line"
    );

    assignTransitionTarget(
      "weakSideRelease",
      ["wideForward", "wideBack"],
      "Transition: weak-side release",
      -sideSign
    );
  }

  if ((profile.widthDiscipline ?? profile.width ?? 0.58) >= 0.52 || isWideChannel(ballPoint)) {
    assignTransitionTarget(
      "carryLane",
      ["wideBack", "wideForward", "connector"],
      "Transition: carry lane",
      sideSign
    );
  }

  if (finalThirdRegain || (ballDepth >= 58 && pressure <= 0.48)) {
    assignTransitionTarget(
      "boxSurge",
      ["striker", "wideForward", "secondStriker", "connector"],
      "Transition: box surge"
    );
  } else {
    assignTransitionTarget(
      "lateTrailer",
      ["connector", "pivot", "wideForward"],
      "Transition: late trailer"
    );
  }

  assignTransitionTarget("restLock", ["pivot", "rest"], "Transition: rest-defence lock");

  return uniquePrincipleLabels(labels);
}

function applyBetweenLinesPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();

  if (!principleText.includes("between-lines") && !principleText.includes("ficka")) {
    return [];
  }

  const labels = [];
  const sideSign = getWideSideSign(ballPoint) || 1;

  const depthRunner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["striker", "wideForward", "secondStriker"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, depthRunner, getHighValueAttackTarget(teamId, ballPoint, "goldenRun", sideSign))) {
    excludedIds.add(depthRunner.id);
    labels.push("Depth threat beyond pocket");
  }

  const bounceSupport = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "connector"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, bounceSupport, getSupportUnderBallTarget(teamId, ballPoint, sideSign, profile))) {
    excludedIds.add(bounceSupport.id);
    labels.push("Bounce support under pocket");
  }

  const weakSide = getMovableAutopilotPlayerByRolesOnSide(
    teamId,
    ["wideForward", "wideBack"],
    targets,
    excludedIds,
    -sideSign,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, weakSide, getFormationIdentityTarget(teamId, ballPoint, "weakSideWidth", sideSign, profile))) {
    excludedIds.add(weakSide.id);
    labels.push("Weak-side width");
  }

  const restLock = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "rest"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, restLock, getFormationIdentityTarget(teamId, ballPoint, "restLock", sideSign, profile))) {
    excludedIds.add(restLock.id);
    labels.push("Rest-defence lock");
  }

  return labels;
}

function getReceptionSupportTarget(teamId, hubPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(hubPoint, teamId);
  const compactness = profile.supportCompactness ?? 0.58;
  const width = profile.widthDiscipline ?? 0.64;
  const directness = profile.directness ?? 0.52;
  const wideY = pitch.width / 2 + sideSign * lerp(22, 29, width);
  const halfSpaceY = pitch.width / 2 + sideSign * 12.5;
  const insideY = lerp(hubPoint.y, halfSpaceY, isWideChannel(hubPoint) ? 0.72 : 0.38);
  const outsideY = clamp(hubPoint.y + sideSign * lerp(5.5, 8.5, width), 3.5, pitch.width - 3.5);
  const points = {
    under: getDepthPoint(teamId, clamp(depth - lerp(8, 13.5, compactness), 18, 78), {
      y: clamp(lerp(hubPoint.y, pitch.width / 2 + sideSign * 5.5, 0.5), 8, pitch.width - 8),
    }),
    inside: getDepthPoint(teamId, clamp(depth - 1.5 + directness * 2.5, 32, 86), {
      y: clamp(insideY, 8, pitch.width - 8),
    }),
    outside: getDepthPoint(teamId, clamp(depth + lerp(1.5, 6.5, width), 34, 93), {
      y: outsideY,
    }),
    beyond: getDepthPoint(teamId, clamp(depth + lerp(7.5, 15, directness), 48, 97), {
      y: clamp(lerp(hubPoint.y, pitch.width / 2 - sideSign * 5.5, 0.42), 11, pitch.width - 11),
    }),
    weakSide: getDepthPoint(teamId, clamp(depth + 3.5, 36, 88), {
      y: clamp(wideY * -1 + pitch.width, 3.5, pitch.width - 3.5),
    }),
    restLink: clampToPitch({
      x: hubPoint.x - sign * (18 + (profile.restBehind ?? 22) * 0.14),
      y: clamp(lerp(hubPoint.y, pitch.width / 2, 0.72), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.under;
}

function applyReceptionSupportPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  if (actionMeta?.actionType !== "pass") {
    return [];
  }

  const labels = [];
  const localExcluded = new Set(excludedIds);
  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const plannedRunner = getPlayerById(actionMeta?.principleRunnerPlayerId);
  const hubPlayer = receiver ?? plannedRunner ?? null;
  const startPoint = actionMeta?.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position;
  const hubPoint = clampToPitch(ballPoint ?? actionMeta?.target ?? state.ball.target, 2.5);
  const sideSign =
    getWideSideSign(hubPoint) ||
    getWideSideSign(hubPlayer) ||
    getWideSideSign(startPoint) ||
    1;
  const targetDepth = getAttackingDepth(hubPoint, teamId);
  const targetIsWide = isWidePrincipleZone(hubPoint);
  const targetIsCentral = Math.abs(hubPoint.y - pitch.width / 2) <= 15;

  if (hubPlayer) {
    localExcluded.add(hubPlayer.id);
  }

  const underSupport = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "connector", "wideBack"],
    targets,
    localExcluded,
    hubPoint
  );
  if (setAutopilotPrincipleTarget(targets, underSupport, getReceptionSupportTarget(teamId, hubPoint, "under", sideSign, profile))) {
    localExcluded.add(underSupport.id);
    excludedIds.add(underSupport.id);
    labels.push("Reception triangle");
  }

  const insideSupport = getMovableAutopilotPlayerByRolesOnSide(
    teamId,
    ["connector", "pivot", "wideForward"],
    targets,
    localExcluded,
    targetIsWide ? sideSign : 0,
    hubPoint
  );
  if (setAutopilotPrincipleTarget(targets, insideSupport, getReceptionSupportTarget(teamId, hubPoint, "inside", sideSign, profile))) {
    localExcluded.add(insideSupport.id);
    excludedIds.add(insideSupport.id);
    labels.push("Inside support angle");
  }

  if (targetIsWide && (profile.overlapBias >= 0.52 || profile.widthDiscipline >= 0.62)) {
    const outsideSupport = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["wideBack", "wideForward"],
      targets,
      localExcluded,
      sideSign,
      hubPoint
    );
    if (setAutopilotPrincipleTarget(targets, outsideSupport, getReceptionSupportTarget(teamId, hubPoint, "outside", sideSign, profile))) {
      localExcluded.add(outsideSupport.id);
      excludedIds.add(outsideSupport.id);
      labels.push("Outside option");
    }
  }

  if (targetDepth >= 38 && (targetIsCentral || profile.directness >= 0.56 || plannedRunner)) {
    const depthOption = getMovableAutopilotPlayerByRoles(
      teamId,
      ["striker", "wideForward", "secondStriker"],
      targets,
      localExcluded,
      hubPoint
    );
    if (setAutopilotPrincipleTarget(targets, depthOption, getReceptionSupportTarget(teamId, hubPoint, "beyond", sideSign, profile))) {
      localExcluded.add(depthOption.id);
      excludedIds.add(depthOption.id);
      labels.push("Next depth option");
    }
  }

  if (!targetIsWide && profile.switchBias >= 0.56) {
    const weakSide = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["wideForward", "wideBack"],
      targets,
      localExcluded,
      -sideSign,
      hubPoint
    );
    if (setAutopilotPrincipleTarget(targets, weakSide, getReceptionSupportTarget(teamId, hubPoint, "weakSide", sideSign, profile))) {
      localExcluded.add(weakSide.id);
      excludedIds.add(weakSide.id);
      labels.push("Weak-side release");
    }
  }

  const restLink = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "rest"],
    targets,
    localExcluded,
    hubPoint
  );
  if (setAutopilotPrincipleTarget(targets, restLink, getReceptionSupportTarget(teamId, hubPoint, "restLink", sideSign, profile))) {
    excludedIds.add(restLink.id);
  }

  return labels;
}

function getOpenGrassCarrySupportTarget(teamId, startPoint, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const halfY = pitch.width / 2 + sideSign * 12.5;
  const farHalfY = pitch.width / 2 - sideSign * 12.5;
  const wideY = clamp(pitch.width / 2 + sideSign * clamp((profile.width ?? 58) * 0.48, 24, 31), 3.4, pitch.width - 3.4);
  const farWideY = clamp(pitch.width / 2 - sideSign * clamp((profile.width ?? 58) * 0.48, 24, 31), 3.4, pitch.width - 3.4);
  const carryDistance = distance(startPoint, ballPoint);
  const points = {
    stretchAhead: getDepthPoint(teamId, clamp(targetDepth + 8 + profile.directness * 6, Math.max(48, targetDepth + 4), 97), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 5.5, 0.45), 9, pitch.width - 9),
    }),
    insideLane: getDepthPoint(teamId, clamp(targetDepth + 1.5 + profile.shortSupport * 5, Math.max(38, startDepth + 5), 86), {
      y: clamp(lerp(ballPoint.y, halfY, 0.58), 8, pitch.width - 8),
    }),
    outsideLane: getDepthPoint(teamId, clamp(targetDepth + 1 + profile.widthDiscipline * 4, Math.max(36, startDepth + 3), 92), {
      y: clamp(lerp(ballPoint.y, wideY, 0.74), 3.4, pitch.width - 3.4),
    }),
    trailingSupport: getDepthPoint(teamId, clamp(targetDepth - 10 - profile.supportCompactness * 6, 20, 76), {
      y: clamp(lerp(startPoint.y, pitch.width / 2 + sideSign * 5.5, 0.48), 10, pitch.width - 10),
    }),
    farRelease: getDepthPoint(teamId, clamp(targetDepth + 4 + profile.switchBias * 8, 38, 90), {
      y: farWideY,
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(72 + profile.shortSupport * 6 + Math.min(carryDistance, 18) * 0.08, 70, 83), {
      y: clamp(pitch.width / 2 - sideSign * 6.2, 14, pitch.width - 14),
    }),
    boxArrive: getDepthPoint(teamId, clamp(86 + profile.directness * 7, 82, 98), {
      y: clamp(pitch.width / 2 + sideSign * 6.8, 12, pitch.width - 12),
    }),
    farPost: getDepthPoint(teamId, clamp(87, 84, 97), {
      y: clamp(pitch.width / 2 - sideSign * 11.5, 11, pitch.width - 11),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.insideLane;
}

function applyOpenGrassCarrySupportTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  if (actionMeta?.actionType !== "dribble" || !ballPoint) {
    return [];
  }

  const startPoint = actionMeta?.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position;
  const carryDistance = distance(startPoint, ballPoint);
  const forwardGain = (ballPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const actionSpace = getActionSpaceValue(startPoint, ballPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isOpenGrassCarry =
    principleText.includes("open-grass") ||
    (
      carryDistance >= 9 &&
      forwardGain >= 5 &&
      actionSpace.openTarget >= 0.5 &&
      actionSpace.targetPressure <= 0.66
    );

  if (!isOpenGrassCarry) {
    return [];
  }

  const labels = [];
  const localExcluded = new Set(excludedIds);
  const sideSign = getWideSideSign(ballPoint) || getWideSideSign(startPoint) || 1;
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const targetIsWide = isWidePrincipleZone(ballPoint);
  const finalThirdCarry = targetDepth >= 64 || targetThreat.box >= 0.18 || targetThreat.behindLine >= 0.3;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, localExcluded, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, localExcluded, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getOpenGrassCarrySupportTarget(teamId, startPoint, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    localExcluded.add(player.id);
    excludedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("stretchAhead", ["striker", "wideForward", "secondStriker"], "Carry support: stretch last line");
  assign("insideLane", ["connector", "wideForward", "secondStriker"], "Carry support: inside lane", targetIsWide ? sideSign : 0);

  if (targetIsWide || profile.overlapBias >= 0.56 || profile.widthDiscipline >= 0.66) {
    assign("outsideLane", ["wideBack", "wideForward"], "Carry support: outside option", sideSign);
  }

  assign("trailingSupport", ["pivot", "connector", "wideBack"], "Carry support: trailing option");

  if (finalThirdCarry) {
    assign("boxArrive", ["striker", "wideForward", "secondStriker"], "Carry support: box arrival");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Carry support: cutback edge");
    assign("farPost", ["wideForward", "striker", "secondStriker"], "Carry support: far-post threat", -sideSign);
  } else if (profile.switchBias >= 0.56 || actionSpace.targetPressure >= 0.46) {
    assign("farRelease", ["wideForward", "wideBack"], "Carry support: far release", -sideSign);
  }

  assign("restLock", ["pivot", "rest"], "Carry support: rest-defence lock");

  return uniquePrincipleLabels(labels);
}

function getBallNearSupportTriangleTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const compactness = profile.supportCompactness ?? 0.56;
  const width = profile.width ?? 58;
  const directness = profile.directness ?? 0.52;
  const halfSpaceY = pitch.width / 2 + sideSign * 12.5;
  const oppositeHalfSpaceY = pitch.width / 2 - sideSign * 10;
  const wideY = clamp(pitch.width / 2 + sideSign * clamp(width * 0.48, 23, 31), 3.5, pitch.width - 3.5);
  const weakWideY = clamp(pitch.width / 2 - sideSign * clamp(width * 0.46, 22, 30), 3.5, pitch.width - 3.5);
  const underDrop = lerp(9.5, 15.5, compactness);
  const points = {
    underSupport: getDepthPoint(teamId, clamp(depth - underDrop, 17, 78), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 5.5, 0.54), 8, pitch.width - 8),
    }),
    insideAngle: getDepthPoint(teamId, clamp(depth + lerp(-1.5, 3, directness), 28, 86), {
      y: clamp(lerp(ballPoint.y, halfSpaceY, isWidePrincipleZone(ballPoint) ? 0.72 : 0.42), 8, pitch.width - 8),
    }),
    beyondOption: getDepthPoint(teamId, clamp(depth + lerp(8, 16, directness), 42, 96), {
      y: clamp(lerp(ballPoint.y, oppositeHalfSpaceY, 0.42), 10, pitch.width - 10),
    }),
    outsideWidth: getDepthPoint(teamId, clamp(depth + lerp(1.5, 6.5, profile.widthDiscipline ?? 0.62), 32, 92), {
      y: wideY,
    }),
    weakSideRelease: getDepthPoint(teamId, clamp(depth + lerp(3, 9, profile.switchBias ?? 0.5), 34, 92), {
      y: weakWideY,
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (18 + (profile.restBehind ?? 22) * 0.16),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.74), 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.underSupport;
}

function applyBallNearSupportTriangleTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return [];
  }

  const labels = [];
  const localExcluded = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const sideSign = getWideSideSign(ballPoint) || 1;
  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 13);
  const gameSpace = getAttackingGameSpaceProfile(ballPoint, teamId);
  const threat = getPitchThreatProfile(ballPoint, teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const isWide = isWidePrincipleZone(ballPoint);
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, localExcluded, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, localExcluded, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getBallNearSupportTriangleTarget(teamId, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    localExcluded.add(player.id);
    labels.push(label);
    return player;
  };

  assign("underSupport", ["pivot", "connector", "wideBack", "rest"], "Ball-near support triangle");
  assign("insideAngle", ["connector", "pivot", "wideForward", "secondStriker"], "Inside support angle", isWide ? sideSign : 0);

  if (depth <= 86 && (gameSpace.key !== "outlet" || pressure <= 0.68 || profile.directness >= 0.5)) {
    assign("beyondOption", ["striker", "wideForward", "secondStriker"], "Depth option beyond");
  }

  if (isWide || profile.widthDiscipline >= 0.62 || profile.overlapBias >= 0.54) {
    assign("outsideWidth", ["wideBack", "wideForward"], "Outside width", sideSign);
  }

  if (!isWide && (profile.switchBias >= 0.56 || threat.centralPocket >= 0.28 || pressure >= 0.5)) {
    assign("weakSideRelease", ["wideForward", "wideBack"], "Weak-side release", -sideSign);
  }

  if (depth >= 38 || pressure >= 0.5) {
    assign("restLock", ["pivot", "rest", "wideBack"], "Rest-defence lock");
  }

  return uniquePrincipleLabels(labels);
}

function getTargetLocalSuperiorityProfile(teamId, targets, point, excludedIds = new Set(), radius = 15) {
  if (!teamId || !point) {
    return {
      supportCount: 0,
      opponentCount: 0,
      closeOpponents: 0,
      underSupport: false,
      lateralSupport: false,
      forwardSupport: false,
      geometryScore: 0,
      sectorVariety: 0,
    };
  }

  const attackSign = getAttackDirectionSign(teamId);
  const sectors = new Set();
  let supportCount = 0;
  let opponentCount = 0;
  let closeOpponents = 0;
  let underSupport = false;
  let lateralSupport = false;
  let forwardSupport = false;

  state.players.forEach((player) => {
    if (isGoalkeeper(player)) {
      return;
    }

    if (player.team === teamId) {
      if (excludedIds.has(player.id)) {
        return;
      }

      const target = targets.get(player.id) ?? player.position;
      const gap = distance(target, point);
      if (gap > radius) {
        return;
      }

      supportCount += 1;
      const forwardOffset = (target.x - point.x) * attackSign;
      const lateralOffset = target.y - point.y;

      if (forwardOffset <= -2.2 && Math.abs(lateralOffset) <= 18) {
        underSupport = true;
        sectors.add("under");
      }

      if (forwardOffset >= 3.2 && Math.abs(lateralOffset) <= 18) {
        forwardSupport = true;
        sectors.add("ahead");
      }

      if (Math.abs(lateralOffset) >= 6.5) {
        lateralSupport = true;
        sectors.add(lateralOffset > 0 ? "outsidePlus" : "outsideMinus");
      }

      if (Math.abs(forwardOffset) <= 5.5 && Math.abs(lateralOffset) <= 9) {
        sectors.add("bounce");
      }
      return;
    }

    const opponentGap = distance(player.position, point);
    if (opponentGap <= radius) {
      opponentCount += 1;
    }

    if (opponentGap <= 5.5) {
      closeOpponents += 1;
    }
  });

  const sectorVariety = sectors.size;
  const geometryScore = clamp(
    (underSupport ? 0.3 : 0) +
      (lateralSupport ? 0.22 : 0) +
      (forwardSupport ? 0.18 : 0) +
      clamp(supportCount / 3, 0, 1) * 0.18 +
      clamp(sectorVariety / 4, 0, 1) * 0.16 -
      clamp(closeOpponents / 3, 0, 1) * 0.16,
    0,
    1
  );

  return {
    supportCount,
    opponentCount,
    closeOpponents,
    underSupport,
    lateralSupport,
    forwardSupport,
    geometryScore,
    sectorVariety,
  };
}

function getLocalSuperioritySupportTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const width = profile.width ?? 58;
  const outsideY = clamp(pitch.width / 2 + sideSign * clamp(width * 0.47, 23, 31), 3.5, pitch.width - 3.5);
  const insideY = clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 8.5, 0.56), 7.5, pitch.width - 7.5);
  const weakSideY = clamp(pitch.width / 2 - sideSign * clamp(width * 0.45, 22, 30), 3.8, pitch.width - 3.8);
  const points = {
    underSupport: getDepthPoint(teamId, clamp(depth - 10.5 - (profile.supportCompactness ?? 0.55) * 4.5, 17, 76), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.8, 0.46), 9, pitch.width - 9),
    }),
    insideSupport: getDepthPoint(teamId, clamp(depth + 1 + (profile.shortSupport ?? 0.55) * 3.5, 30, 84), {
      y: insideY,
    }),
    outsideSupport: getDepthPoint(teamId, clamp(depth + 2 + (profile.widthDiscipline ?? 0.62) * 4.5, 32, 92), {
      y: outsideY,
    }),
    forwardSupport: getDepthPoint(teamId, clamp(depth + 7 + (profile.directness ?? 0.52) * 5, 42, 96), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.36), 10, pitch.width - 10),
    }),
    weakSideRelease: getDepthPoint(teamId, clamp(depth + 3 + (profile.switchBias ?? 0.5) * 7, 34, 91), {
      y: weakSideY,
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.16),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 13, pitch.width - 13),
    }, 3),
  };

  return points[slot] ?? points.underSupport;
}

function applyLocalSuperioritySupportTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const protectedSupportIds = new Set();
  const sideSign = getWideSideSign(ballPoint) || 1;
  const passDistance = actionMeta?.beforeSnapshot?.ball?.position
    ? distance(actionMeta.beforeSnapshot.ball.position, ballPoint)
    : distance(state.ball.startPosition ?? state.ball.position, ballPoint);
  const radius = passDistance >= 26 ? 17 : 14.5;
  const targetThreat = getPitchThreatProfile(ballPoint, teamId);
  const local = getTargetLocalSuperiorityProfile(teamId, targets, ballPoint, assignedIds, radius);
  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 11.5);
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const needsRepair =
    local.geometryScore < 0.62 ||
    local.supportCount <= 1 ||
    pressure >= 0.48 ||
    (local.opponentCount > local.supportCount && targetDepth >= 34);

  if (!needsRepair) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getLocalSuperioritySupportTarget(teamId, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    assignedIds.add(player.id);
    protectedSupportIds.add(player.id);
    labels.push(label);
    return player;
  };

  if (!local.underSupport || pressure >= 0.5) {
    assign("underSupport", ["pivot", "connector", "wideBack", "rest"], "Local superiority: under support");
  }

  const refreshedAfterUnder = getTargetLocalSuperiorityProfile(teamId, targets, ballPoint, assignedIds, radius);
  if (!refreshedAfterUnder.lateralSupport || isWidePrincipleZone(ballPoint)) {
    assign(
      isWidePrincipleZone(ballPoint) ? "outsideSupport" : "insideSupport",
      isWidePrincipleZone(ballPoint) ? ["wideBack", "wideForward"] : ["connector", "wideForward", "pivot"],
      isWidePrincipleZone(ballPoint) ? "Local superiority: outside option" : "Local superiority: lateral angle",
      isWidePrincipleZone(ballPoint) ? sideSign : 0
    );
  }

  const refreshedAfterLateral = getTargetLocalSuperiorityProfile(teamId, targets, ballPoint, assignedIds, radius);
  if (
    !refreshedAfterLateral.forwardSupport &&
    targetDepth >= 36 &&
    (
      targetThreat.betweenLines >= 0.24 ||
      targetThreat.halfSpace >= 0.28 ||
      profile.directness >= 0.55 ||
      local.opponentCount <= local.supportCount + 1
    )
  ) {
    assign("forwardSupport", ["striker", "wideForward", "secondStriker", "connector"], "Local superiority: forward option");
  }

  if (
    (profile.switchBias ?? 0.5) >= 0.56 &&
    (pressure >= 0.48 || local.opponentCount >= local.supportCount + 1 || targetThreat.centralPocket >= 0.26)
  ) {
    assign("weakSideRelease", ["wideForward", "wideBack"], "Local superiority: weak-side release", -sideSign);
  }

  if (targetDepth >= 42 || pressure >= 0.52) {
    assign("restLock", ["pivot", "rest", "wideBack"], "Local superiority: rest lock");
  }

  if (labels.length) {
    labels.unshift("Local superiority support");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedSupportIds,
  };
}

function getOffensivePassingGeometryContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "recovery"].includes(actionType)) {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = clampToPitch(ballPoint, 2.5);
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  if (targetDepth < 24 && actionType !== "recovery") {
    return null;
  }

  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const targetThreat = getPitchThreatProfile(targetPoint, teamId);
  const gameSpace = getAttackingGameSpaceProfile(targetPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const pressure = getOpponentPressureAtPoint(teamId, targetPoint, 12);
  const isWide = isWidePrincipleZone(targetPoint);
  const isFinalThird =
    targetDepth >= 66 ||
    targetThreat.box >= 0.16 ||
    targetThreat.cutbackZone >= 0.22 ||
    targetThreat.assistZone >= 0.32;
  const needsGeometry =
    pressure >= 0.28 ||
    targetDepth >= 34 ||
    gameSpace.key === "space1" ||
    gameSpace.key === "space2" ||
    actionSpace.lineBreakCount >= 1 ||
    actionType === "recovery";

  if (!needsGeometry) {
    return null;
  }

  return {
    actionSpace,
    actionType,
    gameSpace,
    isFinalThird,
    isWide,
    pressure,
    sideSign,
    startPoint: cloneVector(startPoint),
    targetDepth,
    targetPoint,
    targetThreat,
  };
}

function getOffensivePassingGeometryTarget(teamId, context, slot, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const depth = context.targetDepth;
  const width = clamp(profile.width ?? 58, 44, 68);
  const pressure = context.pressure;
  const underDrop = lerp(7.2, 14.2, clamp(pressure, 0, 1));
  const strongHalfY = clamp(pitch.width / 2 + sideSign * 12.2, 8, pitch.width - 8);
  const weakHalfY = clamp(pitch.width / 2 - sideSign * 11.2, 8, pitch.width - 8);
  const strongWideY = clamp(pitch.width / 2 + sideSign * width * 0.49, 3.5, pitch.width - 3.5);
  const weakWideY = clamp(pitch.width / 2 - sideSign * width * 0.48, 3.5, pitch.width - 3.5);
  const points = {
    underAngle: getDepthPoint(teamId, clamp(depth - underDrop - (profile.shortSupport ?? 0.55) * 2.5, 16, 76), {
      y: clamp(lerp(ball.y, pitch.width / 2 - sideSign * 4.2, 0.58), 8, pitch.width - 8),
    }),
    insideAngle: getDepthPoint(teamId, clamp(depth + lerp(-2.2, 3.6, profile.tempo ?? 0.5), 28, 84), {
      y: clamp(lerp(ball.y, strongHalfY, context.isWide ? 0.72 : 0.48), 8, pitch.width - 8),
    }),
    outsideExit: getDepthPoint(teamId, clamp(depth + lerp(0.5, 5.8, profile.widthDiscipline ?? 0.62), 30, 90), {
      y: strongWideY,
    }),
    thirdManAngle: getDepthPoint(teamId, clamp(depth + 5.8 + (profile.lineBreakBias ?? 0.5) * 5.4, 40, 92), {
      y: clamp(lerp(ball.y, context.isWide ? weakHalfY : strongHalfY, 0.54), 8, pitch.width - 8),
    }),
    weakSideRelease: getDepthPoint(teamId, clamp(depth + 4.5 + (profile.switchBias ?? 0.5) * 6.5, 36, 92), {
      y: weakWideY,
    }),
    restBalance: clampToPitch({
      x: ball.x - sign * (20 + (profile.restBehind ?? 22) * 0.16),
      y: clamp(lerp(ball.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    }, 3),
  };

  return points[slot] ?? points.underAngle;
}

function applyOffensivePassingGeometryTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getOffensivePassingGeometryContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const protectedGeometryIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getOffensivePassingGeometryTarget(teamId, context, slot, profile);
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, target)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, target);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedGeometryIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("underAngle", ["pivot", "connector", "wideBack", "rest"], "Passing geometry: under angle");
  assign("insideAngle", ["connector", "pivot", "wideForward", "secondStriker"], "Passing geometry: inside angle", context.isWide ? context.sideSign : 0);

  if (context.isWide || profile.widthDiscipline >= 0.62 || profile.overlapBias >= 0.54) {
    assign("outsideExit", ["wideBack", "wideForward"], "Passing geometry: outside exit", context.sideSign);
  }

  if (!context.isFinalThird || context.gameSpace.key === "space2" || context.pressure >= 0.42) {
    assign("thirdManAngle", ["connector", "wideForward", "secondStriker", "pivot"], "Passing geometry: third-man angle", context.isWide ? -context.sideSign : context.sideSign);
  }

  if (profile.switchBias >= 0.5 || context.pressure >= 0.46 || context.targetThreat.centralPocket >= 0.24) {
    assign("weakSideRelease", ["wideForward", "wideBack"], "Passing geometry: weak-side release", -context.sideSign);
  }

  if (context.targetDepth >= 38 || context.pressure >= 0.44) {
    assign("restBalance", ["pivot", "rest", "wideBack"], "Passing geometry: rest balance");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedGeometryIds,
  };
}

function getLooseBallRecoverySupportTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const width = profile.widthDiscipline ?? 0.62;
  const directness = profile.directness ?? 0.52;
  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 11);
  const halfSpaceY = pitch.width / 2 + sideSign * 11.5;
  const oppositeHalfSpaceY = pitch.width / 2 - sideSign * 10.5;
  const wideY = clamp(pitch.width / 2 + sideSign * lerp(22, 30, width), 4.5, pitch.width - 4.5);
  const points = {
    secureUnder: getDepthPoint(teamId, clamp(depth - lerp(7.5, 13, pressure), 16, 76), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4, 0.54), 8, pitch.width - 8),
    }),
    insideBounce: getDepthPoint(teamId, clamp(depth + lerp(-1.5, 3.5, directness), 28, 84), {
      y: clamp(lerp(ballPoint.y, halfSpaceY, isWidePrincipleZone(ballPoint) ? 0.62 : 0.42), 8, pitch.width - 8),
    }),
    forwardOutlet: getDepthPoint(teamId, clamp(depth + lerp(8, 18, directness), 42, 94), {
      y: clamp(lerp(ballPoint.y, oppositeHalfSpaceY, 0.32), 9, pitch.width - 9),
    }),
    widthRelease: getDepthPoint(teamId, clamp(depth + lerp(1, 7, width), 32, 90), {
      y: wideY,
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * lerp(17, 25, profile.restDefence ?? 0.62),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.secureUnder;
}

function applyLooseBallRecoverySupportTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const isRecoveryAction =
    actionMeta?.actionType === "recovery" ||
    actionMeta?.profileKey === "loose-ball-recovery" ||
    state.ball.actionType === "recovery" ||
    state.ball.profileKey === "loose-ball-recovery";

  if (!isRecoveryAction || !ballPoint || profile?.phaseKey === "setPiece") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const protectedRecoveryIds = new Set();
  const sideSign = getWideSideSign(ballPoint) || 1;
  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 11);
  const threat = getPitchThreatProfile(ballPoint, teamId);
  const directTransition = isTransitionAttackStyle(profile.styleKey) || profile.directness >= 0.62;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, ballPoint);
    const target = getLooseBallRecoverySupportTarget(teamId, ballPoint, slot, sideSign, profile);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedRecoveryIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("secureUnder", ["pivot", "connector", "wideBack", "rest"], "Recovery: secure first pass");
  assign("insideBounce", ["connector", "pivot", "wideForward", "secondStriker"], "Recovery: inside bounce angle");

  if (directTransition || pressure <= 0.5 || threat.depth >= 48) {
    assign("forwardOutlet", ["striker", "wideForward", "secondStriker"], "Recovery: forward outlet");
  }

  if (isWidePrincipleZone(ballPoint) || profile.widthDiscipline >= 0.6 || pressure >= 0.48) {
    assign("widthRelease", ["wideBack", "wideForward"], "Recovery: width release", sideSign);
  }

  assign("restLock", ["pivot", "rest", "wideBack"], "Recovery: rest-defence lock");

  if (labels.length) {
    labels.unshift("Loose-ball recovery support");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedRecoveryIds,
  };
}

function getPostRecoveryAttackSupportContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile?.phaseKey === "setPiece") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const steps = state.sequence?.steps ?? [];
  let recoveryIndex = -1;
  for (let index = steps.length - 1; index >= 0; index -= 1) {
    const step = steps[index];
    const possessionTeamId = getRecordedStepPossessionTeamId(step);
    const isRecovery =
      step?.actionType === "recovery" ||
      step?.profileKey === "loose-ball-recovery" ||
      `${step?.profileLabel ?? ""}`.toLowerCase().includes("loose ball");

    if (isRecovery && possessionTeamId === teamId) {
      recoveryIndex = index;
      break;
    }

    if (possessionTeamId && possessionTeamId !== teamId) {
      break;
    }
  }

  if (recoveryIndex < 0) {
    return null;
  }

  const actionsAfterRecovery = steps.slice(recoveryIndex + 1);
  if (actionsAfterRecovery.length > 4) {
    return null;
  }

  if (actionsAfterRecovery.some((step) => getRecordedStepPossessionTeamId(step) !== teamId)) {
    return null;
  }

  const elapsed = actionsAfterRecovery.reduce(
    (total, step) => total + getRecordedStepDuration(step),
    0
  );
  if (elapsed > 10.5) {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta?.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const recoveryStep = steps[recoveryIndex];
  const recoveryPoint =
    recoveryStep?.target ??
    recoveryStep?.afterSnapshot?.ball?.position ??
    startPoint;
  const originDepth = getAttackingDepth(recoveryPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  const depthGainSinceRecovery = startDepth - originDepth;
  const actionForwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const actionDistance = distance(startPoint, targetPoint);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const currentCarrier = getPlayerById(
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
    actionMeta?.carrierPlayerId ??
    state.ball.initiatorPlayerId ??
    state.ball.ownerPlayerId
  );
  const pressure = currentCarrier?.team === teamId
    ? getPlayerPressureLoad(currentCarrier, startPoint)
    : getOpponentPressureAtPoint(teamId, startPoint, 9.5);
  const localSupport = getTeamSupportCountAroundPoint(
    teamId,
    startPoint,
    new Set([currentCarrier?.id, actionMeta?.receiverPlayerId].filter(Boolean)),
    13
  );
  const forwardProbe = clampToPitch({
    x: startPoint.x + getAttackDirectionSign(teamId) * 20,
    y: lerp(startPoint.y, pitch.width / 2, 0.24),
  }, 2.5);
  const forwardOpenSpace = currentCarrier?.team === teamId
    ? getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(currentCarrier, forwardProbe))
    : actionSpace.openTarget;
  const patterns = actionsAfterRecovery
    .map((step) => getRecordedStepPattern(step, teamId))
    .filter(Boolean);
  const sidewaysOrBackCount = patterns.filter((pattern) => pattern.forwardGain <= 2.5).length;
  const lineBreakCount = patterns.filter((pattern) => pattern.family === "line-break" || pattern.forwardGain >= 9).length;
  const lanes = patterns.map((pattern) => pattern.laneKey).filter(Boolean);
  const laneVariety = new Set(lanes).size;
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const directStyle = isTransitionAttackStyle(profile.styleKey);
  const transitionCue =
    actionForwardGain >= 5.5 &&
    (
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.4 ||
      targetThreat.behindLine >= 0.2 ||
      targetThreat.centralPocket >= 0.24 ||
      forwardOpenSpace >= 0.58
    );
  const secureCue =
    pressure >= 0.5 ||
    localSupport <= 1 ||
    (
      actionType === "pass" &&
      actionDistance <= 22 &&
      actionForwardGain >= -8 &&
      actionSpace.targetPressure <= 0.72
    );
  const staleCue =
    actionsAfterRecovery.length >= 2 &&
    depthGainSinceRecovery < 8 &&
    sidewaysOrBackCount >= 1 &&
    lineBreakCount === 0 &&
    laneVariety <= 2;
  const finalThirdCue =
    targetDepth >= 66 ||
    targetThreat.box >= 0.16 ||
    targetThreat.cutbackZone >= 0.22 ||
    targetThreat.assistZone >= 0.32;
  const counterWindow = clamp(
    (directStyle ? 0.34 : 0) +
      (profile.directness ?? 0.5) * 0.26 +
      (profile.progressionUrgency ?? 0.5) * 0.16 +
      forwardOpenSpace * 0.24 +
      (transitionCue ? 0.22 : 0) -
      Math.max(0, actionsAfterRecovery.length - 2) * 0.08,
    0,
    1.15
  );
  const secureNeed = clamp(
    pressure * 0.34 +
      (localSupport <= 1 ? 0.2 : 0) +
      (secureCue ? 0.16 : 0) +
      (profile.shortSupport ?? 0.5) * 0.08,
    0,
    1.1
  );
  const mode =
    counterWindow >= Math.max(0.58, secureNeed + 0.12)
      ? "counter"
      : secureNeed >= 0.58
        ? "secure"
        : "establish";

  return {
    active: true,
    teamId,
    actionType,
    actionMeta,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    recoveryPoint: cloneVector(recoveryPoint),
    actionsAfterRecovery: actionsAfterRecovery.length,
    elapsed,
    originDepth,
    startDepth,
    targetDepth,
    depthGainSinceRecovery,
    actionForwardGain,
    actionDistance,
    actionSpace,
    targetThreat,
    pressure,
    localSupport,
    forwardOpenSpace,
    sidewaysOrBackCount,
    lineBreakCount,
    laneVariety,
    sideSign,
    directStyle,
    transitionCue,
    secureCue,
    staleCue,
    finalThirdCue,
    counterWindow,
    secureNeed,
    mode,
  };
}

function getPostRecoveryAttackSupportTarget(teamId, context, slot, sideSign = context.sideSign, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(context.targetPoint, teamId);
  const startDepth = getAttackingDepth(context.startPoint, teamId);
  const wideY = clamp(pitch.width / 2 + sideSign * lerp(23, 31, profile.widthDiscipline ?? 0.62), 4, pitch.width - 4);
  const farWideY = clamp(pitch.width / 2 - sideSign * lerp(23, 31, profile.widthDiscipline ?? 0.62), 4, pitch.width - 4);
  const halfY = clamp(pitch.width / 2 + sideSign * 12.5, 8, pitch.width - 8);
  const farHalfY = clamp(pitch.width / 2 - sideSign * 12.5, 8, pitch.width - 8);
  const points = {
    counterRunner: getDepthPoint(teamId, clamp(depth + 13 + (profile.directness ?? 0.5) * 8, Math.max(50, startDepth + 10), 98), {
      y: clamp(lerp(context.targetPoint.y, farHalfY, 0.5), 9, pitch.width - 9),
    }),
    pinLastLine: getDepthPoint(teamId, clamp(depth + 10 + (profile.runnerBoost ?? 7) * 0.34, 48, 98), {
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2, 0.56), 11, pitch.width - 11),
    }),
    wideRelease: getDepthPoint(teamId, clamp(depth + 2 + (profile.widthDiscipline ?? 0.6) * 7, 34, 92), {
      y: wideY,
    }),
    weakSideRelease: getDepthPoint(teamId, clamp(depth + 4 + (profile.switchBias ?? 0.5) * 8, 36, 92), {
      y: farWideY,
    }),
    insideLink: getDepthPoint(teamId, clamp(depth + 1 + (profile.shortSupport ?? 0.55) * 5, 30, 86), {
      y: clamp(lerp(context.targetPoint.y, halfY, context.finalThirdCue ? 0.42 : 0.58), 9, pitch.width - 9),
    }),
    underSupport: getDepthPoint(teamId, clamp(depth - 9 - (profile.supportCompactness ?? 0.55) * 5, 17, 78), {
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2 - sideSign * 4.5, 0.54), 9, pitch.width - 9),
    }),
    trailer: getDepthPoint(teamId, clamp(depth - 4 + (profile.shortSupport ?? 0.55) * 4, 28, 82), {
      y: clamp(lerp(context.targetPoint.y, farHalfY, 0.34), 10, pitch.width - 10),
    }),
    boxArrive: getDepthPoint(teamId, clamp(84 + (profile.directness ?? 0.5) * 8, 80, 98), {
      y: clamp(pitch.width / 2 + sideSign * 6.2, 12, pitch.width - 12),
    }),
    farPostArrive: getDepthPoint(teamId, clamp(86, 82, 98), {
      y: clamp(pitch.width / 2 - sideSign * 10.8, 10, pitch.width - 10),
    }),
    restLock: clampToPitch({
      x: context.targetPoint.x - sign * (18 + (profile.restBehind ?? 22) * 0.22),
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    }, 3),
    farRestCover: clampToPitch({
      x: context.targetPoint.x - sign * (22 + (profile.restBehind ?? 22) * 0.2),
      y: clamp(pitch.width / 2 - sideSign * 10.4, 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.underSupport;
}

function applyPostRecoveryAttackSupportTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getPostRecoveryAttackSupportContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
  ].filter(Boolean));
  const protectedPostRecoveryIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, ballPoint);
    const target = getPostRecoveryAttackSupportTarget(teamId, context, slot, context.sideSign, profile);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedPostRecoveryIds.add(player.id);
    labels.push(label);
    return player;
  };

  if (context.mode === "counter") {
    assign("counterRunner", ["striker", "wideForward", "secondStriker"], "Post-recovery attack: depth runner");
    assign("wideRelease", ["wideForward", "wideBack"], "Post-recovery attack: width release", context.sideSign);
    assign("insideLink", ["connector", "wideForward", "secondStriker"], "Post-recovery attack: inside link", context.sideSign);
    assign("trailer", ["connector", "pivot", "wideForward"], "Post-recovery attack: trailer support");

    if (context.finalThirdCue || context.targetDepth >= 62) {
      assign("boxArrive", ["striker", "secondStriker", "wideForward"], "Post-recovery attack: box arrival");
    }
  } else if (context.mode === "secure") {
    assign("underSupport", ["pivot", "connector", "wideBack", "rest"], "Post-recovery attack: secure under-support");
    assign("insideLink", ["connector", "pivot", "wideForward"], "Post-recovery attack: inside angle");

    if (context.pressure >= 0.48 || context.staleCue || profile.switchBias >= 0.54) {
      assign("weakSideRelease", ["wideForward", "wideBack"], "Post-recovery attack: weak-side release", -context.sideSign);
    }

    assign("trailer", ["connector", "pivot"], "Post-recovery attack: reset trailer");
  } else {
    assign("underSupport", ["pivot", "connector", "wideBack"], "Post-recovery attack: connect under");
    assign("insideLink", ["connector", "wideForward", "secondStriker"], "Post-recovery attack: half-space link", context.sideSign);
    assign("pinLastLine", ["striker", "wideForward", "secondStriker"], "Post-recovery attack: pin last line");

    if (context.staleCue || profile.switchBias >= 0.56) {
      assign("weakSideRelease", ["wideForward", "wideBack"], "Post-recovery attack: change-side outlet", -context.sideSign);
    } else {
      assign("wideRelease", ["wideBack", "wideForward"], "Post-recovery attack: hold width", context.sideSign);
    }
  }

  assign("restLock", ["pivot", "rest", "wideBack"], "Post-recovery attack: rest-defence lock");

  if (context.targetDepth >= 48 || context.mode === "counter") {
    assign("farRestCover", ["rest", "pivot", "wideBack"], "Post-recovery attack: far rest cover", -context.sideSign);
  }

  if (context.finalThirdCue && context.mode !== "secure") {
    assign("farPostArrive", ["wideForward", "striker", "secondStriker"], "Post-recovery attack: far-post threat", -context.sideSign);
  }

  if (labels.length) {
    labels.unshift(
      context.mode === "counter"
        ? "Post-recovery attacking support: counter"
        : context.mode === "secure"
          ? "Post-recovery attacking support: secure"
          : "Post-recovery attacking support: establish"
    );
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedPostRecoveryIds,
  };
}

function getOffensiveRestDefenceNetContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile?.phaseKey === "setPiece") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType === "recovery") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = clampToPitch(actionMeta?.target ?? ballPoint, 2.5);
  const ballDepth = getAttackingDepth(targetPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  if (ballDepth < 34 && startDepth < 34) {
    return null;
  }

  const actionSpace = getActionSpaceValue(startPoint, targetPoint, teamId, profile);
  const targetThreat = actionSpace.targetThreat;
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const actionForwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const highAttack =
    ballDepth >= 58 ||
    targetThreat.assistZone >= 0.28 ||
    targetThreat.cutbackZone >= 0.18 ||
    targetThreat.box >= 0.12;
  const transitionRisk = clamp(
    ballDepth / 100 * 0.34 +
      (profile.risk ?? 0.5) * 0.22 +
      (profile.directness ?? 0.5) * 0.12 +
      (actionForwardGain >= 6 ? 0.12 : 0) +
      (actionType === "dribble" ? 0.08 : 0) +
      (actionType === "shot" ? 0.16 : 0) +
      actionSpace.value * 0.18 +
      clamp(actionSpace.lineBreakCount / 2, 0, 1) * 0.14,
    0,
    1.3
  );
  const counterPressReadiness = clamp(
    (profile.tempo ?? 0.5) * 0.22 +
      (profile.risk ?? 0.5) * 0.18 +
      (profile.supportCompactness ?? 0.55) * 0.14 +
      (profile.styleKey === "gegenpress" ? 0.22 : 0) +
      (profile.styleKey === "vertical-tiki-taka" ? 0.08 : 0) +
      (actionSpace.targetPressure >= 0.44 ? 0.08 : 0) +
      (highAttack ? 0.12 : 0),
    0,
    1.25
  );
  const restNeed = clamp(
    transitionRisk * 0.64 +
      (highAttack ? 0.16 : 0) +
      ((profile.restBehind ?? 22) <= 21 ? 0.1 : 0),
    0,
    1.2
  );

  return {
    actionType,
    actionForwardGain,
    actionSpace,
    ballDepth,
    counterPressReadiness,
    highAttack,
    restNeed,
    sideSign,
    startPoint: cloneVector(startPoint),
    targetPoint,
    targetThreat,
    transitionRisk,
  };
}

function getOffensiveRestDefenceNetTarget(teamId, context, slot, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = context.ballDepth;
  const sideSign = context.sideSign || 1;
  const restBehind = profile.restBehind ?? 22;
  const compactness = profile.supportCompactness ?? 0.56;
  const ball = context.targetPoint;
  const points = {
    centralAnchor: clampToPitch({
      x: ball.x - sign * (19 + restBehind * 0.2 + context.restNeed * 2.2),
      y: clamp(lerp(ball.y, pitch.width / 2, 0.78), 14, pitch.width - 14),
    }, 3),
    farAnchor: clampToPitch({
      x: ball.x - sign * (23 + restBehind * 0.18 + context.transitionRisk * 2),
      y: clamp(pitch.width / 2 - sideSign * 11.5, 10, pitch.width - 10),
    }, 3),
    ballSideScreen: clampToPitch({
      x: ball.x - sign * (9 + context.restNeed * 3.2),
      y: clamp(lerp(ball.y, pitch.width / 2 + sideSign * 5.5, 0.5 + compactness * 0.12), 9, pitch.width - 9),
    }, 3),
    closeCounterPress: clampToPitch({
      x: ball.x - sign * lerp(5.8, 2.8, context.counterPressReadiness),
      y: clamp(ball.y + sideSign * lerp(4.8, 2.7, context.counterPressReadiness), 4.5, pitch.width - 4.5),
    }, 3),
    farSidePrevent: clampToPitch({
      x: ball.x - sign * (14.5 + context.restNeed * 3),
      y: clamp(pitch.width / 2 - sideSign * lerp(17, 24, profile.widthDiscipline ?? 0.62), 5, pitch.width - 5),
    }, 3),
    recoveryLine: clampToPitch({
      x: ball.x - sign * (29 + restBehind * 0.12 + context.transitionRisk * 2.4),
      y: clamp(pitch.width / 2 + sideSign * 5.5, 12, pitch.width - 12),
    }, 3),
  };

  if (slot === "centralAnchor" && depth < 46) {
    points.centralAnchor.x = getDepthX(teamId, clamp(depth - restBehind * 0.72, 14, 48));
  }

  return points[slot] ?? points.centralAnchor;
}

function applyOffensiveRestDefenceNetTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getOffensiveRestDefenceNetContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
  ].filter(Boolean));
  const protectedRestIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getOffensiveRestDefenceNetTarget(teamId, context, slot, profile);
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, target)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, target);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedRestIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("centralAnchor", ["rest", "pivot", "wideBack"], "Rest-defence net: central anchor");

  if (context.restNeed >= 0.42 || context.ballDepth >= 48) {
    assign("farAnchor", ["rest", "wideBack", "pivot"], "Rest-defence net: far cover", -context.sideSign);
  }

  if (context.counterPressReadiness >= 0.46 || context.actionType === "dribble" || context.actionSpace.targetPressure >= 0.44) {
    assign("ballSideScreen", ["pivot", "connector", "wideBack"], "Rest-defence net: ball-side screen", context.sideSign);
    assign("closeCounterPress", ["connector", "wideForward", "secondStriker", "pivot"], "Rest-defence net: counter-press support", context.sideSign);
  }

  if (context.highAttack || profile.switchBias >= 0.56 || profile.widthDiscipline >= 0.64) {
    assign("farSidePrevent", ["wideBack", "wideForward", "connector"], "Rest-defence net: stop weak-side break", -context.sideSign);
  }

  if (context.ballDepth >= 66 || context.actionType === "shot" || context.transitionRisk >= 0.72) {
    assign("recoveryLine", ["rest", "pivot", "wideBack"], "Rest-defence net: recovery line");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedRestIds,
  };
}

function getPressResistanceEscapeTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const compactness = profile.supportCompactness ?? 0.56;
  const isWide = isWidePrincipleZone(ballPoint);
  const insideY = clamp(lerp(ballPoint.y, pitch.width / 2, isWide ? 0.78 : 0.44), 7, pitch.width - 7);
  const oppositeY = clamp(pitch.width / 2 - sideSign * 18.5, 6, pitch.width - 6);
  const sameSideHalfY = clamp(pitch.width / 2 + sideSign * 10.5, 8, pitch.width - 8);
  const points = {
    underEscape: getDepthPoint(teamId, clamp(depth - (10.5 + compactness * 4), 16, 74), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 3.5, 0.52), 8, pitch.width - 8),
    }),
    sideEscape: getDepthPoint(teamId, clamp(depth - 2.5, 24, 82), {
      y: insideY,
    }),
    thirdPlayer: getDepthPoint(teamId, clamp(depth + 4.5 + (profile.directness ?? 0.52) * 4.5, 34, 88), {
      y: clamp(lerp(ballPoint.y, sameSideHalfY, isWide ? 0.42 : 0.68), 8, pitch.width - 8),
    }),
    switchOutlet: getDepthPoint(teamId, clamp(depth + 1.5 + (profile.switchBias ?? 0.5) * 6, 32, 88), {
      y: oppositeY,
    }),
    safetyBehind: clampToPitch({
      x: ballPoint.x - sign * (18 + compactness * 5),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.82), 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.underEscape;
}

function applyPressResistanceEscapeSupportTargets(
  teamId,
  targets,
  ballPoint,
  actionMeta,
  profile,
  protectedIds = new Set()
) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 11.5);
  const nearestGap = getNearestOpponentGapToPoint(teamId, ballPoint);
  const active =
    pressure >= 0.46 ||
    nearestGap <= 4.9 ||
    (actionMeta?.autoPrinciples ?? []).some((label) => String(label).toLowerCase().includes("pressure"));

  if (!active) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const sideSign = getWideSideSign(ballPoint) || 1;
  const depth = getAttackingDepth(ballPoint, teamId);
  const isWide = isWidePrincipleZone(ballPoint);
  const threat = getPitchThreatProfile(ballPoint, teamId);
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getPressResistanceEscapeTarget(teamId, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    assignedIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("underEscape", ["pivot", "connector", "wideBack", "rest"], "Press escape: support under ball");
  assign("sideEscape", ["connector", "pivot", "wideForward", "wideBack"], "Press escape: inside angle", isWide ? 0 : sideSign);

  if (pressure >= 0.56 || nearestGap <= 3.4 || threat.betweenLines >= 0.28) {
    assign("thirdPlayer", ["connector", "wideForward", "secondStriker", "striker"], "Press escape: third-player outlet", isWide ? sideSign : 0);
  }

  if (isWide || profile.switchBias >= 0.56 || pressure >= 0.58) {
    assign("switchOutlet", ["wideForward", "wideBack", "connector"], "Press escape: switch outlet", -sideSign);
  }

  if (depth >= 34 && pressure >= 0.54) {
    assign("safetyBehind", ["pivot", "rest", "wideBack"], "Press escape: safety behind ball");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: assignedIds,
  };
}

function getPressEscapeContinuationTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const halfSpaceY = clamp(pitch.width / 2 + sideSign * 10.5, 8, pitch.width - 8);
  const oppositeHalfSpaceY = clamp(pitch.width / 2 - sideSign * 11.5, 8, pitch.width - 8);
  const wideExitY = clamp(pitch.width / 2 + sideSign * clamp((profile.width ?? 58) * 0.46, 22, 30), 3.5, pitch.width - 3.5);
  const weakWideY = clamp(pitch.width / 2 - sideSign * clamp((profile.width ?? 58) * 0.44, 20, 29), 3.5, pitch.width - 3.5);
  const points = {
    exitLane: getDepthPoint(teamId, clamp(depth + 8 + (profile.directness ?? 0.52) * 6, 42, 94), {
      y: clamp(lerp(ballPoint.y, halfSpaceY, isWidePrincipleZone(ballPoint) ? 0.52 : 0.7), 8, pitch.width - 8),
    }),
    wallRelease: getDepthPoint(teamId, clamp(depth + 2.5, 34, 84), {
      y: clamp(lerp(ballPoint.y, oppositeHalfSpaceY, 0.38), 8, pitch.width - 8),
    }),
    wideExit: getDepthPoint(teamId, clamp(depth + 5 + (profile.overlapBias ?? 0.5) * 5, 38, 92), {
      y: wideExitY,
    }),
    weakSwitch: getDepthPoint(teamId, clamp(depth + 4 + (profile.switchBias ?? 0.5) * 6, 38, 92), {
      y: weakWideY,
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (16 + (profile.restBehind ?? 22) * 0.12),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.exitLane;
}

function applyPressEscapeContinuationTargets(
  teamId,
  targets,
  ballPoint,
  actionMeta,
  profile,
  protectedIds = new Set()
) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const pressure = getOpponentPressureAtPoint(teamId, ballPoint, 12.5);
  const nearestGap = getNearestOpponentGapToPoint(teamId, ballPoint);
  const active =
    pressure >= 0.5 ||
    nearestGap <= 4.4 ||
    principleText.includes("press escape") ||
    principleText.includes("receive escape") ||
    principleText.includes("secure under pressure");

  if (!active) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([...protectedIds].filter(Boolean));
  const sideSign = getWideSideSign(ballPoint) || 1;
  const isWide = isWidePrincipleZone(ballPoint);
  const threat = getPitchThreatProfile(ballPoint, teamId);
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getPressEscapeContinuationTarget(teamId, ballPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    assignedIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("exitLane", ["wideForward", "secondStriker", "striker", "connector"], "Escape continuation: exit lane", isWide ? sideSign : 0);
  assign("wallRelease", ["connector", "pivot", "wideForward", "secondStriker"], "Escape continuation: wall release");

  if (isWide || (profile.overlapBias ?? 0) >= 0.55) {
    assign("wideExit", ["wideBack", "wideForward"], "Escape continuation: wide exit", sideSign);
  }

  if ((profile.switchBias ?? 0) >= 0.56 || pressure >= 0.58 || threat.centralPocket >= 0.24) {
    assign("weakSwitch", ["wideForward", "wideBack", "connector"], "Escape continuation: weak-side switch", -sideSign);
  }

  assign("restLock", ["pivot", "rest", "wideBack"], "Escape continuation: rest lock");

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: assignedIds,
  };
}

function getSwitchLandingAttackContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!teamId || !ballPoint || profile?.phaseKey === "setPiece") {
    return null;
  }

  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType !== "pass" && actionType !== "dribble") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = clampToPitch(actionMeta?.target ?? ballPoint, 2.5);
  const actionDistance = distance(startPoint, targetPoint);
  const laneShift = Math.abs(getPitchLaneIndex(startPoint) - getPitchLaneIndex(targetPoint));
  const targetDepth = getAttackingDepth(targetPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(ballPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const targetThreat = getPitchThreatProfile(targetPoint, teamId);
  const pressure = getOpponentPressureAtPoint(teamId, targetPoint, 12);
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isSwitchAction =
    actionType === "pass" &&
    (
      (actionDistance >= 18 && laneShift >= 2) ||
      principleText.includes("switch") ||
      principleText.includes("weak-side")
    );
  const isPressureEscapeSwitch =
    isSwitchAction &&
    (
      principleText.includes("press escape") ||
      principleText.includes("pressure-trap") ||
      principleText.includes("switch away")
    );
  const isFarSideWideEntry =
    isSwitchAction &&
    isWidePrincipleZone(targetPoint) &&
    targetDepth >= 34;
  const active =
    isPressureEscapeSwitch ||
    isFarSideWideEntry ||
    (
      isSwitchAction &&
      targetDepth >= 42 &&
      ((profile.switchBias ?? 0.5) >= 0.56 || (profile.widthDiscipline ?? 0.62) >= 0.64)
    );

  if (!active) {
    return null;
  }

  const finalThirdCue =
    targetDepth >= 64 ||
    targetThreat.assistZone >= 0.22 ||
    targetThreat.cutbackZone >= 0.18 ||
    targetThreat.box >= 0.16;
  const wideIsolationCue =
    isWidePrincipleZone(targetPoint) &&
    pressure <= 0.5 &&
    ((profile.overlapBias ?? 0.5) >= 0.54 || (profile.dribbleBias ?? 0.5) >= 0.5);
  const settleCue =
    targetDepth < 52 ||
    pressure >= 0.6 ||
    startDepth > targetDepth + 4;

  return {
    actionDistance,
    actionType,
    finalThirdCue,
    isFarSideWideEntry,
    isPressureEscapeSwitch,
    laneShift,
    mode: finalThirdCue
      ? "finalThird"
      : wideIsolationCue
        ? "wideIsolation"
        : settleCue
          ? "settle"
          : "progress",
    pressure,
    sideSign,
    startDepth,
    startPoint: cloneVector(startPoint),
    targetDepth,
    targetPoint,
    targetThreat,
  };
}

function getSwitchLandingAttackTarget(teamId, context, slot, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = context.targetDepth;
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const wideY = clamp(
    pitch.width / 2 + sideSign * clamp((profile.width ?? 58) * 0.49, 25.5, 31.5),
    3.4,
    pitch.width - 3.4
  );
  const outsideY = clamp(ball.y + sideSign * (5.2 + (profile.widthDiscipline ?? 0.62) * 2.2), 3.2, pitch.width - 3.2);
  const halfY = clamp(
    pitch.width / 2 + sideSign * clamp((profile.width ?? 58) * 0.24, 12, 17),
    7,
    pitch.width - 7
  );
  const weakHalfY = clamp(
    pitch.width / 2 - sideSign * clamp((profile.width ?? 58) * 0.23, 11, 16),
    8,
    pitch.width - 8
  );
  const nearBoxY = clamp(pitch.width / 2 + sideSign * 6.8, 9, pitch.width - 9);
  const farPostY = clamp(pitch.width / 2 - sideSign * 12.8, 7, pitch.width - 7);
  const points = {
    outsideOverlap: getDepthPoint(teamId, clamp(depth + 6.8 + (profile.overlapBias ?? 0.5) * 5.2, 42, 96), {
      y: outsideY,
    }),
    underlap: getDepthPoint(teamId, clamp(depth + 5.4 + (profile.shortSupport ?? 0.55) * 4.2, 42, 92), {
      y: clamp(lerp(ball.y, halfY, 0.72), 7, pitch.width - 7),
    }),
    insidePocket: getDepthPoint(teamId, clamp(depth + 2.5 + (profile.lineBreakBias ?? 0.5) * 5.2, 40, 88), {
      y: clamp(lerp(ball.y, halfY, 0.64), 7, pitch.width - 7),
    }),
    underSupport: getDepthPoint(teamId, clamp(depth - 8.5 - (profile.supportCompactness ?? 0.56) * 5.5, 18, 78), {
      y: clamp(lerp(ball.y, pitch.width / 2 - sideSign * 2.8, 0.52), 10, pitch.width - 10),
    }),
    oneVsOneClearout: getDepthPoint(teamId, clamp(depth + 9.5 + (profile.runnerBoost ?? 7) * 0.34, 48, 96), {
      y: clamp(lerp(pitch.width / 2 - sideSign * 6.5, weakHalfY, 0.22), 10, pitch.width - 10),
    }),
    boxRun: getDepthPoint(teamId, clamp(Math.max(depth + 9, 82), 76, 98), {
      y: nearBoxY,
    }),
    farPostRun: getDepthPoint(teamId, clamp(Math.max(depth + 10, 84), 78, 98), {
      y: farPostY,
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(Math.max(depth + 3.5, 69), 62, 86), {
      y: clamp(lerp(pitch.width / 2 + sideSign * 8.5, halfY, 0.28), 10, pitch.width - 10),
    }),
    widthHold: getDepthPoint(teamId, clamp(depth + 2 + (profile.widthDiscipline ?? 0.62) * 4, 38, 88), {
      y: wideY,
    }),
    weakRestLock: clampToPitch({
      x: ball.x - sign * (17 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(pitch.width / 2 - sideSign * 10.5, 11, pitch.width - 11),
    }, 3),
    restBalance: clampToPitch({
      x: ball.x - sign * (22 + (profile.restBehind ?? 22) * 0.2),
      y: clamp(lerp(ball.y, pitch.width / 2, 0.78), 13, pitch.width - 13),
    }, 3),
  };

  return points[slot] ?? points.insidePocket;
}

function applySwitchLandingAttackTargets(
  teamId,
  targets,
  ballPoint,
  actionMeta,
  profile,
  protectedIds = new Set()
) {
  const context = getSwitchLandingAttackContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
  ].filter(Boolean));
  const protectedSwitchIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getSwitchLandingAttackTarget(teamId, context, slot, profile);
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, target)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, target);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedSwitchIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("outsideOverlap", ["wideBack", "wideForward"], "Switch landing: outside overlap", context.sideSign);
  assign("insidePocket", ["connector", "secondStriker", "wideForward", "pivot"], "Switch landing: half-space link", context.sideSign);

  if (context.mode === "wideIsolation") {
    assign("underlap", ["connector", "wideBack", "wideForward"], "Switch landing: underlap option", context.sideSign);
    assign("oneVsOneClearout", ["striker", "secondStriker", "wideForward"], "Switch landing: clear the 1v1");
  } else {
    assign("underSupport", ["pivot", "connector", "rest", "wideBack"], "Switch landing: secure under-support");
  }

  if (context.mode === "finalThird") {
    assign("boxRun", ["striker", "secondStriker", "wideForward"], "Switch landing: near-box run");
    assign("farPostRun", ["wideForward", "striker", "secondStriker"], "Switch landing: far-post run", -context.sideSign);
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Switch landing: cutback edge", context.sideSign);
  } else if (context.mode === "progress") {
    assign("widthHold", ["wideForward", "wideBack"], "Switch landing: hold width to stretch", context.sideSign);
  }

  assign("restBalance", ["rest", "pivot", "wideBack"], "Switch landing: rest balance");
  if (context.targetDepth >= 48 || context.isPressureEscapeSwitch || context.mode === "finalThird") {
    assign("weakRestLock", ["rest", "wideBack", "pivot"], "Switch landing: far-side rest lock", -context.sideSign);
  }

  if (labels.length) {
    labels.unshift(
      context.mode === "finalThird"
        ? "Switch landing attack: attack the far side"
        : context.mode === "wideIsolation"
          ? "Switch landing attack: isolate and support"
          : context.mode === "settle"
            ? "Switch landing attack: secure the far side"
            : "Switch landing attack: progress after switch"
    );
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedSwitchIds,
  };
}

function getBlindsideChannelRunContext(teamId, ballPoint, actionMeta, profile) {
  if (!ballPoint || profile?.phaseKey === "setPiece") {
    return null;
  }

  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const forwardGain = (ballPoint.x - startPoint.x) * getAttackDirectionSign(teamId);
  const targetThreat = getPitchThreatProfile(ballPoint, teamId);
  const gameSpace = getAttackingGameSpaceProfile(ballPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, ballPoint, teamId, profile);
  const lineDepths = targetThreat.opponentLineDepths ?? getOpponentLineDepthsForAttackingTeam(teamId, ballPoint);
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const canThreatenDepth =
    ballDepth >= 36 &&
    (
      gameSpace.key === "space2" ||
      gameSpace.key === "space3" ||
      targetThreat.behindLine >= 0.16 ||
      actionSpace.lineBreakCount >= 1 ||
      forwardGain >= 5 ||
      profile.lineBreakBias >= 0.58 ||
      profile.directness >= 0.62 ||
      principleText.includes("exit lane") ||
      principleText.includes("line break") ||
      principleText.includes("run beyond")
    );

  if (!canThreatenDepth) {
    return null;
  }

  const initiator = getPlayerById(
    actionMeta?.carrierPlayerId ??
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  const actionDistance = distance(startPoint, ballPoint);
  const ballProfile = resolveBallActionProfile(
    actionType,
    startPoint,
    ballPoint,
    initiator,
    actionMeta?.receiverPlayerId ?? null
  );
  const actionSpeed = Math.max(
    actionMeta?.speed ??
      state.ball.speed ??
      ballProfile.averageSpeed ??
      (actionType === "dribble" ? 5.2 : 12),
    0.1
  );
  const eta = actionDistance / actionSpeed;
  const sideSign =
    getWideSideSign(ballPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const breakLine =
    actionSpace.lineBreakCount >= 1 ||
    targetThreat.behindLine >= 0.24 ||
    gameSpace.key === "space3" ||
    (forwardGain >= 8 && profile.lineBreakBias >= 0.52);

  return {
    actionType,
    startPoint,
    targetPoint: ballPoint,
    ballDepth,
    startDepth,
    forwardGain,
    targetThreat,
    gameSpace,
    actionSpace,
    lineDepths,
    eta,
    arrivalWindow: eta + 0.85 + (profile.tempo ?? 0.5) * 0.35,
    sideSign,
    breakLine,
  };
}

function getBlindsideChannelRunTarget(teamId, context, slot) {
  const sign = getAttackDirectionSign(teamId);
  const lineDepth = context.lineDepths.back ?? clamp(context.ballDepth + 18, 56, 88);
  const depthLead = context.breakLine
    ? 3.8 + (context.profile?.lineBreakBias ?? 0.5) * 4.2
    : -1.2;
  const runDepth = clamp(
    Math.max(context.ballDepth + 6, lineDepth + depthLead),
    46,
    97
  );
  const pinDepth = clamp(Math.max(context.ballDepth + 5, lineDepth - 1.4), 44, 93);
  const sideSign = context.sideSign || 1;
  const strongHalfY = clamp(pitch.width / 2 + sideSign * 11.5, 8, pitch.width - 8);
  const weakHalfY = clamp(pitch.width / 2 - sideSign * 11.5, 8, pitch.width - 8);
  const wideChannelY = clamp(pitch.width / 2 + sideSign * 23.5, 4, pitch.width - 4);
  const farChannelY = clamp(pitch.width / 2 - sideSign * 20.5, 5, pitch.width - 5);
  const points = {
    blindsideRun: getDepthPoint(teamId, runDepth, {
      y: clamp(lerp(context.targetPoint.y, weakHalfY, 0.56), 7, pitch.width - 7),
    }),
    nearChannel: getDepthPoint(teamId, clamp(runDepth - 1.2, 45, 96), {
      y: clamp(lerp(context.targetPoint.y, strongHalfY, 0.68), 7, pitch.width - 7),
    }),
    wideChannel: getDepthPoint(teamId, clamp(runDepth - 2.4, 44, 95), {
      y: wideChannelY,
    }),
    farChannel: getDepthPoint(teamId, clamp(runDepth - 1.8, 45, 96), {
      y: farChannelY,
    }),
    pinLine: getDepthPoint(teamId, pinDepth, {
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2, 0.58), 12, pitch.width - 12),
    }),
    restScreen: clampToPitch({
      x: context.targetPoint.x - sign * 22,
      y: clamp(lerp(context.targetPoint.y, pitch.width / 2, 0.74), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.blindsideRun;
}

function chooseBlindsideChannelRunner(teamId, targets, excludedIds, roleKeys, target, context) {
  const roleSet = new Set(roleKeys);
  const arrivalWindow = Math.max(context.arrivalWindow, 0.85);

  return state.players
    .filter((player) => {
      if (player.team !== teamId || excludedIds.has(player.id) || !targets.has(player.id) || isGoalkeeper(player)) {
        return false;
      }

      return roleSet.has(getOffensiveRoleKey(player, teams[teamId]?.formation));
    })
    .map((player) => {
      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      const runDistance = distance(player.position, target);
      const timeToTarget = computeTimeToCoverDistance(player, runDistance, target);
      const timingFit = clamp(1 - Math.abs(timeToTarget - arrivalWindow) / 1.8, 0, 1);
      const playerSide = getWideSideSign(player);
      const targetSide = getWideSideSign(target);
      const sideFit = !targetSide || !playerSide || playerSide === targetSide ? 0.12 : -0.08;
      const roleFit = Math.max(0.4, 1 - roleKeys.indexOf(roleKey) * 0.08);
      const score =
        roleFit * 0.24 +
        timingFit * 0.34 +
        getAutoPilotRoleStrength(player, "runner") * 0.28 +
        getPlayerTendency(player, "boxRun") * 0.16 +
        getPlayerTendency(player, "passAndMove") * 0.1 +
        sideFit -
        Math.max(timeToTarget - arrivalWindow, 0) * 0.14 -
        runDistance * 0.005;

      return {
        player,
        score,
        timeToTarget,
      };
    })
    .filter((entry) => entry.score >= 0.34 || entry.timeToTarget <= arrivalWindow + 1.2)
    .sort((a, b) => b.score - a.score)[0]?.player ?? null;
}

function applyBlindsideChannelRunTargets(
  teamId,
  targets,
  ballPoint,
  actionMeta,
  profile,
  protectedIds = new Set()
) {
  const context = getBlindsideChannelRunContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  context.profile = profile;
  const labels = [];
  const assignedIds = new Set([...protectedIds].filter(Boolean));
  const protectedRunIds = new Set();
  const assign = (slot, roleKeys, label) => {
    const target = getBlindsideChannelRunTarget(teamId, context, slot);
    const player = chooseBlindsideChannelRunner(teamId, targets, assignedIds, roleKeys, target, context);
    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedRunIds.add(player.id);
    labels.push(label);
    return player;
  };

  if (context.breakLine) {
    assign("blindsideRun", ["wideForward", "secondStriker", "striker"], "Blindside run behind line");
    assign("nearChannel", ["striker", "secondStriker", "wideForward"], "Near-channel run");
  } else {
    assign("pinLine", ["striker", "secondStriker", "wideForward"], "Pin last line");
    assign("nearChannel", ["wideForward", "secondStriker", "striker"], "Prepare channel run");
  }

  if (isWidePrincipleZone(context.targetPoint) || profile.overlapBias >= 0.56) {
    assign("wideChannel", ["wideBack", "wideForward"], "Wide channel release");
  }

  if (profile.switchBias >= 0.58 || context.targetThreat.centralPocket >= 0.28 || context.actionSpace.value >= 0.42) {
    assign("farChannel", ["wideForward", "secondStriker", "wideBack"], "Far-side blindside run");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedRunIds,
  };
}

function getPasserContinuationTarget(teamId, passer, receiver, startPoint, ballPoint, profile = {}) {
  const roleKey = getOffensiveRoleKey(passer, teams[teamId]?.formation);
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null;
  const sign = getAttackDirectionSign(teamId);
  const startDepth = getAttackingDepth(startPoint, teamId);
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const sideSign =
    getWideSideSign(ballPoint) ||
    getWideSideSign(passer) ||
    1;
  const passForwardGain = (ballPoint.x - startPoint.x) * sign;
  const passAndMove = getPlayerTendency(passer, "passAndMove");
  const overlapTendency = getPlayerTendency(passer, "overlap");
  const runTendency = Math.max(getAutoPilotRoleStrength(passer, "runner"), getPlayerTendency(passer, "boxRun"));
  const sameSideReceiver = receiver && (getWideSideSign(receiver) || sideSign) === (getWideSideSign(passer) || sideSign);
  const strongWideY = getLaneCenterY(sideSign < 0 ? "leftWide" : "rightWide", profile);
  const strongHalfY = getLaneCenterY(sideSign < 0 ? "leftHalf" : "rightHalf", profile);
  const oppositeHalfY = getLaneCenterY(sideSign < 0 ? "rightHalf" : "leftHalf", profile);
  const supportY = clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.5, 0.5), 9, pitch.width - 9);

  if (
    roleKey === "wideBack" &&
    sameSideReceiver &&
    (receiverRoleKey === "wideForward" || receiverRoleKey === "wideBack") &&
    (profile.overlapBias >= 0.54 || overlapTendency >= 0.58)
  ) {
    return {
      target: getDepthPoint(teamId, clamp(Math.max(targetDepth + 7, startDepth + 8), 46, 94), {
        y: clamp(lerp(strongWideY, ballPoint.y + sideSign * 2.8, 0.26), 3.5, pitch.width - 3.5),
      }),
      label: "Pass-and-move: overlap after pass",
    };
  }

  if (
    roleKey === "wideForward" &&
    passForwardGain >= -2 &&
    (receiverRoleKey === "connector" || receiverRoleKey === "pivot" || receiverRoleKey === "wideBack") &&
    (runTendency >= 0.54 || profile.directness >= 0.58)
  ) {
    return {
      target: getDepthPoint(teamId, clamp(Math.max(targetDepth + 8, startDepth + 9), 54, 96), {
        y: clamp(lerp(ballPoint.y, strongHalfY, 0.62), 8, pitch.width - 8),
      }),
      label: "Pass-and-move: diagonal run",
    };
  }

  if (
    (roleKey === "connector" || roleKey === "secondStriker") &&
    passAndMove >= 0.56 &&
    passForwardGain >= -3 &&
    targetDepth >= 36
  ) {
    return {
      target: getDepthPoint(teamId, clamp(targetDepth + 5 + runTendency * 5, 42, 88), {
        y: clamp(lerp(ballPoint.y, sameSideReceiver ? oppositeHalfY : strongHalfY, 0.38), 9, pitch.width - 9),
      }),
      label: "Pass-and-move: third-player support",
    };
  }

  if (
    (roleKey === "striker" || roleKey === "secondStriker") &&
    passForwardGain <= 3 &&
    (profile.shortSupport >= 0.56 || passAndMove >= 0.56)
  ) {
    return {
      target: getDepthPoint(teamId, clamp(targetDepth + 7 + runTendency * 4, 50, 96), {
        y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 5.5, 0.38), 12, pitch.width - 12),
      }),
      label: "Pass-and-move: spin off",
    };
  }

  if (roleKey === "pivot" || roleKey === "rest") {
    return {
      target: getDepthPoint(teamId, clamp(targetDepth - 12 - profile.supportCompactness * 4, 18, 64), {
        y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.66), 12, pitch.width - 12),
      }),
      label: "Pass-and-move: recycle angle",
    };
  }

  return {
    target: getDepthPoint(teamId, clamp(targetDepth - 7 - profile.shortSupport * 5, 18, 76), {
      y: supportY,
    }),
    label: "Pass-and-move: re-support",
  };
}

function applyPasserContinuationTargets(teamId, targets, ballPoint, actionMeta, profile) {
  if (!ballPoint || actionMeta?.actionType !== "pass" || profile?.phaseKey === "setPiece") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const passer = getPlayerById(
    actionMeta?.carrierPlayerId ??
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId
  );
  if (!passer || passer.team !== teamId || isGoalkeeper(passer)) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    getPlayerBallControlPoint(passer);
  const context = getPasserContinuationTarget(teamId, passer, receiver, startPoint, ballPoint, profile);
  const target = clampToPitch(context.target, 3);

  targets.set(passer.id, target);

  return {
    labels: context.label ? [context.label] : [],
    protectedIds: new Set([passer.id]),
  };
}

function applyThirdManChainSupportTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType !== "pass") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const plannedRunner = getPlayerById(actionMeta?.principleRunnerPlayerId);
  const hubPlayer = receiver ?? plannedRunner ?? null;
  const startPoint = actionMeta?.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position;
  const hubPoint = clampToPitch(ballPoint ?? actionMeta?.target ?? state.ball.target, 2.5);
  const targetDepth = getAttackingDepth(hubPoint, teamId);
  const targetThreat = getPitchThreatProfile(hubPoint, teamId);
  const isThirdManCue =
    principleText.includes("third-man") ||
    principleText.includes("third player") ||
    principleText.includes("third-player") ||
    principleText.includes("receive continuation") ||
    principleText.includes("receive flow") ||
    principleText.includes("wall pass") ||
    principleText.includes("around the corner");
  const shouldActivate =
    isThirdManCue ||
    (
      targetDepth >= 38 &&
      (
        targetThreat.betweenLines >= 0.26 ||
        targetThreat.halfSpace >= 0.28 ||
        targetThreat.centralPocket >= 0.22
      )
    );

  if (!shouldActivate) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const sideSign =
    getWideSideSign(hubPoint) ||
    getWideSideSign(hubPlayer) ||
    getWideSideSign(startPoint) ||
    1;
  const assignedIds = new Set([
    ...protectedIds,
    hubPlayer?.id,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
  ].filter(Boolean));
  const labels = [];
  const protectedChainIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, hubPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, hubPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getReceptionSupportTarget(teamId, hubPoint, slot, sideSign, profile)
    )) {
      return null;
    }

    assignedIds.add(player.id);
    protectedChainIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("under", ["pivot", "connector", "wideBack", "rest"], "Third-man chain: bounce support");
  assign("inside", ["connector", "wideForward", "secondStriker", "pivot"], "Third-man chain: inside angle", isWidePrincipleZone(hubPoint) ? sideSign : 0);
  assign("beyond", ["striker", "wideForward", "secondStriker"], "Third-man chain: next-line runner");

  if (isWidePrincipleZone(hubPoint) || (profile.overlapBias ?? 0) >= 0.56) {
    assign("outside", ["wideBack", "wideForward"], "Third-man chain: outside release", sideSign);
  }

  if ((profile.switchBias ?? 0) >= 0.56 || targetThreat.centralPocket >= 0.28) {
    assign("weakSide", ["wideForward", "wideBack"], "Third-man chain: weak-side outlet", -sideSign);
  }

  assign("restLink", ["pivot", "rest"], "Third-man chain: rest link");

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedChainIds,
  };
}

function getSpaceTwoForwardFacingTarget(teamId, hubPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(hubPoint, teamId);
  const width = clamp(profile.width ?? 58, 42, 66);
  const nearHalfY = clamp(pitch.width / 2 + sideSign * 12.5, 8, pitch.width - 8);
  const farHalfY = clamp(pitch.width / 2 - sideSign * 12.5, 8, pitch.width - 8);
  const nearWideY = clamp(pitch.width / 2 + sideSign * width * 0.48, 3.5, pitch.width - 3.5);
  const farWideY = clamp(pitch.width / 2 - sideSign * width * 0.48, 3.5, pitch.width - 3.5);
  const points = {
    bounceUnder: getDepthPoint(teamId, clamp(depth - 8.5 - profile.shortSupport * 4.5, 22, 72), {
      y: clamp(lerp(hubPoint.y, pitch.width / 2 - sideSign * 4.8, 0.46), 10, pitch.width - 10),
    }),
    nextLinePin: getDepthPoint(teamId, clamp(depth + 11 + profile.runnerBoost * 0.45, 54, 97), {
      y: clamp(lerp(hubPoint.y, pitch.width / 2, 0.5), 13, pitch.width - 13),
    }),
    blindsideDiagonal: getDepthPoint(teamId, clamp(depth + 13 + profile.directness * 5.5, 56, 98), {
      y: clamp(lerp(hubPoint.y, farHalfY, 0.62), 9, pitch.width - 9),
    }),
    insideWall: getDepthPoint(teamId, clamp(depth + 2.5 + profile.shortSupport * 4, 42, 84), {
      y: clamp(lerp(hubPoint.y, nearHalfY, 0.48), 8, pitch.width - 8),
    }),
    outsideWidth: getDepthPoint(teamId, clamp(depth + 2 + profile.widthDiscipline * 5, 40, 90), {
      y: nearWideY,
    }),
    weakSideWidth: getDepthPoint(teamId, clamp(depth + 4 + profile.switchBias * 7, 42, 91), {
      y: farWideY,
    }),
    boxArrive: getDepthPoint(teamId, clamp(84 + profile.directness * 8, 80, 98), {
      y: clamp(pitch.width / 2 + sideSign * 6.4, 12, pitch.width - 12),
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(72 + profile.shortSupport * 6, 68, 83), {
      y: clamp(pitch.width / 2 - sideSign * 6.5, 14, pitch.width - 14),
    }),
    restLock: clampToPitch({
      x: hubPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(hubPoint.y, pitch.width / 2, 0.78), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.bounceUnder;
}

function applySpaceTwoForwardFacingTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const hubPoint = clampToPitch(ballPoint ?? actionMeta?.target ?? state.ball.target, 2.5);
  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    hubPoint;
  const hubSpace = getAttackingGameSpaceProfile(hubPoint, teamId);
  const hubThreat = getPitchThreatProfile(hubPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, hubPoint, teamId, profile);
  const targetDepth = getAttackingDepth(hubPoint, teamId);
  const pressure = getOpponentPressureAtPoint(teamId, hubPoint, 11.5);
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    actionMeta?.firstTouchMode,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const forwardFacingCue =
    principleText.includes("forward") ||
    principleText.includes("space 2") ||
    principleText.includes("spelyta") ||
    principleText.includes("between-lines") ||
    principleText.includes("line break") ||
    actionSpace.forwardGain >= 4 ||
    actionSpace.lineBreakCount >= 1;
  const activeSpace =
    hubSpace.key === "space2" ||
    hubThreat.betweenLines >= 0.32 ||
    hubThreat.centralPocket >= 0.24 ||
    hubThreat.halfSpace >= 0.36;
  const canAttackNextLine =
    activeSpace &&
    targetDepth >= 40 &&
    targetDepth <= 80 &&
    pressure <= 0.68 &&
    forwardFacingCue;

  if (!canAttackNextLine) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
    state.ball.carrierPlayerId,
  ].filter(Boolean));
  const protectedSpaceTwoIds = new Set();
  const sideSign = getWideSideSign(hubPoint) || getWideSideSign(startPoint) || 1;
  const isWideOrHalf = isWidePrincipleZone(hubPoint) || hubThreat.halfSpace >= 0.34;
  const finalThirdEntry =
    targetDepth >= 62 ||
    hubThreat.centralPocket >= 0.34 ||
    hubThreat.behindLine >= 0.22 ||
    actionSpace.value >= 0.46;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const target = getSpaceTwoForwardFacingTarget(teamId, hubPoint, slot, sideSign, profile);
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, hubPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, hubPoint);

    if (!setAutopilotPrincipleTarget(targets, player, target)) {
      return null;
    }

    assignedIds.add(player.id);
    protectedSpaceTwoIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("bounceUnder", ["pivot", "connector", "wideBack", "rest"], "Space 2: bounce support");
  assign("nextLinePin", ["striker", "wideForward", "secondStriker"], "Space 2: pin next line");
  assign("blindsideDiagonal", ["wideForward", "secondStriker", "striker"], "Space 2: blindside diagonal", -sideSign);
  assign("insideWall", ["connector", "wideForward", "secondStriker", "pivot"], "Space 2: inside wall pass", isWideOrHalf ? sideSign : 0);

  if (isWideOrHalf || profile.overlapBias >= 0.56 || profile.widthDiscipline >= 0.62) {
    assign("outsideWidth", ["wideBack", "wideForward"], "Space 2: outside lane", sideSign);
  }

  if (profile.switchBias >= 0.54 || pressure >= 0.48 || !isWideOrHalf) {
    assign("weakSideWidth", ["wideForward", "wideBack"], "Space 2: weak-side release", -sideSign);
  }

  if (finalThirdEntry) {
    assign("boxArrive", ["striker", "wideForward", "secondStriker"], "Space 2: attack box");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Space 2: cutback edge");
  }

  assign("restLock", ["pivot", "rest", "wideBack"], "Space 2: rest-defence lock");

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedSpaceTwoIds,
  };
}

function getSpaceTwoContinuationContext(teamId, ballPoint, actionMeta, profile = {}) {
  if (!ballPoint || profile?.phaseKey === "setPiece" || actionMeta?.actionType === "shot") {
    return null;
  }

  const hubPoint = clampToPitch(ballPoint ?? actionMeta?.target ?? state.ball.target, 2.5);
  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    hubPoint;
  const hubSpace = getAttackingGameSpaceProfile(hubPoint, teamId);
  const hubThreat = getPitchThreatProfile(hubPoint, teamId);
  const actionSpace = getActionSpaceValue(startPoint, hubPoint, teamId, profile);
  const targetDepth = getAttackingDepth(hubPoint, teamId);
  const pressure = getOpponentPressureAtPoint(teamId, hubPoint, 11.5);
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    actionMeta?.profileLabel,
    actionMeta?.label,
    actionMeta?.firstTouchMode,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const continuationCue =
    principleText.includes("space 2") ||
    principleText.includes("spelyta") ||
    principleText.includes("between-lines") ||
    principleText.includes("line break") ||
    principleText.includes("third-man") ||
    actionSpace.lineBreakCount >= 1 ||
    actionSpace.forwardGain >= 4 ||
    actionSpace.gameSpaceGain >= 1;
  const activeSpace =
    hubSpace.key === "space2" ||
    actionSpace.targetGameSpaceKey === "space2" ||
    hubThreat.betweenLines >= 0.28 ||
    hubThreat.centralPocket >= 0.22 ||
    hubThreat.halfSpace >= 0.34;

  if (!activeSpace || !continuationCue || targetDepth < 38 || targetDepth > 86 || pressure > 0.78) {
    return null;
  }

  const sideSign = getWideSideSign(hubPoint) || getWideSideSign(startPoint) || 1;
  const isWideOrHalf = isWidePrincipleZone(hubPoint) || hubThreat.halfSpace >= 0.34;
  const finalThirdSurge =
    targetDepth >= 64 ||
    hubThreat.centralPocket >= 0.34 ||
    hubThreat.behindLine >= 0.2 ||
    actionSpace.value >= 0.5;
  const mode = finalThirdSurge
    ? "finalThird"
    : isWideOrHalf || profile.overlapBias >= 0.58 || profile.widthDiscipline >= 0.64
      ? "wide"
      : "central";

  return {
    actionSpace,
    hubPoint,
    hubThreat,
    mode,
    pressure,
    sideSign,
    startPoint,
    targetDepth,
  };
}

function getSpaceTwoContinuationTarget(teamId, context, slot) {
  const sign = getAttackDirectionSign(teamId);
  const { actionSpace, hubPoint, mode, sideSign, targetDepth } = context;
  const profile = getOffensiveAutopilotProfile(teamId, hubPoint, getOffensivePhaseKey(teamId, hubPoint));
  const width = clamp(profile.width ?? 58, 44, 68);
  const forwardBoost = clamp((actionSpace.forwardGain ?? 0) / 12, 0, 2.5);
  const nearHalfY = clamp(pitch.width / 2 + sideSign * 12.5, 8, pitch.width - 8);
  const farHalfY = clamp(pitch.width / 2 - sideSign * 12.5, 8, pitch.width - 8);
  const nearWideY = clamp(pitch.width / 2 + sideSign * width * 0.5, 3.2, pitch.width - 3.2);
  const farWideY = clamp(pitch.width / 2 - sideSign * width * 0.5, 3.2, pitch.width - 3.2);
  const boxLaneY = clamp(pitch.width / 2 + sideSign * 5.4, 13, pitch.width - 13);
  const farPostY = clamp(pitch.width / 2 - sideSign * 10.5, 10, pitch.width - 10);
  const nextLineDepth = clamp(targetDepth + 10 + profile.directness * 5 + forwardBoost, 54, 97);
  const supportDepth = clamp(targetDepth - 7.5 - profile.shortSupport * 5, 24, 72);

  const points = {
    secureBounce: getDepthPoint(teamId, supportDepth, {
      y: clamp(lerp(hubPoint.y, pitch.width / 2 - sideSign * 5.5, 0.52), 9, pitch.width - 9),
    }),
    thirdManRelease: getDepthPoint(teamId, clamp(targetDepth + 4 + profile.shortSupport * 4, 44, 84), {
      y: clamp(lerp(hubPoint.y, mode === "wide" ? nearHalfY : farHalfY, 0.56), 8, pitch.width - 8),
    }),
    runnerBeyond: getDepthPoint(teamId, nextLineDepth, {
      y: clamp(lerp(hubPoint.y, mode === "central" ? boxLaneY : farHalfY, 0.64), 9, pitch.width - 9),
    }),
    outsideOverlap: getDepthPoint(teamId, clamp(targetDepth + 8 + profile.overlapBias * 6, 48, 96), {
      y: nearWideY,
    }),
    insideUnderlap: getDepthPoint(teamId, clamp(targetDepth + 8 + profile.overlapBias * 4, 50, 92), {
      y: clamp(lerp(hubPoint.y, nearHalfY, 0.72), 8, pitch.width - 8),
    }),
    weakSideArrive: getDepthPoint(teamId, clamp(targetDepth + 8 + profile.switchBias * 7, 50, 94), {
      y: mode === "finalThird" ? farPostY : farWideY,
    }),
    boxPin: getDepthPoint(teamId, clamp(84 + profile.directness * 7, 78, 98), {
      y: clamp(pitch.width / 2 - sideSign * 2.8, 14, pitch.width - 14),
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(71 + profile.shortSupport * 8, 68, 84), {
      y: clamp(pitch.width / 2 + sideSign * 9.5, 14, pitch.width - 14),
    }),
    restShield: clampToPitch({
      x: hubPoint.x - sign * (22 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(hubPoint.y, pitch.width / 2, 0.8), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.thirdManRelease;
}

function applySpaceTwoContinuationTargets(teamId, targets, ballPoint, actionMeta, profile, protectedIds = new Set()) {
  const context = getSpaceTwoContinuationContext(teamId, ballPoint, actionMeta, profile);
  if (!context) {
    return {
      labels: [],
      protectedIds: new Set(),
    };
  }

  const assignedIds = new Set([
    ...protectedIds,
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
  ].filter(Boolean));
  const labels = [];
  const protectedContinuationIds = new Set();
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, assignedIds, preferredSide, context.hubPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, assignedIds, context.hubPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getSpaceTwoContinuationTarget(teamId, context, slot)
    )) {
      return null;
    }

    assignedIds.add(player.id);
    protectedContinuationIds.add(player.id);
    labels.push(label);
    return player;
  };

  if (context.pressure >= 0.48 || profile.shortSupport >= 0.72) {
    assign("secureBounce", ["pivot", "connector", "wideBack", "rest"], "Space 2 continuation: secure bounce");
  }

  assign("thirdManRelease", ["connector", "pivot", "wideForward", "secondStriker"], "Space 2 continuation: third-man release");
  assign("runnerBeyond", ["striker", "wideForward", "secondStriker"], "Space 2 continuation: run beyond");

  if (context.mode === "wide" || profile.overlapBias >= 0.56 || profile.widthDiscipline >= 0.62) {
    assign("outsideOverlap", ["wideBack", "wideForward"], "Space 2 continuation: outside overlap", context.sideSign);
    assign("insideUnderlap", ["connector", "wideBack", "wideForward"], "Space 2 continuation: inside underlap", context.sideSign);
  }

  if (context.mode !== "wide" || profile.switchBias >= 0.54 || context.pressure >= 0.44) {
    assign("weakSideArrive", ["wideForward", "wideBack"], "Space 2 continuation: weak-side arrival", -context.sideSign);
  }

  if (context.mode === "finalThird") {
    assign("boxPin", ["striker", "secondStriker", "wideForward"], "Space 2 continuation: box pin");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Space 2 continuation: cutback edge");
  }

  assign("restShield", ["pivot", "rest", "wideBack"], "Space 2 continuation: rest shield");

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: protectedContinuationIds,
  };
}

function getDepthPoint(teamId, attackingDepth, overrides = {}) {
  return clampToPitch({
    x: getDepthX(teamId, attackingDepth),
    y: pitch.width / 2,
    ...overrides,
  }, 2);
}

function applyGenerativePrincipleSupportTargets(teamId, targets, ballPoint, actionMeta, profile) {
  const labels = [];
  const excludedIds = new Set([
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.carrierPlayerId,
    state.ball.receiverPlayerId,
    state.ball.initiatorPlayerId,
  ].filter(Boolean));
  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, teams[teamId]?.formation) : null;
  const startPoint = actionMeta?.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position;
  const laneShift = Math.abs(getPitchLaneIndex(ballPoint) - getPitchLaneIndex(startPoint));
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const sideSign = getWideSideSign(ballPoint) || getWideSideSign(receiver) || 1;

  if (
    actionMeta?.actionType === "pass" &&
    (receiverRoleKey === "wideForward" || receiverRoleKey === "wideBack") &&
    isWidePrincipleZone(ballPoint)
  ) {
    const support = getMovableAutopilotPlayerByRoles(
      teamId,
      ["connector", "pivot"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, support, getSupportUnderBallTarget(teamId, ballPoint, sideSign, profile))) {
      excludedIds.add(support.id);
      labels.push("Underneath support");
    }

    labels.push("Ask question wide");
  }

  labels.push(...applyGoalkeeperBuildOutPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyShotReboundPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyCornerDeliveryPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyReceptionSupportPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyOpenGrassCarrySupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyGameSpaceOffBallPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyHighValueSpacePrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyTransitionAttackPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyBetweenLinesPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyFormationIdentityPrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyPossessionRoutePrincipleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));
  labels.push(...applyOpponentBlockResponsiveTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));

  if (
    actionMeta?.actionType === "pass" &&
    (receiverRoleKey === "pivot" || receiverRoleKey === "connector" || receiverRoleKey === "secondStriker")
  ) {
    const runner = getMovableAutopilotPlayerByRoles(
      teamId,
      ["wideForward", "striker", "secondStriker"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, runner, getThirdManRunnerTarget(teamId, ballPoint, sideSign, profile))) {
      excludedIds.add(runner.id);
      labels.push("Third-player runner");
    }

    labels.push("Find the Third");
  }

  if (actionMeta?.actionType === "pass" && laneShift >= 2 && distance(startPoint, ballPoint) >= 16) {
    const weakSideRunner = getMovableAutopilotPlayerByRoles(
      teamId,
      ["wideForward", "wideBack"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, weakSideRunner, getThirdManRunnerTarget(teamId, ballPoint, sideSign, profile))) {
      excludedIds.add(weakSideRunner.id);
    }

    labels.push("Change corridor");
  }

  if (
    targetDepth >= 70 ||
    actionMeta?.actionType === "shot" ||
    (actionMeta?.actionType === "pass" && Math.abs(ballPoint.y - pitch.width / 2) <= 18 && targetDepth >= 64)
  ) {
    labels.push(...applyBoxOccupationPrincipleTargets(teamId, targets, ballPoint, excludedIds));
    labels.push("Attack box");
  }

  labels.push(...applyPositionalPlayOccupationTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    excludedIds
  ));

  return {
    labels: uniquePrincipleLabels(labels),
    protectedIds: new Set(excludedIds),
  };
}

function getHighValueAttackTarget(teamId, ballPoint, slot, sideSign = 1) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const baseDepth = clamp(ballDepth + 8, 52, 86);
  const halfSpaceY = pitch.width / 2 + sideSign * 13.5;
  const oppositeHalfSpaceY = pitch.width / 2 - sideSign * 12.5;
  const points = {
    goldenRun: getDepthPoint(teamId, clamp(baseDepth + 8, 62, 91), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.68), 14, pitch.width - 14),
    }),
    halfSpaceRun: getDepthPoint(teamId, clamp(baseDepth + 6, 60, 88), {
      y: clamp(lerp(ballPoint.y, halfSpaceY, 0.5), 8, pitch.width - 8),
    }),
    supportPocket: getDepthPoint(teamId, clamp(ballDepth + 1.5, 42, 72), {
      y: clamp(lerp(ballPoint.y, oppositeHalfSpaceY, 0.34), 9, pitch.width - 9),
    }),
    reboundEdge: getDepthPoint(teamId, 74, {
      y: clamp(pitch.width / 2 - sideSign * 5.5, 17, pitch.width - 17),
    }),
    pinLine: clampToPitch({
      x: ballPoint.x + sign * 12,
      y: clamp(pitch.width / 2 + sideSign * 5.5, 14, pitch.width - 14),
    }, 2),
  };

  return points[slot] ?? points.goldenRun;
}

function applyHighValueSpacePrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  const labels = [];
  const targetThreat = getPitchThreatProfile(ballPoint, teamId);
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const ballSide = getWideSideSign(ballPoint) || 1;
  const shouldAttackHighValueSpace =
    targetDepth >= 46 &&
    (targetThreat.value >= 0.44 ||
      targetThreat.centralPocket >= 0.32 ||
      targetThreat.betweenLines >= 0.42 ||
      targetThreat.assistZone >= 0.42 ||
      actionMeta?.actionType === "dribble");

  if (!shouldAttackHighValueSpace) {
    return labels;
  }

  const plannedRunner = getPlayerById(actionMeta?.principleRunnerPlayerId);
  if (
    plannedRunner?.team === teamId &&
    targets.has(plannedRunner.id) &&
    !excludedIds.has(plannedRunner.id) &&
    setAutopilotPrincipleTarget(targets, plannedRunner, clampToPitch(ballPoint, 2.5))
  ) {
    excludedIds.add(plannedRunner.id);
    labels.push("Runner attacks space");
  }

  const runner = getMovableAutopilotPlayerByRoles(
    teamId,
    ["striker", "wideForward", "secondStriker"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(
    targets,
    runner,
    getHighValueAttackTarget(
      teamId,
      ballPoint,
      targetThreat.assistZone >= 0.5 ? "halfSpaceRun" : "goldenRun",
      ballSide
    )
  )) {
    excludedIds.add(runner.id);
    labels.push(`Attack ${targetThreat.primaryLabel}`);
  }

  const connector = getMovableAutopilotPlayerByRoles(
    teamId,
    ["connector", "pivot"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(
    targets,
    connector,
    getHighValueAttackTarget(teamId, ballPoint, "supportPocket", -ballSide)
  )) {
    excludedIds.add(connector.id);
    labels.push("Support the next action");
  }

  if (targetThreat.box >= 0.34 || targetDepth >= 70) {
    const edge = getMovableAutopilotPlayerByRoles(
      teamId,
      ["connector", "pivot", "wideForward"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, edge, getHighValueAttackTarget(teamId, ballPoint, "reboundEdge", ballSide))) {
      excludedIds.add(edge.id);
      labels.push("Edge-of-box security");
    }
  }

  return labels;
}

function getFormationIdentityTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const points = {
    wideOverlap: getDepthPoint(teamId, clamp(ballDepth + 9 + profile.overlapBias * 4, 48, 94), {
      y: clamp(ballPoint.y + sideSign * (5.5 + profile.widthDiscipline * 2.4), 3.2, pitch.width - 3.2),
    }),
    halfSpaceSupport: getDepthPoint(teamId, clamp(ballDepth - 1 + profile.shortSupport * 5, 42, 78), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 12.5, 0.55), 8, pitch.width - 8),
    }),
    underSupport: getDepthPoint(teamId, clamp(ballDepth - 9, 24, 72), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 8, 0.44), 8, pitch.width - 8),
    }),
    pinCentreBacks: getDepthPoint(teamId, clamp(ballDepth + 12, 58, 97), {
      y: clamp(pitch.width / 2 - sideSign * 3.6, 15, pitch.width - 15),
    }),
    farSideAttack: getDepthPoint(teamId, clamp(ballDepth + 11, 56, 95), {
      y: clamp(pitch.width / 2 - sideSign * 18.5, 5, pitch.width - 5),
    }),
    weakSideWidth: getDepthPoint(teamId, clamp(ballDepth + 3, 38, 82), {
      y: clamp(pitch.width / 2 - sideSign * 28.5, 3.6, pitch.width - 3.6),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (21 + profile.restBehind * 0.16),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.7), 15, pitch.width - 15),
    }, 3),
    secondStrikerLink: getDepthPoint(teamId, clamp(ballDepth + 5, 44, 84), {
      y: clamp(pitch.width / 2 + sideSign * 7.5, 14, pitch.width - 14),
    }),
    secondBallRing: getDepthPoint(teamId, clamp(ballDepth + 2, 42, 76), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.52), 12, pitch.width - 12),
    }),
  };

  return points[slot] ?? points.halfSpaceSupport;
}

function applyFormationIdentityPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  const labels = [];
  const formation = profile.formation ?? teams[teamId]?.formation ?? "4-3-3";
  const receiver = getPlayerById(actionMeta?.receiverPlayerId);
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, formation) : null;
  const ballSide = getWideSideSign(ballPoint) || getWideSideSign(receiver) || 1;
  const targetDepth = getAttackingDepth(ballPoint, teamId);
  const isWideEntry =
    isWidePrincipleZone(ballPoint) &&
    targetDepth >= 38 &&
    (receiverRoleKey === "wideForward" || receiverRoleKey === "wideBack" || actionMeta?.actionType === "dribble");
  const isCentralProgression =
    Math.abs(ballPoint.y - pitch.width / 2) <= 18 &&
    targetDepth >= 38 &&
    targetDepth <= 76;

  if (formation === "4-3-3" && isWideEntry) {
    const overlap = getMovableAutopilotPlayerByRolesOnSide(teamId, ["wideBack"], targets, excludedIds, ballSide, ballPoint);
    if (setAutopilotPrincipleTarget(targets, overlap, getFormationIdentityTarget(teamId, ballPoint, "wideOverlap", ballSide, profile))) {
      excludedIds.add(overlap.id);
      labels.push("4-3-3 overlap");
    }

    const halfSpace = getMovableAutopilotPlayerByRoles(teamId, ["connector"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, halfSpace, getFormationIdentityTarget(teamId, ballPoint, "halfSpaceSupport", ballSide, profile))) {
      excludedIds.add(halfSpace.id);
      labels.push("8/10 half-space support");
    }

    const striker = getMovableAutopilotPlayerByRoles(teamId, ["striker"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, striker, getFormationIdentityTarget(teamId, ballPoint, "pinCentreBacks", ballSide, profile))) {
      excludedIds.add(striker.id);
      labels.push("9 pins the line");
    }

    const farWinger = getMovableAutopilotPlayerByRolesOnSide(teamId, ["wideForward"], targets, excludedIds, -ballSide, ballPoint);
    if (setAutopilotPrincipleTarget(targets, farWinger, getFormationIdentityTarget(teamId, ballPoint, "farSideAttack", ballSide, profile))) {
      excludedIds.add(farWinger.id);
      labels.push("Far-side W attacks");
    }
  }

  if (formation === "3-4-3" && isWideEntry) {
    const insideForward = getMovableAutopilotPlayerByRolesOnSide(teamId, ["wideForward"], targets, excludedIds, ballSide, ballPoint);
    if (setAutopilotPrincipleTarget(targets, insideForward, getFormationIdentityTarget(teamId, ballPoint, "halfSpaceSupport", ballSide, profile))) {
      excludedIds.add(insideForward.id);
      labels.push("3-4-3 inside forward pocket");
    }

    const oppositeWingBack = getMovableAutopilotPlayerByRolesOnSide(teamId, ["wideBack"], targets, excludedIds, -ballSide, ballPoint);
    if (setAutopilotPrincipleTarget(targets, oppositeWingBack, getFormationIdentityTarget(teamId, ballPoint, "weakSideWidth", ballSide, profile))) {
      excludedIds.add(oppositeWingBack.id);
      labels.push("Weak-side WB holds width");
    }

    const striker = getMovableAutopilotPlayerByRoles(teamId, ["striker"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, striker, getFormationIdentityTarget(teamId, ballPoint, "pinCentreBacks", ballSide, profile))) {
      excludedIds.add(striker.id);
      labels.push("Front three pinning");
    }
  }

  if ((formation === "4-4-2" || formation === "3-5-2") && targetDepth >= 42) {
    const secondStriker = getMovableAutopilotPlayerByRoles(teamId, ["secondStriker", "striker"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, secondStriker, getFormationIdentityTarget(teamId, ballPoint, "secondStrikerLink", ballSide, profile))) {
      excludedIds.add(secondStriker.id);
      labels.push("Front-two link");
    }

    const secondBall = getMovableAutopilotPlayerByRoles(teamId, ["connector", "pivot"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, secondBall, getFormationIdentityTarget(teamId, ballPoint, "secondBallRing", ballSide, profile))) {
      excludedIds.add(secondBall.id);
      labels.push("Second-ball ring");
    }
  }

  if (isCentralProgression) {
    const weakSide = getMovableAutopilotPlayerByRolesOnSide(teamId, ["wideForward", "wideBack"], targets, excludedIds, -ballSide, ballPoint);
    if (setAutopilotPrincipleTarget(targets, weakSide, getFormationIdentityTarget(teamId, ballPoint, "weakSideWidth", ballSide, profile))) {
      excludedIds.add(weakSide.id);
      labels.push("Weak-side outlet");
    }

    const restLock = getMovableAutopilotPlayerByRoles(teamId, ["pivot", "rest"], targets, excludedIds, ballPoint);
    if (setAutopilotPrincipleTarget(targets, restLock, getFormationIdentityTarget(teamId, ballPoint, "restLock", ballSide, profile))) {
      excludedIds.add(restLock.id);
      labels.push("Rest-defence lock");
    }
  }

  return labels;
}

function getPossessionRouteOccupationTarget(teamId, ballPoint, slot, context, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const routeY = getLaneCenterY(context.routeTargetLane ?? getPitchLaneKey(ballPoint), profile);
  const nextY = getLaneCenterY(context.nextRouteLane ?? context.routeTargetLane ?? getPitchLaneKey(ballPoint), profile);
  const routeSide =
    Math.sign(routeY - pitch.width / 2) ||
    getWideSideSign(ballPoint) ||
    1;
  const nextSide =
    Math.sign(nextY - pitch.width / 2) ||
    -routeSide;
  const points = {
    routeLaneWidth: getDepthPoint(teamId, clamp(ballDepth + 2.5 + profile.widthDiscipline * 5, 34, 90), {
      y: clamp(routeY, 3.4, pitch.width - 3.4),
    }),
    routeHalfConnection: getDepthPoint(teamId, clamp(ballDepth + 1 + profile.shortSupport * 5, 34, 82), {
      y: clamp(lerp(routeY, pitch.width / 2 + routeSide * 12.5, 0.48), 7, pitch.width - 7),
    }),
    centralLink: getDepthPoint(teamId, clamp(ballDepth - 3 + profile.shortSupport * 4, 28, 76), {
      y: clamp(lerp(routeY, pitch.width / 2, 0.72), 10, pitch.width - 10),
    }),
    underLink: getDepthPoint(teamId, clamp(ballDepth - 10 - profile.supportCompactness * 5, 18, 72), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - routeSide * 5.2, 0.42), 10, pitch.width - 10),
    }),
    nextLaneRun: getDepthPoint(teamId, clamp(ballDepth + 10 + profile.progressionUrgency * 6, 46, 96), {
      y: clamp(nextY, 5.5, pitch.width - 5.5),
    }),
    switchRelease: getDepthPoint(teamId, clamp(ballDepth + 4 + profile.switchBias * 8, 38, 88), {
      y: clamp(nextY || pitch.width / 2 - routeSide * 25, 3.5, pitch.width - 3.5),
    }),
    depthPin: getDepthPoint(teamId, clamp(ballDepth + 13 + profile.directness * 5, 54, 98), {
      y: clamp(lerp(routeY, pitch.width / 2, 0.58), 12, pitch.width - 12),
    }),
    farSideHold: getDepthPoint(teamId, clamp(ballDepth + 1.5 + profile.switchBias * 5, 34, 86), {
      y: clamp(pitch.width / 2 - nextSide * 27, 3.5, pitch.width - 3.5),
    }),
    restBalance: clampToPitch({
      x: ballPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.centralLink;
}

function applyPossessionRoutePrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  const startPoint = actionMeta?.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? state.ball.position;
  if (!startPoint || !ballPoint || profile.phaseKey === "setPiece") {
    return [];
  }

  const plan = getAutoPilotPossessionPlan(teamId, startPoint, profile);
  const rhythm = getPossessionRhythmContext(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const routeStage = getAutoPilotPossessionRouteStage(plan, rhythm, depth);
  const routeTargetLane =
    plan.routeLanes?.[routeStage] ??
    plan.routeLanes?.[0] ??
    getPitchLaneKey(ballPoint);
  const nextRouteLane =
    plan.routeLanes?.[Math.min(routeStage + 1, (plan.routeLanes?.length ?? 1) - 1)] ??
    routeTargetLane;
  const routeIntent =
    plan.routeIntents?.[Math.min(routeStage, (plan.routeIntents?.length ?? 1) - 1)] ??
    "progress";
  const laneDistance = Math.abs(getPitchLaneIndex(routeTargetLane) - getPitchLaneIndex(nextRouteLane));
  const routeSide =
    Math.sign(getLaneCenterY(routeTargetLane, profile) - pitch.width / 2) ||
    getWideSideSign(ballPoint) ||
    1;
  const targetIsWide = routeTargetLane === "leftWide" || routeTargetLane === "rightWide";
  const targetIsHalf = routeTargetLane === "leftHalf" || routeTargetLane === "rightHalf";
  const targetIsCentral = routeTargetLane === "central";
  const context = {
    plan,
    routeStage,
    routeTargetLane,
    nextRouteLane,
    routeIntent,
  };
  const labels = [];
  const localExcluded = new Set(excludedIds);
  const assign = (slot, roleKeys, label, sideSign = 0) => {
    const player = sideSign
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, localExcluded, sideSign, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, localExcluded, ballPoint);

    if (!setAutopilotPrincipleTarget(targets, player, getPossessionRouteOccupationTarget(teamId, ballPoint, slot, context, profile))) {
      return null;
    }

    localExcluded.add(player.id);
    excludedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (targetIsWide) {
    assign("routeLaneWidth", ["wideBack", "wideForward"], "Route width", routeSide);
    assign("routeHalfConnection", ["connector", "wideForward"], "Half-space link", routeSide);
    if (profile.overlapBias >= 0.52 || plan.routeKey === "overlap-cutback") {
      assign("nextLaneRun", ["wideBack", "wideForward"], "Route overlap", routeSide);
    }
  } else if (targetIsHalf) {
    assign("routeHalfConnection", ["connector", "wideForward", "secondStriker"], "Route half-space", routeSide);
    assign("routeLaneWidth", ["wideBack", "wideForward"], "Hold route width", routeSide);
    assign("depthPin", ["striker", "wideForward", "secondStriker"], "Pin for route");
  } else if (targetIsCentral) {
    assign("centralLink", ["pivot", "connector", "secondStriker"], "Central route link");
    assign("depthPin", ["striker", "wideForward", "secondStriker"], "Central depth threat");
    assign("farSideHold", ["wideForward", "wideBack"], "Far-side route outlet", -routeSide);
  }

  if (routeIntent === "switch" || laneDistance >= 2 || plan.routeKey === "wide-overload-switch" || plan.routeKey === "patient-switch") {
    const nextSide = Math.sign(getLaneCenterY(nextRouteLane, profile) - pitch.width / 2) || -routeSide;
    assign("switchRelease", ["wideForward", "wideBack"], "Route switch release", nextSide);
  }

  if (routeIntent === "accelerate" || routeIntent === "finish") {
    assign("nextLaneRun", ["striker", "wideForward", "secondStriker"], "Route acceleration");
  }

  assign("underLink", ["pivot", "connector", "wideBack"], "Route support under");
  assign("restBalance", ["pivot", "rest"], "Route rest-defence");

  if (labels.length) {
    labels.unshift(plan.routeLabel ?? "Possession route");
  }

  return uniquePrincipleLabels(labels);
}

function getPositionalPlayOccupationTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const width = clamp(profile.width ?? 58, 42, 66);
  const farWideY = clamp(pitch.width / 2 - sideSign * width * 0.48, 3.8, pitch.width - 3.8);
  const nearHalfY = clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 13.5, 0.46), 8, pitch.width - 8);
  const farHalfY = clamp(lerp(pitch.width / 2 - sideSign * 13.5, ballPoint.y, 0.16), 8, pitch.width - 8);
  const points = {
    underSupport: getDepthPoint(teamId, clamp(ballDepth - 8.5 - profile.shortSupport * 4, 20, 74), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.5, 0.34), 11, pitch.width - 11),
    }),
    nearHalfSupport: getDepthPoint(teamId, clamp(ballDepth + 2.5 + profile.shortSupport * 4, 38, 82), {
      y: nearHalfY,
    }),
    farHalfConnection: getDepthPoint(teamId, clamp(ballDepth + 3.5, 38, 84), {
      y: farHalfY,
    }),
    weakSideWidth: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.switchBias * 5, 36, 86), {
      y: farWideY,
    }),
    depthPin: getDepthPoint(teamId, clamp(ballDepth + 12 + profile.directness * 4, 52, 98), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.58), 14, pitch.width - 14),
    }),
    diagonalRunner: getDepthPoint(teamId, clamp(ballDepth + 11 + profile.runnerBoost * 0.6, 48, 96), {
      y: clamp(pitch.width / 2 - sideSign * 10.5, 9, pitch.width - 9),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (18 + profile.restBehind * 0.22),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 15, pitch.width - 15),
    }, 3),
    farRestCover: clampToPitch({
      x: ballPoint.x - sign * (22 + profile.restBehind * 0.18),
      y: clamp(pitch.width / 2 - sideSign * 10.5, 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.underSupport;
}

function applyPositionalPlayOccupationTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  if (profile.phaseKey === "setPiece") {
    return [];
  }

  const labels = [];
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const sideSign = getWideSideSign(ballPoint) || 1;
  const targetSpace = getPitchSpaceProfile(ballPoint, teamId);
  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  const isWideAction = targetSpace.wideCorridor >= 0.34 || targetSpace.assistZone >= 0.34 || isWidePrincipleZone(ballPoint);
  const isProgression = ballDepth >= 36;
  const isFinalThird = ballDepth >= 66 || targetSpace.box >= 0.24 || targetSpace.cutbackZone >= 0.28;

  const underSupport = getMovableAutopilotPlayerByRoles(
    teamId,
    ["pivot", "connector"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, underSupport, getPositionalPlayOccupationTarget(teamId, ballPoint, "underSupport", sideSign, profile))) {
    excludedIds.add(underSupport.id);
    labels.push("Under-ball support");
  }

  if (isWideAction || isProgression) {
    const weakSideWidth = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["wideForward", "wideBack"],
      targets,
      excludedIds,
      -sideSign,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, weakSideWidth, getPositionalPlayOccupationTarget(teamId, ballPoint, "weakSideWidth", sideSign, profile))) {
      excludedIds.add(weakSideWidth.id);
      labels.push("Weak-side width");
    }
  }

  if (isProgression) {
    const halfSpaceSupport = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["connector", "wideForward", "secondStriker"],
      targets,
      excludedIds,
      sideSign,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, halfSpaceSupport, getPositionalPlayOccupationTarget(teamId, ballPoint, "nearHalfSupport", sideSign, profile))) {
      excludedIds.add(halfSpaceSupport.id);
      labels.push("Half-space support");
    }
  }

  if (isProgression && !isFinalThird) {
    const depthPin = getMovableAutopilotPlayerByRoles(
      teamId,
      ["striker", "secondStriker", "wideForward"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, depthPin, getPositionalPlayOccupationTarget(teamId, ballPoint, "depthPin", sideSign, profile))) {
      excludedIds.add(depthPin.id);
      labels.push("Pin last line");
    }
  }

  if (isFinalThird) {
    const diagonalRunner = getMovableAutopilotPlayerByRoles(
      teamId,
      ["wideForward", "secondStriker", "striker"],
      targets,
      excludedIds,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, diagonalRunner, getPositionalPlayOccupationTarget(teamId, ballPoint, "diagonalRunner", sideSign, profile))) {
      excludedIds.add(diagonalRunner.id);
      labels.push("Diagonal box threat");
    }

    const farHalfConnection = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["connector", "wideForward"],
      targets,
      excludedIds,
      -sideSign,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, farHalfConnection, getPositionalPlayOccupationTarget(teamId, ballPoint, "farHalfConnection", sideSign, profile))) {
      excludedIds.add(farHalfConnection.id);
      labels.push("Far-half connection");
    }
  }

  const restLock = getMovableAutopilotPlayerByRoles(
    teamId,
    ["rest", "pivot"],
    targets,
    excludedIds,
    ballPoint
  );
  if (setAutopilotPrincipleTarget(targets, restLock, getPositionalPlayOccupationTarget(teamId, ballPoint, "restLock", sideSign, profile))) {
    excludedIds.add(restLock.id);
    labels.push("Rest-defence lock");
  }

  if ((actionType === "pass" || actionType === "dribble") && ballDepth >= 48) {
    const farRestCover = getMovableAutopilotPlayerByRolesOnSide(
      teamId,
      ["rest", "pivot", "wideBack"],
      targets,
      excludedIds,
      -sideSign,
      ballPoint
    );
    if (setAutopilotPrincipleTarget(targets, farRestCover, getPositionalPlayOccupationTarget(teamId, ballPoint, "farRestCover", sideSign, profile))) {
      excludedIds.add(farRestCover.id);
      labels.push("Far rest cover");
    }
  }

  return labels;
}

function getOpponentBlockOccupationTarget(teamId, ballPoint, slot, block, sideSign = 1, profile = {}) {
  const sign = getAttackDirectionSign(teamId);
  const ballDepth = getAttackingDepth(ballPoint, teamId);
  const lineDepths = block?.lineDepths ?? getOpponentLineDepthsForAttackingTeam(teamId, ballPoint);
  const width = clamp(profile.width ?? 58, 42, 66);
  const wideOffset = clamp(width * 0.49, 25.5, 31.5);
  const halfOffset = clamp(width * 0.24, 12, 17);
  const strongWideY = clamp(pitch.width / 2 + sideSign * wideOffset, 3.4, pitch.width - 3.4);
  const weakWideY = clamp(pitch.width / 2 - sideSign * wideOffset, 3.4, pitch.width - 3.4);
  const strongHalfY = clamp(pitch.width / 2 + sideSign * halfOffset, 8, pitch.width - 8);
  const weakHalfY = clamp(pitch.width / 2 - sideSign * halfOffset, 8, pitch.width - 8);
  const betweenLinesDepth = clamp(
    (lineDepths.midfield + lineDepths.back) / 2,
    Math.max(38, ballDepth + 2),
    84
  );
  const highLineRunDepth = clamp((lineDepths.back ?? ballDepth + 18) + 8 + (profile.runnerBoost ?? 7) * 0.25, 56, 98);
  const points = {
    strongWidth: getDepthPoint(teamId, clamp(ballDepth + 2 + profile.widthDiscipline * 5, 34, 90), {
      y: strongWideY,
    }),
    weakWidth: getDepthPoint(teamId, clamp(ballDepth + 4 + profile.switchBias * 7, 36, 88), {
      y: weakWideY,
    }),
    switchRelease: getDepthPoint(teamId, clamp(ballDepth + 7 + profile.switchBias * 8, 42, 92), {
      y: weakWideY,
    }),
    betweenLinesPocket: getDepthPoint(teamId, betweenLinesDepth, {
      y: strongHalfY,
    }),
    farBetweenLinesPocket: getDepthPoint(teamId, clamp(betweenLinesDepth + 1.6, 42, 84), {
      y: weakHalfY,
    }),
    bounceUnder: getDepthPoint(teamId, clamp(ballDepth - 9 - profile.shortSupport * 4, 18, 74), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.5, 0.45), 10, pitch.width - 10),
    }),
    highLineRun: getDepthPoint(teamId, highLineRunDepth, {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 7, 0.46), 10, pitch.width - 10),
    }),
    boxPin: getDepthPoint(teamId, clamp(85 + profile.directness * 7, 82, 98), {
      y: clamp(pitch.width / 2 + sideSign * 5.2, 13, pitch.width - 13),
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(72 + profile.shortSupport * 6, 70, 82), {
      y: clamp(pitch.width / 2 - sideSign * 6.4, 15, pitch.width - 15),
    }),
    farPost: getDepthPoint(teamId, clamp(87, 84, 96), {
      y: clamp(pitch.width / 2 - sideSign * 11.8, 12, pitch.width - 12),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (20 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 14, pitch.width - 14),
    }, 3),
  };

  return points[slot] ?? points.bounceUnder;
}

function applyOpponentBlockResponsiveTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  if (profile.phaseKey === "setPiece" || !ballPoint) {
    return [];
  }

  const block = getOpponentBlockReadProfile(teamId, ballPoint);
  const labels = [];
  const localExcluded = new Set(excludedIds);
  const sideSign = getWideSideSign(ballPoint) || block.ballSide || 1;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, localExcluded, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, localExcluded, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getOpponentBlockOccupationTarget(teamId, ballPoint, slot, block, sideSign, profile)
    )) {
      return null;
    }

    localExcluded.add(player.id);
    excludedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (block.compactCenter >= 0.52) {
    assign("strongWidth", ["wideBack", "wideForward"], "Block read: stretch compact centre", sideSign);
    assign("weakWidth", ["wideForward", "wideBack"], "Block read: hold far width", -sideSign);

    if (block.lineGap >= 0.3 || profile.shortSupport >= 0.6) {
      assign("betweenLinesPocket", ["connector", "wideForward", "secondStriker"], "Block read: pocket outside compact block", sideSign);
    }
  }

  if (block.ballSideCompression >= 0.46) {
    assign("switchRelease", ["wideForward", "wideBack"], "Block read: weak-side release", -sideSign);
    assign("bounceUnder", ["pivot", "connector", "wideBack"], "Block read: bounce to switch");
  }

  if (block.lineGap >= 0.42) {
    assign("betweenLinesPocket", ["connector", "secondStriker", "wideForward"], "Block read: occupy line gap", sideSign);
    assign("farBetweenLinesPocket", ["connector", "wideForward"], "Block read: far pocket", -sideSign);
  }

  if (block.highLine >= 0.38) {
    assign("highLineRun", ["striker", "wideForward", "secondStriker"], "Block read: threaten high line");
    assign("bounceUnder", ["pivot", "connector"], "Block read: set the through ball");
  }

  if (block.deepBlock >= 0.38) {
    assign("strongWidth", ["wideBack", "wideForward"], "Block read: stretch low block", sideSign);
    assign("boxPin", ["striker", "secondStriker", "wideForward"], "Block read: pin box line");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Block read: cutback edge");
    assign("farPost", ["wideForward", "striker", "secondStriker"], "Block read: far-post occupation", -sideSign);
  }

  if (block.nearBallPressure >= 0.5 && block.ballSideCompression < 0.46) {
    assign("bounceUnder", ["pivot", "connector", "wideBack"], "Block read: secure pressure escape");
  }

  assign("restLock", ["pivot", "rest"], "Block read: rest-defence balance");

  return uniquePrincipleLabels(labels);
}

function getGameSpaceOffBallTarget(teamId, ballPoint, slot, sideSign = 1, profile = {}, gameSpace = null) {
  const sign = getAttackDirectionSign(teamId);
  const depth = getAttackingDepth(ballPoint, teamId);
  const lineDepths = gameSpace?.lineDepths ?? getAttackingGameSpaceProfile(ballPoint, teamId).lineDepths;
  const nextLine = gameSpace?.nextLineDepth ?? lineDepths.midfield;
  const backLine = lineDepths.back ?? clamp(depth + 20, 52, 84);
  const spaceTwoDepth = clamp((lineDepths.midfield + lineDepths.back) / 2, 42, 82);
  const runnerBoost = profile.runnerBoost ?? 6;
  const width = profile.width ?? 58;
  const spaceThreeDepth = clamp(backLine + 7.5 + runnerBoost * 0.35, 56, 98);
  const nearHalfY = clamp(lerp(ballPoint.y, pitch.width / 2 + sideSign * 12.5, 0.5), 8, pitch.width - 8);
  const farHalfY = clamp(pitch.width / 2 - sideSign * 12.5, 8, pitch.width - 8);
  const farWideY = clamp(pitch.width / 2 - sideSign * clamp(width * 0.48, 24, 31), 3.5, pitch.width - 3.5);
  const points = {
    outletUnder: getDepthPoint(teamId, clamp(depth - 9 - profile.shortSupport * 5, 16, 68), {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 4.8, 0.42), 10, pitch.width - 10),
    }),
    spaceOneLink: getDepthPoint(teamId, clamp(Math.max(depth + 4, lineDepths.forward + 3), 24, 58), {
      y: clamp(lerp(ballPoint.y, nearHalfY, 0.5), 8, pitch.width - 8),
    }),
    spaceTwoPocket: getDepthPoint(teamId, clamp(spaceTwoDepth, Math.max(38, depth + 2), 84), {
      y: nearHalfY,
    }),
    farSpaceTwoPocket: getDepthPoint(teamId, clamp(spaceTwoDepth + profile.switchBias * 2.2, 42, 84), {
      y: farHalfY,
    }),
    spaceThreeRun: getDepthPoint(teamId, spaceThreeDepth, {
      y: clamp(lerp(ballPoint.y, pitch.width / 2 - sideSign * 7.5, 0.45), 10, pitch.width - 10),
    }),
    wideStretch: getDepthPoint(teamId, clamp(Math.max(depth + 2, nextLine - 2), 34, 90), {
      y: clamp(pitch.width / 2 + sideSign * clamp(width * 0.48, 24, 31), 3.5, pitch.width - 3.5),
    }),
    weakSideHold: getDepthPoint(teamId, clamp(depth + 3 + profile.switchBias * 5, 34, 88), {
      y: farWideY,
    }),
    boxArrive: getDepthPoint(teamId, clamp(87 + profile.directness * 6, 84, 98), {
      y: clamp(pitch.width / 2 + sideSign * 7.5, 13, pitch.width - 13),
    }),
    cutbackEdge: getDepthPoint(teamId, clamp(73 + profile.shortSupport * 5, 70, 82), {
      y: clamp(pitch.width / 2 - sideSign * 6.2, 15, pitch.width - 15),
    }),
    restLock: clampToPitch({
      x: ballPoint.x - sign * (19 + (profile.restBehind ?? 22) * 0.18),
      y: clamp(lerp(ballPoint.y, pitch.width / 2, 0.76), 14, pitch.width - 14),
    }, 3),
    farRestCover: clampToPitch({
      x: ballPoint.x - sign * (24 + (profile.restBehind ?? 22) * 0.16),
      y: clamp(pitch.width / 2 - sideSign * 10.5, 12, pitch.width - 12),
    }, 3),
  };

  return points[slot] ?? points.outletUnder;
}

function applyGameSpaceOffBallPrincipleTargets(teamId, targets, ballPoint, actionMeta, profile, excludedIds) {
  if (profile.phaseKey === "setPiece" || !ballPoint) {
    return [];
  }

  const labels = [];
  const localExcluded = new Set(excludedIds);
  const gameSpace = getAttackingGameSpaceProfile(ballPoint, teamId);
  const targetThreat = getPitchThreatProfile(ballPoint, teamId);
  const sideSign = getWideSideSign(ballPoint) || 1;
  const directStyle = profile.directness >= 0.62 || isTransitionAttackStyle(profile.styleKey);
  const combinationStyle = profile.shortSupport >= 0.62 || profile.tempo >= 0.62;
  const wideStyle = profile.crossBias >= 0.58 || profile.overlapBias >= 0.58 || profile.widthDiscipline >= 0.66;
  const assign = (slot, roleKeys, label, preferredSide = 0) => {
    const player = preferredSide
      ? getMovableAutopilotPlayerByRolesOnSide(teamId, roleKeys, targets, localExcluded, preferredSide, ballPoint)
      : getMovableAutopilotPlayerByRoles(teamId, roleKeys, targets, localExcluded, ballPoint);

    if (!setAutopilotPrincipleTarget(
      targets,
      player,
      getGameSpaceOffBallTarget(teamId, ballPoint, slot, sideSign, profile, gameSpace)
    )) {
      return null;
    }

    localExcluded.add(player.id);
    excludedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (gameSpace.key === "outlet" || gameSpace.key === "space1") {
    assign("outletUnder", ["pivot", "connector", "wideBack"], "Spelyta: secure support");
    assign("spaceOneLink", ["connector", "pivot"], "Spelyta: link behind first line");

    if (combinationStyle) {
      assign("spaceTwoPocket", ["connector", "wideForward", "secondStriker"], "Spelyta: prepare space 2");
    }

    if (wideStyle) {
      assign("wideStretch", ["wideForward", "wideBack"], "Spelyta: hold width", sideSign);
      assign("weakSideHold", ["wideForward", "wideBack"], "Spelyta: weak-side width", -sideSign);
    }

    if (directStyle || profile.lineBreakBias >= 0.58) {
      assign("spaceThreeRun", ["striker", "wideForward", "secondStriker"], "Spelyta: threaten space 3");
    }
  }

  if (gameSpace.key === "space2") {
    assign("outletUnder", ["pivot", "connector", "wideBack"], "Spelyta: bounce support");
    assign("farSpaceTwoPocket", ["connector", "wideForward", "secondStriker"], "Spelyta: far pocket");
    assign("spaceThreeRun", ["striker", "wideForward", "secondStriker"], "Spelyta: run beyond");

    if (wideStyle || isWidePrincipleZone(ballPoint)) {
      assign("wideStretch", ["wideForward", "wideBack"], "Spelyta: outside option", sideSign);
      assign("weakSideHold", ["wideForward", "wideBack"], "Spelyta: switch outlet", -sideSign);
    }
  }

  if (gameSpace.key === "space3" || targetThreat.box >= 0.28 || targetThreat.cutbackZone >= 0.28) {
    assign("boxArrive", ["striker", "secondStriker", "wideForward"], "Spelyta: attack box");
    assign("cutbackEdge", ["connector", "pivot", "wideForward"], "Spelyta: cutback edge");
    assign("weakSideHold", ["wideForward", "wideBack"], "Spelyta: far-post width", -sideSign);
  }

  assign("restLock", ["pivot", "rest"], "Spelyta: rest-defence lock");
  if (getAttackingDepth(ballPoint, teamId) >= 46 || actionMeta?.actionType === "dribble") {
    assign("farRestCover", ["rest", "pivot", "wideBack"], "Spelyta: far rest cover", -sideSign);
  }

  return uniquePrincipleLabels(labels);
}

function buildOffensiveAutopilotTargets(teamId, ballPoint) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const phaseKey = getOffensivePhaseKey(teamId, ballPoint);
  const profile = getOffensiveAutopilotProfile(teamId, ballPoint, phaseKey);
  const roster = teamRosterOrder[teamId] ?? [];
  const basePositions = getFormationPositions(formation, teamId);
  const baseYById = new Map(
    roster.map((playerId, index) => [playerId, basePositions[index]?.y ?? pitch.width / 2])
  );
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    carrierPlayerId: state.ball.carrierPlayerId,
    receiverPlayerId: state.ball.receiverPlayerId,
    beforeSnapshot: {
      ball: {
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const targets = new Map();

  state.players
    .filter((player) => player.team === teamId && !shouldSkipOffensiveAutopilotPlayer(player, actionMeta))
    .forEach((player) => {
      targets.set(
        player.id,
        getOffensiveAutopilotTarget(
          player,
          ballPoint,
          actionMeta,
          profile,
          baseYById.get(player.id) ?? player.position.y
        )
      );
    });

  let runner = chooseOffensiveAutopilotRunner(teamId, targets, actionMeta, ballPoint, profile);
  if (runner) {
    targets.set(
      runner.id,
      getOffensiveAutopilotTarget(
        runner,
        ballPoint,
        actionMeta,
        profile,
        baseYById.get(runner.id) ?? runner.position.y,
        true
      )
    );
  }

  enforceOffensiveOccupationZones(teamId, targets, ballPoint, profile);
  enforceOffensiveTargetSpacing(teamId, targets, ballPoint, profile);
  const principle = getOffensiveActionPrinciple(teamId, ballPoint, actionMeta, profile);
  if (principle?.runner) {
    runner = principle.runner;
    targets.set(principle.runner.id, principle.runnerTarget);
  }
  const supportPrinciple = applyGenerativePrincipleSupportTargets(teamId, targets, ballPoint, actionMeta, profile);
  const coreProtectedIds = new Set([
    actionMeta?.carrierPlayerId,
    actionMeta?.receiverPlayerId,
    actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
    state.ball.initiatorPlayerId,
    state.ball.receiverPlayerId,
    principle?.runner?.id,
    ...(supportPrinciple.protectedIds ?? []),
  ].filter(Boolean));
  const structureBalanceLabels = enforceOffensiveStructureBalance(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    coreProtectedIds
  );
  const fiveLaneLabels = enforceOffensiveFiveLaneOccupation(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    coreProtectedIds
  );
  const ballNearTriangleLabels = applyBallNearSupportTriangleTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    coreProtectedIds
  );
  const looseBallRecoverySupport = applyLooseBallRecoverySupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
    ])
  );
  const postRecoveryAttackSupport = applyPostRecoveryAttackSupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
    ])
  );
  const restDefenceNet = applyOffensiveRestDefenceNetTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
    ])
  );
  const escapeSupport = applyPressResistanceEscapeSupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
    ])
  );
  const escapeContinuation = applyPressEscapeContinuationTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
    ])
  );
  const switchLandingAttack = applySwitchLandingAttackTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
    ])
  );
  enforceOffensiveOccupationZones(teamId, targets, ballPoint, profile);
  enforceOffensiveTargetSpacing(teamId, targets, ballPoint, profile);
  const blindsideChannelRuns = applyBlindsideChannelRunTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
    ])
  );
  const passerContinuation = applyPasserContinuationTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile
  );
  const thirdManChainSupport = applyThirdManChainSupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
    ])
  );
  const spaceTwoForwardFacing = applySpaceTwoForwardFacingTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
    ])
  );
  const spaceTwoContinuation = applySpaceTwoContinuationTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
    ])
  );
  const passingGeometry = applyOffensivePassingGeometryTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
      ...(spaceTwoContinuation.protectedIds ?? []),
    ])
  );
  const boxOccupationChain = applyAttackingBoxOccupationChainTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
      ...(spaceTwoContinuation.protectedIds ?? []),
      ...(passingGeometry.protectedIds ?? []),
    ])
  );
  const timedBoxArrivals = applyTimedFinalThirdBoxArrivals(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
      ...(spaceTwoContinuation.protectedIds ?? []),
      ...(passingGeometry.protectedIds ?? []),
    ])
  );
  const localSuperioritySupport = applyLocalSuperioritySupportTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
      ...(spaceTwoContinuation.protectedIds ?? []),
      ...(passingGeometry.protectedIds ?? []),
      ...(boxOccupationChain.protectedIds ?? []),
      ...(timedBoxArrivals.protectedIds ?? []),
    ])
  );
  const secondBallAnticipation = applyOffensiveSecondBallAnticipationTargets(
    teamId,
    targets,
    ballPoint,
    actionMeta,
    profile,
    new Set([
      ...coreProtectedIds,
      ...(looseBallRecoverySupport.protectedIds ?? []),
      ...(postRecoveryAttackSupport.protectedIds ?? []),
      ...(restDefenceNet.protectedIds ?? []),
      ...(escapeSupport.protectedIds ?? []),
      ...(escapeContinuation.protectedIds ?? []),
      ...(switchLandingAttack.protectedIds ?? []),
      ...(blindsideChannelRuns.protectedIds ?? []),
      ...(passerContinuation.protectedIds ?? []),
      ...(thirdManChainSupport.protectedIds ?? []),
      ...(spaceTwoForwardFacing.protectedIds ?? []),
      ...(spaceTwoContinuation.protectedIds ?? []),
      ...(passingGeometry.protectedIds ?? []),
      ...(boxOccupationChain.protectedIds ?? []),
      ...(timedBoxArrivals.protectedIds ?? []),
      ...(localSuperioritySupport.protectedIds ?? []),
    ])
  );
  const finalProtectedIds = new Set([
    ...coreProtectedIds,
    ...(escapeSupport.protectedIds ?? []),
    ...(looseBallRecoverySupport.protectedIds ?? []),
    ...(postRecoveryAttackSupport.protectedIds ?? []),
    ...(restDefenceNet.protectedIds ?? []),
    ...(escapeContinuation.protectedIds ?? []),
    ...(switchLandingAttack.protectedIds ?? []),
    ...(blindsideChannelRuns.protectedIds ?? []),
    ...(passerContinuation.protectedIds ?? []),
    ...(thirdManChainSupport.protectedIds ?? []),
    ...(spaceTwoForwardFacing.protectedIds ?? []),
    ...(spaceTwoContinuation.protectedIds ?? []),
    ...(passingGeometry.protectedIds ?? []),
    ...(boxOccupationChain.protectedIds ?? []),
    ...(timedBoxArrivals.protectedIds ?? []),
    ...(localSuperioritySupport.protectedIds ?? []),
    ...(secondBallAnticipation.protectedIds ?? []),
  ]);
  const onsideLineLabels = enforceOffensiveOnsideLineAwareness(
    teamId,
    targets,
    ballPoint,
    profile,
    new Set([
      actionMeta?.carrierPlayerId,
      actionMeta?.receiverPlayerId,
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
      state.ball.initiatorPlayerId,
      state.ball.receiverPlayerId,
    ].filter(Boolean))
  );
  enforceOffensiveTargetSpacing(teamId, targets, ballPoint, profile, finalProtectedIds);
  const principleLabels = uniquePrincipleLabels([
    principle?.label,
    ...(supportPrinciple.labels ?? []),
    ...(structureBalanceLabels ?? []),
    ...(fiveLaneLabels ?? []),
    ...(ballNearTriangleLabels ?? []),
    ...(looseBallRecoverySupport.labels ?? []),
    ...(postRecoveryAttackSupport.labels ?? []),
    ...(restDefenceNet.labels ?? []),
    ...(escapeSupport.labels ?? []),
    ...(escapeContinuation.labels ?? []),
    ...(switchLandingAttack.labels ?? []),
    ...(blindsideChannelRuns.labels ?? []),
    ...(passerContinuation.labels ?? []),
    ...(thirdManChainSupport.labels ?? []),
    ...(spaceTwoForwardFacing.labels ?? []),
    ...(spaceTwoContinuation.labels ?? []),
    ...(passingGeometry.labels ?? []),
    ...(boxOccupationChain.labels ?? []),
    ...(timedBoxArrivals.labels ?? []),
    ...(localSuperioritySupport.labels ?? []),
    ...(secondBallAnticipation.labels ?? []),
    ...(onsideLineLabels ?? []),
  ]);
  const resolvedPrinciple = principleLabels.length
    ? {
        ...(principle ?? {}),
        key: principle?.key ?? "generative-principle-chain",
        label: principleLabels.join("; "),
      }
    : principle;
  applyAutopilotTargetVariation(
    teamId,
    targets,
    profile,
    "attack",
    new Set([
      actionMeta?.carrierPlayerId,
      actionMeta?.receiverPlayerId,
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
      state.ball.initiatorPlayerId,
      state.ball.receiverPlayerId,
      ...finalProtectedIds,
    ].filter(Boolean))
  );
  enforceOffensiveOnsideLineAwareness(
    teamId,
    targets,
    ballPoint,
    profile,
    new Set([
      actionMeta?.carrierPlayerId,
      actionMeta?.receiverPlayerId,
      actionMeta?.beforeSnapshot?.ball?.ownerPlayerId,
      state.ball.initiatorPlayerId,
      state.ball.receiverPlayerId,
    ].filter(Boolean))
  );
  enforceOffensiveTargetSpacing(teamId, targets, ballPoint, profile, finalProtectedIds);

  return {
    targets,
    runner,
    profile,
    principle: resolvedPrinciple,
  };
}

function getDefensivePhaseKey(teamId, ballPoint, actionType = state.ball.actionType ?? state.draftStep?.actionType) {
  if (state.restartPhase?.type) {
    if (state.restartPhase.type === "kickoff") {
      return getKickoffDefensivePhaseKey(teamId);
    }

    return "setPiece";
  }

  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, ballPoint);
  const wideRatio = Math.abs(ballPoint.y - pitch.width / 2) / (pitch.width / 2);
  const styleProfile = getTeamDefenseStyleProfile(teamId);

  if (
    ballFromOwnGoal <= 22 ||
    (actionType === "shot" && ballFromOwnGoal <= 34) ||
    (ballFromOwnGoal <= 27 && wideRatio > 0.62)
  ) {
    return "boxDefending";
  }

  if (ballFromOwnGoal <= 36) {
    return "lowBlock";
  }

  if (styleProfile.preferredPhase === "lowBlock" && ballFromOwnGoal <= 52) {
    return "lowBlock";
  }

  if (styleProfile.preferredPhase === "boxDefending" && ballFromOwnGoal <= 46) {
    return ballFromOwnGoal <= 30 ? "boxDefending" : "lowBlock";
  }

  if (
    ballFromOwnGoal >= 67 ||
    (styleProfile.preferredPhase === "highPress" && ballFromOwnGoal >= 52)
  ) {
    return "highPress";
  }

  return "midBlock";
}

function getDefensiveAutopilotLineKey(
  player,
  formation = teams[player.team]?.formation,
  phaseKey = "midBlock"
) {
  const label = getPlayerMagnetLabel(player);
  const isHighPress = phaseKey === "highPress";
  const isDeepDefending = phaseKey === "lowBlock" || phaseKey === "boxDefending";

  if (label === "GK") {
    return "gk";
  }

  if (label === "CB" || label === "LB" || label === "RB") {
    return "back";
  }

  if (label === "WB") {
    return isDeepDefending ? "back" : "midfield";
  }

  if (formation === "4-4-2") {
    return label === "9" || label === "10" ? "forward" : "midfield";
  }

  if (formation === "4-1-4-1" || formation === "4-2-3-1") {
    if (formation === "4-2-3-1") {
      if (isHighPress) {
        return label === "9" || label === "10" || label === "W" ? "forward" : "midfield";
      }

      if (phaseKey === "boxDefending") {
        return label === "9" ? "forward" : "midfield";
      }

      return label === "9" || label === "10" ? "forward" : "midfield";
    }

    return label === "9" ? "forward" : "midfield";
  }

  if (formation === "3-4-3") {
    if (isDeepDefending && label === "W") {
      return "midfield";
    }

    return label === "9" || label === "W" ? "forward" : "midfield";
  }

  if (formation === "3-5-2") {
    return label === "9" ? "forward" : "midfield";
  }

  if (formation === "4-3-3") {
    if (isHighPress && (label === "9" || label === "W")) {
      return "forward";
    }

    return label === "9" ? "forward" : "midfield";
  }

  if (label === "9" || (isHighPress && label === "W")) {
    return "forward";
  }

  return "midfield";
}

function getDefensiveAutopilotProfile(teamId, ballPoint = state.ball.target ?? state.ball.position, phaseKey = null) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const formationProfile = defensiveAutopilotProfiles[formation] ?? defensiveAutopilotProfiles["4-3-3"];
  const referenceProfile = defensiveAutopilotProfiles["4-3-3"];
  const resolvedPhaseKey = phaseKey ?? getDefensivePhaseKey(teamId, ballPoint);
  const phaseProfile = defensivePhaseProfiles[resolvedPhaseKey] ?? defensivePhaseProfiles.midBlock;
  const styleKey = getTeamDefenseStyleKey(teamId);
  const styleProfile = getTeamDefenseStyleProfile(teamId);
  const threatResponse = getDefensiveThreatResponse(teamId, ballPoint);
  const lineActionAdjustment = getDefensiveLineActionAdjustment(teamId, ballPoint, resolvedPhaseKey);
  const gapWeight = phaseProfile.formationGapWeight ?? 0.4;
  const widthWeight = phaseProfile.formationWidthWeight ?? 0.45;

  return {
    ...phaseProfile,
    formation,
    phaseKey: resolvedPhaseKey,
    phaseLabel: phaseProfile.label,
    styleKey,
    styleLabel: styleProfile.label,
    stylePrincipleLabel: styleProfile.principleLabel,
    threatResponse,
    lineActionAdjustment,
    pressingIntensity: styleProfile.pressingIntensity,
    tackleIntent: styleProfile.tackleIntent,
    blockWidth: clamp(
      (phaseProfile.blockWidth + (formationProfile.blockWidth - referenceProfile.blockWidth) * widthWeight) *
        styleProfile.blockWidthMultiplier,
      phaseProfile.minBlockWidth,
      phaseProfile.maxBlockWidth
    ),
    ballSideShift: clamp(
      phaseProfile.ballSideShift +
        (formationProfile.ballSideShift - referenceProfile.ballSideShift) * 0.45 +
        styleProfile.ballSideShiftOffset,
      0.36,
      0.82
    ),
    wideCompression: clamp(
      phaseProfile.wideCompression +
        (formationProfile.wideCompression - referenceProfile.wideCompression) * 0.35,
      0.7,
      0.92
    ),
    backToBall: clamp(
      phaseProfile.backToBall +
        (formationProfile.backToBall - referenceProfile.backToBall) * gapWeight +
        styleProfile.backToBallOffset,
      5,
      30
    ),
    backToMidfield: clamp(
      phaseProfile.backToMidfield +
        (formationProfile.backToMidfield - referenceProfile.backToMidfield) * gapWeight +
        styleProfile.lineGapOffset,
      4.5,
      12.5
    ),
    midfieldToForward: clamp(
      phaseProfile.midfieldToForward +
        (formationProfile.midfieldToForward - referenceProfile.midfieldToForward) * gapWeight +
        styleProfile.lineGapOffset,
      4.5,
      12.5
    ),
    pressOffset: clamp(
      (phaseProfile.pressOffset + (formationProfile.pressOffset - referenceProfile.pressOffset) * 0.35) *
        styleProfile.pressOffsetMultiplier,
      0.55,
      2.7
    ),
    maxBackLineFromOwnGoal: clamp(
      phaseProfile.maxBackLineFromOwnGoal +
        (formationProfile.maxBackLineFromOwnGoal - referenceProfile.maxBackLineFromOwnGoal) * 0.35 +
        styleProfile.lineHeightOffset,
      phaseProfile.minBackLineFromOwnGoal + 3,
      pitch.length - 8
    ),
    minBackLineFromOwnGoal: clamp(
      (phaseProfile.minBackLineFromOwnGoal ?? 9) + styleProfile.lineHeightOffset,
      7,
      pitch.length - 22
    ),
  };
}

function getDefensiveLineActionAdjustment(teamId, ballPoint, phaseKey = "midBlock") {
  if (state.restartPhase?.type || !ballPoint) {
    return {
      mode: "hold",
      shift: 0,
      heightDelta: 0,
      label: null,
    };
  }

  const attackingTeamId = getOtherTeamId(teamId);
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;

  if (!attackingTeamId || !actionType || !startPoint || !targetPoint) {
    return {
      mode: "hold",
      shift: 0,
      heightDelta: 0,
      label: null,
    };
  }

  const carrier = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      actionMeta.carrierPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const passDistance = distance(startPoint, targetPoint);
  const startThreat = getPitchThreatProfile(startPoint, attackingTeamId);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const targetSpace = getAttackingGameSpaceProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const carrierPressure = carrier ? getPlayerPressureLoad(carrier, startPoint) : 0.5;
  const targetFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const startFromOwnGoal = getDistanceFromOwnGoal(teamId, startPoint);
  const isHighPress = phaseKey === "highPress";
  const isLowBlock = phaseKey === "lowBlock";
  const isBoxDefending = phaseKey === "boxDefending";
  const depthThreat =
    actionType === "pass" &&
    (
      targetSpace.key === "space3" ||
      targetThreat.behindLine >= 0.24 ||
      actionSpace.lineBreakCount >= 1 ||
      (forwardGain >= 9 && passDistance >= 13 && targetThreat.value >= startThreat.value + 0.03) ||
      (targetFromOwnGoal <= 31 && forwardGain >= 5)
    );
  const carryThreat =
    actionType === "dribble" &&
    (
      targetThreat.behindLine >= 0.2 ||
      targetThreat.centralPocket >= 0.26 ||
      targetFromOwnGoal <= 42 ||
      (forwardGain >= 7 && actionSpace.value >= 0.3)
    );
  const backwardPass =
    actionType === "pass" &&
    forwardGain <= -4 &&
    targetFromOwnGoal >= startFromOwnGoal + 1.2;
  const lowRiskBackwardPass =
    backwardPass &&
    targetThreat.value <= startThreat.value + 0.04 &&
    targetThreat.behindLine < 0.16 &&
    carrierPressure >= 0.28;

  if (depthThreat) {
    const dropShift =
      isBoxDefending
        ? -1.2
        : isLowBlock
          ? -2.4
          : isHighPress
            ? -5.2
            : -3.6;

    return {
      mode: "drop",
      shift: dropShift,
      heightDelta: isHighPress ? -1.2 : -0.8,
      label: "Back line drops with depth threat",
      forwardGain,
      targetSpaceKey: targetSpace.key,
      lineBreakCount: actionSpace.lineBreakCount,
    };
  }

  if (carryThreat) {
    const carryDrop =
      isBoxDefending
        ? -0.8
        : isLowBlock
          ? -1.6
          : isHighPress
            ? -3.4
            : -2.4;

    return {
      mode: "delayDrop",
      shift: carryDrop,
      heightDelta: isHighPress ? -0.8 : -0.4,
      label: "Back line delays and drops",
      forwardGain,
      targetSpaceKey: targetSpace.key,
      lineBreakCount: actionSpace.lineBreakCount,
    };
  }

  if (lowRiskBackwardPass) {
    const stepShift =
      isBoxDefending
        ? 0.6
        : isLowBlock
          ? 1.8
          : isHighPress
            ? 4.2
            : 2.8;

    return {
      mode: "step",
      shift: stepShift,
      heightDelta: isLowBlock ? 0 : 0.6,
      label: "Back line steps on backward pass",
      forwardGain,
      targetSpaceKey: targetSpace.key,
      lineBreakCount: actionSpace.lineBreakCount,
    };
  }

  return {
    mode: "hold",
    shift: 0,
    heightDelta: 0,
    label: null,
    forwardGain,
    targetSpaceKey: targetSpace.key,
    lineBreakCount: actionSpace.lineBreakCount,
  };
}

function getDefensiveLineDistanceFromOwnGoal(teamId, lineKey, ballPoint, profile) {
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, ballPoint);
  const lineShift = profile.lineActionAdjustment?.shift ?? 0;
  const backLine = clamp(
    ballFromOwnGoal - profile.backToBall + lineShift,
    profile.minBackLineFromOwnGoal ?? 9,
    profile.maxBackLineFromOwnGoal
  );
  const targetBlockHeight = profile.targetBlockHeight
    ? clamp(
        profile.targetBlockHeight + (profile.lineActionAdjustment?.heightDelta ?? 0),
        profile.phaseKey === "boxDefending" ? 14 : 22,
        profile.phaseKey === "boxDefending" ? 19 : 28
      )
    : null;

  if (targetBlockHeight && lineKey !== "gk") {
    const backToMidfield = clamp(
      profile.targetBackToMidfield ?? profile.backToMidfield,
      profile.phaseKey === "boxDefending" ? 6 : 8,
      Math.max(8, targetBlockHeight - 6)
    );
    const midfieldLine = clamp(
      backLine + backToMidfield,
      backLine + 5.5,
      Math.min(backLine + targetBlockHeight - 4.5, pitch.length - 10)
    );
    const forwardLine = clamp(
      backLine + targetBlockHeight,
      midfieldLine + 5,
      Math.min(
        Math.max(
          ballFromOwnGoal + (profile.forwardAheadOfBall ?? 8),
          backLine + targetBlockHeight
        ),
        pitch.length - 8
      )
    );

    if (lineKey === "back") {
      return backLine;
    }

    if (lineKey === "forward") {
      return forwardLine;
    }

    return midfieldLine;
  }

  const midfieldMinimum = Math.max(
    (profile.minBackLineFromOwnGoal ?? 9) + profile.backToMidfield,
    12
  );
  const forwardMinimum = midfieldMinimum + profile.midfieldToForward * 0.8;
  const midfieldCap = Math.max(
    midfieldMinimum,
    Math.min(ballFromOwnGoal + (profile.midfieldAheadOfBall ?? 3), 72)
  );
  const forwardCap = Math.max(
    forwardMinimum,
    Math.min(ballFromOwnGoal + (profile.forwardAheadOfBall ?? 8), 86)
  );
  const midfieldLine = clamp(
    backLine + profile.backToMidfield,
    midfieldMinimum,
    midfieldCap
  );
  const forwardLine = clamp(
    midfieldLine + profile.midfieldToForward,
    forwardMinimum,
    forwardCap
  );

  if (lineKey === "gk") {
    return clamp(
      (profile.gkDepthMin ?? 6.5) +
        Math.max(0, ballFromOwnGoal - (profile.gkSweepStart ?? 35)) *
          (profile.gkSweepFactor ?? 0.08),
      profile.gkDepthMin ?? 6.5,
      profile.gkDepthMax ?? 11
    );
  }

  if (lineKey === "back") {
    return backLine;
  }

  if (lineKey === "forward") {
    return forwardLine;
  }

  return midfieldLine;
}

function getDefensiveLineX(teamId, lineKey, ballPoint, profile) {
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const lineFromOwnGoal = getDefensiveLineDistanceFromOwnGoal(
    teamId,
    lineKey,
    ballPoint,
    profile
  );
  return ownGoalX + getDefendingDirectionSign(teamId) * lineFromOwnGoal;
}

function getDefensiveLineWidth(lineKey, profile, ballPoint, playerCount = 1) {
  if (lineKey === "gk" || playerCount <= 1) {
    return 0;
  }

  if (profile.unitPlayerGap) {
    const gapValue =
      typeof profile.unitPlayerGap === "number"
        ? profile.unitPlayerGap
        : profile.unitPlayerGap?.[lineKey] ?? 8;
    return gapValue * (playerCount - 1);
  }

  const wideRatio = Math.abs(ballPoint.y - pitch.width / 2) / (pitch.width / 2);
  const dangerCompression =
    1 -
    (profile.threatResponse?.protectCenter ?? 0) *
      (lineKey === "forward" ? 0.04 : lineKey === "midfield" ? 0.1 : 0.14);
  const baseWidth = profile.blockWidth * lerp(1, profile.wideCompression, wideRatio) * dangerCompression;
  const lineRatio =
    profile.lineWidthRatio?.[lineKey] ??
    (lineKey === "forward" ? 0.68 : lineKey === "midfield" ? 0.9 : 1);
  const gap = profile.playerGap?.[lineKey] ?? { min: 7, max: 12 };
  const segmentCount = playerCount - 1;
  const minimumWidth = gap.min * segmentCount;
  const maximumWidth = gap.max * segmentCount;
  const shapeWidth = baseWidth * lineRatio;

  return clamp(shapeWidth, minimumWidth, maximumWidth);
}

function getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth) {
  const lineShift = lineKey === "forward" ? 1.12 : lineKey === "midfield" ? 1 : 0.86;
  const centerProtection = profile.threatResponse?.protectCenter ?? 0;
  const shiftReduction = 1 - centerProtection * (lineKey === "forward" ? 0.22 : lineKey === "midfield" ? 0.42 : 0.52);
  const centerY = pitch.width / 2 + (ballPoint.y - pitch.width / 2) * profile.ballSideShift * lineShift * shiftReduction;
  const margin = Math.max(4, lineWidth / 2 + 3);

  return clamp(centerY, margin, pitch.width - margin);
}

function enforceDefensiveUnitCompactness(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const compactnessWeight =
    profile.unitCompactnessWeight ??
    (profile.phaseKey === "lowBlock" ? 0.7 : profile.phaseKey === "boxDefending" ? 0.76 : 0.42);

  if (compactnessWeight <= 0) {
    return [];
  }

  const labels = [];

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? []).filter((player) => !isGoalkeeper(player));
    if (!players.length) {
      return;
    }

    const lineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const lineWidth = getDefensiveLineWidth(lineKey, profile, ballPoint, players.length);
    const centerY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);

    players.forEach((player, index) => {
      if (protectedIds.has(player.id)) {
        return;
      }

      const spreadRatio = players.length === 1 ? 0.5 : index / (players.length - 1);
      const unitSlot = clampToPitch({
        x: lineX,
        y: clamp(centerY - lineWidth / 2 + lineWidth * spreadRatio, 3, pitch.width - 3),
      }, 2.2);
      const currentTarget = targets.get(player.id) ?? player.position;
      const target = clampToPitch({
        x: lerp(currentTarget.x, unitSlot.x, compactnessWeight),
        y: lerp(currentTarget.y, unitSlot.y, compactnessWeight),
      }, 2.2);

      targets.set(player.id, target);
    });
  });

  if (profile.phaseKey === "lowBlock") {
    labels.push("Low-block unit spacing");
  } else if (profile.phaseKey === "boxDefending") {
    labels.push("Box unit spacing");
  }

  return labels;
}

function getDefensiveUnitGap(profile, lineKey) {
  if (typeof profile.unitPlayerGap === "number") {
    return profile.unitPlayerGap;
  }

  if (profile.unitPlayerGap?.[lineKey]) {
    return profile.unitPlayerGap[lineKey];
  }

  const phaseDefault =
    profile.phaseKey === "boxDefending"
      ? 7.5
      : profile.phaseKey === "lowBlock"
        ? 8
        : 9;
  const gapRange = profile.playerGap?.[lineKey];

  if (!gapRange) {
    return phaseDefault;
  }

  return clamp((gapRange.min + gapRange.max) / 2, gapRange.min, gapRange.max);
}

function enforceDefensiveBlockGeometryLock(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  if (profile.phaseKey !== "lowBlock" && profile.phaseKey !== "boxDefending") {
    return [];
  }

  const labels = [];
  const lockWeight = profile.phaseKey === "boxDefending" ? 0.96 : 0.92;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? []).filter((player) => !isGoalkeeper(player));
    if (!players.length) {
      return;
    }

    const gap = getDefensiveUnitGap(profile, lineKey);
    const lineWidth = gap * Math.max(0, players.length - 1);
    const lineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const centerY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);
    const lineWeight = lineKey === "forward" ? lockWeight * 0.84 : lockWeight;

    players.forEach((player, index) => {
      if (protectedIds.has(player.id)) {
        return;
      }

      const spreadRatio = players.length === 1 ? 0.5 : index / (players.length - 1);
      const slot = clampToPitch({
        x: lineX,
        y: clamp(centerY - lineWidth / 2 + lineWidth * spreadRatio, 3, pitch.width - 3),
      }, 2.2);
      const currentTarget = targets.get(player.id) ?? player.position;

      targets.set(player.id, clampToPitch({
        x: lerp(currentTarget.x, slot.x, lineWeight),
        y: lerp(currentTarget.y, slot.y, lineWeight),
      }, 2.2));
    });
  });

  labels.push(profile.phaseKey === "boxDefending" ? "Box geometry lock" : "Low-block geometry lock");
  return labels;
}

function enforceDefensiveLineStaggering(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  if (!ballPoint || state.restartPhase?.type) {
    return [];
  }

  const labels = [];
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ballSide = getWideSideSign(ballPoint) || 1;
  const phaseDepthScale =
    profile.phaseKey === "boxDefending"
      ? 0.68
      : profile.phaseKey === "lowBlock"
        ? 0.86
        : profile.phaseKey === "highPress"
          ? 1.16
          : 1;
  const actionMode = profile.lineActionAdjustment?.mode ?? "hold";
  const actionDropBoost = actionMode === "drop" || actionMode === "delayDrop" ? 0.8 : 0;
  const actionStepBoost = actionMode === "step" ? 0.7 : 0;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? []).filter((player) => !isGoalkeeper(player));
    const available = players
      .filter((player) => targets.has(player.id) && !protectedIds.has(player.id))
      .map((player) => ({
        player,
        target: cloneVector(targets.get(player.id)),
      }))
      .sort((a, b) => Math.abs(a.target.y - ballPoint.y) - Math.abs(b.target.y - ballPoint.y));

    if (!available.length) {
      return;
    }

    const ballNearId = available[0].player.id;
    const lineDepth = getDefensiveLineDistanceFromOwnGoal(teamId, lineKey, ballPoint, profile);
    const maxCoverDrop =
      lineKey === "back"
        ? (2.6 + actionDropBoost) * phaseDepthScale
        : lineKey === "midfield"
          ? (1.8 + actionDropBoost * 0.5) * phaseDepthScale
          : 1.1 * phaseDepthScale;
    const maxStepOut =
      lineKey === "back"
        ? (1.05 + actionStepBoost) * phaseDepthScale
        : lineKey === "midfield"
          ? (1.55 + actionStepBoost) * phaseDepthScale
          : (1.85 + actionStepBoost) * phaseDepthScale;

    players.forEach((player) => {
      if (protectedIds.has(player.id) || !targets.has(player.id) || isGoalkeeper(player)) {
        return;
      }

      const currentTarget = cloneVector(targets.get(player.id));
      const playerSide = Math.sign(currentTarget.y - pitch.width / 2) || ballSide;
      const lateralGap = Math.abs(currentTarget.y - ballPoint.y);
      const ballNear = player.id === ballNearId;
      const sameSide = playerSide === ballSide;
      const farSide = playerSide === -ballSide;
      const centrality = 1 - Math.abs(currentTarget.y - pitch.width / 2) / (pitch.width / 2);
      let depthAdjustment = 0;
      let yAdjustment = 0;

      if (ballNear) {
        depthAdjustment += maxStepOut;
        yAdjustment += (ballPoint.y - currentTarget.y) * (lineKey === "forward" ? 0.18 : 0.1);
      } else if (sameSide && lateralGap <= 14) {
        depthAdjustment -= maxCoverDrop * 0.5;
        yAdjustment += (ballPoint.y - currentTarget.y) * 0.04;
      } else if (farSide) {
        depthAdjustment -= maxCoverDrop * 0.58;
        yAdjustment += (pitch.width / 2 - currentTarget.y) * (lineKey === "back" ? 0.12 : 0.08);
      } else if (centrality >= 0.62) {
        depthAdjustment -= maxCoverDrop * 0.34;
      }

      if (
        lineKey === "back" &&
        (profile.threatResponse?.isBoxThreat || profile.threatResponse?.isGoldenZoneThreat)
      ) {
        depthAdjustment -= maxCoverDrop * (ballNear ? 0.16 : 0.28);
      }

      const targetDepth = clamp(
        lineDepth + depthAdjustment,
        profile.minBackLineFromOwnGoal ?? 5,
        profile.maxBackLineFromOwnGoal + (lineKey === "forward" ? 22 : lineKey === "midfield" ? 12 : 2)
      );
      const staggeredTarget = clampToPitch({
        x: ownGoal.x + sign * targetDepth,
        y: clamp(currentTarget.y + yAdjustment, 3.2, pitch.width - 3.2),
      }, 2.2);

      targets.set(player.id, staggeredTarget);
    });
  });

  labels.push("Line staggering and cover depth");
  return labels;
}

function enforceDefensiveLineChainSpacing(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  fixedIds = new Set()
) {
  const restartType = state.restartPhase?.type;
  if (!ballPoint || (restartType && restartType !== "kickoff")) {
    return [];
  }

  const labels = [];
  let adjusted = false;
  const phaseWeight =
    profile.phaseKey === "boxDefending"
      ? 0.86
      : profile.phaseKey === "lowBlock"
        ? 0.78
        : profile.phaseKey === "highPress"
          ? 0.46
          : 0.62;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? []).filter((player) => !isGoalkeeper(player) && targets.has(player.id));
    if (players.length < 2) {
      return;
    }

    const baseGap = getDefensiveUnitGap(profile, lineKey);
    const minGap = clamp(
      baseGap - (profile.phaseKey === "boxDefending" ? 1.05 : profile.phaseKey === "highPress" ? 1.55 : 1.25),
      lineKey === "forward" ? 5.8 : 6.2,
      9.4
    );
    const maxGap = clamp(
      baseGap + (profile.phaseKey === "highPress" ? 3.1 : profile.phaseKey === "midBlock" ? 2.5 : 1.8),
      minGap + 1.4,
      lineKey === "forward" ? 14.2 : 12.4
    );
    const lineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const maxLineDrift =
      lineKey === "forward"
        ? (profile.phaseKey === "highPress" ? 11.5 : 8.4)
        : lineKey === "midfield"
          ? (profile.phaseKey === "highPress" ? 8.6 : profile.phaseKey === "midBlock" ? 6.8 : 5.8)
          : (profile.phaseKey === "highPress" ? 7.4 : profile.phaseKey === "midBlock" ? 5.8 : 4.8);
    const entries = players
      .map((player) => ({
        player,
        target: cloneVector(targets.get(player.id)),
      }))
      .sort((a, b) => a.target.y - b.target.y);

    for (let pass = 0; pass < 3; pass += 1) {
      entries.sort((a, b) => a.target.y - b.target.y);
      for (let index = 0; index < entries.length - 1; index += 1) {
        const upper = entries[index];
        const lower = entries[index + 1];

        if (fixedIds.has(upper.player.id) && fixedIds.has(lower.player.id)) {
          continue;
        }

        const gap = lower.target.y - upper.target.y;
        let correction = 0;

        if (gap < minGap) {
          correction = (minGap - gap) / 2;
        } else if (gap > maxGap) {
          correction = -(gap - maxGap) / 2;
        }

        if (Math.abs(correction) < 0.02) {
          continue;
        }

        const upperWeight = fixedIds.has(upper.player.id) ? 0 : phaseWeight;
        const lowerWeight = fixedIds.has(lower.player.id) ? 0 : phaseWeight;
        upper.target.y = clamp(upper.target.y - correction * upperWeight, 3.2, pitch.width - 3.2);
        lower.target.y = clamp(lower.target.y + correction * lowerWeight, 3.2, pitch.width - 3.2);
        adjusted = adjusted || upperWeight > 0 || lowerWeight > 0;
      }
    }

    entries.forEach(({ player, target }) => {
      if (fixedIds.has(player.id)) {
        return;
      }

      const currentTarget = targets.get(player.id) ?? target;
      const xDrift = currentTarget.x - lineX;
      const chainX =
        Math.abs(xDrift) > maxLineDrift
          ? lineX + Math.sign(xDrift) * maxLineDrift
          : currentTarget.x;
      adjusted = adjusted || Math.abs(chainX - currentTarget.x) > 0.04;

      targets.set(player.id, clampToPitch({
        x: lerp(currentTarget.x, chainX, phaseWeight * 0.72),
        y: target.y,
      }, 2.2));
    });
  });

  if (adjusted) {
    labels.push("Defensive chain spacing");
  }
  return labels;
}

function enforceDefensiveVerticalBlockConnections(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  fixedIds = new Set()
) {
  if (!ballPoint || state.restartPhase?.type) {
    return [];
  }

  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const sign = getDefendingDirectionSign(teamId);
  const labels = [];
  let adjusted = false;
  const phaseWeight =
    profile.phaseKey === "boxDefending"
      ? 0.82
      : profile.phaseKey === "lowBlock"
        ? 0.74
        : profile.phaseKey === "highPress"
          ? 0.42
          : 0.56;
  const phaseTolerance = {
    back: profile.phaseKey === "boxDefending" ? 2.2 : profile.phaseKey === "lowBlock" ? 2.8 : profile.phaseKey === "highPress" ? 5.4 : 4.2,
    midfield: profile.phaseKey === "boxDefending" ? 2.8 : profile.phaseKey === "lowBlock" ? 3.5 : profile.phaseKey === "highPress" ? 6.6 : 5.1,
    forward: profile.phaseKey === "boxDefending" ? 4.2 : profile.phaseKey === "lowBlock" ? 5.2 : profile.phaseKey === "highPress" ? 9.2 : 7.4,
  };

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? []).filter((player) => !isGoalkeeper(player) && targets.has(player.id));
    if (!players.length) {
      return;
    }

    const lineDepth = getDefensiveLineDistanceFromOwnGoal(teamId, lineKey, ballPoint, profile);
    const tolerance = phaseTolerance[lineKey] ?? 5;

    players.forEach((player) => {
      if (fixedIds.has(player.id)) {
        return;
      }

      const currentTarget = targets.get(player.id);
      const currentDepth = getDistanceFromOwnGoal(teamId, currentTarget);
      const boundedDepth = lineDepth + clamp(currentDepth - lineDepth, -tolerance, tolerance);
      const nextDepth = lerp(currentDepth, boundedDepth, phaseWeight);

      if (Math.abs(nextDepth - currentDepth) > 0.05) {
        adjusted = true;
      }

      targets.set(player.id, clampToPitch({
        x: ownGoalX + sign * nextDepth,
        y: currentTarget.y,
      }, 2.2));
    });
  });

  if (adjusted) {
    labels.push("Vertical block connection");
  }

  return labels;
}

function enforceDefensiveMeasuredBlockEnvelope(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  hardFixedIds = new Set(),
  softFixedIds = new Set()
) {
  if (!ballPoint || state.restartPhase?.type) {
    return [];
  }

  const phaseSettings = {
    highPress: {
      height: 34,
      backToMidfield: 11.2,
      unitGap: 9.5,
      weight: 0.28,
      label: "High-press block envelope",
    },
    midBlock: {
      height: 30,
      backToMidfield: 10.2,
      unitGap: 9,
      weight: 0.46,
      label: "Mid-block measured envelope",
    },
    lowBlock: {
      height: 26,
      backToMidfield: 10.2,
      unitGap: 8,
      weight: 0.72,
      label: "Low-block measured envelope",
    },
    boxDefending: {
      height: 17,
      backToMidfield: 7.2,
      unitGap: 7.5,
      weight: 0.78,
      label: "Box measured envelope",
    },
  };
  const settings = phaseSettings[profile.phaseKey] ?? phaseSettings.midBlock;
  const sign = getDefendingDirectionSign(teamId);
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const targetHeight = clamp(
    profile.targetBlockHeight ?? settings.height,
    profile.phaseKey === "boxDefending" ? 15 : profile.phaseKey === "lowBlock" ? 24 : 26,
    profile.phaseKey === "boxDefending" ? 19 : profile.phaseKey === "lowBlock" ? 28 : 36
  );
  const backDepth = getDefensiveLineDistanceFromOwnGoal(teamId, "back", ballPoint, profile);
  const backToMidfield = clamp(
    profile.targetBackToMidfield ?? settings.backToMidfield,
    profile.phaseKey === "boxDefending" ? 6.4 : 8,
    Math.max(profile.phaseKey === "boxDefending" ? 8.6 : 12, targetHeight - 5.2)
  );
  const depthByLine = {
    back: backDepth,
    midfield: clamp(backDepth + backToMidfield, backDepth + 5.6, backDepth + targetHeight - 4.8),
    forward: clamp(backDepth + targetHeight, backDepth + backToMidfield + 4.8, pitch.length - 8),
  };
  const labels = [];
  let adjusted = false;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = (groups[lineKey] ?? [])
      .filter((player) => !isGoalkeeper(player) && targets.has(player.id))
      .sort((a, b) => {
        const aY = targets.get(a.id)?.y ?? a.position.y;
        const bY = targets.get(b.id)?.y ?? b.position.y;
        return aY - bY;
      });

    if (!players.length) {
      return;
    }

    const unitGap = clamp(
      getDefensiveUnitGap(profile, lineKey) || settings.unitGap,
      profile.phaseKey === "boxDefending" ? 7 : profile.phaseKey === "lowBlock" ? 7.6 : 8,
      profile.phaseKey === "boxDefending" ? 8.2 : profile.phaseKey === "lowBlock" ? 8.6 : 10.8
    );
    const lineWidth = unitGap * Math.max(0, players.length - 1);
    const centerY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);
    const lineX = ownGoalX + sign * depthByLine[lineKey];
    const lineWeight =
      lineKey === "forward"
        ? settings.weight * (profile.phaseKey === "highPress" ? 0.72 : 0.82)
        : settings.weight;

    players.forEach((player, index) => {
      if (hardFixedIds.has(player.id)) {
        return;
      }

      const spreadRatio = players.length === 1 ? 0.5 : index / (players.length - 1);
      const measuredSlot = clampToPitch({
        x: lineX,
        y: clamp(centerY - lineWidth / 2 + lineWidth * spreadRatio, 3.1, pitch.width - 3.1),
      }, 2.2);
      const currentTarget = targets.get(player.id) ?? player.position;
      const weight = softFixedIds.has(player.id) ? lineWeight * 0.42 : lineWeight;
      const nextTarget = clampToPitch({
        x: lerp(currentTarget.x, measuredSlot.x, weight),
        y: lerp(currentTarget.y, measuredSlot.y, weight),
      }, 2.2);

      if (distance(currentTarget, nextTarget) > 0.08) {
        adjusted = true;
      }

      targets.set(player.id, nextTarget);
    });
  });

  if (adjusted) {
    labels.push(settings.label);
  }

  return labels;
}

function enforceDefensiveCollectiveShiftCohesion(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  hardFixedIds = new Set(),
  softFixedIds = new Set()
) {
  if (!ballPoint || state.restartPhase?.type) {
    return [];
  }

  const phaseSettings = {
    highPress: {
      centerWeight: 0.28,
      depthWeight: 0.22,
      widthWeight: 0.3,
      label: "High-press collective shift",
    },
    midBlock: {
      centerWeight: 0.38,
      depthWeight: 0.32,
      widthWeight: 0.42,
      label: "Mid-block collective shift",
    },
    lowBlock: {
      centerWeight: 0.56,
      depthWeight: 0.5,
      widthWeight: 0.68,
      label: "Low-block collective shift",
    },
    boxDefending: {
      centerWeight: 0.62,
      depthWeight: 0.54,
      widthWeight: 0.72,
      label: "Box collective shift",
    },
  };
  const settings = phaseSettings[profile.phaseKey] ?? phaseSettings.midBlock;
  const labels = [];
  let adjusted = false;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const entries = (groups[lineKey] ?? [])
      .filter((player) => !isGoalkeeper(player) && targets.has(player.id))
      .map((player) => ({
        player,
        target: cloneVector(targets.get(player.id)),
      }))
      .sort((a, b) => a.target.y - b.target.y);

    if (!entries.length) {
      return;
    }

    const desiredGap = clamp(
      getDefensiveUnitGap(profile, lineKey),
      profile.phaseKey === "boxDefending" ? 7 : profile.phaseKey === "lowBlock" ? 7.6 : 8,
      profile.phaseKey === "boxDefending" ? 8.2 : profile.phaseKey === "lowBlock" ? 8.8 : 10.8
    );
    const desiredWidth = desiredGap * Math.max(0, entries.length - 1);
    const desiredCenterY = getDefensiveLineCenterY(lineKey, profile, ballPoint, desiredWidth);
    const desiredLineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const yValues = entries.map((entry) => entry.target.y);
    const actualCenterY = yValues.length
      ? yValues.reduce((total, value) => total + value, 0) / yValues.length
      : desiredCenterY;
    const actualWidth = Math.max(0.1, Math.max(...yValues) - Math.min(...yValues));
    const lineTooWide = actualWidth > desiredWidth * 1.16 + 1.1;
    const lineTooNarrow = entries.length > 2 && actualWidth < desiredWidth * 0.78 - 0.8;
    const widthRatio = desiredWidth > 0
      ? clamp(desiredWidth / actualWidth, 0.72, 1.22)
      : 1;

    entries.forEach(({ player, target }) => {
      if (hardFixedIds.has(player.id)) {
        return;
      }

      const softScale = softFixedIds.has(player.id) ? 0.38 : 1;
      const centerPull = settings.centerWeight * softScale;
      const depthPull = settings.depthWeight * softScale;
      const widthPull = (lineTooWide || lineTooNarrow ? settings.widthWeight : settings.widthWeight * 0.24) * softScale;
      const desiredOffset = (target.y - actualCenterY) * widthRatio;
      const cohesiveY = desiredCenterY + desiredOffset;
      const nextTarget = clampToPitch({
        x: lerp(target.x, desiredLineX, depthPull),
        y: lerp(
          lerp(target.y, target.y + (desiredCenterY - actualCenterY), centerPull),
          cohesiveY,
          widthPull
        ),
      }, 2.2);

      if (distance(target, nextTarget) > 0.08) {
        adjusted = true;
      }

      targets.set(player.id, nextTarget);
    });
  });

  if (adjusted) {
    labels.push(settings.label);
  }

  return labels;
}

function getDefensiveCompactLineIntegritySettings(profile, lineKey) {
  if (!profile || profile.phaseKey === "highPress" || profile.phaseKey === "setPiece") {
    return null;
  }

  const phaseSettings = {
    boxDefending: {
      gap: {
        back: 7.5,
        midfield: 7.5,
        forward: 8.2,
      },
      xWeight: {
        back: 0.98,
        midfield: 0.96,
        forward: 0.66,
      },
      yWeight: {
        back: 0.98,
        midfield: 0.96,
        forward: 0.7,
      },
      protectedScale: {
        back: 0.82,
        midfield: 0.78,
        forward: 0.52,
      },
      presserScale: {
        back: 0.72,
        midfield: 0.5,
        forward: 0.42,
      },
      label: "Box line integrity",
    },
    lowBlock: {
      gap: {
        back: 8,
        midfield: 8,
        forward: 8.4,
      },
      xWeight: {
        back: 0.97,
        midfield: 0.94,
        forward: 0.62,
      },
      yWeight: {
        back: 0.98,
        midfield: 0.95,
        forward: 0.68,
      },
      protectedScale: {
        back: 0.84,
        midfield: 0.8,
        forward: 0.56,
      },
      presserScale: {
        back: 0.74,
        midfield: 0.52,
        forward: 0.44,
      },
      label: "Low-block 8m line integrity",
    },
    midBlock: {
      gap: {
        back: 9,
        midfield: 8.8,
        forward: 10.4,
      },
      xWeight: {
        back: 0.62,
        midfield: 0.58,
        forward: 0.34,
      },
      yWeight: {
        back: 0.66,
        midfield: 0.62,
        forward: 0.4,
      },
      protectedScale: {
        back: 0.62,
        midfield: 0.58,
        forward: 0.42,
      },
      presserScale: {
        back: 0.62,
        midfield: 0.5,
        forward: 0.42,
      },
      label: "Mid-block line integrity",
    },
  };
  const settings = phaseSettings[profile.phaseKey];

  if (!settings) {
    return null;
  }

  return {
    gap: settings.gap[lineKey] ?? settings.gap.midfield,
    xWeight: settings.xWeight[lineKey] ?? settings.xWeight.midfield,
    yWeight: settings.yWeight[lineKey] ?? settings.yWeight.midfield,
    protectedScale: settings.protectedScale[lineKey] ?? settings.protectedScale.midfield,
    presserScale: settings.presserScale[lineKey] ?? settings.presserScale.midfield,
    label: settings.label,
  };
}

function enforceDefensiveCompactLineIntegrity(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  presserId = null,
  hardFixedIds = new Set(),
  softFixedIds = new Set()
) {
  const restartType = state.restartPhase?.type;
  if (!ballPoint || (restartType && restartType !== "kickoff")) {
    return [];
  }

  const labels = new Set();
  let adjusted = false;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const settings = getDefensiveCompactLineIntegritySettings(profile, lineKey);
    if (!settings) {
      return;
    }

    const players = (groups[lineKey] ?? []).filter(
      (player) => !isGoalkeeper(player) && targets.has(player.id)
    );
    if (players.length < 2) {
      return;
    }

    const lineWidth = settings.gap * (players.length - 1);
    const lineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const centerY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);

    players.forEach((player, index) => {
      const slotTarget = clampToPitch({
        x: lineX,
        y: clamp(centerY - lineWidth / 2 + settings.gap * index, 3.1, pitch.width - 3.1),
      }, 2.2);
      const currentTarget = targets.get(player.id) ?? player.position;
      const isPresser = presserId && player.id === presserId;
      const protectedScale =
        hardFixedIds.has(player.id) || softFixedIds.has(player.id)
          ? settings.protectedScale
          : 1;
      const presserScale = isPresser ? settings.presserScale : 1;
      const xWeight = settings.xWeight * protectedScale * presserScale;
      const yWeight = settings.yWeight * protectedScale * presserScale;
      const nextTarget = clampToPitch({
        x: lerp(currentTarget.x, slotTarget.x, xWeight),
        y: lerp(currentTarget.y, slotTarget.y, yWeight),
      }, 2.2);

      if (distance(currentTarget, nextTarget) > 0.06) {
        adjusted = true;
        labels.add(settings.label);
      }

      targets.set(player.id, nextTarget);
    });
  });

  return adjusted ? uniquePrincipleLabels([...labels]) : [];
}

function getDefensiveOffsideLineControlContext(teamId, ballPoint, profile) {
  if (!ballPoint || state.restartPhase?.type || profile.phaseKey === "setPiece") {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (actionType !== "pass" && actionType !== "dribble") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const carrier = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      actionMeta.carrierPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const secondLastX = getSecondLastOpponentLineX(attackingTeamId);
  if (secondLastX === null) {
    return null;
  }

  const attackSign = getAttackDirectionSign(attackingTeamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const linePoint = { x: secondLastX, y: pitch.width / 2 };
  const lineDepth = getAttackingDepth(linePoint, attackingTeamId);
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const startDepth = getAttackingDepth(startPoint, attackingTeamId);
  const receiverPoint = receiver ? getPlayerBallControlPoint(receiver) : targetPoint;
  const receiverDepth = getAttackingDepth(receiverPoint, attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const passDistance = distance(startPoint, targetPoint);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const carrierPressure = carrier ? getPlayerPressureLoad(carrier, startPoint) : 0.5;
  const laneClarity = carrier && actionType === "pass"
    ? computePassLaneClarity(carrier, targetPoint)
    : 0.58;
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const backLineDepth = getDefensiveLineDistanceFromOwnGoal(teamId, "back", ballPoint, profile);
  const receiverBeyondLine = (receiverPoint.x - secondLastX) * attackSign > -0.4;
  const targetBehindLine = (targetPoint.x - secondLastX) * attackSign > -1.2;
  const depthThreat =
    actionType === "pass" &&
    forwardGain >= 4.5 &&
    passDistance >= 8 &&
    (
      targetBehindLine ||
      receiverBeyondLine ||
      targetThreat.behindLine >= 0.18 ||
      actionSpace.lineBreakCount >= 1
    );
  const carrierCanPickPass =
    carrierPressure <= 0.42 &&
    laneClarity >= 0.56 &&
    (targetThreat.behindLine >= 0.2 || actionSpace.value >= 0.36);
  const trapCondition =
    depthThreat &&
    (profile.phaseKey === "highPress" || profile.phaseKey === "midBlock") &&
    backLineDepth >= 20 &&
    (
      carrierPressure >= 0.54 ||
      laneClarity <= 0.44 ||
      (receiverBeyondLine && forwardGain <= 10)
    );
  const emergencyCover =
    depthThreat &&
    (
      profile.phaseKey === "boxDefending" ||
      ballFromOwnGoal <= 30 ||
      carrierCanPickPass ||
      targetThreat.box >= 0.16
    );

  if (!depthThreat && !(receiverBeyondLine && receiverDepth >= pitch.length / 2)) {
    return null;
  }

  const mode =
    emergencyCover
      ? "coverDrop"
      : trapCondition
        ? (carrierPressure >= 0.62 || laneClarity <= 0.38 ? "stepTrap" : "holdLine")
        : "holdLine";

  return {
    actionType,
    attackingTeamId,
    carrier,
    receiver,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    receiverPoint: cloneVector(receiverPoint),
    linePoint,
    secondLastX,
    ownGoal,
    attackSign,
    lineDepth,
    startDepth,
    targetDepth,
    receiverDepth,
    forwardGain,
    passDistance,
    targetThreat,
    actionSpace,
    carrierPressure,
    laneClarity,
    ballFromOwnGoal,
    backLineDepth,
    receiverBeyondLine,
    targetBehindLine,
    depthThreat,
    carrierCanPickPass,
    trapCondition,
    emergencyCover,
    mode,
  };
}

function enforceDefensiveOffsideLineControl(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  hardFixedIds = new Set(),
  softFixedIds = new Set()
) {
  const context = getDefensiveOffsideLineControlContext(teamId, ballPoint, profile);
  if (!context) {
    return [];
  }

  const backPlayers = (groups.back ?? [])
    .filter((player) => !isGoalkeeper(player) && targets.has(player.id))
    .sort((a, b) => (targets.get(a.id)?.y ?? a.position.y) - (targets.get(b.id)?.y ?? b.position.y));
  if (!backPlayers.length) {
    return [];
  }

  const sign = getDefendingDirectionSign(teamId);
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const baseDepth = getDefensiveLineDistanceFromOwnGoal(teamId, "back", ballPoint, profile);
  const lineDepthFromOwnGoal = getDistanceFromOwnGoal(teamId, context.linePoint);
  const desiredDepth =
    context.mode === "coverDrop"
      ? clamp(baseDepth - (profile.phaseKey === "boxDefending" ? 1.2 : 2.4), profile.minBackLineFromOwnGoal ?? 6, profile.maxBackLineFromOwnGoal)
      : context.mode === "stepTrap"
        ? clamp(Math.max(baseDepth, lineDepthFromOwnGoal + 0.8), profile.minBackLineFromOwnGoal ?? 6, profile.maxBackLineFromOwnGoal)
        : clamp(lerp(baseDepth, lineDepthFromOwnGoal, 0.5), profile.minBackLineFromOwnGoal ?? 6, profile.maxBackLineFromOwnGoal);
  const unitGap = clamp(
    getDefensiveUnitGap(profile, "back"),
    profile.phaseKey === "highPress" ? 8.4 : 7.6,
    profile.phaseKey === "highPress" ? 10.6 : 9.2
  );
  const lineWidth = unitGap * Math.max(0, backPlayers.length - 1);
  const sideSign =
    getWideSideSign(context.receiverPoint) ||
    getWideSideSign(context.targetPoint) ||
    getWideSideSign(ballPoint) ||
    1;
  const centerY = clamp(
    lerp(pitch.width / 2, context.receiverPoint.y, context.mode === "coverDrop" ? 0.28 : 0.18),
    Math.max(4, lineWidth / 2 + 3),
    pitch.width - Math.max(4, lineWidth / 2 + 3)
  );
  const weightBase =
    context.mode === "stepTrap"
      ? 0.72
      : context.mode === "holdLine"
        ? 0.6
        : 0.46;
  const labels = [];
  let adjusted = false;

  backPlayers.forEach((player, index) => {
    if (hardFixedIds.has(player.id)) {
      return;
    }

    const spreadRatio = backPlayers.length === 1 ? 0.5 : index / (backPlayers.length - 1);
    const slotY = clamp(centerY - lineWidth / 2 + lineWidth * spreadRatio, 3.4, pitch.width - 3.4);
    const ballSideCover =
      context.mode === "coverDrop" &&
      Math.sign(slotY - pitch.width / 2) === sideSign
        ? (context.receiverPoint.y - slotY) * 0.16
        : 0;
    const currentTarget = targets.get(player.id) ?? player.position;
    const weight = softFixedIds.has(player.id) ? weightBase * 0.5 : weightBase;
    const lineTarget = clampToPitch({
      x: ownGoalX + sign * desiredDepth,
      y: clamp(slotY + ballSideCover, 3.4, pitch.width - 3.4),
    }, 2.2);
    const nextTarget = clampToPitch({
      x: lerp(currentTarget.x, lineTarget.x, weight),
      y: lerp(currentTarget.y, lineTarget.y, weight),
    }, 2.2);

    if (distance(currentTarget, nextTarget) > 0.08) {
      adjusted = true;
    }

    targets.set(player.id, nextTarget);
  });

  if (adjusted) {
    labels.push(
      context.mode === "coverDrop"
        ? "Offside line: cover depth"
        : context.mode === "stepTrap"
          ? "Offside line: step together"
          : "Offside line: hold shoulder"
    );
  }

  return labels;
}

function getDefensiveBackLineHandoverContext(teamId, ballPoint, profile) {
  if (!ballPoint || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const principleText = [
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const threats = getDefensiveRunnerThreats(teamId, ballPoint, profile);
  const primaryThreat =
    threats.find((threat) => threat.isBlindsideRun || threat.isChannelRun) ??
    threats.find((threat) => threat.isDepthThreat || threat.isBoxThreat) ??
    threats[0] ??
    null;
  const hasDepthCue =
    principleText.includes("blindside") ||
    principleText.includes("channel") ||
    principleText.includes("run behind") ||
    principleText.includes("line break") ||
    principleText.includes("depth");
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const shouldCoordinate =
    primaryThreat?.isBlindsideRun ||
    primaryThreat?.isChannelRun ||
    primaryThreat?.isDepthThreat ||
    primaryThreat?.isBoxThreat ||
    targetThreat.behindLine >= 0.22 ||
    forwardGain >= 6.5 ||
    (hasDepthCue && forwardGain >= 2.5);

  if (!shouldCoordinate || actionType === "shot") {
    return null;
  }

  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const phaseDrop =
    profile.phaseKey === "boxDefending"
      ? 1.1
      : profile.phaseKey === "lowBlock"
        ? 1.6
        : profile.phaseKey === "highPress"
          ? 2.8
          : 2.2;
  const lineBreakDrop =
    primaryThreat?.isBlindsideRun || targetThreat.behindLine >= 0.32
      ? 2.8
      : primaryThreat?.isChannelRun || forwardGain >= 8
        ? 2.2
        : 1.35;
  const dropDepth = clamp(phaseDrop + lineBreakDrop + Math.max(0, forwardGain - 6) * 0.08, 1.4, 6.8);
  const sideSign =
    getWideSideSign(primaryThreat?.player) ||
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;

  return {
    targetPoint,
    primaryThreat,
    sideSign,
    dropDepth,
    ballFromOwnGoal,
    isChannelThreat: !!(primaryThreat?.isBlindsideRun || primaryThreat?.isChannelRun),
    isDeepThreat: !!(primaryThreat?.isDepthThreat || targetThreat.behindLine >= 0.22 || forwardGain >= 6.5),
  };
}

function applyDefensiveBackLineHandoverTargets(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveBackLineHandoverContext(teamId, ballPoint, profile);
  if (!context) {
    return [];
  }

  const labels = [];
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const backPlayers = (groups.back ?? []).filter((player) => !isGoalkeeper(player));
  const midfieldPlayers = (groups.midfield ?? []).filter((player) => !isGoalkeeper(player));

  if (!backPlayers.length) {
    return [];
  }

  const baseBackDepth = getDefensiveLineDistanceFromOwnGoal(teamId, "back", ballPoint, profile);
  const backDepth = clamp(
    baseBackDepth - context.dropDepth,
    profile.minBackLineFromOwnGoal ?? 6,
    profile.maxBackLineFromOwnGoal ?? 64
  );
  const gap = clamp(getDefensiveUnitGap(profile, "back"), 7.2, 9);
  const lineWidth = gap * Math.max(0, backPlayers.length - 1);
  const runnerY = context.primaryThreat?.player?.position?.y ?? context.targetPoint.y;
  const centerY = clamp(
    lerp(pitch.width / 2, lerp(context.targetPoint.y, runnerY, 0.62), context.isChannelThreat ? 0.38 : 0.24),
    Math.max(4, lineWidth / 2 + 3),
    pitch.width - Math.max(4, lineWidth / 2 + 3)
  );
  const orderedBacks = [...backPlayers].sort((a, b) => (targets.get(a.id)?.y ?? a.position.y) - (targets.get(b.id)?.y ?? b.position.y));

  orderedBacks.forEach((player, index) => {
    if (protectedIds.has(player.id) || !targets.has(player.id)) {
      return;
    }

    const spreadRatio = orderedBacks.length === 1 ? 0.5 : index / (orderedBacks.length - 1);
    const slotY = clamp(centerY - lineWidth / 2 + lineWidth * spreadRatio, 3.5, pitch.width - 3.5);
    const isBallSide = Math.sign(slotY - pitch.width / 2) === context.sideSign;
    const channelNudge = context.isChannelThreat && isBallSide
      ? (runnerY - slotY) * 0.24
      : (pitch.width / 2 - slotY) * 0.08;
    const currentTarget = targets.get(player.id) ?? player.position;
    const slot = clampToPitch({
      x: ownGoal.x + sign * (backDepth + (isBallSide ? 0.35 : -0.45)),
      y: clamp(slotY + channelNudge, 3.5, pitch.width - 3.5),
    }, 2.2);

    targets.set(player.id, clampToPitch({
      x: lerp(currentTarget.x, slot.x, 0.78),
      y: lerp(currentTarget.y, slot.y, 0.74),
    }, 2.2));
  });

  if (midfieldPlayers.length && context.isDeepThreat) {
    const screenDepth = clamp(backDepth + (profile.backToMidfield ?? 10) * 0.72, backDepth + 5.5, backDepth + 12);
    const midfieldGap = clamp(getDefensiveUnitGap(profile, "midfield"), 7.2, 9.5);
    const screenWidth = midfieldGap * Math.max(0, midfieldPlayers.length - 1);
    const screenCenterY = clamp(
      lerp(pitch.width / 2, context.targetPoint.y, 0.26),
      Math.max(5, screenWidth / 2 + 3),
      pitch.width - Math.max(5, screenWidth / 2 + 3)
    );
    const orderedMidfield = [...midfieldPlayers].sort((a, b) => (targets.get(a.id)?.y ?? a.position.y) - (targets.get(b.id)?.y ?? b.position.y));

    orderedMidfield.forEach((player, index) => {
      if (protectedIds.has(player.id) || !targets.has(player.id)) {
        return;
      }

      const spreadRatio = orderedMidfield.length === 1 ? 0.5 : index / (orderedMidfield.length - 1);
      const currentTarget = targets.get(player.id) ?? player.position;
      const slot = clampToPitch({
        x: ownGoal.x + sign * screenDepth,
        y: clamp(screenCenterY - screenWidth / 2 + screenWidth * spreadRatio, 4, pitch.width - 4),
      }, 2.2);

      targets.set(player.id, clampToPitch({
        x: lerp(currentTarget.x, slot.x, 0.42),
        y: lerp(currentTarget.y, slot.y, 0.38),
      }, 2.2));
    });
  }

  labels.push(context.isChannelThreat ? "Back line handover against channel run" : "Back line drops against depth threat");
  if (context.isDeepThreat) {
    labels.push("Midfield screens second ball behind line");
  }

  return uniquePrincipleLabels(labels);
}

function getDefensiveLineActionLabels(profile) {
  const label = profile.lineActionAdjustment?.label;
  return label ? [label] : [];
}

function getDefensiveGoalkeeperTarget(teamId, ballPoint, profile = getDefensiveAutopilotProfile(teamId, ballPoint)) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const sweepDepth = getDefensiveLineDistanceFromOwnGoal(teamId, "gk", ballPoint, profile);
  const yClamp = profile.phaseKey === "boxDefending" ? [22.5, 45.5] : [28.5, 39.5];
  const yInfluence = profile.phaseKey === "boxDefending" ? 0.28 : 0.12;
  const y = clamp(lerp(pitch.width / 2, ballPoint.y, yInfluence), yClamp[0], yClamp[1]);

  return clampToPitch({
    x: ownGoalX + sign * sweepDepth,
    y,
  }, 3);
}

function getDefensiveGoalkeeperSweeperContext(teamId, goalkeeper, ballPoint, profile) {
  if (!goalkeeper || !ballPoint || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    targetKind: state.ball.targetKind,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;

  if (!targetPoint || !startPoint || !["pass", "dribble"].includes(actionType)) {
    return null;
  }

  const targetFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const startFromOwnGoal = getDistanceFromOwnGoal(teamId, startPoint);
  const actionDistance = distance(startPoint, targetPoint);
  const actionSpeed = Math.max(actionMeta.speed ?? state.ball.speed ?? state.ball.currentSpeed ?? 10, 0.1);
  const eta = actionDistance / actionSpeed;
  const profileText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.targetKind,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const centrality = 1 - Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2);
  const ballMovingTowardGoal = targetFromOwnGoal <= startFromOwnGoal - 3 || forwardGain >= 5;
  const isAerialDelivery =
    isAerialFlightStyle(state.ball.flightStyle) ||
    profileText.includes("cross") ||
    profileText.includes("delivery") ||
    profileText.includes("lofted") ||
    profileText.includes("clipped");
  const isThroughThreat =
    ballMovingTowardGoal &&
    (
      targetThreat.behindLine >= 0.2 ||
      targetThreat.box >= 0.18 ||
      profileText.includes("through") ||
      profileText.includes("line-break") ||
      profileText.includes("into-space") ||
      profileText.includes("run behind") ||
      profileText.includes("channel")
    );
  const isCrossClaim =
    actionType === "pass" &&
    targetFromOwnGoal <= 18.5 &&
    isAerialDelivery &&
    (centrality >= 0.24 || targetThreat.box >= 0.16);
  const isBreakawayDribble =
    actionType === "dribble" &&
    targetFromOwnGoal <= 24 &&
    ballMovingTowardGoal &&
    centrality >= 0.18;

  if (!isThroughThreat && !isCrossClaim && !isBreakawayDribble) {
    return null;
  }

  const baseTarget = getDefensiveGoalkeeperTarget(teamId, ballPoint, profile);
  const maxSweepDepth =
    profile.phaseKey === "highPress"
      ? 24
      : profile.phaseKey === "midBlock"
        ? 19
        : profile.phaseKey === "lowBlock"
          ? 15
          : 11.5;
  const desiredDepth = isCrossClaim
    ? clamp(targetFromOwnGoal * 0.46 + 3.4, 5.4, 11.8)
    : isBreakawayDribble
      ? clamp(targetFromOwnGoal * 0.52 + 2.2, 6.2, 13.4)
      : clamp(targetFromOwnGoal - 2.6, 8.2, maxSweepDepth);
  const yInfluence = isCrossClaim ? 0.48 : isBreakawayDribble ? 0.62 : 0.72;
  const yClamp = isCrossClaim
    ? [19.5, 48.5]
    : isBreakawayDribble
      ? [20.5, 47.5]
      : [13.5, 54.5];
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const desiredTarget = clampToPitch({
    x: ownGoal.x + sign * desiredDepth,
    y: clamp(lerp(pitch.width / 2, targetPoint.y, yInfluence), yClamp[0], yClamp[1]),
  }, 2.5);
  const timeToTarget = computeTimeToCoverDistance(
    goalkeeper,
    distance(goalkeeper.position, desiredTarget),
    desiredTarget
  );
  const access = clamp((eta + 0.45) / Math.max(timeToTarget, 0.01), 0.22, 1);
  const target = clampToPitch({
    x: lerp(baseTarget.x, desiredTarget.x, access),
    y: lerp(baseTarget.y, desiredTarget.y, access),
  }, 2.5);
  const label = isCrossClaim
    ? "GK claims box delivery"
    : isBreakawayDribble
      ? "GK narrows breakaway angle"
      : "GK sweeps behind back line";

  return {
    target,
    label,
    focusPoint: targetPoint,
  };
}

function applyDefensiveGoalkeeperSweeperTarget(teamId, targets, groups, ballPoint, profile) {
  const labels = [];

  groups.gk.forEach((goalkeeper) => {
    const context = getDefensiveGoalkeeperSweeperContext(teamId, goalkeeper, ballPoint, profile);
    if (!context) {
      return;
    }

    targets.set(goalkeeper.id, context.target);
    labels.push(context.label);
  });

  return uniquePrincipleLabels(labels);
}

function getDefensiveGoalkeeperShotSetContext(teamId, goalkeeper, ballPoint, profile) {
  if (!goalkeeper || !ballPoint || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    targetKind: state.ball.targetKind,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const threatPoint = actionType === "shot" ? startPoint : targetPoint;
  const threat = getPitchThreatProfile(threatPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, threatPoint);
  const goalDistance = distance(threatPoint, getOwnGoalCenter(teamId));
  const profileText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.targetKind,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isCutback =
    profileText.includes("cutback") ||
    threat.cutbackZone >= 0.24;
  const isBoxDelivery =
    profileText.includes("cross") ||
    profileText.includes("delivery") ||
    threat.assistZone >= 0.36 ||
    (actionType === "pass" && threat.box >= 0.18);
  const isShotThreat =
    actionType === "shot" ||
    profileText.includes("shoot") ||
    profileText.includes("finish") ||
    threat.box >= 0.2 ||
    (ballFromOwnGoal <= 31 && threat.centralPocket >= 0.24);
  const isBreakaway =
    actionType === "dribble" &&
    ballFromOwnGoal <= 25 &&
    (threat.box >= 0.12 || threat.centralPocket >= 0.22);
  const shouldSet =
    isShotThreat ||
    isCutback ||
    isBoxDelivery ||
    isBreakaway ||
    (ballFromOwnGoal <= 28 && threat.value >= 0.42);

  if (!shouldSet) {
    return null;
  }

  const actionDistance = distance(startPoint, targetPoint);
  const actionSpeed = Math.max(actionMeta.speed ?? state.ball.speed ?? state.ball.currentSpeed ?? 10, 0.1);
  const eta = actionDistance / actionSpeed;
  const sideSign =
    getWideSideSign(threatPoint) ||
    getWideSideSign(targetPoint) ||
    1;

  return {
    actionType,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    threatPoint: cloneVector(threatPoint),
    threat,
    ballFromOwnGoal,
    goalDistance,
    eta,
    sideSign,
    isShotThreat,
    isCutback,
    isBoxDelivery,
    isBreakaway,
    phaseKey: profile.phaseKey,
  };
}

function getDefensiveGoalkeeperShotSetTarget(teamId, goalkeeper, context, baseTarget) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const centerY = pitch.width / 2;
  const sideDistance = Math.abs(context.threatPoint.y - centerY);
  const wideRatio = clamp(sideDistance / (pitch.width / 2), 0, 1);
  const nearPostLock = context.isShotThreat && wideRatio >= 0.52;
  const depth =
    context.isBoxDelivery && !context.isShotThreat
      ? clamp(context.ballFromOwnGoal * 0.24 + 2.4, 3.2, 8.8)
      : context.isBreakaway
        ? clamp(context.ballFromOwnGoal * 0.32 + 1.7, 3.4, 9.2)
        : context.isCutback
          ? clamp(context.ballFromOwnGoal * 0.18 + 2.1, 2.4, 6.8)
          : clamp(context.ballFromOwnGoal * 0.16 + 1.45, 1.8, 7.4);
  const yPull =
    context.isBoxDelivery && !context.isShotThreat
      ? 0.3
      : context.isCutback
        ? 0.24
        : nearPostLock
          ? 0.42
          : 0.32;
  const nearPostBias = nearPostLock
    ? context.sideSign * clamp(0.75 + wideRatio * 1.65, 0.75, 2.25)
    : 0;
  const yLimit =
    context.isBoxDelivery && !context.isShotThreat
      ? 7.2
      : context.isBreakaway
        ? 6.2
        : nearPostLock
          ? 4.7
          : 4.15;
  const desiredTarget = clampToPitch({
    x: ownGoal.x + sign * depth,
    y: clamp(
      lerp(centerY, context.threatPoint.y, yPull) + nearPostBias,
      centerY - yLimit,
      centerY + yLimit
    ),
  }, 1.6);
  const timeToTarget = computeTimeToCoverDistance(
    goalkeeper,
    distance(goalkeeper.position, desiredTarget),
    desiredTarget
  );
  const access = clamp((context.eta + 0.42) / Math.max(timeToTarget, 0.01), 0.3, 1);

  return clampToPitch({
    x: lerp(baseTarget.x, desiredTarget.x, access),
    y: lerp(baseTarget.y, desiredTarget.y, access),
  }, 1.6);
}

function applyDefensiveGoalkeeperShotSetTarget(teamId, targets, groups, ballPoint, profile) {
  const labels = [];

  groups.gk.forEach((goalkeeper) => {
    const context = getDefensiveGoalkeeperShotSetContext(teamId, goalkeeper, ballPoint, profile);
    if (!context) {
      return;
    }

    const baseTarget = targets.get(goalkeeper.id) ?? getDefensiveGoalkeeperTarget(teamId, ballPoint, profile);
    targets.set(goalkeeper.id, getDefensiveGoalkeeperShotSetTarget(teamId, goalkeeper, context, baseTarget));
    labels.push(
      context.isShotThreat
        ? "GK sets for shot"
        : context.isCutback
          ? "GK protects cutback angle"
          : context.isBreakaway
            ? "GK narrows breakaway"
            : "GK adjusts to box delivery"
    );
  });

  return uniquePrincipleLabels(labels);
}

function chooseDefensiveAutopilotPresser(teamId, ballPoint, targets, profile) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, ballPoint);
  const candidates = state.players.filter(
    (player) =>
      player.team === teamId &&
      getDefensiveAutopilotLineKey(player, formation, profile.phaseKey) !== "gk"
  );

  let bestCandidate = null;
  let bestScore = Infinity;

  candidates.forEach((player) => {
    const lineKey = getDefensiveAutopilotLineKey(player, formation, profile.phaseKey);
    const target = targets.get(player.id) ?? player.position;
    let score =
      distance(player.position, ballPoint) * 0.58 +
      distance(target, ballPoint) * 0.42;
    const isBallSide =
      Math.sign(ballPoint.y - pitch.width / 2) === Math.sign(target.y - pitch.width / 2) ||
      Math.abs(ballPoint.y - pitch.width / 2) < 6;

    if (profile.phaseKey === "highPress" && lineKey !== "forward") {
      score += 8;
    }

    if (profile.phaseKey === "midBlock" && lineKey === "back" && ballFromOwnGoal > 34) {
      score += 4;
    }

    if (profile.phaseKey === "lowBlock" && lineKey === "forward") {
      score += 5.5;
    }

    if (profile.phaseKey === "boxDefending" && lineKey === "forward") {
      score += 7;
    }

    if (profile.phaseKey === "boxDefending" && lineKey === "back" && ballFromOwnGoal > 15) {
      score += 2;
    }

    if ((profile.threatResponse?.protectCenter ?? 0) >= 0.42) {
      const centralFit = 1 - Math.abs(target.y - pitch.width / 2) / (pitch.width / 2);
      if (lineKey === "midfield") {
        score -= centralFit * (1.7 + profile.threatResponse.protectCenter * 1.8);
      } else if (lineKey === "back" && ballFromOwnGoal <= 38) {
        score -= centralFit * (0.8 + profile.threatResponse.protectCenter * 1.1);
      } else if (lineKey === "forward" && ballFromOwnGoal <= 44) {
        score += 2.2 * profile.threatResponse.protectCenter;
      }
    }

    if (isBallSide) {
      score -= (profile.phaseKey === "highPress" ? 2.5 : 1.4) * (0.8 + profile.pressingIntensity * 0.5);
    }

    score -= profile.pressingIntensity * (lineKey === "forward" ? 1.2 : lineKey === "midfield" ? 0.7 : 0.35);

    if (score < bestScore) {
      bestScore = score;
      bestCandidate = player;
    }
  });

  return bestCandidate;
}

function getDefensivePressTarget(teamId, ballPoint, profile, presser = null) {
  const sign = getDefendingDirectionSign(teamId);
  const protectCenter = profile.threatResponse?.protectCenter ?? 0;
  const ballSide = getWideSideSign(ballPoint);
  const presserSide =
    presser && Number.isFinite(presser.position?.y)
      ? Math.sign(presser.position.y - ballPoint.y)
      : 0;
  const centralApproachSide = presserSide || getWideSideSign(presser) || (ballPoint.y >= pitch.width / 2 ? 1 : -1);
  const widePress = ballSide !== 0;
  const side = widePress ? ballSide : centralApproachSide;
  const insideShield = clamp(
    widePress
      ? 2.1 + Math.abs(ballPoint.y - pitch.width / 2) * 0.055 + protectCenter * 2.4
      : 0.9 + protectCenter * 1.35,
    widePress ? 1.8 : 0.65,
    widePress ? 5.4 : 2.8
  );
  const lineCushion =
    profile.phaseKey === "lowBlock" || profile.phaseKey === "boxDefending"
      ? 0.55
      : profile.phaseKey === "highPress"
        ? -0.25
        : 0;

  return clampToPitch({
    x: ballPoint.x - sign * clamp(profile.pressOffset + protectCenter * 0.75 + lineCushion, 0.7, 4.2),
    y: widePress
      ? clamp(ballPoint.y - side * insideShield, 3, pitch.width - 3)
      : clamp(ballPoint.y + side * insideShield, 3, pitch.width - 3),
  }, 3);
}

function getDefensiveAngledPressTarget(teamId, ballPoint, profile, presser, baseTarget = null, reference = null) {
  const sign = getDefendingDirectionSign(teamId);
  const attackingTeamId = getOtherTeamId(teamId);
  const threat = attackingTeamId ? getPitchThreatProfile(ballPoint, attackingTeamId) : null;
  const basePressTarget = getDefensivePressTarget(teamId, ballPoint, profile, presser);
  const ballSide = getWideSideSign(ballPoint);
  const widePress = ballSide !== 0;
  const protectCenter = profile.threatResponse?.protectCenter ?? 0;
  const targetThreat = threat?.value ?? 0;
  const dribbleContainment = !!reference;
  const goalSideCushion = clamp(
    (dribbleContainment ? 1.15 : 0.55) +
      protectCenter * 0.65 +
      targetThreat * 0.45 +
      (profile.phaseKey === "lowBlock" || profile.phaseKey === "boxDefending" ? 0.4 : 0),
    0.45,
    2.4
  );
  const currentTarget = baseTarget ?? basePressTarget;
  const centralLaneWeight = widePress
    ? clamp(0.14 + protectCenter * 0.2 + targetThreat * 0.1, 0.12, 0.42)
    : clamp(0.05 + protectCenter * 0.12, 0.04, 0.2);
  const sideLockY = widePress
    ? lerp(basePressTarget.y, pitch.width / 2, centralLaneWeight)
    : basePressTarget.y;
  const target = clampToPitch({
    x: lerp(currentTarget.x, basePressTarget.x - sign * goalSideCushion, 0.82),
    y: lerp(currentTarget.y, sideLockY, widePress ? 0.82 : 0.68),
  }, 2.4);

  return {
    target,
    label: widePress
      ? "Curve press to lock inside"
      : dribbleContainment
        ? "Angle contain pressure"
        : "Angled press cover shadow",
  };
}

function applyDefensivePresserAngleTarget(
  teamId,
  targets,
  presser,
  ballPoint,
  profile,
  reference = null
) {
  if (!presser || isGoalkeeper(presser) || !ballPoint || state.restartPhase?.type) {
    return {
      labels: [],
      protectedIds: new Set([presser?.id].filter(Boolean)),
    };
  }

  const currentTarget = targets.get(presser.id) ?? getDefensivePressTarget(teamId, ballPoint, profile, presser);
  const angleProfile = getDefensiveAngledPressTarget(
    teamId,
    ballPoint,
    profile,
    presser,
    currentTarget,
    reference
  );
  const angleWeight = reference
    ? 0.34
    : profile.phaseKey === "highPress"
      ? 0.56
      : profile.phaseKey === "lowBlock" || profile.phaseKey === "boxDefending"
        ? 0.42
        : 0.5;

  targets.set(presser.id, clampToPitch({
    x: lerp(currentTarget.x, angleProfile.target.x, angleWeight),
    y: lerp(currentTarget.y, angleProfile.target.y, angleWeight),
  }, 2.2));

  return {
    labels: [angleProfile.label],
    protectedIds: new Set([presser.id]),
  };
}

function getGoalkeeperBuildOutPressContext(defensiveTeamId, ballPoint) {
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    receiverPlayerId: state.ball.receiverPlayerId,
    beforeSnapshot: {
      ball: {
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const goalkeeper = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );

  if (
    actionMeta.actionType !== "pass" ||
    !goalkeeper ||
    !isGoalkeeper(goalkeeper) ||
    goalkeeper.team !== attackingTeamId
  ) {
    return null;
  }

  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const startPoint = actionMeta.beforeSnapshot?.ball?.position ?? state.ball.startPosition ?? goalkeeper.position;
  const target = actionMeta.target ?? ballPoint;
  const passDistance = distance(startPoint, target);
  const principleText = [
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, teams[attackingTeamId]?.formation) : null;
  const directRelease =
    principleText.includes("gk release") ||
    (!receiver && passDistance >= 24) ||
    (receiverRoleKey && ["striker", "wideForward", "secondStriker"].includes(receiverRoleKey) && passDistance >= 24);
  const shortBuild =
    !directRelease &&
    (principleText.includes("gk build") ||
      !!receiver ||
      passDistance <= 30);

  if (!shortBuild && !directRelease) {
    return null;
  }

  return {
    actionMeta,
    attackingTeamId,
    goalkeeper,
    receiver,
    receiverRoleKey,
    startPoint: cloneVector(startPoint),
    target: cloneVector(target),
    passDistance,
    directRelease,
    shortBuild,
    sideSign: getWideSideSign(target) || getWideSideSign(receiver) || getWideSideSign(startPoint) || 1,
  };
}

function pickDefensiveAutopilotPlayer(groups, lineKeys, excludedIds, referencePoint, preferLabels = []) {
  const labelPreference = new Set(preferLabels);
  const candidates = lineKeys
    .flatMap((lineKey) => groups[lineKey] ?? [])
    .filter((player) => !excludedIds.has(player.id) && !isGoalkeeper(player));

  if (!candidates.length) {
    return null;
  }

  return candidates
    .map((player) => {
      const label = getPlayerMagnetLabel(player);
      return {
        player,
        score:
          distance(player.position, referencePoint) +
          (labelPreference.has(label) ? -4.5 : 0) -
          getPlayerDecisionContext(player).profile.tacticalDiscipline * 1.4 -
          getPlayerDecisionContext(player).profile.decisionSpeed * 1.1,
      };
    })
    .sort((a, b) => a.score - b.score)[0]?.player ?? null;
}

function getGoalkeeperBuildOutPressTarget(defensiveTeamId, context, slot) {
  const sign = getDefendingDirectionSign(defensiveTeamId);
  const target = context.target;
  const sideSign = context.sideSign || 1;
  const points = {
    receiverPress: {
      x: target.x - sign * 1.8,
      y: lerp(target.y, pitch.width / 2, 0.16),
    },
    goalkeeperScreen: {
      x: lerp(context.startPoint.x, target.x, 0.42) - sign * 1.4,
      y: lerp(context.startPoint.y, target.y, 0.52),
    },
    pivotLock: {
      x: lerp(context.startPoint.x, target.x, 0.72),
      y: clamp(pitch.width / 2 - sideSign * 5.8, 17, pitch.width - 17),
    },
    farCenterBackLock: {
      x: lerp(context.startPoint.x, target.x, 0.34),
      y: clamp(pitch.width / 2 - sideSign * 15.5, 7, pitch.width - 7),
    },
    secondBallScreen: {
      x: target.x - sign * 4.5,
      y: clamp(lerp(target.y, pitch.width / 2, 0.42), 12, pitch.width - 12),
    },
    restCover: {
      x: target.x - sign * 14,
      y: clamp(pitch.width / 2, 15, pitch.width - 15),
    },
  };

  return clampToPitch(points[slot] ?? points.receiverPress, 2.5);
}

function applyGoalkeeperBuildOutPressTargets(teamId, targets, groups, basePresser, ballPoint, profile) {
  const context = getGoalkeeperBuildOutPressContext(teamId, ballPoint);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
    };
  }

  const labels = [];
  const excludedIds = new Set();
  let presser = basePresser;
  const firstPressPoint = getGoalkeeperBuildOutPressTarget(teamId, context, "receiverPress");
  const firstPresser = pickDefensiveAutopilotPlayer(
    groups,
    profile.phaseKey === "highPress" ? ["forward", "midfield"] : ["forward"],
    excludedIds,
    firstPressPoint,
    context.receiverRoleKey === "wideBack" || context.receiverRoleKey === "wideForward" ? ["W", "10"] : ["9", "10", "W"]
  );

  if (firstPresser) {
    targets.set(firstPresser.id, firstPressPoint);
    excludedIds.add(firstPresser.id);
    presser = firstPresser;
    labels.push(context.directRelease ? "Press second-ball release" : "Press GK first pass");
  }

  if (context.shortBuild) {
    const screenForward = pickDefensiveAutopilotPlayer(
      groups,
      ["forward"],
      excludedIds,
      getGoalkeeperBuildOutPressTarget(teamId, context, "goalkeeperScreen"),
      ["9", "10"]
    );
    if (screenForward) {
      targets.set(screenForward.id, getGoalkeeperBuildOutPressTarget(teamId, context, "goalkeeperScreen"));
      excludedIds.add(screenForward.id);
      labels.push("Screen pass back to GK");
    }

    const pivotLock = pickDefensiveAutopilotPlayer(
      groups,
      ["midfield", "forward"],
      excludedIds,
      getGoalkeeperBuildOutPressTarget(teamId, context, "pivotLock"),
      ["6", "8", "10"]
    );
    if (pivotLock) {
      targets.set(pivotLock.id, getGoalkeeperBuildOutPressTarget(teamId, context, "pivotLock"));
      excludedIds.add(pivotLock.id);
      labels.push("Lock the 6");
    }

    const farLock = pickDefensiveAutopilotPlayer(
      groups,
      ["forward", "midfield"],
      excludedIds,
      getGoalkeeperBuildOutPressTarget(teamId, context, "farCenterBackLock"),
      ["W", "8"]
    );
    if (farLock) {
      targets.set(farLock.id, getGoalkeeperBuildOutPressTarget(teamId, context, "farCenterBackLock"));
      excludedIds.add(farLock.id);
      labels.push("Curve to far CB");
    }
  }

  if (context.directRelease) {
    const secondBall = pickDefensiveAutopilotPlayer(
      groups,
      ["midfield"],
      excludedIds,
      getGoalkeeperBuildOutPressTarget(teamId, context, "secondBallScreen"),
      ["6", "8"]
    );
    if (secondBall) {
      targets.set(secondBall.id, getGoalkeeperBuildOutPressTarget(teamId, context, "secondBallScreen"));
      excludedIds.add(secondBall.id);
      labels.push("Win second ball");
    }

    const restCover = pickDefensiveAutopilotPlayer(
      groups,
      ["back"],
      excludedIds,
      getGoalkeeperBuildOutPressTarget(teamId, context, "restCover"),
      ["CB"]
    );
    if (restCover) {
      targets.set(restCover.id, getGoalkeeperBuildOutPressTarget(teamId, context, "restCover"));
      labels.push("Rest cover behind release");
    }
  }

  return {
    presser,
    labels,
  };
}

function getDefensiveThreatResponse(teamId, ballPoint = state.ball.target ?? state.ball.position) {
  const attackingTeamId = getOtherTeamId(teamId);
  const threat = attackingTeamId
    ? getPitchThreatProfile(ballPoint, attackingTeamId)
    : {
        value: 0,
        goldenZone: 0,
        centralPocket: 0,
        betweenLines: 0,
        box: 0,
        assistZone: 0,
        cutbackZone: 0,
        halfSpace: 0,
        centrality: 0,
        depth: 0,
        primaryLabel: "open space",
      };
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, ballPoint);
  const centrality = 1 - Math.abs(ballPoint.y - pitch.width / 2) / (pitch.width / 2);
  const protectCenter = clamp(
    threat.value * 0.52 +
      threat.centralPocket * 0.3 +
      threat.betweenLines * 0.2 +
      threat.box * 0.42 +
      threat.cutbackZone * 0.28 +
      threat.halfSpace * 0.16 +
      centrality * 0.12 -
      (ballFromOwnGoal > 64 ? 0.16 : 0),
    0,
    1
  );
  const immediatePressure = clamp(
    protectCenter * 0.72 +
      threat.box * 0.26 +
      (ballFromOwnGoal <= 35 ? 0.16 : 0) +
      (threat.assistZone >= 0.45 ? 0.08 : 0),
    0,
    1
  );

  return {
    threat,
    protectCenter,
    immediatePressure,
    isGoldenZoneThreat: threat.centralPocket >= 0.42 || threat.betweenLines >= 0.54,
    isBoxThreat: threat.box >= 0.34,
    isWideAssistThreat: threat.assistZone >= 0.48,
    ballFromOwnGoal,
  };
}

function getDefensivePrioritySpacePoint(teamId, ballPoint, profile, slot = "screen") {
  const attackingTeamId = getOtherTeamId(teamId);
  const ownPenaltySpot = attackingTeamId
    ? getOpponentPenaltySpot(attackingTeamId)
    : vec(teamId === "home" ? 11 : pitch.length - 11, pitch.width / 2);
  const sign = getDefendingDirectionSign(teamId);
  const protectCenter = profile.threatResponse?.protectCenter ?? 0;
  const ballSide = getWideSideSign(ballPoint) || 1;
  const points = {
    screen: {
      x: lerp(ballPoint.x, ownPenaltySpot.x, 0.28 + protectCenter * 0.18),
      y: lerp(ballPoint.y, pitch.width / 2, 0.58 + protectCenter * 0.18),
    },
    cover: {
      x: ownPenaltySpot.x + sign * 3.4,
      y: pitch.width / 2,
    },
    farPost: {
      x: ownPenaltySpot.x + sign * 1.2,
      y: pitch.width / 2 - ballSide * 9.8,
    },
    cutback: {
      x: ownPenaltySpot.x + sign * 8.8,
      y: pitch.width / 2 + ballSide * 2.4,
    },
  };

  return clampToPitch(points[slot] ?? points.screen, 3);
}

function pickDefensiveProtectionPlayer(teamId, groups, targets, excludedIds, lineKeys, referencePoint) {
  const candidates = lineKeys
    .flatMap((lineKey) => groups[lineKey] ?? [])
    .filter((player) => player.team === teamId && !excludedIds.has(player.id) && !isGoalkeeper(player));

  if (!candidates.length) {
    return null;
  }

  return candidates
    .map((player) => {
      const target = targets.get(player.id) ?? player.position;
      const label = getPlayerMagnetLabel(player);
      const centralRoleBonus = label === "6" || label === "8" || label === "CB" ? 0.42 : label === "10" ? 0.18 : 0;
      const centrality = 1 - Math.abs(target.y - pitch.width / 2) / (pitch.width / 2);
      return {
        player,
        score:
          distance(player.position, referencePoint) * 0.42 +
          distance(target, referencePoint) * 0.34 -
          centrality * 2.2 -
          centralRoleBonus,
      };
    })
    .sort((a, b) => a.score - b.score)[0]?.player ?? null;
}

function applyDefensivePrioritySpaceProtectionTargets(
  teamId,
  targets,
  groups,
  presser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const response = profile.threatResponse;
  if (!response || response.protectCenter < 0.34) {
    return [];
  }

  const labels = [];
  const excludedIds = new Set([
    ...protectedIds,
    presser?.id,
  ].filter(Boolean));
  const screenPoint = getDefensivePrioritySpacePoint(teamId, ballPoint, profile, "screen");
  const screen = pickDefensiveProtectionPlayer(
    teamId,
    groups,
    targets,
    excludedIds,
    ["midfield", "back"],
    screenPoint
  );
  if (screen) {
    targets.set(screen.id, screenPoint);
    excludedIds.add(screen.id);
    labels.push(`Protect ${response.threat.primaryLabel}`);
  }

  if (response.protectCenter >= 0.56 || response.isBoxThreat) {
    const coverPoint = getDefensivePrioritySpacePoint(teamId, ballPoint, profile, "cover");
    const cover = pickDefensiveProtectionPlayer(teamId, groups, targets, excludedIds, ["back"], coverPoint);
    if (cover) {
      targets.set(cover.id, coverPoint);
      excludedIds.add(cover.id);
      labels.push("Goal-side cover");
    }
  }

  if (response.isWideAssistThreat || response.isBoxThreat) {
    const farPostPoint = getDefensivePrioritySpacePoint(teamId, ballPoint, profile, "farPost");
    const farPostDefender = pickDefensiveProtectionPlayer(teamId, groups, targets, excludedIds, ["back", "midfield"], farPostPoint);
    if (farPostDefender) {
      targets.set(farPostDefender.id, farPostPoint);
      excludedIds.add(farPostDefender.id);
      labels.push("Far-post cover");
    }

    const cutbackPoint = getDefensivePrioritySpacePoint(teamId, ballPoint, profile, "cutback");
    const cutbackScreen = pickDefensiveProtectionPlayer(teamId, groups, targets, excludedIds, ["midfield"], cutbackPoint);
    if (cutbackScreen) {
      targets.set(cutbackScreen.id, cutbackPoint);
      labels.push("Cutback screen");
    }
  }

  return labels;
}

function getDefensiveCornerContext(teamId, ballPoint) {
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    beforeSnapshot: {
      restartPhase: cloneRestartPhase(state.restartPhase),
      ball: {
        position: cloneVector(state.ball.position),
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const restart = actionMeta.beforeSnapshot?.restartPhase ?? state.restartPhase;
  if (restart?.type !== "corner" || restart.teamId === teamId || getOtherTeamId(restart.teamId) !== teamId) {
    return null;
  }

  const sideY = Number.isFinite(restart.sideY)
    ? restart.sideY
    : actionMeta.beforeSnapshot?.ball?.position?.y ?? ballPoint.y;
  const attackingTeamId = restart.teamId;
  const sign = getDefendingDirectionSign(teamId);
  const ownGoalX = teamId === "home" ? 0 : pitch.length;
  const sideSign = sideY <= pitch.width / 2 ? -1 : 1;
  const cornerSpot = actionMeta.beforeSnapshot?.ball?.position ?? getCornerKickSpot(attackingTeamId, sideY);
  const deliveryTarget = actionMeta.target ?? ballPoint;

  return {
    actionMeta,
    attackingTeamId,
    sideY,
    sideSign,
    ownGoalX,
    sign,
    cornerSpot: cloneVector(cornerSpot),
    deliveryTarget: cloneVector(deliveryTarget),
    isShortCorner: distance(cornerSpot, deliveryTarget) <= 13,
  };
}

function getDefensiveCornerTarget(teamId, context, slot) {
  const { ownGoalX, sign, sideSign, cornerSpot, deliveryTarget } = context;
  const points = {
    goalkeeper: {
      x: ownGoalX + sign * 2.4,
      y: clamp(lerp(pitch.width / 2, deliveryTarget.y, 0.1), pitch.width / 2 - 2.2, pitch.width / 2 + 2.2),
    },
    nearPost: {
      x: ownGoalX + sign * 2.7,
      y: pitch.width / 2 + sideSign * 3.05,
    },
    farPost: {
      x: ownGoalX + sign * 2.9,
      y: pitch.width / 2 - sideSign * 3.15,
    },
    sixYardCentral: {
      x: ownGoalX + sign * 5.7,
      y: pitch.width / 2 + sideSign * 0.9,
    },
    penaltySpot: {
      x: ownGoalX + sign * 10.8,
      y: pitch.width / 2 - sideSign * 0.6,
    },
    nearZone: {
      x: ownGoalX + sign * 7.6,
      y: pitch.width / 2 + sideSign * 6.6,
    },
    farZone: {
      x: ownGoalX + sign * 8.9,
      y: pitch.width / 2 - sideSign * 8.4,
    },
    edgeSecondBall: {
      x: ownGoalX + sign * 18.2,
      y: pitch.width / 2 - sideSign * 4.6,
    },
    shortCornerPress: {
      x: lerp(cornerSpot.x, ownGoalX + sign * 12.5, 0.55),
      y: lerp(cornerSpot.y, pitch.width / 2 + sideSign * 15, 0.44),
    },
    clearanceOutlet: {
      x: ownGoalX + sign * 25,
      y: pitch.width / 2 - sideSign * 18,
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 1.8);
}

function applyDefensiveCornerSetPieceTargets(teamId, targets, groups, ballPoint, profile) {
  const context = getDefensiveCornerContext(teamId, ballPoint);
  if (!context) {
    return {
      active: false,
      presser: null,
      labels: [],
      focusPoint: null,
    };
  }

  const labels = [];
  const excludedIds = new Set();
  let presser = null;

  groups.gk.forEach((goalkeeper) => {
    targets.set(goalkeeper.id, getDefensiveCornerTarget(teamId, context, "goalkeeper"));
    excludedIds.add(goalkeeper.id);
    labels.push("GK controls six-yard line");
  });

  const nearPost = pickDefensiveAutopilotPlayer(
    groups,
    ["back", "midfield"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "nearPost"),
    ["CB", "LB", "RB", "WB"]
  );
  if (nearPost) {
    targets.set(nearPost.id, getDefensiveCornerTarget(teamId, context, "nearPost"));
    excludedIds.add(nearPost.id);
    labels.push("Near-post protection");
  }

  const farPost = pickDefensiveAutopilotPlayer(
    groups,
    ["back", "midfield"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "farPost"),
    ["CB", "LB", "RB", "WB"]
  );
  if (farPost) {
    targets.set(farPost.id, getDefensiveCornerTarget(teamId, context, "farPost"));
    excludedIds.add(farPost.id);
    labels.push("Far-post protection");
  }

  const sixYard = pickDefensiveAutopilotPlayer(
    groups,
    ["back"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "sixYardCentral"),
    ["CB"]
  );
  if (sixYard) {
    targets.set(sixYard.id, getDefensiveCornerTarget(teamId, context, "sixYardCentral"));
    excludedIds.add(sixYard.id);
    labels.push("Six-yard zone");
  }

  const penaltySpot = pickDefensiveAutopilotPlayer(
    groups,
    ["back", "midfield"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "penaltySpot"),
    ["CB", "6", "8"]
  );
  if (penaltySpot) {
    targets.set(penaltySpot.id, getDefensiveCornerTarget(teamId, context, "penaltySpot"));
    excludedIds.add(penaltySpot.id);
    labels.push("Penalty-spot duel");
  }

  const nearZone = pickDefensiveAutopilotPlayer(
    groups,
    ["midfield", "back"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "nearZone"),
    ["6", "8", "WB", "LB", "RB"]
  );
  if (nearZone) {
    targets.set(nearZone.id, getDefensiveCornerTarget(teamId, context, "nearZone"));
    excludedIds.add(nearZone.id);
    labels.push("Near-zone screen");
  }

  const farZone = pickDefensiveAutopilotPlayer(
    groups,
    ["midfield", "back"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "farZone"),
    ["8", "10", "WB", "LB", "RB"]
  );
  if (farZone) {
    targets.set(farZone.id, getDefensiveCornerTarget(teamId, context, "farZone"));
    excludedIds.add(farZone.id);
    labels.push("Far-zone screen");
  }

  const edge = pickDefensiveAutopilotPlayer(
    groups,
    ["midfield", "forward"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "edgeSecondBall"),
    ["6", "8", "10"]
  );
  if (edge) {
    targets.set(edge.id, getDefensiveCornerTarget(teamId, context, "edgeSecondBall"));
    excludedIds.add(edge.id);
    labels.push("Edge second ball");
  }

  if (context.isShortCorner) {
    const shortPress = pickDefensiveAutopilotPlayer(
      groups,
      ["forward", "midfield"],
      excludedIds,
      getDefensiveCornerTarget(teamId, context, "shortCornerPress"),
      ["W", "9", "10", "8"]
    );
    if (shortPress) {
      targets.set(shortPress.id, getDefensiveCornerTarget(teamId, context, "shortCornerPress"));
      excludedIds.add(shortPress.id);
      presser = shortPress;
      labels.push("Short-corner pressure");
    }
  }

  const outlet = pickDefensiveAutopilotPlayer(
    groups,
    ["forward"],
    excludedIds,
    getDefensiveCornerTarget(teamId, context, "clearanceOutlet"),
    ["9", "W", "10"]
  );
  if (outlet) {
    targets.set(outlet.id, getDefensiveCornerTarget(teamId, context, "clearanceOutlet"));
    labels.push("Clearance outlet");
  }

  return {
    active: true,
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.cornerSpot,
  };
}

function getRestartActionMeta() {
  return state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    beforeSnapshot: {
      restartPhase: cloneRestartPhase(state.restartPhase),
      ball: {
        position: cloneVector(state.ball.position),
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
}

function getDefensiveFreeKickContext(teamId, ballPoint) {
  const actionMeta = getRestartActionMeta();
  const restart = actionMeta.beforeSnapshot?.restartPhase ?? state.restartPhase;
  if (restart?.type !== "freeKick" || restart.teamId === teamId || getOtherTeamId(restart.teamId) !== teamId) {
    return null;
  }

  const attackingTeamId = restart.teamId;
  const freeKickPoint =
    restart.point ??
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.position ??
    ballPoint;
  const opponentGoal = getOpponentGoalCenter(attackingTeamId);
  const goalDistance = distance(freeKickPoint, opponentGoal);
  const centrality = 1 - Math.abs(freeKickPoint.y - pitch.width / 2) / (pitch.width / 2);
  const shotAngle = getShotAngleQuality(freeKickPoint, attackingTeamId);
  const deliveryTarget = actionMeta.target ?? ballPoint;
  const deliveryDistance = distance(freeKickPoint, deliveryTarget);
  const attackingDepth = getAttackingDepth(freeKickPoint, attackingTeamId);
  const directShotThreat =
    goalDistance <= 31.5 &&
    centrality >= 0.14 &&
    shotAngle >= 0.11 &&
    (actionMeta.actionType === "shot" || deliveryDistance <= 18 || getAttackingDepth(deliveryTarget, attackingTeamId) >= 82);
  const wideDeliveryThreat =
    Math.abs(freeKickPoint.y - pitch.width / 2) >= 13 &&
    attackingDepth >= 58;

  return {
    actionMeta,
    attackingTeamId,
    freeKickPoint: cloneVector(freeKickPoint),
    deliveryTarget: cloneVector(deliveryTarget),
    ownGoalX: teamId === "home" ? 0 : pitch.length,
    sign: getDefendingDirectionSign(teamId),
    sideSign: getWideSideSign(freeKickPoint) || getWideSideSign(deliveryTarget) || 1,
    goalDistance,
    centrality,
    shotAngle,
    directShotThreat,
    wideDeliveryThreat,
    isShortFreeKick: deliveryDistance <= 13.5,
  };
}

function getFreeKickWallTarget(teamId, context, slotIndex = 0, wallCount = 3) {
  const ownGoal = getOwnGoalCenter(teamId);
  const wallBaseDistance = clamp(context.goalDistance > 25 ? 9.15 : 8.35, 7.8, 9.15);
  const base = moveTowards(context.freeKickPoint, ownGoal, wallBaseDistance);
  const lane = normalize(context.freeKickPoint, ownGoal);
  const perpendicular = { x: -lane.y, y: lane.x };
  const spread = clamp((wallCount - 1) * 0.68, 0.72, 2.4);
  const offset = wallCount <= 1 ? 0 : -spread / 2 + (spread * slotIndex) / (wallCount - 1);

  return clampToPitch({
    x: base.x + perpendicular.x * offset,
    y: base.y + perpendicular.y * offset,
  }, 1.6);
}

function getDefensiveFreeKickTarget(teamId, context, slot) {
  const { ownGoalX, sign, sideSign, freeKickPoint, deliveryTarget } = context;
  const wallLeanY = lerp(pitch.width / 2, freeKickPoint.y, 0.12);
  const points = {
    goalkeeper: {
      x: ownGoalX + sign * 1.2,
      y: clamp(lerp(pitch.width / 2, deliveryTarget.y, context.directShotThreat ? 0.1 : 0.18), pitch.width / 2 - 3.05, pitch.width / 2 + 3.05),
    },
    blockerEdge: {
      x: ownGoalX + sign * 19.2,
      y: clamp(wallLeanY - sideSign * 5.2, 7, pitch.width - 7),
    },
    nearZone: {
      x: ownGoalX + sign * 8.7,
      y: pitch.width / 2 + sideSign * 7.8,
    },
    farZone: {
      x: ownGoalX + sign * 9.4,
      y: pitch.width / 2 - sideSign * 8.8,
    },
    penaltySpot: {
      x: ownGoalX + sign * 11.4,
      y: pitch.width / 2 - sideSign * 0.8,
    },
    sixYardCentral: {
      x: ownGoalX + sign * 5.7,
      y: pitch.width / 2 + sideSign * 0.7,
    },
    edgeSecondBall: {
      x: ownGoalX + sign * 18.5,
      y: clamp(pitch.width / 2 - sideSign * 4.8, 7, pitch.width - 7),
    },
    shortFreeKickPress: {
      x: lerp(freeKickPoint.x, deliveryTarget.x, 0.42),
      y: lerp(freeKickPoint.y, deliveryTarget.y, 0.42),
    },
    clearanceOutlet: {
      x: ownGoalX + sign * 26,
      y: pitch.width / 2 - sideSign * 18,
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 1.8);
}

function applyDefensiveFreeKickSetPieceTargets(teamId, targets, groups, ballPoint, profile) {
  const context = getDefensiveFreeKickContext(teamId, ballPoint);
  if (!context) {
    return {
      active: false,
      presser: null,
      labels: [],
      focusPoint: null,
    };
  }

  const labels = [];
  const excludedIds = new Set();
  let presser = null;

  groups.gk.forEach((goalkeeper) => {
    targets.set(goalkeeper.id, getDefensiveFreeKickTarget(teamId, context, "goalkeeper"));
    excludedIds.add(goalkeeper.id);
    labels.push(context.directShotThreat ? "GK sets the wall" : "GK commands delivery line");
  });

  const wallCount = context.directShotThreat
    ? clamp(Math.round(2 + (31.5 - context.goalDistance) / 6 + context.centrality * 1.2), 2, 4)
    : context.wideDeliveryThreat
      ? 1
      : 2;

  for (let index = 0; index < wallCount; index += 1) {
    const wallTarget = getFreeKickWallTarget(teamId, context, index, wallCount);
    const wallPlayer = pickDefensiveAutopilotPlayer(
      groups,
      ["midfield", "forward", "back"],
      excludedIds,
      wallTarget,
      ["6", "8", "10", "W", "9", "CB"]
    );

    if (wallPlayer) {
      targets.set(wallPlayer.id, wallTarget);
      excludedIds.add(wallPlayer.id);
    }
  }

  if (wallCount > 0) {
    labels.push(context.directShotThreat ? "Free-kick wall" : "Short wall");
  }

  if (context.isShortFreeKick) {
    const shortPress = pickDefensiveAutopilotPlayer(
      groups,
      ["forward", "midfield"],
      excludedIds,
      getDefensiveFreeKickTarget(teamId, context, "shortFreeKickPress"),
      ["9", "W", "10", "8"]
    );
    if (shortPress) {
      targets.set(shortPress.id, getDefensiveFreeKickTarget(teamId, context, "shortFreeKickPress"));
      excludedIds.add(shortPress.id);
      presser = shortPress;
      labels.push("Short free-kick pressure");
    }
  }

  const deliverySlots = context.directShotThreat
    ? [
        ["blockerEdge", ["midfield"], ["6", "8", "10"]],
        ["penaltySpot", ["back", "midfield"], ["CB", "6", "8"]],
        ["edgeSecondBall", ["midfield", "forward"], ["6", "8", "10"]],
      ]
    : [
        ["sixYardCentral", ["back"], ["CB"]],
        ["nearZone", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"]],
        ["farZone", ["back", "midfield"], ["CB", "LB", "RB", "WB"]],
        ["penaltySpot", ["back", "midfield"], ["CB", "6", "8"]],
        ["edgeSecondBall", ["midfield", "forward"], ["6", "8", "10"]],
      ];

  deliverySlots.forEach(([slot, lineKeys, preferLabels]) => {
    const target = getDefensiveFreeKickTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, excludedIds, target, preferLabels);
    if (player) {
      targets.set(player.id, target);
      excludedIds.add(player.id);
    }
  });

  labels.push(context.directShotThreat ? "Rebound and block line" : "Box delivery protection");

  const outlet = pickDefensiveAutopilotPlayer(
    groups,
    ["forward"],
    excludedIds,
    getDefensiveFreeKickTarget(teamId, context, "clearanceOutlet"),
    ["9", "W", "10"]
  );
  if (outlet) {
    targets.set(outlet.id, getDefensiveFreeKickTarget(teamId, context, "clearanceOutlet"));
    labels.push("Clearance outlet");
  }

  return {
    active: true,
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.freeKickPoint,
  };
}

function getDefensivePenaltyContext(teamId, ballPoint) {
  const actionMeta = getRestartActionMeta();
  const restart = actionMeta.beforeSnapshot?.restartPhase ?? state.restartPhase;
  if (restart?.type !== "penalty" || restart.teamId === teamId || getOtherTeamId(restart.teamId) !== teamId) {
    return null;
  }

  const attackingTeamId = restart.teamId;
  const penaltyPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    getOpponentPenaltySpot(attackingTeamId);

  return {
    actionMeta,
    attackingTeamId,
    penaltyPoint: cloneVector(penaltyPoint),
    ownGoalX: teamId === "home" ? 0 : pitch.length,
    sign: getDefendingDirectionSign(teamId),
    sideSign: getWideSideSign(ballPoint) || 1,
  };
}

function getDefensivePenaltyTarget(teamId, context, slot) {
  const { ownGoalX, sign, sideSign } = context;
  const points = {
    goalkeeper: {
      x: ownGoalX + sign * 0.55,
      y: pitch.width / 2,
    },
    reboundLeft: {
      x: ownGoalX + sign * 18.1,
      y: pitch.width / 2 - 8.3,
    },
    reboundRight: {
      x: ownGoalX + sign * 18.1,
      y: pitch.width / 2 + 8.3,
    },
    arcScreen: {
      x: ownGoalX + sign * 20.4,
      y: pitch.width / 2,
    },
    farClearance: {
      x: ownGoalX + sign * 24.6,
      y: pitch.width / 2 - sideSign * 15.2,
    },
    wideClearance: {
      x: ownGoalX + sign * 26.5,
      y: pitch.width / 2 + sideSign * 19,
    },
  };

  return clampToPitch(points[slot] ?? points.arcScreen, 1.5);
}

function applyDefensivePenaltySetPieceTargets(teamId, targets, groups, ballPoint, profile) {
  const context = getDefensivePenaltyContext(teamId, ballPoint);
  if (!context) {
    return {
      active: false,
      presser: null,
      labels: [],
      focusPoint: null,
    };
  }

  const labels = [];
  const excludedIds = new Set();

  groups.gk.forEach((goalkeeper) => {
    targets.set(goalkeeper.id, getDefensivePenaltyTarget(teamId, context, "goalkeeper"));
    excludedIds.add(goalkeeper.id);
    labels.push("GK on penalty line");
  });

  [
    ["reboundLeft", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"]],
    ["reboundRight", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"]],
    ["arcScreen", ["midfield", "forward"], ["6", "8", "10"]],
    ["farClearance", ["forward", "midfield"], ["9", "W", "10"]],
    ["wideClearance", ["forward", "midfield"], ["W", "9", "10"]],
  ].forEach(([slot, lineKeys, preferLabels]) => {
    const target = getDefensivePenaltyTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, excludedIds, target, preferLabels);
    if (player) {
      targets.set(player.id, target);
      excludedIds.add(player.id);
    }
  });

  labels.push("Penalty rebound line", "Clearance outlets");

  return {
    active: true,
    presser: null,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.penaltyPoint,
  };
}

function getDefensiveThrowInContext(teamId, ballPoint) {
  const actionMeta = getRestartActionMeta();
  const restart = actionMeta.beforeSnapshot?.restartPhase ?? state.restartPhase;
  if (restart?.type !== "throwIn" || restart.teamId === teamId || getOtherTeamId(restart.teamId) !== teamId) {
    return null;
  }

  const throwPoint =
    restart.point ??
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.position ??
    ballPoint;
  const sideSign = getWideSideSign(throwPoint) || (throwPoint.y <= pitch.width / 2 ? -1 : 1);

  return {
    actionMeta,
    attackingTeamId: restart.teamId,
    throwPoint: cloneVector(throwPoint),
    deliveryTarget: cloneVector(actionMeta.target ?? ballPoint),
    sign: getDefendingDirectionSign(teamId),
    sideSign,
    ownGoalX: teamId === "home" ? 0 : pitch.length,
    isShortThrow: distance(throwPoint, actionMeta.target ?? ballPoint) <= 12.5,
  };
}

function getDefensiveThrowInTarget(teamId, context, slot) {
  const { throwPoint, deliveryTarget, sign, sideSign, ownGoalX } = context;
  const insideY = clamp(throwPoint.y - sideSign * 7.5, 4, pitch.width - 4);
  const points = {
    twoMeterPress: moveTowards(
      {
        x: throwPoint.x,
        y: insideY,
      },
      throwPoint,
      Math.max(distance({ x: throwPoint.x, y: insideY }, throwPoint) - 2.15, 0)
    ),
    receiverPress: {
      x: lerp(throwPoint.x, deliveryTarget.x, 0.58),
      y: lerp(insideY, deliveryTarget.y, 0.44),
    },
    insideScreen: {
      x: clamp(throwPoint.x - sign * 3.8, 4, pitch.length - 4),
      y: clamp(insideY - sideSign * 5.4, 7, pitch.width - 7),
    },
    downLineCover: {
      x: clamp(throwPoint.x - sign * 9.4, 4, pitch.length - 4),
      y: clamp(throwPoint.y - sideSign * 2.4, 3.2, pitch.width - 3.2),
    },
    backLineCover: {
      x: ownGoalX + sign * 24,
      y: clamp(insideY - sideSign * 9.5, 8, pitch.width - 8),
    },
    centralScreen: {
      x: ownGoalX + sign * 34,
      y: lerp(pitch.width / 2, insideY, 0.35),
    },
  };

  return clampToPitch(points[slot] ?? points.insideScreen, 1.8);
}

function applyDefensiveThrowInSetPieceTargets(teamId, targets, groups, ballPoint, profile) {
  const context = getDefensiveThrowInContext(teamId, ballPoint);
  if (!context) {
    return {
      active: false,
      presser: null,
      labels: [],
      focusPoint: null,
    };
  }

  const labels = [];
  const excludedIds = new Set(groups.gk.map((goalkeeper) => goalkeeper.id));
  let presser = null;

  const firstPress = pickDefensiveAutopilotPlayer(
    groups,
    ["forward", "midfield"],
    excludedIds,
    getDefensiveThrowInTarget(teamId, context, "twoMeterPress"),
    ["W", "9", "10", "8", "WB"]
  );
  if (firstPress) {
    targets.set(firstPress.id, getDefensiveThrowInTarget(teamId, context, "twoMeterPress"));
    excludedIds.add(firstPress.id);
    presser = firstPress;
    labels.push("Two-metre throw-in pressure");
  }

  const receiverPress = pickDefensiveAutopilotPlayer(
    groups,
    ["midfield", "back"],
    excludedIds,
    getDefensiveThrowInTarget(teamId, context, "receiverPress"),
    ["WB", "LB", "RB", "6", "8"]
  );
  if (receiverPress) {
    targets.set(receiverPress.id, getDefensiveThrowInTarget(teamId, context, "receiverPress"));
    excludedIds.add(receiverPress.id);
    labels.push("Receiver touch pressure");
  }

  [
    ["insideScreen", ["midfield"], ["6", "8", "10"]],
    ["downLineCover", ["back", "midfield"], ["LB", "RB", "WB", "CB"]],
    ["backLineCover", ["back"], ["CB", "LB", "RB", "WB"]],
    ["centralScreen", ["midfield", "forward"], ["6", "8", "10", "9"]],
  ].forEach(([slot, lineKeys, preferLabels]) => {
    const target = getDefensiveThrowInTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, excludedIds, target, preferLabels);
    if (player) {
      targets.set(player.id, target);
      excludedIds.add(player.id);
    }
  });

  labels.push("Touchline trap", "Inside lane cover");

  return {
    active: true,
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.throwPoint,
  };
}

function getNegativeTransitionContext(teamId, ballPoint = state.ball.target ?? state.ball.position, profile = null) {
  const secure =
    state.ball.securePossession ??
    state.draftStep?.beforeSnapshot?.ball?.securePossession ??
    null;
  if (!secure?.ownerPlayerId || !secure?.opponentPlayerId || state.restartPhase?.type) {
    return { active: false };
  }

  const newOwner = getPlayerById(secure.ownerPlayerId);
  const playerWhoLostIt = getPlayerById(secure.opponentPlayerId);
  if (!newOwner || !playerWhoLostIt || playerWhoLostIt.team !== teamId || newOwner.team === teamId) {
    return { active: false };
  }

  const plannedPossessionTeamId = getPlannedPossessionTeamId();
  if (plannedPossessionTeamId && plannedPossessionTeamId !== newOwner.team) {
    return { active: false };
  }

  const lossPoint = secure.point ?? playerWhoLostIt.position ?? ballPoint;
  const elapsed = Math.max(0, state.time - (secure.createdAt ?? state.time));
  const distanceFromLoss = distance(ballPoint, lossPoint);
  const freshness = clamp(
    1 - Math.max(distanceFromLoss / 19.5, elapsed / 4.4),
    0,
    1
  );
  if (freshness <= 0.08) {
    return { active: false };
  }

  const styleKey = getTeamDefenseStyleKey(teamId);
  const styleProfile = getTeamDefenseStyleProfile(teamId);
  const resolvedProfile = profile ?? getDefensiveAutopilotProfile(teamId, ballPoint);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, ballPoint);
  const dangerToOwnGoal = clamp((47 - ballFromOwnGoal) / 29, 0, 1);
  const counterPressStyleBonus = ["counter-press", "gegenpress", "high-press", "press-trap-wide"].includes(styleKey)
    ? 0.18
    : 0;
  const recoveryStyleBonus = ["low-block", "protect-box", "park-the-bus", "catenaccio"].includes(styleKey)
    ? 0.2
    : 0;
  const counterPressIntent = clamp(
    resolvedProfile.pressingIntensity * 0.36 +
      resolvedProfile.tackleIntent * 0.22 +
      freshness * 0.3 +
      counterPressStyleBonus +
      (secure.reason === "interception" ? 0.08 : 0),
    0,
    1
  );
  const recoveryIntent = clamp(
    (1 - resolvedProfile.pressingIntensity) * 0.34 +
      dangerToOwnGoal * 0.34 +
      recoveryStyleBonus +
      (freshness < 0.45 ? 0.1 : 0),
    0,
    1
  );

  return {
    active: true,
    mode: counterPressIntent >= Math.max(0.58, recoveryIntent * 0.86)
      ? "counterPress"
      : "delayRecover",
    teamId,
    winningTeamId: newOwner.team,
    newOwner,
    playerWhoLostIt,
    ballPoint: cloneVector(ballPoint),
    lossPoint: cloneVector(lossPoint),
    freshness,
    counterPressIntent,
    recoveryIntent,
    styleKey,
    styleLabel: styleProfile.label,
    dangerToOwnGoal,
  };
}

function getNegativeTransitionTarget(teamId, context, slot, outlet = null) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const { ballPoint, lossPoint, freshness } = context;
  const sideSign = getWideSideSign(ballPoint) || getWideSideSign(lossPoint) || 1;
  const counterRadius = lerp(5.6, 2.8, freshness);
  const goalSideX = (meters) => ballPoint.x - sign * meters;
  const outletPoint = outlet?.position ?? outlet?.point ?? ballPoint;
  const outletCentrality = 1 - Math.abs(outletPoint.y - pitch.width / 2) / (pitch.width / 2);
  const points = {
    pressBall: {
      x: goalSideX(lerp(1.8, 0.7, freshness)),
      y: lerp(ballPoint.y, pitch.width / 2, 0.08),
    },
    lockInside: {
      x: goalSideX(5.4),
      y: lerp(ballPoint.y, pitch.width / 2, 0.58),
    },
    lockFirstPassNear: {
      x: goalSideX(3.8),
      y: ballPoint.y - sideSign * counterRadius,
    },
    lockFirstPassFar: {
      x: goalSideX(6.4),
      y: ballPoint.y + sideSign * (counterRadius + 1.8),
    },
    passBackTrap: {
      x: lerp(lossPoint.x, ballPoint.x, 0.36) + sign * 1.6,
      y: lerp(lossPoint.y, ballPoint.y, 0.52),
    },
    outletLock: {
      x: lerp(outletPoint.x, ballPoint.x, 0.24) - sign * lerp(0.8, 1.55, outletCentrality),
      y: lerp(outletPoint.y, pitch.width / 2, outletCentrality >= 0.55 ? 0.26 : 0.12),
    },
    touchlineCage: {
      x: goalSideX(3.2),
      y: clamp(ballPoint.y + sideSign * 4.4, 3.2, pitch.width - 3.2),
    },
    restDefence: {
      x: lerp(ballPoint.x, ownGoal.x, 0.38),
      y: pitch.width / 2,
    },
    delayPress: {
      x: goalSideX(2.2),
      y: lerp(ballPoint.y, pitch.width / 2, 0.18),
    },
    recoverScreen: {
      x: lerp(ballPoint.x, ownGoal.x, 0.26),
      y: lerp(ballPoint.y, pitch.width / 2, 0.62),
    },
    recoverBackLine: {
      x: lerp(ballPoint.x, ownGoal.x, 0.48),
      y: pitch.width / 2 - sideSign * 4.8,
    },
  };

  return clampToPitch(points[slot] ?? points.lockInside, 2.2);
}

function getNegativeTransitionOutletOptions(context) {
  const attackSign = getAttackDirectionSign(context.winningTeamId);
  const ballSide = getWideSideSign(context.ballPoint) || 1;
  return state.players
    .filter((player) =>
      player.team === context.winningTeamId &&
      player.id !== context.newOwner?.id &&
      !isGoalkeeper(player)
    )
    .map((player) => {
      const position = cloneVector(player.position);
      const gap = distance(position, context.ballPoint);
      if (gap < 4.2 || gap > 32) {
        return null;
      }

      const threat = getPitchThreatProfile(position, context.winningTeamId);
      const forwardGap = (position.x - context.ballPoint.x) * attackSign;
      const centrality = 1 - Math.abs(position.y - pitch.width / 2) / (pitch.width / 2);
      const sameSide = getWideSideSign(position) === ballSide;
      const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
      const outletScore =
        threat.value * 0.48 +
        threat.centralPocket * 0.34 +
        threat.betweenLines * 0.24 +
        threat.behindLine * 0.2 +
        centrality * 0.16 +
        clamp(forwardGap / 18, -0.08, 0.3) +
        clamp((24 - gap) / 24, 0, 0.24) +
        (sameSide ? 0.08 : 0) +
        (["connector", "wideForward", "secondStriker", "striker"].includes(roleKey) ? 0.12 : 0);

      return {
        player,
        position,
        threat,
        gap,
        forwardGap,
        centrality,
        sameSide,
        roleKey,
        outletScore,
      };
    })
    .filter(Boolean)
    .filter((option) => option.outletScore >= 0.06)
    .sort((a, b) => b.outletScore - a.outletScore)
    .slice(0, 4);
}

function applyNegativeTransitionDefensiveTargets(teamId, targets, groups, ballPoint, profile) {
  const context = getNegativeTransitionContext(teamId, ballPoint, profile);
  if (!context.active) {
    return {
      active: false,
      presser: null,
      labels: [],
      focusPoint: null,
      mode: null,
      protectedIds: new Set(),
    };
  }

  const labels = [];
  const assignedIds = new Set(groups.gk.map((goalkeeper) => goalkeeper.id));
  let presser = null;
  const outlets = getNegativeTransitionOutletOptions(context);
  const assign = (slot, lineKeys, preferLabels, label, outlet = null) => {
    const target = getNegativeTransitionTarget(teamId, context, slot, outlet);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (context.mode === "counterPress") {
    presser = assign(
      "pressBall",
      ["forward", "midfield", "back"],
      ["9", "10", "W", "8", "6"],
      "Counter-press first touch"
    );

    [
      ["lockInside", ["midfield", "back"], ["6", "8", "CB"], "Counter-press cage: close inside"],
      ["lockFirstPassNear", ["midfield", "forward"], ["8", "10", "W", "6"], "Counter-press cage: near outlet"],
      ["passBackTrap", ["forward", "midfield"], ["9", "10", "W", "8"], "Counter-press cage: trap backwards pass"],
    ].forEach(([slot, lineKeys, preferLabels, label]) => {
      assign(slot, lineKeys, preferLabels, label);
    });

    outlets.slice(0, context.counterPressIntent >= 0.66 ? 2 : 1).forEach((outlet, index) => {
      assign(
        "outletLock",
        index === 0 ? ["midfield", "forward", "back"] : ["midfield", "back", "forward"],
        outlet.centrality >= 0.55
          ? ["6", "8", "10", "CB"]
          : ["W", "8", "LB", "RB", "WB", "10"],
        index === 0 ? "Counter-press cage: lock best outlet" : "Counter-press cage: lock second outlet",
        outlet
      );
    });

    if (isWidePrincipleZone(context.ballPoint)) {
      assign(
        "touchlineCage",
        ["back", "midfield", "forward"],
        ["WB", "LB", "RB", "W", "8"],
        "Counter-press cage: use touchline"
      );
    }

    assign("restDefence", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Rest-defence behind counter-press");
  } else {
    presser = assign(
      "delayPress",
      ["forward", "midfield"],
      ["9", "10", "W", "8"],
      "Delay the first action"
    );

    [
      ["recoverScreen", ["midfield"], ["6", "8", "10"], "Recovery transition: screen centre"],
      ["recoverBackLine", ["back"], ["CB", "LB", "RB", "WB"], "Recovery transition: rebuild back line"],
      ["lockInside", ["midfield", "back"], ["6", "8", "CB"], "Recovery transition: protect inside"],
      ["restDefence", ["back", "midfield"], ["CB", "6"], "Recovery transition: protect depth"],
    ].forEach(([slot, lineKeys, preferLabels, label]) => {
      assign(slot, lineKeys, preferLabels, label);
    });

    outlets.slice(0, 1).forEach((outlet) => {
      assign(
        "outletLock",
        ["midfield", "back", "forward"],
        ["6", "8", "10", "CB", "W"],
        "Recovery transition: delay forward outlet",
        outlet
      );
    });
  }

  return {
    active: true,
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.mode === "counterPress" ? context.ballPoint : context.lossPoint,
    mode: context.mode,
    protectedIds: assignedIds,
  };
}

function getDefensiveLooseBallRecoveryTrapContext(teamId, ballPoint, profile) {
  if (!ballPoint || state.restartPhase?.type) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    profileKey: state.ball.profileKey,
    targetKind: state.ball.targetKind,
  };
  const isRecoveryAction =
    actionMeta.actionType === "recovery" ||
    actionMeta.profileKey === "loose-ball-recovery" ||
    state.ball.actionType === "recovery" ||
    state.ball.profileKey === "loose-ball-recovery";

  if (!isRecoveryAction) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  const collector = getPlayerById(actionMeta.carrierPlayerId ?? state.ball.carrierPlayerId);
  if (!attackingTeamId || !collector || collector.team !== attackingTeamId) {
    return null;
  }

  const targetPoint = cloneVector(actionMeta.target ?? ballPoint);
  const attackingProfile = getOffensiveAutopilotProfile(attackingTeamId, targetPoint);
  const threat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(collector) ||
    1;
  const closeAccess = state.players.reduce((count, player) => {
    if (player.team !== teamId || isGoalkeeper(player)) {
      return count;
    }

    return count + (distance(player.position, targetPoint) <= 15.5 ? 1 : 0);
  }, 0);
  const pressStyle = ["counter-press", "gegenpress", "high-press", "press-trap-wide"].includes(profile.styleKey);
  const protectStyle = ["low-block", "protect-box", "park-the-bus", "catenaccio"].includes(profile.styleKey);
  const recoveryDuration = state.ball.recoveryDuration ?? actionMeta.recoveryDuration ?? 1.2;
  const counterPressIntent = clamp(
    profile.pressingIntensity * 0.44 +
      profile.tackleIntent * 0.22 +
      clamp(closeAccess / 3, 0, 1) * 0.2 +
      (pressStyle ? 0.18 : 0) -
      (protectStyle && ballFromOwnGoal <= 32 ? 0.12 : 0),
    0,
    1
  );
  const protectIntent = clamp(
    (1 - profile.pressingIntensity) * 0.26 +
      clamp((38 - ballFromOwnGoal) / 26, 0, 1) * 0.34 +
      (protectStyle ? 0.18 : 0) +
      threat.value * 0.12,
    0,
    1
  );
  const mode =
    counterPressIntent >= Math.max(0.52, protectIntent * 0.9) && closeAccess >= 1
      ? "counterPressRecovery"
      : "delayRecovery";

  return {
    actionMeta,
    attackingTeamId,
    collector,
    targetPoint,
    threat,
    ballFromOwnGoal,
    sideSign,
    closeAccess,
    counterPressIntent,
    protectIntent,
    mode,
    recoveryDuration,
    attackingDirectness: attackingProfile.directness ?? 0.52,
    attackingWidth: attackingProfile.widthDiscipline ?? 0.62,
  };
}

function getDefensiveLooseBallRecoveryTrapTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const attackSign = getAttackDirectionSign(context.attackingTeamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const underPassPoint = {
    x: ball.x - attackSign * (8.5 + context.counterPressIntent * 2.2),
    y: lerp(ball.y, pitch.width / 2, 0.36),
  };
  const forwardOutletPoint = {
    x: ball.x + attackSign * lerp(10, 17, context.attackingDirectness),
    y: clamp(lerp(ball.y, pitch.width / 2 - sideSign * 8, 0.34), 7, pitch.width - 7),
  };
  const widthExitPoint = {
    x: ball.x + attackSign * 4.8,
    y: clamp(pitch.width / 2 + sideSign * lerp(22, 30, context.attackingWidth), 4, pitch.width - 4),
  };
  const pressDistance = context.mode === "counterPressRecovery" ? 0.75 : 1.75;
  const points = {
    pressCollector: {
      ...goalSideOf(ball, pressDistance),
      y: lerp(ball.y, pitch.width / 2, context.mode === "counterPressRecovery" ? 0.1 : 0.22),
    },
    insideCover: {
      ...goalSideOf(ball, context.mode === "counterPressRecovery" ? 4.2 : 6.2),
      y: lerp(ball.y, pitch.width / 2, 0.72),
    },
    underPassLock: {
      ...goalSideOf(underPassPoint, 1.15),
      y: lerp(underPassPoint.y, pitch.width / 2, 0.32),
    },
    forwardOutletLock: {
      ...goalSideOf(forwardOutletPoint, context.threat.behindLine >= 0.18 ? 2.1 : 1.3),
      y: lerp(forwardOutletPoint.y, pitch.width / 2, 0.18),
    },
    widthExitLock: {
      ...goalSideOf(widthExitPoint, 1.2),
      y: clamp(widthExitPoint.y - sideSign * 2.4, 3.5, pitch.width - 3.5),
    },
    restCover: {
      x: lerp(ball.x, ownGoal.x, context.ballFromOwnGoal <= 34 ? 0.5 : 0.36),
      y: clamp(lerp(ball.y, pitch.width / 2, 0.72), 11, pitch.width - 11),
    },
    weakSideTuck: {
      x: lerp(ball.x, ownGoal.x, context.ballFromOwnGoal <= 42 ? 0.44 : 0.32),
      y: clamp(pitch.width / 2 - sideSign * 9.6, 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.pressCollector, 2.1);
}

function applyDefensiveLooseBallRecoveryTrapTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveLooseBallRecoveryTrapContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const pressTarget = getDefensiveLooseBallRecoveryTrapTarget(teamId, context, "pressCollector");
  const basePresserFits =
    presser &&
    !isGoalkeeper(presser) &&
    distance(presser.position, pressTarget) <= (context.mode === "counterPressRecovery" ? 19 : 15);

  if (!basePresserFits) {
    presser = pickDefensiveAutopilotPlayer(
      groups,
      context.mode === "counterPressRecovery"
        ? ["forward", "midfield", "back"]
        : ["midfield", "forward", "back"],
      assignedIds,
      pressTarget,
      context.mode === "counterPressRecovery"
        ? ["9", "10", "W", "8", "6"]
        : ["6", "8", "10", "W", "CB"]
    );
  }

  if (presser) {
    targets.set(presser.id, pressTarget);
    assignedIds.add(presser.id);
    labels.push(
      context.mode === "counterPressRecovery"
        ? "Recovery trap: press collector"
        : "Recovery trap: delay collector"
    );
  }

  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveLooseBallRecoveryTrapTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("insideCover", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Recovery trap: close inside");
  assign("underPassLock", ["midfield", "forward"], ["8", "10", "6", "9", "W"], "Recovery trap: lock safe pass");

  if (context.mode === "counterPressRecovery" || context.ballFromOwnGoal <= 52) {
    assign("forwardOutletLock", ["back", "midfield", "forward"], ["CB", "6", "8", "LB", "RB", "WB"], "Recovery trap: block forward outlet");
  }

  if (isWidePrincipleZone(context.targetPoint) || context.counterPressIntent >= 0.58) {
    assign("widthExitLock", ["back", "midfield", "forward"], ["WB", "LB", "RB", "W", "8"], "Recovery trap: lock width release");
  }

  assign("restCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Recovery trap: rest cover");

  if (context.threat.centralPocket >= 0.22 || context.ballFromOwnGoal <= 42) {
    assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Recovery trap: weak-side tuck");
  }

  if (labels.length) {
    labels.unshift("Defensive loose-ball recovery trap");
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveOpenPlayTriggerContext(teamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return { active: false };
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const attackingTeamId = getOtherTeamId(teamId);
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position;
  const targetPoint = actionMeta.target ?? ballPoint;
  if (!attackingTeamId || !startPoint || !targetPoint) {
    return { active: false };
  }

  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const lateralShift = Math.abs(targetPoint.y - startPoint.y);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const startThreat = getPitchThreatProfile(startPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const targetCentrality = 1 - Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2);
  const wideRatio = Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2);
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const styleKey = profile.styleKey ?? getTeamDefenseStyleKey(teamId);
  const highPressStyle = ["high-press", "gegenpress", "counter-press", "press-trap-wide"].includes(styleKey);
  const deepProtectStyle = ["low-block", "protect-box", "park-the-bus", "catenaccio"].includes(styleKey);
  const centralEntry =
    targetCentrality >= 0.48 &&
    forwardGain >= 5 &&
    (targetThreat.centralPocket >= 0.3 || targetThreat.betweenLines >= 0.46 || ballFromOwnGoal <= 47);
  const boxThreat =
    targetThreat.box >= 0.28 ||
    targetThreat.centralPocket >= 0.48 ||
    targetThreat.cutbackZone >= 0.46 ||
    (targetCentrality >= 0.62 && ballFromOwnGoal <= 32);
  const wideEntry =
    wideRatio >= 0.58 &&
    ballFromOwnGoal <= 62 &&
    (forwardGain >= 2 || actionType === "dribble" || targetThreat.assistZone >= 0.34);
  const backwardsCue =
    forwardGain <= -4.5 &&
    lateralShift <= 18 &&
    ballFromOwnGoal >= 42 &&
    profile.pressingIntensity >= 0.52;
  const lineBreakDanger =
    forwardGain >= 10 &&
    targetThreat.value >= 0.42 &&
    ballFromOwnGoal <= 55;

  let mode = null;
  if (boxThreat || centralEntry) {
    mode = deepProtectStyle && !highPressStyle ? "collapseGoldenZone" : "centralJump";
  } else if (wideEntry) {
    mode = styleKey === "press-trap-wide" || highPressStyle || profile.pressingIntensity >= 0.56
      ? "wideTrap"
      : "wideDelay";
  } else if (backwardsCue) {
    mode = "stepOnBackwardPass";
  } else if (lineBreakDanger) {
    mode = "recoverLineBreak";
  }

  if (!mode) {
    return { active: false };
  }

  return {
    active: true,
    mode,
    actionMeta,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    ballPoint: cloneVector(targetPoint),
    forwardGain,
    lateralShift,
    targetThreat,
    startThreat,
    ballFromOwnGoal,
    targetCentrality,
    wideRatio,
    sideSign: getWideSideSign(targetPoint) || getWideSideSign(startPoint) || 1,
    highPressStyle,
    deepProtectStyle,
  };
}

function getDefensiveOpenPlayTriggerTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ballPoint = context.ballPoint;
  const sideSign = context.sideSign || 1;
  const points = {
    centralPress: {
      x: ballPoint.x - sign * 1.2,
      y: lerp(ballPoint.y, pitch.width / 2, 0.18),
    },
    goldenScreen: {
      x: lerp(ballPoint.x, ownGoal.x, 0.22),
      y: lerp(ballPoint.y, pitch.width / 2, 0.74),
    },
    cutbackScreen: {
      x: lerp(ballPoint.x, ownGoal.x, 0.34),
      y: pitch.width / 2 + sideSign * 5.8,
    },
    centerBackCover: {
      x: lerp(ballPoint.x, ownGoal.x, 0.46),
      y: pitch.width / 2 - sideSign * 4.2,
    },
    widePress: {
      x: ballPoint.x - sign * 1.1,
      y: clamp(ballPoint.y - sideSign * 1.5, 3.2, pitch.width - 3.2),
    },
    touchlineLock: {
      x: ballPoint.x - sign * 5.2,
      y: clamp(ballPoint.y - sideSign * 7.2, 5, pitch.width - 5),
    },
    insideCover: {
      x: ballPoint.x - sign * 8.2,
      y: lerp(ballPoint.y, pitch.width / 2, 0.56),
    },
    farSideTuck: {
      x: lerp(ballPoint.x, ownGoal.x, 0.36),
      y: pitch.width / 2 - sideSign * 10.2,
    },
    stepPress: {
      x: ballPoint.x - sign * 1.7,
      y: lerp(ballPoint.y, pitch.width / 2, 0.12),
    },
    squeezeLine: {
      x: ballPoint.x - sign * 9.5,
      y: pitch.width / 2,
    },
    recoveryRun: {
      x: lerp(ballPoint.x, ownGoal.x, 0.52),
      y: lerp(ballPoint.y, pitch.width / 2, 0.46),
    },
  };

  return clampToPitch(points[slot] ?? points.goldenScreen, 2.2);
}

function applyDefensiveOpenPlayTriggerTargets(teamId, targets, groups, basePresser, ballPoint, profile) {
  const context = getDefensiveOpenPlayTriggerContext(teamId, ballPoint, profile);
  if (!context.active) {
    return {
      active: false,
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set([basePresser?.id].filter(Boolean)),
    };
  }

  const labels = [];
  const excludedIds = new Set(groups.gk.map((goalkeeper) => goalkeeper.id));
  let presser = basePresser;

  if (basePresser) {
    excludedIds.add(basePresser.id);
  }

  const assign = (slot, lineKeys, preferLabels, label, replacePresser = false) => {
    const target = getDefensiveOpenPlayTriggerTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, excludedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    excludedIds.add(player.id);
    if (label) {
      labels.push(label);
    }

    if (replacePresser) {
      presser = player;
    }

    return player;
  };

  if (context.mode === "centralJump") {
    if (!presser) {
      assign("centralPress", ["midfield", "forward"], ["6", "8", "10", "9"], "Jump on central entry", true);
    } else {
      targets.set(presser.id, getDefensiveOpenPlayTriggerTarget(teamId, context, "centralPress"));
      labels.push("Jump on central entry");
    }
    assign("goldenScreen", ["midfield"], ["6", "8"], `Close ${context.targetThreat.primaryLabel}`);
    assign("centerBackCover", ["back"], ["CB"], "Cover the line behind");
    assign("cutbackScreen", ["midfield", "back"], ["6", "8", "LB", "RB", "WB"], "Cutback screen");
  } else if (context.mode === "collapseGoldenZone") {
    assign("goldenScreen", ["midfield"], ["6", "8"], `Collapse ${context.targetThreat.primaryLabel}`);
    assign("centerBackCover", ["back"], ["CB"], "Protect penalty spot");
    assign("cutbackScreen", ["midfield", "back"], ["6", "8", "CB"], "Cutback screen");
    if (presser) {
      targets.set(presser.id, getDefensiveOpenPlayTriggerTarget(teamId, context, "centralPress"));
    }
  } else if (context.mode === "wideTrap" || context.mode === "wideDelay") {
    if (!presser || context.mode === "wideTrap") {
      assign("widePress", ["midfield", "forward", "back"], ["W", "WB", "LB", "RB", "8"], context.mode === "wideTrap" ? "Wide trap press" : "Delay wide entry", true);
    } else {
      targets.set(presser.id, getDefensiveOpenPlayTriggerTarget(teamId, context, "widePress"));
      labels.push("Delay wide entry");
    }
    assign("touchlineLock", ["midfield", "back"], ["WB", "LB", "RB", "W"], "Lock touchline");
    assign("insideCover", ["midfield"], ["6", "8", "10"], "Protect inside lane");
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side tucks in");
  } else if (context.mode === "stepOnBackwardPass") {
    assign("stepPress", ["forward", "midfield"], ["9", "10", "W", "8"], "Step on backward pass", true);
    assign("squeezeLine", ["midfield"], ["6", "8", "10"], "Squeeze midfield line");
    assign("farSideTuck", ["back"], ["CB", "LB", "RB", "WB"], "Back line squeezes");
  } else if (context.mode === "recoverLineBreak") {
    if (presser) {
      targets.set(presser.id, getDefensiveOpenPlayTriggerTarget(teamId, context, "centralPress"));
    }
    assign("recoveryRun", ["back"], ["CB", "LB", "RB", "WB"], "Recover behind line break");
    assign("goldenScreen", ["midfield"], ["6", "8"], `Screen ${context.targetThreat.primaryLabel}`);
    assign("cutbackScreen", ["midfield", "back"], ["6", "8", "CB"], "Protect cutback");
  }

  return {
    active: true,
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.ballPoint,
    protectedIds: excludedIds,
  };
}

function getDefensiveReceptionTrapContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    principleRunnerPlayerId: null,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };

  if (actionMeta.actionType !== "pass") {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const carrier = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      actionMeta.carrierPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiverCandidate = getPlayerById(
    actionMeta.receiverPlayerId ??
      actionMeta.principleRunnerPlayerId ??
      state.ball.receiverPlayerId
  );
  const receiver = receiverCandidate?.team === attackingTeamId ? receiverCandidate : null;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    carrier?.position ??
    state.ball.position;
  const target = actionMeta.target ?? state.ball.target ?? ballPoint;

  if (!attackingTeamId || !startPoint || !target || carrier?.team === defensiveTeamId) {
    return null;
  }

  const passDistance = distance(startPoint, target);
  if (passDistance <= 4.5) {
    return null;
  }

  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (target.x - startPoint.x) * attackSign;
  const lateralShift = Math.abs(target.y - startPoint.y);
  const targetThreat = getPitchThreatProfile(target, attackingTeamId);
  const targetDepth = getAttackingDepth(target, attackingTeamId);
  const startDepth = getAttackingDepth(startPoint, attackingTeamId);
  const targetLaneKey = getPitchLaneKey(target);
  const targetIsWide = targetLaneKey === "leftWide" || targetLaneKey === "rightWide";
  const targetIsCentral =
    targetLaneKey === "central" ||
    targetLaneKey === "leftHalf" ||
    targetLaneKey === "rightHalf";
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, teams[attackingTeamId]?.formation) : null;
  const sideSign =
    getWideSideSign(target) ||
    getWideSideSign(receiver) ||
    getWideSideSign(startPoint) ||
    1;
  const highValueReception =
    targetThreat.value >= 0.34 ||
    targetThreat.betweenLines >= 0.38 ||
    targetThreat.centralPocket >= 0.32 ||
    targetThreat.halfSpace >= 0.42 ||
    targetThreat.assistZone >= 0.36 ||
    targetThreat.box >= 0.24 ||
    forwardGain >= 7.5 ||
    targetDepth >= 54;
  const receiverCanTurn =
    receiverRoleKey === "connector" ||
    receiverRoleKey === "wideForward" ||
    receiverRoleKey === "striker" ||
    receiverRoleKey === "secondStriker";
  const wideTrap =
    targetIsWide &&
    targetDepth >= 34 &&
    (profile.styleKey === "press-trap-wide" ||
      profile.pressingIntensity >= 0.5 ||
      forwardGain >= -2);
  const centralTrap =
    targetIsCentral &&
    (highValueReception ||
      receiverCanTurn ||
      (targetDepth >= 42 && passDistance >= 10));
  const lineBreakTrap =
    forwardGain >= 11 ||
    targetThreat.behindLine >= 0.34 ||
    (targetDepth >= 70 && passDistance >= 15);

  if (!wideTrap && !centralTrap && !lineBreakTrap && passDistance < 18) {
    return null;
  }

  return {
    actionMeta,
    attackingTeamId,
    carrier,
    receiver,
    receiverRoleKey,
    startPoint: cloneVector(startPoint),
    target: cloneVector(target),
    passDistance,
    forwardGain,
    lateralShift,
    targetThreat,
    targetDepth,
    startDepth,
    targetLaneKey,
    targetIsWide,
    targetIsCentral,
    sideSign,
    mode: lineBreakTrap
      ? "lineBreak"
      : wideTrap
        ? "wideTrap"
        : centralTrap
          ? "centralTrap"
          : "screenReception",
  };
}

function getDefensiveReceptionTrapTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.target;
  const sideSign = context.sideSign || 1;
  const isWide = context.targetIsWide;
  const insideBias = isWide ? 0.34 : 0.58;
  const goalSideX = (meters) => target.x - sign * meters;
  const passLaneMidpoint = {
    x: lerp(context.startPoint.x, target.x, 0.58),
    y: lerp(context.startPoint.y, target.y, 0.58),
  };
  const points = {
    firstTouchPress: {
      x: goalSideX(context.mode === "lineBreak" ? 0.85 : 1.25),
      y: lerp(target.y, pitch.width / 2, isWide ? 0.08 : 0.16),
    },
    insideLock: {
      x: goalSideX(isWide ? 4.6 : 5.4),
      y: lerp(target.y, pitch.width / 2, insideBias),
    },
    bounceLock: {
      x: passLaneMidpoint.x - sign * 1.7,
      y: lerp(passLaneMidpoint.y, pitch.width / 2, 0.28),
    },
    outsideTrap: {
      x: goalSideX(3.2),
      y: clamp(target.y + sideSign * (isWide ? 3.8 : 7.2), 3.5, pitch.width - 3.5),
    },
    depthCover: {
      x: lerp(target.x, ownGoal.x, context.mode === "lineBreak" ? 0.42 : 0.3),
      y: lerp(target.y, pitch.width / 2, isWide ? 0.42 : 0.34),
    },
    weakSideTuck: {
      x: lerp(target.x, ownGoal.x, 0.34),
      y: clamp(pitch.width / 2 - sideSign * (isWide ? 8.8 : 11.2), 7.5, pitch.width - 7.5),
    },
  };

  return clampToPitch(points[slot] ?? points.insideLock, 2.2);
}

function applyDefensiveReceptionTrapTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveReceptionTrapContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const firstTouchPoint = getDefensiveReceptionTrapTarget(teamId, context, "firstTouchPress");

  if (presser && !isGoalkeeper(presser)) {
    targets.set(presser.id, firstTouchPoint);
    assignedIds.add(presser.id);
    labels.push("Press first touch");
  } else {
    const firstPress = pickDefensiveAutopilotPlayer(
      groups,
      context.targetIsWide ? ["midfield", "back", "forward"] : ["midfield", "forward", "back"],
      assignedIds,
      firstTouchPoint,
      context.targetIsWide ? ["WB", "LB", "RB", "W", "8"] : ["6", "8", "10", "9"]
    );
    if (firstPress) {
      targets.set(firstPress.id, firstTouchPoint);
      assignedIds.add(firstPress.id);
      presser = firstPress;
      labels.push("Press first touch");
    }
  }

  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveReceptionTrapTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("insideLock", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Lock inside shoulder");
  assign("bounceLock", ["forward", "midfield"], ["9", "10", "8", "W", "6"], "Block bounce pass");

  if (context.mode === "wideTrap") {
    assign("outsideTrap", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Trap touchline side");
    assign("weakSideTuck", ["back", "midfield"], ["CB", "6", "LB", "RB", "WB"], "Far side tucks in");
  } else {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Cover turn and run");
    if (context.mode === "lineBreak" || context.targetThreat.box >= 0.24) {
      assign("weakSideTuck", ["back", "midfield"], ["CB", "6", "LB", "RB", "WB"], "Far side tucks in");
    }
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.target,
    protectedIds: assignedIds,
  };
}

function getDefensiveReceiveContinuationNextPoint(attackingTeamId, target, startPoint, firstTouchMode, intent, sideSign = 1) {
  const sign = getAttackDirectionSign(attackingTeamId);
  const targetIsWide = isWideChannel(target);

  if (intent === "bounce") {
    return clampToPitch({
      x: lerp(target.x, startPoint.x, 0.48),
      y: lerp(target.y, pitch.width / 2, 0.28),
    }, 2.4);
  }

  const forwardMeters =
    intent === "finish"
      ? 12.5
      : intent === "carry"
        ? 9.8
        : intent === "turn"
          ? 8.2
          : 6.8;
  const centerPull =
    firstTouchMode === "inside"
      ? 0.5
      : targetIsWide
        ? 0.42
        : 0.22;
  const yRelease =
    targetIsWide
      ? lerp(target.y, pitch.width / 2, centerPull)
      : clamp(target.y - sideSign * (intent === "finish" ? 2.8 : 1.4), 4, pitch.width - 4);

  return clampToPitch({
    x: target.x + sign * forwardMeters,
    y: yRelease,
  }, 2.4);
}

function getDefensiveReceiveContinuationContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    principleRunnerPlayerId: null,
    autoPrinciples: [],
    firstTouchMode: state.ball.firstTouchMode,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    offensiveAutopilot: null,
  };

  if ((actionMeta.actionType ?? state.ball.actionType) !== "pass") {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const target = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const carrier = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      actionMeta.carrierPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiverCandidate = getPlayerById(
    actionMeta.receiverPlayerId ??
      actionMeta.principleRunnerPlayerId ??
      state.ball.receiverPlayerId
  );
  const receiver = receiverCandidate?.team === attackingTeamId ? receiverCandidate : null;

  if (!attackingTeamId || !startPoint || !target || carrier?.team === defensiveTeamId) {
    return null;
  }

  const passDistance = distance(startPoint, target);
  if (passDistance < 5.2) {
    return null;
  }

  const attackProfile = getOffensiveAutopilotProfile(attackingTeamId, target);
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (target.x - startPoint.x) * attackSign;
  const targetThreat = getPitchThreatProfile(target, attackingTeamId);
  const targetSpace = getAttackingGameSpaceProfile(target, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, target, attackingTeamId, attackProfile);
  const targetDepth = getAttackingDepth(target, attackingTeamId);
  const firstTouchMode = actionMeta.firstTouchMode ?? state.ball.firstTouchMode ?? "auto";
  const principleText = [
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const receiverRoleKey = receiver ? getOffensiveRoleKey(receiver, teams[attackingTeamId]?.formation) : null;
  const sideSign =
    getWideSideSign(target) ||
    getWideSideSign(receiver) ||
    getWideSideSign(startPoint) ||
    1;
  const spaceTwoCue =
    principleText.includes("space 2") ||
    principleText.includes("space-two") ||
    principleText.includes("spelyta") ||
    principleText.includes("between-line") ||
    principleText.includes("between lines") ||
    principleText.includes("open-body");
  const spaceTwoReceive =
    spaceTwoCue ||
    targetSpace.key === "space2" ||
    (targetSpace.index === 2 && targetThreat.centrality >= 0.38) ||
    targetThreat.betweenLines >= 0.32 ||
    targetThreat.centralPocket >= 0.27 ||
    (targetThreat.halfSpace >= 0.44 && targetDepth >= 42 && targetDepth <= 78);
  const receiveFlow =
    principleText.includes("receive") ||
    principleText.includes("third-player") ||
    principleText.includes("first touch") ||
    principleText.includes("next player") ||
    spaceTwoCue;
  const openBodyReceive =
    firstTouchMode === "forward" ||
    firstTouchMode === "inside" ||
    spaceTwoReceive ||
    (firstTouchMode === "auto" && targetSpace.index >= 2 && targetThreat.centrality >= 0.42);
  const bounceReceive =
    firstTouchMode === "back" ||
    principleText.includes("escape") ||
    principleText.includes("bounce");
  const highThreatReceive =
    targetThreat.box >= 0.18 ||
    targetThreat.behindLine >= 0.26 ||
    targetThreat.betweenLines >= 0.34 ||
    targetThreat.centralPocket >= 0.28 ||
    targetThreat.halfSpace >= 0.42 ||
    spaceTwoReceive ||
    actionSpace.lineBreakCount >= 1 ||
    targetSpace.index >= 2 ||
    forwardGain >= 7;
  const receiverCanHurt =
    ["connector", "wideForward", "striker", "secondStriker"].includes(receiverRoleKey) ||
    !receiver;

  if (!receiveFlow && !(openBodyReceive && highThreatReceive && receiverCanHurt)) {
    return null;
  }

  const intent =
    bounceReceive
      ? "bounce"
      : principleText.includes("carry")
        ? "carry"
        : targetThreat.behindLine >= 0.28 || targetThreat.box >= 0.2 || targetDepth >= 72
          ? "finish"
          : spaceTwoReceive || targetSpace.key === "space2" || targetThreat.betweenLines >= 0.34
            ? "turn"
            : "connect";
  const nextPoint = getDefensiveReceiveContinuationNextPoint(
    attackingTeamId,
    target,
    startPoint,
    firstTouchMode,
    intent,
    sideSign
  );

  return {
    actionMeta,
    attackingTeamId,
    attackProfile,
    carrier,
    receiver,
    receiverRoleKey,
    startPoint: cloneVector(startPoint),
    target: cloneVector(target),
    nextPoint,
    ballPoint: cloneVector(ballPoint ?? target),
    passDistance,
    forwardGain,
    targetThreat,
    targetSpace,
    actionSpace,
    targetDepth,
    firstTouchMode,
    principleText,
    receiveFlow,
    openBodyReceive,
    spaceTwoReceive,
    bounceReceive,
    highThreatReceive,
    sideSign,
    targetIsWide: isWideChannel(target),
    intent,
  };
}

function getDefensiveReceiveContinuationTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.target;
  const nextPoint = context.nextPoint;
  const sideSign = context.sideSign || 1;
  const passLaneMidpoint = {
    x: lerp(context.startPoint.x, target.x, 0.58),
    y: lerp(context.startPoint.y, target.y, 0.58),
  };
  const nextLaneMidpoint = {
    x: lerp(target.x, nextPoint.x, 0.6),
    y: lerp(target.y, nextPoint.y, 0.6),
  };
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const points = {
    receiverPress: {
      ...goalSideOf(target, context.intent === "finish" ? 0.65 : 1.05),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.1 : 0.17),
    },
    turnLock: {
      ...goalSideOf(nextLaneMidpoint, context.intent === "turn" ? 2.1 : 2.8),
      y: lerp(nextLaneMidpoint.y, pitch.width / 2, context.targetIsWide ? 0.48 : 0.66),
    },
    thirdManScreen: {
      x: nextLaneMidpoint.x - sign * 1.6,
      y: lerp(nextLaneMidpoint.y, pitch.width / 2, context.intent === "finish" ? 0.38 : 0.26),
    },
    bounceBlock: {
      x: passLaneMidpoint.x - sign * 1.7,
      y: lerp(passLaneMidpoint.y, pitch.width / 2, 0.4),
    },
    outsideLock: {
      x: target.x - sign * 2.2,
      y: clamp(target.y + sideSign * (context.targetIsWide ? 3.6 : 6.2), 3.5, pitch.width - 3.5),
    },
    depthCover: {
      x: lerp(nextPoint.x, ownGoal.x, context.intent === "finish" ? 0.5 : 0.36),
      y: lerp(nextPoint.y, pitch.width / 2, context.targetIsWide ? 0.38 : 0.28),
    },
    farSideTuck: {
      x: lerp(target.x, ownGoal.x, context.intent === "finish" ? 0.42 : 0.32),
      y: clamp(pitch.width / 2 - sideSign * (context.intent === "finish" ? 8.6 : 10.8), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.turnLock, 2.2);
}

function applyDefensiveReceiveContinuationTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveReceiveContinuationContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const pressTarget = getDefensiveReceiveContinuationTarget(teamId, context, "receiverPress");
  const receiverPressLabel = context.spaceTwoReceive
    ? "Press space-2 receiver"
    : "Press receiver's next touch";
  const canReusePresser =
    presser &&
    !isGoalkeeper(presser) &&
    distance(presser.position, pressTarget) <= (context.spaceTwoReceive ? 25 : context.highThreatReceive ? 23 : 18.5);

  if (canReusePresser) {
    targets.set(presser.id, pressTarget);
    assignedIds.add(presser.id);
    labels.push(receiverPressLabel);
  } else {
    const pressPlayer = pickDefensiveAutopilotPlayer(
      groups,
      context.targetIsWide ? ["midfield", "back", "forward"] : ["midfield", "forward", "back"],
      assignedIds,
      pressTarget,
      context.targetIsWide ? ["WB", "LB", "RB", "W", "8"] : ["6", "8", "10", "9", "CB"]
    );
    if (pressPlayer) {
      targets.set(pressPlayer.id, pressTarget);
      assignedIds.add(pressPlayer.id);
      presser = pressPlayer;
      labels.push(receiverPressLabel);
    }
  }

  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveReceiveContinuationTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (context.bounceReceive || context.intent === "bounce") {
    assign("bounceBlock", ["forward", "midfield"], ["9", "10", "8", "6", "W"], "Block bounce after receive");
    assign("turnLock", ["midfield"], ["6", "8", "10"], "Lock second touch inside");
  } else if (context.spaceTwoReceive) {
    assign("turnLock", ["midfield", "back"], ["6", "8", "CB", "10"], "Space 2: lock the turn");
    assign("thirdManScreen", ["midfield", "back"], ["6", "8", "10", "CB"], "Space 2: screen third-player lane");
  } else {
    assign("turnLock", ["midfield", "back"], ["6", "8", "CB", "10"], "Deny open-body turn");
    assign("thirdManScreen", ["midfield", "back"], ["6", "8", "10", "CB"], "Screen third-player lane");
  }

  if (context.targetIsWide) {
    assign("outsideLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Lock outside escape");
  }

  if (context.spaceTwoReceive || context.highThreatReceive || context.intent === "finish") {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Cover receive-and-run depth");
  }

  if (
    context.spaceTwoReceive ||
    context.actionSpace.lineBreakCount >= 1 ||
    context.intent === "finish" ||
    Math.abs(context.target.y - context.startPoint.y) >= 16
  ) {
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side protects next action");
  }

  if (labels.length) {
    labels.unshift(context.spaceTwoReceive ? "Defend space 2 receive" : "Read receive continuation");
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.nextPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveRouteAnticipationContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const plan = state.autoPilotPlay?.possessionPlan;
  if (!attackingTeamId || !plan || plan.teamId !== attackingTeamId || !(plan.routeLanes?.length)) {
    return null;
  }

  const attackProfile = getOffensiveAutopilotProfile(attackingTeamId, ballPoint);
  const rhythm = getPossessionRhythmContext(attackingTeamId);
  const depth = getAttackingDepth(ballPoint, attackingTeamId);
  const routeStage = getAutoPilotPossessionRouteStage(plan, rhythm, depth);
  const routeTargetLane =
    plan.routeLanes?.[routeStage] ??
    plan.routeLanes?.[0] ??
    getPitchLaneKey(ballPoint);
  const nextRouteLane =
    plan.routeLanes?.[Math.min(routeStage + 1, (plan.routeLanes?.length ?? 1) - 1)] ??
    routeTargetLane;
  const routeIntent =
    plan.routeIntents?.[Math.min(routeStage, (plan.routeIntents?.length ?? 1) - 1)] ??
    plan.intentSequence?.[Math.min(routeStage, (plan.intentSequence?.length ?? 1) - 1)] ??
    "progress";
  const currentLane = getPitchLaneKey(ballPoint);
  const routeShiftFromBall = Math.abs(getPitchLaneIndex(routeTargetLane) - getPitchLaneIndex(currentLane));
  const laneDistance = Math.abs(getPitchLaneIndex(routeTargetLane) - getPitchLaneIndex(nextRouteLane));
  const routeY = getLaneCenterY(routeTargetLane, attackProfile);
  const nextY = getLaneCenterY(nextRouteLane, attackProfile);
  const sideSign =
    Math.sign(routeY - pitch.width / 2) ||
    getWideSideSign(ballPoint) ||
    1;
  const targetThreat = getPitchThreatProfile(
    {
      x: ballPoint.x,
      y: routeY,
    },
    attackingTeamId
  );
  const active =
    depth >= 30 ||
    rhythm.steps >= 1 ||
    routeShiftFromBall >= 1 ||
    laneDistance >= 2 ||
    routeIntent === "switch" ||
    routeIntent === "finish";

  if (!active) {
    return null;
  }

  return {
    attackingTeamId,
    plan,
    attackProfile,
    rhythm,
    depth,
    ballPoint: cloneVector(ballPoint),
    routeStage,
    routeTargetLane,
    nextRouteLane,
    routeIntent,
    currentLane,
    routeShiftFromBall,
    laneDistance,
    routeY,
    nextY,
    sideSign,
    targetThreat,
    targetIsWide: routeTargetLane === "leftWide" || routeTargetLane === "rightWide",
    targetIsHalf: routeTargetLane === "leftHalf" || routeTargetLane === "rightHalf",
    targetIsCentral: routeTargetLane === "central",
  };
}

function getDefensiveRouteAnticipationTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const { ballPoint, routeY, nextY, sideSign } = context;
  const goalSideX = (meters) => ballPoint.x - sign * meters;
  const depthCoverRatio =
    context.routeIntent === "finish"
      ? 0.5
      : context.routeIntent === "accelerate"
        ? 0.42
        : 0.34;
  const points = {
    routeLaneScreen: {
      x: goalSideX(context.targetIsWide ? 5.6 : 7.2),
      y: lerp(routeY, pitch.width / 2, context.targetIsWide ? 0.2 : 0.12),
    },
    centralScreen: {
      x: goalSideX(9.6),
      y: lerp(routeY, pitch.width / 2, 0.72),
    },
    touchlineTrap: {
      x: goalSideX(4.8),
      y: clamp(routeY + sideSign * 4.6, 3.4, pitch.width - 3.4),
    },
    insideCover: {
      x: goalSideX(6.8),
      y: lerp(routeY, pitch.width / 2, 0.48),
    },
    weakSideSwitchCover: {
      x: lerp(ballPoint.x, ownGoal.x, 0.3),
      y: clamp(nextY, 5.5, pitch.width - 5.5),
    },
    depthCover: {
      x: lerp(ballPoint.x, ownGoal.x, depthCoverRatio),
      y: lerp(routeY, pitch.width / 2, context.targetIsWide ? 0.46 : 0.32),
    },
    secondBallCover: {
      x: goalSideX(13.4),
      y: lerp(routeY, pitch.width / 2, 0.54),
    },
    restLine: {
      x: lerp(ballPoint.x, ownGoal.x, 0.46),
      y: clamp(pitch.width / 2 - sideSign * 7.2, 8, pitch.width - 8),
    },
  };

  return clampToPitch(points[slot] ?? points.routeLaneScreen, 2.2);
}

function applyDefensiveRouteAnticipationTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveRouteAnticipationContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    basePresser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveRouteAnticipationTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (context.targetIsWide) {
    assign("routeLaneScreen", ["midfield", "back"], ["WB", "LB", "RB", "W", "6"], "Protect route lane");
    assign("touchlineTrap", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Deny outside route");
    assign("insideCover", ["midfield"], ["6", "8", "10"], "Block inside return");
  } else if (context.targetIsHalf) {
    assign("routeLaneScreen", ["midfield"], ["6", "8", "10"], "Screen half-space route");
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Cover route depth");
    assign("centralScreen", ["midfield", "back"], ["6", "8", "CB"], "Protect central lane");
  } else if (context.targetIsCentral) {
    assign("centralScreen", ["midfield"], ["6", "8", "10"], "Protect central route");
    assign("depthCover", ["back"], ["CB"], "Cover line behind");
    if (context.targetThreat.betweenLines >= 0.4 || context.depth >= 50) {
      assign("routeLaneScreen", ["midfield", "back"], ["6", "8", "CB"], "Deny turn inside");
    }
  }

  if (
    context.routeIntent === "switch" ||
    context.laneDistance >= 2 ||
    context.plan.routeKey === "wide-overload-switch" ||
    context.plan.routeKey === "patient-switch"
  ) {
    assign("weakSideSwitchCover", ["back", "midfield"], ["WB", "LB", "RB", "W", "6"], "Cover weak-side switch");
  }

  if (
    context.routeIntent === "accelerate" ||
    context.routeIntent === "finish" ||
    context.plan.routeKey === "direct-second-ball"
  ) {
    assign("secondBallCover", ["midfield", "back"], ["6", "8", "CB"], "Prepare second ball");
    assign("restLine", ["back"], ["CB", "LB", "RB", "WB"], "Rest line protects depth");
  }

  if (labels.length) {
    labels.unshift("Anticipate attacking route");
  }

  return {
    presser: basePresser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: {
      x: ballPoint.x,
      y: context.routeY,
    },
    protectedIds: assignedIds,
  };
}

function getDefensiveSwitchRecoveryContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileLabel: state.ball.profileLabel,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };

  if ((actionMeta.actionType ?? state.ball.actionType) !== "pass") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position;
  const targetPoint = actionMeta.target ?? ballPoint ?? state.ball.target;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const startLane = getPitchLaneKey(startPoint);
  const targetLane = getPitchLaneKey(targetPoint);
  const laneShift =
    startLane && targetLane
      ? Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(startLane))
      : 0;
  const passDistance = distance(startPoint, targetPoint);
  const lateralMeters = Math.abs(targetPoint.y - startPoint.y);
  const startSide = getWideSideSign(startPoint);
  const targetSide =
    getWideSideSign(targetPoint) ||
    Math.sign(targetPoint.y - pitch.width / 2) ||
    1;
  const principleText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.label,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const oppositeSideSwitch = startSide && targetSide && startSide !== targetSide;
  const switchCue =
    principleText.includes("switch") ||
    principleText.includes("change corridor") ||
    principleText.includes("weak-side") ||
    principleText.includes("spelvänd") ||
    (
      passDistance >= 20 &&
      lateralMeters >= 17 &&
      (laneShift >= 2 || oppositeSideSwitch)
    );

  if (!switchCue) {
    return null;
  }

  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const actionSpeed = Math.max(actionMeta.speed ?? state.ball.speed ?? state.ball.currentSpeed ?? 13, 0.1);
  const eta = passDistance / actionSpeed;
  const finalThirdSwitch =
    ballFromOwnGoal <= 42 ||
    targetThreat.assistZone >= 0.32 ||
    targetThreat.box >= 0.12 ||
    targetThreat.cutbackZone >= 0.18;
  const centralDanger =
    targetThreat.centralPocket >= 0.22 ||
    targetThreat.betweenLines >= 0.28 ||
    actionSpace.lineBreakCount >= 1 ||
    forwardGain >= 7;

  return {
    actionMeta,
    attackingTeamId,
    receiver,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    startLane,
    targetLane,
    laneShift,
    passDistance,
    lateralMeters,
    startSide: startSide || -targetSide,
    targetSide,
    targetThreat,
    actionSpace,
    ballFromOwnGoal,
    forwardGain,
    eta,
    finalThirdSwitch,
    centralDanger,
    targetIsWide: isWidePrincipleZone(targetPoint),
    phaseKey: profile.phaseKey,
  };
}

function getDefensiveSwitchRecoveryTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.targetPoint;
  const targetSide = context.targetSide || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const pressureDistance =
    context.phaseKey === "highPress"
      ? 1.2
      : context.phaseKey === "lowBlock" || context.phaseKey === "boxDefending"
        ? 2.3
        : 1.8;
  const lineCoverRatio =
    context.finalThirdSwitch
      ? 0.42
      : context.centralDanger
        ? 0.34
        : 0.28;
  const points = {
    firstPressure: {
      ...goalSideOf(target, pressureDistance),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.08 : 0.18),
    },
    wideLock: {
      x: target.x - sign * 3.1,
      y: clamp(target.y + targetSide * 4.8, 3.4, pitch.width - 3.4),
    },
    centralGate: {
      x: target.x - sign * (context.centralDanger ? 7.8 : 6.2),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.72 : 0.84),
    },
    midfieldSlide: {
      x: target.x - sign * (context.finalThirdSwitch ? 8.4 : 10.2),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.48 : 0.62),
    },
    backLineShift: {
      x: lerp(target.x, ownGoal.x, lineCoverRatio),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.34 : 0.24),
    },
    depthCover: {
      x: lerp(target.x, ownGoal.x, context.finalThirdSwitch ? 0.5 : 0.4),
      y: lerp(target.y, pitch.width / 2, context.targetIsWide ? 0.46 : 0.32),
    },
    oldSideRecover: {
      x: lerp(target.x, ownGoal.x, context.finalThirdSwitch ? 0.38 : 0.3),
      y: clamp(pitch.width / 2 - targetSide * (context.finalThirdSwitch ? 8.2 : 11.5), 7, pitch.width - 7),
    },
    boxBalance: {
      x: lerp(target.x, ownGoal.x, 0.46),
      y: clamp(pitch.width / 2 - targetSide * 4.8, 10, pitch.width - 10),
    },
  };

  return clampToPitch(points[slot] ?? points.centralGate, 2.2);
}

function applyDefensiveSwitchRecoveryTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveSwitchRecoveryContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveSwitchRecoveryTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const pressTarget = getDefensiveSwitchRecoveryTarget(teamId, context, "firstPressure");
  const presserCanRecover =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, pressTarget) <= (context.eta <= 1.6 ? 18 : 23);
  if (presserCanRecover) {
    targets.set(presser.id, pressTarget);
    assignedIds.add(presser.id);
    labels.push("Switch recovery: arrive to new ball side");
  } else {
    const newPresser = assign(
      "firstPressure",
      context.targetIsWide ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      context.targetIsWide ? ["WB", "LB", "RB", "W", "8"] : ["6", "8", "10", "CB"],
      "Switch recovery: arrive to new ball side"
    );
    presser = newPresser ?? presser;
  }

  if (context.targetIsWide) {
    assign("wideLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Switch recovery: lock outside");
  }

  assign("centralGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Switch recovery: close central gate");
  assign("midfieldSlide", ["midfield", "forward"], ["6", "8", "10", "W"], "Switch recovery: midfield slides across");
  assign("backLineShift", ["back"], ["CB", "LB", "RB", "WB"], "Switch recovery: back line shifts");

  if (context.centralDanger || context.forwardGain >= 6 || context.actionSpace.lineBreakCount >= 1) {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Switch recovery: protect depth");
  }

  assign("oldSideRecover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Switch recovery: old ball side narrows");

  if (context.finalThirdSwitch) {
    assign("boxBalance", ["back", "midfield"], ["CB", "6", "8", "LB", "RB", "WB"], "Switch recovery: box balance");
  }

  if (labels.length) {
    labels.unshift("Recover after switch");
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveSwitchLandingLockContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileLabel: state.ball.profileLabel,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const lastStep = getRecentPossessionSteps(attackingTeamId, 4)[0] ?? null;
  if (!lastStep || lastStep.actionType !== "pass") {
    return null;
  }

  const lastStart = lastStep.beforeSnapshot?.ball?.position;
  const lastTarget = lastStep.target;
  if (!lastStart || !lastTarget) {
    return null;
  }

  const lastDistance = distance(lastStart, lastTarget);
  const laneShift = Math.abs(getPitchLaneIndex(lastStart) - getPitchLaneIndex(lastTarget));
  const lastPrincipleText = [
    lastStep.profileKey,
    lastStep.profileLabel,
    lastStep.offensiveAutopilot?.principleKey,
    lastStep.offensiveAutopilot?.principleLabel,
    ...(lastStep.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const wasSwitch =
    (lastDistance >= 18 && laneShift >= 2) ||
    lastPrincipleText.includes("switch") ||
    lastPrincipleText.includes("weak-side") ||
    lastPrincipleText.includes("far side");

  if (!wasSwitch || getRecordedStepDuration(lastStep) > 5.4) {
    return null;
  }

  const actionStart =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    lastTarget;
  const actionTarget = actionMeta.target ?? ballPoint ?? state.ball.target ?? actionStart;
  const currentOwnerId =
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
    actionMeta.carrierPlayerId ??
    state.ball.initiatorPlayerId ??
    state.ball.ownerPlayerId;
  const lastReceiverId =
    lastStep.receiverPlayerId ??
    lastStep.afterSnapshot?.ball?.ownerPlayerId ??
    null;
  const currentOwner = getPlayerById(currentOwnerId);
  const ownerMatchesLanding =
    !!lastReceiverId &&
    (
      currentOwnerId === lastReceiverId ||
      actionMeta.carrierPlayerId === lastReceiverId ||
      state.ball.carrierPlayerId === lastReceiverId ||
      state.ball.ownerPlayerId === lastReceiverId
    );
  const nearLanding =
    distance(actionStart, lastTarget) <= 10 ||
    (currentOwner?.team === attackingTeamId && distance(currentOwner.position, lastTarget) <= 11);

  if (!ownerMatchesLanding && !nearLanding) {
    return null;
  }

  const threatPoint = actionType === "shot" ? actionStart : actionTarget;
  const targetThreat = getPitchThreatProfile(threatPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(actionStart, threatPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, threatPoint);
  const forwardGain = (threatPoint.x - actionStart.x) * getAttackDirectionSign(attackingTeamId);
  const sideSign =
    getWideSideSign(actionStart) ||
    getWideSideSign(threatPoint) ||
    getWideSideSign(lastTarget) ||
    1;
  const targetIsWide = isWidePrincipleZone(actionStart) || isWidePrincipleZone(threatPoint);
  const finalThirdCue =
    ballFromOwnGoal <= 42 ||
    targetThreat.assistZone >= 0.28 ||
    targetThreat.cutbackZone >= 0.18 ||
    targetThreat.box >= 0.12;
  const lockNeed = clamp(
    targetThreat.value * 0.42 +
      targetThreat.cutbackZone * 0.34 +
      targetThreat.assistZone * 0.22 +
      clamp(actionSpace.lineBreakCount / 2, 0, 1) * 0.28 +
      clamp(forwardGain / 18, 0, 1) * 0.18 +
      (targetIsWide ? 0.14 : 0.04) +
      (finalThirdCue ? 0.18 : 0),
    0,
    1.35
  );

  if (lockNeed < 0.34 && !targetIsWide) {
    return null;
  }

  return {
    actionMeta,
    actionSpace,
    actionStart: cloneVector(actionStart),
    actionTarget: cloneVector(actionTarget),
    actionType,
    attackingTeamId,
    ballFromOwnGoal,
    finalThirdCue,
    forwardGain,
    laneShift,
    lastDistance,
    lastStart: cloneVector(lastStart),
    lastTarget: cloneVector(lastTarget),
    lockNeed,
    sideSign,
    targetIsWide,
    targetThreat,
    threatPoint: cloneVector(threatPoint),
  };
}

function getDefensiveSwitchLandingLockTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.actionStart;
  const threat = context.threatPoint;
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const ballToThreat = {
    x: lerp(ball.x, threat.x, context.actionType === "dribble" ? 0.45 : 0.62),
    y: lerp(ball.y, threat.y, context.actionType === "dribble" ? 0.45 : 0.62),
  };
  const lineCoverRatio = context.finalThirdCue ? 0.45 : 0.34;
  const points = {
    firstPressure: {
      ...goalSideOf(ball, context.targetIsWide ? 1.25 : 1.55),
      y: lerp(ball.y, pitch.width / 2, context.targetIsWide ? 0.1 : 0.2),
    },
    outsideContain: {
      x: ball.x - sign * 2.6,
      y: clamp(ball.y + sideSign * 4.5, 3.5, pitch.width - 3.5),
    },
    insideGate: {
      x: ballToThreat.x - sign * (context.finalThirdCue ? 4.6 : 5.8),
      y: lerp(ballToThreat.y, pitch.width / 2, context.targetIsWide ? 0.72 : 0.86),
    },
    bounceScreen: {
      x: ball.x - sign * (context.finalThirdCue ? 7.4 : 8.8),
      y: lerp(ball.y, pitch.width / 2 - sideSign * 2.5, 0.58),
    },
    cutbackGate: {
      x: lerp(threat.x, ownGoal.x, context.finalThirdCue ? 0.34 : 0.25),
      y: clamp(pitch.width / 2 + sideSign * 5.8, 10, pitch.width - 10),
    },
    backLineSlide: {
      x: lerp(threat.x, ownGoal.x, lineCoverRatio),
      y: lerp(threat.y, pitch.width / 2, context.targetIsWide ? 0.42 : 0.3),
    },
    farPostTuck: {
      x: lerp(threat.x, ownGoal.x, context.finalThirdCue ? 0.48 : 0.38),
      y: clamp(pitch.width / 2 - sideSign * (context.finalThirdCue ? 8.4 : 10.8), 7, pitch.width - 7),
    },
    oldSideBalance: {
      x: lerp(ball.x, ownGoal.x, context.finalThirdCue ? 0.38 : 0.28),
      y: clamp(pitch.width / 2 - sideSign * (context.finalThirdCue ? 6.8 : 11.5), 8, pitch.width - 8),
    },
  };

  return clampToPitch(points[slot] ?? points.insideGate, 2.2);
}

function applyDefensiveSwitchLandingLockTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveSwitchLandingLockContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveSwitchLandingLockTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const pressureTarget = getDefensiveSwitchLandingLockTarget(teamId, context, "firstPressure");
  const baseCanPress =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, pressureTarget) <= (context.finalThirdCue ? 20 : 24);
  if (baseCanPress) {
    targets.set(presser.id, pressureTarget);
    assignedIds.add(presser.id);
    labels.push("Switch landing lock: pressure first touch");
  } else {
    const firstPress = assign(
      "firstPressure",
      context.targetIsWide ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      context.targetIsWide ? ["WB", "LB", "RB", "W", "8"] : ["6", "8", "10", "CB"],
      "Switch landing lock: pressure first touch"
    );
    presser = firstPress ?? presser;
  }

  if (context.targetIsWide) {
    assign("outsideContain", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Switch landing lock: contain outside");
  }

  assign("insideGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Switch landing lock: close inside gate");
  assign("bounceScreen", ["midfield", "forward"], ["6", "8", "10", "9", "W"], "Switch landing lock: block bounce pass");
  assign("backLineSlide", ["back"], ["CB", "LB", "RB", "WB"], "Switch landing lock: back line slides");

  if (context.finalThirdCue || context.targetThreat.cutbackZone >= 0.16 || context.targetThreat.assistZone >= 0.24) {
    assign("cutbackGate", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Switch landing lock: protect cutback");
    assign("farPostTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Switch landing lock: far post tuck");
  }

  assign("oldSideBalance", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Switch landing lock: old side balances");

  if (labels.length) {
    labels.unshift(
      context.finalThirdCue
        ? "Lock far-side attack after switch"
        : "Lock switch landing"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.actionStart,
    protectedIds: assignedIds,
  };
}

function getDefensiveGameSpaceResponseContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const startSpace = getAttackingGameSpaceProfile(startPoint, attackingTeamId);
  const targetSpace = getAttackingGameSpaceProfile(targetPoint, attackingTeamId);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const gameSpaceGain = targetSpace.index - startSpace.index;
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const centrality = 1 - Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const lineEntry =
    targetSpace.key === "space2" ||
    targetThreat.betweenLines >= 0.34 ||
    (targetSpace.index >= 2 && gameSpaceGain >= 1 && forwardGain >= 4.5);
  const depthEntry =
    targetSpace.key === "space3" ||
    targetThreat.behindLine >= 0.3 ||
    (targetSpace.index >= 3 && forwardGain >= 6) ||
    (ballFromOwnGoal <= 28 && forwardGain >= 3.5);
  const centralDanger =
    centrality >= 0.48 &&
    (targetThreat.centralPocket >= 0.26 || targetThreat.box >= 0.18 || ballFromOwnGoal <= 36);

  if (!lineEntry && !depthEntry && !centralDanger) {
    return null;
  }

  const mode = depthEntry
    ? "spaceThreeRecovery"
    : lineEntry
      ? "spaceTwoJump"
      : "centralProtection";

  return {
    actionMeta,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    startSpace,
    targetSpace,
    targetThreat,
    forwardGain,
    gameSpaceGain,
    ballFromOwnGoal,
    centrality,
    sideSign,
    actionType,
    mode,
    lineEntry,
    depthEntry,
  };
}

function getDefensiveGameSpaceResponseTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const goalSideX = (meters) => target.x - sign * meters;
  const passLaneMidpoint = {
    x: lerp(context.startPoint.x, target.x, 0.58),
    y: lerp(context.startPoint.y, target.y, 0.58),
  };
  const isDepthEntry = context.mode === "spaceThreeRecovery";
  const points = {
    firstPressure: {
      x: goalSideX(isDepthEntry ? 0.75 : 1.15),
      y: lerp(target.y, pitch.width / 2, isDepthEntry ? 0.1 : 0.16),
    },
    bounceScreen: {
      x: passLaneMidpoint.x - sign * 2.2,
      y: lerp(passLaneMidpoint.y, pitch.width / 2, 0.34),
    },
    insideScreen: {
      x: goalSideX(isDepthEntry ? 6.2 : 5.6),
      y: lerp(target.y, pitch.width / 2, isDepthEntry ? 0.58 : 0.68),
    },
    depthCover: {
      x: lerp(target.x, ownGoal.x, isDepthEntry ? 0.5 : 0.34),
      y: lerp(target.y, pitch.width / 2, isDepthEntry ? 0.3 : 0.24),
    },
    runnerTrack: {
      x: lerp(target.x, ownGoal.x, isDepthEntry ? 0.32 : 0.2),
      y: clamp(target.y + sideSign * (isDepthEntry ? 3.4 : 4.8), 4.5, pitch.width - 4.5),
    },
    cutbackLock: {
      x: lerp(target.x, ownGoal.x, isDepthEntry ? 0.42 : 0.36),
      y: pitch.width / 2 + sideSign * (isDepthEntry ? 4.8 : 5.8),
    },
    farSideTuck: {
      x: lerp(target.x, ownGoal.x, isDepthEntry ? 0.38 : 0.32),
      y: clamp(pitch.width / 2 - sideSign * (isDepthEntry ? 9.2 : 10.6), 6.5, pitch.width - 6.5),
    },
  };

  return clampToPitch(points[slot] ?? points.insideScreen, 2.2);
}

function applyDefensiveGameSpaceResponseTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveGameSpaceResponseContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const firstPressurePoint = getDefensiveGameSpaceResponseTarget(teamId, context, "firstPressure");
  const basePresserLabel = basePresser ? getPlayerMagnetLabel(basePresser) : null;
  const canReuseBasePresser =
    basePresser &&
    !isGoalkeeper(basePresser) &&
    (
      context.mode !== "spaceThreeRecovery" ||
      ["CB", "LB", "RB", "WB", "6", "8"].includes(basePresserLabel) ||
      distance(basePresser.position, firstPressurePoint) <= 15
    );

  if (canReuseBasePresser) {
    targets.set(basePresser.id, firstPressurePoint);
    assignedIds.add(basePresser.id);
    labels.push(context.mode === "spaceThreeRecovery" ? "Recover first touch behind line" : "Press first touch in space 2");
  } else {
    const firstPress = pickDefensiveAutopilotPlayer(
      groups,
      context.mode === "spaceThreeRecovery" ? ["back", "midfield"] : ["midfield", "forward", "back"],
      assignedIds,
      firstPressurePoint,
      context.mode === "spaceThreeRecovery" ? ["CB", "LB", "RB", "WB", "6"] : ["6", "8", "10", "9", "W"]
    );
    if (firstPress) {
      targets.set(firstPress.id, firstPressurePoint);
      assignedIds.add(firstPress.id);
      presser = firstPress;
      labels.push(context.mode === "spaceThreeRecovery" ? "Recover first touch behind line" : "Press first touch in space 2");
    }
  }

  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveGameSpaceResponseTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (context.mode === "spaceThreeRecovery") {
    assign("runnerTrack", ["back"], ["CB", "LB", "RB", "WB"], "Track run behind");
    assign("depthCover", ["back"], ["CB"], "Cover goal-side depth");
    assign("cutbackLock", ["midfield", "back"], ["6", "8", "CB"], "Protect cutback lane");
    assign("bounceScreen", ["midfield"], ["6", "8", "10"], "Prepare second ball");
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side tucks in");
  } else {
    assign("bounceScreen", ["forward", "midfield"], ["9", "10", "8", "W", "6"], "Block bounce pass");
    assign("insideScreen", ["midfield", "back"], ["6", "8", "CB"], "Deny turn inside");
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Cover line behind");
    if (context.targetThreat.cutbackZone >= 0.24 || context.ballFromOwnGoal <= 42) {
      assign("cutbackLock", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Protect cutback lane");
    }
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side tucks in");
  }

  if (labels.length) {
    labels.unshift(`Respond to ${context.targetSpace.label}`);
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveRunnerThreats(defensiveTeamId, ballPoint, profile) {
  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId || state.restartPhase?.type) {
    return [];
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    principleRunnerPlayerId: null,
    beforeSnapshot: {
      ball: {
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const carrierId =
    actionMeta.carrierPlayerId ??
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
    state.ball.initiatorPlayerId ??
    state.ball.ownerPlayerId;
  const actionTarget = actionMeta.target ?? ballPoint;
  const actionThreat = getPitchThreatProfile(actionTarget, attackingTeamId);
  const ballSide = getWideSideSign(actionTarget) || 1;
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const principleText = [
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const snapshotPositions = getSnapshotPlayerMap(actionMeta.beforeSnapshot);
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const hasChannelCue =
    principleText.includes("channel") ||
    principleText.includes("blindside") ||
    principleText.includes("run behind") ||
    principleText.includes("run beyond") ||
    principleText.includes("depth");

  return state.players
    .filter((player) => player.team === attackingTeamId && !isGoalkeeper(player) && player.id !== carrierId)
    .map((player) => {
      const startPosition = snapshotPositions.get(player.id) ?? player.actionOrigin ?? player.position;
      const roleKey = getOffensiveRoleKey(player, teams[attackingTeamId]?.formation);
      const threat = getPitchThreatProfile(player.position, attackingTeamId);
      const depth = getAttackingDepth(player.position, attackingTeamId);
      const startDepth = getAttackingDepth(startPosition, attackingTeamId);
      const runDistance = distance(startPosition, player.position);
      const runForwardGain = (player.position.x - startPosition.x) * attackSign;
      const distanceToAction = distance(player.position, actionTarget);
      const isPrincipleRunner = player.id === actionMeta.principleRunnerPlayerId;
      const isReceiver = player.id === actionMeta.receiverPlayerId;
      const isFrontLine = roleKey === "striker" || roleKey === "wideForward" || roleKey === "secondStriker";
      const isBoxThreat = threat.box >= 0.22 || threat.cutbackZone >= 0.32 || depth >= 72;
      const isDepthThreat = threat.behindLine >= 0.26 || depth >= 66 || (isFrontLine && depth >= 58);
      const movedIntoChannel =
        Math.abs(player.position.y - pitch.width / 2) >= 8.5 ||
        Math.abs(player.position.y - startPosition.y) >= 5.2;
      const isChannelRun =
        runDistance >= 3.2 &&
        runForwardGain >= 1.8 &&
        movedIntoChannel &&
        (
          hasChannelCue ||
          isPrincipleRunner ||
          threat.assistZone >= 0.24 ||
          threat.behindLine >= 0.18 ||
          (isFrontLine && depth >= Math.max(startDepth + 4, 54))
        );
      const isBlindsideRun =
        isChannelRun &&
        (
          principleText.includes("blindside") ||
          isPrincipleRunner ||
          getWideSideSign(startPosition) !== getWideSideSign(player.position) ||
          runForwardGain >= 6
        );
      const isBetweenLinesThreat =
        threat.betweenLines >= 0.34 ||
        threat.centralPocket >= 0.26 ||
        (roleKey === "connector" && depth >= 44);
      const farSideThreat =
        getWideSideSign(player) === -ballSide &&
        (actionThreat.assistZone >= 0.34 || principleText.includes("switch") || principleText.includes("far"));
      const score =
        threat.value * 0.78 +
        threat.box * 0.78 +
        threat.behindLine * 0.62 +
        threat.cutbackZone * 0.42 +
        threat.betweenLines * 0.36 +
        (isPrincipleRunner ? 0.82 : 0) +
        (isReceiver && actionType === "pass" ? 0.22 : 0) +
        (isFrontLine ? 0.28 : 0) +
        (isBoxThreat ? 0.38 : 0) +
        (isDepthThreat ? 0.28 : 0) +
        (isChannelRun ? 0.42 : 0) +
        (isBlindsideRun ? 0.34 : 0) +
        Math.max(0, runForwardGain - 2) * 0.025 +
        (isBetweenLinesThreat ? 0.22 : 0) +
        (farSideThreat ? 0.34 : 0) -
        (distanceToAction > 34 && !isPrincipleRunner ? 0.26 : 0);

      return {
        player,
        roleKey,
        threat,
        depth,
        startPosition,
        startDepth,
        runDistance,
        runForwardGain,
        distanceToAction,
        isPrincipleRunner,
        isReceiver,
        isFrontLine,
        isBoxThreat,
        isDepthThreat,
        isChannelRun,
        isBlindsideRun,
        isBetweenLinesThreat,
        farSideThreat,
        score,
      };
    })
    .filter((entry) =>
      entry.score >= 0.74 ||
      entry.isPrincipleRunner ||
      entry.isBoxThreat ||
      entry.isDepthThreat ||
      entry.isChannelRun ||
      entry.isBlindsideRun ||
      entry.isBetweenLinesThreat
    )
    .sort((a, b) => b.score - a.score)
    .slice(0, 4);
}

function getDefensiveRunnerTrackingTarget(teamId, runnerThreat, slot = "goalSideMark") {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const runner = runnerThreat.player;
  const sideSign = getWideSideSign(runner) || 1;
  const points = {
    goalSideMark: {
      x: runner.position.x - sign * (runnerThreat.isDepthThreat ? 1.8 : 1.25),
      y: lerp(runner.position.y, pitch.width / 2, runnerThreat.isBoxThreat ? 0.18 : 0.1),
    },
    depthCover: {
      x: lerp(runner.position.x, ownGoal.x, 0.34),
      y: lerp(runner.position.y, pitch.width / 2, 0.28),
    },
    blindsideTrack: {
      x: runner.position.x - sign * 2.15,
      y: lerp(runner.position.y, pitch.width / 2, 0.22),
    },
    channelHandover: {
      x: runner.position.x - sign * 1.55,
      y: lerp(runner.position.y, pitch.width / 2, runnerThreat.isBlindsideRun ? 0.28 : 0.18),
    },
    channelCover: {
      x: lerp(runner.position.x, ownGoal.x, 0.3),
      y: lerp(runner.position.y, pitch.width / 2, 0.38),
    },
    weakSideTuck: {
      x: lerp(runner.position.x, ownGoal.x, 0.4),
      y: clamp(pitch.width / 2 - sideSign * 7.8, 10, pitch.width - 10),
    },
    pocketScreen: {
      x: runner.position.x - sign * 2.7,
      y: lerp(runner.position.y, pitch.width / 2, 0.54),
    },
    farPostCover: {
      x: lerp(runner.position.x, ownGoal.x, 0.28),
      y: clamp(pitch.width / 2 + sideSign * 9.4, 8, pitch.width - 8),
    },
    cutbackCover: {
      x: lerp(runner.position.x, ownGoal.x, 0.42),
      y: clamp(pitch.width / 2 - sideSign * 4.8, 12, pitch.width - 12),
    },
  };

  return clampToPitch(points[slot] ?? points.goalSideMark, 2.2);
}

function applyDefensiveRunnerTrackingTargets(
  teamId,
  targets,
  groups,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const threats = getDefensiveRunnerThreats(teamId, ballPoint, profile);
  if (!threats.length) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const maxAssignments =
    profile.phaseKey === "boxDefending"
      ? 4
      : profile.phaseKey === "lowBlock"
        ? 3
        : 2;
  const assignTrackingTarget = (threat, slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveRunnerTrackingTarget(teamId, threat, slot);
    const marker = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!marker) {
      return null;
    }

    targets.set(marker.id, target);
    assignedIds.add(marker.id);
    if (label) {
      labels.push(label);
    }
    return marker;
  };

  threats.slice(0, maxAssignments).forEach((threat, index) => {
    const slot =
      threat.isBlindsideRun
        ? "blindsideTrack"
        : threat.isChannelRun
          ? "channelHandover"
          : threat.farSideThreat
            ? "farPostCover"
            : threat.isBoxThreat
              ? index % 2 === 0 ? "goalSideMark" : "cutbackCover"
              : threat.isDepthThreat
                ? "depthCover"
                : threat.isBetweenLinesThreat
                  ? "pocketScreen"
                  : "goalSideMark";
    const lineKeys =
      threat.isDepthThreat || threat.isBoxThreat || threat.farSideThreat || threat.isChannelRun
        ? ["back", "midfield"]
        : ["midfield", "back"];
    const preferLabels =
      threat.isDepthThreat || threat.isBoxThreat || threat.isChannelRun
        ? ["CB", "LB", "RB", "WB", "6"]
        : ["6", "8", "10", "CB"];
    const marker = assignTrackingTarget(threat, slot, lineKeys, preferLabels, null);
    if (!marker) return;

    if (threat.isBlindsideRun) {
      labels.push("Track blindside channel run");
    } else if (threat.isChannelRun) {
      labels.push("Handover channel runner");
    } else if (threat.isPrincipleRunner) {
      labels.push("Track designed runner");
    } else if (threat.farSideThreat) {
      labels.push("Track far-side runner");
    } else if (threat.isBoxThreat) {
      labels.push("Mark box runner");
    } else if (threat.isDepthThreat) {
      labels.push("Cover depth runner");
    } else if (threat.isBetweenLinesThreat) {
      labels.push("Screen pocket runner");
    }

    if ((threat.isBlindsideRun || threat.isChannelRun) && index === 0) {
      assignTrackingTarget(
        threat,
        "channelCover",
        ["back"],
        ["CB", "LB", "RB", "WB"],
        "Cover depth behind channel run"
      );
      if (profile.phaseKey !== "highPress") {
        assignTrackingTarget(
          threat,
          "weakSideTuck",
          ["back", "midfield"],
          ["CB", "LB", "RB", "WB", "6"],
          "Weak side tucks against runner"
        );
      }
    }
  });

  return {
    labels: uniquePrincipleLabels(labels),
    focusPoint: threats[0]?.player?.position ? cloneVector(threats[0].player.position) : null,
    protectedIds: assignedIds,
  };
}

function getDribblePressureReference(actionMeta = state.draftStep) {
  const actionType = actionMeta?.actionType ?? state.ball.actionType;
  if (actionType !== "dribble") {
    return null;
  }

  const carrier = getPlayerById(actionMeta?.carrierPlayerId ?? state.ball.carrierPlayerId);
  const startPoint =
    actionMeta?.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    carrier?.position ??
    state.ball.position;
  const targetPoint = actionMeta?.target ?? state.ball.target;

  if (!startPoint || !targetPoint || distance(startPoint, targetPoint) <= 0.25) {
    return null;
  }

  return {
    carrier,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
  };
}

function chooseDefensiveDribblePresser(teamId, targets, profile, reference) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const { carrier, startPoint, targetPoint } = reference;
  const laneDistance = Math.max(distance(startPoint, targetPoint), 0.01);
  const candidates = state.players.filter(
    (player) =>
      player.team === teamId &&
      !isGoalkeeper(player) &&
      player.id !== carrier?.id
  );

  let bestCandidate = null;
  let bestScore = Infinity;

  candidates.forEach((player) => {
    const projection = projectPointOnSegmentWithRatio(player.position, startPoint, targetPoint);
    const laneGap = distance(player.position, projection.point);
    const carrierGap = distance(player.position, carrier?.position ?? startPoint);
    const baseTarget = targets.get(player.id) ?? player.position;
    const baseTargetGap = distance(baseTarget, startPoint);
    const lineKey = getDefensiveAutopilotLineKey(player, formation, profile.phaseKey);
    const canPressCarrier = carrierGap <= 18.5;
    const canCutLane =
      projection.ratio >= 0.02 &&
      projection.ratio <= 0.72 &&
      laneGap <= Math.max(7.2, laneDistance * 0.34);

    if (!canPressCarrier && !canCutLane) {
      return;
    }

    const lanePointDistance = distance(player.position, projection.point);
    const timeToCarrier = computeTimeToCoverDistance(
      player,
      Math.max(carrierGap - playerRadiusMeters * 1.35, 0),
      carrier?.position ?? startPoint
    );
    const timeToLane = computeTimeToCoverDistance(player, lanePointDistance, projection.point);
    const nearCarrierBonus = canPressCarrier ? 4.2 : 0;
    const laneCutBonus = canCutLane ? 3.2 : 0;
    const linePenalty =
      lineKey === "forward"
        ? profile.phaseKey === "highPress" ? -1.2 : 1.4
        : lineKey === "back" && profile.phaseKey === "highPress"
          ? 1.8
          : 0;
    const score =
      carrierGap * 0.46 +
      laneGap * 0.4 +
      baseTargetGap * 0.12 +
      timeToCarrier * 0.95 +
      timeToLane * 0.55 +
      Math.abs(projection.ratio - 0.22) * 4.2 +
      linePenalty -
      nearCarrierBonus -
      laneCutBonus;

    if (score < bestScore) {
      bestScore = score;
      bestCandidate = player;
    }
  });

  return bestCandidate;
}

function getDefensiveDribblePressTarget(player, reference, profile, liveBallPoint = null) {
  const { startPoint, targetPoint } = reference;
  const laneDistance = Math.max(distance(startPoint, targetPoint), 0.01);
  const projection = projectPointOnSegmentWithRatio(player.position, startPoint, targetPoint);
  const liveProgress =
    state.ball.actionType === "dribble" && state.ball.inTransit
      ? getBallTravelProgress()
      : 0;
  const ballPoint = liveBallPoint ?? (
    state.ball.actionType === "dribble" && state.ball.inTransit
      ? state.ball.position
      : startPoint
  );
  const closeToCarrier = distance(player.position, ballPoint) <= 8.5;
  const laneRatio = closeToCarrier
    ? clamp(liveProgress + 0.045, 0.04, 0.62)
    : clamp(
        Math.max(projection.ratio, liveProgress + 0.08, laneDistance > 14 ? 0.18 : 0.12),
        0.06,
        laneDistance > 18 ? 0.58 : 0.68
      );
  const lanePoint = {
    x: lerp(startPoint.x, targetPoint.x, laneRatio),
    y: lerp(startPoint.y, targetPoint.y, laneRatio),
  };
  const pressureDistance = closeToCarrier ? 0.55 : 0.15;
  const pressurePoint = moveTowards(ballPoint, lanePoint, pressureDistance);
  const insideBias =
    (profile.phaseKey === "highPress" ? 0.08 : 0.14) +
    (profile.threatResponse?.protectCenter ?? 0) * 0.16;

  return clampToPitch({
    x: pressurePoint.x,
    y: lerp(pressurePoint.y, pitch.width / 2, insideBias),
  }, 2);
}

function getDefensiveCarryContainmentContext(defensiveTeamId, ballPoint, profile, reference = getDribblePressureReference()) {
  if (!reference || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    carrierPlayerId: state.ball.carrierPlayerId,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const { carrier, startPoint, targetPoint } = reference;
  const carryDistance = distance(startPoint, targetPoint);
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId, getOffensiveAutopilotProfile(attackingTeamId, targetPoint));
  const targetThreat = actionSpace.targetThreat;
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const openGrassCarry =
    principleText.includes("open-grass") ||
    (
      carryDistance >= 9 &&
      forwardGain >= 5 &&
      actionSpace.openTarget >= 0.48 &&
      actionSpace.targetPressure <= 0.72
    );
  const dangerousCarry =
    openGrassCarry ||
    targetThreat.behindLine >= 0.24 ||
    targetThreat.centralPocket >= 0.28 ||
    targetThreat.box >= 0.18 ||
    getAttackingDepth(targetPoint, attackingTeamId) >= 54;

  if (!dangerousCarry) {
    return null;
  }

  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const isWideCarry = isWidePrincipleZone(targetPoint) || isWidePrincipleZone(startPoint);
  const finalThirdCarry =
    targetDepth >= 64 ||
    targetThreat.box >= 0.18 ||
    targetThreat.cutbackZone >= 0.24 ||
    targetThreat.behindLine >= 0.3;
  const laneMid = {
    x: lerp(startPoint.x, targetPoint.x, 0.52),
    y: lerp(startPoint.y, targetPoint.y, 0.52),
  };

  return {
    actionMeta,
    attackingTeamId,
    carrier,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    ballPoint: cloneVector(ballPoint ?? targetPoint),
    carryDistance,
    forwardGain,
    actionSpace,
    targetThreat,
    openGrassCarry,
    targetDepth,
    sideSign,
    laneMid,
    isWideCarry,
    finalThirdCarry,
    mode: finalThirdCarry
      ? "emergencyDelay"
      : openGrassCarry
        ? "openGrassDelay"
        : "normalDelay",
  };
}

function getDefensiveCarryContainmentTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const { startPoint, targetPoint, laneMid, sideSign } = context;
  const lanePoint = (ratio) => ({
    x: lerp(startPoint.x, targetPoint.x, ratio),
    y: lerp(startPoint.y, targetPoint.y, ratio),
  });
  const delayPoint = lanePoint(context.finalThirdCarry ? 0.42 : 0.36);
  const secondPressurePoint = lanePoint(context.finalThirdCarry ? 0.64 : 0.58);
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const points = {
    delayCarrier: {
      ...goalSideOf(delayPoint, context.openGrassCarry ? 1.45 : 1.1),
      y: lerp(delayPoint.y, pitch.width / 2, context.isWideCarry ? 0.12 : 0.24),
    },
    insideContain: {
      x: secondPressurePoint.x - sign * 2.8,
      y: lerp(secondPressurePoint.y, pitch.width / 2, context.isWideCarry ? 0.58 : 0.72),
    },
    channelLock: {
      x: secondPressurePoint.x - sign * 1.9,
      y: clamp(secondPressurePoint.y + sideSign * (context.isWideCarry ? 3.8 : 6.2), 3.5, pitch.width - 3.5),
    },
    depthDrop: {
      x: lerp(targetPoint.x, ownGoal.x, context.finalThirdCarry ? 0.48 : 0.36),
      y: lerp(targetPoint.y, pitch.width / 2, context.isWideCarry ? 0.4 : 0.28),
    },
    secondBallScreen: {
      x: laneMid.x - sign * 7.2,
      y: lerp(laneMid.y, pitch.width / 2, 0.62),
    },
    cutbackScreen: {
      x: lerp(targetPoint.x, ownGoal.x, context.finalThirdCarry ? 0.42 : 0.34),
      y: clamp(pitch.width / 2 + sideSign * 5.6, 12, pitch.width - 12),
    },
    farSideTuck: {
      x: lerp(targetPoint.x, ownGoal.x, context.finalThirdCarry ? 0.42 : 0.34),
      y: clamp(pitch.width / 2 - sideSign * 10.2, 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.delayCarrier, 2.2);
}

function applyDefensiveCarryContainmentTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set(),
  reference = getDribblePressureReference()
) {
  const context = getDefensiveCarryContainmentContext(teamId, ballPoint, profile, reference);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const delayTarget = getDefensiveCarryContainmentTarget(teamId, context, "delayCarrier");
  const presserCanContain =
    presser &&
    !isGoalkeeper(presser) &&
    distance(presser.position, delayTarget) <= (context.openGrassCarry ? 22 : 17);

  if (presserCanContain) {
    targets.set(presser.id, delayTarget);
    assignedIds.add(presser.id);
    labels.push(context.openGrassCarry ? "Delay open-grass carry" : "Delay ball carrier");
  } else {
    const containPlayer = pickDefensiveAutopilotPlayer(
      groups,
      context.finalThirdCarry ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      assignedIds,
      delayTarget,
      context.isWideCarry ? ["WB", "LB", "RB", "W", "8", "6"] : ["6", "8", "10", "CB", "9"]
    );
    if (containPlayer) {
      targets.set(containPlayer.id, delayTarget);
      assignedIds.add(containPlayer.id);
      presser = containPlayer;
      labels.push(context.openGrassCarry ? "Delay open-grass carry" : "Delay ball carrier");
    }
  }

  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveCarryContainmentTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("insideContain", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Block inside carry lane");

  if (context.isWideCarry) {
    assign("channelLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Lock outside channel");
  } else {
    assign("secondBallScreen", ["midfield", "forward"], ["6", "8", "10", "9"], "Screen next touch");
  }

  assign("depthDrop", ["back"], ["CB", "LB", "RB", "WB"], "Drop to protect depth");

  if (context.finalThirdCarry) {
    assign("cutbackScreen", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Protect cutback on carry");
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side protects box");
  } else if (context.openGrassCarry) {
    assign("farSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Far side narrows behind carry");
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensivePressureCoverContext(teamId, ballPoint, presser, profile) {
  if (!presser || isGoalkeeper(presser) || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    carrierPlayerId: state.ball.carrierPlayerId,
    receiverPlayerId: state.ball.receiverPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;

  if (!attackingTeamId || !targetPoint || !startPoint) {
    return null;
  }

  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(presser) ||
    getWideSideSign(startPoint) ||
    1;
  const isWidePressure = Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2) >= 0.54;
  const centralDanger =
    targetThreat.centralPocket >= 0.24 ||
    targetThreat.betweenLines >= 0.32 ||
    targetThreat.box >= 0.16 ||
    ballFromOwnGoal <= 45;
  const depthDanger =
    targetThreat.behindLine >= 0.24 ||
    actionSpace.lineBreakCount >= 1 ||
    forwardGain >= 8;

  return {
    actionMeta,
    attackingTeamId,
    presser,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    targetThreat,
    actionSpace,
    ballFromOwnGoal,
    sideSign,
    isWidePressure,
    centralDanger,
    depthDanger,
    forwardGain,
    phaseKey: profile.phaseKey,
  };
}

function getDefensivePressureCoverTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const presserTarget = context.presserTarget ?? goalSideOf(ball, 1.8);
  const coverDistance =
    context.phaseKey === "highPress"
      ? 4.8
      : context.phaseKey === "lowBlock" || context.phaseKey === "boxDefending"
        ? 6.8
        : 5.8;
  const supportDepth =
    context.phaseKey === "highPress"
      ? 4.6
      : context.phaseKey === "lowBlock" || context.phaseKey === "boxDefending"
        ? 6.4
        : 5.4;
  const triangleWidth =
    context.isWidePressure
      ? 4.8
      : context.centralDanger
        ? 3.6
        : 4.2;
  const points = {
    insideCover: {
      ...goalSideOf(presserTarget, supportDepth),
      y: lerp(
        presserTarget.y,
        pitch.width / 2,
        context.isWidePressure ? 0.72 : 0.82
      ),
    },
    pressCover: {
      x: lerp(ball.x, ownGoal.x, context.depthDanger ? 0.38 : 0.28),
      y: lerp(ball.y, pitch.width / 2, context.centralDanger ? 0.74 : 0.58),
    },
    laneScreen: {
      x: lerp(context.startPoint.x, ball.x, 0.6) - sign * (2.4 + context.targetThreat.value * 1.1),
      y: lerp(lerp(context.startPoint.y, ball.y, 0.6), pitch.width / 2, 0.18),
    },
    outsideLock: {
      x: presserTarget.x - sign * 2.2,
      y: clamp(ball.y + sideSign * triangleWidth, 3.5, pitch.width - 3.5),
    },
    weakSideBalance: {
      x: lerp(ball.x, ownGoal.x, context.depthDanger ? 0.42 : 0.34),
      y: clamp(pitch.width / 2 - sideSign * (context.phaseKey === "boxDefending" ? 7.8 : 10.8), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.insideCover, 2.2);
}

function applyDefensivePressureCoverBalanceTargets(
  teamId,
  targets,
  groups,
  presser,
  ballPoint,
  profile
) {
  const context = getDefensivePressureCoverContext(teamId, ballPoint, presser, profile);
  if (!context) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set([presser?.id].filter(Boolean)),
    };
  }

  context.presserTarget = cloneVector(
    targets.get(presser.id) ?? getDefensivePressTarget(teamId, ballPoint, profile, presser)
  );

  const labels = [];
  const assignedIds = new Set([
    presser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensivePressureCoverTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("insideCover", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Second defender covers inside");
  assign("pressCover", ["back", "midfield"], ["CB", "6", "LB", "RB", "WB"], "Third defender covers behind press");

  if (context.isWidePressure) {
    assign("outsideLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Lock outside of press");
  } else {
    assign("laneScreen", ["midfield", "forward"], ["6", "8", "10", "9"], "Screen pass behind press");
  }

  if (context.depthDanger || context.centralDanger || context.isWidePressure) {
    assign("weakSideBalance", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Balance far side");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensivePressChainSupportContext(teamId, ballPoint, presser, profile) {
  if (!presser || isGoalkeeper(presser) || !ballPoint || state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;

  if (!targetPoint || !startPoint || !["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const carrier = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(receiver) ||
    getWideSideSign(carrier) ||
    getWideSideSign(startPoint) ||
    1;
  const isWidePress = isWidePrincipleZone(targetPoint) || Math.abs(targetPoint.y - pitch.width / 2) >= 17;
  const centralRisk =
    targetThreat.centralPocket >= 0.22 ||
    targetThreat.betweenLines >= 0.28 ||
    targetThreat.box >= 0.14 ||
    actionSpace.lineBreakCount >= 1;
  const shouldChain =
    profile.pressingIntensity >= 0.48 ||
    ballFromOwnGoal <= 46 ||
    centralRisk ||
    actionType === "dribble" ||
    forwardGain >= 6;

  if (!shouldChain) {
    return null;
  }

  const attackSign = getAttackDirectionSign(attackingTeamId);
  const carrierId = carrier?.id ?? null;
  const receiverId = receiver?.id ?? null;
  const outlets = state.players
    .filter((player) => player.team === attackingTeamId && player.id !== carrierId && !isGoalkeeper(player))
    .map((player) => {
      const point = player.position;
      const gap = distance(targetPoint, point);
      if (gap < 4.5 || gap > 30) {
        return null;
      }

      const threat = getPitchThreatProfile(point, attackingTeamId);
      const forwardFromBall = (point.x - targetPoint.x) * attackSign;
      const centrality = 1 - Math.abs(point.y - pitch.width / 2) / (pitch.width / 2);
      const receiverBoost = player.id === receiverId ? 0.18 : 0;
      const score =
        threat.value * 0.52 +
        threat.centralPocket * 0.28 +
        threat.betweenLines * 0.24 +
        threat.box * 0.24 +
        clamp(forwardFromBall / 18, -0.12, 0.28) +
        centrality * 0.14 +
        receiverBoost +
        clamp((22 - gap) / 22, 0, 0.22);

      return {
        player,
        point: cloneVector(point),
        threat,
        gap,
        forwardFromBall,
        score,
      };
    })
    .filter(Boolean)
    .sort((a, b) => b.score - a.score)
    .slice(0, 3);

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    carrier,
    receiver,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    targetThreat,
    actionSpace,
    ballFromOwnGoal,
    forwardGain,
    sideSign,
    isWidePress,
    centralRisk,
    outlets,
    phaseKey: profile.phaseKey,
  };
}

function getDefensivePressChainSupportTarget(teamId, context, slot, outlet = null) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const outletPoint = outlet?.point ?? ball;
  const supportDepth =
    context.phaseKey === "highPress"
      ? 4.6
      : context.phaseKey === "lowBlock" || context.phaseKey === "boxDefending"
        ? 7.2
        : 5.8;
  const points = {
    secondWave: {
      ...goalSideOf(ball, supportDepth),
      y: lerp(ball.y, pitch.width / 2, context.isWidePress ? 0.72 : 0.82),
    },
    insideGate: {
      x: lerp(ball.x, ownGoal.x, context.centralRisk ? 0.22 : 0.16),
      y: lerp(ball.y, pitch.width / 2, context.isWidePress ? 0.86 : 0.72),
    },
    touchlineLock: {
      x: ball.x - sign * (context.phaseKey === "highPress" ? 2.8 : 3.8),
      y: clamp(ball.y + sideSign * 5.2, 3.5, pitch.width - 3.5),
    },
    outletLock: {
      ...goalSideOf({
        x: lerp(outletPoint.x, ball.x, 0.24),
        y: lerp(outletPoint.y, pitch.width / 2, outlet?.threat?.centralPocket >= 0.22 ? 0.24 : 0.1),
      }, outlet?.threat?.value >= 0.34 ? 1.65 : 1.1),
    },
    weakSideBalance: {
      x: lerp(ball.x, ownGoal.x, context.centralRisk ? 0.38 : 0.3),
      y: clamp(pitch.width / 2 - sideSign * (context.phaseKey === "boxDefending" ? 7.2 : 10.6), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.secondWave, 2.2);
}

function applyDefensivePressChainSupportTargets(
  teamId,
  targets,
  groups,
  presser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensivePressChainSupportContext(teamId, ballPoint, presser, profile);
  if (!context) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    presser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const assign = (slot, lineKeys, preferLabels, label, outlet = null) => {
    const target = getDefensivePressChainSupportTarget(teamId, context, slot, outlet);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("secondWave", ["midfield", "back"], ["6", "8", "CB", "10"], "Press chain: second wave covers");
  assign("insideGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Press chain: close inside gate");

  context.outlets.slice(0, context.centralRisk ? 2 : 1).forEach((outlet, index) => {
    assign(
      "outletLock",
      index === 0 ? ["midfield", "forward", "back"] : ["midfield", "back", "forward"],
      outlet.threat.box >= 0.12 || outlet.threat.centralPocket >= 0.22
        ? ["6", "8", "CB", "10"]
        : ["W", "8", "LB", "RB", "WB", "10"],
      index === 0 ? "Press chain: lock first outlet" : "Press chain: lock next outlet",
      outlet
    );
  });

  if (context.isWidePress) {
    assign("touchlineLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Press chain: lock touchline");
  }

  if (context.centralRisk || context.ballFromOwnGoal <= 42 || context.isWidePress) {
    assign("weakSideBalance", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Press chain: far side balances");
  }

  if (labels.length) {
    labels.unshift("Defensive press chain support");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getActualLocalSuperiorityProfile(attackingTeamId, defendingTeamId, hubPoint, excludedIds = new Set(), radius = 15) {
  if (!attackingTeamId || !defendingTeamId || !hubPoint) {
    return null;
  }

  const attackSign = getAttackDirectionSign(attackingTeamId);
  const sideSign = getWideSideSign(hubPoint) || 1;
  const sectors = {
    under: 0,
    forward: 0,
    inside: 0,
    outside: 0,
    lateral: 0,
  };
  const supporters = state.players
    .filter((player) => player.team === attackingTeamId && !isGoalkeeper(player) && !excludedIds.has(player.id))
    .map((player) => {
      const gap = distance(player.position, hubPoint);
      if (gap > radius || gap < 2.2) {
        return null;
      }

      const forwardGap = (player.position.x - hubPoint.x) * attackSign;
      const lateralGap = Math.abs(player.position.y - hubPoint.y);
      const isInside = Math.abs(player.position.y - pitch.width / 2) < Math.abs(hubPoint.y - pitch.width / 2) - 1.2;
      const isOutside = (player.position.y - hubPoint.y) * sideSign > 1.6;
      if (forwardGap <= -2.5) {
        sectors.under += 1;
      }
      if (forwardGap >= 3) {
        sectors.forward += 1;
      }
      if (lateralGap >= 4) {
        sectors.lateral += 1;
      }
      if (isInside) {
        sectors.inside += 1;
      }
      if (isOutside) {
        sectors.outside += 1;
      }

      return {
        player,
        point: cloneVector(player.position),
        gap,
        forwardGap,
        lateralGap,
        isInside,
        isOutside,
        threat: getPitchThreatProfile(player.position, attackingTeamId),
      };
    })
    .filter(Boolean)
    .sort((a, b) => {
      const aScore = a.threat.value * 0.5 + clamp((radius - a.gap) / radius, 0, 1) * 0.5;
      const bScore = b.threat.value * 0.5 + clamp((radius - b.gap) / radius, 0, 1) * 0.5;
      return bScore - aScore;
    });

  const defenders = state.players
    .filter((player) => player.team === defendingTeamId && !isGoalkeeper(player))
    .map((player) => {
      const gap = distance(player.position, hubPoint);
      if (gap > radius + 1.5) {
        return null;
      }
      return {
        player,
        point: cloneVector(player.position),
        gap,
      };
    })
    .filter(Boolean)
    .sort((a, b) => a.gap - b.gap);

  const sectorVariety = Object.values(sectors).filter((count) => count > 0).length;
  return {
    attackingTeamId,
    defendingTeamId,
    hubPoint: cloneVector(hubPoint),
    supporters,
    defenders,
    sectors,
    sectorVariety,
    supportCount: supporters.length,
    defenderCount: defenders.length,
    sideSign,
  };
}

function getDefensiveLocalOverloadContext(teamId, ballPoint, presser, profile = {}) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(teamId);
  const plannedPossessionTeamId = getPlannedPossessionTeamId();
  if (!attackingTeamId || (plannedPossessionTeamId && plannedPossessionTeamId !== attackingTeamId)) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    carrierPlayerId: state.ball.carrierPlayerId,
    receiverPlayerId: state.ball.receiverPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint ?? state.ball.position;
  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    targetPoint;

  if (!targetPoint || !startPoint || !["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const carrierId =
    actionMeta.carrierPlayerId ??
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
    state.ball.initiatorPlayerId ??
    state.ball.ownerPlayerId ??
    null;
  const receiverId = actionMeta.receiverPlayerId ?? null;
  const excludedIds = new Set([carrierId, receiverId].filter(Boolean));
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(
    startPoint,
    targetPoint,
    attackingTeamId,
    getOffensiveAutopilotProfile(attackingTeamId, targetPoint)
  );
  const actionDistance = distance(startPoint, targetPoint);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(teamId, targetPoint);
  const radius =
    profile.phaseKey === "lowBlock" || profile.phaseKey === "boxDefending"
      ? 13.5
      : actionType === "dribble"
        ? 12.5
        : 15.5;
  const local = getActualLocalSuperiorityProfile(attackingTeamId, teamId, targetPoint, excludedIds, radius);
  if (!local) {
    return null;
  }

  const centralRisk =
    targetThreat.centralPocket >= 0.2 ||
    targetThreat.betweenLines >= 0.28 ||
    targetThreat.box >= 0.12 ||
    actionSpace.lineBreakCount >= 1 ||
    ballFromOwnGoal <= 45;
  const wideRisk = isWidePrincipleZone(targetPoint) || Math.abs(targetPoint.y - pitch.width / 2) >= 17;
  const supportTriangle = local.supportCount >= 2 && local.sectorVariety >= 2;
  const bounceRisk = local.sectors.under >= 1 && (local.sectors.lateral >= 1 || local.sectors.inside >= 1);
  const overloadScore =
    (local.supportCount - local.defenderCount) * 0.52 +
    local.sectorVariety * 0.16 +
    (supportTriangle ? 0.2 : 0) +
    (bounceRisk ? 0.18 : 0) +
    (centralRisk ? 0.24 : 0) +
    (wideRisk && local.supportCount >= 2 ? 0.12 : 0) +
    clamp(forwardGain / 18, -0.08, 0.22) +
    clamp((targetDepth - 48) / 36, 0, 0.2);
  const shouldRespond =
    overloadScore >= 0.62 ||
    (supportTriangle && local.defenderCount <= local.supportCount) ||
    (centralRisk && local.supportCount >= 1 && local.defenderCount <= 2) ||
    (actionType === "dribble" && targetDepth >= 50 && local.defenderCount <= 2);

  if (!shouldRespond) {
    return null;
  }

  const mode = wideRisk
    ? "wideTrap"
    : centralRisk
      ? "centralLock"
      : "supportDeny";

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    presser,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    targetThreat,
    actionSpace,
    actionDistance,
    forwardGain,
    targetDepth,
    ballFromOwnGoal,
    local,
    radius,
    centralRisk,
    wideRisk,
    supportTriangle,
    bounceRisk,
    overloadScore,
    mode,
    phaseKey: profile.phaseKey,
    sideSign: local.sideSign || getWideSideSign(targetPoint) || 1,
  };
}

function getDefensiveLocalOverloadTarget(teamId, context, slot, support = null) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const supportPoint = support?.point ?? support?.player?.position ?? ball;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const points = {
    pressHub: {
      ...goalSideOf(ball, context.phaseKey === "highPress" ? 1.2 : 1.8),
      y: lerp(ball.y, pitch.width / 2, context.wideRisk ? 0.12 : 0.2),
    },
    underScreen: {
      x: ball.x - sign * (context.centralRisk ? 5.6 : 4.8),
      y: lerp(ball.y, supportPoint.y, 0.42),
    },
    insideGate: {
      x: lerp(ball.x, ownGoal.x, context.centralRisk ? 0.24 : 0.18),
      y: lerp(ball.y, pitch.width / 2, context.wideRisk ? 0.82 : 0.68),
    },
    outsideLock: {
      x: ball.x - sign * (context.phaseKey === "highPress" ? 1.4 : 2.2),
      y: clamp(ball.y + sideSign * 4.6, 3.5, pitch.width - 3.5),
    },
    outletDeny: {
      ...goalSideOf({
        x: lerp(supportPoint.x, ball.x, 0.22),
        y: lerp(supportPoint.y, pitch.width / 2, support?.threat?.centralPocket >= 0.2 ? 0.18 : 0.08),
      }, support?.threat?.value >= 0.34 ? 1.4 : 1.0),
    },
    depthCover: {
      x: lerp(ball.x, ownGoal.x, context.targetDepth >= 62 || context.actionSpace.lineBreakCount >= 1 ? 0.44 : 0.32),
      y: lerp(ball.y, pitch.width / 2, context.wideRisk ? 0.4 : 0.26),
    },
    weakSideTuck: {
      x: lerp(ball.x, ownGoal.x, context.centralRisk || context.targetDepth >= 58 ? 0.42 : 0.34),
      y: clamp(pitch.width / 2 - sideSign * (context.phaseKey === "boxDefending" ? 7.6 : 10.4), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.insideGate, 2.2);
}

function applyDefensiveLocalOverloadResponseTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveLocalOverloadContext(teamId, ballPoint, basePresser, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const pressTarget = getDefensiveLocalOverloadTarget(teamId, context, "pressHub");
  const presserCanLock =
    presser &&
    !isGoalkeeper(presser) &&
    !assignedIds.has(presser.id) &&
    distance(presser.position, pressTarget) <= (context.phaseKey === "lowBlock" ? 16 : 20);

  if (presserCanLock) {
    targets.set(presser.id, pressTarget);
    assignedIds.add(presser.id);
    labels.push("Local overload: pressure ball");
  } else {
    const pressurePlayer = pickDefensiveAutopilotPlayer(
      groups,
      context.wideRisk ? ["midfield", "back", "forward"] : ["midfield", "forward", "back"],
      assignedIds,
      pressTarget,
      context.wideRisk ? ["W", "WB", "LB", "RB", "8", "10"] : ["6", "8", "10", "9", "CB"]
    );
    if (pressurePlayer) {
      targets.set(pressurePlayer.id, pressTarget);
      assignedIds.add(pressurePlayer.id);
      presser = pressurePlayer;
      labels.push("Local overload: pressure ball");
    }
  }

  const assign = (slot, lineKeys, preferLabels, label, support = null) => {
    const target = getDefensiveLocalOverloadTarget(teamId, context, slot, support);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const underSupport = context.local.supporters.find((support) => support.forwardGap <= -2.5) ?? context.local.supporters[0] ?? null;
  const firstOutlet =
    context.local.supporters.find((support) => support.threat.centralPocket >= 0.18 || support.threat.box >= 0.1) ??
    context.local.supporters.find((support) => support.lateralGap >= 4) ??
    context.local.supporters[0] ??
    null;

  if (underSupport || context.bounceRisk) {
    assign("underScreen", ["midfield", "back"], ["6", "8", "10", "CB"], "Local overload: deny bounce pass", underSupport);
  }

  assign("insideGate", ["midfield", "back"], ["6", "8", "CB", "10", "LB", "RB", "WB"], "Local overload: close inside gate");

  if (context.wideRisk) {
    assign("outsideLock", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Local overload: lock outside lane");
  }

  if (firstOutlet) {
    assign(
      "outletDeny",
      firstOutlet.threat.box >= 0.12 || firstOutlet.threat.centralPocket >= 0.2
        ? ["midfield", "back", "forward"]
        : ["midfield", "forward", "back"],
      firstOutlet.threat.box >= 0.12 || firstOutlet.threat.centralPocket >= 0.2
        ? ["6", "8", "CB", "10"]
        : ["W", "8", "10", "LB", "RB", "WB"],
      "Local overload: deny nearest outlet",
      firstOutlet
    );
  }

  if (context.centralRisk || context.targetDepth >= 58 || context.actionSpace.lineBreakCount >= 1) {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Local overload: protect depth behind");
  }

  if (context.local.supportCount >= 2 || context.wideRisk || context.centralRisk) {
    assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Local overload: weak side tucks in");
  }

  if (labels.length) {
    labels.unshift(
      context.mode === "wideTrap"
        ? "Defensive local overload response: wide trap"
        : context.mode === "centralLock"
          ? "Defensive local overload response: central lock"
          : "Defensive local overload response"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensivePostRecoveryResponseContext(defensiveTeamId, ballPoint, profile = {}) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const plannedPossessionTeamId = getPlannedPossessionTeamId();
  if (!attackingTeamId || (plannedPossessionTeamId && plannedPossessionTeamId !== attackingTeamId)) {
    return null;
  }

  const steps = state.sequence?.steps ?? [];
  let recoveryIndex = -1;
  for (let index = steps.length - 1; index >= 0; index -= 1) {
    const step = steps[index];
    const possessionTeamId = getRecordedStepPossessionTeamId(step);
    const isRecovery =
      step?.actionType === "recovery" ||
      step?.profileKey === "loose-ball-recovery" ||
      `${step?.profileLabel ?? ""}`.toLowerCase().includes("loose ball");

    if (isRecovery && possessionTeamId === attackingTeamId) {
      recoveryIndex = index;
      break;
    }

    if (possessionTeamId && possessionTeamId !== attackingTeamId) {
      break;
    }
  }

  if (recoveryIndex < 0) {
    return null;
  }

  const actionsAfterRecovery = steps.slice(recoveryIndex + 1);
  if (actionsAfterRecovery.length > 4) {
    return null;
  }

  if (actionsAfterRecovery.some((step) => getRecordedStepPossessionTeamId(step) !== attackingTeamId)) {
    return null;
  }

  const elapsed = actionsAfterRecovery.reduce(
    (total, step) => total + getRecordedStepDuration(step),
    0
  );
  if (elapsed > 10.5) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    autoPrinciples: [],
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position;
  const targetPoint =
    actionMeta.target ??
    ballPoint ??
    state.ball.target ??
    state.ball.position;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const recoveryStep = steps[recoveryIndex];
  const recoveryPoint =
    recoveryStep?.target ??
    recoveryStep?.afterSnapshot?.ball?.position ??
    startPoint;
  const originDepth = getAttackingDepth(recoveryPoint, attackingTeamId);
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const currentDepth = getAttackingDepth(startPoint, attackingTeamId);
  const depthGainSinceRecovery = currentDepth - originDepth;
  const actionForwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const actionDistance = distance(startPoint, targetPoint);
  const attackingProfile = getOffensiveAutopilotProfile(attackingTeamId, targetPoint);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId, attackingProfile);
  const targetThreat = actionSpace.targetThreat;
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetPoint) - getPitchLaneIndex(startPoint));
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const patterns = actionsAfterRecovery
    .map((step) => getRecordedStepPattern(step, attackingTeamId))
    .filter(Boolean);
  const sidewaysOrBackCount = patterns.filter((pattern) => pattern.forwardGain <= 2.5).length;
  const lineBreakCount = patterns.filter((pattern) => pattern.family === "line-break" || pattern.forwardGain >= 9).length;
  const laneVariety = new Set(patterns.map((pattern) => pattern.laneKey).filter(Boolean)).size;
  const sameLaneStall = actionsAfterRecovery.length >= 2 && laneVariety <= 1 && depthGainSinceRecovery < 8;
  const localDefensiveAccess = getTeamSupportCountAroundPoint(
    defensiveTeamId,
    targetPoint,
    new Set(),
    10.5
  );
  const localAttackingSupport = getTeamSupportCountAroundPoint(
    attackingTeamId,
    targetPoint,
    new Set([actionMeta.receiverPlayerId, actionMeta.carrierPlayerId].filter(Boolean)),
    13
  );
  const transitionThreat =
    actionForwardGain >= 6 &&
    (
      actionSpace.lineBreakCount >= 1 ||
      targetThreat.behindLine >= 0.2 ||
      targetThreat.centralPocket >= 0.24 ||
      targetThreat.box >= 0.14 ||
      targetDepth >= 58
    );
  const secureExit =
    actionType === "pass" &&
    actionDistance <= 22 &&
    actionForwardGain >= -8 &&
    actionSpace.targetPressure <= 0.72;
  const switchExit =
    actionType === "pass" &&
    laneShift >= 2 &&
    actionDistance >= 16;
  const finalThirdThreat =
    ballFromOwnGoal <= 42 ||
    targetThreat.box >= 0.14 ||
    targetThreat.cutbackZone >= 0.2 ||
    targetThreat.assistZone >= 0.32;
  const directAttackStyle = isTransitionAttackStyle(attackingProfile.styleKey);
  const pressStyle = ["counter-press", "gegenpress", "high-press", "press-trap-wide"].includes(profile.styleKey);
  const delayNeed = clamp(
    (transitionThreat ? 0.34 : 0) +
      actionSpace.value * 0.22 +
      clamp((52 - ballFromOwnGoal) / 34, 0, 1) * 0.24 +
      (directAttackStyle ? 0.14 : 0) +
      (localDefensiveAccess <= 1 ? 0.08 : 0),
    0,
    1.1
  );
  const jumpNeed = clamp(
    (secureExit ? 0.24 : 0) +
      (switchExit ? 0.18 : 0) +
      (pressStyle ? 0.22 : 0) +
      (profile.pressingIntensity ?? 0.5) * 0.24 +
      (sameLaneStall ? 0.12 : 0),
    0,
    1.1
  );
  const recoverNeed = clamp(
    clamp((44 - ballFromOwnGoal) / 28, 0, 1) * 0.32 +
      (finalThirdThreat ? 0.2 : 0) +
      (transitionThreat && localDefensiveAccess <= 1 ? 0.16 : 0) +
      (profile.phaseKey === "lowBlock" || profile.phaseKey === "boxDefending" ? 0.14 : 0),
    0,
    1.1
  );
  const mode =
    delayNeed >= Math.max(0.52, jumpNeed * 0.92) || transitionThreat
      ? "delayCounter"
      : jumpNeed >= Math.max(0.5, recoverNeed * 0.9)
        ? "jumpFirstPass"
        : "recoverShape";

  return {
    active: true,
    defensiveTeamId,
    attackingTeamId,
    actionMeta,
    actionType,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    recoveryPoint: cloneVector(recoveryPoint),
    actionsAfterRecovery: actionsAfterRecovery.length,
    elapsed,
    originDepth,
    currentDepth,
    targetDepth,
    depthGainSinceRecovery,
    actionForwardGain,
    actionDistance,
    actionSpace,
    targetThreat,
    ballFromOwnGoal,
    laneShift,
    sideSign,
    sidewaysOrBackCount,
    lineBreakCount,
    laneVariety,
    sameLaneStall,
    localDefensiveAccess,
    localAttackingSupport,
    transitionThreat,
    secureExit,
    switchExit,
    finalThirdThreat,
    directAttackStyle,
    pressStyle,
    delayNeed,
    jumpNeed,
    recoverNeed,
    mode,
  };
}

function getDefensivePostRecoveryResponseTarget(teamId, context, slot, outlet = null) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const ball = context.targetPoint;
  const start = context.startPoint;
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const routePoint = (ratio) => ({
    x: lerp(start.x, ball.x, ratio),
    y: lerp(start.y, ball.y, ratio),
  });
  const gateDepth = clamp(context.ballFromOwnGoal + (context.finalThirdThreat ? 4.5 : 7.5), 16, 52);
  const coverDepth = clamp(context.ballFromOwnGoal - (context.finalThirdThreat ? 3.8 : 7.2), 7.5, 38);
  const outletPoint = outlet?.position ?? outlet?.point ?? ball;
  const points = {
    delayCarrier: {
      ...goalSideOf(context.actionType === "dribble" ? routePoint(0.74) : ball, context.transitionThreat ? 1.35 : 1.85),
      y: lerp(ball.y, pitch.width / 2, context.targetThreat.centralPocket >= 0.24 ? 0.28 : 0.16),
    },
    jumpFirstPass: {
      x: lerp(start.x, ball.x, context.secureExit ? 0.7 : 0.54) - sign * 1.25,
      y: lerp(start.y, ball.y, 0.68),
    },
    centralGate: {
      x: getDepthX(teamId, gateDepth),
      y: lerp(ball.y, pitch.width / 2, context.finalThirdThreat ? 0.88 : 0.74),
    },
    counterLaneGate: {
      x: lerp(ball.x, ownGoal.x, context.finalThirdThreat ? 0.22 : 0.16),
      y: lerp(ball.y, pitch.width / 2, context.targetThreat.centralPocket >= 0.24 ? 0.82 : 0.62),
    },
    firstOutletLock: {
      ...goalSideOf({
        x: lerp(outletPoint.x, ball.x, 0.22),
        y: lerp(outletPoint.y, pitch.width / 2, 0.14),
      }, context.transitionThreat ? 1.55 : 1.1),
    },
    switchLock: {
      x: lerp(ball.x, ownGoal.x, 0.24),
      y: clamp(pitch.width / 2 - sideSign * 16.5, 4.5, pitch.width - 4.5),
    },
    restLineCover: {
      x: getDepthX(teamId, coverDepth),
      y: lerp(ball.y, pitch.width / 2, context.finalThirdThreat ? 0.46 : 0.36),
    },
    weakSideRecover: {
      x: lerp(ball.x, ownGoal.x, context.finalThirdThreat ? 0.4 : 0.32),
      y: clamp(pitch.width / 2 - sideSign * (context.finalThirdThreat ? 8.4 : 12.4), 7, pitch.width - 7),
    },
    boxCover: {
      x: getDepthX(teamId, clamp(context.ballFromOwnGoal - 1.8, 7.5, 23)),
      y: clamp(pitch.width / 2 + sideSign * 4.6, 10, pitch.width - 10),
    },
    farPostCover: {
      x: getDepthX(teamId, clamp(context.ballFromOwnGoal - 3.8, 6.5, 20)),
      y: clamp(pitch.width / 2 - sideSign * 9.4, 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.centralGate, 2.1);
}

function getDefensivePostRecoveryOutletOptions(context) {
  const attackSign = getAttackDirectionSign(context.attackingTeamId);
  return state.players
    .filter((player) => player.team === context.attackingTeamId && !isGoalkeeper(player))
    .map((player) => {
      const forwardGap = (player.position.x - context.targetPoint.x) * attackSign;
      const gap = distance(player.position, context.targetPoint);
      const threat = getPitchThreatProfile(player.position, context.attackingTeamId);
      const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
      const outletScore =
        threat.value * 0.44 +
        clamp(forwardGap / 18, -0.08, 0.34) +
        (["striker", "wideForward", "secondStriker", "connector"].includes(roleKey) ? 0.18 : 0) -
        gap * 0.014;

      return {
        player,
        position: cloneVector(player.position),
        roleKey,
        threat,
        gap,
        outletScore,
      };
    })
    .filter((option) => option.gap <= 30 && option.outletScore >= 0.08)
    .sort((a, b) => b.outletScore - a.outletScore);
}

function applyDefensivePostRecoveryResponseTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensivePostRecoveryResponseContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label, outlet = null) => {
    const target = getDefensivePostRecoveryResponseTarget(teamId, context, slot, outlet);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const delayTarget = getDefensivePostRecoveryResponseTarget(
    teamId,
    context,
    context.mode === "jumpFirstPass" ? "jumpFirstPass" : "delayCarrier"
  );
  const presserCanRespond =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, delayTarget) <= (context.transitionThreat ? 24 : 19);

  if (presserCanRespond) {
    targets.set(presser.id, delayTarget);
    assignedIds.add(presser.id);
    labels.push(context.mode === "jumpFirstPass" ? "Post-recovery defence: jump first pass" : "Post-recovery defence: delay counter");
  } else {
    const delayPlayer = assign(
      context.mode === "jumpFirstPass" ? "jumpFirstPass" : "delayCarrier",
      context.finalThirdThreat ? ["back", "midfield", "forward"] : ["midfield", "forward", "back"],
      context.mode === "jumpFirstPass" ? ["9", "10", "W", "8", "6"] : ["6", "8", "CB", "10", "WB", "LB", "RB"],
      context.mode === "jumpFirstPass" ? "Post-recovery defence: jump first pass" : "Post-recovery defence: delay counter"
    );
    presser = delayPlayer ?? presser;
  }

  const outlets = getDefensivePostRecoveryOutletOptions(context);
  assign("centralGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Post-recovery defence: close central gate");

  if (context.transitionThreat || context.mode === "delayCounter") {
    assign("counterLaneGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Post-recovery defence: block counter lane");
  }

  outlets.slice(0, context.transitionThreat ? 2 : 1).forEach((outlet, index) => {
    assign(
      "firstOutletLock",
      index === 0 ? ["midfield", "forward", "back"] : ["midfield", "back", "forward"],
      outlet.threat.box >= 0.12 || outlet.threat.centralPocket >= 0.2
        ? ["6", "8", "CB", "10"]
        : ["W", "8", "LB", "RB", "WB", "10"],
      index === 0 ? "Post-recovery defence: lock first outlet" : "Post-recovery defence: lock next outlet",
      outlet
    );
  });

  if (context.switchExit || context.sameLaneStall) {
    assign("switchLock", ["back", "midfield"], ["WB", "LB", "RB", "W", "8"], "Post-recovery defence: protect switch");
  }

  assign("restLineCover", ["back"], ["CB", "LB", "RB", "WB"], "Post-recovery defence: protect depth");
  assign("weakSideRecover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Post-recovery defence: weak side recovers");

  if (context.finalThirdThreat) {
    assign("boxCover", ["back", "midfield"], ["CB", "6", "LB", "RB", "WB"], "Post-recovery defence: protect box");
    assign("farPostCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Post-recovery defence: cover far post");
  }

  if (labels.length) {
    labels.unshift(
      context.mode === "delayCounter"
        ? "Defend post-recovery counter"
        : context.mode === "jumpFirstPass"
          ? "Defend post-recovery first pass"
          : "Defend post-recovery shape"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensivePassLaneDenialContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };

  if (!attackingTeamId || actionMeta.actionType !== "pass") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position;
  const targetPoint = actionMeta.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const passDistance = distance(startPoint, targetPoint);
  if (passDistance < 6) {
    return null;
  }

  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const targetThreat = actionSpace.targetThreat;
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(receiver) ||
    getWideSideSign(startPoint) ||
    1;
  const laneDanger =
    actionSpace.lineBreakCount >= 1 ||
    forwardGain >= 7 ||
    targetThreat.betweenLines >= 0.28 ||
    targetThreat.centralPocket >= 0.22 ||
    targetThreat.box >= 0.16 ||
    targetThreat.assistZone >= 0.32;
  const isWidePass = isWidePrincipleZone(targetPoint) || isWidePrincipleZone(startPoint);

  if (!laneDanger && passDistance < 13) {
    return null;
  }

  return {
    actionMeta,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    receiver,
    passDistance,
    forwardGain,
    actionSpace,
    targetThreat,
    sideSign,
    laneDanger,
    isWidePass,
    phaseKey: profile.phaseKey,
  };
}

function getDefensivePassLaneDenialTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const lanePoint = (ratio) => ({
    x: lerp(context.startPoint.x, context.targetPoint.x, ratio),
    y: lerp(context.startPoint.y, context.targetPoint.y, ratio),
  });
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const sideSign = context.sideSign || 1;
  const nearLane = lanePoint(context.passDistance >= 22 ? 0.34 : 0.42);
  const midLane = lanePoint(0.58);
  const lateLane = lanePoint(context.passDistance >= 22 ? 0.72 : 0.68);
  const points = {
    carrierShadow: {
      ...goalSideOf(nearLane, context.phaseKey === "highPress" ? 1.15 : 1.8),
      y: lerp(nearLane.y, pitch.width / 2, context.isWidePass ? 0.22 : 0.36),
    },
    centralLaneScreen: {
      ...goalSideOf(midLane, context.laneDanger ? 3.4 : 2.4),
      y: lerp(midLane.y, pitch.width / 2, context.isWidePass ? 0.42 : 0.68),
    },
    receiverShadow: {
      ...goalSideOf(lateLane, context.targetThreat.box >= 0.16 ? 2.2 : 1.7),
      y: lerp(lateLane.y, pitch.width / 2, context.isWidePass ? 0.18 : 0.32),
    },
    outsideTrap: {
      x: lateLane.x - sign * 1.8,
      y: clamp(lateLane.y + sideSign * 4.6, 3.5, pitch.width - 3.5),
    },
    depthCover: {
      x: lerp(context.targetPoint.x, ownGoal.x, context.targetThreat.box >= 0.2 ? 0.42 : 0.32),
      y: lerp(context.targetPoint.y, pitch.width / 2, context.isWidePass ? 0.44 : 0.28),
    },
    weakSideTuck: {
      x: lerp(context.targetPoint.x, ownGoal.x, 0.34),
      y: clamp(pitch.width / 2 - sideSign * (context.phaseKey === "boxDefending" ? 7.2 : 10.5), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.centralLaneScreen, 2.2);
}

function applyDefensivePassLaneDenialTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensivePassLaneDenialContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    basePresser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensivePassLaneDenialTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  assign("carrierShadow", ["forward", "midfield"], ["9", "10", "W", "8", "6"], "Cover shadow from ball");
  assign("centralLaneScreen", ["midfield", "back"], ["6", "8", "CB", "10"], "Deny central pass lane");
  assign("receiverShadow", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Arrive goal-side of receiver");

  if (context.isWidePass) {
    assign("outsideTrap", ["back", "midfield"], ["WB", "LB", "RB", "W"], "Trap outside receiving lane");
  }

  if (
    context.actionSpace.lineBreakCount >= 1 ||
    context.targetThreat.behindLine >= 0.22 ||
    context.targetThreat.box >= 0.16 ||
    context.forwardGain >= 10
  ) {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Cover behind pass lane");
  }

  if (
    context.passDistance >= 20 ||
    context.targetThreat.assistZone >= 0.32 ||
    context.targetThreat.box >= 0.18
  ) {
    assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Weak side narrows behind lane");
  }

  if (labels.length) {
    labels.unshift("Deny pass lane");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveCentralAccessGateContext(defensiveTeamId, ballPoint, profile) {
  if (state.restartPhase?.type || !ballPoint) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (actionType !== "pass" && actionType !== "dribble") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    state.ball.position ??
    ballPoint;
  const targetPoint = actionMeta.target ?? state.ball.target ?? ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const carrier = getPlayerById(
    actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      actionMeta.carrierPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const startThreat = getPitchThreatProfile(startPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(
    startPoint,
    targetPoint,
    attackingTeamId,
    getOffensiveAutopilotProfile(attackingTeamId, targetPoint)
  );
  const targetGameSpace = getAttackingGameSpaceProfile(targetPoint, attackingTeamId);
  const startGameSpace = getAttackingGameSpaceProfile(startPoint, attackingTeamId);
  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const actionDistance = distance(startPoint, targetPoint);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const centrality = 1 - Math.abs(targetPoint.y - pitch.width / 2) / (pitch.width / 2);
  const carrierPressure = carrier ? getPlayerPressureLoad(carrier, startPoint) : 0.48;
  const laneClarity =
    carrier && actionType === "pass"
      ? computePassLaneClarity(carrier, targetPoint, { receiverPlayerId: receiver?.id })
      : clamp(0.54 + actionSpace.openTarget * 0.18 - carrierPressure * 0.1, 0.22, 0.9);
  const principleText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isSpaceTwoEntry =
    targetGameSpace.key === "space2" ||
    targetThreat.betweenLines >= 0.3 ||
    (
      targetGameSpace.index > startGameSpace.index &&
      targetGameSpace.index >= 2 &&
      forwardGain >= 3.5
    );
  const isCentralOrHalfSpace =
    targetThreat.centralPocket >= 0.2 ||
    targetThreat.halfSpace >= 0.32 ||
    centrality >= 0.46 ||
    Math.abs(targetPoint.y - pitch.width / 2) <= 18;
  const canFaceForward =
    carrierPressure <= 0.5 &&
    laneClarity >= 0.42 &&
    (
      targetThreat.centralPocket >= 0.2 ||
      targetThreat.betweenLines >= 0.28 ||
      targetThreat.halfSpace >= 0.34 ||
      actionSpace.value >= 0.32
    );
  const receiveToTurnCue =
    receiver &&
    actionType === "pass" &&
    actionDistance >= 6 &&
    (
      isSpaceTwoEntry ||
      principleText.includes("space 2") ||
      principleText.includes("between") ||
      principleText.includes("line-break")
    );
  const carryIntoGateCue =
    actionType === "dribble" &&
    forwardGain >= 4 &&
    isCentralOrHalfSpace &&
    (
      targetThreat.betweenLines >= 0.24 ||
      targetThreat.centralPocket >= 0.18 ||
      actionSpace.lineBreakCount >= 1 ||
      actionSpace.value >= 0.28
    );
  const active =
    ballFromOwnGoal <= 68 &&
    isCentralOrHalfSpace &&
    (
      receiveToTurnCue ||
      carryIntoGateCue ||
      canFaceForward ||
      (isSpaceTwoEntry && forwardGain >= 2.5)
    );

  if (!active) {
    return null;
  }

  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(receiver) ||
    getWideSideSign(startPoint) ||
    Math.sign(targetPoint.y - pitch.width / 2) ||
    1;
  const dangerScore = clamp(
    targetThreat.centralPocket * 0.44 +
      targetThreat.betweenLines * 0.42 +
      targetThreat.halfSpace * 0.28 +
      targetThreat.box * 0.22 +
      clamp(actionSpace.lineBreakCount / 2, 0, 1) * 0.26 +
      clamp(forwardGain / 16, 0, 1) * 0.18 +
      (canFaceForward ? 0.18 : 0) +
      (receiveToTurnCue ? 0.12 : 0) -
      carrierPressure * 0.08,
    0,
    1.35
  );

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    carrier,
    receiver,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    targetThreat,
    startThreat,
    actionSpace,
    targetGameSpace,
    startGameSpace,
    forwardGain,
    actionDistance,
    ballFromOwnGoal,
    centrality,
    carrierPressure,
    laneClarity,
    isSpaceTwoEntry,
    isCentralOrHalfSpace,
    canFaceForward,
    receiveToTurnCue,
    carryIntoGateCue,
    sideSign,
    dangerScore,
    mode: carryIntoGateCue
      ? "carryGate"
      : receiveToTurnCue
        ? "receiveGate"
        : "centralScreen",
  };
}

function getDefensiveCentralAccessGateTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const lanePoint = (ratio) => ({
    x: lerp(context.startPoint.x, target.x, ratio),
    y: lerp(context.startPoint.y, target.y, ratio),
  });
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const gateDepth = clamp(
    context.ballFromOwnGoal + (context.targetThreat.box >= 0.14 ? 2.6 : 5.4),
    context.ballFromOwnGoal <= 34 ? 13 : 20,
    context.ballFromOwnGoal <= 44 ? 45 : 58
  );
  const coverDepth = clamp(
    context.ballFromOwnGoal - (context.targetThreat.behindLine >= 0.18 ? 4.6 : 2.4),
    7.5,
    context.ballFromOwnGoal <= 38 ? 32 : 48
  );
  const centralPull =
    context.mode === "carryGate"
      ? 0.72
      : context.targetThreat.centralPocket >= 0.24
        ? 0.86
        : 0.66;
  const points = {
    frontGate: {
      ...goalSideOf(context.mode === "carryGate" ? lanePoint(0.66) : target, context.mode === "carryGate" ? 1.6 : 1.25),
      y: lerp(target.y, pitch.width / 2, context.targetThreat.centralPocket >= 0.24 ? 0.16 : 0.08),
    },
    centralScreen: {
      x: getDepthX(teamId, gateDepth),
      y: lerp(target.y, pitch.width / 2, centralPull),
    },
    halfSpaceLock: {
      x: getDepthX(teamId, clamp(gateDepth - 1.4, 14, 56)),
      y: clamp(
        lerp(target.y, pitch.width / 2 + sideSign * 8.2, context.targetThreat.halfSpace >= 0.34 ? 0.42 : 0.22),
        6,
        pitch.width - 6
      ),
    },
    bounceLock: {
      ...goalSideOf(lanePoint(context.actionType === "pass" ? 0.36 : 0.48), 2.6),
      y: lerp(lanePoint(0.42).y, pitch.width / 2, 0.64),
    },
    backScreen: {
      x: getDepthX(teamId, coverDepth),
      y: lerp(target.y, pitch.width / 2, context.targetThreat.behindLine >= 0.18 ? 0.42 : 0.54),
    },
    weakSideTuck: {
      x: lerp(target.x, ownGoal.x, context.ballFromOwnGoal <= 38 ? 0.4 : 0.3),
      y: clamp(pitch.width / 2 - sideSign * (context.ballFromOwnGoal <= 38 ? 7.8 : 11.2), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.centralScreen, 2.1);
}

function applyDefensiveCentralAccessGateTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const context = getDefensiveCentralAccessGateContext(teamId, ballPoint, profile);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    basePresser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveCentralAccessGateTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const frontGateTarget = getDefensiveCentralAccessGateTarget(teamId, context, "frontGate");
  const canReusePresser =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, frontGateTarget) <= (context.mode === "carryGate" ? 19 : 15.5);

  if (canReusePresser) {
    targets.set(presser.id, frontGateTarget);
    assignedIds.add(presser.id);
    labels.push(context.mode === "carryGate" ? "Central gate: delay carry" : "Central gate: deny turn");
  } else {
    const gatePlayer = assign(
      "frontGate",
      context.ballFromOwnGoal <= 38 ? ["midfield", "back", "forward"] : ["midfield", "forward", "back"],
      context.mode === "carryGate" ? ["6", "8", "10", "CB"] : ["6", "8", "10", "9"],
      context.mode === "carryGate" ? "Central gate: delay carry" : "Central gate: deny turn"
    );
    presser = gatePlayer ?? presser;
  }

  assign("centralScreen", ["midfield", "back"], ["6", "8", "CB", "10"], "Central gate: screen space 2");

  if (context.targetThreat.halfSpace >= 0.26 || Math.abs(context.targetPoint.y - pitch.width / 2) >= 8) {
    assign("halfSpaceLock", ["midfield", "back"], ["8", "6", "WB", "LB", "RB", "CB"], "Central gate: lock half-space");
  }

  if (context.actionType === "pass" || context.laneClarity >= 0.46) {
    assign("bounceLock", ["forward", "midfield"], ["10", "9", "8", "W", "6"], "Central gate: block bounce pass");
  }

  if (
    context.actionSpace.lineBreakCount >= 1 ||
    context.targetThreat.behindLine >= 0.18 ||
    context.dangerScore >= 0.72
  ) {
    assign("backScreen", ["back", "midfield"], ["CB", "6", "LB", "RB", "WB"], "Central gate: protect depth behind");
  }

  assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Central gate: weak side narrows");

  if (labels.length) {
    labels.unshift(
      context.mode === "carryGate"
        ? "Protect central carry gate"
        : context.mode === "receiveGate"
          ? "Protect space 2 receiving gate"
          : "Protect central access"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveChanceDenialContext(defensiveTeamId, ballPoint, profile, reference = getDribblePressureReference()) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    targetKind: state.ball.targetKind,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    reference?.startPoint ??
    state.ball.position ??
    ballPoint;
  const targetPoint =
    actionMeta.target ??
    reference?.targetPoint ??
    state.ball.target ??
    ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const threatPoint = actionType === "shot" ? startPoint : targetPoint;
  const carrier = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const receiver = getPlayerById(actionMeta.receiverPlayerId);
  const principleText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.targetKind,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const targetThreat = getPitchThreatProfile(threatPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, threatPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, threatPoint);
  const goalDistance = distance(threatPoint, getOpponentGoalCenter(attackingTeamId));
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const shotTarget = actionType === "shot"
    ? targetPoint
    : getAutoPilotShotTarget(attackingTeamId, carrier ?? receiver);
  const shotWindow = carrier
    ? getShotWindowProfile(carrier, startPoint, shotTarget)
    : null;
  const pressure = carrier
    ? getPlayerPressureLoad(carrier, startPoint)
    : getOpponentPressureAtPoint(defensiveTeamId, threatPoint, 8);
  const sideSign =
    getWideSideSign(threatPoint) ||
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;
  const isShotCue =
    actionType === "shot" ||
    principleText.includes("shoot") ||
    principleText.includes("finish") ||
    principleText.includes("sweet spot") ||
    (targetThreat.box >= 0.2 && goalDistance <= 31);
  const isCutbackCue =
    principleText.includes("cutback") ||
    targetThreat.cutbackZone >= 0.24 ||
    (actionType === "pass" && targetThreat.assistZone >= 0.34);
  const isFinalPassCue =
    actionType === "pass" &&
    (
      isCutbackCue ||
      targetThreat.box >= 0.18 ||
      targetThreat.centralPocket >= 0.32 ||
      actionSpace.lineBreakCount >= 1
    );
  const isCarryChance =
    actionType === "dribble" &&
    (
      targetThreat.box >= 0.14 ||
      targetThreat.centralPocket >= 0.28 ||
      principleText.includes("runway") ||
      principleText.includes("open-grass")
    );
  const dangerScore = clamp(
    targetThreat.box * 0.46 +
      targetThreat.centralPocket * 0.34 +
      targetThreat.cutbackZone * 0.32 +
      targetThreat.assistZone * 0.2 +
      targetThreat.behindLine * 0.18 +
      clamp((36 - goalDistance) / 24, 0, 1) * 0.28 +
      clamp((35 - ballFromOwnGoal) / 22, 0, 1) * 0.24 +
      (isShotCue ? 0.28 : 0) +
      (isFinalPassCue ? 0.18 : 0) +
      (isCarryChance ? 0.16 : 0) +
      (shotWindow?.quality ?? 0) * 0.22 -
      pressure * 0.12,
    0,
    1.45
  );
  const active =
    dangerScore >= 0.62 ||
    isShotCue ||
    isCutbackCue ||
    (isFinalPassCue && ballFromOwnGoal <= 39);

  if (!active) {
    return null;
  }

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    carrier,
    receiver,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    threatPoint: cloneVector(threatPoint),
    shotTarget: cloneVector(shotTarget),
    targetThreat,
    actionSpace,
    ballFromOwnGoal,
    goalDistance,
    forwardGain,
    pressure,
    shotWindow,
    sideSign,
    isShotCue,
    isCutbackCue,
    isFinalPassCue,
    isCarryChance,
    dangerScore,
    phaseKey: profile.phaseKey,
  };
}

function getDefensiveChanceDenialTarget(teamId, context, slot) {
  const defendingSign = getDefendingDirectionSign(teamId);
  const attackSign = getAttackDirectionSign(context.attackingTeamId);
  const penaltySpot = getOpponentPenaltySpot(context.attackingTeamId);
  const sideSign = context.sideSign || 1;
  const goalSideOf = (point, meters) => ({
    x: point.x - defendingSign * meters,
    y: point.y,
  });
  const shotLinePoint = (ratio) => ({
    x: lerp(context.threatPoint.x, context.shotTarget.x, ratio),
    y: lerp(context.threatPoint.y, context.shotTarget.y, ratio),
  });
  const points = {
    closeShot: {
      ...goalSideOf(context.threatPoint, context.isShotCue ? 1.25 : 1.75),
      y: lerp(context.threatPoint.y, pitch.width / 2, context.isCutbackCue ? 0.22 : 0.1),
    },
    shotBlock: {
      ...goalSideOf(shotLinePoint(context.goalDistance <= 23 ? 0.34 : 0.26), 0.85),
      y: lerp(shotLinePoint(0.32).y, pitch.width / 2, 0.08),
    },
    penaltySpotGuard: {
      x: penaltySpot.x - attackSign * 0.7,
      y: pitch.width / 2,
    },
    cutbackScreen: {
      x: penaltySpot.x - attackSign * 7.4,
      y: clamp(pitch.width / 2 + sideSign * 5.7, 10, pitch.width - 10),
    },
    farPostCover: {
      x: penaltySpot.x + attackSign * 3.5,
      y: clamp(pitch.width / 2 - sideSign * 9.6, 7, pitch.width - 7),
    },
    reboundEdge: {
      x: penaltySpot.x - attackSign * 10.4,
      y: clamp(pitch.width / 2 - sideSign * 3.8, 12, pitch.width - 12),
    },
  };

  return clampToPitch(points[slot] ?? points.shotBlock, 2.1);
}

function applyDefensiveChanceDenialTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set(),
  reference = getDribblePressureReference()
) {
  const context = getDefensiveChanceDenialContext(teamId, ballPoint, profile, reference);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveChanceDenialTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const closeTarget = getDefensiveChanceDenialTarget(teamId, context, "closeShot");
  const presserCanClose =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, closeTarget) <= (context.isShotCue ? 18 : 16);
  if (presserCanClose) {
    targets.set(presser.id, closeTarget);
    assignedIds.add(presser.id);
    labels.push(context.isShotCue ? "Chance denial: close shooter" : "Chance denial: close carrier");
  } else {
    const closePlayer = assign(
      "closeShot",
      context.ballFromOwnGoal <= 24 ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      context.isCutbackCue ? ["6", "8", "LB", "RB", "WB", "CB"] : ["CB", "6", "8", "LB", "RB", "WB"],
      context.isShotCue ? "Chance denial: close shooter" : "Chance denial: close carrier"
    );
    presser = closePlayer ?? presser;
  }

  if (context.isShotCue || context.isCarryChance) {
    assign("shotBlock", ["back", "midfield"], ["CB", "6", "8", "LB", "RB", "WB"], "Chance denial: block shot lane");
  }

  assign("penaltySpotGuard", ["back", "midfield"], ["CB", "6", "8", "LB", "RB", "WB"], "Chance denial: protect penalty spot");

  if (context.isCutbackCue || context.isFinalPassCue || context.targetThreat.cutbackZone >= 0.18) {
    assign("cutbackScreen", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Chance denial: lock cutback");
  }

  if (context.ballFromOwnGoal <= 27 || context.targetThreat.box >= 0.16) {
    assign("farPostCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Chance denial: cover far post");
  }

  if (context.isShotCue || context.dangerScore >= 0.78) {
    assign("reboundEdge", ["midfield", "forward"], ["6", "8", "10", "W"], "Chance denial: secure rebound edge");
  }

  if (labels.length) {
    labels.unshift("Defend the chance first");
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.threatPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveBoxDeliveryChainContext(defensiveTeamId, ballPoint, profile, reference = getDribblePressureReference()) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    targetKind: state.ball.targetKind,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    offensiveAutopilot: null,
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (actionType !== "pass" && actionType !== "dribble") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    reference?.startPoint ??
    state.ball.position ??
    ballPoint;
  const targetPoint =
    actionMeta.target ??
    reference?.targetPoint ??
    state.ball.target ??
    ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const deliveryPoint = actionType === "pass" ? startPoint : targetPoint;
  const targetThreat = getPitchThreatProfile(targetPoint, attackingTeamId);
  const deliveryThreat = getPitchThreatProfile(deliveryPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, targetPoint, attackingTeamId);
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const deliveryDepth = getAttackingDepth(deliveryPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const deliveryFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, deliveryPoint);
  const actionDistance = distance(startPoint, targetPoint);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const lateralMeters = Math.abs(targetPoint.y - startPoint.y);
  const sideSign =
    getWideSideSign(deliveryPoint) ||
    getWideSideSign(targetPoint) ||
    1;
  const principleText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.targetKind,
    actionMeta.label,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const deliveryIsWide =
    isWidePrincipleZone(deliveryPoint) ||
    deliveryThreat.assistZone >= 0.24 ||
    Math.abs(deliveryPoint.y - pitch.width / 2) >= 17;
  const targetIsBox =
    targetThreat.box >= 0.12 ||
    targetThreat.cutbackZone >= 0.14 ||
    targetThreat.centralPocket >= 0.3 ||
    (targetDepth >= 78 && Math.abs(targetPoint.y - pitch.width / 2) <= 24);
  const cutbackCue =
    principleText.includes("cutback") ||
    targetThreat.cutbackZone >= 0.18 ||
    (
      actionType === "pass" &&
      deliveryIsWide &&
      forwardGain <= 1.5 &&
      targetDepth >= 72 &&
      Math.abs(targetPoint.y - pitch.width / 2) <= 24
    );
  const crossCue =
    principleText.includes("cross") ||
    principleText.includes("delivery") ||
    principleText.includes("box") ||
    (
      actionType === "pass" &&
      deliveryIsWide &&
      targetIsBox &&
      lateralMeters >= 8
    );
  const wideCarryCue =
    actionType === "dribble" &&
    deliveryIsWide &&
    deliveryFromOwnGoal <= 36 &&
    (deliveryThreat.assistZone >= 0.24 || deliveryDepth >= 72);
  const active =
    (actionType === "pass" && deliveryIsWide && targetIsBox && deliveryFromOwnGoal <= 48) ||
    cutbackCue ||
    crossCue ||
    wideCarryCue;

  if (!active) {
    return null;
  }

  const deliveryKind = cutbackCue
    ? "cutback"
    : crossCue
      ? "cross"
      : "wideThreat";
  const dangerScore = clamp(
    targetThreat.box * 0.38 +
      targetThreat.cutbackZone * 0.34 +
      targetThreat.centralPocket * 0.24 +
      targetThreat.assistZone * 0.18 +
      deliveryThreat.assistZone * 0.18 +
      clamp((42 - ballFromOwnGoal) / 25, 0, 1) * 0.22 +
      clamp(actionDistance / 24, 0, 1) * 0.1 +
      (cutbackCue ? 0.22 : 0) +
      (crossCue ? 0.16 : 0) +
      (wideCarryCue ? 0.18 : 0),
    0,
    1.35
  );

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    deliveryPoint: cloneVector(deliveryPoint),
    targetThreat,
    deliveryThreat,
    actionSpace,
    targetDepth,
    deliveryDepth,
    ballFromOwnGoal,
    deliveryFromOwnGoal,
    actionDistance,
    forwardGain,
    sideSign,
    deliveryKind,
    dangerScore,
    wideCarryCue,
    phaseKey: profile.phaseKey,
  };
}

function getDefensiveBoxDeliveryChainTarget(teamId, context, slot) {
  const defendingSign = getDefendingDirectionSign(teamId);
  const attackSign = getAttackDirectionSign(context.attackingTeamId);
  const penaltySpot = getOpponentPenaltySpot(context.attackingTeamId);
  const delivery = context.deliveryPoint;
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const lanePoint = (ratio) => ({
    x: lerp(delivery.x, target.x, ratio),
    y: lerp(delivery.y, target.y, ratio),
  });
  const goalSideOf = (point, meters) => ({
    x: point.x - defendingSign * meters,
    y: point.y,
  });
  const cutbackPull = context.deliveryKind === "cutback" ? 1.4 : 0;
  const points = {
    deliveryPressure: {
      x: delivery.x - defendingSign * 1.4,
      y: clamp(delivery.y - sideSign * 1.7, 3.2, pitch.width - 3.2),
    },
    lowLaneBlock: {
      ...goalSideOf(lanePoint(context.deliveryKind === "cutback" ? 0.52 : 0.42), 0.9),
      y: lerp(lanePoint(0.5).y, pitch.width / 2, context.deliveryKind === "cross" ? 0.22 : 0.1),
    },
    nearPostCover: {
      x: penaltySpot.x + attackSign * 3.9,
      y: clamp(pitch.width / 2 + sideSign * 4.4, 6.5, pitch.width - 6.5),
    },
    sixYardCover: {
      x: penaltySpot.x + attackSign * 5.2,
      y: clamp(pitch.width / 2 + sideSign * 1.6, 9, pitch.width - 9),
    },
    penaltySpotGuard: {
      x: penaltySpot.x - attackSign * 0.7,
      y: pitch.width / 2,
    },
    cutbackGate: {
      x: penaltySpot.x - attackSign * (7.4 + cutbackPull),
      y: clamp(pitch.width / 2 + sideSign * 5.4, 9.5, pitch.width - 9.5),
    },
    farPostCover: {
      x: penaltySpot.x + attackSign * 2.9,
      y: clamp(pitch.width / 2 - sideSign * 9.4, 6.5, pitch.width - 6.5),
    },
    edgeLock: {
      x: penaltySpot.x - attackSign * 11.2,
      y: clamp(pitch.width / 2 - sideSign * 3.8, 11, pitch.width - 11),
    },
    weakSideTuck: {
      x: penaltySpot.x - attackSign * 2.8,
      y: clamp(pitch.width / 2 - sideSign * 13.2, 6.5, pitch.width - 6.5),
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpotGuard, 1.8);
}

function applyDefensiveBoxDeliveryChainTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set(),
  reference = getDribblePressureReference()
) {
  const context = getDefensiveBoxDeliveryChainContext(teamId, ballPoint, profile, reference);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveBoxDeliveryChainTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  if (context.wideCarryCue) {
    const pressTarget = getDefensiveBoxDeliveryChainTarget(teamId, context, "deliveryPressure");
    if (presser && !assignedIds.has(presser.id) && !isGoalkeeper(presser)) {
      targets.set(presser.id, pressTarget);
      assignedIds.add(presser.id);
      labels.push("Box delivery chain: press wide carrier");
    } else {
      const widePresser = assign(
        "deliveryPressure",
        ["back", "midfield", "forward"],
        ["WB", "LB", "RB", "W", "8"],
        "Box delivery chain: press wide carrier"
      );
      presser = widePresser ?? presser;
    }
  } else {
    assign("lowLaneBlock", ["back", "midfield"], ["LB", "RB", "WB", "CB", "6"], "Box delivery chain: block delivery lane");
  }

  if (context.deliveryKind === "cross") {
    assign("nearPostCover", ["back"], ["CB", "LB", "RB", "WB"], "Box delivery chain: near-post cover");
    assign("sixYardCover", ["back"], ["CB"], "Box delivery chain: six-yard protection");
    assign("penaltySpotGuard", ["back", "midfield"], ["CB", "6", "8"], "Box delivery chain: penalty-spot guard");
    assign("farPostCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Box delivery chain: far-post cover");
  } else {
    assign("cutbackGate", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Box delivery chain: lock cutback gate");
    assign("penaltySpotGuard", ["back", "midfield"], ["CB", "6", "8"], "Box delivery chain: penalty-spot guard");
    assign("nearPostCover", ["back"], ["CB", "LB", "RB", "WB"], "Box delivery chain: near-post cover");
    if (context.ballFromOwnGoal <= 28 || context.targetThreat.box >= 0.18) {
      assign("farPostCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Box delivery chain: far-post cover");
    }
  }

  if (context.dangerScore >= 0.72 || context.deliveryKind === "cutback") {
    assign("edgeLock", ["midfield", "forward"], ["6", "8", "10", "W"], "Box delivery chain: second-wave edge");
  }

  assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Box delivery chain: weak side tucks in");

  if (labels.length) {
    labels.unshift(
      context.deliveryKind === "cutback"
        ? "Defend cutback chain"
        : context.deliveryKind === "cross"
          ? "Defend box delivery chain"
          : "Prepare box delivery chain"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveLineBreakAdvantageContext(
  defensiveTeamId,
  ballPoint,
  profile,
  reference = getDribblePressureReference()
) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    targetKind: state.ball.targetKind,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    profileKey: state.ball.profileKey,
    profileLabel: state.ball.profileLabel,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
    offensiveAutopilot: null,
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (!["pass", "dribble", "shot"].includes(actionType)) {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    reference?.startPoint ??
    state.ball.position ??
    ballPoint;
  const targetPoint =
    actionMeta.target ??
    reference?.targetPoint ??
    state.ball.target ??
    ballPoint;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const carrier = getPlayerById(
    actionMeta.carrierPlayerId ??
      actionMeta.beforeSnapshot?.ball?.ownerPlayerId ??
      state.ball.initiatorPlayerId ??
      state.ball.ownerPlayerId
  );
  const principleText = [
    actionMeta.profileKey,
    actionMeta.profileLabel,
    actionMeta.targetKind,
    actionMeta.offensiveAutopilot?.principleKey,
    actionMeta.offensiveAutopilot?.principleLabel,
    ...(actionMeta.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const threatPoint = actionType === "shot" ? startPoint : targetPoint;
  const targetThreat = getPitchThreatProfile(threatPoint, attackingTeamId);
  const actionSpace = getActionSpaceValue(startPoint, threatPoint, attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * getAttackDirectionSign(attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, threatPoint);
  const goalDistance = distance(threatPoint, getOpponentGoalCenter(attackingTeamId));
  const pressure = carrier
    ? getPlayerPressureLoad(carrier, startPoint)
    : getOpponentPressureAtPoint(defensiveTeamId, threatPoint, 9);
  const recent = getRecentPossessionSteps(attackingTeamId, 2);
  const previous = recent[0] ?? null;
  const previousText = [
    previous?.profileLabel,
    previous?.offensiveAutopilot?.principleKey,
    previous?.offensiveAutopilot?.principleLabel,
    ...(previous?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const advantageCue =
    principleText.includes("line-break advantage") ||
    principleText.includes("do not reset line-break") ||
    previousText.includes("line-break advantage") ||
    previousText.includes("line-breaking") ||
    previousText.includes("space 2") ||
    previousText.includes("spelyta");
  const lineBreakCue =
    advantageCue ||
    actionSpace.lineBreakCount >= 1 ||
    targetThreat.behindLine >= 0.2 ||
    targetThreat.betweenLines >= 0.32 ||
    targetThreat.centralPocket >= 0.28 ||
    (forwardGain >= 8 && targetThreat.value >= 0.32);
  const isShotCue =
    actionType === "shot" ||
    principleText.includes("shoot") ||
    principleText.includes("finish") ||
    targetThreat.box >= 0.22;
  const isCutbackCue =
    principleText.includes("cutback") ||
    targetThreat.cutbackZone >= 0.24 ||
    (targetThreat.assistZone >= 0.34 && ballFromOwnGoal <= 37);
  const isWideCue =
    isWidePrincipleZone(threatPoint) ||
    isWidePrincipleZone(startPoint) ||
    targetThreat.assistZone >= 0.32 ||
    isCutbackCue;
  const dangerScore = clamp(
    targetThreat.box * 0.42 +
      targetThreat.centralPocket * 0.34 +
      targetThreat.behindLine * 0.3 +
      targetThreat.cutbackZone * 0.3 +
      targetThreat.betweenLines * 0.22 +
      clamp(actionSpace.lineBreakCount / 2, 0, 1) * 0.28 +
      clamp((42 - goalDistance) / 25, 0, 1) * 0.22 +
      clamp((48 - ballFromOwnGoal) / 26, 0, 1) * 0.24 +
      (advantageCue ? 0.3 : 0) +
      (isShotCue ? 0.18 : 0) +
      (isCutbackCue ? 0.16 : 0) -
      pressure * 0.12,
    0,
    1.45
  );

  if (!lineBreakCue || dangerScore < 0.48 || ballFromOwnGoal > 55) {
    return null;
  }

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    carrier,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    threatPoint: cloneVector(threatPoint),
    targetThreat,
    actionSpace,
    forwardGain,
    ballFromOwnGoal,
    goalDistance,
    pressure,
    advantageCue,
    isShotCue,
    isCutbackCue,
    isWideCue,
    dangerScore,
    sideSign:
      getWideSideSign(threatPoint) ||
      getWideSideSign(targetPoint) ||
      getWideSideSign(startPoint) ||
      1,
    mode: isShotCue
      ? "shotCollapse"
      : isCutbackCue
        ? "cutbackCollapse"
        : isWideCue
          ? "wideCollapse"
          : "centralCollapse",
  };
}

function getDefensiveLineBreakAdvantageTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.threatPoint;
  const sideSign = context.sideSign || 1;
  const lanePoint = (ratio) => ({
    x: lerp(context.startPoint.x, target.x, ratio),
    y: lerp(context.startPoint.y, target.y, ratio),
  });
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const penaltySpot = getOpponentPenaltySpot(context.attackingTeamId);
  const lastLineDepth = clamp(
    context.ballFromOwnGoal - (context.dangerScore >= 0.8 ? 5.4 : 4.2),
    7.5,
    context.ballFromOwnGoal <= 28 ? 24 : 35
  );
  const screenDepth = clamp(context.ballFromOwnGoal + 3.8, 16, 42);
  const points = {
    delayBall: {
      ...goalSideOf(lanePoint(context.actionType === "dribble" ? 0.52 : 0.74), context.isShotCue ? 0.85 : 1.25),
      y: lerp(target.y, pitch.width / 2, context.isWideCue ? 0.18 : 0.3),
    },
    lastLineSeal: {
      x: getDepthX(teamId, lastLineDepth),
      y: lerp(target.y, pitch.width / 2, context.isWideCue ? 0.46 : 0.28),
    },
    centralGate: {
      x: getDepthX(teamId, screenDepth),
      y: lerp(target.y, pitch.width / 2, context.isWideCue ? 0.74 : 0.86),
    },
    cutbackGate: {
      x: penaltySpot.x - getAttackDirectionSign(context.attackingTeamId) * 7.2,
      y: clamp(pitch.width / 2 + sideSign * 5.8, 10, pitch.width - 10),
    },
    farPost: {
      x: getDepthX(teamId, clamp(lastLineDepth + 1.6, 7.5, 24)),
      y: clamp(pitch.width / 2 - sideSign * 9.2, 7, pitch.width - 7),
    },
    edgeCover: {
      x: getDepthX(teamId, clamp(context.ballFromOwnGoal + 8.5, 20, 48)),
      y: clamp(lerp(target.y, pitch.width / 2 - sideSign * 3.5, 0.62), 12, pitch.width - 12),
    },
    weakSideCollapse: {
      x: lerp(target.x, ownGoal.x, context.ballFromOwnGoal <= 32 ? 0.46 : 0.36),
      y: clamp(pitch.width / 2 - sideSign * (context.ballFromOwnGoal <= 32 ? 7.2 : 10.4), 7, pitch.width - 7),
    },
  };

  return clampToPitch(points[slot] ?? points.centralGate, 2.1);
}

function applyDefensiveLineBreakAdvantageCollapseTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set(),
  reference = getDribblePressureReference()
) {
  const context = getDefensiveLineBreakAdvantageContext(teamId, ballPoint, profile, reference);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveLineBreakAdvantageTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const delayTarget = getDefensiveLineBreakAdvantageTarget(teamId, context, "delayBall");
  const presserCanDelay =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, delayTarget) <= (context.advantageCue ? 24 : 19);

  if (presserCanDelay) {
    targets.set(presser.id, delayTarget);
    assignedIds.add(presser.id);
    labels.push("Line-break collapse: delay first finish");
  } else {
    const delayPlayer = assign(
      "delayBall",
      context.ballFromOwnGoal <= 30 ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      context.isWideCue ? ["WB", "LB", "RB", "W", "6", "8"] : ["6", "8", "CB", "10", "9"],
      "Line-break collapse: delay first finish"
    );
    presser = delayPlayer ?? presser;
  }

  assign("lastLineSeal", ["back"], ["CB", "LB", "RB", "WB"], "Line-break collapse: seal last line");
  assign("centralGate", ["midfield", "back"], ["6", "8", "CB", "10"], "Line-break collapse: close central gate");

  if (context.isCutbackCue || context.isWideCue || context.targetThreat.cutbackZone >= 0.18) {
    assign("cutbackGate", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Line-break collapse: lock cutback");
  }

  if (context.ballFromOwnGoal <= 32 || context.isShotCue || context.targetThreat.box >= 0.16) {
    assign("farPost", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Line-break collapse: cover far post");
  }

  assign("edgeCover", ["midfield", "back"], ["6", "8", "10", "CB"], "Line-break collapse: secure edge");
  assign("weakSideCollapse", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Line-break collapse: weak side narrows");

  if (labels.length) {
    labels.unshift(
      context.mode === "shotCollapse"
        ? "Collapse after line break: protect shot"
        : context.mode === "cutbackCollapse"
          ? "Collapse after line break: protect cutback"
          : "Collapse after line break"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.threatPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveEmergencyCoverContext(
  defensiveTeamId,
  ballPoint,
  profile,
  reference = getDribblePressureReference()
) {
  if (state.restartPhase?.type) {
    return null;
  }

  const attackingTeamId = getOtherTeamId(defensiveTeamId);
  if (!attackingTeamId) {
    return null;
  }

  const actionMeta = state.draftStep ?? {
    actionType: state.ball.actionType,
    target: state.ball.target,
    receiverPlayerId: state.ball.receiverPlayerId,
    carrierPlayerId: state.ball.carrierPlayerId,
    autoPrinciples: [],
    beforeSnapshot: {
      ball: {
        position: state.ball.startPosition,
        ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
      },
    },
  };
  const actionType = actionMeta.actionType ?? state.ball.actionType;
  if (actionType !== "dribble" && actionType !== "pass") {
    return null;
  }

  const startPoint =
    actionMeta.beforeSnapshot?.ball?.position ??
    state.ball.startPosition ??
    reference?.startPoint ??
    state.ball.position;
  const targetPoint =
    actionMeta.target ??
    reference?.targetPoint ??
    ballPoint ??
    state.ball.target;
  if (!startPoint || !targetPoint) {
    return null;
  }

  const actionDistance = distance(startPoint, targetPoint);
  if (actionDistance < 5.5) {
    return null;
  }

  const attackSign = getAttackDirectionSign(attackingTeamId);
  const forwardGain = (targetPoint.x - startPoint.x) * attackSign;
  const targetDepth = getAttackingDepth(targetPoint, attackingTeamId);
  const ballFromOwnGoal = getDistanceFromOwnGoal(defensiveTeamId, targetPoint);
  const actionSpace = getActionSpaceValue(
    startPoint,
    targetPoint,
    attackingTeamId,
    getOffensiveAutopilotProfile(attackingTeamId, targetPoint)
  );
  const targetThreat = actionSpace.targetThreat;
  const principleText = [
    actionMeta?.offensiveAutopilot?.principleKey,
    actionMeta?.offensiveAutopilot?.principleLabel,
    ...(actionMeta?.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const isRunway =
    principleText.includes("runway") ||
    principleText.includes("open-grass") ||
    (
      actionType === "dribble" &&
      actionDistance >= 12 &&
      forwardGain >= 6 &&
      actionSpace.openTarget >= 0.52
    );
  const isLineBreak =
    actionSpace.lineBreakCount >= 1 ||
    targetThreat.behindLine >= 0.22 ||
    (actionType === "pass" && forwardGain >= 10);
  const isFinalThirdThreat =
    ballFromOwnGoal <= 42 ||
    targetDepth >= 63 ||
    targetThreat.box >= 0.16 ||
    targetThreat.cutbackZone >= 0.22;
  const isCentralThreat =
    targetThreat.centralPocket >= 0.24 ||
    targetThreat.betweenLines >= 0.32 ||
    Math.abs(targetPoint.y - pitch.width / 2) <= 13.5;
  const isWideThreat =
    isWidePrincipleZone(targetPoint) ||
    isWidePrincipleZone(startPoint) ||
    targetThreat.assistZone >= 0.3 ||
    targetThreat.cutbackZone >= 0.2;
  const runnerThreat = getDefensiveRunnerThreats(defensiveTeamId, targetPoint, profile)[0] ?? null;
  const dangerScore = clamp(
    targetThreat.box * 0.54 +
      targetThreat.behindLine * 0.46 +
      targetThreat.centralPocket * 0.36 +
      targetThreat.cutbackZone * 0.34 +
      targetThreat.betweenLines * 0.24 +
      clamp(actionSpace.lineBreakCount / 2, 0, 1) * 0.32 +
      clamp(forwardGain / 24, 0, 1) * 0.24 +
      clamp((48 - ballFromOwnGoal) / 26, 0, 1) * 0.26 +
      (isRunway ? 0.28 : 0) +
      (runnerThreat ? 0.12 : 0) -
      actionSpace.targetPressure * 0.12,
    0,
    1.45
  );
  const active =
    dangerScore >= 0.64 ||
    (isRunway && isFinalThirdThreat) ||
    (isLineBreak && ballFromOwnGoal <= 50) ||
    (runnerThreat?.isDepthThreat && ballFromOwnGoal <= 52);

  if (!active) {
    return null;
  }

  const sideSign =
    getWideSideSign(targetPoint) ||
    getWideSideSign(startPoint) ||
    1;

  return {
    actionMeta,
    actionType,
    attackingTeamId,
    startPoint: cloneVector(startPoint),
    targetPoint: cloneVector(targetPoint),
    ballPoint: cloneVector(ballPoint ?? targetPoint),
    actionDistance,
    forwardGain,
    targetDepth,
    ballFromOwnGoal,
    actionSpace,
    targetThreat,
    isRunway,
    isLineBreak,
    isFinalThirdThreat,
    isCentralThreat,
    isWideThreat,
    runnerThreat,
    dangerScore,
    sideSign,
    mode: isRunway
      ? "runwayEmergency"
      : isLineBreak
        ? "lineBreakEmergency"
        : "boxProtection",
  };
}

function getDefensiveEmergencyCoverTarget(teamId, context, slot) {
  if (slot === "runnerGoalSide" && context.runnerThreat) {
    return getDefensiveRunnerTrackingTarget(teamId, context.runnerThreat, "goalSideMark");
  }

  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const lanePoint = (ratio) => ({
    x: lerp(context.startPoint.x, target.x, ratio),
    y: lerp(context.startPoint.y, target.y, ratio),
  });
  const goalSideOf = (point, meters) => ({
    x: point.x - sign * meters,
    y: point.y,
  });
  const pressurePoint = lanePoint(context.actionType === "dribble" ? 0.6 : 0.72);
  const lastLineDepth = clamp(
    context.ballFromOwnGoal - (context.isFinalThirdThreat ? 4.8 : 7.2),
    7.5,
    context.isFinalThirdThreat ? 27 : 36
  );
  const screenDepth = clamp(
    context.ballFromOwnGoal + (context.isFinalThirdThreat ? 5.6 : 3.2),
    15,
    44
  );
  const cutbackDepth = clamp(
    context.ballFromOwnGoal + 2.5,
    12,
    32
  );
  const points = {
    firstDelay: {
      ...goalSideOf(pressurePoint, context.isRunway ? 1.65 : 1.3),
      y: lerp(pressurePoint.y, pitch.width / 2, context.isWideThreat ? 0.22 : 0.36),
    },
    lastLineCover: {
      x: getDepthX(teamId, lastLineDepth),
      y: lerp(target.y, pitch.width / 2, context.isWideThreat ? 0.44 : 0.3),
    },
    centralScreen: {
      x: getDepthX(teamId, screenDepth),
      y: lerp(target.y, pitch.width / 2, context.isWideThreat ? 0.76 : 0.86),
    },
    cutbackCover: {
      x: getDepthX(teamId, cutbackDepth),
      y: clamp(pitch.width / 2 + sideSign * 5.4, 11, pitch.width - 11),
    },
    farPostCover: {
      x: getDepthX(teamId, clamp(lastLineDepth + 1.6, 7.5, 24)),
      y: clamp(pitch.width / 2 - sideSign * 9.4, 7.5, pitch.width - 7.5),
    },
    weakSideCollapse: {
      x: lerp(target.x, ownGoal.x, context.isFinalThirdThreat ? 0.44 : 0.34),
      y: clamp(pitch.width / 2 - sideSign * (context.isFinalThirdThreat ? 7.4 : 10.6), 7, pitch.width - 7),
    },
    recoveryArc: {
      x: getDepthX(teamId, clamp(context.ballFromOwnGoal + 9, 20, 48)),
      y: lerp(target.y, pitch.width / 2, 0.58),
    },
  };

  return clampToPitch(points[slot] ?? points.lastLineCover, 2.2);
}

function applyDefensiveEmergencyCoverTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set(),
  reference = getDribblePressureReference()
) {
  const context = getDefensiveEmergencyCoverContext(teamId, ballPoint, profile, reference);
  if (!context) {
    return {
      presser: basePresser,
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  let presser = basePresser;
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveEmergencyCoverTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    if (label) {
      labels.push(label);
    }
    return player;
  };

  const firstDelayTarget = getDefensiveEmergencyCoverTarget(teamId, context, "firstDelay");
  const presserCanDelay =
    presser &&
    !assignedIds.has(presser.id) &&
    !isGoalkeeper(presser) &&
    distance(presser.position, firstDelayTarget) <= (context.isRunway ? 23 : 18);
  if (presserCanDelay) {
    targets.set(presser.id, firstDelayTarget);
    assignedIds.add(presser.id);
    labels.push(context.isRunway ? "Emergency: slow the runway" : "Emergency: delay the line break");
  } else if (!presser || !assignedIds.has(presser.id)) {
    const delayPlayer = assign(
      "firstDelay",
      context.isFinalThirdThreat ? ["back", "midfield", "forward"] : ["midfield", "back", "forward"],
      context.isWideThreat ? ["WB", "LB", "RB", "W", "8", "6"] : ["6", "8", "CB", "10", "9"],
      context.isRunway ? "Emergency: slow the runway" : "Emergency: delay the line break"
    );
    presser = delayPlayer ?? presser;
  }

  assign("lastLineCover", ["back"], ["CB", "LB", "RB", "WB"], "Emergency: protect last line");

  if (context.isCentralThreat || context.isLineBreak || context.isRunway) {
    assign("centralScreen", ["midfield", "back"], ["6", "8", "CB", "10"], "Emergency: screen central finish");
  }

  if (context.runnerThreat) {
    assign(
      "runnerGoalSide",
      context.runnerThreat.isDepthThreat || context.runnerThreat.isBoxThreat ? ["back", "midfield"] : ["midfield", "back"],
      context.runnerThreat.isDepthThreat ? ["CB", "LB", "RB", "WB", "6"] : ["6", "8", "CB", "10"],
      "Emergency: stay goal-side of runner"
    );
  }

  if (context.isWideThreat || context.targetThreat.cutbackZone >= 0.2) {
    assign("cutbackCover", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Emergency: lock cutback");
  }

  if (context.isFinalThirdThreat) {
    assign("farPostCover", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Emergency: cover far post");
  } else {
    assign("recoveryArc", ["midfield", "back"], ["6", "8", "CB", "LB", "RB", "WB"], "Emergency: recover behind ball");
  }

  assign("weakSideCollapse", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Emergency: weak side collapses");

  if (labels.length) {
    labels.unshift(
      context.mode === "runwayEmergency"
        ? "Emergency cover against runway"
        : context.mode === "lineBreakEmergency"
          ? "Emergency cover against line break"
          : "Emergency box cover"
    );
  }

  return {
    presser,
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function getDefensiveSecondBallAnticipationTarget(teamId, context, slot) {
  const sign = getDefendingDirectionSign(teamId);
  const ownGoal = getOwnGoalCenter(teamId);
  const target = context.targetPoint;
  const sideSign = context.sideSign || 1;
  const points = {
    firstContact: {
      x: target.x - sign * (context.finalThirdLanding ? 1.2 : 1.8),
      y: lerp(target.y, pitch.width / 2, context.finalThirdLanding ? 0.18 : 0.26),
    },
    dropZoneScreen: {
      x: target.x - sign * (context.aerial ? 6.6 : 4.8),
      y: lerp(target.y, pitch.width / 2, context.finalThirdLanding ? 0.58 : 0.64),
    },
    clearanceLane: {
      x: lerp(target.x, ownGoal.x, context.finalThirdLanding ? 0.38 : 0.26),
      y: clamp(pitch.width / 2 + sideSign * (context.finalThirdLanding ? 7.6 : 10.2), 8, pitch.width - 8),
    },
    depthCover: {
      x: lerp(target.x, ownGoal.x, context.lineBreakLanding ? 0.46 : 0.34),
      y: lerp(target.y, pitch.width / 2, context.finalThirdLanding ? 0.32 : 0.22),
    },
    weakSideTuck: {
      x: lerp(target.x, ownGoal.x, 0.34),
      y: clamp(pitch.width / 2 - sideSign * (context.finalThirdLanding ? 8.4 : 11.6), 7, pitch.width - 7),
    },
    counterPressOutletBlock: {
      x: target.x + sign * 5.6,
      y: lerp(target.y, pitch.width / 2, 0.42),
    },
  };

  return clampToPitch(points[slot] ?? points.dropZoneScreen, 2.2);
}

function applyDefensiveSecondBallAnticipationTargets(
  teamId,
  targets,
  groups,
  basePresser,
  ballPoint,
  profile,
  protectedIds = new Set()
) {
  const attackingTeamId = getOtherTeamId(teamId);
  if (!attackingTeamId) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const attackProfile = getOffensiveAutopilotProfile(attackingTeamId, ballPoint);
  const context = getSecondBallAnticipationContext(
    attackingTeamId,
    ballPoint,
    state.draftStep ?? {
      actionType: state.ball.actionType,
      target: state.ball.target,
      receiverPlayerId: state.ball.receiverPlayerId,
      carrierPlayerId: state.ball.carrierPlayerId,
      beforeSnapshot: {
        ball: {
          position: state.ball.startPosition,
          ownerPlayerId: state.ball.initiatorPlayerId ?? state.ball.ownerPlayerId,
        },
      },
    },
    attackProfile
  );

  if (!context) {
    return {
      labels: [],
      focusPoint: null,
      protectedIds: new Set(protectedIds),
    };
  }

  const labels = [];
  const assignedIds = new Set([
    ...protectedIds,
    basePresser?.id,
    ...groups.gk.map((goalkeeper) => goalkeeper.id),
  ].filter(Boolean));
  const assign = (slot, lineKeys, preferLabels, label) => {
    const target = getDefensiveSecondBallAnticipationTarget(teamId, context, slot);
    const player = pickDefensiveAutopilotPlayer(groups, lineKeys, assignedIds, target, preferLabels);
    if (!player) {
      return null;
    }

    targets.set(player.id, target);
    assignedIds.add(player.id);
    labels.push(label);
    return player;
  };

  assign("firstContact", ["back", "midfield", "forward"], ["CB", "6", "8", "WB", "LB", "RB", "9"], "Second ball: contest first contact");
  assign("dropZoneScreen", ["midfield", "back"], ["6", "8", "CB", "10"], "Second ball: screen drop zone");

  if (context.lineBreakLanding || context.finalThirdLanding) {
    assign("depthCover", ["back"], ["CB", "LB", "RB", "WB"], "Second ball: cover depth behind");
  }

  assign("clearanceLane", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Second ball: clearance lane");
  assign("weakSideTuck", ["back", "midfield"], ["CB", "LB", "RB", "WB", "6"], "Second ball: weak-side protection");

  if (profile.pressingIntensity >= 0.54 || profile.styleKey === "counter-press" || profile.styleKey === "gegenpress") {
    assign("counterPressOutletBlock", ["forward", "midfield"], ["9", "10", "W", "8"], "Second ball: block outlet");
  }

  if (labels.length) {
    labels.unshift("Anticipate second ball");
  }

  return {
    labels: uniquePrincipleLabels(labels),
    focusPoint: context.targetPoint,
    protectedIds: assignedIds,
  };
}

function buildDefensiveAutopilotTargets(teamId, ballPoint) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const phaseKey = getDefensivePhaseKey(teamId, ballPoint);
  const profile = getDefensiveAutopilotProfile(teamId, ballPoint, phaseKey);
  const roster = teamRosterOrder[teamId] ?? [];
  const basePositions = getFormationPositions(formation, teamId);
  const baseYById = new Map(
    roster.map((playerId, index) => [playerId, basePositions[index]?.y ?? pitch.width / 2])
  );
  const groups = {
    gk: [],
    back: [],
    midfield: [],
    forward: [],
  };

  state.players
    .filter((player) => player.team === teamId)
    .forEach((player) => {
      groups[getDefensiveAutopilotLineKey(player, formation, profile.phaseKey)].push(player);
    });

  Object.values(groups).forEach((group) => {
    group.sort((a, b) => (baseYById.get(a.id) ?? a.position.y) - (baseYById.get(b.id) ?? b.position.y));
  });

  const targets = new Map();

  groups.gk.forEach((player) => {
    targets.set(player.id, getDefensiveGoalkeeperTarget(teamId, ballPoint, profile));
  });

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const players = groups[lineKey];
    if (!players.length) {
      return;
    }

    const lineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const lineWidth = getDefensiveLineWidth(lineKey, profile, ballPoint, players.length);
    const centerY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);
    const phaseInsideBoost = profile.phaseKey === "boxDefending" ? 0.08 : profile.phaseKey === "lowBlock" ? 0.04 : 0;
    const insidePull =
      (lineKey === "forward" ? 0.18 : lineKey === "midfield" ? 0.13 : 0.08) +
      phaseInsideBoost;

    players.forEach((player, index) => {
      const spreadRatio = players.length === 1 ? 0.5 : index / (players.length - 1);
      const spreadY = centerY - lineWidth / 2 + lineWidth * spreadRatio;
      const targetY = lerp(spreadY, ballPoint.y, insidePull);

      targets.set(player.id, clampToPitch({
        x: lineX,
        y: clamp(targetY, 3, pitch.width - 3),
      }, 3));
    });
  });

  const cornerSetPiece = applyDefensiveCornerSetPieceTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  if (cornerSetPiece.active) {
    return {
      targets,
      presser: cornerSetPiece.presser,
      profile,
      protectionLabels: cornerSetPiece.labels,
      focusPoint: cornerSetPiece.focusPoint,
    };
  }

  const freeKickSetPiece = applyDefensiveFreeKickSetPieceTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  if (freeKickSetPiece.active) {
    return {
      targets,
      presser: freeKickSetPiece.presser,
      profile,
      protectionLabels: freeKickSetPiece.labels,
      focusPoint: freeKickSetPiece.focusPoint,
    };
  }

  const penaltySetPiece = applyDefensivePenaltySetPieceTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  if (penaltySetPiece.active) {
    return {
      targets,
      presser: penaltySetPiece.presser,
      profile,
      protectionLabels: penaltySetPiece.labels,
      focusPoint: penaltySetPiece.focusPoint,
    };
  }

  const throwInSetPiece = applyDefensiveThrowInSetPieceTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  if (throwInSetPiece.active) {
    return {
      targets,
      presser: throwInSetPiece.presser,
      profile,
      protectionLabels: throwInSetPiece.labels,
      focusPoint: throwInSetPiece.focusPoint,
    };
  }

  const negativeTransition = applyNegativeTransitionDefensiveTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  if (negativeTransition.active) {
    const transitionProfile = {
      ...profile,
      phaseKey: "transitionToDefend",
      phaseLabel: negativeTransition.mode === "counterPress"
        ? "Negative Transition"
        : "Recovery Transition",
    };
    applyAutopilotTargetVariation(
      teamId,
      targets,
      transitionProfile,
      "defence",
      new Set([
        negativeTransition.presser?.id,
        ...(negativeTransition.protectedIds ?? []),
      ].filter(Boolean))
    );

    return {
      targets,
      presser: negativeTransition.presser,
      profile: transitionProfile,
      protectionLabels: negativeTransition.labels,
      focusPoint: negativeTransition.focusPoint,
    };
  }

  const dribbleReference = getDribblePressureReference();
  let presser = dribbleReference
    ? chooseDefensiveDribblePresser(teamId, targets, profile, dribbleReference) ??
      chooseDefensiveAutopilotPresser(teamId, ballPoint, targets, profile)
    : chooseDefensiveAutopilotPresser(teamId, ballPoint, targets, profile);
  if (presser) {
    targets.set(
      presser.id,
      dribbleReference
        ? getDefensiveDribblePressTarget(presser, dribbleReference, profile)
        : getDefensivePressTarget(teamId, ballPoint, profile, presser)
    );
  }
  const buildOutPress = applyGoalkeeperBuildOutPressTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile
  );
  presser = buildOutPress.presser ?? presser;
  const openPlayTrigger = applyDefensiveOpenPlayTriggerTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile
  );
  presser = openPlayTrigger.presser ?? presser;
  const receptionTrap = applyDefensiveReceptionTrapTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    openPlayTrigger.protectedIds
  );
  presser = receptionTrap.presser ?? presser;
  const receiveContinuation = applyDefensiveReceiveContinuationTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    receptionTrap.protectedIds
  );
  presser = receiveContinuation.presser ?? presser;
  const routeAnticipation = applyDefensiveRouteAnticipationTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    receiveContinuation.protectedIds
  );
  presser = routeAnticipation.presser ?? presser;
  const switchRecovery = applyDefensiveSwitchRecoveryTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    routeAnticipation.protectedIds
  );
  presser = switchRecovery.presser ?? presser;
  const switchLandingLock = applyDefensiveSwitchLandingLockTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    switchRecovery.protectedIds
  );
  presser = switchLandingLock.presser ?? presser;
  const gameSpaceResponse = applyDefensiveGameSpaceResponseTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    switchLandingLock.protectedIds
  );
  presser = gameSpaceResponse.presser ?? presser;
  const carryContainment = applyDefensiveCarryContainmentTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    gameSpaceResponse.protectedIds,
    dribbleReference
  );
  presser = carryContainment.presser ?? presser;
  const runnerTracking = applyDefensiveRunnerTrackingTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    carryContainment.protectedIds
  );
  const protectionLabels = applyDefensivePrioritySpaceProtectionTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    runnerTracking.protectedIds
  );
  const pressureAngle = applyDefensivePresserAngleTarget(
    teamId,
    targets,
    presser,
    ballPoint,
    profile,
    dribbleReference
  );
  const pressureCover = applyDefensivePressureCoverBalanceTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile
  );
  const looseBallRecoveryTrap = applyDefensiveLooseBallRecoveryTrapTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    pressureCover.protectedIds
  );
  presser = looseBallRecoveryTrap.presser ?? presser;
  const pressChainSupport = applyDefensivePressChainSupportTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    looseBallRecoveryTrap.protectedIds
  );
  presser = pressChainSupport.presser ?? presser;
  const localOverloadResponse = applyDefensiveLocalOverloadResponseTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    pressChainSupport.protectedIds
  );
  presser = localOverloadResponse.presser ?? presser;
  const postRecoveryResponse = applyDefensivePostRecoveryResponseTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    localOverloadResponse.protectedIds
  );
  presser = postRecoveryResponse.presser ?? presser;
  const passLaneDenial = applyDefensivePassLaneDenialTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    postRecoveryResponse.protectedIds
  );
  const centralAccessGate = applyDefensiveCentralAccessGateTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    passLaneDenial.protectedIds
  );
  presser = centralAccessGate.presser ?? presser;
  const chanceDenialProtectedIds = new Set([
    ...[...(carryContainment.protectedIds ?? [])],
    ...[...(runnerTracking.protectedIds ?? [])],
    ...[...(looseBallRecoveryTrap.protectedIds ?? [])],
    ...[...(postRecoveryResponse.protectedIds ?? [])],
    ...[...(centralAccessGate.protectedIds ?? [])],
  ].filter(Boolean));
  const chanceDenial = applyDefensiveChanceDenialTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    chanceDenialProtectedIds,
    dribbleReference
  );
  presser = chanceDenial.presser ?? presser;
  const boxDeliveryChain = applyDefensiveBoxDeliveryChainTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    chanceDenial.protectedIds,
    dribbleReference
  );
  presser = boxDeliveryChain.presser ?? presser;
  const lineBreakAdvantageCollapse = applyDefensiveLineBreakAdvantageCollapseTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    boxDeliveryChain.protectedIds,
    dribbleReference
  );
  presser = lineBreakAdvantageCollapse.presser ?? presser;
  const emergencyCoverProtectedIds = new Set([
    presser?.id,
    ...[...(pressureAngle.protectedIds ?? [])],
    ...[...(pressureCover.protectedIds ?? [])],
    ...[...(looseBallRecoveryTrap.protectedIds ?? [])],
    ...[...(pressChainSupport.protectedIds ?? [])],
    ...[...(localOverloadResponse.protectedIds ?? [])],
    ...[...(postRecoveryResponse.protectedIds ?? [])],
    ...[...(passLaneDenial.protectedIds ?? [])],
    ...[...(centralAccessGate.protectedIds ?? [])],
    ...[...(chanceDenial.protectedIds ?? [])],
    ...[...(boxDeliveryChain.protectedIds ?? [])],
    ...[...(lineBreakAdvantageCollapse.protectedIds ?? [])],
    ...[...(carryContainment.protectedIds ?? [])],
    ...[...(runnerTracking.protectedIds ?? [])],
  ].filter(Boolean));
  const emergencyCover = applyDefensiveEmergencyCoverTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    emergencyCoverProtectedIds,
    dribbleReference
  );
  presser = emergencyCover.presser ?? presser;
  const secondBallAnticipation = applyDefensiveSecondBallAnticipationTargets(
    teamId,
    targets,
    groups,
    presser,
    ballPoint,
    profile,
    emergencyCover.protectedIds
  );
  const variationProtectedIds = new Set([
    presser?.id,
    ...[...(pressureAngle.protectedIds ?? [])],
    ...[...(pressureCover.protectedIds ?? [])],
    ...[...(looseBallRecoveryTrap.protectedIds ?? [])],
    ...[...(pressChainSupport.protectedIds ?? [])],
    ...[...(localOverloadResponse.protectedIds ?? [])],
    ...[...(postRecoveryResponse.protectedIds ?? [])],
    ...[...(passLaneDenial.protectedIds ?? [])],
    ...[...(chanceDenial.protectedIds ?? [])],
    ...[...(boxDeliveryChain.protectedIds ?? [])],
    ...[...(lineBreakAdvantageCollapse.protectedIds ?? [])],
    ...[...(emergencyCover.protectedIds ?? [])],
    ...[...(secondBallAnticipation.protectedIds ?? [])],
    ...[...(openPlayTrigger.protectedIds ?? [])],
    ...[...(receptionTrap.protectedIds ?? [])],
    ...[...(receiveContinuation.protectedIds ?? [])],
    ...[...(routeAnticipation.protectedIds ?? [])],
    ...[...(switchRecovery.protectedIds ?? [])],
    ...[...(switchLandingLock.protectedIds ?? [])],
    ...[...(gameSpaceResponse.protectedIds ?? [])],
    ...[...(carryContainment.protectedIds ?? [])],
    ...[...(runnerTracking.protectedIds ?? [])],
  ].filter(Boolean));

  applyAutopilotTargetVariation(
    teamId,
    targets,
    profile,
    "defence",
    variationProtectedIds
  );
  const unitCompactnessLabels = enforceDefensiveUnitCompactness(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    variationProtectedIds
  );
  const blockGeometryLabels = enforceDefensiveBlockGeometryLock(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    variationProtectedIds
  );
  const lineStaggeringLabels = enforceDefensiveLineStaggering(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    variationProtectedIds
  );
  const backLineHandoverLabels = applyDefensiveBackLineHandoverTargets(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    variationProtectedIds
  );
  const offsideLineControlLabels = enforceDefensiveOffsideLineControl(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    new Set([presser?.id].filter(Boolean)),
    variationProtectedIds
  );
  const chainSpacingLabels = enforceDefensiveLineChainSpacing(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    new Set([presser?.id].filter(Boolean))
  );
  const verticalBlockConnectionLabels = enforceDefensiveVerticalBlockConnections(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    new Set([presser?.id].filter(Boolean))
  );
  const measuredBlockEnvelopeLabels = enforceDefensiveMeasuredBlockEnvelope(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    new Set([presser?.id].filter(Boolean)),
    variationProtectedIds
  );
  const collectiveShiftLabels = enforceDefensiveCollectiveShiftCohesion(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    new Set([presser?.id].filter(Boolean)),
    variationProtectedIds
  );
  const compactLineIntegrityLabels = enforceDefensiveCompactLineIntegrity(
    teamId,
    targets,
    groups,
    ballPoint,
    profile,
    presser?.id ?? null,
    new Set([presser?.id].filter(Boolean)),
    variationProtectedIds
  );
  const goalkeeperSweeperLabels = applyDefensiveGoalkeeperSweeperTarget(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );
  const goalkeeperShotSetLabels = applyDefensiveGoalkeeperShotSetTarget(
    teamId,
    targets,
    groups,
    ballPoint,
    profile
  );

  return {
    targets,
    presser,
    profile,
    protectionLabels: uniquePrincipleLabels([
      ...getDefensiveLineActionLabels(profile),
      ...(buildOutPress.labels ?? []),
      ...(openPlayTrigger.labels ?? []),
      ...(receptionTrap.labels ?? []),
      ...(receiveContinuation.labels ?? []),
      ...(routeAnticipation.labels ?? []),
      ...(switchRecovery.labels ?? []),
      ...(switchLandingLock.labels ?? []),
      ...(gameSpaceResponse.labels ?? []),
      ...(carryContainment.labels ?? []),
      ...(runnerTracking.labels ?? []),
      ...(protectionLabels ?? []),
      ...(pressureCover.labels ?? []),
      ...(looseBallRecoveryTrap.labels ?? []),
      ...(pressChainSupport.labels ?? []),
      ...(localOverloadResponse.labels ?? []),
      ...(postRecoveryResponse.labels ?? []),
      ...(passLaneDenial.labels ?? []),
      ...(centralAccessGate.labels ?? []),
      ...(chanceDenial.labels ?? []),
      ...(boxDeliveryChain.labels ?? []),
      ...(lineBreakAdvantageCollapse.labels ?? []),
      ...(emergencyCover.labels ?? []),
      ...(secondBallAnticipation.labels ?? []),
      ...(pressureAngle.labels ?? []),
      ...(unitCompactnessLabels ?? []),
      ...(blockGeometryLabels ?? []),
      ...(lineStaggeringLabels ?? []),
      ...(backLineHandoverLabels ?? []),
      ...(offsideLineControlLabels ?? []),
      ...(chainSpacingLabels ?? []),
      ...(verticalBlockConnectionLabels ?? []),
      ...(measuredBlockEnvelopeLabels ?? []),
      ...(collectiveShiftLabels ?? []),
      ...(compactLineIntegrityLabels ?? []),
      ...(goalkeeperSweeperLabels ?? []),
      ...(goalkeeperShotSetLabels ?? []),
    ]),
    focusPoint: lineBreakAdvantageCollapse.focusPoint ?? boxDeliveryChain.focusPoint ?? chanceDenial.focusPoint ?? emergencyCover.focusPoint ?? centralAccessGate.focusPoint ?? localOverloadResponse.focusPoint ?? postRecoveryResponse.focusPoint ?? looseBallRecoveryTrap.focusPoint ?? carryContainment.focusPoint ?? runnerTracking.focusPoint ?? gameSpaceResponse.focusPoint ?? switchLandingLock.focusPoint ?? switchRecovery.focusPoint ?? routeAnticipation.focusPoint ?? receiveContinuation.focusPoint ?? receptionTrap.focusPoint ?? secondBallAnticipation.focusPoint ?? passLaneDenial.focusPoint ?? pressChainSupport.focusPoint ?? pressureCover.focusPoint ?? openPlayTrigger.focusPoint ?? null,
  };
}

function applyOffensiveAutopilotForCurrentAction(options = {}) {
  if (!state.offensiveAutopilot || !hasBallAction() || state.isRunning || state.sequence.isPlaying) {
    return false;
  }

  const possessionTeamId = getPlannedPossessionTeamId();
  if (!possessionTeamId) {
    return false;
  }

  const ballPoint = cloneVector(state.ball.target ?? state.draftStep?.target ?? state.ball.position);
  if (state.restartPhase?.type === "kickoff") {
    const profile = getOffensiveAutopilotProfile(possessionTeamId, ballPoint, "setPiece");
    if (state.draftStep) {
      state.draftStep.offensiveAutopilot = {
        teamId: possessionTeamId,
        ballFocusPoint: cloneVector(ballPoint),
        runnerPlayerId: null,
        phaseKey: profile.phaseKey,
        phaseLabel: profile.phaseLabel,
      };
    }
    return false;
  }

  const { targets, runner, profile, principle } = buildOffensiveAutopilotTargets(possessionTeamId, ballPoint);
  let movedPlayers = 0;

  if (state.draftStep) {
    state.draftStep.offensiveAutopilot = {
      teamId: possessionTeamId,
      ballFocusPoint: cloneVector(ballPoint),
      runnerPlayerId: runner?.id ?? null,
      phaseKey: profile.phaseKey,
      phaseLabel: profile.phaseLabel,
      principleKey: principle?.key ?? null,
      principleLabel: principle?.label ?? null,
    };
  }

  state.players.forEach((player) => {
    if (player.team !== possessionTeamId) {
      return;
    }

    const target = targets.get(player.id);
    if (!target) {
      return;
    }

    if (!player.actionOrigin) {
      player.actionOrigin = cloneVector(player.position);
    }

    const origin = getActionOrigin(player);
    const reachableTarget = clampToPitch(
      clampToCircle(target, origin, getEditableRadius(player)),
      2
    );
    const previousPosition = cloneVector(player.position);

    if (distance(previousPosition, reachableTarget) > 0.03) {
      movedPlayers += 1;
    }

    player.position = reachableTarget;

    if (distance(previousPosition, reachableTarget) > 0.04) {
      rotatePlayerBodyAlongMovement(player, previousPosition, reachableTarget, 0.72);
    }

    rotatePlayerBodyToward(player, ballPoint, runner?.id === player.id ? 0.38 : 0.52);
  });

  if (movedPlayers > 0 && !options.silent) {
    const runnerText = runner ? ` ${getPlayerMagnetLabel(runner)} attacks depth.` : "";
    const principleText = principle ? ` ${principle.label}.` : "";
    logEvent(
      `Offensive autopilot shaped ${teams[possessionTeamId].name} into ${profile.phaseLabel.toLowerCase()} support from ${teams[possessionTeamId].formation} / ${profile.styleLabel}: ${profile.principleLabel}.${runnerText}${principleText}`
    );
  }

  return movedPlayers > 0;
}

function getDefensiveAutopilotGroupsForTeam(teamId, phaseKey, players = state.players) {
  const formation = teams[teamId]?.formation ?? "4-3-3";
  const roster = teamRosterOrder[teamId] ?? [];
  const basePositions = getFormationPositions(formation, teamId);
  const baseYById = new Map(
    roster.map((playerId, index) => [playerId, basePositions[index]?.y ?? pitch.width / 2])
  );
  const groups = {
    gk: [],
    back: [],
    midfield: [],
    forward: [],
  };

  players
    .filter((player) => player.team === teamId)
    .forEach((player) => {
      groups[getDefensiveAutopilotLineKey(player, formation, phaseKey)].push(player);
    });

  Object.values(groups).forEach((group) => {
    group.sort((a, b) => (baseYById.get(a.id) ?? a.position.y) - (baseYById.get(b.id) ?? b.position.y));
  });

  return groups;
}

function applyReachableDefensiveLineCohesion(
  teamId,
  plannedPositions,
  profile,
  ballPoint,
  presserId = null
) {
  if (!ballPoint || !profile || profile.phaseKey === "highPress" || profile.phaseKey === "setPiece") {
    return;
  }

  const groups = getDefensiveAutopilotGroupsForTeam(teamId, profile.phaseKey);
  const phaseWeights = {
    boxDefending: {
      center: 0.84,
      depth: 0.8,
      slot: 0.88,
      forwardSlot: 0.56,
    },
    lowBlock: {
      center: 0.78,
      depth: 0.72,
      slot: 0.84,
      forwardSlot: 0.52,
    },
    midBlock: {
      center: 0.48,
      depth: 0.42,
      slot: 0.54,
      forwardSlot: 0.34,
    },
  };
  const weights = phaseWeights[profile.phaseKey] ?? phaseWeights.midBlock;

  ["back", "midfield", "forward"].forEach((lineKey) => {
    const settings = getDefensiveCompactLineIntegritySettings(profile, lineKey);
    if (!settings) {
      return;
    }

    const linePlayers = (groups[lineKey] ?? []).filter(
      (player) => !isGoalkeeper(player) && plannedPositions.has(player.id)
    );
    if (linePlayers.length < 2) {
      return;
    }

    const currentPositions = linePlayers.map((player) => plannedPositions.get(player.id));
    const currentCenterY =
      currentPositions.reduce((total, point) => total + point.y, 0) / currentPositions.length;
    const currentLineX =
      currentPositions.reduce((total, point) => total + point.x, 0) / currentPositions.length;
    const lineWidth = settings.gap * (linePlayers.length - 1);
    const desiredCenterY = getDefensiveLineCenterY(lineKey, profile, ballPoint, lineWidth);
    const desiredLineX = getDefensiveLineX(teamId, lineKey, ballPoint, profile);
    const cohesiveCenterY = lerp(currentCenterY, desiredCenterY, weights.center);
    const cohesiveLineX = lerp(currentLineX, desiredLineX, weights.depth);
    const slotWeight = lineKey === "forward" ? weights.forwardSlot : weights.slot;

    linePlayers.forEach((player, index) => {
      const currentPosition = plannedPositions.get(player.id);
      const lineSlot = clampToPitch({
        x: cohesiveLineX,
        y: clamp(cohesiveCenterY - lineWidth / 2 + settings.gap * index, 3.1, pitch.width - 3.1),
      }, 2.2);
      const isPresser = presserId && player.id === presserId;
      const playerSlotWeight = isPresser ? slotWeight * settings.presserScale : slotWeight;
      const cohesiveTarget = clampToPitch({
        x: lerp(currentPosition.x, lineSlot.x, playerSlotWeight),
        y: lerp(currentPosition.y, lineSlot.y, playerSlotWeight),
      }, 2.2);
      const origin = getActionOrigin(player);
      const reachableCohesiveTarget = clampToPitch(
        clampToCircle(cohesiveTarget, origin, getEditableRadius(player)),
        2
      );

      plannedPositions.set(player.id, reachableCohesiveTarget);
    });
  });
}

function applyDefensiveAutopilotForCurrentAction(options = {}) {
  if (!state.defensiveAutopilot || !hasBallAction() || state.isRunning || state.sequence.isPlaying) {
    return false;
  }

  const possessionTeamId = getPlannedPossessionTeamId();
  const defensiveTeamId = getOtherTeamId(possessionTeamId);
  if (!defensiveTeamId) {
    return false;
  }

  const ballPoint = cloneVector(state.ball.target ?? state.draftStep?.target ?? state.ball.position);
  const { targets, presser, profile, protectionLabels, focusPoint } = buildDefensiveAutopilotTargets(defensiveTeamId, ballPoint);
  const orientationPoint = focusPoint ?? ballPoint;
  let movedPlayers = 0;

  if (state.draftStep) {
    state.draftStep.defensiveAutopilot = {
      teamId: defensiveTeamId,
      ballFocusPoint: cloneVector(orientationPoint),
      presserPlayerId: presser?.id ?? null,
      phaseKey: profile.phaseKey,
      phaseLabel: profile.phaseLabel,
      protectionLabels: protectionLabels ?? [],
    };
  }

  const plannedPositions = new Map();
  const defensivePlayers = state.players.filter((player) => player.team === defensiveTeamId);

  defensivePlayers.forEach((player) => {
    const target = targets.get(player.id);
    if (!target) {
      return;
    }

    if (!player.actionOrigin) {
      player.actionOrigin = cloneVector(player.position);
    }

    const origin = getActionOrigin(player);
    plannedPositions.set(
      player.id,
      clampToPitch(clampToCircle(target, origin, getEditableRadius(player)), 2)
    );
  });

  applyReachableDefensiveLineCohesion(
    defensiveTeamId,
    plannedPositions,
    profile,
    ballPoint,
    presser?.id ?? null
  );

  defensivePlayers.forEach((player) => {
    if (player.team !== defensiveTeamId) {
      return;
    }

    const reachableTarget = plannedPositions.get(player.id);
    if (!reachableTarget) {
      return;
    }

    if (!player.actionOrigin) {
      player.actionOrigin = cloneVector(player.position);
    }

    const previousPosition = cloneVector(player.position);

    if (distance(previousPosition, reachableTarget) > 0.03) {
      movedPlayers += 1;
    }

    player.position = reachableTarget;

    if (distance(previousPosition, reachableTarget) > 0.04) {
      rotatePlayerBodyAlongMovement(player, previousPosition, reachableTarget, 0.76);
    }

    rotatePlayerBodyToward(player, orientationPoint, presser?.id === player.id ? 0.62 : 0.42);
  });

  if (movedPlayers > 0 && !options.silent) {
    const presserText = presser ? ` ${getPlayerMagnetLabel(presser)} starts the pressure.` : "";
    const protectionText = protectionLabels?.length ? ` ${protectionLabels.join("; ")}.` : "";
    logEvent(
      `Defensive autopilot shaped ${teams[defensiveTeamId].name} into a compact ${profile.phaseLabel.toLowerCase()} from ${teams[defensiveTeamId].formation} / ${profile.styleLabel}.${presserText}${protectionText}`
    );
  }

  return movedPlayers > 0;
}

function applyAutopilotsForCurrentAction(options = {}) {
  const offensiveApplied = applyOffensiveAutopilotForCurrentAction(options);
  const defensiveApplied = applyDefensiveAutopilotForCurrentAction(options);
  return offensiveApplied || defensiveApplied;
}

function getAutoPilotRoleStrength(player, strength) {
  if (!player) {
    return 0;
  }

  const context = getPlayerDecisionContext(player);
  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const roleModel = getPlayerRoleModel(player, teams[player.team]?.formation);
  const paceScore = clamp((context.maxSpeed - 6.5) / 2.8, 0, 1);
  const roleBonuses = {
    creator: {
      gk: -0.08,
      rest: 0.02,
      wideBack: 0.08,
      pivot: 0.14,
      connector: 0.18,
      wideForward: 0.1,
      striker: 0.02,
      secondStriker: 0.12,
    },
    receiver: {
      gk: -0.18,
      rest: -0.02,
      wideBack: 0.06,
      pivot: 0.08,
      connector: 0.16,
      wideForward: 0.14,
      striker: 0.18,
      secondStriker: 0.18,
    },
    runner: {
      gk: -0.28,
      rest: -0.12,
      wideBack: 0.16,
      pivot: -0.04,
      connector: 0.08,
      wideForward: 0.22,
      striker: 0.2,
      secondStriker: 0.14,
    },
    dribbler: {
      gk: -0.24,
      rest: -0.1,
      wideBack: 0.1,
      pivot: 0.02,
      connector: 0.12,
      wideForward: 0.24,
      striker: 0.08,
      secondStriker: 0.13,
    },
    finisher: {
      gk: -0.42,
      rest: -0.18,
      wideBack: -0.08,
      pivot: -0.06,
      connector: 0.08,
      wideForward: 0.16,
      striker: 0.28,
      secondStriker: 0.22,
    },
    crosser: {
      gk: -0.3,
      rest: -0.12,
      wideBack: 0.24,
      pivot: -0.02,
      connector: 0.04,
      wideForward: 0.18,
      striker: -0.1,
      secondStriker: -0.04,
    },
    switcher: {
      gk: 0.02,
      rest: 0.08,
      wideBack: 0.1,
      pivot: 0.2,
      connector: 0.16,
      wideForward: 0.02,
      striker: -0.08,
      secondStriker: 0.02,
    },
  };
  const roleBonus = roleBonuses[strength]?.[roleKey] ?? 0;
  const roleModelBoost = roleModel.strengths?.[strength] ?? 0;
  const profile = context.profile;
  const base =
    strength === "runner"
      ? paceScore * 0.42 + profile.perception * 0.2 + profile.decisionSpeed * 0.18 + profile.tacticalDiscipline * 0.2
      : strength === "dribbler"
        ? profile.technicalSecurity * 0.3 + profile.pressResistance * 0.26 + profile.composure * 0.18 + paceScore * 0.26
        : strength === "finisher"
          ? profile.technicalSecurity * 0.28 + profile.composure * 0.22 + profile.decisionQuality * 0.26 + paceScore * 0.12 + profile.perception * 0.12
          : strength === "crosser" || strength === "switcher"
            ? profile.technicalSecurity * 0.34 + profile.decisionQuality * 0.26 + profile.perception * 0.22 + profile.composure * 0.18
            : strength === "receiver"
              ? profile.perception * 0.24 + profile.technicalSecurity * 0.26 + profile.decisionSpeed * 0.18 + profile.composure * 0.16 + paceScore * 0.16
              : profile.perception * 0.28 + profile.decisionQuality * 0.3 + profile.technicalSecurity * 0.2 + profile.composure * 0.12 + profile.decisionSpeed * 0.1;
  const tendencyBoost =
    strength === "runner"
      ? Math.max(getPlayerTendency(player, "boxRun"), getPlayerTendency(player, "overlap")) - 0.5
      : strength === "dribbler"
        ? getPlayerTendency(player, "dribble") - 0.5
        : strength === "crosser"
          ? getPlayerTendency(player, "earlyCross") - 0.5
          : strength === "switcher"
            ? getPlayerTendency(player, "switchPlay") - 0.5
            : strength === "receiver"
              ? getPlayerTendency(player, "passAndMove") - 0.5
              : strength === "creator"
                ? Math.max(getPlayerTendency(player, "lineBreakPass"), getPlayerTendency(player, "retain")) - 0.5
                : 0;

  return clamp(base + roleBonus + roleModelBoost + tendencyBoost * 0.18, 0, 1.18);
}

function getAutoPilotPossessionPlayer() {
  const owner = getBallOwner();
  if (owner) {
    return owner;
  }

  const claim = resolveLooseBallClaim(
    state.ball.position,
    state.ball.claimRadius + 1.1,
    null,
    0,
    {}
  );

  if (claim.player && claim.gap <= state.ball.claimRadius + 1.4) {
    connectBallToPlayerForNextAction(claim.player, state.ball.position, 0.48);
    return claim.player;
  }

  return null;
}

function getLooseBallRecoveryTarget(player, ballPoint = state.ball.position) {
  const facingAngle = getTeamAttackAngle(player.team);
  return {
    facingAngle,
    position: getPlayerPositionForControlPoint(player, ballPoint, facingAngle),
  };
}

function getSecondBallReactionAdjustment(player, ballPoint, recovery, context = state.ball.secondBallContext) {
  if (!context) {
    return {
      score: 0,
      label: null,
    };
  }

  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const label = getPlayerMagnetLabel(player);
  const playerContext = getPlayerDecisionContext(player);
  const isPreferredPlayer = player.id === context.preferredPlayerId;
  const isPreferredTeam = player.team === context.preferredTeamId;
  const isAttackingTeam = player.team === context.attackingTeamId;
  const isDefendingTeam = player.team === context.defendingTeamId;
  const attackingBox = context.attackingTeamId ? isInsideOpponentBox(ballPoint, context.attackingTeamId) : false;
  const defensiveBox = context.defendingTeamId ? isInsideOwnBox(ballPoint, context.defendingTeamId) : false;
  const proximityUrgency = clamp(1 - recovery.runDistance / 12, 0, 1);
  const anticipation =
    playerContext.profile.perception * 0.28 +
    playerContext.profile.decisionSpeed * 0.22 +
    playerContext.profile.tacticalDiscipline * 0.16 +
    playerContext.profile.composure * 0.12;
  let score = 0;

  score -= anticipation * 0.2 * (context.urgency ?? 0.5);
  score -= proximityUrgency * 0.1;

  if (isPreferredPlayer) {
    score -= 0.32;
  } else if (isPreferredTeam) {
    score -= 0.12;
  }

  if (isAttackingTeam && attackingBox) {
    score -= ["striker", "secondStriker", "wideForward", "connector"].includes(roleKey) ? 0.24 : 0.08;
  }

  if (isDefendingTeam && (attackingBox || defensiveBox)) {
    score -= label === "CB" || label === "6" || label === "GK" ? 0.26 : 0.1;
  }

  if (roleKey === "gk" && !defensiveBox) {
    score += 0.42;
  }

  if (context.source?.includes?.("cross") || context.source?.includes?.("delivery")) {
    score -= label === "CB" || label === "9" || label === "6" ? 0.08 : 0;
  }

  return {
    score,
    label: isPreferredTeam ? "second-ball team reaction" : "second-ball counter reaction",
  };
}

function getLooseBallRecoveryStructureAdjustment(player, ballPoint, recovery, context = state.ball.secondBallContext) {
  if (!player || !ballPoint) {
    return {
      score: 0,
      label: null,
    };
  }

  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const label = getPlayerMagnetLabel(player);
  const profile = getOffensiveAutopilotProfile(player.team, ballPoint);
  const threat = getPitchThreatProfile(ballPoint, player.team);
  const opponentPressure = getOpponentPressureAtPoint(player.team, ballPoint, 10.5);
  const supportCount = getTeamSupportCountAroundPoint(player.team, ballPoint, new Set([player.id]), 11.5);
  const attackSign = getAttackDirectionSign(player.team);
  const coverBehindCount = state.players.reduce((count, teammate) => {
    if (teammate.team !== player.team || teammate.id === player.id || isGoalkeeper(teammate)) {
      return count;
    }

    const behindBall = (ballPoint.x - teammate.position.x) * attackSign >= 1.4;
    return count + (behindBall && distance(teammate.position, ballPoint) <= 17 ? 1 : 0);
  }, 0);
  const depth = getAttackingDepth(ballPoint, player.team);
  const isPreferredTeam = context?.preferredTeamId && player.team === context.preferredTeamId;
  const finalThirdLooseBall = depth >= 64 || threat.box >= 0.18 || threat.assistZone >= 0.22;
  const roleFit =
    roleKey === "pivot"
      ? 0.2
      : roleKey === "connector"
        ? 0.18
        : roleKey === "wideForward" || roleKey === "striker" || roleKey === "secondStriker"
          ? finalThirdLooseBall ? 0.18 : 0.08
          : roleKey === "wideBack"
            ? 0.12
            : roleKey === "rest"
              ? finalThirdLooseBall ? 0.03 : 0.12
              : roleKey === "gk"
                ? -0.18
                : 0.08;
  let score = 0;

  score -= roleFit;
  score -= clamp(supportCount, 0, 3) * 0.045;
  score -= clamp(coverBehindCount, 0, 3) * 0.035;
  score -= profile.counterPress * 0.045;

  if (isPreferredTeam) {
    score -= 0.08;
  }

  if (opponentPressure >= 0.58 && supportCount === 0) {
    score += 0.16 + opponentPressure * 0.08;
  }

  if (finalThirdLooseBall && (label === "9" || label === "W" || label === "10")) {
    score -= 0.1 + threat.value * 0.04;
  }

  if (threat.depth <= 32 && (label === "CB" || label === "6" || label === "GK")) {
    score -= 0.07;
  }

  if (recovery?.runDistance >= 14 && supportCount <= 1 && opponentPressure >= 0.46) {
    score += 0.08;
  }

  return {
    score: clamp(score, -0.36, 0.28),
    label:
      supportCount >= 1 || coverBehindCount >= 1
        ? "loose-ball support structure"
        : null,
  };
}

function getLooseBallNearestOpponent(player, point) {
  if (!player || !point) {
    return null;
  }

  return state.players.reduce((nearest, opponent) => {
    if (opponent.team === player.team) {
      return nearest;
    }

    const gap = distance(opponent.position, point);
    if (!nearest || gap < nearest.gap) {
      return { player: opponent, gap };
    }

    return nearest;
  }, null);
}

function getLooseBallCollectControlTouch(player, ballPoint, context = state.ball.secondBallContext) {
  if (!player || !ballPoint) {
    return null;
  }

  const attackSign = getAttackDirectionSign(player.team);
  const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
  const playerContext = getPlayerDecisionContext(player);
  const pressure = getOpponentPressureAtPoint(player.team, ballPoint, 10.5);
  const nearestOpponent = getLooseBallNearestOpponent(player, ballPoint);
  const threat = getPitchThreatProfile(ballPoint, player.team);
  const isDefensiveRecovery = context?.defendingTeamId && player.team === context.defendingTeamId;
  const isAttackingRecovery = context?.attackingTeamId && player.team === context.attackingTeamId;
  const sideSign =
    Math.sign(ballPoint.y - pitch.width / 2) ||
    Math.sign(player.position.y - pitch.width / 2) ||
    1;
  const forwardVector = { x: attackSign, y: 0 };
  const awayFromPressure = nearestOpponent
    ? normalize(nearestOpponent.player.position, ballPoint)
    : forwardVector;
  const insideExitVector = normalize(ballPoint, {
    x: ballPoint.x + attackSign * 8,
    y: lerp(ballPoint.y, pitch.width / 2, isWideChannel(ballPoint) ? 0.58 : 0.28),
  });
  const wideSafetyVector = normalize(ballPoint, {
    x: ballPoint.x + attackSign * 5,
    y: clamp(ballPoint.y + sideSign * 7.5, 4, pitch.width - 4),
  });
  const goalVector = normalize(ballPoint, getOpponentGoalCenter(player.team));
  const security =
    playerContext.profile.technicalSecurity * 0.32 +
    playerContext.profile.pressResistance * 0.24 +
    playerContext.profile.composure * 0.2 +
    playerContext.profile.decisionQuality * 0.14;
  const forwardIntent =
    (isAttackingRecovery ? 0.16 : 0) +
    (threat.depth >= 46 ? 0.12 : 0) +
    (roleKey === "wideForward" || roleKey === "striker" || roleKey === "secondStriker" ? 0.14 : 0) -
    pressure * 0.1;
  const safetyIntent =
    (isDefensiveRecovery ? 0.18 : 0) +
    (threat.depth <= 38 ? 0.12 : 0) +
    pressure * 0.14 +
    (roleKey === "gk" || roleKey === "rest" ? 0.1 : 0);
  const weights = {
    away: clamp(0.48 + pressure * 0.24 + safetyIntent * 0.36, 0.42, 0.86),
    inside: clamp(0.34 + security * 0.18 + pressure * 0.08, 0.26, 0.62),
    forward: clamp(0.2 + forwardIntent + security * 0.1, 0.08, 0.56),
    wide: clamp(safetyIntent * 0.28 + (isWideChannel(ballPoint) ? 0.12 : 0), 0, 0.36),
    goal: clamp(threat.box * 0.18 + threat.goldenZone * 0.24 + (isAttackingRecovery ? 0.08 : 0), 0, 0.34),
  };
  const combined = {
    x:
      awayFromPressure.x * weights.away +
      insideExitVector.x * weights.inside +
      forwardVector.x * weights.forward +
      wideSafetyVector.x * weights.wide +
      goalVector.x * weights.goal,
    y:
      awayFromPressure.y * weights.away +
      insideExitVector.y * weights.inside +
      forwardVector.y * weights.forward +
      wideSafetyVector.y * weights.wide +
      goalVector.y * weights.goal,
  };
  const length = Math.hypot(combined.x, combined.y) || 1;
  const direction = {
    x: combined.x / length,
    y: combined.y / length,
  };
  const touchDistance = clamp(
    0.74 +
      security * 0.76 +
      (pressure <= 0.32 ? 0.42 : 0) +
      (threat.depth >= 58 ? 0.22 : 0) -
      pressure * 0.18,
    0.68,
    pressure <= 0.38 ? 2.55 : 1.85
  );
  const controlPoint = clampToPitch({
    x: ballPoint.x + direction.x * touchDistance,
    y: ballPoint.y + direction.y * touchDistance,
  }, 1.5);
  const facingAngle = angleBetween(ballPoint, controlPoint);

  return {
    controlPoint,
    playerTarget: clampToPitch(
      getPlayerPositionForControlPoint(player, controlPoint, facingAngle),
      1.5
    ),
    facingAngle,
    pressure,
    touchDistance,
  };
}

function applyLooseBallCollectControlTouch(player, ballPoint = state.ball.position) {
  const touch = getLooseBallCollectControlTouch(player, ballPoint);
  if (!touch) {
    return connectBallToPlayerForNextAction(player, ballPoint, 0.88);
  }

  clearAutoPilotReceiveMomentum(player.id);
  player.position = cloneVector(touch.playerTarget);
  player.bodyAngle = touch.facingAngle;
  player.movementProgress = 0;
  state.ball.ownerPlayerId = player.id;
  keepSecurePossessionOnlyForOwner(player.id);
  state.ball.position = cloneVector(getPlayerBallControlPoint(player));
  state.ball.target = cloneVector(state.ball.position);
  setSecurePossessionAfterControlledTouch(player, state.ball.position, {
    quality: clamp(0.58 + (1 - touch.pressure) * 0.18, 0.42, 0.86),
    reason: "loose-ball-collect",
    minDistanceToExpire: 4.6,
    minTimeToExpire: 1.02,
  });
  state.ball.secondBallContext = null;
  return true;
}

function chooseAutoPilotLooseBallRecovery(ballPoint = state.ball.position) {
  let bestRecovery = null;
  const secondBallContext = state.ball.secondBallContext ?? null;

  state.players.forEach((player) => {
    const recoveryTarget = getLooseBallRecoveryTarget(player, ballPoint);
    const runDistance = distance(player.position, recoveryTarget.position);
    const timeToBall = computeTimeToCoverDistance(player, runDistance, recoveryTarget.position);
    const context = getPlayerDecisionContext(player);
    const roleKey = getOffensiveRoleKey(player, teams[player.team]?.formation);
    const goalkeeperPenalty = roleKey === "gk" ? 0.85 : 0;
    const ballWinnerBonus =
      context.profile.perception * 0.18 +
      context.profile.decisionSpeed * 0.14 +
      context.profile.tacticalDiscipline * 0.08;
    const secondBallAdjustment = getSecondBallReactionAdjustment(
      player,
      ballPoint,
      {
        runDistance,
        timeToBall,
      },
      secondBallContext
    );
    const structureAdjustment = getLooseBallRecoveryStructureAdjustment(
      player,
      ballPoint,
      {
        runDistance,
        timeToBall,
      },
      secondBallContext
    );
    const score =
      timeToBall +
      runDistance * 0.012 +
      goalkeeperPenalty -
      ballWinnerBonus +
      secondBallAdjustment.score +
      structureAdjustment.score;

    const recovery = {
      player,
      ballPoint: cloneVector(ballPoint),
      targetPosition: recoveryTarget.position,
      facingAngle: recoveryTarget.facingAngle,
      runDistance,
      timeToBall,
      duration: Math.max(timeToBall + 0.12, 0.35),
      score,
      secondBallLabel: secondBallAdjustment.label ?? structureAdjustment.label,
    };

    if (!bestRecovery || recovery.score < bestRecovery.score) {
      bestRecovery = recovery;
    }
  });

  return bestRecovery;
}

function issueLooseBallRecoveryCommand(recovery) {
  if (!recovery?.player) {
    return false;
  }

  const player = recovery.player;
  const ballPoint = cloneVector(recovery.ballPoint ?? state.ball.position);
  const targetPosition = clampToPitch(recovery.targetPosition ?? player.position, 2);
  const facingAngle = Number.isFinite(recovery.facingAngle)
    ? recovery.facingAngle
    : getTeamAttackAngle(player.team);
  const recoverySpeed = recovery.runDistance / Math.max(recovery.duration, 0.01);
  const startSnapshot = captureSnapshot();
  startSnapshot.ball.position = cloneVector(ballPoint);
  startSnapshot.ball.ownerPlayerId = null;
  startSnapshot.ball.securePossession = null;

  clearSecurePossession();
  state.draftStep = {
    actionType: "recovery",
    target: cloneVector(ballPoint),
    speed: recoverySpeed,
    speedMode: "auto",
    profileKey: "loose-ball-recovery",
    profileLabel: "Loose Ball Recovery",
    targetKind: "loose-ball",
    recoveryDuration: recovery.duration,
    carrierPlayerId: player.id,
    receiverPlayerId: null,
    beforeSnapshot: startSnapshot,
    autoGenerated: true,
    autoReason: recovery.secondBallLabel ?? "nearest player attacks the loose ball",
    secondBallContext: state.ball.secondBallContext ? {
      ...state.ball.secondBallContext,
      originPoint: cloneVector(state.ball.secondBallContext.originPoint),
      spillPoint: cloneVector(state.ball.secondBallContext.spillPoint),
    } : null,
  };

  state.players.forEach((entry) => {
    entry.actionOrigin = cloneVector(entry.position);
  });

  player.position = cloneVector(targetPosition);
  player.bodyAngle = facingAngle;
  player.movementProgress = 0;
  setSelectedPlayers([player.id], player.id);

  state.ball.position = cloneVector(ballPoint);
  state.ball.startPosition = cloneVector(ballPoint);
  state.ball.target = cloneVector(ballPoint);
  state.ball.speed = recoverySpeed;
  state.ball.currentSpeed = 0;
  state.ball.launchSpeed = 0;
  state.ball.finalSpeed = 0;
  state.ball.deceleration = 0;
  state.ball.profileKey = "loose-ball-recovery";
  state.ball.profileLabel = "Loose Ball Recovery";
  state.ball.profileMode = "auto";
  state.ball.targetKind = "loose-ball";
  state.ball.firstTouchMode = null;
  state.ball.flightStyle = "ground";
  state.ball.peakHeight = 0;
  state.ball.height = 0;
  state.ball.trackDistanceTotal = 0;
  state.ball.trackDistanceCovered = 0;
  state.ball.inTransit = true;
  state.ball.elapsedTravelTime = 0;
  state.ball.actionType = "recovery";
  state.ball.ownerPlayerId = null;
  state.ball.initiatorPlayerId = player.id;
  state.ball.carrierPlayerId = player.id;
  state.ball.receiverPlayerId = null;
  state.ball.recoveryDuration = recovery.duration;

  applyAutopilotsForCurrentAction();

  // Autopilot may shape the possession team, but the recovery runner must still attack the ball.
  player.position = cloneVector(targetPosition);
  player.bodyAngle = facingAngle;
  player.movementProgress = 0;

  logEvent(
    `${recovery.secondBallLabel ? "Second-ball recovery" : "Loose ball recovery"} planned: ${player.shortLabel} ${player.role} attacks the ball in ${formatTime(recovery.duration)}.`
  );
  return true;
}

function getAutoPilotShotTarget(teamId, shooter) {
  const goal = getOpponentGoalCenter(teamId);
  if (!shooter) {
    return resolveShotTarget(goal, null);
  }

  const startPoint = getPlayerBallControlPoint(shooter);
  const shooterSide =
    Math.sign(startPoint.y - pitch.width / 2) ||
    (shooter.preferredFoot === "left" ? -1 : 1);
  const goalDistance = distance(startPoint, goal);
  const isWide = isWideChannel(startPoint);
  const isClose = goalDistance <= 19;
  const finisherStrength = getAutoPilotRoleStrength(shooter, "finisher");
  const options = [
    {
      key: "far-corner",
      label: "far corner",
      y: pitch.width / 2 - shooterSide * 3.08,
      baseScore: 0.34,
      closeBonus: 0.08,
    },
    {
      key: "near-post",
      label: "near post",
      y: pitch.width / 2 + shooterSide * 2.82,
      baseScore: isWide ? 0.28 : 0.04,
      closeBonus: 0.28,
    },
    {
      key: "across-goal",
      label: "across goal",
      y: pitch.width / 2 - shooterSide * 2.18,
      baseScore: 0.22,
      closeBonus: 0.14,
    },
    {
      key: "keeper-wrong-foot",
      label: "wrong-foot finish",
      y: pitch.width / 2 + shooterSide * 1.18,
      baseScore: finisherStrength >= 0.76 ? 0.18 : -0.02,
      closeBonus: 0.1,
    },
  ];

  const rankedTargets = options
    .map((option) => {
      const target = getGoalMouthTarget(teamId, option.y);
      const window = getShotWindowProfile(shooter, startPoint, target);
      const footScore = getFootUsageScore(shooter, angleBetween(startPoint, target));
      const cornerValue = clamp(Math.abs(target.y - pitch.width / 2) / (7.32 / 2), 0, 1);
      const score =
        option.baseScore +
        (isClose ? option.closeBonus : 0) +
        window.laneClarity * 0.34 +
        window.goalkeeperOpenness * 0.36 +
        window.angleQuality * 0.22 +
        footScore * 0.16 +
        cornerValue * 0.18 +
        finisherStrength * 0.14 -
        window.blockRisk * 0.34 -
        (goalDistance > 31 && option.key === "near-post" ? 0.16 : 0);

      return {
        ...option,
        target,
        window,
        score,
      };
    })
    .sort((a, b) => b.score - a.score);

  return rankedTargets[0]?.target ?? resolveShotTarget(goal, shooter);
}

function getAutoPilotBoxTarget(teamId, carrier, variant = "cross") {
  const sign = getAttackDirectionSign(teamId);
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const farPostSide = Math.sign((carrier?.position.y ?? pitch.width / 2) - pitch.width / 2) || 1;

  if (variant === "far-post") {
    return clampToPitch({
      x: penaltySpot.x + sign * 3.8,
      y: pitch.width / 2 - farPostSide * 10.5,
    }, 1.5);
  }

  if (variant === "cutback") {
    return clampToPitch({
      x: penaltySpot.x - sign * 3.5,
      y: pitch.width / 2 + farPostSide * 2.5,
    }, 1.5);
  }

  return clampToPitch({
    x: penaltySpot.x + sign * 0.8,
    y: pitch.width / 2 - farPostSide * 4.2,
  }, 1.5);
}

function getCornerDeliveryTarget(teamId, sideY = 0, slot = "penaltySpot") {
  const sign = getAttackDirectionSign(teamId);
  const sideSign = sideY <= pitch.width / 2 ? -1 : 1;
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const points = {
    nearPost: {
      x: penaltySpot.x + sign * 4.9,
      y: pitch.width / 2 + sideSign * 4.6,
    },
    farPost: {
      x: penaltySpot.x + sign * 4.2,
      y: pitch.width / 2 - sideSign * 7.8,
    },
    penaltySpot: {
      x: penaltySpot.x - sign * 0.4,
      y: pitch.width / 2 - sideSign * 0.8,
    },
    edge: {
      x: penaltySpot.x - sign * 8.4,
      y: pitch.width / 2 - sideSign * 3.2,
    },
    short: {
      x: teamId === "home" ? pitch.length - 9.4 : 9.4,
      y: sideY <= pitch.width / 2 ? 2.8 : pitch.width - 2.8,
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 1.3);
}

function chooseCornerDeliveryRunner(teamId, target, carrierId = null, slot = "penaltySpot") {
  const slotRoleBonus = {
    nearPost: { striker: 0.3, secondStriker: 0.24, wideForward: 0.12, connector: 0.08 },
    farPost: { wideForward: 0.26, striker: 0.22, secondStriker: 0.2, connector: 0.1 },
    penaltySpot: { striker: 0.22, connector: 0.18, secondStriker: 0.18, wideForward: 0.12 },
    edge: { connector: 0.28, pivot: 0.24, wideBack: 0.1 },
    short: { wideBack: 0.26, wideForward: 0.24, connector: 0.18 },
  };

  return state.players
    .filter((player) => player.team === teamId && player.id !== carrierId && !isGoalkeeper(player))
    .map((player) => {
      const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
      const roleFit = slotRoleBonus[slot]?.[roleKey] ?? 0;
      const runnerStrength = getAutoPilotRoleStrength(player, "runner");
      const finisherStrength = getAutoPilotRoleStrength(player, "finisher");
      const receiverStrength = getAutoPilotRoleStrength(player, "receiver");
      const gap = distance(player.position, target);
      const timeToTarget = computeTimeToCoverDistance(player, gap, target);
      const score =
        0.5 +
        roleFit +
        runnerStrength * 0.32 +
        finisherStrength * 0.28 +
        receiverStrength * 0.18 -
        timeToTarget * 0.08 -
        gap * 0.006;

      return {
        player,
        roleKey,
        gap,
        timeToTarget,
        score,
      };
    })
    .sort((a, b) => b.score - a.score)[0] ?? null;
}

function getFreeKickDeliveryTarget(teamId, freeKickPoint, slot = "penaltySpot") {
  const sign = getAttackDirectionSign(teamId);
  const sideSign = getWideSideSign(freeKickPoint) || 1;
  const penaltySpot = getOpponentPenaltySpot(teamId);
  const points = {
    nearPost: {
      x: penaltySpot.x + sign * 4.6,
      y: pitch.width / 2 + sideSign * 5.3,
    },
    farPost: {
      x: penaltySpot.x + sign * 4.1,
      y: pitch.width / 2 - sideSign * 9.2,
    },
    penaltySpot: {
      x: penaltySpot.x - sign * 0.7,
      y: pitch.width / 2 - sideSign * 1.2,
    },
    edge: {
      x: penaltySpot.x - sign * 8.6,
      y: pitch.width / 2 - sideSign * 4.8,
    },
  };

  return clampToPitch(points[slot] ?? points.penaltySpot, 1.5);
}

function chooseFreeKickShortReceiver(teamId, carrier, startPoint, profile) {
  const formation = teams[teamId]?.formation;
  return state.players
    .filter((receiver) => receiver.team === teamId && receiver.id !== carrier.id && !isGoalkeeper(receiver))
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const roleFit =
        roleKey === "connector"
          ? 0.38
          : roleKey === "pivot"
            ? 0.34
            : roleKey === "wideBack"
              ? 0.28
              : roleKey === "wideForward"
                ? 0.16
                : 0.08;
      const score =
        1.5 +
        roleFit +
        laneClarity * 0.74 +
        profile.shortSupport * 0.52 +
        getAutoPilotRoleStrength(receiver, "receiver") * 0.28 -
        receiverPressure * 0.46 -
        Math.abs(passDistance - 10.5) * 0.04 -
        (forwardGain < -8 ? 0.18 : 0);

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        receiverPressure,
        score,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 4.5 &&
      candidate.passDistance <= 18 &&
      candidate.laneClarity >= 0.34 &&
      candidate.receiverPressure <= 0.76
    ))
    .sort((a, b) => b.score - a.score)[0] ?? null;
}

function getAutoPilotDribbleTarget(carrier, profile = getOffensiveAutopilotProfile(carrier.team, carrier.position)) {
  const teamId = carrier.team;
  const sign = getAttackDirectionSign(teamId);
  const startPoint = getPlayerBallControlPoint(carrier);
  const runwayCarry = getRunwayCarryTarget(carrier, startPoint, profile);
  if (runwayCarry?.target) {
    return runwayCarry.target;
  }

  const breakawayTarget = getBreakawayCarryTarget(carrier, startPoint, profile);
  if (breakawayTarget) {
    return breakawayTarget;
  }

  const openGrassCarry = getOpenGrassCarryContext(carrier, startPoint, profile);
  if (openGrassCarry?.target) {
    return openGrassCarry.target;
  }

  const ballDepth = getAttackingDepth(carrier.position, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const forwardFacingSpaceTwo = getForwardFacingSpaceTwoContext(carrier, startPoint);
  const isWide = isWideChannel(carrier.position);
  const openForwardPoint = clampToPitch({
    x: carrier.position.x + sign * 22,
    y: lerp(carrier.position.y, pitch.width / 2, isWide ? 0.42 : 0.22),
  }, 2.5);
  const openSpaceScore = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, openForwardPoint));
  const centralPull = forwardFacingSpaceTwo.active
    ? 0.34
    : isWide ? lerp(0.24, 0.5, openSpaceScore) : pressure > 0.52 ? 0.12 : lerp(0.06, 0.2, openSpaceScore);
  const tendency = getPlayerTendency(carrier, "dribble");
  const carryDistance = clamp(
    6.5 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 4.1 +
      profile.dribbleBias * 2.2 +
      tendency * 1.2 -
      pressure * 3.4 +
      openSpaceScore * 8.5 +
      (forwardFacingSpaceTwo.active ? 4.2 : 0) +
      (ballDepth < 35 ? 1.1 : 0),
    4.5,
    openSpaceScore >= 0.72 && pressure <= 0.36 ? 22 : 14.5
  );

  return clampToPitch({
    x: carrier.position.x + sign * carryDistance,
    y: lerp(carrier.position.y, pitch.width / 2, centralPull),
  }, 2.5);
}

function getTeamSupportCountAroundPoint(teamId, point, excludedIds = new Set(), radius = 12) {
  return state.players.reduce((count, player) => {
    if (player.team !== teamId || excludedIds.has(player.id) || isGoalkeeper(player)) {
      return count;
    }

    return count + (distance(player.position, point) <= radius ? 1 : 0);
  }, 0);
}

function getGoalkeeperDistributionPressure(teamId, startPoint) {
  const opponents = state.players.filter((player) => player.team !== teamId && !isGoalkeeper(player));
  const highPressers = opponents.filter((player) => distance(player.position, startPoint) <= 26).length;
  const closePressers = opponents.filter((player) => distance(player.position, startPoint) <= 15).length;
  const nearest = opponents.reduce(
    (best, player) => Math.min(best, distance(player.position, startPoint)),
    Infinity
  );

  return clamp(
    (Number.isFinite(nearest) ? clamp((24 - nearest) / 18, 0, 1) : 0) * 0.42 +
      clamp(highPressers / 4, 0, 1) * 0.34 +
      clamp(closePressers / 2, 0, 1) * 0.24,
    0,
    1
  );
}

function getGoalkeeperDirectReleaseTarget(teamId, runner, startPoint, profile) {
  const sideSign = getWideSideSign(runner) || getWideSideSign(startPoint) || 1;
  const roleKey = getOffensiveRoleKey(runner, teams[teamId]?.formation);
  const targetDepth =
    roleKey === "striker"
      ? clamp(58 + profile.frontAhead + profile.routeOneBias * 16, 58, 88)
      : clamp(54 + profile.frontAhead + profile.directness * 13, 52, 84);

  return getDepthPoint(teamId, targetDepth, {
    y: clamp(
      roleKey === "wideForward"
        ? pitch.width / 2 + sideSign * 22
        : pitch.width / 2 + sideSign * 7,
      5,
      pitch.width - 5
    ),
  });
}

function buildAutoPilotGoalkeeperDistributionCandidate(carrier, startPoint, profile) {
  if (!isGoalkeeper(carrier) || state.restartPhase?.type === "kickoff") {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const gkPressure = getGoalkeeperDistributionPressure(teamId, startPoint);
  const shouldInviteAndPlay =
    profile.shortSupport >= 0.68 &&
    profile.routeOneBias < 0.48 &&
    gkPressure <= 0.72;
  const shortOptions = state.players
    .filter((receiver) => {
      if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      return roleKey === "rest" || roleKey === "wideBack" || roleKey === "pivot" || roleKey === "connector";
    })
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const roleFit =
        roleKey === "rest"
          ? 0.48
          : roleKey === "pivot"
            ? 0.38
            : roleKey === "wideBack"
              ? 0.28
              : 0.16;
      const score =
        2.05 +
        profile.shortSupport * 0.82 +
        laneClarity * 1.16 +
        getAutoPilotRoleStrength(receiver, "receiver") * 0.44 +
        roleFit -
        receiverPressure * 0.72 -
        Math.abs(passDistance - 13.5) * 0.034 -
        (passDistance > 24 ? 0.34 : 0) -
        (gkPressure > 0.62 && receiverPressure > 0.56 ? 0.46 : 0);

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        laneClarity,
        receiverPressure,
        score,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 4.5 &&
      candidate.passDistance <= 30 &&
      candidate.laneClarity >= 0.32 &&
      candidate.receiverPressure <= 0.84 &&
      candidate.score >= 1.55
    ))
    .sort((a, b) => b.score - a.score);

  const directOptions =
    profile.routeOneBias >= 0.42 || profile.directness >= 0.68 || gkPressure >= 0.58
      ? state.players
          .filter((runner) => {
            if (runner.team !== teamId || runner.id === carrier.id || isGoalkeeper(runner)) {
              return false;
            }

            const roleKey = getOffensiveRoleKey(runner, formation);
            return roleKey === "striker" || roleKey === "wideForward" || roleKey === "secondStriker";
          })
          .map((runner) => {
            const target = getGoalkeeperDirectReleaseTarget(teamId, runner, startPoint, profile);
            const passDistance = distance(startPoint, target);
            const laneClarity = computePassLaneClarity(carrier, target);
            const runnerDistance = distance(runner.position, target);
            const runnerTime = computeTimeToCoverDistance(runner, runnerDistance, target);
            const passTime = passDistance / Math.max(resolveBallActionProfile("pass", startPoint, target, carrier, null).averageSpeed, 0.01);
            const timingFit = clamp(1 - Math.abs(runnerTime - passTime) / 1.65, 0, 1);
            const supportNearTarget = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, runner.id]), 18);
            const score =
              1.42 +
              profile.directness * 0.72 +
              profile.routeOneBias * 0.92 +
              gkPressure * 0.46 +
              laneClarity * 0.72 +
              timingFit * 0.54 +
              getAutoPilotRoleStrength(runner, "runner") * 0.5 +
              getAutoPilotRoleStrength(runner, "receiver") * 0.24 +
              clamp(supportNearTarget, 0, 3) * 0.12 -
              (passDistance > 58 && profile.routeOneBias < 0.72 ? 0.32 : 0);

            return {
              runner,
              target,
              passDistance,
              laneClarity,
              timingFit,
              supportNearTarget,
              score,
            };
          })
          .filter((candidate) => (
            candidate.passDistance >= 24 &&
            candidate.passDistance <= 68 &&
            candidate.laneClarity >= 0.24 &&
            candidate.timingFit >= 0.1 &&
            candidate.score >= 1.6
          ))
          .sort((a, b) => b.score - a.score)
      : [];

  const shortChoice = shortOptions[0] ?? null;
  const directChoice = directOptions[0] ?? null;
  const playDirect =
    directChoice &&
    (!shouldInviteAndPlay ||
      directChoice.score >= (shortChoice?.score ?? 0) + 0.24 ||
      (gkPressure >= 0.74 && directChoice.score >= 1.75));

  if (playDirect) {
    return {
      actionType: "pass",
      target: directChoice.target,
      receiverPlayerId: null,
      passDistance: directChoice.passDistance,
      laneClarity: directChoice.laneClarity,
      receiverPressure: 0.42,
      supportNearTarget: directChoice.supportNearTarget,
      isLineBreak: true,
      isSwitch: false,
      isSidewaysPass: false,
      isBoxPass: false,
      isPrinciplePattern: true,
      principleKey: "gk-direct-release",
      principleLabel: `GK release: ${getPlayerMagnetLabel(directChoice.runner)} attacks territory with support for the second ball`,
      principleRunnerPlayerId: directChoice.runner.id,
      score: directChoice.score,
      firstTouchMode: "forward",
      label: "gk release",
      reason: "goalkeeper bypasses pressure into an attacking runner",
    };
  }

  if (!shortChoice) {
    return null;
  }

  return {
    actionType: "pass",
    target: shortChoice.target,
    receiverPlayerId: shortChoice.receiver.id,
    receiverRoleKey: shortChoice.roleKey,
    passDistance: shortChoice.passDistance,
    laneClarity: shortChoice.laneClarity,
    receiverPressure: shortChoice.receiverPressure,
    isLineBreak: false,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: false,
    isPrinciplePattern: true,
    principleKey: "gk-build-out",
    principleLabel: `GK build-out: ${getPlayerMagnetLabel(shortChoice.receiver)} opens the first line`,
    score: shortChoice.score + (shouldInviteAndPlay ? 0.28 : 0),
    firstTouchMode: shortChoice.roleKey === "rest" || shortChoice.roleKey === "pivot" ? "inside" : "forward",
    label: "gk build-out",
    reason: "goalkeeper secures the first pass and sets the build-up shape",
  };
}

function buildAutoPilotShotCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const goalTarget = getAutoPilotShotTarget(teamId, carrier);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const centrality = 1 - Math.abs(startPoint.y - pitch.width / 2) / (pitch.width / 2);
  const pressure = getPlayerPressureLoad(carrier, getPlayerBallControlPoint(carrier));
  const finisherStrength = getAutoPilotRoleStrength(carrier, "finisher");
  const shotWindow = getShotWindowProfile(carrier, startPoint, goalTarget);
  const carryEndProduct = getAutoPilotCarryEndProductContext(carrier, startPoint, profile);
  const laneClarity = shotWindow.laneClarity;
  const angleQuality = shotWindow.angleQuality;
  const blockRisk = shotWindow.blockRisk;
  const insideBox = isInsideOpponentBox(startPoint, teamId);
  const centralEdgeShot =
    goalDistance <= 30.5 &&
    centrality >= 0.42 &&
    laneClarity >= 0.38 &&
    angleQuality >= 0.22 &&
    blockRisk <= 0.74 &&
    pressure <= 0.78;
  const finalThirdShot =
    goalDistance <= 34.5 &&
    attackingDepth >= 67 &&
    centrality >= 0.18 &&
    angleQuality >= 0.18 &&
    blockRisk <= 0.78 &&
    pressure <= 0.82;
  const finisherRangeShot =
    goalDistance <= 37 &&
    attackingDepth >= 69 &&
    centrality >= 0.22 &&
    laneClarity >= 0.42 &&
    angleQuality >= 0.2 &&
    blockRisk <= 0.66 &&
    pressure <= 0.72 &&
    finisherStrength >= 0.76;
  const nearGoalThreat =
    goalDistance <= 30 &&
    centrality >= 0.16 &&
    angleQuality >= 0.16 &&
    blockRisk <= 0.82 &&
    pressure <= 0.84;
  const clearBreakawayShot =
    goalDistance <= 35 &&
    attackingDepth >= 66 &&
    laneClarity >= 0.34 &&
    angleQuality >= 0.2 &&
    blockRisk <= 0.74 &&
    pressure <= 0.62 &&
    (centrality >= 0.28 || finisherStrength >= 0.78);
  const wideBoxAngle =
    attackingDepth >= 78 &&
    goalDistance <= 29 &&
    centrality >= 0.1 &&
    angleQuality >= 0.14 &&
    pressure <= 0.82;
  const finalThirdCarryShot =
    attackingDepth >= 74 &&
    goalDistance <= 36 &&
    centrality >= 0.1 &&
    angleQuality >= 0.15 &&
    blockRisk <= 0.82 &&
    pressure <= 0.86;
  const carryEndProductShot =
    carryEndProduct.active &&
    carryEndProduct.finishWindow &&
    goalDistance <= 36 &&
    attackingDepth >= 66 &&
    laneClarity >= 0.32 &&
    angleQuality >= 0.14 &&
    blockRisk <= 0.84 &&
    pressure <= 0.84;
  const runwayExitShot =
    carryEndProduct.active &&
    carryEndProduct.wasRunwayCarry &&
    goalDistance <= 39 &&
    attackingDepth >= 63 &&
    laneClarity >= 0.3 &&
    angleQuality >= 0.12 &&
    blockRisk <= 0.88 &&
    pressure <= 0.86;
  const openShotWindow =
    (insideBox && shotWindow.quality >= 0.22) ||
    centralEdgeShot ||
    finalThirdShot ||
    finisherRangeShot ||
    nearGoalThreat ||
    clearBreakawayShot ||
    wideBoxAngle ||
    finalThirdCarryShot ||
    carryEndProductShot ||
    runwayExitShot ||
    goalDistance <= 25.5 ||
    (goalDistance <= 31 &&
      attackingDepth >= 72 &&
      laneClarity >= 0.58 &&
      angleQuality >= 0.2 &&
      blockRisk <= 0.68 &&
      pressure <= 0.55 &&
      finisherStrength >= 0.64);

  if (!openShotWindow && goalDistance > 38 && !(finisherStrength >= 0.9 && attackingDepth >= 72)) {
    return null;
  }

  const recentTeamSteps = getRecentPossessionSteps(teamId, 4);
  const recentTeamShots = recentTeamSteps.filter((step) => step.actionType === "shot").length;
  const lastTeamStep = recentTeamSteps[0] ?? null;
  if (
    !insideBox &&
    goalDistance > 24 &&
    (lastTeamStep?.actionType === "shot" || recentTeamShots >= 2)
  ) {
    return null;
  }

  const distanceScore = clamp(1 - (goalDistance - 10) / 28, 0, 1);
  const score =
    1.18 +
    distanceScore * 1.78 +
    centrality * 0.82 +
    finisherStrength * 1.34 +
    (profile?.shootBias ?? 0.48) * 1.1 +
    laneClarity * 0.85 -
    blockRisk * 0.78 +
    angleQuality * 0.62 +
    shotWindow.goalkeeperOpenness * 0.48 +
    shotWindow.quality * 0.66 -
    pressure * 0.65 -
    (attackingDepth < 62 ? 0.92 : attackingDepth < 68 ? 0.36 : 0) +
    (insideBox ? 1.05 : 0) +
    (centralEdgeShot ? 0.62 : 0) +
    (finalThirdShot ? 0.42 : 0) +
    (finisherRangeShot ? 0.36 : 0) +
    (nearGoalThreat ? 0.7 : 0) +
    (clearBreakawayShot ? 0.85 : 0) +
    (wideBoxAngle ? 0.55 : 0) +
    (finalThirdCarryShot ? 0.45 : 0) +
    (carryEndProductShot ? 0.6 + carryEndProduct.endProductUrgency * 0.28 : 0) +
    (runwayExitShot ? 0.62 + carryEndProduct.endProductUrgency * 0.32 : 0) +
    (openShotWindow ? 0.42 : 0);

  if (score < (openShotWindow ? 1.45 : 2.0)) {
    return null;
  }

  return {
    actionType: "shot",
    target: goalTarget,
    receiverPlayerId: null,
    score,
    goalDistance,
    laneClarity,
    blockRisk,
    angleQuality,
    goalkeeperOpenness: shotWindow.goalkeeperOpenness,
    shotQuality: shotWindow.quality,
    insideBox,
    mustShoot:
      (insideBox && shotWindow.quality >= 0.28) ||
      nearGoalThreat ||
      clearBreakawayShot ||
      wideBoxAngle ||
      (finalThirdCarryShot && (finisherStrength >= 0.62 || laneClarity >= 0.35)) ||
      (carryEndProductShot && (shotWindow.quality >= 0.22 || finisherStrength >= 0.64 || goalDistance <= 29)) ||
      (runwayExitShot && (shotWindow.quality >= 0.18 || finisherStrength >= 0.62 || goalDistance <= 31)) ||
      (centralEdgeShot && goalDistance <= 31) ||
      (finisherRangeShot && finisherStrength >= 0.84),
    label: "shot",
    reason: insideBox
      ? "box chance"
      : runwayExitShot
        ? "runway carry has created a shooting window"
      : carryEndProductShot
        ? "end product after carrying the ball"
      : clearBreakawayShot
        ? "clear route to goal"
        : centralEdgeShot || nearGoalThreat || finalThirdCarryShot
          ? "central shooting lane"
          : wideBoxAngle
            ? "shooting angle in the box"
            : "goal threat",
  };
}

function buildAutoPilotKickoffCandidate(carrier, startPoint, profile) {
  if (state.restartPhase?.type !== "kickoff" || state.restartPhase.teamId !== carrier.team) {
    return null;
  }

  const support = getPlayerById(state.restartPhase.supportPlayerId) ?? getPlayerById(getKickoffSupportId(carrier.team));
  if (!support || support.id === carrier.id) {
    return null;
  }

  const target = getPlayerBallControlPoint(support);
  const passDistance = distance(startPoint, target);
  if (passDistance < 2.5 || passDistance > 12) {
    return null;
  }

  return {
    actionType: "pass",
    target,
    receiverPlayerId: support.id,
    receiverRoleKey: getOffensiveRoleKey(support, teams[carrier.team]?.formation),
    passDistance,
    forwardGain: (target.x - startPoint.x) * getAttackDirectionSign(carrier.team),
    laneClarity: computePassLaneClarity(carrier, target),
    receiverPressure: getPlayerPressureLoad(support, target),
    isLineBreak: false,
    isSwitch: false,
    isBoxPass: false,
    score: 4.6,
    firstTouchMode: "back",
    label: "kick-off reset",
    reason: "play home first and let the possession identity start from a stable shape",
  };
}

function getLastKickoffOpeningProfile(teamId) {
  const lastStep = state.sequence?.steps?.[state.sequence.steps.length - 1];
  const openingKey =
    lastStep?.restartPhase?.openingKey ??
    state.restartPhase?.openingKey ??
    null;

  if (!openingKey || lastStep?.restartPhase?.teamId !== teamId) {
    return kickoffOpeningProfiles["secure-backline"];
  }

  return kickoffOpeningProfiles[openingKey] ?? kickoffOpeningProfiles["secure-backline"];
}

function getKickoffOpeningCandidateFit(openingProfile, candidate, startPoint, teamId, profile) {
  if (!openingProfile || !candidate?.receiver) {
    return {
      score: 0,
      label: "kick-off build-up reset",
      reason: "drop the second touch into the back line before the chosen identity takes over",
      firstTouchMode: profile.directness >= 0.68 ? "forward" : "inside",
    };
  }

  const targetLane = getPitchLaneKey(candidate.target);
  const startLane = getPitchLaneKey(startPoint);
  const laneShift = Math.abs(getPitchLaneIndex(targetLane) - getPitchLaneIndex(startLane));
  const isWeakSide =
    getWideSideSign(candidate.target) &&
    getWideSideSign(startPoint) &&
    getWideSideSign(candidate.target) === -getWideSideSign(startPoint);
  const forwardFit = clamp(candidate.forwardGain / 11, -0.2, 1);
  const backwardFit = clamp((-candidate.forwardGain - 3) / 20, 0, 1);
  const roleFit = openingProfile.receiverRoles.includes(candidate.roleKey) ? 0.72 : -0.38;
  let score = roleFit;

  if (openingProfile.key === "secure-backline") {
    score += backwardFit * 0.46 + candidate.laneClarity * 0.2 - Math.max(candidate.forwardGain - 1, 0) * 0.08;
  } else if (openingProfile.key === "pivot-turnout") {
    score +=
      (candidate.roleKey === "pivot" || candidate.roleKey === "connector" ? 0.38 : 0) +
      clamp(Math.abs(candidate.forwardGain) <= 8 ? 0.22 : -0.12, -0.12, 0.22) +
      candidate.laneClarity * 0.24 -
      candidate.receiverPressure * 0.18;
  } else if (openingProfile.key === "wide-release") {
    score +=
      (candidate.roleKey === "wideBack" || candidate.roleKey === "wideForward" ? 0.42 : 0) +
      laneShift * 0.13 +
      (targetLane.includes("Wide") ? 0.28 : 0) +
      clamp(candidate.forwardGain / 8, -0.08, 0.22);
  } else if (openingProfile.key === "weak-side-shift") {
    score +=
      (isWeakSide ? 0.44 : 0) +
      laneShift * 0.16 +
      candidate.laneClarity * 0.22 +
      profile.switchBias * 0.18;
  } else if (openingProfile.key === "vertical-second-touch") {
    score +=
      forwardFit * 0.58 +
      (candidate.roleKey === "connector" || candidate.roleKey === "secondStriker" ? 0.34 : 0) +
      profile.lineBreakBias * 0.22 -
      candidate.receiverPressure * 0.2;
  }

  return {
    score,
    label: openingProfile.key,
    reason: `${openingProfile.label} after the kick-off reset`,
    firstTouchMode: openingProfile.firstTouchMode,
  };
}

function buildAutoPilotPostKickoffResetCandidate(carrier, startPoint, profile) {
  if (!isLastStepKickoffResetForTeam(carrier.team)) {
    return null;
  }

  const formation = teams[carrier.team]?.formation;
  const openingProfile = getLastKickoffOpeningProfile(carrier.team);
  const candidates = state.players
    .filter((receiver) => {
      if (receiver.team !== carrier.team || receiver.id === carrier.id) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      return (
        roleKey === "rest" ||
        roleKey === "gk" ||
        roleKey === "wideBack" ||
        roleKey === "pivot" ||
        openingProfile.receiverRoles.includes(roleKey)
      );
    })
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(carrier.team);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const roleBase =
        roleKey === "rest"
          ? 1.45
          : roleKey === "gk"
            ? 0.92
            : roleKey === "wideBack"
              ? 0.48
              : 0.24;
      const backwardFit = clamp((-forwardGain - 4) / 22, 0, 1);
      const centralFit = 1 - Math.abs(target.y - pitch.width / 2) / (pitch.width / 2);
      const styleFit =
        profile.directness < 0.45
          ? roleKey === "rest" || roleKey === "gk" ? 0.42 : 0.14
          : roleKey === "rest" ? 0.32 : 0.05;
      const openingFit = getKickoffOpeningCandidateFit(
        openingProfile,
        {
          receiver,
          roleKey,
          target,
          passDistance,
          forwardGain,
          laneClarity,
          receiverPressure,
        },
        startPoint,
        carrier.team,
        profile
      );
      const score =
        3.55 +
        roleBase +
        openingFit.score +
        laneClarity * 0.62 +
        backwardFit * 0.88 +
        centralFit * 0.22 +
        profile.recycleWindow * 0.46 +
        styleFit -
        receiverPressure * 0.34 -
        Math.abs(passDistance - 24) * 0.014;

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        receiverPressure,
        openingFit,
        score,
      };
    })
    .filter((candidate) => {
      if (candidate.passDistance < 7 || candidate.passDistance > 38) {
        return false;
      }

      if (openingProfile.key === "vertical-second-touch") {
        return candidate.forwardGain <= 10 && candidate.receiverPressure <= 0.72;
      }

      if (openingProfile.key === "wide-release" || openingProfile.key === "weak-side-shift") {
        return candidate.forwardGain <= 6 || candidate.roleKey === "wideBack";
      }

      return candidate.forwardGain <= 2 || candidate.roleKey === "gk";
    })
    .sort((a, b) => b.score - a.score);

  const selected = chooseScoredCandidateWithVariation(candidates, profile, {
    tolerance: 0.9,
    temperature: 0.34,
    carrier,
    startPoint,
  });
  if (!selected) {
    return null;
  }

  return {
    actionType: "pass",
    target: selected.target,
    receiverPlayerId: selected.receiver.id,
    receiverRoleKey: selected.roleKey,
    passDistance: selected.passDistance,
    forwardGain: selected.forwardGain,
    laneClarity: selected.laneClarity,
    receiverPressure: selected.receiverPressure,
    isLineBreak: false,
    isSwitch: false,
    isBoxPass: false,
    score: selected.score,
    firstTouchMode: selected.openingFit.firstTouchMode,
    label: selected.openingFit.label,
    reason: selected.openingFit.reason,
    principleLabels: [selected.openingFit.reason],
  };
}

function buildAutoPilotCornerCandidate(carrier, startPoint, profile) {
  if (state.restartPhase?.type !== "corner" || state.restartPhase.teamId !== carrier.team) {
    return null;
  }

  const teamId = carrier.team;
  const sideY = Number.isFinite(state.restartPhase.sideY) ? state.restartPhase.sideY : startPoint.y;
  const deliverySlots = [
    {
      key: "near-post-corner",
      slot: "nearPost",
      label: "near-post corner",
      styleFit: 0.42 + profile.directness * 0.18 + profile.crossBias * 0.28,
    },
    {
      key: "far-post-corner",
      slot: "farPost",
      label: "far-post corner",
      styleFit: 0.38 + profile.crossBias * 0.42 + profile.risk * 0.12,
    },
    {
      key: "penalty-spot-corner",
      slot: "penaltySpot",
      label: "penalty-spot corner",
      styleFit: 0.52 + profile.shortSupport * 0.12 + profile.deliveryBias * 0.22,
    },
    {
      key: "edge-corner",
      slot: "edge",
      label: "edge-box corner",
      styleFit: 0.28 + profile.shortSupport * 0.36 + (profile.directness < 0.48 ? 0.16 : 0),
    },
  ];

  const options = deliverySlots
    .map((option) => {
      const target = getCornerDeliveryTarget(teamId, sideY, option.slot);
      const runner = chooseCornerDeliveryRunner(teamId, target, carrier.id, option.slot);
      const passDistance = distance(startPoint, target);
      const profileForPass = resolveBallActionProfile("pass", startPoint, target, carrier, null);
      const passTime = passDistance / Math.max(profileForPass.averageSpeed, 0.01);
      const timingFit = runner
        ? clamp(1 - Math.abs(runner.timeToTarget - passTime) / 2.35, 0, 1)
        : 0.35;
      const targetThreat = getPitchThreatProfile(target, teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const runnerScore = runner
        ? runner.score + getAutoPilotRoleStrength(runner.player, "finisher") * 0.24
        : 0;
      const score =
        2.15 +
        option.styleFit +
        laneClarity * 0.42 +
        timingFit * 0.62 +
        targetThreat.box * 0.42 +
        runnerScore * 0.44 -
        Math.abs(passDistance - 23) * 0.008;

      return {
        ...option,
        target,
        runner,
        passDistance,
        laneClarity,
        timingFit,
        score,
      };
    })
    .sort((a, b) => b.score - a.score);

  const selected = options[0];
  if (!selected) {
    return null;
  }

  return {
    actionType: "pass",
    target: selected.target,
    receiverPlayerId: null,
    passDistance: selected.passDistance,
    laneClarity: selected.laneClarity,
    receiverPressure: 0.54,
    supportNearTarget: getTeamSupportCountAroundPoint(
      teamId,
      selected.target,
      new Set([carrier.id, selected.runner?.player.id].filter(Boolean)),
      13
    ),
    isLineBreak: false,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: true,
    isPrinciplePattern: true,
    principleKey: selected.key,
    principleLabel: `Corner routine: ${selected.label}${selected.runner ? ` for ${getPlayerMagnetLabel(selected.runner.player)}` : ""}`,
    principleRunnerPlayerId: selected.runner?.player.id ?? null,
    score: selected.score,
    firstTouchMode: "kill",
    label: selected.label,
    reason: `${profile.styleLabel.toLowerCase()} set-piece delivery attacks ${selected.slot.replace(/([A-Z])/g, " $1").toLowerCase()}`,
  };
}

function buildAutoPilotThrowInCandidate(carrier, startPoint, profile) {
  if (state.restartPhase?.type !== "throwIn" || state.restartPhase.teamId !== carrier.team) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const throwPoint = state.restartPhase.point ?? startPoint;
  const sideSign = getWideSideSign(throwPoint) || (throwPoint.y <= pitch.width / 2 ? -1 : 1);
  const insideY = clamp(throwPoint.y - sideSign * 8, 4, pitch.width - 4);
  const downLinePoint = clampToPitch({
    x: throwPoint.x + getAttackDirectionSign(teamId) * 11,
    y: clamp(throwPoint.y - sideSign * 2.6, 2.8, pitch.width - 2.8),
  }, 2.2);

  const receiverOptions = state.players
    .filter((receiver) => receiver.team === teamId && receiver.id !== carrier.id && !isGoalkeeper(receiver))
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const sideFit = clamp(1 - Math.abs(target.y - insideY) / 18, 0, 1);
      const roleFit =
        roleKey === "wideBack"
          ? 0.38
          : roleKey === "wideForward"
            ? 0.34
            : roleKey === "connector" || roleKey === "pivot"
              ? 0.28
              : roleKey === "striker"
                ? 0.16
                : 0.08;
      const score =
        1.7 +
        sideFit * 0.52 +
        roleFit +
        laneClarity * 0.74 +
        getAutoPilotRoleStrength(receiver, "receiver") * 0.36 +
        profile.shortSupport * 0.28 +
        clamp(forwardGain / 14, -0.25, 0.42) -
        receiverPressure * 0.58 -
        Math.abs(passDistance - 9.5) * 0.035;

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        receiverPressure,
        score,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 3.5 &&
      candidate.passDistance <= 18.5 &&
      candidate.receiverPressure <= 0.88 &&
      candidate.laneClarity >= 0.22
    ))
    .sort((a, b) => b.score - a.score);

  const bestReceiver = receiverOptions[0];
  if (bestReceiver) {
    return {
      actionType: "pass",
      target: bestReceiver.target,
      receiverPlayerId: bestReceiver.receiver.id,
      receiverRoleKey: bestReceiver.roleKey,
      passDistance: bestReceiver.passDistance,
      forwardGain: bestReceiver.forwardGain,
      laneClarity: bestReceiver.laneClarity,
      receiverPressure: bestReceiver.receiverPressure,
      supportNearTarget: getTeamSupportCountAroundPoint(teamId, bestReceiver.target, new Set([carrier.id, bestReceiver.receiver.id]), 10),
      isLineBreak: bestReceiver.forwardGain >= 6,
      isSwitch: false,
      isSidewaysPass: Math.abs(bestReceiver.forwardGain) < 4,
      isBoxPass: false,
      isPrinciplePattern: true,
      principleKey: "throw-in-support",
      principleLabel: `Throw-in: ${getPlayerMagnetLabel(bestReceiver.receiver)} shows inside the touchline`,
      score: bestReceiver.score,
      firstTouchMode: profile.directness >= 0.62 ? "forward" : "inside",
      label: "throw-in support",
      reason: "restart through the nearest safe support angle",
    };
  }

  return {
    actionType: "pass",
    target: downLinePoint,
    receiverPlayerId: null,
    passDistance: distance(startPoint, downLinePoint),
    laneClarity: computePassLaneClarity(carrier, downLinePoint),
    receiverPressure: 0.52,
    supportNearTarget: getTeamSupportCountAroundPoint(teamId, downLinePoint, new Set([carrier.id]), 12),
    isLineBreak: true,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: false,
    isPrinciplePattern: true,
    principleKey: "throw-in-down-line",
    principleLabel: "Throw-in: play down the line when inside support is blocked",
    score: 1.65 + profile.directness * 0.42,
    firstTouchMode: "forward",
    label: "throw-in down line",
    reason: "blocked throw-in support releases the ball down the touchline",
  };
}

function buildAutoPilotPenaltyCandidate(carrier, startPoint, profile) {
  if (state.restartPhase?.type !== "penalty" || state.restartPhase.teamId !== carrier.team) {
    return null;
  }

  const teamId = carrier.team;
  const target = getAutoPilotShotTarget(teamId, carrier);
  const finisherStrength = getAutoPilotRoleStrength(carrier, "finisher");

  return {
    actionType: "shot",
    target,
    receiverPlayerId: null,
    score: 6.8 + finisherStrength * 0.42 + profile.shootBias * 0.18,
    goalDistance: distance(startPoint, getOpponentGoalCenter(teamId)),
    laneClarity: 0.98,
    blockRisk: 0,
    angleQuality: 0.9,
    goalkeeperOpenness: getGoalkeeperTargetOpenness(teamId, target),
    shotQuality: clamp(0.72 + finisherStrength * 0.18, 0.72, 0.94),
    insideBox: true,
    mustShoot: true,
    isPrinciplePattern: true,
    principleKey: "penalty-execution",
    principleLabel: `Penalty: ${getPlayerMagnetLabel(carrier)} isolates the finish`,
    label: "penalty",
    reason: "penalty execution",
  };
}

function buildAutoPilotFreeKickCandidate(carrier, startPoint, profile) {
  if (state.restartPhase?.type !== "freeKick" || state.restartPhase.teamId !== carrier.team) {
    return null;
  }

  const teamId = carrier.team;
  const freeKickPoint = state.restartPhase.point ?? startPoint;
  const goalDistance = distance(startPoint, getOpponentGoalCenter(teamId));
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const centrality = 1 - Math.abs(startPoint.y - pitch.width / 2) / (pitch.width / 2);
  const angleQuality = getShotAngleQuality(startPoint, teamId);
  const finisherStrength = getAutoPilotRoleStrength(carrier, "finisher");
  const creatorStrength = getAutoPilotRoleStrength(carrier, "creator");
  const directShotViable =
    goalDistance <= 30 &&
    attackingDepth >= 70 &&
    centrality >= 0.2 &&
    angleQuality >= 0.12;

  const candidates = [];

  if (directShotViable) {
    const target = getAutoPilotShotTarget(teamId, carrier);
    const shotWindow = getShotWindowProfile(carrier, startPoint, target);
    candidates.push({
      actionType: "shot",
      target,
      receiverPlayerId: null,
      score:
        2.35 +
        profile.shootBias * 0.9 +
        finisherStrength * 0.72 +
        shotWindow.quality * 0.64 +
        angleQuality * 0.38 +
        centrality * 0.22 -
        Math.max(goalDistance - 23, 0) * 0.05,
      goalDistance,
      laneClarity: shotWindow.laneClarity,
      blockRisk: shotWindow.blockRisk,
      angleQuality,
      goalkeeperOpenness: shotWindow.goalkeeperOpenness,
      shotQuality: shotWindow.quality,
      insideBox: false,
      mustShoot: shotWindow.quality >= 0.58 || goalDistance <= 23,
      isPrinciplePattern: true,
      principleKey: "direct-free-kick",
      principleLabel: `Free-kick: ${getPlayerMagnetLabel(carrier)} can shoot directly`,
      label: "direct free-kick",
      reason: "direct free-kick shooting window",
    });
  }

  if (attackingDepth >= 56 && goalDistance <= 48) {
    ["penaltySpot", "farPost", "nearPost", "edge"].forEach((slot) => {
      const target = getFreeKickDeliveryTarget(teamId, freeKickPoint, slot);
      const runner = chooseCornerDeliveryRunner(teamId, target, carrier.id, slot);
      const passDistance = distance(startPoint, target);
      const profileForPass = resolveBallActionProfile("pass", startPoint, target, carrier, null);
      const passTime = passDistance / Math.max(profileForPass.averageSpeed, 0.01);
      const timingFit = runner
        ? clamp(1 - Math.abs(runner.timeToTarget - passTime) / 2.45, 0, 1)
        : 0.34;
      const targetThreat = getPitchThreatProfile(target, teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const slotFit =
        slot === "farPost"
          ? profile.crossBias * 0.36 + profile.risk * 0.12
          : slot === "edge"
            ? profile.shortSupport * 0.32
            : profile.deliveryBias * 0.34 + profile.directness * 0.12;
      const score =
        1.92 +
        slotFit +
        creatorStrength * 0.34 +
        laneClarity * 0.36 +
        timingFit * 0.58 +
        targetThreat.box * 0.4 +
        (runner ? runner.score * 0.34 : 0) -
        Math.abs(passDistance - 24) * 0.01;

      candidates.push({
        actionType: "pass",
        target,
        receiverPlayerId: null,
        passDistance,
        laneClarity,
        receiverPressure: 0.46,
        supportNearTarget: getTeamSupportCountAroundPoint(
          teamId,
          target,
          new Set([carrier.id, runner?.player.id].filter(Boolean)),
          13
        ),
        isLineBreak: false,
        isSwitch: false,
        isSidewaysPass: false,
        isBoxPass: true,
        isPrinciplePattern: true,
        principleKey: `free-kick-${slot}`,
        principleLabel: `Free-kick delivery: ${slot.replace(/([A-Z])/g, " $1").toLowerCase()}${runner ? ` for ${getPlayerMagnetLabel(runner.player)}` : ""}`,
        principleRunnerPlayerId: runner?.player.id ?? null,
        score,
        firstTouchMode: "kill",
        label: slot === "edge" ? "free-kick second ball" : "free-kick delivery",
        reason: `${profile.styleLabel.toLowerCase()} free-kick delivery attacks ${slot.replace(/([A-Z])/g, " $1").toLowerCase()}`,
      });
    });
  }

  const shortReceiver = chooseFreeKickShortReceiver(teamId, carrier, startPoint, profile);
  if (shortReceiver) {
    candidates.push({
      actionType: "pass",
      target: shortReceiver.target,
      receiverPlayerId: shortReceiver.receiver.id,
      receiverRoleKey: shortReceiver.roleKey,
      passDistance: shortReceiver.passDistance,
      forwardGain: shortReceiver.forwardGain,
      laneClarity: shortReceiver.laneClarity,
      receiverPressure: shortReceiver.receiverPressure,
      isLineBreak: false,
      isSwitch: false,
      isSidewaysPass: Math.abs(shortReceiver.forwardGain) < 4,
      isBoxPass: false,
      isPrinciplePattern: true,
      principleKey: "short-free-kick",
      principleLabel: `Free-kick restart: ${getPlayerMagnetLabel(shortReceiver.receiver)} receives short`,
      score: shortReceiver.score + (profile.shortSupport >= 0.72 || goalDistance > 42 ? 0.52 : 0),
      firstTouchMode: profile.firstTouchForwardBias >= 0.6 ? "forward" : "inside",
      label: "short free-kick",
      reason: "short free-kick to restart possession",
    });
  }

  if (!candidates.length) {
    return null;
  }

  candidates.sort((a, b) => b.score - a.score);
  return candidates[0];
}

function buildAutoPilotRegainReleaseCandidate(carrier, startPoint, profile) {
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  if (!regain.active || regain.freshness < 0.12) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const directAllowed =
    regain.directStyle ||
    profile.directness >= 0.62 ||
    (regain.forwardOpenSpace >= 0.66 && regain.pressure <= 0.46);
  const shouldSecureFirst =
    regain.pressure >= 0.5 ||
    (!directAllowed && profile.shortSupport >= 0.54) ||
    (regain.localSupport >= 2 && profile.directness < 0.58);

  const secureCandidates = state.players
    .filter((receiver) => {
      if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      return roleKey === "pivot" || roleKey === "connector" || roleKey === "wideBack" || roleKey === "rest";
    })
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const roleFit =
        roleKey === "pivot"
          ? 0.42
          : roleKey === "connector"
            ? 0.36
            : roleKey === "wideBack"
              ? 0.22
              : 0.14;
      const score =
        1.72 +
        laneClarity * 1.08 +
        getAutoPilotRoleStrength(receiver, "receiver") * 0.46 +
        regain.secureIntent * regain.freshness * 0.74 +
        roleFit +
        (forwardGain >= -4 && forwardGain <= 7 ? 0.22 : 0) -
        receiverPressure * 0.54 -
        Math.abs(passDistance - 13) * 0.025 -
        (forwardGain < -8 && regain.pressure <= 0.38 ? 0.32 : 0);

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        receiverPressure,
        score,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 5 &&
      candidate.passDistance <= 24 &&
      candidate.forwardGain >= -11 &&
      candidate.laneClarity >= 0.34 &&
      candidate.receiverPressure <= 0.82 &&
      candidate.score >= 1.55
    ))
    .sort((a, b) => b.score - a.score);

  const directCandidates = directAllowed
    ? state.players
        .filter((runner) => {
          if (runner.team !== teamId || runner.id === carrier.id || isGoalkeeper(runner)) {
            return false;
          }

          const roleKey = getOffensiveRoleKey(runner, formation);
          return ["striker", "wideForward", "secondStriker", "connector"].includes(roleKey) &&
            !isPassReceiverOffside(runner, startPoint);
        })
        .map((runner) => {
          const roleKey = getOffensiveRoleKey(runner, formation);
          const sideSign = getWideSideSign(runner) || getWideSideSign(startPoint) || 1;
          const target = getHighValueAttackTarget(
            teamId,
            startPoint,
            roleKey === "wideForward" ? "halfSpaceRun" : "goldenRun",
            sideSign
          );
          const passDistance = distance(startPoint, target);
          const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
          const laneClarity = computePassLaneClarity(carrier, target);
          const targetThreat = getPitchThreatProfile(target, teamId);
          const runnerDistance = distance(runner.position, target);
          const runnerTime = computeTimeToCoverDistance(runner, runnerDistance, target);
          const passTime = passDistance / Math.max(resolveBallActionProfile("pass", startPoint, target, carrier, null).averageSpeed, 0.01);
          const timingFit = clamp(1 - Math.abs(runnerTime - passTime) / 1.45, 0, 1);
          const supportNearTarget = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, runner.id]), 17);
          const score =
            1.48 +
            regain.counterIntent * regain.freshness * 0.96 +
            regain.forwardOpenSpace * 0.4 +
            targetThreat.value * 0.88 +
            laneClarity * 0.82 +
            timingFit * 0.46 +
            getAutoPilotRoleStrength(runner, "runner") * 0.42 +
            clamp(forwardGain / 24, 0, 0.8) +
            clamp(supportNearTarget, 0, 3) * 0.08 -
            regain.pressure * 0.22 -
            (passDistance > 32 && profile.routeOneBias < 0.35 ? 0.36 : 0);

          return {
            runner,
            roleKey,
            target,
            passDistance,
            forwardGain,
            laneClarity,
            targetThreat,
            supportNearTarget,
            score,
            timingFit,
          };
        })
        .filter((candidate) => (
          candidate.passDistance >= 10 &&
          candidate.passDistance <= 36 &&
          candidate.forwardGain >= 6 &&
          candidate.laneClarity >= 0.38 &&
          candidate.timingFit >= 0.12 &&
          candidate.targetThreat.value >= 0.34 &&
          candidate.score >= 1.7
        ))
        .sort((a, b) => b.score - a.score)
    : [];

  const secure = secureCandidates[0] ?? null;
  const direct = directCandidates[0] ?? null;
  const selectedDirect =
    direct &&
    (!shouldSecureFirst || direct.score >= (secure?.score ?? 0) + 0.28 || regain.forwardOpenSpace >= 0.76);

  if (selectedDirect) {
    return {
      actionType: "pass",
      target: direct.target,
      receiverPlayerId: null,
      receiverRoleKey: direct.roleKey,
      passDistance: direct.passDistance,
      forwardGain: direct.forwardGain,
      laneClarity: direct.laneClarity,
      receiverPressure: 0.42,
      supportNearTarget: direct.supportNearTarget,
      isLineBreak: true,
      isSwitch: false,
      isSidewaysPass: false,
      isBoxPass: direct.targetThreat.box >= 0.28,
      isPrinciplePattern: true,
      principleKey: "regain-forward-release",
      principleLabel: `Regain release: ${getPlayerMagnetLabel(direct.runner)} attacks open transition space`,
      principleRunnerPlayerId: direct.runner.id,
      score: direct.score,
      firstTouchMode: "forward",
      label: "regain release",
      reason: "fresh regain with open forward space",
    };
  }

  if (!secure) {
    return null;
  }

  return {
    actionType: "pass",
    target: secure.target,
    receiverPlayerId: secure.receiver.id,
    receiverRoleKey: secure.roleKey,
    passDistance: secure.passDistance,
    forwardGain: secure.forwardGain,
    laneClarity: secure.laneClarity,
    receiverPressure: secure.receiverPressure,
    isLineBreak: false,
    isSwitch: false,
    isSidewaysPass: Math.abs(secure.forwardGain) < 4 && Math.abs(secure.target.y - startPoint.y) >= 6.5,
    isBoxPass: false,
    isPrinciplePattern: true,
    principleKey: "secure-regain",
    principleLabel: `Secure first pass: ${getPlayerMagnetLabel(secure.receiver)} supports the regain`,
    score: secure.score + (shouldSecureFirst ? 0.34 : 0),
    firstTouchMode: secure.forwardGain >= 2 && profile.firstTouchForwardBias >= 0.62 ? "forward" : "inside",
    label: "secure regain",
    reason: "fresh regain needs a stable first pass before the next attacking action",
  };
}

function getPressedRegainExitVector(carrier, startPoint) {
  if (!carrier || !startPoint) {
    return { x: getAttackDirectionSign(carrier?.team), y: 0 };
  }

  let pressureX = 0;
  let pressureY = 0;
  let pressureWeight = 0;
  state.players.forEach((player) => {
    if (player.team === carrier.team) {
      return;
    }

    const gap = distance(player.position, startPoint);
    if (gap > 10.5) {
      return;
    }

    const weight = clamp(1 - gap / 10.5, 0, 1) ** 1.25;
    pressureX += (player.position.x - startPoint.x) * weight;
    pressureY += (player.position.y - startPoint.y) * weight;
    pressureWeight += weight;
  });

  const attackSign = getAttackDirectionSign(carrier.team);
  const touchlineSide =
    Math.sign(startPoint.y - pitch.width / 2) ||
    (startPoint.y <= pitch.width / 2 ? -1 : 1);

  if (pressureWeight <= 0.01) {
    return normalize(
      startPoint,
      {
        x: startPoint.x + attackSign * 8,
        y: clamp(startPoint.y + touchlineSide * 6, 3, pitch.width - 3),
      }
    );
  }

  const awayFromPressure = normalize(
    {
      x: startPoint.x + pressureX / pressureWeight,
      y: startPoint.y + pressureY / pressureWeight,
    },
    startPoint
  );
  const forwardVector = { x: attackSign, y: 0 };
  const insideTarget = {
    x: startPoint.x + attackSign * 5,
    y: pitch.width / 2,
  };
  const insideVector = normalize(startPoint, insideTarget);
  const combined = {
    x: awayFromPressure.x * 0.68 + forwardVector.x * 0.2 + insideVector.x * 0.12,
    y: awayFromPressure.y * 0.68 + insideVector.y * 0.18 + touchlineSide * 0.08,
  };
  const length = Math.hypot(combined.x, combined.y) || 1;

  return {
    x: combined.x / length,
    y: combined.y / length,
  };
}

function buildAutoPilotPressedRegainExitCandidate(carrier, startPoint, profile) {
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  if (
    !carrier ||
    !startPoint ||
    !regain.active ||
    regain.freshness < 0.28 ||
    regain.pressure < 0.5 ||
    isInsideOwnBox(startPoint, carrier.team)
  ) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const attackSign = getAttackDirectionSign(teamId);
  const exitVector = getPressedRegainExitVector(carrier, startPoint);
  const directStyle = isTransitionAttackStyle(profile.styleKey);
  const candidates = [];

  state.players
    .filter((receiver) => {
      if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      return roleKey === "pivot" || roleKey === "connector" || roleKey === "wideBack" || roleKey === "rest";
    })
    .forEach((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * attackSign;
      const passVector = normalize(startPoint, target);
      const escapeFit = clamp((passVector.x * exitVector.x + passVector.y * exitVector.y + 1) / 2, 0, 1);
      const lateralEscape = Math.abs(target.y - startPoint.y);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const targetPressure = getOpponentPressureAtPoint(teamId, target, 9);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const roleFit =
        roleKey === "pivot"
          ? 0.38
          : roleKey === "connector"
            ? 0.34
            : roleKey === "wideBack"
              ? 0.24
              : 0.14;
      const distanceFit = clamp(1 - Math.abs(passDistance - 12.5) / 13, 0, 1);
      const score =
        2.02 +
        regain.freshness * 0.34 +
        regain.secureIntent * 0.46 +
        laneClarity * 0.98 +
        escapeFit * 0.62 +
        distanceFit * 0.26 +
        roleFit +
        getAutoPilotRoleStrength(receiver, "receiver") * 0.32 +
        clamp(lateralEscape / 14, 0, 0.24) -
        receiverPressure * 0.52 -
        targetPressure * 0.38 -
        (forwardGain < -8 && directStyle ? 0.34 : 0) -
        (passDistance > 22 ? 0.2 : 0);

      if (
        passDistance >= 5.5 &&
        passDistance <= 24 &&
        forwardGain >= -12 &&
        forwardGain <= 13 &&
        laneClarity >= 0.34 &&
        receiverPressure <= 0.82 &&
        targetPressure <= 0.78 &&
        escapeFit >= 0.36 &&
        score >= 1.68
      ) {
        candidates.push({
          actionType: "pass",
          target,
          receiverPlayerId: receiver.id,
          receiverRoleKey: roleKey,
          passDistance,
          forwardGain,
          laneClarity,
          receiverPressure,
          supportNearTarget: getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, receiver.id]), 12),
          isLineBreak: false,
          isSwitch: false,
          isSidewaysPass: Math.abs(forwardGain) < 4 && lateralEscape >= 6,
          isBoxPass: false,
          isPrinciplePattern: true,
          principleKey: "pressed-regain-exit-pass",
          principleLabel: `Pressed regain exit: ${getPlayerMagnetLabel(receiver)} opens the first safe angle`,
          score,
          firstTouchMode: forwardGain >= 2 && profile.firstTouchForwardBias >= 0.58 ? "forward" : "inside",
          label: "pressed regain exit",
          reason: "fresh ball win under pressure; first pass exits the counter-press before building",
        });
      }
    });

  const carryDistance = clamp(4.8 + regain.pressure * 4.2 + profile.carryBias * 1.8, 4.2, 10.2);
  const carryTarget = clampToPitch({
    x: startPoint.x + exitVector.x * carryDistance + attackSign * clamp(profile.directness * 2.2, 0.4, 2.4),
    y: startPoint.y + exitVector.y * carryDistance,
  }, 2);
  const carryForwardGain = (carryTarget.x - startPoint.x) * attackSign;
  const carryTargetPressure = getOpponentPressureAtPoint(teamId, carryTarget, 8);
  const carryOpenSpace = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, carryTarget));
  const dribbleStrength = getAutoPilotRoleStrength(carrier, "dribbler");
  const carryScore =
    1.82 +
    regain.freshness * 0.28 +
    regain.pressure * 0.32 +
    carryOpenSpace * 0.7 +
    dribbleStrength * 0.42 +
    profile.carryBias * 0.28 +
    clamp(carryForwardGain / 10, -0.08, 0.28) -
    carryTargetPressure * 0.56;

  if (carryOpenSpace >= 0.42 && carryTargetPressure <= 0.68 && carryScore >= 1.62) {
    candidates.push({
      actionType: "dribble",
      target: carryTarget,
      receiverPlayerId: null,
      score: carryScore,
      isOpenGrassCarry: false,
      isRunwayCarry: false,
      isPrinciplePattern: true,
      principleKey: "pressed-regain-carry-out",
      principleLabel: `Pressed regain exit: ${getPlayerMagnetLabel(carrier)} carries first touch away from pressure`,
      principleLabels: ["Exit counter-press with first touch"],
      label: "pressed regain carry",
      reason: "fresh ball win under pressure; first touch carries out of the counter-press",
    });
  }

  const preferredPass = candidates
    .filter((candidate) => candidate.actionType === "pass")
    .sort((a, b) => b.score - a.score)[0] ?? null;

  return chooseScoredCandidateWithVariation(candidates, profile, {
    tolerance: 0.3,
    temperature: 0.12,
    preferredCandidate: preferredPass,
    carrier,
    startPoint,
  });
}

function buildAutoPilotDangerZoneEscapeCandidate(carrier, startPoint, profile) {
  if (!carrier || !startPoint || isGoalkeeper(carrier)) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const regain = getAutoPilotRegainContext(carrier, startPoint, profile);
  const ownGoalDistance = getDistanceFromOwnGoal(teamId, startPoint);
  const insideOwnBox = isInsideOwnBox(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const dangerActive =
    insideOwnBox ||
    ownGoalDistance <= 22 ||
    (ownGoalDistance <= 31 && pressure >= 0.46) ||
    (regain.active && regain.freshness >= 0.18 && ownGoalDistance <= 36);

  if (!dangerActive) {
    return null;
  }

  const attackSign = getAttackDirectionSign(teamId);
  const sideSign = getWideSideSign(startPoint) || (startPoint.y <= pitch.width / 2 ? -1 : 1);
  const directness = profile.directness ?? 0.5;
  const shortSupport = profile.shortSupport ?? 0.5;
  const boxStress = insideOwnBox ? 1 : clamp((36 - ownGoalDistance) / 22, 0, 1);
  const clearanceDistance = clamp(
    24 + pressure * 12 + directness * 14 + boxStress * 10,
    24,
    58
  );
  const clearanceTarget = clampToPitch(
    {
      x: startPoint.x + attackSign * clearanceDistance,
      y: pitch.width / 2 + sideSign * clamp(21 + pressure * 8 + boxStress * 4, 20, 31),
    },
    2
  );
  const clearancePassDistance = distance(startPoint, clearanceTarget);
  const clearanceForwardGain = (clearanceTarget.x - startPoint.x) * attackSign;
  const clearanceLaneClarity = computePassLaneClarity(carrier, clearanceTarget);
  const clearanceScore =
    2.12 +
    boxStress * 0.68 +
    pressure * 0.5 +
    directness * 0.36 +
    clearanceLaneClarity * 0.58 -
    shortSupport * 0.14;
  const clearanceCandidate = {
    actionType: "pass",
    target: clearanceTarget,
    receiverPlayerId: null,
    receiverRoleKey: null,
    passDistance: clearancePassDistance,
    forwardGain: clearanceForwardGain,
    laneClarity: clearanceLaneClarity,
    receiverPressure: 0.38,
    supportNearTarget: getTeamSupportCountAroundPoint(teamId, clearanceTarget, new Set([carrier.id]), 18),
    isLineBreak: clearanceForwardGain >= 18,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: false,
    isPrinciplePattern: true,
    principleKey: "danger-zone-clearance",
    principleLabel: "Danger-zone escape: clear first contact away from goal",
    score: clearanceScore,
    firstTouchMode: "forward",
    label: "danger clearance",
    reason: "ball recovered near own goal; first priority is to move danger away from the box",
  };

  const outletCandidates = state.players
    .filter((receiver) => {
      if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      return roleKey === "wideBack" || roleKey === "pivot" || roleKey === "connector" || roleKey === "rest";
    })
    .map((receiver) => {
      const target = getPlayerBallControlPoint(receiver);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * attackSign;
      const lateralEscape = Math.abs(target.y - startPoint.y);
      const laneClarity = computePassLaneClarity(carrier, target);
      const receiverPressure = getPlayerPressureLoad(receiver, target);
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const receiverStrength = getAutoPilotRoleStrength(receiver, "receiver");
      const roleFit =
        roleKey === "wideBack"
          ? 0.38
          : roleKey === "pivot"
            ? 0.3
            : roleKey === "connector"
              ? 0.2
              : 0.12;
      const score =
        1.88 +
        laneClarity * 1.08 +
        receiverStrength * 0.44 +
        roleFit +
        shortSupport * 0.36 +
        clamp(lateralEscape / 18, 0, 0.26) +
        (forwardGain >= -3 ? 0.14 : 0) -
        receiverPressure * 0.66 -
        pressure * 0.12 -
        Math.abs(passDistance - 13) * 0.025 -
        (forwardGain < -8 ? 0.36 : 0);

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        receiverPressure,
        score,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 5 &&
      candidate.passDistance <= 25 &&
      candidate.forwardGain >= -10 &&
      candidate.laneClarity >= 0.3 &&
      candidate.receiverPressure <= 0.82 &&
      candidate.score >= 1.48
    ))
    .sort((a, b) => b.score - a.score);

  const outlet = outletCandidates[0] ?? null;
  const outletCandidate = outlet
    ? {
        actionType: "pass",
        target: outlet.target,
        receiverPlayerId: outlet.receiver.id,
        receiverRoleKey: outlet.roleKey,
        passDistance: outlet.passDistance,
        forwardGain: outlet.forwardGain,
        laneClarity: outlet.laneClarity,
        receiverPressure: outlet.receiverPressure,
        supportNearTarget: getTeamSupportCountAroundPoint(teamId, outlet.target, new Set([carrier.id, outlet.receiver.id]), 13),
        isLineBreak: false,
        isSwitch: false,
        isSidewaysPass: Math.abs(outlet.forwardGain) < 4 && Math.abs(outlet.target.y - startPoint.y) >= 6,
        isBoxPass: false,
        isPrinciplePattern: true,
        principleKey: "danger-zone-wide-outlet",
        principleLabel: `Danger-zone escape: ${getPlayerMagnetLabel(outlet.receiver)} is the first safe outlet`,
        score: outlet.score + (boxStress >= 0.58 && pressure < 0.64 ? 0.2 : 0),
        firstTouchMode: outlet.forwardGain >= 2 ? "forward" : "inside",
        label: "danger outlet",
        reason: "ball recovered near own goal; first pass finds a safe support outside the pressure",
      }
    : null;

  if (insideOwnBox && pressure >= 0.62) {
    return clearanceCandidate;
  }

  return chooseScoredCandidateWithVariation(
    [clearanceCandidate, outletCandidate],
    profile,
    {
      tolerance: 0.24,
      temperature: 0.12,
      preferredCandidate: outletCandidate && outletCandidate.score >= clearanceCandidate.score - 0.12
        ? outletCandidate
        : clearanceCandidate,
      carrier,
      startPoint,
    }
  );
}

function buildAutoPilotBoxDeliveryCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const startsWide = isWideChannel(startPoint);
  if (!startsWide || attackingDepth < 63) {
    return null;
  }

  const isCutback = isBylineZone(startPoint, teamId);
  const target = getAutoPilotBoxTarget(teamId, carrier, isCutback ? "cutback" : "cross");
  const creatorStrength = Math.max(
    getAutoPilotRoleStrength(carrier, "crosser"),
    getAutoPilotRoleStrength(carrier, "creator")
  );
  const runners = state.players.filter((player) => {
    if (player.team !== teamId || player.id === carrier.id) {
      return false;
    }

    const roleKey = getOffensiveRoleKey(player, teams[teamId]?.formation);
    return roleKey === "striker" || roleKey === "secondStriker" || roleKey === "wideForward" || roleKey === "connector";
  });
  const runnerThreat = runners.reduce(
    (best, player) => Math.max(best, getAutoPilotRoleStrength(player, "runner") + getAutoPilotRoleStrength(player, "finisher") * 0.55),
    0.3
  );
  const boxSupportCount = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id]), 20);
  const laneClarity = computePassLaneClarity(carrier, target);
  const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
  const hopefulDelivery =
    !isCutback &&
    boxSupportCount <= 1 &&
    profile.crossBias < 0.74 &&
    laneClarity < 0.66;
  const score =
    1.35 +
    creatorStrength * 1.1 +
    runnerThreat * 0.82 +
    laneClarity * 0.6 +
    actionSpace.value * 0.36 +
    profile.crossBias * 0.74 +
    profile.deliveryBias * 0.36 +
    getPlayerTendency(carrier, "earlyCross") * 0.42 +
    clamp(boxSupportCount, 0, 4) * 0.16 -
    (boxSupportCount <= 1 && !isCutback ? 0.46 : 0) +
    (isCutback ? 0.36 : 0) +
    (profile.phaseKey === "finalThird" ? 0.32 : 0) -
    (hopefulDelivery ? 0.62 : 0);

  if (score < (isCutback ? 1.48 : 1.72) || (hopefulDelivery && score < 2.05)) {
    return null;
  }

  return {
    actionType: "pass",
    target,
    receiverPlayerId: null,
    score,
    label: isCutback ? "cutback" : "cross",
    reason: isCutback ? "cutback from wide final-third position" : `${profile.styleLabel.toLowerCase()} delivery into the box`,
  };
}

function getFinalThirdCombinationVariants(teamId, carrier, startPoint, profile) {
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const startsWide = isWideChannel(startPoint);
  const byline = isBylineZone(startPoint, teamId);
  const sideSign = getWideSideSign(startPoint) || 1;
  const cutbackBias = profile.cutbackBias ?? clamp(0.24 + profile.shortSupport * 0.28 + profile.overlapBias * 0.22, 0.22, 0.82);
  const variants = [];

  if (startsWide && attackingDepth >= 62) {
    variants.push({
      key: "cutback",
      label: "cutback",
      target: getAutoPilotBoxTarget(teamId, carrier, "cutback"),
      roles: ["connector", "striker", "secondStriker", "wideForward"],
      styleFit: 0.48 + cutbackBias * 0.3 + (byline ? 0.36 : 0),
      maxDistance: 30,
      timingWindow: 1.55,
    });

    variants.push({
      key: "far-post-cross",
      label: "cross",
      target: getAutoPilotBoxTarget(teamId, carrier, "far-post"),
      roles: ["striker", "wideForward", "secondStriker"],
      styleFit: 0.28 + profile.crossBias * 0.44,
      maxDistance: 38,
      timingWindow: 1.85,
    });
  }

  if (attackingDepth >= 58) {
    variants.push({
      key: "golden-zone-slip",
      label: "final pass",
      target: getHighValueAttackTarget(teamId, startPoint, "goldenRun", sideSign),
      roles: ["striker", "secondStriker", "wideForward"],
      styleFit: 0.28 + profile.lineBreakBias * 0.34 + profile.shootBias * 0.12,
      maxDistance: 27,
      timingWindow: 1.45,
    });

    variants.push({
      key: "edge-cutback",
      label: "cutback",
      target: getHighValueAttackTarget(teamId, startPoint, "reboundEdge", sideSign),
      roles: ["connector", "pivot", "wideForward"],
      styleFit: 0.22 + cutbackBias * 0.28 + profile.shortSupport * 0.16,
      maxDistance: 24,
      timingWindow: 1.5,
    });
  }

  return variants;
}

function buildAutoPilotFinalThirdCombinationCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const ownerPressure = getPlayerPressureLoad(carrier, startPoint);
  if (attackingDepth < 58 || ownerPressure > 0.86) {
    return null;
  }

  const formation = teams[teamId]?.formation;
  const creatorQuality = Math.max(
    getAutoPilotRoleStrength(carrier, "creator"),
    getAutoPilotRoleStrength(carrier, "crosser")
  );
  const variants = getFinalThirdCombinationVariants(teamId, carrier, startPoint, profile);
  const candidates = [];

  variants.forEach((variant) => {
    state.players.forEach((runner) => {
      if (runner.team !== teamId || runner.id === carrier.id || isGoalkeeper(runner)) {
        return;
      }

      const roleKey = getOffensiveRoleKey(runner, formation);
      if (!variant.roles.includes(roleKey) || isPassReceiverOffside(runner, startPoint)) {
        return;
      }

      const runnerBlend = roleKey === "connector" || roleKey === "pivot" ? 0.14 : 0.08;
      const target = clampToPitch({
        x: lerp(variant.target.x, runner.position.x, runnerBlend),
        y: lerp(variant.target.y, runner.position.y, runnerBlend),
      }, 2);
      const passDistance = distance(startPoint, target);
      if (passDistance < 5 || passDistance > variant.maxDistance) {
        return;
      }

      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
      const runnerDistance = distance(runner.position, target);
      const runnerTime = computeTimeToCoverDistance(runner, runnerDistance, target);
      const passTime = passDistance / Math.max(resolveBallActionProfile("pass", startPoint, target, carrier, null).averageSpeed, 0.01);
      const timingFit = clamp(1 - Math.abs(runnerTime - passTime) / variant.timingWindow, 0, 1);
      const boxThreat = actionSpace.targetThreat.box;
      const cutbackThreat = variant.key.includes("cutback") ? actionSpace.targetThreat.centrality * 0.18 : 0;
      const runnerQuality =
        getAutoPilotRoleStrength(runner, "finisher") * 0.42 +
        getAutoPilotRoleStrength(runner, "runner") * 0.28 +
        getAutoPilotRoleStrength(runner, "receiver") * 0.18 +
        getPlayerTendency(runner, "boxRun") * 0.18;
      const supportCount = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, runner.id]), 18);
      const hopefulCrossPenalty =
        variant.key === "far-post-cross" && supportCount <= 1
          ? 0.36
          : 0;
      const score =
        1.24 +
        creatorQuality * 0.72 +
        runnerQuality * 0.82 +
        laneClarity * 0.78 +
        actionSpace.value * 1.04 +
        boxThreat * 0.46 +
        cutbackThreat +
        timingFit * 0.56 +
        variant.styleFit +
        clamp(supportCount, 0, 4) * 0.1 +
        (forwardGain >= -2 ? 0.16 : -0.1) -
        ownerPressure * 0.32 -
        actionSpace.targetPressure * 0.46 -
        hopefulCrossPenalty -
        (passDistance > 28 && variant.key !== "far-post-cross" ? 0.18 : 0);

      candidates.push({
        variant,
        runner,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        actionSpace,
        supportCount,
        score,
        timingFit,
      });
    });
  });

  const selected = candidates
    .filter((candidate) => (
      candidate.laneClarity >= 0.34 &&
      candidate.timingFit >= 0.12 &&
      candidate.actionSpace.value >= 0.32 &&
      candidate.score >= 1.7
    ))
    .sort((a, b) => b.score - a.score)[0];

  if (!selected) {
    return null;
  }

  const isCutback = selected.variant.key.includes("cutback");
  return {
    actionType: "pass",
    target: selected.target,
    receiverPlayerId: null,
    receiverRoleKey: selected.roleKey,
    passDistance: selected.passDistance,
    forwardGain: selected.forwardGain,
    laneClarity: selected.laneClarity,
    receiverPressure: selected.actionSpace.targetPressure,
    supportNearTarget: selected.supportCount,
    isLineBreak: selected.forwardGain >= 4 || selected.actionSpace.lineBreakCount >= 1,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: true,
    isPrinciplePattern: true,
    principleKey: `final-third-${selected.variant.key}`,
    principleLabel: `${isCutback ? "Cutback" : "Final-third delivery"}: ${getPlayerMagnetLabel(selected.runner)} attacks the chance`,
    principleRunnerPlayerId: selected.runner.id,
    score: selected.score,
    firstTouchMode: "forward",
    label: selected.variant.label,
    reason: isCutback
      ? "final-third cutback to a runner arriving in the highest-value zone"
      : "final-third chance creation before the defence can reset",
  };
}

function buildAutoPilotWideOverlapCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const carrierRoleKey = getOffensiveRoleKey(carrier, teams[teamId]?.formation);
  const attackingDepth = getAttackingDepth(startPoint, teamId);
  const sideSign = getWideSideSign(startPoint) || getWideSideSign(carrier);

  if (carrierRoleKey !== "wideForward" || attackingDepth < 42 || !isWidePrincipleZone(startPoint)) {
    return null;
  }

  const overlap = chooseWideOverlapRunner(
    teamId,
    sideSign,
    startPoint,
    profile,
    new Set([carrier.id])
  );
  if (!overlap) {
    return null;
  }

  const runnerPoint = getPlayerBallControlPoint(overlap.player);
  const runnerDepth = getAttackingDepth(runnerPoint, teamId);
  const overlapDepth = getAttackingDepth(overlap.target, teamId);
  const runnerHasArrived = runnerDepth >= attackingDepth - 1.5 && distance(runnerPoint, overlap.target) <= 9.5;
  const target = runnerHasArrived ? runnerPoint : overlap.target;
  const passDistance = distance(startPoint, target);

  if (passDistance < 5 || passDistance > 30 || isPassReceiverOffside(overlap.player, startPoint)) {
    return null;
  }

  const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
  const laneClarity = computePassLaneClarity(carrier, target);
  const receiverPressure = getPlayerPressureLoad(overlap.player, target);
  const runnerQuality =
    getAutoPilotRoleStrength(overlap.player, "runner") +
    getAutoPilotRoleStrength(overlap.player, "crosser") * 0.42 +
    getPlayerTendency(overlap.player, "overlap") * 0.35;
  const score =
    1.35 +
    overlap.principleFit * 0.96 +
    runnerQuality * 0.74 +
    laneClarity * 0.72 +
    profile.overlapBias * 0.72 +
    profile.crossBias * 0.26 +
    clamp(forwardGain / 20, -0.12, 0.55) -
    receiverPressure * 0.48 -
    Math.max(0, Math.abs(overlapDepth - runnerDepth) - 10) * 0.025;

  if (score < 1.62) {
    return null;
  }

  return {
    actionType: "pass",
    target,
    receiverPlayerId: overlap.player.id,
    receiverRoleKey: "wideBack",
    passDistance,
    forwardGain,
    laneClarity,
    receiverPressure,
    isLineBreak: forwardGain >= 7.5,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: getAttackingDepth(target, teamId) >= 73 && isWidePrincipleZone(target),
    isPrinciplePattern: true,
    principleKey: "wide-overlap",
    principleLabel: `Wide overload: W releases ${getPlayerMagnetLabel(overlap.player)} on the overlap`,
    score,
    firstTouchMode: attackingDepth >= 64 ? "forward" : "inside",
    label: "overlap pass",
    reason: "wide-overload principle: winger receives high, then releases the outside full-back or wing-back run",
  };
}

function getLastSwitchLandingActionContext(carrier, startPoint, profile) {
  if (!carrier || !startPoint || state.restartPhase?.type) {
    return null;
  }

  const teamId = carrier.team;
  const lastStep = getRecentPossessionSteps(teamId, 4)[0] ?? null;
  if (
    !lastStep ||
    lastStep.actionType !== "pass" ||
    lastStep.receiverPlayerId !== carrier.id ||
    getRecordedStepDuration(lastStep) > 5
  ) {
    return null;
  }

  const start = lastStep.beforeSnapshot?.ball?.position;
  const target = lastStep.target ?? startPoint;
  if (!start || !target) {
    return null;
  }

  const actionDistance = distance(start, target);
  const laneShift = Math.abs(getPitchLaneIndex(start) - getPitchLaneIndex(target));
  const principleText = [
    lastStep.profileLabel,
    lastStep.offensiveAutopilot?.principleKey,
    lastStep.offensiveAutopilot?.principleLabel,
    ...(lastStep.autoPrinciples ?? []),
  ].filter(Boolean).join(" ").toLowerCase();
  const wasSwitch =
    (actionDistance >= 18 && laneShift >= 2) ||
    principleText.includes("switch") ||
    principleText.includes("weak-side") ||
    principleText.includes("far side");

  if (!wasSwitch) {
    return null;
  }

  const sideSign =
    getWideSideSign(startPoint) ||
    getWideSideSign(target) ||
    1;
  const depth = getAttackingDepth(startPoint, teamId);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const targetThreat = getPitchThreatProfile(startPoint, teamId);
  const startsWide = isWidePrincipleZone(startPoint);
  const finalThirdCue =
    depth >= 62 ||
    targetThreat.assistZone >= 0.22 ||
    targetThreat.cutbackZone >= 0.18 ||
    targetThreat.box >= 0.14;

  if (!startsWide && depth < 44 && pressure >= 0.46) {
    return null;
  }

  return {
    actionDistance,
    depth,
    finalThirdCue,
    lastStep,
    laneShift,
    pressure,
    sideSign,
    start,
    target,
    targetThreat,
    startsWide,
    switchBias: profile.switchBias ?? 0.5,
  };
}

function buildAutoPilotSwitchLandingContinuationCandidate(carrier, startPoint, profile) {
  const context = getLastSwitchLandingActionContext(carrier, startPoint, profile);
  if (!context) {
    return null;
  }

  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const carrierRoleKey = getOffensiveRoleKey(carrier, formation);
  const options = [];
  const addOption = (option) => {
    if (option && Number.isFinite(option.score)) {
      options.push(option);
    }
  };
  const addPassToReceiver = (receiver, target, meta = {}) => {
    if (!receiver || receiver.team !== teamId || receiver.id === carrier.id || isPassReceiverOffside(receiver, startPoint)) {
      return;
    }

    const passDistance = distance(startPoint, target);
    if (passDistance < (meta.minDistance ?? 4) || passDistance > (meta.maxDistance ?? 30)) {
      return;
    }

    const roleKey = getOffensiveRoleKey(receiver, formation);
    const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
    const laneClarity = computePassLaneClarity(carrier, target, { receiverPlayerId: receiver.id });
    const receiverPressure = getPlayerPressureLoad(receiver, target);
    const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
    const supportNearTarget = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, receiver.id]), 14);
    const score =
      (meta.baseScore ?? 1.55) +
      laneClarity * 0.84 +
      getAutoPilotRoleStrength(receiver, "receiver") * 0.24 +
      getAutoPilotRoleStrength(receiver, "runner") * (meta.runnerWeight ?? 0.28) +
      actionSpace.value * 0.36 +
      clamp(forwardGain / 18, -0.1, 0.48) +
      clamp(supportNearTarget, 0, 3) * 0.08 +
      (meta.bonus ?? 0) -
      receiverPressure * 0.42 -
      Math.max(0, passDistance - 22) * 0.026;

    if (score < (meta.minScore ?? 1.72)) {
      return;
    }

    addOption({
      actionType: "pass",
      target,
      receiverPlayerId: receiver.id,
      receiverRoleKey: roleKey,
      passDistance,
      forwardGain,
      laneClarity,
      receiverPressure,
      supportNearTarget,
      isLineBreak: forwardGain >= 6 || actionSpace.lineBreakCount >= 1,
      isSwitch: false,
      isSidewaysPass: false,
      isBoxPass: actionSpace.targetThreat.box >= 0.18 || actionSpace.targetThreat.assistZone >= 0.28,
      isPrinciplePattern: true,
      principleKey: meta.principleKey ?? "switch-landing-continuation",
      principleLabel: meta.principleLabel ?? `Switch landing: ${getPlayerMagnetLabel(carrier)} continues the far-side attack`,
      principleRunnerPlayerId: receiver.id,
      score,
      firstTouchMode: actionSpace.targetThreat.box >= 0.18 || forwardGain >= 5 ? "forward" : "inside",
      label: meta.label ?? "switch continuation",
      reason: meta.reason ?? "switch landing has opened the far side, so the next action continues that advantage",
    });
  };

  if (context.startsWide && context.depth >= 42 && (profile.overlapBias ?? 0.5) >= 0.48) {
    const overlap = chooseWideOverlapRunner(teamId, context.sideSign, startPoint, profile, new Set([carrier.id]));
    if (overlap) {
      const runnerPoint = getPlayerBallControlPoint(overlap.player);
      const runnerArrived = distance(runnerPoint, overlap.target) <= 8.8;
      addPassToReceiver(overlap.player, runnerArrived ? runnerPoint : overlap.target, {
        baseScore: 1.72,
        bonus: overlap.principleFit * 0.42 + getPlayerTendency(overlap.player, "overlap") * 0.22,
        label: "overlap after switch",
        maxDistance: 31,
        minScore: 1.68,
        principleKey: "switch-overlap-continuation",
        principleLabel: `Switch landing: ${getPlayerMagnetLabel(overlap.player)} overlaps outside`,
        reason: "far-side switch creates the timing for an outside overlap",
        runnerWeight: 0.42,
      });
    }
  }

  const halfSpaceTarget = getSwitchLandingAttackTarget(teamId, {
    sideSign: context.sideSign,
    targetDepth: context.depth,
    targetPoint: startPoint,
  }, context.finalThirdCue ? "cutbackEdge" : "insidePocket", profile);
  const insideReceiver = state.players
    .filter((player) => {
      if (player.team !== teamId || player.id === carrier.id || isGoalkeeper(player)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(player, formation);
      return ["connector", "secondStriker", "wideForward", "striker"].includes(roleKey);
    })
    .sort((a, b) => distance(a.position, halfSpaceTarget) - distance(b.position, halfSpaceTarget))[0] ?? null;
  addPassToReceiver(insideReceiver, halfSpaceTarget, {
    baseScore: context.finalThirdCue ? 1.82 : 1.58,
    bonus: (profile.shortSupport ?? 0.55) * 0.18 + (context.finalThirdCue ? 0.3 : 0),
    label: context.finalThirdCue ? "cutback edge" : "underlap pass",
    maxDistance: context.finalThirdCue ? 26 : 24,
    minScore: context.finalThirdCue ? 1.66 : 1.78,
    principleKey: context.finalThirdCue ? "switch-cutback-edge" : "switch-underlap-continuation",
    principleLabel: context.finalThirdCue
      ? "Switch landing: cutback edge arrives"
      : "Switch landing: underlap into half-space",
    reason: context.finalThirdCue
      ? "switch lands wide in the final third and the cutback edge is available"
      : "switch lands wide and the half-space support is the next forward option",
  });

  if (context.finalThirdCue) {
    const boxCandidate = buildAutoPilotBoxDeliveryCandidate(carrier, startPoint, profile);
    if (boxCandidate) {
      addOption({
        ...boxCandidate,
        score: boxCandidate.score + 0.34 + (profile.deliveryBias ?? 0.45) * 0.16,
        isPrinciplePattern: true,
        principleKey: "switch-final-third-delivery",
        principleLabel: "Switch landing: deliver before the block resets",
        principleLabels: uniquePrincipleLabels([
          ...(boxCandidate.principleLabels ?? []),
          "Switch landing: deliver before the block resets",
        ]),
        reason: "far-side switch reaches the final third before the block can slide across",
      });
    }
  }

  if (
    context.pressure <= 0.52 &&
    (carrierRoleKey === "wideForward" || carrierRoleKey === "wideBack" || carrierRoleKey === "connector")
  ) {
    const carryTarget = getSwitchLandingAttackTarget(teamId, {
      sideSign: context.sideSign,
      targetDepth: context.depth,
      targetPoint: startPoint,
    }, context.finalThirdCue ? "cutbackEdge" : "underlap", profile);
    const actionDistance = distance(startPoint, carryTarget);
    const forwardGain = (carryTarget.x - startPoint.x) * getAttackDirectionSign(teamId);
    const actionSpace = getActionSpaceValue(startPoint, carryTarget, teamId, profile);
    const score =
      1.5 +
      getAutoPilotRoleStrength(carrier, "dribbler") * 0.48 +
      (profile.carryBias ?? 0.5) * 0.26 +
      (profile.dribbleBias ?? 0.5) * 0.2 +
      Math.max(0, forwardGain) * 0.045 +
      actionSpace.value * 0.34 -
      context.pressure * 0.36;

    if (actionDistance >= 4.5 && forwardGain >= 2 && score >= 1.68) {
      addOption({
        actionType: "dribble",
        target: carryTarget,
        receiverPlayerId: null,
        passDistance: actionDistance,
        forwardGain,
        laneClarity: 0.72,
        receiverPressure: context.pressure,
        isLineBreak: actionSpace.lineBreakCount >= 1,
        isSwitch: false,
        isSidewaysPass: false,
        isBoxPass: actionSpace.targetThreat.box >= 0.18,
        isPrinciplePattern: true,
        principleKey: "switch-landing-carry",
        principleLabel: `Switch landing: ${getPlayerMagnetLabel(carrier)} attacks the isolated side`,
        score,
        firstTouchMode: null,
        label: "carry after switch",
        reason: "far-side switch creates a moment to carry before pressure arrives",
      });
    }
  }

  if (!options.length) {
    return null;
  }

  return options.sort((a, b) => b.score - a.score)[0];
}

function buildAutoPilotThroughBallCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const ownerPressure = getPlayerPressureLoad(carrier, startPoint);
  if (
    ballDepth < 42 ||
    ownerPressure > 0.72 ||
    (profile.phaseKey === "buildUp" && profile.directness < 0.75)
  ) {
    return null;
  }

  const formation = teams[teamId]?.formation;
  const candidates = state.players
    .filter((runner) => {
      if (runner.team !== teamId || runner.id === carrier.id || isGoalkeeper(runner)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(runner, formation);
      if (!["striker", "wideForward", "secondStriker", "connector"].includes(roleKey)) {
        return false;
      }

      return !isPassReceiverOffside(runner, startPoint);
    })
    .map((runner) => {
      const roleKey = getOffensiveRoleKey(runner, formation);
      const sideSign = getWideSideSign(runner) || getWideSideSign(startPoint) || 1;
      const baseTarget = getHighValueAttackTarget(
        teamId,
        startPoint,
        roleKey === "wideForward" ? "halfSpaceRun" : "goldenRun",
        sideSign
      );
      const target = clampToPitch({
        x: lerp(baseTarget.x, runner.position.x, roleKey === "connector" ? 0.18 : 0.08),
        y: lerp(baseTarget.y, runner.position.y, roleKey === "wideForward" ? 0.22 : 0.12),
      }, 2.5);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const targetDepth = getAttackingDepth(target, teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const targetThreat = getPitchThreatProfile(target, teamId);
      const runnerDistance = distance(runner.position, target);
      const runnerTime = computeTimeToCoverDistance(runner, runnerDistance, target);
      const passTime = passDistance / Math.max(resolveBallActionProfile("pass", startPoint, target, carrier, null).averageSpeed, 0.01);
      const timingFit = clamp(1 - Math.abs(runnerTime - passTime) / 1.35, 0, 1);
      const runnerStrength =
        getAutoPilotRoleStrength(runner, "runner") * 0.56 +
        getAutoPilotRoleStrength(runner, "receiver") * 0.28 +
        getPlayerTendency(runner, "boxRun") * 0.16;
      const supportNearTarget = getTeamSupportCountAroundPoint(teamId, target, new Set([carrier.id, runner.id]), 16);
      const score =
        1.02 +
        targetThreat.value * 1.05 +
        targetThreat.centralPocket * 0.42 +
        targetThreat.behindLine * 0.28 +
        laneClarity * 0.92 +
        runnerStrength * 0.8 +
        timingFit * 0.64 +
        clamp(forwardGain / 22, 0, 0.82) +
        profile.lineBreakBias * 0.58 +
        profile.directness * 0.34 +
        clamp(supportNearTarget, 0, 3) * 0.08 -
        ownerPressure * 0.38 -
        (passDistance > 34 && profile.routeOneBias < 0.5 ? 0.38 : 0) -
        (runnerTime > passTime + 1.1 ? 0.42 : 0);

      return {
        runner,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        targetDepth,
        targetThreat,
        supportNearTarget,
        score,
        timingFit,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 11 &&
      candidate.passDistance <= 38 &&
      candidate.forwardGain >= 7 &&
      candidate.laneClarity >= 0.42 &&
      candidate.targetThreat.value >= 0.42 &&
      candidate.timingFit >= 0.18 &&
      candidate.score >= 1.72
    ))
    .sort((a, b) => b.score - a.score);

  const selected = candidates[0];
  if (!selected) {
    return null;
  }

  return {
    actionType: "pass",
    target: selected.target,
    receiverPlayerId: null,
    receiverRoleKey: selected.roleKey,
    passDistance: selected.passDistance,
    forwardGain: selected.forwardGain,
    laneClarity: selected.laneClarity,
    receiverPressure: 0.42,
    supportNearTarget: selected.supportNearTarget,
    isLineBreak: true,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: selected.targetDepth >= 72 && Math.abs(selected.target.y - pitch.width / 2) <= 18,
    isPrinciplePattern: true,
    principleKey: "pass-into-space",
    principleLabel: `Pass into space: ${getPlayerMagnetLabel(selected.runner)} attacks ${selected.targetThreat.primaryLabel}`,
    principleRunnerPlayerId: selected.runner.id,
    score: selected.score,
    firstTouchMode: "forward",
    label: "through ball",
    reason: `${profile.styleLabel.toLowerCase()} pass into space for ${getPlayerMagnetLabel(selected.runner)} to attack the next line`,
  };
}

function buildAutoPilotBetweenLinesCandidate(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const ownerPressure = getPlayerPressureLoad(carrier, startPoint);
  if (ballDepth < 34 || ballDepth > 76 || ownerPressure > 0.7) {
    return null;
  }

  const formation = teams[teamId]?.formation;
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const startSide = getWideSideSign(startPoint) || 1;
  const candidates = state.players
    .filter((receiver) => {
      if (receiver.team !== teamId || receiver.id === carrier.id || isGoalkeeper(receiver)) {
        return false;
      }

      const roleKey = getOffensiveRoleKey(receiver, formation);
      if (!["connector", "striker", "secondStriker", "wideForward"].includes(roleKey)) {
        return false;
      }

      return !isPassReceiverOffside(receiver, startPoint);
    })
    .map((receiver) => {
      const roleKey = getOffensiveRoleKey(receiver, formation);
      const receiverSide = getWideSideSign(receiver) || startSide;
      const pocketSide =
        roleKey === "wideForward"
          ? receiverSide
          : Math.abs(startPoint.y - pitch.width / 2) < 10
            ? receiverSide
            : -startSide;
      const pocketDepth = clamp(
        ballDepth +
          (roleKey === "connector" ? 8 : roleKey === "secondStriker" ? 10 : 12) +
          profile.lineBreakBias * 4,
        45,
        78
      );
      const halfSpaceY = pitch.width / 2 + pocketSide * (roleKey === "striker" ? 8.5 : 13.5);
      const target = clampToPitch({
        x: getDepthX(teamId, pocketDepth),
        y: clamp(lerp(receiver.position.y, halfSpaceY, roleKey === "wideForward" ? 0.54 : 0.7), 9, pitch.width - 9),
      }, 2.5);
      const passDistance = distance(startPoint, target);
      const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
      const laneClarity = computePassLaneClarity(carrier, target);
      const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
      const targetThreat = actionSpace.targetThreat;
      const runnerDistance = distance(receiver.position, target);
      const runnerTime = computeTimeToCoverDistance(receiver, runnerDistance, target);
      const passTime = passDistance / Math.max(resolveBallActionProfile("pass", startPoint, target, carrier, null).averageSpeed, 0.01);
      const timingFit = clamp(1 - Math.abs(runnerTime - passTime) / 1.4, 0, 1);
      const receiverRoleFit =
        roleKey === "connector"
          ? 0.48
          : roleKey === "secondStriker"
            ? 0.42
            : roleKey === "striker"
              ? 0.34
              : 0.28;
      const receiveQuality =
        getAutoPilotRoleStrength(receiver, "receiver") * 0.44 +
        getPlayerTendency(receiver, "passAndMove") * 0.22 +
        getAutoPilotRoleStrength(receiver, "creator") * 0.18;
      const score =
        1.18 +
        laneClarity * 0.92 +
        actionSpace.value * 1.15 +
        clamp(actionSpace.lineBreakCount, 0, 3) * 0.18 +
        timingFit * 0.52 +
        receiveQuality +
        receiverRoleFit +
        profile.shortSupport * 0.2 +
        profile.lineBreakBias * 0.4 +
        (progressionWindow.active ? 0.48 + progressionWindow.urgency * 0.24 : 0) +
        (
          targetThreat.centralPocket >= 0.34 ||
          targetThreat.betweenLines >= 0.46 ||
          targetThreat.halfSpace >= 0.45
            ? 0.34
            : 0
        ) -
        ownerPressure * 0.36 -
        actionSpace.targetPressure * 0.38 -
        Math.abs(passDistance - 18) * 0.012;

      return {
        receiver,
        roleKey,
        target,
        passDistance,
        forwardGain,
        laneClarity,
        actionSpace,
        score,
        timingFit,
      };
    })
    .filter((candidate) => (
      candidate.passDistance >= 7 &&
      candidate.passDistance <= 29 &&
      candidate.forwardGain >= 3.5 &&
      candidate.laneClarity >= 0.38 &&
      candidate.timingFit >= 0.14 &&
      candidate.actionSpace.value >= 0.34 &&
      candidate.score >= 1.74
    ))
    .sort((a, b) => b.score - a.score);

  const selected = candidates[0];
  if (!selected) {
    return null;
  }

  return {
    actionType: "pass",
    target: selected.target,
    receiverPlayerId: null,
    receiverRoleKey: selected.roleKey,
    passDistance: selected.passDistance,
    forwardGain: selected.forwardGain,
    laneClarity: selected.laneClarity,
    receiverPressure: selected.actionSpace.targetPressure,
    supportNearTarget: getTeamSupportCountAroundPoint(teamId, selected.target, new Set([carrier.id, selected.receiver.id]), 14),
    isLineBreak: selected.actionSpace.lineBreakCount >= 1 || selected.forwardGain >= 8,
    isSwitch: false,
    isSidewaysPass: false,
    isBoxPass: selected.actionSpace.targetThreat.box >= 0.24,
    isPrinciplePattern: true,
    principleKey: "between-lines-pocket",
    principleLabel: `Between-lines pocket: ${getPlayerMagnetLabel(selected.receiver)} receives in ${selected.actionSpace.targetThreat.primaryLabel}`,
    principleRunnerPlayerId: selected.receiver.id,
    score: selected.score,
    firstTouchMode:
      selected.actionSpace.targetThreat.centralPocket >= 0.36 ||
      selected.actionSpace.targetThreat.betweenLines >= 0.5
        ? "forward"
        : "inside",
    label: "between-lines pass",
    reason: `${profile.styleLabel.toLowerCase()} finds ${getPlayerMagnetLabel(selected.receiver)} between lines to attack ${selected.actionSpace.targetThreat.primaryLabel}`,
  };
}

function buildAutoPilotPassCandidates(carrier, startPoint, profile) {
  const teamId = carrier.team;
  const formation = teams[teamId]?.formation;
  const ownerPressure = getPlayerPressureLoad(carrier, startPoint);
  const forwardFacingSpaceTwo = getForwardFacingSpaceTwoContext(carrier, startPoint);
  const ballDepth = getAttackingDepth(startPoint, teamId);
  const maxPassDistance = profile.routeOneBias >= 0.55
    ? 36 + profile.directness * 22 + profile.routeOneBias * 18 + (profile.phaseKey === "finalThird" ? 8 : 0)
    : profile.shortSupport >= 0.78 && profile.directness < 0.5
      ? 26 + profile.lineBreakBias * 9 + (profile.phaseKey === "finalThird" ? 5 : 0)
      : 34 + profile.directness * 18 + (profile.phaseKey === "finalThird" ? 7 : 0);
  const rhythm = getPossessionRhythmContext(teamId);
  const possessionMaturity = clamp(
    rhythm.duration / Math.max(profile.targetPossessionSeconds ?? 8.8, 0.1),
    0,
    1.45
  );
  const candidates = [];

  state.players.forEach((receiver) => {
    if (receiver.team !== teamId || receiver.id === carrier.id) {
      return;
    }

    if (isPassReceiverOffside(receiver, startPoint)) {
      return;
    }

    const receiverRoleKey = getOffensiveRoleKey(receiver, formation);
    const target = getPlayerBallControlPoint(receiver);
    const passDistance = distance(startPoint, target);
    if (passDistance < 3.2 || passDistance > maxPassDistance) {
      return;
    }

    const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(teamId);
    const targetDepth = getAttackingDepth(target, teamId);
    const lateralMeters = Math.abs(target.y - startPoint.y);
    const laneClarity = computePassLaneClarity(carrier, target);
    const receiverPressure = getPlayerPressureLoad(receiver, target);
    const supportNearTarget = getTeamSupportCountAroundPoint(
      teamId,
      target,
      new Set([carrier.id, receiver.id]),
      passDistance >= 26 ? 15 : 11
    );
    const wideEntryPrinciple = getWideEntryPrincipleContext(carrier, receiver, startPoint, target, profile);
    const receiverStrength = getAutoPilotRoleStrength(receiver, "receiver");
    const runnerStrength = getAutoPilotRoleStrength(receiver, "runner");
    const creatorStrength = getAutoPilotRoleStrength(carrier, "creator");
    const switchStrength = getAutoPilotRoleStrength(carrier, "switcher");
    const passAndMoveTendency = getPlayerTendency(receiver, "passAndMove");
    const lineBreakTendency = getPlayerTendency(carrier, "lineBreakPass");
    const retainTendency = getPlayerTendency(carrier, "retain");
    const isSwitch = lateralMeters >= 19 && passDistance >= 22;
    const isRouteOnePass =
      profile.routeOneBias >= 0.55 &&
      passDistance >= 20 &&
      forwardGain >= 10 &&
      (receiverRoleKey === "striker" || receiverRoleKey === "secondStriker" || receiverRoleKey === "wideForward");
    const isSwitchOpportunity =
      isSwitch &&
      (ownerPressure >= 0.46 ||
        (profile.switchBias >= 0.68 && laneClarity >= 0.72 && receiverPressure <= 0.48) ||
        (switchStrength >= 0.82 && laneClarity >= 0.78 && receiverPressure <= 0.42));
    const isLineBreak = forwardGain >= 7.5 && targetDepth >= ballDepth + 5;
    const isBoxPass = targetDepth >= 73 && Math.abs(target.y - pitch.width / 2) <= 17;
    const isBackPass = forwardGain < -6;
    const sameLanePass = getPitchLaneKey(startPoint) === getPitchLaneKey(target);
    const isSidewaysPass = Math.abs(forwardGain) < 4 && lateralMeters >= 6.5 && !isSwitch;
    const threatGain = getActionThreatGain(startPoint, target, teamId);
    const targetThreat = getPitchThreatProfile(target, teamId);
    const actionSpace = getActionSpaceValue(startPoint, target, teamId, profile);
    const centralPocketScore = targetThreat.centralPocket;
    const centralPocketPassBonus =
      centralPocketScore > 0.42
        ? 0.48 +
          centralPocketScore * 0.92 +
          (forwardFacingSpaceTwo.active ? 0.42 : 0) +
          (receiverPressure <= 0.56 ? 0.16 : 0)
        : 0;
    const highValueSpaceBonus =
      Math.max(0, threatGain) * 0.86 +
      targetThreat.value * 0.34 +
      targetThreat.halfSpace * 0.14 +
      targetThreat.betweenLines * 0.14 +
      targetThreat.cutbackZone * 0.18 +
      actionSpace.spacePriority.score * 0.42 +
      targetThreat.assistZone * (profile.crossBias >= 0.56 || profile.overlapBias >= 0.56 ? 0.18 : 0.08);
    const progressionSpaceBonus =
      forwardGain >= 3
        ? actionSpace.value * (0.34 + profile.progressionUrgency * 0.42) +
          clamp(actionSpace.lineBreakCount, 0, 3) * 0.15 +
          (actionSpace.openTarget >= 0.68 && targetDepth >= 48 ? 0.12 : 0)
        : 0;
    const rightWayBackPassPenalty =
      forwardFacingSpaceTwo.active && isBackPass
        ? 1.15 + profile.progressionUrgency * 0.42 + (ownerPressure <= 0.28 ? 0.28 : 0)
        : 0;
    const lowValueSafetyPenalty =
      forwardFacingSpaceTwo.active &&
      !isLineBreak &&
      !isSwitch &&
      targetThreat.value < getPitchThreatProfile(startPoint, teamId).value + 0.05 &&
      centralPocketScore < 0.35 &&
      forwardGain < 2
        ? 0.72
        : 0;
    const lowValueProgressionWindowPenalty =
      forwardFacingSpaceTwo.active &&
      !isLineBreak &&
      !isSwitch &&
      actionSpace.value < 0.28 &&
      actionSpace.lineBreakCount === 0 &&
      forwardGain < 2 &&
      ownerPressure < 0.55
        ? 0.36 + profile.progressionUrgency * 0.36
        : 0;
    const possessionHasSettled = rhythm.steps >= 2 || possessionMaturity >= 0.38;
    const sidewaysRepeatPenalty = isSidewaysPass
      ? clamp(rhythm.sidewaysPasses - profile.sidewaysTolerance * 2, 0, 4) *
          (0.28 + profile.progressionUrgency * 0.22) +
        (possessionHasSettled ? possessionMaturity * (0.22 + profile.directness * 0.36) : 0)
      : 0;
    const progressionRhythmBonus =
      isLineBreak || isBoxPass || isRouteOnePass
        ? (0.24 + profile.progressionUrgency * 0.48) * clamp(possessionMaturity + 0.4, 0.35, 1.25)
        : 0;
    const controlledRecycleBonus =
      isBackPass && rhythm.steps <= 1
        ? profile.recycleWindow * Math.max(0.2, 0.54 - profile.directness * 0.18)
        : 0;
    const sterileRecyclePenalty =
      isBackPass && rhythm.backPasses >= 1 && rhythm.forwardPasses === 0
        ? 0.26 + profile.progressionUrgency * 0.38
        : 0;
    const lowValueSwitchPenalty =
      isSwitch && forwardGain < 4 && ownerPressure < 0.42 && profile.switchBias < 0.72
        ? 0.32 + possessionMaturity * 0.3
        : 0;
    if (isSwitch && !isSwitchOpportunity) {
      return;
    }

    if (passDistance > 42 && profile.phaseKey !== "finalThird" && profile.directness < 0.72 && !isRouteOnePass) {
      return;
    }

    const rolePreference = profile.runnerPreferences?.[receiverRoleKey] ?? 0.2;
    const distancePenalty = passDistance <= 22
      ? passDistance * 0.006
      : 0.13 + (passDistance - 22) * (0.058 - profile.directness * 0.026);
    const supportPassBonus = passDistance >= 6 && passDistance <= 18 && forwardGain > -4
      ? 0.18 + profile.shortSupport * 0.42 + passAndMoveTendency * 0.18
      : 0;
    const pressureEscape = ownerPressure >= 0.5 && passDistance <= 18 ? 0.32 : 0;
    const longPassPenalty =
      passDistance >= 32 && !isBoxPass && !isSwitchOpportunity && !isRouteOnePass
        ? 0.8 - profile.directness * 0.52 - profile.routeOneBias * 0.28 + (supportNearTarget <= 0 ? 0.36 : 0)
        : passDistance >= 26 && !isBoxPass
          ? 0.38 - profile.directness * 0.22 - profile.routeOneBias * 0.2 + (supportNearTarget <= 0 ? 0.22 : 0)
          : 0;
    const secondBallSupportBonus =
      passDistance >= 24 && forwardGain >= 8
        ? clamp(supportNearTarget, 0, 3) * (0.1 + profile.directness * 0.06 + profile.routeOneBias * 0.08)
        : 0;
    const activeFirstTouchMode = isSwitch
      ? isWideChannel(target) ? "inside" : "forward"
      : isLineBreak || isBoxPass
        ? "forward"
        : supportPassBonus > 0 && receiverPressure <= 0.52 && forwardGain >= 1.5 &&
            (profile.firstTouchForwardBias >= 0.56 || passAndMoveTendency >= 0.68)
          ? "forward"
          : profile.tempo >= 0.62 && forwardGain >= -1.5
            ? "inside"
            : receiverPressure <= 0.65
              ? "inside"
              : "kill";
    const score =
      0.72 +
      laneClarity * 1.55 +
      receiverStrength * 0.82 +
      creatorStrength * 0.42 +
      profile.passBias * 0.24 +
      clamp(forwardGain / 24, -0.32, 0.74) * (0.72 + profile.directness * 0.62) +
      clamp(targetDepth / 100, 0, 1) * 0.35 +
      rolePreference * 0.22 +
      (isLineBreak ? 0.42 + profile.lineBreakBias * 0.72 + lineBreakTendency * 0.32 + runnerStrength * 0.38 : 0) +
      (isSwitch ? 0.12 + profile.switchBias * 0.42 + switchStrength * 0.34 + ownerPressure * 0.32 : 0) +
      (isRouteOnePass ? 0.42 + profile.routeOneBias * 0.58 + runnerStrength * 0.26 : 0) +
      (isBoxPass ? 0.48 + getAutoPilotRoleStrength(receiver, "finisher") * 0.5 : 0) +
      secondBallSupportBonus +
      centralPocketPassBonus +
      highValueSpaceBonus +
      progressionSpaceBonus +
      (wideEntryPrinciple ? wideEntryPrinciple.scoreBonus : 0) +
      progressionRhythmBonus +
      supportPassBonus +
      controlledRecycleBonus +
      pressureEscape -
      receiverPressure * 0.52 -
      distancePenalty -
      longPassPenalty -
      sidewaysRepeatPenalty -
      sterileRecyclePenalty -
      lowValueSwitchPenalty -
      rightWayBackPassPenalty -
      lowValueSafetyPenalty -
      lowValueProgressionWindowPenalty -
      (sameLanePass && forwardGain < 7 && ownerPressure < 0.5 ? 0.32 : 0) -
      (isBackPass ? 0.28 + profile.directness * 0.4 - retainTendency * 0.18 : 0);

    if (score < 1.55) {
      return;
    }

    candidates.push({
      actionType: "pass",
      target,
      receiverPlayerId: receiver.id,
      receiverRoleKey,
      passDistance,
      forwardGain,
      laneClarity,
      receiverPressure,
      supportNearTarget,
      isLineBreak,
      isSwitch,
      isSidewaysPass,
      isBoxPass,
      isPrinciplePattern: !!wideEntryPrinciple,
      principleKey: wideEntryPrinciple?.key ?? null,
      principleLabel: wideEntryPrinciple
        ? `Wide overload: W receives high, ${getPlayerMagnetLabel(wideEntryPrinciple.runner)} overlaps outside`
        : null,
      principleRunnerPlayerId: wideEntryPrinciple?.runner.id ?? null,
      score,
      firstTouchMode: activeFirstTouchMode,
      label: wideEntryPrinciple ? "wide entry" : isSwitch ? "switch" : isLineBreak ? "line-breaking pass" : "pass",
      reason: isSwitch
        ? "switching play away from pressure"
        : isRouteOnePass
          ? "route-one territory and second-ball pressure"
          : wideEntryPrinciple
          ? `${profile.styleLabel.toLowerCase()} wide overload: play into W and trigger the outside overlap`
          : isLineBreak
          ? `${profile.styleLabel.toLowerCase()} line break`
          : `${profile.styleLabel.toLowerCase()} support option`,
    });
  });

  return candidates;
}

function buildAutoPilotDribbleCandidate(carrier, startPoint, profile) {
  const target = getAutoPilotDribbleTarget(carrier, profile);
  const travelDistance = distance(startPoint, target);
  if (travelDistance < 3.5) {
    return null;
  }

  const openGrassCarry = getOpenGrassCarryContext(carrier, startPoint, profile);
  const openSpaceScore = getCarryLaneOpenSpaceScore(getNearestOpponentGapInCarryLane(carrier, target));
  const runwayProfile = getCarryRunwayProfile(carrier, startPoint, target, profile);
  const pressure = getPlayerPressureLoad(carrier, startPoint);
  const dribbleStrength = getAutoPilotRoleStrength(carrier, "dribbler");
  const dribbleTendency = getPlayerTendency(carrier, "dribble");
  const forwardGain = (target.x - startPoint.x) * getAttackDirectionSign(carrier.team);
  const goalDistance = distance(startPoint, getOpponentGoalCenter(carrier.team));
  const targetGoalDistance = distance(target, getOpponentGoalCenter(carrier.team));
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const forwardFacingSpaceTwo = getForwardFacingSpaceTwoContext(carrier, startPoint);
  const progressionWindow = getForwardProgressionWindow(carrier, startPoint, profile);
  const threatGain = getActionThreatGain(startPoint, target, carrier.team);
  const targetThreat = getPitchThreatProfile(target, carrier.team);
  const actionSpace = getActionSpaceValue(startPoint, target, carrier.team, profile);
  const valuableCarryBonus =
    targetThreat.centralPocket * 0.58 +
    targetThreat.betweenLines * 0.24 +
    targetThreat.halfSpace * 0.18 +
    Math.max(0, threatGain) * 0.62 +
    targetThreat.value * 0.22 +
    actionSpace.spacePriority.score * 0.28 +
    (forwardFacingSpaceTwo.active && forwardGain >= 3 ? 0.46 : 0);
  const isBreakawayCarry =
    goalDistance <= 50 &&
    targetGoalDistance <= goalDistance - 7 &&
    openSpaceScore >= 0.62 &&
    pressure <= 0.46;
  const isOpenGrassCarry =
    !!openGrassCarry &&
    distance(openGrassCarry.target, target) <= 1.4 &&
    openGrassCarry.openSpaceScore >= 0.56;
  const isRunwayCarry =
    runwayProfile.shouldExtend &&
    runwayProfile.openSpaceScore >= 0.56 &&
    runwayProfile.forwardGain >= 6;
  const roleKey = getOffensiveRoleKey(carrier, teams[carrier.team]?.formation);
  const roleFreedom =
    roleKey === "wideForward" || roleKey === "wideBack" || roleKey === "connector"
      ? 0.18
      : roleKey === "rest" || roleKey === "gk"
        ? -0.18
        : 0;
  const score =
    0.58 +
    openSpaceScore * 1.28 +
    dribbleStrength * 1.05 +
    profile.dribbleBias * 0.55 +
    profile.carryBias * 0.36 +
    dribbleTendency * 0.28 +
    clamp(forwardGain / 18, 0, 0.72) +
    valuableCarryBonus +
    actionSpace.value * 0.34 +
      roleFreedom +
      (isBreakawayCarry ? 0.72 : 0) +
      (isOpenGrassCarry ? 0.42 + openGrassCarry.score * 0.34 + profile.carryBias * 0.16 : 0) +
      (isRunwayCarry ? 0.36 + runwayProfile.runwayScore * 0.28 + clamp(runwayProfile.forwardGain / 30, 0, 0.18) : 0) +
      (progressionWindow.active ? 0.3 + progressionWindow.openLane * 0.28 + progressionWindow.urgency * 0.22 : 0) +
      (flow.carrierJustReceived ? 0.4 + profile.carryBias * 0.22 : 0) +
    (flow.consecutivePasses >= 2 ? 0.32 + Math.min(flow.consecutivePasses, 4) * 0.08 : 0) +
    (profile.phaseKey === "buildUp" ? -0.12 : 0.08) -
    pressure * 0.62;

  const minimumScore = progressionWindow.active || flow.carrierJustReceived || flow.consecutivePasses >= 2 ? 1.5 : 1.85;
  if (score < minimumScore) {
    return null;
  }

  return {
    actionType: "dribble",
    target,
    receiverPlayerId: null,
    score,
    isOpenGrassCarry: isOpenGrassCarry || isRunwayCarry,
    isRunwayCarry,
    runwayProfile,
    label: isBreakawayCarry
      ? "breakaway carry"
      : isRunwayCarry
        ? "open-grass runway"
      : isOpenGrassCarry
        ? openGrassCarry.label
        : "carry",
    reason: isBreakawayCarry
      ? "open grass to attack the goal"
      : isRunwayCarry
        ? "open grass gives the carrier a longer runway toward goal"
      : isOpenGrassCarry
        ? "open grass ahead allows a longer natural carry"
        : "space to commit the next defender",
    principleLabels: isRunwayCarry
      ? ["Open-grass runway"]
      : isOpenGrassCarry ? ["Open-grass carry"] : [],
  };
}

function chooseAutoPilotNextAction() {
  const carrier = getAutoPilotPossessionPlayer();
  if (!carrier) {
    return null;
  }

  const startPoint = cloneVector(getPlayerBallControlPoint(carrier));
  state.ball.ownerPlayerId = carrier.id;
  state.ball.position = cloneVector(startPoint);
  state.ball.startPosition = cloneVector(startPoint);
  state.ball.target = cloneVector(startPoint);

  const teamId = carrier.team;
  const profile = getOffensiveAutopilotProfile(teamId, startPoint);
  const kickoffChoice = buildAutoPilotKickoffCandidate(carrier, startPoint, profile);
  if (kickoffChoice) {
    return {
      ...kickoffChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const postKickoffResetChoice = buildAutoPilotPostKickoffResetCandidate(carrier, startPoint, profile);
  if (postKickoffResetChoice) {
    return {
      ...postKickoffResetChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const cornerChoice = buildAutoPilotCornerCandidate(carrier, startPoint, profile);
  if (cornerChoice) {
    return {
      ...cornerChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const penaltyChoice = buildAutoPilotPenaltyCandidate(carrier, startPoint, profile);
  if (penaltyChoice) {
    return {
      ...penaltyChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const freeKickChoice = buildAutoPilotFreeKickCandidate(carrier, startPoint, profile);
  if (freeKickChoice) {
    return {
      ...freeKickChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const throwInChoice = buildAutoPilotThrowInCandidate(carrier, startPoint, profile);
  if (throwInChoice) {
    return {
      ...throwInChoice,
      carrier,
      teamId,
      phaseLabel: profile.phaseLabel,
      styleLabel: profile.styleLabel,
      formation: teams[teamId]?.formation,
    };
  }

  const candidates = [
    buildAutoPilotGoalkeeperDistributionCandidate(carrier, startPoint, profile),
    buildAutoPilotDangerZoneEscapeCandidate(carrier, startPoint, profile),
    buildAutoPilotPressedRegainExitCandidate(carrier, startPoint, profile),
    buildAutoPilotRegainReleaseCandidate(carrier, startPoint, profile),
    buildAutoPilotPressureTrapEscapeCandidate(carrier, startPoint, profile),
    buildAutoPilotReceiveContinuationCandidate(carrier, startPoint, profile),
    buildAutoPilotSwitchLandingContinuationCandidate(carrier, startPoint, profile),
    buildAutoPilotShotCandidate(carrier, startPoint, profile),
    buildAutoPilotFinalThirdCombinationCandidate(carrier, startPoint, profile),
    buildAutoPilotBoxDeliveryCandidate(carrier, startPoint, profile),
    buildAutoPilotWideOverlapCandidate(carrier, startPoint, profile),
    buildAutoPilotBetweenLinesCandidate(carrier, startPoint, profile),
    buildAutoPilotThroughBallCandidate(carrier, startPoint, profile),
    buildAutoPilotDribbleCandidate(carrier, startPoint, profile),
    ...buildAutoPilotPassCandidates(carrier, startPoint, profile),
  ]
    .filter(Boolean)
    .map((candidate) => {
      const spacingBonus = getAutoPilotSpacingBonus(candidate, carrier, startPoint, profile);
      const repetitionPenalty = getAutoPilotRepetitionPenalty(candidate, carrier, startPoint, profile);
      const flowAdjustment = getAutoPilotFlowAdjustment(candidate, carrier, startPoint, profile);
      const principleAdjustment = getAutoPilotPrincipleAdjustment(candidate, carrier, startPoint, profile);
      const possessionIntentAdjustment = getAutoPilotPossessionIntentAdjustment(candidate, carrier, startPoint, profile);
      const tempoPhaseAdjustment = getAutoPilotTempoPhaseAdjustment(candidate, carrier, startPoint, profile);
      const rhythmGovernorAdjustment = getAutoPilotRhythmGovernorAdjustment(candidate, carrier, startPoint, profile);
      const openingVariationAdjustment = getAutoPilotOpeningVariationAdjustment(candidate, carrier, startPoint, profile);
      const opponentBlockReadAdjustment = getAutoPilotOpponentBlockReadAdjustment(candidate, carrier, startPoint, profile);
      const patternDiversityAdjustment = getAutoPilotPatternDiversityAdjustment(candidate, carrier, startPoint, profile);
      const receiveMomentumAdjustment = getAutoPilotReceiveMomentumAdjustment(candidate, carrier, startPoint, profile);
      const firstActionAfterReceiveAdjustment = getAutoPilotFirstActionAfterReceiveAdjustment(candidate, carrier, startPoint, profile);
      const receiveFlowAdjustment = getAutoPilotReceiveFlowAdjustment(candidate, carrier, startPoint, profile);
      const gameSpaceAdjustment = getAutoPilotGameSpaceAdjustment(candidate, carrier, startPoint, profile);
      const spatialDecisionAdjustment = getAutoPilotSpatialDecisionAdjustment(candidate, carrier, startPoint, profile);
      const laneRealityAdjustment = getAutoPilotLaneRealityAdjustment(candidate, carrier, startPoint, profile);
      const receiverAvailabilityAdjustment = getAutoPilotReceiverAvailabilityAdjustment(candidate, carrier, startPoint, profile);
      const receivePressureTrapAdjustment = getAutoPilotReceivePressureTrapAdjustment(candidate, carrier, startPoint, profile);
      const spaceDominanceAdjustment = getAutoPilotSpaceDominanceAdjustment(candidate, carrier, startPoint, profile);
      const carryEndProductAdjustment = getAutoPilotCarryEndProductAdjustment(candidate, carrier, startPoint, profile);
      const spaceTwoAdvantageAdjustment = getAutoPilotSpaceTwoAdvantageAdjustment(candidate, carrier, startPoint, profile);
      const possessionLoopAdjustment = getAutoPilotPossessionLoopAdjustment(candidate, carrier, startPoint, profile);
      const corridorTempoReleaseAdjustment = getAutoPilotCorridorTempoReleaseAdjustment(candidate, carrier, startPoint, profile);
      const nextSupportNetworkAdjustment = getAutoPilotNextSupportNetworkAdjustment(candidate, carrier, startPoint, profile);
      const spaceLadderAdjustment = getAutoPilotSpaceLadderAdjustment(candidate, carrier, startPoint, profile);
      const advantageRetentionAdjustment = getAutoPilotAdvantageRetentionAdjustment(candidate, carrier, startPoint, profile);
      const endProductUrgencyAdjustment = getAutoPilotEndProductUrgencyAdjustment(candidate, carrier, startPoint, profile);
      const chanceHierarchyAdjustment = getAutoPilotChanceHierarchyAdjustment(candidate, carrier, startPoint, profile);
      const lineBreakAdvantageAdjustment = getAutoPilotLineBreakAdvantageAdjustment(candidate, carrier, startPoint, profile);
      const advantageLifecycleAdjustment = getAutoPilotAdvantageLifecycleAdjustment(candidate, carrier, startPoint, profile);
      const combinationChainAdjustment = getAutoPilotCombinationChainAdjustment(candidate, carrier, startPoint, profile);
      const passLaneDenialAdjustment = getAutoPilotPassLaneDenialAdjustment(candidate, carrier, startPoint, profile);
      const counterPressEscapeAdjustment = getAutoPilotCounterPressEscapeAdjustment(candidate, carrier, startPoint, profile);
      const recoveryFirstActionAdjustment = getAutoPilotRecoveryFirstActionAdjustment(candidate, carrier, startPoint, profile);
      const postRecoveryPhaseAdjustment = getAutoPilotPostRecoveryPhaseAdjustment(candidate, carrier, startPoint, profile);
      const transitionNumbersAdjustment = getAutoPilotTransitionNumbersAdjustment(candidate, carrier, startPoint, profile);
      const pressureEscapeAdjustment = getAutoPilotPressureEscapeAdjustment(candidate, carrier, startPoint, profile);
      const visionScanAdjustment = getAutoPilotVisionScanAdjustment(candidate, carrier, startPoint, profile);
      const roleResponsibilityAdjustment = getAutoPilotRoleResponsibilityAdjustment(candidate, carrier, startPoint, profile);
      const localSuperiorityAdjustment = getAutoPilotLocalSuperiorityAdjustment(candidate, carrier, startPoint, profile);
      return {
        ...candidate,
        rawScore: candidate.score,
        spacingBonus,
        repetitionPenalty,
        flowAdjustment,
        principleAdjustment: principleAdjustment.score,
        possessionIntentAdjustment: possessionIntentAdjustment.score,
        tempoPhaseAdjustment: tempoPhaseAdjustment.score,
        rhythmGovernorAdjustment: rhythmGovernorAdjustment.score,
        openingVariationAdjustment: openingVariationAdjustment.score,
        opponentBlockReadAdjustment: opponentBlockReadAdjustment.score,
        patternDiversityAdjustment: patternDiversityAdjustment.score,
        receiveMomentumAdjustment: receiveMomentumAdjustment.score,
        firstActionAfterReceiveAdjustment: firstActionAfterReceiveAdjustment.score,
        receiveFlowAdjustment: receiveFlowAdjustment.score,
        gameSpaceAdjustment: gameSpaceAdjustment.score,
        spatialDecisionAdjustment: spatialDecisionAdjustment.score,
        laneRealityAdjustment: laneRealityAdjustment.score,
        receiverAvailabilityAdjustment: receiverAvailabilityAdjustment.score,
        receivePressureTrapAdjustment: receivePressureTrapAdjustment.score,
        spaceDominanceAdjustment: spaceDominanceAdjustment.score,
        carryEndProductAdjustment: carryEndProductAdjustment.score,
        spaceTwoAdvantageAdjustment: spaceTwoAdvantageAdjustment.score,
        possessionLoopAdjustment: possessionLoopAdjustment.score,
        corridorTempoReleaseAdjustment: corridorTempoReleaseAdjustment.score,
        nextSupportNetworkAdjustment: nextSupportNetworkAdjustment.score,
        spaceLadderAdjustment: spaceLadderAdjustment.score,
        advantageRetentionAdjustment: advantageRetentionAdjustment.score,
        endProductUrgencyAdjustment: endProductUrgencyAdjustment.score,
        chanceHierarchyAdjustment: chanceHierarchyAdjustment.score,
        lineBreakAdvantageAdjustment: lineBreakAdvantageAdjustment.score,
        advantageLifecycleAdjustment: advantageLifecycleAdjustment.score,
        combinationChainAdjustment: combinationChainAdjustment.score,
        passLaneDenialAdjustment: passLaneDenialAdjustment.score,
        counterPressEscapeAdjustment: counterPressEscapeAdjustment.score,
        recoveryFirstActionAdjustment: recoveryFirstActionAdjustment.score,
        postRecoveryPhaseAdjustment: postRecoveryPhaseAdjustment.score,
        transitionNumbersAdjustment: transitionNumbersAdjustment.score,
        pressureEscapeAdjustment: pressureEscapeAdjustment.score,
        visionScanAdjustment: visionScanAdjustment.score,
        roleResponsibilityAdjustment: roleResponsibilityAdjustment.score,
        localSuperiorityAdjustment: localSuperiorityAdjustment.score,
        receiveFlowContext: receiveFlowAdjustment.context ?? null,
        tempoPhaseContext: tempoPhaseAdjustment.context ?? null,
        rhythmGovernorContext: rhythmGovernorAdjustment.context ?? null,
        gameSpaceContext: gameSpaceAdjustment.context ?? null,
        spatialDecisionContext: spatialDecisionAdjustment.context ?? null,
        carryEndProductContext: carryEndProductAdjustment.context ?? null,
        spaceTwoAdvantageContext: spaceTwoAdvantageAdjustment.context ?? null,
        possessionLoopContext: possessionLoopAdjustment.context ?? null,
        corridorTempoReleaseContext: corridorTempoReleaseAdjustment.context ?? null,
        nextSupportNetwork: nextSupportNetworkAdjustment.network ?? null,
        spaceLadderContext: spaceLadderAdjustment.context ?? null,
        advantageRetentionContext: advantageRetentionAdjustment.context ?? null,
        endProductUrgencyContext: endProductUrgencyAdjustment.context ?? null,
        chanceHierarchyContext: chanceHierarchyAdjustment.context ?? null,
        lineBreakAdvantageContext: lineBreakAdvantageAdjustment.context ?? null,
        advantageLifecycleContext: advantageLifecycleAdjustment.context ?? null,
        combinationChainContext: combinationChainAdjustment.context ?? null,
        passLaneDenialContext: passLaneDenialAdjustment.context ?? null,
        counterPressEscapeContext: counterPressEscapeAdjustment.context ?? null,
        recoveryFirstActionContext: recoveryFirstActionAdjustment.context ?? null,
        postRecoveryPhaseContext: postRecoveryPhaseAdjustment.context ?? null,
        transitionNumbersContext: transitionNumbersAdjustment.context ?? null,
        pressureEscapeContext: pressureEscapeAdjustment.context ?? null,
        visionScanContext: visionScanAdjustment.context ?? null,
        roleResponsibilityContext: roleResponsibilityAdjustment.context ?? null,
        localSuperiorityContext: localSuperiorityAdjustment.context ?? null,
        receivePressureTrapContext: receivePressureTrapAdjustment.context ?? null,
        opponentBlockRead: opponentBlockReadAdjustment.block ?? null,
        spaceDominance: spaceDominanceAdjustment.dominance ?? null,
        receiverAvailability: receiverAvailabilityAdjustment.availability ?? null,
        patternFamily: patternDiversityAdjustment.pattern?.family ?? null,
        possessionIntent: possessionIntentAdjustment.intentKey,
        principleLabels: uniquePrincipleLabels([
          candidate.principleLabel,
          ...(candidate.principleLabels ?? []),
          ...principleAdjustment.labels,
          ...possessionIntentAdjustment.labels,
          ...tempoPhaseAdjustment.labels,
          ...rhythmGovernorAdjustment.labels,
          ...openingVariationAdjustment.labels,
          ...opponentBlockReadAdjustment.labels,
          ...patternDiversityAdjustment.labels,
          ...receiveMomentumAdjustment.labels,
          ...firstActionAfterReceiveAdjustment.labels,
          ...receiveFlowAdjustment.labels,
          ...gameSpaceAdjustment.labels,
          ...spatialDecisionAdjustment.labels,
          ...laneRealityAdjustment.labels,
          ...receiverAvailabilityAdjustment.labels,
          ...receivePressureTrapAdjustment.labels,
          ...spaceDominanceAdjustment.labels,
          ...carryEndProductAdjustment.labels,
          ...spaceTwoAdvantageAdjustment.labels,
          ...possessionLoopAdjustment.labels,
          ...corridorTempoReleaseAdjustment.labels,
          ...nextSupportNetworkAdjustment.labels,
          ...spaceLadderAdjustment.labels,
          ...advantageRetentionAdjustment.labels,
          ...endProductUrgencyAdjustment.labels,
          ...chanceHierarchyAdjustment.labels,
          ...lineBreakAdvantageAdjustment.labels,
          ...advantageLifecycleAdjustment.labels,
          ...combinationChainAdjustment.labels,
          ...passLaneDenialAdjustment.labels,
          ...counterPressEscapeAdjustment.labels,
          ...recoveryFirstActionAdjustment.labels,
          ...postRecoveryPhaseAdjustment.labels,
          ...transitionNumbersAdjustment.labels,
          ...pressureEscapeAdjustment.labels,
          ...visionScanAdjustment.labels,
          ...roleResponsibilityAdjustment.labels,
          ...localSuperiorityAdjustment.labels,
        ]),
        score:
          candidate.score +
          spacingBonus +
          flowAdjustment +
          principleAdjustment.score +
          possessionIntentAdjustment.score +
          tempoPhaseAdjustment.score +
          rhythmGovernorAdjustment.score +
          openingVariationAdjustment.score -
          repetitionPenalty +
          opponentBlockReadAdjustment.score +
          patternDiversityAdjustment.score +
          receiveMomentumAdjustment.score +
          firstActionAfterReceiveAdjustment.score +
          receiveFlowAdjustment.score +
          gameSpaceAdjustment.score +
          spatialDecisionAdjustment.score +
          laneRealityAdjustment.score +
          receiverAvailabilityAdjustment.score +
          receivePressureTrapAdjustment.score +
          spaceDominanceAdjustment.score +
          carryEndProductAdjustment.score +
          spaceTwoAdvantageAdjustment.score +
          possessionLoopAdjustment.score +
          corridorTempoReleaseAdjustment.score +
          nextSupportNetworkAdjustment.score +
          spaceLadderAdjustment.score +
          advantageRetentionAdjustment.score +
          endProductUrgencyAdjustment.score +
          chanceHierarchyAdjustment.score +
          lineBreakAdvantageAdjustment.score +
          advantageLifecycleAdjustment.score +
          combinationChainAdjustment.score +
          passLaneDenialAdjustment.score +
          counterPressEscapeAdjustment.score +
          recoveryFirstActionAdjustment.score +
          postRecoveryPhaseAdjustment.score +
          transitionNumbersAdjustment.score +
          pressureEscapeAdjustment.score +
          visionScanAdjustment.score +
          roleResponsibilityAdjustment.score +
          localSuperiorityAdjustment.score,
      };
    })
    .filter((candidate) => candidate.score >= 1.25 || candidate.actionType === "shot");

  if (!candidates.length) {
    return null;
  }

  candidates.sort((a, b) => b.score - a.score);
  const bestCandidate = candidates[0];
  const shotTolerance = profile.phaseKey === "finalThird" ? 1.8 : 0.85;
  const shotCandidate = candidates.find(
    (candidate) =>
      candidate.actionType === "shot" &&
      (candidate.mustShoot || candidate.score >= bestCandidate.score - shotTolerance)
  );
  const selectedCandidate = shotCandidate?.mustShoot
    ? shotCandidate
    : chooseScoredCandidateWithVariation(candidates, profile, {
        preferredCandidate: shotCandidate ?? null,
        tolerance: clamp(
          0.72 + profile.risk * 0.52 + profile.tempo * 0.26 + (profile.phaseKey === "finalThird" ? 0.34 : 0),
          0.72,
          1.65
        ),
        temperature: clamp(0.24 + profile.risk * 0.18 + profile.tempo * 0.12, 0.22, 0.62),
        carrier,
        startPoint,
      }) ?? bestCandidate;

  return {
    ...selectedCandidate,
    carrier,
    teamId,
    phaseLabel: profile.phaseLabel,
    styleLabel: profile.styleLabel,
    formation: teams[teamId]?.formation,
  };
}

function describeAutoPilotChoice(choice) {
  if (!choice) {
    return "no action";
  }

  const receiver = choice.receiverPlayerId ? getPlayerById(choice.receiverPlayerId) : null;
  const receiverText = receiver ? ` to ${getPlayerMagnetLabel(receiver)}` : "";
  const teamName = teams[choice.teamId]?.name ?? "Team";
  const styleText = choice.styleLabel ? ` in ${choice.styleLabel}` : "";
  const principleText = choice.principleLabels?.length
    ? ` Principle: ${choice.principleLabels.join(" + ")}.`
    : "";
  return `${teamName} auto play chooses ${choice.label}${receiverText} from ${choice.formation} ${choice.phaseLabel.toLowerCase()}${styleText} to ${choice.reason}.${principleText}`;
}

function planAutoPilotNextAction({ startImmediately = true } = {}) {
  if (!state.offensiveAutopilot || state.isRunning || state.sequence.isPlaying) {
    return false;
  }

  if (hasBallAction() || state.draftStep) {
    if (startImmediately) {
      executePlannedAction();
    }
    return true;
  }

  const possessionPlayer = getAutoPilotPossessionPlayer();
  if (!possessionPlayer) {
    const recovery = chooseAutoPilotLooseBallRecovery();
    if (recovery && issueLooseBallRecoveryCommand(recovery)) {
      if (startImmediately) {
        executePlannedAction();
      }
      return true;
    }
  }

  const choice = chooseAutoPilotNextAction();
  if (!choice) {
    state.autoPilotPlay.active = false;
    logEvent("Auto play paused: no stable attacking action was available.");
    updateSequenceButtons();
    render();
    return false;
  }

  clearKeyboardActionGrace();
  state.actionMode = null;
  if (choice.actionType === "shot") {
    issueShotCommand(choice.target);
  } else if (choice.actionType === "dribble") {
    issueDribbleCommand(choice.target);
  } else {
    issuePassCommand(choice.target, choice.receiverPlayerId ?? null);
  }

  if (!state.draftStep) {
    state.autoPilotPlay.active = false;
    updateSequenceButtons();
    render();
    return false;
  }

  state.draftStep.autoGenerated = true;
  state.draftStep.autoReason = choice.reason;
  state.draftStep.autoPrinciples = [...(choice.principleLabels ?? [])];
  state.draftStep.principleRunnerPlayerId = choice.principleRunnerPlayerId ?? null;
  if (choice.firstTouchMode && choice.actionType === "pass") {
    state.draftStep.firstTouchMode = choice.firstTouchMode;
    state.ball.firstTouchMode = choice.firstTouchMode;
  }
  if (state.draftStep.principleRunnerPlayerId || state.draftStep.autoPrinciples.length) {
    applyAutopilotsForCurrentAction({ silent: true });
  }
  logEvent(describeAutoPilotChoice(choice));

  if (startImmediately) {
    executePlannedAction();
  }

  return true;
}

function cancelAutoPilotContinuation() {
  if (state.autoPilotPlay?.nextActionTimeoutId) {
    window.clearTimeout(state.autoPilotPlay.nextActionTimeoutId);
    state.autoPilotPlay.nextActionTimeoutId = null;
  }
}

function pauseAutoPilotPlay(message = "Auto play paused.") {
  cancelAutoPilotContinuation();
  if (state.autoPilotPlay) {
    state.autoPilotPlay.active = false;
  }
  if (state.isRunning) {
    pauseLiveSimulation(message);
    return;
  }
  logEvent(message);
  updateSequenceButtons();
  render();
}

function getAutoPilotContinuationContext(actionType = state.ball.actionType) {
  const carrier = getAutoPilotPossessionPlayer();
  if (!carrier) {
    return {
      carrier: null,
      profile: null,
      flow: null,
      momentum: null,
      pressure: 0,
      firstTouchMode: null,
      justReceived: false,
      depth: 0,
      threat: getPitchThreatProfile(state.ball.position, defaultKickoffTeamId),
    };
  }

  const startPoint = cloneVector(getPlayerBallControlPoint(carrier));
  const profile = getOffensiveAutopilotProfile(carrier.team, startPoint);
  const flow = getAutoPilotFlowContext(carrier, startPoint);
  const momentum = getAutoPilotReceiveMomentum(carrier, startPoint);

  return {
    carrier,
    profile,
    flow,
    momentum,
    pressure: getPlayerPressureLoad(carrier, startPoint),
    firstTouchMode: momentum?.mode ?? (actionType === "pass" ? state.ball.firstTouchMode : null),
    justReceived: !!flow.carrierJustReceived || !!momentum,
    depth: getAttackingDepth(startPoint, carrier.team),
    threat: getPitchThreatProfile(startPoint, carrier.team),
  };
}

function getAutoPilotContinuationDelay(actionType = state.ball.actionType) {
  const context = getAutoPilotContinuationContext(actionType);
  const profile = context.profile;
  const tempo = profile?.tempo ?? 0.55;
  const pressure = context.pressure ?? 0;
  const touchMode = context.firstTouchMode ?? "auto";
  const highTempo = tempo >= 0.68 || profile?.styleKey === "gegenpress" || profile?.styleKey === "vertical-play";
  const finalThirdUrgency = context.depth >= 70 || context.threat?.box >= 0.22 || context.threat?.centralPocket >= 0.42;
  const base =
    actionType === "dribble"
      ? 105
      : actionType === "shot"
        ? 185
        : actionType === "recovery"
          ? 170
          : 145;
  const touchDelay =
    touchMode === "kill"
      ? 170
      : touchMode === "back"
        ? 140
        : touchMode === "inside" || touchMode === "across"
          ? 92
          : touchMode === "forward"
            ? 58
            : 88;
  const pressureAdjustment =
    pressure >= 0.68
      ? -58
      : pressure >= 0.5
        ? -28
        : pressure <= 0.24
          ? 84
          : 22;
  const styleAdjustment =
    highTempo
      ? -48
      : profile?.shortSupport >= 0.72
        ? 38
        : profile?.directness <= 0.44
          ? 58
          : 0;
  const receiveAdjustment = context.justReceived ? touchDelay : 0;
  const finalThirdAdjustment = finalThirdUrgency ? -34 : 0;
  const variation = randomBetween(-26, 42);

  return clamp(
    Math.round(base + receiveAdjustment + pressureAdjustment + styleAdjustment + finalThirdAdjustment + variation),
    highTempo ? 90 : 125,
    profile?.styleKey === "control-possession" || profile?.styleKey === "tiki-taka" ? 560 : 430
  );
}

function scheduleAutoPilotContinuation(delayMs = null, actionType = state.ball.actionType) {
  if (!state.autoPilotPlay?.active || !state.offensiveAutopilot) {
    return;
  }

  cancelAutoPilotContinuation();
  const resolvedDelay = delayMs ?? getAutoPilotContinuationDelay(actionType);
  state.autoPilotPlay.nextActionTimeoutId = window.setTimeout(() => {
    state.autoPilotPlay.nextActionTimeoutId = null;
    if (
      !state.autoPilotPlay.active ||
      !state.offensiveAutopilot ||
      state.isRunning ||
      state.sequence.isPlaying ||
      hasBallAction() ||
      state.draftStep
    ) {
      return;
    }

    planAutoPilotNextAction({ startImmediately: true });
  }, resolvedDelay);
}

function refreshPlannedBallActionProfile() {
  if (!state.draftStep || !hasBallAction() || state.isRunning || state.sequence.isPlaying) {
    return;
  }

  const actionType = state.draftStep.actionType;
  const target = cloneVector(state.ball.target);
  const startPoint = cloneVector(state.ball.startPosition);
  const initiator = getPlayerById(state.draftStep.beforeSnapshot?.ball?.ownerPlayerId);
  const resolvedProfile = resolveBallActionProfile(
    actionType,
    startPoint,
    target,
    initiator,
    state.draftStep.receiverPlayerId ?? null
  );

  state.draftStep.speed = resolvedProfile.averageSpeed;
  state.draftStep.speedMode = resolvedProfile.source;
  state.draftStep.profileKey = resolvedProfile.key;
  state.draftStep.profileLabel = resolvedProfile.label;
  state.draftStep.targetKind = resolvedProfile.targetKind;
  if (actionType === "pass") {
    state.draftStep.firstTouchMode = state.firstTouchMode;
    state.ball.firstTouchMode = state.firstTouchMode;
  }

  applyResolvedBallProfile(resolvedProfile);
  applyBallExecutionProfile(actionType, initiator, target, resolvedProfile);
  configureBallTravelProfile(
    actionType,
    distance(startPoint, target),
    getActionSpeed(),
    resolvedProfile
  );
}

function clearBallAction() {
  state.ball.startPosition = cloneVector(state.ball.position);
  state.ball.target = cloneVector(state.ball.position);
  state.ball.currentSpeed = 0;
  state.ball.launchSpeed = 0;
  state.ball.finalSpeed = 0;
  state.ball.deceleration = 0;
  state.ball.profileKey = null;
  state.ball.profileLabel = null;
  state.ball.profileMode = state.ballSpeedMode;
  state.ball.targetKind = null;
  state.ball.firstTouchMode = state.firstTouchMode;
  state.ball.flightStyle = "ground";
  state.ball.peakHeight = 0;
  state.ball.height = 0;
  state.ball.controlHeightThreshold = 0.12;
  state.ball.landingPhaseStart = 0.58;
  state.ball.curveAmount = 0;
  state.ball.curveDirection = 1;
  state.ball.spinRate = 0;
  state.ball.spinAngle = 0;
  state.ball.trackDistanceTotal = 0;
  state.ball.trackDistanceCovered = 0;
  state.ball.dribblePath = null;
  state.ball.bounceCount = 0;
  state.ball.inTransit = false;
  state.ball.elapsedTravelTime = 0;
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.laneClarity = 0.84;
  state.ball.executionQuality = 0.84;
  state.ball.shotPlacement = null;
  state.ball.claimRadius = 2.2;
  state.ball.controlRadius = 1.4;
  state.ball.carrierPlayerId = null;
  state.ball.receiverPlayerId = null;
  state.ball.recoveryDuration = 0;
  state.ball.secondBallContext = null;
  state.activeActionTargets = null;
  state.sequence.actionTargets = null;
  state.draftStep = null;
  state.players.forEach((player) => {
    player.actionOrigin = null;
  });
  resetPlayerMovementProgress();
}

function setBallOwner(playerId) {
  if (!canEditScenario()) {
    return;
  }

  const player = getPlayerById(playerId);
  if (!player) {
    return;
  }

  rotatePlayerBodyToward(player, {
    x: player.position.x + Math.cos(getTeamAttackAngle(player.team)) * 4,
    y: player.position.y,
  });
  clearBallAction();
  clearAutoPilotReceiveMomentum();
  clearSecurePossession();
  state.ball.ownerPlayerId = player.id;
  const controlPoint = getPlayerBallControlPoint(player);
  state.ball.position = cloneVector(controlPoint);
  state.ball.startPosition = cloneVector(controlPoint);
  state.ball.target = cloneVector(controlPoint);
  state.ball.receiverPlayerId = null;
  logEvent(`${player.shortLabel} ${player.role} is now the ball carrier.`);
}

function issuePassLikeCommand(actionType, targetPoint, receiverPlayerId = null) {
  const receiver = receiverPlayerId ? getPlayerById(receiverPlayerId) : null;
  const initiator = getBallOwner() ?? getSelectedPlayer();
  if (actionType === "pass" && receiver) {
    const passStartPoint = initiator ? getPlayerBallControlPoint(initiator) : state.ball.position;
    const offsideInfo = getOffsideInfo(receiver, passStartPoint);
    if (offsideInfo.isOffside) {
      clearBallAction();
      logEvent(`Offside: ${offsideInfo.reason}`);
      render();
      return;
    }
  }

  if (state.ball.securePossession && state.ball.securePossession.ownerPlayerId !== initiator?.id) {
    clearSecurePossession();
  }
  if (actionType === "pass" && receiver) {
    const incomingPoint = initiator ? getPlayerBallControlPoint(initiator) : state.ball.position;
    applyBestReceiveBodyAngle(receiver, incomingPoint, 0.9);
  }
  const target = receiver
    ? getPlayerBallControlPoint(receiver)
    : actionType === "shot"
      ? resolveShotTarget(targetPoint, initiator)
      : clampToPitch(targetPoint);
  const travelDistance = distance(state.ball.position, target);
  const isShot = actionType === "shot";
  const label = isShot ? "Shot target" : "Ball target";

  if (travelDistance <= 0.05) {
    clearBallAction();
    logEvent(`${label} was cleared because the start point and target were the same.`);
    return;
  }

  const resolvedProfile = resolveBallActionProfile(
    actionType,
    state.ball.position,
    target,
    initiator,
    receiver?.id ?? null
  );

  const startSnapshot = captureSnapshot();
  state.draftStep = {
    actionType,
    target: cloneVector(target),
    speed: resolvedProfile.averageSpeed,
    speedMode: resolvedProfile.source,
    profileKey: resolvedProfile.key,
    profileLabel: resolvedProfile.label,
    targetKind: resolvedProfile.targetKind,
    firstTouchMode: !isShot ? state.firstTouchMode : null,
    receiverPlayerId: !isShot ? receiver?.id ?? null : null,
    beforeSnapshot: startSnapshot,
  };

  state.ball.startPosition = cloneVector(state.ball.position);
  state.ball.target = target;
  state.ball.inTransit = true;
  state.ball.elapsedTravelTime = 0;
  state.ball.actionType = actionType;
  state.ball.initiatorPlayerId = initiator?.id ?? null;
  state.ball.carrierPlayerId = null;
  state.ball.receiverPlayerId = !isShot ? receiver?.id ?? null : null;
  state.ball.firstTouchMode = !isShot ? state.firstTouchMode : null;
  state.ball.ownerPlayerId = null;
  applyResolvedBallProfile(resolvedProfile);
  applyBallExecutionProfile(actionType, initiator, target, resolvedProfile);
  configureBallTravelProfile(actionType, travelDistance, getActionSpeed(), resolvedProfile);
  state.players.forEach((player) => {
    player.actionOrigin = cloneVector(player.position);
  });
  if (initiator) {
    rotatePlayerBodyToward(initiator, target, 0.8);
    const launchPoint = getPlayerBallControlPoint(initiator);
    state.ball.position = cloneVector(launchPoint);
    state.ball.startPosition = cloneVector(launchPoint);
  }

  applyAutopilotsForCurrentAction();

  if (!isShot && receiver) {
    logEvent(
      `New pass planned: ${resolvedProfile.label} at ${formatSpeed(resolvedProfile.averageSpeed)} to ${receiver.shortLabel} ${receiver.role}.`
    );
  } else if (isShot) {
    logEvent(
      `New shot planned: ${resolvedProfile.label} at ${formatSpeed(resolvedProfile.averageSpeed)} to x ${target.x.toFixed(1)}, y ${target.y.toFixed(1)}.`
    );
  } else {
    logEvent(
      `New pass planned: ${resolvedProfile.label} at ${formatSpeed(resolvedProfile.averageSpeed)} to x ${target.x.toFixed(1)}, y ${target.y.toFixed(1)}.`
    );
  }
}

function issuePassCommand(targetPoint, receiverPlayerId = null) {
  issuePassLikeCommand("pass", targetPoint, receiverPlayerId);
}

function issueShotCommand(targetPoint) {
  issuePassLikeCommand("shot", targetPoint);
}

function issueDribbleCommand(targetPoint) {
  const owner = getBallOwner();
  const carrier = owner ?? getSelectedPlayer();
  if (!carrier) {
    logEvent("Select a player or set a ball carrier before planning a dribble.");
    return;
  }

  if (!owner && distance(state.ball.position, carrier.position) > 2.5) {
    logEvent("Set the selected player as ball carrier before planning a dribble.");
    return;
  }

  if (state.ball.securePossession && state.ball.securePossession.ownerPlayerId !== carrier.id) {
    clearSecurePossession();
  }

  const target = clampToPitch(targetPoint);
  const resolvedProfile = resolveBallActionProfile(
    "dribble",
    getPlayerBallControlPoint(carrier),
    target,
    carrier
  );
  const startSnapshot = captureSnapshot();
  startSnapshot.ball.position = cloneVector(getPlayerBallControlPoint(carrier));
  startSnapshot.ball.ownerPlayerId = carrier.id;
  state.draftStep = {
    actionType: "dribble",
    target: cloneVector(target),
    speed: resolvedProfile.averageSpeed,
    speedMode: resolvedProfile.source,
    profileKey: resolvedProfile.key,
    profileLabel: resolvedProfile.label,
    targetKind: resolvedProfile.targetKind,
    carrierPlayerId: carrier.id,
    beforeSnapshot: startSnapshot,
  };

  state.ball.ownerPlayerId = carrier.id;
  state.ball.position = cloneVector(getPlayerBallControlPoint(carrier));

  const travelDistance = distance(carrier.position, target);
  if (travelDistance <= 0.05) {
    clearBallAction();
    state.ball.ownerPlayerId = carrier.id;
    state.ball.position = cloneVector(getPlayerBallControlPoint(carrier));
    logEvent("The dribble was cleared because the start point and target were the same.");
    return;
  }

  state.ball.startPosition = cloneVector(getPlayerBallControlPoint(carrier));
  state.ball.target = target;
  state.ball.inTransit = true;
  state.ball.elapsedTravelTime = 0;
  state.ball.actionType = "dribble";
  state.ball.initiatorPlayerId = carrier.id;
  state.ball.carrierPlayerId = carrier.id;
  state.ball.receiverPlayerId = null;
  applyResolvedBallProfile(resolvedProfile);
  applyBallExecutionProfile("dribble", carrier, target, resolvedProfile);
  configureBallTravelProfile("dribble", travelDistance, getActionSpeed(), resolvedProfile);
  state.players.forEach((player) => {
    player.actionOrigin = cloneVector(player.position);
  });
  setDribbleCarryPathForBall(carrier, carrier.position, target);
  rotatePlayerBodyToward(carrier, target, 0.92);
  const carrierControlPoint = getPlayerBallControlPoint(carrier);
  state.ball.position = cloneVector(carrierControlPoint);
  state.ball.startPosition = cloneVector(carrierControlPoint);

  applyAutopilotsForCurrentAction();

  logEvent(
    `${carrier.shortLabel} ${carrier.role} dribbles toward x ${target.x.toFixed(1)}, y ${target.y.toFixed(1)} at ${formatSpeed(resolvedProfile.averageSpeed)}.`
  );
}

function issueBallCommand(targetPoint, forcedMode = null) {
  const actionMode = forcedMode ?? getRequestedActionMode();

  if (actionMode === null) {
    logEvent("Hold P, D or S, or arm a mode button, before placing a ball action.");
    return;
  }

  if (actionMode === "dribble") {
    issueDribbleCommand(targetPoint);
    return;
  }

  if (actionMode === "shot") {
    issueShotCommand(targetPoint);
    return;
  }

  issuePassCommand(targetPoint);
}

function detectShotGoal(previousPosition, currentPosition) {
  if (state.ball.actionType !== "shot") {
    return null;
  }

  const shooter =
    getPlayerById(state.ball.initiatorPlayerId) ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId);
  const scoringTeamId = shooter?.team ?? getPlannedPossessionTeamId();
  if (!scoringTeamId) {
    return null;
  }

  const side = getOpponentGoalSide(scoringTeamId);
  const sign = getGoalDirectionSign(side);
  const goalLineX = getGoalLineX(side);
  const previousSideValue = (previousPosition.x - goalLineX) * sign;
  const currentSideValue = (currentPosition.x - goalLineX) * sign;
  const targetSideValue = (state.ball.target.x - goalLineX) * sign;
  const crossedGoalLine =
    previousSideValue < -0.01 &&
    (currentSideValue >= -0.01 || targetSideValue > 0);

  if (!crossedGoalLine) {
    return null;
  }

  const segmentX = currentPosition.x - previousPosition.x;
  const ratio = Math.abs(segmentX) <= 0.001
    ? 1
    : clamp((goalLineX - previousPosition.x) / segmentX, 0, 1);
  const goalY = lerp(previousPosition.y, currentPosition.y, ratio);
  if (!isBetweenGoalPosts(goalY, ballRadiusMeters * 0.85)) {
    return null;
  }

  return {
    scoringTeamId,
    concedingTeamId: getOtherTeamId(scoringTeamId),
    side,
    scoredAt: state.time,
    point: { x: goalLineX, y: goalY },
    displayPoint: getGoalNetDisplayPoint(side, goalY),
  };
}

function detectShotOutOfPlay(previousPosition, currentPosition) {
  if (state.ball.actionType !== "shot") {
    return null;
  }

  const shooter =
    getPlayerById(state.ball.initiatorPlayerId) ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId);
  const shootingTeamId = shooter?.team ?? getPlannedPossessionTeamId();
  if (!shootingTeamId) {
    return null;
  }

  const side = getOpponentGoalSide(shootingTeamId);
  const sign = getGoalDirectionSign(side);
  const goalLineX = getGoalLineX(side);
  const previousSideValue = (previousPosition.x - goalLineX) * sign;
  const currentSideValue = (currentPosition.x - goalLineX) * sign;
  const targetSideValue = (state.ball.target.x - goalLineX) * sign;
  const crossedGoalLine =
    previousSideValue < -0.01 &&
    (currentSideValue >= -0.01 || targetSideValue > 0);

  if (!crossedGoalLine) {
    return null;
  }

  const segmentX = currentPosition.x - previousPosition.x;
  const ratio = Math.abs(segmentX) <= 0.001
    ? 1
    : clamp((goalLineX - previousPosition.x) / segmentX, 0, 1);
  const outY = clamp(lerp(previousPosition.y, currentPosition.y, ratio), 0, pitch.width);
  if (isBetweenGoalPosts(outY, ballRadiusMeters * 0.85)) {
    return null;
  }

  return {
    type: "goalKick",
    shootingTeamId,
    restartTeamId: getOtherTeamId(shootingTeamId),
    side,
    occurredAt: state.time,
    point: { x: goalLineX, y: outY },
    displayPoint: {
      x: goalLineX - sign * 0.45,
      y: outY,
    },
  };
}

function detectTouchlineOutOfPlay(previousPosition, currentPosition) {
  const actionType = state.ball.actionType;
  if (actionType !== "pass" && actionType !== "shot") {
    return null;
  }

  const crossedTop =
    previousPosition.y >= 0 &&
    currentPosition.y < 0;
  const crossedBottom =
    previousPosition.y <= pitch.width &&
    currentPosition.y > pitch.width;

  if (!crossedTop && !crossedBottom) {
    return null;
  }

  const touchlineY = crossedTop ? 0 : pitch.width;
  const segmentY = currentPosition.y - previousPosition.y;
  const ratio = Math.abs(segmentY) <= 0.001
    ? 1
    : clamp((touchlineY - previousPosition.y) / segmentY, 0, 1);
  const outX = clamp(lerp(previousPosition.x, currentPosition.x, ratio), 0, pitch.length);
  const initiator =
    getPlayerById(state.ball.initiatorPlayerId) ??
    getPlayerById(state.draftStep?.beforeSnapshot?.ball?.ownerPlayerId) ??
    getActionInitiator();
  const lastTouchTeamId = initiator?.team ?? getPlannedPossessionTeamId();

  if (!lastTouchTeamId) {
    return null;
  }

  return {
    type: "throwIn",
    lastTouchTeamId,
    restartTeamId: getOtherTeamId(lastTouchTeamId),
    sideY: touchlineY,
    occurredAt: state.time,
    point: { x: outX, y: touchlineY },
    displayPoint: {
      x: outX,
      y: touchlineY === 0 ? -0.45 : pitch.width + 0.45,
    },
  };
}

function getGoalkeeperForTeam(teamId) {
  return state.players.find((player) => player.team === teamId && isGoalkeeper(player)) ?? null;
}

function getPreferredParrySafetyPlayer(teamId, spillPoint, goalkeeperId) {
  if (!teamId || !spillPoint) {
    return null;
  }

  const safetyRoles = new Set(["CB", "LB", "RB", "WB", "6"]);
  let bestCandidate = null;

  state.players.forEach((player) => {
    if (player.team !== teamId || player.id === goalkeeperId || isGoalkeeper(player)) {
      return;
    }

    const label = getPlayerMagnetLabel(player);
    const context = getPlayerDecisionContext(player);
    const gap = distance(player.position, spillPoint);
    const timeToBall = computeTimeToCoverDistance(player, gap, spillPoint);
    const safetyRoleBonus = safetyRoles.has(label) ? 0.42 : label === "8" ? 0.16 : 0;
    const boxProtectionBonus = isInsideOwnBox(spillPoint, teamId) && safetyRoles.has(label) ? 0.18 : 0;
    const score =
      safetyRoleBonus +
      boxProtectionBonus +
      context.profile.perception * 0.2 +
      context.profile.tacticalDiscipline * 0.22 +
      context.profile.composure * 0.16 -
      timeToBall * 0.22 -
      gap * 0.018;

    if (!bestCandidate || score > bestCandidate.score) {
      bestCandidate = { player, score };
    }
  });

  return bestCandidate?.player ?? null;
}

function getGoalkeeperParryProfile(goalInfo, savePoint, goalkeeper, metrics) {
  const goalSign = getGoalDirectionSign(goalInfo.side);
  const parrySide =
    Math.sign(goalInfo.point.y - pitch.width / 2) ||
    (goalkeeper.position.y >= pitch.width / 2 ? 1 : -1);
  const control = clamp(
    metrics.saveScore * 0.46 +
      metrics.catchScore * 0.24 +
      metrics.access * 0.16 +
      metrics.reading * 0.18 -
      metrics.closeRange * 0.22 -
      metrics.shotPower * 0.12,
    0,
    1
  );
  const lateralWeight = lerp(0.34, 1.22, control) + metrics.cornerReach * 0.2;
  const awayWeight = clamp(
    lerp(0.58, 1.46, control) - metrics.closeRange * 0.16,
    0.42,
    1.55
  );
  const angle = Math.atan2(parrySide * lateralWeight, -goalSign * awayWeight);
  const distanceMeters = clamp(
    2.1 +
      metrics.shotPower * 3.8 +
      metrics.cornerReach * 0.9 +
      control * 2.4 -
      metrics.closeRange * 1.15,
    1.8,
    9.4
  );
  const spillPoint = clampToPitch({
    x: savePoint.x + Math.cos(angle) * distanceMeters,
    y: savePoint.y + Math.sin(angle) * distanceMeters,
  }, 0.75);
  const penaltySpot = getOpponentPenaltySpot(goalInfo.scoringTeamId);
  const centralDanger =
    clamp(1 - Math.abs(spillPoint.y - pitch.width / 2) / 10, 0, 1) *
    clamp(1 - distance(spillPoint, penaltySpot) / 15, 0, 1);
  const safeParry = control >= 0.58 && centralDanger <= 0.45;

  return {
    angle,
    distanceMeters,
    spillPoint,
    control,
    centralDanger,
    safeParry,
    label: safeParry ? "safe parry" : centralDanger >= 0.55 ? "danger rebound" : "parry",
    urgency: clamp(
      0.72 +
        metrics.shotPower * 0.14 +
        metrics.closeRange * 0.14 +
        centralDanger * 0.12 -
        control * 0.26,
      safeParry ? 0.42 : 0.58,
      0.92
    ),
  };
}

function resolveGoalkeeperSave(goalInfo, previousPosition) {
  const goalkeeper = getGoalkeeperForTeam(goalInfo?.concedingTeamId);
  if (!goalkeeper || !goalInfo?.point) {
    return null;
  }

  const goalSign = getGoalDirectionSign(goalInfo.side);
  const savePoint = clampToPitch({
    x: goalInfo.point.x - goalSign * 0.9,
    y: goalInfo.point.y,
  }, 0.25);
  const shotStart = state.ball.startPosition ?? previousPosition;
  const shotDistance = distance(shotStart, goalInfo.point);
  const shotSpeed = Math.max(state.ball.currentSpeed || state.ball.launchSpeed || state.ball.speed || 0, 0.1);
  const shotPower = clamp((shotSpeed - 9.5) / 17, 0, 1);
  const shotQuality = clamp(state.ball.executionQuality ?? 0.72, 0.35, 0.98);
  const cornerReach = clamp(Math.abs(goalInfo.point.y - pitch.width / 2) / (7.32 / 2), 0, 1.15);
  const closeRange = clamp((23 - shotDistance) / 18, 0, 1);
  const context = getPlayerDecisionContext(goalkeeper);
  const distanceToSave = distance(goalkeeper.position, savePoint);
  const diveReach =
    1.35 +
    context.profile.perception * 0.45 +
    context.profile.decisionSpeed * 0.34 +
    context.profile.composure * 0.26 +
    clamp(context.maxSpeed / 8, 0, 1) * 0.42;
  const movementDistance = Math.max(distanceToSave - diveReach, 0);
  const saveTime = computeTimeToCoverDistance(goalkeeper, movementDistance, savePoint);
  const availableTime = Math.max(state.ball.elapsedTravelTime, 0.05);
  const access = clamp((availableTime - saveTime + 0.18) / 0.82, 0, 1);
  const positioning = clamp(1 - distanceToSave / 9.8, 0, 1);
  const reading =
    context.profile.perception * 0.24 +
    context.profile.decisionSpeed * 0.2 +
    context.profile.decisionQuality * 0.18 +
    context.profile.composure * 0.18 +
    context.profile.technicalSecurity * 0.12 +
    clamp(context.maxSpeed / 8, 0, 1) * 0.08;
  const difficulty =
    shotPower * 0.28 +
    shotQuality * 0.22 +
    cornerReach * 0.36 +
    closeRange * 0.26 +
    (state.ball.flightStyle === "driven" ? 0.08 : 0);
  const saveScore = access * 0.48 + reading * 0.36 + positioning * 0.24 - difficulty * 0.42;
  const catchScore =
    saveScore +
    context.profile.technicalSecurity * 0.2 +
    context.profile.composure * 0.16 -
    shotPower * 0.32 -
    cornerReach * 0.18 -
    closeRange * 0.1;
  const saveThreshold = closeRange > 0.68 ? 0.5 : cornerReach > 0.92 ? 0.48 : 0.38;

  if (saveScore < saveThreshold) {
    return null;
  }

  rotatePlayerBodyToward(goalkeeper, savePoint, 0.9);
  goalkeeper.position = clampToPitch({
    x: lerp(goalkeeper.position.x, savePoint.x, clamp(access * 0.72, 0.22, 0.88)),
    y: lerp(goalkeeper.position.y, savePoint.y, clamp(access * 0.86, 0.3, 0.94)),
  }, 0.8);

  if (catchScore >= 0.52 && shotPower <= 0.72 && closeRange <= 0.74) {
    connectBallToPlayerForNextAction(goalkeeper, savePoint, 0.92);
    clearSecurePossession();
    return {
      kind: "catch",
      goalkeeper,
      point: cloneVector(savePoint),
      saveScore,
    };
  }

  const parrySide = Math.sign(goalInfo.point.y - pitch.width / 2) || (goalkeeper.position.y >= pitch.width / 2 ? 1 : -1);
  const parryDistance = clamp(3.4 + shotPower * 4.2 + cornerReach * 1.2 - catchScore * 0.8, 2.4, 8.6);
  const shouldParryBehindForCorner =
    (cornerReach >= 0.78 && shotPower >= 0.42 && catchScore < 0.48) ||
    (cornerReach >= 0.94 && catchScore < 0.58) ||
    (closeRange >= 0.62 && cornerReach >= 0.72 && catchScore < 0.42);

  if (shouldParryBehindForCorner) {
    clearSecurePossession();
    state.ball.ownerPlayerId = null;
    const displayY = clamp(
      goalInfo.point.y + parrySide * clamp(1.05 + parryDistance * 0.18, 1.05, 2.4),
      0,
      pitch.width
    );
    return {
      kind: "corner",
      goalkeeper,
      point: {
        x: goalInfo.point.x - goalSign * 0.35,
        y: displayY,
      },
      displayPoint: {
        x: goalInfo.point.x - goalSign * 0.35,
        y: displayY,
      },
      restartTeamId: goalInfo.scoringTeamId,
      sideY: displayY <= pitch.width / 2 ? 0 : pitch.width,
      saveScore,
    };
  }

  const parryProfile = getGoalkeeperParryProfile(goalInfo, savePoint, goalkeeper, {
    saveScore,
    catchScore,
    access,
    reading,
    shotPower,
    closeRange,
    cornerReach,
  });
  const preferredSafetyPlayer = parryProfile.safeParry
    ? getPreferredParrySafetyPlayer(goalInfo.concedingTeamId, parryProfile.spillPoint, goalkeeper.id)
    : null;
  const spill = createLooseBallSpill(
    savePoint,
    parryProfile.angle,
    parryProfile.distanceMeters,
    preferredSafetyPlayer?.id ?? null,
    preferredSafetyPlayer ? 0.08 + parryProfile.control * 0.08 : -0.02,
    {
      canClaimPlayer: (player) => player.id !== goalkeeper.id,
      source: parryProfile.safeParry ? "goalkeeper-safe-parry" : "goalkeeper-danger-parry",
      reboundType: parryProfile.label,
      attackingTeamId: goalInfo.scoringTeamId,
      defendingTeamId: goalInfo.concedingTeamId,
      urgency: parryProfile.urgency,
      preferredTeamId: parryProfile.safeParry ? goalInfo.concedingTeamId : goalInfo.scoringTeamId,
    }
  );

  return {
    kind: "parry",
    goalkeeper,
    point: spill.spillPoint,
    winner: spill.winner,
    saveScore,
    saveControl: parryProfile.control,
    label: parryProfile.label,
  };
}

function registerGoalFlash(goalInfo) {
  const scoringTeamName = teams[goalInfo.scoringTeamId]?.name ?? "Team";
  state.goalFlash = {
    ...cloneGoalEvent(goalInfo),
    scoringTeamName,
    createdAtMs: Date.now(),
    expiresAtMs: Date.now() + 2600,
  };
}

function completeGoalkeeperSave(saveOutcome, completedTravelTime) {
  const savedGoalkeeperPosition = cloneVector(saveOutcome.goalkeeper.position);
  const isCornerRestart = saveOutcome.kind === "corner";
  const savedBallPosition = isCornerRestart
    ? cloneVector(saveOutcome.displayPoint ?? saveOutcome.point)
    : cloneVector(state.ball.position);
  const savedBallTarget = cloneVector(savedBallPosition);
  const savedBallOwnerId = isCornerRestart ? null : state.ball.ownerPlayerId ?? null;
  state.ball.inTransit = false;
  state.ball.height = 0;

  if (state.sequence.isPlaying) {
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step) {
      const afterSnapshot = cloneSnapshot(captureSnapshot());
      step.afterSnapshot = afterSnapshot;
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    if (isCornerRestart) {
      logEvent(
        `${saveOutcome.goalkeeper.shortLabel} ${saveOutcome.goalkeeper.role} saves and turns the shot behind for a corner after ${formatTime(completedTravelTime)}.`
      );
    } else {
      const saveAction = saveOutcome.kind === "catch"
        ? "catches"
        : saveOutcome.label === "safe parry"
          ? "saves and pushes away"
          : "saves and parries";
      logEvent(
        `${saveOutcome.goalkeeper.shortLabel} ${saveOutcome.goalkeeper.role} ${saveAction} the shot after ${formatTime(completedTravelTime)}.`
      );
    }
    queueNextSequenceStep();
    return;
  }

  completeLiveActionPlayersBeforeCommit(saveOutcome.point);
  saveOutcome.goalkeeper.position = savedGoalkeeperPosition;
  state.ball.position = savedBallPosition;
  state.ball.target = savedBallTarget;
  state.ball.ownerPlayerId = savedBallOwnerId;
  if (isCornerRestart && state.draftStep) {
    state.draftStep.nextRestartPhase = {
      type: "corner",
      teamId: saveOutcome.restartTeamId,
      label: setPiecePhaseProfiles.corner.label,
      sideY: saveOutcome.sideY,
    };
    state.draftStep.target = cloneVector(saveOutcome.point);
  }
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.receiverPlayerId = null;
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  if (isCornerRestart) {
    logEvent(
      `${saveOutcome.goalkeeper.shortLabel} ${saveOutcome.goalkeeper.role} saves and turns the shot behind for a corner after ${formatTime(completedTravelTime)}.`
    );
  } else {
    const saveAction = saveOutcome.kind === "catch"
      ? "catches"
      : saveOutcome.label === "safe parry"
        ? "saves and pushes away"
        : "saves and parries";
    logEvent(
      `${saveOutcome.goalkeeper.shortLabel} ${saveOutcome.goalkeeper.role} ${saveAction} the shot after ${formatTime(completedTravelTime)}.`
    );
  }
  scheduleAutoPilotContinuation(null, "shot");
}

function completeShotGoal(goalInfo, completedTravelTime) {
  registerGoalFlash(goalInfo);
  state.ball.position = cloneVector(goalInfo.displayPoint ?? goalInfo.point);
  state.ball.target = cloneVector(state.ball.position);
  state.ball.height = 0;
  state.ball.inTransit = false;

  if (state.sequence.isPlaying) {
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.afterSnapshot) {
      applyCommittedSnapshot(step.afterSnapshot);
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    logEvent(
      `GOAL: ${teams[goalInfo.scoringTeamId]?.name ?? "Team"} scores. ${teams[goalInfo.concedingTeamId]?.name ?? "Opponent"} restart with kick-off.`
    );
    queueNextSequenceStep();
    return;
  }

  completeLiveActionPlayersBeforeCommit(goalInfo.point);
  if (state.draftStep) {
    state.draftStep.goal = cloneGoalEvent(goalInfo);
    state.draftStep.target = cloneVector(goalInfo.point);
  }
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.receiverPlayerId = null;
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(
    `GOAL: ${teams[goalInfo.scoringTeamId]?.name ?? "Team"} scores after ${formatTime(completedTravelTime)}. ${teams[goalInfo.concedingTeamId]?.name ?? "Opponent"} restart with kick-off.`
  );
  scheduleAutoPilotContinuation(null, "shot");
}

function completeShotOutOfPlay(outInfo, completedTravelTime) {
  const displayPoint = outInfo.displayPoint ?? outInfo.point;
  const restartTeamName = teams[outInfo.restartTeamId]?.name ?? "Defending team";
  state.ball.position = cloneVector(displayPoint);
  state.ball.target = cloneVector(displayPoint);
  state.ball.height = 0;
  state.ball.inTransit = false;

  if (state.sequence.isPlaying) {
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.afterSnapshot) {
      applyCommittedSnapshot(step.afterSnapshot);
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    logEvent(`Shot misses after ${formatTime(completedTravelTime)}. ${restartTeamName} restart with a goal-kick.`);
    queueNextSequenceStep();
    return;
  }

  completeLiveActionPlayersBeforeCommit(outInfo.point);
  if (state.draftStep) {
    state.draftStep.nextRestartPhase = {
      type: "goalKick",
      teamId: outInfo.restartTeamId,
      label: setPiecePhaseProfiles.goalKick.label,
    };
    state.draftStep.target = cloneVector(outInfo.point);
  }
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.receiverPlayerId = null;
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(`Shot misses after ${formatTime(completedTravelTime)}. ${restartTeamName} restart with a goal-kick.`);
  scheduleAutoPilotContinuation(null, "shot");
}

function completeTouchlineOutOfPlay(outInfo, completedTravelTime) {
  const displayPoint = outInfo.displayPoint ?? outInfo.point;
  const restartTeamName = teams[outInfo.restartTeamId]?.name ?? "Restart team";
  const actionLabel = state.ball.actionType === "shot" ? "Shot" : "Pass";
  state.ball.position = cloneVector(displayPoint);
  state.ball.target = cloneVector(displayPoint);
  state.ball.height = 0;
  state.ball.inTransit = false;

  if (state.sequence.isPlaying) {
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.afterSnapshot) {
      applyCommittedSnapshot(step.afterSnapshot);
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    logEvent(`${actionLabel} goes out after ${formatTime(completedTravelTime)}. ${restartTeamName} restart with a throw-in.`);
    queueNextSequenceStep();
    return;
  }

  completeLiveActionPlayersBeforeCommit(outInfo.point);
  if (state.draftStep) {
    state.draftStep.nextRestartPhase = {
      type: "throwIn",
      teamId: outInfo.restartTeamId,
      label: setPiecePhaseProfiles.throwIn.label,
      point: cloneVector(outInfo.point),
      sideY: outInfo.sideY,
    };
    state.draftStep.target = cloneVector(outInfo.point);
  }
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.receiverPlayerId = null;
  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(`${actionLabel} goes out after ${formatTime(completedTravelTime)}. ${restartTeamName} restart with a throw-in.`);
  scheduleAutoPilotContinuation(null, outInfo.type);
}

function updateBall(dt) {
  if (!state.ball.inTransit) {
    return;
  }

  if (state.ball.actionType === "dribble") {
    updateDribble(dt);
    return;
  }

  if (state.ball.actionType === "recovery") {
    updateLooseBallRecovery(dt);
    return;
  }

  const previousPosition = cloneVector(state.ball.position);
  const speedBefore = Math.max(
    state.ball.currentSpeed || state.ball.launchSpeed || getActionSpeed(),
    0.01
  );
  const speedAfter = Math.max(
    state.ball.finalSpeed,
    speedBefore - state.ball.deceleration * dt
  );
  const moveDistance = Math.max(((speedBefore + speedAfter) * 0.5) * dt, 0);
  state.ball.trackDistanceCovered = clamp(
    state.ball.trackDistanceCovered + moveDistance,
    0,
    Math.max(state.ball.trackDistanceTotal, 0)
  );
  const progress = state.ball.trackDistanceTotal <= 0.01
    ? 1
    : state.ball.trackDistanceCovered / state.ball.trackDistanceTotal;
  state.ball.position = getBallTravelPoint(progress);
  state.ball.currentSpeed = speedAfter;
  state.ball.spinAngle += state.ball.spinRate * dt;
  state.ball.elapsedTravelTime += dt;
  updateBallFlightHeight();

  const transitOutcome =
    resolveShotBlockCommitment(previousPosition) ??
    resolvePassTransitInterception(previousPosition, state.ball.actionType);
  if (transitOutcome) {
    const actionLabel = state.ball.actionType === "shot" ? "shot" : "pass";
    state.ball.inTransit = false;

    if (state.sequence.isPlaying) {
      state.ball.actionType = null;
      state.ball.initiatorPlayerId = null;
      state.ball.receiverPlayerId = null;
      state.sequence.phase = null;
      state.sequence.actionTargets = null;
      const step = state.sequence.steps[state.sequence.playbackIndex];
      if (step) {
        const afterSnapshot = cloneSnapshot(captureSnapshot());
        step.afterSnapshot = afterSnapshot;
        state.sequence.currentFrameIndex = state.sequence.playbackIndex;
      }
      if (transitOutcome.kind === "block") {
        logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} blocks the ${actionLabel}.`);
      } else if (transitOutcome.kind === "interception") {
        logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} intercepts the ${actionLabel}.`);
      } else if (transitOutcome.kind === "deflection") {
        logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} gets a touch on the ${actionLabel}.`);
      } else {
        logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} meets the ${actionLabel} early.`);
      }
      queueNextSequenceStep();
      return;
    }

    completeLiveActionPlayersBeforeCommit(state.ball.position);
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    finalizeCurrentActionStep();
    state.isRunning = false;
    ui.playPauseButton.textContent = "Start";
    if (transitOutcome.kind === "block") {
      logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} blocks the ${actionLabel}.`);
    } else if (transitOutcome.kind === "interception") {
      logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} intercepts the ${actionLabel}.`);
    } else if (transitOutcome.kind === "deflection") {
      logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} gets a touch on the ${actionLabel}.`);
    } else {
      logEvent(`${transitOutcome.player.shortLabel} ${transitOutcome.player.role} meets the ${actionLabel} early.`);
    }
    scheduleAutoPilotContinuation(null, actionLabel);
    return;
  }

  const goalInfo = detectShotGoal(previousPosition, state.ball.position);
  if (goalInfo) {
    const saveOutcome = resolveGoalkeeperSave(goalInfo, previousPosition);
    if (saveOutcome) {
      completeGoalkeeperSave(saveOutcome, state.ball.elapsedTravelTime);
      return;
    }

    completeShotGoal(goalInfo, state.ball.elapsedTravelTime);
    return;
  }

  const shotOutInfo = detectShotOutOfPlay(previousPosition, state.ball.position);
  if (shotOutInfo) {
    completeShotOutOfPlay(shotOutInfo, state.ball.elapsedTravelTime);
    return;
  }

  const touchlineOutInfo = detectTouchlineOutOfPlay(previousPosition, state.ball.position);
  if (touchlineOutInfo) {
    completeTouchlineOutOfPlay(touchlineOutInfo, state.ball.elapsedTravelTime);
    return;
  }

  const receiver = state.ball.actionType === "pass" && state.ball.receiverPlayerId
    ? getPlayerById(state.ball.receiverPlayerId)
    : null;
  const receiverControlPoint = receiver ? getPlayerBallControlPoint(receiver) : null;
  const reachedReceiverControlZone =
    !!receiverControlPoint &&
    distance(state.ball.position, receiverControlPoint) <= state.ball.controlRadius &&
    getBallFlightControlFactor(state.ball.actionType) >= 0.6;

  const reachedTravelEnd =
    state.ball.trackDistanceTotal > 0 &&
    state.ball.trackDistanceCovered >= Math.max(state.ball.trackDistanceTotal - 0.01, 0);

  if (distance(state.ball.position, state.ball.target) <= 0.01 || reachedReceiverControlZone || reachedTravelEnd) {
    const actionType = state.ball.actionType;
    const actionLabel = actionType === "shot" ? "Shot" : actionType === "pass" ? "Pass" : "Ball";
    const completedTravelTime = state.ball.elapsedTravelTime;
    const completedBallPosition = cloneVector(state.ball.position);
    state.ball.position = cloneVector(receiverControlPoint ?? state.ball.target);
    if (reachedTravelEnd && actionType === "shot") {
      state.ball.position = cloneVector(completedBallPosition);
      state.ball.target = cloneVector(completedBallPosition);
    }
    state.ball.height = 0;

    if (shouldTriggerLandingBounce(actionType, reachedReceiverControlZone) && startLandingBounceSkid(previousPosition)) {
      return;
    }

    state.ball.inTransit = false;
    if (state.sequence.isPlaying) {
      state.ball.actionType = null;
      state.ball.initiatorPlayerId = null;
      state.sequence.phase = null;
      state.sequence.actionTargets = null;
      logEvent(`${actionLabel} connects into the next step after ${formatTime(state.ball.elapsedTravelTime)}.`);
      const step = state.sequence.steps[state.sequence.playbackIndex];
      if (step?.afterSnapshot) {
        applyCommittedSnapshot(step.afterSnapshot);
        state.sequence.currentFrameIndex = state.sequence.playbackIndex;
      }
      queueNextSequenceStep();
      return;
    }

    completeLiveActionPlayersBeforeCommit(state.ball.position);
    settleBallForNextAction(actionType);
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.receiverPlayerId = null;
    finalizeCurrentActionStep();
    state.isRunning = false;
    ui.playPauseButton.textContent = "Start";
    logEvent(`${actionLabel} connects into the next step after ${formatTime(completedTravelTime)}.`);
    scheduleAutoPilotContinuation(null, actionType);
  }
}

function updateDribble(dt) {
  const carrier = getPlayerById(state.ball.carrierPlayerId);
  if (!carrier) {
    clearBallAction();
    state.isRunning = false;
    ui.playPauseButton.textContent = "Start";
    return;
  }

  if (!state.ball.dribblePath) {
    setDribbleCarryPathForBall(carrier, getActionOrigin(carrier), state.ball.target);
  }

  const currentCarrySpeed = getLiveDribbleSpeed(carrier, state.ball.target);
  const previousPosition = cloneVector(carrier.position);
  state.ball.trackDistanceCovered = clamp(
    (state.ball.trackDistanceCovered ?? 0) + currentCarrySpeed * dt,
    0,
    Math.max(state.ball.trackDistanceTotal, 0)
  );
  carrier.position = getDribbleCarryPathPoint(
    state.ball.dribblePath,
    state.ball.trackDistanceCovered
  );
  if (distance(previousPosition, carrier.position) > 0.006) {
    rotatePlayerBodyAlongMovement(carrier, previousPosition, carrier.position, 0.56);
  } else {
    rotatePlayerBodyToward(carrier, state.ball.target, 0.28);
  }
  state.ball.position = cloneVector(getPlayerBallControlPoint(carrier));
  state.ball.currentSpeed = currentCarrySpeed;
  state.ball.height = 0;
  state.ball.elapsedTravelTime += dt;
  state.ball.ownerPlayerId = carrier.id;

  if (
    state.ball.trackDistanceCovered >= Math.max(state.ball.trackDistanceTotal - 0.03, 0) ||
    distance(carrier.position, state.ball.target) <= 0.08
  ) {
    const completedTravelTime = state.ball.elapsedTravelTime;
    carrier.position = cloneVector(state.ball.target);
    state.ball.position = cloneVector(getPlayerBallControlPoint(carrier));
    state.ball.height = 0;
    state.ball.inTransit = false;
    completeLiveActionPlayersBeforeCommit(state.ball.position);
    state.ball.actionType = null;
    state.ball.initiatorPlayerId = null;
    state.ball.carrierPlayerId = null;
    if (state.sequence.isPlaying) {
      state.sequence.phase = null;
      state.sequence.actionTargets = null;
      logEvent(
        `${carrier.shortLabel} ${carrier.role} finishes the dribble after ${formatTime(state.ball.elapsedTravelTime)}.`
      );
      const step = state.sequence.steps[state.sequence.playbackIndex];
      if (step?.afterSnapshot) {
        applyCommittedSnapshot(step.afterSnapshot);
        state.sequence.currentFrameIndex = state.sequence.playbackIndex;
      }
      queueNextSequenceStep();
      return;
    }

    finalizeCurrentActionStep();
    state.isRunning = false;
    ui.playPauseButton.textContent = "Start";
    logEvent(
      `${carrier.shortLabel} ${carrier.role} finishes the dribble after ${formatTime(completedTravelTime)}.`
    );
    scheduleAutoPilotContinuation(null, "dribble");
  }
}

function updateLooseBallRecovery(dt) {
  const carrier = getPlayerById(state.ball.carrierPlayerId);
  if (!carrier) {
    clearBallAction();
    state.isRunning = false;
    ui.playPauseButton.textContent = "Start";
    return;
  }

  state.ball.elapsedTravelTime += dt;
  state.ball.currentSpeed = 0;
  state.ball.height = 0;
  state.ball.ownerPlayerId = null;
  const recoveryDuration = Math.max(state.ball.recoveryDuration ?? 0, 0.05);
  const controlGap = distance(getPlayerBallControlPoint(carrier), state.ball.position);

  if (state.ball.elapsedTravelTime < recoveryDuration && controlGap > ballRadiusMeters * 1.1) {
    return;
  }

  completeLiveActionPlayersBeforeCommit(state.ball.position);
  applyLooseBallCollectControlTouch(carrier, state.ball.position);
  state.ball.inTransit = false;
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.carrierPlayerId = null;
  state.ball.receiverPlayerId = null;

  if (state.sequence.isPlaying) {
    state.sequence.phase = null;
    state.sequence.actionTargets = null;
    logEvent(`${carrier.shortLabel} ${carrier.role} collects the loose ball.`);
    const step = state.sequence.steps[state.sequence.playbackIndex];
    if (step?.afterSnapshot) {
      applyCommittedSnapshot(step.afterSnapshot);
      state.sequence.currentFrameIndex = state.sequence.playbackIndex;
    }
    queueNextSequenceStep();
    return;
  }

  finalizeCurrentActionStep();
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(`${carrier.shortLabel} ${carrier.role} collects the loose ball and can play forward.`);
  scheduleAutoPilotContinuation(null, "recovery");
}

function updateActionPlayers(targetMap, actionMeta) {
  if (!targetMap || !actionMeta) {
    return;
  }

  const elapsed = state.ball.elapsedTravelTime;
  const defensiveFocusPoint = getDefensiveAutopilotFocusPoint(actionMeta);
  const offensiveFocusPoint = getOffensiveAutopilotFocusPoint(actionMeta);
  const passIncomingPoint =
    actionMeta.actionType === "pass"
      ? actionMeta.beforeSnapshot?.ball?.position ?? state.ball.startPosition
      : null;

  state.players.forEach((player) => {
    if (actionMeta.actionType === "dribble" && player.id === actionMeta.carrierPlayerId) {
      return;
    }

    let targetPosition = targetMap.get(player.id);
    if (!targetPosition) {
      return;
    }

    const isPassReceiver = actionMeta.actionType === "pass" && player.id === actionMeta.receiverPlayerId;
    const isDefensiveAutopilotRunner = isDefensiveAutopilotPlayer(player, actionMeta);
    const isOffensiveAutopilotRunner = isOffensiveAutopilotPlayer(player, actionMeta);
    const isDribbleAutopilotPresser = isDefensiveDribblePresser(player, actionMeta);
    if (isDribbleAutopilotPresser) {
      targetPosition = getLiveDefensiveDribblePressTarget(player, actionMeta, targetPosition);
    }

    const origin = getActionOrigin(player);
    const movementPath = isPassReceiver
      ? { start: origin, end: targetPosition, waypoint: null, totalDistance: distance(origin, targetPosition) }
      : buildMovementPath(player, origin, targetPosition, actionMeta);
    const fullDistance = movementPath.totalDistance;
    if (fullDistance <= 0.001) {
      player.position = cloneVector(targetPosition);
      if (isPassReceiver) {
        applyBestReceiveBodyAngle(player, passIncomingPoint, 0.22);
      } else if (isOffensiveAutopilotRunner && offensiveFocusPoint) {
        rotatePlayerBodyToward(player, state.ball.inTransit ? state.ball.position : offensiveFocusPoint, 0.82);
      } else if (isDefensiveAutopilotRunner && defensiveFocusPoint) {
        rotatePlayerBodyToward(player, defensiveFocusPoint, 0.92);
      }
      return;
    }

    const previousPosition = cloneVector(player.position);
    const reachableDistance = Math.min(
      fullDistance,
      computeReachDistance(player, elapsed, targetPosition)
    );
    const nextProgress = Math.max(player.movementProgress ?? 0, reachableDistance);
    player.movementProgress = nextProgress;
    player.position = getMovementPathPoint(movementPath, nextProgress);
    const movementDistance = distance(previousPosition, player.position);
    const hasArrived = nextProgress >= fullDistance - 0.02 || distance(player.position, targetPosition) <= 0.08;
    if (isPassReceiver) {
      applyBestReceiveBodyAngle(player, passIncomingPoint, 0.2);
    } else if (isDribbleAutopilotPresser) {
      rotatePlayerBodyToward(player, state.ball.position, 0.72);
    } else if (isOffensiveAutopilotRunner && offensiveFocusPoint && hasArrived) {
      rotatePlayerBodyToward(player, state.ball.inTransit ? state.ball.position : offensiveFocusPoint, 0.78);
    } else if (isDefensiveAutopilotRunner && defensiveFocusPoint && hasArrived) {
      rotatePlayerBodyToward(player, defensiveFocusPoint, 0.9);
    } else if (movementDistance > 0.006) {
      rotatePlayerBodyAlongMovement(player, previousPosition, player.position, 0.42);
    } else if (distance(player.position, targetPosition) > 0.02) {
      rotatePlayerBodyTowardAngle(
        player,
        angleBetween(player.position, targetPosition),
        0.18,
        0.08
      );
    }
  });
}

function updateSequenceActionPlayers() {
  if (!state.sequence.isPlaying || state.sequence.phase !== "action") {
    return;
  }

  const step = state.sequence.steps[state.sequence.playbackIndex];
  if (!step || !state.sequence.actionTargets) {
    return;
  }

  updateActionPlayers(state.sequence.actionTargets, step);
}

function updateLiveActionPlayers() {
  if (!state.isRunning || !state.activeActionTargets || !state.draftStep) {
    return;
  }

  updateActionPlayers(state.activeActionTargets, state.draftStep);
}

function updateSequenceTransition(dt) {
  const plan = state.sequence.transition;
  if (!plan) {
    return;
  }

  plan.elapsed = Math.min(plan.elapsed + dt, plan.duration);

  state.players.forEach((player) => {
    const target = plan.playerTargets.get(player.id);
    if (!target) {
      return;
    }

    const fullDistance = distance(target.start, target.end);
    const movementPath = buildMovementPath(player, target.start, target.end);
    if (movementPath.totalDistance <= 0.001) {
      player.position = cloneVector(target.end);
      player.movementProgress = 0;
      return;
    }

    const reachableDistance = Math.min(
      movementPath.totalDistance,
      computeReachDistance(player, plan.elapsed, target.end)
    );
    const nextProgress = Math.max(player.movementProgress ?? 0, reachableDistance);
    player.movementProgress = nextProgress;
    player.position = getMovementPathPoint(movementPath, nextProgress);
    if (distance(player.position, target.end) > 0.02) {
      rotatePlayerBodyToward(player, target.end, 0.28);
    }
  });

  if (plan.ballOwnerPlayerId) {
    const owner = getPlayerById(plan.ballOwnerPlayerId);
    if (owner) {
      state.ball.ownerPlayerId = owner.id;
      state.ball.position = cloneVector(getPlayerBallControlPoint(owner));
    }
  } else {
    const fullDistance = distance(plan.ballStart, plan.ballEnd);
    const progress =
      plan.duration <= 0.001 ? 1 : Math.min(1, plan.elapsed / plan.duration);
    state.ball.ownerPlayerId = null;
    state.ball.position = moveTowards(plan.ballStart, plan.ballEnd, fullDistance * progress);
  }

  state.ball.startPosition = cloneVector(state.ball.position);
  state.ball.target = cloneVector(state.ball.position);
  state.ball.inTransit = false;
  state.ball.elapsedTravelTime = 0;
  state.ball.actionType = null;
  state.ball.initiatorPlayerId = null;
  state.ball.carrierPlayerId = null;

  if (plan.elapsed >= plan.duration - 0.0001) {
    applySnapshot(plan.targetSnapshot);
    state.sequence.transition = null;
    state.sequence.phase = null;
    const nextStep = state.sequence.steps[state.sequence.playbackIndex];
    if (nextStep) {
      startRecordedAction(nextStep);
      logEvent(`Playing ${describeStep(nextStep, state.sequence.playbackIndex).title.toLowerCase()}.`);
    } else {
      finishSequencePlayback();
    }
  }
}

function stepSimulation(realDt) {
  const dt = realDt * state.playbackSpeed;

  if (state.sequence.isPlaying && state.sequence.phase === "transition") {
    state.time += dt;
    updateSequenceTransition(dt);
    return;
  }

  if (!state.ball.inTransit) {
    return;
  }

  state.time += dt;
  updateBall(dt);

  if (state.sequence.isPlaying && state.sequence.phase === "action") {
    updateSequenceActionPlayers();
    resolveDribbleDefensiveChallenge();
    return;
  }

  if (state.isRunning && state.activeActionTargets) {
    updateLiveActionPlayers();
    resolveDribbleDefensiveChallenge();
  }
}

function getBallStatus() {
  if (state.sequence.isPlaying && state.sequence.phase === "transition") {
    return state.isRunning ? "Transition" : "Transition Paused";
  }

  if (state.isRunning && state.ball.inTransit) {
    return "In Motion";
  }

  if (!state.isRunning && state.ball.inTransit && state.ball.elapsedTravelTime > 0) {
    return "Paused";
  }

  if (hasBallAction()) {
    return "Planned";
  }

  return "Still";
}

function getActionTypeLabel() {
  if (state.sequence.isPlaying && state.sequence.phase === "transition") {
    return "Transition";
  }

  if (state.ball.actionType === "pass") {
    return "Pass";
  }

  if (state.ball.actionType === "dribble") {
    return "Dribble";
  }

  if (state.ball.actionType === "shot") {
    return "Shot";
  }

  if (state.ball.actionType === "recovery") {
    return "Loose Ball";
  }

  const requestedMode = getRequestedActionMode();
  if (requestedMode === "dribble") {
    return "Dribble Selected";
  }

  if (requestedMode === "shot") {
    return "Shot Selected";
  }

  if (requestedMode === "pass") {
    return "Pass Selected";
  }

  return "Free Move";
}

function describeStep(step, index) {
  const target = `x ${step.target.x.toFixed(1)}, y ${step.target.y.toFixed(1)}`;
  const profileText = step.profileLabel ? `${step.profileLabel} • ` : "";
  const restartPrefix = step.restartPhase?.type
    ? `${setPiecePhaseProfiles[step.restartPhase.type]?.label ?? "Restart"} `
    : "";

  if (step.nextRestartPhase?.type === "penalty") {
    const restartTeam = teams[step.nextRestartPhase.teamId]?.name ?? "Attacking team";
    return {
      title: `Step ${index + 1}: Penalty Won`,
      meta: `${profileText}Foul in the box. Next restart: ${restartTeam} penalty`,
    };
  }

  if (step.nextRestartPhase?.type === "freeKick") {
    const restartTeam = teams[step.nextRestartPhase.teamId]?.name ?? "Attacking team";
    return {
      title: `Step ${index + 1}: Foul`,
      meta: `${profileText}Next restart: ${restartTeam} free-kick`,
    };
  }

  if (step.nextRestartPhase?.type === "throwIn") {
    const restartTeam = teams[step.nextRestartPhase.teamId]?.name ?? "Restart team";
    return {
      title: `Step ${index + 1}: Ball Out`,
      meta: `${profileText}Next restart: ${restartTeam} throw-in`,
    };
  }

  if (step.actionType === "recovery") {
    const carrier = step.carrierPlayerId
      ? getPlayerById(step.carrierPlayerId)?.shortLabel ?? step.carrierPlayerId
      : "player";
    return {
      title: `Step ${index + 1}: ${restartPrefix}Loose Ball Recovery`,
      meta: `${profileText}${carrier} collects the loose ball`,
    };
  }

  if (step.actionType === "dribble") {
    const carrier = step.carrierPlayerId
      ? getPlayerById(step.carrierPlayerId)?.shortLabel ?? step.carrierPlayerId
      : "player";
    return {
      title: `Step ${index + 1}: ${restartPrefix}Dribble`,
      meta: `${profileText}${carrier} to ${target}`,
    };
  }

  if (step.actionType === "shot") {
    if (step.goal) {
      const scoringTeam = teams[step.goal.scoringTeamId]?.name ?? "Team";
      const concedingTeam = teams[step.goal.concedingTeamId]?.name ?? "Opponent";
      return {
        title: `Step ${index + 1}: Goal`,
        meta: `${profileText}${scoringTeam} score. Next restart: ${concedingTeam} kick-off`,
      };
    }

    if (step.nextRestartPhase?.type === "corner") {
      const restartTeam = teams[step.nextRestartPhase.teamId]?.name ?? "Attacking team";
      return {
        title: `Step ${index + 1}: Shot Saved`,
        meta: `${profileText}Turned behind. Next restart: ${restartTeam} corner`,
      };
    }

    if (step.nextRestartPhase?.type === "goalKick") {
      const restartTeam = teams[step.nextRestartPhase.teamId]?.name ?? "Defending team";
      return {
        title: `Step ${index + 1}: Shot Wide`,
        meta: `${profileText}Missed target. Next restart: ${restartTeam} goal-kick`,
      };
    }

    return {
      title: `Step ${index + 1}: ${restartPrefix}Shot`,
      meta: `${profileText}To ${target}`,
    };
  }

  if (step.receiverPlayerId) {
    const receiver = getPlayerById(step.receiverPlayerId)?.shortLabel ?? step.receiverPlayerId;
    const firstTouchText = step.firstTouchMode
      ? ` • First Touch: ${getFirstTouchModeLabel(step.firstTouchMode)}`
      : "";
    return {
      title: `Step ${index + 1}: ${restartPrefix}Pass`,
      meta: `${profileText}To ${receiver}${firstTouchText}`,
    };
  }

  return {
    title: `Step ${index + 1}: ${restartPrefix}Pass`,
    meta: `${profileText}To ${target}`,
  };
}

function getSequenceStartSnapshot() {
  if (state.sequence.initialSnapshot) {
    return cloneSnapshot(state.sequence.initialSnapshot);
  }

  if (state.sequence.steps[0]?.beforeSnapshot) {
    return cloneSnapshot(state.sequence.steps[0].beforeSnapshot);
  }

  return cloneSnapshot(captureSnapshot());
}

function getSequenceFrameSnapshot(frameIndex) {
  if (frameIndex < 0) {
    return getSequenceStartSnapshot();
  }

  const step = state.sequence.steps[frameIndex];
  if (!step) {
    return getSequenceStartSnapshot();
  }

  return cloneSnapshot(getRecordedStepEndSnapshot(step));
}

function persistCurrentFrameSnapshot(snapshot = captureSnapshot()) {
  const normalizedSnapshot = cloneSnapshot(snapshot);
  if (state.sequence.steps.length && !state.sequence.isPlaying) {
    markSequenceDirty();
  }

  if (state.sequence.currentFrameIndex < 0) {
    state.sequence.initialSnapshot = normalizedSnapshot;
    if (state.sequence.steps[0]) {
      state.sequence.steps[0].beforeSnapshot = cloneSnapshot(normalizedSnapshot);
    }
    return;
  }

  const currentStep = state.sequence.steps[state.sequence.currentFrameIndex];
  if (currentStep) {
    currentStep.afterSnapshot = cloneSnapshot(normalizedSnapshot);
  }

  const nextStep = state.sequence.steps[state.sequence.currentFrameIndex + 1];
  if (nextStep) {
    nextStep.beforeSnapshot = cloneSnapshot(normalizedSnapshot);
  }
}

function finalizeCurrentActionStep() {
  if (!state.draftStep) {
    clearBallAction();
    return;
  }

  const beforeSnapshot = cloneSnapshot(state.draftStep.beforeSnapshot);
  persistCurrentFrameSnapshot(beforeSnapshot);

  if (state.sequence.currentFrameIndex < state.sequence.steps.length - 1) {
    state.sequence.steps = state.sequence.steps.slice(0, state.sequence.currentFrameIndex + 1);
  }

  if (!state.sequence.initialSnapshot) {
    state.sequence.initialSnapshot = cloneSnapshot(beforeSnapshot);
  }

  const goalEvent = cloneGoalEvent(state.draftStep.goal);
  const nextRestartPhase = cloneRestartPhase(state.draftStep.nextRestartPhase);
  const afterSnapshot = createCommittedSnapshotFromCurrentState();
  if (goalEvent?.concedingTeamId) {
    applyKickoffSetup(afterSnapshot, {
      teamId: goalEvent.concedingTeamId,
      resetFormations: false,
    });
  } else if (nextRestartPhase?.type === "goalKick" && nextRestartPhase.teamId) {
    applyGoalKickSetup(afterSnapshot, {
      teamId: nextRestartPhase.teamId,
      resetFormations: false,
    });
  } else if (nextRestartPhase?.type === "corner" && nextRestartPhase.teamId) {
    applyCornerSetup(afterSnapshot, {
      teamId: nextRestartPhase.teamId,
      sideY: Number.isFinite(nextRestartPhase.sideY) ? nextRestartPhase.sideY : state.ball.position.y,
      resetFormations: false,
    });
  } else if (nextRestartPhase?.type === "throwIn" && nextRestartPhase.teamId) {
    applyThrowInSetup(afterSnapshot, {
      teamId: nextRestartPhase.teamId,
      point: nextRestartPhase.point ?? state.ball.position,
      sideY: Number.isFinite(nextRestartPhase.sideY) ? nextRestartPhase.sideY : state.ball.position.y,
      resetFormations: false,
    });
  } else if (nextRestartPhase?.type === "freeKick" && nextRestartPhase.teamId) {
    applyFreeKickSetup(afterSnapshot, {
      teamId: nextRestartPhase.teamId,
      point: nextRestartPhase.point ?? state.ball.position,
      resetFormations: false,
    });
  } else if (nextRestartPhase?.type === "penalty" && nextRestartPhase.teamId) {
    applyPenaltySetup(afterSnapshot, {
      teamId: nextRestartPhase.teamId,
      resetFormations: false,
    });
  } else if (state.restartPhase) {
    afterSnapshot.matchPhase = "inPossession";
    afterSnapshot.restartPhase = null;
  }
  const completedStep = {
    id: `step-${Date.now()}-${state.sequence.steps.length}`,
    matchPhase: state.matchPhase ?? null,
    restartPhase: cloneRestartPhase(state.restartPhase),
    actionType: state.draftStep.actionType,
    autoGenerated: !!state.draftStep.autoGenerated,
    autoPrinciples: [...(state.draftStep.autoPrinciples ?? [])],
    target: cloneVector(state.draftStep.target),
    speed: state.draftStep.speed,
    speedMode: state.draftStep.speedMode ?? state.ball.profileMode ?? state.ballSpeedMode,
    profileKey: state.draftStep.profileKey ?? state.ball.profileKey ?? null,
    profileLabel: state.draftStep.profileLabel ?? state.ball.profileLabel ?? null,
    targetKind: state.draftStep.targetKind ?? state.ball.targetKind ?? null,
    intendedTarget: state.draftStep.intendedTarget
      ? cloneVector(state.draftStep.intendedTarget)
      : null,
    shotPlacement: cloneShotPlacement(state.draftStep.shotPlacement),
    nextRestartPhase,
    goal: goalEvent,
    recoveryDuration: state.draftStep.recoveryDuration ?? state.ball.recoveryDuration ?? 0,
    firstTouchMode: state.draftStep.firstTouchMode ?? state.ball.firstTouchMode ?? "auto",
    carrierPlayerId: state.draftStep.carrierPlayerId ?? null,
    receiverPlayerId: state.draftStep.receiverPlayerId ?? null,
    defensiveAutopilot: state.draftStep.defensiveAutopilot
      ? {
          teamId: state.draftStep.defensiveAutopilot.teamId,
          ballFocusPoint: cloneVector(state.draftStep.defensiveAutopilot.ballFocusPoint ?? state.draftStep.target),
          presserPlayerId: state.draftStep.defensiveAutopilot.presserPlayerId ?? null,
          phaseKey: state.draftStep.defensiveAutopilot.phaseKey ?? null,
          phaseLabel: state.draftStep.defensiveAutopilot.phaseLabel ?? null,
        }
      : null,
    offensiveAutopilot: state.draftStep.offensiveAutopilot
      ? {
          teamId: state.draftStep.offensiveAutopilot.teamId,
          ballFocusPoint: cloneVector(state.draftStep.offensiveAutopilot.ballFocusPoint ?? state.draftStep.target),
          runnerPlayerId: state.draftStep.offensiveAutopilot.runnerPlayerId ?? null,
          phaseKey: state.draftStep.offensiveAutopilot.phaseKey ?? null,
          phaseLabel: state.draftStep.offensiveAutopilot.phaseLabel ?? null,
          principleKey: state.draftStep.offensiveAutopilot.principleKey ?? null,
          principleLabel: state.draftStep.offensiveAutopilot.principleLabel ?? null,
        }
      : null,
    beforeSnapshot,
    afterSnapshot,
  };

  state.sequence.steps.push(completedStep);
  state.sequence.currentFrameIndex = state.sequence.steps.length - 1;
  markSequenceDirty();
  clearBallAction();
  applyCommittedSnapshot(afterSnapshot);
  if (completedStep.restartPhase && !completedStep.goal && !completedStep.nextRestartPhase) {
    state.matchPhase = "inPossession";
    state.restartPhase = null;
  }

  const description = describeStep(completedStep, state.sequence.currentFrameIndex);
  logEvent(`${description.title} was saved automatically.`);
}

function goToSequenceFrame(frameIndex) {
  if (!canEditScenario()) {
    return;
  }

  if (hasBallAction() || state.draftStep) {
    logEvent("Finish or clear the current action before switching steps.");
    return;
  }

  const maxFrameIndex = state.sequence.steps.length - 1;
  const nextFrameIndex = clamp(frameIndex, -1, maxFrameIndex);

  if (state.sequence.steps.length) {
    persistCurrentFrameSnapshot(captureSnapshot());
  }

  clearBallAction();
  applySnapshot(getSequenceFrameSnapshot(nextFrameIndex));
  state.sequence.currentFrameIndex = nextFrameIndex;
  state.time = 0;
  ui.playPauseButton.textContent = "Start";
}

function cancelSequenceAdvance() {
  if (state.sequence.playbackTimeoutId !== null) {
    window.clearTimeout(state.sequence.playbackTimeoutId);
    state.sequence.playbackTimeoutId = null;
  }
}

function stopSequencePlayback(shouldLog = true) {
  const restoreFrameIndex = clamp(
    state.sequence.currentFrameIndex,
    -1,
    state.sequence.steps.length - 1
  );

  cancelSequenceAdvance();
  state.sequence.isPlaying = false;
  state.sequence.playbackIndex = -1;
  state.sequence.phase = null;
  state.sequence.transition = null;
  state.sequence.actionTargets = null;
  clearBallAction();

  if (state.sequence.steps.length) {
    applySnapshot(getSequenceFrameSnapshot(restoreFrameIndex));
    state.sequence.currentFrameIndex = restoreFrameIndex;
  }

  state.isRunning = false;
  state.time = 0;
  ui.playPauseButton.textContent = "Start";
  updateSequenceButtons();
  if (shouldLog) {
    logEvent("Sequence playback stopped.");
  }
}

function finishSequencePlayback() {
  cancelSequenceAdvance();
  state.sequence.isPlaying = false;
  state.sequence.currentFrameIndex = state.sequence.steps.length - 1;
  state.sequence.playbackIndex = -1;
  state.sequence.phase = null;
  state.sequence.transition = null;
  state.sequence.actionTargets = null;
  state.isRunning = false;
  state.time = 0;
  ui.playPauseButton.textContent = "Start";
  updateSequenceButtons();
  logEvent("Sequence playback is complete.");
}

function queueNextSequenceStep() {
  const nextIndex = state.sequence.playbackIndex + 1;
  if (nextIndex >= state.sequence.steps.length) {
    finishSequencePlayback();
    return;
  }

  cancelSequenceAdvance();
  state.sequence.playbackTimeoutId = window.setTimeout(() => {
    state.sequence.playbackTimeoutId = null;
    startSequenceStep(nextIndex);
  }, 16);
}

function startRecordedAction(step) {
  applySnapshot(step.beforeSnapshot);
  state.ballSpeedMode = step.speedMode ?? state.ballSpeedMode;
  const resolvedProfile = resolveRecordedStepProfile(step);
  state.sequence.phase = "action";
  state.sequence.transition = null;
  state.sequence.actionTargets = new Map(
    getRecordedStepEndSnapshot(step).players.map((player) => [
      player.id,
      cloneVector(player.position),
    ])
  );

  if (step.actionType === "dribble") {
    state.dribbleSpeed = step.speed;
    ui.dribbleSpeed.value = String(step.speed);
    ui.dribbleSpeedLabel.textContent = `${step.speed.toFixed(1)} m/s`;
    applyResolvedBallProfile(resolvedProfile);
    state.ball.ownerPlayerId = step.carrierPlayerId;
    state.ball.position = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.startPosition = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.target = cloneVector(step.target);
    state.ball.inTransit = true;
    state.ball.elapsedTravelTime = 0;
    state.ball.actionType = "dribble";
    state.ball.initiatorPlayerId = step.carrierPlayerId ?? null;
    state.ball.carrierPlayerId = step.carrierPlayerId;
    state.ball.receiverPlayerId = null;
    applyBallExecutionProfile("dribble", getPlayerById(step.carrierPlayerId), step.target, resolvedProfile);
    configureBallTravelProfile(
      "dribble",
      distance(state.ball.startPosition, state.ball.target),
      getActionSpeed(),
      resolvedProfile
    );
    {
      const carrier = getPlayerById(step.carrierPlayerId);
      if (carrier) {
        setDribbleCarryPathForBall(carrier, carrier.position, state.ball.target);
      }
    }
  } else if (step.actionType === "recovery") {
    applyResolvedBallProfile(resolvedProfile);
    state.ball.speed = step.speed;
    state.ball.position = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.startPosition = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.target = cloneVector(step.target);
    state.ball.inTransit = true;
    state.ball.elapsedTravelTime = 0;
    state.ball.actionType = "recovery";
    state.ball.initiatorPlayerId = step.carrierPlayerId ?? null;
    state.ball.carrierPlayerId = step.carrierPlayerId ?? null;
    state.ball.receiverPlayerId = null;
    state.ball.ownerPlayerId = null;
    state.ball.recoveryDuration = Math.max(step.recoveryDuration ?? 0, 0.35);
    state.ball.currentSpeed = 0;
    state.ball.launchSpeed = 0;
    state.ball.finalSpeed = 0;
    state.ball.deceleration = 0;
    state.ball.trackDistanceTotal = 0;
    state.ball.trackDistanceCovered = 0;
  } else {
    state.ball.speed = step.speed;
    if (step.actionType === "pass") {
      state.firstTouchMode = step.firstTouchMode ?? state.firstTouchMode;
    }
    if (step.speedMode === "manual") {
      state.ball.manualSpeed = step.speed;
    }
    applyResolvedBallProfile(resolvedProfile);
    state.ball.position = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.startPosition = cloneVector(step.beforeSnapshot.ball.position);
    state.ball.target = cloneVector(step.target);
    state.ball.inTransit = true;
    state.ball.elapsedTravelTime = 0;
    state.ball.actionType = step.actionType;
    state.ball.initiatorPlayerId = step.beforeSnapshot.ball.ownerPlayerId ?? null;
    state.ball.carrierPlayerId = null;
    state.ball.receiverPlayerId = step.actionType === "pass" ? step.receiverPlayerId ?? null : null;
    state.ball.firstTouchMode = step.actionType === "pass" ? step.firstTouchMode ?? "auto" : null;
    state.ball.ownerPlayerId = null;
    applyBallExecutionProfile(step.actionType, getPlayerById(step.beforeSnapshot.ball.ownerPlayerId), step.target, resolvedProfile);
    configureBallTravelProfile(
      step.actionType,
      distance(state.ball.startPosition, state.ball.target),
      getActionSpeed(),
      resolvedProfile
    );
  }

  state.players.forEach((player) => {
    player.actionOrigin = cloneVector(player.position);
  });

  state.isRunning = true;
  ui.playPauseButton.textContent = "Pause";
}

function createCommittedSnapshotFromCurrentState() {
  const snapshot = captureSnapshot();

  if (state.draftStep?.actionType === "dribble") {
    const carrier = snapshot.players.find(
      (player) => player.id === state.draftStep.carrierPlayerId
    );
    if (carrier && distance(carrier.position, state.ball.position) > 0.02) {
      carrier.position = cloneVector(state.ball.target);
    }
  }

  return snapshot;
}

function applyCommittedSnapshot(snapshot) {
  applySnapshot(snapshot);
}

function serializeSequence() {
  if (
    state.sequence.steps.length &&
    !state.sequence.isPlaying &&
    !state.isRunning &&
    !hasBallAction() &&
    !state.draftStep
  ) {
    persistCurrentFrameSnapshot(captureSnapshot());
  }

  return {
    version: 1,
    savedAt: new Date().toISOString(),
    surfacePreset: state.surfacePreset,
    weatherPreset: state.weatherPreset,
    scenario: cloneScenarioInfo(state.scenario),
    initialSnapshot: state.sequence.initialSnapshot
      ? cloneSnapshot(state.sequence.initialSnapshot)
      : null,
    steps: state.sequence.steps.map(cloneSequenceStep),
  };
}

function loadSequenceData(data) {
  if (!data || !Array.isArray(data.steps)) {
    return false;
  }

  state.sequence.isPlaying = false;
  state.sequence.playbackIndex = -1;
  state.sequence.currentFrameIndex = -1;
  state.sequence.phase = null;
  state.sequence.transition = null;
  state.sequence.actionTargets = null;
  state.sequence.initialSnapshot = data.initialSnapshot
    ? cloneSnapshot(data.initialSnapshot)
    : data.steps[0]?.beforeSnapshot
      ? cloneSnapshot(data.steps[0].beforeSnapshot)
      : null;
  state.surfacePreset = data.surfacePreset ?? state.surfacePreset;
  state.weatherPreset = data.weatherPreset ?? state.weatherPreset;
  state.sequence.steps = data.steps.map(cloneSequenceStep);
  markSimulatorSaved();
  state.example = null;
  state.scenario = cloneScenarioInfo(data.scenario ?? defaultScenarioInfo);
  clearBallAction();
  state.time = 0;
  ui.playPauseButton.textContent = "Start";

  if (state.sequence.initialSnapshot) {
    applySnapshot(state.sequence.initialSnapshot);
  }

  updateSequenceButtons();
  return true;
}

function saveSequenceToLocal() {
  if (!state.sequence.steps.length) {
    logEvent("There is no sequence to save yet.");
    return;
  }

  const defaultName =
    state.scenario.title && state.scenario.title !== defaultScenarioInfo.title
      ? state.scenario.title
      : `Sequence ${new Date().toLocaleDateString("en-GB")}`;
  const requestedName = window.prompt("What would you like to name this sequence?", defaultName);

  if (requestedName === null) {
    return;
  }

  const name = requestedName.trim() || defaultName;
  const sequence = serializeSequence();
  const entry = {
    id: `saved-sequence-${Date.now()}`,
    name,
    savedAt: sequence.savedAt,
    sequence,
  };

  writeSavedSequenceLibrary([entry, ...state.savedSequences]);
  markSimulatorSaved();
  logEvent(`Sequence "${name}" was saved centrally.`);
}

function loadSequenceFromLocal() {
  if (state.savedSequences.length) {
    const latest = state.savedSequences[0];
    if (loadSequenceData(latest.sequence)) {
      logEvent(`Latest central sequence loaded: ${latest.name}.`);
    } else {
      logEvent("The latest central sequence could not be read.");
    }
    return;
  }

  const raw = window.localStorage.getItem(sequenceStorageKey);
  if (!raw) {
    logEvent("No saved central sequence was found.");
    return;
  }

  try {
    const data = JSON.parse(raw);
    if (loadSequenceData(data)) {
      logEvent(`Saved sequence loaded with ${state.sequence.steps.length} steps.`);
    } else {
      logEvent("The saved sequence could not be read.");
    }
  } catch {
    logEvent("The saved sequence is corrupted and could not be loaded.");
  }
}

function downloadSequence(sequenceData = null, suggestedName = null) {
  const data = sequenceData ?? serializeSequence();

  if (!data?.steps?.length) {
    logEvent("There is no sequence to download yet.");
    return;
  }

  const blob = new Blob([JSON.stringify(data, null, 2)], {
    type: "application/json",
  });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  const datePart = new Date().toISOString().slice(0, 10);
  link.href = url;
  const fileStem = sanitizeFileName(suggestedName ?? data.scenario?.title ?? "football-sequence");
  link.download = `${fileStem}-${datePart}.json`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  logEvent("Sequence downloaded as JSON.");
}

function createStepThumbnail(snapshot) {
  const width = 168;
  const height = 108;
  const sx = width / pitch.length;
  const sy = height / pitch.width;

  const playerCircles = snapshot.players
    .map((player) => {
      const original = squadBlueprints.find((item) => item.id === player.id);
      const color = original?.team === "home" ? teams.home.color : teams.away.color;
      return `<circle cx="${(player.position.x * sx).toFixed(1)}" cy="${(player.position.y * sy).toFixed(1)}" r="3.4" fill="${color}" stroke="white" stroke-width="0.8" />`;
    })
    .join("");

  const ball = snapshot.ball
    ? `<circle cx="${(snapshot.ball.position.x * sx).toFixed(1)}" cy="${(snapshot.ball.position.y * sy).toFixed(1)}" r="2.6" fill="#fff5d6" stroke="#5f4d2d" stroke-width="0.8" />`
    : "";

  const svg = `
    <svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
      <rect width="${width}" height="${height}" rx="10" fill="#1f7a45"/>
      <rect x="2" y="2" width="${width - 4}" height="${height - 4}" rx="8" fill="none" stroke="rgba(255,255,255,0.9)" stroke-width="1.6"/>
      <line x1="${width / 2}" y1="2" x2="${width / 2}" y2="${height - 2}" stroke="rgba(255,255,255,0.9)" stroke-width="1.2"/>
      <circle cx="${width / 2}" cy="${height / 2}" r="14" fill="none" stroke="rgba(255,255,255,0.9)" stroke-width="1.2"/>
      ${playerCircles}
      ${ball}
    </svg>
  `;

  return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;
}

function startSequenceStep(index) {
  if (!state.sequence.isPlaying) {
    return;
  }

  const step = state.sequence.steps[index];
  if (!step) {
    finishSequencePlayback();
    return;
  }

  state.sequence.playbackIndex = index;
  if (index > 0 && !snapshotsMatch(captureSnapshot(), step.beforeSnapshot)) {
    const transitionPlan = createTransitionPlan(captureSnapshot(), step.beforeSnapshot);
    if (step.beforeSnapshot.formations) {
      teams.home.formation = step.beforeSnapshot.formations.home ?? teams.home.formation;
      teams.away.formation = step.beforeSnapshot.formations.away ?? teams.away.formation;
    }

    if (transitionPlan.duration > 0.02) {
      clearBallAction();
      state.sequence.phase = "transition";
      state.sequence.transition = transitionPlan;
      state.isRunning = true;
      ui.playPauseButton.textContent = "Pause";
      logEvent(`Transitioning into step ${index + 1}.`);
      return;
    }

    applySnapshot(step.beforeSnapshot);
  }

  startRecordedAction(step);

  const description = describeStep(step, index);
  logEvent(`Playing ${description.title.toLowerCase()}.`);
}

function startSequencePlayback() {
  if (!state.sequence.steps.length) {
    logEvent("There is no sequence to play yet.");
    return;
  }

  if (hasBallAction() || state.draftStep) {
    logEvent("Finish or clear the current action before starting sequence playback.");
    return;
  }

  const startIndex = state.sequence.currentFrameIndex < 0
    ? 0
    : state.sequence.currentFrameIndex;

  persistCurrentFrameSnapshot(captureSnapshot());

  cancelSequenceAdvance();
  state.sequence.isPlaying = true;
  state.sequence.playbackIndex = -1;
  state.sequence.phase = null;
  state.sequence.transition = null;
  state.sequence.actionTargets = null;
  state.time = 0;
  ui.playPauseButton.textContent = "Pause";
  updateSequenceButtons();
  startSequenceStep(startIndex);
}

function getActiveExampleOverlay() {
  if (!state.example?.overlaySteps?.length) {
    return null;
  }

  if (state.sequence.isPlaying && state.sequence.playbackIndex >= 0) {
    return (
      state.example.overlaySteps[state.sequence.playbackIndex] ??
      state.example.overlaySteps[state.example.overlaySteps.length - 1]
    );
  }

  return state.example.overlaySteps[0];
}

function getSavedSequenceById(sequenceId) {
  return state.savedSequences.find((entry) => entry.id === sequenceId) ?? null;
}

function loadSavedSequenceEntry(sequenceId) {
  const entry = getSavedSequenceById(sequenceId);
  if (!entry) {
    logEvent("The saved sequence could not be found.");
    return;
  }

  if (loadSequenceData(entry.sequence)) {
    logEvent(`Sequence "${entry.name}" loaded.`);
  } else {
    logEvent(`Sequence "${entry.name}" could not be read.`);
  }
}

function removeSavedSequenceEntry(sequenceId) {
  const entry = getSavedSequenceById(sequenceId);
  if (!entry) {
    return;
  }

  writeSavedSequenceLibrary(
    state.savedSequences.filter((candidate) => candidate.id !== sequenceId)
  );
  logEvent(`Sequence "${entry.name}" was removed from local storage.`);
}

function drawOverlayArrow(arrow) {
  const start = toCanvas(arrow.from);
  const end = toCanvas(arrow.to);
  const direction = normalize(arrow.from, arrow.to);
  const arrowSize = 11;
  const left = {
    x: end.x - direction.x * arrowSize - direction.y * arrowSize * 0.55,
    y: end.y - direction.y * arrowSize + direction.x * arrowSize * 0.55,
  };
  const right = {
    x: end.x - direction.x * arrowSize + direction.y * arrowSize * 0.55,
    y: end.y - direction.y * arrowSize - direction.x * arrowSize * 0.55,
  };

  ctx.save();
  ctx.strokeStyle = arrow.color;
  ctx.fillStyle = arrow.color;
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.moveTo(start.x, start.y);
  ctx.lineTo(end.x, end.y);
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(end.x, end.y);
  ctx.lineTo(left.x, left.y);
  ctx.lineTo(right.x, right.y);
  ctx.closePath();
  ctx.fill();

  if (arrow.label) {
    const labelX = (start.x + end.x) / 2;
    const labelY = (start.y + end.y) / 2 - 14;
    ctx.font = "600 12px Georgia";
    const textWidth = ctx.measureText(arrow.label).width;
    ctx.fillStyle = "rgba(17, 24, 29, 0.72)";
    ctx.fillRect(labelX - textWidth / 2 - 8, labelY - 12, textWidth + 16, 22);
    ctx.fillStyle = "rgba(255,255,255,0.96)";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText(arrow.label, labelX, labelY - 1);
  }
  ctx.restore();
}

function drawExampleOverlay() {
  const overlay = getActiveExampleOverlay();
  if (!overlay) {
    return;
  }

  overlay.arrows.forEach(drawOverlayArrow);

  ctx.save();
  ctx.font = "700 14px Georgia";
  ctx.fillStyle = "rgba(255,255,255,0.94)";
  ctx.textAlign = "left";
  ctx.textBaseline = "top";
  ctx.fillText(overlay.title, 18, 18);
  ctx.restore();
}

function drawPitch() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  ctx.fillStyle = "#1f7a45";
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const fieldInset = 10;
  const fieldLeft = fieldInset;
  const fieldTop = fieldInset;
  const fieldWidth = canvas.width - fieldInset * 2;
  const fieldHeight = canvas.height - fieldInset * 2;
  const scaleX = fieldWidth / pitch.length;
  const scaleY = fieldHeight / pitch.width;
  const meterScale = Math.min(scaleX, scaleY);
  const centerX = fieldLeft + fieldWidth / 2;
  const centerY = fieldTop + fieldHeight / 2;
  const penaltyAreaDepth = 16.5 * scaleX;
  const penaltyAreaHeight = 40.32 * scaleY;
  const sixYardDepth = 5.5 * scaleX;
  const sixYardHeight = 18.32 * scaleY;
  const goalWidth = 7.32 * scaleY;
  const goalDepth = Math.max(12, 2.5 * scaleX);
  const penaltySpotDistance = 11 * scaleX;
  const penaltyArcRadius = 9.15 * meterScale;
  const penaltyArcAngle = Math.acos(clamp((16.5 - 11) / 9.15, -1, 1));
  const goalTop = centerY - goalWidth / 2;
  const goalBottom = centerY + goalWidth / 2;
  const leftPenaltyTop = centerY - penaltyAreaHeight / 2;
  const sixYardTop = centerY - sixYardHeight / 2;
  const rightFieldX = fieldLeft + fieldWidth;

  ctx.strokeStyle = "rgba(255,255,255,0.92)";
  ctx.lineWidth = 3;
  ctx.strokeRect(fieldLeft, fieldTop, fieldWidth, fieldHeight);

  ctx.beginPath();
  ctx.moveTo(centerX, fieldTop);
  ctx.lineTo(centerX, fieldTop + fieldHeight);
  ctx.stroke();

  ctx.beginPath();
  ctx.arc(centerX, centerY, 9.15 * meterScale, 0, Math.PI * 2);
  ctx.stroke();

  ctx.strokeRect(fieldLeft, leftPenaltyTop, penaltyAreaDepth, penaltyAreaHeight);
  ctx.strokeRect(rightFieldX - penaltyAreaDepth, leftPenaltyTop, penaltyAreaDepth, penaltyAreaHeight);
  ctx.strokeRect(fieldLeft, sixYardTop, sixYardDepth, sixYardHeight);
  ctx.strokeRect(rightFieldX - sixYardDepth, sixYardTop, sixYardDepth, sixYardHeight);

  const leftPenaltySpotX = fieldLeft + penaltySpotDistance;
  const rightPenaltySpotX = rightFieldX - penaltySpotDistance;

  ctx.save();
  ctx.strokeStyle = "rgba(255,255,255,0.8)";
  ctx.lineWidth = 2.1;
  ctx.beginPath();
  ctx.arc(leftPenaltySpotX, centerY, penaltyArcRadius, -penaltyArcAngle, penaltyArcAngle);
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(
    rightPenaltySpotX,
    centerY,
    penaltyArcRadius,
    Math.PI - penaltyArcAngle,
    Math.PI + penaltyArcAngle
  );
  ctx.stroke();
  ctx.restore();

  ctx.fillStyle = "rgba(255,255,255,0.92)";
  ctx.beginPath();
  ctx.arc(leftPenaltySpotX, centerY, 3.6, 0, Math.PI * 2);
  ctx.arc(rightPenaltySpotX, centerY, 3.6, 0, Math.PI * 2);
  ctx.fill();

  function drawGoal(side) {
    const direction = side === "left" ? -1 : 1;
    const frontX = side === "left" ? fieldLeft : rightFieldX;
    const backX = frontX + direction * goalDepth;
    const backTop = goalTop + goalDepth * 0.24;
    const backBottom = goalBottom - goalDepth * 0.24;

    ctx.save();
    ctx.fillStyle = "rgba(255,255,255,0.06)";
    ctx.strokeStyle = "rgba(255,255,255,0.98)";
    ctx.lineWidth = 2.2;

    ctx.beginPath();
    ctx.moveTo(frontX, goalTop);
    ctx.lineTo(backX, backTop);
    ctx.lineTo(backX, backBottom);
    ctx.lineTo(frontX, goalBottom);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    ctx.lineWidth = 2.5;
    ctx.beginPath();
    ctx.moveTo(frontX, goalTop);
    ctx.lineTo(frontX, goalBottom);
    ctx.moveTo(backX, backTop);
    ctx.lineTo(backX, backBottom);
    ctx.stroke();

    ctx.strokeStyle = "rgba(255,255,255,0.38)";
    ctx.lineWidth = 0.9;
    for (let row = 1; row <= 4; row += 1) {
      const ratio = row / 5;
      const yFront = lerp(goalTop, goalBottom, ratio);
      const yBack = lerp(backTop, backBottom, ratio);
      ctx.beginPath();
      ctx.moveTo(frontX, yFront);
      ctx.lineTo(backX, yBack);
      ctx.stroke();
    }

    for (let column = 1; column <= 4; column += 1) {
      const ratio = column / 5;
      const x = lerp(frontX, backX, ratio);
      const topY = lerp(goalTop, backTop, ratio);
      const bottomY = lerp(goalBottom, backBottom, ratio);
      ctx.beginPath();
      ctx.moveTo(x, topY);
      ctx.lineTo(x, bottomY);
      ctx.stroke();
    }

    ctx.restore();
  }

  drawGoal("left");
  drawGoal("right");
}

function getPlaybackStep() {
  if (!state.sequence.isPlaying || state.sequence.playbackIndex < 0) {
    return null;
  }

  return state.sequence.steps[state.sequence.playbackIndex] ?? null;
}

function shouldShowActionPlanningOverlay() {
  const playbackStep = getPlaybackStep();

  return !(
    state.autoPilotPlay?.active ||
    state.draftStep?.autoGenerated ||
    playbackStep?.autoGenerated
  );
}

function drawBallTarget() {
  if (!hasBallAction() || !shouldShowActionPlanningOverlay()) {
    return;
  }

  const target = toCanvas(state.ball.target);
  const current = toCanvas(state.ball.position);
  const isDribble = state.ball.actionType === "dribble";
  const isShot = state.ball.actionType === "shot";

  ctx.save();
  ctx.strokeStyle = isDribble
    ? "rgba(129, 184, 255, 0.7)"
    : isShot
      ? "rgba(255, 128, 128, 0.72)"
      : "rgba(255, 245, 214, 0.6)";
  ctx.lineWidth = 2;
  ctx.setLineDash(isDribble ? [12, 8] : isShot ? [4, 6] : [8, 8]);
  ctx.beginPath();
  ctx.moveTo(current.x, current.y);
  ctx.lineTo(target.x, target.y);
  ctx.stroke();

  ctx.setLineDash([]);
  ctx.strokeStyle = "rgba(255, 191, 105, 0.9)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(target.x - 10, target.y);
  ctx.lineTo(target.x + 10, target.y);
  ctx.moveTo(target.x, target.y - 10);
  ctx.lineTo(target.x, target.y + 10);
  ctx.stroke();
  ctx.restore();
}

function drawReachZones() {
  if (!hasBallAction() || !shouldShowActionPlanningOverlay()) {
    return;
  }

  const currentDuration = state.ball.elapsedTravelTime;
  const projectedDuration = getProjectedActionDuration();
  const metersToPixels = getMetersToPixels();

  state.players.forEach((player) => {
    const currentReach = computeReachDistance(player, currentDuration);
    const projectedReach = computeReachDistance(player, projectedDuration);

    if (projectedReach <= 0.02) {
      return;
    }

    const point = toCanvas(getActionOrigin(player));
    const selected = isPlayerRenderedSelected(player.id);

    ctx.save();

    if (currentReach > 0.02) {
      ctx.beginPath();
      ctx.fillStyle =
        player.team === "home"
          ? selected
            ? "rgba(129, 184, 255, 0.16)"
            : "rgba(129, 184, 255, 0.08)"
          : selected
            ? "rgba(255, 155, 155, 0.16)"
            : "rgba(255, 155, 155, 0.08)";
      ctx.arc(point.x, point.y, currentReach * metersToPixels, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.beginPath();
    ctx.strokeStyle = selected ? player.accent : "rgba(255,255,255,0.22)";
    ctx.lineWidth = selected ? 2.4 : 1.3;
    ctx.setLineDash(selected ? [8, 6] : [5, 9]);
    ctx.arc(point.x, point.y, projectedReach * metersToPixels, 0, Math.PI * 2);
    ctx.stroke();

    ctx.restore();
  });
}

function drawPlayer(player) {
  const point = toCanvas(player.position);
  const radius = playerRadiusMeters * getMetersToPixels();
  const selected = isPlayerRenderedSelected(player.id);
  const isPrimarySelected = player.id === getRenderedPrimarySelectedPlayerId();
  const selectionStroke = isPrimarySelected
    ? "#ffd76b"
    : selected
      ? "#f6e6a0"
      : "rgba(255,255,255,0.92)";
  const selectionLineWidth = isPrimarySelected ? 3.4 : selected ? 2.7 : 2;

  ctx.save();
  ctx.beginPath();
  ctx.fillStyle = player.color;
  ctx.arc(point.x, point.y, radius, 0, Math.PI * 2);
  ctx.fill();

  ctx.lineWidth = selectionLineWidth;
  ctx.strokeStyle = selectionStroke;
  ctx.stroke();

  const facingAngle = getPlayerFacingAngle(player);
  const footCenterOffset = radius * 0.97;
  const footSideOffset = radius * 0.68;
  const footLength = radius * 0.29;
  const footWidth = radius * 0.18;
  const footAngle = Math.PI / 6;

  ctx.save();
  ctx.translate(point.x, point.y);
  ctx.rotate(facingAngle);
  ctx.fillStyle = "rgba(255,255,255,0.99)";
  ctx.strokeStyle = "rgba(110, 110, 110, 0.22)";
  ctx.lineWidth = Math.max(0.9, radius * 0.08);

  [-1, 1].forEach((side) => {
    const footCenterX = footCenterOffset;
    const footCenterY = side * footSideOffset;
    ctx.beginPath();
    ctx.ellipse(
      footCenterX,
      footCenterY,
      footLength,
      footWidth,
      side * footAngle,
      0,
      Math.PI * 2
    );
    ctx.fill();
    ctx.stroke();
  });
  ctx.restore();

  const magnetLabel = getPlayerMagnetLabel(player);
  const fontSize = magnetLabel.length <= 3 ? 13 : magnetLabel.length <= 5 ? 11 : 9;
  ctx.fillStyle = "white";
  ctx.font = `bold ${fontSize}px Georgia`;
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(magnetLabel, point.x, point.y, radius * 1.55);
  ctx.restore();
}

function drawBall() {
  const groundPoint = toCanvas(state.ball.position);
  const radius = ballRadiusMeters * getMetersToPixels();
  const heightPixels = Math.max(0, state.ball.height * getMetersToPixels() * 0.42);
  const point = {
    x: groundPoint.x,
    y: groundPoint.y - heightPixels,
  };

  ctx.save();
  if (heightPixels > 0.5) {
    ctx.beginPath();
    ctx.fillStyle = `rgba(15, 16, 18, ${clamp(0.22 + heightPixels / 48, 0.22, 0.4)})`;
    ctx.ellipse(
      groundPoint.x,
      groundPoint.y + radius * 0.12,
      radius * (1 + heightPixels * 0.016),
      radius * 0.58,
      0,
      0,
      Math.PI * 2
    );
    ctx.fill();
  }
  ctx.beginPath();
  ctx.fillStyle = "#fbfbf7";
  ctx.arc(point.x, point.y, radius, 0, Math.PI * 2);
  ctx.fill();
  ctx.lineWidth = 1.4;
  ctx.strokeStyle = "#2d2d2d";
  ctx.stroke();

  const panelRadius = radius * 0.28;
  const seamRadius = radius * 0.58;

  ctx.save();
  ctx.translate(point.x, point.y);
  ctx.rotate(state.ball.spinAngle || 0);

  ctx.fillStyle = "#232323";
  ctx.beginPath();
  for (let index = 0; index < 5; index += 1) {
    const angle = -Math.PI / 2 + (Math.PI * 2 * index) / 5;
    const x = Math.cos(angle) * panelRadius;
    const y = Math.sin(angle) * panelRadius;
    if (index === 0) {
      ctx.moveTo(x, y);
    } else {
      ctx.lineTo(x, y);
    }
  }
  ctx.closePath();
  ctx.fill();

  ctx.strokeStyle = "rgba(35,35,35,0.92)";
  ctx.lineWidth = 0.85;
  for (let index = 0; index < 5; index += 1) {
    const angle = -Math.PI / 2 + (Math.PI * 2 * index) / 5;
    ctx.beginPath();
    ctx.moveTo(
      Math.cos(angle) * panelRadius * 0.82,
      Math.sin(angle) * panelRadius * 0.82
    );
    ctx.lineTo(
      Math.cos(angle) * seamRadius,
      Math.sin(angle) * seamRadius
    );
    ctx.stroke();
  }

  ctx.fillStyle = "rgba(35,35,35,0.9)";
  [-0.9, 0.8].forEach((angleOffset) => {
    ctx.beginPath();
    ctx.arc(
      Math.cos(angleOffset) * radius * 0.48,
      Math.sin(angleOffset) * radius * 0.36,
      radius * 0.11,
      0,
      Math.PI * 2
    );
    ctx.fill();
  });
  ctx.restore();
  ctx.restore();
}

function drawGoalFlash() {
  const flash = state.goalFlash;
  if (!flash) {
    return;
  }

  const now = Date.now();
  if (now > flash.expiresAtMs) {
    state.goalFlash = null;
    return;
  }

  const progress = clamp((now - flash.createdAtMs) / Math.max(flash.expiresAtMs - flash.createdAtMs, 1), 0, 1);
  const alpha = progress < 0.18 ? progress / 0.18 : 1 - clamp((progress - 0.72) / 0.28, 0, 1);
  const point = toCanvas(flash.displayPoint ?? flash.point);
  const linePoint = toCanvas(flash.point ?? flash.displayPoint);
  const goalSign = getGoalDirectionSign(flash.side);
  const ballRadius = ballRadiusMeters * getMetersToPixels() * 1.15;
  const burstRadius = lerp(12, 46, progress);

  ctx.save();
  ctx.globalAlpha = alpha;

  ctx.strokeStyle = "rgba(255, 245, 214, 0.78)";
  ctx.lineWidth = 3;
  ctx.setLineDash([10, 7]);
  ctx.beginPath();
  ctx.moveTo(linePoint.x - goalSign * 28, linePoint.y);
  ctx.lineTo(point.x, point.y);
  ctx.stroke();
  ctx.setLineDash([]);

  ctx.strokeStyle = "rgba(255, 215, 107, 0.72)";
  ctx.lineWidth = 2.2;
  ctx.beginPath();
  ctx.arc(point.x, point.y, burstRadius, 0, Math.PI * 2);
  ctx.stroke();

  ctx.beginPath();
  ctx.fillStyle = "rgba(255, 245, 214, 0.96)";
  ctx.arc(point.x, point.y, ballRadius, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = "rgba(25, 24, 22, 0.82)";
  ctx.lineWidth = 1.5;
  ctx.stroke();

  const bannerText = `GOAL • ${flash.scoringTeamName ?? "Team"}`;
  ctx.font = "800 28px Georgia";
  const textWidth = ctx.measureText(bannerText).width;
  const bannerX = canvas.width / 2;
  const bannerY = 42;
  ctx.fillStyle = "rgba(15, 16, 18, 0.76)";
  ctx.strokeStyle = "rgba(255, 245, 214, 0.7)";
  ctx.lineWidth = 1.4;
  ctx.beginPath();
  ctx.roundRect(bannerX - textWidth / 2 - 24, bannerY - 22, textWidth + 48, 44, 20);
  ctx.fill();
  ctx.stroke();
  ctx.fillStyle = "rgba(255, 245, 214, 0.98)";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(bannerText, bannerX, bannerY);

  ctx.restore();
}

function drawSelectionBox() {
  if (state.drag?.type !== "selection" || !state.drag.moved) {
    return;
  }

  const start = toCanvas(state.drag.startPoint);
  const end = toCanvas(state.drag.currentPoint);
  const left = Math.min(start.x, end.x);
  const top = Math.min(start.y, end.y);
  const width = Math.abs(end.x - start.x);
  const height = Math.abs(end.y - start.y);

  ctx.save();
  ctx.setLineDash([6, 5]);
  ctx.lineWidth = 1.25;
  ctx.strokeStyle = "rgba(255,255,255,0.9)";
  ctx.fillStyle = "rgba(255,255,255,0.04)";
  ctx.fillRect(left, top, width, height);
  ctx.strokeRect(left, top, width, height);
  ctx.restore();
}

function syncOwnedBallPosition() {
  if (!state.ball.ownerPlayerId || state.ball.inTransit || hasBallAction()) {
    return;
  }

  const owner = getBallOwner();
  if (!owner) {
    return;
  }

  const controlPoint = getPlayerBallControlPoint(owner);
  state.ball.position = cloneVector(controlPoint);
  state.ball.startPosition = cloneVector(controlPoint);
  state.ball.target = cloneVector(controlPoint);
  state.ball.height = 0;
}

function renderSidebar() {
  const selectedPlayer = getSelectedPlayer();
  const ballOwner = getBallOwner();
  const projectedDuration = getProjectedActionDuration();
  const actionDistanceText = formatMeters(getActionDistance());
  const currentReach = selectedPlayer
    ? computeReachDistance(selectedPlayer, getCurrentActionDuration())
    : null;
  const selectedPlayerControlPoint = selectedPlayer
    ? getPlayerBallControlPoint(selectedPlayer)
    : null;
  const distanceToBall = selectedPlayerControlPoint
    ? distance(selectedPlayerControlPoint, state.ball.position)
    : null;
  const actionOrigin = selectedPlayer ? getActionOrigin(selectedPlayer) : null;
  const movedDistance = selectedPlayer && actionOrigin
    ? distance(actionOrigin, selectedPlayer.position)
    : null;
  const editableRadius = selectedPlayer ? getEditableRadius(selectedPlayer) : null;
  const selectedPlayerIntelligence = selectedPlayer
    ? Math.round(selectedPlayer.intelligenceProfile?.intelligence ?? 0)
    : null;

  if (ui.scenarioTitle) {
    ui.scenarioTitle.textContent = state.scenario.title;
  }
  if (ui.scenarioText) {
    ui.scenarioText.textContent = state.scenario.text;
  }
  if (ui.scenarioMeta) {
    ui.scenarioMeta.textContent = state.scenario.meta;
  }
  const ballEtaText =
    state.sequence.phase === "transition" && state.sequence.transition
      ? formatTime(
          Math.max(0, state.sequence.transition.duration - state.sequence.transition.elapsed)
        )
      : hasBallAction()
        ? formatTime(getRemainingBallTravelTime())
        : "0.00 s";
  const ballProfileText = getBallProfileLabel();
  const displayedBallSpeed = getDisplayedBallSpeed();
  const ballSpeedText = displayedBallSpeed !== null ? formatSpeed(displayedBallSpeed) : "-";
  const ballOwnerText = ballOwner
    ? `${ballOwner.shortLabel} ${ballOwner.role}`
    : "None";
  const selectedPlayerText = selectedPlayer
    ? `${selectedPlayer.shortLabel} ${selectedPlayer.role}`
    : "No Player Selected";
  const selectedRoleModel = selectedPlayer ? getPlayerRoleModel(selectedPlayer) : null;
  const selectedPhysicalLabel = selectedPlayer
    ? selectedPlayer.physicalProfile?.label ?? getCompetitionPhysicalLabel(state.physicalProfile)
    : "-";
  const selectedPlayerCardMarkup = selectedPlayer
    ? `
    <div class="selected-grid">
      ${renderSelectedMetric("Team", teams[selectedPlayer.team].name, "team")}
      ${renderSelectedMetric("Formation", teams[selectedPlayer.team].formation, "formation")}
      ${renderSelectedProfileControl(selectedPlayer)}
      ${renderSelectedMetric("Role Model", selectedRoleModel?.label ?? "Balanced Role", "roleModel")}
      ${renderSelectedMetric("Physical Level", selectedPhysicalLabel, "physicalProfile")}
      ${renderSelectedMetric("Top Speed", `${selectedPlayer.maxSpeed.toFixed(1)} m/s`, "topSpeed")}
      ${renderSelectedMetric("Acceleration", `${selectedPlayer.acceleration.toFixed(1)} m/s²`, "acceleration")}
      ${renderSelectedMetric("Reaction Time", `${selectedPlayer.reactionTime.toFixed(2)} s`, "reactionTime")}
      ${renderSelectedMetric("Game Intelligence", String(selectedPlayerIntelligence), "gameIntelligence")}
      ${renderSelectedMetric("Can Reach Now", formatMeters(currentReach), "canReachNow")}
      ${renderSelectedMetric("Max Movement in Action", hasBallAction() ? formatMeters(editableRadius) : "Free", "maxMovement")}
      ${renderSelectedMetric(
        "Player Ball Status",
        state.ball.ownerPlayerId === selectedPlayer.id
          ? state.ball.actionType === "dribble"
            ? "Carrying"
            : "On the Ball"
          : "Off the Ball",
        "ballStatus"
      )}
      ${renderSelectedMetric("Distance to Ball", formatMeters(distanceToBall), "distanceToBall")}
      ${renderSelectedMetric(
        "Distance Moved from Action Start",
        hasBallAction() ? formatMeters(movedDistance) : "0.0 m",
        "movedFromStart",
        "selected-span"
      )}
    </div>
  `
    : `<p class="selected-empty">No player selected. Click or box-select a player to inspect them.</p>`;
  const fullscreenSelectedPlayerCardMarkup = selectedPlayer
    ? `
    <div class="selected-grid">
      ${renderSelectedMetric("Top Speed", `${selectedPlayer.maxSpeed.toFixed(1)} m/s`, "topSpeed")}
      ${renderSelectedMetric("Acceleration", `${selectedPlayer.acceleration.toFixed(1)} m/s²`, "acceleration")}
      ${renderSelectedMetric("Reaction Time", `${selectedPlayer.reactionTime.toFixed(2)} s`, "reactionTime")}
      ${renderSelectedMetric("Physical", selectedPhysicalLabel, "physicalProfile")}
      ${renderSelectedMetric("Role", selectedRoleModel?.label ?? "Balanced Role", "roleModel")}
      ${renderSelectedMetric("Profile", selectedPlayer.tendencyProfile?.label ?? "Balanced Profile", "playerProfile")}
      ${renderSelectedMetric("Game Intelligence", String(selectedPlayerIntelligence), "gameIntelligence")}
      ${renderSelectedMetric(
        "Ball Status",
        state.ball.ownerPlayerId === selectedPlayer.id
          ? state.ball.actionType === "dribble"
            ? "Carrying"
            : "On the Ball"
          : "Off the Ball",
        "ballStatus"
      )}
      ${renderSelectedMetric("Distance to Ball", formatMeters(distanceToBall), "distanceToBall")}
      ${renderSelectedMetric("Max Movement", hasBallAction() ? formatMeters(editableRadius) : "Free", "maxMovement")}
    </div>
  `
    : `<p class="selected-empty">No player selected.</p>`;

  ui.simTime.textContent = formatTime(state.time);
  ui.ballStatus.textContent = getBallStatus();
  ui.ballEta.textContent = ballEtaText;
  ui.actionTime.textContent = formatTime(projectedDuration);
  ui.actionType.textContent = getActionTypeLabel();
  ui.ballProfile.textContent = ballProfileText;
  ui.ballCurrentSpeed.textContent = ballSpeedText;
  ui.ballOwner.textContent = ballOwnerText;
  ui.selectedPlayerName.textContent = selectedPlayerText;
  ui.selectedReachAtArrival.textContent = selectedPlayer ? actionDistanceText : "-";
  ui.selectedPlayerCard.innerHTML = selectedPlayerCardMarkup;

  if (ui.fullscreenSimTime) {
    ui.fullscreenSimTime.textContent = formatTime(state.time);
  }
  if (ui.fullscreenBallStatus) {
    ui.fullscreenBallStatus.textContent = getBallStatus();
  }
  if (ui.fullscreenBallEta) {
    ui.fullscreenBallEta.textContent = ballEtaText;
  }
  if (ui.fullscreenActionTime) {
    ui.fullscreenActionTime.textContent = formatTime(projectedDuration);
  }
  if (ui.fullscreenActionType) {
    ui.fullscreenActionType.textContent = getActionTypeLabel();
  }
  if (ui.fullscreenBallProfile) {
    ui.fullscreenBallProfile.textContent = ballProfileText;
  }
  if (ui.fullscreenBallCurrentSpeed) {
    ui.fullscreenBallCurrentSpeed.textContent = ballSpeedText;
  }
  if (ui.fullscreenActionDistance) {
    ui.fullscreenActionDistance.textContent = actionDistanceText;
  }
  if (ui.fullscreenBallOwner) {
    ui.fullscreenBallOwner.textContent = ballOwnerText;
  }
  if (ui.fullscreenSelectedPlayerName) {
    ui.fullscreenSelectedPlayerName.textContent = selectedPlayerText;
  }
  if (ui.fullscreenSelectedReachAtArrival) {
    ui.fullscreenSelectedReachAtArrival.textContent = selectedPlayer ? actionDistanceText : "-";
  }
  if (ui.fullscreenSelectedPlayerCard) {
    ui.fullscreenSelectedPlayerCard.innerHTML = fullscreenSelectedPlayerCardMarkup;
  }

  ui.playerTable.innerHTML = Object.values(teams)
    .map((team) => {
      const rows = state.players
        .filter((player) => player.team === team.id)
        .map((player) => {
          const reachAtArrival = computeReachDistance(player, projectedDuration);
          const moveDistance = distance(getActionOrigin(player), player.position);
          const withinRadius = !hasBallAction() || moveDistance <= getEditableRadius(player) + 0.001;
          const isOwner = state.ball.ownerPlayerId === player.id;
          const selectedClass = isPlayerRenderedSelected(player.id) ? " is-selected" : "";
          const badgeText = !hasBallAction() ? "Free" : withinRadius ? "Inside Radius" : "Outside";
          const badgeClass = !hasBallAction()
            ? ""
            : withinRadius
              ? " is-positive"
              : " is-negative";

          return `
            <button type="button" class="player-chip${selectedClass}" data-player-id="${player.id}">
              <span class="chip-main${isOwner ? " is-owner" : ""}">${player.shortLabel} ${player.role}</span>
              <span class="chip-meta">
                <small>Max in Action: ${hasBallAction() ? formatMeters(reachAtArrival) : "Free"}</small>
                <small>Moved So Far: ${formatMeters(moveDistance)}</small>
              </span>
              <span class="chip-badge${badgeClass}">${badgeText}</span>
            </button>
          `;
        })
        .join("");

      return `
        <section class="team-block">
          <header class="team-heading">
            <span>${team.name}</span>
            <strong>${team.formation}</strong>
          </header>
          <div class="team-players">${rows}</div>
        </section>
      `;
    })
    .join("");

  ui.eventLog.innerHTML = [...state.eventLog]
    .slice(-8)
    .reverse()
    .map((entry) => `<li>${entry}</li>`)
    .join("");

  if (!state.sequence.steps.length) {
    ui.sequenceStatus.textContent = "No sequence recorded yet.";
    ui.sequenceList.innerHTML = "";
  } else {
    const frameLabel =
      state.sequence.currentFrameIndex < 0
        ? `Viewing start frame • ${state.sequence.steps.length} steps saved`
        : `Viewing step ${state.sequence.currentFrameIndex + 1}/${state.sequence.steps.length}`;
    const statusParts = [frameLabel];

    if (state.sequence.isPlaying && state.sequence.playbackIndex >= 0) {
      statusParts.push(
        `Playing step ${state.sequence.playbackIndex + 1}/${state.sequence.steps.length}`
      );
    }

    ui.sequenceStatus.textContent = statusParts.join(" • ");
    ui.sequenceList.innerHTML = state.sequence.steps
      .map((step, index) => {
        const description = describeStep(step, index);
        const isCurrentFrame = !state.sequence.isPlaying && state.sequence.currentFrameIndex === index;
        const isPlaybackFrame = state.sequence.isPlaying && state.sequence.playbackIndex === index;
        const activeClass = isCurrentFrame || isPlaybackFrame ? " is-playing" : "";

        return `
          <article class="sequence-step${activeClass}" data-sequence-frame-index="${index}">
            <img class="sequence-thumb" src="${createStepThumbnail(step.afterSnapshot ?? step.beforeSnapshot)}" alt="${description.title}" />
            <div>
              <strong>${description.title}</strong>
              <small>${description.meta}</small>
            </div>
            <small>${step.speed.toFixed(1)} m/s</small>
          </article>
        `;
      })
      .join("");
  }

  if (!state.savedSequences.length) {
    ui.savedSequenceStatus.textContent = "No central sequences saved yet.";
    ui.savedSequenceList.innerHTML = "";
  } else {
    ui.savedSequenceStatus.textContent = `${state.savedSequences.length} central sequences saved.`;
    ui.savedSequenceList.innerHTML = state.savedSequences
      .map((entry) => {
        const stepCount = entry.sequence?.steps?.length ?? 0;
        const scenarioTitle = entry.sequence?.scenario?.title ?? "Custom Sequence";
        const savedDate = new Date(entry.savedAt).toLocaleString("en-GB");

        return `
          <article class="saved-sequence-item">
            <div class="saved-sequence-head">
              <div>
                <strong>${entry.name}</strong>
                <small>${scenarioTitle}</small>
              </div>
              <small>${stepCount} steps</small>
            </div>
            <p>Saved ${savedDate}</p>
            <div class="saved-sequence-actions">
              <button type="button" class="secondary" data-saved-sequence-action="load" data-saved-sequence-id="${entry.id}">Load</button>
              <button type="button" class="secondary" data-saved-sequence-action="download" data-saved-sequence-id="${entry.id}">Download</button>
              <button type="button" class="secondary" data-saved-sequence-action="delete" data-saved-sequence-id="${entry.id}">Delete</button>
            </div>
          </article>
        `;
      })
      .join("");
  }
}

function render() {
  syncFormationControls();
  syncTeamIdentityControls();
  syncPhysicalProfileControls();
  syncSurfaceControls();
  syncWeatherControls();
  syncFirstTouchControls();
  syncDefensiveAggressionControls();
  syncBallSpeedControls();
  syncDribbleSpeedControls();
  syncDefensiveAutopilotButton();
  syncOffensiveAutopilotButton();
  updateSequenceButtons();
  syncOwnedBallPosition();
  drawPitch();
  drawBallTarget();
  drawReachZones();
  drawExampleOverlay();
  state.players.forEach(drawPlayer);
  drawBall();
  drawGoalFlash();
  drawSelectionBox();
  renderSidebar();
  updatePitchFullscreenHudLayout();
}

function pickPlayer(point) {
  const hitRadius = playerRadiusMeters + 0.5;
  const reversed = [...state.players].reverse();
  return reversed.find((player) => distance(player.position, point) <= hitRadius) ?? null;
}

function isBallHit(point) {
  return distance(state.ball.position, point) <= ballRadiusMeters + 0.55;
}

function clampGroupDragDelta(initialPositions, delta) {
  let minDx = -Infinity;
  let maxDx = Infinity;
  let minDy = -Infinity;
  let maxDy = Infinity;

  Object.values(initialPositions).forEach((position) => {
    minDx = Math.max(minDx, pitch.inset - position.x);
    maxDx = Math.min(maxDx, pitch.length - pitch.inset - position.x);
    minDy = Math.max(minDy, pitch.inset - position.y);
    maxDy = Math.min(maxDy, pitch.width - pitch.inset - position.y);
  });

  return {
    x: clamp(delta.x, minDx, maxDx),
    y: clamp(delta.y, minDy, maxDy),
  };
}

function hasSelectionDragMoved(drag, point) {
  return distance(drag.startPoint, point) > 0.35;
}

function getSelectionRect(startPoint, endPoint) {
  return {
    left: Math.min(startPoint.x, endPoint.x),
    right: Math.max(startPoint.x, endPoint.x),
    top: Math.min(startPoint.y, endPoint.y),
    bottom: Math.max(startPoint.y, endPoint.y),
  };
}

function getPlayersInsideSelectionRect(rect) {
  const selectionPadding = playerRadiusMeters * 0.4;
  return state.players
    .filter((player) =>
      player.position.x >= rect.left - selectionPadding &&
      player.position.x <= rect.right + selectionPadding &&
      player.position.y >= rect.top - selectionPadding &&
      player.position.y <= rect.bottom + selectionPadding
    )
    .map((player) => player.id);
}

function updateSelectionDragPreview(drag, point) {
  drag.currentPoint = cloneVector(point);
  drag.moved = drag.moved || hasSelectionDragMoved(drag, point);

  if (!drag.moved) {
    drag.previewSelectedPlayerIds = [...drag.baseSelectedPlayerIds];
    drag.previewPrimaryPlayerId = drag.basePrimaryPlayerId;
    return;
  }

  const rect = getSelectionRect(drag.startPoint, point);
  const hitPlayerIds = getPlayersInsideSelectionRect(rect);
  const previewSelectedPlayerIds = drag.append
    ? normalizeSelectedPlayerIds(
        [...drag.baseSelectedPlayerIds, ...hitPlayerIds],
        drag.basePrimaryPlayerId ?? hitPlayerIds[0] ?? state.selectedPlayerId
      )
    : hitPlayerIds;
  const previewPrimaryPlayerId =
    previewSelectedPlayerIds.includes(drag.basePrimaryPlayerId)
      ? drag.basePrimaryPlayerId
      : previewSelectedPlayerIds[0] ?? drag.basePrimaryPlayerId ?? state.selectedPlayerId;

  drag.previewSelectedPlayerIds = previewSelectedPlayerIds;
  drag.previewPrimaryPlayerId = previewPrimaryPlayerId;
}

function syncBallToManualPlayerMove(playerIds) {
  const movedPlayerIds = new Set(playerIds);

  if (!hasBallAction() && state.ball.ownerPlayerId && movedPlayerIds.has(state.ball.ownerPlayerId)) {
    const owner = getPlayerById(state.ball.ownerPlayerId);
    if (owner) {
      const controlPoint = getPlayerBallControlPoint(owner);
      state.ball.position = cloneVector(controlPoint);
      state.ball.startPosition = cloneVector(controlPoint);
      state.ball.target = cloneVector(controlPoint);
    }
  }

  if (state.ball.actionType === "dribble" && state.ball.carrierPlayerId && movedPlayerIds.has(state.ball.carrierPlayerId) && !state.isRunning) {
    const carrier = getPlayerById(state.ball.carrierPlayerId);
    if (carrier) {
      state.ball.position = cloneVector(getPlayerBallControlPoint(carrier));
    }
  }

  if (state.ball.actionType === "pass" && state.ball.receiverPlayerId && movedPlayerIds.has(state.ball.receiverPlayerId) && !state.isRunning) {
    const receiver = getPlayerById(state.ball.receiverPlayerId);
    if (receiver) {
      state.ball.target = cloneVector(getPlayerBallControlPoint(receiver));
      if (state.draftStep?.actionType === "pass") {
        state.draftStep.target = cloneVector(getPlayerBallControlPoint(receiver));
        refreshPlannedBallActionProfile();
      }
    }
  }
}

function handlePointerDown(event) {
  const point = clampToPitch(eventToPitch(event));

  if (state.isRunning || state.sequence.isPlaying) {
    const player = pickPlayer(point);
    if (player) {
      setSingleSelectedPlayer(player.id);
      render();
    }
    return;
  }

  const activeActionMode = getPointerRequestedActionMode();
  if (activeActionMode && !isBallHit(point)) {
    const player = pickPlayer(point);

    if (activeActionMode === "pass" && player) {
      issuePassCommand(player.position, player.id);
    } else {
      issueBallCommand(player ? player.position : point, activeActionMode);
    }

    consumePointerActionMode(activeActionMode);
    render();
    return;
  }

  if (isBallHit(point)) {
    if (hasBallAction() || state.draftStep) {
      clearBallAction();
      logEvent("Ball action cleared. Players can move freely again.");
    }
    state.drag = {
      type: "ball",
      pointerId: event.pointerId,
      startPosition: cloneVector(point),
      moved: false,
    };
    canvas.setPointerCapture(event.pointerId);
    return;
  }

  const player = pickPlayer(point);
  if (player) {
    if (!hasBallAction() && isSelectionModifierActive(event)) {
      toggleSelectedPlayer(player.id);
      render();
      return;
    }

    if (!isPlayerSelected(player.id) || hasBallAction()) {
      setSingleSelectedPlayer(player.id);
    } else {
      setSelectedPlayers(getSelectedPlayerIds(), player.id);
    }

    const dragPlayerIds = !hasBallAction()
      ? getSelectedPlayerIds()
      : [player.id];

    state.drag = {
      type: "player",
      pointerId: event.pointerId,
      playerId: player.id,
      playerIds: dragPlayerIds,
      pointerStart: cloneVector(point),
      actionOrigin: hasBallAction() ? cloneVector(getActionOrigin(player)) : null,
      editableRadius: hasBallAction() ? getEditableRadius(player) : null,
      initialPositions: Object.fromEntries(
        dragPlayerIds.map((playerId) => [playerId, cloneVector(getPlayerById(playerId).position)])
      ),
      moved: false,
    };
    canvas.setPointerCapture(event.pointerId);
    render();
    return;
  }

  if (!hasBallAction()) {
    state.drag = {
      type: "selection",
      pointerId: event.pointerId,
      startPoint: cloneVector(point),
      currentPoint: cloneVector(point),
      append: isSelectionModifierActive(event),
      baseSelectedPlayerIds: getSelectedPlayerIds(),
      basePrimaryPlayerId: state.selectedPlayerId,
      previewSelectedPlayerIds: getSelectedPlayerIds(),
      previewPrimaryPlayerId: state.selectedPlayerId,
      moved: false,
    };
    canvas.setPointerCapture(event.pointerId);
  }
}

function handlePointerMove(event) {
  if (!state.drag || state.isRunning || state.sequence.isPlaying) {
    return;
  }

  const point = clampToPitch(eventToPitch(event));

  if (state.drag.type === "player") {
    const dragPlayerIds = state.drag.playerIds?.filter((playerId) => getPlayerById(playerId)) ?? [];
    if (!dragPlayerIds.length) {
      return;
    }

    if (!hasBallAction() && dragPlayerIds.length > 1) {
      const delta = subtract(point, state.drag.pointerStart);
      const clampedDelta = clampGroupDragDelta(state.drag.initialPositions, delta);

      dragPlayerIds.forEach((playerId) => {
        const player = getPlayerById(playerId);
        const startPosition = state.drag.initialPositions[playerId];
        if (!player || !startPosition) {
          return;
        }

        player.position = {
          x: startPosition.x + clampedDelta.x,
          y: startPosition.y + clampedDelta.y,
        };
      });

      state.drag.moved = Math.abs(clampedDelta.x) > 0.001 || Math.abs(clampedDelta.y) > 0.001;
      syncBallToManualPlayerMove(dragPlayerIds);
      render();
      return;
    }

    const player = getPlayerById(state.drag.playerId);
    if (!player) {
      return;
    }

    const previousPosition = cloneVector(player.position);
    if (hasBallAction()) {
      player.position = clampToCircle(
        point,
        state.drag.actionOrigin ?? getActionOrigin(player),
        state.drag.editableRadius ?? getEditableRadius(player)
      );
    } else {
      player.position = point;
    }

    if (hasBallAction()) {
      rotatePlayerBodyAlongMovement(player, previousPosition, player.position, 0.95);
    }

    state.drag.moved =
      state.drag.moved || distance(state.drag.initialPositions[player.id], player.position) > 0.001;
    syncBallToManualPlayerMove([player.id]);
    setSelectedPlayers(getSelectedPlayerIds(), player.id);
    render();
    return;
  }

  if (state.drag.type === "ball") {
    clearBallAction();
    clearSecurePossession();
    state.ball.ownerPlayerId = null;
    state.ball.position = point;
    state.ball.startPosition = point;
    state.ball.target = point;
    state.drag.moved =
      state.drag.moved || distance(state.drag.startPosition, state.ball.position) > 0.001;
    render();
  }

  if (state.drag.type === "selection") {
    updateSelectionDragPreview(state.drag, point);
    render();
  }
}

function handlePointerUp(event) {
  if (!state.drag) {
    return;
  }

  if (state.drag.type === "player" && state.drag.moved) {
    markSimulatorDirty();
    const movedPlayerCount = state.drag.playerIds?.length ?? 1;
    const player = getPlayerById(state.drag.playerId);
    if (movedPlayerCount > 1 && !hasBallAction()) {
      logEvent(`${movedPlayerCount} players moved manually.`);
    } else if (player) {
      logEvent(`${player.shortLabel} ${player.role} moved manually.`);
    }
  }

  if (state.drag.type === "ball" && state.drag.moved) {
    markSimulatorDirty();
    logEvent("Ball moved manually.");
  }

  if (state.drag.type === "selection" && state.drag.moved) {
    const previewSelectedPlayerIds = state.drag.previewSelectedPlayerIds ?? [];
    const selectionChanged =
      previewSelectedPlayerIds.length !== state.drag.baseSelectedPlayerIds.length ||
      previewSelectedPlayerIds.some((playerId, index) => playerId !== state.drag.baseSelectedPlayerIds[index]);

    if (previewSelectedPlayerIds.length && selectionChanged) {
      setSelectedPlayers(previewSelectedPlayerIds, state.drag.previewPrimaryPlayerId);
      logEvent(
        previewSelectedPlayerIds.length === 1
          ? "1 player selected."
          : `${previewSelectedPlayerIds.length} players selected.`
      );
    }
  }

  if (canvas.hasPointerCapture(event.pointerId)) {
    canvas.releasePointerCapture(event.pointerId);
  }

  state.drag = null;
  render();
}

function handlePointerCancel(event) {
  if (canvas.hasPointerCapture(event.pointerId)) {
    canvas.releasePointerCapture(event.pointerId);
  }
  state.drag = null;
}

function handleCanvasDoubleClick() {
  if (state.isRunning || state.sequence.isPlaying) {
    return;
  }

  if (!getSelectedPlayerIds().length && !state.selectedPlayerId) {
    return;
  }

  clearSelectedPlayers();
  logEvent("All players deselected.");
  render();
}

function isGameSimulatorWorkspaceActive() {
  return hubState?.activeWorkspaceId === "game-simulator";
}

function resetSimulatorAnimationClock() {
  lastFrame = null;
}

async function getSimulatorAnimationRuntime() {
  if (simulatorAnimationRuntime) {
    return simulatorAnimationRuntime;
  }

  if (!simulatorAnimationRuntimePromise) {
    simulatorAnimationRuntimePromise = import("./src/modules/game-simulator/runtime.mjs")
      .then(({ createSimulatorAnimationLoop }) => {
        simulatorAnimationRuntime = createSimulatorAnimationLoop({
          shouldRun: () => simulatorAnimationLoopRequested && isGameSimulatorWorkspaceActive(),
          onFrame: animationFrame,
        });
        return simulatorAnimationRuntime;
      })
      .catch((error) => {
        simulatorAnimationRuntimePromise = null;
        console.error(error);
        throw error;
      });
  }

  return simulatorAnimationRuntimePromise;
}

function startSimulatorAnimationLoop() {
  simulatorAnimationLoopRequested = true;
  getSimulatorAnimationRuntime()
    .then((runtime) => {
      if (simulatorAnimationLoopRequested && isGameSimulatorWorkspaceActive()) {
        runtime.start();
      }
    })
    .catch(() => {});
}

function stopSimulatorAnimationLoop() {
  simulatorAnimationLoopRequested = false;
  simulatorAnimationRuntime?.stop();
  resetSimulatorAnimationClock();
}

function animationFrame(timestamp) {
  if (!isGameSimulatorWorkspaceActive()) {
    resetSimulatorAnimationClock();
    return;
  }

  if (lastFrame === null) {
    lastFrame = timestamp;
  }

  const realDt = Math.min((timestamp - lastFrame) / 1000, 0.05);
  lastFrame = timestamp;

  if (state.isRunning) {
    stepSimulation(realDt);
  }

  applyNearbyBallOrientation(realDt);

  render();
}

function executePlannedAction() {
  if (!isGameSimulatorWorkspaceActive()) {
    return;
  }

  if (state.isRunning || state.sequence.isPlaying) {
    return;
  }

  if (!hasBallAction()) {
    logEvent("Set a new ball target before starting the action.");
    render();
    return;
  }

  if (state.draftStep?.beforeSnapshot && !state.activeActionTargets) {
    const actionTargetSnapshot = captureSnapshot();
    const resolvedProfile = resolveRecordedStepProfile(state.draftStep);
    state.activeActionTargets = new Map(
      actionTargetSnapshot.players.map((player) => [
        player.id,
        cloneVector(player.position),
      ])
    );

    applySnapshot(state.draftStep.beforeSnapshot);
    setSelectedPlayers(
      actionTargetSnapshot.selectedPlayerIds ?? [],
      actionTargetSnapshot.selectedPlayerId ?? actionTargetSnapshot.selectedPlayerIds?.[0] ?? null
    );

    if (state.draftStep.actionType === "dribble") {
      const carrier = getPlayerById(state.draftStep.carrierPlayerId);
      state.dribbleSpeed = state.draftStep.speed;
      ui.dribbleSpeed.value = String(state.draftStep.speed);
      ui.dribbleSpeedLabel.textContent = `${state.draftStep.speed.toFixed(1)} m/s`;
      applyResolvedBallProfile(resolvedProfile);
      state.ball.position = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      state.ball.startPosition = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      state.ball.target = cloneVector(state.draftStep.target);
      state.ball.inTransit = true;
      state.ball.elapsedTravelTime = 0;
      state.ball.actionType = "dribble";
      state.ball.initiatorPlayerId = state.draftStep.carrierPlayerId ?? null;
      state.ball.carrierPlayerId = state.draftStep.carrierPlayerId ?? null;
      state.ball.receiverPlayerId = null;
      state.ball.ownerPlayerId = state.draftStep.carrierPlayerId ?? null;
      applyBallExecutionProfile("dribble", carrier, state.draftStep.target, resolvedProfile);
      configureBallTravelProfile(
        "dribble",
        distance(state.ball.startPosition, state.ball.target),
        getActionSpeed(),
        resolvedProfile
      );
      if (carrier) {
        setDribbleCarryPathForBall(carrier, carrier.position, state.ball.target);
      }
    } else if (state.draftStep.actionType === "recovery") {
      applyResolvedBallProfile(resolvedProfile);
      state.ball.speed = state.draftStep.speed;
      state.ball.position = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      state.ball.startPosition = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      state.ball.target = cloneVector(state.draftStep.target);
      state.ball.inTransit = true;
      state.ball.elapsedTravelTime = 0;
      state.ball.actionType = "recovery";
      state.ball.initiatorPlayerId = state.draftStep.carrierPlayerId ?? null;
      state.ball.carrierPlayerId = state.draftStep.carrierPlayerId ?? null;
      state.ball.receiverPlayerId = null;
      state.ball.ownerPlayerId = null;
      state.ball.recoveryDuration = Math.max(state.draftStep.recoveryDuration ?? 0, 0.35);
      state.ball.currentSpeed = 0;
      state.ball.launchSpeed = 0;
      state.ball.finalSpeed = 0;
      state.ball.deceleration = 0;
      state.ball.trackDistanceTotal = 0;
      state.ball.trackDistanceCovered = 0;
    } else {
      const initiator = getPlayerById(state.draftStep.beforeSnapshot.ball.ownerPlayerId);
      state.ballSpeedMode = state.draftStep.speedMode ?? state.ballSpeedMode;
      state.ball.speed = state.draftStep.speed;
      if (state.draftStep.speedMode === "manual") {
        state.ball.manualSpeed = state.draftStep.speed;
      }
      applyResolvedBallProfile(resolvedProfile);
      state.ball.position = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      state.ball.startPosition = cloneVector(state.draftStep.beforeSnapshot.ball.position);
      const intendedTarget = cloneVector(state.draftStep.target);
      state.ball.target = cloneVector(intendedTarget);
      state.ball.inTransit = true;
      state.ball.elapsedTravelTime = 0;
      state.ball.actionType = state.draftStep.actionType;
      state.ball.initiatorPlayerId = state.draftStep.beforeSnapshot.ball.ownerPlayerId ?? null;
      state.ball.carrierPlayerId = null;
      state.ball.receiverPlayerId = state.draftStep.receiverPlayerId ?? null;
      state.ball.firstTouchMode = state.draftStep.firstTouchMode ?? "auto";
      state.ball.ownerPlayerId = null;
      applyBallExecutionProfile(state.draftStep.actionType, initiator, intendedTarget, resolvedProfile);
      if (state.draftStep.actionType === "shot") {
        const executedTarget = resolveExecutedShotTarget(initiator, intendedTarget, resolvedProfile) ?? intendedTarget;
        state.ball.target = cloneVector(executedTarget);
        state.draftStep.intendedTarget = cloneVector(intendedTarget);
        state.draftStep.target = cloneVector(executedTarget);
        state.draftStep.shotPlacement = cloneShotPlacement(state.ball.shotPlacement);
      }
      configureBallTravelProfile(
        state.draftStep.actionType,
        distance(state.ball.startPosition, state.ball.target),
        getActionSpeed(),
        resolvedProfile
      );
    }

    state.players.forEach((player) => {
      player.actionOrigin = cloneVector(player.position);
    });
  }

  state.isRunning = true;
  ui.playPauseButton.textContent = "Pause";
  logEvent("Action started.");
}

function pauseLiveSimulation(message = "Simulation paused.") {
  state.isRunning = false;
  ui.playPauseButton.textContent = "Start";
  logEvent(message);
  updateSequenceButtons();
  render();
}

function resumeLiveSimulation(message = "Simulation resumed.") {
  state.isRunning = true;
  ui.playPauseButton.textContent = "Pause";
  logEvent(message);
  updateSequenceButtons();
  render();
}

function toggleSpaceAutopilotPlayback() {
  if (!state.offensiveAutopilot) {
    return;
  }

  if (state.sequence.isPlaying) {
    if (state.isRunning) {
      pauseAutoPilotPlay("Auto play paused.");
      return;
    }

    state.autoPilotPlay.active = true;
    resumeLiveSimulation("Autopilot playback resumed.");
    return;
  }

  if (state.isRunning) {
    pauseAutoPilotPlay("Auto play paused.");
    return;
  }

  if (state.autoPilotPlay?.active && !hasBallAction() && !state.draftStep) {
    pauseAutoPilotPlay("Auto play paused.");
    return;
  }

  state.autoPilotPlay.active = true;

  if (state.ball.inTransit && (hasBallAction() || state.draftStep)) {
    resumeLiveSimulation("Auto play resumed.");
    return;
  }

  if (hasBallAction() || state.draftStep) {
    executePlannedAction();
    render();
    return;
  }

  planAutoPilotNextAction({ startImmediately: true });
}

function positionMetricTooltip(target) {
  if (!ui.metricTooltip || !target) {
    return;
  }

  if (!target.isConnected) {
    hideMetricTooltip({ force: true });
    return;
  }

  const rect = target.getBoundingClientRect();
  const padding = 12;
  const tooltipWidth = ui.metricTooltip.offsetWidth;
  const tooltipHeight = ui.metricTooltip.offsetHeight;
  let left = rect.left + rect.width / 2 - tooltipWidth / 2;
  let top = rect.bottom + 10;

  left = clamp(left, padding, window.innerWidth - tooltipWidth - padding);
  if (top + tooltipHeight > window.innerHeight - padding) {
    top = rect.top - tooltipHeight - 10;
  }
  top = clamp(top, padding, window.innerHeight - tooltipHeight - padding);

  ui.metricTooltip.style.left = `${left}px`;
  ui.metricTooltip.style.top = `${top}px`;
}

function ensureMetricTooltipLayer() {
  if (!ui.metricTooltip) {
    return;
  }

  const layerRoot = document.fullscreenElement ?? document.body;
  if (ui.metricTooltip.parentElement !== layerRoot) {
    layerRoot.appendChild(ui.metricTooltip);
  }
}

function showMetricTooltip(target, { pinned = false } = {}) {
  const helpText = target?.dataset?.metricHelp;
  if (!ui.metricTooltip || !helpText) {
    return;
  }

  ensureMetricTooltipLayer();
  activeMetricTooltipTarget = target;
  pinnedMetricTooltipTarget = pinned ? target : pinnedMetricTooltipTarget;
  ui.metricTooltip.textContent = helpText;
  ui.metricTooltip.hidden = false;
  ui.metricTooltip.classList.add("is-visible");
  ui.metricTooltip.dataset.metricLabel = target.dataset.metricLabel ?? "";
  target.setAttribute("aria-expanded", "true");
  positionMetricTooltip(target);
}

function hideMetricTooltip({ force = false } = {}) {
  if (!ui.metricTooltip) {
    return;
  }

  if (!force && pinnedMetricTooltipTarget) {
    return;
  }

  if (activeMetricTooltipTarget) {
    activeMetricTooltipTarget.setAttribute("aria-expanded", "false");
  }

  activeMetricTooltipTarget = null;
  pinnedMetricTooltipTarget = null;
  ui.metricTooltip.classList.remove("is-visible");
  ui.metricTooltip.hidden = true;
  delete ui.metricTooltip.dataset.metricLabel;
}

