    writePeriodizationDay(
      sessionPlannerPeriodizationOverlayDate,
      {
        [fieldKey]: getPeriodizationCustomFieldValue(
          periodizationCustomField,
          sessionPlannerPeriodizationOverlayDate
        ),
      },
      false
    );
    refreshSessionPlannerPeriodizationEditSurfaces(fieldKey);
